window.SIDURON_SHABBAT = {"edot_mizrach": {"maariv": [{"kind": "header", "text": "קבלת שבת"}, {"kind": "text", "text": "<b>לְ֭כוּ</b> (תהילים צ״ה:א׳-ב׳) נְרַנְּנָ֣ה לַיהֹוָ֑ה נָ֝רִ֗יעָה לְצ֣וּר יִשְׁעֵֽנוּ׃ נְקַדְּמָ֣ה פָנָ֣יו בְּתוֹדָ֑ה בִּ֝זְמִר֗וֹת נָרִ֥יעַֽ לֽוֹ׃ כִּ֤י אֵ֣ל גָּד֣וֹל יְהֹוָ֑ה וּמֶ֥לֶךְ גָּ֝ד֗וֹל עַל־כׇּל־אֱלֹהִֽים׃ אֲשֶׁ֣ר בְּ֭יָדוֹ מֶחְקְרֵי־אָ֑רֶץ וְתוֹעֲפֹ֖ת הָרִ֣ים לֽוֹ׃ אֲשֶׁר־ל֣וֹ הַ֭יָּם וְה֣וּא עָשָׂ֑הוּ וְ֝יַבֶּ֗שֶׁת יָדָ֥יו יָצָֽרוּ׃ בֹּ֭אוּ נִשְׁתַּחֲוֶ֣ה וְנִכְרָ֑עָה נִ֝בְרְכָ֗ה לִֽפְנֵי־יְהֹוָ֥ה עֹשֵֽׂנוּ׃ כִּ֘י ה֤וּא אֱלֹהֵ֗ינוּ וַאֲנַ֤חְנוּ עַ֣ם מַ֭רְעִיתוֹ וְצֹ֣אן יָד֑וֹ הַ֝יּ֗וֹם אִֽם־בְּקֹל֥וֹ תִשְׁמָֽעוּ׃ אַל־תַּקְשׁ֣וּ לְ֭בַבְכֶם כִּמְרִיבָ֑ה כְּי֥וֹם מַ֝סָּ֗ה בַּמִּדְבָּֽר׃ אֲשֶׁ֣ר נִ֭סּוּנִי אֲבֽוֹתֵיכֶ֑ם בְּ֝חָנ֗וּנִי גַּם־רָא֥וּ פׇעֳלִֽי׃ אַרְבָּ֘עִ֤ים שָׁנָ֨ה ׀ אָ֘ק֤וּט בְּד֗וֹר וָאֹמַ֗ר עַ֤ם תֹּעֵ֣י לֵבָ֣ב הֵ֑ם וְ֝הֵ֗ם לֹא־יָדְע֥וּ דְרָכָֽי׃ אֲשֶׁר־נִשְׁבַּ֥עְתִּי בְאַפִּ֑י אִם־יְ֝בֹא֗וּן אֶל־מְנוּחָתִֽי׃"}, {"kind": "text", "text": "<b>שִׁ֣ירוּ</b> (תהילים צ״ו:א׳-ב׳) לַ֭יהֹוָה שִׁ֣יר חָדָ֑שׁ שִׁ֥ירוּ לַ֝יהֹוָ֗ה כׇּל־הָאָֽרֶץ׃ שִׁ֣ירוּ לַ֭יהֹוָה בָּרְכ֣וּ שְׁמ֑וֹ בַּשְּׂר֥וּ מִיּֽוֹם־לְ֝י֗וֹם יְשׁוּעָתֽוֹ׃ סַפְּר֣וּ בַגּוֹיִ֣ם כְּבוֹד֑וֹ בְּכׇל־הָ֝עַמִּ֗ים נִפְלְאוֹתָֽיו׃ כִּ֥י גָ֘ד֤וֹל יְהֹוָ֣ה וּמְהֻלָּ֣ל מְאֹ֑ד נוֹרָ֥א ה֗֝וּא עַל־כׇּל־אֱלֹהִֽים׃ כִּ֤י ׀ כׇּל־אֱלֹהֵ֣י הָעַמִּ֣ים אֱלִילִ֑ים וַ֝יהֹוָ֗ה שָׁמַ֥יִם עָשָֽׂה׃ הוֹד־וְהָדָ֥ר לְפָנָ֑יו עֹ֥ז וְ֝תִפְאֶ֗רֶת בְּמִקְדָּשֽׁוֹ׃ הָב֣וּ לַ֭יהֹוָה מִשְׁפְּח֣וֹת עַמִּ֑ים הָב֥וּ לַ֝יהֹוָ֗ה כָּב֥וֹד וָעֹֽז׃ הָב֣וּ לַ֭יהֹוָה כְּב֣וֹד שְׁמ֑וֹ שְׂאֽוּ־מִ֝נְחָ֗ה וּבֹ֥אוּ לְחַצְרוֹתָֽיו׃ הִשְׁתַּחֲו֣וּ לַ֭יהֹוָה בְּהַדְרַת־קֹ֑דֶשׁ חִ֥ילוּ מִ֝פָּנָ֗יו כׇּל־הָאָֽרֶץ׃ אִמְר֤וּ בַגּוֹיִ֨ם ׀ יְהֹ֘וָ֤ה מָלָ֗ךְ אַף־תִּכּ֣וֹן תֵּ֭בֵל בַּל־תִּמּ֑וֹט יָדִ֥ין עַ֝מִּ֗ים בְּמֵישָׁרִֽים׃ יִשְׂמְח֣וּ הַ֭שָּׁמַיִם וְתָגֵ֣ל הָאָ֑רֶץ יִֽרְעַ֥ם הַ֝יָּ֗ם וּמְלֹאֽוֹ׃ יַעֲלֹ֣ז שָׂ֭דַי וְכׇל־אֲשֶׁר־בּ֑וֹ אָ֥ז יְ֝רַנְּנ֗וּ כׇּל־עֲצֵי־יָֽעַר׃ לִפְנֵ֤י יְהֹוָ֨ה ׀ כִּ֬י בָ֗א כִּ֥י בָא֮ לִשְׁפֹּ֢ט הָ֫אָ֥רֶץ יִשְׁפֹּֽט־תֵּבֵ֥ל בְּצֶ֑דֶק וְ֝עַמִּ֗ים בֶּאֱמוּנָתֽוֹ׃"}, {"kind": "text", "text": "<b>יְהֹוָ֣ה</b> (תהילים צ״ז:א׳-ב׳) מָ֭לָךְ תָּגֵ֣ל הָאָ֑רֶץ יִ֝שְׂמְח֗וּ אִיִּ֥ים רַבִּֽים׃ עָנָ֣ן וַעֲרָפֶ֣ל סְבִיבָ֑יו צֶ֥דֶק וּ֝מִשְׁפָּ֗ט מְכ֣וֹן כִּסְאֽוֹ׃ אֵ֭שׁ לְפָנָ֣יו תֵּלֵ֑ךְ וּתְלַהֵ֖ט סָבִ֣יב צָרָֽיו׃ הֵאִ֣ירוּ בְרָקָ֣יו תֵּבֵ֑ל רָאֲתָ֖ה וַתָּחֵ֣ל הָאָֽרֶץ׃ הָרִ֗ים כַּדּוֹנַ֗ג נָ֭מַסּוּ מִלִּפְנֵ֣י יְהֹוָ֑ה מִ֝לִּפְנֵ֗י אֲד֣וֹן כׇּל־הָאָֽרֶץ׃ הִגִּ֣ידוּ הַשָּׁמַ֣יִם צִדְק֑וֹ וְרָא֖וּ כׇל־הָעַמִּ֣ים כְּבוֹדֽוֹ׃ יֵבֹ֤שׁוּ ׀ כׇּל־עֹ֬בְדֵי פֶ֗סֶל הַמִּֽתְהַלְלִ֥ים בָּאֱלִילִ֑ים הִשְׁתַּחֲווּ־ל֗֝וֹ כׇּל־אֱלֹהִֽים׃ שָׁמְעָ֬ה וַתִּשְׂמַ֨ח ׀ צִיּ֗וֹן וַ֭תָּגֵלְנָה בְּנ֣וֹת יְהוּדָ֑ה לְמַ֖עַן מִשְׁפָּטֶ֣יךָ יְהֹוָֽה׃ כִּֽי־אַתָּ֤ה יְהֹוָ֗ה עֶלְי֥וֹן עַל־כׇּל־הָאָ֑רֶץ מְאֹ֥ד נַ֝עֲלֵ֗יתָ עַל־כׇּל־אֱלֹהִֽים׃ אֹֽהֲבֵ֥י יְהֹוָ֗ה שִׂנְא֫וּ רָ֥ע שֹׁ֭מֵר נַפְשׁ֣וֹת חֲסִידָ֑יו מִיַּ֥ד רְ֝שָׁעִ֗ים יַצִּילֵֽם׃ א֭וֹר זָרֻ֣עַ לַצַּדִּ֑יק וּֽלְיִשְׁרֵי־לֵ֥ב שִׂמְחָֽה׃ שִׂמְח֣וּ צַ֭דִּיקִים בַּיהֹוָ֑ה וְ֝הוֹד֗וּ לְזֵ֣כֶר קׇדְשֽׁוֹ׃"}, {"kind": "text", "text": "<b>מִזְמ֡וֹר</b> (תהילים צ״ח:א׳) שִׁ֤ירוּ לַיהֹוָ֨ה ׀ שִׁ֣יר חָ֭דָשׁ כִּֽי־נִפְלָא֣וֹת עָשָׂ֑ה הוֹשִׁיעָה־לּ֥וֹ יְ֝מִינ֗וֹ וּזְר֥וֹעַ קׇדְשֽׁוֹ׃ הוֹדִ֣יעַ יְ֭הֹוָה יְשׁוּעָת֑וֹ לְעֵינֵ֥י הַ֝גּוֹיִ֗ם גִּלָּ֥ה צִדְקָתֽוֹ׃ זָ֘כַ֤ר חַסְדּ֨וֹ ׀ וֶ֥אֱֽמוּנָתוֹ֮ לְבֵ֢ית יִשְׂרָ֫אֵ֥ל רָא֥וּ כׇל־אַפְסֵי־אָ֑רֶץ אֵ֗֝ת יְשׁוּעַ֥ת אֱלֹהֵֽינוּ׃ הָרִ֣יעוּ לַ֭יהֹוָה כׇּל־הָאָ֑רֶץ פִּצְח֖וּ וְרַנְּנ֣וּ וְזַמֵּֽרוּ׃ זַמְּר֣וּ לַיהֹוָ֣ה בְּכִנּ֑וֹר בְּ֝כִנּ֗וֹר וְק֣וֹל זִמְרָֽה׃ בַּ֭חֲצֹ֣צְרוֹת וְק֣וֹל שׁוֹפָ֑ר הָ֝רִ֗יעוּ לִפְנֵ֤י ׀ הַמֶּ֬לֶךְ יְהֹוָֽה׃ יִרְעַ֣ם הַ֭יָּם וּמְלֹא֑וֹ תֵּ֝בֵ֗ל וְיֹ֣שְׁבֵי בָֽהּ׃ נְהָר֥וֹת יִמְחֲאוּ־כָ֑ף יַ֗֝חַד הָרִ֥ים יְרַנֵּֽנוּ׃ לִ֥פְֽנֵי יְהֹוָ֗ה כִּ֥י בָא֮ לִשְׁפֹּ֢ט הָ֫אָ֥רֶץ יִשְׁפֹּֽט־תֵּבֵ֥ל בְּצֶ֑דֶק וְ֝עַמִּ֗ים בְּמֵישָׁרִֽים׃"}, {"kind": "text", "text": "<b>יְהֹוָ֣ה</b> (תהילים צ״ט:א׳-ב׳) מָ֭לָךְ יִרְגְּז֣וּ עַמִּ֑ים יֹשֵׁ֥ב כְּ֝רוּבִ֗ים תָּנ֥וּט הָאָֽרֶץ׃ יְ֭הֹוָה בְּצִיּ֣וֹן גָּד֑וֹל וְרָ֥ם ה֗֝וּא עַל־כׇּל־הָעַמִּֽים׃ יוֹד֣וּ שִׁ֭מְךָ גָּד֥וֹל וְנוֹרָ֗א קָד֥וֹשׁ הֽוּא׃ וְעֹ֥ז מֶלֶךְ֮ מִשְׁפָּ֢ט אָ֫הֵ֥ב אַ֭תָּה כּוֹנַ֣נְתָּ מֵישָׁרִ֑ים מִשְׁפָּ֥ט וּ֝צְדָקָ֗ה בְּיַעֲקֹ֤ב ׀ אַתָּ֬ה עָשִֽׂיתָ׃ רוֹמְמ֡וּ יְהֹ֘וָ֤ה אֱלֹהֵ֗ינוּ וְֽ֭הִשְׁתַּחֲווּ לַהֲדֹ֥ם רַגְלָ֗יו קָד֥וֹשׁ הֽוּא׃ מֹ֘שֶׁ֤ה וְאַֽהֲרֹ֨ן ׀ בְּֽכֹהֲנָ֗יו וּ֭שְׁמוּאֵל בְּקֹרְאֵ֣י שְׁמ֑וֹ קֹרִ֥אים אֶל־יְ֝הֹוָ֗ה וְה֣וּא יַעֲנֵֽם׃ בְּעַמּ֣וּד עָ֭נָן יְדַבֵּ֣ר אֲלֵיהֶ֑ם שָׁמְר֥וּ עֵ֝דֹתָ֗יו וְחֹ֣ק נָֽתַן־לָֽמוֹ׃ יְהֹוָ֣ה אֱלֹהֵינוּ֮ אַתָּ֢ה עֲנִ֫יתָ֥ם אֵ֣ל נֹ֭שֵׂא הָיִ֣יתָ לָהֶ֑ם וְ֝נֹקֵ֗ם עַל־עֲלִילוֹתָֽם׃ רוֹמְמ֡וּ יְהֹ֘וָ֤ה אֱלֹהֵ֗ינוּ וְֽ֭הִשְׁתַּחֲווּ לְהַ֣ר קׇדְשׁ֑וֹ כִּי־קָ֝ד֗וֹשׁ יְהֹוָ֥ה אֱלֹהֵֽינוּ׃"}, {"kind": "text", "text": "<b>מִזְמ֥וֹר</b> (תהילים ק׳:א׳-ב׳) לְתוֹדָ֑ה הָרִ֥יעוּ לַ֝יהֹוָ֗ה כׇּל־הָאָֽרֶץ׃ עִבְד֣וּ אֶת־יְהֹוָ֣ה בְּשִׂמְחָ֑ה בֹּ֥אוּ לְ֝פָנָ֗יו בִּרְנָנָֽה׃ דְּע֗וּ כִּֽי־יְהֹוָה֮ ה֤וּא אֱלֹ֫הִ֥ים הֽוּא־עָ֭שָׂנוּ ולא [וְל֣וֹ] אֲנַ֑חְנוּ עַ֝מּ֗וֹ וְצֹ֣אן מַרְעִיתֽוֹ׃ בֹּ֤אוּ שְׁעָרָ֨יו ׀ בְּתוֹדָ֗ה חֲצֵרֹתָ֥יו בִּתְהִלָּ֑ה הוֹדוּ־ל֗֝וֹ בָּרְכ֥וּ שְׁמֽוֹ׃ כִּי־ט֣וֹב יְ֭הֹוָה לְעוֹלָ֣ם חַסְדּ֑וֹ וְעַד־דֹּ֥ר וָ֝דֹ֗ר אֱמוּנָתֽוֹ׃"}, {"kind": "text", "text": "עומדים ואומרים<br><b>מִזְמ֗וֹר</b> (תהילים כ״ט) לְדָ֫וִ֥ד הָב֣וּ לַ֭יהֹוָה בְּנֵ֣י אֵלִ֑ים הָב֥וּ לַ֝יהֹוָ֗ה כָּב֥וֹד וָעֹֽז׃ הָב֣וּ לַ֭יהֹוָה כְּב֣וֹד שְׁמ֑וֹ הִשְׁתַּחֲו֥וּ לַ֝יהֹוָ֗ה בְּהַדְרַת־קֹֽדֶשׁ׃ ק֥וֹל יֶהֶוֶ֗הֶ עַל־הַ֫מָּ֥יִם אֵֽל־הַכָּב֥וֹד הִרְעִ֑ים יְ֝הֹוָ֗ה עַל־מַ֥יִם רַבִּֽים׃ קוֹל־יְהְוְ֥הְ בַּכֹּ֑חַ ק֥וֹל יֹ֝הֹוֹ֗הֹ בֶּהָדָֽר׃ ק֣וֹל יִ֭הִוִהִ שֹׁבֵ֣ר אֲרָזִ֑ים וַיְשַׁבֵּ֥ר יְ֝הֹוָ֗ה אֶת־אַרְזֵ֥י הַלְּבָנֽוֹן׃ וַיַּרְקִידֵ֥ם כְּמוֹ־עֵ֑גֶל לְבָנ֥וֹן וְ֝שִׂרְיֹ֗ן כְּמ֣וֹ בֶן־רְאֵמִֽים׃ קוֹל־יֻהֻוֻ֥הֻ חֹצֵ֗ב לַהֲב֥וֹת אֵֽשׁ׃ ק֣וֹל י֭וּהוּווּהוּ יָחִ֣יל מִדְבָּ֑ר יָחִ֥יל יְ֝הֹוָ֗ה מִדְבַּ֥ר קָדֵֽשׁ׃ ק֤וֹל יְהֹוָ֨ה ׀ יְחוֹלֵ֣ל אַיָּלוֹת֮ וַֽיֶּחֱשֹׂ֢ף יְעָ֫ר֥וֹת וּבְהֵיכָל֑וֹ כֻּ֝לּ֗וֹ אֹמֵ֥ר כָּבֽוֹד׃ יְ֭הֹוָה לַמַּבּ֣וּל יָשָׁ֑ב וַיֵּ֥שֶׁב יְ֝הֹוָ֗ה מֶ֣לֶךְ לְעוֹלָֽם׃ יְֽהֹוָ֗ה עֹ֭ז לְעַמּ֣וֹ יִתֵּ֑ן יְהֹוָ֓ה ׀ יְבָרֵ֖ךְ אֶת־עַמּ֣וֹ בַשָּׁלֽוֹם׃ <br><br>יש אומרים<br>אָֽנָּֽא בְּכֹֽחַ. גְּדוּלַת יְמִינֶֽךָ. תַּתִּיר צְרוּרָה: (אב\"ג ית\"ץ)<br>קַבֵּל רִנַּת. עַמֶּֽךָ שַׂגְּבֵֽנוּ. טַהֲרֵֽנוּ נוֹרָא: (קר\"ע שט\"ן)<br>נָא גִבּוֹר. דּֽוֹרְשֵֽׁי יִחוּדֶֽךָ. כְּבָבַת שָׁמְרֵם: (נג\"ד יכ\"ש)<br>בָּֽרְכֵֽם טַהֲרֵם. רַחֲמֵי צִדְקָתֶֽךָ. תָּמִיד גָּמְלֵם: (בט\"ר צת\"ג)<br>חֲסִין קָדוֹשׁ. בְּרֹב טֽוּבְךָֽ. נַהֵל עֲדָתֶֽךָ: (חק\"ב טנ\"ע)<br>יָחִיד גֵּאֶה. לְעַמְּךָ פְנֵה. זֽוֹכְרֵֽי קְדֻשָּׁתֶֽךָ: (יג\"ל פז\"ק)<br>שַׁוְעָתֵֽנוּ קַבֵּל. וּשְׁמַע צַעֲקָתֵֽנוּ. יוֹדֵֽעַ תַּעֲלוּמוֹת: (שק\"ו צי\"ת)<br>ואומר בלחש: בָּרוּךְ, שֵׁם כְּבוֹד מַלְכוּתוֹ, לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "<b>לְכָה דוֹדִי לִקְרַאת כַּלָּה, פְּנֵי שַׁבָּת נְקַבְּלָה:</b>"}, {"kind": "text", "text": "<b>שָׁ</b>מוֹר וְזָכוֹר בְּדִבּוּר אֶחָד, הִשְׁמִיעָנוּ אֵל הַמְּיֻחָד, יְהֹוָה אֶחָד וּשְׁמוֹ אֶחָד, לְשֵׁם וּלְתִפְאֶרֶת וְלִתְהִלָּה: לכה"}, {"kind": "text", "text": "<b>לִ</b>קְרַאת שַׁבָּת לְכוּ וְנֵלְכָה, כִּי הִיא מְקוֹר הַבְּרָכָה, מֵרֹאשׁ מִקֶּדֶם נְסוּכָה, סוֹף מַעֲשֶׂה בְּמַחֲשָׁבָה תְּחִלָּה: לכה"}, {"kind": "text", "text": "<b>מִ</b>קְדַּשׁ מֶלֶךְ עִיר מְלוּכָה, קוּמִי צְאִי מִתּוֹךְ הַהֲפֵכָה, רַב לָךְ שֶׁבֶת בְּעֵמֶק הַבָּכָא, וְהוּא יַחְמוֹל עָלַיִךְ חֶמְלָה: לכה"}, {"kind": "text", "text": "<b>הִ</b>תְנַעֲרִי מֵעָפָר קוּמִי, לִבְשִׁי בִּגְדֵי תִפְאַרְתֵּךְ עַמִּי, עַל יַד בֶּן יִשַּׁי בֵּית הַלַּחְמִי, קָרְבָה אֶל נַפְשִׁי גְּאָלָהּ: לכה"}, {"kind": "text", "text": "<b>הִ</b>תְעוֹרְרִי הִתְעוֹרְרִי, כִּי בָא אוֹרֵךְ קוּמִי אוֹרִי, עוּרִי עוּרִי שִׁיר דַּבֵּרִי, כְּבוֹד יְהֹוָה עָלַיִךְ נִגְלָה: לכה"}, {"kind": "text", "text": "<b>לֹ</b>א תֵבוֹשִׁי וְלֹא תִכָּלְמִי, מַה תִּשְׁתּוֹחֲחִי וּמַה תֶּהֱמִי, בָּךְ יֶחֱסוּ עֲנִיֵּי עַמִּי, וְנִבְנְתָה עִיר עַל תִּלָּהּ: לכה"}, {"kind": "text", "text": "<b>וְ</b>הָיוּ לִמְשִׁסָּה שׁוֹסַיִךְ, וְרָחֲקוּ כָּל מְבַלְּעָיִךְ, יָשִׂישׂ עָלַיִךְ אֱלֹהָיִךְ, כִּמְשׂוֹשׂ חָתָן עַל כַּלָּה: לכה"}, {"kind": "text", "text": "<b>יָ</b>מִין וּשְׂמֹאל תִּפְרוֹצִי, וְאֶת יְהֹוָה תַּעֲרִיצִי, עַל יַד אִישׁ בֶּן פַּרְצִי, וְנִשְׂמְחָה וְנָגִילָה: לכה"}, {"kind": "text", "text": "<b>בֹּ</b>אִי בְשָׁלוֹם עֲטֶרֶת בַּעְלָהּ, גַּם בְּשִׂמְחָה בְּרִנָּה וּבְצָהֳלָה, תּוֹךְ אֱמוּנֵי עַם סְגֻלָּה: לכה"}, {"kind": "instruction", "text": "ויאמר בקול"}, {"kind": "text", "text": "בֹּאִי כַלָּה יפנה לצד ימין,"}, {"kind": "text", "text": "בֹּאִי כַלָּה יפנה לצד שמאל,"}, {"kind": "text", "text": "תּוֹךְ אֱמוּנֵי עַם סְגֻלָּה:"}, {"kind": "instruction", "text": "כשיאמר בואי כלה פעם שלישית יכוין לקבל תוספת הנפש, ויאמר בלחש"}, {"kind": "text", "text": "בֹּאִי כַלָּה, שַׁבָּת מַלְכְּתָא:"}, {"kind": "text", "text": "<b>מִזְמ֥וֹר</b> (תהילים צ״ב:א׳-ג׳) שִׁ֗יר לְי֣וֹם הַשַּׁבָּֽת׃ ט֗וֹב לְהֹד֥וֹת לַיהֹוָ֑ה וּלְזַמֵּ֖ר לְשִׁמְךָ֣ עֶלְיֽוֹן׃ לְהַגִּ֣יד בַּבֹּ֣קֶר חַסְדֶּ֑ךָ וֶ֝אֱמ֥וּנָתְךָ֗ בַּלֵּילֽוֹת׃ עֲֽלֵי־עָ֭שׂוֹר וַעֲלֵי־נָ֑בֶל עֲלֵ֖י הִגָּי֣וֹן בְּכִנּֽוֹר׃ כִּ֤י שִׂמַּחְתַּ֣נִי יְהֹוָ֣ה בְּפׇעֳלֶ֑ךָ בְּֽמַעֲשֵׂ֖י יָדֶ֣יךָ אֲרַנֵּֽן׃ מַה־גָּדְל֣וּ מַעֲשֶׂ֣יךָ יְהֹוָ֑ה מְ֝אֹ֗ד עָמְק֥וּ מַחְשְׁבֹתֶֽיךָ׃ אִֽישׁ־בַּ֭עַר לֹ֣א יֵדָ֑ע וּ֝כְסִ֗יל לֹא־יָבִ֥ין אֶת־זֹֽאת׃ בִּפְרֹ֤חַ רְשָׁעִ֨ים ׀ כְּמ֥וֹ עֵ֗שֶׂב וַ֭יָּצִיצוּ כׇּל־פֹּ֣עֲלֵי אָ֑וֶן לְהִשָּׁמְדָ֥ם עֲדֵי־עַֽד׃ וְאַתָּ֥ה מָר֗וֹם לְעֹלָ֥ם יְהֹוָֽה׃ כִּ֤י הִנֵּ֪ה אֹיְבֶ֡יךָ ׀ יְֽהֹוָ֗ה כִּֽי־הִנֵּ֣ה אֹיְבֶ֣יךָ יֹאבֵ֑דוּ יִ֝תְפָּרְד֗וּ כׇּל־פֹּ֥עֲלֵי אָֽוֶן׃ וַתָּ֣רֶם כִּרְאֵ֣ים קַרְנִ֑י בַּ֝לֹּתִ֗י בְּשֶׁ֣מֶן רַעֲנָֽן׃ וַתַּבֵּ֥ט עֵינִ֗י בְּשׁ֫וּרָ֥י בַּקָּמִ֖ים עָלַ֥י מְרֵעִ֗ים תִּשְׁמַ֥עְנָה אׇזְנָֽי׃ צַ֭דִּיק כַּתָּמָ֣ר יִפְרָ֑ח כְּאֶ֖רֶז בַּלְּבָנ֣וֹן יִשְׂגֶּֽה׃ שְׁ֭תוּלִים בְּבֵ֣ית יְהֹוָ֑ה בְּחַצְר֖וֹת אֱלֹהֵ֣ינוּ יַפְרִֽיחוּ׃ ע֭וֹד יְנוּב֣וּן בְּשֵׂיבָ֑ה דְּשֵׁנִ֖ים וְֽרַעֲנַנִּ֣ים יִהְיֽוּ׃ לְ֭הַגִּיד כִּֽי־יָשָׁ֣ר יְהֹוָ֑ה צ֝וּרִ֗י וְֽלֹא־[עַוְלָ֥תָה] עלתה בּֽוֹ׃"}, {"kind": "text", "text": "<b>יְהֹוָ֣ה</b> (תהילים צ״ג:א׳-ב׳) מָלָךְ֮ גֵּא֢וּת לָ֫בֵ֥שׁ לָבֵ֣שׁ יְ֭הֹוָה עֹ֣ז הִתְאַזָּ֑ר אַף־תִּכּ֥וֹן תֵּ֝בֵ֗ל בַּל־תִּמּֽוֹט׃ נָכ֣וֹן כִּסְאֲךָ֣ מֵאָ֑ז מֵעוֹלָ֣ם אָֽתָּה׃ נָשְׂא֤וּ נְהָר֨וֹת ׀ יְֽהֹוָ֗ה נָשְׂא֣וּ נְהָר֣וֹת קוֹלָ֑ם יִשְׂא֖וּ נְהָר֣וֹת דׇּכְיָֽם׃ מִקֹּל֨וֹת ׀ מַ֤יִם רַבִּ֗ים אַדִּירִ֣ים מִשְׁבְּרֵי־יָ֑ם אַדִּ֖יר בַּמָּר֣וֹם יְהֹוָֽה׃ עֵֽדֹתֶ֨יךָ ׀ נֶאֶמְנ֬וּ מְאֹ֗ד לְבֵיתְךָ֥ נַאֲוָה־קֹ֑דֶשׁ יְ֝הֹוָ֗ה לְאֹ֣רֶךְ יָמִֽים׃"}, {"kind": "text", "text": "<b>כָּל</b> יִשְׂרָאֵל יֵשׁ לָהֶם חֵלֶק לָעוֹלָם הַבָּא, שֶׁנֶּאֱמַר וְעַמְּךָ כֻּלָּם צַדִּיקִים, לְעוֹלָם יִיְרְשׁוּ אָרֶץ, נֵצֶר מַטָּעַי מַעֲשֵׂה יָדַי להִתְפָּאֵר:"}, {"kind": "instruction", "text": "אין אומרים במה מדליקין בערב שבת שחל בו יום טוב או ערב יום טוב, ולא בחול המועד, ולא בערב שבת חנוכה או ערב חנוכה, ולא בבית האבל, אלא יתכיל מאמר רבי אלעזר."}, {"kind": "instruction", "text": "א. בַּמֶּה מַדְלִיקִין וּבַמֶּה אֵין מַדְלִיקִין אֵין מַדְלִיקִין לֹא בְלֶכֶשׁ, וְלֹא בְחֹסֶן, וְלֹא בְכָלָךְ, וְלֹא בִּפְתִילַת הָאִידָן, וְלֹא בִּפְתִילַת הַמִּדְבָּר, וְלֹא בִירוֹקָה שֶׁעַל פּנֵי הַמָּיִם. לֹא בְזֶפֶת וְלֹא בשַׁעֲוָה, וְלֹא בְשֶׁמֶן קִיק, וְלֹא בְשֶׁמֶן שְׂרֵפָה, וְלֹא בְאַלְיָה, וְלֹא בְחֵלֶב. נַחוּם הַמָּדִי אוֹמֵר מַדְלִיקִין בְּחֵלֶב מְבֻשָּׁל, וַחֲכָמִים אוֹמְרִים אֶחָד מְבֻשָּׁל וְאֶחָד שֶׁאֵינוֹ מְבֻשָּׁל אֵין מַדְלִיקִין בּוֹ: ב. אֵין מַדְלִיקִין בְּשֶׁמֶן שְׂרֵפָה בְּיוֹם טוֹב, רִבִּי יִשְׁמָעֵאל אוֹמֵר אֵין מַדְלִיקִין בְּעִטְרָן מִפְּנֵי כְּבוֹד הַשַּׁבָּת, וַחֲכָמִים מַתִּירִים בְּכָל הַשּׁמָנִים בְּשֶׁמֶן שֻׁמְשְׁמִין, בְּשֶׁמֶן אֱגוֹזִים, בְּשֶׁמֶן צְנוֹנוֹת, בְּשֶׁמֶן דָּגִים, בְּשֶׁמֶן פַּקּוּעוֹת, בְּעִטְרָן וּבְנֵפְטְ. רִבִּי טַרְפוֹן אוֹמֵר אֵין מַדְלִיקִין אֶלָּא בְשֶׁמֶן זַיִת בִּלְבָד: ג. כָּל הַיּוֹצֵא מִן הָעֵץ אֵין מַדְלִיקִין בּוֹ אֶלָּא פִשְׁתָּן, וְכָל הַיּוֹצֵא מִן הָעֵץ אֵינוֹ מִטַּמֵּא טֻמְאַת אֹהָלִים, אֶלָּא פִשְׁתָּן. פְּתִילַת הַבֶּגֶד שֶׁקִּפְּלָהּ וְלֹא הִבְהֲבָהּ, רִבִּי אֱלִיעֶזֶר אוֹמֵר טְמֵאָה הִיא, וְאֵין מַדְלִיקִין בָּהּ, רִבִּי עֲקִיבָא אוֹמֵר טְהוֹרָה הִיא, וּמַדְלִיקִין בָּהּ: ד. לֹא יִקּוֹב אָדָם שְׁפוֹפֶרֶת שֶׁל בֵּיצָה, וִימַלּאֶנָּה שֶׁמֶן, וְיִתּנֶנָּה עַל פִּי הַנֵּר בִּשְׁבִיל שֶׁתְּהֵא מְנַטֶּפֶת, וַאֲפִלּוּ הִיא שֶׁל חֶרֶס, וְרִבִּי יְהוּדָה מַתִּיר, אֲבָל אִם חִבְּרָהּ הַיּוֹצֵר מִתְּחִלָּה מֻתָּר, מִפְּנֵי שֶׁהוּא כְּלִי אֶחָד: לֹא יְמַלֵּא אָדָם קְעָרָה שֶׁמֶן, וְיִתּנֶנָּה בְּצַד הַנֵּר, ויִתֵּן רֹאשׁ הַפְּתִילָה בְּתוֹכָהּ, בִּשְׁבִיל שֶׁתְּהֵא שׁוֹאֶבֶת, וְרִבִּי יְהוּדָה מַתִּיר: ה. הַמְכַבֶּה אֶת הַנֵּר מִפְּנֵי שֶׁהוּא מִתְיָרֵא מִפְּנֵי גוֹיִם, מִפְּנֵי לִסְטִים, מִפְּנֵי רוּחַ רָעָה, מִפְּנֵי הַחוֹלֶה שֶׁיִּשָׁן פָּטוּר. כְּחָס עַל הַנֵּר, כְּחָס עַל הַשֶּׁמֶן, כְּחָס עַל הַפְּתִילָה חַיָּב, וְרִבִּי יוֹסֵי פּוֹטֵר בְּכֻלָּן, חוּץ מִן הַפְּתִילָה, מִפְּנֵי שֶׁהוּא עוֹשָׂהּ פֶּחָם: ו. עַל שָׁלֹשׁ עֲבֵירוֹת נָשִׁים מֵתוֹת בִּשְׁעַת לִדְתָּן עַל שֶׁאֵינָן זְהִירוֹת בַּנִּדָּה וּבַחַלָּה וּבְהַדְלָקַת הַנֵּר: ז. שְׁלֹשָׁה דְבָרִים צָרִיךְ אָדָם לוֹמַר בּתוֹךְ בֵּיתוֹ עֶרֶב שַׁבָּת עִם חֲשֵׁכָה, עִשַּׂרְתֶּן, עֵרַבְתֶּן, הַדְלִיקוּ אֶת הַנֵּר. סָפֵק חֲשֵׁכָה, סָפֵק אֵינָהּ חֲשֵׁכָה, אֵין מעַשְּׂרִין אֶת הַוַּדַּאי, וְאֵין מַטְבִּילִין אֶת הַכֵּלִים, וְאֵין מַדְלִיקִין אֶת הַנֵּרוֹת, אֲבָל מעַשְּׂרִין אֶת הַדְּמַאי, וּמְעָרבִין וְטוֹמנִין אֶת הַחַמִּין:"}, {"kind": "text", "text": "<b>אָמַר</b> רִבִּי אֶלְעָזָר אָמַר רִבִּי חֲנִינָא תַּלְמִידֵי חֲכָמִים מַרְבִּים שָׁלוֹם בָּעוֹלָם, שֶׁנֶּאֱמַר וְכׇל־בָּנַ֖יִךְ לִמּוּדֵ֣י יְהֹוָ֑ה וְרַ֖ב שְׁל֥וֹם בָּנָֽיִךְ׃ אַל תִּקְרֵי בָנַיִךְ אֶלָּא בוֹנָיִךְ: יְהִי־שָׁל֥וֹם בְּחֵילֵ֑ךְ שַׁ֝לְוָ֗ה בְּאַרְמְנוֹתָֽיִךְ׃ לְ֭מַעַן אַחַ֣י וְרֵעָ֑י אֲדַבְּרָה־נָּ֖א שָׁל֣וֹם בָּֽךְ׃ לְ֭מַעַן בֵּית־יְהֹוָ֣ה אֱלֹהֵ֑ינוּ אֲבַקְשָׁ֖ה ט֣וֹב לָֽךְ׃ וּרְאֵֽה־בָנִ֥ים לְבָנֶ֑יךָ שָׁ֝ל֗וֹם עַל־יִשְׂרָאֵֽל׃ שָׁל֣וֹם רָ֭ב לְאֹהֲבֵ֣י תוֹרָתֶ֑ךָ וְאֵֽין־לָ֥מוֹ מִכְשֽׁוֹל׃ יְֽהֹוָ֗ה עֹ֭ז לְעַמּ֣וֹ יִתֵּ֑ן יְהֹוָ֓ה ׀ יְבָרֵ֖ךְ אֶת־עַמּ֣וֹ בַשָּׁלֽוֹם׃"}, {"kind": "instruction", "text": "ואומרים קדיש \"על ישראל\""}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל־בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "עַל יִשְׂרָאֵל וְעַל רַבָּנָן. וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן. דְּעָסְקִין בְּאוֹרַיְתָא קַדִּשְׁתָּא. דִּי בְאַתְרָא הָדֵין וְדִי בְכָל אֲתַר וַאֲתַר. יְהֵא לָנָא וּלְהוֹן וּלְכוֹן חִנָּא וְחִסְדָּא וְרַחֲמֵי. מִן קֳדָם מָארֵי שְׁמַיָּא וְאַרְעָא וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא. חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה. וְשֵׁיזָבָא וּרְפוּאָה וּגְאוּלָה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו. הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "header", "text": "תפילת ערבית של שבת"}, {"kind": "instruction", "text": "בליל ראש חודש יש נוהגים לומר מזמור ברכי נפשי (שנמצע בערבית של חול)"}, {"kind": "instruction", "text": "לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם יוֹ\"ד קֵ\"י בְּוָא\"ו קֵ\"י בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל. הִנֵּה אֲנַחְנוּ בָּאִים לְהִתְפַּלֵּל תְּפִלַּת עַרְבִית שֶׁל שַׁבָּת קֹדֶשׁ, שֶׁתִּקֵּן יַעֲקֹב אָבִינוּ עָלָיו הַשָּׁלוֹם, עִם כָּל הַמִּצְוֹת הַכְּלוּלות בָּהּ, לְתַקֵּן אֶת שָׁרְשָׁהּ בְּמָקוֹם עֶלְיוֹן, לַעֲשׂות נַחַת רוּחַ לְיוֹצְרֵנוּ וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ:"}, {"kind": "text", "text": "יִמְלֹ֤ךְ יְהֹוָ֨ה ׀ לְעוֹלָ֗ם אֱלֹהַ֣יִךְ צִ֭יּוֹן לְדֹ֥ר וָדֹ֗ר הַֽלְלוּיָֽהּ׃ יוֹמָ֤ם ׀ יְצַוֶּ֬ה יְהֹוָ֨ה ׀ חַסְדּ֗וֹ וּ֭בַלַּיְלָה שִׁירֹ֣ה עִמִּ֑י תְּ֝פִלָּ֗ה לְאֵ֣ל חַיָּֽי׃ כֹּ֣ל הַ֭נְּשָׁמָה תְּהַלֵּ֥ל יָ֗הּ הַֽלְלוּיָֽהּ׃ וִיבָֽרְכוּ֙ שֵׁ֣ם כְּבֹדֶ֔ךָ וּמְרוֹמַ֥ם עַל־כׇּל־בְּרָכָ֖ה וּתְהִלָּֽה׃"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל־בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "ואומר החזן: בָּרְכוּ אֶת יְהֹוָה הַמְּבֹרָךְ:"}, {"kind": "text", "text": "ועונים הקהל: בָּרוּךְ יְהֹוָה הַמְּבֹרָךְ לְעוֹלָם וָעֵד:"}, {"kind": "text", "text": "וחוזר החזן: בָּרוּךְ יְהֹוָה הַמְּבֹרָךְ לְעוֹלָם וָעֵד:"}, {"kind": "header", "text": "ק\"ש וברכותיה"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בִּדְבָרוֹ מַעֲרִיב עֲרָבִים בְּחָכְמָה, פּוֹתֵחַ שְׁעָרִים בִּתְבוּנָה, מְשַׁנֶּה עִתִּים וּמַחֲלִיף אֶת הַזְּמַנִּים, וּמְסַדֵּר אֶת הַכּוֹכָבִים בְּמִשְׁמְרוֹתֵיהֶם בָּרָקִיעַ כִּרְצוֹנוֹ, בּוֹרֵא יוֹמָם וָלַיְלָה, גּוֹלֵל אוֹר מִפְּנֵי חֹשֶׁךְ וְחֹשֶׁךְ מִפְּנֵי אוֹר, הַמַּעֲבִיר יוֹם וּמֵבִיא לַיְלָה, וּמַבְדִּיל בֵּין יוֹם וּבֵין לָיְלָה. יְהֹוָה צְבָאוֹת שְׁמוֹ. בָּרוּךְ אַתָּה יְהֹוָה, הַמַּעֲרִיב עֲרָבִים:"}, {"kind": "text", "text": "<b>אַהֲבַת</b> עוֹלָם בֵּית יִשְׂרָאֵל עַמְּךָ אָהַבְתָּ, תּוֹרָה וּמִצְוֹת חֻקִּים וּמִשְׁפָּטִים אוֹתָנוּ לִמַּדְתָּ. עַל כֵּן יְהֹוָה אֱלֹהֵינוּ, בְּשֹׁכְבֵנוּ וּבְקוּמֵנוּ נָשִׂיחַ בְּחֻקֶּיךָ, וְנִשְׂמַח וְנַעֲלֹז בְּדִבְרֵי תַלְמוּד תּוֹרָתֶךָ, וּמִצְוֹתֶיךָ וְחֻקּוֹתֶיךָ לְעוֹלָם וָעֶד, כִּי הֵם חַיֵּינוּ וְאֹרֶךְ יָמֵינוּ, וּבָהֶם נֶהְגֶּה יוֹמָם וָלָיְלָה. וְאַהֲבָתְךָ לֹא תָסוּר מִמֶּנּוּ לְעוֹלָמִים, בָּרוּךְ אַתָּה יְהֹוָה, אוֹהֵב אֶת עַמּוֹ יִשְׂרָאֵל:"}, {"kind": "instruction", "text": "קודם שיקרא קריאת שמע יכוין לקיים מצוות עשה שנצטוינו לקרא קריאת שמע שתי פעמים ביום, וגם יכוין לקיים מצות עשה ליחד את השם, ויסגור עיניו ביד ימינו בפסוק ראשון עד שישלים ברוך שם, וכן הוא כאן אומר שמע ישראל כלומר קבל דברים אלו והבינם ותדעם שתאמין בם והוא כי ה' הוא אלהינו, ועוד הנה הוא ה' אחד, ונמצא בזה יש קבלה והודאה בשתי דברים האחד הוא קבלת מלכות שמים באומרו ה' אלהינו דמודה שקבלנו אלהותו להיות לנו לאלוה ואנחנו עבדים לו, והשני הוא ענין יחוד השם באומרו ה' אחד שהוא בלי שיתוף אחר (בא\"ח וארא ה\"ו-ז)"}, {"kind": "text", "text": "<b>שְׁמַ֖ע יִשְׂרָאֵ֑ל יְהֹוָ֥ה אֱלֹהֵ֖ינוּ יְהֹוָ֥ה ׀ אֶחָֽד</b>"}, {"kind": "instruction", "text": "בלחש: בָּרוּךְ שֵּׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "<b>וְאָ֣הַבְתָּ֔</b> (דברים ו ה) אֵ֖ת יְהֹוָ֣ה אֱלֹהֶ֑יךָ בְּכׇל־לְבָבְךָ֥ וּבְכׇל־נַפְשְׁךָ֖ וּבְכׇל־מְאֹדֶֽךָ׃ וְהָי֞וּ הַדְּבָרִ֣ים הָאֵ֗לֶּה אֲשֶׁ֨ר אָנֹכִ֧י מְצַוְּךָ֛ הַיּ֖וֹם עַל־לְבָבֶֽךָ׃ וְשִׁנַּנְתָּ֣ם לְבָנֶ֔יךָ וְדִבַּרְתָּ֖ בָּ֑ם בְּשִׁבְתְּךָ֤ בְּבֵיתֶ֙ךָ֙ וּבְלֶכְתְּךָ֣ בַדֶּ֔רֶךְ וּֽבְשׇׁכְבְּךָ֖ וּבְקוּמֶֽךָ׃ וּקְשַׁרְתָּ֥ם לְא֖וֹת עַל־יָדֶ֑ךָ וְהָי֥וּ לְטֹטָפֹ֖ת בֵּ֥ין עֵינֶֽיךָ׃ וּכְתַבְתָּ֛ם עַל־מְזֻז֥וֹת בֵּיתֶ֖ךָ וּבִשְׁעָרֶֽיךָ׃"}, {"kind": "text", "text": "<b>וְהָיָ֗ה</b> (דברים יא יג) אִם־שָׁמֹ֤עַ תִּשְׁמְעוּ֙ אֶל־מִצְוֺתַ֔י אֲשֶׁ֧ר אָנֹכִ֛י מְצַוֶּ֥ה אֶתְכֶ֖ם הַיּ֑וֹם לְאַהֲבָ֞ה אֶת־יְהֹוָ֤ה אֱלֹֽהֵיכֶם֙ וּלְעׇבְד֔וֹ בְּכׇל־לְבַבְכֶ֖ם וּבְכׇל־נַפְשְׁכֶֽם׃ וְנָתַתִּ֧י מְטַֽר־אַרְצְכֶ֛ם בְּעִתּ֖וֹ יוֹרֶ֣ה וּמַלְק֑וֹשׁ וְאָסַפְתָּ֣ דְגָנֶ֔ךָ וְתִֽירֹשְׁךָ֖ וְיִצְהָרֶֽךָ׃ וְנָתַתִּ֛י עֵ֥שֶׂב בְּשָׂדְךָ֖ לִבְהֶמְתֶּ֑ךָ וְאָכַלְתָּ֖ וְשָׂבָֽעְתָּ׃ הִשָּֽׁמְר֣וּ לָכֶ֔ם פֶּ֥ן יִפְתֶּ֖ה לְבַבְכֶ֑ם וְסַרְתֶּ֗ם וַעֲבַדְתֶּם֙ אֱלֹהִ֣ים אֲחֵרִ֔ים וְהִשְׁתַּחֲוִיתֶ֖ם לָהֶֽם׃ וְחָרָ֨ה אַף־יְהֹוָ֜ה בָּכֶ֗ם וְעָצַ֤ר אֶת־הַשָּׁמַ֙יִם֙ וְלֹֽא־יִהְיֶ֣ה מָטָ֔ר וְהָ֣אֲדָמָ֔ה לֹ֥א תִתֵּ֖ן אֶת־יְבוּלָ֑הּ וַאֲבַדְתֶּ֣ם מְהֵרָ֗ה מֵעַל֙ הָאָ֣רֶץ הַטֹּבָ֔ה אֲשֶׁ֥ר יְהֹוָ֖ה נֹתֵ֥ן לָכֶֽם׃ וְשַׂמְתֶּם֙ אֶת־דְּבָרַ֣י אֵ֔לֶּה עַל־לְבַבְכֶ֖ם וְעַֽל־נַפְשְׁכֶ֑ם וּקְשַׁרְתֶּ֨ם אֹתָ֤ם לְאוֹת֙ עַל־יֶדְכֶ֔ם וְהָי֥וּ לְטוֹטָפֹ֖ת בֵּ֥ין עֵינֵיכֶֽם׃ וְלִמַּדְתֶּ֥ם אֹתָ֛ם אֶת־בְּנֵיכֶ֖ם לְדַבֵּ֣ר בָּ֑ם בְּשִׁבְתְּךָ֤ בְּבֵיתֶ֙ךָ֙ וּבְלֶכְתְּךָ֣ בַדֶּ֔רֶךְ וּֽבְשׇׁכְבְּךָ֖ וּבְקוּמֶֽךָ׃ וּכְתַבְתָּ֛ם עַל־מְזוּז֥וֹת בֵּיתֶ֖ךָ וּבִשְׁעָרֶֽיךָ׃ לְמַ֨עַן יִרְבּ֤וּ יְמֵיכֶם֙ וִימֵ֣י בְנֵיכֶ֔ם עַ֚ל הָֽאֲדָמָ֔ה אֲשֶׁ֨ר נִשְׁבַּ֧ע יְהֹוָ֛ה לַאֲבֹתֵיכֶ֖ם לָתֵ֣ת לָהֶ֑ם כִּימֵ֥י הַשָּׁמַ֖יִם עַל־הָאָֽרֶץ׃"}, {"kind": "text", "text": "<b>וַיֹּ֥אמֶר</b> (במדבר טו לז) יְהֹוָ֖ה אֶל־מֹשֶׁ֥ה לֵּאמֹֽר׃ דַּבֵּ֞ר אֶל־בְּנֵ֤י יִשְׂרָאֵל֙ וְאָמַרְתָּ֣ אֲלֵהֶ֔ם וְעָשׂ֨וּ לָהֶ֥ם צִיצִ֛ת עַל־כַּנְפֵ֥י בִגְדֵיהֶ֖ם לְדֹרֹתָ֑ם וְנָ֥תְנ֛וּ עַל־צִיצִ֥ת הַכָּנָ֖ף פְּתִ֥יל תְּכֵֽלֶת׃ וְהָיָ֣ה לָכֶם֮ לְצִיצִת֒ וּרְאִיתֶ֣ם אֹת֗וֹ וּזְכַרְתֶּם֙ אֶת־כׇּל־מִצְוֺ֣ת יְהֹוָ֔ה וַעֲשִׂיתֶ֖ם אֹתָ֑ם וְלֹֽא־תָת֜וּרוּ אַחֲרֵ֤י לְבַבְכֶם֙ וְאַחֲרֵ֣י עֵֽינֵיכֶ֔ם אֲשֶׁר־אַתֶּ֥ם זֹנִ֖ים אַחֲרֵיהֶֽם׃ לְמַ֣עַן תִּזְכְּר֔וּ וַעֲשִׂיתֶ֖ם אֶת־כׇּל־מִצְוֺתָ֑י וִהְיִיתֶ֥ם קְדֹשִׁ֖ים לֵאלֹֽהֵיכֶֽם׃ אֲנִ֞י יְהֹוָ֣ה אֱלֹֽהֵיכֶ֗ם אֲשֶׁ֨ר הוֹצֵ֤אתִי אֶתְכֶם֙ מֵאֶ֣רֶץ מִצְרַ֔יִם לִהְי֥וֹת לָכֶ֖ם לֵאלֹהִ֑ים אֲנִ֖י יְהֹוָ֥ה אֱלֹהֵיכֶֽם׃ אֱמֶת."}, {"kind": "text", "text": "וחוזר החזן: יְהֹוָה אֱלֹהֵיכֶם אֱמֶת:"}, {"kind": "text", "text": "<b>וֶאֱמוּנָה</b> כָּל זֹאת וְקַיָּם עָלֵינוּ, כִּי הוּא יְהֹוָה אֱלֹהֵינוּ וְאֵין זוּלָתוֹ, וַאֲנַחְנוּ יִשְׂרָאֵל עַמּוֹ, הַפּוֹדֵנוּ מִיַּד מְלָכִים, הַגֹּאֲלֵנוּ מַלְכֵּנוּ מִכַּף כָּל עָרִיצִים, הָאֵל הַנִּפְרָע לָנוּ מִצָּרֵינוּ, הַמְשַׁלֵּם גְּמוּל לְכָל אוֹיְבֵי נַפְשֵׁנוּ, הַשָּׂם נַפְשֵׁנוּ בַּחַיִּים, וְלֹא נָתַן לַמּוֹט רַגְלֵנוּ, הַמַּדְרִיכֵנוּ עַל בָּמוֹת אוֹיְבֵינוּ, וַיָּרֶם קַרְנֵנוּ עַל כָּל שׂוֹנְאֵינוּ, הָאֵל הָעֹשֶׂה לָנוּ נְקָמָה בְּפַרְעֹה, בְּאוֹתוֹת וּבְמוֹפְתִים בְּאַדְמַת בְּנֵי חָם. הַמַּכֶּה בְעֶבְרָתו כָּל בְּכוֹרֵי מִצְרָיִם, וַיּוֹצִיא אֶת עַמּוֹ יִשְׂרָאֵל מִתּוֹכָם לְחֵרוּת עוֹלָם, הַמַּעֲבִיר בָּנָיו בֵּין גִּזְרֵי יַם סוּף, וְאֶת רוֹדְפֵיהֶם וְאֶת שׂונְאֵיהֶם בִּתְהוֹמוֹת טִבַּע. רָאוּ בָנִים אֶת גְּבוּרָתוֹ, שִׁבְּחוּ וְהוֹדוּ לִשְׁמוֹ, וּמַלְכוּתוֹ בְּרָצוֹן קִבְּלוּ עֲלֵיהֶם. מֹשֶׁה וּבְנֵי יִשְׂרָאֵל, לְךָ עָנוּ שִׁירָה בְשִׂמְחָה רַבָּה, וְאָמְרוּ כֻלָּם מִֽי־כָמֹ֤כָה בָּֽאֵלִם֙ יְהֹוָ֔ה מִ֥י כָּמֹ֖כָה נֶאְדָּ֣ר בַּקֹּ֑דֶשׁ נוֹרָ֥א תְהִלֹּ֖ת עֹ֥שֵׂה פֶֽלֶא׃ מַלְכוּתְךָ יְהֹוָה אֱלֹהֵינוּ רָאוּ בָנֶיךָ עַל הַיָּם, יַחַד כֻּלָּם הוֹדוּ וְהִמְלִיכוּ וְאָמְרוּ יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד׃ וְנֶאֱמַר: כִּֽי־פָדָ֥ה יְהֹוָ֖ה אֶֽת־יַעֲקֹ֑ב וּגְאָל֕וֹ מִיַּ֖ד חָזָ֥ק מִמֶּֽנּוּ׃ בָּרוּךְ אַתָּה יְהֹוָה, גָּאַל יִשְׂרָאֵל:"}, {"kind": "text", "text": "<b>הַשְׁכִּיבֵנוּ</b> אָבִינוּ לְשָׁלוֹם, וְהַעֲמִידֵנוּ מַלְכֵּנוּ לְחַיִּים טוֹבִים וּלְשָׁלוֹם, וּפְרֹשׂ עָלֵינוּ סֻכַּת שְׁלוֹמֶךָ, וְתַקְּנֵנוּ מַלְכֵּנוּ בְּעֵצָה טוֹבָה מִלְּפָנֶיךָ, וְהוֹשִׁיעֵנוּ מְהֵרָה לְמַעַן שְׁמְךָ, וְהָגֵן בַּעֲדֵנוּ, באמרו \"ופרש עלינו\" יעמוד ויכון לקבל תוספת נשמה וּפְרֹשׂ עָלֵינוּ וְעַל יְרוּשָׁלַיִם עִירְךָ סֻכַּת [רַחֲמִים וְ]שָׁלוֹם. בָּרוּךְ אַתָּה יְהֹוָה, הַפּוֹרֵשׂ סֻכַּת שָׁלוֹם עָלֵינוּ וְעַל־כָּל־עַמּוֹ יִשְׂרָאֵל, וְעַל־יְרוּשָׁלַיִם. אָמֵן:"}, {"kind": "text", "text": "<b>וְשָׁמְר֥וּ</b> בְנֵֽי־יִשְׂרָאֵ֖ל אֶת־הַשַּׁבָּ֑ת לַעֲשׂ֧וֹת אֶת־הַשַּׁבָּ֛ת לְדֹרֹתָ֖ם בְּרִ֥ית עוֹלָֽם׃ בֵּינִ֗י וּבֵין֙ בְּנֵ֣י יִשְׂרָאֵ֔ל א֥וֹת הִ֖וא לְעֹלָ֑ם כִּי־שֵׁ֣שֶׁת יָמִ֗ים עָשָׂ֤ה יְהֹוָה֙ אֶת־הַשָּׁמַ֣יִם וְאֶת־הָאָ֔רֶץ וּבַיּוֹם֙ הַשְּׁבִיעִ֔י שָׁבַ֖ת וַיִּנָּפַֽשׁ׃"}, {"kind": "instruction", "text": "ואומר החזן חצי קדיש"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל־בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "header", "text": "תפילת עמידה לליל שבת"}, {"kind": "text", "text": "<b>אֲ֭דֹנָי</b> שְׂפָתַ֣י תִּפְתָּ֑ח וּ֝פִ֗י יַגִּ֥יד תְּהִלָּתֶֽךָ׃"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵֽאלֹהֵי יַעֲקֹב. הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, קוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵּי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַֽעַן שְׁמוֹ בְּאַֽהֲבָה: בשבת תשובה אומרים: זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, כָּתְבֵנוּ בְּסֵפֶר חַיִּים, לְמַעַנָךְ אֱלֹהִים חַיִּים. מֶֽלֶךְ עוֹזֵר וּמוֹשִֽׁיעַ וּמָגֵן: בָּרוּךְ אַתָּה יַהַוַהַ, מָגֵן אַבְרָהָם:"}, {"kind": "text", "text": "<b>אַתָּה</b> גִבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֶּה מֵתִים אַתָּה, רַב לְהוֹשִֽׁיעַ."}, {"kind": "text", "text": "בקיץ: מוֹרִיד הַטָּל. בחורף: מַשִּׁיב הָרֽוּחַ וּמוֹרִיד הַגֶּֽשֶׁם."}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶֽסֶד, מְחַיֵּה מֵתִים בְּרַֽחֲמִים רַבִּים, סוֹמֵךְ נֽוֹפְלִים, וְרוֹפֵא חוֹלִים, וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמֽוּנָתוֹ לִֽישֵׁנֵי עָפָר. מִי כָמֽוֹךָ בַּֽעַל גְּבוּרוֹת, וּמִי דֽוֹמֶה לָךְ, מֶֽלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִֽיחַ יְשׁוּעָה. בשבת תשובה אומרים: מִי כָמוֹךָ אָב הָרַחֲמָן, זוֹכֵר יְצוּרָיו בְּרַחֲמִים לְחַיִּים. וְנֶֽאֱמָן אַתָּה לְהַֽחֲיוֹת מֵתִים: בָּרוּךְ אַתָּה יֵהֵוֵהֵ, מְחַיֵּה הַמֵּתִים:"}, {"kind": "text", "text": "<b>אַתָּה</b> קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ, וּקְדוֹשִׁים בְּכָל־יוֹם יְהַֽלְלֽוּךָ סֶּֽלָה: בָּרוּךְ אַתָּה יֹהֵוָהֵ, הָאֵל הַקָּדוֹשׁ: בשבת תשובה אומרים: הַמֶּלֶךְ הַקָּדוֹשׁ:"}, {"kind": "text", "text": "<b>אַתָּה</b> קִדַּשְׁתָּ אֶת־יוֹם הַשְּׁבִיעִי לִשְׁמֶךָ, תַּכְלִית מַעֲשֵׂה שָׁמַיִם וָאָרֶץ, וּבֵרַכְתּוֹ מִכָּל־הַיָּמִים, וְקִדַּשְׁתּוֹ מִכָּל־הַזְּמַנִּים, וְכֵן כָּתוּב בְּתוֹרָתָךְ:"}, {"kind": "text", "text": "<b>וַיְכֻלּ֛וּ</b> הַשָּׁמַ֥יִם וְהָאָ֖רֶץ וְכׇל־צְבָאָֽם וַיְכַ֤ל אֱלֹהִים֙ בַּיּ֣וֹם הַשְּׁבִיעִ֔י מְלַאכְתּ֖וֹ אֲשֶׁ֣ר עָשָׂ֑ה וַיִּשְׁבֹּת֙ בַּיּ֣וֹם הַשְּׁבִיעִ֔י מִכׇּל־מְלַאכְתּ֖וֹ אֲשֶׁ֥ר עָשָֽׂה׃ וַיְבָ֤רֶךְ אֱלֹהִים֙ אֶת־י֣וֹם הַשְּׁבִיעִ֔י וַיְקַדֵּ֖שׁ אֹת֑וֹ כִּ֣י ב֤וֹ שָׁבַת֙ מִכׇּל־מְלַאכְתּ֔וֹ אֲשֶׁר־בָּרָ֥א אֱלֹהִ֖ים לַעֲשֽׂוֹת׃"}, {"kind": "text", "text": "<b>יִשְׂמְחוּ</b> בְמַלְכוּתָךְ שׁוֹמְרֵי שַׁבָּת וְקוֹרְאֵי עֹנֶג. עַם מְקַדְּשֵׁי שְׁבִיעִי, כֻּלָּם יִשְׂבְּעוּ וְיִתְעַנְּגוּ מִטּוּבָךְ. וְהַשְּׁבִיעִי רָצִיתָ־בּוֹ וְקִדַּשְׁתּוֹ, חֶמְדַּת יָמִים אוֹתוֹ קָרָאתָ, זֵכֶר לְמַעֲשֵׂה בְרֵאשִׁית."}, {"kind": "text", "text": "<b>אֱלֹהֵינוּ</b> וֵאלֹהֵי אֲבוֹתֵינוּ, רְצֵה נָא בִּמְנוּחָתֵנוּ, קַדְּשֵׁנוּ בְּמִצְוֹתֶיךָ, שִׂים חֶלְקֵנוּ בְּתוֹרָתָךְ, שַׂבְּעֵנוּ מִטּוּבָךְ, שַׂמֵּחַ נַפְשֵׁנוּ בִּישׁוּעָתָךְ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶאֱמֶת, וְהַנְחִילֵנוּ יְהֹוָה אֱלֹהֵינוּ בְּאַהֲבָה וּבְרָצוֹן שַׁבַּת קָדְשֶׁךָ, וְיָנוּחוּ בָהּ כָּל יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יְהֹוָה, מְקַדֵּשׁ הַשַּׁבָּת:"}, {"kind": "text", "text": "<b>רְצֵה</b> יְהֹוָה אֱלֹהֵֽינוּ בְּעַמְּךָ יִשְׂרָאֵל וְלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב הָֽעֲבוֹדָה לִדְבִיר בֵּיתֶֽךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, מְהֵרָה בְּאַֽהֲבָה תְקַבֵּל בְּרָצוֹן, וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּֽךָ:"}, {"kind": "instruction", "text": "בראש חודש ובחול המועד אומרים:"}, {"kind": "instruction", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּֽיעַ וְיֵרָאֶה, וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵֽנוּ וְזִכְרוֹן אֲבוֹתֵֽינוּ, זִכְרוֹן יְרוּשָׁלַֽיִם עִירָךְ, וְזִכְרוֹן מָשִֽׁיחַ בֶּן־דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל־עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶֽיךָ, לִפְלֵיטָה, לְטוֹבָה, לְחֵן, לְחֶֽסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם, בְּיוֹם"}, {"kind": "text", "text": "בראש חדש: רֹאשׁ חֹֽדֶשׁ הַזֶּה,"}, {"kind": "text", "text": "בחוה\"מ פסח: חַג הַמַּצּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹֽדֶשׁ הַזֶּה,"}, {"kind": "text", "text": "בחוה\"מ סוכות: חַג הַסֻּכּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹֽדֶשׁ הַזֶּה,"}, {"kind": "instruction", "text": "לְרַחֵם בּוֹ עָלֵֽינוּ וּלְהוֹשִׁיעֵֽנוּ. זָכְרֵֽנוּ יְהֹוָה אֱלֹהֵֽינוּ בּוֹ לְטוֹבָה, וּפָקְדֵֽנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵֽנוּ בוֹ לְחַיִּים טוֹבִים, בִּדְבַר יְשׁוּעָה וְרַחֲמִים. חוּס וְחָנֵּֽנוּ, וַחֲמוֹל וְרַחֵם עָלֵֽינוּ, וְהוֹשִׁיעֵֽנוּ כִּי אֵלֶֽיךָ עֵינֵֽינוּ, כִּי אֵל מֶֽלֶךְ חַנּוּן וְרַחוּם אָֽתָּה:"}, {"kind": "text", "text": "<b>וְאַתָּה</b> בְּרַֽחֲמֶֽיךָ הָרַבִּים, תַּחְפֹּץ בָּֽנוּ וְתִרְצֵֽנוּ, וְתֶֽחֱזֶֽינָה עֵינֵֽינוּ בְּשֽׁוּבְךָ לְצִיּוֹן בְּרַֽחֲמִים: בָּרוּךְ אַתָּה יִהִוִהִ, הַמַּֽחֲזִיר שְׁכִֽינָתוֹ לְצִיּוֹן:"}, {"kind": "instruction", "text": "בברכת \"מודים\" יכרע ב\"מודים\" ויזקוף בשם (בא\"ח בשלח הכ\"א)"}, {"kind": "text", "text": "<b>מוֹדִים</b> אֲנַֽחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ לְעוֹלָם וָעֶד, צוּרֵֽנוּ צוּר חַיֵּֽינוּ וּמָגֵן יִשְׁעֵֽנוּ אַתָּה הוּא, לְדוֹר וָדוֹר נוֹדֶה לְךָ וּנְסַפֵּר תְּהִלָּתֶֽךָ, עַל חַיֵּֽינוּ הַמְּסוּרִים בְּיָדֶֽךָ, וְעַל נִשְׁמוֹתֵֽינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּֽיךָ שֶׁבְּכָל־יוֹם עִמָּֽנוּ, וְעַל נִפְלְאוֹתֶֽיךָ וְטֽוֹבוֹתֶֽיךָ שֶׁבְּכָל־עֵת, עֶֽרֶב וָבֹֽקֶר וְצָֽהֳרָֽיִם. הַטּוֹב, כִּי לֹא כָלוּ רַחֲמֶֽיךָ, הַמְּרַחֵם, כִּי לֹא תַֽמּוּ חֲסָדֶֽיךָ, כִּי מֵֽעוֹלָם קִוִּֽינוּ לָךְ:"}, {"kind": "instruction", "text": "בחנוכה ופורים אומרים:"}, {"kind": "instruction", "text": "עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת שֶׁעָשִֽׂיתָ לַאֲבוֹתֵֽינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה:"}, {"kind": "text", "text": "בחנוכה אומרים: <b>בִּימֵי מַתִּתְיָה</b> בֶן־יוֹחָנָן כֹּהֵן גָּדוֹל. חַשְׁמוֹנָאִי וּבָנָיו כְּשֶׁעָֽמְדָֽה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל. לְשַׁכְּחָם תּוֹרָתָךְ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנָךְ. וְאַתָּה בְּרַחֲמֶֽיךָ הָרַבִּים עָמַֽדְתָּ לָהֶם בְּעֵת צָרָתָם. רַֽבְתָּ אֶת רִיבָם. דַּֽנְתָּ אֶת דִּינָם. נָקַֽמְתָּ אֶת נִקְמָתָם. מָסַֽרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים. וְרַבִּים בְּיַד מְעַטִּים. וּרְשָׁעִים בְּיַד צַדִּיקִים. וּטְמֵאִים בְּיַד טְהוֹרִים. וְזֵדִים בְּיַד עֽוֹסְקֵֽי תוֹרָתֶֽךָ. לְךָ עָשִֽׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמָךְ. וּלְעַמְּךָ יִשְׂרָאֵל עָשִֽׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כָּךְ בָּֽאוּ בָנֶֽיךָ לִדְבִיר בֵּיתֶֽךָ. וּפִנּוּ אֶת־הֵיכָלֶֽךָ. וְטִהֲרוּ אֶת־מִקְדָּשֶֽׁךָ. וְהִדְלִֽיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶֽׁךָ. וְקָֽבְעֽוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵֽלּוּ בְּהַלֵּל וּבְהוֹדָאָה. וְעָשִֽׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶֽלָה:"}, {"kind": "text", "text": "בפורים אומרים <b>בִּימֵי מָרְדְּכַי</b> וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה. כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע. בִּקֵּשׁ לְהַשְׁמִיד לַהֲרֹג וּלְאַבֵּד אֶת־כָּל־הַיְּהוּדִים מִנַּֽעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד. בִּשְׁלֹשָׁה עָשָׂר לְחֹֽדֶשׁ שְׁנֵים עָשָׂר. הוּא חֹֽדֶשׁ אֲדָר. וּשְׁלָלָם לָבוֹז. וְאַתָּה בְּרַחֲמֶֽיךָ הָרַבִּים הֵפַֽרְתָּ אֶת־עֲצָתוֹ וְקִלְקַֽלְתָּ אֶת־מַחֲשַׁבְתּוֹ. וַהֲשֵׁבֽוֹתָ לּוֹ גְּמוּלוֹ בְרֹאשׁוֹ. וְתָלוּ אוֹתוֹ וְאֶת־בָּנָיו עַל הָעֵץ. וְעָשִֽׂיתָ עִמָּהֶם נֵס וָפֶֽלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶֽלָה:"}, {"kind": "text", "text": "<b>וְעַל</b> כֻּלָּם יִתְבָּרַךְ, וְיִתְרוֹמָם, וְיִתְנַשֵּׂא, תָּמִיד, שִׁמְךָ מַלְכֵּֽנוּ, לְעוֹלָם וָעֶד. וְכָל־הַחַיִּים יוֹדֽוּךָ סֶּֽלָה: בשבת תשובה אומרים: וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ. וִֽיהַֽלְלוּ וִֽיבָֽרְכוּ אֶת־שִׁמְךָ הַגָּדוֹל בֶּֽאֱמֶת לְעוֹלָם כִּי טוֹב, הָאֵל יְשֽׁוּעָתֵֽנוּ וְעֶזְרָתֵֽנוּ סֶֽלָה, הָאֵל הַטּוֹב: בָּרוּךְ אַתָּה יֻהֻוֻהֻ, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת:"}, {"kind": "text", "text": "<b>שִׂים</b> שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים חֵן וָחֶֽסֶד וְרַֽחֲמִים, עָלֵֽינוּ וְעַל כָּל־יִשְׂרָאֵל עַמֶּֽךָ. וּבָֽרְכֵֽנוּ אָבִֽינוּ כֻּלָּֽנוּ כְּאֶחָד בְּאוֹר פָּנֶֽיךָ, כִּי בְאוֹר פָּנֶֽיךָ נָתַֽתָּ לָּֽנוּ יְהֹוָה אֱלֹהֵֽינוּ תּוֹרָה וְחַיִּים, אַֽהֲבָה וָחֶֽסֶד, צְדָקָה וְרַֽחֲמִים, בְּרָכָה וְשָׁלוֹם. וְטוֹב בְּעֵינֶֽיךָ לְבָֽרְכֵֽנוּ וּלְבָרֵךְ אֶת־כָּל־עַמְּךָ יִשְׂרָאֵל, בְּרֹב עֹז וְשָׁלוֹם: בשבת תשובה אומרים: וּבְסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה וִישׁוּעָה וְנֶחָמָה, וּגְזֵרוֹת טוֹבוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם. בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמְּבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם. אָמֵן:"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>אֱלֹהַי</b>, נְצֹר לְשׁוֹנִי מֵרָע וְשִׂפְתוֹתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּֽעָפָר לַכֹּל תִּֽהְיֶה, פְּתַח לִבִּי בְּתוֹרָתֶֽךָ, וְאַחֲרֵי מִצְוֹתֶֽיךָ תִּרְדֹּף נַפְשִׁי. וְכָל־הַקָּמִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחְשְׁבוֹתָם. יִֽהְי֗וּ כְּמֹ֥ץ לִפְנֵי־ר֑וּחַ וּמַלְאַ֖ךְ יְהֹוָ֣ה דּוֹחֶֽה. קַבֵּל רִנַּת עַמֶּךָ. שַׂגְּבֵנוּ טַהֲרֵנוּ נוֹרָא. עֲשֵׂה לְמַֽעַן שְׁמָךְ, עֲשֵׂה לְמַֽעַן יְמִינָךְ, עֲשֵׂה לְמַֽעַן תּֽוֹרָתָךְ, עֲשֵׂה לְמַֽעַן קְדֻשָּׁתָךְ."}, {"kind": "text", "text": "סגולה לומר פסוק המתחיל וגומר באות שמתחיל וגומר שמו לְ֭מַעַן יֵחָלְצ֣וּן יְדִידֶ֑יךָ הוֹשִׁ֖יעָה יְמִֽינְךָ֣ וַעֲנֵֽנִי:"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>עֹשֶׂה</b> שָׁלוֹם בשבת תשובה אומרים: הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵֽינוּ, וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן:"}, {"kind": "instruction", "text": "יְהִי רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְּיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ, לַעֲשׂוֹת חֻקֵּי רְצוֹנָךְ וּלְעָבְדָךְ בְּלֵבָב שָׁלֵם:"}, {"kind": "instruction", "text": "עומדים ואומרים"}, {"kind": "text", "text": "<b>וַיְכֻלּ֛וּ</b> הַשָּׁמַ֥יִם וְהָאָ֖רֶץ וְכׇל־צְבָאָֽם וַיְכַ֤ל אֱלֹהִים֙ בַּיּ֣וֹם הַשְּׁבִיעִ֔י מְלַאכְתּ֖וֹ אֲשֶׁ֣ר עָשָׂ֑ה וַיִּשְׁבֹּת֙ בַּיּ֣וֹם הַשְּׁבִיעִ֔י מִכׇּל־מְלַאכְתּ֖וֹ אֲשֶׁ֥ר עָשָֽׂה׃ וַיְבָ֤רֶךְ אֱלֹהִים֙ אֶת־י֣וֹם הַשְּׁבִיעִ֔י וַיְקַדֵּ֖שׁ אֹת֑וֹ כִּ֣י ב֤וֹ שָׁבַת֙ מִכׇּל־מְלַאכְתּ֔וֹ אֲשֶׁר־בָּרָ֥א אֱלֹהִ֖ים לַעֲשֽׂוֹת׃"}, {"kind": "instruction", "text": "ואומר החזן ברכת מעין שבע לבדו"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק וֵאלֹהֵי יַעֲקֹב, הָאֵל הַגָּדוֹל, הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, קוֹנֵה בְרַחֲמָיו שָׁמַיִם וָאָרֶץ, מָגֵן אָבוֹת בִּדְבָרוֹ, מְחַיֵּה מֵתִים בְּמַאֲמָרוֹ, הָאֵל בשבת תשובה אומר: הַמֶּלֶךְ הַקָּדוֹשׁ שֶׁאֵין כָּמוֹהוּ, הַמֵּנִיחַ לְעַמּוֹ בְּיוֹם שַׁבַּת קָדְשׁוֹ, כִּי בָם רָצָה לְהָנִיחַ לָהֶם. לְפָנָיו נַעֲבֹד בְּיִרְאָה וָפַחַד, וְנוֹדֶה לִשְׁמוֹ בְּכָל יוֹם תָּמִיד מֵעֵין הַבְּרָכוֹת וְהַהוֹדָאוֹת, לַאֲדוֹן הַשָּׁלוֹם, מְקַדֵּשׁ הַשַּׁבָּת וּמְבָרֵךְ הַשְּׁבִיעִי, וּמֵנִיחַ בִּקְדֻשָּׁה לְעַם מדֻשְּׁנֵי עֹנֶג, זֵכֶר לְמַעֲשֵׂה בְרֵאשִׁית:"}, {"kind": "text", "text": "<b>אֱלֹהֵינוּ</b> וֵאלֹהֵי אֲבוֹתֵינוּ, רְצֵה נָא בִּמְנוּחָתֵנוּ, קַדְּשֵׁנוּ בְּמִצְוֹתֶיךָ, שִׂים חֶלְקֵנוּ בְּתוֹרָתָךְ, שַׂבְּעֵנוּ מִטּוּבָךְ, שַׂמֵּחַ נַפְשֵׁנוּ בִּישׁוּעָתָךְ, וְטַהֵר לִבֵּנוּ לְעָבְדּךָ בֶאֱמֶת. וְהַנְחִילֵנוּ יְהֹוָה אֱלֹהֵינוּ בְּאַהֲבָה וּבְרָצוֹן שַׁבָּת קָדְשֶׁךָ, וְיָנוּחוּ בָהּ כָּל יִשְׂרָאֵל מְקַדּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יְהֹוָה, מְקַדֵּשׁ הַשַּׁבָּת:"}, {"kind": "instruction", "text": "ואומר החזן קדיש תתקבל"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל־בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "תִּתְקַבַּל צְלוֹתָֽנָא וּבָֽעוּתָֽנָא, עִם צְלֽוֹתְהוֹן וּבָעֽוּתְהוֹן דְּכָל־בֵּית יִשְׂרָאֵל, קֳדָם אֲבוּנָא דְּבִשְׁמַיָּא וְאַרְעָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא. חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה. וְשֵׁיזָבָא וּרְפוּאָה וּגְאוּלָה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "יפסע שלש פסיעות לאחור<br>עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו. הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>מִזְמ֥וֹר</b> (תהילים כ״ג:א׳-ב׳) לְדָוִ֑ד יְהֹוָ֥ה רֹ֝עִ֗י לֹ֣א אֶחְסָֽר׃ בִּנְא֣וֹת דֶּ֭שֶׁא יַרְבִּיצֵ֑נִי עַל מֵ֖י מְנֻח֣וֹת יְנַהֲלֵֽנִי׃ נַפְשִׁ֥י יְשׁוֹבֵ֑ב יַֽנְחֵ֥נִי בְמַעְגְּלֵי־צֶ֝֗דֶק לְמַ֣עַן שְׁמֽוֹ׃ גַּ֤ם כִּֽי־אֵלֵ֨ךְ בְּגֵ֪יא צַלְמָ֡וֶת לֹא־אִ֘ירָ֤א רָ֗ע כִּי־אַתָּ֥ה עִמָּדִ֑י שִׁבְטְךָ֥ וּ֝מִשְׁעַנְתֶּ֗ךָ הֵ֣מָּה יְנַֽחֲמֻֽנִי׃ תַּעֲרֹ֬ךְ לְפָנַ֨י ׀ שֻׁלְחָ֗ן נֶ֥גֶד צֹרְרָ֑י דִּשַּׁ֥נְתָּ בַשֶּׁ֥מֶן רֹ֝אשִׁ֗י כּוֹסִ֥י רְוָיָֽה אַ֤ךְ ׀ ט֤וֹב וָחֶ֣סֶד יִ֭רְדְּפוּנִי כׇּל־יְמֵ֣י חַיָּ֑י וְשַׁבְתִּ֥י בְּבֵית־יְ֝הֹוָ֗ה לְאֹ֣רֶךְ יָמִֽים׃"}, {"kind": "instruction", "text": "ואומרים כאן קדיש \"יהא שלמא\""}, {"kind": "instruction", "text": "תִּתְקַבַּל צְלוֹתָֽנָא וּבָֽעוּתָֽנָא, עִם צְלֽוֹתְהוֹן וּבָעֽוּתְהוֹן דְּכָל־בֵּית יִשְׂרָאֵל, קֳדָם אֲבוּנָא דְּבִשְׁמַיָּא וְאַרְעָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>יְהֵא</b> שְׁלָמָא רַבָּא מִן שְׁמַיָּא. חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה. וְשֵׁיזָבָא וּרְפוּאָה וּגְאוּלָה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]<br><br><b>עוֹשֶׂה</b> שָׁלוֹם בִּמְרוֹמָיו. הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "ואומרים: <b>בָּרְכוּ</b> אֶת יְהֹוָה הַמְּבֹרָךְ:"}, {"kind": "text", "text": "ועונים: <b>בָּרוּךְ</b> יְהֹוָה הַמְּבֹרָךְ לְעוֹלָם וָעֵד:"}, {"kind": "header", "text": "עלינו לשבח"}, {"kind": "text", "text": "<b>עָלֵֽינוּ</b> לְשַׁבֵּֽחַ לַֽאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָֽׂנוּ כְּגוֹיֵי הָֽאֲרָצוֹת, וְלֹא שָׂמָֽנוּ כְּמִשְׁפְּחוֹת הָֽאֲדָמָה, שֶׁלֹּא שָׂם חֶלְקֵֽנוּ כָּהֶם וְגוֹרָלֵֽנוּ כְּכָל־הֲמוֹנָם, שֶׁהֵם מִשְׁתַּֽחֲוִים לָהֶֽבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל־אֵל לֹֽא יוֹשִׁיעַ. וַֽאֲנַֽחְנוּ מִשְׁתַּחֲוִים לִפְנֵי מֶֽלֶךְ מַלְכֵי הַֽמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַֽיִם וְיוֹסֵד אָֽרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַֽיִם מִמַּֽעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵֽינוּ, וְאֵין עוֹד אַחֵר, אֱמֶת מַלְכֵּֽנוּ וְאֶֽפֶס זוּלָתוֹ. כַּכָּתוּב בַּתּוֹרָה. וְיָדַעְתָּ֣ הַיּ֗וֹם וַהֲשֵׁבֹתָ֮ אֶל־לְבָבֶךָ֒ כִּ֤י יְהֹוָה֙ ה֣וּא הָֽאֱלֹהִ֔ים בַּשָּׁמַ֣יִם מִמַּ֔עַל וְעַל־הָאָ֖רֶץ מִתָּ֑חַת אֵ֖ין עֽוֹד׃"}, {"kind": "text", "text": "<b>עַל</b> כֵּן נְקַוֶּה לָךְ, יְהֹוָה אֱלֹהֵֽינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶֽרֶת עֻזָּךְ, לְהַֽעֲבִיר גִּלּוּלִים מִן הָאָֽרֶץ, וְהָֽאֱלִילִים כָּרוֹת יִכָּֽרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל־בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶֽךָ, לְהַפְנוֹת אֵלֶֽיךָ כָּל־רִשְׁעֵי אָֽרֶץ. יַכִּֽירוּ וְיֵֽדְעוּ כָּל־יֽוֹשְׁבֵי תֵבֵֽל, כִּי לְךָ תִכְרַע כָּל־בֶּֽרֶךְ, תִּשָּׁבַע כָּל־לָשׁוֹן. לְפָנֶֽיךָ, יְהֹוָה אֱלֹהֵֽינוּ יִכְרְעוּ וְיִפֹּֽלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּֽנוּ, וִיקַבְּלוּ כֻלָּם אֶת־עֹל מַלְכוּתֶֽךָ, וְתִמְלוֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעֽוֹלְמֵי עַד תִּמְלוֹךְ בְּכָבוֹד. כַּכָּתוּב בְּתוֹרָתָךְ: יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד׃ וְנֶאֱמַר. וְהָיָ֧ה יְהֹוָ֛ה לְמֶ֖לֶךְ עַל־כָּל־הָאָ֑רֶץ בַּיּ֣וֹם הַה֗וּא יִהְיֶ֧ה יְהֹוָ֛ה אֶחָ֖ד וּשְׁמ֥וֹ אֶחָֽד׃"}, {"kind": "instruction", "text": "יש נוהגים לומר אחר התפילה:"}, {"kind": "text", "text": "<b>יִגְדַּל</b> אֱלֹהִים חַי וְיִשְׁתַּבַּח. נִמְצָא וְאֵין עֵת אֶל מְצִיאוּתוֹ:"}, {"kind": "text", "text": "אֶחָד וְאֵין יָחִיד כְּיִחוּדוֹ. נֶעְלָם וְגַם אֵין סוֹף לְאַחְדוּתוֹ:"}, {"kind": "text", "text": "אֵין לוֹ דְּמוּת הַגּוּף וְאֵינוֹ גּוּף. לֹא נַעֲרֹךְ אֵלָיו קְדֻשָּׁתוֹ:"}, {"kind": "text", "text": "קַדְמוֹן לְכָל דָּבָר אֲשֶׁר נִבְרָא. רִאשׁוֹן וְאֵין רֵאשִׁית לְרֵאשִׁיתוֹ:"}, {"kind": "text", "text": "הִנּוֹ אֲדוֹן עוֹלָם לְכָל נוֹצָר. יוֹרֶה גְּדֻלָּתוֹ וּמַלְכוּתוֹ:"}, {"kind": "text", "text": "שֶׁפַע נְבוּאָתוֹ נְתָנוֹ אֶל. אַנְשֵׁי סְגֻלָּתוֹ וְתִפְאַרְתּוֹ:"}, {"kind": "text", "text": "לֹא קָם בְּיִשְׂרָאֵל כְּמֹשֶׁה עוֹד. נָבִיא וּמַבִּיט אֶת תְּמוּנָתוֹ:"}, {"kind": "text", "text": "תּוֹרַת אֱמֶת נָתַן לְעַמּוֹ אֵל. עַל יַד נְבִיאוֹ נֶאֱמַן בֵּיתוֹ:"}, {"kind": "text", "text": "לֹא יַחֲלִיף הָאֵל וְלֹא יָמִיר. דָּתוֹ לְעוֹלָמִים לְזוּלָתוֹ:"}, {"kind": "text", "text": "צוֹפֶה וְיוֹדֵעַ סְתָרֵינוּ. מַבִּיט לְסוֹף דָּבָר בְּקַדְמוּתוֹ:"}, {"kind": "text", "text": "גּוֹמֵל לְאִישׁ חָסִיד כְּמִפְעָלוֹ. נוֹתֵן לְרָשָׁע רָע כְּרִשְׁעָתוֹ:"}, {"kind": "text", "text": "יִשְׁלַח לְקֵץ יָמִין מְשִׁיחֵנוּ. לִפְדּוֹת מְחַכֵּי קֵץ יְשׁוּעָתוֹ:"}, {"kind": "text", "text": "מֵתִים יְחַיֶּה אֵל בְּרֹב חַסְדּוֹ. בָּרוּךְ עֲדֵי עַד שֵׁם תְּהִלָּתוֹ:"}, {"kind": "text", "text": "אֵלֶּה שְׁלֹשׁ עֶשְׂרֵה לְעִקָּרִים. הֵן הֵם יְסוֹד דַּת אֵל וְתוֹרָתוֹ:"}, {"kind": "text", "text": "תּוֹרַת מֹשֶׁה אֱמֶת וּנְבוּאָתוֹ. בָּרוּךְ עֲדֵי עַד שֵׁם תְּהִלָּתוֹ:"}], "shacharit": [{"kind": "header", "text": "סדר השכמת הבוקר"}, {"kind": "header", "text": "מודה אני"}, {"kind": "instruction", "text": "כשיעור משנתו יאמר"}, {"kind": "text", "text": "<b>מוֹדֶה</b> האשה אומרת: מוֹדָה אֲנִי לְפָנֶיךָ מֶלֶךְ חַי וְקַיָּם שֶהֶחֱזַרְתָּ בִּי נִשְׁמָתִי בְחֶמְלָה, רַבָּה אֱמוּנָתֶךָ:"}, {"kind": "header", "text": "ברכות השחר"}, {"kind": "instruction", "text": "יעשה צרכיו תחלה, ואחר כך יברך על נטילת ידים ואשר יצר (בא\"ח ויצא ה\"ב). אחר שנטל ידיו תכף ומיד תזקיף ידיו ואצבעותיו למעלה ותגביהם עד הראש, ולפחות תגביהם עד כנגד הפנים, ותברך על נטילת ידים, (בא\"ח תולדות ה\"ד) ואם היה ער כל הלילה לא יברך אלא יטול בלא ברכה (שם הי\"ג)"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוֹתָיו וְצִוָּנוּ עַל נְטִילַת יָדָיִם:"}, {"kind": "instruction", "text": "אם הטיל מים או עשה צרכיו יברך תוך חצי שעה (בא\"ח ויצא הי\"ב)"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אֲשֶׁר יָצַר אֶת הָאָדָם בְּחָכְמָה, וּבָרָא בוֹ נְקָבִים נְקָבִים, חֲלוּלִים חֲלוּלִים, גָּלוּי וְיָדוּעַ לִפְנֵי כִסֵּא כְבוֹדֶךָ, שֶׁאִם יִסָּתֵם אֶחָד מֵהֶם, אוֹ אִם יִפָּתֵח אֶחָד מֵהֶם, אֵי אֶפְשָׁר לְהִתְקַיֵּם אַפִלּוּ שָׁעָה אֶחָת. בָּרוּךְ אַתָּה יְהֹוָה, רוֹפֵא כָל־בָּשָׂר וּמַפְלִיא לַעֲשׂוֹת:"}, {"kind": "instruction", "text": "יסמוך ברכה זו של אלהי וכו' לברכת אשר יצר (בא\"ח וישב ה\"ב)"}, {"kind": "text", "text": "<b>אֱלֹהַי</b>, נְשָׁמָה שֶׁנָּתַתָּ בִּי טְהוֹרָה, אַתָּה בְרָאתָהּ, אַתָּה יְצַרְתָּהּ, אַתָּה נְפַחְתָּהּ בִּי, וְאַתָּה מְשַׁמְּרָהּ בְּקִרְבִּי, וְאַתָּה עָתִיד לִטְּלָהּ מִמֶּנִּי, וּלְהַחֲזִירָהּ בִּי לֶעָתִיד לָבוֹא, כָּל־זְמַן שֶׁהַנְּשָׁמָה בְקִרְבִּי, מוֹדֶה (האשה אומרת מוֹדָה) אֲנִי לְפָנֶיךָ יְהֹוָה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, רִבּוֹן כָּל־הַמַּעֲשִׂים אֲדוֹן כָּל־הַנְּשָׁמוֹת. בָּרוּךְ אַתָּה יְהֹוָה, הַמַּחֲזִיר נְשָׁמוֹת לִפְגָרִים מֵתִים:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, הַנוֹתֵן לַשֶּׂכְוִי בִינָה, לְהַבְחִין בֵּין יוֹם וּבֵין לָיְלָה:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, פּוֹקֵחַ עִוְרִים:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, מַתִּיר אֲסוּרִים:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, זוֹקֵף כְּפוּפִים:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, מַלְבִּישׁ עֲרֻמִּים:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, הַנּוֹתֵן לַיָּעֵף כֹּחַ:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, רוֹקַע הָאָרֶץ עַל הַמָּיִם:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, הַמֵּכִין מִצְעֲדֵי גָבֶר:"}, {"kind": "instruction", "text": "בתשעה באב ויום הכיפורים אין אומרים ברכה זו (בא\"ח וישב ה\"ט)"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, שֶׁעָשָׂה לִי כָּל־צָרְכִּי:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אוֹזֵר יִשְׂרָאֵל בִּגְבוּרָה:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, עוֹטֵר יִשְׂרָאֵל בְּתִפְאָרָה:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, שֶׁלֹּא עָשַׂנִי גוֹי: האשה אומרת: <b>גּוֹיָה</b>"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, שֶׁלֹּא עָשַׂנִי עָבֶד: האשה אומרת: <b>שִׁפְחָה</b>"}, {"kind": "instruction", "text": "האיש מברך"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, שֶׁלֹּא עָשַׂנִי אִשָּׁה:"}, {"kind": "instruction", "text": "האשה מברכת בלי שם ומלכות"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> שֶׁעָשַׂנִי כִּרְצוֹנוֹ:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, הַמַּעֲבִיר חֶבְלֵי שֵׁנָה מֵעֵינָי וּתְנוּמָה מֵעַפְעַפָּי. וִיהִי רָצוֹן מִלְפָנֶיךָ יְהֹוָה, אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתַרְגִּילֵנִי בְּתוֹרָתֶךָ, וְתַדְבִּיקֵנִי בְּמִצְוֹתֶיךָ, וְאַל תְּבִיאֵנִי לִידֵי חֵטְא, וְלֹא לִידֵי עָוֹן, וְלֹא לִידֵי נִסָיוֹן, וְלֹא לִידֵי בִזָּיוֹן, וְתַרְחִיקֵנִי מִיֵּצֶר הָרָע, וְתַדְבִּיקֵנִי בְּיֵצֶר הַטּוֹב, וְכוֹף אֶת־יִצְרִי לְהִשְׁתַּעְבֶּד לָּךְ, וּתְנֵנִי הַיּוֹם וּבְכָל־יוֹם לְחֵן וּלְחֶסֶד וּלְרַחֲמִים בְּעֵינֶיךָ וּבְעֵינֵי כָל־רוֹאַי, וְגָמְלֵנִי חֲסָדִים טוֹבִים. בָּרוּךְ אַתָּה יְהֹוָה, גּוֹמֵל חֲסָדִים טוֹבִים לְעַמּוֹ יִשְׂרָאֵל:"}, {"kind": "text", "text": "<b>יְהִי</b> רָצוֹן מִלְּפָנֶיךָ יְהֹוָה, אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתַּצִּילֵנִי הַיּוֹם וּבְכָל יוֹם וָיוֹם, מֵעַזֵּי פָנִים, וּמֵעַזּוּת פָּנִים, מֵאָדָם רָע, מִיֵּצֶר רָע, מֵחָבֵר רָע, מִשָּׁכֵן רָע, מִפֶּגַע רָע, מֵעַיִן הָרָע, וּמִלָּשׁוֹן הָרָע, מִדִּין קָשֶׁה, וּמִבַּעַל דִּין קָשֶׁה, בֵּין שֶׁהוּא בֶן־בְּרִית, וּבֵין שֶׁאֵינוֹ בֶן־בְּרִית:"}, {"kind": "header", "text": "ברכות התורה"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוֹתָיו וְצִוָּנוּ עַל דִּבְרֵי תוֹרָה:"}, {"kind": "text", "text": "<b>וְהַעֲרֵב</b> נָא, יְהֹוָה אֱלֹהֵֽינוּ, אֶת־דִּבְרֵי תוֹרָתְךָ בְּפִינוּ וּבְפִיפִיּוֹת עַמְּךָ בֵּית יִשְׂרָאֵל, וְנִהְיֶה אֲנַחְנוּ וְצֶאֱצָאֵינוּ, וְצֶאֱצָאֵי צֶאֱצָאֵינוּ, כֻּלָּנוּ יוֹדְעֵי שְׁמֶךָ, וְלוֹמְדֵי תוֹרָתְךָ לִשְׁמָהּ. בָּרוּךְ אַתָּה יְהֹוָה, הַמְלַמֵּד תּוֹרָה לְעַמּוֹ יִשְׂרָאֵל:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בָּנוּ מִכָּל־הָעַמִּים וְנָתַן לָנוּ אֶת־תּוֹרָתוֹ. בָּרוּךְ אַתָּה יְהֹוָה נוֹתֵן הַתּוֹרָה:"}, {"kind": "text", "text": "<b>וַיְדַבֵּ֥ר</b> יְהֹוָ֖ה אֶל־מֹשֶׁ֥ה לֵּאמֹֽר׃ דַּבֵּ֤ר אֶֽל־אַהֲרֹן֙ וְאֶל־בָּנָ֣יו לֵאמֹ֔ר כֹּ֥ה תְבָרְכ֖וּ אֶת־בְּנֵ֣י יִשְׂרָאֵ֑ל אָמ֖וֹר לָהֶֽם׃ יְבָרֶכְךָ֥ יְהֹוָ֖ה וְיִשְׁמְרֶֽךָ׃ יָאֵ֨ר יְהֹוָ֧ה ׀ פָּנָ֛יו אֵלֶ֖יךָ וִֽיחֻנֶּֽךָּ׃ יִשָּׂ֨א יְהֹוָ֤ה ׀ פָּנָיו֙ אֵלֶ֔יךָ וְיָשֵׂ֥ם לְךָ֖ שָׁלֽוֹם׃ וְשָׂמ֥וּ אֶת־שְׁמִ֖י עַל־בְּנֵ֣י יִשְׂרָאֵ֑ל וַאֲנִ֖י אֲבָרְכֵֽם׃"}, {"kind": "header", "text": "תפילת שחרית לימי החול"}, {"kind": "header", "text": "פתיחת אליהו"}, {"kind": "instruction", "text": "אחר המזמורים של תיקון לאה המנהג לומר פתיחת אליהו (בא\"ח וישלח הי\"ב)"}, {"kind": "text", "text": "וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ׃"}, {"kind": "text", "text": "<b>פָּתַח אֵלִיָּֽהוּ</b> הַנָּבִיא זָכוּר לְטוֹב וְאָמַר: רִבּוֹן עָֽלְמִֽין דְּאַנְתְּ הוּא חָד וְלָא בְּחֻשְׁבָּן. אַנְתְּ הוּא עִלָּאָה עַל־כָּל־עִלָּאִין סְתִימָא עַל־כָּל־סְתִימִין. לֵית מַחֲשָׁבָה תְּפִיסָא בָךְ כְּלָל: אַנְתְּ הוּא דְאַפַּקְתְּ עֶֽשֶׂר תִּקּוּנִין וְקָרֵינָן לוֹן עֶֽשֶׂר סְפִירָן. לְאַנְהָגָא בְהוֹן עָֽלְמִֽין סְתִימִין דְּלָא אִתְגַּלְיָן וְעָֽלְמִֽין דְּאִתְגַּלְיָן. וּבְהוֹן אִתְכַּסִּיאַת מִבְּנֵי נָשָׁא. וְאַנְתְּ הוּא דְּקָשִׁיר לוֹן וּמְיַחֵד לוֹן: וּבְגִין דְּאַנְתְּ מִלְּגָאו. כָּל־מָאן דְּאַפְרִישׁ חַד מִן חַבְרֵיהּ מֵאִלֵּין עֶֽשֶׂר אִתְחַשִּׁיב לֵיהּ כְּאִלּוּ אַפְרִישׁ בָּֽךְ:"}, {"kind": "text", "text": "וְאִלֵּין עֶֽשֶׂר סְפִירָן אִנּוּן אָֽזְלִֽין כְּסִדְרָן. חַד אָרִיךְ וְחַד קָצֵר וְחַד בֵּינוֹנִי: וְאַנְתְּ הוּא דְּאַנְהִיג לוֹן. וְלֵית מָאן דְּאַנְהִיג לָךְ. לָא לְעֵֽלָּא וְלָא לְתַֽתָּא וְלָא מִכָּל־סִטְרָא. לְבוּשִׁין תַּקַּנְתְּ לוֹן דְּמִנַּֽיְהוּ פָֽרְחִֽין נִשְׁמָתִין לִבְנֵי נָשָׁא: וְכַמָּה גוּפִין תַּקַּנְתְּ לוֹן דְּאִתְקְרִֽיאוּ גוּפָא לְגַבֵּי לְבוּשִׁין דִּמְכַסְיָן עֲלֵיהוֹן: וְאִתְקְרִֽיאוּ בְּתִקּוּנָא דָא. חֶֽסֶד דְּרוֹעָא יְמִינָא. גְּבוּרָה דְּרוֹעָא שְׂמָאלָא. תִּפְאֶֽרֶת גּוּפָא. נֶֽצַח וְהוֹד תְּרֵין שׁוֹקִין. יְסוֹד סִיּוּמָא דְגוּפָא אוֹת בְּרִית קֽוֹדֶשׁ. מַלְכוּת פֶּה תּוֹרָה שֶׁבְּעַל־פֶּה קָרֵֽינָן לָהּ. חָכְמָה מוֹחָא אִֽיהִי מַחֲשָׁבָה מִלְּגָאו. בִּינָה לִבָּא וּבָהּ הַלֵּב מֵבִין. וְעַל אִלֵּין תְּרֵין כְּתִיב הַנִּ֨סְתָּרֹ֔ת לַיהֹוָ֖ה אֱלֹהֵ֑ינוּ. כֶּֽתֶר עֶלְיוֹן אִֽיהוּ כֶּֽתֶר מַלְכוּת. וְעָלֵיהּ אִתְמַר מַגִּיד מֵרֵאשִׁית אַחֲרִית. וְאִֽיהוּ קַרְקַפְתָּא דִתְפִלֵּי: מִלְּגָאו אִֽיהוּ [אוֹת] יוֹ\"ד [וְאוֹת] הֵ\"א [וְאוֹת] וָא\"ו [וְאוֹת] הֵ\"א דְּאִֽיהוּ אֹֽרַח אֲצִילוּת. אִֽיהוּ שַׁקְיוּ דְאִילָנָא בִּדְרוֹעוֹי וְעַנְפּוֹי. כְּמַיָּא דְאַשְׁקֵי לְאִילָנָא וְאִתְרַבֵּי בְּהַהוּא שַׁקְיוּ:"}, {"kind": "text", "text": "<b>רִבּוֹן</b> עָֽלְמִֽין אַנְתְּ הוּא עִלַּת הָעִלּוֹת וְסִבַּת הַסִּבּוֹת דְּאַשְׁקֵי לְאִילָנָא בְּהַהוּא נְבִיעוּ. וְהַהוּא נְבִיעוּ אִֽיהוּ כְּנִשְׁמְתָא לְגוּפָא דְּאִֽיהִי חַיִּים לְגוּפָא: וּבָךְ לֵית דִּמְיוֹן וְלֵית דִּיּוּקְנָא (דְּגוּפָא) מִכָּל־מַה־דִּלְגַאו וּלְבַר. וּבָרָֽאתָ שְׁמַיָּא וְאַרְעָא. וְאַפַּקְתְּ מִנְּהוֹן שִׁמְשָׁא וְסִיהֲרָא וְכוֹכְבַיָּא וּמַזָּלֵי. וּבְאַרְעָא אִילָנִין וּדְשָׁאִין וְגִנְּתָא דְעֵֽדֶן וְעִשְׂבִּין וְחֵיוָן וְעוֹפִין וְנוּנִין וּבְעִירִין וּבְנֵי נָשָׁא. לְאִשְׁתְּמֽוֹדְעָֽא בְהוֹן עִלָּאִין וְאֵיךְ יִתְנַהֲגוּן בְּהוֹן עִלָּאִין וְתַתָּאִין. וְאֵיךְ אִשְׁתְּמֽוֹדְעָֽן מֵעִלָּאֵי וְתַתָּאֵי וְלֵית דְּיָדַע בָּךְ כְּלָל. וּבַר מִנָּךְ לֵית יִחוּדָא בְּעִלָּאֵי וְתַתָּאֵי. וְאַנְתְּ אִשְׁתְּמוֹדָע אָדוֹן עַל־כֹּֽלָּא: וְכָל־סְפִירָן כָּל־חַד אִית לֵיהּ שֵׁם יְדִֽיעַ. וּבְהוֹן אִתְקְרִֽיאוּ מַלְאָכַיָּא. וְאַנְתְּ לֵית לָךְ שֵׁם יְדִֽיעַ. דְּאַנְתְּ הוּא מְמַלֵּא כָּל־שְׁמָהָן וְאַנְתְּ הוּא שְׁלִֽימוּ דְּכֻלְּהוּ: וְכַד אַנְתְּ תִּסְתַּלָּק מִנְּהוֹן. אִשְׁתְּאָֽרוּ כֻּלְּהוּ שְׁמָהָן כְּגוּפָא בְלָא נִשְׁמָתָא: אַנְתְּ הוּא חַכִּים וְלָאו בְּחָכְמָה יְדִיעָא. אַנְתְּ הוּא מֵבִין וְלָאו מִבִּינָה יְדִיעָא. לֵית לָךְ אֲתָר יְדִיעָא. אֶלָּא לְאִשְׁתְּמֽוֹדְעָא תֻּקְפָךְ וְחֵילָךְ לִבְנֵי נָשָׁא. וּלְאַחְזָאָה לוֹן אֵיךְ אִתְנְהִיג עָֽלְמָא בְּדִינָא וּבְרַחֲמֵי דְּאִנּוּן צֶֽדֶק וּמִשְׁפָּט כְּפוּם עוֹבָדֵיהוֹן דִּבְנֵי נָשָׁא: דִּין אִֽיהוּ גְבוּרָה. מִשְׁפָּט עַמּוּדָא דְאֶמְצָעִיתָא. צֶֽדֶק מַלְכוּתָא קַדִּישָׁא. מֹֽאזְנֵֽי צֶֽדֶק תְּרֵין סַמְכֵי קְשׁוֹט. הִין צֶֽדֶק אוֹת בְּרִית. כֹּלָּא לְאַחְזָאָה אֵיךְ אִתְנְהִיג עָֽלְמָא: אֲבָל לָאו דְּאִית לָךְ צֶֽדֶק יְדִיעָא דְּאִֽיהוּ דִין. וְלָאו מִשְׁפָּט יְדִיעָא דְאִֽיהוּ רַחֲמֵי. וְלָאו מִכָּל־אִלֵּין מִדּוֹת כְּלָל: קוּם רִבִּי שִׁמְעוֹן וְיִתְחַדְּשׁוּן מִלִּין עַל יְדָךְ, דְּהָא רְשׁוּתָא אִית לָךְ לְגַלָּאָה רָזִין טְמִירִין עַל יְדָךְ, מַה דְּלָא אִתְיְהִב רְשׁוּ לְגַלָּאָה לָשׂוּם בַּר־נָשׁ עַד כְּעָן:"}, {"kind": "text", "text": "<b>קָם</b> רַבִּי שִׁמְעוֹן פָּתַח וְאָמַר, לְךָ֣ יְ֠הֹוָ֠ה הַגְּדֻלָּ֨ה וְהַגְּבוּרָ֤ה וְהַתִּפְאֶ֙רֶת֙ וְהַנֵּ֣צַח וְהַה֔וֹד כִּי־כֹ֖ל בַּשָּׁמַ֣יִם וּבָאָ֑רֶץ לְךָ֤ יְהֹוָה֙ הַמַּמְלָכָ֔ה וְהַמִּתְנַשֵּׂ֖א לְכֹ֥ל ׀ לְרֹֽאשׁ, עִלָּאִין שִׁמְעוּ אִינוּן דְמִיכִין דְּחֶבְרוֹן, וְרַעְיָא מְהֵימְנָא אִתְּעָרוּ מִשְּׁנַתְכוֹן, הָקִיצוּ וְרַנְּנוּ שׁוֹכְנֵי עָפָר, אִלֵּין אִינוּן צַדִּיקַיָּא דְּאִינוּן מִסִּטְרָא דְּהַהִיא דְּאִתְמַר בָּהּ אֲנִ֥י יְשֵׁנָ֖ה וְלִבִּ֣י עֵ֑ר, וְלָאו אִינוּן מֵתִים, וּבְגִין דָּא אִתְמַר בְּהוֹן הָקִיצוּ וְרַנְּנוּ וְכוּ', רַעְיָא מְהֵימְנָא, אַנְתְּ וַאֲבָהָן הָקִיצוּ וְרַנְּנוּ לְאִתְּעָרוּתָא דִּשְׁכִינְתָּא, דְּאִיהִי יְשֵׁנָהּ בְּגָלוּתָא, דְּעַד כְּעַן צַדִּיקַיָּא כֻּלְּהוּ דְמִיכִין וְשִׁנְתָּא בְּחוֹרֵיהוֹן: מִיַּד יְהִיבַת שְׁכִינְתָּא תְּלָת קָלִין לְגַבֵּי רַעְיָא מְהֵימְנָא, וְיֵימָא לֵיהּ קוּם רַעְיָא מְהֵימְנָא, דְּהָא עֲלָךְ אִתְמַר ק֣וֹל ׀ דּוֹדִ֣י דוֹפֵ֗ק לְגַבָּאי בְּאַרְבַּע אַתְוָן דִּילֵיהּ, וְיֵימָא בְּהוֹן, פִּתְחִי־לִ֞י אֲחֹתִ֤י רַעְיָתִי֙ יוֹנָתִ֣י תַמָּתִ֔י, דְּהָא תַּם־עֲוֺנֵךְ֙ בַּת־צִיּ֔וֹן, לֹ֥א יוֹסִ֖יף לְהַגְלוֹתֵ֑ךְ: שֶׁרֹּאשִׁי֙ נִמְלָא־טָ֔ל, מַאי נִמְלָא טָל, אֶלָּא אָמַר קוּדְשָׁא בְּרִיךְ הוּא, אַנְתְּ חָשַׁבְתְּ דְּמִיּוֹמָא דְאִתְחָרַב בֵּי מַקְדְּשָׁא דְּעָֽאלְנָא בְּבֵיתָא דִילִי, וְעָֽאלְנָא בְיִשּׁוּבָא, לָאו הָכִי, דְּלָא עָֽאלְנָא כָּל זִמְנָא דְּאַנְתְּ בְּגָלוּתָא, הֲרֵי לְךָ סִימָנָא, שֶׁרֹּאשִׁי֙ נִמְלָא־טָ֔ל, הֵ\"א שְׁכִינְתָּא בְּגָלוּתָא, שְׁלִימוּ דִילָהּ וְחַיִּים דִילָהּ אִיהוּ טַ\"ל, וְדָא אִיהוּ [אוֹת] יוֹ\"ד [וְאוֹת] הֵ\"א [וְאוֹת] וָא\"ו, וְהֵ\"א אִיהִי שְׁכִינְתָּא דְּלָא מֵחֻשְׁבָּן טָ\"ל, אֶלָּא [אוֹת] יוֹ\"ד [וְאוֹת] הֵ\"א [וְאוֹת] וָא\"ו, דִּסְלִיקוּ אַתְוָן לְחֻשְׁבָּן טָ\"ל, דְּאִיהִי מַלְיָא לִשְׁכִינְתָּא מִנְּבִיעוּ דְכָל־מְקוֹרִין עִלָּאִין, מִיַּד קָם רַעְיָא מְהֵימְנָא, וַאֲבָהָן קַדִּישִׁין עִמֵּיהּ, עַד כָּאן רָזָא דְיִחוּדָא. בָּר֖וּךְ יְהֹוָ֥ה לְ֝עוֹלָ֗ם אָ֘מֵ֥ן ׀ וְאָמֵֽן:"}, {"kind": "instruction", "text": "יְהֵא רַעֲוָא מִן קֳדָם עַתִּיקָא קַדִּישָׁא דְכָל־קַדִּישִׁין. טְמִירָא דְּכָל־טְמִירִין סְתִימָא דְכֹֽלָּא דְּיִתְמְשָׁךְ טַלָּא עִלָּאָה מִנֵּיהּ לְמַלְיָא רֵישֵׁיהּ דִזְעֵיר אַנְפִּין וּלְהַטִּיל לַחֲקַל תַּפּוּחִין קַדִּישִׁין בִּנְהִֽירוּ דְּאַנְפִּין בְּרַעֲוָא וּבְחֶדְוָתָא דְכֹֽלָּא. וְיִתְמְשָָׁךְ מִן קֳדָם עַתִּיקָא קַדִּישָׁא דְכָל־קַדִּישִׁין טְמִירָא דְכָל־טְמִירִין סְתִימָא דְכֹֽלָא רְעוּתָא וְרַחֲמֵי חִנָּא וְחִסְדָּא בִּנְהִֽירוּ עִלָּאָה בִּרְעוּתָא וְחֶדְוָא עָלַי וְעַל־כָּל־בְּנֵי בֵֽיתִי וְעַל־כָּל־הַנִּלְוִים אֵלַי וְעַל־כָּל־יִשְׂרָאֵל עַמֵּיהּ. וְיִפְרְקִינָן מִכָּל־עַקְתִין בִּישִׁין דְּיֵיתוּן לְעָֽלְמָא וְיַזְמִין וְיִתְיְהִיב לָֽנָא וּלְכָל־נַפְשָׁתָֽנָא חִנָּא וְחִסְדָּא וְחַיֵּי אֲרִיכֵי וּמְזוֹנֵי רְוִיחֵי וְרַחֲמֵי מִן קֳדָמֵיהּ. אָמֵן כֵּן יְהִי רָצוֹן אָמֵן וְאָמֵן:"}, {"kind": "instruction", "text": "אחר פתיחת אליהו זכור לטוב יאמרו מאמר רבי שמעון בר יוחאי הכתוב בזוהר הקדוש פרשת נח דף ס״ה ופקודי דף רס״ה: (בא״ח וישלח י״ב)"}, {"kind": "text", "text": "<b>אָמַר</b> רִבִּי שִׁמְעוֹן: אֲרִימִית יְדָאי בִּצְלוֹתִין לְעֵֽלָא, דְּכַד רְעוּתָא עִלָּאָה לְעֵֽלָא לְעֵֽלָא קַיְמָא עַל הַהוּא רְעוּתָא דְּלָא אִתְיְדַע וְלָא אִתְפַס כְּלָל לְעָֽלְמִֽין, רֵישָׁא דְסָתִים יַתִּיר לְעֵֽלָא, וְהַהוּא רֵישָׁא אַפִּיק מָאי דְּאַפִּיק וְלָא יְדִֽיעַ, וְנָהִיר מָאי דְּנָהִיר כֹּֽלָּא בִּסְתִֽימוּ, רְעוּ דְּמַחֲשָׁבָה עִלָּאָה לְמִרְדַּף אֲבַּתְרֵיהּ וּלְאִתְנַהֲרָא מִנֵּיהּ. חָד פְּרִֽיסוּ אִתְפְּרִיס, וּמִגּוֹ הַהוּא פְרִיסָא בִּרְדִיפוּ דְּהַהִיא מַחֲשָׁבָה עִלָּאָה מָטֵי וְלָא מָטֵי, עַד הַהוּא פְרִיסָא נָהִיר מָאי דְּנָהִיר, וּכְדֵין הַהוּא מַחֲשָׁבָה עִלָּאָה נָהִיר בִּנְהִירוּ סָתִים דְּלָא יְדִֽיעַ, וְהַהוּא מַחֲשָׁבָה לָא יָדַע, כְּדֵין בָּטַשׁ הַאי נְהִֽירוּ דְמַחֲשָׁבָה דְּלָא אִתְיְדַע בִּנְהִֽירוּ דְפַרְסָא דְּקָיְמָא דְּנָהִיר מִמָּה דְלָא יְדִֽיעַ וְלָא אִתְיְדַע וְלָא אִתְגַּלְיָא, וּכְדֵין דָּא נְהִֽירוּ דְמַחֲשָׁבָה דְּלָא אִתְיְדַע בָּטַשׁ בִּנְהִֽירוּ דִפְרִסָא וְנַהֲרִין כַּחֲדָא, וְאִתְעֲבִֽידוּ תִּשְׁעָה הֵיכָלִין. וְהֵיכָלִין לָאו אִנּוּן נְהוֹרִין, וְלָאו אִנּוּן רוּחִין, וְלָאו אִנּוּן נִשְׁמָתִין, וְלָא אִית מָאן דְּקַיְמָא בְהוּ. רְעוּתָא דְכָל־תִּשְׁעָה נְהוֹרִין דְּקַיְמֵי כֻלְּהוּ בְּמַחֲשָׁבָה, דְּאִֽיהוּ חָד מִנַּֽיְהוּ בְּחוּשְׁבָּנָא, כֻלְּהוּ לְמִרְדַּף בַּתְרַֽיְהוּ, בְּשַׁעְתָּא דְקַיְמֵי בְמַחֲשָׁבָה וְלָא מִתְדַּבְּקָן וְלָא אִתְיְדָֽעוּ, וְאִלֵּין לָא קַיְמֵי לָא בִרְעוּתָא וְלָא בְמַחֲשָׁבָה עִלָּאָה תַּפְסִין בָּהּ וְלָא תַּפְסִין, בְּאִלֵּין קַיְמֵי כָּל־רָזֵי דִמְהֵימְנוּתָא. וְכָל־אִנּוּן נְהוֹרִין מֵרָזָא דְמַחֲשָׁבָה עִלָּאָה וּלְתַתָּא, כֻּלְּהוּ אִקְּרוּן אֵין סוֹף. עַד הָכָא מָטוּ נְהוֹרִין, וְלָא מָטוּן וְלָא אִתְיְדָֽעוּ, לָאו הָכָא רְעוּתָא וְלָא מַחֲשָׁבָה כַּד נָהִיר מַחֲשָׁבָה וְלָא אִתְיְדַע מִמָּאן דְּנָהִיר, כְּדֵין אִתְלַבַּשׁ וְאַסְתִּים גּוֹ בִינָה, וְנָהִיר לְמָאן דְּנָהִיר, וְאָעִיל דָּא בְדָא, עַד דְּאִתְכְּלִֽילוּ כֻּלְּהוּ כַּחֲדָא. וּבְרָזָא דְקָרְבָּנָא כַּד סָלִיק, כֹּלָּא אִתְקְשַׁר דָּא בְדָא, וְנָהִיר דָּא בְדָא, כְּדֵין קַיְמֵי כֻלְּהוּ בִּסְלִֽיקוּ וּמַחֲשָׁבָה אִתְעַטָּר בְּאֵין סוֹף. הַהוּא נְהִֽירוּ דְּאִתְנְהִיר מִנֵּיהּ מַחֲשָׁבָה עִלָּאָה (דְּלָא אִתְיְדַע בָּהּ כְּלָל) אִקְּרֵי אֵין סוֹף, דְּמִנֵּיהּ אִשְׁתַּכַּח וְקַיְמָא וְנָהִיר לְמָאן דְּנָהִיר, וְעַל דָּא כֹּֽלָּא קָאִים. זַכָּאָה חוּלָקֵיהוֹן דְּצַדִּיקַיָא בְּעָֽלְמָא דֵין וּבְעָֽלְמָא דְאָתֵי:"}, {"kind": "header", "text": "סדר עטיפת ציצית"}, {"kind": "text", "text": "<b>לְשֵׁם</b> יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם יוֹ\"ד קֵ\"י בְּוָא\"ו קֵ\"י בְּיִחוּדָא שְׁלִים (יהוה) בְּשֵׁם כָּל־יִשְׂרָאֵל. הֲרֵינִי מוּכָן לְקַיֵּם מִצְוַת עֲשֵׂה לִלְבֹּשׁ טַלִּית מְצֻיֶּצֶת כְּהִלְכָתָהּ, כְּמוֹ שֶׁצִּוָּנוּ יְהֹוָה אֱלֹהֵֽינוּ בְּתוֹרָתוֹ הַקְּדוֹשָׁה: (במדבר טו לח) וְעָשׂ֨וּ לָהֶ֥ם צִיצִ֛ת עַל־כַּנְפֵ֥י בִגְדֵיהֶ֖ם. כְדֵי שֶׁנִּזְכֹּר כָּל־מִצְוֹתָיו לַעֲשׂוֹתָם שֶׁנֶּאֱמַר (במדבר טו לט) וּרְאִיתֶ֣ם אֹת֗וֹ וּזְכַרְתֶּם֙ אֶת־כׇּל־מִצְוֺ֣ת יְהֹוָ֔ה וַעֲשִׂיתֶ֖ם אֹתָ֑ם. וַהֲרֵינִי מוּכָן לְבָרֵךְ עַל עֲטִיפַת הַטָּלִית כְּתִקּוּן רַבּוֹתֵינוּ זִכְרוֹנָם לִבְרָכָה. וַהֲרֵינִי מְכַוֵּן לִפְטֹר בִּבְרָכָה זוֹ גַּם טַלִּית הַקָּטָן שֶׁעָלַי. כְּדֵי לַעֲשׂוֹת נַֽחַת רֽוּחַ לְיֽוֹצְרֵֽנוּ וְלַעֲשׂוֹת רְצוֹן בּֽוֹרְאֵֽנוּ. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ׃"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוֹתָיו וְצִוָּנוּ לְהִתְעַטֵּף בְּצִיצִית:"}, {"kind": "header", "text": "סדר הנחת תפילין"}, {"kind": "text", "text": "<b>לְשֵׁם</b> יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם יוֹ\"ד קֵ\"י בְּוָא\"ו קֵ\"י בְּיִחוּדָא שְׁלִים (יהוה) בְּשֵׁם כָּל־יִשְׂרָאֵל. הֲרֵינִי מוּכָן לְקַיֵּם מִצְוַת עֲשֵׂה לְהָנִיחַ תְּפִלִּין בְּיָדִי וּבְרֹאשִׁי, כְּמוֹ שֶׁצִּוָּנוּ יְהֹוָה אֱלֹהֵֽינוּ: (דברים יא יח) וּקְשַׁרְתֶּ֨ם אֹתָ֤ם לְאוֹת֙ עַל־יֶדְכֶ֔ם וְהָי֥וּ לְטוֹטָפֹ֖ת בֵּ֥ין עֵינֵיכֶֽם. וְצִוָּנוּ הַקָּדוֹשׁ בָּרוּךְ הוּא לְהָנִיחַ אַרְבַּע פַּרְשִׁיּוֹת אֵלּוּ שֶׁיֵּשׁ בָּהֶם יִחוּד שְׁמוֹ וִיצִיאַת מִצְרַיִם עַל הַזְּרוֹעַ כְּנֶגֶד הַלֵּב, וְעַל הָרֹאשׁ כְּנֶגֶד הַמֹּחַ, כְּדֵי שֶׁנִּזְכֹּר נִסִּים וְנִפְלָאוֹת שֶׁעָשָׂה עִמָּנוּ. וַהֲרֵינִי מוּכָן לְבָרֵךְ הַבְּרָכָה שֶׁתִּקְנוּ רַבּוֹתֵינוּ זִכְרוֹנָם לִבְרָכָה עַל מִצְוַת הַתְּפִלִּין, וַהֲרֵינִי מְכַוֵּן לִפְטֹר בִּבְרָכָה זוֹ תְּפִלִּין שֶׁל יָד וּתְפִלִּין שֶׁל רֹאשׁ, וְיַעֲלֶה לְפָנֶיךָ יְהֹוָה אֱלֹהֵֽינוּ וֵאלהֵי אֲבוֹתֵינוּ כְּאִלּוּ כִּוַּנְתִּי בְּכָל הַכַּוָּנוֹת הָרְאוּיוֹת לְכַוֵּן בַּהֲנָחַת הַתְּפִלִּין וּבַבְּרָכָה. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ׃"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוֹתָיו, וְצִוָּנוּ לְהָנִיחַ תְּפִלִּין:<br><br>אם הפסיק בין תפלין של יד לתפלין של ראש בדבר דחשיב הפסק, אז יברך על תפלין של ראש (בא\"ח וירא ו')<br><b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָֽׁנוּ בְּמִצְוֹתָיו, וְצִוָּנוּ עַל מִצְוַת תְּפִלִּין:"}, {"kind": "text", "text": "אחר שהניח תפלין של ראש, אז תכף ומיד יגמור הנחת תפלין של יד בשלש כריכות שכורך באצבע האמצעי הנקרא אמה, ויעשה כריכה אחת בפרק האמצעי של האצבע ושתי כריכות בפרק התחתון, ויאמר בעת שעושה הכריכות הנזכרות (בא\"ח וירא ט\"ז)<br>וְאֵרַשְׂתִּ֥יךְ לִ֖י לְעוֹלָ֑ם וְאֵרַשְׂתִּ֥יךְ לִי֙ בְּצֶ֣דֶק וּבְמִשְׁפָּ֔ט וּבְחֶ֖סֶד וּֽבְרַחֲמִֽים׃ וְאֵרַשְׂתִּ֥יךְ לִ֖י בֶּאֱמוּנָ֑ה וְיָדַ֖עַתְּ אֶת־יְהֹוָֽה׃"}, {"kind": "text", "text": "אחר שיניח התפילין יאמר פרשת קדש ווהיה כי יביאך כדי להשלים ארבעת פרשיות בכל יום ואם אינו יכול לאומרם קודם תפלה יאמר אותם אחר תפלה (בא\"ח וירא כ\"ה)<br><b>וַיְדַבֵּ֥ר</b> יְהֹוָ֖ה אֶל־מֹשֶׁ֥ה לֵּאמֹֽר׃ קַדֶּשׁ־לִ֨י כׇל־בְּכ֜וֹר פֶּ֤טֶר כׇּל־רֶ֙חֶם֙ בִּבְנֵ֣י יִשְׂרָאֵ֔ל בָּאָדָ֖ם וּבַבְּהֵמָ֑ה לִ֖י הֽוּא׃ וַיֹּ֨אמֶר מֹשֶׁ֜ה אֶל־הָעָ֗ם זָכ֞וֹר אֶת־הַיּ֤וֹם הַזֶּה֙ אֲשֶׁ֨ר יְצָאתֶ֤ם מִמִּצְרַ֙יִם֙ מִבֵּ֣ית עֲבָדִ֔ים כִּ֚י בְּחֹ֣זֶק יָ֔ד הוֹצִ֧יא יְהֹוָ֛ה אֶתְכֶ֖ם מִזֶּ֑ה וְלֹ֥א יֵאָכֵ֖ל חָמֵֽץ׃ הַיּ֖וֹם אַתֶּ֣ם יֹצְאִ֑ים בְּחֹ֖דֶשׁ הָאָבִֽיב׃ וְהָיָ֣ה כִֽי־יְבִיאֲךָ֣ יְהֹוָ֡ה אֶל־אֶ֣רֶץ הַֽ֠כְּנַעֲנִ֠י וְהַחִתִּ֨י וְהָאֱמֹרִ֜י וְהַחִוִּ֣י וְהַיְבוּסִ֗י אֲשֶׁ֨ר נִשְׁבַּ֤ע לַאֲבֹתֶ֙יךָ֙ לָ֣תֶת לָ֔ךְ אֶ֛רֶץ זָבַ֥ת חָלָ֖ב וּדְבָ֑שׁ וְעָבַדְתָּ֛ אֶת־הָעֲבֹדָ֥ה הַזֹּ֖את בַּחֹ֥דֶשׁ הַזֶּֽה׃ שִׁבְעַ֥ת יָמִ֖ים תֹּאכַ֣ל מַצֹּ֑ת וּבַיּוֹם֙ הַשְּׁבִיעִ֔י חַ֖ג לַיהֹוָֽה׃ מַצּוֹת֙ יֵֽאָכֵ֔ל אֵ֖ת שִׁבְעַ֣ת הַיָּמִ֑ים וְלֹֽא־יֵרָאֶ֨ה לְךָ֜ חָמֵ֗ץ וְלֹֽא־יֵרָאֶ֥ה לְךָ֛ שְׂאֹ֖ר בְּכׇל־גְּבֻלֶֽךָ׃ וְהִגַּדְתָּ֣ לְבִנְךָ֔ בַּיּ֥וֹם הַה֖וּא לֵאמֹ֑ר בַּעֲב֣וּר זֶ֗ה עָשָׂ֤ה יְהֹוָה֙ לִ֔י בְּצֵאתִ֖י מִמִּצְרָֽיִם׃ וְהָיָה֩ לְךָ֨ לְא֜וֹת עַל־יָדְךָ֗ וּלְזִכָּרוֹן֙ בֵּ֣ין עֵינֶ֔יךָ לְמַ֗עַן תִּהְיֶ֛ה תּוֹרַ֥ת יְהֹוָ֖ה בְּפִ֑יךָ כִּ֚י בְּיָ֣ד חֲזָקָ֔ה הוֹצִֽאֲךָ֥ יְהֹוָ֖ה מִמִּצְרָֽיִם׃ וְשָׁמַרְתָּ֛ אֶת־הַחֻקָּ֥ה הַזֹּ֖את לְמוֹעֲדָ֑הּ מִיָּמִ֖ים יָמִֽימָה׃"}, {"kind": "text", "text": "<b>וְהָיָ֞ה</b> כִּֽי־יְבִאֲךָ֤ יְהֹוָה֙ אֶל־אֶ֣רֶץ הַֽכְּנַעֲנִ֔י כַּאֲשֶׁ֛ר נִשְׁבַּ֥ע לְךָ֖ וְלַֽאֲבֹתֶ֑יךָ וּנְתָנָ֖הּ לָֽךְ׃ וְהַעֲבַרְתָּ֥ כׇל־פֶּֽטֶר־רֶ֖חֶם לַֽיהֹוָ֑ה וְכׇל־פֶּ֣טֶר ׀ שֶׁ֣גֶר בְּהֵמָ֗ה אֲשֶׁ֨ר יִהְיֶ֥ה לְךָ֛ הַזְּכָרִ֖ים לַיהֹוָֽה׃ וְכׇל־פֶּ֤טֶר חֲמֹר֙ תִּפְדֶּ֣ה בְשֶׂ֔ה וְאִם־לֹ֥א תִפְדֶּ֖ה וַעֲרַפְתּ֑וֹ וְכֹ֨ל בְּכ֥וֹר אָדָ֛ם בְּבָנֶ֖יךָ תִּפְדֶּֽה׃ וְהָיָ֞ה כִּֽי־יִשְׁאׇלְךָ֥ בִנְךָ֛ מָחָ֖ר לֵאמֹ֣ר מַה־זֹּ֑את וְאָמַרְתָּ֣ אֵלָ֔יו בְּחֹ֣זֶק יָ֗ד הוֹצִיאָ֧נוּ יְהֹוָ֛ה מִמִּצְרַ֖יִם מִבֵּ֥ית עֲבָדִֽים׃ וַיְהִ֗י כִּֽי־הִקְשָׁ֣ה פַרְעֹה֮ לְשַׁלְּחֵ֒נוּ֒ וַיַּהֲרֹ֨ג יְהֹוָ֤ה כׇּל־בְּכוֹר֙ בְּאֶ֣רֶץ מִצְרַ֔יִם מִבְּכֹ֥ר אָדָ֖ם וְעַד־בְּכ֣וֹר בְּהֵמָ֑ה עַל־כֵּן֩ אֲנִ֨י זֹבֵ֜חַ לַֽיהֹוָ֗ה כׇּל־פֶּ֤טֶר רֶ֙חֶם֙ הַזְּכָרִ֔ים וְכׇל־בְּכ֥וֹר בָּנַ֖י אֶפְדֶּֽה׃ וְהָיָ֤ה לְאוֹת֙ עַל־יָ֣דְכָ֔ה וּלְטוֹטָפֹ֖ת בֵּ֣ין עֵינֶ֑יךָ כִּ֚י בְּחֹ֣זֶק יָ֔ד הוֹצִיאָ֥נוּ יְהֹוָ֖ה מִמִּצְרָֽיִם׃"}, {"kind": "header", "text": "תפילת חנה"}, {"kind": "text", "text": "<b>וַתִּתְפַּלֵּ֤ל</b> חַנָּה֙ וַתֹּאמַ֔ר עָלַ֤ץ לִבִּי֙ בַּֽיהֹוָ֔ה רָ֥מָה קַרְנִ֖י בַּֽיהֹוָ֑ה רָ֤חַב פִּי֙ עַל־א֣וֹיְבַ֔י כִּ֥י שָׂמַ֖חְתִּי בִּישׁוּעָתֶֽךָ׃ אֵין־קָד֥וֹשׁ כַּיהֹוָ֖ה כִּ֣י אֵ֣ין בִּלְתֶּ֑ךָ וְאֵ֥ין צ֖וּר כֵּאלֹהֵֽינוּ׃ אַל־תַּרְבּ֤וּ תְדַבְּרוּ֙ גְּבֹהָ֣ה גְבֹהָ֔ה יֵצֵ֥א עָתָ֖ק מִפִּיכֶ֑ם כִּ֣י אֵ֤ל דֵּעוֹת֙ יְהֹוָ֔ה ולא [וְל֥וֹ] נִתְכְּנ֖וּ עֲלִלֽוֹת׃ קֶ֥שֶׁת גִּבֹּרִ֖ים חַתִּ֑ים וְנִכְשָׁלִ֖ים אָ֥זְרוּ חָֽיִל׃ שְׂבֵעִ֤ים בַּלֶּ֙חֶם֙ נִשְׂכָּ֔רוּ וּרְעֵבִ֖ים חָדֵ֑לּוּ עַד־עֲקָרָה֙ יָלְדָ֣ה שִׁבְעָ֔ה וְרַבַּ֥ת בָּנִ֖ים אֻמְלָֽלָה׃ יְהֹוָ֖ה מֵמִ֣ית וּמְחַיֶּ֑ה מוֹרִ֥יד שְׁא֖וֹל וַיָּֽעַל׃ יְהֹוָ֖ה מוֹרִ֣ישׁ וּמַעֲשִׁ֑יר מַשְׁפִּ֖יל אַף־מְרוֹמֵֽם׃ מֵקִ֨ים מֵעָפָ֜ר דָּ֗ל מֵֽאַשְׁפֹּת֙ יָרִ֣ים אֶבְי֔וֹן לְהוֹשִׁיב֙ עִם־נְדִיבִ֔ים וְכִסֵּ֥א כָב֖וֹד יַנְחִלֵ֑ם כִּ֤י לַֽיהֹוָה֙ מְצֻ֣קֵי אֶ֔רֶץ וַיָּ֥שֶׁת עֲלֵיהֶ֖ם תֵּבֵֽל׃ רַגְלֵ֤י חֲסִידָו֙ יִשְׁמֹ֔ר וּרְשָׁעִ֖ים בַּחֹ֣שֶׁךְ יִדָּ֑מּוּ כִּי־לֹ֥א בְכֹ֖חַ יִגְבַּר־אִֽישׁ׃ יְהֹוָ֞ה יֵחַ֣תּוּ מְרִיבָ֗ו עָלָו֙ בַּשָּׁמַ֣יִם יַרְעֵ֔ם יְהֹוָ֖ה יָדִ֣ין אַפְסֵי־אָ֑רֶץ וְיִתֶּן־עֹ֣ז לְמַלְכּ֔וֹ וְיָרֵ֖ם קֶ֥רֶן מְשִׁיחֽוֹ׃ אָת֙וֹהִי֙ כְּמָ֣ה רַבְרְבִ֔ין וְתִמְה֖וֹהִי כְּמָ֣ה תַקִּיפִ֑ין מַלְכוּתֵהּ֙ מַלְכ֣וּת עָלַ֔ם וְשׇׁלְטָנֵ֖הּ עִם־דָּ֥ר וְדָֽר: וַאֲנַ֤חְנוּ עַמְּךָ֨ ׀ וְצֹ֥אן מַרְעִיתֶךָ֮ נ֤וֹדֶ֥ה לְּךָ֗ לְע֫וֹלָ֥ם לְד֥וֹר וָדֹ֑ר נְ֝סַפֵּ֗ר תְּהִלָּתֶֽךָ: עֶ֤רֶב וָבֹ֣קֶר וְ֭צׇהֳרַיִם אָשִׂ֣יחָה וְאֶֽהֱמֶ֑ה וַיִּשְׁמַ֥ע קוֹלִֽי: בְּרׇן־יַ֭חַד כּ֣וֹכְבֵי בֹ֑קֶר וַ֝יָּרִ֗יעוּ כׇּל־בְּנֵ֥י אֱלֹהִֽים: לֹֽא־אִ֭ירָא מֵרִבְב֥וֹת עָ֑ם אֲשֶׁ֥ר סָ֝בִ֗יב שָׁ֣תוּ עָלָֽי: וַֽאֲנִי֙ בַּיהֹוָ֣ה אֲצַפֶּ֔ה אוֹחִ֖ילָה לֵאלֹהֵ֣י יִשְׁעִ֑י יִשְׁמָעֵ֖נִי אֱלֹהָֽי: בשבת ויום טוב אין אומרים פסוק זה אַֽל־תִּשְׂמְחִ֤י אֹיַ֙בְתִּי֙ לִ֔י כִּ֥י נָפַ֖לְתִּי קָ֑מְתִּי כִּֽי־אֵשֵׁ֣ב בַּחֹ֔שֶׁךְ יְהֹוָ֖ה א֥וֹר לִֽי: כִּֽי־לְךָ֣ יְהֹוָ֣ה הוֹחָ֑לְתִּי אַתָּ֥ה תַ֝עֲנֶ֗ה אֲדֹנָ֥י אֱלֹהָֽי: רַ֭גְלִי עָמְדָ֣ה בְמִישׁ֑וֹר בְּ֝מַקְהֵלִ֗ים אֲבָרֵ֥ךְ יְהֹוָֽה:"}, {"kind": "header", "text": "תפילת שחרית"}, {"kind": "text", "text": "יזהר כל אדם לומר קודם פרשת העקידה נוסח זה, ובזה הנוסח שאומר האדם בכל יום קודם תפלה יהיה מוצל מלטותא דרבי שמעון בר יוחאי דלייט באדרא רבא דף קמ\"א עמוד ב (ח\"ג קמא, ב), וה' לא ימנע טוב להולכים בתמים (בא\"ח מקץ י\"ב)<br><b>רִבּוֹן</b> עָֽלְמָא יְהֵא רַעֲוָא קַמָּךְ לְמֵיהַב לָן חֵילָא לְאִתְעֲרָא בִּיקָרָךְ, וּלְמֶעְבַּד רְעוּתָךְ, וּלְסַדְּרָא כֹֽלָּא כִּדְקָא יָאוּת. וְאַף עַל גַּב דְּלֵית אֲנַן יָֽדְעִֽין לְשַׁוְּאָה רְעוּתָא וְלִבָּא לְתַקְּנָא כֹֽלָּא, יְהֵא רַעֲוָא קַמָּךְ דְּתִתְרְעֵי בְמִלִּין וּצְלוֹתָא דִּילָן, לְתַקָּנָא תִּקּוּנָא דִלְעֵֽלָּא כִּדְקָא יָאוּת, וְלֶהֱווּ הֵיכָלִין עִלָּאִין, וְרוּחִין עִלָּאִין עַיְלֵי הֵיכָלָא בְּהֵיכָלָא, וְרוּחָא בְּרוּחָא, עַד דְּמִתְחַבְּרָן בְּדוּכְתַּיְהוּ כִּדְקָא חָזֵי, שַׁיְפָא בְשַׁיְפָא, וְאִשְׁתְּלִימוּ דָּא בְדָא, וְאִתְיַחֲדוּ דָּא בְדָא עַד אִנּוּן חָד, וְנַהֲרִין דָּא בְדָא, וּכְדֵין נִשְׁמְתָא עִלָּאָה דְכֹלָּא אַתְיָא מִלְּעֵלָּא וְנָהִיר לוֹן, וְלֶהֱווּ נְהִירִין כֻּלְּהוּ בוֹצִינִין בִּשְׁלִימוּ כִּדְקָא חָזֵי, עַד דְּהַהוּא נְהוֹרָא עִלָּאָה אִתְּעַר, וְכֹלָּא אָעִיל לְגַבֵּי קֹדֶשׁ קָדָשִׁים, וְאִתְבָּרְכָא וְאִתְמַלְיָא כְּבֵירָא דְמַיִּין נָבְעִין וְלָא פָסְקִין, וְכֻלְּהוּ מִתְבָּרְכָן לְעֵלָּא וְתַתָּא, וְהַהוּא דְלָּא אִתְיְדַע וְלָא אָעִיל בְּחוּשְׁבָּנָא רְעוּתָא דְלָא אִתְּפַס לְעָלְמִין בָּסִים לְגוֹ לְגוֹ בְּגַוָּיְהוּ וְלָא אִתְיְדַע הַהוּא רְעוּתָא וְלָא אִתְּפַס לְמִנְדַּע, וּכְדֵין כֹּלָּא רְעוּתָא חֲדָא עַד אֵין סוֹף וְכֹלָּא אִיהוּ בִּשְׁלִימוּ מִלְּתַתָּא וּמִגּוֹ לְגוֹ עַד דְּאִתְעָבִיד כֹּלָּא חָד, וְאִתְמַלְיָא כֹּלָּא וְאִשְׁתְּלִים כֹּלָּא וְאִתְנְהִיר וְאִתְבַּסָּם כֹּלָּא כִּדְקָא יָאוּת:<br><b>רִבּוֹן</b> עָֽלְמָא יְהֵא רְעוּתָךְ עִם עַמָּךְ יִשְׂרָאֵל לְעָלַם, וּפֻרְקַן יְמִינָךְ אַחֲזֵי לְעַמָּךְ בְּבֵית מַקְדְּשָׁךְ, וּלְאַמְטוּיֵי לָנָא מִטּוּב נְהוֹרָךְ, וּלְקַבְּלָא צְלוֹתָנָא בְּרַחֲמֵי, יְהֵא רַעֲוָא קַמָּךְ דְּתֶהֱוֵי סָעִיד וְסָמִיךְ לָן, דְּנֵימָא מִלִּין בְּאֹרַח מֵישַׁר, בְּתִקּוּנָא דִלְעֵלָּא, בְּתִקּוּנִין דְּמַלְכָּא קַדִּישָׁא וּמַטְרוֹנִיתָא קַדִּישָׁא, וּלְמֶעְבַּד יִחוּדָא שְׁלִים, לְאַשְׁלָפָא לְהַהִיא נִשְׁמְתָה דְכָל־חַיֵי מִדַּרְגָּא לְדַרְגָּא עַד סוֹפָא דְכָל־דַּרְגִּין, בְּגִין דְּתֶהֱוֵי הַהִיא נִשְׁמְתָא מִשְׁתַּכְּחָא בְּכֹלָּא וּמִתְפַּשְּׁטָא בְּכֹלָּא, דְּהָא עֵילָּא וְתַתָּא תַּלְיָן בְּהַהִיא נִשְׁמְתָא וּמִתְקַיְּמֵי בָהּ:"}, {"kind": "instruction", "text": "לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ, בִּדְחִֽילוּ וּרְחִֽימוּ, וּרְחִֽימוּ וּדְחִֽילוּ, לְיַחֲדָא שֵׁם יוֹ\"ד קֵ\"א בְּוָא\"ו קֵ\"א בְּיִחוּדָא שְׁלִים, בְּשֵׁם כָּל־יִשְׂרָאֵל, הִנֵּה אֲנַֽחְנוּ בָּאִים לְהִתְפַּלֵּל תְּפִלַּת שַׁחֲרִית, שֶׁתִּקֵּן אַבְרָהָם אָבִינוּ עָלָיו הַשָּׁלוֹם, עִם כָּל הַמִּצְוֹת הַכְּלוּלוֹת בָּהּ, לְתַקֵּן אֶת שָׁרְשָׁהּ בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַֽחַת רֽוּחַ לְיֽוֹצְרֵֽנוּ וְלַעֲשׂוֹת רְצוֹן בּֽוֹרְאֵֽנוּ. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ׃<br><br>וַהֲרֵינִי מְקַבֵּל עָלַי מִצְוַת עֲשֵׂה שֶׁל \"וְאָהַבְתָּ לְרֵעֲךָ כָּמוֹךָ\" וַהֲרֵינִי אוֹהֵב כָּל אֶחָד מִבְּנֵי יִשְׂרָאֵל כְּנַפְשִׁי וּמְאוֹדִי, וַהֲרֵינִי מְזַמֵּן אֶת פִּי לְהִתְפַּלֵּל לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים, הַקָּדוֹשׁ בָּרוּךְ הוּא:"}, {"kind": "text", "text": "<b>אֱלֹהֵינוּ</b> וֵאלֹהֵי אֲבוֹתֵינוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב מִלְּפָנֶיךָ, וּפָקְדֵנוּ בִּפְקֻדַת יְשׁוּעָה וְרַחֲמִים מִשְּׁמֵי שְׁמֵי קֶדֶם, וּזְכֹר־לָנוּ יְהֹוָה אֱלֹהֵינוּ אַהֲבַת הַקַּדְמוֹנִים אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל עֲבָדֶיךָ, אֶת הַבְּרִית וְאֶת הַחֶסֶד וְאֶת הַשְּׁבוּעָה שֶׁנִּשְׁבַּעְתָּ לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה, וְאֶת הָעֲקֵדָה שֶׁעָקַד אֶת יִצְחָק בְּנוֹ עַל־גַּבֵּי הַמִּזְבֵּחַ כַּכָּתוּב בְּתוֹרָתָךְ:"}, {"kind": "text", "text": "<b>וַיְהִ֗י</b> אַחַר֙ הַדְּבָרִ֣ים הָאֵ֔לֶּה וְהָ֣אֱלֹהִ֔ים נִסָּ֖ה אֶת־אַבְרָהָ֑ם וַיֹּ֣אמֶר אֵלָ֔יו אַבְרָהָ֖ם וַיֹּ֥אמֶר הִנֵּֽנִי׃ וַיֹּ֡אמֶר קַח־נָ֠א אֶת־בִּנְךָ֨ אֶת־יְחִֽידְךָ֤ אֲשֶׁר־אָהַ֙בְתָּ֙ אֶת־יִצְחָ֔ק וְלֶ֨ךְ־לְךָ֔ אֶל־אֶ֖רֶץ הַמֹּרִיָּ֑ה וְהַעֲלֵ֤הוּ שָׁם֙ לְעֹלָ֔ה עַ֚ל אַחַ֣ד הֶֽהָרִ֔ים אֲשֶׁ֖ר אֹמַ֥ר אֵלֶֽיךָ׃ וַיַּשְׁכֵּ֨ם אַבְרָהָ֜ם בַּבֹּ֗קֶר וַֽיַּחֲבֹשׁ֙ אֶת־חֲמֹר֔וֹ וַיִּקַּ֞ח אֶת־שְׁנֵ֤י נְעָרָיו֙ אִתּ֔וֹ וְאֵ֖ת יִצְחָ֣ק בְּנ֑וֹ וַיְבַקַּע֙ עֲצֵ֣י עֹלָ֔ה וַיָּ֣קׇם וַיֵּ֔לֶךְ אֶל־הַמָּק֖וֹם אֲשֶׁר־אָֽמַר־ל֥וֹ הָאֱלֹהִֽים׃ בַּיּ֣וֹם הַשְּׁלִישִׁ֗י וַיִּשָּׂ֨א אַבְרָהָ֧ם אֶת־עֵינָ֛יו וַיַּ֥רְא אֶת־הַמָּק֖וֹם מֵרָחֹֽק׃ וַיֹּ֨אמֶר אַבְרָהָ֜ם אֶל־נְעָרָ֗יו שְׁבוּ־לָכֶ֥ם פֹּה֙ עִֽם־הַחֲמ֔וֹר וַאֲנִ֣י וְהַנַּ֔עַר נֵלְכָ֖ה עַד־כֹּ֑ה וְנִֽשְׁתַּחֲוֶ֖ה וְנָשׁ֥וּבָה אֲלֵיכֶֽם׃ וַיִּקַּ֨ח אַבְרָהָ֜ם אֶת־עֲצֵ֣י הָעֹלָ֗ה וַיָּ֙שֶׂם֙ עַל־יִצְחָ֣ק בְּנ֔וֹ וַיִּקַּ֣ח בְּיָד֔וֹ אֶת־הָאֵ֖שׁ וְאֶת־הַֽמַּאֲכֶ֑לֶת וַיֵּלְכ֥וּ שְׁנֵיהֶ֖ם יַחְדָּֽו׃ וַיֹּ֨אמֶר יִצְחָ֜ק אֶל־אַבְרָהָ֤ם אָבִיו֙ וַיֹּ֣אמֶר אָבִ֔י וַיֹּ֖אמֶר הִנֶּ֣נִּֽי בְנִ֑י וַיֹּ֗אמֶר הִנֵּ֤ה הָאֵשׁ֙ וְהָ֣עֵצִ֔ים וְאַיֵּ֥ה הַשֶּׂ֖ה לְעֹלָֽה׃ וַיֹּ֙אמֶר֙ אַבְרָהָ֔ם אֱלֹהִ֞ים יִרְאֶה־לּ֥וֹ הַשֶּׂ֛ה לְעֹלָ֖ה בְּנִ֑י וַיֵּלְכ֥וּ שְׁנֵיהֶ֖ם יַחְדָּֽו׃ וַיָּבֹ֗אוּ אֶֽל־הַמָּקוֹם֮ אֲשֶׁ֣ר אָֽמַר־ל֣וֹ הָאֱלֹהִים֒ וַיִּ֨בֶן שָׁ֤ם אַבְרָהָם֙ אֶת־הַמִּזְבֵּ֔חַ וַֽיַּעֲרֹ֖ךְ אֶת־הָעֵצִ֑ים וַֽיַּעֲקֹד֙ אֶת־יִצְחָ֣ק בְּנ֔וֹ וַיָּ֤שֶׂם אֹתוֹ֙ עַל־הַמִּזְבֵּ֔חַ מִמַּ֖עַל לָעֵצִֽים׃ וַיִּשְׁלַ֤ח אַבְרָהָם֙ אֶת־יָד֔וֹ וַיִּקַּ֖ח אֶת־הַֽמַּאֲכֶ֑לֶת לִשְׁחֹ֖ט אֶת־בְּנֽוֹ׃ וַיִּקְרָ֨א אֵלָ֜יו מַלְאַ֤ךְ יְהֹוָה֙ מִן־הַשָּׁמַ֔יִם וַיֹּ֖אמֶר אַבְרָהָ֣ם ׀ אַבְרָהָ֑ם וַיֹּ֖אמֶר הִנֵּֽנִי׃ וַיֹּ֗אמֶר אַל־תִּשְׁלַ֤ח יָֽדְךָ֙ אֶל־הַנַּ֔עַר וְאַל־תַּ֥עַשׂ ל֖וֹ מְא֑וּמָה כִּ֣י ׀ עַתָּ֣ה יָדַ֗עְתִּי כִּֽי־יְרֵ֤א אֱלֹהִים֙ אַ֔תָּה וְלֹ֥א חָשַׂ֛כְתָּ אֶת־בִּנְךָ֥ אֶת־יְחִידְךָ֖ מִמֶּֽנִּי׃ וַיִּשָּׂ֨א אַבְרָהָ֜ם אֶת־עֵינָ֗יו וַיַּרְא֙ וְהִנֵּה־אַ֔יִל אַחַ֕ר נֶאֱחַ֥ז בַּסְּבַ֖ךְ בְּקַרְנָ֑יו וַיֵּ֤לֶךְ אַבְרָהָם֙ וַיִּקַּ֣ח אֶת־הָאַ֔יִל וַיַּעֲלֵ֥הוּ לְעֹלָ֖ה תַּ֥חַת בְּנֽוֹ׃ וַיִּקְרָ֧א אַבְרָהָ֛ם שֵֽׁם־הַמָּק֥וֹם הַה֖וּא יְהֹוָ֣ה ׀ יִרְאֶ֑ה אֲשֶׁר֙ יֵאָמֵ֣ר הַיּ֔וֹם בְּהַ֥ר יְהֹוָ֖ה יֵרָאֶֽה׃ וַיִּקְרָ֛א מַלְאַ֥ךְ יְהֹוָ֖ה אֶל־אַבְרָהָ֑ם שֵׁנִ֖ית מִן־הַשָּׁמָֽיִם׃ וַיֹּ֕אמֶר בִּ֥י נִשְׁבַּ֖עְתִּי נְאֻם־יְהֹוָ֑ה כִּ֗י יַ֚עַן אֲשֶׁ֤ר עָשִׂ֙יתָ֙ אֶת־הַדָּבָ֣ר הַזֶּ֔ה וְלֹ֥א חָשַׂ֖כְתָּ אֶת־בִּנְךָ֥ אֶת־יְחִידֶֽךָ׃ כִּֽי־בָרֵ֣ךְ אֲבָרֶכְךָ֗ וְהַרְבָּ֨ה אַרְבֶּ֤ה אֶֽת־זַרְעֲךָ֙ כְּכוֹכְבֵ֣י הַשָּׁמַ֔יִם וְכַח֕וֹל אֲשֶׁ֖ר עַל־שְׂפַ֣ת הַיָּ֑ם וְיִרַ֣שׁ זַרְעֲךָ֔ אֵ֖ת שַׁ֥עַר אֹיְבָֽיו׃ וְהִתְבָּרְכ֣וּ בְזַרְעֲךָ֔ כֹּ֖ל גּוֹיֵ֣י הָאָ֑רֶץ עֵ֕קֶב אֲשֶׁ֥ר שָׁמַ֖עְתָּ בְּקֹלִֽי׃ וַיָּ֤שׇׁב אַבְרָהָם֙ אֶל־נְעָרָ֔יו וַיָּקֻ֛מוּ וַיֵּלְכ֥וּ יַחְדָּ֖ו אֶל־בְּאֵ֣ר שָׁ֑בַע וַיֵּ֥שֶׁב אַבְרָהָ֖ם בִּבְאֵ֥ר שָֽׁבַע׃"}, {"kind": "instruction", "text": "יש נוהגים לומר את הקטע הבא"}, {"kind": "text", "text": "וְשָׁחַ֨ט אֹת֜וֹ עַ֣ל יֶ֧רֶךְ הַמִּזְבֵּ֛חַ צָפֹ֖נָה לִפְנֵ֣י יְהֹוָ֑ה וְזָרְק֡וּ בְּנֵי֩ אַהֲרֹ֨ן הַכֹּהֲנִ֧ים אֶת־דָּמ֛וֹ עַל־הַמִּזְבֵּ֖חַ סָבִֽיב:"}, {"kind": "text", "text": "יְהִי רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּתְמַלֵּא רַחֲמִים עָלֵינוּ, וּבְכֵן בְּרוֹב רַחֲמֶיךָ תִּזְכּוֹר לָנוּ עֲקֵדָתוֹ שֶׁל יִצְחָק אָבִינוּ בֶּן אַבְרָהָם אָבִינוּ עָלָיו הַשָּׁלוֹם, כְּאִלּוּ אֶפְרוֹ צָבוּר וּמֻנָּח עַל גַּבֵּי הַמִּזְבֵּחַ, וְתַבִּיט בְּאֶפְרוֹ לְרַחֵם עָלֵינוּ, וּלְבַטֵּל מֵעָלֵינוּ כָּל־גְּזֵירוֹת קָשׁוֹת וְרָעוֹת, וּתְזַכֵּנוּ לָשׁוּב בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ, וְתַצִּילֵנוּ מִיֵּצֶר הָרָע וּמִכָּל חֵטְא וְעָוֹן, וְתַאֲרִיךְ יָמֵינוּ בַּטּוֹב וּשְׁנוֹתֵינוּ בַּנְּעִימִים:"}, {"kind": "text", "text": "<b>רִבּוֹנוֹ</b> שֶׁל עוֹלָם, כְּמוֹ שֶׁכָּבַשׁ אַבְרָהָם אָבִינוּ אֶת רַחֲמָיו לַעֲשׂוֹת רְצוֹנְךָ בְּלֵבָב שָׁלֵם, כֵּן יִכְבְּשׁוּ רַחֲמֶיךָ אֶת כַּעַסֶֽךָ, וְיִּגֹּלוּ רַחֲמֶיךָ עַל מִדּוֹתֶיךָ, וְתִתְנַהֵג עִמָּנוּ יְהֹוָה אֱלֹהֵינוּ בְּמִדַּת הַחֶסֶד וּבְמִדַּת הָרַחֲמִים, וְתִכָּנֵס לָנוּ לִפְנִים מִשּׁוּרַת הַדִּין, וּבְטוּבְךָ הַגָּדוֹל יָשׁוּב חֲרוֹן אַפָּךְ, מֵעַמָּךְ וּמֵעִירָךְ וּמֵאַרְצָךְ וּמִנַּחֲלָתָךְ, וְקַיֵם לָנוּ יְהֹוָה אֱלֹהֵינוּ אֶת הַדָּבָר שֶׁהִבְטַחְתָּנוּ בְּתוֹרָתָךְ עַל יְדֵי מֹשֶׁה עַבְדָּךְ כָּאָמוּר: וְזָכַרְתִּ֖י אֶת־בְּרִיתִ֣י יַעֲק֑וֹב וְאַף֩ אֶת־בְּרִיתִ֨י יִצְחָ֜ק וְאַ֨ף אֶת־בְּרִיתִ֧י אַבְרָהָ֛ם אֶזְכֹּ֖ר וְהָאָ֥רֶץ אֶזְכֹּֽר: וְנֶאֱמַר: וְאַף־גַּם־זֹ֠את בִּֽהְיוֹתָ֞ם בְּאֶ֣רֶץ אֹֽיְבֵיהֶ֗ם לֹֽא־מְאַסְתִּ֤ים וְלֹֽא־גְעַלְתִּים֙ לְכַלֹּתָ֔ם לְהָפֵ֥ר בְּרִיתִ֖י אִתָּ֑ם כִּ֛י אֲנִ֥י יְהֹוָ֖ה אֱלֹהֵיהֶֽם: וְזָכַרְתִּ֥י לָהֶ֖ם בְּרִ֣ית רִאשֹׁנִ֑ים אֲשֶׁ֣ר הוֹצֵֽאתִי־אֹתָם֩ מֵאֶ֨רֶץ מִצְרַ֜יִם לְעֵינֵ֣י הַגּוֹיִ֗ם לִהְי֥וֹת לָהֶ֛ם לֵאלֹהִ֖ים אֲנִ֥י יְהֹוָֽה: וְנֶאֱמַר: וְשָׁ֨ב יְהֹוָ֧ה אֱלֹהֶ֛יךָ אֶת־שְׁבוּתְךָ֖ וְרִחֲמֶ֑ךָ וְשָׁ֗ב וְקִבֶּצְךָ֙ מִכׇּל־הָ֣עַמִּ֔ים אֲשֶׁ֧ר הֱפִֽיצְךָ֛ יְהֹוָ֥ה אֱלֹהֶ֖יךָ שָֽׁמָּה: אִם־יִהְיֶ֥ה נִֽדַּחֲךָ֖ בִּקְצֵ֣ה הַשָּׁמָ֑יִם מִשָּׁ֗ם יְקַבֶּצְךָ֙ יְהֹוָ֣ה אֱלֹהֶ֔יךָ וּמִשָּׁ֖ם יִקָּחֶֽךָ: וֶהֱבִיאֲךָ֞ יְהֹוָ֣ה אֱלֹהֶ֗יךָ אֶל־הָאָ֛רֶץ אֲשֶׁר־יָרְשׁ֥וּ אֲבֹתֶ֖יךָ וִֽירִשְׁתָּ֑הּ וְהֵיטִֽבְךָ֥ וְהִרְבְּךָ֖ מֵאֲבֹתֶֽיךָ: וְנֶאֱמַר עַל יְדֵי נְבִיאֶךָ: יְהֹוָ֥ה חׇנֵּ֖נוּ לְךָ֣ קִוִּ֑ינוּ הֱיֵ֤ה זְרֹעָם֙ לַבְּקָרִ֔ים אַף־יְשׁוּעָתֵ֖נוּ בְּעֵ֥ת צָרָֽה: וְנֶאֱמַר: וְעֵֽת־צָרָ֥ה הִיא֙ לְיַֽעֲקֹ֔ב וּמִמֶּ֖נָּה יִוָּשֵֽׁעַ: וְנֶאֱמַר: בְּֽכׇל־צָרָתָ֣ם ׀ לא [ל֣וֹ] צָ֗ר וּמַלְאַ֤ךְ פָּנָיו֙ הוֹשִׁיעָ֔ם בְּאַהֲבָת֥וֹ וּבְחֶמְלָת֖וֹ ה֣וּא גְאָלָ֑ם וַֽיְנַטְּלֵ֥ם וַֽיְנַשְּׂאֵ֖ם כׇּל־יְמֵ֥י עוֹלָֽם: וְנֶאֱמַר: יכוין לי\"ג מדות מִי־אֵ֣ל כָּמ֗וֹךָ אל נֹשֵׂ֤א עָוֺן֙ רחום וְעֹבֵ֣ר עַל־פֶּ֔שַׁע וחנון לִשְׁאֵרִ֖ית נַחֲלָת֑וֹ ארך לֹֽא־הֶחֱזִ֤יק לָעַד֙ אַפּ֔וֹ אפים כִּֽי־חָפֵ֥ץ חֶ֖סֶד הֽוּא ורב חסד: יָשׁ֣וּב יְרַחֲמֵ֔נוּ ואמת יִכְבֹּ֖שׁ עֲוֺנֹתֵ֑ינוּ נצר חסד וְתַשְׁלִ֛יךְ בִּמְצֻל֥וֹת יָ֖ם כׇּל־חַטֹּאותָֽם לאלפים: תִּתֵּ֤ן אֱמֶת֙ לְיַֽעֲקֹ֔ב נושא עון חֶ֖סֶד לְאַבְרָהָ֑ם ופשע אֲשֶׁר־נִשְׁבַּ֥עְתָּ לַאֲבֹתֵ֖ינוּ וחטאה מִ֥ימֵי קֶֽדֶם ונקה: וְנֶאֱמַר: וַהֲבִיאוֹתִ֞ים אֶל־הַ֣ר קׇדְשִׁ֗י וְשִׂמַּחְתִּים֙ בְּבֵ֣ית תְּפִלָּתִ֔י עוֹלֹתֵיהֶ֧ם וְזִבְחֵיהֶ֛ם לְרָצ֖וֹן עַֽל־מִזְבְּחִ֑י כִּ֣י בֵיתִ֔י בֵּית־תְּפִלָּ֥ה יִקָּרֵ֖א לְכׇל־הָעַמִּֽים:"}, {"kind": "text", "text": "<b>אֵלּוּ</b> דְבָרִים שֶׁאֵין לָהֶם שִׁעוּר: הַפֵּאָה, וְהַבִּכּוּרִים, וְהָרֵאָיוֹן, וּגְמִילוּת חֲסָדִים, וְתַלְמוּד תּוֹרָה: אֵלּוּ דְבָרִים שֶׁאָדָם עוֹשֶׂה אוֹתָם וְאוֹכֵל פֵּרוֹתֵיהֶם בָּעוֹלָם הַזֶּה, וְהַקֶּרֶן קַיֶּמֶת לָעוֹלָם הַבָּא: וְאֵלּוּ הֵן: כִּבּוּד אָב וָאֵם, וּגְמִילוּת חֲסָדִים, וּבִקּוּר חוֹלִים, וְהַכְנָסַת אוֹרְחִים, וְהַשְׁכָּמַת בֵּית הַכְּנֶסֶת, וַהֲבָאַת שָׁלוֹם בֵּין אָדָם לַחֲבֵרוֹ וּבֵין אִישׁ לְאִשְׁתוֹ וְתַלְמוּד תּוֹרָה כְּנֶגֶד כֻּלָּם."}, {"kind": "text", "text": "<b>לְעוֹלָם</b> יְהֵא אָדָם יְרֵא שָׁמַיִם בַּסֵּתֶר כְּבַגָּלוּי, וּמוֹדֶה עַל הָאֱמֶת, וְדוֹבֵר אֱמֶת בִּלְבָבוֹ, וְיַשְׁכִּים וְיֹאמַר: רִבּוֹן הָעוֹלָמִים וַאֲדוֹנֵי הָאֲדוֹנִים, לֹא עַל צִּדְקוֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ כִּי עַל רַחֲמֶיךָ הָרַבִּים: אֲדֹנָ֤י ׀ שְׁמָ֙עָה֙ אֲדֹנָ֣י ׀ סְלָ֔חָה אֲדֹנָ֛י הַֽקְשִׁ֥יבָה וַעֲשֵׂ֖ה אַל־תְּאַחַ֑ר לְמַֽעַנְךָ֣ אֱלֹהַ֔י כִּֽי־שִׁמְךָ֣ נִקְרָ֔א עַל־עִירְךָ֖ וְעַל־עַמֶּֽךָ׃ מָה אֲנַחְנוּ, מַה חַיֵּינוּ, מַה חַסְדֵנוּ, מַה־צִּדְקוֹתֵינוּ, מַה־כֹּחֵנוּ, מַה־גְּבוּרָתֵנוּ. מַה נֹּאמַר לְפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, הֲלֹא כָּל־הַגִבּוֹרִים כְּאַיִן לְפָנֶיךָ, וְאַנְשֵׁי הַשֵּׁם כְּלֹא הָיוּ, וַחֲכָמִים כִּבְלִי מַדָּע, וּנְבוֹנִים כִּבְלִי הַשְׂכֵּל, כִּי כָל־מַעֲשֵֽׂינוּ תֹֽהוּ, וִימֵי חַיֵּינוּ הֶבֶֶל לְפָנֶיךָ, וּמוֹתַ֨ר הָאָדָ֤ם מִן־הַבְּהֵמָה֙ אָ֔יִן כִּ֥י הַכֹּ֖ל הָֽבֶל׃ לְבַד הַנְּשָׁמָה הַטְּהוֹרָה שֶׁהִיא עֲתִידָה לִתֵּן דִּין וְחֶשְׁבּוֹן לִפְנֵי כִסֵּא כְבוֹדֶךָ. וְכָל־הַגּוֹיִם כְּאַיִן נֶגְדֶּךָ, שֶׁנֶּאֱמַר: הֵ֤ן גּוֹיִם֙ כְּמַ֣ר מִדְּלִ֔י וּכְשַׁ֥חַק מֹאזְנַ֖יִם נֶחְשָׁ֑בוּ הֵ֥ן אִיִּ֖ים כַּדַּ֥ק יִטּֽוֹל׃ אֲבָל אֲנַחְנוּ עַמְּךָ בְּנֵי בְרִיתֶךָ, בְּנֵי אַבְרָהָם אֹהֲבֶךָ שֶׁנִּשְׁבַּעְתָּ־לוֹ בְּהַר הַמּוֹרִיָּה, זֶרַע יִצְחָק עֲקֵדֶךָ שֶׁנֶּעֱקַד עַל־גַּבֵּי הַמִּזְבֵּחַ, עֲדַת יַעֲקֹב בִּנְךָ בְכוֹרֶךָ, שֶׁמֵּאַהֲבָתְךָ שֶׁאָהַבְתָּ אוֹתוֹ, וּמִשִּׂמְחָתְךָ שֶׁשָּׂמַחְתָּ־בּוֹ, קָרָאתָ אוֹתוֹ יִשְׂרָאֵל וִישֻׁרוּן:"}, {"kind": "text", "text": "<b>לְפִיכָךְ</b> אֲנַחְנוּ חַיָּבִים לְהוֹדוֹת לָךְ, וּלְשַׁבְּחָךְ וּלְפָאֲרָךְ וּלְרוֹמְמָךְ, וְלִתֵּן שִׁיר שֶׁבַח וְהוֹדָאָה לְשִׁמְךָ הַגָּדוֹל בְּכָל יוֹם תָּמִיד. אַשְׁרֵינוּ, מַה טוֹב חֶלְקֵינוּ, וּמַה נָעִים גּוֹרָלֵנוּ, וּמַה יָפָה מְאוֹד יְרוּשָׁתֵינוּ, אַשְׁרֵינוּ כְּשֶׁאֲנַחְנוּ מַשְׁכִּימִים וּמַעֲרִיבִים בְּבָתֵּי כְּנֵסִיּוֹת וּבְבָתֵּי מִדְרָשׁוֹת וּמְיַחֲדִים שִׁמְךָ בְּכָל יוֹם תָּמִיד אוֹמְרִים פַּעֲמַיִם בְּאַהֲבָה:"}, {"kind": "text", "text": "כשיגיע לקריאת שמע קודם פרשת התמיד יזהר לומר פסוקים שמע ישראל וברוך בכונה גדולה כמו קריאת שמע דיוצר (בא\"ח מקץ ה\"ז), ואם רואה שזמן קריאת שמע עובר יאמר כאן קריאת שמע כולה"}, {"kind": "text", "text": "<b>שְׁמַ֖ע יִשְׂרָאֵ֑ל יְהֹוָ֥ה אֱלֹהֵ֖ינוּ יְהֹוָ֥ה ׀ אֶחָֽד</b>׃"}, {"kind": "text", "text": "ואומר בלחש בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "<b>אַתָּה</b> הוּא אֶחָד קוֹדֵם שֶׁבָּרָאתָ הָעוֹלָם, וְאַתָּה הוּא אֶחָד לְאַחַר שֶׁבָּרָאתָ הָעוֹלָם, אַתָּה הוּא אֵל בָּעוֹלָם הַזֶּה, וְאַתָּה הוּא אֵל בָּעוֹלָם הַבָּא, וְאַתָּה־ה֑וּא וּ֝שְׁנוֹתֶ֗יךָ לֹ֣א יִתָּֽמּוּ׃ קַדֵּשׁ שְׁמָךְ בְּעוֹלָמָךְ עַל־עַם מְקַדְּשֵׁי שְׁמֶךָ, וּבִישׁוּעָתְךָ מַלְכֵּנוּ תָּרוּם וְתַגְבִּיהַּ קַרְנֵנוּ, וְתוֹשִׁיעֵנוּ בְּקָרוֹב לְמַעַן שְׁמֶךָ, בָּרוּךְ הַמְקַדֵּשׁ שְׁמוֹ בָּרַבִּים:"}, {"kind": "text", "text": "<b>אַתָּה</b> הוּא יְהֹוָה הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל־הָאָרֶץ מִתַּחַת, בִּשְׁמֵי הַשָּׁמַיִם הָעֶלְיוֹנִים וְהַתַּחְתּוֹנִים, אַתָּה הוּא רִאשׁוֹן וְאַתָּה הוּא אַחֲרוֹן וּמִבַּלְעָדֶיךָ אֵין אֱלֹהִים. קַבֵּץ נְפוּצוֹת קֹוֶיךָ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל בָּאֵי עוֹלָם כִּי אַתָּה הוּא הָאֱלֹהִים לְבַדְּךָ לְכָל מַמְלְכוֹת הָאָרֶץ, אַתָּה עָשִׂיתָ אֶת הַשָּׁמַיִם וְאֶת הָאָרֶץ, אֶת הַיָּם וְאֶת כָּל אֲשֶׁר בָּם, וּמִי בְּכָל מַעֲשֵׂה יָדֶיךָ בָּעֶלְיוֹנִים וּבַתַּחְתּוֹנִים שֶׁיֹּאמַר לָךְ מַה־תַּעֲשֶׂה וּמַה־תִּפְעָל. אָבִינוּ שֶׁבַּשָּׁמַיִם חַי וְקַיָּם, עֲשֵׂה עִמָּנוּ חֶסֶד בַּעֲבוּר כְּבוֹד שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ, וְקַיֵּם לָנוּ יְהֹוָה אֱלֹהֵינוּ אֶת הַדָּבָר שֶׁהִבְטַחְתָּנוּ עַל יְדֵי צְפַנְיָה חוֹזָךְ כָּאָמוּר: בָּעֵ֤ת הַהִיא֙ אָבִ֣יא אֶתְכֶ֔ם וּבָעֵ֖ת קַבְּצִ֣י אֶתְכֶ֑ם כִּֽי־אֶתֵּ֨ן אֶתְכֶ֜ם לְשֵׁ֣ם וְלִתְהִלָּ֗ה בְּכֹל֙ עַמֵּ֣י הָאָ֔רֶץ בְּשׁוּבִ֧י אֶת־שְׁבוּתֵיכֶ֛ם לְעֵינֵיכֶ֖ם אָמַ֥ר יְהֹוָֽה:"}, {"kind": "text", "text": "<b>יְהִי רָצוֹן</b> מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ שֶׁתְּרַחֵם עָלֵינוּ, וְתִמְחוֹל לָנוּ אֶת כָּל חַטְּאוֹתֵינוּ, וּתְכַפֵּר לָנוּ אֶת־כָּל־עֲוֹנוֹתֵינוּ, וְתִמְחוֹל וְתִסְלַח לְכָל פְּשָׁעֵינוּ, וְתִּבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְנַקְרִיב לְפָנֶיךָ קָרְבַּן הַתָּמִיד שֶׁיְּכַפֵּר בַּעֲדֵינוּ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתָךְ עַל יְדֵי מֹשֶׁה עַבְדָּךְ כָּאָמוּר:"}, {"kind": "text", "text": "<b>וַיְדַבֵּ֥ר</b> יְהֹוָ֖ה אֶל־מֹשֶׁ֥ה לֵּאמֹֽר׃ צַ֚ו אֶת־בְּנֵ֣י יִשְׂרָאֵ֔ל וְאָמַרְתָּ֖ אֲלֵהֶ֑ם אֶת־קׇרְבָּנִ֨י לַחְמִ֜י לְאִשַּׁ֗י רֵ֚יחַ נִֽיחֹחִ֔י תִּשְׁמְר֕וּ לְהַקְרִ֥יב לִ֖י בְּמוֹעֲדֽוֹ׃ וְאָמַרְתָּ֣ לָהֶ֔ם זֶ֚ה הָֽאִשֶּׁ֔ה אֲשֶׁ֥ר תַּקְרִ֖יבוּ לַיהֹוָ֑ה כְּבָשִׂ֨ים בְּנֵֽי־שָׁנָ֧ה תְמִימִ֛ם שְׁנַ֥יִם לַיּ֖וֹם עֹלָ֥ה תָמִֽיד׃ אֶת־הַכֶּ֥בֶשׂ אֶחָ֖ד תַּעֲשֶׂ֣ה בַבֹּ֑קֶר וְאֵת֙ הַכֶּ֣בֶשׂ הַשֵּׁנִ֔י תַּעֲשֶׂ֖ה בֵּ֥ין הָֽעַרְבָּֽיִם׃ וַעֲשִׂירִ֧ית הָאֵיפָ֛ה סֹ֖לֶת לְמִנְחָ֑ה בְּלוּלָ֛ה בְּשֶׁ֥מֶן כָּתִ֖ית רְבִיעִ֥ת הַהִֽין׃ עֹלַ֖ת תָּמִ֑יד הָעֲשֻׂיָה֙ בְּהַ֣ר סִינַ֔י לְרֵ֣יחַ נִיחֹ֔חַ אִשֶּׁ֖ה לַֽיהֹוָֽה׃ וְנִסְכּוֹ֙ רְבִיעִ֣ת הַהִ֔ין לַכֶּ֖בֶשׂ הָאֶחָ֑ד בַּקֹּ֗דֶשׁ הַסֵּ֛ךְ נֶ֥סֶךְ שֵׁכָ֖ר לַיהֹוָֽה׃ וְאֵת֙ הַכֶּ֣בֶשׂ הַשֵּׁנִ֔י תַּעֲשֶׂ֖ה בֵּ֣ין הָֽעַרְבָּ֑יִם כְּמִנְחַ֨ת הַבֹּ֤קֶר וּכְנִסְכּוֹ֙ תַּעֲשֶׂ֔ה אִשֵּׁ֛ה רֵ֥יחַ נִיחֹ֖חַ לַיהֹוָֽה׃"}, {"kind": "header", "text": "פטום הקטורת"}, {"kind": "text", "text": "<b>אַתָּה</b> הוּא יְהֹוָה אֱלֹהֵֽינוּ, שֶׁהִקְטִֽירוּ אֲבוֹתֵֽינוּ לְפָנֶֽיךָ אֶת קְטֹֽרֶת הַסַּמִּים, בִּזְמַן שֶׁבֵּית הַמִּקְדָשׁ קַיָּם, כַּאֲשֶׁר צִוִּֽיתָ אוֹתָם עַל־יַד מֹשֶׁה נְבִיאָךְ, כַּכָּתוּב בְּתֽוֹרָתָךְ:"}, {"kind": "text", "text": "<b>וַיֹּ֩אמֶר֩</b> יְהֹוָ֨ה אֶל־מֹשֶׁ֜ה קַח־לְךָ֣ סַמִּ֗ים נָטָ֤ף | וּשְׁחֵ֙לֶת֙ וְחֶלְבְּנָ֔ה סַמִּ֖ים וּלְבֹנָ֣ה זַכָּ֑ה בַּ֥ד בְּבַ֖ד יִהְיֶֽה׃ וְעָשִׂ֤יתָ אֹתָהּ֙ קְטֹ֔רֶת רֹ֖קַח מַעֲשֵׂ֣ה רוֹקֵ֑חַ מְמֻלָּ֖ח טָה֥וֹר קֹֽדֶשׁ׃ וְשָֽׁחַקְתָּ֣ מִמֶּ֘נָּה֮ הָדֵק֒ וְנָתַתָּ֨ה מִמֶּ֜נָּה לִפְנֵ֤י הָעֵדֻת֙ בְּאֹ֣הֶל מוֹעֵ֔ד אֲשֶׁ֛ר אִוָּעֵ֥ד לְךָ֖ שָׁ֑מָּה קֹ֥דֶשׁ קׇֽדָשִׁ֖ים תִּהְיֶ֥ה לָכֶֽם׃ וְנֶֽאֱמַר וְהִקְטִ֥יר עָלָ֛יו אַהֲרֹ֖ן קְטֹ֣רֶת סַמִּ֑ים בַּבֹּ֣קֶר בַּבֹּ֗קֶר בְּהֵיטִיב֛וֹ אֶת־הַנֵּרֹ֖ת יַקְטִירֶֽנָּה: וּבְהַעֲלֹ֨ת אַהֲרֹ֧ן אֶת־הַנֵּרֹ֛ת בֵּ֥ין הָעַרְבַּ֖יִם יַקְטִירֶ֑נָּה קְטֹ֧רֶת תָּמִ֛יד לִפְנֵ֥י יְהֹוָ֖ה לְדֹרֹתֵיכֶֽם:"}, {"kind": "text", "text": "<b>תָּנוּ</b> רַבָּנָן: פִּטּוּם הַקְּטֹֽרֶת כֵּיצַד? שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וּשְׁמוֹנָה מָנִים הָיוּ בָהּ. שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וַֽחֲמִשָּׁה כְּמִנְיַן יְמוֹת הַחַמָּה, מָנֶה בְּכָל־יוֹם, מַֽחֲצִיתוֹ בַּבֹּֽקֶר וּמַֽחֲצִיתוֹ בָּעֶרֶב. וּשְׁלֹשָׁה מָנִים יְתֵרִים, שֶׁמֵּהֶם מַכְנִיס כֹּהֵן גָּדוֹל, וְנוֹטֵל מֵהֶם מְלֹא חָפְנָיו בְּיוֹם הַכִּפּוּרִים, וּמַֽחֲזִירָן לְמַכְתֶּֽשֶׁת בְּעֶֽרֶב יוֹם הַכִּפּוּרִים, כְּדֵי לְקַיֵּם מִצְוַת דַקָּה מִן הַדַּקָּה. וְאַחַד־עָשָׂר סַמָּנִים הָיוּ בָהּ, וְאֵֽלּוּ הֵן:"}, {"kind": "text", "text": "א הַצֳּרִי ב וְהַצִּפֹּֽרֶן ג וְהַחֶלְבְּנָה ד וְהַלְּבוֹנָה, מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה. ה מוֹר, ו וּקְצִיעָה ז וְשִׁבֹּֽלֶת נֵרְדְּ ח וְכַרְכֹּם, מִשְׁקַל שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה. ט קֹשְׁטְ שְׁנֵים עָשָׂר, י קִלּוּפָה שְׁלֹשָׁה, יא קִנָּמוֹן תִּשְׁעָה, בּוֹרִית־כַּרְשִׁינָה תִּשְׁעָה קַבִּין. יֵין קַפְרִיסִין סְאִין תְּלָת וְקַבִּין תְּלָתָא. וְאִם לֹא מָצָא יֵין קַפְרִיסִין, מֵבִיא חֲמַר חִיוָר עַתִּיק. מֶֽלַח סְדוֹמִית, רֽוֹבַע. מַעֲלֶה עָשָׁן, כָּל־שֶׁהוּא. רִבִּי נָתָן הַבַּבְלִי אוֹמֵר: אַף כִּפַּת הַיַּרְדֵּן כָּל־שֶׁהִיא, אִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ, וְאִם חִסֵּר אַחַת מִכָּל־סַמְמָנֶֽיהָ, חַיָּיב מִיתָה:"}, {"kind": "text", "text": "<b>רַבָּן</b> שִׁמְעוֹן בֶּן־גַּמְלִיאֵל אוֹמֵר: הַצֳּרִי אֵינוֹ אֶלָּא שְׁרָף, הַנּוֹטֵף מֵֽעֲצֵי הַקְּטָף. בֹּרִית כַּרְשִׁינָה, לְמָה הִיא בָֽאָה? כְּדֵי לְשַׁפּוֹת בָּהּ אֶת־הַצִּפֹּֽרֶן, כְּדֵי שֶׁתְּהֵא נָאָה. יֵין קַפְרִיסִין, לְמָה הוּא בָא? כְּדֵי לִשְׁרוֹת בּוֹ אֶת־הַצִּפֹּֽרֶן כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלֹא מֵי רַגְלַֽיִם יָפִין לָהּ? אֶלָּא שֶׁאֵין מַכְנִיסִין מֵי רַגְלַֽיִם בַּמִּקְדָּשׁ, מִפְּנֵי הַכָּבוֹד:"}, {"kind": "text", "text": "<b>תַּנְיָא</b> רִבִּי נָתָן אוֹמֵר: כְּשֶׁהוּא שׁוֹחֵק, אוֹמֵר: הָדֵק הֵיטֵב, הֵיטֵב הָדֵק. מִפְּנֵי שֶׁהַקּוֹל יָפֶה לַבְּשָׂמִים. פִּטְּמָהּ לַֽחֲצָאִין, כְּשֵׁרָה. לְשָׁלִישׁ וּלְרָבִֽיעַ, לֹא שָׁמַֽעְנוּ. אָמַר רִבִּי יְהוּדָה: זֶה הַכְּלָל, אִם כְּמִדָּתָהּ, כְּשֵׁרָה לַֽחֲצָאִין. וְאִם חִסֵּר אַחַת מִכָּל־סַמְמָנֶֽיהָ, חַיָּיב מִיתָה:"}, {"kind": "text", "text": "<b>תָּנֵי</b> בַר־קַפָּרָא: אַחַת לְשִׁשִּׁים אוֹ לְשִׁבְעִים שָׁנָה, הָֽיְתָה בָֽאָה שֶׁל שִׁירַֽיִם לַֽחֲצָאִין. וְעוֹד תָּנֵי בַר־קַפָּרָא: אִלּוּ הָיָה נוֹתֵן בָּהּ קָרְטוֹב שֶׁל דְּבַשׁ, אֵין אָדָם יָכוֹל לַֽעֲמֹד מִפְּנֵי רֵיחָהּ. וְלָֽמָּה אֵין מְעָֽרְבִין בָּהּ דְּבַשׁ? מִפְּנֵי שֶׁהַתּוֹרָה אָֽמְרָה: כִּ֤י כָל־שְׂאֹר֙ וְכָל־דְּבַ֔שׁ לֹֽא־תַקְטִ֧ירוּ מִמֶּ֛נּוּ אִשֶּׁ֖ה לַֽיהֹוָֽה: יְהֹוָ֣ה צְבָא֣וֹת עִמָּ֑נוּ מִשְׂגָּֽב־לָ֨נוּ אֱלֹהֵ֖י יַֽעֲקֹ֣ב סֶֽלָה׃ יְהֹוָ֥ה צְבָא֑וֹת אַֽשְׁרֵ֥י אָ֝דָ֗ם בֹּטֵ֥חַ בָּֽךְ׃ יְהֹוָ֥ה הוֹשִׁ֑יעָה הַ֝מֶּ֗לֶךְ יַעֲנֵ֥נוּ בְיוֹם־קׇרְאֵֽנוּ: וְעָֽרְבָה֙ לַֽיהֹוָ֔ה מִנְחַ֥ת יְהוּדָ֖ה וִירֽוּשָׁלָ֑‍ִם כִּימֵ֣י עוֹלָ֔ם וּכְשָׁנִ֖ים קַדְמֹנִיֹּֽת:"}, {"kind": "text", "text": "<b>אַבַּיֵּי</b> יפסיק מעט הֲוָה מְסַדֵּר סֵדֶר הַמַּעֲרָכָה מִשְּׁמָא דִגְמָרָא, וְאַלִבָּא דְאַבָּא שָׁאוּל. מַעֲרָכָה גְּדוֹלָה קוֹדֶמֶת לְמַעֲרָכָה שְׁנִיָּה שֶׁל קְטֹרֶת, וּמַעֲרָכָה שְׁנִיָּה שֶׁל קְטֹרֶת קוֹדֶמֶת לְסִדּוּר שְׁנֵי גְזִירֵי עֵצִים, וְסִדּוּר שְׁנֵי גְזִירֵי עֵצִים קוֹדֵם לְדִישּׁוּן מִזְבַּח הַפְּנִימִי, וְדִישּׁוּן מִזְבַּח הַפְּנִימִי קוֹדֵם לַהֲטָבַת חָמֵשׁ נֵרוֹת, וַהֲטָבַת חָמֵשׁ נֵרוֹת קוֹדֶמֶת לְדַם הַתָּמִיד, וְדַם הַתָּמִיד קוֹדֵם לַהֲטָבַת שְׁתֵּי נֵרוֹת, וַהֲטָבַת שְׁתֵּי נֵרוֹת קוֹדֶמֶת לִקְטֹרֶת, וּקְטֹרֶת לְאֵבָרִים, וְאֵבָרִים לְמִנְחָה, וּמִנְחָה לַחֲבִיתִּין, וַחֲבִיתִּין לִנְסָכִין, וּנְסָכִין לְמוּסָפִין, וּמוּסָפִין לְבָזִיכִין, וּבָזִיכִין קוֹדְמִין לְתָמִיד שֶׁל בֵּין הָעַרְבָּיִם, שֶׁנֶּאֱמַר: וְעָרַ֤ךְ עָלֶ֙יהָ֙ הָֽעֹלָ֔ה וְהִקְטִ֥יר עָלֶ֖יהָ חֶלְבֵ֥י הַשְּׁלָמִֽים: עָלֶיהָ הַשְׁלֵם כָּל הַקָּרְבָּנוֹת כֻּלָּם:"}, {"kind": "text", "text": "אָֽנָּֽא בְּכֹֽחַ. גְּדוּלַת יְמִינֶֽךָ. תַּתִּיר צְרוּרָה: (אב\"ג ית\"ץ)"}, {"kind": "text", "text": "קַבֵּל רִנַּת. עַמֶּֽךָ שַׂגְּבֵֽנוּ. טַהֲרֵֽנוּ נוֹרָא: (קר\"ע שט\"ן)"}, {"kind": "text", "text": "נָא גִבּוֹר. דּֽוֹרְשֵֽׁי יִחוּדֶֽךָ. כְּבָבַת שָׁמְרֵם: (נג\"ד יכ\"ש)"}, {"kind": "text", "text": "בָּֽרְכֵֽם טַהֲרֵם. רַחֲמֵי צִדְקָתֶֽךָ. תָּמִיד גָּמְלֵם: (בט\"ר צת\"ג)"}, {"kind": "text", "text": "חֲסִין קָדוֹשׁ. בְּרֹב טֽוּבְךָֽ. נַהֵל עֲדָתֶֽךָ: (חק\"ב טנ\"ע)"}, {"kind": "text", "text": "יָחִיד גֵּאֶה. לְעַמְּךָ פְנֵה. זֽוֹכְרֵֽי קְדֻשָּׁתֶֽךָ: (יג\"ל פז\"ק)"}, {"kind": "text", "text": "שַׁוְעָתֵֽנוּ קַבֵּל. וּשְׁמַע צַעֲקָתֵֽנוּ. יוֹדֵֽעַ תַּעֲלוּמוֹת: (שק\"ו צי\"ת)"}, {"kind": "instruction", "text": "ואומר בלחש"}, {"kind": "text", "text": "בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "<b>רִבּוֹן</b> הָעוֹלָמִים, אַתָּה צִוִיתָנוּ לְהַקְרִיב קָרְבַּן הַתָּמִיד בְּמוֹעֲדוֹ, וְלִהְיוֹת כֹּהֲנִים בַּעֲבוֹדָתָם, וּלְוִיִּם בְּדוּכָנָם, וְיִשְׂרָאֵל בְּמַעֲמָדָם. וְעַתָּה בַּעֲווֹנוֹתֵינוּ חָרַב בֵּית הַמִּקְדָּשׁ וּבֻטַּל הַתָּמִיד, וְאֵין לָנוּ לֹא כֹּהֵן בַּעֲבוֹדָתוֹ וְלֹא לֵוִי בְּדוּכָנוֹ, וְלֹא יִשְׂרָאֵל בְּמַעֲמָדוֹ, וְאַתָּה אָמַרְתָּ: וּֽנְשַׁלְּמָ֥ה פָרִ֖ים שְׂפָתֵֽינוּ:"}, {"kind": "text", "text": "<b>לָכֵן</b> יְהִי רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁיְּהֵא שִׂיחַ שִׂפְתוֹתֵינוּ זֶה חָשׁוּב וּמְקֻבָּל וּמְרוּצֶה לְפָנֶיךָ כְּאִילוּ הִקְרַבְנוּ קָרְבַּן הַתָּמִיד בְּמוֹעֲדוֹ וְעָמַדְנוּ עַל מַעֲמָדוֹ, כְּמוֹ שֶׁנֶּאֱמַר: וּֽנְשַׁלְּמָ֥ה פָרִ֖ים שְׂפָתֵֽינוּ׃ וְנֶאֱמַר: וְשָׁחַ֨ט אֹת֜וֹ עַ֣ל יֶ֧רֶךְ הַמִּזְבֵּ֛חַ צָפֹ֖נָה לִפְנֵ֣י יְהֹוָ֑ה וְזָרְק֡וּ בְּנֵי֩ אַהֲרֹ֨ן הַכֹּהֲנִ֧ים אֶת־דָּמ֛וֹ עַל־הַמִּזְבֵּ֖חַ סָבִֽיב: וְנֶאֱמַר: זֹ֣את הַתּוֹרָ֗ה לָֽעֹלָה֙ לַמִּנְחָ֔ה וְלַֽחַטָּ֖את וְלָאָשָׁ֑ם וְלַ֨מִּלּוּאִ֔ים וּלְזֶ֖בַח הַשְּׁלָמִֽים:"}, {"kind": "text", "text": "<b>אֵיזֶהוּ</b> מְקוֹמָן שֶׁל זְבָחִים, קָדְשִׁי קָדָשִׁים שְׁחִיטָתָן בַּצָּפוֹן, פַּר וְשָׂעִיר שֶׁל יוֹם הַכִּפּוּרִים שְׁחִיטָתָן בַּצָּפון, וְקִבּוּל דָּמָן בִּכְלֵי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן הַזָּיָה עַל בֵּין הַבַּדִּים וְעַל הַפָּרֹכֶת וְעַל מִזְבַּח הַזָּהָב. מַתָּנָה אַחַת מֵהֶן מְעַכֶּבֶת. שִׁיְּירֵי הַדָּם הָיָה שׁוֹפֵךְ עַל יְסוֹד מַעֲרָבִי שֶׁל מִזְבֵּחַ הַחִיצוֹן. אִם לֹא נָתַן, לֹא עִכֵּב:"}, {"kind": "text", "text": "<b>פָּרִים</b> הַנִּשְׂרָפִים וּשְׂעִירִים הַנִּשְׂרָפִים שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלֵי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן הַזָּיָה עַל הַפָּרֹכֶת וְעַל מִזְבַּח הַזָּהָב. מַתָּנָה אַחַת מֵהֶן מְעַכֶּבֶת. שִׁיְרֵי הַדָּם הָיָה שׁוֹפֵךְ עַל יְסוֹד מַעֲרָבִי שֶׁל מִזְבַּח הַחִיצוֹן. אִם לֹא נָתַן, לֹא עִכֵּב. אֵלּוּ וְאֵלּוּ נִשְׂרָפִין בְּבֵית הַדָּשֶׁן:"}, {"kind": "text", "text": "<b>חַטֹּאת</b> הַצִּבּוּר וְהַיָּחִיד. אֵלּוּ הֵן חַטֹּאת הַצִּבּוּר, שְׂעִירֵי רָאשֵׁי חֳדָשִׁים וְשֶׁל מוֹעֲדוֹת, שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלֵי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן אַרְבַּע מַתָּנוֹת עַל אַרְבַּע קְרָנוֹת, כֵּיצַד, עָלָה בַכֶּבֶשׁ וּפָנָה לַסּוֹבֵב, וּבָא לוֹ לְקֶרֶן דְּרוֹמִית מִזְרָחִית, מִזְרָחִית צְפוֹנִית, צְפוֹנִית מַעֲרָבִית, מַעֲרָבִית דְּרוֹמִית. שְׁיָרֵי הַדָּם הָיָה שׁוֹפֵךְ עַל יְסוֹד דְרוֹמִי, וְנֶאֱכָלִין לִפָנִים מִן הַקְּלָעִים לְזִכְרֵי כְהֻנָּה בְּכָל מַאֲכָל לְיוֹם וָלַיְלָה עַד חֲצוֹת:"}, {"kind": "text", "text": "<b>הָעוֹלָה</b>, קֹדֶשׁ קָדָשִׁים, שְׁחִיטָתָהּ בַּצָּפוֹן, וְקִבּוּל דָּמָהּ בִּכְלֵי שָׁרֵת בַּצָּפוֹן, וְדָמָהּ טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וּטְעוּנָה הֶפְשֵׁט וְנִתּוּחַ וְכָלִיל לָאִשִּׁים:"}, {"kind": "text", "text": "<b>זִבְחֵי</b> שַׁלְמֵי צִבּוּר וַאֲשָׁמוֹת. אֵלּוּ הֵן אֲשָׁמוֹת, אָשָׁם גְּזֵלוֹת, אָשָׁם מְעִילוֹת, אָשָׁם שִׁפְחָה חֲרוּפָה, אָשָׁם נָזִיר, אָשָׁם מְצוֹרָע, אָשָׁם תָּלוּי, שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וְנֶאֱכָלִין לְפָנִים מִן הַקְּלָעִים לְזִכְרֵי כְהֻנָּה בְּכָל מַאֲכָל לְיוֹם וָלַיְלָה עַד חֲצוֹת:"}, {"kind": "text", "text": "<b>הַתּוֹדָה</b> וְאֵיל נָזִיר, קָדָשִׁים קַלִּים, שְׁחִיטָתָן בְּכָל מָקוֹם בָּעֲזָרָה, וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וְנֶאֱכָלִין בְּכָל הָעִיר, לְכָל אָדָם, בְּכָל מַאֲכָל, לְיוֹם וָלַיְלָה עַד חֲצוֹת. הַמּוּרָם מֵהֶם כַּיּוֹצֵא בָהֶם, אֶלָּא שֶׁהַמּוּרָם נֶאֱכָל לַכֹּהֲנִים לִנְשֵׁיהֶם וְלִבְנֵיהֶם וּלְעַבְדֵיהֶם:"}, {"kind": "text", "text": "<b>שְׁלָמִים</b>, קָדָשִׁים קַלִּים, שְׁחִיטָתָן בְּכָל מָקוֹם בָּעֲזָרָה, וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וְנֶאֱכָלִין בְּכָל הָעִיר לְכָל אָדָם בְּכָל מַאֲכָל לִשְׁנֵי יָמִים וָלַיְלָה אֶחָד. הַמּוּרָם מֵהֶם כַּיּוֹצֵא בָּהֶם, אֶלָּא שֶׁהַמּוּרָם נֶאֱכָל לַכֹּהֲנִים, לִנְשֵׁיהֶם וְלִבְנֵיהֶם וּלְעַבְדֵיהֶם:"}, {"kind": "text", "text": "<b>הַבְּכוֹר</b> וְהַמַּעֲשֵׂר וְהַפֶּסַח, קָדָשִׁים קַלִּים, שְׁחִיטָתָן בְּכָל מָקוֹם בָּעֲזָרָה, וְדָמָן טָעוּן מַתָּנָה אַחַת, וּבִלְבָד שֶׁיִּתֵּן כְּנֶגֶד הַיְסוֹד. שִׁנָּה בַאֲכִילָתָן, הַבְּכוֹר נֶאֱכָל לַכֹּהֲנִים, וְהַמַּעֲשֵׂר לְכָל אָדָם, וְנֶאֱכָלִין בְּכָל הָעִיר בְּכָל מַאֲכָל לִשְׁנֵי יָמִים וָלַיְלָה אֶחָד. הַפֶּסַח אֵינוֹ נֶאֱכָל אֶלָּא בַלַּיְלָה, וְאֵינוֹ נֶאֱכָל אֶלָּא עַד חֲצוֹת, וְאֵינוֹ נֶאֱכָל אֶלָּא לִמְנוּיָו, וְאֵינוֹ נֶאֱכָל אֶלָּא צָלִי:"}, {"kind": "text", "text": "<b>רִבִּי</b> יִשְׁמָעֵאל אוֹמֵר: בִּשְׁלֹשׁ עֶשְׂרֵה מִדּוֹת הַתּוֹרָה נִדְרֶשֶׁת: מִקַּל וָחוֹמֶר, מִגְּזֵרָה שָׁוֶה, מִבִּנְיַן אָב וְכָתוּב אֶחָד, וּמִבִּנְיַן אָב וּשְׁנֵי כְתוּבִים, מִכְּלָל וּפְרָט, מִפְּרָט וּכְלָל, כְּלָל וּפְרָט וּכְלָל, אֵי אַתָּה דָן אֶלָּא כְּעֵין הַפְּרָט, מִכְּלָל שֶׁהוּא צָרִיךְ לִפְרָט, וּמִפְּרָט שֶׁהוּא צָרִיךְ לִכְלַל, וְכָל דָּבָר שֶׁהָיָה בִכְלָל וְיָצָא מִן הַכְּלָל לְלַמֵּד, לֹא לְלַמֵּד עַל עַצְמוֹ יָצָא, אֶלָּא לְלַמֵּד עַל הַכְּלָל כֻּלּוֹ יָצָא, וְכָל דָּבָר שֶׁהָיָה בִכְלָל, וְיָצָא לִטְעוֹן טָעוּן אַחֵר שֶׁהוּא כְעִנְיָנוֹ, יָצָא לְהָקֵל וְלֹא לְהַחְמִיר, וְכָל דָּבָר שֶׁהָיָה בִּכְלָל, וְיָצָא לִטְעֹן טָעוּן אַחֵר שֶׁלֹּא כְעִנְיָנוֹ, יָצָא לְהָקֵל וּלְהַחְמִיר, וְכָל דָּבָר שֶׁהָיָה בִּכְלָל, וְיָצָא לִדּוֹן בְּדָבָר חָדָשׁ, אֵי אַתָּה יָכוֹל לְהַחֲזִירוֹ לִכְלָלוֹ עַד שֶׁיַּחֲזִירֶנּוּ הַכָּתוּב לִכְלָלוֹ בְפֵירוּשׁ, וְדָבָר הַלָּמֵד מֵעִנְיָנוֹ, וְדָבָר הַלָּמֵד מִסּוֹפוֹ, וְכַן שְׁנֵי כְתוּבִים הַמַּכְחִישִׁים זֶה אֶת זֶה, עַד שֶׁיָּבֹא הַכָּתוּב הַשְּׁלִישִׁי וְיַכְרִיעַ בְּנֵיהֶם:"}, {"kind": "text", "text": "<b>יְהוּדָה</b> בֶּן תֵּימָא אוֹמֵר, הֱוֵי עַז כַּנָּמֵר, וְקַל כַּנֶּשֶׁר, וְרָץ כַּצְּבִי, וְגִבּוֹר כַּאֲרִי לַעֲשׂוֹת רְצוֹן אָבִיךָ שֶׁבַּשָּׁמַיִם. הוּא הָיָה אוֹמֵר, עַז פָּנִים לַגֵּיהִנָּם, וּבוֹשֶׁת פָּנִים לְגַן עֵדֶן:"}, {"kind": "text", "text": "<b>יְהִי </b> רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ, לַעֲשׂוֹת חֻקֵּי רְצוֹנָךְ, וּלְעָבְדָךְ בְּלֵבָב שָׁלֵם:"}, {"kind": "instruction", "text": "ואומרים כאן קדיש \"על ישראל\""}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל־בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "עַל יִשְׂרָאֵל וְעַל רַבָּנָן. וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן. דְּעָסְקִין בְּאוֹרַיְתָא קַדִּשְׁתָּא. דִּי בְאַתְרָא הָדֵין וְדִי בְכָל אֲתַר וַאֲתַר. יְהֵא לָנָא וּלְהוֹן וּלְכוֹן חִנָּא וְחִסְדָּא וְרַחֲמֵי. מִן קֳדָם מָארֵי שְׁמַיָּא וְאַרְעָא וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>יְהֵא</b> שְׁלָמָא רַבָּא מִן שְׁמַיָּא. חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה. וְשֵׁיזָבָא וּרְפוּאָה וּגְאוּלָה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]<br><br><b>עוֹשֶׂה</b> שָׁלוֹם בִּמְרוֹמָיו. הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "header", "text": "הודו"}, {"kind": "text", "text": "<b>הוֹד֤וּ</b> לַֽיהֹוָה֙ קִרְא֣וּ בִשְׁמ֔וֹ הוֹדִ֥יעוּ בָעַמִּ֖ים עֲלִילֹתָֽיו׃ שִׁ֤ירוּ לוֹ֙ זַמְּרוּ־ל֔וֹ שִׂ֖יחוּ בְּכׇל־נִפְלְאֹתָֽיו׃ הִֽתְהַלְלוּ֙ בְּשֵׁ֣ם קׇדְשׁ֔וֹ יִשְׂמַ֕ח לֵ֖ב מְבַקְשֵׁ֥י יְהֹוָֽה׃ דִּרְשׁ֤וּ יְהֹוָה֙ וְעֻזּ֔וֹ בַּקְּשׁ֥וּ פָנָ֖יו תָּמִֽיד׃ זִכְר֗וּ נִפְלְאֹתָיו֙ אֲשֶׁ֣ר עָשָׂ֔ה מֹפְתָ֖יו וּמִשְׁפְּטֵי־פִֽיהוּ׃ זֶ֚רַע יִשְׂרָאֵ֣ל עַבְדּ֔וֹ בְּנֵ֥י יַעֲקֹ֖ב בְּחִירָֽיו: ה֚וּא יְהֹוָ֣ה אֱלֹהֵ֔ינוּ בְּכׇל־הָאָ֖רֶץ מִשְׁפָּטָֽיו׃ זִכְר֤וּ לְעוֹלָם֙ בְּרִית֔וֹ דָּבָ֥ר צִוָּ֖ה לְאֶ֥לֶף דּֽוֹר׃ אֲשֶׁ֤ר כָּרַת֙ אֶת־אַבְרָהָ֔ם וּשְׁבוּעָת֖וֹ לְיִצְחָֽק׃ וַיַּעֲמִידֶ֤הָ לְיַֽעֲקֹב֙ לְחֹ֔ק לְיִשְׂרָאֵ֖ל בְּרִ֥ית עוֹלָֽם׃ לֵאמֹ֗ר לְךָ֙ אֶתֵּ֣ן אֶֽרֶץ־כְּנָ֔עַן חֶ֖בֶל נַחֲלַתְכֶֽם׃ בִּהְיֽוֹתְכֶם֙ מְתֵ֣י מִסְפָּ֔ר כִּמְעַ֖ט וְגָרִ֥ים בָּֽהּ׃ וַיִּֽתְהַלְּכוּ֙ מִגּ֣וֹי אֶל־גּ֔וֹי וּמִמַּמְלָכָ֖ה אֶל־עַ֥ם אַחֵֽר׃ לֹֽא־הִנִּ֤יחַ לְאִישׁ֙ לְעׇשְׁקָ֔ם וַיּ֥וֹכַח עֲלֵיהֶ֖ם מְלָכִֽים׃ אַֽל־תִּגְּעוּ֙ בִּמְשִׁיחָ֔י וּבִנְבִיאַ֖י אַל־תָּרֵֽעוּ׃"}, {"kind": "text", "text": "<b>שִׁ֤ירוּ</b> לַֽיהֹוָה֙ כׇּל־הָאָ֔רֶץ בַּשְּׂר֥וּ מִיּֽוֹם־אֶל־י֖וֹם יְשׁוּעָתֽוֹ׃ סַפְּר֤וּ בַגּוֹיִם֙ אֶת־כְּבוֹד֔וֹ בְּכׇל־הָעַמִּ֖ים נִפְלְאֹתָֽיו׃ כִּי֩ גָד֨וֹל יְהֹוָ֤ה וּמְהֻלָּל֙ מְאֹ֔ד וְנוֹרָ֥א ה֖וּא עַל־כׇּל־אֱלֹהִֽים׃ כִּ֠י כׇּל־אֱלֹהֵ֤י הָֽעַמִּים֙ אֱלִילִ֔ים יפסיק מעט וַיהֹוָ֖ה שָׁמַ֥יִם עָשָֽׂה׃ ה֤וֹד וְהָדָר֙ לְפָנָ֔יו עֹ֥ז וְחֶדְוָ֖ה בִּמְקֹמֽוֹ׃ הָב֤וּ לַֽיהֹוָה֙ מִשְׁפְּח֣וֹת עַמִּ֔ים הָב֥וּ לַיהֹוָ֖ה כָּב֥וֹד וָעֹֽז׃ הָב֥וּ לַֽיהֹוָ֖ה כְּב֣וֹד שְׁמ֑וֹ שְׂא֤וּ מִנְחָה֙ וּבֹ֣אוּ לְפָנָ֔יו הִשְׁתַּחֲו֥וּ לַֽיהֹוָ֖ה בְּהַדְרַת־קֹֽדֶשׁ׃ חִ֤ילוּ מִלְּפָנָיו֙ כׇּל־הָאָ֔רֶץ אַף־תִּכּ֥וֹן תֵּבֵ֖ל בַּל־תִּמּֽוֹט׃ יִשְׂמְח֤וּ הַשָּׁמַ֙יִם֙ וְתָגֵ֣ל הָאָ֔רֶץ וְיֹאמְר֥וּ בַגּוֹיִ֖ם יְהֹוָ֥ה מָלָֽךְ׃ יִרְעַ֤ם הַיָּם֙ וּמְלוֹא֔וֹ יַעֲלֹ֥ץ הַשָּׂדֶ֖ה וְכׇל־אֲשֶׁר־בּֽוֹ׃ אָ֥ז יְרַנְּנ֖וּ עֲצֵ֣י הַיָּ֑עַר מִלִּפְנֵ֣י יְהֹוָ֔ה כִּי־בָ֖א לִשְׁפּ֥וֹט אֶת־הָאָֽרֶץ׃ הוֹד֤וּ לַֽיהֹוָה֙ כִּ֣י ט֔וֹב כִּ֥י לְעוֹלָ֖ם חַסְדּֽוֹ׃ וְאִמְר֕וּ הוֹשִׁיעֵ֙נוּ֙ אֱלֹהֵ֣י יִשְׁעֵ֔נוּ וְקַבְּצֵ֥נוּ וְהַצִּילֵ֖נוּ מִן־הַגּוֹיִ֑ם לְהֹדוֹת֙ לְשֵׁ֣ם קׇדְשֶׁ֔ךָ לְהִשְׁתַּבֵּ֖חַ בִּתְהִלָּתֶֽךָ׃ בָּר֤וּךְ יְהֹוָה֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל מִן־הָעוֹלָ֖ם וְעַ֣ד הָעֹלָ֑ם וַיֹּאמְר֤וּ כׇל־הָעָם֙ אָמֵ֔ן וְהַלֵּ֖ל לַיהֹוָֽה׃"}, {"kind": "text", "text": "<b>רוֹמְמ֡וּ</b> יְהֹ֘וָ֤ה אֱלֹהֵ֗ינוּ וְֽ֭הִשְׁתַּחֲווּ לַהֲדֹ֥ם רַגְלָ֗יו קָד֥וֹשׁ הֽוּא: רוֹמְמ֡וּ יְהֹ֘וָ֤ה אֱלֹהֵ֗ינוּ וְֽ֭הִשְׁתַּחֲווּ לְהַ֣ר קׇדְשׁ֑וֹ כִּי־קָ֝ד֗וֹשׁ יְהֹוָ֥ה אֱלֹהֵֽינוּ: וְה֤וּא רַח֨וּם ׀ יְכַפֵּ֥ר עָוֺן֮ וְֽלֹא־יַֽ֫שְׁחִ֥ית וְ֭הִרְבָּה לְהָשִׁ֣יב אַפּ֑וֹ וְלֹא־יָ֝עִ֗יר כׇּל־חֲמָתֽוֹ׃ אַתָּ֤ה יְהֹוָ֗ה לֹֽא־תִכְלָ֣א רַחֲמֶ֣יךָ מִמֶּ֑נִּי חַסְדְּךָ֥ וַ֝אֲמִתְּךָ֗ תָּמִ֥יד יִצְּרֽוּנִי: זְכֹר־רַחֲמֶ֣יךָ יְ֭הֹוָה וַחֲסָדֶ֑יךָ כִּ֖י מֵעוֹלָ֣ם הֵֽמָּה: תְּנ֥וּ עֹ֗ז לֵאלֹ֫הִ֥ים עַֽל־יִשְׂרָאֵ֥ל גַּאֲוָת֑וֹ וְ֝עֻזּ֗וֹ בַּשְּׁחָקִֽים: נ֤וֹרָ֥א אֱלֹהִ֗ים מִֽמִּקְדָּ֫שֶׁ֥יךָ אֵ֤ל יִשְׂרָאֵ֗ל ה֤וּא נֹתֵ֨ן ׀ עֹ֖ז וְתַעֲצֻמ֥וֹת לָעָ֗ם בָּר֥וּךְ אֱלֹהִֽים:"}, {"kind": "text", "text": "<b>אֵל־נְקָמ֥וֹת</b> יְהֹוָ֑ה אֵ֖ל נְקָמ֣וֹת הוֹפִֽיעַ: הִ֭נָּשֵׂא שֹׁפֵ֣ט הָאָ֑רֶץ הָשֵׁ֥ב גְּ֝מ֗וּל עַל־גֵּאִֽים: לַֽיהֹוָ֥ה הַיְשׁוּעָ֑ה עַֽל־עַמְּךָ֖ בִרְכָתֶ֣ךָ סֶּֽלָה: יְהֹוָ֣ה צְבָא֣וֹת עִמָּ֑נוּ מִשְׂגָּֽב־לָ֨נוּ אֱלֹהֵ֖י יַֽעֲקֹ֣ב סֶֽלָה׃ יְהֹוָ֥ה צְבָא֑וֹת אַֽשְׁרֵ֥י אָ֝דָ֗ם בֹּטֵ֥חַ בָּֽךְ׃ יְהֹוָ֥ה הוֹשִׁ֑יעָה הַ֝מֶּ֗לֶךְ יַעֲנֵ֥נוּ בְיוֹם־קׇרְאֵֽנוּ: הוֹשִׁ֤יעָה ׀ אֶת־עַמֶּ֗ךָ וּבָרֵ֥ךְ אֶת־נַחֲלָתֶ֑ךָ וּֽרְעֵ֥ם וְ֝נַשְּׂאֵ֗ם עַד־הָעוֹלָֽם: נַ֭פְשֵׁנוּ חִכְּתָ֣ה לַֽיהֹוָ֑ה עֶזְרֵ֖נוּ וּמָגִנֵּ֣נוּ הֽוּא: כִּי־ב֭וֹ יִשְׂמַ֣ח לִבֵּ֑נוּ כִּ֤י בְשֵׁ֖ם קׇדְשׁ֣וֹ בָטָֽחְנוּ: יְהִי־חַסְדְּךָ֣ יְהֹוָ֣ה עָלֵ֑ינוּ כַּ֝אֲשֶׁ֗ר יִחַ֥לְנוּ לָֽךְ: הַרְאֵ֣נוּ יְהֹוָ֣ה חַסְדֶּ֑ךָ וְ֝יֶשְׁעֲךָ֗ תִּתֶּן־לָֽנוּ: ק֭וּמָֽה עֶזְרָ֣תָה לָּ֑נוּ וּ֝פְדֵ֗נוּ לְמַ֣עַן חַסְדֶּֽךָ: אָֽנֹכִ֨י ׀ יְהֹ֘וָ֤ה אֱלֹהֶ֗יךָ הַֽ֭מַּעַלְךָ מֵאֶ֣רֶץ מִצְרָ֑יִם הַרְחֶב־פִּ֗֝יךָ וַאֲמַלְאֵֽהוּ: אַשְׁרֵ֣י הָ֭עָם שֶׁכָּ֣כָה לּ֑וֹ אַֽשְׁרֵ֥י הָ֝עָ֗ם שֱׁיְהֹוָ֥ה אֱלֹהָֽיו: וַאֲנִ֤י ׀ בְּחַסְדְּךָ֣ בָטַחְתִּי֮ יָ֤גֵ֥ל לִבִּ֗י בִּֽישׁוּעָ֫תֶ֥ךָ אָשִׁ֥ירָה לַֽיהֹוָ֑ה כִּ֖י גָמַ֣ל עָלָֽי:"}, {"kind": "text", "text": "<b>אֲרוֹמִמְךָ֣</b> יְ֭הֹוָה כִּ֣י דִלִּיתָ֑נִי וְלֹֽא־שִׂמַּ֖חְתָּ אֹיְבַ֣י לִֽי׃ יְהֹוָ֥ה אֱלֹהָ֑י שִׁוַּ֥עְתִּי אֵ֝לֶ֗יךָ וַתִּרְפָּאֵֽנִי׃ יְֽהֹוָ֗ה הֶעֱלִ֣יתָ מִן־שְׁא֣וֹל נַפְשִׁ֑י חִ֝יִּיתַ֗נִי מיורדי [מִיׇּֽרְדִי]־בֽוֹר׃ זַמְּר֣וּ לַיהֹוָ֣ה חֲסִידָ֑יו וְ֝הוֹד֗וּ לְזֵ֣כֶר קׇדְשֽׁוֹ׃ כִּ֤י רֶ֨גַע ׀ בְּאַפּוֹ֮ חַיִּ֢ים בִּרְצ֫וֹנ֥וֹ בָּ֭עֶרֶב יָלִ֥ין בֶּ֗כִי וְלַבֹּ֥קֶר רִנָּֽה׃ וַ֭אֲנִי אָמַ֣רְתִּי בְשַׁלְוִ֑י בַּל־אֶמּ֥וֹט לְעוֹלָֽם׃ יְֽהֹוָ֗ה בִּרְצוֹנְךָ֮ הֶעֱמַ֢דְתָּה לְֽהַרְרִ֫י עֹ֥ז הִסְתַּ֥רְתָּ פָנֶ֗יךָ הָיִ֥יתִי נִבְהָֽל׃ אֵלֶ֣יךָ יְהֹוָ֣ה אֶקְרָ֑א וְאֶל־אֲ֝דֹנָ֗י אֶתְחַנָּֽן׃ מַה־בֶּ֥צַע בְּדָמִי֮ בְּרִדְתִּ֢י אֶ֫ל שָׁ֥חַת הֲיוֹדְךָ֥ עָפָ֑ר הֲיַגִּ֥יד אֲמִתֶּֽךָ׃ שְׁמַע־יְהֹוָ֥ה וְחׇנֵּ֑נִי יְ֝הֹוָ֗ה הֱֽיֵה־עֹזֵ֥ר לִֽי׃ הָפַ֣כְתָּ מִסְפְּדִי֮ לְמָח֢וֹל לִ֥י פִּתַּ֥חְתָּ שַׂקִּ֑י וַֽתְּאַזְּרֵ֥נִי שִׂמְחָֽה׃ לְמַ֤עַן ׀ יְזַמֶּרְךָ֣ כָ֭בוֹד וְלֹ֣א יִדֹּ֑ם יְהֹוָ֥ה אֱ֝לֹהַ֗י לְעוֹלָ֥ם אוֹדֶֽךָּ:"}, {"kind": "instruction", "text": "בעשרת ימי תשובה והושענא רבה אומרים"}, {"kind": "instruction", "text": "יְהֹוָה֙ ה֣וּא הָאֱלֹהִ֔ים יְהֹוָ֖ה ה֥וּא הָאֱלֹהִֽים׃ שתי פעמים"}, {"kind": "instruction", "text": "עומדים ואומרים (בא\"ח ויגש ה\"ב)"}, {"kind": "text", "text": "<b>יְהֹוָה מֶֽלֶךְ, יְהֹוָה מָלָֽךְ יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד:</b> שתי פעמים"}, {"kind": "text", "text": "<b>וְהָיָ֧ה</b> יְהֹוָ֛ה לְמֶ֖לֶךְ עַל־כׇּל־הָאָ֑רֶץ בַּיּ֣וֹם הַה֗וּא יִהְיֶ֧ה יְהֹוָ֛ה אֶחָ֖ד וּשְׁמ֥וֹ אֶחָֽד:"}, {"kind": "text", "text": "<b>הוֹשִׁיעֵ֨נוּ</b> ׀ יְהֹ֘וָ֤ה אֱלֹהֵ֗ינוּ וְקַבְּצֵנוּ֮ מִֽן־הַגּ֫וֹיִ֥ם לְ֭הֹדוֹת לְשֵׁ֣ם קׇדְשֶׁ֑ךָ לְ֝הִשְׁתַּבֵּ֗חַ בִּתְהִלָּתֶֽךָ: בָּ֤רֽוּךְ יְהֹוָ֨ה אֱלֹהֵ֪י יִשְׂרָאֵ֡ל מִן־הָ֤עוֹלָ֨ם ׀ וְעַ֬ד הָעוֹלָ֗ם וְאָמַ֖ר כׇּל־הָעָ֥ם אָמֵ֗ן הַֽלְלוּיָֽהּ: כֹּ֣ל הַ֭נְּשָׁמָה תְּהַלֵּ֥ל יָ֗הּ הַֽלְלוּיָֽהּ:"}, {"kind": "header", "text": "שחרית של שבת"}, {"kind": "text", "text": "<b>לַמְנַצֵּ֗חַ</b> (תהילים י״ט:א׳-ג׳) מִזְמ֥וֹר לְדָוִֽד׃ הַשָּׁמַ֗יִם מְֽסַפְּרִ֥ים כְּבֽוֹד־אֵ֑ל וּֽמַעֲשֵׂ֥ה יָ֝דָ֗יו מַגִּ֥יד הָרָקִֽיעַ׃ י֣וֹם לְ֭יוֹם יַבִּ֣יעַֽ אֹ֑מֶר וְלַ֥יְלָה לְּ֝לַ֗יְלָה יְחַוֶּה־דָּֽעַת׃ אֵֽין־אֹ֭מֶר וְאֵ֣ין דְּבָרִ֑ים בְּ֝לִ֗י נִשְׁמָ֥ע קוֹלָֽם׃ בְּכׇל־הָאָ֨רֶץ ׀ יָ֘צָ֤א קַוָּ֗ם וּבִקְצֵ֣ה תֵ֭בֵל מִלֵּיהֶ֑ם לַ֝שֶּׁ֗מֶשׁ שָֽׂם־אֹ֥הֶל בָּהֶֽם׃ וְה֗וּא כְּ֭חָתָן יֹצֵ֣א מֵחֻפָּת֑וֹ יָשִׂ֥ישׂ כְּ֝גִבּ֗וֹר לָר֥וּץ אֹֽרַח׃ מִקְצֵ֤ה הַשָּׁמַ֨יִם ׀ מֽוֹצָא֗וֹ וּתְקוּפָת֥וֹ עַל־קְצוֹתָ֑ם וְאֵ֥ין נִ֝סְתָּ֗ר מֵחַמָּתֽוֹ׃ תּ֘וֹרַ֤ת יְהֹוָ֣ה תְּ֭מִימָה מְשִׁ֣יבַת נָ֑פֶשׁ עֵד֥וּת יְהֹוָ֥ה נֶ֝אֱמָנָ֗ה מַחְכִּ֥ימַת פֶּֽתִי׃ פִּקּ֘וּדֵ֤י יְהֹוָ֣ה יְ֭שָׁרִים מְשַׂמְּחֵי־לֵ֑ב מִצְוַ֥ת יְהֹוָ֥ה בָּ֝רָ֗ה מְאִירַ֥ת עֵינָֽיִם׃ יִרְאַ֤ת יְהֹוָ֨ה ׀ טְהוֹרָה֮ עוֹמֶ֢דֶת לָ֫עַ֥ד מִֽשְׁפְּטֵי־יְהֹוָ֥ה אֱמֶ֑ת צָֽדְק֥וּ יַחְדָּֽו׃ הַֽנֶּחֱמָדִ֗ים מִ֭זָּהָב וּמִפַּ֣ז רָ֑ב וּמְתוּקִ֥ים מִ֝דְּבַ֗שׁ וְנֹ֣פֶת צוּפִֽים׃ גַּֽם־עַ֭בְדְּךָ נִזְהָ֣ר בָּהֶ֑ם בְּ֝שׇׁמְרָ֗ם עֵ֣קֶב רָֽב׃ שְׁגִיא֥וֹת מִֽי־יָבִ֑ין מִֽנִּסְתָּר֥וֹת נַקֵּֽנִי׃ גַּ֤ם מִזֵּדִ֨ים ׀ חֲשֹׂ֬ךְ עַבְדֶּ֗ךָ אַֽל־יִמְשְׁלוּ־בִ֣י אָ֣ז אֵיתָ֑ם וְ֝נִקֵּ֗יתִי מִפֶּ֥שַֽׁע רָֽב׃ יִ֥הְיֽוּ לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>רַנְּנ֣וּ</b> (תהילים ל״ג:א׳-ב׳) צַ֭דִּיקִים בַּֽיהֹוָ֑ה לַ֝יְשָׁרִ֗ים נָאוָ֥ה תְהִלָּֽה׃ הוֹד֣וּ לַיהֹוָ֣ה בְּכִנּ֑וֹר בְּנֵ֥בֶל עָ֝שׂ֗וֹר זַמְּרוּ־לֽוֹ׃ שִֽׁירוּ־ל֭וֹ שִׁ֣יר חָדָ֑שׁ הֵיטִ֥יבוּ נַ֝גֵּ֗ן בִּתְרוּעָֽה׃ כִּֽי־יָשָׁ֥ר דְּבַר־יְהֹוָ֑ה וְכׇל־מַ֝עֲשֵׂ֗הוּ בֶּאֱמוּנָֽה׃ אֹ֭הֵב צְדָקָ֣ה וּמִשְׁפָּ֑ט חֶ֥סֶד יְ֝הֹוָ֗ה מָלְאָ֥ה הָאָֽרֶץ׃ בִּדְבַ֣ר יְ֭הֹוָה שָׁמַ֣יִם נַעֲשׂ֑וּ וּבְר֥וּחַ פִּ֗֝יו כׇּל־צְבָאָֽם׃ כֹּנֵ֣ס כַּ֭נֵּד מֵ֣י הַיָּ֑ם נֹתֵ֖ן בְּאוֹצָר֣וֹת תְּהוֹמֽוֹת׃ יִֽירְא֣וּ מֵ֭יְהֹוָה כׇּל־הָאָ֑רֶץ מִמֶּ֥נּוּ יָ֝ג֗וּרוּ כׇּל־יֹשְׁבֵ֥י תֵבֵֽל׃ כִּ֤י ה֣וּא אָמַ֣ר וַיֶּ֑הִי הֽוּא־צִ֝וָּ֗ה וַֽיַּעֲמֹֽד׃ יְֽהֹוָ֗ה הֵפִ֥יר עֲצַת־גּוֹיִ֑ם הֵ֝נִ֗יא מַחְשְׁב֥וֹת עַמִּֽים׃ עֲצַ֣ת יְ֭הֹוָה לְעוֹלָ֣ם תַּעֲמֹ֑ד מַחְשְׁב֥וֹת לִ֝בּ֗וֹ לְדֹ֣ר וָדֹֽר׃ אַשְׁרֵ֣י הַ֭גּוֹי אֲשֶׁר־יְהֹוָ֣ה אֱלֹהָ֑יו הָעָ֓ם ׀ בָּחַ֖ר לְנַחֲלָ֣ה לֽוֹ׃ מִ֭שָּׁמַיִם הִבִּ֣יט יְהֹוָ֑ה רָ֝אָ֗ה אֶֽת־כׇּל־בְּנֵ֥י הָאָדָֽם׃ מִֽמְּכוֹן־שִׁבְתּ֥וֹ הִשְׁגִּ֑יחַ אֶ֖ל כׇּל־יֹשְׁבֵ֣י הָאָֽרֶץ׃ הַיֹּצֵ֣ר יַ֣חַד לִבָּ֑ם הַ֝מֵּבִ֗ין אֶל־כׇּל־מַעֲשֵׂיהֶֽם׃ אֵֽין־הַ֭מֶּלֶךְ נוֹשָׁ֣ע בְּרׇב־חָ֑יִל גִּ֝בּ֗וֹר לֹא־יִנָּצֵ֥ל בְּרׇב־כֹּֽחַ׃ שֶׁ֣קֶר הַ֭סּוּס לִתְשׁוּעָ֑ה וּבְרֹ֥ב חֵ֝יל֗וֹ לֹ֣א יְמַלֵּֽט׃ הִנֵּ֤ה עֵ֣ין יְ֭הֹוָה אֶל־יְרֵאָ֑יו לַֽמְיַחֲלִ֥ים לְחַסְדּֽוֹ׃ לְהַצִּ֣יל מִמָּ֣וֶת נַפְשָׁ֑ם וּ֝לְחַיּוֹתָ֗ם בָּרָעָֽב׃ נַ֭פְשֵׁנוּ חִכְּתָ֣ה לַֽיהֹוָ֑ה עֶזְרֵ֖נוּ וּמָגִנֵּ֣נוּ הֽוּא׃ כִּי־ב֭וֹ יִשְׂמַ֣ח לִבֵּ֑נוּ כִּ֤י בְשֵׁ֖ם קׇדְשׁ֣וֹ בָטָֽחְנוּ׃ יְהִי־חַסְדְּךָ֣ יְהֹוָ֣ה עָלֵ֑ינוּ כַּ֝אֲשֶׁ֗ר יִחַ֥לְנוּ לָֽךְ׃"}, {"kind": "text", "text": "<b>לְדָוִ֗ד</b> (תהילים ל״ד:א׳-ב׳) בְּשַׁנּוֹת֣וֹ אֶת־טַ֭עְמוֹ לִפְנֵ֣י אֲבִימֶ֑לֶךְ וַ֝יְגָרְשֵׁ֗הוּ וַיֵּלַֽךְ׃ אֲבָרְכָ֣ה אֶת־יְהֹוָ֣ה בְּכׇל־עֵ֑ת תָּ֝מִ֗יד תְּֽהִלָּת֥וֹ בְּפִֽי׃ בַּ֭יהֹוָה תִּתְהַלֵּ֣ל נַפְשִׁ֑י יִשְׁמְע֖וּ עֲנָוִ֣ים וְיִשְׂמָֽחוּ׃ גַּדְּל֣וּ לַיהֹוָ֣ה אִתִּ֑י וּנְרוֹמְמָ֖ה שְׁמ֣וֹ יַחְדָּֽו׃ דָּרַ֣שְׁתִּי אֶת־יְהֹוָ֣ה וְעָנָ֑נִי וּמִכׇּל־מְ֝גוּרוֹתַ֗י הִצִּילָֽנִי׃ הִבִּ֣יטוּ אֵלָ֣יו וְנָהָ֑רוּ וּ֝פְנֵיהֶ֗ם אַל־יֶחְפָּֽרוּ׃ זֶ֤ה עָנִ֣י קָ֭רָא וַיהֹוָ֣ה שָׁמֵ֑עַ וּמִכׇּל־צָ֝רוֹתָ֗יו הוֹשִׁיעֽוֹ׃ חֹנֶ֤ה מַלְאַךְ־יְהֹוָ֓ה סָ֘בִ֤יב לִירֵאָ֗יו וַֽיְחַלְּצֵֽם׃ טַעֲמ֣וּ וּ֭רְאוּ כִּֽי־ט֣וֹב יְהֹוָ֑ה אַֽשְׁרֵ֥י הַ֝גֶּ֗בֶר יֶחֱסֶה־בּֽוֹ׃ יְר֣אוּ אֶת־יְהֹוָ֣ה קְדֹשָׁ֑יו כִּי־אֵ֥ין מַ֝חְס֗וֹר לִירֵאָֽיו׃ כְּ֭פִירִים רָשׁ֣וּ וְרָעֵ֑בוּ וְדֹרְשֵׁ֥י יְ֝הֹוָ֗ה לֹא־יַחְסְר֥וּ כׇל־טֽוֹב׃ לְֽכוּ־בָ֭נִים שִׁמְעוּ־לִ֑י יִֽרְאַ֥ת יְ֝הֹוָ֗ה אֲלַמֶּדְכֶֽם׃ מִֽי־הָ֭אִישׁ הֶחָפֵ֣ץ חַיִּ֑ים אֹהֵ֥ב יָ֝מִ֗ים לִרְא֥וֹת טֽוֹב׃ נְצֹ֣ר לְשׁוֹנְךָ֣ מֵרָ֑ע וּ֝שְׂפָתֶ֗יךָ מִדַּבֵּ֥ר מִרְמָֽה׃ ס֣וּר מֵ֭רָע וַעֲשֵׂה־ט֑וֹב בַּקֵּ֖שׁ שָׁל֣וֹם וְרׇדְפֵֽהוּ׃ עֵינֵ֣י יְ֭הֹוָה אֶל־צַדִּיקִ֑ים וְ֝אׇזְנָ֗יו אֶל־שַׁוְעָתָֽם׃ פְּנֵ֣י יְ֭הֹוָה בְּעֹ֣שֵׂי רָ֑ע לְהַכְרִ֖ית מֵאֶ֣רֶץ זִכְרָֽם׃ צָ֭עֲקוּ וַיהֹוָ֣ה שָׁמֵ֑עַ וּמִכׇּל־צָ֝רוֹתָ֗ם הִצִּילָֽם׃ קָר֣וֹב יְ֭הֹוָה לְנִשְׁבְּרֵי־לֵ֑ב וְֽאֶת־דַּכְּאֵי־ר֥וּחַ יוֹשִֽׁיעַ׃ רַ֭בּוֹת רָע֣וֹת צַדִּ֑יק וּ֝מִכֻּלָּ֗ם יַצִּילֶ֥נּוּ יְהֹוָֽה׃ שֹׁמֵ֥ר כׇּל־עַצְמוֹתָ֑יו אַחַ֥ת מֵ֝הֵ֗נָּה לֹ֣א נִשְׁבָּֽרָה׃ תְּמוֹתֵ֣ת רָשָׁ֣ע רָעָ֑ה וְשֹׂנְאֵ֖י צַדִּ֣יק יֶאְשָֽׁמוּ׃ פֹּדֶ֣ה יְ֭הֹוָה נֶ֣פֶשׁ עֲבָדָ֑יו וְלֹ֥א יֶ֝אְשְׁמ֗וּ כׇּֽל־הַחֹסִ֥ים בּֽוֹ׃"}, {"kind": "text", "text": "<b>תְּפִלָּה֮</b> (תהילים צ׳:א׳-ב׳) לְמֹשֶׁ֢ה אִֽישׁ־הָאֱלֹ֫הִ֥ים אֲֽדֹנָ֗י מָע֣וֹן אַ֭תָּה הָיִ֥יתָ לָּ֗נוּ בְּדֹ֣ר וָדֹֽר׃ בְּטֶ֤רֶם ׀ הָ֘רִ֤ים יֻלָּ֗דוּ וַתְּח֣וֹלֵֽל אֶ֣רֶץ וְתֵבֵ֑ל וּֽמֵעוֹלָ֥ם עַד־ע֝וֹלָ֗ם אַתָּ֥ה אֵֽל׃ תָּשֵׁ֣ב אֱ֭נוֹשׁ עַד־דַּכָּ֑א וַ֝תֹּ֗אמֶר שׁ֣וּבוּ בְנֵֽי־אָדָֽם׃ כִּ֤י אֶ֪לֶף שָׁנִ֡ים בְּֽעֵינֶ֗יךָ כְּי֣וֹם אֶ֭תְמוֹל כִּ֣י יַֽעֲבֹ֑ר וְאַשְׁמוּרָ֥ה בַלָּֽיְלָה׃ זְ֭רַמְתָּם שֵׁנָ֣ה יִהְי֑וּ בַּ֝בֹּ֗קֶר כֶּחָצִ֥יר יַחֲלֹֽף׃ בַּ֭בֹּקֶר יָצִ֣יץ וְחָלָ֑ף לָ֝עֶ֗רֶב יְמוֹלֵ֥ל וְיָבֵֽשׁ׃ כִּֽי־כָלִ֥ינוּ בְאַפֶּ֑ךָ וּֽבַחֲמָתְךָ֥ נִבְהָֽלְנוּ׃ שַׁתָּ֣ עֲוֺנֹתֵ֣ינוּ לְנֶגְדֶּ֑ךָ עֲ֝לֻמֵ֗נוּ לִמְא֥וֹר פָּנֶֽיךָ׃ כִּ֣י כׇל־יָ֭מֵינוּ פָּנ֣וּ בְעֶבְרָתֶ֑ךָ כִּלִּ֖ינוּ שָׁנֵ֣ינוּ כְמוֹ־הֶֽגֶה׃ יְמֵֽי־שְׁנוֹתֵ֨ינוּ בָהֶ֥ם שִׁבְעִ֪ים שָׁנָ֡ה וְאִ֤ם בִּגְבוּרֹ֨ת ׀ שְׁמ֘וֹנִ֤ים שָׁנָ֗ה וְ֭רׇהְבָּם עָמָ֣ל וָאָ֑וֶן כִּי־גָ֥ז חִ֗֝ישׁ וַנָּעֻֽפָה׃ מִֽי־י֭וֹדֵעַ עֹ֣ז אַפֶּ֑ךָ וּ֝כְיִרְאָתְךָ֗ עֶבְרָתֶֽךָ׃ לִמְנ֣וֹת יָ֭מֵינוּ כֵּ֣ן הוֹדַ֑ע וְ֝נָבִ֗א לְבַ֣ב חׇכְמָֽה׃ שׁוּבָ֣ה יְ֭הֹוָה עַד־מָתָ֑י וְ֝הִנָּחֵ֗ם עַל־עֲבָדֶֽיךָ׃ שַׂבְּעֵ֣נוּ בַבֹּ֣קֶר חַסְדֶּ֑ךָ וּֽנְרַנְּנָ֥ה וְ֝נִשְׂמְחָ֗ה בְּכׇל־יָמֵֽינוּ׃ שַׂ֭מְּחֵנוּ כִּימ֣וֹת עִנִּיתָ֑נוּ שְׁ֝נ֗וֹת רָאִ֥ינוּ רָעָֽה׃ יֵרָאֶ֣ה אֶל־עֲבָדֶ֣יךָ פׇעֳלֶ֑ךָ וַ֝הֲדָרְךָ֗ עַל־בְּנֵיהֶֽם׃ וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ׃"}, {"kind": "text", "text": "<b>יֹ֭שֵׁב</b> (תהילים צ״א:א׳-ב׳) בְּסֵ֣תֶר עֶלְי֑וֹן בְּצֵ֥ל שַׁ֝דַּ֗י יִתְלוֹנָֽן׃ אֹמַ֗ר לַ֭יהֹוָה מַחְסִ֣י וּמְצוּדָתִ֑י אֱ֝לֹהַ֗י אֶבְטַח־בּֽוֹ׃ כִּ֤י ה֣וּא יַ֭צִּילְךָ מִפַּ֥ח יָק֗וּשׁ מִדֶּ֥בֶר הַוּֽוֹת׃ בְּאֶבְרָת֨וֹ ׀ יָ֣סֶךְ לָ֭ךְ וְתַחַת־כְּנָפָ֣יו תֶּחְסֶ֑ה צִנָּ֖ה וְסֹחֵרָ֣ה אֲמִתּֽוֹ׃ לֹֽא־תִ֭ירָא מִפַּ֣חַד לָ֑יְלָה מֵ֝חֵ֗ץ יָע֥וּף יוֹמָֽם׃ מִ֭דֶּבֶר בָּאֹ֣פֶל יַהֲלֹ֑ךְ מִ֝קֶּ֗טֶב יָשׁ֥וּד צׇהֳרָֽיִם׃ יִפֹּ֤ל מִצִּדְּךָ֨ ׀ אֶ֗לֶף וּרְבָבָ֥ה מִימִינֶ֑ךָ אֵ֝לֶ֗יךָ לֹ֣א יִגָּֽשׁ׃ רַ֭ק בְּעֵינֶ֣יךָ תַבִּ֑יט וְשִׁלֻּמַ֖ת רְשָׁעִ֣ים תִּרְאֶֽה׃ כִּֽי־אַתָּ֣ה יְהֹוָ֣ה מַחְסִ֑י עֶ֝לְי֗וֹן שַׂ֣מְתָּ מְעוֹנֶֽךָ׃ לֹא־תְאֻנֶּ֣ה אֵלֶ֣יךָ רָעָ֑ה וְ֝נֶ֗גַע לֹא־יִקְרַ֥ב בְּאׇהֳלֶֽךָ׃ כִּ֣י מַ֭לְאָכָיו יְצַוֶּה־לָּ֑ךְ לִ֝שְׁמׇרְךָ֗ בְּכׇל־דְּרָכֶֽיךָ׃ עַל־כַּפַּ֥יִם יִשָּׂא֑וּנְךָ פֶּן־תִּגֹּ֖ף בָּאֶ֣בֶן רַגְלֶֽךָ׃ עַל־שַׁ֣חַל וָפֶ֣תֶן תִּדְרֹ֑ךְ תִּרְמֹ֖ס כְּפִ֣יר וְתַנִּֽין׃ כִּ֤י בִ֣י חָ֭שַׁק וַאֲפַלְּטֵ֑הוּ אֲ֝שַׂגְּבֵ֗הוּ כִּֽי־יָדַ֥ע שְׁמִֽי׃ יִקְרָאֵ֨נִי ׀ וְֽאֶעֱנֵ֗הוּ עִמּֽוֹ־אָנֹכִ֥י בְצָרָ֑ה אֲ֝חַלְּצֵ֗הוּ וַאֲכַבְּדֵֽהוּ׃ אֹ֣רֶךְ יָ֭מִים אַשְׂבִּיעֵ֑הוּ וְ֝אַרְאֵ֗הוּ בִּישׁוּעָתִֽי׃"}, {"kind": "instruction", "text": "ביו\"ט מוסיפים המזמור השייך לאותו חג שנמצא בתפילה לשלש רגלים"}, {"kind": "text", "text": "<b>מִזְמ֡וֹר</b> (תהילים צ״ח:א׳) שִׁ֤ירוּ לַיהֹוָ֨ה ׀ שִׁ֣יר חָ֭דָשׁ כִּֽי־נִפְלָא֣וֹת עָשָׂ֑ה הוֹשִׁיעָה־לּ֥וֹ יְ֝מִינ֗וֹ וּזְר֥וֹעַ קׇדְשֽׁוֹ׃ הוֹדִ֣יעַ יְ֭הֹוָה יְשׁוּעָת֑וֹ לְעֵינֵ֥י הַ֝גּוֹיִ֗ם גִּלָּ֥ה צִדְקָתֽוֹ׃ זָ֘כַ֤ר חַסְדּ֨וֹ ׀ וֶ֥אֱֽמוּנָתוֹ֮ לְבֵ֢ית יִשְׂרָ֫אֵ֥ל רָא֥וּ כׇל־אַפְסֵי־אָ֑רֶץ אֵ֗֝ת יְשׁוּעַ֥ת אֱלֹהֵֽינוּ׃ הָרִ֣יעוּ לַ֭יהֹוָה כׇּל־הָאָ֑רֶץ פִּצְח֖וּ וְרַנְּנ֣וּ וְזַמֵּֽרוּ׃ זַמְּר֣וּ לַיהֹוָ֣ה בְּכִנּ֑וֹר בְּ֝כִנּ֗וֹר וְק֣וֹל זִמְרָֽה׃ בַּ֭חֲצֹ֣צְרוֹת וְק֣וֹל שׁוֹפָ֑ר הָ֝רִ֗יעוּ לִפְנֵ֤י ׀ הַמֶּ֬לֶךְ יְהֹוָֽה׃ יִרְעַ֣ם הַ֭יָּם וּמְלֹא֑וֹ תֵּ֝בֵ֗ל וְיֹ֣שְׁבֵי בָֽהּ׃ נְהָר֥וֹת יִמְחֲאוּ־כָ֑ף יַ֗֝חַד הָרִ֥ים יְרַנֵּֽנוּ׃ לִ֥פְֽנֵי יְהֹוָ֗ה כִּ֥י בָא֮ לִשְׁפֹּ֢ט הָ֫אָ֥רֶץ יִשְׁפֹּֽט־תֵּבֵ֥ל בְּצֶ֑דֶק וְ֝עַמִּ֗ים בְּמֵישָׁרִֽים׃"}, {"kind": "text", "text": "<b>שִׁ֗יר</b> (תהילים קכ״א:א׳-ב׳) לַֽמַּ֫עֲל֥וֹת אֶשָּׂ֣א עֵ֭ינַי אֶל־הֶהָרִ֑ים מֵ֝אַ֗יִן יָבֹ֥א עֶזְרִֽי׃ עֶ֭זְרִי מֵעִ֣ם יְהֹוָ֑ה עֹ֝שֵׂ֗ה שָׁמַ֥יִם וָאָֽרֶץ׃ אַל־יִתֵּ֣ן לַמּ֣וֹט רַגְלֶ֑ךָ אַל־יָ֝נ֗וּם שֹׁמְרֶֽךָ׃ הִנֵּ֣ה לֹֽא־יָ֭נוּם וְלֹ֣א יִישָׁ֑ן שׁ֝וֹמֵ֗ר יִשְׂרָאֵֽל׃ יְהֹוָ֥ה שֹׁמְרֶ֑ךָ יְהֹוָ֥ה צִ֝לְּךָ֗ עַל־יַ֥ד יְמִינֶֽךָ׃ יוֹמָ֗ם הַשֶּׁ֥מֶשׁ לֹֽא־יַכֶּ֗כָּה וְיָרֵ֥חַ בַּלָּֽיְלָה׃ יְֽהֹוָ֗ה יִשְׁמׇרְךָ֥ מִכָּל־רָ֑ע יִ֝שְׁמֹ֗ר אֶת־נַפְשֶֽׁךָ׃ יְֽהֹוָ֗ה יִשְׁמׇר־צֵאתְךָ֥ וּבוֹאֶ֑ךָ מֵ֝עַתָּ֗ה וְעַד־עוֹלָֽם׃"}, {"kind": "text", "text": "<b>שִׁ֥יר</b> (תהילים קכ״ב:א׳-ב׳) הַֽמַּעֲל֗וֹת לְדָ֫וִ֥ד שָׂ֭מַחְתִּי בְּאֹמְרִ֣ים לִ֑י בֵּ֖ית יְהֹוָ֣ה נֵלֵֽךְ׃ עֹ֭מְדוֹת הָי֣וּ רַגְלֵ֑ינוּ בִּ֝שְׁעָרַ֗יִךְ יְרוּשָׁלָֽ‍ִם׃ יְרוּשָׁלַ֥‍ִם הַבְּנוּיָ֑ה כְּ֝עִ֗יר שֶׁחֻבְּרָה־לָּ֥הּ יַחְדָּֽו׃ שֶׁשָּׁ֨ם עָל֪וּ שְׁבָטִ֡ים שִׁבְטֵי־יָ֭הּ עֵד֣וּת לְיִשְׂרָאֵ֑ל לְ֝הֹד֗וֹת לְשֵׁ֣ם יְהֹוָֽה׃ כִּ֤י שָׁ֨מָּה ׀ יָשְׁב֣וּ כִסְא֣וֹת לְמִשְׁפָּ֑ט כִּ֝סְא֗וֹת לְבֵ֣ית דָּוִֽד׃ שַׁ֭אֲלוּ שְׁל֣וֹם יְרוּשָׁלָ֑‍ִם יִ֝שְׁלָ֗יוּ אֹהֲבָֽיִךְ׃ יְהִי־שָׁל֥וֹם בְּחֵילֵ֑ךְ שַׁ֝לְוָ֗ה בְּאַרְמְנוֹתָֽיִךְ׃ לְ֭מַעַן אַחַ֣י וְרֵעָ֑י אֲדַבְּרָה־נָּ֖א שָׁל֣וֹם בָּֽךְ׃ לְ֭מַעַן בֵּית־יְהֹוָ֣ה אֱלֹהֵ֑ינוּ אֲבַקְשָׁ֖ה ט֣וֹב לָֽךְ׃"}, {"kind": "text", "text": "<b>שִׁ֗יר</b> (תהילים קכ״ג:א׳-ב׳) הַֽמַּ֫עֲל֥וֹת אֵ֭לֶיךָ נָשָׂ֣אתִי אֶת־עֵינַ֑י הַ֝יֹּשְׁבִ֗י בַּשָּׁמָֽיִם׃ הִנֵּ֨ה כְעֵינֵ֪י עֲבָדִ֡ים אֶל־יַ֤ד אֲֽדוֹנֵיהֶ֗ם כְּעֵינֵ֣י שִׁפְחָה֮ אֶל־יַ֢ד גְּבִ֫רְתָּ֥הּ כֵּ֣ן עֵ֭ינֵינוּ אֶל־יְהֹוָ֣ה אֱלֹהֵ֑ינוּ עַ֗֝ד שֶׁיְּחׇנֵּֽנוּ׃ חׇנֵּ֣נוּ יְהֹוָ֣ה חׇנֵּ֑נוּ כִּי־רַ֗֝ב שָׂבַ֥עְנוּ בֽוּז׃ רַבַּת֮ שָֽׂבְעָה־לָּ֢הּ נַ֫פְשֵׁ֥נוּ הַלַּ֥עַג הַשַּֽׁאֲנַנִּ֑ים הַ֝בּ֗וּז לגאיונים [לִגְאֵ֥י יוֹנִֽים]׃"}, {"kind": "text", "text": "<b>שִׁ֥יר </b> (תהילים קכ״ד:א׳-ב׳) הַֽמַּעֲל֗וֹת לְדָ֫וִ֥ד לוּלֵ֣י יְ֭הֹוָה שֶׁהָ֣יָה לָ֑נוּ יֹאמַר־נָ֗֝א יִשְׂרָאֵֽל׃ לוּלֵ֣י יְ֭הֹוָה שֶׁהָ֣יָה לָ֑נוּ בְּק֖וּם עָלֵ֣ינוּ אָדָֽם׃ אֲ֭זַי חַיִּ֣ים בְּלָע֑וּנוּ בַּחֲר֖וֹת אַפָּ֣ם בָּֽנוּ׃ אֲ֭זַי הַמַּ֣יִם שְׁטָפ֑וּנוּ נַ֗֝חְלָה עָבַ֥ר עַל־נַפְשֵֽׁנוּ׃ אֲ֭זַי עָבַ֣ר עַל־נַפְשֵׁ֑נוּ הַ֝מַּ֗יִם הַזֵּידוֹנִֽים׃ בָּר֥וּךְ יְהֹוָ֑ה שֶׁלֹּ֥א נְתָנָ֥נוּ טֶ֗֝רֶף לְשִׁנֵּיהֶֽם׃ נַפְשֵׁ֗נוּ כְּצִפּ֥וֹר נִמְלְטָה֮ מִפַּ֢ח י֫וֹקְשִׁ֥ים הַפַּ֥ח נִשְׁבָּ֗ר וַאֲנַ֥חְנוּ נִמְלָֽטְנוּ׃ עֶ֭זְרֵנוּ בְּשֵׁ֣ם יְהֹוָ֑ה עֹ֝שֵׂ֗ה שָׁמַ֥יִם וָאָֽרֶץ׃"}, {"kind": "text", "text": "<b>הַ֥לְלוּיָ֨הּ</b> ׀ (תהילים קל״ה:א׳-ב׳) הַֽ֭לְלוּ אֶת־שֵׁ֣ם יְהֹוָ֑ה הַֽ֝לְל֗וּ עַבְדֵ֥י יְהֹוָֽה׃ שֶׁ֣֭עֹמְדִים בְּבֵ֣ית יְהֹוָ֑ה בְּ֝חַצְר֗וֹת בֵּ֣ית אֱלֹהֵֽינוּ׃ הַֽלְלוּיָ֭הּ כִּֽי־ט֣וֹב יְהֹוָ֑ה זַמְּר֥וּ לִ֝שְׁמ֗וֹ כִּ֣י נָעִֽים׃ כִּֽי־יַעֲקֹ֗ב בָּחַ֣ר ל֣וֹ יָ֑הּ יִ֝שְׂרָאֵ֗ל לִסְגֻלָּתֽוֹ׃ כִּ֤י אֲנִ֣י יָ֭דַעְתִּי כִּֽי־גָד֣וֹל יְהֹוָ֑ה וַ֝אֲדֹנֵ֗ינוּ מִכׇּל־אֱלֹהִֽים׃ כֹּ֤ל אֲשֶׁר־חָפֵ֥ץ יְהֹוָ֗ה עָ֫שָׂ֥ה בַּשָּׁמַ֥יִם וּבָאָ֑רֶץ בַּ֝יַּמִּ֗ים וְכׇל־תְּהֹמֽוֹת׃ מַעֲלֶ֣ה נְשִׂאִים֮ מִקְצֵ֢ה הָ֫אָ֥רֶץ בְּרָקִ֣ים לַמָּטָ֣ר עָשָׂ֑ה מֽוֹצֵא־ר֗֝וּחַ מֵאֽוֹצְרוֹתָֽיו׃ שֶׁ֭הִכָּה בְּכוֹרֵ֣י מִצְרָ֑יִם מֵ֝אָדָ֗ם עַד־בְּהֵמָֽה׃ שָׁלַ֤ח ׀ אוֹתֹ֣ת וּ֭מֹפְתִים בְּתוֹכֵ֣כִי מִצְרָ֑יִם בְּ֝פַרְעֹ֗ה וּבְכׇל־עֲבָדָֽיו׃ שֶׁ֭הִכָּה גּוֹיִ֣ם רַבִּ֑ים וְ֝הָרַ֗ג מְלָכִ֥ים עֲצוּמִֽים׃ לְסִיח֤וֹן ׀ מֶ֤לֶךְ הָאֱמֹרִ֗י וּ֭לְעוֹג מֶ֣לֶךְ הַבָּשָׁ֑ן וּ֝לְכֹ֗ל מַמְלְכ֥וֹת כְּנָֽעַן׃ וְנָתַ֣ן אַרְצָ֣ם נַחֲלָ֑ה נַ֝חֲלָ֗ה לְיִשְׂרָאֵ֥ל עַמּֽוֹ׃ יְ֭הֹוָה שִׁמְךָ֣ לְעוֹלָ֑ם יְ֝הֹוָ֗ה זִכְרְךָ֥ לְדֹר־וָדֹֽר׃ כִּֽי־יָדִ֣ין יְהֹוָ֣ה עַמּ֑וֹ וְעַל־עֲ֝בָדָ֗יו יִתְנֶחָֽם׃ עֲצַבֵּ֣י הַ֭גּוֹיִם כֶּ֣סֶף וְזָהָ֑ב מַ֝עֲשֵׂ֗ה יְדֵ֣י אָדָֽם׃ פֶּֽה־לָ֭הֶם וְלֹ֣א יְדַבֵּ֑רוּ עֵינַ֥יִם לָ֝הֶ֗ם וְלֹ֣א יִרְאֽוּ׃ אׇזְנַ֣יִם לָ֭הֶם וְלֹ֣א יַאֲזִ֑ינוּ אַ֗֝ף אֵין־יֶשׁ־ר֥וּחַ בְּפִיהֶֽם׃ כְּ֭מוֹהֶם יִהְי֣וּ עֹשֵׂיהֶ֑ם כֹּ֖ל אֲשֶׁר־בֹּטֵ֣חַ בָּהֶֽם׃ בֵּ֣ית יִ֭שְׂרָאֵל בָּרְכ֣וּ אֶת־יְהֹוָ֑ה בֵּ֥ית אַ֝הֲרֹ֗ן בָּרְכ֥וּ אֶת־יְהֹוָֽה׃ בֵּ֣ית הַ֭לֵּוִי בָּרְכ֣וּ אֶת־יְהֹוָ֑ה יִֽרְאֵ֥י יְ֝הֹוָ֗ה בָּרְכ֥וּ אֶת־יְהֹוָֽה׃ בָּ֘ר֤וּךְ יְהֹוָ֨ה ׀ מִצִּיּ֗וֹן שֹׁ֘כֵ֤ן יְֽרוּשָׁלָ֗‍ִם הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>הוֹד֣וּ</b> (תהילים קל״ו:א׳) לַיהֹוָ֣ה כִּי־ט֑וֹב כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "ה֭וֹדוּ לֵאלֹהֵ֣י הָאֱלֹהִ֑ים כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "ה֭וֹדוּ לַאֲדֹנֵ֣י הָאֲדֹנִ֑ים כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "לְעֹ֘שֵׂ֤ה נִפְלָא֣וֹת גְּדֹל֣וֹת לְבַדּ֑וֹ כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "לְעֹשֵׂ֣ה הַ֭שָּׁמַיִם בִּתְבוּנָ֑ה כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "לְרֹקַ֣ע הָ֭אָרֶץ עַל־הַמָּ֑יִם כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "לְ֭עֹשֵׂה אוֹרִ֣ים גְּדֹלִ֑ים כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "אֶת־הַ֭שֶּׁמֶשׁ לְמֶמְשֶׁ֣לֶת בַּיּ֑וֹם כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "אֶת־הַיָּרֵ֣חַ וְ֭כוֹכָבִים לְמֶמְשְׁל֣וֹת בַּלָּ֑יְלָה כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "לְמַכֵּ֣ה מִ֭צְרַיִם בִּבְכוֹרֵיהֶ֑ם כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "וַיּוֹצֵ֣א יִ֭שְׂרָאֵל מִתּוֹכָ֑ם כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "בְּיָ֣ד חֲ֭זָקָה וּבִזְר֣וֹעַ נְטוּיָ֑ה כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "לְגֹזֵ֣ר יַם־ס֭וּף לִגְזָרִ֑ים כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "וְהֶעֱבִ֣יר יִשְׂרָאֵ֣ל בְּתוֹכ֑וֹ כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "וְנִ֘עֵ֤ר פַּרְעֹ֣ה וְחֵיל֣וֹ בְיַם־ס֑וּף כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "לְמוֹלִ֣יךְ עַ֭מּוֹ בַּמִּדְבָּ֑ר כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "לְ֭מַכֵּה מְלָכִ֣ים גְּדֹלִ֑ים כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "וַֽ֭יַּהֲרֹג מְלָכִ֣ים אַדִּירִ֑ים כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "לְ֭סִיחוֹן מֶ֣לֶךְ הָאֱמֹרִ֑י כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "וּ֭לְעוֹג מֶ֣לֶךְ הַבָּשָׁ֑ן כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "וְנָתַ֣ן אַרְצָ֣ם לְנַחֲלָ֑ה כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "נַ֭חֲלָה לְיִשְׂרָאֵ֣ל עַבְדּ֑וֹ כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "שֶׁ֭בְּשִׁפְלֵנוּ זָ֣כַר לָ֑נוּ כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "וַיִּפְרְקֵ֥נוּ מִצָּרֵ֑ינוּ כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "נֹתֵ֣ן לֶ֭חֶם לְכׇל־בָּשָׂ֑ר כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "ה֭וֹדוּ לְאֵ֣ל הַשָּׁמָ֑יִם כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "header", "text": "פסוקי דזמרה"}, {"kind": "text", "text": "יש אומרים <br>כִּ֥י גָ֘בַ֤ר עָלֵ֨ינוּ ׀ חַסְדּ֗וֹ וֶאֱמֶת־יְהֹוָ֥ה לְעוֹלָ֗ם הַֽלְלוּיָֽהּ׃ בָּרוּךְ הַמַּנְחִיל מְנוּחָה לְעַמּוֹ יִשְׂרָאֵל בְּיוֹם שַׁבָּת קֹֽדֶשׁ: <br> בָּרוּךְ שֶׁאָמַר וְהָיָה הָעוֹלָם. בָּרוּךְ הוּא. בָּרוּךְ אוֹמֵר וְעוֹשֶׂה. בָּרוּךְ גּוֹזֵר וּמְקַיֵּם: בָּרוּךְ עוֹשֶׂה בְרֵאשִׁית, בָּרוּךְ מְרַחֵם עַל הָאָרֶץ. בָּרוּךְ מְרַחֵם עַל הַבְּרִיּוֹת בָּרוּךְ מְשַׁלֵּם שָׂכָר טוֹב לִירֵאָיו. בָּרוּךְ חַי לָעַד וְקַיָּם לָנֶצַח בָּרוּךְ פּוֹדֶה וּמַצִּיל בָּרוּךְ שְׁמוֹ. בָּרוּךְ אַתָּה יְהֹוָה אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם הָאֵל אָב הָרַחֲמָן הַמְהֻלָּל בְּפֶה עַמּוֹ מְשֻׁבָּח וּמְפֹאָר בִּלְשׁוֹן חֲסִידָיו וַעֲבָדָיו וּבְשִׁירֵי דָּוִד עַבְדָּךָ נְהַלְלָךְ יְהֹוָה אֱלֹהֵֽינוּ בִּשְׁבָחות וּבִזְמִירוֹת וּנְגַדְּלָךְ וּנְשַׁבְּחָךְ וּנְפָאֲרָךְ וְנַמְלִיכָךְ וְנַזְכִּיר שִׁמְךָ מַלְכֵּנוּ, אֱלֹהֵינוּ, יָחִיד, חַי הָעוֹלָמִים, מֶלֶךְ מְשֻׁבָּח וּמְפֹאָר עֲדֵי עַד שְׁמוֹ הַגָּדוֹל: בָּרוּךְ אַתָּה יְהֹוָה מֶלֶךְ מְהֻלָּל בַּתִּשְׁבָּחוֹת:<br>אם סיים האדם ברוך שאמר קודם שסיים החזן, יזדרז לומר תיכף מזמור, ויענה אמן על ברכת החזן (בא\"ח ויגש ה\"ח)"}, {"kind": "text", "text": "<b>מִזְמ֥וֹר</b> (תהילים צ״ב:א׳-ג׳) שִׁ֗יר לְי֣וֹם הַשַּׁבָּֽת׃ ט֗וֹב לְהֹד֥וֹת לַיהֹוָ֑ה וּלְזַמֵּ֖ר לְשִׁמְךָ֣ עֶלְיֽוֹן׃ לְהַגִּ֣יד בַּבֹּ֣קֶר חַסְדֶּ֑ךָ וֶ֝אֱמ֥וּנָתְךָ֗ בַּלֵּילֽוֹת׃ עֲֽלֵי־עָ֭שׂוֹר וַעֲלֵי־נָ֑בֶל עֲלֵ֖י הִגָּי֣וֹן בְּכִנּֽוֹר׃ כִּ֤י שִׂמַּחְתַּ֣נִי יְהֹוָ֣ה בְּפׇעֳלֶ֑ךָ בְּֽמַעֲשֵׂ֖י יָדֶ֣יךָ אֲרַנֵּֽן׃ מַה־גָּדְל֣וּ מַעֲשֶׂ֣יךָ יְהֹוָ֑ה מְ֝אֹ֗ד עָמְק֥וּ מַחְשְׁבֹתֶֽיךָ׃ אִֽישׁ־בַּ֭עַר לֹ֣א יֵדָ֑ע וּ֝כְסִ֗יל לֹא־יָבִ֥ין אֶת־זֹֽאת׃ בִּפְרֹ֤חַ רְשָׁעִ֨ים ׀ כְּמ֥וֹ עֵ֗שֶׂב וַ֭יָּצִיצוּ כׇּל־פֹּ֣עֲלֵי אָ֑וֶן לְהִשָּׁמְדָ֥ם עֲדֵי־עַֽד׃ וְאַתָּ֥ה מָר֗וֹם לְעֹלָ֥ם יְהֹוָֽה׃ כִּ֤י הִנֵּ֪ה אֹיְבֶ֡יךָ ׀ יְֽהֹוָ֗ה כִּֽי־הִנֵּ֣ה אֹיְבֶ֣יךָ יֹאבֵ֑דוּ יִ֝תְפָּרְד֗וּ כׇּל־פֹּ֥עֲלֵי אָֽוֶן׃ וַתָּ֣רֶם כִּרְאֵ֣ים קַרְנִ֑י בַּ֝לֹּתִ֗י בְּשֶׁ֣מֶן רַעֲנָֽן׃ וַתַּבֵּ֥ט עֵינִ֗י בְּשׁ֫וּרָ֥י בַּקָּמִ֖ים עָלַ֥י מְרֵעִ֗ים תִּשְׁמַ֥עְנָה אׇזְנָֽי׃ צַ֭דִּיק כַּתָּמָ֣ר יִפְרָ֑ח כְּאֶ֖רֶז בַּלְּבָנ֣וֹן יִשְׂגֶּֽה׃ שְׁ֭תוּלִים בְּבֵ֣ית יְהֹוָ֑ה בְּחַצְר֖וֹת אֱלֹהֵ֣ינוּ יַפְרִֽיחוּ׃ ע֭וֹד יְנוּב֣וּן בְּשֵׂיבָ֑ה דְּשֵׁנִ֖ים וְֽרַעֲנַנִּ֣ים יִהְיֽוּ׃ לְ֭הַגִּיד כִּֽי־יָשָׁ֣ר יְהֹוָ֑ה צ֝וּרִ֗י וְֽלֹא־[עַוְלָ֥תָה] עלתה בּֽוֹ׃"}, {"kind": "text", "text": "<b>יְהֹוָ֣ה</b> (תהילים צ״ג:א׳-ב׳) מָלָךְ֮ גֵּא֢וּת לָ֫בֵ֥שׁ לָבֵ֣שׁ יְ֭הֹוָה עֹ֣ז הִתְאַזָּ֑ר אַף־תִּכּ֥וֹן תֵּ֝בֵ֗ל בַּל־תִּמּֽוֹט׃ נָכ֣וֹן כִּסְאֲךָ֣ מֵאָ֑ז מֵעוֹלָ֣ם אָֽתָּה׃ נָשְׂא֤וּ נְהָר֨וֹת ׀ יְֽהֹוָ֗ה נָשְׂא֣וּ נְהָר֣וֹת קוֹלָ֑ם יִשְׂא֖וּ נְהָר֣וֹת דׇּכְיָֽם׃ מִקֹּל֨וֹת ׀ מַ֤יִם רַבִּ֗ים אַדִּירִ֣ים מִשְׁבְּרֵי־יָ֑ם אַדִּ֖יר בַּמָּר֣וֹם יְהֹוָֽה׃ עֵֽדֹתֶ֨יךָ ׀ נֶאֶמְנ֬וּ מְאֹ֗ד לְבֵיתְךָ֥ נַאֲוָה־קֹ֑דֶשׁ יְ֝הֹוָ֗ה לְאֹ֣רֶךְ יָמִֽים׃"}, {"kind": "text", "text": "ש <b>יְהִ֤י כְב֣וֹד</b> יְהֹוָ֣ה לְעוֹלָ֑ם יִשְׂמַ֖ח יְהֹוָ֣ה בְּמַעֲשָֽׂיו: ד יְהִ֤י שֵׁ֣ם יְהֹוָ֣ה מְבֹרָ֑ךְ מֵ֝עַתָּ֗ה וְעַד־עוֹלָֽם: י מִמִּזְרַח־שֶׁ֥מֶשׁ עַד־מְבוֹא֑וֹ מְ֝הֻלָּ֗ל שֵׁ֣ם יְהֹוָֽה: ש רָ֖ם עַל־כָּל־גּוֹיִ֥ם ׀ יְהֹוָ֑ה עַ֖ל הַשָּׁמַ֣יִם כְּבוֹדֽוֹ: י יְ֭הֹוָה שִׁמְךָ֣ לְעוֹלָ֑ם יְ֝הֹוָ֗ה זִכְרְךָ֥ לְדֹר־וָדֹֽר: ד יְֽהֹוָ֗ה בַּ֭שָּׁמַיִם הֵכִ֣ין כִּסְא֑וֹ וּ֝מַלְכוּת֗וֹ בַּכֹּ֥ל מָשָֽׁלָה: ד יִשְׂמְח֤וּ הַשָּׁמַ֙יִם֙ וְתָגֵ֣ל הָאָ֔רֶץ וְיֹאמְר֥וּ בַגּוֹיִ֖ם יְהֹוָ֥ה מָלָֽךְ: ש יְהֹוָה מֶֽלֶךְ, יְהֹוָה מָלָֽךְ יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד: י יְהֹוָ֣ה מֶ֭לֶךְ עוֹלָ֣ם וָעֶ֑ד אָבְד֥וּ ג֝וֹיִ֗ם מֵאַרְצֽוֹ: ד יְֽהֹוָ֗ה הֵפִ֥יר עֲצַת־גּוֹיִ֑ם הֵ֝נִ֗יא מַחְשְׁב֥וֹת עַמִּֽים: י רַבּ֣וֹת מַחֲשָׁב֣וֹת בְּלֶב־אִ֑ישׁ וַעֲצַ֥ת יְ֝הֹוָ֗ה הִ֣יא תָקֽוּם: ש עֲצַ֣ת יְ֭הֹוָה לְעוֹלָ֣ם תַּעֲמֹ֑ד מַחְשְׁב֥וֹת לִ֝בּ֗וֹ לְדֹ֣ר וָדֹֽר: י כִּ֤י ה֣וּא אָמַ֣ר וַיֶּ֑הִי הֽוּא־צִ֝וָּ֗ה וַֽיַּעֲמֹֽד: ש כִּי־בָחַ֣ר יְהֹוָ֣ה בְּצִיּ֑וֹן אִ֝וָּ֗הּ לְמוֹשָׁ֥ב לֽוֹ: ד כִּֽי־יַעֲקֹ֗ב בָּחַ֣ר ל֣וֹ יָ֑הּ יִ֝שְׂרָאֵ֗ל לִסְגֻלָּתֽוֹ: י כִּ֤י ׀ לֹא־יִטֹּ֣שׁ יְהֹוָ֣ה עַמּ֑וֹ וְ֝נַחֲלָת֗וֹ לֹ֣א יַעֲזֹֽב: ד וְה֤וּא רַח֨וּם ׀ יְכַפֵּ֥ר עָוֺן֮ וְֽלֹא־יַֽ֫שְׁחִ֥ית וְ֭הִרְבָּה לְהָשִׁ֣יב אַפּ֑וֹ וְלֹא־יָ֝עִ֗יר כׇּל־חֲמָתֽוֹ: ש יְהֹוָ֥ה הוֹשִׁ֑יעָה הַ֝מֶּ֗לֶךְ יַעֲנֵ֥נוּ בְיוֹם־קׇרְאֵֽנוּ:"}, {"kind": "text", "text": "<b>אַ֭שְׁרֵי</b> יוֹשְׁבֵ֣י בֵיתֶ֑ךָ ע֝֗וֹד יְֽהַלְל֥וּךָ סֶּֽלָה: אַשְׁרֵ֣י הָ֭עָם שֶׁכָּ֣כָה לּ֑וֹ אַֽשְׁרֵ֥י הָ֝עָ֗ם שֱׁיְהֹוָ֥ה אֱלֹהָֽיו:"}, {"kind": "text", "text": "<b>תְּהִלָּ֗ה</b> (תהילים קמ״ה:א׳-ב׳) לְדָ֫וִ֥ד אֲרוֹמִמְךָ֣ אֱלוֹהַ֣י הַמֶּ֑לֶךְ וַאֲבָרְכָ֥ה שִׁ֝מְךָ֗ לְעוֹלָ֥ם וָעֶֽד׃ בְּכָל־י֥וֹם אֲבָֽרְכֶ֑ךָּ וַאֲהַֽלְלָ֥ה שִׁ֝מְךָ֗ לְעוֹלָ֥ם וָעֶֽד׃ גָּ֘ד֤וֹל יְהֹוָ֣ה וּמְהֻלָּ֣ל מְאֹ֑ד וְ֝לִגְדֻלָּת֗וֹ אֵ֣ין חֵֽקֶר׃ דּ֣וֹר לְ֭דוֹר יְשַׁבַּ֣ח מַעֲשֶׂ֑יךָ וּגְב֖וּרֹתֶ֣יךָ יַגִּֽידוּ׃ הֲ֭דַר כְּב֣וֹד הוֹדֶ֑ךָ וְדִבְרֵ֖י נִפְלְאֹתֶ֣יךָ אָשִֽׂיחָה׃ וֶעֱז֣וּז נֽוֹרְאֹתֶ֣יךָ יֹאמֵ֑רוּ וגדלותיך [וּגְדֻלָּתְךָ֥] אֲסַפְּרֶֽנָּה׃ זֵ֣כֶר רַב־טוּבְךָ֣ יַבִּ֑יעוּ וְצִדְקָתְךָ֥ יְרַנֵּֽנוּ׃ חַנּ֣וּן וְרַח֣וּם יְהֹוָ֑ה אֶ֥רֶךְ אַ֝פַּ֗יִם וּגְדׇל־חָֽסֶד׃ טוֹב־יְהֹוָ֥ה לַכֹּ֑ל וְ֝רַחֲמָ֗יו עַל־כׇּל־מַעֲשָֽׂיו׃ יוֹד֣וּךָ יְ֭הֹוָה כׇּל־מַעֲשֶׂ֑יךָ וַ֝חֲסִידֶ֗יךָ יְבָרְכֽוּכָה׃ כְּב֣וֹד מַלְכוּתְךָ֣ יֹאמֵ֑רוּ וּגְבוּרָתְךָ֥ יְדַבֵּֽרוּ׃ לְהוֹדִ֤יעַ ׀ לִבְנֵ֣י הָ֭אָדָם גְּבוּרֹתָ֑יו וּ֝כְב֗וֹד הֲדַ֣ר מַלְכוּתֽוֹ׃ מַֽלְכוּתְךָ֗ מַלְכ֥וּת כׇּל־עֹלָמִ֑ים וּ֝מֶֽמְשַׁלְתְּךָ֗ בְּכׇל־דּ֥וֹר וָדֹֽר׃ סוֹמֵ֣ךְ יְ֭הֹוָה לְכׇל־הַנֹּפְלִ֑ים וְ֝זוֹקֵ֗ף לְכׇל־הַכְּפוּפִֽים׃ עֵֽינֵי־כֹ֭ל אֵלֶ֣יךָ יְשַׂבֵּ֑רוּ וְאַתָּ֤ה נֽוֹתֵן־לָהֶ֖ם אֶת־אׇכְלָ֣ם בְּעִתּֽוֹ׃ פּוֹתֵ֥חַ אֶת־יָדֶ֑ךָ וּמַשְׂבִּ֖יעַ לְכׇל־חַ֣י רָצֽוֹן׃ צַדִּ֣יק יְ֭הֹוָה בְּכׇל־דְּרָכָ֑יו וְ֝חָסִ֗יד בְּכׇל־מַעֲשָֽׂיו׃ קָר֣וֹב יְ֭הֹוָה לְכׇל־קֹרְאָ֑יו לְכֹ֤ל אֲשֶׁ֖ר יִקְרָאֻ֣הוּ בֶֽאֱמֶֽת׃ רְצוֹן־יְרֵאָ֥יו יַעֲשֶׂ֑ה וְֽאֶת־שַׁוְעָתָ֥ם יִ֝שְׁמַ֗ע וְיוֹשִׁיעֵֽם׃ שׁוֹמֵ֣ר יְ֭הֹוָה אֶת־כׇּל־אֹהֲבָ֑יו וְאֵ֖ת כׇּל־הָרְשָׁעִ֣ים יַשְׁמִֽיד׃ תְּהִלַּ֥ת יְהֹוָ֗ה יְֽדַבֶּ֫ר פִּ֥י וִיבָרֵ֣ךְ כׇּל־בָּ֭שָׂר שֵׁ֥ם קׇדְשׁ֗וֹ לְעוֹלָ֥ם וָעֶֽד׃ וַאֲנַ֤חְנוּ ׀ נְבָ֘רֵ֤ךְ יָ֗הּ מֵעַתָּ֥ה וְעַד־עוֹלָ֗ם הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>הַֽלְלוּיָ֡הּ</b> (תהילים קמ״ו:א׳-ג׳) הַֽלְלִ֥י נַ֝פְשִׁ֗י אֶת־יְהֹוָֽה׃ אֲהַלְלָ֣ה יְהֹוָ֣ה בְּחַיָּ֑י אֲזַמְּרָ֖ה לֵאלֹהַ֣י בְּעוֹדִֽי׃ אַל־תִּבְטְח֥וּ בִנְדִיבִ֑ים בְּבֶן־אָדָ֓ם ׀ שֶׁ֤אֵ֖ין ל֥וֹ תְשׁוּעָֽה׃ תֵּצֵ֣א ר֭וּחוֹ יָשֻׁ֣ב לְאַדְמָת֑וֹ בַּיּ֥וֹם הַ֝ה֗וּא אָבְד֥וּ עֶשְׁתֹּֽנֹתָֽיו׃ אַשְׁרֵ֗י שֶׁ֤אֵ֣ל יַעֲקֹ֣ב בְּעֶזְר֑וֹ שִׂ֝בְר֗וֹ עַל־יְהֹוָ֥ה אֱלֹהָֽיו׃ עֹשֶׂ֤ה ׀ שָׁ֘מַ֤יִם וָאָ֗רֶץ אֶת־הַיָּ֥ם וְאֶת־כׇּל־אֲשֶׁר־בָּ֑ם הַשֹּׁמֵ֖ר אֱמֶ֣ת לְעוֹלָֽם׃ עֹשֶׂ֤ה מִשְׁפָּ֨ט ׀ לָעֲשׁוּקִ֗ים נֹתֵ֣ן לֶ֭חֶם לָרְעֵבִ֑ים יְ֝הֹוָ֗ה מַתִּ֥יר אֲסוּרִֽים׃ יְהֹוָ֤ה ׀ פֹּ֘קֵ֤חַ עִוְרִ֗ים יְ֭הֹוָה זֹקֵ֣ף כְּפוּפִ֑ים יְ֝הֹוָ֗ה אֹהֵ֥ב צַדִּיקִֽים׃ יְהֹוָ֤ה ׀ שֹׁ֘מֵ֤ר אֶת־גֵּרִ֗ים יָת֣וֹם וְאַלְמָנָ֣ה יְעוֹדֵ֑ד וְדֶ֖רֶךְ רְשָׁעִ֣ים יְעַוֵּֽת׃ יִמְלֹ֤ךְ יְהֹוָ֨ה ׀ לְעוֹלָ֗ם אֱלֹהַ֣יִךְ צִ֭יּוֹן לְדֹ֥ר וָדֹ֗ר הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>הַ֥לְלוּיָ֨הּ</b> (תהילים קמ״ז:א׳-ב׳) ׀ כִּי־ט֭וֹב זַמְּרָ֣ה אֱלֹהֵ֑ינוּ כִּי־נָ֝עִ֗ים נָאוָ֥ה תְהִלָּֽה׃ בּוֹנֵ֣ה יְרֽוּשָׁלַ֣‍ִם יְהֹוָ֑ה נִדְחֵ֖י יִשְׂרָאֵ֣ל יְכַנֵּֽס׃ הָ֭רֹפֵא לִשְׁב֣וּרֵי לֵ֑ב וּ֝מְחַבֵּ֗שׁ לְעַצְּבוֹתָֽם׃ מוֹנֶ֣ה מִ֭סְפָּר לַכּוֹכָבִ֑ים לְ֝כֻלָּ֗ם שֵׁמ֥וֹת יִקְרָֽא׃ גָּד֣וֹל אֲדוֹנֵ֣ינוּ וְרַב־כֹּ֑חַ לִ֝תְבוּנָת֗וֹ אֵ֣ין מִסְפָּֽר׃ מְעוֹדֵ֣ד עֲנָוִ֣ים יְהֹוָ֑ה מַשְׁפִּ֖יל רְשָׁעִ֣ים עֲדֵי־אָֽרֶץ׃ עֱנ֣וּ לַֽיהֹוָ֣ה בְּתוֹדָ֑ה זַמְּר֖וּ לֵאלֹהֵ֣ינוּ בְכִנּֽוֹר׃ הַֽמְכַסֶּ֬ה שָׁמַ֨יִם ׀ בְּעָבִ֗ים הַמֵּכִ֣ין לָאָ֣רֶץ מָטָ֑ר הַמַּצְמִ֖יחַ הָרִ֣ים חָצִֽיר׃ נוֹתֵ֣ן לִבְהֵמָ֣ה לַחְמָ֑הּ לִבְנֵ֥י עֹ֝רֵ֗ב אֲשֶׁ֣ר יִקְרָֽאוּ׃ לֹ֤א בִגְבוּרַ֣ת הַסּ֣וּס יֶחְפָּ֑ץ לֹא־בְשׁוֹקֵ֖י הָאִ֣ישׁ יִרְצֶֽה׃ רוֹצֶ֣ה יְ֭הֹוָה אֶת־יְרֵאָ֑יו אֶת־הַֽמְיַחֲלִ֥ים לְחַסְדּֽוֹ׃ שַׁבְּחִ֣י יְ֭רוּשָׁלַ‍ִם אֶת־יְהֹוָ֑ה הַֽלְלִ֖י אֱלֹהַ֣יִךְ צִיּֽוֹן׃ כִּֽי־חִ֭זַּק בְּרִיחֵ֣י שְׁעָרָ֑יִךְ בֵּרַ֖ךְ בָּנַ֣יִךְ בְּקִרְבֵּֽךְ׃ הַשָּׂם־גְּבוּלֵ֥ךְ שָׁל֑וֹם חֵ֥לֶב חִ֝טִּ֗ים יַשְׂבִּיעֵֽךְ׃ הַשֹּׁלֵ֣חַ אִמְרָת֣וֹ אָ֑רֶץ עַד־מְ֝הֵרָ֗ה יָר֥וּץ דְּבָרֽוֹ׃ הַנֹּתֵ֣ן שֶׁ֣לֶג כַּצָּ֑מֶר כְּ֝פ֗וֹר כָּאֵ֥פֶר יְפַזֵּֽר׃ מַשְׁלִ֣יךְ קַֽרְח֣וֹ כְפִתִּ֑ים לִפְנֵ֥י קָ֝רָת֗וֹ מִ֣י יַעֲמֹֽד׃ יִשְׁלַ֣ח דְּבָר֣וֹ וְיַמְסֵ֑ם יַשֵּׁ֥ב ר֝וּח֗וֹ יִזְּלוּ־מָֽיִם׃ מַגִּ֣יד דְּבָרָ֣ו לְיַעֲקֹ֑ב חֻקָּ֥יו וּ֝מִשְׁפָּטָ֗יו לְיִשְׂרָאֵֽל׃ לֹ֘א עָ֤שָׂה כֵ֨ן ׀ לְכׇל־גּ֗וֹי וּמִשְׁפָּטִ֥ים בַּל־יְדָע֗וּם הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>הַ֥לְלוּיָ֨הּ</b> ׀ (תהילים קמ״ח:א׳-ב׳) הַֽלְל֣וּ אֶת־יְ֭הֹוָה מִן־הַשָּׁמַ֑יִם הַֽ֝לְל֗וּהוּ בַּמְּרוֹמִֽים׃ הַֽלְל֥וּהוּ כׇל־מַלְאָכָ֑יו הַ֝לְל֗וּהוּ כׇּל־צְבָאָֽו׃ הַֽ֭לְלוּהוּ שֶׁ֣מֶשׁ וְיָרֵ֑חַ הַֽ֝לְל֗וּהוּ כׇּל־כּ֥וֹכְבֵי אֽוֹר׃ הַֽ֭לְלוּהוּ שְׁמֵ֣י הַשָּׁמָ֑יִם וְ֝הַמַּ֗יִם אֲשֶׁ֤ר ׀ מֵעַ֬ל הַשָּׁמָֽיִם׃ יְֽ֭הַלְלוּ אֶת־שֵׁ֣ם יְהֹוָ֑ה כִּ֤י ה֖וּא צִוָּ֣ה וְנִבְרָֽאוּ׃ וַיַּעֲמִידֵ֣ם לָעַ֣ד לְעוֹלָ֑ם חׇק־נָ֝תַ֗ן וְלֹ֣א יַעֲבֽוֹר׃ הַֽלְל֣וּ אֶת־יְ֭הֹוָה מִן־הָאָ֑רֶץ תַּ֝נִּינִ֗ים וְכׇל־תְּהֹמֽוֹת׃ אֵ֣שׁ וּ֭בָרָד שֶׁ֣לֶג וְקִיט֑וֹר ר֥וּחַ סְ֝עָרָ֗ה עֹשָׂ֥ה דְבָרֽוֹ׃ הֶהָרִ֥ים וְכׇל־גְּבָע֑וֹת עֵ֥ץ פְּ֝רִ֗י וְכׇל־אֲרָזִֽים׃ הַחַיָּ֥ה וְכׇל־בְּהֵמָ֑ה רֶ֗֝מֶשׂ וְצִפּ֥וֹר כָּנָֽף׃ מַלְכֵי־אֶ֭רֶץ וְכׇל־לְאֻמִּ֑ים שָׂ֝רִ֗ים וְכׇל־שֹׁ֥פְטֵי אָֽרֶץ׃ בַּחוּרִ֥ים וְגַם־בְּתוּל֑וֹת זְ֝קֵנִ֗ים עִם־נְעָרִֽים׃ יְהַלְל֤וּ ׀ אֶת־שֵׁ֬ם יְהֹוָ֗ה כִּֽי־נִשְׂגָּ֣ב שְׁמ֣וֹ לְבַדּ֑וֹ ה֝וֹד֗וֹ עַל־אֶ֥רֶץ וְשָׁמָֽיִם׃ וַיָּ֤רֶם קֶ֨רֶן ׀ לְעַמּ֡וֹ תְּהִלָּ֤ה לְֽכׇל־חֲסִידָ֗יו לִבְנֵ֣י יִ֭שְׂרָאֵל עַ֥ם קְרֹב֗וֹ הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>הַ֥לְלוּיָ֨הּ</b> ׀ (תהילים קמ״ט:א׳-ב׳) שִׁ֣ירוּ לַֽ֭יהֹוָה שִׁ֣יר חָדָ֑שׁ תְּ֝הִלָּת֗וֹ בִּקְהַ֥ל חֲסִידִֽים׃ יִשְׂמַ֣ח יִשְׂרָאֵ֣ל בְּעֹשָׂ֑יו בְּנֵֽי־צִ֝יּ֗וֹן יָגִ֥ילוּ בְמַלְכָּֽם׃ יְהַלְל֣וּ שְׁמ֣וֹ בְמָח֑וֹל בְּתֹ֥ף וְ֝כִנּ֗וֹר יְזַמְּרוּ־לֽוֹ׃ כִּֽי־רוֹצֶ֣ה יְהֹוָ֣ה בְּעַמּ֑וֹ יְפָאֵ֥ר עֲ֝נָוִ֗ים בִּישׁוּעָֽה׃ יַעְלְז֣וּ חֲסִידִ֣ים בְּכָב֑וֹד יְ֝רַנְּנ֗וּ עַל־מִשְׁכְּבוֹתָֽם׃ רוֹמְמ֣וֹת אֵ֭ל בִּגְרוֹנָ֑ם וְחֶ֖רֶב פִּיפִיּ֣וֹת בְּיָדָֽם׃ לַעֲשׂ֣וֹת נְ֭קָמָה בַּגּוֹיִ֑ם תּ֝וֹכֵח֗וֹת בַּלְאֻמִּֽים׃ לֶאְסֹ֣ר מַלְכֵיהֶ֣ם בְּזִקִּ֑ים וְ֝נִכְבְּדֵיהֶ֗ם בְּכַבְלֵ֥י בַרְזֶֽל׃ לַעֲשׂ֤וֹת בָּהֶ֨ם ׀ מִשְׁפָּ֬ט כָּת֗וּב הָדָ֣ר ה֭וּא לְכׇל־חֲסִידָ֗יו הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>הַ֥לְלוּיָ֨הּ</b> ׀ (תהילים ק״נ:א׳-ב׳) הַֽלְלוּ־אֵ֥ל בְּקָדְשׁ֑וֹ הַֽ֝לְל֗וּהוּ בִּרְקִ֥יעַ עֻזּֽוֹ׃ הַלְל֥וּהוּ בִגְבוּרֹתָ֑יו הַ֝לְל֗וּהוּ כְּרֹ֣ב גֻּדְלֽוֹ׃ הַ֭לְלוּהוּ בְּתֵ֣קַע שׁוֹפָ֑ר הַ֝לְל֗וּהוּ בְּנֵ֣בֶל וְכִנּֽוֹר׃ הַ֭לְלוּהוּ בְּתֹ֣ף וּמָח֑וֹל הַֽ֝לְל֗וּהוּ בְּמִנִּ֥ים וְעֻגָֽב׃ הַלְל֥וּהוּ בְצִלְצְלֵי־שָׁ֑מַע הַֽ֝לְל֗וּהוּ בְּֽצִלְצְלֵ֥י תְרוּעָֽה׃ כֹּ֣ל הַ֭נְּשָׁמָה תְּהַלֵּ֥ל יָ֗הּ הַֽלְלוּיָֽהּ׃ כֹּ֣ל הַ֭נְּשָׁמָה תְּהַלֵּ֥ל יָ֗הּ הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>בָּר֖וּךְ</b> יְהֹוָ֥ה לְ֝עוֹלָ֗ם אָ֘מֵ֥ן ׀ וְאָמֵֽן: בָּ֘ר֤וּךְ יְהֹוָ֨ה ׀ מִצִּיּ֗וֹן שֹׁ֘כֵ֤ן יְֽרוּשָׁלָ֗‍ִם הַֽלְלוּיָֽהּ: בָּר֤וּךְ ׀ יְהֹוָ֣ה אֱ֭לֹהִים אֱלֹהֵ֣י יִשְׂרָאֵ֑ל עֹשֵׂ֖ה נִפְלָא֣וֹת לְבַדּֽוֹ: וּבָר֤וּךְ ׀ שֵׁ֥ם כְּבוֹד֗וֹ לְע֫וֹלָ֥ם וְיִמָּלֵ֣א כְ֭בוֹדוֹ אֶת־כֹּ֥ל הָאָ֗רֶץ אָ֘מֵ֥ן ׀ וְאָמֵֽן:"}, {"kind": "instruction", "text": "יאמר מעומד"}, {"kind": "text", "text": "<b>וַיְבָ֤רֶךְ</b> דָּוִיד֙ אֶת־יְהֹוָ֔ה לְעֵינֵ֖י כׇּל־הַקָּהָ֑ל וַיֹּ֣אמֶר דָּוִ֗יד בָּר֨וּךְ אַתָּ֤ה יְהֹוָה֙ אֱלֹהֵי֙ יִשְׂרָאֵ֣ל אָבִ֔ינוּ מֵעוֹלָ֖ם וְעַד־עוֹלָֽם׃ לְךָ֣ יְ֠הֹוָ֠ה הַגְּדֻלָּ֨ה וְהַגְּבוּרָ֤ה וְהַתִּפְאֶ֙רֶת֙ וְהַנֵּ֣צַח וְהַה֔וֹד כִּי־כֹ֖ל בַּשָּׁמַ֣יִם וּבָאָ֑רֶץ לְךָ֤ יְהֹוָה֙ הַמַּמְלָכָ֔ה וְהַמִּתְנַשֵּׂ֖א לְכֹ֥ל ׀ לְרֹֽאשׁ׃ וְהָעֹ֤שֶׁר וְהַכָּבוֹד֙ מִלְּפָנֶ֔יךָ וְאַתָּה֙ מוֹשֵׁ֣ל בַּכֹּ֔ל וּבְיָדְךָ֖ כֹּ֣חַ וּגְבוּרָ֑ה וּבְיָ֣דְךָ֔ לְגַדֵּ֥ל וּלְחַזֵּ֖ק לַכֹּֽל׃ וְעַתָּ֣ה אֱלֹהֵ֔ינוּ מוֹדִ֥ים אֲנַ֖חְנוּ לָ֑ךְ וּֽמְהַלְלִ֖ים לְשֵׁ֥ם תִּפְאַרְתֶּֽךָ׃ וִיבָֽרְכוּ֙ שֵׁ֣ם כְּבֹדֶ֔ךָ וּמְרוֹמַ֥ם עַל־כׇּל־בְּרָכָ֖ה וּתְהִלָּֽה׃ אַתָּה־ה֣וּא יְהֹוָה֮ לְבַדֶּ֒ךָ֒ את [אַתָּ֣ה] עָשִׂ֡יתָ אֶֽת־הַשָּׁמַ֩יִם֩ שְׁמֵ֨י הַשָּׁמַ֜יִם וְכׇל־צְבָאָ֗ם הָאָ֜רֶץ וְכׇל־אֲשֶׁ֤ר עָלֶ֙יהָ֙ הַיַּמִּים֙ וְכׇל־אֲשֶׁ֣ר בָּהֶ֔ם וְאַתָּ֖ה מְחַיֶּ֣ה אֶת־כֻּלָּ֑ם וּצְבָ֥א הַשָּׁמַ֖יִם לְךָ֥ מִשְׁתַּחֲוִֽים׃ אַתָּה־הוּא֙ יְהֹוָ֣ה הָאֱלֹהִ֔ים ר״ת אהיה. עד כאן מעומד (כה״ח נג:מג) אֲשֶׁ֤ר בָּחַ֙רְתָּ֙ בְּאַבְרָ֔ם וְהוֹצֵאת֖וֹ מֵא֣וּר כַּשְׂדִּ֑ים וְשַׂ֥מְתָּ שְּׁמ֖וֹ אַבְרָהָֽם׃ וּמָצָ֣אתָ אֶת־לְבָבוֹ֮ נֶאֱמָ֣ן לְפָנֶ֒יךָ֒ וְכָר֨וֹת עִמּ֜וֹ הַבְּרִ֗ית לָתֵ֡ת אֶת־אֶ֩רֶץ֩ הַכְּנַעֲנִ֨י הַחִתִּ֜י הָאֱמֹרִ֧י וְהַפְּרִזִּ֛י וְהַיְבוּסִ֥י וְהַגִּרְגָּשִׁ֖י לָתֵ֣ת לְזַרְע֑וֹ וַתָּ֙קֶם֙ אֶת־דְּבָרֶ֔יךָ כִּ֥י צַדִּ֖יק אָֽתָּה׃ וַתֵּ֛רֶא אֶת־עֳנִ֥י אֲבֹתֵ֖ינוּ בְּמִצְרָ֑יִם וְאֶת־זַעֲקָתָ֥ם שָׁמַ֖עְתָּ עַל־יַם־סֽוּף׃ וַ֠תִּתֵּ֠ן אֹתֹ֨ת וּמֹֽפְתִ֜ים בְּפַרְעֹ֤ה וּבְכׇל־עֲבָדָיו֙ וּבְכׇל־עַ֣ם אַרְצ֔וֹ כִּ֣י יָדַ֔עְתָּ כִּ֥י הֵזִ֖ידוּ עֲלֵיהֶ֑ם וַתַּֽעַשׂ־לְךָ֥ שֵׁ֖ם כְּהַיּ֥וֹם הַזֶּֽה׃ וְהַיָּם֙ בָּקַ֣עְתָּ לִפְנֵיהֶ֔ם וַיַּֽעַבְר֥וּ בְתוֹךְ־הַיָּ֖ם בַּיַּבָּשָׁ֑ה וְֽאֶת־רֹ֨דְפֵיהֶ֜ם הִשְׁלַ֧כְתָּ בִמְצוֹלֹ֛ת כְּמוֹ־אֶ֖בֶן בְּמַ֥יִם עַזִּֽים׃"}, {"kind": "text", "text": "<b>וַיּ֨וֹשַׁע</b> (שמות יד ל) יְהֹוָ֜ה בַּיּ֥וֹם הַה֛וּא אֶת־יִשְׂרָאֵ֖ל מִיַּ֣ד מִצְרָ֑יִם וַיַּ֤רְא יִשְׂרָאֵל֙ אֶת־מִצְרַ֔יִם מֵ֖ת עַל־שְׂפַ֥ת הַיָּֽם׃ וַיַּ֨רְא יִשְׂרָאֵ֜ל אֶת־הַיָּ֣ד הַגְּדֹלָ֗ה אֲשֶׁ֨ר עָשָׂ֤ה יְהֹוָה֙ בְּמִצְרַ֔יִם וַיִּֽירְא֥וּ הָעָ֖ם אֶת־יְהֹוָ֑ה וַיַּֽאֲמִ֙ינוּ֙ בַּֽיהֹוָ֔ה וּבְמֹשֶׁ֖ה עַבְדּֽוֹ׃"}, {"kind": "text", "text": "<b>אָ֣ז</b> (שמות ט״ו:א׳) יָשִֽׁיר־מֹשֶׁה֩ וּבְנֵ֨י יִשְׂרָאֵ֜ל אֶת־הַשִּׁירָ֤ה הַזֹּאת֙ לַֽיהֹוָ֔ה וַיֹּאמְר֖וּ לֵאמֹ֑ר אָשִׁ֤ירָה לַֽיהֹוָה֙ כִּֽי־גָאֹ֣ה גָּאָ֔ה ס֥וּס וְרֹכְב֖וֹ רָמָ֥ה בַיָּֽם׃ עָזִּ֤י וְזִמְרָת֙ יָ֔הּ וַֽיְהִי־לִ֖י לִֽישׁוּעָ֑ה זֶ֤ה אֵלִי֙ וְאַנְוֵ֔הוּ אֱלֹהֵ֥י אָבִ֖י וַאֲרֹמְמֶֽנְהוּ׃ יְהֹוָ֖ה אִ֣ישׁ מִלְחָמָ֑ה יְהֹוָ֖ה שְׁמֽוֹ׃ מַרְכְּבֹ֥ת פַּרְעֹ֛ה וְחֵיל֖וֹ יָרָ֣ה בַיָּ֑ם וּמִבְחַ֥ר שָֽׁלִשָׁ֖יו טֻבְּע֥וּ בְיַם־סֽוּף׃ תְּהֹמֹ֖ת יְכַסְיֻ֑מוּ יָרְד֥וּ בִמְצוֹלֹ֖ת כְּמוֹ־אָֽבֶן׃ יְמִֽינְךָ֣ יְהֹוָ֔ה נֶאְדָּרִ֖י בַּכֹּ֑חַ יְמִֽינְךָ֥ יְהֹוָ֖ה תִּרְעַ֥ץ אוֹיֵֽב׃ וּבְרֹ֥ב גְּאוֹנְךָ֖ תַּהֲרֹ֣ס קָמֶ֑יךָ תְּשַׁלַּח֙ חֲרֹ֣נְךָ֔ יֹאכְלֵ֖מוֹ כַּקַּֽשׁ׃ וּבְר֤וּחַ אַפֶּ֙יךָ֙ נֶ֣עֶרְמוּ מַ֔יִם נִצְּב֥וּ כְמוֹ־נֵ֖ד נֹזְלִ֑ים קָֽפְא֥וּ תְהֹמֹ֖ת בְּלֶב־יָֽם׃ אָמַ֥ר אוֹיֵ֛ב אֶרְדֹּ֥ף אַשִּׂ֖יג אֲחַלֵּ֣ק שָׁלָ֑ל תִּמְלָאֵ֣מוֹ נַפְשִׁ֔י אָרִ֣יק חַרְבִּ֔י תּוֹרִישֵׁ֖מוֹ יָדִֽי׃ נָשַׁ֥פְתָּ בְרוּחֲךָ֖ כִּסָּ֣מוֹ יָ֑ם צָֽלְלוּ֙ כַּֽעוֹפֶ֔רֶת בְּמַ֖יִם אַדִּירִֽים׃ מִֽי־כָמֹ֤כָה בָּֽאֵלִם֙ יְהֹוָ֔ה מִ֥י כָּמֹ֖כָה נֶאְדָּ֣ר בַּקֹּ֑דֶשׁ נוֹרָ֥א תְהִלֹּ֖ת עֹ֥שֵׂה פֶֽלֶא׃ נָטִ֙יתָ֙ יְמִ֣ינְךָ֔ תִּבְלָעֵ֖מוֹ אָֽרֶץ׃ נָחִ֥יתָ בְחַסְדְּךָ֖ עַם־ז֣וּ גָּאָ֑לְתָּ נֵהַ֥לְתָּ בְעׇזְּךָ֖ אֶל־נְוֵ֥ה קׇדְשֶֽׁךָ׃ שָֽׁמְע֥וּ עַמִּ֖ים יִרְגָּז֑וּן חִ֣יל אָחַ֔ז יֹשְׁבֵ֖י פְּלָֽשֶׁת׃ אָ֤ז נִבְהֲלוּ֙ אַלּוּפֵ֣י אֱד֔וֹם אֵילֵ֣י מוֹאָ֔ב יֹֽאחֲזֵ֖מוֹ רָ֑עַד נָמֹ֕גוּ כֹּ֖ל יֹשְׁבֵ֥י כְנָֽעַן׃ תִּפֹּ֨ל עֲלֵיהֶ֤ם אֵימָ֙תָה֙ וָפַ֔חַד בִּגְדֹ֥ל זְרוֹעֲךָ֖ יִדְּמ֣וּ כָּאָ֑בֶן עַד־יַעֲבֹ֤ר עַמְּךָ֙ יְהֹוָ֔ה עַֽד־יַעֲבֹ֖ר עַם־ז֥וּ קָנִֽיתָ׃ תְּבִאֵ֗מוֹ וְתִטָּעֵ֙מוֹ֙ בְּהַ֣ר נַחֲלָֽתְךָ֔ מָכ֧וֹן לְשִׁבְתְּךָ֛ פָּעַ֖לְתָּ יְהֹוָ֑ה מִקְּדָ֕שׁ אֲדֹנָ֖י כּוֹנְנ֥וּ יָדֶֽיךָ׃ יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד׃ יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד׃יְהֹוָה מַלְכוּתֵהּ קָאִים לְעָלַם וּלְעָלְמֵי עָלְמַיָּא: כִּ֣י בָא֩ ס֨וּס פַּרְעֹ֜ה בְּרִכְבּ֤וֹ וּבְפָרָשָׁיו֙ בַּיָּ֔ם וַיָּ֧שֶׁב יְהֹוָ֛ה עֲלֵהֶ֖ם אֶת־מֵ֣י הַיָּ֑ם וּבְנֵ֧י יִשְׂרָאֵ֛ל הָלְכ֥וּ בַיַּבָּשָׁ֖ה בְּת֥וֹךְ הַיָּֽם׃"}, {"kind": "text", "text": "<b>כִּ֣י</b> לַ֭יהֹוָה הַמְּלוּכָ֑ה וּ֝מֹשֵׁ֗ל בַּגּוֹיִֽם׃ וְעָל֤וּ מֽוֹשִׁעִים֙ בְּהַ֣ר צִיּ֔וֹן לִשְׁפֹּ֖ט אֶת־הַ֣ר עֵשָׂ֑ו וְהָיְתָ֥ה לַֽיהֹוָ֖ה הַמְּלוּכָֽה׃ וְהָיָ֧ה יְהֹוָ֛ה לְמֶ֖לֶךְ עַל־כׇּל־הָאָ֑רֶץ בַּיּ֣וֹם הַה֗וּא יִהְיֶ֧ה יְהֹוָ֛ה אֶחָ֖ד וּשְׁמ֥וֹ אֶחָֽד׃"}, {"kind": "instruction", "text": "כשאומר נשמת כל חי יכון לקבל תוספת נפש יתירה דבחינת היום"}, {"kind": "text", "text": "<b>נִשְׁמַת</b> נִשְׁמַת כָּל־חַי תְּבָרֵךְ אֶת שִׁמְךָ יְהֹוָה אֱלֹהֵֽינוּ, וְרֽוּחַ כָּל־בָּשָׂר תְּפָאֵר וּתְרוֹמֵם זִכְרְךָ מַלְכֵּֽנוּ תָּמִיד, מִן־הָעוֹלָם וְעַד־הָעוֹלָם אַתָּה אֵל. וּמִבַּלְעָדֶֽיךָ אֵין לָֽנוּ מֶֽלֶךְ גּוֹאֵל וּמוֹשִֽׁיעַ, פּוֹדֶה וּמַצִּיל, וְעוֹנֶה וּמְרַחֵם, בְּכָל־עֵת צָרָה וְצוּקָה, אֵין לָֽנוּ מֶֽלֶךְ עוֹזֵר וְסוֹמֵךְ אֶלָּא אָֽתָּה:"}, {"kind": "text", "text": "<b>אֱלֹהֵי</b> הָרִאשׁוֹנִים וְהָאַחֲרוֹנִים, אֱלֽוֹהַּ כָּל־בְּרִיּוֹת, אֲדוֹן כָּל־תּוֹלָדוֹת, הַמְּהֻלָּל בְּכָל־הַתִּשְׁבָּחוֹת, הַמְּנַהֵג עוֹלָמוֹ בְּחֶֽסֶד, וּבְרִיּוֹתָיו בְּרַחֲמִים. וַיהֹוָה אֱלֹהִים אֱמֶת, לֹא יָנוּם וְלֹא יִישָׁן, הַמְעוֹרֵר יְשֵׁנִים וְהַמֵּקִיץ נִרְדָּמִים, מְחַיֶּה מֵתִים וְרוֹפֵא חוֹלִים, פּוֹקֵחַ עִוְרִים וְזוֹקֵף כְּפוּפִים, הַמֵּשִֽׂיחַ אִלְּמִים וְהַמְפַעֲנֵֽחַ נֶעֱלָמִים, וּלְךָ לְבַדְּךָ אֲנַֽחְנוּ מוֹדִים:"}, {"kind": "text", "text": "<b>וְאִלּוּ</b> פִֽינוּ מָלֵא שִׁירָה כַיָּם, וּלְשׁוֹנֵֽנוּ רִנָּה כַּהֲמוֹן גַּלָּיו, וְשִׂפְתוֹתֵֽינוּ שֶֽׁבַח כְּמֶרְחֲבֵי רָקִֽיעַ, וְעֵינֵֽינוּ מְאִירוֹת כַּשֶּֽׁמֶשׁ וְכַיָּרֵֽחַ, וְיָדֵֽינוּ פְרוּשׂוֹת כְּנִשְׁרֵי שָׁמָֽיִם, וְרַגְלֵֽינוּ קַלּוֹת כָּאַיָּלוֹת, אֵין אֲנַֽחְנוּ מַסְפִּיקִין לְהוֹדוֹת לְךָ יְהֹוָה אֱלֹהֵֽינוּ, וּלְבָרֵךְ אֶת־שִׁמְךָ מַלְכֵּֽנוּ, עַל־אַחַת מֵאֶֽלֶף אַלְפֵי אֲלָפִים, וְרוֹב רִבֵּי רִבָבוֹת פְּעָמִים, הַטּוֹבוֹת נִסִּים וְנִפְלָאוֹת שֶׁעָשִֽׂיתָ עִמָּֽנוּ וְעִם אֲבוֹתֵֽינוּ. מִלְּפָנִים מִמִּצְרַֽיִם גְּאַלְתָּֽנוּ יְהֹוָה אֱלֹהֵֽינוּ, מִבֵּית עֲבָדִים פְּדִיתָֽנוּ, בְּרָעָב זַנְתָּֽנוּ וּבְשָׂבָע כִּלְכַּלְתָּֽנוּ, מֵחֶֽרֶב הִצַּלְתָּֽנוּ, מִדֶּֽבֶר מִלַּטְתָּֽנוּ, וּמֵחֳלָאִים רָעִים וְרַבִּים דִּלִּיתָֽנוּ. עַד הֵֽנָּה עֲזָרֽוּנוּ רַחֲמֶֽיךָ, וְלֹא עֲזָבֽוּנוּ חֲסָדֶֽיךָ. עַל כֵּן אֵבָרִים שֶׁפִּלַּֽגְתָּ בָּֽנוּ, וְרֽוּחַ וּנְשָׁמָה שֶׁנָּפַֽחְתָּ בְּאַפֵּֽינוּ, וְלָשׁוֹן אֲשֶׁר שַֽׂמְתָּ בְּפִֽינוּ, הֵן הֵם יוֹדוּ וִיבָֽרְכֽוּ וִישַׁבְּחוּ וִיפָאֲרוּ וִישׁוֹרְרוּ אֶת־שִׁמְךָ מַלְכֵּֽנוּ תָּמִיד. כִּי כָל־פֶּה לְךָ יוֹדֶה, וְכָל־לָשׁוֹן לְךָ תְשַׁבֵּֽחַ, וְכָל־עַֽיִן לְךָ תְצַפֶּה, וְכָל־בֶּֽרֶךְ לְךָ תִכְרַע, וְכָל־קוֹמָה לְפָנֶֽיךָ תִשְׁתַּחֲוֶה, וְהַלְּבָבוֹת יִירָאֽוּךָ, וְהַקֶּֽרֶב וְהַכְּלָיוֹת יְזַמְּרוּ לִשְׁמֶֽךָ, כַּדָּבָר שֶׁנֶּאֱמַר כָּ֥ל עַצְמוֹתַ֨י ׀ תֹּאמַרְנָה֮ יְהֹוָ֗ה מִ֥י כָ֫מ֥וֹךָ מַצִּ֣יל עָ֭נִי מֵחָזָ֣ק מִמֶּ֑נּוּ וְעָנִ֥י וְ֝אֶבְי֗וֹן מִגֹּזְלֽוֹ:"}, {"kind": "text", "text": "<b>שַׁוְעַת</b> עֲנִיִּים אַתָּה תִשְׁמַע, צַעֲקַת הַדַּל תַּקְשִׁיב וְתוֹשִֽׁיעַ. וְכָתוּב רַנְּנ֣וּ צַ֭דִּיקִים בַּֽיהֹוָ֑ה לַ֝יְשָׁרִ֗ים נָאוָ֥ה תְהִלָּֽה:"}, {"kind": "text", "text": "בְּפִי <b>יְ</b>שָׁרִים תִּתְ<b>ר</b>וֹמָם,"}, {"kind": "text", "text": "וּבְשִׂפְתֵי <b>צַ</b>דִּיקִים תִּתְ<b>בָּ</b>רַךְ,"}, {"kind": "text", "text": "וּבִלְשׁוֹן <b>חֲ</b>סִידִים תִּתְ<b>קַ</b>דָּשׁ,"}, {"kind": "text", "text": "וּבְקֶֽרֶב <b>קְ</b>דוֹשִׁים תִּתְ<b>הַ</b>לָּל,"}, {"kind": "text", "text": "<b>בְּמִקְהֲלוֹת</b> רִבְבוֹת עַמְּךָ בֵּית יִשְׂרָאֵל, שֶׁכֵּן חוֹבַת כָּל־הַיְצוּרִים לְפָנֶֽיךָ יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ, לְהוֹדוֹת, לְהַלֵּל, לְשַׁבֵּֽחַ, לְפָאֵר, לְרוֹמֵם, לְהַדֵּר וּלְנַצֵּֽחַ, עַל כָּל־דִּבְרֵי שִׁירוֹת וְתִשְׁבְּחוֹת דָּוִד בֶּן־יִשַׁי עַבְדְּךָ מְשִׁיחֶֽךָ. וּבְכֵן"}, {"kind": "instruction", "text": "שבח ברכת ישתבח הוא עצום ונורא, וצריך לאומרם בנעימה כמסדר שבחו של מלך, לכך לא יאמר אותם בנשימה אחת כמנהג קצת בני אדם, ומצאתי כתוב, שימנה אותם באצבעותיו, והוא דבר נכון ויציב, וכך אני נוהג (בא\"ח ויגש הט\"ו)"}, {"kind": "text", "text": "<b>יִשְׁתַּבַּח</b> שִׁמְךָ לָעַד מַלְכֵּֽנוּ, הָאֵל הַמֶּֽלֶךְ הַגָּדוֹל וְהַקָּדוֹשׁ, בַּשָּׁמַֽיִם וּבָאָֽרֶץ. כִּי לְךָ נָאֶה יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ לְעוֹלָם וָעֶד. א שִׁיר, ב וּשְׁבָחָה, ג הַלֵּל, ד וְזִמְרָה, ה עֹז, ו וּמֶמְשָׁלָה, ז נֶֽצַח, ח גְּדֻלָּה, ט גְּבוּרָה, י תְּהִלָּה, יא וְתִפְאֶֽרֶת, יב קְדֻשָּׁה, יג וּמַלְכוּת. בְּרָכוֹת וְהוֹדָאוֹת, לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, וּמֵעוֹלָם וְעַד עוֹלָם אַתָּה אֵל. בָּרוּךְ אַתָּה יְהֹוָה, מֶֽלֶךְ גָּדוֹל וּמְהֻלָּל בַּתִּשְׁבָּחוֹת, אֵל הַהוֹדָאוֹת, אֲדוֹן הַנִּפְלָאוֹת, בּוֹרֵא כָּל־הַנְּשָׁמוֹת, רִבּוֹן כָּל־הַמַּעֲשִׂים, הַבּוֹחֵר בְּשִׁירֵי זִמְרָה, מֶֽלֶךְ אֵל חַי הָעוֹלָמִים, אָמֵן:"}, {"kind": "instruction", "text": "בשבת תשובה אומרים"}, {"kind": "text", "text": "<b>שִׁ֥יר</b> (תהילים ק״ל) הַֽמַּעֲל֑וֹת מִמַּעֲמַקִּ֖ים קְרָאתִ֣יךָ יְהֹוָֽה׃ אֲדֹנָי֮ שִׁמְעָ֢ה בְק֫וֹלִ֥י תִּהְיֶ֣ינָה אׇ֭זְנֶיךָ קַשֻּׁב֑וֹת לְ֝ק֗וֹל תַּחֲנוּנָֽי׃ אִם־עֲוֺנ֥וֹת תִּשְׁמׇר־יָ֑הּ אֲ֝דֹנָ֗י מִ֣י יַעֲמֹֽד׃ כִּֽי־עִמְּךָ֥ הַסְּלִיחָ֑ה לְ֝מַ֗עַן תִּוָּרֵֽא׃ קִוִּ֣יתִי יְ֭הֹוָה קִוְּתָ֣ה נַפְשִׁ֑י וְֽלִדְבָר֥וֹ הוֹחָֽלְתִּי׃ נַפְשִׁ֥י לַאדֹנָ֑י מִשֹּׁמְרִ֥ים לַ֝בֹּ֗קֶר שֹׁמְרִ֥ים לַבֹּֽקֶר׃ יַחֵ֥ל יִשְׂרָאֵ֗ל אֶל־יְהֹ֫וָ֥ה כִּֽי־עִם־יְהֹוָ֥ה הַחֶ֑סֶד וְהַרְבֵּ֖ה עִמּ֣וֹ פְדֽוּת׃ וְ֭הוּא יִפְדֶּ֣ה אֶת־יִשְׂרָאֵ֑ל מִ֝כֹּ֗ל עֲוֺנֹתָֽיו׃"}, {"kind": "text", "text": "ואומר החזן חצי קדיש"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "ואומר החזן: בָּֽרְכֽוּ אֶת יְהֹוָה הַמְּבֹרָךְ:"}, {"kind": "text", "text": "ועונים הקהל: בָּרוּךְ יְהֹוָה הַמְּבֹרָךְ לְעוֹלָם וָעֵד:"}, {"kind": "text", "text": "ואומר החזן: בָּרוּךְ יְהֹוָה הַמְּבֹרָךְ לְעוֹלָם וָעֵד:"}, {"kind": "header", "text": "ק\"ש וברכותיה"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, יוֹצֵר אוֹר וּבוֹרֵא חֹשֶׁךְ, עֹשֶׂה שָׁלוֹם וּבוֹרֵא אֶת הַכֹּל. הַכֹּל יוֹדוּךָ, וְהַכֹּל יְשַׁבְּחוּךָ, וְהַכֹּל יֹאמְרוּ אֵין קָדוֹשׁ כַּיהֹוָה . הַכֹּל יְרוֹמְמוּךָ סֶּלָה, יוֹצֵר הַכֹּל. הָאֵל הַפּוֹתֵחַ בְּכָל יוֹם דַּלְתוֹת שַׁעֲרֵי מִזְרָח, וּבוֹקֵעַ חַלּוֹנֵי רָקִיעַ, מוֹצִיא חַמָּה מִמְּקוֹמָהּ וּלְבָנָה מִמְּכוֹן שִׁבְתָּהּ, וּמֵאִיר לָעוֹלָם כֻּלּוֹ וּלְיוֹשְׁבָיו, שֶׁבָּרָא בְּמִדַּת הָרַחֲמִים. הַמֵּאִיר לָאָרֶץ וְלַדָּרִים עָלֶיהָ בְּרַחֲמִים, וּבְטוּבוֹ מְחַדֵּשׁ בְּכָל יוֹם תָּמִיד מַעֲשֵׂה בְּרֵאשִׁית. מָה רַבּוּ מַעֲשֶׂיךָ יְהֹוָה כֻּלָּם בְּחָכְמָה עָשִׂיתָ, מָלְאָה הָאָרֶץ קִנְיָנֶךָ. הַמֶּלֶךְ הַמְּרוֹמָם לְבַדּוֹ מֵאָז, הַמְּשֻׁבָּח וְהַמְּפוֹאָר וְהַמִּתְנַשֵּׂא מִימוֹת עוֹלָם. אֱלֹהֵי עוֹלָם בְּרַחֲמֶיךָ הָרַבִּים רַחֵם עָלֵינוּ, אֲדוֹן עוּזֵּנוּ, צוּר מִשְׂגַּבֵּנוּ, מָגֵן יִשְׁעֵנוּ, מִשְׂגָּב בַּעֲדֵנוּ:"}, {"kind": "text", "text": "<b>אֵין</b> עֲרוֹךְ לָךְ וְאֵין זוּלָתָךְ, אֶפֶס בִּלְתָּךְ, וּמִי דוֹמֶה לָּךְ. אֵין עֲרוֹךְ לָךְ יְהֹוָה אֱלֹהֵינוּ בָּעוֹלָם הַזֶּה, וְאֵין זוּלָתָךְ מַלְכֵּנוּ לְחַיֵּי הָעוֹלָם הַבָּא, אֶפֶס בִּלְתָּךְ גּוֹאֲלֵנוּ לִימוֹת הַמָּשִׁיחַ, וּמִי דוֹמֶה לָּךְ מוֹשִׁיעֵנוּ לִתְחִיַּת הַמֵּתִים:"}, {"kind": "text", "text": "<b>אֵל</b>, אָדוֹן עַל כָּל הַמַּעֲשִׂים, בָּרוּךְ וּמְבֹרָךְ בְּפִי כָל הַנְּשָׁמָה: גָּדְלוּ וְטוּבוֹ מָלֵא עוֹלָם, דַּעַת וּתְבוּנָה סוֹבבִים הוֹדוֹ: הַמִּתְגָּאֶה עַל חַיּוֹת הַקֹּדֶשׁ, וְנֶהְדָּר בְּכָבוֹד עַל הַמֶּרְכָּבָה: זְכוּת וּמִישׁוֹר לִפְנֵי כִסְאוֹ, חֶסֶד וְרַחֲמִים מָלֵא כְבוֹדוֹ: טוֹבִים מְאוֹרוֹת שֶׁבְּרָאָם אֱלֹהֵינוּ, יְצָרָם בְּדַעַת בְּבִינָה וּבְהַשְׂכֵּל: כֹּחַ וּגְבוּרָה נָתַן בָּהֶם, לִהְיוֹת מוֹשְׁלִים בְּקֶרֶב תֵּבֵל: מְלֵאִים זִיו וּמְפִיקִים נֹגַהּ, נָאֶה זִיוָם בְּכָל הָעוֹלָם: שְׂמֵחִים בְּצֵאתָם שָׂשִׂים בּבֹאָם, עוֹשִׂים בְּאֵימָה רְצוֹן קוֹנֵיהֶם: פְּאֵר וְכָבוֹד נוֹתְנִים לִשְׁמוֹ, צָהֳלָה וְרִנָּה לְזֵכֶר מַלְכוּתוֹ: קָרָא לַשֶּׁמֶשׁ וַיִּזְרַח אוֹר, רָאָה וְהִתְקִין צוּרַת הַלְּבָנָה: שֶׁבַח נוֹתְנִים לוֹ כָּל צְבָא מָרוֹם, תִּפְאֶרֶת וּגְדֻלָּה, שְׂרָפִים וְחַיּוֹת וְאוֹפַנֵּי הַקֹּדֶשׁ:"}, {"kind": "instruction", "text": "ביום־טוב שאינו שבת מדלגים"}, {"kind": "text", "text": "<b>לָאֵל</b> אֲשֶׁר שָׁבַת מִכָּל הַמַּעֲשִׂים, וּבַיּוֹם הַשְּׁבִיעִי נִתְעַלָּה וְיָשַׁב עַל כִּסֵּא כְבוֹדוֹ, תִּפְאֶרֶת עָטָה לְיוֹם הַמְּנוּחָה, עֹנֶג קָרָא לְיוֹם הַשַּׁבָּת. זֶה שִׁיר שֶׁבַח שֶׁל יוֹם הַשְּׁבִיעִי, שֶׁבּוֹ שָׁבַת אֵל מִכּל מְלַאכְתּוֹ. וְיוֹם הַשְּׁבִיעִי מְשַׁבֵּחַ וְאוֹמֵר מִזְמ֥וֹר שִׁ֗יר לְי֣וֹם הַשַּׁבָּֽת׃ לְפִיכָךְ יְפָאֲרוּ לָאֵל כָּל יצוּרָיו, שֶׁבַח וִיקָר וּגְדֻלָּה וְכָבוֹד יִתְּנוּ לַמֶּלֶךְ יוֹצֵר כֹּל, הַמַּנְחִיל מְנוּחָה לְעַמּוֹ יִשְׂרָאֵל בְּיוֹם שַׁבַּת קֹדֶשׁ:"}, {"kind": "text", "text": "<b>שִׁמְךָ</b> יְהֹוָה אֱלֹהֵינוּ יִתְקַדָּשׁ, וְזִכְרְךָ יִתְפָּאַר מַלְכֵּנוּ, בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת, עַל כָּל שֶׁבַח מַעֲשֵׂה יָדֶיךָ, וְעַל מְאוֹרֵי אוֹר שֶׁיָּצַרְתָּ, הֵמָּה יְפָאֲרוּךָ סֶּלָה."}, {"kind": "text", "text": "<b>תִּתְבָּרַךְ</b> לָנֶצַח צוּרֵנוּ מַלְכֵּנוּ וְגוֹאֲלֵנוּ בּוֹרֵא קְדוֹשִׁים, יִשְׁתַּבַּח שִׁמְךָ לָעַד מַלְכֵּנוּ יוֹצֵר מְשָׁרְתִים, וַאֲשֶׁר מְשָׁרְתָיו כֻּלָּם עוֹמְדִים בְּרוּם עוֹלָם וּמַשְׁמִיעִים בְּיִרְאָה יַחַד בְּקוֹל דִּבְרֵי אֱלֹהִים חַיִּים וּמֶלֶךְ עוֹלָם. כֻּלָּם אֲהוּבִים, כֻּלָּם בְּרוּרִים, כֻּלָּם גִיבוֹרִים, כֻּלָּם קְדוֹשִׁים, כֻּלָּם עוֹשִׂים בְּאֵימָה וּבְיִרְאָה רָצוֹן קוֹנֵיהֶם, וְכֻלָּם פּוֹתְחִים אֶת פִּיהֶם בִּקְדוּשָׁה וּבְטָהֳרָה, בְּשִׁירָה וּבְזִמְרָה, וּמְבָרְכִין וּמְשַׁבְּחִין וּמְפָאֲרִין וּמַקְדִּישִׁין וּמַעֲרִיצִין וּמַמְלִיכִין אֶת שֵׁם הָאֵל הַמֶּלֶךְ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא קָדוֹשׁ הוּא. וְכֻלָּם מְקַבְּלִים עֲלֵיהֶם עֹל מַלְכוּת שָׁמַיִם זֶה מִזֶּה, וְנוֹתְנִים רְשׁוּת זֶה לָזֶה לְהַקְדִּישׁ לְיוֹצְרָם בְּנַחַת רוּחַ בְּשָׂפָה בְּרוּרָה וּבִנְעִימָה קְדוּשָׁה, כֻּלָּם כְּאֶחָד עוֹנִים בְּאֵימָה, וְאוֹמְרִים בְּיִרְאָה:"}, {"kind": "instruction", "text": "קדושת יוצר צריך לאמרה מיושב ואם היה עומד צריך שישב (בא\"ח שמות ב')"}, {"kind": "text", "text": "<b>קָד֧וֹשׁ</b> ׀ קָד֛וֹשׁ קָד֖וֹשׁ יְהֹוָ֣ה צְבָא֑וֹת מְלֹ֥א כׇל־הָאָ֖רֶץ כְּבוֹדֽוֹ: וְהָאוֹפַנִּים וְחַיּוֹת הַקֹדֶשׁ בְּרַעַשׁ גָּדוֹל מִתְנַשְּׂאִים לְעֻמַּת הַשְׂרָפִים, לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים: בָּר֥וּךְ כְּבוֹד־יְהֹוָ֖ה מִמְּקוֹמֽוֹ:"}, {"kind": "text", "text": "<b>לָאֵל</b> בָּרוּךְ, נְעִימוֹת יִתֵּנוּ, לַמֶּלֶךְ אֵל חַי וְקַיָּם, זְמִירוֹת יֹאמְרוּ וְתִשְׁבָּחוֹת יַשְׁמִיעוּ, כִּי הוּא לְבַדּוֹ מָרוֹם וְקָדוֹשׁ, פּוֹעֵל גְּבוּרוֹת, עוֹשֶׂה חֲדָשׁוֹת, בַּעַל מִלְחָמוֹת, זוֹרֵעַ צְדָקוֹת, מַצְמִיחַ יְשׁוּעוֹת, בּוֹרֵא רְפוּאוֹת, נוֹרָא תְהִלּוֹת, אֲדוֹן הַנִּפְלָאוֹת, הַמְחַדֵּשׁ בְּטוּבוֹ בְּכָל יוֹם תָּמִיד מַעֲשֵׂה בְרֵאשִׁית כָּאָמוּר: לְ֭עֹשֵׂה אוֹרִ֣ים גְּדֹלִ֑ים כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃ בָּרוּךְ אַתָּה יְהֹוָה יוֹצֵר הַמְּאוֹרוֹת:"}, {"kind": "text", "text": "<b>אַהֲבַת</b> עוֹלָם אֲהַבְתָּנוּ יְהֹוָה אֱלֹהֵינוּ, חֶמְלָה גְּדוֹלָה וִיתֵרָה חָמַלְתָּ עָלֵינוּ. אָבִינוּ מַלְכֵּנוּ, בַּעֲבוּר שִׁמְךָ הַגָּדוֹל וּבַעֲבוּר אֲבוֹתֵינוּ שֶׁבָּטְחוּ בָּךְ וַתְּלַמְּדֵמוֹ חֻקֵּי חַיִּים לַעֲשׂוֹת רְצוֹנְךָ בְּלֵבָב שָׁלֵם, כֵּן תְּחָנֵּנוּ אָבִינוּ, אָב הָרַחֲמָן הַמְרַחֵם, רַחֵם נָא עָלֵינוּ, וְתֵן בְּלִבֵּנוּ בִינָה לְהָבִין, לְהַשְׂכִּיל, לִשְׁמֹעַ, לִלְמֹד וּלְלַמֵּד, לִשְׁמֹר וְלַעֲשׂוֹת וּלְקַיֵּים אֶת כָּל דִּבְרֵי תַּלְמוּד תוֹרָתֶךָ בְּאַהֲבָה:"}, {"kind": "text", "text": "וְהָאֵר עֵינֵינוּ בְּתוֹרָתֶךָ וְדַבֵּק לִבֵּנוּ בְמִצְוֹתֶיךָ, וְיַחֵד לְבָבֵנוּ לְאַהֲבָה וּלְיִרְאָה אֶת־שְׁמֶךָ. לֹא נֵבוֹשׁ וְלֹא נִכָּלֵם וְלֹא נִכָּשֵׁל לְעוֹלָם וָעֶד. כִּי בְשֵׁם קָדְשְׁךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא בָּטָחְנוּ, נָגִילָה וְנִשְׂמְחָה בִּישׁוּעָתֶךָ, וְרַחֲמֶיךָ יְהֹוָה אֱלֹהֵינוּ וַחֲסָדֶיךָ הָרַבִּים, אֶל יַעַזְבוּנוּ נֶצַח סֶלָה וָעֶד:"}, {"kind": "text", "text": "כשיאמר מהר והבא עלינו ישים שני צדדי הטלית על כתפיו וכשיאמר ברכה ושלום מהרה מארבע כנפות כל הארץ יקבץ כל ארבע כנפות הטלית ויאחזם בידו השמאלית כנגד הלב שהוא בשמאל (בא\"ח שמות ה\"ה) מַהֵר וְהַבֵא עָלֵינוּ בְּרָכָה וְשָׁלוֹם מְהֵרָה מֵאַרְבַּע כַּנְפוֹת כָּל־הָאָרֶץ, וּשְׁבֹר עֹל הַגּוֹיִם מֵעַל צַוָּארֵנוּ, וְהוֹלִיכֵנוּ מְהֵרָה קוֹמְמִיּוּת לְאַרְצֵנוּ, כִּי אֵל פּוֹעֵל יְשׁוּעוֹת אַתָּה, וּבָנוּ בָחַרְתָּ מִכָּל עַם וְלָשׁוֹן, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לְשִׁמְךָ הַגָּדוֹל בְּאַהֲבָה, לְהוֹדוֹת לָךְ וּלְיַחֶדְךָ לְיִרְאָה וּלְאַהֲבָה אֶת־שִׁמְךָ, בָּרוּךְ אַתָּה יְהֹוָה, הַבּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל בְּאַהֲבָה:"}, {"kind": "instruction", "text": "קודם שיקרא קריאת שמע יכוין לקיים מצוות עשה שנצטוינו לקרא קריאת שמע שתי פעמים ביום, וגם יכוין לקיים מצות עשה ליחד את השם, ויסגור עיניו ביד ימינו בפסוק ראשון עד שישלים ברוך שם, וכן הוא כאן אומר שמע ישראל כלומר קבל דברים אלו והבינם ותדעם שתאמין בם והוא כי ה' הוא אלהינו, ועוד הנה הוא ה' אחד, ונמצא בזה יש קבלה והודאה בשתי דברים האחד הוא קבלת מלכות שמים באומרו ה' אלהינו דמודה שקבלנו אלהותו להיות לנו לאלוה ואנחנו עבדים לו, והשני הוא ענין יחוד השם באומרו ה' אחד שהוא בלי שיתוף אחר (בא\"ח וארא ה\"ו-ז)"}, {"kind": "text", "text": "<b>שְׁמַ֖ע יִשְׂרָאֵ֑ל יְהֹוָ֥ה אֱלֹהֵ֖ינוּ יְהֹוָ֥ה ׀ אֶחָֽד</b>"}, {"kind": "instruction", "text": "בלחש: בָּרוּךְ שֵּׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "<b>וְאָ֣הַבְתָּ֔</b> (דברים ו ה) אֵ֖ת יְהֹוָ֣ה אֱלֹהֶ֑יךָ בְּכׇל־לְבָבְךָ֥ וּבְכׇל־נַפְשְׁךָ֖ וּבְכׇל־מְאֹדֶֽךָ׃ וְהָי֞וּ הַדְּבָרִ֣ים הָאֵ֗לֶּה אֲשֶׁ֨ר אָנֹכִ֧י מְצַוְּךָ֛ הַיּ֖וֹם עַל־לְבָבֶֽךָ׃ וְשִׁנַּנְתָּ֣ם לְבָנֶ֔יךָ וְדִבַּרְתָּ֖ בָּ֑ם בְּשִׁבְתְּךָ֤ בְּבֵיתֶ֙ךָ֙ וּבְלֶכְתְּךָ֣ בַדֶּ֔רֶךְ וּֽבְשׇׁכְבְּךָ֖ וּבְקוּמֶֽךָ׃ וּקְשַׁרְתָּ֥ם לְא֖וֹת עַל־יָדֶ֑ךָ וְהָי֥וּ לְטֹטָפֹ֖ת בֵּ֥ין עֵינֶֽיךָ׃ וּכְתַבְתָּ֛ם עַל־מְזֻז֥וֹת בֵּיתֶ֖ךָ וּבִשְׁעָרֶֽיךָ׃"}, {"kind": "text", "text": "<b>וְהָיָ֗ה</b> (דברים יא יג) אִם־שָׁמֹ֤עַ תִּשְׁמְעוּ֙ אֶל־מִצְוֺתַ֔י אֲשֶׁ֧ר אָנֹכִ֛י מְצַוֶּ֥ה אֶתְכֶ֖ם הַיּ֑וֹם לְאַהֲבָ֞ה אֶת־יְהֹוָ֤ה אֱלֹֽהֵיכֶם֙ וּלְעׇבְד֔וֹ בְּכׇל־לְבַבְכֶ֖ם וּבְכׇל־נַפְשְׁכֶֽם׃ וְנָתַתִּ֧י מְטַֽר־אַרְצְכֶ֛ם בְּעִתּ֖וֹ יוֹרֶ֣ה וּמַלְק֑וֹשׁ וְאָסַפְתָּ֣ דְגָנֶ֔ךָ וְתִֽירֹשְׁךָ֖ וְיִצְהָרֶֽךָ׃ וְנָתַתִּ֛י עֵ֥שֶׂב בְּשָׂדְךָ֖ לִבְהֶמְתֶּ֑ךָ וְאָכַלְתָּ֖ וְשָׂבָֽעְתָּ׃ הִשָּֽׁמְר֣וּ לָכֶ֔ם פֶּ֥ן יִפְתֶּ֖ה לְבַבְכֶ֑ם וְסַרְתֶּ֗ם וַעֲבַדְתֶּם֙ אֱלֹהִ֣ים אֲחֵרִ֔ים וְהִשְׁתַּחֲוִיתֶ֖ם לָהֶֽם׃ וְחָרָ֨ה אַף־יְהֹוָ֜ה בָּכֶ֗ם וְעָצַ֤ר אֶת־הַשָּׁמַ֙יִם֙ וְלֹֽא־יִהְיֶ֣ה מָטָ֔ר וְהָ֣אֲדָמָ֔ה לֹ֥א תִתֵּ֖ן אֶת־יְבוּלָ֑הּ וַאֲבַדְתֶּ֣ם מְהֵרָ֗ה מֵעַל֙ הָאָ֣רֶץ הַטֹּבָ֔ה אֲשֶׁ֥ר יְהֹוָ֖ה נֹתֵ֥ן לָכֶֽם׃ וְשַׂמְתֶּם֙ אֶת־דְּבָרַ֣י אֵ֔לֶּה עַל־לְבַבְכֶ֖ם וְעַֽל־נַפְשְׁכֶ֑ם וּקְשַׁרְתֶּ֨ם אֹתָ֤ם לְאוֹת֙ עַל־יֶדְכֶ֔ם וְהָי֥וּ לְטוֹטָפֹ֖ת בֵּ֥ין עֵינֵיכֶֽם׃ וְלִמַּדְתֶּ֥ם אֹתָ֛ם אֶת־בְּנֵיכֶ֖ם לְדַבֵּ֣ר בָּ֑ם בְּשִׁבְתְּךָ֤ בְּבֵיתֶ֙ךָ֙ וּבְלֶכְתְּךָ֣ בַדֶּ֔רֶךְ וּֽבְשׇׁכְבְּךָ֖ וּבְקוּמֶֽךָ׃ וּכְתַבְתָּ֛ם עַל־מְזוּז֥וֹת בֵּיתֶ֖ךָ וּבִשְׁעָרֶֽיךָ׃ לְמַ֨עַן יִרְבּ֤וּ יְמֵיכֶם֙ וִימֵ֣י בְנֵיכֶ֔ם עַ֚ל הָֽאֲדָמָ֔ה אֲשֶׁ֨ר נִשְׁבַּ֧ע יְהֹוָ֛ה לַאֲבֹתֵיכֶ֖ם לָתֵ֣ת לָהֶ֑ם כִּימֵ֥י הַשָּׁמַ֖יִם עַל־הָאָֽרֶץ׃"}, {"kind": "text", "text": "<b>וַיֹּ֥אמֶר</b> (במדבר טו לז) יְהֹוָ֖ה אֶל־מֹשֶׁ֥ה לֵּאמֹֽר׃ דַּבֵּ֞ר אֶל־בְּנֵ֤י יִשְׂרָאֵל֙ וְאָמַרְתָּ֣ אֲלֵהֶ֔ם וְעָשׂ֨וּ לָהֶ֥ם צִיצִ֛ת עַל־כַּנְפֵ֥י בִגְדֵיהֶ֖ם לְדֹרֹתָ֑ם וְנָ֥תְנ֛וּ עַל־צִיצִ֥ת הַכָּנָ֖ף פְּתִ֥יל תְּכֵֽלֶת׃ וְהָיָ֣ה לָכֶם֮ לְצִיצִת֒ וּרְאִיתֶ֣ם אֹת֗וֹ יסתכל בציציות שבידיו, יעבירם על גבי עיניו וינשקם שתי פעמים וּזְכַרְתֶּם֙ אֶת־כׇּל־מִצְוֺ֣ת יְהֹוָ֔ה וַעֲשִׂיתֶ֖ם אֹתָ֑ם וְלֹֽא־תָת֜וּרוּ אַחֲרֵ֤י לְבַבְכֶם֙ וְאַחֲרֵ֣י עֵֽינֵיכֶ֔ם יעביר הציציות על גבי עיניו וינשקם אֲשֶׁר־אַתֶּ֥ם זֹנִ֖ים אַחֲרֵיהֶֽם׃ לְמַ֣עַן תִּזְכְּר֔וּ וַעֲשִׂיתֶ֖ם אֶת־כׇּל־מִצְוֺתָ֑י וִהְיִיתֶ֥ם קְדֹשִׁ֖ים לֵאלֹֽהֵיכֶֽם׃ אֲנִ֞י יְהֹוָ֣ה אֱלֹֽהֵיכֶ֗ם אֲשֶׁ֨ר הוֹצֵ֤אתִי אֶתְכֶם֙ מֵאֶ֣רֶץ מִצְרַ֔יִם לִהְי֥וֹת לָכֶ֖ם לֵאלֹהִ֑ים אֲנִ֖י יְהֹוָ֥ה אֱלֹהֵיכֶֽם׃ אֱמֶת."}, {"kind": "text", "text": "וחוזר החזן: יְהֹוָה אֱלֹהֵיכֶם אֱמֶת:"}, {"kind": "text", "text": "<b>וְיַצִּיב</b>, וְנָכוֹן, וְקַיָּם, וְיָשָׁר, וְנֶאֱמָן, וְאָהוּב, וְחָבִיב, וְנֶחְמָד, וְנָעִים, וְנוֹרָא, וְאַדִּיר, וּמְתוּקָן, וּמְקוּבל, וְטוֹב, וְיָפֶה, הַדָּבָר הַזֶּה עָלֵינוּ לְעולָם וָעֶד."}, {"kind": "text", "text": "אֱמֶת, אֱלֹהֵי עוֹלָם מַלְכֵּנוּ צוּר יַעֲקֹב מָגֵן יִשְׁעֵנוּ, לְדוֹר וָדוֹר הוּא קַיָּם, וּשְׁמוֹ קַיָּם, וְכִסְאוֹ נָכוֹן, וּמַלְכוּתו וֶאֱמוּנָתו לָעַד קַיֶּמֶת, וּדְבָרָיו חַיִּים וְקַיָּמִים, וְנֶאֱמָנִים וְנֶחֱמָדִים לָעַד ינשק הציציות שהיה אוחז בהם ויעבירם על גבי עיניו ויסירם מידו (בא\"ח שמות ה\"ח) וּלְעוֹלְמֵי עוֹלָמִים. עַל אֲבוֹתֵינוּ, עָלֵינוּ וְעַל בָּנֵינוּ וְעַל דּוֹרוֹתֵינוּ וְעַל כָּל דּוֹרוֹת זֶרַע יִשְׂרָאֵל עֲבָדֶיךָ. עַל הָרִאשׁוֹנִים וְעַל הָאַחֲרוֹנִים דָּבָר טוֹב וְקַיָּם בֶּאֱמֶת וֶאֱמוּנָה חוֹק וְלֹא יַעֲבוֹר. אֱמֶת שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ. מַלְכֵּנוּ מֶלֶךְ אֲבוֹתֵינוּ. גּוֹאֲלֵנוּ גּוֹאֵל אֲבוֹתֵינוּ. יוֹצְרֵנוּ צוּר יְשׁוּעָתֵנוּ. פּוֹדֵנוּ וּמַצִּילֵנוּ מֵעוֹלָם הוּא שְׁמֶךָ, וְאֵין לָנוּ עוֹד אֱלֹהִים זוּלָתְךָ סֶלָה:"}, {"kind": "text", "text": "<b>עֶזְרַת</b> אֲבוֹתֵינוּ אַתָּה הוּא מֵעוֹלָם, מָגֵן וּמושִׁיעַ לָהֶם וְלִבְנֵיהֶם אַחֲרֵיהֶם בְּכָל דּוֹר וָדוֹר, בְּרוּם עוֹלָם מוֹשָׁבֶךָ, וּמִשְׁפָּטֶיךָ, וְצִדְקָתְךָ עַד אַפְסֵי אָרֶץ, אֱמֶת אַשְׁרֵי אִישׁ שֶׁיִּשְׁמַע לְמִצְוֹתֶיךָ וְתוֹרָתְךָ וּדְבָרְךָ יָשִׂים עַל לִבּוֹ. אֱמֶת שֶׁאַתָּה הוּא אֲדוֹן לְעַמְּךָ וּמֶלֶךְ גִּבּוֹר לָרִיב רִיבָם לְאָבוֹת וּבָנִים, אֱמֶת אַתָּה הוּא רִאשׁוֹן וְאַתָּה הוּא אַחֲרוֹן וּמִבַּלְעָדֶיךָ אֵין לָנוּ מֶלֶךְ גּוֹאֵל וּמושִׁיעַ. אֱמֶת מִמִּצְרַיִם גְּאַלְתָּנוּ יְהֹוָה אֱלֹהֵינוּ, מִבֵּית עֲבָדִים פְּדִיתָנוּ, כָּל בְּכוֹרֵיהֶם הָרַגְתָּ, וּבְכוֹרְךָ יִשְׂרָאֵל גָּאַלְתָּ, וְיָם סוֹף לָהֶם בָּקַעְתָּ, וְזֵדִים טִבַּעְתָּ, וִידִידִים עָבְרוּ יָם. וַיְכַסּוּ מַיִם צָרֵיהֶם אֶחָד מֵהֶם לֹא נוֹתַר. עַל זֹאת שִׁבְּחוּ אֲהוּבִים, וְרוֹמְמוּ לָאֵל, וְנָתְנוּ יְדִידִים זְמִירוֹת שִׁירוֹת וְתִשְׁבָּחוֹת בְּרָכוֹת וְהוֹדָאוֹת לַמֶּלֶךְ אֶל חַי וְקַיָּם, רָם וְנִשָּׂא, גָּדוֹל וְנוֹרָא, מַשְׁפִּיל גֵּאִים עֲדֵי אָרֶץ, מַגְבִּיהַּ שְׁפָלִים עַד מָרוֹם, מוֹצִיא אֲסִירִים, פּוֹדֶה עֲנָוִים, עוֹזֵר דַּלִּים, הָעוֹנֶה לְעַמּוֹ יִשְׂרָאֵל בְּעֵת שַׁוְּעָם אֵלָיו."}, {"kind": "instruction", "text": "תכף בתחלת מלת תהלות יקום לעמוד ויסיים מלת תהלות מעומד (בא\"ח שמות ה\"ח)"}, {"kind": "text", "text": "<b>תְהִילוֹת</b> לָאֵל עֶלְיוֹן גּוֹאֲלָם, בָּרוּךְ הוּא וּמְבוֹרָךְ, מֹשֶׁה וּבְנֵי יִשְׂרָאֵל לְךָ עָנוּ שִׁירָה בְשִׂמְחָה רַבָּה, וְאָמְרוּ כֻלָּם: מִֽי־כָמֹ֤כָה בָּֽאֵלִם֙ יְהֹוָ֔ה מִ֥י כָּמֹ֖כָה נֶאְדָּ֣ר בַּקֹּ֑דֶשׁ נוֹרָ֥א תְהִלֹּ֖ת עֹ֥שֵׂה פֶֽלֶא׃ שִׁירָה חֲדָשָׁה שִׁבְּחוּ גְאוּלִים לְשִׁמְךָ הַגָּדוֹל עַל שְׂפַת הַיָּם, יַחַד כֻלָּם הוֹדוּ וְהִמְלִיכוּ וְאָמְרוּ: יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד׃ וְנֶאֱמַר: גֹּאֲלֵ֕נוּ יְהֹוָ֥ה צְבָא֖וֹת שְׁמ֑וֹ קְד֖וֹשׁ יִשְׂרָאֵֽל׃ בָּרוּךְ אַתָּה יְהֹוָה גָּאַל יִשְׂרָאֵל:"}, {"kind": "header", "text": "עמידה לשחרית של שבת קודש"}, {"kind": "text", "text": "<b>אֲ֭דֹנָי</b> שְׂפָתַ֣י תִּפְתָּ֑ח וּ֝פִ֗י יַגִּ֥יד תְּהִלָּתֶֽךָ׃"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵֽאלֹהֵי יַעֲקֹב. הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, קוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵּי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַֽעַן שְׁמוֹ בְּאַֽהֲבָה: בשבת תשובה אומרים: זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, כָּתְבֵנוּ בְּסֵפֶר חַיִּים, לְמַעַנָךְ אֱלֹהִים חַיִּים. מֶֽלֶךְ עוֹזֵר וּמוֹשִֽׁיעַ וּמָגֵן: בָּרוּךְ אַתָּה יַהַוַהַ, מָגֵן אַבְרָהָם:"}, {"kind": "text", "text": "<b>אַתָּה</b> גִבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֶּה מֵתִים אַתָּה, רַב לְהוֹשִֽׁיעַ."}, {"kind": "text", "text": "בקיץ: מוֹרִיד הַטָּל. בחורף: מַשִּׁיב הָרֽוּחַ וּמוֹרִיד הַגֶּֽשֶׁם."}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶֽסֶד, מְחַיֵּה מֵתִים בְּרַֽחֲמִים רַבִּים, סוֹמֵךְ נֽוֹפְלִים, וְרוֹפֵא חוֹלִים, וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמֽוּנָתוֹ לִֽישֵׁנֵי עָפָר. מִי כָמֽוֹךָ בַּֽעַל גְּבוּרוֹת, וּמִי דֽוֹמֶה לָךְ, מֶֽלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִֽיחַ יְשׁוּעָה. בשבת תשובה אומרים: מִי כָמוֹךָ אָב הָרַחֲמָן, זוֹכֵר יְצוּרָיו בְּרַחֲמִים לְחַיִּים. וְנֶֽאֱמָן אַתָּה לְהַֽחֲיוֹת מֵתִים: בָּרוּךְ אַתָּה יֵהֵוֵהֵ, מְחַיֵּה הַמֵּתִים:"}, {"kind": "instruction", "text": "קדושה בחזרת הש\"ץ: אומרים:"}, {"kind": "instruction", "text": "נַקְדִּישָׁךְ וְנַעֲרִיצָךְ, כְּנֹֽעַם שִֽׂיחַ סוֹד שַׂרְפֵי קֹֽדֶשׁ, הַמְשַׁלְּשִׁים לְךָ קְדֻשָּׁה, וְכֵן כָּתוּב עַל יַד נְבִיאָךְ: וְקָרָ֨א זֶ֤ה אֶל־זֶה֙ וְאָמַ֔ר קָד֧וֹשׁ ׀ קָד֛וֹשׁ קָד֖וֹשׁ יְהֹוָ֣ה צְבָא֑וֹת מְלֹ֥א כָל־הָאָ֖רֶץ כְּבוֹדֽוֹ׃ לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים: בָּר֥וּךְ כְּבוֹד־יְהֹוָ֖ה מִמְּקוֹמֽוֹ׃ וּבְדִבְרֵי קָדְשָׁךְ כָּתוּב לֵאמֹר: יִמְלֹ֤ךְ יְהֹוָ֨ה ׀ לְעוֹלָ֗ם אֱלֹהַ֣יִךְ צִ֭יּוֹן לְדֹ֥ר וָדֹ֗ר הַֽלְלוּיָֽהּ:"}, {"kind": "text", "text": "<b>אַתָּה</b> קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ, וּקְדוֹשִׁים בְּכָל־יוֹם יְהַֽלְלֽוּךָ סֶּֽלָה: בָּרוּךְ אַתָּה יֹהֵוָהֵ, הָאֵל הַקָּדוֹשׁ: בשבת תשובה אומרים: הַמֶּלֶךְ הַקָּדוֹשׁ:"}, {"kind": "text", "text": "<b>יִשְׂמַח</b> מֹשֶׁה בְּמַתְּנַת חֶלְקוֹ, כִּי עֶבֶד נֶאֱמָן קָרָאתָ לּוֹ. כְּלִיל תִּפְאֶרֶת בּרֹאשׁוֹ נָתַתָּ, בְּעָמְדוֹ לְפָנֶיךָ עַל־הַר סִינַי. שְׁנֵי לוּחוֹת אֲבָנִים הוֹרִיד בְּיָדוֹ, וְכָתוּב בָּהֶם שְׁמִירַת שַׁבָּת, וְכֵן כָּתוּב בְּתוֹרָתָךְ:"}, {"kind": "text", "text": "<b>וְשָׁמְר֥וּ</b> בְנֵֽי־יִשְׂרָאֵ֖ל אֶת־הַשַּׁבָּ֑ת לַעֲשׂ֧וֹת אֶת־הַשַּׁבָּ֛ת לְדֹרֹתָ֖ם בְּרִ֥ית עוֹלָֽם׃ בֵּינִ֗י וּבֵין֙ בְּנֵ֣י יִשְׂרָאֵ֔ל א֥וֹת הִ֖וא לְעֹלָ֑ם כִּי־שֵׁ֣שֶׁת יָמִ֗ים עָשָׂ֤ה יְהֹוָה֙ אֶת־הַשָּׁמַ֣יִם וְאֶת־הָאָ֔רֶץ וּבַיּוֹם֙ הַשְּׁבִיעִ֔י שָׁבַ֖ת וַיִּנָּפַֽשׁ׃"}, {"kind": "text", "text": "<b>וְלֹא</b> נְתַתּוֹ יְהֹוָה אֱלֹהֵינוּ לְגוֹיֵי הָאֲרָצוֹת, וְלֹא הִנְחַלְתּוֹ מַלְכֵּנוּ לְעוֹבְדֵי אֱלִילִים, גַּם בִּמְנוּחָתוֹ לֹא יִשְׁכְּנוּ עֲרֵלִים, כִּי לְעַמְּךָ יִשְׂרָאֵל נְתַתּוֹ בְּאַהֲבָה, לְזֶרַע יַעֲקֹב אֲשֶׁר בָּם בָּחָרְתָּ:"}, {"kind": "text", "text": "<b>יִשְׂמְחוּ</b> בְמַלְכוּתָךְ שׁוֹמְרֵי שַׁבָּת וְקוֹרְאֵי עֹנֶג, עַם מְקַדְּשֵׁי שְׁבִיעִי, כֻּלָּם יִשְׂבְּעוּ וְיִתְעַנְּגוּ מִטּוּבֶךְ, וְהַשְּׁבִיעִי רָצִיתָ בּוֹ וְקִדַּשְׁתּוֹ, חֶמְדַּת יָמִים אוֹתוֹ קָרָאתָ:"}, {"kind": "text", "text": "<b>אֱלֹהֵינוּ</b> וֵאלֹהֵי אֲבוֹתֵינוּ, רְצֵה נָא בִּמְנוּחָתֵנוּ, קַדְּשֵׁנוּ בְּמִצְוֹתֶיךָ, שִׂים חֶלְקֵנוּ בְּתוֹרָתָךְ, שַׂבְּעֵנוּ מִטּוּבָךְ, שַׂמֵּחַ נַפְשֵׁנוּ בִּישׁוּעָתָךְ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶאֱמֶת, וְהַנְחִילֵנוּ יְהֹוָה אֱלֹהֵינוּ בְּאַהֲבָה וּבְרָצוֹן שַׁבָּת קָדְשֶׁךָ, וְיָנוּחוּ בוֹ כָּל־יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יְהֹוָה, מְקַדֵּשׁ הַשַּׁבָּת:"}, {"kind": "text", "text": "<b>רְצֵה</b> יְהֹוָה אֱלֹהֵֽינוּ בְּעַמְּךָ יִשְׂרָאֵל וְלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב הָֽעֲבוֹדָה לִדְבִיר בֵּיתֶֽךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, מְהֵרָה בְּאַֽהֲבָה תְקַבֵּל בְּרָצוֹן, וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּֽךָ:"}, {"kind": "instruction", "text": "בראש חודש ובחול המועד מוסיפים:"}, {"kind": "instruction", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּֽיעַ וְיֵרָאֶה, וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵֽנוּ וְזִכְרוֹן אֲבוֹתֵֽינוּ, זִכְרוֹן יְרוּשָׁלַֽיִם עִירָךְ, וְזִכְרוֹן מָשִֽׁיחַ בֶּן־דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל־עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶֽיךָ, לִפְלֵיטָה, לְטוֹבָה, לְחֵן, לְחֶֽסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם, בְּיוֹם"}, {"kind": "text", "text": "בראש חדש: רֹאשׁ חֹֽדֶשׁ הַזֶּה,"}, {"kind": "text", "text": "בחוה\"מ פסח: חַג הַמַּצּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹֽדֶשׁ הַזֶּה,"}, {"kind": "text", "text": "בחוה\"מ סוכות: חַג הַסֻּכּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹֽדֶשׁ הַזֶּה,"}, {"kind": "instruction", "text": "לְרַחֵם בּוֹ עָלֵֽינוּ וּלְהוֹשִׁיעֵֽנוּ. זָכְרֵֽנוּ יְהֹוָה אֱלֹהֵֽינוּ בּוֹ לְטוֹבָה, וּפָקְדֵֽנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵֽנוּ בוֹ לְחַיִּים טוֹבִים, בִּדְבַר יְשׁוּעָה וְרַחֲמִים. חוּס וְחָנֵּֽנוּ, וַחֲמוֹל וְרַחֵם עָלֵֽינוּ, וְהוֹשִׁיעֵֽנוּ כִּי אֵלֶֽיךָ עֵינֵֽינוּ, כִּי אֵל מֶֽלֶךְ חַנּוּן וְרַחוּם אָֽתָּה:"}, {"kind": "text", "text": "<b>וְאַתָּה</b> בְּרַֽחֲמֶֽיךָ הָרַבִּים, תַּחְפֹּץ בָּֽנוּ וְתִרְצֵֽנוּ, וְתֶֽחֱזֶֽינָה עֵינֵֽינוּ בְּשֽׁוּבְךָ לְצִיּוֹן בְּרַֽחֲמִים: בָּרוּךְ אַתָּה יִהִוִהִ, הַמַּֽחֲזִיר שְׁכִֽינָתוֹ לְצִיּוֹן:"}, {"kind": "instruction", "text": "בברכת \"מודים\" יכרע ב\"מודים\" ויזקוף בשם (בא\"ח בשלח הכ\"א)"}, {"kind": "text", "text": "<b>מוֹדִים</b> אֲנַֽחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ לְעוֹלָם וָעֶד, צוּרֵֽנוּ צוּר חַיֵּֽינוּ וּמָגֵן יִשְׁעֵֽנוּ אַתָּה הוּא, לְדוֹר וָדוֹר נוֹדֶה לְךָ וּנְסַפֵּר תְּהִלָּתֶֽךָ, עַל חַיֵּֽינוּ הַמְּסוּרִים בְּיָדֶֽךָ, וְעַל נִשְׁמוֹתֵֽינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּֽיךָ שֶׁבְּכָל־יוֹם עִמָּֽנוּ, וְעַל נִפְלְאוֹתֶֽיךָ וְטֽוֹבוֹתֶֽיךָ שֶׁבְּכָל־עֵת, עֶֽרֶב וָבֹֽקֶר וְצָֽהֳרָֽיִם. הַטּוֹב, כִּי לֹא כָלוּ רַחֲמֶֽיךָ, הַמְּרַחֵם, כִּי לֹא תַֽמּוּ חֲסָדֶֽיךָ, כִּי מֵֽעוֹלָם קִוִּֽינוּ לָךְ:"}, {"kind": "text", "text": "<b>מודים דרבנן</b><br>בחזרת הש\"ץ כשהחזן אומר מודים, הקהל אומרים:<br>מוֹדִים אֲנַחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׁר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית. בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְחָנֵּנוּ וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמֹר חֻקֶּיךָ וְלַעֲשׂוֹת רְצוֹנְךָ וּלְעָבְדְךָ בְלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ, בָּרוּךְ אֵל הַהוֹדָאוֹת."}, {"kind": "instruction", "text": "בחנוכה ופורים אומרים:"}, {"kind": "instruction", "text": "עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת שֶׁעָשִֽׂיתָ לַאֲבוֹתֵֽינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה:"}, {"kind": "text", "text": "בחנוכה אומרים: <b>בִּימֵי מַתִּתְיָה</b> בֶן־יוֹחָנָן כֹּהֵן גָּדוֹל. חַשְׁמוֹנָאִי וּבָנָיו כְּשֶׁעָֽמְדָֽה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל. לְשַׁכְּחָם תּוֹרָתָךְ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנָךְ. וְאַתָּה בְּרַחֲמֶֽיךָ הָרַבִּים עָמַֽדְתָּ לָהֶם בְּעֵת צָרָתָם. רַֽבְתָּ אֶת רִיבָם. דַּֽנְתָּ אֶת דִּינָם. נָקַֽמְתָּ אֶת נִקְמָתָם. מָסַֽרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים. וְרַבִּים בְּיַד מְעַטִּים. וּרְשָׁעִים בְּיַד צַדִּיקִים. וּטְמֵאִים בְּיַד טְהוֹרִים. וְזֵדִים בְּיַד עֽוֹסְקֵֽי תוֹרָתֶֽךָ. לְךָ עָשִֽׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמָךְ. וּלְעַמְּךָ יִשְׂרָאֵל עָשִֽׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כָּךְ בָּֽאוּ בָנֶֽיךָ לִדְבִיר בֵּיתֶֽךָ. וּפִנּוּ אֶת־הֵיכָלֶֽךָ. וְטִהֲרוּ אֶת־מִקְדָּשֶֽׁךָ. וְהִדְלִֽיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶֽׁךָ. וְקָֽבְעֽוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵֽלּוּ בְּהַלֵּל וּבְהוֹדָאָה. וְעָשִֽׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶֽלָה:"}, {"kind": "text", "text": "בפורים אומרים <b>בִּימֵי מָרְדְּכַי</b> וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה. כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע. בִּקֵּשׁ לְהַשְׁמִיד לַהֲרֹג וּלְאַבֵּד אֶת־כָּל־הַיְּהוּדִים מִנַּֽעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד. בִּשְׁלֹשָׁה עָשָׂר לְחֹֽדֶשׁ שְׁנֵים עָשָׂר. הוּא חֹֽדֶשׁ אֲדָר. וּשְׁלָלָם לָבוֹז. וְאַתָּה בְּרַחֲמֶֽיךָ הָרַבִּים הֵפַֽרְתָּ אֶת־עֲצָתוֹ וְקִלְקַֽלְתָּ אֶת־מַחֲשַׁבְתּוֹ. וַהֲשֵׁבֽוֹתָ לּוֹ גְּמוּלוֹ בְרֹאשׁוֹ. וְתָלוּ אוֹתוֹ וְאֶת־בָּנָיו עַל הָעֵץ. וְעָשִֽׂיתָ עִמָּהֶם נֵס וָפֶֽלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶֽלָה:"}, {"kind": "text", "text": "<b>וְעַל</b> כֻּלָּם יִתְבָּרַךְ, וְיִתְרוֹמָם, וְיִתְנַשֵּׂא, תָּמִיד, שִׁמְךָ מַלְכֵּֽנוּ, לְעוֹלָם וָעֶד. וְכָל־הַחַיִּים יוֹדֽוּךָ סֶּֽלָה: בשבת תשובה אומרים: וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ. וִֽיהַֽלְלוּ וִֽיבָֽרְכוּ אֶת־שִׁמְךָ הַגָּדוֹל בֶּֽאֱמֶת לְעוֹלָם כִּי טוֹב, הָאֵל יְשֽׁוּעָתֵֽנוּ וְעֶזְרָתֵֽנוּ סֶֽלָה, הָאֵל הַטּוֹב: בָּרוּךְ אַתָּה יֻהֻוֻהֻ, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת:"}, {"kind": "text", "text": "ברכת כהנים"}, {"kind": "text", "text": "כשעוקר הכהן רגליו לישא כפיו יאמר (בא\"ח תצוה י\"ב)<br>לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ. בִּדְחִֽילוּ וּרְחִֽימוּ. וּרְחִֽימוּ וּדְחִֽילוּ. לְיַחֲדָא שֵׁם יוֹ\"ד קֵ\"א בְּוָא\"ו קֵ\"א בְּיִחוּדָא שְׁלִים. בְּשֵׁם כָּל־יִשְׂרָאֵל הִנֵּה אָנֹכִי מוּכָן וּמְזוּמָן לְקַיֵּם מִצְוַת עֲשֵׂה לְבָרֵךְ אֶת יִשְׂרָאֵל בִּרְכַּת כֹּהַנִים בִּנְשִׂיאוּת כַּפַּיִם, לַעֲשׂוֹת נַֽחַת רֽוּחַ לְיֽוֹצְרֵֽנוּ וּלְהַמְשִׁיךְ שֶׁפַע וּבְרָכָה לְכָל־הָעוֹלָמוֹת וְלַעֲשׂוֹת רְצוֹן בּֽוֹרְאֵֽנוּ. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ:"}, {"kind": "text", "text": "וכשעומדים הכהנים על הדוכן לאחר שענו \"מודים דרבנן\", אומרים<br>יְהִי רָצוֹן מִלְּפָנֶֽיךָ יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ שֶׁתִּהְיֶה בְּרָכָה זוֹ שֶׁצִּּוִיתָֽנוּ לְבָרֵךְ אֶת־עַמְּךָ יִשְׂרָאֵל בְּרָכָה שְׁלֵמָה וְלֹא יִהְיֶה בָהּ מִכְשׁוֹל וְעָוֹן מֵעַתָּה וְעַד עוֹלָם:"}, {"kind": "text", "text": "בחזרת הש\"ץ אומרים ברכת כהנים, אם יש יותר מכהן אחד קורא להם החזן: כֹּהֲנִים: הכהנים מברכים:<br>בָּרוּךְ אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָֽעוֹלָם, אֲשֶׁר קִדְּשָֽׁנוּ בִּקְדֻשָּׁתוֹ שֶׁל־אַֽהֲרֹן, וְצִוָּֽנוּ לְבָרֵךְ אֶת־עַמּוֹ יִשְׂרָאֵל בְּאַֽהֲבָה: הקהל עונים אָמֵן:"}, {"kind": "instruction", "text": "ואומר החזן והכהנים אחריו מילה במילה:"}, {"kind": "text", "text": "יְבָרֶכְךָ֥ יְהֹוָ֖ה וְיִשְׁמְרֶֽךָ׃ ועונים אָמֵן:"}, {"kind": "text", "text": "יָאֵ֨ר יְהֹוָ֧ה ׀ פָּנָ֛יו אֵלֶ֖יךָ וִֽיחֻנֶּֽךָּ׃ ועונים אָמֵן:"}, {"kind": "text", "text": "יִשָּׂ֨א יְהֹוָ֤ה ׀ פָּנָיו֙ אֵלֶ֔יךָ וְיָשֵׂ֥ם לְךָ֖ שָׁלֽוֹם׃ ועונים אָמֵן:"}, {"kind": "instruction", "text": "וכשמתחיל שליח ציבור \"שים שלום\" אז מחזירין פניהם כלפי ההיכל, ולא יחזירו פניהם קודם, ואז הכהנים אומרים<br>רִבּוֹן הָעוֹלָמִים עָשִֽׂינוּ מַה־שֶּׁגָּזַֽרְתָּ עָלֵֽינוּ, עַשֵׂה אַתָּה מַה־שֶּׁהִבְטָחְתָּֽנוּ. הַשְׁקִ֩יפָה֩ מִמְּע֨וֹן קׇדְשְׁךָ֜ מִן־הַשָּׁמַ֗יִם וּבָרֵ֤ךְ אֶֽת־עַמְּךָ֙ אֶת־יִשְׂרָאֵ֔ל:"}, {"kind": "text", "text": "אם אין עולים כהנים אומר החזן:<br><b>אֱלֹהֵינוּ</b> וֵאלֹהֵי אֲבוֹתֵינוּ, בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶת בַּתּוֹרָה הַכְּתוּבָה עַל יְדֵי מֹשֶׁה עַבְדֶּֽךָ, הָאֲמוּרָה מִפִּי אַהֲרֹן וּבָנָיו הַכֹּהֲנִים עַם קְדוֹשֶׁיךָ כָּאָמוּר:"}, {"kind": "instruction", "text": "יְבָרֶכְךָ֥ יְהֹוָ֖ה וְיִשְׁמְרֶֽךָ׃ ועונים כן יהי רצון:"}, {"kind": "instruction", "text": "יָאֵ֨ר יְהֹוָ֧ה ׀ פָּנָ֛יו אֵלֶ֖יךָ וִֽיחֻנֶּֽךָּ׃ ועונים כן יהי רצון:"}, {"kind": "text", "text": "יִשָּׂ֨א יְהֹוָ֤ה ׀ פָּנָיו֙ אֵלֶ֔יךָ וְיָשֵׂ֥ם לְךָ֖ שָׁלֽוֹם׃ ועונים כֵּן יְהִי רָצוֹן: וְשָׂמ֥וּ אֶת־שְׁמִ֖י עַל־בְּנֵ֣י יִשְׂרָאֵ֑ל וַאֲנִ֖י אֲבָרְכֵֽם:"}, {"kind": "text", "text": "<b>שִׂים</b> שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים חֵן וָחֶֽסֶד וְרַֽחֲמִים, עָלֵֽינוּ וְעַל כָּל־יִשְׂרָאֵל עַמֶּֽךָ. וּבָֽרְכֵֽנוּ אָבִֽינוּ כֻּלָּֽנוּ כְּאֶחָד בְּאוֹר פָּנֶֽיךָ, כִּי בְאוֹר פָּנֶֽיךָ נָתַֽתָּ לָּֽנוּ יְהֹוָה אֱלֹהֵֽינוּ תּוֹרָה וְחַיִּים, אַֽהֲבָה וָחֶֽסֶד, צְדָקָה וְרַֽחֲמִים, בְּרָכָה וְשָׁלוֹם. וְטוֹב בְּעֵינֶֽיךָ לְבָֽרְכֵֽנוּ וּלְבָרֵךְ אֶת־כָּל־עַמְּךָ יִשְׂרָאֵל, בְּרֹב עֹז וְשָׁלוֹם: בשבת תשובה אומרים: וּבְסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה וִישׁוּעָה וְנֶחָמָה, וּגְזֵרוֹת טוֹבוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם. בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמְּבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם. אָמֵן:"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>אֱלֹהַי</b>, נְצֹר לְשׁוֹנִי מֵרָע וְשִׂפְתוֹתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּֽעָפָר לַכֹּל תִּֽהְיֶה, פְּתַח לִבִּי בְּתוֹרָתֶֽךָ, וְאַחֲרֵי מִצְוֹתֶֽיךָ תִּרְדֹּף נַפְשִׁי. וְכָל־הַקָּמִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחְשְׁבוֹתָם. יִֽהְי֗וּ כְּמֹ֥ץ לִפְנֵי־ר֑וּחַ וּמַלְאַ֖ךְ יְהֹוָ֣ה דּוֹחֶֽה. קַבֵּל רִנַּת עַמֶּךָ. שַׂגְּבֵנוּ טַהֲרֵנוּ נוֹרָא. עֲשֵׂה לְמַֽעַן שְׁמָךְ, עֲשֵׂה לְמַֽעַן יְמִינָךְ, עֲשֵׂה לְמַֽעַן תּֽוֹרָתָךְ, עֲשֵׂה לְמַֽעַן קְדֻשָּׁתָךְ."}, {"kind": "text", "text": "סגולה לומר פסוק המתחיל וגומר באות שמתחיל וגומר שמו לְ֭מַעַן יֵחָלְצ֣וּן יְדִידֶ֑יךָ הוֹשִׁ֖יעָה יְמִֽינְךָ֣ וַעֲנֵֽנִי:"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>עֹשֶׂה</b> שָׁלוֹם בשבת תשובה אומרים: הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵֽינוּ, וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן:"}, {"kind": "instruction", "text": "יְהִי רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְּיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ, לַעֲשׂוֹת חֻקֵּי רְצוֹנָךְ וּלְעָבְדָךְ בְּלֵבָב שָׁלֵם:"}, {"kind": "instruction", "text": "אבינו מלכנו בשבת תשובה אומרים:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ חַדֵּשׁ עָלֵינוּ שָׁנָה טוֹבָה:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ בַּטֵּל מֵעָלֵינוּ כָּל־גְּזֵרוֹת קָשׁוֹת וְרָעוֹת:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ בַּטֵּל מַחְשְׁבוֹת שֹׂנְאֵינוּ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ הָפֵר עֲצַת אוֹיְבֵינוּ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָה וְרָעָב וּשְׁבִי וּבִזָּה וּמַשְׁחִית וּמַגֵּפָה וְיֵצֶר הָרָע וְחוֹלָאִים רָעִים מִבְּנֵי בְרִיתֶךָ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ שְׁלַח רְפוּאָה שְׁלֵמָה לְכָל־חוֹלֵי עַמֶּךָ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ זָכוּר כִּי עָפָר אֲנָחְנוּ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ קְרַע רוֹעַ גְּזַר דִּינֵנוּ: (יכוין בשם קר\"ע שט\"ן)"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ כָּתְבֵנוּ בְּסֵפֶר צַדִּיקִים וַחֲסִידִים:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ כָּתְבֵנוּ בְּסֵפֶר יְשָׁרִים וּתְמִימִים:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה טוֹבָה:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ זָכְרֵנוּ בְּזִכְרוֹן טוֹב מִלְּפָנֶיךָ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוֹב:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ וְהָרֵם קֶרֶן מְשִׁיחֶךָ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ חָנֵּנוּ וַעֲנֵנוּ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ הַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ שְׁמַע קוֹלֵנוּ חוּס וְרַחֵם עָלֵינוּ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ עֲשֵׂה לְמַעֲנָךְ אִם לֹא לְמַעֲנֵנוּ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ קַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ:"}, {"kind": "instruction", "text": "אָבִינוּ מַלְכֵּנוּ אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ:"}, {"kind": "text", "text": "<b>יְהִ֤י</b> שֵׁ֣ם יְהֹוָ֣ה מְבֹרָ֑ךְ מֵ֝עַתָּ֗ה וְעַד־עוֹלָֽם׃ מִמִּזְרַח־שֶׁ֥מֶשׁ עַד־מְבוֹא֑וֹ מְ֝הֻלָּ֗ל שֵׁ֣ם יְהֹוָֽה׃ רָ֖ם עַל־כׇּל־גּוֹיִ֥ם ׀ יְהֹוָ֑ה עַ֖ל הַשָּׁמַ֣יִם כְּבוֹדֽוֹ׃ יְהֹוָ֥ה אֲדֹנֵ֑ינוּ מָה־אַדִּ֥יר שִׁ֝מְךָ֗ בְּכׇל־הָאָֽרֶץ׃"}, {"kind": "instruction", "text": "בשבת ר\"ח או חול המועד או חנוכה אומרים הלל לפני הקדיש"}, {"kind": "instruction", "text": "ואומר החזן קדיש תתקבל"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "תִּתְקַבַּל צְלוֹתָֽנָא וּבָֽעוּתָֽנָא, עִם צְלֽוֹתְהוֹן וּבָעֽוּתְהוֹן דְּכָל־בֵּית יִשְׂרָאֵל, קֳדָם אֲבוּנָא דְּבִשְׁמַיָּא וְאַרְעָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא. חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה. וְשֵׁיזָבָא וּרְפוּאָה וּגְאוּלָה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "יפסע שלש פסיעות לאחור<br>עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו. הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "header", "text": "סדר קריאת התורה בשבת"}, {"kind": "instruction", "text": "בעת פתיחת ההיכל אומרים, וביו\"ט שאינו בשבת מדלגים שני הפסוקים הראשונים ומתחילים מיהי ה'"}, {"kind": "text", "text": "<b>אַתָּה֙</b> הׇרְאֵ֣תָ לָדַ֔עַת כִּ֥י יְהֹוָ֖ה ה֣וּא הָאֱלֹהִ֑ים אֵ֥ין ע֖וֹד מִלְּבַדּֽוֹ׃ אֵין־כָּמ֖וֹךָ בָאֱלֹהִ֥ים ׀ אֲדֹנָ֗י וְאֵ֣ין כְּֽמַעֲשֶֽׂיךָ׃"}, {"kind": "text", "text": "יְהִ֨י יְהֹוָ֤ה אֱלֹהֵ֙ינוּ֙ עִמָּ֔נוּ כַּאֲשֶׁ֥ר הָיָ֖ה עִם־אֲבֹתֵ֑ינוּ אַל־יַעַזְבֵ֖נוּ וְאַֽל־יִטְּשֵֽׁנוּ׃ הוֹשִׁ֤יעָה ׀ אֶת־עַמֶּ֗ךָ וּבָרֵ֥ךְ אֶת־נַחֲלָתֶ֑ךָ וּֽרְעֵ֥ם וְ֝נַשְּׂאֵ֗ם עַד־הָעוֹלָֽם׃ וַיְהִ֛י בִּנְסֹ֥עַ הָאָרֹ֖ן וַיֹּ֣אמֶר מֹשֶׁ֑ה קוּמָ֣ה ׀ יְהֹוָ֗ה וְיָפֻ֙צוּ֙ אֹֽיְבֶ֔יךָ וְיָנֻ֥סוּ מְשַׂנְאֶ֖יךָ מִפָּנֶֽיךָ׃ קוּמָ֣ה יְ֭הֹוָה לִמְנוּחָתֶ֑ךָ אַ֝תָּ֗ה וַאֲר֥וֹן עֻזֶּֽךָ׃ כֹּהֲנֶ֥יךָ יִלְבְּשׁוּ־צֶ֑דֶק וַחֲסִידֶ֥יךָ יְרַנֵּֽנוּ׃ בַּֽ֭עֲבוּר דָּוִ֣ד עַבְדֶּ֑ךָ אַל־תָּ֝שֵׁ֗ב פְּנֵ֣י מְשִׁיחֶֽךָ׃"}, {"kind": "instruction", "text": "פותחים ההיכל"}, {"kind": "instruction", "text": "אומרים בריך שמיה שכתוב בזוהר פרשת ויקהל דף ר\"ו"}, {"kind": "text", "text": "<b>בְּרִיךְ שְׁמֵהּ</b> דְּמָארֵי עָלְמָא, בְּרִיךְ כִּתְרָךְ וְאַתְרָךְ. יְהֵא רְעוּתָךְ, עִם עַמָּךְ יִשְׂרָאֵל לְעָלַם, וּפוּרְקַן יְמִינָךְ אַחְזֵי לְעַמָּךְ בְּבֵית מִקְדָּשָׁךְ, לְאַמְטוּיֵי לָנָא מִטּוּב נְהוֹרָךְ, וּלְקַבְּלָא צְלוֹתָנָא בְּרַחֲמֵי. יְהֵא רַעֲוָא קֳדָמָךְ דְּתוֹרִיךְ לָן חַיִּין בּטִיבוּ, וְלֶהֱוֵי אֲנָא עַבְדָּךְ פְּקִידָא בְּגוֹ צַדִּיקַיָּא, לְמִרְחַם עָלַי וּלְמִנְטַר יָתִי, וְיַת כּל דִּי לִי, וְדִי לְעַמָּךְ יִשְׂרָאֵל. אַנְתְּ הוּא זָן לְכֹלָא וּמְפַרְנֵס לְכֹלָא. אַנְתְּ הוּא שַׁלִּיט עַל כֹּלָא, אַנְתְּ הוּא דְשַׁלִּיט עַל מַלְכַיָּא, וּמַלְכוּתָא דִילָךְ הִיא. אֲנָא עַבְדָּא דְקֻדְשָׁא בְּרִיךְ הוּא, דְסָגִידְנָא קַמֵּהּ מִקַמֵּי דִּיקַר אוֹרַיְתֵהּ בְּכל עִידָּן וְעִידָּן. לָא עַל אֱנָשׁ רָחִיצְנָא, וְלָא עַל בַּר אֱלָהִין סְמִיכְנָא, אֶלָּא בֵאלָהָא דִשְׁמַיָּא, דְּהוּא אֱלָהָא דִקְשׁוֹט, וְאוֹרַיְתֵהּ קְשׁוֹט, וּנְבִיאוֹהִי קְשׁוֹט, וּמַסְגֵּי לְמֶעְבַּד טַבְוָן וּקְשׁוֹט, בֵּהּ אֲנָא רְחִיץ וְלִשְׁמֵהּ יַקִּירָא קַדִּישָׁא אֲנָא אֵמַר תֻּשְׁבְּחָן. יְהֵא רַעֲוָא קֳדָמָךְ דְּתִפְתַּח לִבִּי בְּאוֹרַיְתָךְ, (וְתִיהַב לִי בְּנִין דִּכְרִין דְּעַבְדִּין רְעוּתָךְ) וְתַשְׁלִים מִשְׁאֲלִין דְּלִבָּאי וְלִבָּא דכל עַמָּךְ יִשְׂרָאֵל לְטַב וּלְחַיִּין וְלִשְׁלָם אָמֵן:"}, {"kind": "instruction", "text": "מוציאים ספר תורה ואומרים"}, {"kind": "text", "text": "<b>צְאֶ֧נָה</b> ׀ וּֽרְאֶ֛ינָה בְּנ֥וֹת צִיּ֖וֹן בַּמֶּ֣לֶךְ שְׁלֹמֹ֑ה בָּעֲטָרָ֗ה שֶׁעִטְּרָה־לּ֤וֹ אִמּוֹ֙ בְּי֣וֹם חֲתֻנָּת֔וֹ וּבְי֖וֹם שִׂמְחַ֥ת לִבּֽוֹ׃"}, {"kind": "text", "text": "בָּרוּךְ הַמָּקוֹם שֶׁנָּתַן תּוֹרָה לְעַמּוֹ יִשְׂרָאֵל, בָּרוּךְ הוּא: אַשְׁרֵי הָעָם שֶׁכָּכָה לּוֹ, אַשְׁרֵי הָעָם שֶׁיְהֹוָה אֱלֹהָיו:"}, {"kind": "instruction", "text": "מוליכים ספר תורה לתיבה ואומרים"}, {"kind": "text", "text": "<b>גַּדְּל֣וּ</b> לַיהֹוָ֣ה אִתִּ֑י וּנְרוֹמְמָ֖ה שְׁמ֣וֹ יַחְדָּֽו׃ רוֹמְמ֡וּ יְהֹ֘וָ֤ה אֱלֹהֵ֗ינוּ וְֽ֭הִשְׁתַּחֲווּ לַהֲדֹ֥ם רַגְלָ֗יו קָד֥וֹשׁ הֽוּא׃"}, {"kind": "text", "text": "רוֹמְמ֡וּ יְהֹ֘וָ֤ה אֱלֹהֵ֗ינוּ וְֽ֭הִשְׁתַּחֲווּ לַהֲדֹ֥ם רַגְלָ֗יו קָד֥וֹשׁ הֽוּא׃"}, {"kind": "text", "text": "אֵין־קָד֥וֹשׁ כַּיהֹוָ֖ה כִּ֣י אֵ֣ין בִּלְתֶּ֑ךָ וְאֵ֥ין צ֖וּר כֵּאלֹהֵֽינוּ׃ כִּ֤י מִ֣י אֱ֭לוֹהַּ מִבַּלְעֲדֵ֣י יְהֹוָ֑ה וּמִ֥י צ֝֗וּר זוּלָתִ֥י אֱלֹהֵֽינוּ׃ תּוֹרָ֥ה צִוָּה־לָ֖נוּ מֹשֶׁ֑ה מוֹרָשָׁ֖ה קְהִלַּ֥ת יַעֲקֹֽב׃ עֵץ־חַיִּ֣ים הִ֭יא לַמַּחֲזִיקִ֣ים בָּ֑הּ וְֽתֹמְכֶ֥יהָ מְאֻשָּֽׁר׃ דְּרָכֶ֥יהָ דַרְכֵי־נֹ֑עַם וְֽכׇל־נְתִ֖יבוֹתֶ֣יהָ שָׁלֽוֹם׃ שָׁל֣וֹם רָ֭ב לְאֹהֲבֵ֣י תוֹרָתֶ֑ךָ וְאֵֽין־לָ֥מוֹ מִכְשֽׁוֹל׃ יְֽהֹוָ֗ה עֹ֭ז לְעַמּ֣וֹ יִתֵּ֑ן יְהֹוָ֓ה ׀ יְבָרֵ֖ךְ אֶת־עַמּ֣וֹ בַשָּׁלֽוֹם׃"}, {"kind": "text", "text": "כִּ֛י שֵׁ֥ם יְהֹוָ֖ה אֶקְרָ֑א הָב֥וּ גֹ֖דֶל לֵאלֹהֵֽינוּ׃ הַכֹּל תְּנוּ עֹז לֵאלֹהִים, וּתְנוּ כָבוֹד לַתּוֹרָה:"}, {"kind": "instruction", "text": "מגביה ספר תורה ומראה לקהל ומשתחוים ואומרים"}, {"kind": "text", "text": "<b>וְזֹ֖את </b> הַתּוֹרָ֑ה אֲשֶׁר־שָׂ֣ם מֹשֶׁ֔ה לִפְנֵ֖י בְּנֵ֥י יִשְׂרָאֵֽל׃ תּוֹרָ֥ה צִוָּה־לָ֖נוּ מֹשֶׁ֑ה מוֹרָשָׁ֖ה קְהִלַּ֥ת יַעֲקֹֽב׃ הָאֵל֮ תָּמִ֢ים דַּ֫רְכּ֥וֹ אִמְרַֽת־יְהֹוָ֥ה צְרוּפָ֑ה מָגֵ֥ן ה֝֗וּא לְכֹ֤ל ׀ הַחֹסִ֬ים בּֽוֹ׃"}, {"kind": "instruction", "text": "אסור לדבר בשעת הקריאה"}, {"kind": "instruction", "text": "לפני קריאת התורה"}, {"kind": "instruction", "text": "אומר העולה: הַשֵּׁם עִמָּכֶם:"}, {"kind": "instruction", "text": "ועונים הקהל: יְבָרֶכְךָ הַשֵּׁם:"}, {"kind": "text", "text": "ואומר העולה: בָּרְכוּ אֶת יְהֹוָה הַמְּבֹרָךְ:"}, {"kind": "text", "text": "ועונים הקהל: בָּרוּךְ יְהֹוָה הַמְּבֹרָךְ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "וחוזר העולה: בָּרוּךְ יְהֹוָה הַמְּבֹרָךְ לְעוֹלָם וָעֶד:"}, {"kind": "instruction", "text": "ומברך העולה"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בָּנוּ מִכָּל־הָעַמִּים וְנָתַן לָנוּ אֶת־תּוֹרָתוֹ. בָּרוּךְ אַתָּה יְהֹוָה, נוֹתֵן הַתּוֹרָה:"}, {"kind": "instruction", "text": "ואחר קריאת התורה מברך העולה"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר נָתַן לָנוּ אֶת־תּוֹרָתוֹ תּוֹרַת אֱמֶת, וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. בָּרוּךְ אַתָּה יְהֹוָה, נוֹתֵן הַתּוֹרָה:"}, {"kind": "header", "text": "ברכת הגומל"}, {"kind": "instruction", "text": "ארבעה צריכין להודות שהם: חבוש, יסורין, ים, מדבר וסימנם: \"וכל ה'חיים' יודוך סלה\""}, {"kind": "instruction", "text": "צריך לברך בפני עשרה ותרי מנייהו דתנו הלכתא, וטוב להזהר שיהיו י\"ב עם המברך וגם בהדי תרי רבנן הנזכרים, ואם לא נזדמן לו תרי דתנו הלכתא אפילו הכי יברך ואין לבטל הברכה בעבור זה, ונהגו לברך אחר קריאת התורה בציבור שעל הרוב נמצא שם תרי דתנו הלכתא (בא\"ח עקב ה\"ב)"}, {"kind": "instruction", "text": "לפני הברכה אומר"}, {"kind": "text", "text": "<b>אוֹדֶ֣ה</b> יְ֭הֹוָה בְּכׇל־לֵבָ֑ב בְּס֖וֹד יְשָׁרִ֣ים וְעֵדָֽה׃"}, {"kind": "instruction", "text": "ומברך"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, הַגּוֹמֵל לְחַיָּבִים טוֹבוֹת, שֶׁגְּמָלַֽנִי כָּל־טוּב:"}, {"kind": "instruction", "text": "והקהל עונים"}, {"kind": "text", "text": "אָמֵן. הָאֵל שֶׁגְּמָלְךָ כָּל־טוּב, הוּא יִגְמָלְךָ כָּל־טוּב סֶֽלָה:"}, {"kind": "instruction", "text": "ועונה המברך"}, {"kind": "text", "text": "אָמֵן כֵּן יְהִי רָצוֹן:"}, {"kind": "header", "text": "סדר זבד הבת"}, {"kind": "text", "text": "<b>יוֹנָתִ֞י</b> בְּחַגְוֵ֣י הַסֶּ֗לַע בְּסֵ֙תֶר֙ הַמַּדְרֵגָ֔ה הַרְאִ֙ינִי֙ אֶת־מַרְאַ֔יִךְ הַשְׁמִיעִ֖נִי אֶת־קוֹלֵ֑ךְ כִּי־קוֹלֵ֥ךְ עָרֵ֖ב וּמַרְאֵ֥יךְ נָאוֶֽה׃"}, {"kind": "text", "text": "<b>מִי שֶׁבֵּרַךְ</b> אִמוֹתֵינוּ, שָׂרָה, רִבְקָה, רָחֵל וְלֵאָה וּמִרְיָם הַנְּבִיאָה וַאֲבִיגַיִל, וְאֶסְתֵּר הַמַּלְכָּה בַּת אֲבִיחַיִל, הוּא יְבָרֵךְ אֶת הַיַּלְדָּה הַנְּעִימָה הַזֹּאת, וְיִקָּרֵא שְׁמָהּ (פלונית) בְּמַזָּל טוֹב וּבִשְׁעַת בְּרָכָה, וִיגַדְּלָהּ בִבְרִיאוּת שָׁלוֹם וּמְנוּחָה, וִיזַכֶּה לְאָבִיהָ וּלְאִמָּהּ לִרְאוֹת בְּשִׂמְחָתָהּ וּבְחֻפָּתָהּ, בְּבָנִים זְכָרִים, עֹשֶׁר וְכָבוֹד, דְּשֵׁנִים וְרַעֲנַנִּים יְנוּבוּן בְּשֵׂיבָה, וְכֵן יְהִי רָצוֹן וְנֹאמַר אָמֵן:"}, {"kind": "header", "text": "לשבת חתן"}, {"kind": "instruction", "text": "מי שברך לחתן בר מצוה"}, {"kind": "text", "text": "<b>מִי</b> שֶׁבֵּרַךְ אֲבוֹתֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקֹב, הוּא יְבָרֵךְ וְיִשְׁמֹר וְיִנְצֹר וִיגַדֵּל לְמַעְלָה לְמַעְלָה אֶת חֲתַן הַבַּר מִצְוָה (פלוני בן פלונית), הַקָּדוֹשׁ בָּרוּךְ הוּא יִשְׁמְרֵהוּ וִיחַיֵּהוּ, וּמִכָּל צָרָה וָנֶֽזֶק יַצִּילֵהוּ, וְיִשְׁלַח בְּרָכָה וְהַצְלָחָה בְּכָל מַעֲשׂה יָדָיו, כְּשֵׁם שֶׁזָּכָה לְהִכָּנֵס לְעוֹל הַמִּצְוֹת, כָּךְ יִזְכֶּה לַתּוֹרָה לַחֻפָּה וּלְמַעֲשִׂים טוֹבִים. וְכֵן יְהִי רָצוֹן וְנֹאמַר אָמֵן:"}, {"kind": "instruction", "text": "מי שברך לחתן"}, {"kind": "text", "text": "<b>מִי</b> שֶׁבֵּרַךְ אֲבוֹתֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקֹב, הוּא יְבָרֵךְ וְיִשְׁמֹר וְיִנְצֹר וִיגַדֵּל לְמַעְלָה לְמַעְלָה אֶת הֶחָתָן הַמְּהֻלָּל (פלוני בן פלונית), הַקָּדוֹשׁ בָּרוּךְ הוּא יִשְׁמְרֵהוּ וִיחַיֵּהוּ, וּמִכָּל צָרָה וָנֶֽזֶק יַצִּילֵהוּ, וְיִשְׁלַח בְּרָכָה וְהַצְלָחָה בְּכָל מַעֲשֵׂה יָדָיו, וִיזַכֵּהוּ לִבְנוֹת בֵּיתוֹ בַּיִת נֶאמָן בְּיִשְׂרָאֵל, בְּבָנִים וּבָנוֹת עוֹסְקִים בַּתּוֹרָה וּבַמִּצְוֹת. וְכֵן יְהִי רָצוֹן וְנֹאמַר אָמֵן:"}, {"kind": "instruction", "text": "יש נוהגים לקרוא לחתן פסוקים מפרשת חיי שרה"}, {"kind": "text", "text": "וְאַבְרָהָ֣ם זָקֵ֔ן בָּ֖א בַּיָּמִ֑ים וַֽיהֹוָ֛ה בֵּרַ֥ךְ אֶת־אַבְרָהָ֖ם בַּכֹּֽל׃"}, {"kind": "instruction", "text": "וְאַבְרָהָם סִיב עָאל בְּיוֹמִין וַיהֹוָה בָּרֵיךְ יָת אַבְרָהָם בְּכוֹלָא׃"}, {"kind": "text", "text": "וַיֹּ֣אמֶר אַבְרָהָ֗ם אֶל־עַבְדּוֹ֙ זְקַ֣ן בֵּית֔וֹ הַמֹּשֵׁ֖ל בְּכׇל־אֲשֶׁר־ל֑וֹ שִֽׂים־נָ֥א יָדְךָ֖ תַּ֥חַת יְרֵכִֽי׃"}, {"kind": "instruction", "text": "וַאֲמַר אַבְרָהָם לְעַבְדֵּיהּ סָבָא דְּבֵיתֵיהּ דְּשַׁלִּיט בְּכָל דְּלֵיהּ שַׁו כְּעַן יְדָךְ תְּחוֹת יִרְכִּי׃"}, {"kind": "text", "text": "וְאַשְׁבִּ֣יעֲךָ֔ בַּֽיהֹוָה֙ אֱלֹהֵ֣י הַשָּׁמַ֔יִם וֵֽאלֹהֵ֖י הָאָ֑רֶץ אֲשֶׁ֨ר לֹֽא־תִקַּ֤ח אִשָּׁה֙ לִבְנִ֔י מִבְּנוֹת֙ הַֽכְּנַעֲנִ֔י אֲשֶׁ֥ר אָנֹכִ֖י יוֹשֵׁ֥ב בְּקִרְבּֽוֹ׃"}, {"kind": "instruction", "text": "וַאֲקַיֵּים עֲלָךְ בְּמֵימְרָא דַּיהֹוָה אֱלָהָא דִּשְׁמַיָּא וֵאלָהָא דְּאַרְעָא דְּלָא תִּסַּב אִתְּתָא לִבְרִי מִבְּנָת כְּנַעֲנָאֵי דַּאֲנָא יָתֵיב בֵּינֵיהוֹן׃"}, {"kind": "text", "text": "כִּ֧י אֶל־אַרְצִ֛י וְאֶל־מוֹלַדְתִּ֖י תֵּלֵ֑ךְ וְלָקַחְתָּ֥ אִשָּׁ֖ה לִבְנִ֥י לְיִצְחָֽק׃ ..."}, {"kind": "instruction", "text": "אֱלָהֵין לְאַרְעִי וּלְיַלָּדוּתִי תֵּיזֵיל וְתִסַּב אִתְּתָא לִבְרִי לְיִצְחָק׃"}, {"kind": "text", "text": "וַיֹּ֤אמֶר אֵלָיו֙ הָעֶ֔בֶד אוּלַי֙ לֹא־תֹאבֶ֣ה הָֽאִשָּׁ֔ה לָלֶ֥כֶת אַחֲרַ֖י אֶל־הָאָ֣רֶץ הַזֹּ֑את הֶֽהָשֵׁ֤ב אָשִׁיב֙ אֶת־בִּנְךָ֔ אֶל־הָאָ֖רֶץ אֲשֶׁר־יָצָ֥אתָ מִשָּֽׁם׃"}, {"kind": "instruction", "text": "וַאֲמַר לֵיהּ עַבְדָּא מָאִם לָא תֵּיבֵי אִתְּתָא לְמֵיתֵי בָּתְרַי לְאַרְעָא הָדָא הַאָתָבָא אָתִיב יָת בְּרָךְ לְאַרְעָא דִּנְפַקְתָּא מִתַּמָּן׃"}, {"kind": "text", "text": "וַיֹּ֥אמֶר אֵלָ֖יו אַבְרָהָ֑ם הִשָּׁ֣מֶר לְךָ֔ פֶּן־תָּשִׁ֥יב אֶת־בְּנִ֖י שָֽׁמָּה׃"}, {"kind": "instruction", "text": "וַאֲמַר לֵיהּ אַבְרָהָם אִסְתְּמַר לָךְ דִּלְמָא תָּתִיב יָת בְּרִי לְתַמָּן׃"}, {"kind": "text", "text": "יְהֹוָ֣ה ׀ אֱלֹהֵ֣י הַשָּׁמַ֗יִם אֲשֶׁ֨ר לְקָחַ֜נִי מִבֵּ֣ית אָבִי֮ וּמֵאֶ֣רֶץ מֽוֹלַדְתִּי֒ וַאֲשֶׁ֨ר דִּבֶּר־לִ֜י וַאֲשֶׁ֤ר נִֽשְׁבַּֽע־לִי֙ לֵאמֹ֔ר לְזַ֨רְעֲךָ֔ אֶתֵּ֖ן אֶת־הָאָ֣רֶץ הַזֹּ֑את ה֗וּא יִשְׁלַ֤ח מַלְאָכוֹ֙ לְפָנֶ֔יךָ וְלָקַחְתָּ֥ אִשָּׁ֛ה לִבְנִ֖י מִשָּֽׁם׃"}, {"kind": "instruction", "text": "יְהֹוָה אֱלָהָא דִּשְׁמַיָּא דְּדַבְרַנִי מִבֵּית אַבָּא וּמֵאֲרַע יַלָּדוּתִי וּדְמַלֵּיל לִי וּדְקַיֵּים לִי לְמֵימַר לִבְנָךְ אֶתֵּין יָת אַרְעָא הָדָא הוּא יִשְׁלַח מַלְאֲכֵיהּ קֳדָמָךְ וְתִסַּב אִתְּתָא לִבְרִי מִתַּמָּן׃"}, {"kind": "header", "text": "ברכות ההפטרה"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בִּנְבִיאִים טוֹבִים וְרָצָה בְדִבְרֵיהֶם הַנֶּאֱמָרִים בֶּאֱמֶת. בָּרוּךְ אַתָּה יְהֹוָה, הַבּוֹחֵר בַּתּוֹרָה וּבְמֹשֶׁה עַבְדּוֹ, וּבְיִשְׂרָאֵל עַמּוֹ וּבִנְבִיאֵי הָאֱמֶת וְהַצֶּדֶק:"}, {"kind": "instruction", "text": "וקורא ההפטרה, והקהל קוראים אותה בלחש"}, {"kind": "instruction", "text": "אחר קריאת ההפטרה יאמר"}, {"kind": "instruction", "text": "גֹּאֲלֵ֕נוּ יְהֹוָ֥ה צְבָא֖וֹת שְׁמ֑וֹ קְד֖וֹשׁ יִשְׂרָאֵֽל׃"}, {"kind": "instruction", "text": "ואחר כך יברך"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, צוּר כָּל־הָעוֹלָמִים, צַדִּיק בְּכָל־הַדּוֹרוֹת, הָאֵל הַנֶּאֱמָן הָאֹמֵר וְעֹשֶׂה, הַמְדַבֵּר וּמְקַיֵּם, שֶׁכָּל־דְּבָרָיו אֱמֶת וָצֶדֶק. נֶאֱמָן, אַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ, וְנֶאֱמָנִים דְּבָרֶיךָ, וְדָבָר אֶחָד מִדְּבָרֶיךָ אָחוֹר לֹא יָשׁוּב רֵיקָם, כִּי אֵל מֶלֶךְ נֶאֱמָן וְרַחֲמָן אָתָּה. בָּרוּךְ אַתָּה יְהֹוָה, הָאֵל הַנֶּאֱמָן בְּכָל־דְּבָרָיו:"}, {"kind": "text", "text": "<b>רַחֵם</b> עַל צִיּוֹן כִּי הִיא בֵּית חַיֵּינוּ, וְלַעֲלוּבַת נֶפֶשׁ תּוֹשִׁיעַ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יְהֹוָה, מְשַׂמֵּחַ צִיּוֹן בְּבָנֶיהָ:"}, {"kind": "text", "text": "<b>שַׂמְּחֵנוּ</b> יְהֹוָה אֱלֹהֵינוּ, בְּאֵלִיָהוּ הַנָּבִיא עַבְדָּךְ, וּבְמַלְכוּת בֵּית דָּוִד מְשִׁיחָךְ, בִּמְהֵרָה יָבֹא וְיָגֵל לִבֵּנוּ, עַל כִּסְאוֹ לֹא יֵשֶׁב זָר, וְלֹא יִנְחֲלוּ עוֹד אֲחֵרִים אֶת כְּבוֹדוֹ, כִּי בְשֵׁם קָדְשְׁךָ נִשְׁבַּעְתָּ לּוֹ, שֶׁלֹּא יִכְבֶּה נֵרוֹ לְעוֹלָם וָעֶד. בָּרוּךְ אַתָּה יְהֹוָה, מָגֵן דָּוִד:"}, {"kind": "text", "text": "<b>עַל</b> הַתּוֹרָה, וְעַל הָעֲבוֹדָה, וְעַל הַנְּבִיאִים, וְעַל יוֹם הַשַּׁבָּת הַזֶּה שֶׁנָּתַתָּ לָּנוּ יְהֹוָה אֱלֹהֵינוּ לִקְדֻשָּׁה וְלִמְנוּחָה לְכָבוֹד וּלְתִפְאָרֶת. עַל הַכֹּל יְהֹוָה אֱלֹהֵינוּ אֲנַחְנוּ מוֹדִים לָךְ וּמְבָרְכִים אוֹתָךְ. יִתְבָּרַךְ שִׁמְךָ בְּפִי כָּל־חַי תָּמִיד לְעוֹלָם וָעֶד. בָּרוּךְ אַתָּה יְהֹוָה מְקַדֵּשׁ הַשַּׁבָּת, אָמֵן."}, {"kind": "header", "text": "הכרזת ראש חדש"}, {"kind": "instruction", "text": "בשבת שלפני ראש חדש חוץ מראש חדש תשרי (ואפילו בראש חדש אב) מכריזין ראש חדש, דכתיב: \"בכסה ליום חגנו\". ונכון לידע זמן המולד, ולכן יש נוהגים להכריז בשעת קריאת \"יהי רצון\" על זמן המולד בדיוק"}, {"kind": "text", "text": "<b>יְהִי</b> רָצוֹן מִלִּפְנֵי אֱלֹהֵי הַשָּׁמַיִם, לְכוֹנֵן אֶת בֵּית חַיֵּינוּ וּלְהָשִׁיב שְׁכִינָתוֹ לְתוֹכוֹ בִּמְהֵרָה בְּיָמֵינוּ, וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "<b>יְהִי</b> רָצוֹן מִלִּפְנֵי אֱלֹהֵי הַשָּׁמַיִם, לְרַחֵם עַל פְּלֵיטָתֵנוּ, וְלַעֲצוֹר הַמַּגֵּפָה, וְהַמַּשְׁחִית, וְהַחֶרֶב, וְהָרָעָב, וְהַשְּׁבִי, וְהַבִּזָּה, מֵעָלֵינוּ וּמֵעַל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "<b>יְהִי</b> רָצוֹן מִלִּפְנֵי אֱלֹהֵי הַשָּׁמַיִם, לְקַיֵּם לָנוּ אֶת כָּל־חַכְמֵי יִשְׂרָאֵל, הֵם וּנְשֵׁיהֶם וּבְנֵיהֶם וְתַלְמִידֵיהֶם, בְּכָל־מְקוֹמוֹת מוֹשְׁבוֹתֵיהֶם, וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "<b>יְהִי</b> רָצוֹן מִלִּפְנֵי אֱלֹהֵי הַשָּׁמַיִם, שֶׁנִּשְׁמַע וְנִתְבַּשֵּׂר בְּשׂוֹרוֹת טוֹבוֹת, בְּשׂוֹרוֹת יְשׁוּעוֹת וְנֶחָמוֹת, מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ, וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "<b>מִי</b> שֶׁעָשָׂה נִסִּים לַאֲבוֹתֵינוּ וּמִמִּצְרַיִם גְּאָלָם, הוּא יִגְאַל אוֹתָנוּ וְיָשִׁיב בָּנִים לִגְבוּלָם, בְּסִימָן טוֹב יְהֵא לָנוּ רֹאשׁ חֹדֶשׁ פלוני בְּיוֹם פלוני ופלוני (חִדּוּשֵׁיהּ בְּיוֹם פְּלוֹנִי וּקְבוּעֵיהּ וּמִנְיָנֵיהּ בְּיוֹם פְּלוֹנִי). יְחַדְּשֵׁהוּ הַקָּדוֹשׁ בָּרוּךְ הוּא עָלֵינוּ וְעַל עַמּוֹ יִשְׂרָאֵל בְּכָל־מָקוֹם שֶׁהֵם, לְטוֹבָה וְלִבְרָכָה, לְשָׂשׂוֹן וּלְשִׂמְחָה, לִישׁוּעָה וּלְנֶחָמָה, לְפַרְנָסָה וּלְכַלְכָּלָה טוֹבָה, לִשְׁמוּעוֹת טוֹבוֹת, וְלִבְשׂוֹרוֹת טוֹבוֹת, בחורף וְלִגְשָׁמִים בְּעִתָּם, בקיץ וּלְטַלְלֵי בְרָכָה, וְלִרְפוּאָה שְׁלֵמָה, וְלִגְאֻלָּה קְרוֹבָה, וְאִמְרוּ אָמֵן:"}, {"kind": "header", "text": "הכרזת תענית"}, {"kind": "instruction", "text": "בשבת שלפני הצום של י\"ז בתמוז ושל י' בטבת מכריז החזן ואין מכריזין בצום ט' באב וכיפור ותענית אסתר"}, {"kind": "text", "text": "<b>אַחֵינוּ</b> בֵּית יִשְׂרָאֵל שְׁמָעוּ. צוֹם לי\"ז בתמוז הָרְבִיעִי לעשרה בטבת הָעֲשִׂירִי יִהְיֶה יוֹם פלוני. יַהֲפֹךְ אוֹתוֹ הַקָּדוֹשׁ בָּרוּךְ הוּא לְשָׂשׂוֹן וּלְשִׂמְחָה, כְּדִכְתִיב כֹּֽה־אָמַ֞ר יְהֹוָ֣ה צְבָא֗וֹת צ֣וֹם הָרְבִיעִ֡י (י\"ז בתמוז) וְצ֣וֹם הַחֲמִישִׁי֩ (ט' באב) וְצ֨וֹם הַשְּׁבִיעִ֜י (צום גדליה) וְצ֣וֹם הָעֲשִׂירִ֗י (עשרה בטבת) יִהְיֶ֤ה לְבֵית־יְהוּדָה֙ לְשָׂשׂ֣וֹן וּלְשִׂמְחָ֔ה וּֽלְמֹעֲדִ֖ים טוֹבִ֑ים וְהָאֱמֶ֥ת וְהַשָּׁל֖וֹם אֱהָֽבוּ׃"}, {"kind": "header", "text": "מי שברך לקהל"}, {"kind": "text", "text": "<b>יְהִי שֵׁם</b> יְהֹוָה מְבֹרָךְ מֵעַתָּה וְעַד עוֹלָם:"}, {"kind": "text", "text": "<b>מִי</b> שֶׁבֵּרַךְ אֲבוֹתֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקֹב וּמֹשֶׁה וְאַהֲרֹן וְדָוִד וּשְׁלֹמֹה, וְכָל הַקְּהִלּוֹת הַקְּדוֹשׁוֹת וְהַטְּהוֹרוֹת, הוּא יְבָרֵךְ אֶת־כָּל־הַקָּהָל הַקָּדוֹשׁ הַזֶּה, גְּדוֹלִים וּקְטַנִּים, הֵם וּנְשֵׁיהֶם וּבְנֵיהֶם וְתַלְמִידֵיהֶם, וְכָל־אֲשֶׁר לָהֶם. מַלְכָּא דְעָלְמָא הוּא יְבָרֵךְ יַתְכוֹן, וִיזַכֶּה יַתְכוֹן, וְיִשְׁמַע בְּקָל צְלוֹתְכוֹן, תִּתְפָּרְקוּן וְתִשְׁתֵּזְבוּן מִכָּל צָרָה וְעַקְתָּא, וִיהֵא מֵימְרָא דַּיהֹוָה בְּסַעְדְכֶם, וְיָגֵן בַּעַדְכֶם, וְיִפְרוֹשׂ סֻכַּת שְׁלוֹמוֹ עֲלֵיכֶם, וְיִטַּע בֵּינֵיכֶם אַהֲבָה וְאַחְוָה, שָׁלוֹם וְרֵעוּת, וִיסַלֵּק שִׂנְאַת חִנָּם מִבֵּינֵיכֶם, וְיִשְׁבּוֹר עֹל הַגּוֹיִם מֵעַל צַוָּארֵיכֶם, וִיקַיֵּם בָּכֶם מִקְרָא שֶׁכָּתוּב יְהֹוָ֞ה אֱלֹהֵ֣י אֲבֽוֹתֵכֶ֗ם יֹסֵ֧ף עֲלֵיכֶ֛ם כָּכֶ֖ם אֶ֣לֶף פְּעָמִ֑ים וִיבָרֵ֣ךְ אֶתְכֶ֔ם כַּאֲשֶׁ֖ר דִּבֶּ֥ר לָכֶֽם׃ בשבת תשובה וְיִכְתָּבְכֶם הָאֵל בְּסֵפֶר חַיִּים טוֹבִים. וְכֵן יְהִי רָצוֹן וְנֹאמַר אָמֵן:"}, {"kind": "header", "text": "סיום תפילת שחרית"}, {"kind": "text", "text": "<b>יְהִי־חַסְדְּךָ֣</b> יְהֹוָ֣ה עָלֵ֑ינוּ כַּ֝אֲשֶׁ֗ר יִחַ֥לְנוּ לָֽךְ׃"}, {"kind": "text", "text": "<b>אַ֭שְׁרֵי</b> יוֹשְׁבֵ֣י בֵיתֶ֑ךָ ע֝֗וֹד יְֽהַלְל֥וּךָ סֶּֽלָה: אַשְׁרֵ֣י הָ֭עָם שֶׁכָּ֣כָה לּ֑וֹ אַֽשְׁרֵ֥י הָ֝עָ֗ם שֱׁיְהֹוָ֥ה אֱלֹהָֽיו:"}, {"kind": "text", "text": "<b>תְּהִלָּ֗ה</b> (תהילים קמ״ה:א׳-ב׳) לְדָ֫וִ֥ד אֲרוֹמִמְךָ֣ אֱלוֹהַ֣י הַמֶּ֑לֶךְ וַאֲבָרְכָ֥ה שִׁ֝מְךָ֗ לְעוֹלָ֥ם וָעֶֽד׃ בְּכָל־י֥וֹם אֲבָֽרְכֶ֑ךָּ וַאֲהַֽלְלָ֥ה שִׁ֝מְךָ֗ לְעוֹלָ֥ם וָעֶֽד׃ גָּ֘ד֤וֹל יְהֹוָ֣ה וּמְהֻלָּ֣ל מְאֹ֑ד וְ֝לִגְדֻלָּת֗וֹ אֵ֣ין חֵֽקֶר׃ דּ֣וֹר לְ֭דוֹר יְשַׁבַּ֣ח מַעֲשֶׂ֑יךָ וּגְב֖וּרֹתֶ֣יךָ יַגִּֽידוּ׃ הֲ֭דַר כְּב֣וֹד הוֹדֶ֑ךָ וְדִבְרֵ֖י נִפְלְאֹתֶ֣יךָ אָשִֽׂיחָה׃ וֶעֱז֣וּז נֽוֹרְאֹתֶ֣יךָ יֹאמֵ֑רוּ וגדלותיך [וּגְדֻלָּתְךָ֥] אֲסַפְּרֶֽנָּה׃ זֵ֣כֶר רַב־טוּבְךָ֣ יַבִּ֑יעוּ וְצִדְקָתְךָ֥ יְרַנֵּֽנוּ׃ חַנּ֣וּן וְרַח֣וּם יְהֹוָ֑ה אֶ֥רֶךְ אַ֝פַּ֗יִם וּגְדׇל־חָֽסֶד׃ טוֹב־יְהֹוָ֥ה לַכֹּ֑ל וְ֝רַחֲמָ֗יו עַל־כׇּל־מַעֲשָֽׂיו׃ יוֹד֣וּךָ יְ֭הֹוָה כׇּל־מַעֲשֶׂ֑יךָ וַ֝חֲסִידֶ֗יךָ יְבָרְכֽוּכָה׃ כְּב֣וֹד מַלְכוּתְךָ֣ יֹאמֵ֑רוּ וּגְבוּרָתְךָ֥ יְדַבֵּֽרוּ׃ לְהוֹדִ֤יעַ ׀ לִבְנֵ֣י הָ֭אָדָם גְּבוּרֹתָ֑יו וּ֝כְב֗וֹד הֲדַ֣ר מַלְכוּתֽוֹ׃ מַֽלְכוּתְךָ֗ מַלְכ֥וּת כׇּל־עֹלָמִ֑ים וּ֝מֶֽמְשַׁלְתְּךָ֗ בְּכׇל־דּ֥וֹר וָדֹֽר׃ סוֹמֵ֣ךְ יְ֭הֹוָה לְכׇל־הַנֹּפְלִ֑ים וְ֝זוֹקֵ֗ף לְכׇל־הַכְּפוּפִֽים׃ עֵֽינֵי־כֹ֭ל אֵלֶ֣יךָ יְשַׂבֵּ֑רוּ וְאַתָּ֤ה נֽוֹתֵן־לָהֶ֖ם אֶת־אׇכְלָ֣ם בְּעִתּֽוֹ׃ פּוֹתֵ֥חַ אֶת־יָדֶ֑ךָ וּמַשְׂבִּ֖יעַ לְכׇל־חַ֣י רָצֽוֹן׃ צַדִּ֣יק יְ֭הֹוָה בְּכׇל־דְּרָכָ֑יו וְ֝חָסִ֗יד בְּכׇל־מַעֲשָֽׂיו׃ קָר֣וֹב יְ֭הֹוָה לְכׇל־קֹרְאָ֑יו לְכֹ֤ל אֲשֶׁ֖ר יִקְרָאֻ֣הוּ בֶֽאֱמֶֽת׃ רְצוֹן־יְרֵאָ֥יו יַעֲשֶׂ֑ה וְֽאֶת־שַׁוְעָתָ֥ם יִ֝שְׁמַ֗ע וְיוֹשִׁיעֵֽם׃ שׁוֹמֵ֣ר יְ֭הֹוָה אֶת־כׇּל־אֹהֲבָ֑יו וְאֵ֖ת כׇּל־הָרְשָׁעִ֣ים יַשְׁמִֽיד׃ תְּהִלַּ֥ת יְהֹוָ֗ה יְֽדַבֶּ֫ר פִּ֥י וִיבָרֵ֣ךְ כׇּל־בָּ֭שָׂר שֵׁ֥ם קׇדְשׁ֗וֹ לְעוֹלָ֥ם וָעֶֽד׃ וַאֲנַ֤חְנוּ ׀ נְבָ֘רֵ֤ךְ יָ֗הּ מֵעַתָּ֥ה וְעַד־עוֹלָ֗ם הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "ביום טוב שחל בחול מדלגים פסוק ראשון<br><b>בָּר֣וּךְ</b> יְהֹוָ֗ה אֲשֶׁ֨ר נָתַ֤ן מְנוּחָה֙ לְעַמּ֣וֹ יִשְׂרָאֵ֔ל כְּכֹ֖ל אֲשֶׁ֣ר דִּבֵּ֑ר לֹֽא־נָפַ֞ל דָּבָ֣ר אֶחָ֗ד מִכֹּל֙ דְּבָר֣וֹ הַטּ֔וֹב אֲשֶׁ֣ר דִּבֶּ֔ר בְּיַ֖ד מֹשֶׁ֥ה עַבְדּֽוֹ׃ יְהִ֨י יְהֹוָ֤ה אֱלֹהֵ֙ינוּ֙ עִמָּ֔נוּ כַּאֲשֶׁ֥ר הָיָ֖ה עִם־אֲבֹתֵ֑ינוּ אַל־יַעַזְבֵ֖נוּ וְאַֽל־יִטְּשֵֽׁנוּ׃ לְהַטּ֥וֹת לְבָבֵ֖נוּ אֵלָ֑יו לָלֶ֣כֶת בְּכׇל־דְּרָכָ֗יו וְלִשְׁמֹ֨ר מִצְוֺתָ֤יו וְחֻקָּיו֙ וּמִשְׁפָּטָ֔יו אֲשֶׁ֥ר צִוָּ֖ה אֶת־אֲבֹתֵֽינוּ׃ וְיִֽהְי֨וּ דְבָרַ֜י אֵ֗לֶּה אֲשֶׁ֤ר הִתְחַנַּ֙נְתִּי֙ לִפְנֵ֣י יְהֹוָ֔ה קְרֹבִ֛ים אֶל־יְהֹוָ֥ה אֱלֹהֵ֖ינוּ יוֹמָ֣ם וָלָ֑יְלָה לַעֲשׂ֣וֹת ׀ מִשְׁפַּ֣ט עַבְדּ֗וֹ וּמִשְׁפַּ֛ט עַמּ֥וֹ יִשְׂרָאֵ֖ל דְּבַר־י֥וֹם בְּיוֹמֽוֹ׃ לְמַ֗עַן דַּ֚עַת כׇּל־עַמֵּ֣י הָאָ֔רֶץ כִּ֥י יְהֹוָ֖ה ה֣וּא הָאֱלֹהִ֑ים אֵ֖ין עֽוֹד׃ לֹֽא־יָמ֡וּשׁ סֵ֩פֶר֩ הַתּוֹרָ֨ה הַזֶּ֜ה מִפִּ֗יךָ וְהָגִ֤יתָ בּוֹ֙ יוֹמָ֣ם וָלַ֔יְלָה לְמַ֙עַן֙ תִּשְׁמֹ֣ר לַעֲשׂ֔וֹת כְּכׇל־הַכָּת֖וּב בּ֑וֹ כִּי־אָ֛ז תַּצְלִ֥יחַ אֶת־דְּרָכֶ֖ךָ וְאָ֥ז תַּשְׂכִּֽיל׃ הֲל֤וֹא צִוִּיתִ֙יךָ֙ חֲזַ֣ק וֶאֱמָ֔ץ אַֽל־תַּעֲרֹ֖ץ וְאַל־תֵּחָ֑ת כִּ֤י עִמְּךָ֙ יְהֹוָ֣ה אֱלֹהֶ֔יךָ בְּכֹ֖ל אֲשֶׁ֥ר תֵּלֵֽךְ׃"}, {"kind": "text", "text": "<b>יִמְלֹךְ</b> יִמְלֹ֤ךְ יְהֹוָ֨ה ׀ לְעוֹלָ֗ם אֱלֹהַ֣יִךְ צִ֭יּוֹן לְדֹ֥ר וָדֹ֗ר הַֽלְלוּיָֽהּ׃ ב' פעמים"}, {"kind": "instruction", "text": "מחזירים את ספר התורה למקומו ואומרים מזמור הבו לה'"}, {"kind": "text", "text": "<b>מִזְמ֗וֹר </b> (תהילים כ״ט:א׳-ב׳) לְדָ֫וִ֥ד הָב֣וּ לַ֭יהֹוָה בְּנֵ֣י אֵלִ֑ים הָב֥וּ לַ֝יהֹוָ֗ה כָּב֥וֹד וָעֹֽז׃ הָב֣וּ לַ֭יהֹוָה כְּב֣וֹד שְׁמ֑וֹ הִשְׁתַּחֲו֥וּ לַ֝יהֹוָ֗ה בְּהַדְרַת־קֹֽדֶשׁ׃ ק֥וֹל יְהֹוָ֗ה עַל־הַ֫מָּ֥יִם אֵֽל־הַכָּב֥וֹד הִרְעִ֑ים יְ֝הֹוָ֗ה עַל־מַ֥יִם רַבִּֽים׃ קוֹל־יְהֹוָ֥ה בַּכֹּ֑חַ ק֥וֹל יְ֝הֹוָ֗ה בֶּהָדָֽר׃ ק֣וֹל יְ֭הֹוָה שֹׁבֵ֣ר אֲרָזִ֑ים וַיְשַׁבֵּ֥ר יְ֝הֹוָ֗ה אֶת־אַרְזֵ֥י הַלְּבָנֽוֹן׃ וַיַּרְקִידֵ֥ם כְּמוֹ־עֵ֑גֶל לְבָנ֥וֹן וְ֝שִׂרְיֹ֗ן כְּמ֣וֹ בֶן־רְאֵמִֽים׃ קוֹל־יְהֹוָ֥ה חֹצֵ֗ב לַהֲב֥וֹת אֵֽשׁ׃ ק֣וֹל יְ֭הֹוָה יָחִ֣יל מִדְבָּ֑ר יָחִ֥יל יְ֝הֹוָ֗ה מִדְבַּ֥ר קָדֵֽשׁ׃ ק֤וֹל יְהֹוָ֨ה ׀ יְחוֹלֵ֣ל אַיָּלוֹת֮ וַֽיֶּחֱשֹׂ֢ף יְעָ֫ר֥וֹת וּבְהֵיכָל֑וֹ כֻּ֝לּ֗וֹ אֹמֵ֥ר כָּבֽוֹד׃ יְ֭הֹוָה לַמַּבּ֣וּל יָשָׁ֑ב וַיֵּ֥שֶׁב יְ֝הֹוָ֗ה מֶ֣לֶךְ לְעוֹלָֽם׃ יְֽהֹוָ֗ה עֹ֭ז לְעַמּ֣וֹ יִתֵּ֑ן יְהֹוָ֓ה ׀ יְבָרֵ֖ךְ אֶת־עַמּ֣וֹ בַשָּׁלֽוֹם׃"}, {"kind": "instruction", "text": "כשמכניסים את ספר התורה להיכל אומר החזן"}, {"kind": "text", "text": "<b>שׁוּבָה</b> לִמְעוֹנָךְ וּשְׁכוֹן בְּבֵית מַאֲוָיָךְ, כִּי כָל־פֶּה וְכָל־לָשׁוֹן יִתְּנוּ הוֹד וְהָדָר לְמַלְכוּתָךְ: וּבְנֻחֹ֖ה יֹאמַ֑ר שׁוּבָ֣ה יְהֹוָ֔ה רִֽבְב֖וֹת אַלְפֵ֥י יִשְׂרָאֵֽל׃ הֲשִׁיבֵ֨נוּ יְהֹוָ֤ה ׀ אֵלֶ֙יךָ֙ ונשוב [וְֽנָשׁ֔וּבָה] חַדֵּ֥שׁ יָמֵ֖ינוּ כְּקֶֽדֶם׃"}, {"kind": "header", "text": "מוסף של שבת"}, {"kind": "instruction", "text": "לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְכִינְתֵּהּ בִּדְחִילוּ וּרְחִימוּ וּרְחִימוּ וּדְחִילוּ לְיַחֲדָא שֵׁם יוֹ”ד קֵ\"א בְּוָא\"ו קֵ\"א בְּיִחוּדָא שְׁלִים, בְּשֵׁם כָּל־יִשְׂרָאֵל, הִנֵּה אֲנַחְנוּ בָּאִים לְהִתְפַּלֵּל תְּפִלַּת מוּסָף שֶׁל שַׁבַּת קֹדֶשׁ, כְּמוּ שֶׁתִּקְּנוּ לָנוּ רַבּוֹתֵנוּ ז\"ל, עִם כָּל־הַמִּצְוֹת הַכְּלוּלוֹת בָּהּ, לְתַקֵּן אֶת־שָׁרְשָׁהּ בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַחַת רוּחַ לְיוֹצְרֵנוּ וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ:"}, {"kind": "instruction", "text": "ואומר החזן חצי קדיש"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>אֲ֭דֹנָי</b> שְׂפָתַ֣י תִּפְתָּ֑ח וּ֝פִ֗י יַגִּ֥יד תְּהִלָּתֶֽךָ׃"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵֽאלֹהֵי יַעֲקֹב. הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, קוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵּי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַֽעַן שְׁמוֹ בְּאַֽהֲבָה: בשבת תשובה אומרים: זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, כָּתְבֵנוּ בְּסֵפֶר חַיִּים, לְמַעַנָךְ אֱלֹהִים חַיִּים. מֶֽלֶךְ עוֹזֵר וּמוֹשִֽׁיעַ וּמָגֵן: בָּרוּךְ אַתָּה יַהַוַהַ, מָגֵן אַבְרָהָם:"}, {"kind": "text", "text": "<b>אַתָּה</b> גִבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֶּה מֵתִים אַתָּה, רַב לְהוֹשִֽׁיעַ."}, {"kind": "text", "text": "בקיץ: מוֹרִיד הַטָּל. בחורף: מַשִּׁיב הָרֽוּחַ וּמוֹרִיד הַגֶּֽשֶׁם."}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶֽסֶד, מְחַיֵּה מֵתִים בְּרַֽחֲמִים רַבִּים, סוֹמֵךְ נֽוֹפְלִים, וְרוֹפֵא חוֹלִים, וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמֽוּנָתוֹ לִֽישֵׁנֵי עָפָר. מִי כָמֽוֹךָ בַּֽעַל גְּבוּרוֹת, וּמִי דֽוֹמֶה לָךְ, מֶֽלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִֽיחַ יְשׁוּעָה. בשבת תשובה אומרים: מִי כָמוֹךָ אָב הָרַחֲמָן, זוֹכֵר יְצוּרָיו בְּרַחֲמִים לְחַיִּים. וְנֶֽאֱמָן אַתָּה לְהַֽחֲיוֹת מֵתִים: בָּרוּךְ אַתָּה יֵהֵוֵהֵ, מְחַיֵּה הַמֵּתִים:"}, {"kind": "instruction", "text": "בחזרת הש\"ץ אומרים:"}, {"kind": "text", "text": "<b>כֶּתֶר</b> יִתְּנוּ לְךָ, יְהֹוָה אֱלֹהֵינוּ, מַלְאָכִים הֲמוֹנֵי מַעְלָה, עִם עַמְּךָ יִשְׂרָאֵל קְבוּצֵי מַטָּה. יַחַד כֻּלָּם קְדֻשָּׁה לְךָ יְשַׁלֵּשׁוּ, כַּדָּבָר הָאָמוּר עַל יַד נְבִיאָךְ וְקָרָ֨א זֶ֤ה אֶל־זֶה֙ וְאָמַ֔ר <b>קָד֧וֹשׁ ׀ קָד֛וֹשׁ קָד֖וֹשׁ יְהֹוָ֣ה צְבָא֑וֹת מְלֹ֥א כָל־הָאָ֖רֶץ כְּבוֹדֽוֹ׃</b> כְּבוֹדוֹ מָלֵא עוֹלָם, וּמְשָׁרְתָיו שׁוֹאֲלִים <b>אַיֵּה</b> בתיבת איה יכוון לקבל תוספת נשמה דבחינת היום <b>מְקוֹם כְּבוֹדוֹ לְהַעֲרִיצוֹ:</b> לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים <b>בָּר֥וּךְ כְּבוֹד־יְהֹוָ֖ה מִמְּקוֹמֽוֹ׃</b> מִמְּקוֹמוֹ הוּא יִפֶן בְּרַחֲמָיו לְעַמּוֹ הַמְיַחֲדִים שְׁמוֹ עֶרֶב וָבֹקֶר, בְּכָל יוֹם תָּמִיד אוֹמְרִים פַּעֲמַיִם בְּאַהֲבָה <b>שְׁמַ֖ע יִשְׂרָאֵ֑ל יְהֹוָ֥ה אֱלֹהֵ֖ינוּ יְהֹוָ֥ה ׀ אֶחָֽד׃</b> בתיבת <b>אחד</b> יכוון שהוּא מוכן למסור נפשו על קידוש השם הוּא אֱלֹהֵינוּ, הוּא אָבִינוּ, הוּא מַלְכֵּנוּ, הוּא מוֹשִׁיעֵנוּ, הוּא יוֹשִׁיעֵנוּ וְיִגְאָלֵנוּ שֵׁנִית, וְיַשְׁמִיעֵנוּ בְּרַחֲמָיו לְעֵינֵי כָּל חַי לֵאמֹר, הֵן גָּאַלְתִּי אֶתְכֶם אַחֲרִית כְּרֵאשִׁית לִהְיוֹת לָכֶם לֵאלֹהִים, אֲנִי יְהֹוָה אֱלֹהֵיכֶם: וּבְדִבְרֵי קָדְשְׁךָ כָּתוּב לֵאמֹר <b>יִמְלֹ֤ךְ יְהֹוָ֨ה ׀ לְעוֹלָ֗ם אֱלֹהַ֣יִךְ צִ֭יּוֹן לְדֹ֥ר וָדֹ֗ר הַֽלְלוּיָֽהּ:</b>"}, {"kind": "text", "text": "<b>אַתָּה</b> קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ, וּקְדוֹשִׁים בְּכָל־יוֹם יְהַֽלְלֽוּךָ סֶּֽלָה: בָּרוּךְ אַתָּה יֹהֵוָהֵ, הָאֵל הַקָּדוֹשׁ: בשבת תשובה אומרים: הַמֶּלֶךְ הַקָּדוֹשׁ:"}, {"kind": "instruction", "text": "בשבת יאמר"}, {"kind": "text", "text": "<b>תִּכַּנְתָּ</b> שַׁבָּת, רָצִיתָ קָרְבּנוֹתֶיהָ, צִוִּיתָ פֵירוּשֶׁיהָ עִם סִדּוּרֵי נְסָכֶיהָ, מְעַנְּגֶיהָ לְעוֹלָם כָּבוֹד יִנְחָלוּ, טוֹעֲמֶיהָ חַיִּים זָכוּ, וְגַם הָאוֹהֲבִים דְבָרֶיהָ גְּדֻלָּה בָחָרוּ. אָז מִסִּינַי נִצְטַוּוּ צִוּוּיֵי פְעָלֶיהָ כָּרָאוּי:"}, {"kind": "text", "text": "<b>יְהִי</b> רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתַּעֲלֵנוּ בְשִׂמְחָה לְאַרְצֵנוּ וְתִטָּעֵנוּ בִּגְבוּלֵנוּ, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבּנוֹת חוֹבוֹתֵינוּ תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם. אֶת מוּסַף יוֹם הַשַּׁבָּת הַזֶּה נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה, כְּמִצְוַת רְצוֹנָךְ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתָךְ, עַל יְדֵי מֹשֶׁה עַבְדָּךְ, כָּאָמוּר:"}, {"kind": "text", "text": "<b>וּבְיוֹם֙</b> הַשַּׁבָּ֔ת שְׁנֵֽי־כְבָשִׂ֥ים בְּנֵֽי־שָׁנָ֖ה תְּמִימִ֑ם וּשְׁנֵ֣י עֶשְׂרֹנִ֗ים סֹ֧לֶת מִנְחָ֛ה בְּלוּלָ֥ה בַשֶּׁ֖מֶן וְנִסְכּֽוֹ׃ עֹלַ֥ת שַׁבַּ֖ת בְּשַׁבַּתּ֑וֹ עַל־עֹלַ֥ת הַתָּמִ֖יד וְנִסְכָּֽהּ׃"}, {"kind": "instruction", "text": "ואם חל ראש חודש בשבת יאמר"}, {"kind": "instruction", "text": "אַתָּה יָצַרְתָּ עוֹלָמְךָ מִקֶּדֶם, כִּלִּיתָ מְלַאכְתְּךָ בַּיּוֹם הַשְּׁבִיעִי, בָּחַרְתָּ בָּנוּ מִכָּל הָאֻמּוֹת וְרָצִיתָ בָּנוּ מִכָּל הַלְּשׁוֹנוֹת, וְקִדַשְׁתָּנוּ בְּמִצְוֹתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ. וַתִּתֶּן לָנוּ יְהֹוָה אֱלֹהֵינוּ בְּאַהֲבָה שַׁבָּתוֹת לִמְנוּחָה וְרָאשֵׁי חֳדָשִׁים לְכַפָּרָה. וּלְפִי שֶׁחָטָאנוּ לְפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, חָרְבָה עִירֵנוּ וְשָׁמֵם מִקְדָּשֵׁנוּ, וְגָלָה יְקָרֵנוּ, וְנֻטַּל כָּבוֹד מִבֵּית חַיֵּינוּ, וְאֵין אֲנַחְנוּ יְכוֹלִים לְהַקְרִיב לְפָנֶיךָ קָרְבָּן, וְלֹא כֹהֵן שֶׁיְּכַפֵּר בַּעֲדֵנוּ:"}, {"kind": "instruction", "text": "יְהִי רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתַּעֲלֵנוּ בְשִׂמְחָה לְאַרְצֵנוּ וְתִטָּעֵנוּ בִּגְבוּלֵנוּ, וְשָׁם נַעֲשֶׂה לפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ, תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם. אֶת מוּסְפֵי יוֹם הַשַּׁבָּת הַזֶּה, וְיוֹם רֹאשׁ הַחֹדֶשׁ הַזֶּה, נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנָךְ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתָךְ עַל יְדֵי מֹשֶׁה עַבְדָּךְ כָּאָמוּר:"}, {"kind": "instruction", "text": "וּבְיוֹם֙ הַשַּׁבָּ֔ת שְׁנֵֽי־כְבָשִׂ֥ים בְּנֵֽי־שָׁנָ֖ה תְּמִימִ֑ם וּשְׁנֵ֣י עֶשְׂרֹנִ֗ים סֹ֧לֶת מִנְחָ֛ה בְּלוּלָ֥ה בַשֶּׁ֖מֶן וְנִסְכּֽוֹ׃ עֹלַ֥ת שַׁבַּ֖ת בְּשַׁבַּתּ֑וֹ עַל־עֹלַ֥ת הַתָּמִ֖יד וְנִסְכָּֽהּ׃"}, {"kind": "instruction", "text": "וּבְרָאשֵׁי֙ חׇדְשֵׁיכֶ֔ם תַּקְרִ֥יבוּ עֹלָ֖ה לַיהֹוָ֑ה פָּרִ֨ים בְּנֵֽי־בָקָ֤ר שְׁנַ֙יִם֙ וְאַ֣יִל אֶחָ֔ד כְּבָשִׂ֧ים בְּנֵי־שָׁנָ֛ה שִׁבְעָ֖ה תְּמִימִֽם׃ וּמִנְחָתָם וְנִסְכֵּיהֶם כַּמְדֻבָּר: שְׁלֹשָׁה עֶשְׂרֹנִים לַפָּר וּשְׁנֵי עֶשְׂרֹנִים לָאַיִל וְעִשָּׂרוֹן לַכֶּבֶשׂ, וְיַיִן כְּנִסְכּוֹ, וְשָׂעִיר לְכַפֵּר, וּשְׁנֵי תְמִידִים כְּהִלְכָתָם:"}, {"kind": "text", "text": "<b>אֱלֹהֵינוּ</b> וֵאלֹהֵי אֲבוֹתֵינוּ, חַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה, לְשָׂשׂוֹן וּלְשִׂמְחָה, לִישׁוּעָה וּלְנֶחָמָה, לְפַרְנָסָה וּלְכַלְכָּלָה, לְחַיִּים טוֹבִים וּלְשָׁלוֹם, לִמְחִילַת חֵטְא, וְלִסְלִיחַת עָוֹן, בשנה מעוברת אומרים: וּלְכַפָּרַת פֶּשַׁע. וְיִהְיֶה רֹאשׁ חֹדֶשׁ הַזֶּה סוֹף וָקֵץ לְכָל צָרוֹתֵינוּ, תְּחִלָּה וָרֹאשׁ לְפִדְיוֹן נַפְשֵׁנוּ, כִּי בְעַמְּךָ יִשְׂרָאֵל מִכָּל הָאֻמּוֹת בָּחַרְתָּ, וְחֻקֵּי רָאשֵׁי חֳדָשִׁים לָהֶם קָבָעְתָּ:"}, {"kind": "text", "text": "<b>יִשְׂמְחוּ</b> בְמַלְכוּתָךְ שׁוֹמְרֵי שַׁבָּת וְקוֹרְאֵי עֹנֶג, עַם מְקַדְּשֵׁי שְׁבִיעִי, כֻּלָּם יִשְׂבְּעוּ וְיִתְעַנְּגוּ מִטּוּבָךְ, וְהַשְּׁבִיעִי רָצִיתָ בּוֹ וְקִדַּשְׁתּוֹ, חֶמְדַּת יָמִים אוֹתוֹ קָרָאתָ, זֵכֶר לְמַעֲשֵׂה בְרֵאשִׁית:"}, {"kind": "text", "text": "<b>אֱלֹהֵינוּ</b> וֵאלֹהֵי אֲבוֹתֵינוּ, רְצֵה נָא בִּמְנוּחָתֵנוּ, קַדְּשֵׁנוּ בְּמִצְוֹתֶיךָ, שִׂים חֶלְקֵנוּ בְּתוֹרָתָךְ, שַׂבְּעֵנוּ מִטּוּבָךְ, שַׂמֵּחַ נַפְשֵׁנוּ בִּישׁוּעָתָךְ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶאֱמֶת, וְהַנְחִילֵנוּ יְהֹוָה אֱלֹהֵינוּ בְּאַהֲבָה וּבְרָצוֹן שַׁבָּת קָדְשֶׁךָ, וְיָנוּחוּ בוֹ כָּל יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יְהֹוָה, מְקַדֵּשׁ הַשַּׁבָּת: בראש חודש אומרים וְיִשְׂרָאֵל וְרָאשֵׁי חֳדָשִׁים:"}, {"kind": "text", "text": "<b>רְצֵה</b> יְהֹוָה אֱלֹהֵֽינוּ בְּעַמְּךָ יִשְׂרָאֵל וְלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב הָֽעֲבוֹדָה לִדְבִיר בֵּיתֶֽךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, מְהֵרָה בְּאַֽהֲבָה תְקַבֵּל בְּרָצוֹן, וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּֽךָ: וְאַתָּה בְּרַֽחֲמֶֽיךָ הָרַבִּים, תַּחְפֹּץ בָּֽנוּ וְתִרְצֵֽנוּ, וְתֶֽחֱזֶֽינָה עֵינֵֽינוּ בְּשֽׁוּבְךָ לְצִיּוֹן בְּרַֽחֲמִים: בָּרוּךְ אַתָּה יִהִוִהִ, הַמַּֽחֲזִיר שְׁכִֽינָתוֹ לְצִיּוֹן:"}, {"kind": "instruction", "text": "בברכת \"מודים\" יכרע ב\"מודים\" ויזקוף בשם (בא\"ח בשלח הכ\"א)"}, {"kind": "text", "text": "<b>מוֹדִים</b> אֲנַֽחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ לְעוֹלָם וָעֶד, צוּרֵֽנוּ צוּר חַיֵּֽינוּ וּמָגֵן יִשְׁעֵֽנוּ אַתָּה הוּא, לְדוֹר וָדוֹר נוֹדֶה לְךָ וּנְסַפֵּר תְּהִלָּתֶֽךָ, עַל חַיֵּֽינוּ הַמְּסוּרִים בְּיָדֶֽךָ, וְעַל נִשְׁמוֹתֵֽינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּֽיךָ שֶׁבְּכָל־יוֹם עִמָּֽנוּ, וְעַל נִפְלְאוֹתֶֽיךָ וְטֽוֹבוֹתֶֽיךָ שֶׁבְּכָל־עֵת, עֶֽרֶב וָבֹֽקֶר וְצָֽהֳרָֽיִם. הַטּוֹב, כִּי לֹא כָלוּ רַחֲמֶֽיךָ, הַמְּרַחֵם, כִּי לֹא תַֽמּוּ חֲסָדֶֽיךָ, כִּי מֵֽעוֹלָם קִוִּֽינוּ לָךְ:"}, {"kind": "text", "text": "<b>מודים דרבנן</b><br>בחזרת הש\"ץ כשהחזן אומר מודים, הקהל אומרים:<br>מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׁר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית. בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְחָנֵּנוּ וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמֹר חֻקֶּיךָ וְלַעֲשׂוֹת רְצוֹנְךָ וּלְעָבְדְךָ בְלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ, בָּרוּךְ אֵל הַהוֹדָאוֹת."}, {"kind": "instruction", "text": "בחנוכה ופורים אומרים:"}, {"kind": "instruction", "text": "עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת שֶׁעָשִֽׂיתָ לַאֲבוֹתֵֽינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה:"}, {"kind": "text", "text": "בחנוכה אומרים: <b>בִּימֵי מַתִּתְיָה</b> בֶן־יוֹחָנָן כֹּהֵן גָּדוֹל. חַשְׁמוֹנָאִי וּבָנָיו כְּשֶׁעָֽמְדָֽה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל. לְשַׁכְּחָם תּוֹרָתָךְ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנָךְ. וְאַתָּה בְּרַחֲמֶֽיךָ הָרַבִּים עָמַֽדְתָּ לָהֶם בְּעֵת צָרָתָם. רַֽבְתָּ אֶת רִיבָם. דַּֽנְתָּ אֶת דִּינָם. נָקַֽמְתָּ אֶת נִקְמָתָם. מָסַֽרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים. וְרַבִּים בְּיַד מְעַטִּים. וּרְשָׁעִים בְּיַד צַדִּיקִים. וּטְמֵאִים בְּיַד טְהוֹרִים. וְזֵדִים בְּיַד עֽוֹסְקֵֽי תוֹרָתֶֽךָ. לְךָ עָשִֽׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמָךְ. וּלְעַמְּךָ יִשְׂרָאֵל עָשִֽׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כָּךְ בָּֽאוּ בָנֶֽיךָ לִדְבִיר בֵּיתֶֽךָ. וּפִנּוּ אֶת־הֵיכָלֶֽךָ. וְטִהֲרוּ אֶת־מִקְדָּשֶֽׁךָ. וְהִדְלִֽיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶֽׁךָ. וְקָֽבְעֽוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵֽלּוּ בְּהַלֵּל וּבְהוֹדָאָה. וְעָשִֽׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶֽלָה:"}, {"kind": "text", "text": "בפורים אומרים <b>בִּימֵי מָרְדְּכַי</b> וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה. כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע. בִּקֵּשׁ לְהַשְׁמִיד לַהֲרֹג וּלְאַבֵּד אֶת־כָּל־הַיְּהוּדִים מִנַּֽעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד. בִּשְׁלֹשָׁה עָשָׂר לְחֹֽדֶשׁ שְׁנֵים עָשָׂר. הוּא חֹֽדֶשׁ אֲדָר. וּשְׁלָלָם לָבוֹז. וְאַתָּה בְּרַחֲמֶֽיךָ הָרַבִּים הֵפַֽרְתָּ אֶת־עֲצָתוֹ וְקִלְקַֽלְתָּ אֶת־מַחֲשַׁבְתּוֹ. וַהֲשֵׁבֽוֹתָ לּוֹ גְּמוּלוֹ בְרֹאשׁוֹ. וְתָלוּ אוֹתוֹ וְאֶת־בָּנָיו עַל הָעֵץ. וְעָשִֽׂיתָ עִמָּהֶם נֵס וָפֶֽלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶֽלָה:"}, {"kind": "text", "text": "<b>וְעַל</b> כֻּלָּם יִתְבָּרַךְ, וְיִתְרוֹמָם, וְיִתְנַשֵּׂא, תָּמִיד, שִׁמְךָ מַלְכֵּֽנוּ, לְעוֹלָם וָעֶד. וְכָל־הַחַיִּים יוֹדֽוּךָ סֶּֽלָה: בשבת תשובה אומרים: וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ. וִֽיהַֽלְלוּ וִֽיבָֽרְכוּ אֶת־שִׁמְךָ הַגָּדוֹל בֶּֽאֱמֶת לְעוֹלָם כִּי טוֹב, הָאֵל יְשֽׁוּעָתֵֽנוּ וְעֶזְרָתֵֽנוּ סֶֽלָה, הָאֵל הַטּוֹב: בָּרוּךְ אַתָּה יֻהֻוֻהֻ, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת:"}, {"kind": "text", "text": "ברכת כהנים"}, {"kind": "text", "text": "כשעוקר הכהן רגליו לישא כפיו יאמר (בא\"ח תצוה י\"ב)<br>לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ. בִּדְחִֽילוּ וּרְחִֽימוּ. וּרְחִֽימוּ וּדְחִֽילוּ. לְיַחֲדָא שֵׁם יוֹ\"ד קֵ\"א בְּוָא\"ו קֵ\"א בְּיִחוּדָא שְׁלִים. בְּשֵׁם כָּל־יִשְׂרָאֵל הִנֵּה אָנֹכִי מוּכָן וּמְזוּמָן לְקַיֵּם מִצְוַת עֲשֵׂה לְבָרֵךְ אֶת יִשְׂרָאֵל בִּרְכַּת כֹּהַנִים בִּנְשִׂיאוּת כַּפַּיִם, לַעֲשׂוֹת נַֽחַת רֽוּחַ לְיֽוֹצְרֵֽנוּ וּלְהַמְשִׁיךְ שֶׁפַע וּבְרָכָה לְכָל־הָעוֹלָמוֹת וְלַעֲשׂוֹת רְצוֹן בּֽוֹרְאֵֽנוּ. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ:"}, {"kind": "text", "text": "וכשעומדים הכהנים על הדוכן לאחר שענו \"מודים דרבנן\", אומרים<br>יְהִי רָצוֹן מִלְּפָנֶֽיךָ יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ שֶׁתִּהְיֶה בְּרָכָה זוֹ שֶׁצִּּוִיתָֽנוּ לְבָרֵךְ אֶת־עַמְּךָ יִשְׂרָאֵל בְּרָכָה שְׁלֵמָה וְלֹא יִהְיֶה בָהּ מִכְשׁוֹל וְעָוֹן מֵעַתָּה וְעַד עוֹלָם:"}, {"kind": "text", "text": "בחזרת הש\"ץ אומרים ברכת כהנים, אם יש יותר מכהן אחד קורא להם החזן: כֹּהֲנִים: הכהנים מברכים:<br>בָּרוּךְ אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָֽעוֹלָם, אֲשֶׁר קִדְּשָֽׁנוּ בִּקְדֻשָּׁתוֹ שֶׁל־אַֽהֲרֹן, וְצִוָּֽנוּ לְבָרֵךְ אֶת־עַמּוֹ יִשְׂרָאֵל בְּאַֽהֲבָה: הקהל עונים אָמֵן:"}, {"kind": "instruction", "text": "ואומר החזן והכהנים אחריו מילה במילה:"}, {"kind": "text", "text": "יְבָרֶכְךָ֥ יְהֹוָ֖ה וְיִשְׁמְרֶֽךָ׃ ועונים אָמֵן:"}, {"kind": "text", "text": "יָאֵ֨ר יְהֹוָ֧ה ׀ פָּנָ֛יו אֵלֶ֖יךָ וִֽיחֻנֶּֽךָּ׃ ועונים אָמֵן:"}, {"kind": "text", "text": "יִשָּׂ֨א יְהֹוָ֤ה ׀ פָּנָיו֙ אֵלֶ֔יךָ וְיָשֵׂ֥ם לְךָ֖ שָׁלֽוֹם׃ ועונים אָמֵן:"}, {"kind": "instruction", "text": "וכשמתחיל שליח ציבור \"שים שלום\" אז מחזירין פניהם כלפי ההיכל, ולא יחזירו פניהם קודם, ואז הכהנים אומרים<br>רִבּוֹן הָעוֹלָמִים עָשִֽׂינוּ מַה־שֶּׁגָּזַֽרְתָּ עָלֵֽינוּ, עַשֵׂה אַתָּה מַה־שֶּׁהִבְטָחְתָּֽנוּ. הַשְׁקִ֩יפָה֩ מִמְּע֨וֹן קׇדְשְׁךָ֜ מִן־הַשָּׁמַ֗יִם וּבָרֵ֤ךְ אֶֽת־עַמְּךָ֙ אֶת־יִשְׂרָאֵ֔ל:"}, {"kind": "text", "text": "אם אין כהנים אומר החזן:<br><b>אֱלֹהֵינוּ</b> וֵאלֹהֵי אֲבוֹתֵינוּ, בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶת בַּתּוֹרָה הַכְּתוּבָה עַל יְדֵי מֹשֶׁה עַבְדֶּֽךָ, הָאֲמוּרָה מִפִּי אַהֲרֹן וּבָנָיו הַכֹּהֲנִים עַם קְדוֹשֶׁיךָ כָּאָמוּר:"}, {"kind": "text", "text": "יְבָרֶכְךָ֥ יְהֹוָ֖ה וְיִשְׁמְרֶֽךָ׃ ועונים כֵּן יְהִי רָצוֹן:"}, {"kind": "text", "text": "יָאֵ֨ר יְהֹוָ֧ה ׀ פָּנָ֛יו אֵלֶ֖יךָ וִֽיחֻנֶּֽךָּ׃ ועונים כֵּן יְהִי רָצוֹן:"}, {"kind": "text", "text": "יִשָּׂ֨א יְהֹוָ֤ה ׀ פָּנָיו֙ אֵלֶ֔יךָ וְיָשֵׂ֥ם לְךָ֖ שָׁלֽוֹם׃ ועונים כֵּן יְהִי רָצוֹן: וְשָׂמ֥וּ אֶת־שְׁמִ֖י עַל־בְּנֵ֣י יִשְׂרָאֵ֑ל וַאֲנִ֖י אֲבָרְכֵֽם:"}, {"kind": "text", "text": "<b>שִׂים</b> שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים חֵן וָחֶֽסֶד וְרַֽחֲמִים, עָלֵֽינוּ וְעַל כָּל־יִשְׂרָאֵל עַמֶּֽךָ. וּבָֽרְכֵֽנוּ אָבִֽינוּ כֻּלָּֽנוּ כְּאֶחָד בְּאוֹר פָּנֶֽיךָ, כִּי בְאוֹר פָּנֶֽיךָ נָתַֽתָּ לָּֽנוּ יְהֹוָה אֱלֹהֵֽינוּ תּוֹרָה וְחַיִּים, אַֽהֲבָה וָחֶֽסֶד, צְדָקָה וְרַֽחֲמִים, בְּרָכָה וְשָׁלוֹם. וְטוֹב בְּעֵינֶֽיךָ לְבָֽרְכֵֽנוּ וּלְבָרֵךְ אֶת־כָּל־עַמְּךָ יִשְׂרָאֵל, בְּרֹב עֹז וְשָׁלוֹם: בשבת תשובה אומרים: וּבְסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה וִישׁוּעָה וְנֶחָמָה, וּגְזֵרוֹת טוֹבוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם. בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמְּבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם. אָמֵן:"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>אֱלֹהַי</b>, נְצֹר לְשׁוֹנִי מֵרָע וְשִׂפְתוֹתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּֽעָפָר לַכֹּל תִּֽהְיֶה, פְּתַח לִבִּי בְּתוֹרָתֶֽךָ, וְאַחֲרֵי מִצְוֹתֶֽיךָ תִּרְדֹּף נַפְשִׁי. וְכָל־הַקָּמִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחְשְׁבוֹתָם. יִֽהְי֗וּ כְּמֹ֥ץ לִפְנֵי־ר֑וּחַ וּמַלְאַ֖ךְ יְהֹוָ֣ה דּוֹחֶֽה. קַבֵּל רִנַּת עַמֶּךָ. שַׂגְּבֵנוּ טַהֲרֵנוּ נוֹרָא. עֲשֵׂה לְמַֽעַן שְׁמָךְ, עֲשֵׂה לְמַֽעַן יְמִינָךְ, עֲשֵׂה לְמַֽעַן תּֽוֹרָתָךְ, עֲשֵׂה לְמַֽעַן קְדֻשָּׁתָךְ."}, {"kind": "text", "text": "סגולה לומר פסוק המתחיל וגומר באות שמתחיל וגומר שמו לְ֭מַעַן יֵחָלְצ֣וּן יְדִידֶ֑יךָ הוֹשִׁ֖יעָה יְמִֽינְךָ֣ וַעֲנֵֽנִי:"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>עֹשֶׂה</b> שָׁלוֹם בשבת תשובה אומרים: הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵֽינוּ, וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן:"}, {"kind": "instruction", "text": "יְהִי רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְּיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ, לַעֲשׂוֹת חֻקֵּי רְצוֹנָךְ וּלְעָבְדָךְ בְּלֵבָב שָׁלֵם:"}, {"kind": "instruction", "text": "אחרי חזרת הש''צ אומרים"}, {"kind": "text", "text": "<b>יְהִ֤י</b> שֵׁ֣ם יְהֹוָ֣ה מְבֹרָ֑ךְ מֵ֝עַתָּ֗ה וְעַד־עוֹלָֽם׃ מִמִּזְרַח־שֶׁ֥מֶשׁ עַד־מְבוֹא֑וֹ מְ֝הֻלָּ֗ל שֵׁ֣ם יְהֹוָֽה׃ רָ֖ם עַל־כׇּל־גּוֹיִ֥ם ׀ יְהֹוָ֑ה עַ֖ל הַשָּׁמַ֣יִם כְּבוֹדֽוֹ׃ יְהֹוָ֥ה אֲדֹנֵ֑ינוּ מָה־אַדִּ֥יר שִׁ֝מְךָ֗ בְּכׇל־הָאָֽרֶץ׃"}, {"kind": "instruction", "text": "ואומר החזן קדיש תתקבל"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "תִּתְקַבַּל צְלוֹתָֽנָא וּבָֽעוּתָֽנָא, עִם צְלֽוֹתְהוֹן וּבָעֽוּתְהוֹן דְּכָל־בֵּית יִשְׂרָאֵל, קֳדָם אֲבוּנָא דְּבִשְׁמַיָּא וְאַרְעָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא. חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה. וְשֵׁיזָבָא וּרְפוּאָה וּגְאוּלָה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "יפסע שלש פסיעות לאחור<br>עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו. הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>כָּל יִשְׂרָאֵל</b> יֵשׁ לָהֶם חֵלֶק לָעוֹלָם הַבָּא, שֶׁנֶּאֱמַר וְעַמֵּךְ֙ כֻּלָּ֣ם צַדִּיקִ֔ים לְעוֹלָ֖ם יִ֣ירְשׁוּ אָ֑רֶץ נֵ֧צֶר מטעו [מַטָּעַ֛י] מַעֲשֵׂ֥ה יָדַ֖י לְהִתְפָּאֵֽר׃"}, {"kind": "text", "text": "<b>אָמַר</b> רִבִּי יְהוּדָה אַשְׁרֵי מִי שֶׁעֲמָלוֹ בַּתּוֹרָה וְעֹשֶׂה נַחַת רוּחַ לְיוֹצְרוֹ, גָּדֵל בְּשֵׁם טוֹב, וְנִפְטָר בְּשֵׁם טוֹב מִן הָעוֹלָם, וְעָלָיו אָמַר שׁלֹמֹה בְּחָכְמָתוֹ טוֹב שֵׁם מִשֶּׁמֶן טוֹב, וְיוֹם הַמָּוֶת מִיּוֹם הִוָּלְדוֹ. לְמֹד תּוֹרָה הַרְבֵּה וְיִתּנוּ לְךָ שָׂכָר הַרְבֵּה. וְדַע, מַתַּן שְׂכָרָם שֶׁל צַדִּיקִים לֶעָתִיד לָבֹא:"}, {"kind": "text", "text": "<b>רִבִּי</b> חֲנַנְיָה בֶּן עֲקַשְׁיָא אוֹמֵר רָצָה הַקָּדוֹשׁ בָּרוּךְ הוּא לְזַכּוֹת אֶת יִשְׂרָאֵל, לְפִיכָךְ הִרְבָּה לָהֶם תּוֹרָה וּמִצְוֹת, שֶׁנֶּאֱמַר יְהֹוָ֥ה חָפֵ֖ץ לְמַ֣עַן צִדְק֑וֹ יַגְדִּ֥יל תּוֹרָ֖ה וְיַאְדִּֽיר׃"}, {"kind": "text", "text": "<b>אֵין</b> כֵּאלֹהֵינוּ, אֵין כַּאדוֹנֵנוּ, אֵין כְּמַלְכֵּנוּ, אֵין כְּמוֹשִׁיעֵנוּ: מִי כֵּאלֹהֵינוּ, מִי כַּאדוֹנֵנוּ, מִי כְּמַלְכֵּנוּ, מִי כְּמוֹשִׁיעֵנוּ: נוֹדֶה לֵאלֹהֵינוּ, נוֹדֶה לַאדוֹנֵנוּ, נוֹדֶה לְמַלְכֵּנוּ, נוֹדֶה לְמוֹשִׁיעֵנוּ: בָּרוּךְ אֱלֹהֵינוּ, בָּרוּךְ אֲדוֹנֵנוּ, בָּרוּךְ מַלְכֵּנוּ, בָּרוּךְ מוֹשִׁיעֵנוּ: אַתָּה הוּא אֱלֹהֵינוּ, אַתָּה הוּא אֲדוֹנֵנוּ, אַתָּה הוּא מַלְכֵּנוּ, אַתָּה הוּא מוֹשִׁיעֵנוּ. אַתָּה תוֹשִׁיעֵנוּ. אַתָּ֣ה תָ֭קוּם תְּרַחֵ֣ם צִיּ֑וֹן כִּי־עֵ֥ת לְ֝חֶֽנְנָ֗הּ כִּי־בָ֥א מוֹעֵֽד׃"}, {"kind": "header", "text": "פטום הקטורת"}, {"kind": "text", "text": "<b>אַתָּה</b> הוּא יְהֹוָה אֱלֹהֵֽינוּ, שֶׁהִקְטִֽירוּ אֲבוֹתֵֽינוּ לְפָנֶֽיךָ אֶת קְטֹֽרֶת הַסַּמִּים, בִּזְמַן שֶׁבֵּית הַמִּקְדָשׁ קַיָּם, כַּאֲשֶׁר צִוִּֽיתָ אוֹתָם עַל־יַד מֹשֶׁה נְבִיאָךְ, כַּכָּתוּב בְּתֽוֹרָתָךְ:"}, {"kind": "text", "text": "<b>וַיֹּ֩אמֶר֩</b> יְהֹוָ֨ה אֶל־מֹשֶׁ֜ה קַח־לְךָ֣ סַמִּ֗ים נָטָ֤ף | וּשְׁחֵ֙לֶת֙ וְחֶלְבְּנָ֔ה סַמִּ֖ים וּלְבֹנָ֣ה זַכָּ֑ה בַּ֥ד בְּבַ֖ד יִהְיֶֽה׃ וְעָשִׂ֤יתָ אֹתָהּ֙ קְטֹ֔רֶת רֹ֖קַח מַעֲשֵׂ֣ה רוֹקֵ֑חַ מְמֻלָּ֖ח טָה֥וֹר קֹֽדֶשׁ׃ וְשָֽׁחַקְתָּ֣ מִמֶּ֘נָּה֮ הָדֵק֒ וְנָתַתָּ֨ה מִמֶּ֜נָּה לִפְנֵ֤י הָעֵדֻת֙ בְּאֹ֣הֶל מוֹעֵ֔ד אֲשֶׁ֛ר אִוָּעֵ֥ד לְךָ֖ שָׁ֑מָּה קֹ֥דֶשׁ קׇֽדָשִׁ֖ים תִּהְיֶ֥ה לָכֶֽם׃ וְנֶֽאֱמַר וְהִקְטִ֥יר עָלָ֛יו אַהֲרֹ֖ן קְטֹ֣רֶת סַמִּ֑ים בַּבֹּ֣קֶר בַּבֹּ֗קֶר בְּהֵיטִיב֛וֹ אֶת־הַנֵּרֹ֖ת יַקְטִירֶֽנָּה: וּבְהַעֲלֹ֨ת אַהֲרֹ֧ן אֶת־הַנֵּרֹ֛ת בֵּ֥ין הָעַרְבַּ֖יִם יַקְטִירֶ֑נָּה קְטֹ֧רֶת תָּמִ֛יד לִפְנֵ֥י יְהֹוָ֖ה לְדֹרֹתֵיכֶֽם:"}, {"kind": "text", "text": "<b>תָּנוּ</b> רַבָּנָן: פִּטּוּם הַקְּטֹֽרֶת כֵּיצַד, שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וּשְׁמוֹנָה מָנִים הָיוּ בָהּ. שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וַֽחֲמִשָּׁה כְּמִנְיַן יְמוֹת הַחַמָּה, מָנֶה בְּכָל־יוֹם, מַֽחֲצִיתוֹ בַּבֹּֽקֶר וּמַֽחֲצִיתוֹ בָּעֶרֶב. וּשְׁלֹשָׁה מָנִים יְתֵרִים, שֶׁמֵּהֶם מַכְנִיס כֹּהֵן גָּדוֹל, וְנוֹטֵל מֵהֶם מְלֹא חָפְנָיו בְּיוֹם הַכִּפּוּרִים, וּמַֽחֲזִירָן לְמַכְתֶּֽשֶׁת בְּעֶֽרֶב יוֹם הַכִּפּוּרִים, כְּדֵי לְקַיֵּם מִצְוַת דַקָּה מִן הַדַּקָּה. וְאַחַד־עָשָׂר סַמָּנִים הָיוּ בָהּ, וְאֵֽלּוּ הֵן:"}, {"kind": "text", "text": "א הַצֳּרִי ב וְהַצִּפֹּֽרֶן ג וְהַחֶלְבְּנָה ד וְהַלְּבוֹנָה, מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה. ה מוֹר, ו וּקְצִיעָה ז וְשִׁבֹּֽלֶת נֵרְדְּ ח וְכַרְכֹּם, מִשְׁקַל שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה. ט קֹשְׁטְ שְׁנֵים עָשָׂר, י קִלּוּפָה שְׁלֹשָׁה, יא קִנָּמוֹן תִּשְׁעָה, בּוֹרִית־כַּרְשִׁינָה תִּשְׁעָה קַבִּין. יֵין קַפְרִיסִין סְאִין תְּלָת וְקַבִּין תְּלָתָא. וְאִם לֹא מָצָא יֵין קַפְרִיסִין, מֵבִיא חֲמַר חִיוָר עַתִּיק. מֶֽלַח סְדוֹמִית, רֽוֹבַע. מַעֲלֶה עָשָׁן, כָּל־שֶׁהוּא. רִבִּי נָתָן הַבַּבְלִי אוֹמֵר: אַף כִּפַּת הַיַּרְדֵּן כָּל־שֶׁהִיא, אִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ, וְאִם חִסֵּר אַחַת מִכָּל־סַמְמָנֶֽיהָ, חַיָּיב מִיתָה:"}, {"kind": "text", "text": "<b>רַבָּן</b> שִׁמְעוֹן בֶּן־גַּמְלִיאֵל אוֹמֵר: הַצֳּרִי אֵינוֹ אֶלָּא שְׁרָף, הַנּוֹטֵף מֵֽעֲצֵי הַקְּטָף. בֹּרִית כַּרְשִׁינָה, לְמָה הִיא בָֽאָה, כְּדֵי לְשַׁפּוֹת בָּהּ אֶת־הַצִּפֹּֽרֶן, כְּדֵי שֶׁתְּהֵא נָאָה. יֵין קַפְרִיסִין, לְמָה הוּא בָא? כְּדֵי לִשְׁרוֹת בּוֹ אֶת־הַצִּפֹּֽרֶן כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלֹא מֵי רַגְלַֽיִם יָפִין לָהּ? אֶלָּא שֶׁאֵין מַכְנִיסִין מֵי רַגְלַֽיִם בַּמִּקְדָּשׁ, מִפְּנֵי הַכָּבוֹד:"}, {"kind": "text", "text": "<b>תַּנְיָא</b> רִבִּי נָתָן אוֹמֵר: כְּשֶׁהוּא שׁוֹחֵק, אוֹמֵר: הָדֵק הֵיטֵב, הֵיטֵב הָדֵק. מִפְּנֵי שֶׁהַקּוֹל יָפֶה לַבְּשָׂמִים. פִּטְּמָהּ לַֽחֲצָאִין, כְּשֵׁרָה. לְשָׁלִישׁ וּלְרָבִֽיעַ, לֹא שָׁמַֽעְנוּ. אָמַר רִבִּי יְהוּדָה: זֶה הַכְּלָל, אִם כְּמִדָּתָהּ, כְּשֵׁרָה לַֽחֲצָאִין. וְאִם חִסֵּר אַחַת מִכָּל־סַמְמָנֶֽיהָ, חַיָּיב מִיתָה:"}, {"kind": "text", "text": "<b>תָּנֵי</b> בַר־קַפָּרָא: אַחַת לְשִׁשִּׁים אוֹ לְשִׁבְעִים שָׁנָה, הָֽיְתָה בָֽאָה שֶׁל שִׁירַֽיִם לַֽחֲצָאִין. וְעוֹד תָּנֵי בַר־קַפָּרָא: אִלּוּ הָיָה נוֹתֵן בָּהּ קָרְטוֹב שֶׁל דְּבַשׁ, אֵין אָדָם יָכוֹל לַֽעֲמֹד מִפְּנֵי רֵיחָהּ. וְלָֽמָּה אֵין מְעָֽרְבִין בָּהּ דְּבַשׁ, מִפְּנֵי שֶׁהַתּוֹרָה אָֽמְרָה: כִּ֤י כָל־שְׂאֹר֙ וְכָל־דְּבַ֔שׁ לֹֽא־תַקְטִ֧ירוּ מִמֶּ֛נּוּ אִשֶּׁ֖ה לַֽיהֹוָֽה: יְהֹוָ֣ה צְבָא֣וֹת עִמָּ֑נוּ מִשְׂגָּֽב־לָ֨נוּ אֱלֹהֵ֖י יַֽעֲקֹ֣ב סֶֽלָה׃ יְהֹוָ֥ה צְבָא֑וֹת אַֽשְׁרֵ֥י אָ֝דָ֗ם בֹּטֵ֥חַ בָּֽךְ׃ יְהֹוָ֥ה הוֹשִׁ֑יעָה הַ֝מֶּ֗לֶךְ יַעֲנֵ֥נוּ בְיוֹם־קׇרְאֵֽנוּ: וְעָֽרְבָה֙ לַֽיהֹוָ֔ה מִנְחַ֥ת יְהוּדָ֖ה וִירֽוּשָׁלָ֑‍ִם כִּימֵ֣י עוֹלָ֔ם וּכְשָׁנִ֖ים קַדְמֹנִיֹּֽת:"}, {"kind": "text", "text": "<b>תָּנָא </b> דְּבֵי־אֵלִיָּהוּ: כָּל־הַשּׁוֹנֶה הֲלָכוֹת בְּכָל־יוֹם, מֻבְטָח לוֹ שֶׁהוּא בֶּן־הָעוֹלָם הַבָּא, שֶׁנֶּאֱמַר הֲלִיכ֥וֹת עוֹלָ֖ם לֽוֹ, אַל־תִּקְרֵי הֲלִיכוֹת, אֶלָּא הֲלָכוֹת: אָמַר רִבִּי אֶלְעָזָר אָמַר רִבִּי חֲנִינָא, תַּלְמִידֵי חֲכָמִים מַרְבִּים שָׁלוֹם בָּעוֹלָם, שֶׁנֶּאֱמַר וְכׇל־בָּנַ֖יִךְ לִמּוּדֵ֣י יְהֹוָ֑ה וְרַ֖ב שְׁל֥וֹם בָּנָֽיִךְ, אַל־תִּקְרֵי בָנָיִךְ אֶלָּא בוֹנָיִךְ: יְהִֽי־שָׁל֥וֹם בְּחֵילֵ֑ךְ שַׁ֝לְוָ֗ה בְּאַרְמְנוֹתָֽיִךְ׃ לְ֭מַעַן אַחַ֣י וְרֵעָ֑י אֲדַבְּרָה־נָּ֖א שָׁל֣וֹם בָּֽךְ׃ לְ֭מַעַן בֵּית־יְהֹוָ֣ה אֱלֹהֵ֑ינוּ אֲבַקְשָׁ֖ה ט֣וֹב לָֽךְ׃ וּרְאֵֽה־בָנִ֥ים לְבָנֶ֑יךָ שָׁ֝ל֗וֹם עַל־יִשְׂרָאֵֽל: שָׁל֣וֹם רָ֭ב לְאֹהֲבֵ֣י תוֹרָתֶ֑ךָ וְאֵֽין־לָ֥מוֹ מִכְשֽׁוֹל: יְֽהֹוָ֗ה עֹ֭ז לְעַמּ֣וֹ יִתֵּ֑ן יְהֹוָ֓ה ׀ יְבָרֵ֖ךְ אֶת־עַמּ֣וֹ בַשָּׁלֽוֹם:"}, {"kind": "instruction", "text": "ואומרים קדיש על ישראל"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל־בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "עַל יִשְׂרָאֵל וְעַל רַבָּנָן. וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן. דְּעָסְקִין בְּאוֹרַיְתָא קַדִּשְׁתָּא. דִּי בְאַתְרָא הָדֵין וְדִי בְכָל אֲתַר וַאֲתַר. יְהֵא לָנָא וּלְהוֹן וּלְכוֹן חִנָּא וְחִסְדָּא וְרַחֲמֵי. מִן קֳדָם מָארֵי שְׁמַיָּא וְאַרְעָא וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>יְהֵא</b> שְׁלָמָא רַבָּא מִן שְׁמַיָּא. חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה. וְשֵׁיזָבָא וּרְפוּאָה וּגְאוּלָה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]<br><b>עוֹשֶׂה</b> שָׁלוֹם בִּמְרוֹמָיו. הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "ואומר החזן: (רַבָּנָן) בָּרְכוּ אֶת יְהֹוָה הַמְּבֹרָךְ:"}, {"kind": "text", "text": "ועונים הקהל: בָּרוּךְ יְהֹוָה הַמְּבֹרָךְ לְעוֹלָם וָעֵד:"}, {"kind": "text", "text": "ואומר החזן: בָּרוּךְ יְהֹוָה הַמְּבֹרךְ לְעוֹלָם וָעֵד:"}, {"kind": "header", "text": "עלינו לשבח"}, {"kind": "text", "text": "<b>עָלֵֽינוּ</b> לְשַׁבֵּֽחַ לַֽאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָֽׂנוּ כְּגוֹיֵי הָֽאֲרָצוֹת, וְלֹא שָׂמָֽנוּ כְּמִשְׁפְּחוֹת הָֽאֲדָמָה, שֶׁלֹּא שָׂם חֶלְקֵֽנוּ כָּהֶם וְגוֹרָלֵֽנוּ כְּכָל-הֲמוֹנָם, שֶׁהֵם מִשְׁתַּֽחֲוִים לָהֶֽבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל-אֵל לֹֽא יוֹשִׁיעַ. וַֽאֲנַֽחְנוּ מִשְׁתַּחֲוִים לִפְנֵי מֶֽלֶךְ מַלְכֵי הַֽמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַֽיִם וְיוֹסֵד אָֽרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַֽיִם מִמַּֽעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵֽינוּ, וְאֵין עוֹד אַחֵר, אֱמֶת מַלְכֵּֽנוּ וְאֶֽפֶס זוּלָתוֹ. כַּכָּתוּב בַּתּוֹרָה. וְיָדַעְתָּ֣ הַיּ֗וֹם וַהֲשֵׁבֹתָ֮ אֶל־לְבָבֶךָ֒ כִּ֤י יְהֹוָה֙ ה֣וּא הָֽאֱלֹהִ֔ים בַּשָּׁמַ֣יִם מִמַּ֔עַל וְעַל־הָאָ֖רֶץ מִתָּ֑חַת אֵ֖ין עֽוֹד:"}, {"kind": "text", "text": "<b>עַל</b> כֵּן נְקַוֶּה לָךְ, יְהֹוָה אֱלֹהֵֽינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶֽרֶת עֻזָּךְ, לְהַֽעֲבִיר גִּלּוּלִים מִן הָאָֽרֶץ, וְהָֽאֱלִילִים כָּרוֹת יִכָּֽרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל-בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶֽךָ, לְהַפְנוֹת אֵלֶֽיךָ כָּל-רִשְׁעֵי אָֽרֶץ. יַכִּֽירוּ וְיֵֽדְעוּ כָּל-יֽוֹשְׁבֵי תֵבֵֽל, כִּי לְךָ תִכְרַע כָּל-בֶּֽרֶךְ, תִּשָּׁבַע כָּל-לָשׁוֹן. לְפָנֶֽיךָ, יְהֹוָה אֱלֹהֵֽינוּ יִכְרְעוּ וְיִפֹּֽלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּֽנוּ, וִיקַבְּלוּ כֻלָּם אֶת-עֹל מַלְכוּתֶֽךָ, וְתִמְלוֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעֽוֹלְמֵי עַד תִּמְלוֹךְ בְּכָבוֹד. כַּכָּתוּב בְּתוֹרָתָךְ: יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד׃ וְנֶאֱמַר. וְהָיָ֧ה יְהֹוָ֛ה לְמֶ֖לֶךְ עַל־כָּל־הָאָ֑רֶץ בַּיּ֣וֹם הַה֗וּא יִהְיֶ֧ה יְהֹוָ֛ה אֶחָ֖ד וּשְׁמ֥וֹ אֶחָֽד׃"}, {"kind": "text", "text": "<b>מִזְמ֥וֹר</b> שִׁ֗יר לְי֣וֹם הַשַּׁבָּֽת׃ ט֗וֹב לְהֹד֥וֹת לַיהֹוָ֑ה וּלְזַמֵּ֖ר לְשִׁמְךָ֣ עֶלְיֽוֹן׃ לְהַגִּ֣יד בַּבֹּ֣קֶר חַסְדֶּ֑ךָ וֶ֝אֱמ֥וּנָתְךָ֗ בַּלֵּילֽוֹת׃ עֲֽלֵי־עָ֭שׂוֹר וַעֲלֵי־נָ֑בֶל עֲלֵ֖י הִגָּי֣וֹן בְּכִנּֽוֹר׃ כִּ֤י שִׂמַּחְתַּ֣נִי יְהֹוָ֣ה בְּפׇעֳלֶ֑ךָ בְּֽמַעֲשֵׂ֖י יָדֶ֣יךָ אֲרַנֵּֽן׃ מַה־גָּדְל֣וּ מַעֲשֶׂ֣יךָ יְהֹוָ֑ה מְ֝אֹ֗ד עָמְק֥וּ מַחְשְׁבֹתֶֽיךָ׃ אִֽישׁ־בַּ֭עַר לֹ֣א יֵדָ֑ע וּ֝כְסִ֗יל לֹא־יָבִ֥ין אֶת־זֹֽאת׃ בִּפְרֹ֤חַ רְשָׁעִ֨ים ׀ כְּמ֥וֹ עֵ֗שֶׂב וַ֭יָּצִיצוּ כׇּל־פֹּ֣עֲלֵי אָ֑וֶן לְהִשָּׁמְדָ֥ם עֲדֵי־עַֽד׃ וְאַתָּ֥ה מָר֗וֹם לְעֹלָ֥ם יְהֹוָֽה׃ כִּ֤י הִנֵּ֪ה אֹיְבֶ֡יךָ ׀ יְֽהֹוָ֗ה כִּֽי־הִנֵּ֣ה אֹיְבֶ֣יךָ יֹאבֵ֑דוּ יִ֝תְפָּרְד֗וּ כׇּל־פֹּ֥עֲלֵי אָֽוֶן׃ וַתָּ֣רֶם כִּרְאֵ֣ים קַרְנִ֑י בַּ֝לֹּתִ֗י בְּשֶׁ֣מֶן רַעֲנָֽן׃ וַתַּבֵּ֥ט עֵינִ֗י בְּשׁ֫וּרָ֥י בַּקָּמִ֖ים עָלַ֥י מְרֵעִ֗ים תִּשְׁמַ֥עְנָה אׇזְנָֽי׃ צַ֭דִּיק כַּתָּמָ֣ר יִפְרָ֑ח כְּאֶ֖רֶז בַּלְּבָנ֣וֹן יִשְׂגֶּֽה׃ שְׁ֭תוּלִים בְּבֵ֣ית יְהֹוָ֑ה בְּחַצְר֖וֹת אֱלֹהֵ֣ינוּ יַפְרִֽיחוּ׃ ע֭וֹד יְנוּב֣וּן בְּשֵׂיבָ֑ה דְּשֵׁנִ֖ים וְֽרַעֲנַנִּ֣ים יִהְיֽוּ׃ לְ֭הַגִּיד כִּֽי־יָשָׁ֣ר יְהֹוָ֑ה צ֝וּרִ֗י וְֽלֹא־עַוְלָ֥תָה [עלתה] בּֽוֹ׃"}], "mincha": [{"kind": "header", "text": "קרבנות"}, {"kind": "text", "text": "<b>מנחה לשבת קודש</b>"}, {"kind": "instruction", "text": "לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם יוֹד קֵ\"י בְּוָא\"ו קֵ\"י בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל־יִשְׂרָאֵל. הִנֵּה אֲנַחְנוּ בָּאִים לְהִתְפַּלֵּל תְּפִלַּת מִנְחָה שֶׁל שַׁבָּת קֹדֶשׁ, שֶׁתִּקֵּן יִצְחָק אָבִינוּ עָלָיו הַשָּׁלוֹם, עִם־כָּל־הַמִּצְוֹת הַכְּלוּלוֹת בָּהּ, לְתַקֵּן אֶת־שָׁרְשָׁהּ בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַחַת רוּחַ לְיוֹצְרֵנוּ וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ׃"}, {"kind": "text", "text": "<b>לַמְנַצֵּ֥חַ</b> עַֽל־הַגִּתִּ֑ית לִבְנֵי־קֹ֥רַח מִזְמֽוֹר׃ מַה־יְּדִיד֥וֹת מִשְׁכְּנוֹתֶ֗יךָ יְהֹוָ֥ה צְבָאֽוֹת׃ נִכְסְפָ֬ה וְגַם־כָּֽלְתָ֨ה ׀ נַפְשִׁי֮ לְחַצְר֢וֹת יְהֹ֫וָ֥ה לִבִּ֥י וּבְשָׂרִ֑י יְ֝רַנְּנ֗וּ אֶ֣ל אֵֽל־חָֽי׃ גַּם־צִפּ֨וֹר מָ֪צְאָה בַ֡יִת וּדְר֤וֹר ׀ קֵ֥ן לָהּ֮ אֲשֶׁר־שָׁ֢תָה אֶפְרֹ֫חֶ֥יהָ אֶֽת־מִ֭זְבְּחוֹתֶיךָ יְהֹוָ֣ה צְבָא֑וֹת מַ֝לְכִּ֗י וֵאלֹהָֽי׃ אַ֭שְׁרֵי יוֹשְׁבֵ֣י בֵיתֶ֑ךָ ע֗֝וֹד יְֽהַלְל֥וּךָ סֶּֽלָה׃ אַשְׁרֵ֣י אָ֭דָם עֽוֹז־ל֥וֹ בָ֑ךְ מְ֝סִלּ֗וֹת בִּלְבָבָֽם׃ עֹבְרֵ֤י ׀ בְּעֵ֣מֶק הַ֭בָּכָא מַעְיָ֣ן יְשִׁית֑וּהוּ גַּם־בְּ֝רָכ֗וֹת יַעְטֶ֥ה מוֹרֶֽה׃ יֵ֭לְכוּ מֵחַ֣יִל אֶל־חָ֑יִל יֵרָאֶ֖ה אֶל־אֱלֹהִ֣ים בְּצִיּֽוֹן׃ יְהֹ֘וָ֤ה אֱלֹהִ֣ים צְ֭בָאוֹת שִׁמְעָ֣ה תְפִלָּתִ֑י הַאֲזִ֨ינָה אֱלֹהֵ֖י יַעֲקֹ֣ב סֶֽלָה׃ מָ֭גִנֵּנוּ רְאֵ֣ה אֱלֹהִ֑ים וְ֝הַבֵּ֗ט פְּנֵ֣י מְשִׁיחֶֽךָ׃ כִּ֤י טֽוֹב־י֥וֹם בַּחֲצֵרֶ֗יךָ מֵ֫אָ֥לֶף בָּחַ֗רְתִּי הִ֭סְתּוֹפֵף בְּבֵ֣ית אֱלֹהַ֑י מִ֝דּ֗וּר בְּאׇהֳלֵי־רֶֽשַׁע׃ כִּ֤י שֶׁ֨מֶשׁ ׀ וּמָגֵן֮ יְהֹוָ֢ה אֱלֹ֫הִ֥ים חֵ֣ן וְ֭כָבוֹד יִתֵּ֣ן יְהֹוָ֑ה לֹ֥א יִמְנַע־ט֗֝וֹב לַֽהֹלְכִ֥ים בְּתָמִֽים׃ יְהֹוָ֥ה צְבָא֑וֹת אַֽשְׁרֵ֥י אָ֝דָ֗ם בֹּטֵ֥חַ בָּֽךְ׃"}, {"kind": "text", "text": "<b>וַיְדַבֵּ֥ר</b> יְהֹוָ֖ה אֶל־מֹשֶׁ֥ה לֵּאמֹֽר׃ צַ֚ו אֶת־בְּנֵ֣י יִשְׂרָאֵ֔ל וְאָמַרְתָּ֖ אֲלֵהֶ֑ם אֶת־קׇרְבָּנִ֨י לַחְמִ֜י לְאִשַּׁ֗י רֵ֚יחַ נִֽיחֹחִ֔י תִּשְׁמְר֕וּ לְהַקְרִ֥יב לִ֖י בְּמוֹעֲדֽוֹ׃ וְאָמַרְתָּ֣ לָהֶ֔ם זֶ֚ה הָֽאִשֶּׁ֔ה אֲשֶׁ֥ר תַּקְרִ֖יבוּ לַיהֹוָ֑ה כְּבָשִׂ֨ים בְּנֵֽי־שָׁנָ֧ה תְמִימִ֛ם שְׁנַ֥יִם לַיּ֖וֹם עֹלָ֥ה תָמִֽיד׃ אֶת־הַכֶּ֥בֶשׂ אֶחָ֖ד תַּעֲשֶׂ֣ה בַבֹּ֑קֶר וְאֵת֙ הַכֶּ֣בֶשׂ הַשֵּׁנִ֔י תַּעֲשֶׂ֖ה בֵּ֥ין הָֽעַרְבָּֽיִם׃ וַעֲשִׂירִ֧ית הָאֵיפָ֛ה סֹ֖לֶת לְמִנְחָ֑ה בְּלוּלָ֛ה בְּשֶׁ֥מֶן כָּתִ֖ית רְבִיעִ֥ת הַהִֽין׃ עֹלַ֖ת תָּמִ֑יד הָעֲשֻׂיָה֙ בְּהַ֣ר סִינַ֔י לְרֵ֣יחַ נִיחֹ֔חַ אִשֶּׁ֖ה לַֽיהֹוָֽה׃ וְנִסְכּוֹ֙ רְבִיעִ֣ת הַהִ֔ין לַכֶּ֖בֶשׂ הָאֶחָ֑ד בַּקֹּ֗דֶשׁ הַסֵּ֛ךְ נֶ֥סֶךְ שֵׁכָ֖ר לַיהֹוָֽה׃ וְאֵת֙ הַכֶּ֣בֶשׂ הַשֵּׁנִ֔י תַּעֲשֶׂ֖ה בֵּ֣ין הָֽעַרְבָּ֑יִם כְּמִנְחַ֨ת הַבֹּ֤קֶר וּכְנִסְכּוֹ֙ תַּעֲשֶׂ֔ה אִשֵּׁ֛ה רֵ֥יחַ נִיחֹ֖חַ לַיהֹוָֽה׃"}, {"kind": "text", "text": "<b>אַתָּה</b> הוּא יְהֹוָה אֱלֹהֵֽינוּ, שֶׁהִקְטִֽירוּ אֲבוֹתֵֽינוּ לְפָנֶֽיךָ אֶת קְטֹֽרֶת הַסַּמִּים, בִּזְמַן שֶׁבֵּית הַמִּקְדָשׁ קַיָּם, כַּאֲשֶׁר צִוִּֽיתָ אוֹתָם עַל־יַד מֹשֶׁה נְבִיאָךְ, כַּכָּתוּב בְּתֽוֹרָתָךְ:"}, {"kind": "text", "text": "<b>וַיֹּ֩אמֶר֩</b> יְהֹוָ֨ה אֶל־מֹשֶׁ֜ה קַח־לְךָ֣ סַמִּ֗ים נָטָ֤ף | וּשְׁחֵ֙לֶת֙ וְחֶלְבְּנָ֔ה סַמִּ֖ים וּלְבֹנָ֣ה זַכָּ֑ה בַּ֥ד בְּבַ֖ד יִהְיֶֽה׃ וְעָשִׂ֤יתָ אֹתָהּ֙ קְטֹ֔רֶת רֹ֖קַח מַעֲשֵׂ֣ה רוֹקֵ֑חַ מְמֻלָּ֖ח טָה֥וֹר קֹֽדֶשׁ׃ וְשָֽׁחַקְתָּ֣ מִמֶּ֘נָּה֮ הָדֵק֒ וְנָתַתָּ֨ה מִמֶּ֜נָּה לִפְנֵ֤י הָעֵדֻת֙ בְּאֹ֣הֶל מוֹעֵ֔ד אֲשֶׁ֛ר אִוָּעֵ֥ד לְךָ֖ שָׁ֑מָּה קֹ֥דֶשׁ קׇֽדָשִׁ֖ים תִּהְיֶ֥ה לָכֶֽם׃ וְנֶֽאֱמַר וְהִקְטִ֥יר עָלָ֛יו אַהֲרֹ֖ן קְטֹ֣רֶת סַמִּ֑ים בַּבֹּ֣קֶר בַּבֹּ֗קֶר בְּהֵיטִיב֛וֹ אֶת־הַנֵּרֹ֖ת יַקְטִירֶֽנָּה: וּבְהַעֲלֹ֨ת אַהֲרֹ֧ן אֶת־הַנֵּרֹ֛ת בֵּ֥ין הָעַרְבַּ֖יִם יַקְטִירֶ֑נָּה קְטֹ֧רֶת תָּמִ֛יד לִפְנֵ֥י יְהֹוָ֖ה לְדֹרֹתֵיכֶֽם:"}, {"kind": "text", "text": "<b>תָּנוּ</b> רַבָּנָן: פִּטּוּם הַקְּטֹֽרֶת כֵּיצַד, שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וּשְׁמוֹנָה מָנִים הָיוּ בָהּ. שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וַֽחֲמִשָּׁה כְּמִנְיַן יְמוֹת הַחַמָּה, מָנֶה בְּכָל־יוֹם, מַֽחֲצִיתוֹ בַּבֹּֽקֶר וּמַֽחֲצִיתוֹ בָּעֶרֶב. וּשְׁלֹשָׁה מָנִים יְתֵרִים, שֶׁמֵּהֶם מַכְנִיס כֹּהֵן גָּדוֹל, וְנוֹטֵל מֵהֶם מְלֹא חָפְנָיו בְּיוֹם הַכִּפּוּרִים, וּמַֽחֲזִירָן לְמַכְתֶּֽשֶׁת בְּעֶֽרֶב יוֹם הַכִּפּוּרִים, כְּדֵי לְקַיֵּם מִצְוַת דַקָּה מִן הַדַּקָּה. וְאַחַד־עָשָׂר סַמָּנִים הָיוּ בָהּ, וְאֵֽלּוּ הֵן:"}, {"kind": "text", "text": "א הַצֳּרִי ב וְהַצִּפֹּֽרֶן ג וְהַחֶלְבְּנָה ד וְהַלְּבוֹנָה, מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה. ה מוֹר, ו וּקְצִיעָה ז וְשִׁבֹּֽלֶת נֵרְדְּ ח וְכַרְכֹּם, מִשְׁקַל שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה. ט קֹשְׁטְ שְׁנֵים עָשָׂר, י קִלּוּפָה שְׁלֹשָׁה, יא קִנָּמוֹן תִּשְׁעָה, בּוֹרִית־כַּרְשִׁינָה תִּשְׁעָה קַבִּין. יֵין קַפְרִיסִין סְאִין תְּלָת וְקַבִּין תְּלָתָא. וְאִם לֹא מָצָא יֵין קַפְרִיסִין, מֵבִיא חֲמַר חִיוָר עַתִּיק. מֶֽלַח סְדוֹמִית, רֽוֹבַע. מַעֲלֶה עָשָׁן, כָּל־שֶׁהוּא. רִבִּי נָתָן הַבַּבְלִי אוֹמֵר: אַף כִּפַּת הַיַּרְדֵּן כָּל־שֶׁהִיא, אִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ, וְאִם חִסֵּר אַחַת מִכָּל־סַמְמָנֶֽיהָ, חַיָּיב מִיתָה:"}, {"kind": "text", "text": "<b>רַבָּן</b> שִׁמְעוֹן בֶּן־גַּמְלִיאֵל אוֹמֵר: הַצֳּרִי אֵינוֹ אֶלָּא שְׁרָף, הַנּוֹטֵף מֵֽעֲצֵי הַקְּטָף. בֹּרִית כַּרְשִׁינָה, לְמָה הִיא בָֽאָה, כְּדֵי לְשַׁפּוֹת בָּהּ אֶת־הַצִּפֹּֽרֶן, כְּדֵי שֶׁתְּהֵא נָאָה. יֵין קַפְרִיסִין, לְמָה הוּא בָא? כְּדֵי לִשְׁרוֹת בּוֹ אֶת־הַצִּפֹּֽרֶן כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלֹא מֵי רַגְלַֽיִם יָפִין לָהּ? אֶלָּא שֶׁאֵין מַכְנִיסִין מֵי רַגְלַֽיִם בַּמִּקְדָּשׁ, מִפְּנֵי הַכָּבוֹד:"}, {"kind": "text", "text": "<b>תַּנְיָא</b> רִבִּי נָתָן אוֹמֵר: כְּשֶׁהוּא שׁוֹחֵק, אוֹמֵר: הָדֵק הֵיטֵב, הֵיטֵב הָדֵק. מִפְּנֵי שֶׁהַקּוֹל יָפֶה לַבְּשָׂמִים. פִּטְּמָהּ לַֽחֲצָאִין, כְּשֵׁרָה. לְשָׁלִישׁ וּלְרָבִֽיעַ, לֹא שָׁמַֽעְנוּ. אָמַר רִבִּי יְהוּדָה: זֶה הַכְּלָל, אִם כְּמִדָּתָהּ, כְּשֵׁרָה לַֽחֲצָאִין. וְאִם חִסֵּר אַחַת מִכָּל־סַמְמָנֶֽיהָ, חַיָּיב מִיתָה:"}, {"kind": "text", "text": "<b>תָּנֵי</b> בַר־קַפָּרָא: אַחַת לְשִׁשִּׁים אוֹ לְשִׁבְעִים שָׁנָה, הָֽיְתָה בָֽאָה שֶׁל שִׁירַֽיִם לַֽחֲצָאִין. וְעוֹד תָּנֵי בַר־קַפָּרָא: אִלּוּ הָיָה נוֹתֵן בָּהּ קָרְטוֹב שֶׁל דְּבַשׁ, אֵין אָדָם יָכוֹל לַֽעֲמֹד מִפְּנֵי רֵיחָהּ. וְלָֽמָּה אֵין מְעָֽרְבִין בָּהּ דְּבַשׁ, מִפְּנֵי שֶׁהַתּוֹרָה אָֽמְרָה: כִּ֤י כָל־שְׂאֹר֙ וְכָל־דְּבַ֔שׁ לֹֽא־תַקְטִ֧ירוּ מִמֶּ֛נּוּ אִשֶּׁ֖ה לַֽיהֹוָֽה: יְהֹוָ֣ה צְבָא֣וֹת עִמָּ֑נוּ מִשְׂגָּֽב־לָ֨נוּ אֱלֹהֵ֖י יַֽעֲקֹ֣ב סֶֽלָה׃ יְהֹוָ֥ה צְבָא֑וֹת אַֽשְׁרֵ֥י אָ֝דָ֗ם בֹּטֵ֥חַ בָּֽךְ׃ יְהֹוָ֥ה הוֹשִׁ֑יעָה הַ֝מֶּ֗לֶךְ יַעֲנֵ֥נוּ בְיוֹם־קׇרְאֵֽנוּ: וְעָֽרְבָה֙ לַֽיהֹוָ֔ה מִנְחַ֥ת יְהוּדָ֖ה וִירֽוּשָׁלָ֑‍ִם כִּימֵ֣י עוֹלָ֔ם וּכְשָׁנִ֖ים קַדְמֹנִיֹּֽת:"}, {"kind": "text", "text": "<b>אַ֭שְׁרֵי</b> יוֹשְׁבֵ֣י בֵיתֶ֑ךָ ע֝֗וֹד יְֽהַלְל֥וּךָ סֶּֽלָה: אַשְׁרֵ֣י הָ֭עָם שֶׁכָּ֣כָה לּ֑וֹ אַֽשְׁרֵ֥י הָ֝עָ֗ם שֱׁיְהֹוָ֥ה אֱלֹהָֽיו:"}, {"kind": "text", "text": "<b>תְּהִלָּ֗ה</b> לְדָ֫וִ֥ד אֲרוֹמִמְךָ֣ אֱלוֹהַ֣י הַמֶּ֑לֶךְ וַאֲבָרְכָ֥ה שִׁ֝מְךָ֗ לְעוֹלָ֥ם וָעֶֽד׃ בְּכָל־י֥וֹם אֲבָֽרְכֶ֑ךָּ וַאֲהַֽלְלָ֥ה שִׁ֝מְךָ֗ לְעוֹלָ֥ם וָעֶֽד׃ גָּ֘ד֤וֹל יְהֹוָ֣ה וּמְהֻלָּ֣ל מְאֹ֑ד וְ֝לִגְדֻלָּת֗וֹ אֵ֣ין חֵֽקֶר׃ דּ֣וֹר לְ֭דוֹר יְשַׁבַּ֣ח מַעֲשֶׂ֑יךָ וּגְב֖וּרֹתֶ֣יךָ יַגִּֽידוּ׃ הֲ֭דַר כְּב֣וֹד הוֹדֶ֑ךָ וְדִבְרֵ֖י נִפְלְאֹתֶ֣יךָ אָשִֽׂיחָה׃ וֶעֱז֣וּז נֽוֹרְאֹתֶ֣יךָ יֹאמֵ֑רוּ וגדלותיך [וּגְדֻלָּתְךָ֥] אֲסַפְּרֶֽנָּה׃ זֵ֣כֶר רַב־טוּבְךָ֣ יַבִּ֑יעוּ וְצִדְקָתְךָ֥ יְרַנֵּֽנוּ׃ חַנּ֣וּן וְרַח֣וּם יְהֹוָ֑ה אֶ֥רֶךְ אַ֝פַּ֗יִם וּגְדׇל־חָֽסֶד׃ טוֹב־יְהֹוָ֥ה לַכֹּ֑ל וְ֝רַחֲמָ֗יו עַל־כׇּל־מַעֲשָֽׂיו׃ יוֹד֣וּךָ יְ֭הֹוָה כׇּל־מַעֲשֶׂ֑יךָ וַ֝חֲסִידֶ֗יךָ יְבָרְכֽוּכָה׃ כְּב֣וֹד מַלְכוּתְךָ֣ יֹאמֵ֑רוּ וּגְבוּרָתְךָ֥ יְדַבֵּֽרוּ׃ לְהוֹדִ֤יעַ ׀ לִבְנֵ֣י הָ֭אָדָם גְּבוּרֹתָ֑יו וּ֝כְב֗וֹד הֲדַ֣ר מַלְכוּתֽוֹ׃ מַֽלְכוּתְךָ֗ מַלְכ֥וּת כׇּל־עֹלָמִ֑ים וּ֝מֶֽמְשַׁלְתְּךָ֗ בְּכׇל־דּ֥וֹר וָדֹֽר׃ סוֹמֵ֣ךְ יְ֭הֹוָה לְכׇל־הַנֹּפְלִ֑ים וְ֝זוֹקֵ֗ף לְכׇל־הַכְּפוּפִֽים׃ עֵֽינֵי־כֹ֭ל אֵלֶ֣יךָ יְשַׂבֵּ֑רוּ וְאַתָּ֤ה נֽוֹתֵן־לָהֶ֖ם אֶת־אׇכְלָ֣ם בְּעִתּֽוֹ׃ פּוֹתֵ֥חַ אֶת־יָדֶ֑ךָ וּמַשְׂבִּ֖יעַ לְכׇל־חַ֣י רָצֽוֹן׃ צַדִּ֣יק יְ֭הֹוָה בְּכׇל־דְּרָכָ֑יו וְ֝חָסִ֗יד בְּכׇל־מַעֲשָֽׂיו׃ קָר֣וֹב יְ֭הֹוָה לְכׇל־קֹרְאָ֑יו לְכֹ֤ל אֲשֶׁ֖ר יִקְרָאֻ֣הוּ בֶֽאֱמֶֽת׃ רְצוֹן־יְרֵאָ֥יו יַעֲשֶׂ֑ה וְֽאֶת־שַׁוְעָתָ֥ם יִ֝שְׁמַ֗ע וְיוֹשִׁיעֵֽם׃ שׁוֹמֵ֣ר יְ֭הֹוָה אֶת־כׇּל־אֹהֲבָ֑יו וְאֵ֖ת כׇּל־הָרְשָׁעִ֣ים יַשְׁמִֽיד׃ תְּהִלַּ֥ת יְהֹוָ֗ה יְֽדַבֶּ֫ר פִּ֥י וִיבָרֵ֣ךְ כׇּל־בָּ֭שָׂר שֵׁ֥ם קׇדְשׁ֗וֹ לְעוֹלָ֥ם וָעֶֽד׃ וַאֲנַ֤חְנוּ ׀ נְבָ֘רֵ֤ךְ יָ֗הּ מֵעַתָּ֥ה וְעַד־עוֹלָ֗ם הַֽלְלוּיָֽהּ׃"}, {"kind": "header", "text": "ובא לציון גואל"}, {"kind": "text", "text": "<b>וּבָ֤א</b> לְצִיּוֹן֙ גּוֹאֵ֔ל וּלְשָׁבֵ֥י פֶ֖שַׁע בְּיַֽעֲקֹ֑ב נְאֻ֖ם יְהֹוָֽה׃ וַאֲנִ֗י זֹ֣את בְּרִיתִ֤י אוֹתָם֙ אָמַ֣ר יְהֹוָ֔ה רוּחִי֙ אֲשֶׁ֣ר עָלֶ֔יךָ וּדְבָרַ֖י אֲשֶׁר־שַׂ֣מְתִּי בְּפִ֑יךָ לֹֽא־יָמ֡וּשׁוּ מִפִּ֩יךָ֩ וּמִפִּ֨י זַרְעֲךָ֜ וּמִפִּ֨י זֶ֤רַע זַרְעֲךָ֙ אָמַ֣ר יְהֹוָ֔ה מֵעַתָּ֖ה וְעַד־עוֹלָֽם׃ וְאַתָּ֥ה קָד֑וֹשׁ י֝וֹשֵׁ֗ב תְּהִלּ֥וֹת יִשְׂרָאֵֽל׃ וְקָרָ֨א זֶ֤ה אֶל־זֶה֙ וְאָמַ֔ר קָד֧וֹשׁ ׀ קָד֛וֹשׁ קָד֖וֹשׁ יְהֹוָ֣ה צְבָא֑וֹת מְלֹ֥א כׇל־הָאָ֖רֶץ כְּבוֹדֽוֹ׃ וּמְקַבְּלִין דֵין מִן דֵין וְאָמְרִין קָדִיש בִּשְמֵי מֵרוֹמַא עִלָאַה בֵּית שְכִינְתֵּהּ, קַדִּישׁ עַל אַרְעָא עובַד גְּבוּרְתֵּהּ, קַדִּישׁ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא, יְהֹוָה צְבָאוֹת מַלְיָא כָּל אַרְעָא זִיו יִקְרֵיהּ: וַתִּשָּׂאֵ֣נִי ר֔וּחַ וָאֶשְׁמַ֣ע אַחֲרַ֔י ק֖וֹל רַ֣עַשׁ גָּד֑וֹל בָּר֥וּךְ כְּבוֹד־יְהֹוָ֖ה מִמְּקוֹמֽוֹ׃ וּנְטָלַתְנִי רוּחָא וּשְׁמָעִית בַּתְרַי קַל זִיעַ שַׂגִּיא דִמְשַׁבְּחִין וְאָמְרִין, בְּרִיךְ יְקָרָא דַיהֹוָה מֵאֲתָר בֵּית שְכִינְתֵּהּ, יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד׃ יְהֹוָה מַלְכוּתֵיהּ קָאִים לְעָלַם וּלְעָלְמֵי עָלְמַיָּא: יְהֹוָ֗ה אֱ֠לֹהֵ֠י אַבְרָהָ֞ם יִצְחָ֤ק וְיִשְׂרָאֵל֙ אֲבֹתֵ֔ינוּ שׇׁמְרָה־זֹּ֣את לְעוֹלָ֔ם לְיֵ֥צֶר מַחְשְׁב֖וֹת לְבַ֣ב עַמֶּ֑ךָ וְהָכֵ֥ן לְבָבָ֖ם אֵלֶֽיךָ׃ וְה֤וּא רַח֨וּם ׀ יְכַפֵּ֥ר עָוֺן֮ וְֽלֹא־יַֽ֫שְׁחִ֥ית וְ֭הִרְבָּה לְהָשִׁ֣יב אַפּ֑וֹ וְלֹא־יָ֝עִ֗יר כׇּל־חֲמָתֽוֹ׃ כִּֽי־אַתָּ֣ה אֲ֭דֹנָי ט֣וֹב וְסַלָּ֑ח וְרַב־חֶ֗֝סֶד לְכׇל־קֹֽרְאֶֽיךָ׃ צִדְקָתְךָ֣ צֶ֣דֶק לְעוֹלָ֑ם וְֽתוֹרָתְךָ֥ אֱמֶֽת׃ תִּתֵּ֤ן אֱמֶת֙ לְיַֽעֲקֹ֔ב חֶ֖סֶד לְאַבְרָהָ֑ם אֲשֶׁר־נִשְׁבַּ֥עְתָּ לַאֲבֹתֵ֖ינוּ מִ֥ימֵי קֶֽדֶם׃ בָּ֤ר֣וּךְ אֲדֹנָי֮ י֤וֹם ׀ י֥֫וֹם יַעֲמָס־לָ֗נוּ הָ֘אֵ֤ל יְֽשׁוּעָתֵ֬נוּ סֶֽלָה׃ יְהֹוָ֣ה צְבָא֣וֹת עִמָּ֑נוּ מִשְׂגָּֽב־לָ֨נוּ אֱלֹהֵ֖י יַֽעֲקֹ֣ב סֶֽלָה׃ יְהֹוָ֥ה צְבָא֑וֹת אַֽשְׁרֵ֥י אָ֝דָ֗ם בֹּטֵ֥חַ בָּֽךְ׃ יְהֹוָ֥ה הוֹשִׁ֑יעָה הַ֝מֶּ֗לֶךְ יַעֲנֵ֥נוּ בְיוֹם־קׇרְאֵֽנוּ:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אֱלֹהֵינוּ שֶׁבְּרָאָנוּ לִכְבוֹדוֹ, וְהִבְדִּילָנוּ מִן הַתּוֹעִים, וְנָתַן לָנוּ תּוֹרַת אֱמֶת, וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵנוּ. הוּא יִפְתַּח לִבֵּנוּ בְּתוֹרָתוֹ, וְיָשִׂים בְּלִבֵּנוּ אַהֲבָתוֹ וְיִרְאָתוֹ לַעֲשׂוֹת רְצוֹנוֹ וּלְעָבְדוֹ בְּלֵבָב שָׁלֵם. לֹא נִיגַע לָרִיק, וְלֹא נֵלֵד לַבֶּהָלָה. יְהִי רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ שֶׁנִּשְׁמֹר חֻקֶּיךָ וּמִצְוֹתֶיךָ בָּעוֹלָם הַזֶּה, וְנִזְכֶּה וְנִחְיֶה וְנִירַשׁ טוֹבָה וּבְרָכָה לְחַיֵּי הָעוֹלָם הַבָּא: לְמַ֤עַן ׀ יְזַמֶּרְךָ֣ כָ֭בוֹד וְלֹ֣א יִדֹּ֑ם יְהֹוָ֥ה אֱ֝לֹהַ֗י לְעוֹלָ֥ם אוֹדֶֽךָּ׃ יְהֹוָ֥ה חָפֵ֖ץ לְמַ֣עַן צִדְק֑וֹ יַגְדִּ֥יל תּוֹרָ֖ה וְיַאְדִּֽיר׃ וְיִבְטְח֣וּ בְ֭ךָ יוֹדְעֵ֣י שְׁמֶ֑ךָ כִּ֤י לֹֽא־עָזַ֖בְתָּ דֹרְשֶׁ֣יךָ יְהֹוָֽה׃ יְהֹוָ֥ה אֲדֹנֵ֑ינוּ מָה־אַדִּ֥יר שִׁ֝מְךָ֗ בְּכׇל־הָאָֽרֶץ׃ חִ֭זְקוּ וְיַאֲמֵ֣ץ לְבַבְכֶ֑ם כׇּל־הַ֝מְיַחֲלִ֗ים לַֽיהֹוָֽה׃"}, {"kind": "instruction", "text": "ואומר החזן חצי קדיש"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "קודם פתיחת ההיכל אומרים"}, {"kind": "text", "text": "<b>וַאֲנִ֤י</b> תְפִלָּֽתִי־לְךָ֨ ׀ יְהֹוָ֡ה עֵ֤ת רָצ֗וֹן אֱלֹהִ֥ים בְּרׇב־חַסְדֶּ֑ךָ עֲ֝נֵ֗נִי בֶּאֱמֶ֥ת יִשְׁעֶֽךָ׃ב' פעמים"}, {"kind": "instruction", "text": "פותחים ההיכל ואומרים"}, {"kind": "text", "text": "<b>בְּרִיךְ</b> שְׁמֵהּ דְּמָארֵי עָלְמָא, בְּרִיךְ כִּתְרָךְ וְאַתְרָךְ. יְהֵא רְעוּתָךְ, עִם עַמָּךְ יִשְׂרָאֵל לְעָלַם, וּפוּרְקַן יְמִינָךְ אַחְזֵי לְעַמָּךְ בְּבֵית מִקְדָּשָׁךְ, לְאַמְטוּיֵי לָנָא מִטּוּב נְהוֹרָךְ, וּלְקַבְּלָא צְלוֹתָנָא בְּרַחֲמֵי. יְהֵא רַעֲוָא קֳדָמָךְ דְּתוֹרִיךְ לָן חַיִּין בּטִיבוּ, וְלֶהֱוֵי אֲנָא עַבְדָּךְ פְּקִידָא בְּגוֹ צַדִּיקַיָּא, לְמִרְחַם עָלַי וּלְמִנְטַר יָתִי, וְיַת כּל דִּי לִי, וְדִי לְעַמָּךְ יִשְׂרָאֵל. אַנְתְּ הוּא זָן לְכֹלָא וּמְפַרְנֵס לְכֹלָא. אַנְתְּ הוּא שַׁלִּיט עַל כֹּלָא, אַנְתְּ הוּא דְשַׁלִּיט עַל מַלְכַיָּא, וּמַלְכוּתָא דִילָךְ הִיא. אֲנָא עַבְדָּא דְקֻדְשָׁא בְּרִיךְ הוּא, דְסָגִידְנָא קַמֵּהּ מִקַמֵּי דִּיקַר אוֹרַיְתֵהּ בְּכל עִידָּן וְעִידָּן. לָא עַל אֱנָשׁ רָחִיצְנָא, וְלָא עַל בַּר אֱלָהִין סְמִיכְנָא, אֶלָּא בֵאלָהָא דִשְׁמַיָּא, דְּהוּא אֱלָהָא דִקְשׁוֹט, וְאוֹרַיְתֵהּ קְשׁוֹט, וּנְבִיאוֹהִי קְשׁוֹט, וּמַסְגֵּי לְמֶעְבַּד טַבְוָן וּקְשׁוֹט, בֵּהּ אֲנָא רְחִיץ וְלִשְׁמֵהּ יַקִּירָא קַדִּישָׁא אֲנָא אֵמַר תֻּשְׁבְּחָן. יְהֵא רַעֲוָא קֳדָמָךְ דְּתִפְתַּח לִבִּי בְּאוֹרַיְתָךְ, (וְתִיהַב לִי בְּנִין דִּכְרִין דְּעַבְדִּין רְעוּתָךְ) וְתַשְׁלִים מִשְׁאֲלִין דְּלִבָּאי וְלִבָּא דכל עַמָּךְ יִשְׂרָאֵל לְטַב וּלְחַיִּין וְלִשְׁלָם אָמֵן:"}, {"kind": "instruction", "text": "מוציאים ספר תורה ואומרים"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> הַמָּקוֹם שֶׁנָּתַן תּוֹרָה לְעַמּוֹ יִשְׂרָאֵל, בָּרוּךְ הוּא: אַשְׁרֵי הָעָם שֶׁכָּכָה לּוֹ, אַשְׁרֵי הָעָם שֶׁיְהֹוָה אֱלֹהָיו:"}, {"kind": "instruction", "text": "מוליכים ספר תורה לתיבה אומרים"}, {"kind": "text", "text": "<b>גַּדְּל֣וּ</b> לַיהֹוָ֣ה אִתִּ֑י וּנְרוֹמְמָ֖ה שְׁמ֣וֹ יַחְדָּֽו׃ רוֹמְמ֡וּ יְהֹ֘וָ֤ה אֱלֹהֵ֗ינוּ וְֽ֭הִשְׁתַּחֲווּ לַהֲדֹ֥ם רַגְלָ֗יו קָד֥וֹשׁ הֽוּא׃ רוֹמְמ֡וּ יְהֹ֘וָ֤ה אֱלֹהֵ֗ינוּ וְֽ֭הִשְׁתַּחֲווּ לְהַ֣ר קׇדְשׁ֑וֹ כִּי־קָ֝ד֗וֹשׁ יְהֹוָ֥ה אֱלֹהֵֽינוּ׃"}, {"kind": "text", "text": "אֵין־קָד֥וֹשׁ כַּיהֹוָ֖ה כִּ֣י אֵ֣ין בִּלְתֶּ֑ךָ וְאֵ֥ין צ֖וּר כֵּאלֹהֵֽינוּ׃ כִּ֤י מִ֣י אֱ֭לוֹהַּ מִבַּלְעֲדֵ֣י יְהֹוָ֑ה וּמִ֥י צ֝֗וּר זוּלָתִ֥י אֱלֹהֵֽינוּ׃ תּוֹרָ֥ה צִוָּה־לָ֖נוּ מֹשֶׁ֑ה מוֹרָשָׁ֖ה קְהִלַּ֥ת יַעֲקֹֽב׃ עֵץ־חַיִּ֣ים הִ֭יא לַמַּחֲזִיקִ֣ים בָּ֑הּ וְֽתֹמְכֶ֥יהָ מְאֻשָּֽׁר׃ דְּרָכֶ֥יהָ דַרְכֵי־נֹ֑עַם וְֽכׇל־נְתִ֖יבוֹתֶ֣יהָ שָׁלֽוֹם׃ שָׁל֣וֹם רָ֭ב לְאֹהֲבֵ֣י תוֹרָתֶ֑ךָ וְאֵֽין־לָ֥מוֹ מִכְשֽׁוֹל׃ יְֽהֹוָ֗ה עֹ֭ז לְעַמּ֣וֹ יִתֵּ֑ן יְהֹוָ֓ה ׀ יְבָרֵ֖ךְ אֶת־עַמּ֣וֹ בַשָּׁלֽוֹם׃ כִּ֛י שֵׁ֥ם יְהֹוָ֖ה אֶקְרָ֑א הָב֥וּ גֹ֖דֶל לֵאלֹהֵֽינוּ׃ הַכֹּל תְּנוּ עֹז לֵאלֹהִים, וּתְנוּ כָבוֹד לַתּוֹרָה:"}, {"kind": "instruction", "text": "מגביה ספר תורה ומראה הכתב לקהל ואומרים:"}, {"kind": "text", "text": "<b>וְזֹ֖את </b> הַתּוֹרָ֑ה אֲשֶׁר־שָׂ֣ם מֹשֶׁ֔ה לִפְנֵ֖י בְּנֵ֥י יִשְׂרָאֵֽל׃ תּוֹרָ֥ה צִוָּה־לָ֖נוּ מֹשֶׁ֑ה מוֹרָשָׁ֖ה קְהִלַּ֥ת יַעֲקֹֽב׃ הָאֵל֮ תָּמִ֢ים דַּ֫רְכּ֥וֹ אִמְרַֽת־יְהֹוָ֥ה צְרוּפָ֑ה מָגֵ֥ן ה֝֗וּא לְכֹ֤ל ׀ הַחֹסִ֬ים בּֽוֹ׃"}, {"kind": "instruction", "text": "קוראים לפחות עשרה פסוקים מפרשת שבוע הבא"}, {"kind": "text", "text": "<b>מִזְמ֥וֹר</b> (תהילים צ״ב:א׳-ג׳) שִׁ֗יר לְי֣וֹם הַשַּׁבָּֽת׃ ט֗וֹב לְהֹד֥וֹת לַיהֹוָ֑ה וּלְזַמֵּ֖ר לְשִׁמְךָ֣ עֶלְיֽוֹן׃ לְהַגִּ֣יד בַּבֹּ֣קֶר חַסְדֶּ֑ךָ וֶ֝אֱמ֥וּנָתְךָ֗ בַּלֵּילֽוֹת׃ עֲֽלֵי־עָ֭שׂוֹר וַעֲלֵי־נָ֑בֶל עֲלֵ֖י הִגָּי֣וֹן בְּכִנּֽוֹר׃ כִּ֤י שִׂמַּחְתַּ֣נִי יְהֹוָ֣ה בְּפׇעֳלֶ֑ךָ בְּֽמַעֲשֵׂ֖י יָדֶ֣יךָ אֲרַנֵּֽן׃ מַה־גָּדְל֣וּ מַעֲשֶׂ֣יךָ יְהֹוָ֑ה מְ֝אֹ֗ד עָמְק֥וּ מַחְשְׁבֹתֶֽיךָ׃ אִֽישׁ־בַּ֭עַר לֹ֣א יֵדָ֑ע וּ֝כְסִ֗יל לֹא־יָבִ֥ין אֶת־זֹֽאת׃ בִּפְרֹ֤חַ רְשָׁעִ֨ים ׀ כְּמ֥וֹ עֵ֗שֶׂב וַ֭יָּצִיצוּ כׇּל־פֹּ֣עֲלֵי אָ֑וֶן לְהִשָּׁמְדָ֥ם עֲדֵי־עַֽד׃ וְאַתָּ֥ה מָר֗וֹם לְעֹלָ֥ם יְהֹוָֽה׃ כִּ֤י הִנֵּ֪ה אֹיְבֶ֡יךָ ׀ יְֽהֹוָ֗ה כִּֽי־הִנֵּ֣ה אֹיְבֶ֣יךָ יֹאבֵ֑דוּ יִ֝תְפָּרְד֗וּ כׇּל־פֹּ֥עֲלֵי אָֽוֶן׃ וַתָּ֣רֶם כִּרְאֵ֣ים קַרְנִ֑י בַּ֝לֹּתִ֗י בְּשֶׁ֣מֶן רַעֲנָֽן׃ וַתַּבֵּ֥ט עֵינִ֗י בְּשׁ֫וּרָ֥י בַּקָּמִ֖ים עָלַ֥י מְרֵעִ֗ים תִּשְׁמַ֥עְנָה אׇזְנָֽי׃ צַ֭דִּיק כַּתָּמָ֣ר יִפְרָ֑ח כְּאֶ֖רֶז בַּלְּבָנ֣וֹן יִשְׂגֶּֽה׃ שְׁ֭תוּלִים בְּבֵ֣ית יְהֹוָ֑ה בְּחַצְר֖וֹת אֱלֹהֵ֣ינוּ יַפְרִֽיחוּ׃ ע֭וֹד יְנוּב֣וּן בְּשֵׂיבָ֑ה דְּשֵׁנִ֖ים וְֽרַעֲנַנִּ֣ים יִהְיֽוּ׃ לְ֭הַגִּיד כִּֽי־יָשָׁ֣ר יְהֹוָ֑ה צ֝וּרִ֗י וְֽלֹא־[עַוְלָ֥תָה] עלתה בּֽוֹ׃"}, {"kind": "instruction", "text": "ומחזירים ספר התורה למקומו ואומרים"}, {"kind": "instruction", "text": "יְהַלְל֤וּ ׀ אֶת־שֵׁ֬ם יְהֹוָ֗ה כִּֽי־נִשְׂגָּ֣ב שְׁמ֣וֹ לְבַדּ֑וֹ ה֝וֹד֗וֹ עַל־אֶ֥רֶץ וְשָׁמָֽיִם׃ וַיָּ֤רֶם קֶ֨רֶן ׀ לְעַמּ֡וֹ תְּהִלָּ֤ה לְֽכׇל־חֲסִידָ֗יו לִבְנֵ֣י יִ֭שְׂרָאֵל עַ֥ם קְרֹב֗וֹ הַֽלְלוּיָֽהּ׃ יְהֹוָה הוּא הָאֱלֹהִים, יְהֹוָה֙ ה֣וּא הָֽאֱלֹהִ֔ים בַּשָּׁמַ֣יִם מִמַּ֔עַל וְעַל־הָאָ֖רֶץ מִתָּ֑חַת אֵ֖ין עֽוֹד: אֵין־כָּמ֖וֹךָ בָאֱלֹהִ֥ים ׀ אֲדֹנָ֗י וְאֵ֣ין כְּֽמַעֲשֶֽׂיךָ׃ הֲשִׁיבֵ֨נוּ יְהֹוָ֤ה ׀ אֵלֶ֙יךָ֙ ונשוב [וְֽנָשׁ֔וּבָה] חַדֵּ֥שׁ יָמֵ֖ינוּ כְּקֶֽדֶם׃"}, {"kind": "text", "text": "<b>כִּ֤י</b> לֶ֣קַח ט֭וֹב נָתַ֣תִּי לָכֶ֑ם תּ֝וֹרָתִ֗י אַֽל־תַּעֲזֹֽבוּ׃ תִּכּ֤וֹן תְּפִלָּתִ֣י קְטֹ֣רֶת לְפָנֶ֑יךָ מַֽשְׂאַ֥ת כַּ֝פַּ֗י מִנְחַת־עָֽרֶב: הַקְשִׁ֤יבָה ׀ לְק֬וֹל שַׁוְעִ֗י מַלְכִּ֥י וֵאלֹהָ֑י כִּֽי־אֵ֝לֶ֗יךָ אֶתְפַּלָּֽל:"}, {"kind": "instruction", "text": "ואומר החזן חצי קדיש"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "header", "text": "עמידה"}, {"kind": "text", "text": "<b>עמידה למנחה של שבת</b>"}, {"kind": "text", "text": "<b>אֲ֭דֹנָי</b> שְׂפָתַ֣י תִּפְתָּ֑ח וּ֝פִ֗י יַגִּ֥יד תְּהִלָּתֶֽךָ׃"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵֽאלֹהֵי יַעֲקֹב. הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, קוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵּי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַֽעַן שְׁמוֹ בְּאַֽהֲבָה: בשבת תשובה אומרים: זָכְרֵנוּ לְחַיִּים, מֶלֶךְ חָפֵץ בַּחַיִּים, כָּתְבֵנוּ בְּסֵפֶר חַיִּים, לְמַעַנָךְ אֱלֹהִים חַיִּים. מֶֽלֶךְ עוֹזֵר וּמוֹשִֽׁיעַ וּמָגֵן: בָּרוּךְ אַתָּה יַהַוַהַ, מָגֵן אַבְרָהָם:"}, {"kind": "text", "text": "<b>אַתָּה</b> גִבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֶּה מֵתִים אַתָּה, רַב לְהוֹשִֽׁיעַ."}, {"kind": "text", "text": "בקיץ: מוֹרִיד הַטָּל. בחורף: מַשִּׁיב הָרֽוּחַ וּמוֹרִיד הַגֶּֽשֶׁם."}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶֽסֶד, מְחַיֵּה מֵתִים בְּרַֽחֲמִים רַבִּים, סוֹמֵךְ נֽוֹפְלִים, וְרוֹפֵא חוֹלִים, וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמֽוּנָתוֹ לִֽישֵׁנֵי עָפָר. מִי כָמֽוֹךָ בַּֽעַל גְּבוּרוֹת, וּמִי דֽוֹמֶה לָךְ, מֶֽלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִֽיחַ יְשׁוּעָה. בשבת תשובה אומרים: מִי כָמוֹךָ אָב הָרַחֲמָן, זוֹכֵר יְצוּרָיו בְּרַחֲמִים לְחַיִּים. וְנֶֽאֱמָן אַתָּה לְהַֽחֲיוֹת מֵתִים: בָּרוּךְ אַתָּה יֵהֵוֵהֵ, מְחַיֵּה הַמֵּתִים:"}, {"kind": "instruction", "text": "קדושה בחזרת הש\"ץ אומרים:"}, {"kind": "instruction", "text": "נַקְדִּישָׁךְ וְנַעֲרִיצָךְ, כְּנֹֽעַם שִֽׂיחַ סוֹד שַׂרְפֵי קֹֽדֶשׁ, הַמְשַׁלְּשִׁים לְךָ קְדֻשָּׁה, וְכֵן כָּתוּב עַל יַד נְבִיאָךְ: וְקָרָ֨א זֶ֤ה אֶל־זֶה֙ וְאָמַ֔ר קָד֧וֹשׁ ׀ קָד֛וֹשׁ קָד֖וֹשׁ יְהֹוָ֣ה צְבָא֑וֹת מְלֹ֥א כָל־הָאָ֖רֶץ כְּבוֹדֽוֹ׃ לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים: בָּר֥וּךְ כְּבוֹד־יְהֹוָ֖ה מִמְּקוֹמֽוֹ׃ וּבְדִבְרֵי קָדְשָׁךְ כָּתוּב לֵאמֹר: יִמְלֹ֤ךְ יְהֹוָ֨ה ׀ לְעוֹלָ֗ם אֱלֹהַ֣יִךְ צִ֭יּוֹן לְדֹ֥ר וָדֹ֗ר הַֽלְלוּיָֽהּ:"}, {"kind": "text", "text": "<b>אַתָּה</b> קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ, וּקְדוֹשִׁים בְּכָל־יוֹם יְהַֽלְלֽוּךָ סֶּֽלָה: בָּרוּךְ אַתָּה יֹהֵוָהֵ, הָאֵל הַקָּדוֹשׁ: בשבת תשובה אומרים: הַמֶּלֶךְ הַקָּדוֹשׁ:"}, {"kind": "text", "text": "<b>אַתָּה</b> אֶחָד וְשִׁמְךָ אֶחָד, וּמִי כְעַמְּךָ כְּיִשְׂרָאֵל גוֹי אֶחָד בָּאָרֶץ. תִּפְאֶרֶת גְּדֻלָּה, וַעֲטֶרֶת יְשׁוּעָה, יוֹם מְנוּחָה וּקְדֻשָּׁה לְעַמְּךָ נָתַתָּ. אַבְרָהָם יָגֵל, יִצְחָק יְרַנֵּן, יַעֲקֹב וּבָנָיו יָנוּחוּ בוֹ. מְנוּחַת אַהֲבָה וּנְדָבָה, מְנוּחַת אֱמֶת וֶאֱמוּנָה, מְנוּחַת שָׁלוֹם הַשְׁקֵט וָבֶטַח, מְנוּחָה שְׁלֵמָה שֶׁאַתָּה הוּא רוֹצֶה בָהּ. יַכִּירוּ בָנֶיךָ וְיֵדְעוּ כִּי מֵאִתְּךָ הִיא מְנוּחָתָם, וְעַל מְנוּחָתָם יַקְדִּישׁוּ אֶת שְׁמֶךָ:"}, {"kind": "text", "text": "<b>אֱלֹהֵינוּ</b> וֵאלֹהֵי אֲבוֹתֵינוּ, רְצֵה נָא בִּמְנוּחָתֵנוּ, קַדְּשֵׁנוּ בְּמִצְוֹתֶיךָ, שִׂים חֶלְקֵנוּ בְּתוֹרָתָךְ, שַׂבְּעֵנוּ מִטּוּבָךְ, שַׂמֵּחַ נַפְשֵׁנוּ בִּישׁוּעָתָךְ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶּאֱמֶת, וְהַנְחִילֵנוּ יְהֹוָה אֱלֹהֵינוּ בְּאַהֲבָה וּבְרָצוֹן שַׁבְּתוֹת קָדְשֶׁךָ, וְיָנוּחוּ בָם כָּל יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יְהֹוָה, מְקַדֵּשׁ הַשַּׁבָּת:"}, {"kind": "text", "text": "<b>רְצֵה</b> יְהֹוָה אֱלֹהֵֽינוּ בְּעַמְּךָ יִשְׂרָאֵל וְלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב הָֽעֲבוֹדָה לִדְבִיר בֵּיתֶֽךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, מְהֵרָה בְּאַֽהֲבָה תְקַבֵּל בְּרָצוֹן, וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּֽךָ:"}, {"kind": "instruction", "text": "בראש חודש ובחול המועד אומרים:"}, {"kind": "instruction", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּֽיעַ וְיֵרָאֶה, וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵֽנוּ וְזִכְרוֹן אֲבוֹתֵֽינוּ, זִכְרוֹן יְרוּשָׁלַֽיִם עִירָךְ, וְזִכְרוֹן מָשִֽׁיחַ בֶּן־דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל־עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶֽיךָ, לִפְלֵיטָה, לְטוֹבָה, לְחֵן, לְחֶֽסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם, בְּיוֹם"}, {"kind": "text", "text": "בראש חדש: רֹאשׁ חֹֽדֶשׁ הַזֶּה,"}, {"kind": "text", "text": "בחוה\"מ פסח: חַג הַמַּצּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹֽדֶשׁ הַזֶּה,"}, {"kind": "text", "text": "בחוה\"מ סוכות: חַג הַסֻּכּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹֽדֶשׁ הַזֶּה,"}, {"kind": "instruction", "text": "לְרַחֵם בּוֹ עָלֵֽינוּ וּלְהוֹשִׁיעֵֽנוּ. זָכְרֵֽנוּ יְהֹוָה אֱלֹהֵֽינוּ בּוֹ לְטוֹבָה, וּפָקְדֵֽנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵֽנוּ בוֹ לְחַיִּים טוֹבִים, בִּדְבַר יְשׁוּעָה וְרַחֲמִים. חוּס וְחָנֵּֽנוּ, וַחֲמוֹל וְרַחֵם עָלֵֽינוּ, וְהוֹשִׁיעֵֽנוּ כִּי אֵלֶֽיךָ עֵינֵֽינוּ, כִּי אֵל מֶֽלֶךְ חַנּוּן וְרַחוּם אָֽתָּה:"}, {"kind": "text", "text": "<b>וְאַתָּה</b> בְּרַֽחֲמֶֽיךָ הָרַבִּים, תַּחְפֹּץ בָּֽנוּ וְתִרְצֵֽנוּ, וְתֶֽחֱזֶֽינָה עֵינֵֽינוּ בְּשֽׁוּבְךָ לְצִיּוֹן בְּרַֽחֲמִים: בָּרוּךְ אַתָּה יִהִוִהִ, הַמַּֽחֲזִיר שְׁכִֽינָתוֹ לְצִיּוֹן:"}, {"kind": "instruction", "text": "בברכת \"מודים\" יכרע ב\"מודים\" ויזקוף בשם (בא\"ח בשלח הכ\"א)"}, {"kind": "text", "text": "<b>מוֹדִים</b> אֲנַֽחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ לְעוֹלָם וָעֶד, צוּרֵֽנוּ צוּר חַיֵּֽינוּ וּמָגֵן יִשְׁעֵֽנוּ אַתָּה הוּא, לְדוֹר וָדוֹר נוֹדֶה לְךָ וּנְסַפֵּר תְּהִלָּתֶֽךָ, עַל חַיֵּֽינוּ הַמְּסוּרִים בְּיָדֶֽךָ, וְעַל נִשְׁמוֹתֵֽינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּֽיךָ שֶׁבְּכָל־יוֹם עִמָּֽנוּ, וְעַל נִפְלְאוֹתֶֽיךָ וְטֽוֹבוֹתֶֽיךָ שֶׁבְּכָל־עֵת, עֶֽרֶב וָבֹֽקֶר וְצָֽהֳרָֽיִם. הַטּוֹב, כִּי לֹא כָלוּ רַחֲמֶֽיךָ, הַמְּרַחֵם, כִּי לֹא תַֽמּוּ חֲסָדֶֽיךָ, כִּי מֵֽעוֹלָם קִוִּֽינוּ לָךְ:"}, {"kind": "text", "text": "<b>מודים דרבנן</b><br>בחזרת הש\"ץ כשהחזן אומר מודים, הקהל אומרים:<br>מוֹדִים אֲנַחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׁר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית. בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְחָנֵּנוּ וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמֹר חֻקֶּיךָ וְלַעֲשׂוֹת רְצוֹנְךָ וּלְעָבְדְךָ בְלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ, בָּרוּךְ אֵל הַהוֹדָאוֹת."}, {"kind": "instruction", "text": "בחנוכה ופורים אומרים:"}, {"kind": "instruction", "text": "עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת שֶׁעָשִֽׂיתָ לַאֲבוֹתֵֽינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה:"}, {"kind": "text", "text": "בחנוכה אומרים: <b>בִּימֵי מַתִּתְיָה</b> בֶן־יוֹחָנָן כֹּהֵן גָּדוֹל. חַשְׁמוֹנָאִי וּבָנָיו כְּשֶׁעָֽמְדָֽה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל. לְשַׁכְּחָם תּוֹרָתָךְ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנָךְ. וְאַתָּה בְּרַחֲמֶֽיךָ הָרַבִּים עָמַֽדְתָּ לָהֶם בְּעֵת צָרָתָם. רַֽבְתָּ אֶת רִיבָם. דַּֽנְתָּ אֶת דִּינָם. נָקַֽמְתָּ אֶת נִקְמָתָם. מָסַֽרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים. וְרַבִּים בְּיַד מְעַטִּים. וּרְשָׁעִים בְּיַד צַדִּיקִים. וּטְמֵאִים בְּיַד טְהוֹרִים. וְזֵדִים בְּיַד עֽוֹסְקֵֽי תוֹרָתֶֽךָ. לְךָ עָשִֽׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמָךְ. וּלְעַמְּךָ יִשְׂרָאֵל עָשִֽׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כָּךְ בָּֽאוּ בָנֶֽיךָ לִדְבִיר בֵּיתֶֽךָ. וּפִנּוּ אֶת־הֵיכָלֶֽךָ. וְטִהֲרוּ אֶת־מִקְדָּשֶֽׁךָ. וְהִדְלִֽיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶֽׁךָ. וְקָֽבְעֽוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵֽלּוּ בְּהַלֵּל וּבְהוֹדָאָה. וְעָשִֽׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶֽלָה:"}, {"kind": "text", "text": "בפורים אומרים <b>בִּימֵי מָרְדְּכַי</b> וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה. כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע. בִּקֵּשׁ לְהַשְׁמִיד לַהֲרֹג וּלְאַבֵּד אֶת־כָּל־הַיְּהוּדִים מִנַּֽעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד. בִּשְׁלֹשָׁה עָשָׂר לְחֹֽדֶשׁ שְׁנֵים עָשָׂר. הוּא חֹֽדֶשׁ אֲדָר. וּשְׁלָלָם לָבוֹז. וְאַתָּה בְּרַחֲמֶֽיךָ הָרַבִּים הֵפַֽרְתָּ אֶת־עֲצָתוֹ וְקִלְקַֽלְתָּ אֶת־מַחֲשַׁבְתּוֹ. וַהֲשֵׁבֽוֹתָ לּוֹ גְּמוּלוֹ בְרֹאשׁוֹ. וְתָלוּ אוֹתוֹ וְאֶת־בָּנָיו עַל הָעֵץ. וְעָשִֽׂיתָ עִמָּהֶם נֵס וָפֶֽלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶֽלָה:"}, {"kind": "text", "text": "<b>וְעַל</b> כֻּלָּם יִתְבָּרַךְ, וְיִתְרוֹמָם, וְיִתְנַשֵּׂא, תָּמִיד, שִׁמְךָ מַלְכֵּֽנוּ, לְעוֹלָם וָעֶד. וְכָל־הַחַיִּים יוֹדֽוּךָ סֶּֽלָה: בשבת תשובה אומרים: וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ. וִֽיהַֽלְלוּ וִֽיבָֽרְכוּ אֶת־שִׁמְךָ הַגָּדוֹל בֶּֽאֱמֶת לְעוֹלָם כִּי טוֹב, הָאֵל יְשֽׁוּעָתֵֽנוּ וְעֶזְרָתֵֽנוּ סֶֽלָה, הָאֵל הַטּוֹב: בָּרוּךְ אַתָּה יֻהֻוֻהֻ, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת:"}, {"kind": "text", "text": "<b>שִׂים</b> שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים חֵן וָחֶֽסֶד וְרַֽחֲמִים, עָלֵֽינוּ וְעַל כָּל־יִשְׂרָאֵל עַמֶּֽךָ. וּבָֽרְכֵֽנוּ אָבִֽינוּ כֻּלָּֽנוּ כְּאֶחָד בְּאוֹר פָּנֶֽיךָ, כִּי בְאוֹר פָּנֶֽיךָ נָתַֽתָּ לָּֽנוּ יְהֹוָה אֱלֹהֵֽינוּ תּוֹרָה וְחַיִּים, אַֽהֲבָה וָחֶֽסֶד, צְדָקָה וְרַֽחֲמִים, בְּרָכָה וְשָׁלוֹם. וְטוֹב בְּעֵינֶֽיךָ לְבָֽרְכֵֽנוּ וּלְבָרֵךְ אֶת־כָּל־עַמְּךָ יִשְׂרָאֵל, בְּרֹב עֹז וְשָׁלוֹם: בשבת תשובה אומרים: וּבְסֵפֶר חַיִּים, בְּרָכָה וְשָׁלוֹם, וּפַרְנָסָה טוֹבָה וִישׁוּעָה וְנֶחָמָה, וּגְזֵרוֹת טוֹבוֹת, נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ, אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל, לְחַיִּים טוֹבִים וּלְשָׁלוֹם. בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמְּבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם. אָמֵן:"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>אֱלֹהַי</b>, נְצֹר לְשׁוֹנִי מֵרָע וְשִׂפְתוֹתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּֽעָפָר לַכֹּל תִּֽהְיֶה, פְּתַח לִבִּי בְּתוֹרָתֶֽךָ, וְאַחֲרֵי מִצְוֹתֶֽיךָ תִּרְדֹּף נַפְשִׁי. וְכָל־הַקָּמִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחְשְׁבוֹתָם. יִֽהְי֗וּ כְּמֹ֥ץ לִפְנֵי־ר֑וּחַ וּמַלְאַ֖ךְ יְהֹוָ֣ה דּוֹחֶֽה. קַבֵּל רִנַּת עַמֶּךָ. שַׂגְּבֵנוּ טַהֲרֵנוּ נוֹרָא. עֲשֵׂה לְמַֽעַן שְׁמָךְ, עֲשֵׂה לְמַֽעַן יְמִינָךְ, עֲשֵׂה לְמַֽעַן תּֽוֹרָתָךְ, עֲשֵׂה לְמַֽעַן קְדֻשָּׁתָךְ. לְ֭מַעַן יֵחָלְצ֣וּן יְדִידֶ֑יךָ הוֹשִׁ֖יעָה יְמִֽינְךָ֣ וַעֲנֵֽנִי:"}, {"kind": "instruction", "text": "סגולה לומר פסוק המתחיל וגומר באות שמתחיל וגומר שמו"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>עֹשֶׂה</b> שָׁלוֹם בשבת תשובה אומרים: הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵֽינוּ, וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן:"}, {"kind": "instruction", "text": "יְהִי רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְּיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ, לַעֲשׂוֹת חֻקֵּי רְצוֹנָךְ וּלְעָבְדָךְ בְּלֵבָב שָׁלֵם:"}, {"kind": "instruction", "text": "בשבת שובה אומרים כאן אבינו מלכינו"}, {"kind": "instruction", "text": "ביום שהיו אומרים בו תחנון במנחה אילו היה חל ביום חול עומדים ואומרים צדקתך:"}, {"kind": "text", "text": "<b>צִדְקָתְךָ֨</b> ׀ כְּֽהַרְרֵי־אֵ֗ל מִ֭שְׁפָּטֶיךָ תְּה֣וֹם רַבָּ֑ה אָ֤דָֽם וּבְהֵמָ֖ה תוֹשִׁ֣יעַ יְהֹוָֽה׃ וְצִדְקָתְךָ֥ אֱלֹהִ֗ים עַד־מָ֫ר֥וֹם אֲשֶׁר־עָשִׂ֥יתָ גְדֹל֑וֹת אֱ֝לֹהִ֗ים מִ֣י כָמֽוֹךָ׃ צִדְקָתְךָ֣ צֶ֣דֶק לְעוֹלָ֑ם וְֽתוֹרָתְךָ֥ אֱמֶֽת׃"}, {"kind": "instruction", "text": "ביום שאין אומרים בו תחנון במנחה אין אומרים בו צדקתך אלא אומרים יהי שם"}, {"kind": "text", "text": "<b>יְהִ֤י</b> שֵׁ֣ם יְהֹוָ֣ה מְבֹרָ֑ךְ מֵ֝עַתָּ֗ה וְעַד־עוֹלָֽם׃ מִמִּזְרַח־שֶׁ֥מֶשׁ עַד־מְבוֹא֑וֹ מְ֝הֻלָּ֗ל שֵׁ֣ם יְהֹוָֽה׃ רָ֖ם עַל־כׇּל־גּוֹיִ֥ם ׀ יְהֹוָ֑ה עַ֖ל הַשָּׁמַ֣יִם כְּבוֹדֽוֹ׃ יְהֹוָ֥ה אֲדֹנֵ֑ינוּ מָה־אַדִּ֥יר שִׁ֝מְךָ֗ בְּכׇל־הָאָֽרֶץ׃"}, {"kind": "instruction", "text": "ואומר החזן קדיש תתקבל"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "תִּתְקַבַּל צְלוֹתָֽנָא וּבָֽעוּתָֽנָא, עִם צְלֽוֹתְהוֹן וּבָעֽוּתְהוֹן דְּכָל-בֵּית יִשְׂרָאֵל, קֳדָם אֲבוּנָא דְּבִשְׁמַיָּא וְאַרְעָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא. חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה. וְשֵׁיזָבָא וּרְפוּאָה וּגְאוּלָה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "יפסע שלש פסיעות לאחור<br>עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו. הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>הַ֥לְלוּיָ֨הּ</b> ׀ (תהילים קי״א:א׳-ב׳) אוֹדֶ֣ה יְ֭הֹוָה בְּכׇל־לֵבָ֑ב בְּס֖וֹד יְשָׁרִ֣ים וְעֵדָֽה׃ גְּ֭דֹלִים מַעֲשֵׂ֣י יְהֹוָ֑ה דְּ֝רוּשִׁ֗ים לְכׇל־חֶפְצֵיהֶֽם׃ הוֹד־וְהָדָ֥ר פׇּעֳל֑וֹ וְ֝צִדְקָת֗וֹ עֹמֶ֥דֶת לָעַֽד׃ זֵ֣כֶר עָ֭שָׂה לְנִפְלְאוֹתָ֑יו חַנּ֖וּן וְרַח֣וּם יְהֹוָֽה׃ טֶ֭רֶף נָתַ֣ן לִירֵאָ֑יו יִזְכֹּ֖ר לְעוֹלָ֣ם בְּרִיתֽוֹ׃ כֹּ֣חַ מַ֭עֲשָׂיו הִגִּ֣יד לְעַמּ֑וֹ לָתֵ֥ת לָ֝הֶ֗ם נַחֲלַ֥ת גּוֹיִֽם׃ מַעֲשֵׂ֣י יָ֭דָיו אֱמֶ֣ת וּמִשְׁפָּ֑ט נֶ֝אֱמָנִ֗ים כׇּל־פִּקּוּדָֽיו׃ סְמוּכִ֣ים לָעַ֣ד לְעוֹלָ֑ם עֲ֝שׂוּיִ֗ם בֶּאֱמֶ֥ת וְיָשָֽׁר׃ פְּד֤וּת ׀ שָׁ֘לַ֤ח לְעַמּ֗וֹ צִוָּֽה־לְעוֹלָ֥ם בְּרִית֑וֹ קָד֖וֹשׁ וְנוֹרָ֣א שְׁמֽוֹ׃ רֵ֘אשִׁ֤ית חׇכְמָ֨ה ׀ יִרְאַ֬ת יְהֹוָ֗ה שֵׂ֣כֶל ט֭וֹב לְכׇל־עֹֽשֵׂיהֶ֑ם תְּ֝הִלָּת֗וֹ עֹמֶ֥דֶת לָעַֽד׃"}, {"kind": "instruction", "text": "ואומרים קדיש יהא שלמא"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>יְהֵא</b> שְׁלָמָא רַבָּא מִן שְׁמַיָּא. חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה. וְשֵׁיזָבָא וּרְפוּאָה וּגְאוּלָה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]<br><br><b>עוֹשֶׂה</b> שָׁלוֹם בִּמְרוֹמָיו. הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "header", "text": "עלינו לשבח"}, {"kind": "text", "text": "<b>עָלֵֽינוּ</b> לְשַׁבֵּֽחַ לַֽאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָֽׂנוּ כְּגוֹיֵי הָֽאֲרָצוֹת, וְלֹא שָׂמָֽנוּ כְּמִשְׁפְּחוֹת הָֽאֲדָמָה, שֶׁלֹּא שָׂם חֶלְקֵֽנוּ כָּהֶם וְגוֹרָלֵֽנוּ כְּכָל־הֲמוֹנָם, שֶׁהֵם מִשְׁתַּֽחֲוִים לָהֶֽבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל־אֵל לֹֽא יוֹשִׁיעַ. וַֽאֲנַֽחְנוּ מִשְׁתַּחֲוִים לִפְנֵי מֶֽלֶךְ מַלְכֵי הַֽמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַֽיִם וְיוֹסֵד אָֽרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַֽיִם מִמַּֽעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵֽינוּ, וְאֵין עוֹד אַחֵר, אֱמֶת מַלְכֵּֽנוּ וְאֶֽפֶס זוּלָתוֹ. כַּכָּתוּב בַּתּוֹרָה. וְיָדַעְתָּ֣ הַיּ֗וֹם וַהֲשֵׁבֹתָ֮ אֶל־לְבָבֶךָ֒ כִּ֤י יְהֹוָה֙ ה֣וּא הָֽאֱלֹהִ֔ים בַּשָּׁמַ֣יִם מִמַּ֔עַל וְעַל־הָאָ֖רֶץ מִתָּ֑חַת אֵ֖ין עֽוֹד:"}, {"kind": "text", "text": "<b>עַל</b> כֵּן נְקַוֶּה לָךְ, יְהֹוָה אֱלֹהֵֽינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶֽרֶת עֻזָּךְ, לְהַֽעֲבִיר גִּלּוּלִים מִן הָאָֽרֶץ, וְהָֽאֱלִילִים כָּרוֹת יִכָּֽרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל־בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶֽךָ, לְהַפְנוֹת אֵלֶֽיךָ כָּל־רִשְׁעֵי אָֽרֶץ. יַכִּֽירוּ וְיֵֽדְעוּ כָּל־יֽוֹשְׁבֵי תֵבֵֽל, כִּי לְךָ תִכְרַע כָּל־בֶּֽרֶךְ, תִּשָּׁבַע כָּל־לָשׁוֹן. לְפָנֶֽיךָ, יְהֹוָה אֱלֹהֵֽינוּ יִכְרְעוּ וְיִפֹּֽלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּֽנוּ, וִיקַבְּלוּ כֻלָּם אֶת־עֹל מַלְכוּתֶֽךָ, וְתִמְלוֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעֽוֹלְמֵי עַד תִּמְלוֹךְ בְּכָבוֹד. כַּכָּתוּב בְּתוֹרָתָךְ: יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד׃ וְנֶאֱמַר. וְהָיָ֧ה יְהֹוָ֛ה לְמֶ֖לֶךְ עַל־כָּל־הָאָ֑רֶץ בַּיּ֣וֹם הַה֗וּא יִהְיֶ֧ה יְהֹוָ֛ה אֶחָ֖ד וּשְׁמ֥וֹ אֶחָֽד׃"}]}, "sfard": {"maariv": [{"kind": "header", "text": "תהלים צה"}, {"kind": "text", "text": "לְכוּ נְרַנְּנָה לַיהֹוָה"}, {"kind": "text", "text": "נָרִֽיעָה"}, {"kind": "text", "text": "לְצוּר יִשְׁעֵֽנוּ:"}, {"kind": "text", "text": "נְקַדְּמָה פָנָיו"}, {"kind": "text", "text": "בְּתוֹדָה"}, {"kind": "text", "text": "בִּזְמִרוֹת נָרִֽיעַ לוֹ:"}, {"kind": "text", "text": "כִּי אֵל גָּדוֹל יְהֹוָה"}, {"kind": "text", "text": "וּמֶֽלֶךְ גָּדוֹל עַל־כָּל־אֱלֹהִים:"}, {"kind": "text", "text": "אֲשֶׁר בְּיָדוֹ מֶחְקְרֵי־אָֽרֶץ"}, {"kind": "text", "text": "וְתוֹעֲפוֹת הָרִים לוֹ:"}, {"kind": "text", "text": "אֲשֶׁר־לוֹ הַיָּם וְהוּא עָשָֽׂהוּ"}, {"kind": "text", "text": "וְיַבֶּֽשֶׁת יָדָיו יָצָֽרוּ:"}, {"kind": "text", "text": "בֹּֽאוּ נִשְׁתַּחֲוֶה וְנִכְרָֽעָה"}, {"kind": "text", "text": "נִבְרְכָה"}, {"kind": "text", "text": "לִפְנֵי־יְהֹוָה עֹשֵֽׂנוּ:"}, {"kind": "text", "text": "כִּי הוּא אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וַאֲנַֽחְנוּ עַם מַרְעִיתוֹ"}, {"kind": "text", "text": "וְצֹאן יָדוֹ"}, {"kind": "text", "text": "הַיּוֹם אִם־בְּקֹלוֹ תִשְׁמָֽעוּ:"}, {"kind": "text", "text": "אַל־תַּקְשׁוּ לְבַבְכֶם כִּמְרִיבָה"}, {"kind": "text", "text": "כְּיוֹם מַסָּה בַּמִּדְבָּר:"}, {"kind": "text", "text": "אֲשֶׁר נִסּֽוּנִי אֲבוֹתֵיכֶם"}, {"kind": "text", "text": "בְּחָנֽוּנִי"}, {"kind": "text", "text": "גַּם־רָאוּ פָעֳלִי:"}, {"kind": "text", "text": "אַרְבָּעִים שָׁנָה אָקוּט בְּדוֹר"}, {"kind": "text", "text": "וָאֹמַר"}, {"kind": "text", "text": "עַם תֹּעֵי לֵבָב הֵם"}, {"kind": "text", "text": "וְהֵם לֹא־יָדְעוּ דְרָכָי:"}, {"kind": "text", "text": "אֲשֶׁר־נִשְׁבַּֽעְתִּי בְאַפִּי"}, {"kind": "text", "text": "אִם־יְבֹאוּן אֶל־מְנוּחָתִי:"}, {"kind": "header", "text": "תהלים צו"}, {"kind": "text", "text": "שִֽׁירוּ לַיהֹוָה שִׁיר חָדָשׁ"}, {"kind": "text", "text": "שִֽׁירוּ לַיהֹוָה"}, {"kind": "text", "text": "כָּל־הָאָֽרֶץ:"}, {"kind": "text", "text": "שִֽׁירוּ לַיהֹוָה בָּרְכוּ שְׁמוֹ"}, {"kind": "text", "text": "בַּשְּׂרוּ מִיּוֹם־לְיוֹם יְשׁוּעָתוֹ:"}, {"kind": "text", "text": "סַפְּרוּ בַגּוֹיִם כְּבוֹדוֹ"}, {"kind": "text", "text": "בְּכָל־הָעַמִּים נִפְלְאוֹתָיו:"}, {"kind": "text", "text": "כִּי גָדוֹל יְהֹוָה וּמְהֻלָּל מְאֹד"}, {"kind": "text", "text": "נוֹרָא הוּא עַל־כָּל־אֱלֹהִים:"}, {"kind": "text", "text": "כִּי כָּל־אֱלֹהֵי הָעַמִּים"}, {"kind": "text", "text": "אֱלִילִים"}, {"kind": "text", "text": "וַיהֹוָה שָׁמַֽיִם עָשָׂה:"}, {"kind": "text", "text": "הוֹד־וְהָדָר לְפָנָיו"}, {"kind": "text", "text": "עֹז וְתִפְאֶֽרֶת בְּמִקְדָּשׁוֹ:"}, {"kind": "text", "text": "הָבוּ לַיהֹוָה מִשְׁפְּחוֹת עַמִּים"}, {"kind": "text", "text": "הָבוּ לַיהֹוָה כָּבוֹד וָעֹז:"}, {"kind": "text", "text": "הָבוּ לַיהֹוָה כְּבוֹד שְׁמוֹ"}, {"kind": "text", "text": "שְׂאוּ־מִנְחָה"}, {"kind": "text", "text": "וּבֹֽאוּ לְחַצְרוֹתָיו:"}, {"kind": "text", "text": "הִשְׁתַּחֲווּ לַיהֹוָה"}, {"kind": "text", "text": "בְּהַדְרַת־קֹֽדֶשׁ"}, {"kind": "text", "text": "חִֽילוּ מִפָּנָיו"}, {"kind": "text", "text": "כָּל־הָאָֽרֶץ:"}, {"kind": "text", "text": "אִמְרוּ בַגּוֹיִם"}, {"kind": "text", "text": "יְהֹוָה מָלָךְ"}, {"kind": "text", "text": "אַף־תִּכּוֹן תֵּבֵל"}, {"kind": "text", "text": "בַּל־תִּמּוֹט"}, {"kind": "text", "text": "יָדִין עַמִּים בְּמֵישָׁרִים:"}, {"kind": "text", "text": "יִשְׂמְחוּ הַשָּׁמַֽיִם"}, {"kind": "text", "text": "וְתָגֵל הָאָֽרֶץ"}, {"kind": "text", "text": "יִרְעַם הַיָּם וּמְלֹאוֹ:"}, {"kind": "text", "text": "יַעֲלֹז שָׂדַי וְכָל־אֲשֶׁר־בּוֹ"}, {"kind": "text", "text": "אָז"}, {"kind": "text", "text": "יְרַנְּנוּ כָּל־עֲצֵי־יָֽעַר:"}, {"kind": "text", "text": "לִפְנֵי יְהֹוָה כִּי בָא"}, {"kind": "text", "text": "כִּי בָא לִשְׁפֹּט הָאָֽרֶץ"}, {"kind": "text", "text": "יִשְׁפֹּט־תֵּבֵל בְּצֶֽדֶק"}, {"kind": "text", "text": "וְעַמִּים בֶּאֱמוּנָתוֹ:"}, {"kind": "header", "text": "תהלים צז"}, {"kind": "text", "text": "יְהֹוָה"}, {"kind": "text", "text": "מָלָךְ"}, {"kind": "text", "text": "תָּגֵל הָאָֽרֶץ"}, {"kind": "text", "text": "יִשְׂמְחוּ אִיִּים רַבִּים:"}, {"kind": "text", "text": "עָנָן וַעֲרָפֶל סְבִיבָיו"}, {"kind": "text", "text": "צֶֽדֶק וּמִשְׁפָּט"}, {"kind": "text", "text": "מְכוֹן כִּסְאוֹ:"}, {"kind": "text", "text": "אֵשׁ לְפָנָיו תֵּלֵךְ"}, {"kind": "text", "text": "וּתְלַהֵט סָבִיב צָרָיו:"}, {"kind": "text", "text": "הֵאִֽירוּ בְרָקָיו"}, {"kind": "text", "text": "תֵּבֵל"}, {"kind": "text", "text": "רָאֲתָה וַתָּחֵל הָאָֽרֶץ:"}, {"kind": "text", "text": "הָרִים כַּדּוֹנַג נָמַֽסּוּ"}, {"kind": "text", "text": "מִלִּפְנֵי יְהֹוָה"}, {"kind": "text", "text": "מִלִּפְנֵי אֲדוֹן כָּל־הָאָֽרֶץ:"}, {"kind": "text", "text": "הִגִּֽידוּ הַשָּׁמַֽיִם צִדְקוֹ"}, {"kind": "text", "text": "וְרָאוּ כָל־הָעַמִּים כְּבוֹדוֹ:"}, {"kind": "text", "text": "יֵבֽשׁוּ"}, {"kind": "text", "text": "כָּל־עֹֽבְדֵי פֶֽסֶל"}, {"kind": "text", "text": "הַמִּתְהַלְלִים בָּאֱלִילִים"}, {"kind": "text", "text": "הִשְׁתַּחֲווּ־לוֹ כָּל־אֱלֹהִים:"}, {"kind": "text", "text": "שָׁמְעָה וַתִּשְׂמַח צִיּוֹן"}, {"kind": "text", "text": "וַתָּגֵֽלְנָה בְּנוֹת יְהוּדָה"}, {"kind": "text", "text": "לְמַֽעַן מִשְׁפָּטֶֽיךָ יְהֹוָה:"}, {"kind": "text", "text": "כִּי־אַתָּה יְהֹוָה עֶלְיוֹן"}, {"kind": "text", "text": "עַל־כָּל־הָאָֽרֶץ"}, {"kind": "text", "text": "מְאֹד נַעֲלֵֽיתָ עַל־כָּל־אֱלֹהִים:"}, {"kind": "text", "text": "אֹהֲבֵי יְהֹוָה שִׂנְאוּ רָע"}, {"kind": "text", "text": "שֹׁמֵר נַפְשׁוֹת חֲסִידָיו"}, {"kind": "text", "text": "מִיַּד רְשָׁעִים יַצִּילֵם:"}, {"kind": "text", "text": "אוֹר זָרֻֽעַ לַצַּדִּיק"}, {"kind": "text", "text": "וּלְיִשְׁרֵי־לֵב שִׂמְחָה:"}, {"kind": "text", "text": "שִׂמְחוּ צַדִּיקִים בַּיהֹוָה"}, {"kind": "text", "text": "וְהוֹדוּ לְזֵֽכֶר קָדְשׁוֹ:"}, {"kind": "header", "text": "תהלים צח"}, {"kind": "text", "text": "מִזְמוֹר"}, {"kind": "text", "text": "שִֽׁירוּ לַיהֹוָה שִׁיר חָדָשׁ"}, {"kind": "text", "text": "כִּי־נִפְלָאוֹת עָשָׂה"}, {"kind": "text", "text": "הוֹשִֽׁיעָה־לּוֹ יְמִינוֹ"}, {"kind": "text", "text": "וּזְרֽוֹעַ קָדְשׁוֹ:"}, {"kind": "text", "text": "הוֹדִֽיעַ יְהֹוָה יְשׁוּעָתוֹ"}, {"kind": "text", "text": "לְעֵינֵי הַגּוֹיִם"}, {"kind": "text", "text": "גִּלָּה צִדְקָתוֹ:"}, {"kind": "text", "text": "זָכַר חַסְדּוֹ"}, {"kind": "text", "text": "וֶאֱמוּנָתוֹ"}, {"kind": "text", "text": "לְבֵית יִשְׂרָאֵל"}, {"kind": "text", "text": "רָאוּ כָל־אַפְסֵי־אָֽרֶץ"}, {"kind": "text", "text": "אֵת יְשׁוּעַת אֱלֹהֵֽינוּ:"}, {"kind": "text", "text": "הָרִֽיעוּ לַיהֹוָה"}, {"kind": "text", "text": "כָּל־הָאָֽרֶץ"}, {"kind": "text", "text": "פִּצְחוּ"}, {"kind": "text", "text": "וְרַנְּנוּ וְזַמֵּֽרוּ:"}, {"kind": "text", "text": "זַמְּרוּ לַיהֹוָה בְּכִנּוֹר"}, {"kind": "text", "text": "בְּכִנּוֹר וְקוֹל זִמְרָה:"}, {"kind": "text", "text": "בַּחֲצֹצְרוֹת וְקוֹל שׁוֹפָר"}, {"kind": "text", "text": "הָרִֽיעוּ לִפְנֵי הַמֶּֽלֶךְ יְהֹוָה:"}, {"kind": "text", "text": "יִרְעַם הַיָּם וּמְלֹאוֹ"}, {"kind": "text", "text": "תֵּבֵל"}, {"kind": "text", "text": "וְיֽשְׁבֵי בָהּ:"}, {"kind": "text", "text": "נְהָרוֹת יִמְחֲאוּ־כָף"}, {"kind": "text", "text": "יַֽחַד הָרִים יְרַנֵּֽנוּ:"}, {"kind": "text", "text": "לִפְנֵי־יְהֹוָה"}, {"kind": "text", "text": "כִּי בָא לִשְׁפֹּט הָאָֽרֶץ"}, {"kind": "text", "text": "יִשְׁפֹּט־תֵּבֵל בְּצֶֽדֶק"}, {"kind": "text", "text": "וְעַמִּים בְּמֵישָׁרִים:"}, {"kind": "header", "text": "תהלים צט"}, {"kind": "text", "text": "יְהֹוָה"}, {"kind": "text", "text": "מָלָךְ"}, {"kind": "text", "text": "יִרְגְּזוּ עַמִּים"}, {"kind": "text", "text": "ישֵׁב"}, {"kind": "text", "text": "כְּרוּבִים"}, {"kind": "text", "text": "תָּנוּט הָאָֽרֶץ:"}, {"kind": "text", "text": "יְהֹוָה בְּצִיּוֹן גָּדוֹל"}, {"kind": "text", "text": "וְרָם הוּא עַל־כָּל הָעַמִּים:"}, {"kind": "text", "text": "יוֹדוּ שִׁמְךָ"}, {"kind": "text", "text": "גָּדוֹל וְנוֹרָא קָדוֹשׁ הוּא:"}, {"kind": "text", "text": "וְעֹז מֶֽלֶךְ"}, {"kind": "text", "text": "מִשְׁפָּט אָהֵב"}, {"kind": "text", "text": "אַתָּה כּוֹנַֽנְתָּ מֵישָׁרִים"}, {"kind": "text", "text": "מִשְׁפָּט וּצְדָקָה בְּיַעֲקֹב"}, {"kind": "text", "text": "אַתָּה עָשִֽׂיתָ:"}, {"kind": "text", "text": "רוֹמְמוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וְהִשְׁתַּחֲווּ לַהֲדֹם רַגְלָיו"}, {"kind": "text", "text": "קָדוֹשׁ הוּא:"}, {"kind": "text", "text": "משֶׁה וְאַהֲרֹן בְּכֹהֲנָיו"}, {"kind": "text", "text": "וּשְׁמוּאֵל"}, {"kind": "text", "text": "בְּקֹרְאֵי שְׁמוֹ"}, {"kind": "text", "text": "קֹרִאים אֶל־יְהֹוָה וְהוּא יַעֲנֵם:"}, {"kind": "text", "text": "בְּעַמּוּד עָנָן יְדַבֵּר אֲלֵיהֶם"}, {"kind": "text", "text": "שָׁמְרוּ עֵדֹתָיו"}, {"kind": "text", "text": "וְחֹק נָֽתַן־לָֽמוֹ:"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ אַתָּה עֲנִיתָם"}, {"kind": "text", "text": "אֵל נֹשֵׂא הָיִֽיתָ לָהֶם"}, {"kind": "text", "text": "וְנֹקֵם"}, {"kind": "text", "text": "עַל־עֲלִילוֹתָם:"}, {"kind": "text", "text": "רוֹמְמוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וְהִשְׁתַּחֲווּ"}, {"kind": "text", "text": "לְהַר קָדְשׁוֹ"}, {"kind": "text", "text": "כִּי־קָדוֹשׁ יְהֹוָה אֱלֹהֵֽינוּ:"}, {"kind": "instruction", "text": "בּוֹאוּ וְנֵצֵא לִקְרַאת כַּלָּה, לִקְרַאת שַׁבָּת מַלְכְּתָא, דַחֲקַל תַּפּוּחִין קַדִּישִׁין"}, {"kind": "header", "text": "תהלים כט"}, {"kind": "text", "text": "מִזְמוֹר לְדָוִד"}, {"kind": "text", "text": "הָבוּ לַיהֹוָה"}, {"kind": "text", "text": "בְּנֵי אֵלִים"}, {"kind": "text", "text": "הָבוּ לַיהֹוָה כָּבוֹד וָעֹז:"}, {"kind": "text", "text": "הָבוּ לַיהֹוָה כְּבוֹד שְׁמוֹ"}, {"kind": "text", "text": "הִשְׁתַּחֲווּ לַיהֹוָה"}, {"kind": "text", "text": "בְּהַדְרַת־קֹֽדֶשׁ:"}, {"kind": "text", "text": "קוֹל יְהֹוָה עַל־הַמָּֽיִם"}, {"kind": "text", "text": "אֵל־הַכָּבוֹד הִרְעִים"}, {"kind": "text", "text": "יְהֹוָה עַל־מַֽיִם רַבִּים:"}, {"kind": "text", "text": "קוֹל־יְהֹוָה בַּכֹּֽחַ"}, {"kind": "text", "text": "קוֹל יְהֹוָה בֶּהָדָר:"}, {"kind": "text", "text": "קוֹל יְהֹוָה שֹׁבֵר אֲרָזִים"}, {"kind": "text", "text": "וַיְשַׁבֵּר יְהֹוָה"}, {"kind": "text", "text": "אֶת־אַרְזֵי הַלְּבָנוֹן:"}, {"kind": "text", "text": "וַיַּרְקִידֵם כְּמוֹ־עֵֽגֶל"}, {"kind": "text", "text": "לְבָנוֹן וְשִׂרְיוֹן כְּמוֹ בֶן־רְאֵמִים:"}, {"kind": "text", "text": "קוֹל־יְהֹוָה"}, {"kind": "text", "text": "חֹצֵב לַהֲבוֹת אֵשׁ:"}, {"kind": "text", "text": "קוֹל יְהֹוָה"}, {"kind": "text", "text": "יָחִיל מִדְבָּר"}, {"kind": "text", "text": "יָחִיל יְהֹוָה מִדְבַּר קָדֵשׁ:"}, {"kind": "text", "text": "קוֹל יְהֹוָה יְחוֹלֵל אַיָּלוֹת"}, {"kind": "text", "text": "וַיֶּחֱשׂף יְעָרוֹת"}, {"kind": "text", "text": "וּבְהֵיכָלוֹ"}, {"kind": "text", "text": "כֻּלּוֹ טֹמֵר כָּבוֹד:"}, {"kind": "text", "text": "יְהֹוָה לַמַּבּוּל יָשָׁב"}, {"kind": "text", "text": "וַיֵּֽשֶׁב יְהֹוָה מֶֽלֶךְ לְעוֹלָם:"}, {"kind": "text", "text": "יְהֹוָה עֹז לְעַמּוֹ יִתֵּן"}, {"kind": "text", "text": "יְהֹוָה יְבָרֵךְ אֶת־עַמּוֹ בַשָּׁלוֹם:"}, {"kind": "text", "text": "אָֽנָּא, בְּכֹֽחַ"}, {"kind": "text", "text": "גְּדֻלַּת יְמִינְ֒ךָ"}, {"kind": "text", "text": "תַּתִּיר צְרוּרָה:"}, {"kind": "text", "text": "קַבֵּל רִנַּת עַמְּ֒ךָ"}, {"kind": "text", "text": "שַׂגְּ֒בֵֽנוּ טַהֲרֵֽנוּ נוֹרָא:"}, {"kind": "text", "text": "נָא גִבּוֹר"}, {"kind": "text", "text": "דּוֹרְ֒שֵׁי יִחוּדְ֒ךָ"}, {"kind": "text", "text": "כְּבָבַת שָׁמְ֒רֵם:"}, {"kind": "text", "text": "בָּרְ֒כֵם טַהֲרֵם"}, {"kind": "text", "text": "רַחֲמֵי"}, {"kind": "text", "text": "צִדְ֒קָתְ֒ךָ"}, {"kind": "text", "text": "תָּמִיד גָּמְ֒לֵם:"}, {"kind": "text", "text": "חֲסִין קָדוֹשׁ"}, {"kind": "text", "text": "בְּרֹב טוּבְ֒ךָ"}, {"kind": "text", "text": "נַהֵל עֲדָתֶֽךָ:"}, {"kind": "text", "text": "יָחִיד גֵּאֶה לְעַמְּ֒ךָ פְּנֵה,"}, {"kind": "text", "text": "זוֹכְ֒רֵי קְדֻשָּׁתֶֽךָ:"}, {"kind": "text", "text": "שַׁוְעָתֵֽנוּ קַבֵּל וּשְׁ֒מַע צַעֲקָתֵֽנוּ"}, {"kind": "text", "text": "יוֹדֵֽעַ תַּעֲלוּמוֹת:"}, {"kind": "text", "text": "בָּרוּךְ שֵׁם"}, {"kind": "text", "text": "כְּבוֹד מַלְ֒כוּתוֹ"}, {"kind": "text", "text": "לְעוֹלָם וָעֶד:"}, {"kind": "header", "text": "לכה דודי"}, {"kind": "text", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה."}, {"kind": "text", "text": "פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה."}, {"kind": "text", "text": "פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "שָׁמוֹר וְזָכוֹר"}, {"kind": "text", "text": "בְּדִבּוּר אֶחָד."}, {"kind": "text", "text": "הִשְׁמִיעָֽנוּ אֵל הַמְיוּחָד."}, {"kind": "text", "text": "יְהֹוָה אֶחָד וּשְׁמוֹ אֶחָד."}, {"kind": "text", "text": "לְשֵׁם וּלְתִפְאֶֽרֶת וְלִתְהִלָּה:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה."}, {"kind": "instruction", "text": "פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "לִקְרַאת שַׁבָּת לְכוּ וְנֵלְ֒כָה."}, {"kind": "text", "text": "כִּי הִיא מְקוֹר הַבְּ֒רָכָה."}, {"kind": "text", "text": "מֵרֹאשׁ מִקֶּֽדֶם"}, {"kind": "text", "text": "נְסוּכָה."}, {"kind": "text", "text": "סוֹף מַעֲשֶׂה בְּמַחֲשָׁבָה תְּחִלָּה:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה."}, {"kind": "instruction", "text": "פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "מִקְדַּשׁ מֶֽלֶךְ עִיר מְלוּכָה."}, {"kind": "text", "text": "קֽוּמִי צְאִי מִתּוֹךְ הַהֲפֵכָה."}, {"kind": "text", "text": "רַב לָךְ שֶֽׁבֶת"}, {"kind": "text", "text": "בְּעֵֽמֶק הַבָּכָא."}, {"kind": "text", "text": "וְהוּא יַחְמוֹל עָלַֽיִךְ חֶמְלָה:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה."}, {"kind": "instruction", "text": "פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "הִתְנַעֲרִי מֵעָפָר קֽוּמִי."}, {"kind": "text", "text": "לִבְשִׁי בִּגְדֵי תִפְאַרְתֵּךְ"}, {"kind": "text", "text": "עַמִּי."}, {"kind": "text", "text": "עַל יַד בֶּן יִשַּׁי בֵּית הַלַּחְמִי."}, {"kind": "text", "text": "קָרְבָה אֶל נַפְשִׁי גְּאָלָהּ:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה."}, {"kind": "instruction", "text": "פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "הִתְעוֹרְ֒רִי. הִתְעוֹרְ֒רִי."}, {"kind": "text", "text": "כִּי בָא אוֹרֵךְ"}, {"kind": "text", "text": "קֽוּמִי אֽוֹרִי."}, {"kind": "text", "text": "עֽוּרִי עֽוּרִי שִׁיר דַּבֵּֽרִי."}, {"kind": "text", "text": "כְּבוֹד יְהֹוָה עָלַֽיִךְ נִגְלָה:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה."}, {"kind": "instruction", "text": "פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "לֹא תֵבֽוֹשִׁי וְלֹא תִכָּלְ֒מִי."}, {"kind": "text", "text": "מַה תִּשְׁתּוֹחֲחִי"}, {"kind": "text", "text": "וּמַה תֶּהֱמִי."}, {"kind": "text", "text": "בָּךְ יֶחֱסוּ"}, {"kind": "text", "text": "עֲנִיֵּי עַמִּי."}, {"kind": "text", "text": "וְנִבְנְ֒תָה עִיר"}, {"kind": "text", "text": "עַל תִּלָּהּ:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה."}, {"kind": "instruction", "text": "פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "וְהָיוּ לִמְשִׁסָּה"}, {"kind": "text", "text": "שֹׁסָֽיִךְ."}, {"kind": "text", "text": "וְרָחֲקוּ"}, {"kind": "text", "text": "כָּל מְבַלְּ֒עָֽיִךְ."}, {"kind": "text", "text": "יָשִׂישׂ עָלַֽיִךְ אֱלֹהָֽיִךְ."}, {"kind": "text", "text": "כִּמְשׂוֹשׂ חָתָן עַל כַּלָּה:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה."}, {"kind": "instruction", "text": "פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "יָמִין וּשְׂמֹאל תִּפְרֽוֹצִי."}, {"kind": "text", "text": "וְאֶת יְהֹוָה תַּעֲרִֽיצִי."}, {"kind": "text", "text": "עַל יַד אִישׁ בֶּן פַּרְצִי."}, {"kind": "text", "text": "וְנִשְׂמְ֒חָה וְנָגִֽילָה:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה."}, {"kind": "instruction", "text": "פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "בּֽוֹאִי בְשָׁלוֹם עֲטֶֽרֶת בַּעְלָהּ."}, {"kind": "text", "text": "גַּם בְּרִנָּה (ביו\"ט בְּשִׂמְחָה)"}, {"kind": "text", "text": "וּבְצָהֳלָה."}, {"kind": "text", "text": "תּוֹךְ אֱמוּנֵי עַם סְגֻלָּה."}, {"kind": "text", "text": "בֹּֽאִי כַלָּה בֹּֽאִי כַלָּה"}, {"kind": "text", "text": "בֹּֽאִי כַלָּה שַׁבָּת מַלְכְּתָא:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה."}, {"kind": "instruction", "text": "פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "header", "text": "תהלים צב"}, {"kind": "text", "text": "מִזְמוֹר שִׁיר לְיוֹם הַשַּׁבָּת:"}, {"kind": "text", "text": "טוֹב לְהֹדוֹת לַיהֹוָה"}, {"kind": "text", "text": "וּלְזַמֵּר לְשִׁמְךָ עֶלְיוֹן:"}, {"kind": "text", "text": "לְהַגִּיד בַּבֹּֽקֶר חַסְדֶּֽךָ"}, {"kind": "text", "text": "וֶאֱמוּנָתְךָ בַּלֵּילוֹת:"}, {"kind": "text", "text": "עֲלֵי־עָשׂוֹר וַעֲלֵי־נָֽבֶל"}, {"kind": "text", "text": "עֲלֵי הִגָּיוֹן בְּכִנּוֹר:"}, {"kind": "text", "text": "כִּי שִׂמַּחְתַּֽנִי יְהֹוָה"}, {"kind": "text", "text": "בְּפָעֳלֶֽךָ"}, {"kind": "text", "text": "בְּמַעֲשֵׂי יָדֶֽיךָ אֲרַנֵּן:"}, {"kind": "text", "text": "מַה־גָּדְלוּ מַעֲשֶֽׂיךָ יְהֹוָה"}, {"kind": "text", "text": "מְאֹד עָמְקוּ מַחְשְׁבֹתֶֽיךָ:"}, {"kind": "text", "text": "אִישׁ־בַּֽעַר לֹא יֵדָע"}, {"kind": "text", "text": "וּכְסִיל לֹא־יָבִין אֶת־זֹאת:"}, {"kind": "text", "text": "בִּפְרֹֽחַ רְשָׁעִים כְּמוֹ עֵֽשֶׂב"}, {"kind": "text", "text": "וַיָּצִֽיצוּ כָּל־פֹּֽעֲלֵי אָֽוֶן"}, {"kind": "text", "text": "לְהִשָּׁמְדָם עֲדֵי־עַד:"}, {"kind": "text", "text": "וְאַתָּה מָרוֹם לְעֹלָם"}, {"kind": "text", "text": "יְהֹוָה:"}, {"kind": "text", "text": "כִּי הִנֵּה אֹיְבֶֽיךָ יְהֹוָה"}, {"kind": "text", "text": "כִּי־הִנֵּה אֹיְבֶֽיךָ יֹאבֵֽדוּ"}, {"kind": "text", "text": "יִתְפָּרְדוּ כָּל־פֹּֽעֲלֵי אָֽוֶן:"}, {"kind": "text", "text": "וַתָּֽרֶם כִּרְאֵים קַרְנִי"}, {"kind": "text", "text": "בַּלֹּתִי בְּשֶֽׁמֶן רַעֲנָן:"}, {"kind": "text", "text": "וַתַּבֵּט עֵינִי"}, {"kind": "text", "text": "בְּשׁוּרָי"}, {"kind": "text", "text": "בַּקָּמִים עָלַי מְרֵעִים"}, {"kind": "text", "text": "תִּשְׁמַֽעְנָה אָזְנָי:"}, {"kind": "text", "text": "צַדִּיק כַּתָּמָר יִפְרָח"}, {"kind": "text", "text": "כְּאֶֽרֶז בַּלְּבָנוֹן יִשְׂגֶּה:"}, {"kind": "text", "text": "שְׁתוּלִים בְּבֵית יְהֹוָה"}, {"kind": "text", "text": "בְּחַצְרוֹת אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "יַפְרִֽיחוּ:"}, {"kind": "text", "text": "עוֹד יְנוּבוּן בְּשֵׂיבָה"}, {"kind": "text", "text": "דְּשֵׁנִים וְרַעֲנַנִּים יִהְיוּ:"}, {"kind": "text", "text": "לְהַגִּיד כִּי־יָשָׁר יְהֹוָה"}, {"kind": "text", "text": "צוּרִי"}, {"kind": "text", "text": "וְלֹא־עַוְלָֽתָה בּוֹ:"}, {"kind": "header", "text": "תהלים צג"}, {"kind": "text", "text": "יְהֹוָה מָלָךְ"}, {"kind": "text", "text": "גֵּאוּת לָבֵשׁ"}, {"kind": "text", "text": "לָבֵשׁ יְהֹוָה"}, {"kind": "text", "text": "עֹז הִתְאַזָּר"}, {"kind": "text", "text": "אַף־תִּכּוֹן תֵּבֵל"}, {"kind": "text", "text": "בַּל־תִּמּוֹט:"}, {"kind": "text", "text": "נָכוֹן כִּסְאֲךָ מֵאָז"}, {"kind": "text", "text": "מֵעוֹלָם אָֽתָּה:"}, {"kind": "text", "text": "נָשְׂאוּ נְהָרוֹת יְהֹוָה"}, {"kind": "text", "text": "נָשְׂאוּ נְהָרוֹת קוֹלָם"}, {"kind": "text", "text": "יִשְׂאוּ נְהָרוֹת דָּכְיָם:"}, {"kind": "text", "text": "מִקֹּלוֹת מַֽיִם רַבִּים"}, {"kind": "text", "text": "אַדִּירִים מִשְׁבְּרֵי־יָם"}, {"kind": "text", "text": "אַדִּיר בַּמָּרוֹם יְהֹוָה:"}, {"kind": "text", "text": "עֵדֹתֶֽיךָ נֶאֶמְנוּ מְאֹד"}, {"kind": "text", "text": "לְבֵיתְךָ נָֽאֲוָה־קֹּֽדֶשׁ"}, {"kind": "text", "text": "יְהֹוָה לְאֹֽרֶךְ יָמִים:"}, {"kind": "header", "text": "קדיש יתום"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְ֒מָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְ֒עוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְ֒כוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְ֒קָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ"}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְ֒יוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְ֒חַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל,"}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְ֒מַן קָרִיב"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְ֒עָלְ֒מֵי עָלְ֒מַיָּא:"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקוּדְשָׁא, בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵֽלָּא (בעשי\"ת וּלְ֒עֵֽלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְ֒כָתָא וְשִׁירָתָא,"}, {"kind": "text", "text": "תֻּשְׁבְּחָתָא וְנֶחֱמָתָא,"}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְ֒מָא, וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא"}, {"kind": "text", "text": "וְחַיִּים טוֹבִים"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "עוֹשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "(בעשי\"ת הַשָּׁלוֹם)"}, {"kind": "text", "text": "בִּמְ֒רוֹמָיו"}, {"kind": "text", "text": "הוּא יַעֲשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן"}, {"kind": "text", "text": "כְּגַוְנָא דְאִנּוּן מִתְיַחֲדִין לְעֵלָּא בְּאֶחָד. אוֹף הָכִי אִיהִי אִתְיַחֲדַת לְתַתָּא בְּרָזָא דְאֶחָד לְמֶהֱוֵי עִמְּהוֹן לְעֵלָּא חָד לָקֳבֵל חָד. קוּדְשָׁא בְּרִיךְ הוּא אֶחָד. לְעֵלָּא לָא יָתִיב עַל כּוּרְסַיָּא דִּיקָרֵיהּ עַד דְאִיהִי אִתְעֲבִידַת בְּרָזָא דְאֶחָד. כְּגַוְנָא דִילֵיהּ לְמֶהֱוֵי אֶחָד בְּאֶחָד. וְהָא אוּקִימְנָא רָזָא דַיהֹוָה אֶחָד וּשְׁמוֹ אֶחָד:"}, {"kind": "text", "text": "רָזָא דְשַׁבָּת אִיהִי שַׁבָּת דְּאִתְאַחֲדַת בְּרָזָא דְאֶחָד. לְמִשְׁרֵי עֲלָהּ רָזָא דְאֶחָד. צְלוֹתָא דְמַעֲלֵי שַׁבְּתָא, דְּהָא אִתְאַחֲדַת כּוּרְסַיָּא יַקִּירָא קַדִּישָׁא בְּרָזָא דְאֶחָד. וְאִתְתַּקָּנַת לְמִשְׁרֵי עֲלָהּ מַלְכָּא קַדִּישָׁא עִלָּאָה. כַּד עַיִּל שַׁבְּתָא אִיהִי אִתְיַחֲדַת וְאִתְפַּרְשַׁת מִסִּטְרָא אַחֲרָא. וְכָל דִּינִין מִתְעַבְּרִין מִנָּהּ וְאִיהִי אִשְׁתְּאָרַת בְּיִחוּדָא דִנְהִירוּ קַדִּישָׁא. וְאִתְעַטְּרַת בְּכַמָה עִטְרִין לְגַבֵּי מַלְכָּא קַדִּישָׁא. וְכָל שׁוּלְטָנֵי רוּגְזִין וּמָארֵי דְדִינָא כֻּלְּהוּ עַרְקִין וְאִתְעַבְּרוּ מִנָּהּ. וְלֵית שׁוּלְטָנָא אַחֲרָא בְּכֻלְּהוּ עָלְמִין (בַּר מִנָּהּ). וְאַנְפָּהָא נְהִירִין בִּנְהִירוּ עִלָּאָה וְאִתְעַטְּרַת לְתַתָּא בְּעַמָּא קַדִּישָׁא. וְכֻלְּהוֹן מִתְעַטְּרִין בְּנִשְׁמָתִין חַדְתִּין כְּדֵין שֵׁירוּתָא דִצְלוֹתָא. לְבָרְכָא לָהּ בְּחֶדְוָה בִּנְהִירוּ דְּאַנְפִּין. וְלוֹמַר:"}, {"kind": "text", "text": "וְלוֹמַר בָּרְכוּ אֶת יְהוָה הַמְבוֹרָךְ. אֶת דַּיְקָא; דָא שַׁבָּת דְּמַעֲלֵי שַׁבְּתָא. בָּרוּךְ יְהוָה הַמְבוֹרָךְ. דָּא אַפִּיקוּ דְבִרְכָאָן מִמְּקוֹרָא דְחַיֵּי וַאֲתַר דְּנָפִיק מִנֵּיהּ כָּל שַׁקְיוּ לְּאַשְׁקָאָה לְכלָּא, וּבְגִין דְּאִיהוּ מְקוֹרָא בְּרָזָא דְאָת קַיָמָא קְרִינָן לֵיהּ הַמְבוֹרָךְ, אִיהוּ מַבּוּעָא דְבֵירָא. וְכֵיוָן דִּמְטָאָן הָתָם הָא כוּלְהוּ לְעוֹלָם וָעֶד, וְדָא אִיהוּ \"בָּרוּךְ יְהוָה הַמְבוֹרָךְ לְעוֹלָם וָעֶד\":"}, {"kind": "header", "text": "ברכו"}, {"kind": "text", "text": "<b>בָּרְ֒כוּ אֶת יְהֹוָה הַמְ֒בֹרָךְ:</b>"}, {"kind": "text", "text": "<b>בָּרוּךְ יְהֹוָה הַמְ֒בֹרָךְ</b>"}, {"kind": "text", "text": "<b>לְעוֹלָם וָעֶד:</b>"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "אֲשֶׁר בִּדְבָרוֹ מַעֲרִיב עֲרָבִים"}, {"kind": "text", "text": "בְּחָכְמָה פּוֹתֵֽחַ שְׁעָרִים"}, {"kind": "text", "text": "וּבִתְבוּנָה מְשַׁנֶּה עִתִּים"}, {"kind": "text", "text": "וּמַחֲלִיף אֶת הַזְּ֒מַנִּים"}, {"kind": "text", "text": "וּמְסַדֵּר אֶת הַכּוֹכָבִים"}, {"kind": "text", "text": "בְּמִשְׁמְ֒רוֹתֵיהֶם בָּרָקִֽיעַ"}, {"kind": "text", "text": "כִּרְצוֹנוֹ."}, {"kind": "text", "text": "בּוֹרֵא יוֹם וָלָֽיְלָה"}, {"kind": "text", "text": "גּוֹלֵל אוֹר מִפְּ֒נֵי חֽשֶׁךְ"}, {"kind": "text", "text": "וְחֽשֶׁךְ מִפְּ֒נֵי אוֹר"}, {"kind": "text", "text": "וּמַעֲבִיר יוֹם"}, {"kind": "text", "text": "וּמֵבִיא לָֽיְלָה"}, {"kind": "text", "text": "וּמַבְדִּיל בֵּין יוֹם וּבֵין לָֽיְלָה"}, {"kind": "text", "text": "יְהֹוָה צְבָאוֹת שְׁמוֹ:"}, {"kind": "text", "text": "❖אֵל"}, {"kind": "text", "text": "חַי וְקַיָּם"}, {"kind": "text", "text": "תָּמִיד יִמְלֹךְ עָלֵֽינוּ"}, {"kind": "text", "text": "לְעוֹלָם וָעֶד."}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַמַּעֲרִיב עֲרָבִים:"}, {"kind": "text", "text": "אַהֲבַת עוֹלָם"}, {"kind": "text", "text": "בֵּית יִשְׂרָאֵל עַמְּ֒ךָ אָהָֽבְתָּ"}, {"kind": "text", "text": "תּוֹרָה וּמִצְוֹת"}, {"kind": "text", "text": "חֻקִּים וּמִשְׁפָּטִים"}, {"kind": "text", "text": "אוֹתָֽנוּ לִמַּֽדְתָּ."}, {"kind": "text", "text": "עַל כֵּן יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בְּשָׁכְבֵֽנוּ וּבְקוּמֵֽנוּ"}, {"kind": "text", "text": "נָשִֽׂיחַ בְּחֻקֶּֽיךָ"}, {"kind": "text", "text": "וְנִשְׂמַח"}, {"kind": "text", "text": "בְּדִבְרֵי תַלמוּד תּוֹרָתֶֽךָ"}, {"kind": "text", "text": "וּבְמִצְוֹתֶֽיךָ לְעוֹלָם וָעֶד."}, {"kind": "text", "text": "כִּי הֵם חַיֵּֽינוּ"}, {"kind": "text", "text": "וְאֹֽרֶךְ יָמֵֽינוּ"}, {"kind": "text", "text": "וּבָהֶם נֶהְגֶּה יוֹמָם וָלָֽיְלָה."}, {"kind": "text", "text": "❖וְאַהֲבָתְ֒ךָ"}, {"kind": "text", "text": "אַל תָּסִיר מִמֶּֽנּוּ לְעוֹלָמִים."}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אוֹהֵב עַמּוֹ יִשְׂרָאֵל:"}, {"kind": "instruction", "text": "אֵל מֶֽלֶךְ נֶאֱמָן:"}, {"kind": "text", "text": "<b>שְׁמַע יִשְׂרָאֵל</b>"}, {"kind": "text", "text": "<b>יְהֹוָה אֱלֹהֵֽינוּ יְהֹוָה אֶחָד :</b>"}, {"kind": "instruction", "text": "בָּרוּךְ שֵׁם"}, {"kind": "instruction", "text": "כְּבוֹד מַלְ֒כוּתוֹ"}, {"kind": "instruction", "text": "לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "וְאָהַבְתָּ אֵת יְהֹוָה אֱלֹהֶֽיךָ"}, {"kind": "text", "text": "בְּכָל֯־לְ֯בָבְ֒ךָ"}, {"kind": "text", "text": "וּבְ֒כָל־נַפְשְׁךָ"}, {"kind": "text", "text": "וּבְ֒כָל־מְאֹדֶֽךָ:"}, {"kind": "text", "text": "וְהָיוּ הַדְּ֒בָרִים הָאֵֽלֶּה"}, {"kind": "text", "text": "אֲשֶׁר֯ אָ֯נֹכִי מְצַוְּ֒ךָ הַיּוֹם"}, {"kind": "text", "text": "עַל֯־לְ֯בָבֶֽךָ:"}, {"kind": "text", "text": "וְשִׁנַּנְתָּם"}, {"kind": "text", "text": "לְבָנֶֽיךָ"}, {"kind": "text", "text": "וְדִבַּרְתָּ בָּם"}, {"kind": "text", "text": "בְּשִׁבְתְּ֒ךָ בְּבֵיתֶֽךָ"}, {"kind": "text", "text": "וּבְ֒לֶכְתְּךָ בַדֶּֽרֶךְ"}, {"kind": "text", "text": "וּבְ֒שָׁכְבְּךָ וּבְ֒קוּמֶֽךָ:"}, {"kind": "text", "text": "וּקְ֒שַׁרְתָּם לְאוֹת"}, {"kind": "text", "text": "עַל֯־יָ֯דֶֽךָ"}, {"kind": "text", "text": "וְהָיוּ לְטֹטָפֹת"}, {"kind": "text", "text": "בֵּין עֵינֶֽיךָ:"}, {"kind": "text", "text": "וּכְ֒תַבְתָּם"}, {"kind": "text", "text": "עַל־מְזֻזוֹת בֵּיתֶֽךָ"}, {"kind": "text", "text": "וּבִשְׁ֒עָרֶֽיךָ:"}, {"kind": "text", "text": "וְהָיָה"}, {"kind": "text", "text": "אִם־שָׁמֹֽעַ תִּשְׁמְעוּ אֶל־מִצְוֹתַי"}, {"kind": "text", "text": "אֲשֶׁר֯ אָ֯נֹכִי מְצַוֶּה אֶתְ֒כֶם הַיּוֹם"}, {"kind": "text", "text": "לְאַהֲבָה אֶת־יְהֹוָה אֱלֹהֵיכֶם"}, {"kind": "text", "text": "וּלְ֒עָבְ֒דוֹ"}, {"kind": "text", "text": "בְּכָלּ־לְּבַבְ֒כֶם"}, {"kind": "text", "text": "וּבְ֒כָל־נַפְשְׁכֶם:"}, {"kind": "text", "text": "וְנָתַתִּי מְטַר֯־אַ֯רְצְכֶם"}, {"kind": "text", "text": "בְּעִתּוֹ"}, {"kind": "text", "text": "יּוֹרֶה"}, {"kind": "text", "text": "וּמַלְקוֹשׁ"}, {"kind": "text", "text": "וְאָסַפְתָּ דְגָנֶֽךָ"}, {"kind": "text", "text": "וְתִירשְׁךָ וְיִצְהָרֶֽךָ:"}, {"kind": "text", "text": "וְנָתַתִּי עֵֽשֶׂב֯"}, {"kind": "text", "text": "בְּ֯שָׂדְ֒ךָ לִבְ֒הֶמְתֶּֽךָ"}, {"kind": "text", "text": "וְאָכַלְתָּ וְשָׂבָֽעְתָּ:"}, {"kind": "text", "text": "הִשָּׁמְ֒רוּ לָכֶם פֶּן֯־יִ֯פְתֶּה לְבַבְ֒כֶם"}, {"kind": "text", "text": "וְסַרְתֶּם"}, {"kind": "text", "text": "וַעֲבַדְתֶּם אֱלֹהִים֯ אֲ֯חֵרִים"}, {"kind": "text", "text": "וְהִשְׁתַּחֲוִיתֶם לָהֶם:"}, {"kind": "text", "text": "וְחָרָה אַף־יְהֹוָה בָּכֶם"}, {"kind": "text", "text": "וְעָצַר֯ אֶ֯ת־הַשָּׁמַֽיִם"}, {"kind": "text", "text": "וְלֹּא֯־יִ֯הְיֶה מָטָר"}, {"kind": "text", "text": "וְהָאֲדָמָה לֹא תִתֵּן אֶת֯־יְ֯בוּלָהּ"}, {"kind": "text", "text": "וַאֲבַדְתֶּם֯ מְ֯הֵרָה"}, {"kind": "text", "text": "מֵעַל הָאָֽרֶץ הַטֹּבָה"}, {"kind": "text", "text": "אֲשֶׁר֯ יְ֯הֹוָה נֹתֵן לָכֶם:"}, {"kind": "text", "text": "וְשַׂמְתֶּם֯ אֶ֯ת־דְּבָרַי֯ אֵֽ֯לֶּה"}, {"kind": "text", "text": "עַל֯־לְ֯בַבְ֒כֶם וְעַל־נַפְשְׁ֒כֶם"}, {"kind": "text", "text": "וּקְ֒שַׁרְתֶּם֯ אֹ֯תָם לְאוֹת"}, {"kind": "text", "text": "עַלּ־יֶּדְ֒כֶם"}, {"kind": "text", "text": "וְהָיוּ לְטוֹטָפֹת"}, {"kind": "text", "text": "בֵּין עֵינֵיכֶם:"}, {"kind": "text", "text": "וְלִמַּדְתֶּם֯ אֹ֯תָם אֶת־בְּנֵיכֶם"}, {"kind": "text", "text": "לְדַבֵּר בָּם"}, {"kind": "text", "text": "בְּשִׁבְתְּךָ בְּבֵיתֶֽךָ"}, {"kind": "text", "text": "וּבְ֒לֶכְתְּ֒ךָ בַדֶּֽרֶךְ"}, {"kind": "text", "text": "וּבְ֒שָׁכְבְּ֒ךָ וּבְ֒קוּמֶֽךָ:"}, {"kind": "text", "text": "וּכְ֒תַבְתָּם"}, {"kind": "text", "text": "עַל־מְזוּזוֹת בֵּיתֶֽךָ"}, {"kind": "text", "text": "וּבִשְׁ֒עָרֶֽיךָ:"}, {"kind": "text", "text": "לְמַֽעַן֯ יִ֯רְבּוּ יְמֵיכֶם"}, {"kind": "text", "text": "וִימֵי בְנֵיכֶם"}, {"kind": "text", "text": "עַל הָאֲדָמָה"}, {"kind": "text", "text": "אֲשֶׁר נִשְׁבַּע יְהֹוָה לַאֲבֹתֵיכֶם"}, {"kind": "text", "text": "לָתֵת לָהֶם"}, {"kind": "text", "text": "כִּימֵי הַשָּׁמַֽיִם עַל־הָאָֽרֶץ:"}, {"kind": "text", "text": "וַֽיֹּאמֶר֯ יְהֹוָה אֶ֯ל־משֶׁה לֵּאמֹר:"}, {"kind": "text", "text": "דַּבֵּר֯ אֶ֯ל־בְּנֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאָמַרְתָּ אֲלֵהֶם"}, {"kind": "text", "text": "וְעָשׂוּ לָהֶם צִיצִת"}, {"kind": "text", "text": "עַל־כַּנְ֒פֵי בִגְ֒דֵיהֶם"}, {"kind": "text", "text": "לְדֹרֹתָם"}, {"kind": "text", "text": "וְנָתְ֒נוּ עַל־צִיצִת"}, {"kind": "text", "text": "הַכָּנָף֯"}, {"kind": "text", "text": "פְּ֯תִיל תְּכֵֽלֶת:"}, {"kind": "text", "text": "וְהָיָה לָכֶם לְצִיצִת"}, {"kind": "text", "text": "וּרְ֒אִיתֶם֯ אֹ֯תוֹ"}, {"kind": "text", "text": "וּזְ֒כַרְתֶּם֯"}, {"kind": "text", "text": "אֶ֯ת־כָּל־מִצְוֹת֯ יְ֯הֹוָה"}, {"kind": "text", "text": "וַעֲשִׂיתֶם֯ אֹ֯תָם"}, {"kind": "text", "text": "וְלֹא תָתֽוּרוּ אַחֲרֵי לְבַבְ֒כֶם"}, {"kind": "text", "text": "וְאַחֲרֵי עֵינֵיכֶם"}, {"kind": "text", "text": "אֲשֶׁר֯־אַ֯תֶּם זֹנִים֯ אַ֯חֲרֵיהֶם:"}, {"kind": "text", "text": "לְמַֽעַן תִּזְכְּרוּ"}, {"kind": "text", "text": "וַעֲשִׂיתֶם֯ אֶ֯ת־כָּל־מִצְוֹתָי"}, {"kind": "text", "text": "וִהְיִיתֶם קְדשִׁים לֵאלֹהֵיכֶם:"}, {"kind": "text", "text": "אֲנִי יְהֹוָה אֱלֹהֵיכֶם֯"}, {"kind": "text", "text": "אֲ֯שֶׁר הוֹצֵֽאתִי אֶתְ֒כֶם֯"}, {"kind": "text", "text": "מֵּאֶֽרֶץ מִצְרַֽיִם"}, {"kind": "text", "text": "לִהְיוֹת לָכֶם לֵאלֹהִים֯"}, {"kind": "text", "text": "אֲ֯נִי יְהֹוָה אֱלֹהֵיכֶם֯:"}, {"kind": "text", "text": "אֱ֯מֶת"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵיכֶם֯ אֱ֯מֶת:"}, {"kind": "text", "text": "וֶאֱמוּנָה כָּל זֹאת"}, {"kind": "text", "text": "וְקַיָּם עָלֵֽינוּ"}, {"kind": "text", "text": "כִּי הוּא יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וְאֵין זוּלָתוֹ"}, {"kind": "text", "text": "וַאֲנַֽחְנוּ יִשְׂרָאֵל עַמּוֹ:"}, {"kind": "text", "text": "הַפּוֹדֵֽנוּ"}, {"kind": "text", "text": "מִיַּד מְלָכִים"}, {"kind": "text", "text": "מַלְכֵּֽנוּ הַגּוֹאֲלֵֽנוּ"}, {"kind": "text", "text": "מִכַּף כָּל הֶעָרִיצִים:"}, {"kind": "text", "text": "הָאֵל"}, {"kind": "text", "text": "הַנִּפְרָע לָֽנוּ"}, {"kind": "text", "text": "מִצָּרֵֽינוּ"}, {"kind": "text", "text": "וְהַמְ֒שַׁלֵּם גְּמוּל"}, {"kind": "text", "text": "לְכָל אֹיְ֒בֵי נַפְשֵֽׁנוּ:"}, {"kind": "text", "text": "הָעֹשֶׂה גְדוֹלוֹת"}, {"kind": "text", "text": "עַד אֵין חֵֽקֶר"}, {"kind": "text", "text": "נִסִּים וְנִפְלָאוֹת עַד אֵין מִסְפָּר:"}, {"kind": "text", "text": "הַשָּׂם נַפְשֵֽׁנוּ בַּחַיִּים"}, {"kind": "text", "text": "וְלֹא נָתַן לַמּוֹט רַגְלֵֽנוּ"}, {"kind": "text", "text": "הַמַּדְרִיכֵֽנוּ"}, {"kind": "text", "text": "עַל בָּמוֹת אֹיְ֒בֵֽינוּ"}, {"kind": "text", "text": "וַיָּֽרֶם קַרְנֵֽנוּ"}, {"kind": "text", "text": "עַל כָּל שׂוֹנְ֒אֵֽינוּ:"}, {"kind": "text", "text": "הָעֹֽשֶׂה לָּֽנוּ נִסִּים"}, {"kind": "text", "text": "וּנְקָמָה בְּפַרְעֹה"}, {"kind": "text", "text": "אוֹתוֹת וּמוֹפְ֒תִים"}, {"kind": "text", "text": "בְּאַדְמַת בְּנֵי חָם:"}, {"kind": "text", "text": "הַמַּכֶּה בְעֶבְרָתוֹ"}, {"kind": "text", "text": "כָּל בְּכוֹרֵי מִצְרָֽיִם"}, {"kind": "text", "text": "וַיּוֹצֵא אֶת עַמּוֹ יִשְׂרָאֵל"}, {"kind": "text", "text": "מִתּוֹכָם"}, {"kind": "text", "text": "לְחֵרוּת עוֹלָם:"}, {"kind": "text", "text": "הַמַּעֲבִיר בָּנָיו"}, {"kind": "text", "text": "בֵּין גִּזְרֵי"}, {"kind": "text", "text": "יַם סוּף"}, {"kind": "text", "text": "אֶת רוֹדְ֒פֵיהֶם וְאֶת שׂוֹנְ֒אֵיהֶם"}, {"kind": "text", "text": "בִּתְהוֹמוֹת טִבַּע:"}, {"kind": "text", "text": "וְרָאוּ בָנָיו גְּבוּרָתוֹ"}, {"kind": "text", "text": "שִׁבְּ֒חוּ וְהוֹדוּ לִשְׁמוֹ."}, {"kind": "text", "text": "❖וּמַלְכוּתוֹ"}, {"kind": "text", "text": "בְרָצוֹן קִבְּ֒לוּ עֲלֵיהֶם"}, {"kind": "text", "text": "משֶׁה וּבְנֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "לְךָ עָנוּ שִׁירָה בְּשִׂמְחָה רַבָּה"}, {"kind": "text", "text": "וְאָמְ֒רוּ כֻלָּם:"}, {"kind": "text", "text": "מִי כָמֹֽכָה בָּאֵלִם יְהֹוָה"}, {"kind": "text", "text": "מִי כָּמֹֽכָה"}, {"kind": "text", "text": "נֶאְדָּר בַּקֹּֽדֶשׁ"}, {"kind": "text", "text": "נוֹרָא תְהִלֹּת עֹֽשֵׂה פֶלֶא:"}, {"kind": "text", "text": "❖מַלְכוּתְךָ רָאוּ בָנֶֽיךָ"}, {"kind": "text", "text": "בּוֹקֵֽעַ יָם לִפְנֵי משֶׁה"}, {"kind": "text", "text": "זֶה אֵלִי עָנוּ"}, {"kind": "text", "text": "וְאָמְ֒רוּ:"}, {"kind": "text", "text": "יְהֹוָה יִמְלֹךְ לְעֹלָם וָעֶד:"}, {"kind": "text", "text": "❖וְנֶאֱמַר"}, {"kind": "text", "text": "כִּי פָדָה יְהֹוָה אֶת יַעֲקֹב"}, {"kind": "text", "text": "וּגְאָלוֹ"}, {"kind": "text", "text": "מִיַּד חָזָק מִמֶּֽנּוּ."}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "גָּאַל יִשְׂרָאֵל:"}, {"kind": "text", "text": "הַשְׁכִּיבֵֽנוּ יְהֹוָה אֱלֹהֵֽינוּ לְשָׁלוֹם"}, {"kind": "text", "text": "וְהַעֲמִידֵֽנוּ מַלְכֵּֽנוּ לְחַיִּים"}, {"kind": "text", "text": "טוֹבִים וּלְשָׁלוֹם"}, {"kind": "text", "text": "וּפְרוֹשׂ עָלֵֽינוּ סֻכַּת שְׁלוֹמֶֽךָ"}, {"kind": "text", "text": "וְתַקְּ֒נֵֽנוּ"}, {"kind": "text", "text": "בְּעֵצָה טוֹבָה מִלְּ֒פָנֶֽיךָ"}, {"kind": "text", "text": "וְהוֹשִׁיעֵֽנוּ מְהֵרָה לְמַֽעַן שְׁמֶֽךָ."}, {"kind": "text", "text": "וְהָגֵן בַּעֲדֵֽנוּ וְהָסֵר מֵעָלֵֽינוּ"}, {"kind": "text", "text": "אוֹיֵב דֶּֽבֶר וְחֶֽרֶב"}, {"kind": "text", "text": "וְרָעָב וְיָגוֹן"}, {"kind": "text", "text": "וְהָסֵר שָׂטָן מִלְּ֒פָנֵֽינוּ"}, {"kind": "text", "text": "וּמֵאַחֲרֵֽינוּ"}, {"kind": "text", "text": "וּבְצֵל כְּנָפֶֽיךָ תַּסְתִּירֵֽנוּ."}, {"kind": "text", "text": "כִּי אֵל"}, {"kind": "text", "text": "שׁוֹמְ֒רֵֽנוּ וּמַצִּילֵֽנוּ אָֽתָּה"}, {"kind": "text", "text": "כִּי אֵל"}, {"kind": "text", "text": "מֶֽלֶךְ חַנּוּן וְרַחוּם אָֽתָּה."}, {"kind": "text", "text": "וּשְׁמוֹר צֵאתֵֽנוּ וּבוֹאֵֽנוּ"}, {"kind": "text", "text": "לְחַיִּים וּלְשָׁלוֹם"}, {"kind": "text", "text": "מֵעַתָּה וְעַד עוֹלָם."}, {"kind": "text", "text": "❖וּפְרוֹשׂ עָלֵֽינוּ"}, {"kind": "text", "text": "סֻכַּת רַחֲמִים וְחַיִּים וְשָׁלוֹם:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַפּוֹרֵשׂ סֻכַּת שָׁלוֹם עָלֵֽינוּ"}, {"kind": "text", "text": "וְעַל כָּל עַמּוֹ יִשְׂרָאֵל"}, {"kind": "text", "text": "וְעַל יְרוּשָׁלָֽיִם:"}, {"kind": "text", "text": "וְשָׁמְ֒רוּ בְנֵי־יִשְׂרָאֵל"}, {"kind": "text", "text": "אֶת־הַשַּׁבָּת."}, {"kind": "text", "text": "לַעֲשׂוֹת אֶת־הַשַּׁבָּת"}, {"kind": "text", "text": "לְדֹרֹתָם"}, {"kind": "text", "text": "בְּרִית עוֹלָם:"}, {"kind": "text", "text": "בֵּינִי"}, {"kind": "text", "text": "וּבֵין בְּנֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "אוֹת הִיא לְעֹלָם."}, {"kind": "text", "text": "כִּי־שֵֽׁשֶׁת יָמִים עָשָׂה יְהֹוָה"}, {"kind": "text", "text": "אֶת־הַשָּׁמַֽיִם וְאֶת־הָאָֽרֶץ"}, {"kind": "text", "text": "וּבַיּוֹם הַשְּׁ֒בִיעִי"}, {"kind": "text", "text": "שָׁבַת"}, {"kind": "text", "text": "וַיִּנָּפַשׁ:"}, {"kind": "text", "text": "וַיְדַבֵּר משֶׁה"}, {"kind": "text", "text": "אֶת מוֹעֲדֵי יְהֹוָה"}, {"kind": "text", "text": "אֶל בְּנֵי יִשְׂרָאֵל:"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְ֒מָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְ֒עוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְ֒כוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְקָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ."}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְ֒יוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְ֒חַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל,"}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְ֒מַן קָרִיב"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְ֒עָלְ֒מֵי עָלְ֒מַיָּא"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקוּדְשָׁא, בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵֽלָּא (בעשי\"ת וּלְעֵֽלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְ֒כָתָא וְשִׁירָתָא,"}, {"kind": "text", "text": "תֻּשְׁבְּחָתָא וְנֶחֱמָתָא,"}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְ֒מָא, וְאִמְ֒רוּ אָמֵן:"}, {"kind": "header", "text": "עמידה לערבית של שבת"}, {"kind": "instruction", "text": "אֲדֹנָי שְׂפָתַי תִּפְתָּח"}, {"kind": "instruction", "text": "וּפִי יַגִּיד תְּהִלָּתֶֽךָ:"}, {"kind": "text", "text": "<b>אבות</b>"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "אֱלֹהֵי אַבְרָהָם אֱלֹהֵי יִצְחָק"}, {"kind": "text", "text": "וֵאלֹהֵי יַעֲקֹב"}, {"kind": "text", "text": "הָאֵל"}, {"kind": "text", "text": "הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא"}, {"kind": "text", "text": "אֵל עֶלְיוֹן"}, {"kind": "text", "text": "גּוֹמֵל חֲסָדִים טוֹבִים"}, {"kind": "text", "text": "וְקוֹנֵה הַכֹּל"}, {"kind": "text", "text": "וְזוֹכֵר חַסְ֒דֵי אָבוֹת"}, {"kind": "text", "text": "וּמֵבִיא גוֹאֵל"}, {"kind": "text", "text": "לִבְ֒נֵי בְנֵיהֶם"}, {"kind": "text", "text": "לְמַֽעַן שְׁמוֹ בְּאַהֲבָה:"}, {"kind": "instruction", "text": "זָכְ֒רֵֽנוּ לְחַיִּים"}, {"kind": "instruction", "text": "מֶֽלֶךְ חָפֵץ בַּחַיִּים"}, {"kind": "instruction", "text": "וְכָתְ֒בֵֽנוּ בְּסֵֽפֶר הַחַיִּים"}, {"kind": "instruction", "text": "לְמַעַנְ֒ךָ אֱלֹהִים חַיִּים:"}, {"kind": "text", "text": "מֶֽלֶךְ עוֹזֵר וּמוֹשִֽׁיעַ וּמָגֵן:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "מָגֵן אַבְרָהָם:"}, {"kind": "text", "text": "<b>גבורות</b>"}, {"kind": "text", "text": "אַתָּה גִבּוֹר לְעוֹלָם אֲדֹנָי"}, {"kind": "text", "text": "מְחַיֶּה מֵתִים אַתָּה"}, {"kind": "text", "text": "רַב לְהוֹשִֽׁיעַ:"}, {"kind": "text", "text": "<b>מוֹרִיד הַטָּל</b>"}, {"kind": "text", "text": "<b>מַשִּׁיב הָרֽוּחַ</b>"}, {"kind": "text", "text": "<b>וּמוֹרִיד הַגֶּֽשֶׁם:</b>"}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶֽסֶד"}, {"kind": "text", "text": "מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים"}, {"kind": "text", "text": "סוֹמֵךְ נוֹפְ֒לִים"}, {"kind": "text", "text": "וְרוֹפֵא חוֹלִים"}, {"kind": "text", "text": "וּמַתִּיר אֲסוּרִים"}, {"kind": "text", "text": "וּמְ֒קַיֵּם אֱמוּנָתוֹ"}, {"kind": "text", "text": "לִישֵׁנֵי עָפָר,"}, {"kind": "text", "text": "מִי כָמֽוֹךָ בַּֽעַל גְּבוּרוֹת"}, {"kind": "text", "text": "וּמִי דּֽוֹמֶה לָּךְ"}, {"kind": "text", "text": "מֶֽלֶךְ מֵמִית וּמְ֒חַיֶּה"}, {"kind": "text", "text": "וּמַצְמִֽיחַ יְשׁוּעָה:"}, {"kind": "instruction", "text": "מִי כָמֽוֹךָ אָב הָרַחַמָן"}, {"kind": "instruction", "text": "זוֹכֵר יְצוּרָיו לְחַיִּים"}, {"kind": "instruction", "text": "בְּרַחֲמִים:"}, {"kind": "text", "text": "וְנֶאֱמָן אַתָּה"}, {"kind": "text", "text": "לְהַחֲיוֹת מֵתִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "מְחַיֵּה הַמֵּתִים:"}, {"kind": "text", "text": "<b>קדושת השם</b>"}, {"kind": "text", "text": "אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ"}, {"kind": "text", "text": "וּקְ֒דוֹשִׁים"}, {"kind": "text", "text": "בְּכָל יוֹם יְהַלְ֒לֽוּךָ סֶּֽלָה:"}, {"kind": "text", "text": "כִּי אֵל מֶֽלֶךְ"}, {"kind": "text", "text": "גָּדוֹל וְקָדוֹשׁ אָֽתָּה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הָאֵל הַקָּדוֹשׁ:"}, {"kind": "instruction", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "instruction", "text": "הַמֶּֽלֶךְ הַקָּדוֹשׁ:"}, {"kind": "text", "text": "אַתָּה קִדַּֽשְׁתָּ אֶת יוֹם הַשְּׁ֒בִיעִי"}, {"kind": "text", "text": "לִשְׁמֶךָ."}, {"kind": "text", "text": "תַּכְלִית"}, {"kind": "text", "text": "מַעֲשֵׂה שָׁמַֽיִם וָאָֽרֶץ."}, {"kind": "text", "text": "וּבֵרַכְתּוֹ מִכָּל הַיָּמִים."}, {"kind": "text", "text": "וְקִדַּשְׁתּוֹ מִכָּל הַזְּ֒מַנִּים"}, {"kind": "text", "text": "וְכֵן כָּתוּב בְּתוֹרָתֶֽךָ:"}, {"kind": "text", "text": "וַיְכֻלּוּ הַשָּׁמַֽיִם וְהָאָֽרֶץ"}, {"kind": "text", "text": "וְכָל־צְבָאָם:"}, {"kind": "text", "text": "וַיְכַל אֱלֹהִים בַּיּוֹם הַשְּׁ֒בִיעִי"}, {"kind": "text", "text": "מְלַאכְתּוֹ אֲשֶׁר עָשָׂה."}, {"kind": "text", "text": "וַיִּשְׁבֹּת בַּיּוֹם הַשְּׁ֒בִיעִי"}, {"kind": "text", "text": "מִכָּל־מְלַאכְתּוֹ אֲשֶׁר עָשָׂה:"}, {"kind": "text", "text": "וַיְבָֽרֶךְ אֱלֹהִים אֶת־יוֹם הַשְּׁ֒בִיעִי"}, {"kind": "text", "text": "וַיְקַדֵּשׁ אֹתוֹ."}, {"kind": "text", "text": "כִּי בוֹ שָׁבַת"}, {"kind": "text", "text": "מִכָּל־מְלַאכְתּוֹ"}, {"kind": "text", "text": "אֲשֶׁר־בָּרָא אֱלֹהִים לַעֲשׂוֹת:"}, {"kind": "text", "text": "יִשְׂמְחוּ בְמַלְכוּתְ֒ךָ"}, {"kind": "text", "text": "שׁוֹמְ֒רֵי שַׁבָּת"}, {"kind": "text", "text": "וְקוֹרְ֒אֵי עֹֽנֶג."}, {"kind": "text", "text": "עַם מְקַדְּ֒שֵׁי שְׁבִיעִי."}, {"kind": "text", "text": "כֻּלָּם יִשְׂבְּ֒עוּ"}, {"kind": "text", "text": "וְיִתְעַנְּ֒גוּ מִטּוּבֶֽךָ."}, {"kind": "text", "text": "וּבַשְּׁ֒בִיעִי רָצִֽיתָ בּוֹ"}, {"kind": "text", "text": "וְקִדַּשְׁתּוֹ."}, {"kind": "text", "text": "חֶמְדַּת יָמִים אוֹתוֹ קָרָֽאתָ."}, {"kind": "text", "text": "זֵֽכֶר"}, {"kind": "text", "text": "לְמַעֲשֵׂה בְרֵאשִׁית:"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "רְצֵה נָא בִמְנוּחָתֵֽנוּ."}, {"kind": "text", "text": "קַדְּ֒שֵֽׁנוּ בְּמִצְוֹתֶֽיךָ"}, {"kind": "text", "text": "וְתֵן חֶלְקֵֽנוּ בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "שַׂבְּ֒עֵֽנוּ מִטּוּבֶֽךָ."}, {"kind": "text", "text": "וְשַׂמַּח נַפְשֵֽׁנוּ בִּישׁוּעָתֶֽךָ."}, {"kind": "text", "text": "וְטַהֵר לִבֵּֽנוּ לְעָבְדְּ֒ךָ בֶּאֱמֶת."}, {"kind": "text", "text": "וְהַנְחִילֵֽנוּ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בְּאַהֲבָה וּבְרָצוֹן"}, {"kind": "text", "text": "שַׁבַּת קָדְשֶֽׁךָ."}, {"kind": "text", "text": "וְיָנֽוּחוּ בָהּ כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "מְקַדְּ֒שֵׁי שְׁמֶֽךָ."}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "מְקַדֵּשׁ הַשַּׁבָּת:"}, {"kind": "text", "text": "<b>עבודה</b>"}, {"kind": "text", "text": "רְצֵה יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בְּעַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "וְלִתְ֒פִלָּתָם שְׁעֵה,"}, {"kind": "text", "text": "וְהָשֵׁב אֶת הָעֲבוֹדָה"}, {"kind": "text", "text": "לִדְ֒בִיר בֵּיתֶֽךָ"}, {"kind": "text", "text": "וְאִשֵּׁי יִשְׂרָאֵל,"}, {"kind": "text", "text": "וּתְ֒פִלָּתָם בְּאַהֲבָה תְקַבֵּל"}, {"kind": "text", "text": "בְּרָצוֹן"}, {"kind": "text", "text": "וּתְ֒הִי לְרָצוֹן תָּמִיד"}, {"kind": "text", "text": "עֲבוֹדַת יִשְׂרָאֵל עַמֶּֽךָ:"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "יַעֲלֶה וְיָבֹא וְיַגִּֽיעַ"}, {"kind": "text", "text": "וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע"}, {"kind": "text", "text": "וְיִפָּקֵד וְיִזָּכֵר"}, {"kind": "text", "text": "זִכְרוֹנֵֽנוּ וּפִקְ֒דוֹנֵֽנוּ"}, {"kind": "text", "text": "וְזִכְרוֹן אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "וְזִכְרוֹן מָשִֽׁיחַ"}, {"kind": "text", "text": "בֶּן דָּוִד עַבְדֶּֽךָ"}, {"kind": "text", "text": "וְזִכְרוֹן יְרוּשָׁלַֽיִם"}, {"kind": "text", "text": "עִיר קָדְשֶֽׁךָ"}, {"kind": "text", "text": "וְזִכְרוֹן כָּל עַמְּ֒ךָ"}, {"kind": "text", "text": "בֵּית יִשְׂרָאֵל לְפָנֶֽיךָ,"}, {"kind": "text", "text": "לִפְ֒לֵיטָה לְטוֹבָה"}, {"kind": "text", "text": "לְחֵן וּלְ֒חֶֽסֶד וּלְ֒רַחֲמִים"}, {"kind": "text", "text": "וּלְ֒חַיִּים טוֹבִים וּלְ֒שָׁלוֹם"}, {"kind": "text", "text": "בְּיוֹם"}, {"kind": "text", "text": "לר\"ח: רֹאשׁ הַחֹֽדֶשׁ הַזֶּה"}, {"kind": "text", "text": "לפסח: חַג הַמַּצּוֹת הַזֶּה"}, {"kind": "text", "text": "לסכות: חַג הַסֻּכּוֹת הַזֶּה"}, {"kind": "text", "text": "זָכְ֒רֵֽנוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בּוֹ לְטוֹבָה,"}, {"kind": "text", "text": "וּפָקְ֒דֵֽנוּ בוֹ לִבְ֒רָכָה,"}, {"kind": "text", "text": "וְהוֹשִׁיעֵֽנוּ בוֹ לְחַיִּים טוֹבִים,"}, {"kind": "text", "text": "וּבִדְ֒בַר יְשׁוּעָה"}, {"kind": "text", "text": "וְרַחֲמִים"}, {"kind": "text", "text": "חוּס וְחָנֵּֽנוּ,"}, {"kind": "text", "text": "וְרַחֵם עָלֵֽינוּ וְהוֹשִׁיעֵֽנוּ,"}, {"kind": "text", "text": "כִּי אֵלֶֽיךָ עֵינֵֽינוּ,"}, {"kind": "text", "text": "כִּי אֵל"}, {"kind": "text", "text": "מֶֽלֶךְ חַנּוּן וְרַחוּם אָֽתָּה:"}, {"kind": "text", "text": "וְתֶחֱזֶֽינָה עֵינֵֽינוּ"}, {"kind": "text", "text": "בְּשׁוּבְ֒ךָ לְצִיּוֹן בְּרַחֲמִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן:"}, {"kind": "text", "text": "<b>הודאה</b>"}, {"kind": "text", "text": "מוֹדִים אֲנַֽחְנוּ לָךְ"}, {"kind": "text", "text": "שָׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וֵאלֹהֵי אֲבוֹתֵֽינוּ לְעוֹלָם וָעֶד"}, {"kind": "text", "text": "צוּרֵֽנוּ צוּר חַיֵּֽינוּ"}, {"kind": "text", "text": "מָגֵן יִשְׁעֵֽנוּ"}, {"kind": "text", "text": "אַתָּה הוּא לְדוֹר וָדוֹר"}, {"kind": "text", "text": "נוֹדֶה לְּךָ"}, {"kind": "text", "text": "וּנְ֒סַפֵּר תְּהִלָּתֶֽךָ"}, {"kind": "text", "text": "עַל חַיֵּֽינוּ"}, {"kind": "text", "text": "הַמְּ֒סוּרִים בְּיָדֶֽךָ"}, {"kind": "text", "text": "וְעַל נִשְׁ֒מוֹתֵֽינוּ"}, {"kind": "text", "text": "הַפְּ֒קוּדוֹת לָךְ"}, {"kind": "text", "text": "וְעַל נִסֶּֽיךָ שֶׁבְּ֒כָל יוֹם עִמָּֽנוּ"}, {"kind": "text", "text": "וְעַל נִפְלְאוֹתֶֽיךָ וְטוֹבוֹתֶֽיךָ"}, {"kind": "text", "text": "שֶׁבְּ֒כָל עֵת,"}, {"kind": "text", "text": "עֶֽרֶב וָבֹֽקֶר וְצָהֳרָֽיִם,"}, {"kind": "text", "text": "הַטּוֹב"}, {"kind": "text", "text": "כִּי לֹא כָלוּ רַחֲמֶֽיךָ"}, {"kind": "text", "text": "וְהַמְ֒רַחֵם"}, {"kind": "text", "text": "כִּי לֹא תַֽמּוּ חֲסָדֶֽיךָ,"}, {"kind": "text", "text": "כִּי מֵעוֹלָם קִוִּֽינוּ לָךְ:"}, {"kind": "text", "text": "וְעַל הַנִּסִּים"}, {"kind": "text", "text": "וְעַל הַפֻּרְקָן וְעַל הַגְּ֒בוּרוֹת"}, {"kind": "text", "text": "וְעַל הַתְּ֒שׁוּעוֹת וְעַל הַנִּפְלָאוֹת"}, {"kind": "text", "text": "וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת"}, {"kind": "text", "text": "שֶׁעָשִֽׂיתָ לַאֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "בַּיָּמִים הָהֵם בִּזְּ֒מַן הַזֶּה:"}, {"kind": "text", "text": "בִּימֵי מַתִּתְיָֽהוּ"}, {"kind": "text", "text": "בֶּן יוֹחָנָן כֹּהֵן גָּדוֹל"}, {"kind": "text", "text": "חַשְׁמוֹנָאִי וּבָנָיו"}, {"kind": "text", "text": "כְּשֶׁעָמְ֒דָה מַלְ֒כוּת יָוָן הָרְ֒שָׁעָה"}, {"kind": "text", "text": "עַל עַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "לְהַשְׁכִּיחָם תּוֹרָתֶֽךָ"}, {"kind": "text", "text": "וּלְ֒הַעֲבִירָם"}, {"kind": "text", "text": "מֵחֻקֵּי רְצוֹנֶֽךָ,"}, {"kind": "text", "text": "וְאַתָּה בְּרַחֲמֶֽיךָ הָרַבִּים"}, {"kind": "text", "text": "עָמַֽדְתָּ לָהֶם בְּעֵת צָרָתָם"}, {"kind": "text", "text": "רַֽבְתָּ אֶת רִיבָם"}, {"kind": "text", "text": "דַּֽנְתָּ אֶת דִּינָם"}, {"kind": "text", "text": "נָקַֽמְתָּ אֶת נִקְ֒מָתָם"}, {"kind": "text", "text": "מָסַֽרְתָּ גִבּוֹרִים"}, {"kind": "text", "text": "בְּיַד חַלָּשִׁים"}, {"kind": "text", "text": "וְרַבִּים בְּיַד מְעַטִּים"}, {"kind": "text", "text": "וּטְ֒מֵאִים בְּיַד טְהוֹרִים"}, {"kind": "text", "text": "וּרְ֒שָׁעִים בְּיַד צַדִּיקִים"}, {"kind": "text", "text": "וְזֵדִים בְּיַד"}, {"kind": "text", "text": "עוֹסְ֒קֵי תוֹרָתֶֽךָ"}, {"kind": "text", "text": "וּלְ֒ךָ עָשִֽׂיתָ"}, {"kind": "text", "text": "שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶֽךָ"}, {"kind": "text", "text": "וּלְ֒עַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "עָשִֽׂיתָ תְּשׁוּעָה גְדוֹלָה"}, {"kind": "text", "text": "וּפֻרְקָן כְּהַיּוֹם הַזֶּה"}, {"kind": "text", "text": "וְאַחַר כַּךְ בָּֽאוּ בָנֶֽיךָ"}, {"kind": "text", "text": "לִדְ֒בִיר בֵּיתֶֽךָ"}, {"kind": "text", "text": "וּפִנּוּ אֶת הֵיכָלֶֽךָ"}, {"kind": "text", "text": "וְטִהֲרוּ אֶת מִקְדָּשֶֽׁךָ"}, {"kind": "text", "text": "וְהִדְלִֽיקוּ נֵרוֹת"}, {"kind": "text", "text": "בְּחַצְ֒רוֹת קָדְשֶֽׁךָ"}, {"kind": "text", "text": "וְקָבְ֒עוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵֽלּוּ"}, {"kind": "text", "text": "לְהוֹדוֹת וּלְ֒הַלֵּל לְשִׁמְ֒ךָ הַגָּדוֹל:"}, {"kind": "text", "text": "וְעַל כֻּלָּם"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵׂא"}, {"kind": "text", "text": "שִׁמְ֒ךָ מַלְכֵּֽנוּ"}, {"kind": "text", "text": "תָּמִיד לְעוֹלָם וָעֶד:"}, {"kind": "instruction", "text": "וּכְ֒תוֹב לְחַיִּים טוֹבִים"}, {"kind": "instruction", "text": "כָּל בְּנֵי בְרִיתֶֽךָ:"}, {"kind": "text", "text": "וְכֹל הַחַיִּים יוֹדֽוּךָ סֶּֽלָה"}, {"kind": "text", "text": "וִיהַלְ֒לוּ וְיבָרְ֒כוּ"}, {"kind": "text", "text": "אֶת שִׁמְ֒ךָ הַגָּדוֹל בְּאֱמֶת לְעוֹלָם"}, {"kind": "text", "text": "כִּי טוֹב"}, {"kind": "text", "text": "הָאֵל יְשׁוּעָתֵֽנוּ"}, {"kind": "text", "text": "וְעֶזְרָתֵֽנוּ סֶֽלָה"}, {"kind": "text", "text": "הָאֵל הַטּוֹב:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַטּוֹב שִׁמְ֒ךָ"}, {"kind": "text", "text": "וּלְ֒ךָ נָאֶה לְהוֹדוֹת:"}, {"kind": "text", "text": "<b>שלום</b>"}, {"kind": "text", "text": "שִׂים שָׁלוֹם טוֹבָה וּבְ֒רָכָה"}, {"kind": "text", "text": "חַיִים חֵן וָחֶֽסֶד וְרַחֲמִים"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּֽךָ,"}, {"kind": "text", "text": "בָּרְ֒כֵֽנוּ אָבִֽינוּ כֻּלָּֽנוּ כְּאֶחָד"}, {"kind": "text", "text": "בְּאוֹר פָּנֶֽיךָ"}, {"kind": "text", "text": "כִּי בְאוֹר פָּנֶֽיךָ"}, {"kind": "text", "text": "נָתַֽתָּ לָּֽנוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "תּוֹרַת חַיִּים וְאַהֲבַת חֶֽסֶד"}, {"kind": "text", "text": "וּצְ֒דָקָה וּבְ֒רָכָה וְרַחֲמִים"}, {"kind": "text", "text": "וְחַיִּים וְשָׁלוֹם,"}, {"kind": "text", "text": "וְטוֹב יִהְיֶה בְּעֵינֶֽיךָ"}, {"kind": "text", "text": "לְבָרְ֒כֵֽנוּ"}, {"kind": "text", "text": "וּלְ֒בָרֵךְ אֶת כָּל עַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "בְּכָל עֵת וּבְכָל שָׁעָה"}, {"kind": "text", "text": "בִּשְׁ֒לוֹמֶֽךָ"}, {"kind": "text", "text": "(בְּרוֹב עוֹז וְשָׁלוֹם)."}, {"kind": "instruction", "text": "בְּסֵֽפֶר חַיִּים בְּרָכָה וְשָׁלוֹם"}, {"kind": "instruction", "text": "וּפַרְנָסָה טוֹבָה"}, {"kind": "instruction", "text": "וּגְ֒זֵרוֹת טוֹבוֹת, יְשׁוּעוֹת וְנֶחָמוֹת,"}, {"kind": "instruction", "text": "נִזָּכֵר וְנִכָּתֵב"}, {"kind": "instruction", "text": "לְפָנֶֽיךָ"}, {"kind": "instruction", "text": "אֲנַֽחְנוּ וְכָל עַמְּ֒ךָ בֵּית יִשְׂרָאֵל"}, {"kind": "instruction", "text": "לְחַיִּים טוֹבִים וּלְ֒שָׁלוֹם:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַמְּ֒בָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל"}, {"kind": "text", "text": "בַּשָּׁלוֹם:"}, {"kind": "text", "text": "שָׁלוֹם רָב"}, {"kind": "text", "text": "עַל יִשְׂרָאֵל עַמְּ֒ךָ."}, {"kind": "text", "text": "תָּשִׂים לְעוֹלָם"}, {"kind": "text", "text": "כִּי אַתָּה הוּא מֶֽלֶךְ"}, {"kind": "text", "text": "אָדוֹן לְכָל הַשָּׁלוֹם"}, {"kind": "text", "text": "וְטוֹב יִהְיֶה בְּעֵינֶֽיךָ"}, {"kind": "text", "text": "לְבָרְ֒כֵֽנוּ"}, {"kind": "text", "text": "וּלְ֒בָרֵךְ אֶת כָּל עַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "בְּכָל עֵת וּבְכָל שָׁעָה"}, {"kind": "text", "text": "בִּשְׁ֒לוֹמֶֽךָ"}, {"kind": "instruction", "text": "בְּסֵֽפֶר חַיִּים בְּרָכָה וְשָׁלוֹם"}, {"kind": "instruction", "text": "וּפַרְנָסָה טוֹבָה"}, {"kind": "instruction", "text": "וּגְ֒זֵרוֹת טוֹבוֹת, יְשׁוּעוֹת וְנֶחָמוֹת,"}, {"kind": "instruction", "text": "נִזָּכֵר וְנִכָּתֵב"}, {"kind": "instruction", "text": "לְפָנֶֽיךָ"}, {"kind": "instruction", "text": "אֲנַֽחְנוּ וְכָל עַמְּ֒ךָ בֵּית יִשְׂרָאֵל"}, {"kind": "instruction", "text": "לְחַיִּים טוֹבִים וּלְ֒שָׁלוֹם:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַמְּ֒בָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל"}, {"kind": "text", "text": "בַּשָּׁלוֹם:"}, {"kind": "text", "text": "יִהְיוּ לְרָצוֹן"}, {"kind": "text", "text": "אִמְ֒רֵי פִי"}, {"kind": "text", "text": "וְהֶגְיוֹן לִבִּי לְפָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה צוּרִי וְגוֹאֲלִי:"}, {"kind": "text", "text": "אֱלֹהַי נְצוֹר לְשׁוֹנִי מֵרָע"}, {"kind": "text", "text": "וּשְׂ֒פָתַי מִדַּבֵּר מִרְמָה"}, {"kind": "text", "text": "וְלִמְ֒קַלְ֒לַי"}, {"kind": "text", "text": "נַפְשִׁי תִדּוֹם"}, {"kind": "text", "text": "וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה"}, {"kind": "text", "text": "פְּתַח לִבִּי בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "וְאַחֲרֵי מִצְוֹתֶֽיךָ תִּרְדּוֹף נַפְשִׁי"}, {"kind": "text", "text": "וְכָל הַקָמִים וְהַחוֹשְׁ֒בִים עָלַי רָעָה"}, {"kind": "text", "text": "מְהֵרָה הָפֵר עֲצָתָם"}, {"kind": "text", "text": "וְקַלְקֵל מַחֲשַׁבְתָּם:"}, {"kind": "text", "text": "(יְהִי רָצוֹן מִלְ֒פָנֶיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי"}, {"kind": "text", "text": "שֶׁלֹּא תַעֲלֶה קִנְאַת אָדָם עָלַי"}, {"kind": "text", "text": "וְלֹא קִנְאָתִי עַל אֲחֵרִים"}, {"kind": "text", "text": "וְשֶׁלֹּא אֶכְעֹס הַיּוֹם"}, {"kind": "text", "text": "וְשֶׁלֹּא אַכְעִיסֶֽךָ"}, {"kind": "text", "text": "וְתַצִּילֵנִי מִיֵּֽצֶר הָרָע"}, {"kind": "text", "text": "וְתֵן בְּלִבִּי הַכְנָעָה וַעֲנָוָה."}, {"kind": "text", "text": "מַלְכֵּֽנוּ וֵאלֹהֵֽינוּ"}, {"kind": "text", "text": "יַחֵד שִׁמְ֒ךָ בְּעוֹלָמֶֽךָ,"}, {"kind": "text", "text": "בְּנֵה עִירְ֒ךָ, יַסֵּד בֵּיתֶֽךָ,"}, {"kind": "text", "text": "וְשַׁכְלֵל הֵיכָלֶֽךָ."}, {"kind": "text", "text": "וְקַבֵּץ קִבּוּץ גָּלֻיּוֹת,"}, {"kind": "text", "text": "וּפְ֒דֵה צֹאנֶֽךָ וְשַׂמַּח עֲדָתֶֽךָ.)"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן שְׁמֶֽךָ,"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן יְמִינֶֽךָ,"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן תּוֹרָתֶֽךָ,"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן קְדֻשָּׁתֶֽךָ."}, {"kind": "text", "text": "לְמַֽעַן יֵחָלְ֒צוּן יְדִידֶֽיךָ"}, {"kind": "text", "text": "הוֹשִֽׁיעָה יְמִינְ֒ךָ וַעֲנֵֽנִי:"}, {"kind": "text", "text": "יִהְיוּ לְרָצוֹן"}, {"kind": "text", "text": "אִמְרֵי פִי"}, {"kind": "text", "text": "וְהֶגְיוֹן לִבִּי לְפָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה צוּרִי וְגוֹאֲלִי:"}, {"kind": "text", "text": "עֹשֶׂה (בעשי\"ת הַשָּׁלוֹם) שָׁלוֹם"}, {"kind": "text", "text": "בִּמְ֒רוֹמָיו"}, {"kind": "text", "text": "הוּא יַעֲשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהִי רָצוֹן מִלְּ֒פָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ"}, {"kind": "text", "text": "בִּמְהֵרָה בְיָמֵֽינוּ"}, {"kind": "text", "text": "וְתֵן חֶלְקֵֽנוּ בְּתוֹרָתֶֽךָ:"}, {"kind": "text", "text": "וְשָׁם נַעֲבָדְ֒ךָ בְּיִרְאָה"}, {"kind": "text", "text": "כִּימֵי עוֹלָם"}, {"kind": "text", "text": "וּכְ֒שָׁנִים קַדְמוֹנִיּוֹת:"}, {"kind": "text", "text": "וְעָרְ֒בָה לַיהֹוָה"}, {"kind": "text", "text": "מִנְחַת יְהוּדָה וִירוּשָׁלָֽםִ"}, {"kind": "text", "text": "כִּימֵי עוֹלָם וּכְ֒שָׁנִים קַדְמוֹנִיּוֹת:"}, {"kind": "header", "text": "ויכלו"}, {"kind": "text", "text": "וַיְכֻלּוּ הַשָּׁמַֽיִם וְהָאָֽרֶץ"}, {"kind": "text", "text": "וְכָל־צְבָאָם:"}, {"kind": "text", "text": "וַיְכַל אֱלֹהִים בַּיּוֹם הַשְּׁ֒בִיעִי"}, {"kind": "text", "text": "מְלַאכְתּוֹ אֲשֶׁר עָשָׂה."}, {"kind": "text", "text": "וַיִּשְׁבֹּת בַּיּוֹם הַשְּׁ֒בִיעִי"}, {"kind": "text", "text": "מִכָּל־מְלַאכְתּוֹ אֲשֶׁר עָשָׂה:"}, {"kind": "text", "text": "וַיְבָֽרֶךְ אֱלֹהִים אֶת־יוֹם הַשְּׁ֒בִיעִי"}, {"kind": "text", "text": "וַיְקַדֵּשׁ אֹתוֹ."}, {"kind": "text", "text": "כִּי בוֹ שָׁבַת"}, {"kind": "text", "text": "מִכָּל־מְלַאכְתּוֹ"}, {"kind": "text", "text": "אֲשֶׁר־בָּרָא אֱלֹהִים לַעֲשׂוֹת:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "אֱלֹהֵי אַבְרָהָם אֱלֹהֵי יִצְחָק"}, {"kind": "text", "text": "וֵאלֹהֵי יַעֲקֹב"}, {"kind": "text", "text": "הָאֵל"}, {"kind": "text", "text": "הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא."}, {"kind": "text", "text": "אֵל עֶלְיוֹן"}, {"kind": "text", "text": "קוֹנֵה שָׁמַֽיִם וָאָֽרֶץ:"}, {"kind": "header", "text": "מגן אבות"}, {"kind": "text", "text": "מָגֵן אָבוֹת בִּדְבָרוֹ."}, {"kind": "text", "text": "מְחַיֵּה מֵתִים"}, {"kind": "text", "text": "בְּמַאֲמָרוֹ."}, {"kind": "text", "text": "הָאֵל הַקָּדוֹשׁ"}, {"kind": "instruction", "text": "(הַמֶּלֶךְ הַקָּדוֹשׁ)"}, {"kind": "text", "text": "שֶׁאֵין כָּמֽוֹהוּ."}, {"kind": "text", "text": "הַמֵּנִֽיחַ לְעַמּוֹ"}, {"kind": "text", "text": "בְּיוֹם שַׁבַּת קָדְשׁוֹ."}, {"kind": "text", "text": "כִּי בָם רָצָה"}, {"kind": "text", "text": "לְהָנִֽיחַ לָהֶם."}, {"kind": "text", "text": "לְפָנָיו נַעֲבוֹד"}, {"kind": "text", "text": "בְּיִרְאָה וָפַֽחַד."}, {"kind": "text", "text": "וְנוֹדֶה לִשְׁמוֹ"}, {"kind": "text", "text": "בְּכָל יוֹם תָּמִיד"}, {"kind": "text", "text": "מֵעֵין הַבְּ֒רָכוֹת:"}, {"kind": "text", "text": "אֵל הַהוֹדָאוֹת."}, {"kind": "text", "text": "אֲדוֹן הַשָּׁלוֹם."}, {"kind": "text", "text": "מְקַדֵּשׁ הַשַּׁבָּת"}, {"kind": "text", "text": "וּמְבָרֵךְ שְׁבִיעִי."}, {"kind": "text", "text": "וּמֵנִֽיחַ בִּקְדֻשָּׁה"}, {"kind": "text", "text": "לְעַם מְדֻשְּׁ֒נֵי עֹֽנֶג"}, {"kind": "text", "text": "זֵֽכֶר לְמַעֲשֵׂה בְרֵאשִׁית:"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "רְצֵה נָא בִמְנוּחָתֵֽנוּ."}, {"kind": "text", "text": "קַדְּ֒שֵֽׁנוּ בְּמִצְוֹתֶֽיךָ"}, {"kind": "text", "text": "וְתֵן חֶלְקֵֽנוּ בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "שַׂבְּ֒עֵֽנוּ מִטּוּבֶֽךָ."}, {"kind": "text", "text": "וְשַׂמַּח נַפְשֵֽׁנוּ בִּישׁוּעָתֶֽךָ."}, {"kind": "text", "text": "וְטַהֵר לִבֵּֽנוּ לְעָבְדְּ֒ךָ בֶּאֱמֶת."}, {"kind": "text", "text": "וְהַנְחִילֵֽנוּ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בְּאַהֲבָה וּבְרָצוֹן"}, {"kind": "text", "text": "שַׁבַּת קָדְשֶֽׁךָ."}, {"kind": "text", "text": "וְיָנֽוּחוּ בָהּ כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "מְקַדְּ֒שֵׁי שְׁמֶֽךָ."}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "מְקַדֵּשׁ הַשַּׁבָּת:"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְ֒מָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְ֒עוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְ֒כוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְ֒קָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ"}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְ֒יוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְ֒חַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל,"}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְ֒מַן קָרִיב"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְ֒עָלְ֒מֵי עָלְ֒מַיָּא:"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקוּדְשָׁא, בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵֽלָּא (בעשי\"ת וּלְ֒עֵֽלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְ֒כָתָא וְשִׁירָתָא,"}, {"kind": "text", "text": "תֻּשְׁבְּחָתָא וְנֶחֱמָתָא,"}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְ֒מָא, וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "תִּתְקַבֵּל"}, {"kind": "text", "text": "צְלוֹתְ֒הוֹן וּבָעוּתְ֒הוֹן"}, {"kind": "text", "text": "דְּכָל בֵּית יִשְׂרָאֵל"}, {"kind": "text", "text": "קֳדָם אֲבוּהוֹן דִּי בִשְׁ֒מַיָּא"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא"}, {"kind": "text", "text": "וְחַיִּים טוֹבִים"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "עוֹשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "(בעשי\"ת הַשָּׁלוֹם)"}, {"kind": "text", "text": "בִּמְ֒רוֹמָיו"}, {"kind": "text", "text": "הוּא יַעֲשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "מִזְמוֹר לְדָוִד"}, {"kind": "text", "text": "יְהֹוָה רֹעִי לֹא אֶחְסָר:"}, {"kind": "text", "text": "בִּנְאוֹת דֶּֽשֶׁא יַרְבִּיצֵֽנִי"}, {"kind": "text", "text": "עַל־מֵי מְנֻחוֹת יְנַהֲלֵֽנִי:"}, {"kind": "text", "text": "נַפְשִׁי יְשׁוֹבֵב"}, {"kind": "text", "text": "יַנְחֵֽנִי בְּמַעְגְּלֵי־צֶֽדֶק"}, {"kind": "text", "text": "לְמַֽעַן שְׁמוֹ:"}, {"kind": "text", "text": "גַּם כִּי־אֵלֵךְ"}, {"kind": "text", "text": "בְּגֵיא צַלְמָֽוֶת"}, {"kind": "text", "text": "לֹא־אִירָא רָע כִּי־אַתָּה עִמָּדִי"}, {"kind": "text", "text": "שִׁבְטְךָ וּמִשְׁעַנְתֶּֽךָ הֵֽמָּה יְנַחֲמֻֽנִי:"}, {"kind": "text", "text": "תַּעֲרֹךְ לְפָנַי שֻׁלְחָן"}, {"kind": "text", "text": "נֶֽגֶד צֹרְרָי"}, {"kind": "text", "text": "דִּשַּֽׁנְתָּ בַשֶּֽׁמֶן רֹאשִׁי"}, {"kind": "text", "text": "כּוֹסִי רְוָיָה:"}, {"kind": "text", "text": "אַךְ טוֹב וָחֶֽסֶד יִרְדְּפֽוּנִי"}, {"kind": "text", "text": "כָּל־יְמֵי חַיָּי"}, {"kind": "text", "text": "וְשַׁבְתִּי בְּבֵית־יְהֹוָה"}, {"kind": "text", "text": "לְאֹֽרֶךְ יָמִים:"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְ֒מָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְ֒עוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְ֒כוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְקָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ."}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְ֒יוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְ֒חַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל,"}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְ֒מַן קָרִיב"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְ֒עָלְ֒מֵי עָלְ֒מַיָּא"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקוּדְשָׁא, בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵֽלָּא (בעשי\"ת וּלְעֵֽלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְ֒כָתָא וְשִׁירָתָא,"}, {"kind": "text", "text": "תֻּשְׁבְּחָתָא וְנֶחֱמָתָא,"}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְ֒מָא, וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "<b>בָּרְ֒כוּ אֶת יְהֹוָה הַמְ֒בֹרָךְ:</b>"}, {"kind": "text", "text": "<b>בָּרוּךְ יְהֹוָה הַמְ֒בֹרָךְ</b>"}, {"kind": "text", "text": "<b>לְעוֹלָם וָעֶד:</b>"}, {"kind": "header", "text": "עלינו"}, {"kind": "text", "text": "עָלֵֽינוּ לְשַׁבֵּֽחַ"}, {"kind": "text", "text": "לַאֲדוֹן הַכֹּל"}, {"kind": "text", "text": "לָתֵת גְּדֻלָּה"}, {"kind": "text", "text": "לְיוֹצֵר בְּרֵאשִׁית"}, {"kind": "text", "text": "שֶׁלֹּא עָשָֽׂנוּ"}, {"kind": "text", "text": "כְּגוֹיֵי הָאֲרָצוֹת"}, {"kind": "text", "text": "וְלֹא שָׂמָֽנוּ"}, {"kind": "text", "text": "כְּמִשְׁפְּחוֹת הָאֲדָמָה"}, {"kind": "text", "text": "שֶׁלֹּא שָׂם"}, {"kind": "text", "text": "חֶלְקֵֽנוּ כָּהֶם"}, {"kind": "text", "text": "וְגוֹרָלֵֽנוּ כְּכָל הֲמוֹנָם:"}, {"kind": "text", "text": "שֶׁהֵם מִשְׁתַּחֲוִים"}, {"kind": "text", "text": "לָהֶֽבֶל וָרִיק"}, {"kind": "text", "text": "וּמִתְפַּלְּ֒לִים אֶל אֵל לֹא יוֹשִֽׁיעַ,"}, {"kind": "text", "text": "וַאֲנַֽחְנוּ כּוֹרְ֒עִים וּמִשְׁתַּחֲוִים"}, {"kind": "text", "text": "וּמוֹדִים"}, {"kind": "text", "text": "לִפְ֒נֵי מֶֽלֶךְ מַלְ֒כֵי הַמְּ֒לָכִים"}, {"kind": "text", "text": "הַקָּדוֹשׁ בָּרוּךְ הוּא,"}, {"kind": "text", "text": "שֶׁהוּא נוֹטֶה שָׁמַֽיִם"}, {"kind": "text", "text": "וְיוֹסֵד אָֽרֶץ,"}, {"kind": "text", "text": "וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַֽיִם מִמַּֽעַל,"}, {"kind": "text", "text": "וּשְׁ֒כִינַת עֻזּוֹ"}, {"kind": "text", "text": "בְּגָבְ֒הֵי מְרוֹמִים,"}, {"kind": "text", "text": "הוּא אֱלֹהֵֽינוּ אֵין עוֹד,"}, {"kind": "text", "text": "אֱמֶת מַלְכֵּֽנוּ"}, {"kind": "text", "text": "אֶֽפֶס זוּלָתוֹ"}, {"kind": "text", "text": "כַּכָּתוּב בְּתוֹרָתוֹ"}, {"kind": "text", "text": "וְיָדַעְתָּ הַיּוֹם"}, {"kind": "text", "text": "וַהֲשֵׁבֹתָ אֶל לְבָבֶֽךָ"}, {"kind": "text", "text": "כִּי יְהֹוָה הוּא הָאֱלֹהִים"}, {"kind": "text", "text": "בַּשָּׁמַֽיִם מִמַּֽעַל"}, {"kind": "text", "text": "וְעַל הָאָֽרֶץ מִתָּֽחַת"}, {"kind": "text", "text": "אֵין עוֹד:"}, {"kind": "text", "text": "עַל כֵּן נְקַוֶּה לְךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "לִרְאוֹת מְהֵרָה בְּתִפְאֶֽרֶת עֻזֶּֽךָ"}, {"kind": "text", "text": "לְהַעֲבִיר גִּלּוּלִים מִן הָאָֽרֶץ"}, {"kind": "text", "text": "וְהָאֱלִילִים"}, {"kind": "text", "text": "כָּרוֹת יִכָּרֵתוּן"}, {"kind": "text", "text": "לְתַקֵּן עוֹלָם"}, {"kind": "text", "text": "בְּמַלְ֒כוּת שַׁדַּי"}, {"kind": "text", "text": "וְכָל בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁ֒מֶֽךָ,"}, {"kind": "text", "text": "לְהַפְנוֹת אֵלֶֽיךָ"}, {"kind": "text", "text": "כָּל רִשְׁ֒עֵי אָֽרֶץ,"}, {"kind": "text", "text": "יַכִּֽירוּ וְיֵדְ֒עוּ"}, {"kind": "text", "text": "כָּל יוֹשְׁ֒בֵי תֵבֵל"}, {"kind": "text", "text": "כִּי לְךָ תִכְרַע כָּל בֶּֽרֶךְ"}, {"kind": "text", "text": "תִּשָּׁבַע כָּל לָשׁוֹן:"}, {"kind": "text", "text": "לְפָנֶֽיךָ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "יִכְרְעוּ וְיִפֹּֽלוּ,"}, {"kind": "text", "text": "וְלִכְ֒בוֹד שִׁמְ֒ךָ יְקָר יִתֵּֽנוּ,"}, {"kind": "text", "text": "וִיקַבְּ֒לוּ כֻלָּם"}, {"kind": "text", "text": "אֶת עֹל מַלְ֒כוּתֶֽךָ,"}, {"kind": "text", "text": "וְתִמְלֹךְ עֲלֵיהֶם מְהֵרָה"}, {"kind": "text", "text": "לְעוֹלָם וָעֶד,"}, {"kind": "text", "text": "כִּי הַמַּלְ֒כוּת שֶׁלְּ֒ךָ הִיא"}, {"kind": "text", "text": "וּלְ֒עֽוֹלְ֒מֵי עַד תִּמְלוֹךְ בְּכָבוֹד,"}, {"kind": "text", "text": "כַּכָּתוּב בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "יְהֹוָה יִמְלֹךְ לְעֹלָם וָעֶד:"}, {"kind": "text", "text": "❖וְנֶאֱמַר"}, {"kind": "text", "text": "וְהָיָה יְהֹוָה לְמֶֽלֶךְ"}, {"kind": "text", "text": "עַל כָּל הָאָֽרֶץ"}, {"kind": "text", "text": "בַּיּוֹם הַהוּא יִהְיֶה יְהֹוָה אֶחָד"}, {"kind": "text", "text": "וּשְׁ֒מוֹ אֶחָד:"}, {"kind": "text", "text": "אַל תִּירָא מִפַּֽחַד פִּתְאֹם"}, {"kind": "text", "text": "וּמִשֹּׁאַת רְשָׁעִים"}, {"kind": "text", "text": "כִּי תָבֹא:"}, {"kind": "text", "text": "עֻֽצוּ עֵצָה וְתֻפָר"}, {"kind": "text", "text": "דַּבְּ֒רוּ דָבָר וְלֹא יָקוּם"}, {"kind": "text", "text": "כִּי עִמָּֽנוּ אֵל:"}, {"kind": "text", "text": "וְעַד זִקְנָה אֲנִי הוּא"}, {"kind": "text", "text": "וְעַד שֵׂיבָה אֲנִי אֶסְבֹּל:"}, {"kind": "text", "text": "אֲנִי עָשִֽׂיתִי וַאֲנִי אֶשָּׂא"}, {"kind": "text", "text": "וַאֲנִי אֶסְבֹּל וַאֲמַלֵּט:"}, {"kind": "header", "text": "קדיש יתום"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְ֒מָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְ֒עוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְ֒כוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְ֒קָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ"}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְ֒יוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְ֒חַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל,"}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְ֒מַן קָרִיב"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְ֒עָלְ֒מֵי עָלְ֒מַיָּא:"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקוּדְשָׁא, בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵֽלָּא (בעשי\"ת וּלְ֒עֵֽלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְ֒כָתָא וְשִׁירָתָא,"}, {"kind": "text", "text": "תֻּשְׁבְּחָתָא וְנֶחֱמָתָא,"}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְ֒מָא, וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא"}, {"kind": "text", "text": "וְחַיִּים טוֹבִים"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "עוֹשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "(בעשי\"ת הַשָּׁלוֹם)"}, {"kind": "text", "text": "בִּמְ֒רוֹמָיו"}, {"kind": "text", "text": "הוּא יַעֲשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן:"}], "shacharit": [{"kind": "header", "text": "סדר השכמת הבוקר"}, {"kind": "text", "text": "מוֹדֶה אֲנִי לְפָנֶֽיךָ"}, {"kind": "text", "text": "מֶֽלֶךְ חַי וְקַיָּם"}, {"kind": "text", "text": "שֶׁהֶחֱזַֽרְתָּ בִּי נִשְׁ֒מָתִי בְּחֶמְלָה,"}, {"kind": "text", "text": "רַבָּה אֱמוּנָתֶֽךָ:"}, {"kind": "text", "text": "רֵאשִׁית חָכְמָה יִרְאַת יְהֹוָה,"}, {"kind": "text", "text": "שֵֽׂכֶל טוֹב"}, {"kind": "text", "text": "לְכָל עֹשֵׂיהֶם,"}, {"kind": "text", "text": "תְּהִלָּתוֹ עוֹמֶֽדֶת לָעַד:"}, {"kind": "text", "text": "בָּרוּךְ שֵׁם"}, {"kind": "text", "text": "כְּבוֹד מַלְכוּתוֹ"}, {"kind": "text", "text": "לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "אֲשֶׁר קִדְּ֒שָֽׁנוּ בְּמִצְוֹתָיו"}, {"kind": "text", "text": "וְצִוָּֽנוּ"}, {"kind": "text", "text": "עַל מִצְוַת צִיצִית:"}, {"kind": "text", "text": "יְהִי רָצוֹן מִלְּ֒פָנֶיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי"}, {"kind": "text", "text": "שֶׁתְּ֒הֵא חֲשׁוּבָה"}, {"kind": "text", "text": "מִצְוַת צִיצִית לְפָנֶֽיךָ"}, {"kind": "text", "text": "כְּאִלּוּ קִיַּמְתִּֽיהָ"}, {"kind": "text", "text": "בְּכָל פְּרָטֶֽיהָ"}, {"kind": "text", "text": "וְדִקְדּוּקֶֽיהָ וְכַוָּ֒נוֹתֶֽיהָ"}, {"kind": "text", "text": "וְתַרְיַ\"ג מִצְווֹת"}, {"kind": "text", "text": "הַתְּ֒לוּיוֹת בָּהּ,"}, {"kind": "text", "text": "אָמֵן סֶלָה:"}, {"kind": "header", "text": "סדר עטיפת טלית"}, {"kind": "text", "text": "בָּרְ֒כִי נַפְשִׁי אֶת־יְהֹוָה,"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהַי גָּדַֽלְתָּ מְאֹד,"}, {"kind": "text", "text": "הוֹד וְהָדָר"}, {"kind": "text", "text": "לָבָֽשְׁתָּ:"}, {"kind": "text", "text": "עֹֽטֶה־אוֹר כַּשַּׂלְמָה,"}, {"kind": "text", "text": "נוֹטֶה שָׁמַֽיִם כַּיְ֒רִיעָה:"}, {"kind": "text", "text": "לְשֵׁם יִחוּד קוּדְ֒שָׁא בְּרִיךְ הוּא וּשְׁ֒כִינְתֵּהּ, בִּדְ֒חִילוּ וּרְ֒חִימוּ לְיַחֵד שֵׁם י\"ה בו\"ה בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, הֲרֵינִי מִתְעַטֵּף גּוּפִי בַּצִּיצִית, כֵּן תִּתְעַטֵּף נִשְׁ֒מָתִי וּרְ֒מַ\"ח אֵיבָרַי וּשְׁסָ\"ה גִידַי בְּאוֹר הַצִּיצִית הָעוֹלֶה תַּרְיַ\"ג, וּכְ֒שֵׁם שֶׁאֲנִי מִתְכַּסֶּה בַּטַּלִּית בָּעוֹלָם הַזֶּה כַּךְ אֶזְכֶּה לַחֲלוּקָא דְרַבָּנָן וּלְ֒טַלִּית נָאָה לָעוֹלָם הַבָּא בְּגַן עֵֽדֶן, וְעַל יְדֵי מִצְוַת צִיצִית, תִּנָּצֵל נַפְשִׁי רוּחִי וְנִשְׁ֒מָתִי וּתְ֒פִלָּתִי מִן הַחִיצוֹנִים, וְהַטַּלִּית יִפְרֹשׂ כְּנָפָיו עֲלֵיהֶם, וְיַצִּילֵם כְּנֶֽשֶׁר יָעִיר קִנּוֹ עַל גּוֹזָלָיו יְרַחֵף, וּתְ֒הֵא חֲשׁוּבָה מִצְוַת צִיצִית לִפְ֒נֵי הַקָּדוֹשׁ בָּרוּךְ הוּא, כְּאִלּוּ קִיַּמְתִּֽיהָ בְּכָל פְּרָטֶֽיהָ, וְדִקְדּוּקֶֽיהָ, וְכַוָּ֒נוֹתֶֽיהָ, וְתַרְיַ\"ג מִצְווֹת הַתְּ֒לוּיוֹת בָּהּ, אָמֵן סֶֽלָה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "אֲשֶׁר קִדְּ֒שָֽׁנוּ בְּמִצְוֹתָיו"}, {"kind": "text", "text": "וְצִוָּֽנוּ"}, {"kind": "text", "text": "לְהִתְעַטֵּף בַּצִּיצִית:"}, {"kind": "text", "text": "מַה יָּקָר חַסְ֒דְּךָ אֱלֹהִים"}, {"kind": "text", "text": "וּבְ֒נֵי אָדָם"}, {"kind": "text", "text": "בְּצֵל כְּנָפֶֽיךָ יֶחֱסָֽיוּן:"}, {"kind": "text", "text": "יִרְוְיֻן"}, {"kind": "text", "text": "מִדֶּֽשֶׁן בֵּיתֶֽךָ"}, {"kind": "text", "text": "וְנַֽחַל עֲדָנֶֽיךָ"}, {"kind": "text", "text": "תַשְׁקֵם:"}, {"kind": "text", "text": "כִּי־עִמְּ֒ךָ מְקוֹר חַיִּים,"}, {"kind": "text", "text": "בְּאוֹרְ֒ךָ נִרְאֶה־אוֹר:"}, {"kind": "text", "text": "מְשֹׁךְ חַסְדְּךָ"}, {"kind": "text", "text": "לְיֹדְ֒עֶֽיךָ"}, {"kind": "text", "text": "וְצִדְ֒קָתְ֒ךָ"}, {"kind": "text", "text": "לְיִשְׁ֒רֵי־לֵב:"}, {"kind": "header", "text": "מה טובו"}, {"kind": "text", "text": "הֲרֵינִי מְקַבֵּל עָלַי"}, {"kind": "text", "text": "מִצְוַת עֲֹשֵׂה שֶׁל"}, {"kind": "text", "text": "וְאָהַבְתָּ לְרֵעֲךָ כָּמֽוֹךָ:"}, {"kind": "text", "text": "מַה טֹּֽבוּ אֹהָלֶֽיךָ יַעֲקֹב"}, {"kind": "text", "text": "מִשְׁכְּ֒נֹתֶֽיךָ יִשְׂרָאֵל:"}, {"kind": "text", "text": "וַאֲנִי בְּרֹב חַסְדְּ֒ךָ"}, {"kind": "text", "text": "אָבוֹא בֵיתֶֽךָ"}, {"kind": "text", "text": "אֶשְׁתַּחֲוֶה"}, {"kind": "text", "text": "אֶל הֵיכַל־קָדְשְׁ֒ךָ בְּיִרְאָתֶֽךָ:"}, {"kind": "text", "text": "יְהֹוָה אָהַֽבְתִּי מְעוֹן בֵּיתֶֽךָ"}, {"kind": "text", "text": "וּמְ֒קוֹם מִשְׁכַּן כְּבוֹדֶֽךָ:"}, {"kind": "text", "text": "וַאֲנִי אֶשְׁתַּחֲוֶה וְאֶכְרָֽעָה"}, {"kind": "text", "text": "אֶבְרְכָה לִפְ֒נֵי יְהֹוָה עֹשִׂי:"}, {"kind": "text", "text": "וַאֲנִי תְפִלָּתִי־לְךָ יְהֹוָה"}, {"kind": "text", "text": "עֵת רָצוֹן"}, {"kind": "text", "text": "אֱלֹהִים בְּרָב־חַסְדֶּֽךָ"}, {"kind": "text", "text": "עֲנֵֽנִי"}, {"kind": "text", "text": "בֶּאֱמֶת יִשְׁעֶֽךָ:"}, {"kind": "header", "text": "אדון עולם"}, {"kind": "text", "text": "אֲדוֹן עוֹלָם אֲשֶׁר מָלַךְ,"}, {"kind": "text", "text": "בְּטֶֽרֶם כָּל יְצִיר נִבְרָא:"}, {"kind": "text", "text": "לְעֵת נַעֲשָׂה בְחֶפְצוֹ כֹּל,"}, {"kind": "text", "text": "אֲזַי מֶֽלֶךְ שְׁמוֹ נִקְרָא:"}, {"kind": "text", "text": "וְאַחֲרֵי כִּכְ֒לוֹת הַכֹּל,"}, {"kind": "text", "text": "לְבַדּוֹ יִמְלֹךְ נוֹרָא:"}, {"kind": "text", "text": "וְהוּא הָיָה וְהוּא הֹוֶה,"}, {"kind": "text", "text": "וְהוּא יִהְיֶה בְּתִפְאָרָה:"}, {"kind": "text", "text": "וְהוּא אֶחָד וְאֵין שֵׁנִי,"}, {"kind": "text", "text": "לְהַמְשִׁיל לוֹ לְהַחְבִּֽירָה:"}, {"kind": "text", "text": "בְּלִי רֵאשִׁית בְּלִי תַכְלִית,"}, {"kind": "text", "text": "וְלוֹ הָעֹז וְהַמִּשְׂרָה:"}, {"kind": "text", "text": "וְהוּא אֵלִי וְחַי גּוֹאֲלִי,"}, {"kind": "text", "text": "וְצוּר חֶבְלִי בְּעֵת צָרָה:"}, {"kind": "text", "text": "וְהוּא נִסִּי וּמָנוֹס לִי,"}, {"kind": "text", "text": "מְנָת כּוֹסִי בְּיוֹם אֶקְרָא:"}, {"kind": "text", "text": "בְּיָדוֹ אַפְקִיד רוּחִי,"}, {"kind": "text", "text": "בְּעֵת אִישַׁן וְאָעִֽירָה:"}, {"kind": "text", "text": "וְעִם רוּחִי גְּוִיָּתִי,"}, {"kind": "text", "text": "יְהֹוָה לִי וְלֹא אִירָא:"}, {"kind": "header", "text": "יגדל"}, {"kind": "text", "text": "יִגְדַּל אֱלֹהִים חַי וְיִשְׁתַּבַּח,"}, {"kind": "text", "text": "נִמְצָא וְאֵין עֵת אֶל מְצִיאוּתוֹ:"}, {"kind": "text", "text": "אֶחָד וְאֵין יָחִיד כְּיִחוּדוֹ,"}, {"kind": "text", "text": "נֶעְלָם וְגַם אֵין סוֹף לְאַחְדּוּתוֹ:"}, {"kind": "text", "text": "אֵין לוֹ דְמוּת הַגּוּף"}, {"kind": "text", "text": "וְאֵינוֹ גוּף,"}, {"kind": "text", "text": "לֹא נַעֲרֹךְ אֵלָיו קְדֻשָּׁתוֹ:"}, {"kind": "text", "text": "קַדְמוֹן לְכָל דָּבָר אֲשֶׁר נִבְרָא,"}, {"kind": "text", "text": "רִאשׁוֹן"}, {"kind": "text", "text": "וְאֵין רֵאשִׁית לְרֵאשִׁיתוֹ:"}, {"kind": "text", "text": "הִנּוֹ אֲדוֹן עוֹלָם לְכָל נוֹצָר,"}, {"kind": "text", "text": "יוֹרֶה גְדֻלָּתוֹ וּמַלְ֒כוּתוֹ:"}, {"kind": "text", "text": "שֶֽׁפַע נְבוּאָתוֹ נְתָנוֹ,"}, {"kind": "text", "text": "אֶל אַנְ֒שֵׁי סְגֻלָּתוֹ"}, {"kind": "text", "text": "וְתִפְאַרְתּוֹ:"}, {"kind": "text", "text": "לֹא קָם בְּיִשְׂרָאֵל"}, {"kind": "text", "text": "כְּמשֶׁה עוֹד,"}, {"kind": "text", "text": "נָבִיא וּמַבִּיט אֶת תְּמוּנָתוֹ:"}, {"kind": "text", "text": "תּוֹרַת אֱמֶת"}, {"kind": "text", "text": "נָתַן לְעַמּוֹ אֵל,"}, {"kind": "text", "text": "עַל יַד נְבִיאוֹ"}, {"kind": "text", "text": "נֶאֱמַן בֵּיתוֹ:"}, {"kind": "text", "text": "לֹא יַחֲלִיף הָאֵל"}, {"kind": "text", "text": "וְלֹא יָמִיר דָּתוֹ,"}, {"kind": "text", "text": "לְעוֹלָמִים לְזוּלָתוֹ:"}, {"kind": "text", "text": "צוֹפֶה וְיוֹדֵֽעַ סְתָרֵֽינוּ,"}, {"kind": "text", "text": "מַבִּיט לְסוֹף דָּבָר בְּקַדְמָתוֹ:"}, {"kind": "text", "text": "גּוֹמֵל לְאִישׁ חֶֽסֶד"}, {"kind": "text", "text": "כְּמִפְעָלוֹ,"}, {"kind": "text", "text": "נוֹתֵן לְרָשָׁע רָע"}, {"kind": "text", "text": "כְּרִשְׁעָתוֹ:"}, {"kind": "text", "text": "יִשְׁלַח לְקֵץ הַיָּמִין מְשִׁיחֵֽנוּ,"}, {"kind": "text", "text": "לִפְדּוֹת מְחַכֵּי קֵץ יְשׁוּעָתוֹ:"}, {"kind": "text", "text": "מֵתִים יְחַיֶּה אֵל"}, {"kind": "text", "text": "בְּרֹב חַסְדּוֹ,"}, {"kind": "text", "text": "בָּרוּךְ עֲדֵי עַד שֵׁם תְּהִלָּתוֹ:"}, {"kind": "header", "text": "ברכות השכמה"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "אֲשֶׁר קִדְּ֒שָֽׁנוּ בְּמִצְוֹתָיו"}, {"kind": "text", "text": "וְצִוָּֽנוּ"}, {"kind": "text", "text": "עַל נְטִילַת יָדָֽיִם:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "אֲשֶׁר יָצַר אֶת הָאָדָם בְּחָכְמָה"}, {"kind": "text", "text": "וּבָֽרָא בוֹ נְקָבִים נְקָבִים"}, {"kind": "text", "text": "חֲלוּלִים חֲלוּלִים"}, {"kind": "text", "text": "גָּלוּי וְיָדֽוּעַ"}, {"kind": "text", "text": "לִפְ֒נֵי כִסֵּא כְבוֹדֶֽךָ"}, {"kind": "text", "text": "שֶׁאִם יִפָּתֵֽחַ אֶחָד מֵהֶם"}, {"kind": "text", "text": "אוֹ יִסָּתֵם אֶחָד מֵהֶם"}, {"kind": "text", "text": "אִי אֶפְשַׁר לְהִתְקַיֵּם"}, {"kind": "text", "text": "וְלַעֲמֹד לְפָנֶֽיךָ"}, {"kind": "text", "text": "אֲפִילוּ שָׁעָה אֶחָת."}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "רוֹפֵא כָל בָּשָׂר"}, {"kind": "text", "text": "וּמַפְלִיא לַעֲשׂוֹת:"}, {"kind": "text", "text": "אֱלֹהַי,"}, {"kind": "text", "text": "נְשָׁמָה שֶׁנָּתַֽתָּ בִּי טְהוֹרָה הִיא"}, {"kind": "text", "text": "אַתָּה בְרָאתָהּ אַתָּה יְצַרְתָּהּ"}, {"kind": "text", "text": "אַתָּה נְפַחְתָּהּ בִּי"}, {"kind": "text", "text": "וְאַתָּה מְשַׁמְּ֒רָהּ בְּקִרְבִּי"}, {"kind": "text", "text": "וְאַתָּה עָתִיד לִטְּ֒לָהּ מִמֶּֽנִּי"}, {"kind": "text", "text": "וּלְהַחֲזִירָהּ בִּי לֶעָתִיד לָבֹא,"}, {"kind": "text", "text": "כָּל זְמַן שֶׁהַנְּ֒שָׁמָה בְקִרְבִּי"}, {"kind": "text", "text": "מוֹדֶה אֲנִי לְפָנֶֽיךָ יְהֹוָה אֱלֹהַי"}, {"kind": "text", "text": "וֵאלֹהֵי אֲבוֹתַי"}, {"kind": "text", "text": "רִבּוֹן כָּל הַמַּעֲשִׂים"}, {"kind": "text", "text": "אֲדוֹן כָּל הַנְּ֒שָׁמוֹת:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַמַּחֲזִיר נְשָׁמוֹת"}, {"kind": "text", "text": "לִפְגָרִים מֵתִים:"}, {"kind": "header", "text": "ברכות התורה"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "אֲשֶׁר קִדְּ֒שָֽׁנוּ בְּמִצְוֹתָיו"}, {"kind": "text", "text": "וְצִוָּֽנוּ"}, {"kind": "text", "text": "לַעֲסֹק בְּדִבְ֒רֵי תוֹרָה:"}, {"kind": "text", "text": "וְהַעֲרֶב נָא יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "אֶת דִּבְ֒רֵי תוֹרָתְ֒ךָ בְּפִֽינוּ"}, {"kind": "text", "text": "וּבְ֒פִי עַמְּ֒ךָ בֵּית יִשְׂרָאֵל"}, {"kind": "text", "text": "וְנִהְיֶה אֲנַֽחְנוּ וְצֶאֱצָאֵֽינוּ"}, {"kind": "text", "text": "וְצֶאֱצָאֵי עַמְּ֒ךָ"}, {"kind": "text", "text": "בֵּית יִשְׂרָאֵל"}, {"kind": "text", "text": "כֻּלָּֽנוּ יוֹדְ֒עֵי שְׁמֶֽךָ"}, {"kind": "text", "text": "וְלוֹמְ֒דֵי תוֹרָתֶֽךָ לִשְׁ֒מָהּ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַמְ֒לַמֵּד תּוֹרָה לְעַמּוֹ יִשְׂרָאֵל:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "אֲשֶׁר בָּֽחַר בָּֽנוּ מִכָּל הָעַמִּים"}, {"kind": "text", "text": "וְנָֽתַן לָֽנוּ אֶת תּוֹרָתוֹ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "נוֹתֵן הַתּוֹרָה:"}, {"kind": "text", "text": "וַיְדַבֵּר יְהֹוָה אֶל מֹשֶׁה לֵאמֹר"}, {"kind": "text", "text": "דַבֵּר אֶל אַהֲרֹן וְאֶל בָּנָיו לֵאמֹר"}, {"kind": "text", "text": "כֹּה תְבָרְ֒כוּ אֶת בְּנֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "אָמוֹר לָהֶם:"}, {"kind": "text", "text": "יְבָרֶכְ֒ךָ יְהֹוָה וְיִשְׁמְרֶֽךָ:"}, {"kind": "text", "text": "יָאֵר יְהֹוָה"}, {"kind": "text", "text": "פָּנָיו אֵלֶֽיךָ"}, {"kind": "text", "text": "וִיחֻנֶּֽךָ:"}, {"kind": "text", "text": "יִשָּׂא יְהֹוָה"}, {"kind": "text", "text": "פָּנָיו אֵלֶֽיךָ"}, {"kind": "text", "text": "וְיָשֵׂם לְךָ שָׁלוֹם:"}, {"kind": "text", "text": "וְשָׂמוּ אֶת שְׁמִי"}, {"kind": "text", "text": "עַל בְּנֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "וַאֲנִי אַבָרְ֒כֵם:"}, {"kind": "text", "text": "אֵֽלּוּ דְבָרִים"}, {"kind": "text", "text": "שֶׁאֵין לָהֶם שִׁעוּר"}, {"kind": "text", "text": "הַפֵּאָה"}, {"kind": "text", "text": "וְהַבִּכּוּרִים"}, {"kind": "text", "text": "וְהָרְ֒אָיוֹן"}, {"kind": "text", "text": "וּגְ֒מִילוּת חֲסָדִים"}, {"kind": "text", "text": "וְתַלְמוּד תּוֹרָה:"}, {"kind": "text", "text": "אֵֽלּוּ דְבָרִים"}, {"kind": "text", "text": "שֶׁאָדָם אוֹכֵל פֵּרוֹתֵיהֶם"}, {"kind": "text", "text": "בָּעוֹלָם הַזֶּה"}, {"kind": "text", "text": "וְהַקֶּֽרֶן"}, {"kind": "text", "text": "קַיֶּֽמֶת לָעוֹלָם הַבָּא,"}, {"kind": "text", "text": "וְאֵֽלּוּ הֵן"}, {"kind": "text", "text": "כִּבּוּד אָב וָאֵם"}, {"kind": "text", "text": "וּגְ֒מִילוּת חֲסָדִים"}, {"kind": "text", "text": "וְהַשְׁכָּמַת בֵּית הַמִּדְרָשׁ"}, {"kind": "text", "text": "שַׁחֲרִית וְעַרְ֒בִית"}, {"kind": "text", "text": "וְהַכְנָסַת אוֹרְ֒חִים"}, {"kind": "text", "text": "וּבִקּוּר חוֹלִים"}, {"kind": "text", "text": "וְהַכְנָסַת כַּלָּה"}, {"kind": "text", "text": "וּלְ֒וָיַת הַמֵּת"}, {"kind": "text", "text": "וְעִיּוּן תְּפִלָּה"}, {"kind": "text", "text": "וַהֲבָאַת שָׁלוֹם בֵּין אָדָם לַחֲבֵרוֹ"}, {"kind": "text", "text": "ובֵין אִישׁ לְאִשְׁתּוֹ"}, {"kind": "text", "text": "וְתַלְמוּד תּוֹרָה כְּנֶֽגֶד כֻּלָּם:"}, {"kind": "header", "text": "ברכות השחר"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "הַּנוֹתֵן לַשֶּֽׂכְוִי בִינָה"}, {"kind": "text", "text": "לְהַבְחִין בֵּין יוֹם וּבֵין לָֽיְלָה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "שֶׁלֹּא עָשַֽׂנִי גּוֹי:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "שֶׁלֹּא עָשַֽׂנִי עָֽבֶד:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "שֶׁלֹּא עָשַֽׂנִי אִשָּׁה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "שֶׁעָשַֽׂנִי כִּרְ֒צוֹנוֹ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "פּוֹקֵֽחַ עִוְ֒רִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "מַלְבִּישׁ עֲרֻמִּים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "מַתִּיר אֲסוּרִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "זוֹקֵף כְּפוּפִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "רוֹקַע הָאָֽרֶץ עַל הַמָּֽיִם:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "הַמֵּכִין מִצְעֲדֵי גָֽבֶר:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "שֶׁעָשָׂה לִי כָּל צָרְכִּי:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "אוֹזֵר יִשְׂרָאֵל בִּגְ֒בוּרָה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "עוֹטֵר יִשְׂרָאֵל בְּתִפְאָרָה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "הַנּוֹתֵן לַיָּעֵף כֹּֽחַ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "הַמַּעֲבִיר שֵׁנָה מֵעֵינָי"}, {"kind": "text", "text": "וּתְ֒נוּמָה מֵעַפְעַפָּי:"}, {"kind": "text", "text": "וִיהִי רָצוֹן מִלְּ֒פָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "שֶׁתַּרְגִּילֵֽנוּ בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "וְדַבְּ֒קֵֽנוּ בְּמִצְוֹתֶֽיךָ,"}, {"kind": "text", "text": "וְאַל תְּבִיאֵֽנוּ"}, {"kind": "text", "text": "לֹא לִידֵי חֵטְא"}, {"kind": "text", "text": "וְלֹא לִידֵי"}, {"kind": "text", "text": "עֲבֵרָה וְעָוֹן"}, {"kind": "text", "text": "וְלֹא לִידֵי נִסָּיוֹן"}, {"kind": "text", "text": "וְלֹא לִידֵי בִזָּיוֹן"}, {"kind": "text", "text": "וְאַל יִשְׁלֹט בָּֽנוּ"}, {"kind": "text", "text": "יֵֽצֶר הָרָע"}, {"kind": "text", "text": "וְהַרְחִיקֵֽנוּ מֵאָדָם רָע"}, {"kind": "text", "text": "וּמֵחָבֵר רָע"}, {"kind": "text", "text": "וְדַבְּ֒קֵֽנוּ בְּיֵֽצֶר הַטּוֹב"}, {"kind": "text", "text": "וּבְ֒מַעֲשִׂים טוֹבִים"}, {"kind": "text", "text": "וְכוֹף אֶת יִצְרֵֽנוּ הָרַע"}, {"kind": "text", "text": "לְהִשְׁתַּעְבֶּד־לָךְ"}, {"kind": "text", "text": "וּתְ֒נֵֽנוּ הַיּוֹם וּבְ֒כָל יוֹם"}, {"kind": "text", "text": "לְחֵן וּלְחֶֽסֶד וּלְ֒רַחֲמִים"}, {"kind": "text", "text": "בְּעֵינֶֽיךָ"}, {"kind": "text", "text": "וּבְ֒עֵינֵי כָל רוֹאֵֽינוּ"}, {"kind": "text", "text": "וְתִגְמְ֒לֵֽנוּ חֲסָדִים טוֹבִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַגּוֹמֵל חֲסָדִים טוֹבִים"}, {"kind": "text", "text": "לְעַמּוֹ יִשְׂרָאֵל:"}, {"kind": "text", "text": "יְהִי רָצוֹן מִלְּ֒פָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהַי"}, {"kind": "text", "text": "וֵאלֹהֵי אֲבוֹתַי"}, {"kind": "text", "text": "שֶׁתַּצִּילֵֽנִי הַיּוֹם וּבְ֒כָל יוֹם"}, {"kind": "text", "text": "מֵעַזֵּי פָנִים וּמֵעַזּוּת פָּנִים"}, {"kind": "text", "text": "מֵאָדָם רָע, מִיֵֽצֶר רָע"}, {"kind": "text", "text": "וּמֵחָבֵר רָע"}, {"kind": "text", "text": "וּמִשָּׁכֵן רָע"}, {"kind": "text", "text": "וּמִפֶּֽגַע רָע"}, {"kind": "text", "text": "מֵעַֽיִן הָרָע,"}, {"kind": "text", "text": "מִלָּשׁוֹן הָרָע, מִמַּלְשִׁינוּת."}, {"kind": "text", "text": "מֵעֵדוּת שֶֽׁקֶר, מִשִּׂנְ֒אַת הַבְּ֒רִיּוֹת,"}, {"kind": "text", "text": "מֵעֲלִילָה, מִמִּיתָה מְשׁוּנָה,"}, {"kind": "text", "text": "מֵחֳלָיִם רָעִים, וּמִמִּקְ֒רִים רָעִים"}, {"kind": "text", "text": "וּמִשָּׂטָן הַמַּשְׁחִית"}, {"kind": "text", "text": "מִדִּין קָשֶׁה"}, {"kind": "text", "text": "וּמִבַּֽעַל דִּין קָשֶׁה,"}, {"kind": "text", "text": "בֵּין שֶׁהוּא בֶן בְּרִית"}, {"kind": "text", "text": "וּבֵין שֶׁאֵינוֹ בֶן בְּרִית,"}, {"kind": "text", "text": "וּמִדִּינָהּ שֶׁל גֵּיהִנֹּם:"}, {"kind": "header", "text": "עקידה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "זָכְ֒רֵֽנוּ בְּזִכָּרוֹן טוֹב לְפָנֶֽיךָ"}, {"kind": "text", "text": "וּפָקְ֒דֵֽנוּ בִּפְ֒קֻדַּת"}, {"kind": "text", "text": "יְשׁוּעָה וְרַחֲמִים"}, {"kind": "text", "text": "מִשְּׁ֒מֵי שְׁמֵי קֶֽדֶם"}, {"kind": "text", "text": "וּזְ֒כָר לָֽנוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "אַהֲבַת הַקַּדְמוֹנִים"}, {"kind": "text", "text": "אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל עֲבָדֶֽיךָ"}, {"kind": "text", "text": "אֶת הַבְּ֒רִית וְאֶת הַחֶֽסֶד"}, {"kind": "text", "text": "וְאֶת הַשְּׁ֒בוּעָה שֶׁנִּשְׁבַּֽעְתָּ"}, {"kind": "text", "text": "לְאַבְרָהָם אָבִֽינוּ בְּהַר הַמֹּרִיָּה"}, {"kind": "text", "text": "וְאֶת הָעֲקֵדָה שֶׁעָקַד"}, {"kind": "text", "text": "אֶת יִצְחָק בְּנוֹ"}, {"kind": "text", "text": "עַל גַּבֵּי הַמִּזְבֵּֽחַ"}, {"kind": "text", "text": "כַּכָּתוּב בְּתוֹרָתֶֽךָ:"}, {"kind": "text", "text": "וַיְ֒הִי אַחַר הַדְּ֒בָרִים הָאֵֽלֶּה"}, {"kind": "text", "text": "וְהָאֱלֹהִים נִסָּה אֶת־אַבְרָהָם"}, {"kind": "text", "text": "וַיֹּֽאמֶר אֵלָיו אַבְרָהָם"}, {"kind": "text", "text": "וַיֹּֽאמֶר הִנֵּֽנִי:"}, {"kind": "text", "text": "וַיֹּֽאמֶר קַח־נָא אֶת־בִּנְ֒ךָ"}, {"kind": "text", "text": "אֶת־יְחִידְ֒ךָ"}, {"kind": "text", "text": "אֲשֶׁר־אָהַֽבְתָּ אֶת־יִצְחָק"}, {"kind": "text", "text": "וְלֶךְ־לְךָ אֶל־אֶֽרֶץ הַמֹּרִיָּה"}, {"kind": "text", "text": "וְהַעֲלֵֽהוּ שָׁם לְעֹלָה"}, {"kind": "text", "text": "עַל אַחַד הֶהָרִים"}, {"kind": "text", "text": "אֲשֶׁר אֹמַר אֵלֶֽיךָ:"}, {"kind": "text", "text": "וַיַּשְׁכֵּם אַבְרָהָם בַּבֹּֽקֶר"}, {"kind": "text", "text": "וַיַּחֲבשׁ אֶת־חֲמֹרוֹ"}, {"kind": "text", "text": "וַיִּקַּח אֶת־שְׁנֵי נְעָרָיו אִתּוֹ"}, {"kind": "text", "text": "וְאֵת יִצְחָק בְּנוֹ"}, {"kind": "text", "text": "וַיְ֒בַקַּע עֲצֵי עֹלָה"}, {"kind": "text", "text": "וַיָּֽקָם וַיֵּֽלֶךְ אֶל־הַמָּקוֹם"}, {"kind": "text", "text": "אֲשֶׁר־אָֽמַר־לוֹ הָאֱלֹהִֽים:"}, {"kind": "text", "text": "בַּיּוֹם הַשְּׁ֒לִישִׁי"}, {"kind": "text", "text": "וַיִּשָּׂא אַבְרָהָם אֶת־עֵינָיו"}, {"kind": "text", "text": "וַיַּרְא אֶת־הַמָּקוֹם מֵרָחֹק:"}, {"kind": "text", "text": "וַיֹּֽאמֶר אַבְרָהָם אֶל־נְעָרָיו"}, {"kind": "text", "text": "שְׁבוּ־לָכֶם פֹּה עִם־הַחֲמוֹר"}, {"kind": "text", "text": "וַאֲנִי וְהַנַּֽעַר נֵלְ֒כָה עַד־כֹּה"}, {"kind": "text", "text": "וְנִשְׁתַּחֲוֶה"}, {"kind": "text", "text": "וְנָשֽׁוּבָה אֲלֵיכֶם:"}, {"kind": "text", "text": "וַיִּקַּח אַבְרָהָם"}, {"kind": "text", "text": "אֶת־עֲצֵי הָעֹלָה"}, {"kind": "text", "text": "וַיָּֽשֶׂם עַל־יִצְחָק בְּנוֹ"}, {"kind": "text", "text": "וַיִּקַּח בְּיָדוֹ"}, {"kind": "text", "text": "אֶת־הָאֵשׁ וְאֶת־הַמַּאֲכֶֽלֶת"}, {"kind": "text", "text": "וַיֵּלְ֒כוּ שְׁנֵיהֶם יַחְדָּו:"}, {"kind": "text", "text": "וַיֹּֽאמֶר יִצְחָק אֶל־אַבְרָהָם אָבִיו"}, {"kind": "text", "text": "וַיֹּֽאמֶר אָבִי"}, {"kind": "text", "text": "וַיֹּֽאמֶר הִנֶּֽנִּי בְנִי"}, {"kind": "text", "text": "וַיֹּֽאמֶר הִנֵּה הָאֵשׁ וְהָעֵצִים"}, {"kind": "text", "text": "וְאַיֵּה הַשֶּׂה לְעֹלָֽה:"}, {"kind": "text", "text": "וַיֹּֽאמֶר אַבְרָהָם"}, {"kind": "text", "text": "אֱלֹהִים יִרְאֶה־לּוֹ הַשֶּׂה"}, {"kind": "text", "text": "לְעֹלָה בְּנִי"}, {"kind": "text", "text": "וַיֵּלְ֒כוּ שְׁנֵיהֶם יַחְדָּו:"}, {"kind": "text", "text": "וַיָּבֹֽאוּ אֶל־הַמָּקוֹם"}, {"kind": "text", "text": "אֲשֶׁר אָֽמַר־לוֹ הָאֱלֹהִים"}, {"kind": "text", "text": "וַיִּֽבֶן שָׁם אַבְרָהָם אֶת־הַמִּזְבֵּֽחַ"}, {"kind": "text", "text": "וַיַּעֲרֹךְ אֶת־הָעֵצִים"}, {"kind": "text", "text": "וַיַּעֲקֹד אֶת־יִצְחָק בְּנוֹ"}, {"kind": "text", "text": "וַיָּֽשֶׂם אֹתוֹ עַל־הַמִּזְבֵּֽחַ"}, {"kind": "text", "text": "מִמַּֽעַל לָעֵצִים:"}, {"kind": "text", "text": "וַיִּשְׁלַח אַבְרָהָם אֶת־יָדוֹ"}, {"kind": "text", "text": "וַיִּקַּח אֶת־הַמַּאֲכֶֽלֶת"}, {"kind": "text", "text": "לִשְׁחֹט אֶת־בְּנוֹ:"}, {"kind": "text", "text": "וַיִּקְרָא אֵלָיו מַלְאַךְ יְהֹוָה"}, {"kind": "text", "text": "מִן־הַשָּׁמַֽיִם"}, {"kind": "text", "text": "וַיֹּֽאמֶר אַבְרָהָם אַבְרָהָם"}, {"kind": "text", "text": "וַיֹּֽאמֶר הִנֵּֽנִי:"}, {"kind": "text", "text": "וַיֹּֽאמֶר"}, {"kind": "text", "text": "אַל־תִּשְׁלַח יָֽדְ֒ךָ אֶל־הַנַּֽעַר"}, {"kind": "text", "text": "וְאַל־תַּֽעַשׂ לוֹ מְאוּמָה"}, {"kind": "text", "text": "כִּי עַתָּה יָדַֽעְתִּי"}, {"kind": "text", "text": "כִּי־יְרֵא אֱלֹהִים אַֽתָּה"}, {"kind": "text", "text": "וְלֹא חָשַֽׂכְתָּ אֶת־בִּנְ֒ךָ"}, {"kind": "text", "text": "אֶת־יְחִידְ֒ךָ מִמֶּֽנִּי:"}, {"kind": "text", "text": "וַיִּשָּׂא אַבְרָהָם אֶת־עֵינָיו"}, {"kind": "text", "text": "וַיַּרְא וְהִנֵּה־אַֽיִל"}, {"kind": "text", "text": "אַחַר נֶאֱחַז בַּסְּ֒בַךְ"}, {"kind": "text", "text": "בְּקַרְנָיו"}, {"kind": "text", "text": "וַיֵּֽלֶךְ אַבְרָהָם וַיִּקַּח אֶת־הָאַֽיִל"}, {"kind": "text", "text": "וַיַּעֲלֵֽהוּ לְעֹלָה"}, {"kind": "text", "text": "תַּֽחַת בְּנוֹ:"}, {"kind": "text", "text": "וַיִּקְרָא אַבְרָהָם"}, {"kind": "text", "text": "שֵׁם־הַמָּקוֹם הַהוּא"}, {"kind": "text", "text": "יְהֹוָה יִרְאֶה"}, {"kind": "text", "text": "אֲשֶׁר יֵאָמֵר הַיּוֹם"}, {"kind": "text", "text": "בְּהַר יְהֹוָה יֵרָאֶה:"}, {"kind": "text", "text": "וַיִּקְרָא מַלְאַךְ יְהֹוָה אֶל־אַבְרָהָם"}, {"kind": "text", "text": "שֵׁנִית מִן־הַשָּׁמָֽיִם: וַיֹּאמֶר"}, {"kind": "text", "text": "בִּי נִשְׁבַּֽעְתִּי נְאֻם־יְהֹוָה"}, {"kind": "text", "text": "כִּי יַֽעַן אֲשֶׁר עָשִֽׂיתָ"}, {"kind": "text", "text": "אֶת־הַדָּבָר הַזֶּה"}, {"kind": "text", "text": "וְלֹא חָשַֽׂכְתָּ"}, {"kind": "text", "text": "אֶת־בִּנְךָ אֶת־יְחִידֶֽךָ:"}, {"kind": "text", "text": "כִּי־בָרֵךְ אֲבָרֶכְ֒ךָ"}, {"kind": "text", "text": "וְהַרְבָּה אַרְבֶּה אֶת־זַרְעֲךָ"}, {"kind": "text", "text": "כְּכוֹכְ֒בֵי הַשָּׁמַֽיִם"}, {"kind": "text", "text": "וְכַחוֹל אֲשֶׁר עַל־שְׂפַת הַיָּם"}, {"kind": "text", "text": "וְיִרַשׁ זַרְעֲךָ"}, {"kind": "text", "text": "אֵת שַֽׁעַר אֹיְ֒בָיו:"}, {"kind": "text", "text": "וְהִתְבָּרְכוּ בְזַרְעֲךָ"}, {"kind": "text", "text": "כֹּל גּוֹיֵי הָאָֽרֶץ"}, {"kind": "text", "text": "עֵֽקֶב אֲשֶׁר שָׁמַֽעְתָּ בְּקֹלִי:"}, {"kind": "text", "text": "וַיָּֽשָׁב אַבְרָהָם אֶל־נְעָרָיו"}, {"kind": "text", "text": "וַיָּקֻֽמוּ וַיֵּלְ֒כוּ יַחְדָּו"}, {"kind": "text", "text": "אֶל־בְּאֵר שָֽׁבַע"}, {"kind": "text", "text": "וַיֵּֽשֶׁב אַבְרָהָם בִּבְ֒אֵר שָֽׁבַע:"}, {"kind": "header", "text": "בקשות"}, {"kind": "text", "text": "לְעוֹלָם יְהֵא אָדָם יְרֵא שָׁמַֽיִם"}, {"kind": "text", "text": "בַּסֵּֽתֶר וּבַגָּלוּי"}, {"kind": "text", "text": "וּמוֹדֶה עַל הָאֱמֶת"}, {"kind": "text", "text": "וְדוֹבֵר אֱמֶת בִּלְ֒בָבוֹ"}, {"kind": "text", "text": "וְיַשְׁכֵּם וְיֹאמַר:"}, {"kind": "text", "text": "רִבּוֹן כָּל הָעוֹלָמִים"}, {"kind": "text", "text": "וַאֲדוֹנֵי הָאֲדוֹנִים,"}, {"kind": "text", "text": "לֹא עַל צִדְ֒קוֹתֵֽינוּ"}, {"kind": "text", "text": "אֲנַֽחְנוּ מַפִּילִים תַּחֲנוּנֵֽינוּ לְפָנֶֽיךָ"}, {"kind": "text", "text": "כִּי עַל רַחֲמֶֽיךָ הָרַבִּים,"}, {"kind": "text", "text": "מָה אָֽנוּ מֶה חַיֵּֽינוּ"}, {"kind": "text", "text": "מֶה חַסְדֵּֽנוּ,"}, {"kind": "text", "text": "מַה צִּדְ֒קוֹתֵֽינוּ,"}, {"kind": "text", "text": "מַה יְּשׁוּעָתֵֽנוּ,"}, {"kind": "text", "text": "מַה כֹּחֵֽנוּ מַה גְּבוּרָתֵֽנוּ,"}, {"kind": "text", "text": "מַה נֹּאמַר לְפָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "הֲלֹא כָּל הַגִּבּוֹרִים"}, {"kind": "text", "text": "כְּאַֽיִן לְפָנֶֽיךָ"}, {"kind": "text", "text": "וְאַנְ֒שֵׁי הַשֵּׁם כְּלֹא הָיוּ"}, {"kind": "text", "text": "וַחֲכָמִים כִּבְ֒לִי מַדָּע"}, {"kind": "text", "text": "וּנְ֒בוֹנִים"}, {"kind": "text", "text": "כִּבְ֒לִי הַשְׂכֵּל"}, {"kind": "text", "text": "כִּי רוֹב מַעֲשֵׂיהֶם תֹּֽהוּ"}, {"kind": "text", "text": "וִימֵי חַיֵּיהֶם"}, {"kind": "text", "text": "הֶֽבֶל לְפָנֶֽיךָ,"}, {"kind": "text", "text": "וּמוֹתַר הָאָדָם מִן הַבְּ֒הֵמָה"}, {"kind": "text", "text": "אָֽיִן"}, {"kind": "text", "text": "כִּי הַכֹּל הָֽבֶל,"}, {"kind": "text", "text": "לְבַד הַנְ֒שָׁמָה הַטְּ֒הוֹרָה"}, {"kind": "text", "text": "שֶׁהִיא עֲתִידָה לִתֵּן דִּין וְחֶשְׁבּוֹן"}, {"kind": "text", "text": "לִפְ֒נֵי כִסֵּא כְבוֹדֶֽךָ,"}, {"kind": "text", "text": "וְכָל הַגּוֹיִם כְּאַֽיִן נֶגְדֶּֽךָ"}, {"kind": "text", "text": "שֶׁנֶּאֶמַר"}, {"kind": "text", "text": "הֵן גּוֹיִם כְּמַר מִדְּ֒לִי"}, {"kind": "text", "text": "וּכְ֒שַֽׁחַק מְאֹזְ֒נַֽיִם"}, {"kind": "text", "text": "נֶחְשָֽׁבוּ"}, {"kind": "text", "text": "הֵן אִיִּים כַּדַּק יִטּוֹל:"}, {"kind": "text", "text": "אֲבָל אֲנַֽחְנוּ עַמְּ֒ךָ"}, {"kind": "text", "text": "בְּנֵי בְרִיתֶֽךָ,"}, {"kind": "text", "text": "בְּנֵי אַבְרָהָם אֹהַבְ֒ךָ"}, {"kind": "text", "text": "שֶׁנִּשְׁבַּֽעְתָּ לּוֹ בְּהַר הַמֹּרִיָּה,"}, {"kind": "text", "text": "זֶֽרַע יִצְחָק יְחִידוֹ"}, {"kind": "text", "text": "שֶׁנֶּעֱקַד עַל גַּבֵּי הַמִּזְבֵּֽחַ,"}, {"kind": "text", "text": "עֲדַת יַעֲקֹב בִּנְ֒ךָ בְּכוֹרֶֽךָ"}, {"kind": "text", "text": "שֶׁמֵּאַהֲבָתְ֒ךָ שֶׁאָהַֽבְתָּ אוֹתוֹ"}, {"kind": "text", "text": "וּמִשִּׂמְחָתְ֒ךָ שֶׁשָּׂמַֽחְתָּ בּוֹ"}, {"kind": "text", "text": "קָרָֽאתָ אֶת שְׁמוֹ יִשְׂרָאֵל"}, {"kind": "text", "text": "וִישֻׁרוּן:"}, {"kind": "text", "text": "לְפִיכָךְ אֲנַֽחְנוּ חַיָּבִים"}, {"kind": "text", "text": "לְהוֹדוֹת לְךָ"}, {"kind": "text", "text": "וּלְ֒שַׁבֵּחֲךָ וּלְ֒פָאֶרְ֒ךָ"}, {"kind": "text", "text": "וּלְ֒בָרֵךְ וּלְ֒קַדֵּשׁ"}, {"kind": "text", "text": "וְלִתֵּן שֶֽׁבַח וְהוֹדָיָה לִשְׁ֒מֶֽךָ:"}, {"kind": "text", "text": "אַשְׁרֵֽינוּ מַה טּוֹב חֶלְקֵֽנוּ"}, {"kind": "text", "text": "וּמַה נָּעִים גּוֹרָלֵֽנוּ"}, {"kind": "text", "text": "וּמַה יָּפָה יְרֻשָּׁתֵֽנוּ:"}, {"kind": "text", "text": "❖אַשְׁרֵֽינוּ"}, {"kind": "text", "text": "שֶׁאָֽנוּ מַשְׁכִּימִים וּמַעֲרִיבִים"}, {"kind": "text", "text": "בְּבָתֵּי כְנֵסִיּוֹת וּבְ֒בָתֵּי מִדְרָשׁוֹת"}, {"kind": "text", "text": "וּמְיַ֒חֲדִים שִׁמְ֒ךָ בְּכָל־יוֹם תָּמִיד"}, {"kind": "text", "text": "וְאוֹמְ֒רִים פַּעֲמַֽיִם בְּאַהֲבָה:"}, {"kind": "text", "text": "<b>שְׁמַע יִשְׂרָאֵל יְהֹוָה אֱלֹהֵֽינוּ</b>"}, {"kind": "text", "text": "<b>יְהֹוָה אֶחָד:</b>"}, {"kind": "instruction", "text": "בָּרוּךְ שֵׁם"}, {"kind": "instruction", "text": "כְּבוֹד מַלְ֒כוּתוֹ"}, {"kind": "instruction", "text": "לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "וְאָהַבְתָּ אֵת יְהֹוָה אֱלֹהֶֽיךָ"}, {"kind": "text", "text": "בְּכָלּ־לְּבָבְ֒ךָ"}, {"kind": "text", "text": "וּבְ֒כָל־נַפְשְׁךָ"}, {"kind": "text", "text": "וּבְ֒כָל־מְאֹדֶֽךָ:"}, {"kind": "text", "text": "וְהָיוּ הַדְּ֒בָרִים הָאֵֽ֒לֶּה"}, {"kind": "text", "text": "אֲשֶׁר֯ אָ֯נֹכִי מְצַוְּ֒ךָ הַיּוֹם"}, {"kind": "text", "text": "עַל֯־לְ֯בָבֶֽךָ:"}, {"kind": "text", "text": "וְשִׁנַּנְתָּם"}, {"kind": "text", "text": "לְבָנֶֽיךָ"}, {"kind": "text", "text": "וְדִבַּרְתָּ בָּם"}, {"kind": "text", "text": "בְּשִׁבְתְּ֒ךָ בְּבֵיתֶֽךָ"}, {"kind": "text", "text": "וּבְ֒לֶכְתְּךָ בַדֶּֽרֶךְ"}, {"kind": "text", "text": "וּבְ֒שָׁכְבְּךָ וּבְ֒קוּמֶֽךָ:"}, {"kind": "text", "text": "וּקְ֒שַׁרְתָּם לְאוֹת"}, {"kind": "text", "text": "עַל֯־יָ֯דֶֽךָ"}, {"kind": "text", "text": "וְהָיוּ לְטֹטָפֹת"}, {"kind": "text", "text": "בֵּין עֵינֶֽיךָ:"}, {"kind": "text", "text": "וּכְ֒תַבְתָּם"}, {"kind": "text", "text": "עַל־מְזֻזוֹת בֵּיתֶֽךָ"}, {"kind": "text", "text": "וּבִשְׁ֒עָרֶֽיךָ:"}, {"kind": "text", "text": "אַתָּה הוּא"}, {"kind": "text", "text": "עַד שֶׁלֹּא נִבְרָא הָעוֹלָם,"}, {"kind": "text", "text": "אַתָּה הוּא"}, {"kind": "text", "text": "מִשֶּׁנִּבְרָא הָעוֹלָם,"}, {"kind": "text", "text": "אַתָּה הוּא בָּעוֹלָם הַזֶּה"}, {"kind": "text", "text": "וְאַתָּה הוּא לָעוֹלָם הַבָּא,"}, {"kind": "text", "text": "קַדֵּשׁ אֶת שִׁמְ֒ךָ"}, {"kind": "text", "text": "עַל מַקְדִּישֵׁי שְׁמֶֽךָ"}, {"kind": "text", "text": "וְקַדֵּשׁ אֶת שִׁמְ֒ךָ בְּעֹלָמֶֽךָ,"}, {"kind": "text", "text": "וּבִישׁוּעָתְ֒ךָ"}, {"kind": "text", "text": "תָּרִים"}, {"kind": "text", "text": "וְתַגְבִּֽיהַּ קרְנֵֽנוּ לְמַֽעְלָה,"}, {"kind": "text", "text": "וְהוֹשִׁיעֵֽנוּ בְּקָרוֹב"}, {"kind": "text", "text": "לְמַֽעַן שְׁמֶֽךָ."}, {"kind": "text", "text": "בָּרוּךְ הַמְקַדֵּשׁ שְׁמוֹ"}, {"kind": "text", "text": "בָּרַבִּים:"}, {"kind": "text", "text": "אַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בַּשָּׁמַֽיִם וּבָאָֽרֶץ"}, {"kind": "text", "text": "וּבִשְׁ֒מֵי הַשָּׁמַֽיִם הָעֶלְיוֹנִים,"}, {"kind": "text", "text": "אֱמֶת אַתָּה הוּא רִאשׁוֹן"}, {"kind": "text", "text": "וְאַתָּה הוּא אַחֲרוֹן"}, {"kind": "text", "text": "וּמִבַּלְעָדֶֽיךָ אֵין אֱלֹהִים:"}, {"kind": "text", "text": "קַבֵּץ נְפוּצוֹת קֹוֶֽיךָ"}, {"kind": "text", "text": "מֵאַרְבַּע כַּנְ֒פוֹת הָאָֽרֶץ,"}, {"kind": "text", "text": "יַכִּֽירוּ וְיֵדְ֒עוּ כָּל בָּאֵי עוֹלָם"}, {"kind": "text", "text": "כִּי אַתָּה הוּא הָאֱלֹהִים לְבַדֶּֽךָ"}, {"kind": "text", "text": "לְכֹל מַמְלְ֒כוֹת הָאָֽרֶץ,"}, {"kind": "text", "text": "אַתָּה עָשִֽׂיתָ אֶת הַשָּׁמַֽיִם"}, {"kind": "text", "text": "וְאֶת הָאָֽרֶץ"}, {"kind": "text", "text": "אֶת הַיָּם וְאֶת כָּל אֲשֶׁר בָּם"}, {"kind": "text", "text": "וּמִי בְּכָל מַעֲשֵׂה יָדֶֽיךָ"}, {"kind": "text", "text": "בָּעֶלְיוֹנִים אוֹ בַתַּחְתּוֹנִים"}, {"kind": "text", "text": "שֶׁיֹּאמַר לְךָ מַה תַּעֲשֶׂה,"}, {"kind": "text", "text": "ומַה תִּפְעָל"}, {"kind": "text", "text": "אָבִינוּ שֶׁבַּשָּׁמַֽיִם"}, {"kind": "text", "text": "חַי וְקַיָם"}, {"kind": "text", "text": "עֲשֵׂה עִמָּֽנוּ צְדָקָה וָחֶֽסֶד"}, {"kind": "text", "text": "בַּעֲבוּר שִׁמְ֒ךָ הַגָּדוֹל"}, {"kind": "text", "text": "הַגִּבּוֹר וְהַנּוֹרָא"}, {"kind": "text", "text": "שֶׁנִּקְרָא עָלֵֽינוּ"}, {"kind": "text", "text": "וְקַיֶּם־לָֽנוּ יְהֹוָה אֶלֹהֵֽינוּ"}, {"kind": "text", "text": "אֶת הַדָבָר שֶׁהִבְטַחְתָּֽנוּ"}, {"kind": "text", "text": "עַל יְדֵי צְפַנְיָה חוֹזָךְ"}, {"kind": "text", "text": "כָּאָמוּר,"}, {"kind": "text", "text": "בָּעֵת הַהִיא אָבִיא אֶתְ֒כֶם"}, {"kind": "text", "text": "וּבָעֵת קַבְּ֒צִי אֶתְ֒כֶם"}, {"kind": "text", "text": "כִּי־אֶתֵּן אֶתְ֒כֶם לְשֵׁם וְלִתְ֒הִלָּה"}, {"kind": "text", "text": "בְּכֹל עַמֵּי הָאָֽרֶץ"}, {"kind": "text", "text": "בְּשׁוּבִי אֶת־שְׁבוּתֵיכֶם"}, {"kind": "text", "text": "לְעֵינֵיכֶם אָמַר יְהֹוָה:"}, {"kind": "header", "text": "קרבנות"}, {"kind": "text", "text": "וַיְדַבֵּר יְהֹוָה אֶל־משֶׁה לֵּאמֹר:"}, {"kind": "text", "text": "וְעָשִֽׂיתָ כִּיּוֹר נְחֽשֶׁת"}, {"kind": "text", "text": "וְכַנּוֹ נְחֽשֶׁת לְרָחְצָה"}, {"kind": "text", "text": "וְנָתַתָּ אֹת֒וֹ"}, {"kind": "text", "text": "בֵּין־אֹֽהֶל מוֹעֵד וּבֵין הַמִּזְבֵּֽחַ"}, {"kind": "text", "text": "וְנָתַתָּ שָֽׁמָּה מָֽיִם:"}, {"kind": "text", "text": "וְרָחֲצוּ אַהֲרֹן וּבָנָיו מִמֶּֽנּוּ"}, {"kind": "text", "text": "אֶת־יְדֵיהֶם וְאֶת־רַגְלֵיהֶם:"}, {"kind": "text", "text": "בְּבֹאָם אֶל־אֹֽהֶל מוֹעֵד"}, {"kind": "text", "text": "יִרְחֲצוּ־מַֽיִם וְלֹא יָמֻֽתוּ"}, {"kind": "text", "text": "אוֹ בְגִשְׁתָּם אֶל־הַמִּזְבֵּֽחַ"}, {"kind": "text", "text": "לְשָׁרֵת לְהַקְטִיר אִשֶּׁה לַיהוֹה:"}, {"kind": "text", "text": "וְרָחֲצוּ יְדֵיהֶם וְרַגְלֵיהֶם"}, {"kind": "text", "text": "וְלֹא יָמֻֽתוּ"}, {"kind": "text", "text": "וְהָיְ֒תָה לָהֶם חָק־עוֹלָם"}, {"kind": "text", "text": "לוֹ וּלְ֒זַרְעוֹ"}, {"kind": "text", "text": "לְדֹרֹתָם:"}, {"kind": "text", "text": "וַיְדַבֵּר יְהֹוָה אֶל־משֶׁה לֵּאמֹר:"}, {"kind": "text", "text": "צַו אֶת־אַהֲרֹן וְאֶת־בָּנָיו לֵאמֹר"}, {"kind": "text", "text": "זֹאת תּוֹרַת הָעֹלָה"}, {"kind": "text", "text": "הִוא הָעֹלָה"}, {"kind": "text", "text": "עַל מוֹקְ֒דָה"}, {"kind": "text", "text": "עַל־הַמִּזְבֵּֽחַ כָּל־הַלַּֽיְלָה"}, {"kind": "text", "text": "עַד־הַבֹּֽקֶר"}, {"kind": "text", "text": "וְאֵשׁ הַמִּזְבֵּֽחַ"}, {"kind": "text", "text": "תּוּקַד בּוֹ:"}, {"kind": "text", "text": "וְלָבַשׁ הַכֹּהֵן מִדּוֹ בַד"}, {"kind": "text", "text": "וּמִכְנְ֒סֵי־בַד יִלְבַּשׁ עַל־בְּשָׂרוֹ"}, {"kind": "text", "text": "וְהֵרִים אֶת־הַדֶּֽשֶׁן"}, {"kind": "text", "text": "אֲשֶׁר תֹּאכַל הָאֵשׁ"}, {"kind": "text", "text": "אֶת הָעֹלָה עַל־הַמִּזְבֵּֽחַ"}, {"kind": "text", "text": "וְשָׂמוֹ אֵֽצֶל הַמִּזְבֵּֽחַ:"}, {"kind": "text", "text": "וּפָשַׁט אֶת־בְּגָדָיו"}, {"kind": "text", "text": "וְלָבַשׁ בְּגָדִים אֲחֵרִים"}, {"kind": "text", "text": "וְהוֹצִיא אֶת־הַדֶּֽשֶׁן"}, {"kind": "text", "text": "אֶל־מִחוּץ לַמַּחֲנֶה"}, {"kind": "text", "text": "אֶל־מָקוֹם טָהוֹר:"}, {"kind": "text", "text": "וְהָאֵשׁ עַל־הַמִּזְבֵּֽחַ תּֽוּקַד־בּוֹ"}, {"kind": "text", "text": "לֹא תִכְבֶּה"}, {"kind": "text", "text": "וּבִעֵר עָלֶֽיהָ הַכֹּהֵן עֵצִים"}, {"kind": "text", "text": "בַּבֹּֽקֶר בַּבֹּֽקֶר"}, {"kind": "text", "text": "וְעָרַךְ עָלֶֽיהָ הָעֹלָה"}, {"kind": "text", "text": "וְהִקְטִיר עָלֶֽיהָ חֶלְ֒בֵי הַשְּׁ֒לָמִים:"}, {"kind": "text", "text": "אֵשׁ תָּמִיד"}, {"kind": "text", "text": "תּוּקַד עַל־הַמִּזְבֵּֽחַ"}, {"kind": "text", "text": "לֹא תִכְבֶּה:"}, {"kind": "header", "text": "קרבן תמיד"}, {"kind": "text", "text": "יְהִי רָצוֹן מִלְּ֒פָנֶֽיךָ,"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ,"}, {"kind": "text", "text": "שֶׁתְּ֒רַחֵם עָלֵֽינוּ"}, {"kind": "text", "text": "וְתִמְחָל לָֽנוּ עַל כָּל חַטֹּאתֵֽינוּ"}, {"kind": "text", "text": "וּתְ֒כַפֶּר לָֽנוּ אֶת כָּל עֲוֹנוֹתֵֽינוּ"}, {"kind": "text", "text": "וְתִסְלַח לָֽנוּ עַל־כָּל פְּשָׁעֵֽינוּ"}, {"kind": "text", "text": "וְשֶׁתִּבְנֶה בֵּית הַמִּקְדָּשׁ"}, {"kind": "text", "text": "בִּמְ֒הֵרָה בְיָמֵֽינוּ"}, {"kind": "text", "text": "וְנַקְרִיב לְפָנֶֽיךָ"}, {"kind": "text", "text": "קָרְבַּן הַתָּמִיד שֶׁיְּ֒כַפֵּר בַּעֲדֵֽנוּ"}, {"kind": "text", "text": "כְּמוֹ שֶׁכָּתַֽבְתָּ עָלֵֽינוּ בְּתוֹרָתֶֽךָ,"}, {"kind": "text", "text": "עַל יְדֵי משֶׁה עַבְדֶּֽךָ,"}, {"kind": "text", "text": "מִפִּי כְבוֹדֶֽךָ"}, {"kind": "text", "text": "כָּאָמוּר:"}, {"kind": "text", "text": "וַיְ֒דַבֵּר יְהֹוָה אֶל־משֶׁה לֵּאמֹר:"}, {"kind": "text", "text": "צַו אֶת־בְּנֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאָמַרְתָּ אֲלֵהֶם"}, {"kind": "text", "text": "אֶת־קָרְבָּנִי לַחְמִי"}, {"kind": "text", "text": "לְאִשַּׁ֒י"}, {"kind": "text", "text": "רֵֽיחַ נִיחֹחִי"}, {"kind": "text", "text": "תִּשְׁמְ֒רוּ לְהַקְרִיב לִי"}, {"kind": "text", "text": "בְּמוֹעֲדוֹ:"}, {"kind": "text", "text": "וְאָמַרְתָּ לָהֶם"}, {"kind": "text", "text": "זֶה הָאִשֶּׁה"}, {"kind": "text", "text": "אֲשֶׁר תַּקְרִֽיבוּ לַיהוֹה"}, {"kind": "text", "text": "כְּבָשִׂים בְּנֵי־שָׁנָה"}, {"kind": "text", "text": "תְמִימִם"}, {"kind": "text", "text": "שְׁנַֽיִם לַיּוֹם"}, {"kind": "text", "text": "עֹלָה תָמִיד:"}, {"kind": "text", "text": "אֶת־הַכֶּֽבֶשׂ אֶחָד תַּעֲשֶׂה בַבֹּֽקֶר"}, {"kind": "text", "text": "וְאֵת הַכֶּֽבֶשׂ הַשֵּׁנִי"}, {"kind": "text", "text": "תַּעֲשֶׂה בֵּין הָעַרְבָּֽיִם:"}, {"kind": "text", "text": "וַֽעֲשִׂירִית הָאֵיפָה סֹֽלֶת"}, {"kind": "text", "text": "לְמִנְחָה"}, {"kind": "text", "text": "בְּלוּלָה בְּשֶֽׁמֶן כָּתִית"}, {"kind": "text", "text": "רְבִיעִת הַהִין:"}, {"kind": "text", "text": "עֹלַת תָּמִיד"}, {"kind": "text", "text": "הָעֲשֻׂיָה בְּהַר סִינַי"}, {"kind": "text", "text": "לְרֵֽיחַ נִיחֹֽחַ אִשֶּׁה לַיהוֹה:"}, {"kind": "text", "text": "וְנִסְכּוֹ"}, {"kind": "text", "text": "רְבִיעִת הַהִין לַכֶּֽבֶשׂ הָאֶחָד"}, {"kind": "text", "text": "בַּקֹּֽדֶשׁ הַסֵּךְ"}, {"kind": "text", "text": "נֶֽסֶךְ שֵׁכָר לַיהוֹה:"}, {"kind": "text", "text": "וְאֵת הַכֶּֽבֶשׂ הַשֵּׁנִי"}, {"kind": "text", "text": "תַּעֲשֶׂה בֵּין הָעַרְבָּֽיִם"}, {"kind": "text", "text": "כְּמִנְחַת הַבֹּֽקֶר"}, {"kind": "text", "text": "וּכְ֒נִסְכּוֹ תַּעֲשֶׂה"}, {"kind": "text", "text": "אִשֵּׁה רֵֽיחַ נִיחֹֽחַ לַיהוֹה:"}, {"kind": "text", "text": "וְשָׁחַט אֹתוֹ"}, {"kind": "text", "text": "עַל יֶֽרֶךְ הַמִּזְבֵּֽחַ צָפֹֽנָה"}, {"kind": "text", "text": "לִפְ֒נֵי יְהֹוָה"}, {"kind": "text", "text": "וְזָרְקוּ בְּנֵי אַהֲרֹן הַכֹּהֲנִים"}, {"kind": "text", "text": "אֶת־דָּמוֹ עַל־הַמִּזְבֵּֽחַ סָבִיב:"}, {"kind": "text", "text": "יְהִי רָצוֹן מִלְּ֒פָנֶֽיךָ,"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ,"}, {"kind": "text", "text": "שֶׁתְּ֒הֵא אֲמִירָה זוּ,"}, {"kind": "text", "text": "חֲשׁוּבָה וּמְ֒קֻבֶּֽלֶת,"}, {"kind": "text", "text": "וּמְ֒רֻצָּה לְפָנֶֽיךָ,"}, {"kind": "text", "text": "כְּאִלּוּ הִקְרַֽבְנוּ"}, {"kind": "text", "text": "קָרְבַּן הַתָּמִיד"}, {"kind": "text", "text": "בְּמוֹעֲדוֹ,"}, {"kind": "text", "text": "וּבִמְ֒קוֹמוֹ"}, {"kind": "text", "text": "וּכְ֒הִלְ֒כָתוֹ:"}, {"kind": "header", "text": "קטורת"}, {"kind": "text", "text": "אַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "שֶׁהִקְטִֽירוּ אֲבוֹתֵֽינוּ לְפָנֶֽיךָ"}, {"kind": "text", "text": "אֶת קְטֹֽרֶת הַסַּמִּים"}, {"kind": "text", "text": "בִּזְ֒מַן שֶׁבֵּית הַמִּקְדָּשׁ הָיָה קַיָּם"}, {"kind": "text", "text": "כַּאֲשֶׁר צִוִּֽיתָ אוֹתָם"}, {"kind": "text", "text": "עַל יְדֵי משֶׁה נְבִיאֶֽךָ"}, {"kind": "text", "text": "כַּכָּתוּב בְּתוֹרָתֶֽךָ:"}, {"kind": "text", "text": "וַיֹּֽאמֶר יְהֹוָה אֶל־משֶׁה"}, {"kind": "text", "text": "קַח־לְךָ סַמִּים"}, {"kind": "text", "text": "נָטָף וּשְׁ֒חֵֽלֶת וְחֶלְבְּנָה"}, {"kind": "text", "text": "סַמִּים וּלְ֒בֹנָה זַכָּה"}, {"kind": "text", "text": "בַּד בְּבַד יִהְיֶה:"}, {"kind": "text", "text": "וְעָשִֽׂיתָ אֹתָהּ קְטֹֽרֶת"}, {"kind": "text", "text": "רֹֽקַח מַעֲשֵׂה רוֹקֵֽחַ"}, {"kind": "text", "text": "מְמֻלָּח טָהוֹר קֹֽדֶשׁ:"}, {"kind": "text", "text": "וְשָׁחַקְתָּ מִמֶּֽנָּה הָדֵק֒"}, {"kind": "text", "text": "וְנָתַתָּה מִמֶּֽנָּה לִפְ֒נֵי הָעֵדֻת"}, {"kind": "text", "text": "בְּאֹֽהֶל מוֹעֵד"}, {"kind": "text", "text": "אֲשֶׁר אִוָּעֵד לְךָ שָֽׁמָּה"}, {"kind": "text", "text": "קֹֽדֶשׁ קָדָשִׁים תִּהְיֶה לָכֶם:"}, {"kind": "text", "text": "וְנֶאֱמַר"}, {"kind": "text", "text": "וְהִקְטִיר עָלָיו אַהֲרֹן"}, {"kind": "text", "text": "קְטֹֽרֶת סַמִּים בַּבֹּֽקֶר בַּבֹּֽקֶר"}, {"kind": "text", "text": "בְּהֵיטִיבוֹ אֶת־הַנֵּרֹת"}, {"kind": "text", "text": "יַקְטִירֶֽנָּה:"}, {"kind": "text", "text": "וּבְ֒הַעֲלֹת אַהֲרֹן אֶת־הַנֵּרֹת"}, {"kind": "text", "text": "בֵּין הָֽעַרְבַּֽיִם"}, {"kind": "text", "text": "יַקְטִירֶֽנָּה"}, {"kind": "text", "text": "קְטֹֽרֶת תָּמִיד לִפְ֒נֵי יְהֹוָה"}, {"kind": "text", "text": "לְדֹרֹתֵיכֶם:"}, {"kind": "text", "text": "תָּנוּ רַבָּנָן"}, {"kind": "text", "text": "פִּטּוּם הַקְּ֒טֹֽרֶת כֵּיצַד"}, {"kind": "text", "text": "שְׁלֹש מֵאוֹת וְשִׁשִּׁים וּשְׁ֒מוֹנָה"}, {"kind": "text", "text": "מָנִים הָיוּ בָהּ,"}, {"kind": "text", "text": "שְׁלֹש מֵאוֹת וְשִׁשִּׁים וַחֲמִשָּׁה"}, {"kind": "text", "text": "כְּמִנְיַן"}, {"kind": "text", "text": "יְמוֹת הַחַמָּה"}, {"kind": "text", "text": "מָנֶה לְכָל יוֹם,"}, {"kind": "text", "text": "פְּרַס בַּשַּׁחֲרִית"}, {"kind": "text", "text": "וּפְ֒רַס בֵּין הָעַרְבָּֽיִם,"}, {"kind": "text", "text": "וּשְׁ֒לשָׁה מָנִים יְתֵרִים"}, {"kind": "text", "text": "שֶׁמֵּהֶם מַכְנִיס כֹּהֵן גָּדוֹל"}, {"kind": "text", "text": "מְלֹא חָפְנָיו"}, {"kind": "text", "text": "בְּיוֹם הַכִּפּוּרִים,"}, {"kind": "text", "text": "וּמַחֲזִירָן"}, {"kind": "text", "text": "לְמַכְתֶּֽשֶׁת"}, {"kind": "text", "text": "בְּעֶֽרֶב יוֹם הַכִּפּוּרִים,"}, {"kind": "text", "text": "וְשׁוֹחֲקָן יָפֶה יָפֶה"}, {"kind": "text", "text": "כְּדֵי שֶׁתְּ֒הֵא דַקָּה מִן הַדַּקָּה,"}, {"kind": "text", "text": "וְאַחַד עָשָׂר סַמָּנִים הָֽיוּ בָהּ,"}, {"kind": "text", "text": "וְאֵֽלּוּ הֵן"}, {"kind": "text", "text": "הַצֳּרִי וְהַצִּפֹּֽרֶן"}, {"kind": "text", "text": "הַחֶלְבְּנָה וְהַלְּ֒בוֹנָה"}, {"kind": "text", "text": "מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה,"}, {"kind": "text", "text": "מוֹר וּקְ֒צִיעָה"}, {"kind": "text", "text": "שִׁבֹּֽלֶת נֵרְדְּ וְכַרְכֹּם"}, {"kind": "text", "text": "מִשְׁקַל"}, {"kind": "text", "text": "שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה,"}, {"kind": "text", "text": "הַקּשְׁטְ שְׁנֵים עָשָׂר"}, {"kind": "text", "text": "וְקִלּוּפָה שְׁלשָׁה"}, {"kind": "text", "text": "וְקִנָּמוֹן תִּשְׁעָה,"}, {"kind": "text", "text": "בֹּרִית כַּרְשִׁינָה תִּשְׁעָה קַבִּין,"}, {"kind": "text", "text": "יֵין קַפְרִיסִין"}, {"kind": "text", "text": "סְאִין תְּלָתָא וְקַבִּין תְּלָתָא,"}, {"kind": "text", "text": "וְאִם אֵין לוֹ יֵין קַפְרִיסִין"}, {"kind": "text", "text": "מֵבִיא חֲמַר חִוַּרְיָן עַתִּיק,"}, {"kind": "text", "text": "מֶֽלַח סְדוֹמִית רֹֽבַע הַקָּב,"}, {"kind": "text", "text": "מַעֲלֶה עָשָׁן כָּל שֶׁהוּא,"}, {"kind": "text", "text": "רַבִּי נָתָן הַבַּבְלִי אוֹמֵר"}, {"kind": "text", "text": "אַף כִּפַּת הַיַּרְדֵּן"}, {"kind": "text", "text": "כָּל שֶׁהוּא,"}, {"kind": "text", "text": "וְאִם נָֽתַן בָּהּ דְּבַשׁ"}, {"kind": "text", "text": "פְּסָלָהּ"}, {"kind": "text", "text": "וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶֽיהָ"}, {"kind": "text", "text": "חַיָּב מִיתָה:"}, {"kind": "text", "text": "רַבָּן שִׁמְעוֹן בֶּן גַּמְלִיאֵל"}, {"kind": "text", "text": "אוֹמֵר"}, {"kind": "text", "text": "הַצֳּרִי אֵינוֹ אֶלָּא שְׂרָף"}, {"kind": "text", "text": "הַנּוֹטֵף מֵעֲצֵי הַקְּ֒טָף,"}, {"kind": "text", "text": "בֹּרִית כַּרְשִׁינָה"}, {"kind": "text", "text": "שֶׁשָׁפִין בָּה אֶת הַצִפֹּרֶן"}, {"kind": "text", "text": "כִּדֵי שֶׁתְּ֒הֵא נָאֶה"}, {"kind": "text", "text": "יֵין קַפְרִיסִין"}, {"kind": "text", "text": "שֶׁשׁוֹרִין בּוֹ אֶת הַצִפֹּרֶן"}, {"kind": "text", "text": "כְּדֵי שֶׁתְּ֒הֵא עַזָּה,"}, {"kind": "text", "text": "וַהֲלֹא מֵי רַגְלַֽיִם"}, {"kind": "text", "text": "יָפִין לָהּ"}, {"kind": "text", "text": "אֶלָּא שֶׁאֵין מַכְנִיסִין"}, {"kind": "text", "text": "מֵי רַגְלַֽיִם בַּמִּקְדָּשׁ"}, {"kind": "text", "text": "מִפְּנֵי הַכָּבוֹד:"}, {"kind": "text", "text": "תַּנְיָא"}, {"kind": "text", "text": "רַבִּי נָתָן אוֹמֵר"}, {"kind": "text", "text": "כְּשֶׁהוּא שׁוֹחֵק"}, {"kind": "text", "text": "אוֹמֵר"}, {"kind": "text", "text": "הָדֵק הֵיטֵב הֵיטֵב הָדֵק"}, {"kind": "text", "text": "מִפְּ֒נֵי שֶׁהַקּוֹל יָפֶה לַבְּ֒שָׂמִים,"}, {"kind": "text", "text": "פִּטְּ֒מָהּ לַחֲצָאִין"}, {"kind": "text", "text": "כְּשֵׁרָה"}, {"kind": "text", "text": "לִשְׁ֒לִישׁ"}, {"kind": "text", "text": "וְלִרְ֒בִֽיעַ"}, {"kind": "text", "text": "לֹא שָׁמַֽעְנוּ:"}, {"kind": "text", "text": "אָמַר רַבִּי יְהוּדָה"}, {"kind": "text", "text": "זֶה הַכְּ֒לָל"}, {"kind": "text", "text": "אִם"}, {"kind": "text", "text": "כְּמִדָּתָהּ"}, {"kind": "text", "text": "כְּשֵׁרָה"}, {"kind": "text", "text": "לַחֲצָאִין"}, {"kind": "text", "text": "וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶֽיהָ"}, {"kind": "text", "text": "חַיָּב מִיתָה:"}, {"kind": "text", "text": "תַּנְיָא"}, {"kind": "text", "text": "בַּר קַפָּרָא אוֹמֵר"}, {"kind": "text", "text": "אַחַת לְשִׁשִּׁים אוֹ לְשִׁבְעִים שָׁנָה"}, {"kind": "text", "text": "הָיְ֒תָה בָאָה שֶׁל שִׁירַֽיִם"}, {"kind": "text", "text": "לַחֲצָאִין:"}, {"kind": "text", "text": "וְעוֹד תָּנֵי בַּר קַפָּרָא"}, {"kind": "text", "text": "אִלּוּ הָיָה נוֹתֵן בָּהּ"}, {"kind": "text", "text": "קוֹרְ֒טוֹב שֶׁל דְּבַשׁ"}, {"kind": "text", "text": "אֵין אָדָם יָכוֹל לַעֲמֹד"}, {"kind": "text", "text": "מִפְּ֒נֵי רֵיחָהּ"}, {"kind": "text", "text": "וְלָֽמָּה אֵין מְעָרְ֒בִין בָּהּ דְּבַשׁ"}, {"kind": "text", "text": "מִפְּ֒נֵי שֶׁהַתּוֹרָה אָמְ֒רָה"}, {"kind": "text", "text": "כִּי כָל־שְׂאֹר וְכָל־דְּבַשׁ"}, {"kind": "text", "text": "לֹא־תַקְטִֽירוּ מִמֶּֽנּוּ"}, {"kind": "text", "text": "אִשֶּׁה לַיהוֹה:"}, {"kind": "text", "text": "יְהֹוָה צְבָאוֹת עִמָּֽנוּ"}, {"kind": "text", "text": "מִשְׂגָּב לָֽנוּ אֱלֹהֵי יַעֲקֹב"}, {"kind": "text", "text": "סֶֽלָה:"}, {"kind": "text", "text": "יְהֹוָה צְבָאוֹת"}, {"kind": "text", "text": "אַשְׁרֵי אָדָם בֹּטֵֽחַ בָּךְ:"}, {"kind": "text", "text": "יְהֹוָה הוֹשִֽׁיעָה"}, {"kind": "text", "text": "הַמֶּֽלֶךְ יַעֲנֵֽנוּ בְיוֹם־קָרְ֒אֵֽנוּ:"}, {"kind": "text", "text": "אַתָּה סֵֽתֶר לִי"}, {"kind": "text", "text": "מִצַּר תִּצְּ֒רֵֽנִי"}, {"kind": "text", "text": "רָנֵּי פַלֵּט תְּסוֹבְ֒בֵֽנִי"}, {"kind": "text", "text": "סֶֽלָה:"}, {"kind": "text", "text": "וְעָרְ֒בָה לַיהוֹה"}, {"kind": "text", "text": "מִנְחַת יְהוּדָה וִירוּשָׁלָֽםִ"}, {"kind": "text", "text": "כִּימֵי עוֹלָם וּכְ֒שָׁנִים קַדְמֹנִיּוֹת:"}, {"kind": "text", "text": "אַבַּיֵּי, הֲוָה מְסַדֵּר"}, {"kind": "text", "text": "סֵֽדֶר הַמַּעֲרָכָה"}, {"kind": "text", "text": "מִשְּׁ֒מָא דִגְ֒מָרָא"}, {"kind": "text", "text": "וְאַלִּבָּא דְאַבָּא שָׁאוּל,"}, {"kind": "text", "text": "מַעֲרָכָה גְדוֹלָה"}, {"kind": "text", "text": "קוֹדֶֽמֶת לְמַעֲרָכָה שְׁנִיָּה"}, {"kind": "text", "text": "שֶׁל קְטֹֽרֶת,"}, {"kind": "text", "text": "וּמַעֲרָכָה שְׁנִיָּה שֶׁל קְטֹֽרֶת"}, {"kind": "text", "text": "קוֹדֶֽמֶת"}, {"kind": "text", "text": "לְסִדּוּר שְׁנֵי גִזְ֒רֵי עֵצִים,"}, {"kind": "text", "text": "וְסִדּוּר שְׁנֵי גִזְ֒רֵי עֵצִים קֽוֹדֶם"}, {"kind": "text", "text": "לְדִשּׁוּן"}, {"kind": "text", "text": "מִזְבֵּֽחַ הַפְּ֒נִימִי,"}, {"kind": "text", "text": "וְדִשּׁוּן מִזְבֵּֽחַ הַפְּ֒נִימִי"}, {"kind": "text", "text": "קֽוֹדֶם"}, {"kind": "text", "text": "לְהַטָּבַת חָמֵשׁ נֵרוֹת,"}, {"kind": "text", "text": "וְהַטָּבַת חָמֵשׁ נֵרוֹת קוֹדֶֽמֶת"}, {"kind": "text", "text": "לְדַם הַתָּמִיד,"}, {"kind": "text", "text": "וְדַם הַתָּמִיד קֽוֹדֶם"}, {"kind": "text", "text": "לְהַטָּבַת שְׁתֵּי נֵרוֹת,"}, {"kind": "text", "text": "וְהַטָּבַת שְׁתֵּי נֵרוֹת קוֹדֶֽמֶת"}, {"kind": "text", "text": "לִקְ֒טֹֽרֶת,"}, {"kind": "text", "text": "וּקְ֒טֹֽרֶת קוֹדֶֽמֶת"}, {"kind": "text", "text": "לְאֵבָרִים,"}, {"kind": "text", "text": "וְאֵבָרִים"}, {"kind": "text", "text": "לְמִנְחָה,"}, {"kind": "text", "text": "וּמִנְחָה"}, {"kind": "text", "text": "לַחֲבִתִּין,"}, {"kind": "text", "text": "וַחֲבִתִּין"}, {"kind": "text", "text": "לִנְ֒סָכִין,"}, {"kind": "text", "text": "וּנְ֒סָכִין"}, {"kind": "text", "text": "לְמוּסָפִין,"}, {"kind": "text", "text": "וּמוּסָפִין"}, {"kind": "text", "text": "לְבָזִיכִין,"}, {"kind": "text", "text": "וּבָזִיכִין קוֹדְ֒מִין"}, {"kind": "text", "text": "לְתָמִיד שֶׁל בֵּין הָעַרְבָּֽיִם,"}, {"kind": "text", "text": "שֶׁנֶּאֱמַר"}, {"kind": "text", "text": "וְעָרַךְ עָלֶֽיהָ"}, {"kind": "text", "text": "הָעֹלָה"}, {"kind": "text", "text": "וְהִקְטִיר עָלֶֽיהָ חֶלְ֒בֵי הַשְּׁ֒לָמִים,"}, {"kind": "text", "text": "עָלֶֽיהָ הַשְׁלֵם"}, {"kind": "text", "text": "כָּל הַקָּרְבָּנוֹת כֻּלָּם:"}, {"kind": "text", "text": "אָֽנָּא, בְּכֹֽחַ גְּדֻלַּת יְמִינְ֒ךָ"}, {"kind": "text", "text": "תַּתִּיר צְרוּרָה:"}, {"kind": "text", "text": "קַבֵּל רִנַּת עַמְּ֒ךָ"}, {"kind": "text", "text": "שַׂגְּ֒בֵֽנוּ טַהֲרֵֽנוּ נוֹרָא:"}, {"kind": "text", "text": "נָא גִבּוֹר"}, {"kind": "text", "text": "דּוֹרְ֒שֵׁי יִחוּדְ֒ךָ"}, {"kind": "text", "text": "כְּבָבַת שָׁמְ֒רֵם:"}, {"kind": "text", "text": "בָּרְ֒כֵם טַהֲרֵם"}, {"kind": "text", "text": "רַחֲמֵי"}, {"kind": "text", "text": "צִדְ֒קָתְ֒ךָ"}, {"kind": "text", "text": "תָּמִיד גָּמְ֒לֵם:"}, {"kind": "text", "text": "חֲסִין קָדוֹשׁ"}, {"kind": "text", "text": "בְּרֹב טוּבְ֒ךָ"}, {"kind": "text", "text": "נַהֵל עֲדָתֶֽךָ:"}, {"kind": "text", "text": "יָחִיד גֵּאֶה לְעַמְּ֒ךָ פְּנֵה,"}, {"kind": "text", "text": "זוֹכְ֒רֵי קְדֻשָּׁתֶֽךָ:"}, {"kind": "text", "text": "שַׁוְעָתֵֽנוּ קַבֵּל וּשְׁ֒מַע צַעֲקָתֵֽנוּ"}, {"kind": "text", "text": "יוֹדֵֽעַ תַּעֲלוּמוֹת:"}, {"kind": "text", "text": "בָּרוּךְ שֵׁם"}, {"kind": "text", "text": "כְּבוֹד מַלְ֒כוּתוֹ"}, {"kind": "text", "text": "לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "רִבּוֹן הָעוֹלָמִים אַתָּה צִוִּיתָֽנוּ"}, {"kind": "text", "text": "לְהַקְרִיב קָרְבַּן הַתָּמִיד"}, {"kind": "text", "text": "בְּמוֹעֲדוֹ"}, {"kind": "text", "text": "וְלִהְ֒יוֹת כֹּהֲנִים בַּעֲבוֹדָתָם"}, {"kind": "text", "text": "וּלְ֒וִיִּם"}, {"kind": "text", "text": "בְּדוּכָנָם"}, {"kind": "text", "text": "וְיִשְׂרָאֵל"}, {"kind": "text", "text": "בְּמַעֲמָדָם,"}, {"kind": "text", "text": "וְעַתָּה בַּעֲוֹנוֹתֵֽינוּ"}, {"kind": "text", "text": "חָרַב בֵּית הַמִּקְדָּשׁ"}, {"kind": "text", "text": "וּבֻטַּל הַתָּמִיד"}, {"kind": "text", "text": "וְאֵין לָֽנוּ לֹא כֹהֵן בַּעֲבוֹדָתוֹ"}, {"kind": "text", "text": "וְלֹא לֵוִי בְּדוּכָנוֹ"}, {"kind": "text", "text": "וְלֹא יִשְׂרָאֵל בְּמַעֲמָדוֹ."}, {"kind": "text", "text": "לָכֵן יְהִי רָצוֹן מִלְּ֒פָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "שֶׁיְּ֒הֵא שִֽׂיחַ שִׂפְ֒תוֹתֵֽינוּ"}, {"kind": "text", "text": "חָשׁוּב וּמְ֒קֻבָּל"}, {"kind": "text", "text": "וּמְ֒רֻצֶּה לְפָנֶֽיךָ"}, {"kind": "text", "text": "כְּאִלּוּ הִקְרַֽבְנוּ קָרְבַּן הַתָּמִיד"}, {"kind": "text", "text": "בְּמוֹעֲדוֹ"}, {"kind": "text", "text": "וְעָמַֽדְנוּ עַל מַעֲמָדוֹ."}, {"kind": "text", "text": "כְּמָה שֶׁנֶּאֱמַר"}, {"kind": "text", "text": "וּנְ֒שַׁלְּ֒מָה פָרִים"}, {"kind": "text", "text": "שְׂפָתֵֽינוּ:"}, {"kind": "text", "text": "וְנֶאֶמַר"}, {"kind": "text", "text": "וְשָׁחַט אֹתוֹ"}, {"kind": "text", "text": "עַל יֶֽרֶךְ הַמִּזְבֵּֽחַ צָפֹֽנָה"}, {"kind": "text", "text": "לִפְ֒נֵי יְהֹוָה"}, {"kind": "text", "text": "וְזָרְ֒קוּ בְּנֵי אַהֲרֹן הַכֹּהֲנִים"}, {"kind": "text", "text": "אֶת־דָּמוֹ עַל־הַמִּזְבֵּֽחַ סָבִיב:"}, {"kind": "text", "text": "וְנֶאֱמַר"}, {"kind": "text", "text": "זֹאת הַתּוֹרָה"}, {"kind": "text", "text": "לָעֹלָה"}, {"kind": "text", "text": "לַמִּנְחָה"}, {"kind": "text", "text": "וְלַחַטָּאת"}, {"kind": "text", "text": "וְלָאָשָׁם"}, {"kind": "text", "text": "וְלַמִּלּוּאִים"}, {"kind": "text", "text": "וּלְ֒זֶֽבַח הַשְּׁ֒לָמִים:"}, {"kind": "text", "text": "וּבְיוֹם הַשַּׁבָּת"}, {"kind": "text", "text": "שְׁנֵי־כְבָשִׂים בְּנֵי־שָׁנָה תְּמִימִם"}, {"kind": "text", "text": "וּשְׁנֵי עֶשְׂרֹנִים סֹֽלֶת"}, {"kind": "text", "text": "מִנְחָה"}, {"kind": "text", "text": "בְּלוּלָה בַשֶּֽׁמֶן וְנִסְכּוֹ:"}, {"kind": "text", "text": "עֹלַת שַׁבַּת בְּשַׁבַּתּוֹ"}, {"kind": "text", "text": "עַל־עֹלַת הַתָּמִיד"}, {"kind": "text", "text": "וְנִסְכָּהּ:"}, {"kind": "text", "text": "וּבְ֒רָאשֵׁי חָדְ֒שֵׁיכֶם"}, {"kind": "text", "text": "תַּקְרִֽיבוּ עֹלָה לַיהוֹה"}, {"kind": "text", "text": "פָּרִים בְּנֵי־בָקָר שְׁנַֽיִם"}, {"kind": "text", "text": "וְאַֽיִל אֶחָד"}, {"kind": "text", "text": "כְּבָשִׂים בְּנֵי־שָׁנָה שִׁבְעָה"}, {"kind": "text", "text": "תְּמִימִם:"}, {"kind": "text", "text": "וּשְׁ֒לשָׁה עֶשְׂרֹנִים סֹֽלֶת"}, {"kind": "text", "text": "מִנְחָה בְּלוּלָה בַשֶּֽׁמֶן"}, {"kind": "text", "text": "לַפָּר הָאֶחָד"}, {"kind": "text", "text": "וּשְׁ֒נֵי עֶשְׂרֹנִים סֹֽלֶת"}, {"kind": "text", "text": "מִנְחָה בְּלוּלָה בַשֶּֽׁמֶן"}, {"kind": "text", "text": "לָאַֽיִל הָאֶחָד:"}, {"kind": "text", "text": "וְעִשָּׂרֹן עִשָּׂרוֹן סֹֽלֶת"}, {"kind": "text", "text": "מִנְחָה בְּלוּלָה בַשֶּֽׁמֶן"}, {"kind": "text", "text": "לַכֶּֽבֶשׂ הָאֶחָד"}, {"kind": "text", "text": "עֹלָה רֵֽיחַ נִיחֹֽחַ"}, {"kind": "text", "text": "אִשֶּׁה לַיהוֹה:"}, {"kind": "text", "text": "וְנִסְכֵּיהֶם"}, {"kind": "text", "text": "חֲצִי הַהִין יִהְיֶה לַפָּר"}, {"kind": "text", "text": "וּשְׁלִישִׁת הַהִין לָאַֽיִל"}, {"kind": "text", "text": "וּרְ֒בִיעִת הַהִין לַכֶּֽבֶשׂ יָֽיִן"}, {"kind": "text", "text": "זֹאת עֹלַת חֹֽדֶשׁ"}, {"kind": "text", "text": "בְּחָדְשׁוֹ"}, {"kind": "text", "text": "לְחָדְ֒שֵׁי הַשָּׁנָה:"}, {"kind": "text", "text": "וּשְׂ֒עִיר עִזִּים אֶחָד"}, {"kind": "text", "text": "לְחַטָּאת לַיהוֹה"}, {"kind": "text", "text": "עַל עֹלַת הַתָּמִיד יֵעָשֶׂה"}, {"kind": "text", "text": "וְנִסְכּוֹ:"}, {"kind": "text", "text": "<b>משנה א</b>"}, {"kind": "text", "text": "אֵיזֶהוּ מְקוֹמָן שֶׁל זְבָחִים"}, {"kind": "text", "text": "קָדְ֒שֵׁי קָדָשִׁים שְׁחִיטָתָן"}, {"kind": "text", "text": "בַּצָּפוֹן"}, {"kind": "text", "text": "פָּר וְשָׂעִיר שֶׁל יוֹם הַכִּפּוּרִים"}, {"kind": "text", "text": "שְׁחִיטָתָן בַּצָּפוֹן"}, {"kind": "text", "text": "וְקִבּוּל דָּמָן"}, {"kind": "text", "text": "בִּכְ֒לִי שָׁרֵת בַּצָּפוֹן"}, {"kind": "text", "text": "וְדָמָן טָעוּן הַזָּיָה"}, {"kind": "text", "text": "עַל בֵּין הַבַּדִּים"}, {"kind": "text", "text": "וְעַל הַפָּרֹֽכֶת"}, {"kind": "text", "text": "וְעַל מִזְבַּח הַזָּהָב"}, {"kind": "text", "text": "מַתָּנָה אַחַת מֵהֶן"}, {"kind": "text", "text": "מְעַכָּֽבֶת:"}, {"kind": "text", "text": "שְׁיָרֵי הַדָּם"}, {"kind": "text", "text": "הָיָה שׁוֹפֵךְ"}, {"kind": "text", "text": "עַל יְסוֹד מַעֲרָבִי"}, {"kind": "text", "text": "שֶׁל מִזְבֵּֽחַ הַחִיצוֹן"}, {"kind": "text", "text": "אִם לֹא נָתַן"}, {"kind": "text", "text": "לֹא עִכֵּב:"}, {"kind": "text", "text": "<b>משנה ב</b>"}, {"kind": "text", "text": "פָּרִים הַנִּשְׂרָפִים"}, {"kind": "text", "text": "וּשְׂ֒עִירִים הַנִּשְׂרָפִים"}, {"kind": "text", "text": "שְׁחִיטָתָן בַּצָּפוֹן"}, {"kind": "text", "text": "וְקִבּוּל דָּמָן"}, {"kind": "text", "text": "בִּכְ֒לִי שָׁרֵת בַּצָּפוֹן"}, {"kind": "text", "text": "וְדָמָן טָעוּן הַזָּיָה"}, {"kind": "text", "text": "עַל הַפָּרֹֽכֶת"}, {"kind": "text", "text": "וְעַל מִזְבַּח הַזָּהָב"}, {"kind": "text", "text": "מַתָּנָה אַחַת מֵהֶן"}, {"kind": "text", "text": "מְעַכָּֽבֶת:"}, {"kind": "text", "text": "שְׁיָרֵי הַדָּם"}, {"kind": "text", "text": "הָיָה שׁוֹפֵךְ"}, {"kind": "text", "text": "עַל יְסוֹד מַעֲרָבִי"}, {"kind": "text", "text": "שֶׁל מִזְבֵּֽחַ הַחִיצוֹן"}, {"kind": "text", "text": "אִם לֹא נָתַן"}, {"kind": "text", "text": "לֹא עִכֵּב"}, {"kind": "text", "text": "אֵֽלּוּ וָאֵֽלּוּ נִשְׂרָפִין"}, {"kind": "text", "text": "בְּבֵית הַדָּֽשֶׁן:"}, {"kind": "text", "text": "<b>משנה ג</b>"}, {"kind": "text", "text": "חַטֹּאת הַצִּבּוּר וְהַיָּחִיד"}, {"kind": "text", "text": "אֵֽלּוּ הֵן חַטֹּאת הַצִּבּוּר"}, {"kind": "text", "text": "שְׂעִירֵי רָאשֵׁי חֳדָשִׁים"}, {"kind": "text", "text": "וְשֶׁל מוֹעֲדוֹת"}, {"kind": "text", "text": "שְׁחִיטָתָן בַּצָּפוֹן"}, {"kind": "text", "text": "וְקִבּוּל דָּמָן"}, {"kind": "text", "text": "בִּכְ֒לִי שָׁרֵת בַּצָּפוֹן"}, {"kind": "text", "text": "וְדָמָן טָעוּן אַרְבַּע מַתָּנוֹת"}, {"kind": "text", "text": "עַל אַרְבַּע קְרָנוֹת,"}, {"kind": "text", "text": "כֵּיצַד"}, {"kind": "text", "text": "עָלָה"}, {"kind": "text", "text": "בַכֶּֽבֶשׁ"}, {"kind": "text", "text": "וּפָנָה לַסּוֹבֵב"}, {"kind": "text", "text": "וּבָא לוֹ לְקֶֽרֶן דְּרוֹמִית מִזְרָחִית,"}, {"kind": "text", "text": "מִזְרָחִית צְפוֹנִית,"}, {"kind": "text", "text": "צְפוֹנִית מַעֲרָבִית,"}, {"kind": "text", "text": "מַעֲרָבִית דְּרוֹמִית,"}, {"kind": "text", "text": "שְׁיָרֵי הַדָּם הָיָה שׁוֹפֵךְ"}, {"kind": "text", "text": "עַל יְסוֹד דְּרוֹמִי"}, {"kind": "text", "text": "וְנֶאֱכָלִין"}, {"kind": "text", "text": "לִפְ֒נִים מִן הַקְּ֒לָעִים"}, {"kind": "text", "text": "לְזִכְ֒רֵי כְהֻנָּה"}, {"kind": "text", "text": "בְּכָל מַאֲכָל"}, {"kind": "text", "text": "לְיוֹם וָלַֽיְלָה"}, {"kind": "text", "text": "עַד חֲצוֹת:"}, {"kind": "text", "text": "<b>משנה ד</b>"}, {"kind": "text", "text": "הָעוֹלָה"}, {"kind": "text", "text": "קֹֽדֶשׁ קָדָשִׁים"}, {"kind": "text", "text": "שְׁחִיטָתָהּ בַּצָּפוֹן"}, {"kind": "text", "text": "וְקִבּוּל דָּמָהּ בִּכְ֒לִי שָׁרֵת"}, {"kind": "text", "text": "בַּצָּפוֹן"}, {"kind": "text", "text": "וְדָמָהּ טָעוּן שְׁתֵּי מַתָּנוֹת"}, {"kind": "text", "text": "שֶׁהֵן אַרְבַּע"}, {"kind": "text", "text": "וּטְ֒עוּנָה הֶפְשֵׁט וְנִתּֽוּחַ"}, {"kind": "text", "text": "וְכָלִיל לָאִשִּׁים:"}, {"kind": "text", "text": "<b>משנה ה</b>"}, {"kind": "text", "text": "זִבְ֒חֵי שַׁלְ֒מֵי צִבּוּר"}, {"kind": "text", "text": "וַאֲשָׁמוֹת,"}, {"kind": "text", "text": "אֵֽלּוּ הֵן אֲשָׁמוֹת"}, {"kind": "text", "text": "אֲשַׁם גְּזֵלוֹת"}, {"kind": "text", "text": "אֲשַׁם"}, {"kind": "text", "text": "מְעִילוֹת"}, {"kind": "text", "text": "אֲשַׁם"}, {"kind": "text", "text": "שִׁפְחָה חֲרוּפָה"}, {"kind": "text", "text": "אֲשַׁם נָזִיר"}, {"kind": "text", "text": "אֲשַׁם מְצוֹרָע"}, {"kind": "text", "text": "אָשָׁם תָּלוּי,"}, {"kind": "text", "text": "שְׁחִיטָתָן בַּצָּפוֹן"}, {"kind": "text", "text": "וְקִבּוּל דָּמָן בִּכְ֒לִי שָׁרֵת"}, {"kind": "text", "text": "בַּצָּפוֹן,"}, {"kind": "text", "text": "וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת"}, {"kind": "text", "text": "שֶׁהֵן אַרְבַּע,"}, {"kind": "text", "text": "וְנֶאֱכָלִין"}, {"kind": "text", "text": "לִפְ֒נִים מִן הַקְּ֒לָעִים"}, {"kind": "text", "text": "לְזִכְ֒רֵי כְהֻנָּה"}, {"kind": "text", "text": "בְּכָל מַאֲכָל"}, {"kind": "text", "text": "לְיוֹם וָלַֽיְלָה"}, {"kind": "text", "text": "עַד חֲצוֹת:"}, {"kind": "text", "text": "<b>משנה ו</b>"}, {"kind": "text", "text": "הַתּוֹדָה"}, {"kind": "text", "text": "וְאֵיל נָזִיר"}, {"kind": "text", "text": "קָדָשִׁים קַלִּים"}, {"kind": "text", "text": "שְׁחִיטָתָן"}, {"kind": "text", "text": "בְּכָל־מָקוֹם בָּעֲזָרָה"}, {"kind": "text", "text": "וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת"}, {"kind": "text", "text": "שֶׁהֵן אַרְבַּע,"}, {"kind": "text", "text": "וְנֶאֱכָלִין בְּכָל־הָעִיר"}, {"kind": "text", "text": "לְכָל־אָדָם"}, {"kind": "text", "text": "בְּכָל־מַאֲכָל"}, {"kind": "text", "text": "לְיוֹם וָלַֽיְלָה"}, {"kind": "text", "text": "עַד־חֲצוֹת,"}, {"kind": "text", "text": "הַמּוּרָם מֵהֶם"}, {"kind": "text", "text": "כַּיּוֹצֵא בָהֶם"}, {"kind": "text", "text": "אֶלָּא שֶׁהַמּוּרָם נֶאֱכָל לַכֹּהֲנִים"}, {"kind": "text", "text": "לִנְ֒שֵׁיהֶם וְלִבְ֒נֵיהֶם וּלְ֒עַבְ֒דֵיהֶם:"}, {"kind": "text", "text": "<b>משנה ז</b>"}, {"kind": "text", "text": "שְׁלָמִים"}, {"kind": "text", "text": "קָדָשִׁים קַלִּים"}, {"kind": "text", "text": "שְׁחִיטָתָן"}, {"kind": "text", "text": "בְּכָל מָקוֹם בָּעֲזָרָה"}, {"kind": "text", "text": "וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת"}, {"kind": "text", "text": "שֶׁהֵן אַרְבַּע,"}, {"kind": "text", "text": "וְנֶאֱכָלִין בְּכָל הָעִיר"}, {"kind": "text", "text": "לְכָל אָדָם"}, {"kind": "text", "text": "בְּכָל מַאֲכָל"}, {"kind": "text", "text": "לִשְׁ֒נֵי יָמִים וְלַֽיְלָה אֶחָד:"}, {"kind": "text", "text": "הַמּוּרָם מֵהֶם"}, {"kind": "text", "text": "כַּיּוֹצֵא בָהֶם"}, {"kind": "text", "text": "אֶלָּא שֶׁהַמּוּרָם נֶאֱכָל לַכֹּהֲנִים"}, {"kind": "text", "text": "לִנְ֒שֵׁיהֶם וְלִבְ֒נֵיהֶם וּלְ֒עַבְ֒דֵיהֶם:"}, {"kind": "text", "text": "<b>משנה ח</b>"}, {"kind": "text", "text": "הַבְּ֒כוֹר וְהַמַּעֲשֵׂר"}, {"kind": "text", "text": "וְהַפֶּֽסַח"}, {"kind": "text", "text": "קָדָשִׁים קַלִּים"}, {"kind": "text", "text": "שְׁחִיטָתָן"}, {"kind": "text", "text": "בְּכָל מָקוֹם בָּעֲזָרָה"}, {"kind": "text", "text": "וְדָמָן טָעוּן מַתָּנָה אֶחָת"}, {"kind": "text", "text": "וּבִלְ֒בָד"}, {"kind": "text", "text": "שֶׁיִּתֵּן כְּנֶֽגֶד הַיְּ֒סוֹד,"}, {"kind": "text", "text": "שִׁנָּה בַאֲכִילָתָן"}, {"kind": "text", "text": "הַבְּ֒כוֹר נֶאֱכָל לַכֹּהֲנִים"}, {"kind": "text", "text": "וְהַמַּעֲשֵׂר לְכָל אָדָם,"}, {"kind": "text", "text": "וְנֶאֱכָלִין בְּכָל הָעִיר"}, {"kind": "text", "text": "בְּכָל מַאֲכָל"}, {"kind": "text", "text": "לִשְׁ֒נֵי יָמִים וְלַֽיְלָה אֶחָד:"}, {"kind": "text", "text": "הַפֶּֽסַח אֵינוֹ נֶאֱכָל אֶלָּא בַלַּֽיְלָה"}, {"kind": "text", "text": "וְאֵינוֹ נֶאֱכָל אֶלָּא עַד חֲצוֹת"}, {"kind": "text", "text": "וְאֵינוֹ נֶאֱכָל"}, {"kind": "text", "text": "אֶלָּא לִמְ֒נוּיָו"}, {"kind": "text", "text": "וְאֵינוֹ נֶאֱכָל אֶלָּא צָלִי:"}, {"kind": "text", "text": "רַבִּי יִשְׁמָעֵאל אוֹמֵר"}, {"kind": "text", "text": "בִּשְׁ֒לשׁ עֶשְׂרֵה מִדּוֹת"}, {"kind": "text", "text": "הַתּוֹרָה נִדְרֶֽשֶׁת בָּהֵן:"}, {"kind": "text", "text": "מִקַּל"}, {"kind": "text", "text": "וָחֹֽמֶר,"}, {"kind": "text", "text": "וּמִגְּ֒זֵרָה שָׁוָה,"}, {"kind": "text", "text": "מִבִּנְיַן אָב מִכָּתוּב אֶחָד,"}, {"kind": "text", "text": "וּמִבִּנְיַן אָב מִשְּׁ֒נֵי כְתוּבִים,"}, {"kind": "text", "text": "מִכְּ֒לָל וּפְ֒רָט,"}, {"kind": "text", "text": "וּמִפְּ֒רָט וּכְ֒לָל,"}, {"kind": "text", "text": "כְּלָל וּפְ֒רָט"}, {"kind": "text", "text": "וּכְ֒לָל"}, {"kind": "text", "text": "אִי אַתָּה דָן אֶלָּא כְּעֵין הַפְּ֒רָט,"}, {"kind": "text", "text": "מִכְּ֒לָל שֶׁהוּא צָרִיךְ"}, {"kind": "text", "text": "לִפְ֒רָט"}, {"kind": "text", "text": "וּמִפְּ֒רָט שֶׁהוּא צָרִיךְ לִכְ֒לָל,"}, {"kind": "text", "text": "כָּל דָּבָר שֶׁהָיָה בִּכְ֒לָל"}, {"kind": "text", "text": "וְיָצָא מִן הַכְּ֒לָל לְלַמֵּד"}, {"kind": "text", "text": "לֹא לְלַמֵּד עַל עַצְמוֹ יָצָא"}, {"kind": "text", "text": "אֶלָּא לְלַמֵּד"}, {"kind": "text", "text": "עַל הַכְּ֒לָל כֻּלּוֹ יָצָא,"}, {"kind": "text", "text": "כָּל דָּבָר שֶׁהָיָה בִּכְ֒לָל"}, {"kind": "text", "text": "וְיָצָא לִטְעֹן טֹֽעַן אֶחָד"}, {"kind": "text", "text": "שֶׁהוּא כְעִנְיָנוֹ"}, {"kind": "text", "text": "יָצָא לְהָקֵל"}, {"kind": "text", "text": "וְלֹא לְהַחֲמִיר,"}, {"kind": "text", "text": "כָּל דָּבָר שֶׁהָיָה בִּכְלָל"}, {"kind": "text", "text": "וְיָצָא לִטְעֹן טֹֽעַן אַחֵר"}, {"kind": "text", "text": "שֶׁלֹּא כְעִנְיָנוֹ"}, {"kind": "text", "text": "יָצָא לְהָקֵל"}, {"kind": "text", "text": "וּלְ֒הַחֲמִיר,"}, {"kind": "text", "text": "כָּל דָּבָר שֶׁהָיָה בִּכְ֒לָל"}, {"kind": "text", "text": "וְיָצָא לִדּוֹן בַּדָּבָר הֶחָדָשׁ"}, {"kind": "text", "text": "אִי אַתָּה יָכוֹל לְהַחֲזִירוֹ לִכְ֒לָלוֹ"}, {"kind": "text", "text": "עַד שֶׁיַּחֲזִירֶֽנּוּ הַכָּתוּב לִכְ֒לָלוֹ"}, {"kind": "text", "text": "בְּפֵרוּשׁ,"}, {"kind": "text", "text": "דָּבָר הַלָּמֵד מֵעִנְיָנוֹ"}, {"kind": "text", "text": "וְדָבָר הַלָּמֵד מִסּוֹפוֹ,"}, {"kind": "text", "text": "וְכֵן שְׁנֵי כְתוּבִים"}, {"kind": "text", "text": "הַמַּכְחִישִׁים זֶה אֶת זֶה"}, {"kind": "text", "text": "עַד שֶׁיָּבֹא הַכָּתוּב הַשְּׁ֒לִישִׁי"}, {"kind": "text", "text": "וְיַכְרִֽיעַ בֵּינֵיהֶם:"}, {"kind": "text", "text": "❖יְהִי רָצוֹן מִלְּ֒פָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ"}, {"kind": "text", "text": "בִּמְ֒הֵרָה בְיָמֵֽינוּ"}, {"kind": "text", "text": "וְתֵן חֶלְקֵֽנוּ בְּתוֹרָתֶֽךָ:"}, {"kind": "text", "text": "וְשָׁם נַעֲבָדְ֒ךָ בְּיִרְאָה"}, {"kind": "text", "text": "כִּימֵי עוֹלָם"}, {"kind": "text", "text": "וּכְ֒שָׁנִים קַדְמוֹנִיּוֹת:"}, {"kind": "header", "text": "קדיש דרבנן"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְ֒מָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְ֒עוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְ֒כוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְקָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ."}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְ֒יוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְ֒חַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל,"}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְ֒מַן קָרִיב"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְ֒עָלְ֒מֵי עָלְ֒מַיָּא"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקוּדְשָׁא, בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵֽלָּא (בעשי\"ת וּלְעֵֽלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְ֒כָתָא וְשִׁירָתָא,"}, {"kind": "text", "text": "תֻּשְׁבְּחָתָא וְנֶחֱמָתָא,"}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְ֒מָא, וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "עַל יִשְׂרָאֵל וְעַל רַבָּנָן"}, {"kind": "text", "text": "וְעַל תַּלְמִידֵיהוֹן"}, {"kind": "text", "text": "וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן,"}, {"kind": "text", "text": "וְעַל כָּל מָאן דְּעָסְ֒קִין בְּאוֹרַיְ֒תָא,"}, {"kind": "text", "text": "דִּי בְאַתְרָא הָדֵין"}, {"kind": "text", "text": "וְדִי בְכָל אֲתַר וַאֲתַר,"}, {"kind": "text", "text": "יְהֵא לְהוֹן וּלְ֒כוֹן"}, {"kind": "text", "text": "שְׁלָמָא רַבָּא חִנָּא וְחִסְדָּא"}, {"kind": "text", "text": "וְרַחֲמִין וְחַיִּין אֲרִיכִין"}, {"kind": "text", "text": "וּמְ֒זוֹנָא רְוִיחֵי וּפוּרְ֒קָנָא"}, {"kind": "text", "text": "מִן קֳדָם אֲבוּהוֹן"}, {"kind": "text", "text": "דְבִשְׁ֒מַיָּא וְאַרְעָא"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא"}, {"kind": "text", "text": "וְחַיִּים טוֹבִים"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "עוֹשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "(בעשי\"ת הַשָּׁלוֹם)"}, {"kind": "text", "text": "בִּמְ֒רוֹמָיו"}, {"kind": "text", "text": "הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן:"}, {"kind": "header", "text": "הודו"}, {"kind": "text", "text": "הוֹדוּ לַיהֹוָה קִרְ֒אוּ בִּשְׁ֒מוֹ"}, {"kind": "text", "text": "הוֹדִֽיעוּ בָעַמִּים עֲלִילֹתָיו:"}, {"kind": "text", "text": "שִֽׁירוּ לוֹ זַמְּ֒רוּ־לוֹ"}, {"kind": "text", "text": "שִֽׂיחוּ בְּכָל־נִפְלְאוֹתָיו:"}, {"kind": "text", "text": "הִתְהַלְּ֒לוּ בְּשֵׁם קָדְשׁוֹ"}, {"kind": "text", "text": "יִשְׂמַח לֵב"}, {"kind": "text", "text": "מְבַקְ֒שֵׁי יְהֹוָה:"}, {"kind": "text", "text": "דִּרְ֒שׁוּ יְהֹוָה וְעֻזּוֹ"}, {"kind": "text", "text": "בַּקְּ֒שׁוּ פָנָיו תָּמִיד:"}, {"kind": "text", "text": "זִכְ֒רוּ נִפְלְ֒אֹתָיו אֲשֶׁר עָשָׂה"}, {"kind": "text", "text": "מֹפְ֒תָיו וּמִשְׁפְּ֒טֵי־פִֽיהוּ:"}, {"kind": "text", "text": "זֶֽרַע יִשְׂרָאֵל עַבְדּוֹ"}, {"kind": "text", "text": "בְּנֵי יַעֲקֹב בְּחִירָיו:"}, {"kind": "text", "text": "הוּא יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בְּכָל־הָאָֽרֶץ מִשְׁפָּטָיו:"}, {"kind": "text", "text": "זִכְ֒רוּ לְעוֹלָם בְּרִיתוֹ"}, {"kind": "text", "text": "דָּבָר צִוָּה"}, {"kind": "text", "text": "לְאֶֽלֶף דּוֹר:"}, {"kind": "text", "text": "אֲשֶׁר כָּרַת אֶת־אַבְרָהָם"}, {"kind": "text", "text": "וּשְׁ֒בוּעָתוֹ לְיִצְחָק:"}, {"kind": "text", "text": "וַיַּעֲמִידֶֽהָ לְיַעֲקֹב לְחֹק"}, {"kind": "text", "text": "לְיִשְׂרָאֵל בְּרִית עוֹלָם:"}, {"kind": "text", "text": "לֵאמֹר"}, {"kind": "text", "text": "לְךָ אֶתֵּן אֶֽרֶץ־כְּנָעַן"}, {"kind": "text", "text": "חֶֽבֶל נַחֲלַתְ֒כֶם:"}, {"kind": "text", "text": "בִּהְ֒יוֹתְ֒כֶם מְתֵי מִסְפָּר"}, {"kind": "text", "text": "כִּמְ֒עַט וְגָרִים בָּהּ:"}, {"kind": "text", "text": "וַיִּתְהַלְּ֒כוּ מִגּוֹי אֶל־גּוֹי"}, {"kind": "text", "text": "וּמִמַּמְלָכָה אֶל־עַם אַחֵר:"}, {"kind": "text", "text": "לֹא־הִנִּֽיחַ לְאִישׁ לְעָשְׁ֒קָם"}, {"kind": "text", "text": "וַיּֽוֹכַח עֲלֵיהֶם מְלָכִים:"}, {"kind": "text", "text": "אַל־תִּגְּ֒עוּ בִּמְ֒שִׁיחָי"}, {"kind": "text", "text": "וּבִנְ֒בִיאַי אַל־תָּרֵֽעוּ:"}, {"kind": "text", "text": "שִֽׁירוּ לַיהֹוָה כָּל־הָאָֽרֶץ"}, {"kind": "text", "text": "בַּשְּׂ֒רוּ מִיּוֹם־אֶל־יוֹם יְשׁוּעָתוֹ:"}, {"kind": "text", "text": "סַפְּ֒רוּ בַגּוֹיִם אֶת־כְּבוֹדוֹ"}, {"kind": "text", "text": "בְּכָל־הָעַמִּים נִפְלְאֹתָיו:"}, {"kind": "text", "text": "❖כִּי גָדוֹל יְהֹוָה וּמְ֒הֻלָּל מְאֹד"}, {"kind": "text", "text": "וְנוֹרָא הוּא עַל־כָּל־אֱלֹהִים:"}, {"kind": "text", "text": "כִּי כָּל־אֱלֹהֵי הָעַמִּים אֱלִילִים"}, {"kind": "text", "text": "וַיהֹוָה שָׁמַֽיִם עָשָׂה:"}, {"kind": "text", "text": "הוֹד וְהָדָר לְפָנָיו"}, {"kind": "text", "text": "עֹז וְחֶדְוָה בִּמְ֒קֹמוֹ:"}, {"kind": "text", "text": "הָבוּ לַיהֹוָה מִשְׁפְּ֒חוֹת עַמִּים"}, {"kind": "text", "text": "הָבוּ לַיהֹוָה כָּבוֹד וָעֹז:"}, {"kind": "text", "text": "הָבוּ לַיהֹוָה כְּבוֹד שְׁמוֹ"}, {"kind": "text", "text": "שְׂאוּ מִנְחָה וּבֹֽאוּ לְפָנָיו"}, {"kind": "text", "text": "הִשְׁתַּחֲווּ לַיהֹוָה"}, {"kind": "text", "text": "בְּהַדְרַת־קֹֽדֶשׁ:"}, {"kind": "text", "text": "חִֽילוּ מִלְּ֒פָנָיו כָּל־הָאָֽרֶץ"}, {"kind": "text", "text": "אַף־תִּכּוֹן תֵּבֵל"}, {"kind": "text", "text": "בַּל־תִּמּוֹט:"}, {"kind": "text", "text": "יִשְׂמְחוּ הַשָּׁמַֽיִם"}, {"kind": "text", "text": "וְתָגֵל הָאָֽרֶץ"}, {"kind": "text", "text": "וְיֹאמְ֒רוּ בַגּוֹיִם"}, {"kind": "text", "text": "יְהֹוָה מָלָךְ:"}, {"kind": "text", "text": "יִרְעַם הַיָּם וּמְ֒לוֹאוֹ"}, {"kind": "text", "text": "יַעֲלֹץ הַשָּׂדֶה וְכָל־אֲשֶׁר־בּוֹ:"}, {"kind": "text", "text": "אָז יְרַנְּ֒נוּ עֲצֵי הַיָּעַר"}, {"kind": "text", "text": "מִלִּפְ֒נֵי יְהֹוָה"}, {"kind": "text", "text": "כִּי־בָא לִשְׁפּוֹט אֶת־הָאָֽרֶץ:"}, {"kind": "text", "text": "הוֹדוּ לַיהֹוָה כִּי טוֹב"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "וְאִמְ֒רוּ הוֹשִׁיעֵֽנוּ אֱלֹהֵי יִשְׁעֵֽנוּ"}, {"kind": "text", "text": "וְקַבְּ֒צֵֽנוּ וְהַצִּילֵֽנוּ מִן־הַגּוֹיִם"}, {"kind": "text", "text": "לְהוֹדוֹת לְשֵׁם קָדְשֶֽׁךָ"}, {"kind": "text", "text": "לְהִשְׁתַּבֵּֽחַ בִּתְ֒הִלָּתֶֽךָ:"}, {"kind": "text", "text": "בָּרוּךְ יְהֹוָה אֱלֹהֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "מִן־הָעוֹלָם וְעַד הָעֹלָם"}, {"kind": "text", "text": "וַיֹּאמְ֒רוּ כָל־הָעָם אָמֵן"}, {"kind": "text", "text": "וְהַלֵּל לַיהֹוָה:"}, {"kind": "text", "text": "רוֹמְ֒מוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וְהִשְׁתַּחֲווּ"}, {"kind": "text", "text": "לַהֲדֹם רַגְלָיו"}, {"kind": "text", "text": "קָדוֹשׁ הוּא:"}, {"kind": "text", "text": "❖רוֹמְ֒מוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וְהִשְׁתַּחֲווּ"}, {"kind": "text", "text": "לְהַר קָדְשׁוֹ"}, {"kind": "text", "text": "כִּי קָדוֹשׁ יְהֹוָה אֱלֹהֵֽינוּ:"}, {"kind": "text", "text": "וְהוּא רַחוּם"}, {"kind": "text", "text": "יְכַפֵּר עָוֹן וְלֹא־יַשְׁחִית"}, {"kind": "text", "text": "וְהִרְבָּה לְהָשִׁיב אַפּוֹ"}, {"kind": "text", "text": "וְלֹא־יָעִיר כָּל־חֲמָתוֹ:"}, {"kind": "text", "text": "אַתָּה יְהֹוָה"}, {"kind": "text", "text": "לֹא־תִכְלָא רַחֲמֶֽיךָ מִמֶּֽנִּי"}, {"kind": "text", "text": "חַסְדְּ֒ךָ וַאֲמִתְּ֒ךָ"}, {"kind": "text", "text": "תָּמִיד יִצְּ֒רֽוּנִי:"}, {"kind": "text", "text": "זְכֹר רַחֲמֶֽיךָ יְהֹוָה"}, {"kind": "text", "text": "וַחֲסָדֶֽיךָ"}, {"kind": "text", "text": "כִּי"}, {"kind": "text", "text": "מֵעוֹלָם הֵֽמָּה:"}, {"kind": "text", "text": "תְּנוּ עֹז לֵאלֹהִים"}, {"kind": "text", "text": "עַל־יִשְׂרָאֵל גַּאֲוָתוֹ"}, {"kind": "text", "text": "וְעֻזּוֹ בַּשְּׁ֒חָקִים:"}, {"kind": "text", "text": "נוֹרָא אֱלֹהִים"}, {"kind": "text", "text": "מִמִּקְדָּשֶֽׁיךָ"}, {"kind": "text", "text": "אֵל יִשְׂרָאֵל"}, {"kind": "text", "text": "הוּא נֹתֵן עֹז וְתַעֲצֻמוֹת לָעָם"}, {"kind": "text", "text": "בָּרוּךְ אֱלֹהִים:"}, {"kind": "text", "text": "אֵל־נְקָמוֹת יְהֹוָה"}, {"kind": "text", "text": "אֵל נְקָמוֹת הוֹפִֽיעַ:"}, {"kind": "text", "text": "הִנָּשֵׂא שֹׁפֵט הָאָֽרֶץ"}, {"kind": "text", "text": "הָשֵׁב גְּמוּל עַל־גֵּאִים:"}, {"kind": "text", "text": "לַיהֹוָה הַיְ֒שׁוּעָה"}, {"kind": "text", "text": "עַל־עַמְּ֒ךָ בִרְ֒כָתֶֽךָ סֶּֽלָה:"}, {"kind": "text", "text": "יְהֹוָה צְבָאוֹת עִמָּנוּ"}, {"kind": "text", "text": "מִשְׂגָּב לָֽנוּ אֱלֹהֵי יַעֲקֹב סֶֽלָה:"}, {"kind": "text", "text": "❖יְהֹוָה צְבָאוֹת"}, {"kind": "text", "text": "אַשְׁרֵי אָדָם בֹּטֵֽחַ בָּךְ:"}, {"kind": "text", "text": "יְהֹוָה הוֹשִֽׁיעָה"}, {"kind": "text", "text": "הַמֶּֽלֶךְ יַעֲנֵֽנוּ בְיוֹם־קָרְ֒אֵֽנוּ:"}, {"kind": "text", "text": "הוֹשִֽׁיעָה אֶת־עַמֶּֽךָ"}, {"kind": "text", "text": "וּבָרֵךְ אֶת־נַחֲלָתֶֽךָ"}, {"kind": "text", "text": "וּרְ֒עֵם וְנַשְּׂ֒אֵם עַד־הָעוֹלָם:"}, {"kind": "text", "text": "נַפְשֵֽׁנוּ חִכְּ֒תָה לַיהֹוָה"}, {"kind": "text", "text": "עֶזְרֵֽנוּ וּמָגִנֵּֽנוּ הוּא:"}, {"kind": "text", "text": "כִּי־בוֹ יִשְׂמַח לִבֵּֽנוּ"}, {"kind": "text", "text": "כִּי בְשֵׁם קָדְשׁוֹ בָטָֽחְנוּ:"}, {"kind": "text", "text": "יְהִי־חַסְדְּךָ יְהֹוָה עָלֵֽינוּ"}, {"kind": "text", "text": "כַּאֲשֶׁר יִחַֽלְנוּ לָךְ:"}, {"kind": "text", "text": "הַרְאֵֽנוּ יְהֹוָה חַסְדֶּֽךָ"}, {"kind": "text", "text": "וְיֶשְׁעֲךָ תִּֽתֶּן־לָֽנוּ:"}, {"kind": "text", "text": "קֽוּמָה עֶזְרָֽתָה לָּנוּ"}, {"kind": "text", "text": "וּפְ֒דֵֽנוּ לְמַֽעַן חַסְדֶּֽךָ:"}, {"kind": "text", "text": "אָנֹכִי יְהֹוָה אֱלֹהֶֽיךָ"}, {"kind": "text", "text": "הַמַּעַלְ֒ךָ מֵאֶֽרֶץ מִצְרָֽיִם"}, {"kind": "text", "text": "הַרְחֶב־פִּֽיךָ וַאֲמַלְ֒אֵֽהוּ:"}, {"kind": "text", "text": "❖אַשְׁרֵי הָעָם שֶׁכָּֽכָה לּוֹ"}, {"kind": "text", "text": "אַשְׁרֵי הָעָם"}, {"kind": "text", "text": "שֶׁיְהֹוָה אֱלֹהָיו:"}, {"kind": "text", "text": "וַאֲנִי בְּחַסְדְּ֒ךָ בָטַֽחְתִּי"}, {"kind": "text", "text": "יָגֵל לִבִּי בִּישׁוּעָתֶֽךָ"}, {"kind": "text", "text": "אָשִֽׁירָה לַיהֹוָה"}, {"kind": "text", "text": "כִּי גָמַל עָלָי:"}, {"kind": "header", "text": "מזמור שיר"}, {"kind": "text", "text": "מִזְמוֹר"}, {"kind": "text", "text": "שִׁיר־חֲנֻכַּת הַבַּֽיִת"}, {"kind": "text", "text": "לְדָוִד:"}, {"kind": "text", "text": "אֲרוֹמִמְ֒ךָ יְהֹוָה"}, {"kind": "text", "text": "כִּי דִלִּיתָֽנִי"}, {"kind": "text", "text": "וְלֹא־שִׂמַּֽחְתָּ אֹיְ֒בַי לִי:"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהָי"}, {"kind": "text", "text": "שִׁוַּֽעְתִּי אֵלֶֽיךָ וַתִּרְפָּאֵֽנִי:"}, {"kind": "text", "text": "יְהֹוָה הֶעֱלִֽיתָ"}, {"kind": "text", "text": "מִן־שְׁאוֹל נַפְשִׁי"}, {"kind": "text", "text": "חִיִּיתַֽנִי"}, {"kind": "text", "text": "מִיָּרְ֒דִי־בוֹר:"}, {"kind": "text", "text": "זַמְּ֒רוּ לַיהֹוָה חֲסִידָיו"}, {"kind": "text", "text": "וְהוֹדוּ לְזֵֽכֶר קָדְשׁוֹ:"}, {"kind": "text", "text": "כִּי רֶֽגַע בְּאַפּוֹ"}, {"kind": "text", "text": "חַיִּים בִּרְצוֹנוֹ"}, {"kind": "text", "text": "בָּעֶֽרֶב יָלִין בֶּֽכִי"}, {"kind": "text", "text": "וְלַבֹּֽקֶר רִנָּה:"}, {"kind": "text", "text": "וַאֲנִי אָמַֽרְתִּי בְשַׁלְוִי"}, {"kind": "text", "text": "בַּל־אֶמּוֹט לְעוֹלָם:"}, {"kind": "text", "text": "יְהֹוָה בִּרְ֒צוֹנְ֒ךָ"}, {"kind": "text", "text": "הֶעֱמַֽדְתָּה לְהַרְרִי"}, {"kind": "text", "text": "עֹז"}, {"kind": "text", "text": "הִסְתַּֽרְתָּ פָנֶֽיךָ"}, {"kind": "text", "text": "הָיִֽיתִי נִבְהָל:"}, {"kind": "text", "text": "אֵלֶֽיךָ יְהֹוָה אֶקְרָא"}, {"kind": "text", "text": "וְאֶל־אֲדֹנָי אֶתְחַנָּן:"}, {"kind": "text", "text": "מַה־בֶּֽצַע"}, {"kind": "text", "text": "בְּדָמִי"}, {"kind": "text", "text": "בְּרִדְתִּי אֶל שָֽׁחַת"}, {"kind": "text", "text": "הֲיוֹדְ֒ךָ עָפָר"}, {"kind": "text", "text": "הֲיַגִּיד אֲמִתֶּֽךָ:"}, {"kind": "text", "text": "שְׁמַע יְהֹוָה וְחָנֵּֽנִי"}, {"kind": "text", "text": "יְהֹוָה הֱיֵה־עֹזֵר לִי:"}, {"kind": "text", "text": "❖הָפַֽכְתָּ מִסְפְּדִי לְמָחוֹל לִי"}, {"kind": "text", "text": "פִּתַּחְתָּ שַׂקִּי"}, {"kind": "text", "text": "וַתְּ֒אַזְּ֒רֵֽנִי שִׂמְחָה:"}, {"kind": "text", "text": "לְמַֽעַן יְזַמֶּרְ֒ךָ כָבוֹד"}, {"kind": "text", "text": "וְלֹא יִדֹּם"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהַי לְעוֹלָם אוֹדֶֽךָ:"}, {"kind": "text", "text": "יְהֹוָה מֶֽלֶךְ, יְהֹוָה מָלָֽךְ,"}, {"kind": "text", "text": "יְהֹוָה יִמְלֹךְ, לְעֹלָם וָעֶד:"}, {"kind": "text", "text": "יְהֹוָה מֶֽלֶךְ, יְהֹוָה מָלָֽךְ,"}, {"kind": "text", "text": "יְהֹוָה יִמְלֹךְ, לְעֹלָם וָעֶד:"}, {"kind": "text", "text": "וְהָיָה יְהֹוָה לְמֶֽלֶךְ"}, {"kind": "text", "text": "עַל־כָּל־הָאָֽרֶץ,"}, {"kind": "text", "text": "בַּיּוֹם הַהוּא יִהְיֶה יְהֹוָה אֶחָד,"}, {"kind": "text", "text": "וּשְׁ֒מוֹ אֶחָד:"}, {"kind": "text", "text": "הֽוֹשִׁיעֵֽנוּ יְהֹוָה אֱלֹהֵֽינוּ,"}, {"kind": "text", "text": "וְקַבְּ֒צֵֽנוּ מִן־הַגּוֹיִם"}, {"kind": "text", "text": "לְהוֹדוֹת לְשֵׁם קָדְשֶֽׁךָ,"}, {"kind": "text", "text": "לְהִשְׁתַּבֵּֽחַ בִּתְ֒הִלָּתֶֽךָ:"}, {"kind": "text", "text": "בָּרוּךְ יְהֹוָה אֱלֹהֵי יִשְׂרָאֵל,"}, {"kind": "text", "text": "מִן־הָֽעוֹלָם וְעַד הָֽעוֹלָם,"}, {"kind": "text", "text": "וְאָמַר כָּל־הָעָם אָמֵן, הַֽלְ֒לוּיָהּ:"}, {"kind": "text", "text": "כֹּל הַנְּ֒שָׁמָה תְּהַלֵּל יָהּ,"}, {"kind": "text", "text": "הַֽלְ֒לוּיָהּ:"}, {"kind": "text", "text": "<b>תהלים יט</b>"}, {"kind": "text", "text": "לַמְנַצֵּֽחַ"}, {"kind": "text", "text": "מִזְמוֹר לְדָוִד:"}, {"kind": "text", "text": "הַשָּׁמַֽיִם מְסַפְּרִים כְּבוֹד־אֵל"}, {"kind": "text", "text": "וּמַעֲשֵׂה יָדָיו"}, {"kind": "text", "text": "מַגִּיד הָרָקִֽיעַ:"}, {"kind": "text", "text": "יוֹם לְיוֹם יַבִּֽיעַ אֹֽמֶר"}, {"kind": "text", "text": "וְלַֽיְלָה לְלַֽיְלָה יְחַוֶּה־דָּֽעַת:"}, {"kind": "text", "text": "אֵין־אֹֽמֶר וְאֵין דְּבָרִים"}, {"kind": "text", "text": "בְּלִי נִשְׁמָע קוֹלָם:"}, {"kind": "text", "text": "בְּכָל־הָאָֽרֶץ יָצָא קַוָּם"}, {"kind": "text", "text": "וּבִקְצֵה תֵבֵל"}, {"kind": "text", "text": "מִלֵּיהֶם"}, {"kind": "text", "text": "לַשֶּֽׁמֶשׁ"}, {"kind": "text", "text": "שָׂם־אֹֽהֶל בָּהֶם:"}, {"kind": "text", "text": "וְהוּא כְּחָתָן"}, {"kind": "text", "text": "יֹצֵא מֵחֻפָּתוֹ"}, {"kind": "text", "text": "יָשִׂישׂ כְּגִבּוֹר לָרוּץ אֹֽרַח:"}, {"kind": "text", "text": "מִקְצֵה הַשָּׁמַֽיִם מוֹצָאוֹ"}, {"kind": "text", "text": "וּתְקוּפָתוֹ עַל־קְצוֹתָם"}, {"kind": "text", "text": "וְאֵין נִסְתָּר מֵחַמָּֽתוֹ:"}, {"kind": "text", "text": "תּוֹרַת יְהֹוָה תְּמִימָה"}, {"kind": "text", "text": "מְשִֽׁיבַת נָֽפֶשׁ"}, {"kind": "text", "text": "עֵדוּת יְהֹוָה נֶאֱמָנָה"}, {"kind": "text", "text": "מַחְכִּֽימַת פֶּֽתִי:"}, {"kind": "text", "text": "פִּקּוּדֵי יְהֹוָה יְשָׁרִים"}, {"kind": "text", "text": "מְשַׂמְּחֵי־לֵב"}, {"kind": "text", "text": "מִצְוַת יְהֹוָה בָּרָה"}, {"kind": "text", "text": "מְאִירַת עֵינָֽיִם:"}, {"kind": "text", "text": "יִרְאַת יְהֹוָה טְהוֹרָה"}, {"kind": "text", "text": "עוֹמֶֽדֶת לָעַד"}, {"kind": "text", "text": "מִשְׁפְּטֵי־יְהֹוָה אֱמֶת"}, {"kind": "text", "text": "צָדְקוּ יַחְדָּו:"}, {"kind": "text", "text": "הַנֶּחֱמָדִים מִזָּהָב"}, {"kind": "text", "text": "וּמִפָּז רָב"}, {"kind": "text", "text": "וּמְתוּקִים מִדְּבַשׁ"}, {"kind": "text", "text": "וְנֹֽפֶת צוּפִים:"}, {"kind": "text", "text": "גַּם־עַבְדְּךָ נִזְהָר בָּהֶם"}, {"kind": "text", "text": "בְּשָׁמְרָם עֵֽקֶב רָב:"}, {"kind": "text", "text": "שְׁגִיאוֹת מִי־יָבִין"}, {"kind": "text", "text": "מִנִּסְתָּרוֹת נַקֵּֽנִי:"}, {"kind": "text", "text": "גַּם מִזֵּדִים"}, {"kind": "text", "text": "חֲשׂךְ עַבְדֶּֽךָ"}, {"kind": "text", "text": "אַל־יִמְשְׁלוּ־בִי"}, {"kind": "text", "text": "אָז אֵיתָם"}, {"kind": "text", "text": "וְנִקֵּֽיתִי מִפֶּֽשַׁע רָב:"}, {"kind": "text", "text": "❖יִהְיוּ לְרָצוֹן"}, {"kind": "text", "text": "אִמְרֵי־פִי"}, {"kind": "text", "text": "וְהֶגְיוֹן לִבִּי לְפָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה צוּרִי וְגֹאֲלִי:"}, {"kind": "text", "text": "<b>תהלים לג</b>"}, {"kind": "text", "text": "רַנְּנוּ צַדִּיקִים בַּיהֹוָה"}, {"kind": "text", "text": "לַיְשָׁרִים נָאוָה תְהִלָּה:"}, {"kind": "text", "text": "הוֹדוּ לַיהֹוָה בְּכִנּוֹר"}, {"kind": "text", "text": "בְּנֵֽבֶל עָשׂוֹר זַמְּרוּ־לוֹ:"}, {"kind": "text", "text": "שִֽׁירוּ־לוֹ שִׁיר חָדָשׁ"}, {"kind": "text", "text": "הֵיטִֽיבוּ נַגֵּן בִּתְרוּעָה:"}, {"kind": "text", "text": "כִּי־יָשָׁר דְּבַר־יְהֹוָה"}, {"kind": "text", "text": "וְכָל־מַעֲשֵֽׂהוּ בֶּאֱמוּנָה:"}, {"kind": "text", "text": "אֹהֵב צְדָקָה וּמִשְׁפָּט"}, {"kind": "text", "text": "חֶֽסֶד יְהֹוָה מָלְאָה הָאָֽרֶץ:"}, {"kind": "text", "text": "בִּדְבַר יְהֹוָה שָׁמַֽיִם נַעֲשׂוּ"}, {"kind": "text", "text": "וּבְרֽוּחַ פִּיו"}, {"kind": "text", "text": "כָּל־צְבָאָם:"}, {"kind": "text", "text": "כֹּנֵס כַּנֵּד"}, {"kind": "text", "text": "מֵי הַיָּם"}, {"kind": "text", "text": "נֹתֵן בְּאוֹצָרוֹת תְּהוֹמוֹת:"}, {"kind": "text", "text": "יִירְאוּ מֵיְהֹוָה כָּל־הָאָֽרֶץ"}, {"kind": "text", "text": "מִמֶּֽנּוּ יָגֽוּרוּ"}, {"kind": "text", "text": "כָּל־ישְׁבֵי תֵבֵל:"}, {"kind": "text", "text": "כִּי הוּא אָמַר וַיֶּֽהִי"}, {"kind": "text", "text": "הוּא־צִוָּה וַיַּעֲמֹד:"}, {"kind": "text", "text": "יְהֹוָה הֵפִיר עֲצַת־גּוֹיִם"}, {"kind": "text", "text": "הֵנִיא מַחְשְׁבוֹת עַמִּים:"}, {"kind": "text", "text": "עֲצַת יְהֹוָה לְעוֹלָם תַּעֲמֹד"}, {"kind": "text", "text": "מַחְשְׁבוֹת לִבּוֹ"}, {"kind": "text", "text": "לְדֹר וָדֹר:"}, {"kind": "text", "text": "אַשְׁרֵי הַגּוֹי"}, {"kind": "text", "text": "אֲשֶׁר־יְהֹוָה אֱלֹהָיו"}, {"kind": "text", "text": "הָעָם בָּחַר לְנַֽחֲלָה לוֹ:"}, {"kind": "text", "text": "מִשָּׁמַֽיִם הִבִּיט יְהֹוָה"}, {"kind": "text", "text": "רָאָה אֶת־כָּל־בְּנֵי הָאָדָם:"}, {"kind": "text", "text": "מִמְּכוֹן־שִׁבְתּוֹ"}, {"kind": "text", "text": "הִשְׁגִּֽיחַ"}, {"kind": "text", "text": "אֶל כָּל־ישְׁבֵי הָאָֽרֶץ:"}, {"kind": "text", "text": "הַיֹּצֵר יַֽחַד לִבָּם"}, {"kind": "text", "text": "הַמֵּבִין אֶל־כָּל־מַעֲשֵׂיהֶם:"}, {"kind": "text", "text": "אֵין הַמֶּֽלֶךְ נוֹשָׁע בְּרָב־חָֽיִל"}, {"kind": "text", "text": "גִּבּוֹר לֹא־יִנָּצֵל"}, {"kind": "text", "text": "בְּרָב־כֹּֽחַ:"}, {"kind": "text", "text": "שֶֽׁקֶר הַסּוּס"}, {"kind": "text", "text": "לִתְשׁוּעָה"}, {"kind": "text", "text": "וּבְרֹב חֵילוֹ"}, {"kind": "text", "text": "לֹא יְמַלֵּט:"}, {"kind": "text", "text": "הִנֵּה עֵין יְהֹוָה"}, {"kind": "text", "text": "אֶל־יְרֵאָיו"}, {"kind": "text", "text": "לַמְיַחֲלִים לְחַסְדּוֹ:"}, {"kind": "text", "text": "לְהַצִּיל מִמָּֽוֶת נַפְשָׁם"}, {"kind": "text", "text": "וּלְחַיּוֹתָם בָּרָעָב:"}, {"kind": "text", "text": "נַפְשֵֽׁנוּ חִכְּתָה לַיהֹוָה"}, {"kind": "text", "text": "עֶזְרֵֽנוּ וּמָגִנֵּֽנוּ הוּא:"}, {"kind": "text", "text": "❖כִּי־בוֹ יִשְׂמַח לִבֵּֽנוּ"}, {"kind": "text", "text": "כִּי בְשֵׁם קָדְשׁוֹ בָטָֽחְנוּ:"}, {"kind": "text", "text": "יְהִי־חַסְדְּךָ יְהֹוָה עָלֵֽינוּ"}, {"kind": "text", "text": "כַּאֲשֶׁר יִחַֽלְנוּ לָךְ:"}, {"kind": "text", "text": "<b>תהלים לד</b>"}, {"kind": "text", "text": "לְדָוִד"}, {"kind": "text", "text": "בְּשַׁנּוֹתוֹ אֶת־טַעְמוֹ"}, {"kind": "text", "text": "לִפְנֵי אֲבִימֶֽלֶךְ"}, {"kind": "text", "text": "וַיְגָרְשֵֽׁהוּ"}, {"kind": "text", "text": "וַיֵּלַךְ:"}, {"kind": "text", "text": "אֲבָרְכָה אֶת־יְהֹוָה בְּכָל־עֵת"}, {"kind": "text", "text": "תָּמִיד תְּהִלָּתוֹ בְּפִי:"}, {"kind": "text", "text": "בַּיהֹוָה תִּתְהַלֵּל נַפְשִׁי"}, {"kind": "text", "text": "יִשְׁמְעוּ עֲנָוִים וְיִשְׂמָֽחוּ:"}, {"kind": "text", "text": "גַּדְּלוּ לַיהֹוָה אִתִּי"}, {"kind": "text", "text": "וּנְרוֹמְמָה שְׁמוֹ יַחְדָּו:"}, {"kind": "text", "text": "דָּרַֽשְׁתִּי אֶת־יְהֹוָה וְעָנָֽנִי"}, {"kind": "text", "text": "וּמִכָּל־מְגוּרוֹתַי הִצִּילָֽנִי:"}, {"kind": "text", "text": "הִבִּֽיטוּ אֵלָיו וְנָהָֽרוּ"}, {"kind": "text", "text": "וּפְנֵיהֶם"}, {"kind": "text", "text": "אַל־יֶחְפָּֽרוּ:"}, {"kind": "text", "text": "זֶה עָנִי קָרָא וַיהֹוָה שָׁמֵֽעַ"}, {"kind": "text", "text": "וּמִכָּל־צָרוֹתָיו הוֹשִׁיעוֹ:"}, {"kind": "text", "text": "חֹנֶה מַלְאַךְ־יְהֹוָה"}, {"kind": "text", "text": "סָבִיב לִירֵאָיו"}, {"kind": "text", "text": "וַיְחַלְּצֵם:"}, {"kind": "text", "text": "טַעֲמוּ וּרְאוּ כִּי־טוֹב יְהֹוָה"}, {"kind": "text", "text": "אַשְׁרֵי הַגֶּֽבֶר"}, {"kind": "text", "text": "יֶֽחֱסֶה־בּוֹ:"}, {"kind": "text", "text": "יְראוּ אֶת־יְהֹוָה קְדֹשָׁיו"}, {"kind": "text", "text": "כִּי־אֵין מַחְסוֹר"}, {"kind": "text", "text": "לִירֵאָיו:"}, {"kind": "text", "text": "כְּפִירִים רָשׁוּ וְרָעֵֽבוּ"}, {"kind": "text", "text": "וְדֹרְשֵׁי יְהֹוָה"}, {"kind": "text", "text": "לֹא־יַחְסְרוּ כָל־טוֹב:"}, {"kind": "text", "text": "לְכוּ־בָנִים שִׁמְעוּ־לִי"}, {"kind": "text", "text": "יִרְאַת יְהֹוָה אֲלַמֶּדְכֶם:"}, {"kind": "text", "text": "מִי־הָאִישׁ הֶחָפֵץ חַיִּים"}, {"kind": "text", "text": "אֹהֵב יָמִים לִרְאוֹת טוֹב:"}, {"kind": "text", "text": "נְצֹר לְשׁוֹנְךָ מֵרָע"}, {"kind": "text", "text": "וּשְׂפָתֶֽיךָ מִדַּבֵּר מִרְמָה:"}, {"kind": "text", "text": "סוּר מֵרָע וַעֲשֵׂה־טוֹב"}, {"kind": "text", "text": "בַּקֵּשׁ שָׁלוֹם וְרָדְפֵֽהוּ:"}, {"kind": "text", "text": "עֵינֵי יְהֹוָה אֶל־צַדִּיקִים"}, {"kind": "text", "text": "וְאָזְנָיו אֶל־שַׁוְעָתָם:"}, {"kind": "text", "text": "פְּנֵי יְהֹוָה בְּעֹֽשֵׂי רָע"}, {"kind": "text", "text": "לְהַכְרִית מֵאֶֽרֶץ זִכְרָם:"}, {"kind": "text", "text": "צָעֲקוּ וַיהֹוָה שָׁמֵֽעַ"}, {"kind": "text", "text": "וּמִכָּל־צָרוֹתָם הִצִּילָם:"}, {"kind": "text", "text": "קָרוֹב יְהֹוָה לְנִשְׁבְּרֵי־לֵב"}, {"kind": "text", "text": "וְאֶת־דַכְּאֵי־רֽוּחַ יוֹשִֽׁיעַ:"}, {"kind": "text", "text": "רַבּוֹת רָעוֹת צַדִּיק"}, {"kind": "text", "text": "וּמִכֻּלָּם יַצִּילֶֽנּוּ יְהֹוָה:"}, {"kind": "text", "text": "שֹׁמֵר כָּל־עַצְמֹתָיו"}, {"kind": "text", "text": "אַחַת מֵהֵֽנָּה לֹא נִשְׁבָּֽרָה:"}, {"kind": "text", "text": "תְּמוֹתֵת רָשָע רָעָה"}, {"kind": "text", "text": "וְשׂנְאֵי צַדִּיק יֶאְשָֽׁמוּ:"}, {"kind": "text", "text": "❖פּוֹדֶה יְהֹוָה נֶֽפֶשׁ עֲבָדָיו"}, {"kind": "text", "text": "וְלֹא יֶאְשְׁמוּ"}, {"kind": "text", "text": "כָּל־הַחֹסִים בּוֹ:"}, {"kind": "text", "text": "<b>תהלים צ</b>"}, {"kind": "text", "text": "תְּפִלָּה לְמשֶׁה אִישׁ־הָאֱלֹהִים"}, {"kind": "text", "text": "אֲדֹנָי"}, {"kind": "text", "text": "מָעוֹן אַתָּה הָיִֽיתָ לָּֽנוּ"}, {"kind": "text", "text": "בְּדֹר וָדֹר:"}, {"kind": "text", "text": "בְּטֶֽרֶם הָרִים יֻלָּֽדוּ"}, {"kind": "text", "text": "וַתְּחוֹלֵל אֶֽרֶץ"}, {"kind": "text", "text": "וְתֵבֵל"}, {"kind": "text", "text": "וּמֵעוֹלָם עַד־עוֹלָם"}, {"kind": "text", "text": "אַתָּה אֵל:"}, {"kind": "text", "text": "תָּשֵׁב אֱנוֹשׁ"}, {"kind": "text", "text": "עַד־דַּכָּא"}, {"kind": "text", "text": "וַתֹּֽאמֶר"}, {"kind": "text", "text": "שֽׁוּבוּ בְנֵי־אָדָם:"}, {"kind": "text", "text": "כִּי אֶֽלֶף שָׁנִים בְּעֵינֶֽיךָ"}, {"kind": "text", "text": "כְּיוֹם אֶתְמוֹל כִּי יַעֲבֹר"}, {"kind": "text", "text": "וְאַשְׁמוּרָה בַלָּֽיְלָה:"}, {"kind": "text", "text": "זְרַמְתָּם שֵׁנָה יִהְיוּ"}, {"kind": "text", "text": "בַּבֹּֽקֶר"}, {"kind": "text", "text": "כֶּחָצִיר יַחֲלֹף:"}, {"kind": "text", "text": "בַּבֹּֽקֶר יָצִיץ"}, {"kind": "text", "text": "וְחָלָף"}, {"kind": "text", "text": "לָעֶֽרֶב יְמוֹלֵל וְיָבֵשׁ:"}, {"kind": "text", "text": "כִּי־כָלִֽינוּ בְאַפֶּֽךָ"}, {"kind": "text", "text": "וּבַחֲמָתְךָ נִבְהָֽלְנוּ:"}, {"kind": "text", "text": "שַׁתָּה עֲוֹנֹתֵֽינוּ לְנֶגְדֶּֽךָ"}, {"kind": "text", "text": "עֲלֻמֵֽנוּ"}, {"kind": "text", "text": "לִמְאוֹר פָּנֶֽיךָ:"}, {"kind": "text", "text": "כִּי כָל־יָמֵֽינוּ"}, {"kind": "text", "text": "פָּנוּ בְעֶבְרָתֶֽךָ"}, {"kind": "text", "text": "כִּלִּֽינוּ שָׁנֵֽינוּ"}, {"kind": "text", "text": "כְמוֹ־הֶֽגֶה:"}, {"kind": "text", "text": "יְמֵי־שְׁנוֹתֵֽינוּ בָהֶם"}, {"kind": "text", "text": "שִׁבְעִים שָׁנָה"}, {"kind": "text", "text": "וְאִם בִּגְבוּרֹת שְׁמוֹנִים שָׁנָה"}, {"kind": "text", "text": "וְרָהְבָּם עָמָל וָאָֽוֶן"}, {"kind": "text", "text": "כִּי־גָז חִישׁ וַנָּעֻֽפָה:"}, {"kind": "text", "text": "מִי־יוֹדֵֽעַ"}, {"kind": "text", "text": "עֹז אַפֶּֽךָ"}, {"kind": "text", "text": "וּכְיִרְאָתְךָ עֶבְרָתֶֽךָ:"}, {"kind": "text", "text": "לִמְנוֹת יָמֵֽינוּ כֵּן הוֹדַע"}, {"kind": "text", "text": "וְנָבִא לְבַב חָכְמָה:"}, {"kind": "text", "text": "שׁוּבָה יְהֹוָה עַד־מָתָי"}, {"kind": "text", "text": "וְהִנָּחֵם עַל־עֲבָדֶֽיךָ:"}, {"kind": "text", "text": "שַׂבְּעֵֽנוּ בַבֹּֽקֶר"}, {"kind": "text", "text": "חַסְדֶּךָ"}, {"kind": "text", "text": "וּנְרַנְּנָה וְנִשְׂמְחָה"}, {"kind": "text", "text": "בְּכָל־יָמֵֽינוּ:"}, {"kind": "text", "text": "שַׂמְּחֵֽנוּ"}, {"kind": "text", "text": "כִּימוֹת עִנִּיתָֽנוּ"}, {"kind": "text", "text": "שְׁנוֹת רָאִֽינוּ רָעָה:"}, {"kind": "text", "text": "יֵרָאֶה אֶל־עֲבָדֶֽיךָ"}, {"kind": "text", "text": "פָעָלֶֽךָ"}, {"kind": "text", "text": "וַהֲדָרְךָ עַל־בְּנֵיהֶם:"}, {"kind": "text", "text": "❖וִיהִי נֹֽעַם אֲדֹנָי אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "עָלֵֽינוּ"}, {"kind": "text", "text": "וּמַעֲשֵׂה יָדֵֽינוּ כּוֹנְנָה עָלֵֽינוּ"}, {"kind": "text", "text": "וּמַעֲשֵׂה יָדֵֽינוּ כּוֹנְנֵֽהוּ:"}, {"kind": "text", "text": "<b>תהלים צא</b>"}, {"kind": "text", "text": "ישֵׁב"}, {"kind": "text", "text": "בְּסֵֽתֶר עֶלְיוֹן"}, {"kind": "text", "text": "בְּצֵל שַׁדַּי יִתְלוֹנָן:"}, {"kind": "text", "text": "אֹמַר לַיהֹוָה"}, {"kind": "text", "text": "מַחְסִי וּמְצוּדָתִי"}, {"kind": "text", "text": "אֱלֹהַי אֶבְטַח־בּוֹ:"}, {"kind": "text", "text": "כִּי הוּא יַצִּילְךָ מִפַּח יָקוּשׁ"}, {"kind": "text", "text": "מִדֶּֽבֶר הַוּוֹת:"}, {"kind": "text", "text": "בְּאֶבְרָתוֹ יָֽסֶךְ לָךְ"}, {"kind": "text", "text": "וְתַֽחַת־כְּנָפָיו תֶּחְסֶה"}, {"kind": "text", "text": "צִנָּה וְסֹחֵרָה אֲמִתּוֹ:"}, {"kind": "text", "text": "לֹא־תִירָא מִפַּֽחַד לָֽיְלָה"}, {"kind": "text", "text": "מֵחֵץ יָעוּף יוֹמָם:"}, {"kind": "text", "text": "מִדֶּֽבֶר בָּאֹֽפֶל יַהֲלֹךְ"}, {"kind": "text", "text": "מִקֶּֽטֶב יָשׁוּד צָהֳרָֽיִם:"}, {"kind": "text", "text": "יִפֹּל מִצִּדְּךָ אֶֽלֶף"}, {"kind": "text", "text": "וּרְבָבָה מִימִינֶֽךָ"}, {"kind": "text", "text": "אֵלֶֽיךָ לֹא יִגָּשׁ:"}, {"kind": "text", "text": "רַק בְּעֵינֶֽיךָ תַבִּיט"}, {"kind": "text", "text": "וְשִׁלֻּמַת רְשָׁעִים תִּרְאֶה:"}, {"kind": "text", "text": "כִּי־אַתָּה"}, {"kind": "text", "text": "יְהֹוָה מַחְסִי"}, {"kind": "text", "text": "עֶלְיוֹן"}, {"kind": "text", "text": "שַֽׂמְתָּ מְעוֹנֶֽךָ:"}, {"kind": "text", "text": "לֹא־תְאֻנֶּה אֵלֶֽיךָ רָעָה"}, {"kind": "text", "text": "וְנֶֽגַע לֹא־יִקְרַב בְּאָהֳלֶֽךָ:"}, {"kind": "text", "text": "כִּי מַלְאָכָיו"}, {"kind": "text", "text": "יְצַוֶּה־לָּךְ"}, {"kind": "text", "text": "לִשְׁמָרְךָ בְּכָל־דְּרָכֶֽיךָ:"}, {"kind": "text", "text": "עַל־כַּפַּֽיִם יִשָּׂאֽוּנְךָ"}, {"kind": "text", "text": "פֶּן־תִּגֹּף בָּאֶֽבֶן רַגְלֶֽךָ:"}, {"kind": "text", "text": "עַל־שַֽׁחַל וָפֶֽתֶן תִּדְרֹךְ"}, {"kind": "text", "text": "תִּרְמֹס כְּפִיר וְתַנִּין:"}, {"kind": "text", "text": "כִּי בִי חָשַׁק"}, {"kind": "text", "text": "וַאֲפַלְּטֵֽהוּ"}, {"kind": "text", "text": "אֲשַׂגְּבֵֽהוּ"}, {"kind": "text", "text": "כִּי־יָדַע שְׁמִי:"}, {"kind": "text", "text": "יִקְרָאֵֽנִי וְאֶעֱנֵֽהוּ"}, {"kind": "text", "text": "עִמּוֹ־אָנֹכִי בְצָרָה"}, {"kind": "text", "text": "אֲחַלְּצֵֽהוּ וַאֲכַבְּדֵֽהוּ:"}, {"kind": "text", "text": "❖אֹֽרֶךְ יָמִים אַשְׂבִּיעֵֽהוּ"}, {"kind": "text", "text": "וְאַרְאֵֽהוּ בִּישׁוּעָתִי:"}, {"kind": "text", "text": "אֹֽרֶךְ יָמִים אַשְׂבִּיעֵֽהוּ"}, {"kind": "text", "text": "וְאַרְאֵֽהוּ בִּישׁוּעָתִי:"}, {"kind": "text", "text": "<b>תהלים צח</b>"}, {"kind": "text", "text": "מִזְמוֹר"}, {"kind": "text", "text": "שִֽׁירוּ לַיהֹוָה שִׁיר חָדָשׁ"}, {"kind": "text", "text": "כִּי־נִפְלָאוֹת עָשָׂה"}, {"kind": "text", "text": "הוֹשִֽׁיעָה־לּוֹ יְמִינוֹ"}, {"kind": "text", "text": "וּזְרֽוֹעַ קָדְשׁוֹ:"}, {"kind": "text", "text": "הוֹדִֽיעַ יְהֹוָה יְשׁוּעָתוֹ"}, {"kind": "text", "text": "לְעֵינֵי הַגּוֹיִם"}, {"kind": "text", "text": "גִּלָּה צִדְקָתוֹ:"}, {"kind": "text", "text": "זָכַר חַסְדּוֹ"}, {"kind": "text", "text": "וֶאֱמוּנָתוֹ"}, {"kind": "text", "text": "לְבֵית יִשְׂרָאֵל"}, {"kind": "text", "text": "רָאוּ כָל־אַפְסֵי־אָֽרֶץ"}, {"kind": "text", "text": "אֵת יְשׁוּעַת אֱלֹהֵֽינוּ:"}, {"kind": "text", "text": "הָרִֽיעוּ לַיהֹוָה"}, {"kind": "text", "text": "כָּל־הָאָֽרֶץ"}, {"kind": "text", "text": "פִּצְחוּ"}, {"kind": "text", "text": "וְרַנְּנוּ וְזַמֵּֽרוּ:"}, {"kind": "text", "text": "זַמְּרוּ לַיהֹוָה בְּכִנּוֹר"}, {"kind": "text", "text": "בְּכִנּוֹר וְקוֹל זִמְרָה:"}, {"kind": "text", "text": "בַּחֲצֹצְרוֹת וְקוֹל שׁוֹפָר"}, {"kind": "text", "text": "הָרִֽיעוּ לִפְנֵי הַמֶּֽלֶךְ יְהֹוָה:"}, {"kind": "text", "text": "יִרְעַם הַיָּם וּמְלֹאוֹ"}, {"kind": "text", "text": "תֵּבֵל וְיֽשְׁבֵי בָהּ:"}, {"kind": "text", "text": "❖נְהָרוֹת יִמְחֲאוּ־כָף"}, {"kind": "text", "text": "יַֽחַד הָרִים יְרַנֵּֽנוּ:"}, {"kind": "text", "text": "לִפְנֵי־יְהֹוָה"}, {"kind": "text", "text": "כִּי בָא לִשְׁפֹּט הָאָֽרֶץ"}, {"kind": "text", "text": "יִשְׁפֹּט־תֵּבֵל בְּצֶֽדֶק"}, {"kind": "text", "text": "וְעַמִּים בְּמֵישָׁרִים:"}, {"kind": "text", "text": "<b>תהלים קכא</b>"}, {"kind": "text", "text": "שִׁיר לַמַּעֲלוֹת"}, {"kind": "text", "text": "אֶשָּׂא עֵינַי אֶל־הֶהָרִים"}, {"kind": "text", "text": "מֵאַֽיִן יָבֹא עֶזְרִי:"}, {"kind": "text", "text": "עֶזְרִי מֵעִם יְהֹוָה"}, {"kind": "text", "text": "עֹשֵׂה שָׁמַֽיִם וָאָֽרֶץ:"}, {"kind": "text", "text": "אַל־יִתֵּן לַמּוֹט רַגְלֶֽךָ"}, {"kind": "text", "text": "אַל־יָנוּם שֹׁמְרֶֽךָ:"}, {"kind": "text", "text": "הִנֵּה לֹא־יָנוּם"}, {"kind": "text", "text": "וְלֹא יִישָׁן שׁוֹמֵר יִשְׂרָאֵל:"}, {"kind": "text", "text": "יְהֹוָה שֹׁמְרֶֽךָ"}, {"kind": "text", "text": "יְהֹוָה צִלְּךָ עַל־יַד יְמִינֶֽךָ:"}, {"kind": "text", "text": "יוֹמָם הַשֶּֽׁמֶשׁ לֹא־יַכֶּֽכָּה"}, {"kind": "text", "text": "וְיָרֵֽחַ בַּלָּֽיְלָה:"}, {"kind": "text", "text": "❖יְהֹוָה יִשְׁמָרְךָ מִכָּל־רָע"}, {"kind": "text", "text": "יִשְׁמֹר אֶת־נַפְשֶֽׁךָ:"}, {"kind": "text", "text": "יְהֹוָה יִשְׁמָר־צֵאתְךָ וּבוֹאֶֽךָ"}, {"kind": "text", "text": "מֵעַתָּה וְעַד־עוֹלָם:"}, {"kind": "text", "text": "<b>תהלים קכב</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת לְדָוִד"}, {"kind": "text", "text": "שָׂמַֽחְתִּי בְּאֹמְרִים לִי"}, {"kind": "text", "text": "בֵּית יְהֹוָה נֵלֵךְ:"}, {"kind": "text", "text": "עֹמְדוֹת הָיוּ רַגְלֵֽינוּ"}, {"kind": "text", "text": "בִּשְׁעָרַֽיִךְ יְרוּשָׁלָֽםִ:"}, {"kind": "text", "text": "יְרוּשָׁלַֽםִ הַבְּנוּיָה"}, {"kind": "text", "text": "כְּעִיר שֶׁחֻבְּרָה־לָּהּ יַחְדָּו:"}, {"kind": "text", "text": "שֶׁשָּׁם עָלוּ שְׁבָטִים"}, {"kind": "text", "text": "שִׁבְטֵי־יָהּ"}, {"kind": "text", "text": "עֵדוּת לְיִשְׂרָאֵל"}, {"kind": "text", "text": "לְהֹדוֹת לְשֵׁם יְהֹוָה:"}, {"kind": "text", "text": "כִּי שָֽׁמָּה"}, {"kind": "text", "text": "יָשְׁבוּ כִסְאוֹת לְמִשְׁפָּט"}, {"kind": "text", "text": "כִּסְאוֹת לְבֵית דָּוִד:"}, {"kind": "text", "text": "שַׁאֲלוּ שְׁלוֹם יְרוּשָׁלָֽםִ"}, {"kind": "text", "text": "יִשְׁלָֽיוּ אֹהֲבָֽיִךְ:"}, {"kind": "text", "text": "יְהִי־שָׁלוֹם בְּחֵילֵךְ"}, {"kind": "text", "text": "שַׁלְוָה בְּאַרְמְנוֹתָֽיִךְ:"}, {"kind": "text", "text": "❖לְמַֽעַן אַחַי וְרֵעָי"}, {"kind": "text", "text": "אֲדַבְּרָה־נָּא שָׁלוֹם בָּךְ:"}, {"kind": "text", "text": "לְמַֽעַן בֵּית־יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "אֲבַקְשָׁה טוֹב לָךְ:"}, {"kind": "text", "text": "<b>תהלים קכג</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת"}, {"kind": "text", "text": "אֵלֶֽיךָ נָשָֽׂאתִי אֶת־עֵינַי"}, {"kind": "text", "text": "הַיּשְׁבִי בַּשָּׁמָֽיִם:"}, {"kind": "text", "text": "הִנֵּה כְעֵינֵי עֲבָדִים"}, {"kind": "text", "text": "אֶל־יַד אֲדוֹנֵיהֶם"}, {"kind": "text", "text": "כְּעֵינֵי שִׁפְחָה"}, {"kind": "text", "text": "אֶל־יַד גְּבִרְתָּהּ"}, {"kind": "text", "text": "כֵּן עֵינֵֽינוּ אֶל־יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "עַד שֶׁיְּחָנֵּֽנוּ:"}, {"kind": "text", "text": "חָנֵּֽנוּ יְהֹוָה חָנֵּֽנוּ"}, {"kind": "text", "text": "כִּי־רַב שָׂבַֽעְנוּ בוּז:"}, {"kind": "text", "text": "❖רַבַּת שָֽׂבְעָה־לָּהּ נַפְשֵֽׁנוּ"}, {"kind": "text", "text": "הַלַּֽעַג הַשַּׁאֲנַנִּים"}, {"kind": "text", "text": "הַבּוּז"}, {"kind": "text", "text": "לִגְאֵי יוֹנִֽים:"}, {"kind": "text", "text": "<b>תהלים קכד</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת לְדָוִד"}, {"kind": "text", "text": "לוּלֵי יְהֹוָה שֶׁהָֽיָה לָֽנוּ"}, {"kind": "text", "text": "יֹֽאמַר־נָא יִשְׂרָאֵל:"}, {"kind": "text", "text": "לוּלֵי יְהֹוָה"}, {"kind": "text", "text": "שֶׁהָֽיָה לָֽנוּ"}, {"kind": "text", "text": "בְּקוּם עָלֵֽינוּ אָדָם:"}, {"kind": "text", "text": "אֲזַי חַיִּים בְּלָעֽוּנוּ"}, {"kind": "text", "text": "בַּחֲרוֹת אַפָּם בָּֽנוּ:"}, {"kind": "text", "text": "אֲזַי הַמַּֽיִם שְׁטָפֽוּנוּ"}, {"kind": "text", "text": "נַֽחְלָה עָבַר עַל־נַפְשֵֽׁנוּ:"}, {"kind": "text", "text": "אֲזַי עָבַר עַל־נַפְשֵֽׁנוּ"}, {"kind": "text", "text": "הַמַּֽיִם הַזֵּידוֹנִים:"}, {"kind": "text", "text": "בָּרוּךְ יְהֹוָה"}, {"kind": "text", "text": "שֶׁלֹּא נְתָנָֽנוּ"}, {"kind": "text", "text": "טֶֽרֶף לְשִׁנֵּיהֶם:"}, {"kind": "text", "text": "❖נַפְשֵֽׁנוּ כְּצִפּוֹר נִמְלְטָה"}, {"kind": "text", "text": "מִפַּח יוֹקְשִׁים"}, {"kind": "text", "text": "הַפַּח נִשְׁבָּר וַאֲנַֽחְנוּ נִמְלָֽטְנוּ:"}, {"kind": "text", "text": "עֶזְרֵֽנוּ בְּשֵׁם יְהֹוָה"}, {"kind": "text", "text": "עֹשֵׂה שָׁמַֽיִם וָאָֽרֶץ:"}, {"kind": "text", "text": "<b>תהלים קלה</b>"}, {"kind": "text", "text": "הַלְלוּיָהּ"}, {"kind": "text", "text": "הַלְלוּ אֶת־שֵׁם יְהֹוָה"}, {"kind": "text", "text": "הַלְלוּ עַבְדֵי יְהֹוָה:"}, {"kind": "text", "text": "שֶׁעֹמְדִים בְּבֵית יְהֹוָה"}, {"kind": "text", "text": "בְּחַצְרוֹת בֵּית אֱלֹהֵֽינוּ:"}, {"kind": "text", "text": "הַלְלוּיָהּ כִּי־טוֹב יְהֹוָה"}, {"kind": "text", "text": "זַמְּרוּ לִשְׁמוֹ כִּי נָעִים:"}, {"kind": "text", "text": "כִּי־יַעֲקֹב בָּחַר לוֹ יָהּ"}, {"kind": "text", "text": "יִשְׂרָאֵל לִסְגֻלָּתוֹ:"}, {"kind": "text", "text": "כִּי אֲנִי יָדַֽעְתִּי"}, {"kind": "text", "text": "כִּי־גָדוֹל יְהֹוָה"}, {"kind": "text", "text": "וַאֲדֹנֵֽינוּ מִכָּל־אֱלֹהִים:"}, {"kind": "text", "text": "כֹּל אֲשֶׁר־חָפֵץ יְהֹוָה"}, {"kind": "text", "text": "עָשָׂה בַּשָּׁמַֽיִם וּבָאָֽרֶץ"}, {"kind": "text", "text": "בַּיַּמִּים וְכָל־תְּהֹמוֹת:"}, {"kind": "text", "text": "מַעֲלֶה נְשִׂאִים"}, {"kind": "text", "text": "מִקְצֵה הָאָֽרֶץ"}, {"kind": "text", "text": "בְּרָקִים לַמָּטָר עָשָׂה"}, {"kind": "text", "text": "מֽוֹצֵא־רֽוּחַ מֵאוֹצְרוֹתָיו:"}, {"kind": "text", "text": "שֶׁהִכָּה בְּכוֹרֵי מִצְרָֽיִם"}, {"kind": "text", "text": "מֵאָדָם עַד־בְּהֵמָה:"}, {"kind": "text", "text": "שָׁלַח אוֹתֹת וּמֹפְתִים"}, {"kind": "text", "text": "בְּתוֹכֵֽכִי מִצְרָֽיִם"}, {"kind": "text", "text": "בְּפַרְעֹה וּבְכָל־עֲבָדָיו:"}, {"kind": "text", "text": "שֶׁהִכָּה גּוֹיִם רַבִּים"}, {"kind": "text", "text": "וְהָרַג מְלָכִים עֲצוּמִים:"}, {"kind": "text", "text": "לְסִיחוֹן מֶֽלֶךְ הָאֱמֹרִי"}, {"kind": "text", "text": "וּלְעוֹג מֶֽלֶךְ הַבָּשָׁן"}, {"kind": "text", "text": "וּלְכֹל מַמְלְכוֹת כְּנָֽעַן:"}, {"kind": "text", "text": "וְנָתַן אַרְצָם נַחֲלָה"}, {"kind": "text", "text": "נַחֲלָה לְיִשְׂרָאֵל עַמּוֹ:"}, {"kind": "text", "text": "יְהֹוָה שִׁמְךָ לְעוֹלָם"}, {"kind": "text", "text": "יְהֹוָה זִכְרְךָ לְדֹר־וָדֹר:"}, {"kind": "text", "text": "כִּי־יָדִין יְהֹוָה עַמּוֹ"}, {"kind": "text", "text": "וְעַל־עֲבָדָיו יִתְנֶחָם:"}, {"kind": "text", "text": "עֲצַבֵּי הַגּוֹיִם"}, {"kind": "text", "text": "כֶּֽסֶף וְזָהָב"}, {"kind": "text", "text": "מַעֲשֵׂה יְדֵי אָדָם:"}, {"kind": "text", "text": "פֶּה־לָהֶם וְלֹא יְדַבֵּֽרוּ"}, {"kind": "text", "text": "עֵינַֽיִם לָהֶם וְלֹא יִרְאוּ:"}, {"kind": "text", "text": "אָזְנַֽיִם לָהֶם וְלֹא יַאֲזִֽינוּ"}, {"kind": "text", "text": "אַף אֵין־יֶשׁ־רֽוּחַ בְּפִיהֶם:"}, {"kind": "text", "text": "כְּמוֹהֶם יִהְיוּ עֹשֵׂיהֶם"}, {"kind": "text", "text": "כֹּל אֲשֶׁר־בֹּטֵֽחַ בָּהֶם:"}, {"kind": "text", "text": "❖בֵּית יִשְׂרָאֵל בָּרְכוּ אֶת־יְהֹוָה"}, {"kind": "text", "text": "בֵּית אַהֲרֹן בָּרְכוּ אֶת־יְהֹוָה:"}, {"kind": "text", "text": "בֵּית הַלֵּוִי בָּרְכוּ אֶת־יְהֹוָה"}, {"kind": "text", "text": "יִרְאֵי יְהֹוָה בָּרְכוּ אֶת־יְהֹוָה:"}, {"kind": "text", "text": "בָּרוּךְ יְהֹוָה מִצִּיּוֹן"}, {"kind": "text", "text": "שֹׁכֵן יְרוּשָׁלָֽםִ"}, {"kind": "text", "text": "הַלְלוּיָהּ:"}, {"kind": "text", "text": "<b>תהלים קלו</b>"}, {"kind": "text", "text": "הוֹדוּ לַיהֹוָה כִּי־טוֹב"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "הוֹדוּ לֵאלֹהֵי הָאֱלֹהִים"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "הוֹדוּ לַאֲדֹנֵי הָאֲדֹנִים"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "לְעֹשֵׂה נִפְלָאוֹת גְּדֹלוֹת לְבַדּוֹ"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "לְעֹשֵׂה הַשָּׁמַֽיִם"}, {"kind": "text", "text": "בִּתְבוּנָה"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "לְרֹקַע הָאָֽרֶץ עַל־הַמָּֽיִם"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "לְעֹשֵׂה אוֹרִים גְּדֹלִים"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "אֶת־הַשֶּֽׁמֶשׁ לְמֶמְשֶֽׁלֶת בַּיּוֹם"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "אֶת־הַיָּרֵֽחַ וְכוֹכָבִים"}, {"kind": "text", "text": "לְמֶמְשְׁלוֹת בַּלָּֽיְלָה"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "לְמַכֵּה מִצְרַֽיִם"}, {"kind": "text", "text": "בִּבְכוֹרֵיהֶם"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "וַיּוֹצֵא יִשְׂרָאֵל מִתּוֹכָם"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "בְּיָד חֲזָקָה וּבִזְרֽוֹעַ נְטוּיָה"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "לְגֹזֵר יַם־סוּף לִגְזָרִים"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "וְהֶעֱבִיר יִשְׂרָאֵל בְּתוֹכוֹ"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "וְנִעֵר פַּרְעֹה וְחֵילוֹ"}, {"kind": "text", "text": "בְיַם־סוּף"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "לְמוֹלִיךְ עַמּוֹ"}, {"kind": "text", "text": "בַּמִּדְבָּר"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "לְמַכֵּה מְלָכִים גְּדֹלִים"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "וַיַּהֲרֹג מְלָכִים אַדִּירִים"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "לְסִיחוֹן מֶֽלֶךְ הָאֱמֹרִי"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "וּלְעוֹג מֶֽלֶךְ הַבָּשָׁן"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "וְנָתַן אַרְצָם לְנַחֲלָה"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "נַחֲלָה לְיִשְׂרָאֵל עַבְדּוֹ"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "שֶׁבְּשִׁפְלֵֽנוּ זָֽכַר־לָֽנוּ"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "וַיִּפְרְקֵֽנוּ מִצָּרֵֽינוּ"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "❖נֹתֵן לֶֽחֶם לְכָל־בָּשָׂר"}, {"kind": "text", "text": "כִּי־לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "❖הוֹדוּ לְאֵל הַשָּׁמָֽיִם"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "הָאֲדֶּֽרֶת וְהָאֱמוּנָה"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַבִּינָה וְהַבְּרָכָה"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַגַּאֲוָה וְהַגְּדֻלָּה"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַדֵּעָה וְהַדִּבּוּר"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַהוֹד וְהֶהָדָר"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַוַּֽעַד"}, {"kind": "text", "text": "וְהַוָּתִיקוּת"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַזָּךְ וְהַזֹּֽהַר"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַחַֽיִל וְהַחֹֽסֶן"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַטֶּֽכֶס וְהַטֹּהַר"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַיִּחוּד וְהַיִּרְאָה"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַכֶּֽתֶר וְהַכָּבוֹד"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַלֶּֽקַח וְהַלִּבּוּב"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַמְּלוּכָה וְהַמֶּמְשָׁלָה"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַנּוֹי וְהַנֵּֽצַח"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַסִּגּוּי וְהַשֶּֽׂגֶב"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הָעֹז וְהָעֲנָוָה"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַפְּדוּת וְהַפְּאֵר"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַצְּבִי וְהַצֶּֽדֶק"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַקְּרִיאָה וְהַקְּדֻשָּׁה"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הָרוֹן וְהָרוֹמֵמוּת"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַשִּׁיר וְהַשֶּֽׁבַח"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "text", "text": "הַתְּהִלָּה וְהַתִּפְאֶֽרֶת"}, {"kind": "text", "text": "לְחַי עוֹלָמִים:"}, {"kind": "header", "text": "ברוך שאמר"}, {"kind": "text", "text": "הֲרֵינִי מְזַמֵּן אֶת פִּי לְהוֹדוֹת וּלְהַלֵּל וּלְשַׁבֵּחַ אֶת בּוֹרְאִי לְשֵׁם יִחוּד קוּדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּהּ עַל יְדֵי הַהוּא טָמִיר וְנֶעְלָם בְּשֵׁם כָּל יִשְּׂרָאֵל:"}, {"kind": "text", "text": "בָּרוּךְ שֶׁאָמַר"}, {"kind": "text", "text": "וְהָיָה הָעוֹלָם,"}, {"kind": "text", "text": "בָּרוּךְ הוּא,"}, {"kind": "text", "text": "בָּרוּךְ אוֹמֵר וְעוֹשֶׂה,"}, {"kind": "text", "text": "בָּרוּךְ גּוֹזֵר וּמְקַיֵּם,"}, {"kind": "text", "text": "בָּרוּךְ עֹשֶׂה בְרֵאשִׁית,"}, {"kind": "text", "text": "בָּרוּךְ מְרַחֵם"}, {"kind": "text", "text": "עַל הָאָֽרֶץ,"}, {"kind": "text", "text": "בָּרוּךְ מְרַחֵם"}, {"kind": "text", "text": "עַל הַבְּ֒רִיּוֹת,"}, {"kind": "text", "text": "בָּרוּךְ מְשַׁלֵּם שָׂכָר טוֹב"}, {"kind": "text", "text": "לִירֵאָיו,"}, {"kind": "text", "text": "בָּרוּךְ חַי לָעַד"}, {"kind": "text", "text": "וְקַיָּם לָנֶֽצַח,"}, {"kind": "text", "text": "בָּרוּךְ פּוֹדֶה וּמַצִּיל,"}, {"kind": "text", "text": "בָּרוּךְ שְׁמוֹ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "הָאֵל הָאָב הָרַחֲמָן"}, {"kind": "text", "text": "הַמְּ֒הֻלָּל בְּפֶה עַמּוֹ"}, {"kind": "text", "text": "מְשֻׁבָּח וּמְ֒פֹאָר"}, {"kind": "text", "text": "בִּלְ֒שׁוֹן חֲסִידָיו"}, {"kind": "text", "text": "וַעֲבָדָיו"}, {"kind": "text", "text": "וּבְ֒שִׁירֵי דָוִד עַבְדֶּֽךָ,"}, {"kind": "text", "text": "נְהַלֶּלְ֒ךָ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בִּשְׁ֒בָחוֹת וּבִזְ֒מִירוֹת"}, {"kind": "text", "text": "נְ֒גַדֶּלְ֒ךָ וּנְ֒שַׁבֵּחֲךָ וּנְ֒פָאֶרְ֒ךָ"}, {"kind": "text", "text": "וְנַמְלִיכְ֒ךָ"}, {"kind": "text", "text": "וְנַזְכִּיר שִׁמְ֒ךָ"}, {"kind": "text", "text": "מַלְכֵּֽנוּ אֱלֹהֵֽינוּ,"}, {"kind": "text", "text": "❖יָחִיד, חֵי הָעוֹלָמִים מֶֽלֶךְ"}, {"kind": "text", "text": "מְשֻׁבָּח וּמְ֒פֹאָר עֲדֵי עַד"}, {"kind": "text", "text": "שְׁמוֹ הַגָּדוֹל:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "מֶֽלֶךְ מְהֻלָּל בַּתִּשְׁבָּחוֹת:"}, {"kind": "header", "text": "תהלים צב"}, {"kind": "text", "text": "מִזְמוֹר שִׁיר לְיוֹם הַשַּׁבָּת:"}, {"kind": "text", "text": "טוֹב לְהֹדוֹת לַיהֹוָה"}, {"kind": "text", "text": "וּלְזַמֵּר לְשִׁמְךָ עֶלְיוֹן:"}, {"kind": "text", "text": "לְהַגִּיד בַּבֹּֽקֶר חַסְדֶּֽךָ"}, {"kind": "text", "text": "וֶאֱמוּנָתְךָ בַּלֵּילוֹת:"}, {"kind": "text", "text": "עֲלֵי־עָשׂוֹר וַעֲלֵי־נָֽבֶל"}, {"kind": "text", "text": "עֲלֵי הִגָּיוֹן בְּכִנּוֹר:"}, {"kind": "text", "text": "כִּי שִׂמַּחְתַּֽנִי יְהֹוָה"}, {"kind": "text", "text": "בְּפָעֳלֶֽךָ"}, {"kind": "text", "text": "בְּמַעֲשֵׂי יָדֶֽיךָ אֲרַנֵּן:"}, {"kind": "text", "text": "מַה־גָּדְלוּ מַעֲשֶֽׂיךָ יְהֹוָה"}, {"kind": "text", "text": "מְאֹד עָמְקוּ מַחְשְׁבֹתֶֽיךָ:"}, {"kind": "text", "text": "אִישׁ־בַּֽעַר לֹא יֵדָע"}, {"kind": "text", "text": "וּכְסִיל לֹא־יָבִין אֶת־זֹאת:"}, {"kind": "text", "text": "בִּפְרֹֽחַ רְשָׁעִים כְּמוֹ עֵֽשֶׂב"}, {"kind": "text", "text": "וַיָּצִֽיצוּ כָּל־פֹּֽעֲלֵי אָֽוֶן"}, {"kind": "text", "text": "לְהִשָּׁמְדָם עֲדֵי־עַד:"}, {"kind": "text", "text": "וְאַתָּה מָרוֹם לְעֹלָם"}, {"kind": "text", "text": "יְהֹוָה:"}, {"kind": "text", "text": "כִּי הִנֵּה אֹיְבֶֽיךָ יְהֹוָה"}, {"kind": "text", "text": "כִּי־הִנֵּה אֹיְבֶֽיךָ יֹאבֵֽדוּ"}, {"kind": "text", "text": "יִתְפָּרְדוּ כָּל־פֹּֽעֲלֵי אָֽוֶן:"}, {"kind": "text", "text": "וַתָּֽרֶם כִּרְאֵים קַרְנִי"}, {"kind": "text", "text": "בַּלֹּתִי בְּשֶֽׁמֶן רַעֲנָן:"}, {"kind": "text", "text": "וַתַּבֵּט עֵינִי"}, {"kind": "text", "text": "בְּשׁוּרָי"}, {"kind": "text", "text": "בַּקָּמִים עָלַי מְרֵעִים"}, {"kind": "text", "text": "תִּשְׁמַֽעְנָה אָזְנָי:"}, {"kind": "text", "text": "צַדִּיק כַּתָּמָר יִפְרָח"}, {"kind": "text", "text": "כְּאֶֽרֶז בַּלְּבָנוֹן יִשְׂגֶּה:"}, {"kind": "text", "text": "שְׁתוּלִים בְּבֵית יְהֹוָה"}, {"kind": "text", "text": "בְּחַצְרוֹת אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "יַפְרִֽיחוּ:"}, {"kind": "text", "text": "עוֹד יְנוּבוּן בְּשֵׂיבָה"}, {"kind": "text", "text": "דְּשֵׁנִים וְרַעֲנַנִּים יִהְיוּ:"}, {"kind": "text", "text": "לְהַגִּיד כִּי־יָשָׁר יְהֹוָה"}, {"kind": "text", "text": "צוּרִי"}, {"kind": "text", "text": "וְלֹא־עַוְלָֽתָה בּוֹ:"}, {"kind": "header", "text": "תהלים צג"}, {"kind": "text", "text": "יְהֹוָה מָלָךְ"}, {"kind": "text", "text": "גֵּאוּת לָבֵשׁ"}, {"kind": "text", "text": "לָבֵשׁ יְהֹוָה"}, {"kind": "text", "text": "עֹז הִתְאַזָּר"}, {"kind": "text", "text": "אַף־תִּכּוֹן תֵּבֵל"}, {"kind": "text", "text": "בַּל־תִּמּוֹט:"}, {"kind": "text", "text": "נָכוֹן כִּסְאֲךָ מֵאָז"}, {"kind": "text", "text": "מֵעוֹלָם אָֽתָּה:"}, {"kind": "text", "text": "נָשְׂאוּ נְהָרוֹת יְהֹוָה"}, {"kind": "text", "text": "נָשְׂאוּ נְהָרוֹת קוֹלָם"}, {"kind": "text", "text": "יִשְׂאוּ נְהָרוֹת דָּכְיָם:"}, {"kind": "text", "text": "מִקֹּלוֹת מַֽיִם רַבִּים"}, {"kind": "text", "text": "אַדִּירִים מִשְׁבְּרֵי־יָם"}, {"kind": "text", "text": "אַדִּיר בַּמָּרוֹם יְהֹוָה:"}, {"kind": "text", "text": "עֵדֹתֶֽיךָ נֶאֶמְנוּ מְאֹד"}, {"kind": "text", "text": "לְבֵיתְךָ נָֽאֲוָה־קֹּֽדֶשׁ"}, {"kind": "text", "text": "יְהֹוָה לְאֹֽרֶךְ יָמִים:"}, {"kind": "header", "text": "יהי כבוד"}, {"kind": "text", "text": "יְהִי כְבוֹד יְהֹוָה לְעוֹלָם"}, {"kind": "text", "text": "יִשְׂמַח יְהֹוָה בְּמַעֲשָׂיו:"}, {"kind": "text", "text": "יְהִי שֵׁם יְהֹוָה מְבֹרָךְ"}, {"kind": "text", "text": "מֵעַתָּה וְעַד־עוֹלָם:"}, {"kind": "text", "text": "מִמִּזְרַח־שֶֽׁמֶשׁ עַד־מְבוֹאוֹ"}, {"kind": "text", "text": "מְהֻלָּל שֵׁם יְהֹוָה:"}, {"kind": "text", "text": "רָם עַל־כָּל־גּוֹיִם יְהֹוָה"}, {"kind": "text", "text": "עַל הַשָּׁמַֽיִם כְּבוֹדוֹ:"}, {"kind": "text", "text": "יְהֹוָה שִׁמְ֒ךָ לְעוֹלָם"}, {"kind": "text", "text": "יְהֹוָה זִכְרְ֒ךָ לְדֹר־וָדֹר:"}, {"kind": "text", "text": "יְהֹוָה בַּשָּׁמַֽיִם הֵכִין כִּסְאוֹ"}, {"kind": "text", "text": "וּמַלְ֒כוּתוֹ בַּכֹּל מָשָֽׁלָה:"}, {"kind": "text", "text": "יִשְׂמְחוּ הַשָּׁמַֽיִם וְתָגֵל הָאָֽרֶץ"}, {"kind": "text", "text": "וְיֹאמְ֒רוּ בַגּוֹיִם"}, {"kind": "text", "text": "יְהֹוָה מָלָךְ:"}, {"kind": "text", "text": "יְהֹוָה מֶֽלֶךְ יְהֹוָה מָלָךְ"}, {"kind": "text", "text": "יְהֹוָה יִמְלֹךְ לְעֹלָם וָעֶד:"}, {"kind": "text", "text": "יְהֹוָה מֶֽלֶךְ עוֹלָם וָעֶד"}, {"kind": "text", "text": "אָבְ֒דוּ גוֹיִם"}, {"kind": "text", "text": "מֵאַרְצוֹ:"}, {"kind": "text", "text": "יְהֹוָה הֵפִיר עֲצַת־גּוֹיִם"}, {"kind": "text", "text": "הֵנִיא מַחְשְׁבוֹת עַמִּים:"}, {"kind": "text", "text": "רַבּוֹת מַחֲשָׁבוֹת בְּלֶב־אִישׁ"}, {"kind": "text", "text": "וַעֲצַת יְהֹוָה הִיא תָקוּם:"}, {"kind": "text", "text": "עֲצַת יְהֹוָה לְעוֹלָם תַּעֲמֹד"}, {"kind": "text", "text": "מַחְשְׁבוֹת לִבּוֹ"}, {"kind": "text", "text": "לְדֹר וָדֹר:"}, {"kind": "text", "text": "כִּי הוּא אָמַר וַיֶּֽהִי"}, {"kind": "text", "text": "הוּא־צִוָּה וַיַּעֲמֹד:"}, {"kind": "text", "text": "כִּי בָחַר יְהֹוָה בְּצִיּוֹן"}, {"kind": "text", "text": "אִוָּהּ לְמוֹשָׁב לוֹ:"}, {"kind": "text", "text": "כִּי־יַעֲקֹב בָּחַר לוֹ יָהּ"}, {"kind": "text", "text": "יִשְׂרָאֵל לִסְ֒גֻלָּתוֹ:"}, {"kind": "text", "text": "כִּי לֹא יִטּשׁ יְהֹוָה עַמּוֹ"}, {"kind": "text", "text": "וְנַחֲלָתוֹ לֹא יַעֲזֹב:"}, {"kind": "text", "text": "❖וְהוּא רַחוּם"}, {"kind": "text", "text": "יְכַפֵּר עָוֹן וְלֹא־יַשְׁחִית"}, {"kind": "text", "text": "וְהִרְבָּה לְהָשִׁיב אַפּוֹ"}, {"kind": "text", "text": "וְלֹא־יָעִיר כָּל־חֲמָתוֹ:"}, {"kind": "text", "text": "יְהֹוָה הוֹשִׁיעָה"}, {"kind": "text", "text": "הַמֶּֽלֶךְ יַעֲנֵֽנוּ בְיוֹם־קָרְ֒אֵֽנוּ:"}, {"kind": "header", "text": "אשרי"}, {"kind": "text", "text": "אַשְׁרֵי יוֹשְׁ֒בֵי"}, {"kind": "text", "text": "בֵיתֶֽךָ"}, {"kind": "text", "text": "עוֹד יְהַלְ֒לֽוּךָ סֶּֽלָה:"}, {"kind": "text", "text": "אַשְׁרֵי הָעָם שֶׁכָּֽכָה לּוֹ"}, {"kind": "text", "text": "אַשְׁרֵי הָעָם"}, {"kind": "text", "text": "שֶׁיְהֹוָה אֱלֹהָיו:"}, {"kind": "text", "text": "תְּהִלָּה לְדָוִד"}, {"kind": "text", "text": "אֲרוֹמִמְ֒ךָ אֱלוֹהַי הַמֶּֽלֶךְ"}, {"kind": "text", "text": "וַאֲבָרְ֒כָה שִׁמְ֒ךָ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "בְּכָל־יוֹם אֲבָרְ֒כֶֽךָ"}, {"kind": "text", "text": "וַאֲהַלְ֒לָה שִׁמְ֒ךָ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "גָּדוֹל יְהֹוָה וּמְ֒הֻלָּל מְאֹד"}, {"kind": "text", "text": "וְלִגְ֒דֻלָּתוֹ אֵין חֵֽקֶר:"}, {"kind": "text", "text": "דּוֹר לְדוֹר"}, {"kind": "text", "text": "יְשַׁבַּח מַעֲשֶׂיךָ"}, {"kind": "text", "text": "וּגְ֒בוּרֹתֶֽיךָ יַגִּֽידוּ:"}, {"kind": "text", "text": "הֲדַר כְּבוֹד הוֹדֶֽךָ"}, {"kind": "text", "text": "וְדִבְ֒רֵי נִפְלְ֒אֹתֶֽיךָ אָשִֽׂיחָה:"}, {"kind": "text", "text": "וֶעֱזוּז נוֹרְ֒אֹתֶֽיךָ יֹאמֵרוּ"}, {"kind": "text", "text": "וּגְ֒דֻלָּתְ֒ךָ אֲסַפְּ֒רֶֽנָּה:"}, {"kind": "text", "text": "זֵֽכֶר רַב־טוּבְ֒ךָ"}, {"kind": "text", "text": "יַבִּֽיעוּ"}, {"kind": "text", "text": "וְצִדְ֒קָתְ֒ךָ יְרַנֵּֽנוּ:"}, {"kind": "text", "text": "חַנּוּן וְרַחוּם יְהֹוָה"}, {"kind": "text", "text": "אֶֽרֶךְ אַפַּֽיִם וּגְ֒דָל־חָֽסֶד:"}, {"kind": "text", "text": "טוֹב־יְהֹוָה לַכֹּל"}, {"kind": "text", "text": "וְרַחֲמָיו עַל־כָּל־מַעֲשָׂיו:"}, {"kind": "text", "text": "יוֹדֽוּךָ יְהֹוָה כָּל־מַעֲשֶֽׂיךָ"}, {"kind": "text", "text": "וַחֲסִידֶֽיךָ יְבָרְ֒כֽוּכָה:"}, {"kind": "text", "text": "כְּבוֹד מַלְ֒כוּתְ֒ךָ"}, {"kind": "text", "text": "יֹאמֵרוּ"}, {"kind": "text", "text": "וּגְ֒בוּרָתְ֒ךָ יְדַבֵּֽרוּ:"}, {"kind": "text", "text": "לְהוֹדִֽיעַ לִבְ֒נֵי הָאָדָם גְּבוּרֹתָיו"}, {"kind": "text", "text": "וּכְ֒בוֹד הֲדַר מַלְ֒כוּתוֹ:"}, {"kind": "text", "text": "מַלְ֒כוּתְ֒ךָ מַלְ֒כוּת כָּל־עֹלָמִים"}, {"kind": "text", "text": "וּמֶמְשַׁלְתְּךָ בְּכָל־דּוֹר וָדֹר:"}, {"kind": "text", "text": "סוֹמֵךְ יְהֹוָה לְכָל־הַנֹּפְ֒לִים"}, {"kind": "text", "text": "וְזוֹקֵף לְכָל־הַכְּ֒פוּפִים:"}, {"kind": "text", "text": "עֵינֵי־כֹל אֵלֶֽיךָ יְשַׂבֵּֽרוּ"}, {"kind": "text", "text": "וְאַתָּה נוֹתֵן־לָהֶם"}, {"kind": "text", "text": "אֶת־אָכְלָם בְּעִתּוֹ:"}, {"kind": "text", "text": "פּוֹתֵֽחַ אֶת־יָדֶֽךָ"}, {"kind": "text", "text": "וּמַשְׂבִּֽיעַ לְכָל־חַי רָצוֹן:"}, {"kind": "text", "text": "צַדִּיק יְהֹוָה בְּכָל־דְּרָכָיו"}, {"kind": "text", "text": "וְחָסִיד בְּכָל־מַעֲשָׂיו:"}, {"kind": "text", "text": "קָרוֹב יְהֹוָה לְכָל־קֹרְ֒אָיו"}, {"kind": "text", "text": "לְכֹל אֲשֶׁר יִקְרָאֻֽהוּ בֶאֱמֶת:"}, {"kind": "text", "text": "רְצוֹן־יְרֵאָיו יַעֲשֶׂה"}, {"kind": "text", "text": "וְאֶת־שַׁוְעָתָם יִשְׁמַע וְיוֹשִׁיעֵם:"}, {"kind": "text", "text": "שׁוֹמֵר יְהֹוָה אֶת־כָּל־אֹהֲבָיו"}, {"kind": "text", "text": "וְאֵת כָּל־הָרְ֒שָׁעִים יַשְׁמִיד:"}, {"kind": "text", "text": "❖תְּהִלַּת יְהֹוָה יְדַבֶּר פִּי"}, {"kind": "text", "text": "וִיבָרֵךְ כָּל־בָּשָׂר"}, {"kind": "text", "text": "שֵׁם קָדְשׁוֹ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "וַאֲנַֽחְנוּ נְבָרֵךְ יָהּ"}, {"kind": "text", "text": "מֵעַתָּה וְעַד־עוֹלָם"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ:"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ"}, {"kind": "text", "text": "הַלְ֒לִי נַפְשִׁי אֶת־יְהֹוָה:"}, {"kind": "text", "text": "אֲהַלְ֒לָה יְהֹוָה בְּחַיָּי"}, {"kind": "text", "text": "אֲזַמְּ֒רָה לֵאלֹהַי בְּעוֹדִי:"}, {"kind": "text", "text": "אַל־תִּבְטְחוּ בִנְ֒דִיבִים"}, {"kind": "text", "text": "בְּבֶן־אָדָם שֶׁאֵין לוֹ תְשׁוּעָה:"}, {"kind": "text", "text": "תֵּצֵא רוּחוֹ"}, {"kind": "text", "text": "יָשֻׁב לְאַדְ֒מָתוֹ"}, {"kind": "text", "text": "בַּיּוֹם הַהוּא אָבְ֒דוּ עֶשְׁתֹּנֹתָיו:"}, {"kind": "text", "text": "אַשְׁרֵי"}, {"kind": "text", "text": "שֶׁאֵל יַעֲקֹב בְּעֶזְרוֹ,"}, {"kind": "text", "text": "שִׂבְרוֹ עַל־יְהֹוָה אֱלֹהָיו:"}, {"kind": "text", "text": "עֹשֶׂה שָׁמַֽיִם וָאָֽרֶץ"}, {"kind": "text", "text": "אֶת־הַיָּם וְאֶת־כָּל־אֲשֶׁר־בָּם,"}, {"kind": "text", "text": "הַשֹּׁמֵר אֱמֶת לְעוֹלָם:"}, {"kind": "text", "text": "עֹשֶׂה מִשְׁפָּט לַעֲשׁוּקִים"}, {"kind": "text", "text": "נֹתֵן לֶֽחֶם לָרְ֒עֵבִים"}, {"kind": "text", "text": "יְהֹוָה מַתִּיר אֲסוּרִים:"}, {"kind": "text", "text": "יְהֹוָה פֹּקֵֽחַ עִוְ֒רִים"}, {"kind": "text", "text": "יְהֹוָה זֹקֵף כְּפוּפִים"}, {"kind": "text", "text": "יְהֹוָה אֹהֵב צַדִּיקִים:"}, {"kind": "text", "text": "יְהֹוָה שֹׁמֵר אֶת־גֵּרִים"}, {"kind": "text", "text": "יָתוֹם וְאַלְמָנָה"}, {"kind": "text", "text": "יְעוֹדֵד"}, {"kind": "text", "text": "וְדֶֽרֶךְ רְשָׁעִים יְעַוֵּת:"}, {"kind": "text", "text": "❖יִמְלֹךְ יְהֹוָה לְעוֹלָם"}, {"kind": "text", "text": "אֱלֹהַֽיִךְ צִיּוֹן לְדֹר וָדֹר"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ:"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ"}, {"kind": "text", "text": "כִּי־טוֹב זַמְּ֒רָה אֱלֹהֵֽינוּ,"}, {"kind": "text", "text": "כִּי־נָעִים נָאוָה תְהִלָּה:"}, {"kind": "text", "text": "בּוֹנֵה יְרוּשָׁלַֽםִ יְהֹוָה"}, {"kind": "text", "text": "נִדְחֵי יִשְׂרָאֵל יְכַנֵּס:"}, {"kind": "text", "text": "הָרוֹפֵא לִשְׁ֒בֽוּרֵי לֵב"}, {"kind": "text", "text": "וּמְ֒חַבֵּשׁ לְעַצְּ֒בוֹתָם:"}, {"kind": "text", "text": "מוֹנֶה מִסְפָּר לַכּוֹכָבִים"}, {"kind": "text", "text": "לְכֻלָּם שֵׁמוֹת יִקְרָא:"}, {"kind": "text", "text": "גָּדוֹל אֲדוֹנֵֽינוּ וְרַב־כֹּֽחַ"}, {"kind": "text", "text": "לִתְבוּנָתוֹ אֵין מִסְפָּר:"}, {"kind": "text", "text": "מְעוֹדֵד עֲנָוִים יְהֹוָה"}, {"kind": "text", "text": "מַשְׁפִּיל רְשָׁעִים עֲדֵי־אָֽרֶץ:"}, {"kind": "text", "text": "עֱנוּ לַיהֹוָה בְּתוֹדָה"}, {"kind": "text", "text": "זַמְּ֒רוּ לֵאלֹהֵֽינוּ בְכִנּוֹר:"}, {"kind": "text", "text": "הַמְ֒כַסֶּה שָׁמַֽיִם בְּעָבִים"}, {"kind": "text", "text": "הַמֵּכִין לָאָֽרֶץ מָטָר"}, {"kind": "text", "text": "הַמַּצְמִֽיחַ הָרִים חָצִיר:"}, {"kind": "text", "text": "נוֹתֵן לִבְ֒הֵמָה לַחְמָהּ"}, {"kind": "text", "text": "לִבְ֒נֵי עֹרֵב אֲשֶׁר יִקְרָֽאוּ:"}, {"kind": "text", "text": "לֹא בִגְ֒בוּרַת הַסּוּס יֶחְפָּץ"}, {"kind": "text", "text": "לֹא בְשׁוֹקֵי הָאִישׁ יִרְצֶה:"}, {"kind": "text", "text": "רוֹצֶה יְהֹוָה אֶת־יְרֵאָיו"}, {"kind": "text", "text": "אֶת־הַמְ֒יַחֲלִים לְחַסְדּוֹ:"}, {"kind": "text", "text": "שַׁבְּ֒חִי יְרוּשָׁלַֽםִ אֶת יְהֹוָה"}, {"kind": "text", "text": "הַלְ֒לִי אֱלֹהַֽיִךְ צִיּוֹן:"}, {"kind": "text", "text": "כִּי־חִזַּק בְּרִיחֵי שְׁעָרָֽיִךְ"}, {"kind": "text", "text": "בֵּרַךְ בָּנַֽיִךְ בְּקִרְבֵּךְ:"}, {"kind": "text", "text": "הַשָּׂם־גְּבוּלֵךְ שָׁלוֹם"}, {"kind": "text", "text": "חֵֽלֶב חִטִּים יַשְׂבִּיעֵךְ:"}, {"kind": "text", "text": "הַשֹּׁלֵֽחַ אִמְרָתוֹ אָֽרֶץ"}, {"kind": "text", "text": "עַד־מְהֵרָה יָרוּץ דְּבָרוֹ:"}, {"kind": "text", "text": "הַנֹּתֵן שֶֽׁלֶג כַּצָּֽמֶר"}, {"kind": "text", "text": "כְּפוֹר כָּאֵֽפֶר יְפַזֵּר:"}, {"kind": "text", "text": "מַשְׁלִיךְ קַרְחוֹ כְפִתִּים"}, {"kind": "text", "text": "לִפְנֵי קָרָתוֹ מִי יַעֲמֹד:"}, {"kind": "text", "text": "יִשְׁלַח דְּבָרוֹ וְיַמְסֵם"}, {"kind": "text", "text": "יַשֵּׁב רוּחוֹ יִזְּ֒לוּ־מָֽיִם:"}, {"kind": "text", "text": "❖מַגִּיד דְּבָרָיו לְיַעֲקֹב"}, {"kind": "text", "text": "חֻקָּיו וּמִשְׁפָּטָיו לְיִשְׂרָאֵל:"}, {"kind": "text", "text": "לֹא עָֽשָׂה כֵן לְכָל־גּוֹי"}, {"kind": "text", "text": "וּמִשְׁפָּטִים בַּל־יְדָעוּם"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ:"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ"}, {"kind": "text", "text": "הַלְ֒לוּ אֶת־יְהֹוָה מִן הַשָּׁמַֽיִם"}, {"kind": "text", "text": "הַלְ֒לֽוּהוּ בַּמְּ֒רוֹמִים:"}, {"kind": "text", "text": "הַלְ֒לֽוּהוּ כָּל־מַלְאָכָיו"}, {"kind": "text", "text": "הַלְ֒לֽוּהוּ כָּל־צְבָאָיו:"}, {"kind": "text", "text": "הַלְ֒לֽוּהוּ שֶֽׁמֶשׁ וְיָרֵֽחַ"}, {"kind": "text", "text": "הַלְ֒לֽוּהוּ כָּל־כּֽוֹכְ֒בֵי אוֹר:"}, {"kind": "text", "text": "הַלְ֒לֽוּהוּ שְׁמֵי הַשָּׁמָֽיִם"}, {"kind": "text", "text": "וְהַמַּֽיִם אֲשֶׁר מֵעַל הַשָּׁמָֽיִם:"}, {"kind": "text", "text": "יְהַלְ֒לוּ אֶת־שֵׁם יְהֹוָה"}, {"kind": "text", "text": "כִּי הוּא צִוָּה וְנִבְרָֽאוּ:"}, {"kind": "text", "text": "וַיַּעֲמִידֵם לָעַד"}, {"kind": "text", "text": "לְעוֹלָם"}, {"kind": "text", "text": "חָק־נָתַן וְלֹא יַעֲבוֹר:"}, {"kind": "text", "text": "הַלְ֒לוּ אֶת־יְהֹוָה מִן־הָאָֽרֶץ"}, {"kind": "text", "text": "תַּנִּינִים"}, {"kind": "text", "text": "וְכָל־תְּהֹמוֹת:"}, {"kind": "text", "text": "אֵשׁ וּבָרָד שֶֽׁלֶג וְקִיטוֹר"}, {"kind": "text", "text": "רֽוּחַ סְעָרָה עֹשָׂה דְבָרוֹ:"}, {"kind": "text", "text": "הֶהָרִים וְכָל־גְּבָעוֹת"}, {"kind": "text", "text": "עֵץ פְּרִי וְכָל־אֲרָזִים:"}, {"kind": "text", "text": "הַחַיָּה וְכָל־בְּהֵמָה"}, {"kind": "text", "text": "רֶֽמֶשׂ וְצִפּוֹר כָּנָף:"}, {"kind": "text", "text": "מַלְ֒כֵי־אֶֽרֶץ וְכָל־לְאֻמִּים"}, {"kind": "text", "text": "שָׂרִים וְכָל־שֹׁפְטֵי אָֽרֶץ:"}, {"kind": "text", "text": "בַּחוּרִים וְגַם־בְּתוּלוֹת"}, {"kind": "text", "text": "זְקֵנִים עִם־נְעָרִים:"}, {"kind": "text", "text": "יְהַלְ֒לוּ אֶת־שֵׁם יְהֹוָה"}, {"kind": "text", "text": "כִּי־נִשְׂגָּב שְׁמוֹ לְבַדּוֹ"}, {"kind": "text", "text": "הוֹדוֹ עַל־אֶֽרֶץ וְשָׁמָֽיִם:"}, {"kind": "text", "text": "❖וַיָּֽרֶם קֶֽרֶן לְעַמּוֹ"}, {"kind": "text", "text": "תְּהִלָּה לְכָל־חֲסִידָיו"}, {"kind": "text", "text": "לִבְ֒נֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "עַם קְרֹבוֹ"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ:"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ"}, {"kind": "text", "text": "שִֽׁירוּ לַיהֹוָה שִׁיר חָדָשׁ"}, {"kind": "text", "text": "תְּהִלָּתוֹ בִּקְ֒הַל חֲסִידִים:"}, {"kind": "text", "text": "יִשְׂמַח יִשְׂרָאֵל בְּעֹשָׂיו"}, {"kind": "text", "text": "בְּנֵי־צִיּוֹן יָגִֽילוּ בְמַלְכָּם:"}, {"kind": "text", "text": "יְהַלְ֒לוּ שְׁמוֹ בְמָחוֹל"}, {"kind": "text", "text": "בְּתֹף וְכִנּוֹר"}, {"kind": "text", "text": "יְזַמְּ֒רוּ־לוֹ:"}, {"kind": "text", "text": "כִּי־רוֹצֶה יְהֹוָה בְּעַמּוֹ"}, {"kind": "text", "text": "יְפָאֵר עֲנָוִים בִּישׁוּעָה:"}, {"kind": "text", "text": "יַעְלְזוּ חֲסִידִים בְּכָבוֹד"}, {"kind": "text", "text": "יְרַנְ֒נוּ עַל־מִשְׁכְּבוֹתָם:"}, {"kind": "text", "text": "רוֹמְ֒מוֹת אֵל בִּגְ֒רוֹנָם"}, {"kind": "text", "text": "וְחֶֽרֶב פִּיפִיּוֹת בְּיָדָם:"}, {"kind": "text", "text": "לַעֲשׂוֹת נְקָמָה בַגּוֹיִם"}, {"kind": "text", "text": "תּוֹכֵחוֹת בַּלְ֒אֻמִּים:"}, {"kind": "text", "text": "❖לֶאְסֹר מַלְ֒כֵיהֶם בְּזִקִּים"}, {"kind": "text", "text": "וְנִכְבְּדֵיהֶם בְּכַבְ֒לֵי בַרְזֶל:"}, {"kind": "text", "text": "לַעֲשׂוֹת בָּהֶם"}, {"kind": "text", "text": "מִשְׁפָּט כָּתוּב"}, {"kind": "text", "text": "הָדָר הוּא לְכָל־חֲסִידָיו"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ:"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ"}, {"kind": "text", "text": "הַֽלְ֒לוּ־אֵל בְּקָדְשׁוֹ"}, {"kind": "text", "text": "הַלְ֒לֽוּהוּ"}, {"kind": "text", "text": "בִּרְ֒קִֽיעַ עֻזּוֹ:"}, {"kind": "text", "text": "הַלְ֒לֽוּהוּ בִּגְבוּרֹתָיו"}, {"kind": "text", "text": "הַלְ֒לֽוּהוּ"}, {"kind": "text", "text": "כְּרֹב גֻּדְלוֹ:"}, {"kind": "text", "text": "הַלְ֒לֽוּהוּ בְּתֵֽקַע שׁוֹפָר"}, {"kind": "text", "text": "הַלְ֒לֽוּהוּ בְּנֵֽבֶל וְכִנּוֹר:"}, {"kind": "text", "text": "הַלְ֒לֽוּהוּ בְּתֹף וּמָחוֹל"}, {"kind": "text", "text": "הַלְ֒לֽוּהוּ"}, {"kind": "text", "text": "בְּמִנִּים וְעֻגָב:"}, {"kind": "text", "text": "הַלְ֒לֽוּהוּ בְצִלְצְלֵי־שָֽׁמַע"}, {"kind": "text", "text": "הַלְ֒לֽוּהוּ בְּצִלְצְלֵי תְרוּעָה:"}, {"kind": "text", "text": "כֹּל הַנְּ֒שָׁמָה תְּהַלֵּל יָהּ"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ:"}, {"kind": "text", "text": "❖כֹּל הַנְּ֒שָׁמָה תְּהַלֵּל יָהּ"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ:"}, {"kind": "text", "text": "בָּרוּךְ יְהֹוָה לְעוֹלָם"}, {"kind": "text", "text": "אָמֵן וְאָמֵן:"}, {"kind": "text", "text": "בָּרוּךְ יְהֹוָה מִצִּיּוֹן"}, {"kind": "text", "text": "שֹׁכֵן יְרוּשָׁלָֽםִ"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ:"}, {"kind": "text", "text": "בָּרוּךְ יְהֹוָה אֱלֹהִים"}, {"kind": "text", "text": "אֱלֹהֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "עֹשֵׂה נִפְלָאוֹת לְבַדּוֹ:"}, {"kind": "text", "text": "❖וּבָרוּךְ שֵׁם כְּבוֹדוֹ לְעוֹלָם"}, {"kind": "text", "text": "וְיִמָּלֵא כְבוֹדוֹ אֶת־כָּל־הָאָֽרֶץ"}, {"kind": "text", "text": "אָמֵן וְאָמֵן:"}, {"kind": "text", "text": "וַיְבָֽרֶךְ דָּוִיד אֶת־יְהֹוָה"}, {"kind": "text", "text": "לְעֵינֵי כָּל־הַקָּהָל"}, {"kind": "text", "text": "וַיֹּֽאמֶר דָּוִיד"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵי יִשְׂרָאֵל אָבִֽינוּ,"}, {"kind": "text", "text": "מֵעוֹלָם וְעַד־עוֹלָם:"}, {"kind": "text", "text": "לְךָ יְהֹוָה"}, {"kind": "text", "text": "הַגְּ֒דֻלָּה וְהַגְּ֒בוּרָה וְהַתִּפְאֶֽרֶת"}, {"kind": "text", "text": "וְהַנֵּֽצַח וְהַהוֹד"}, {"kind": "text", "text": "כִּי־כֹל בַּשָּׁמַֽיִם וּבָאָֽרֶץ"}, {"kind": "text", "text": "לְךָ יְהֹוָה הַמַּמְלָכָה"}, {"kind": "text", "text": "וְהַמִּתְנַשֵּׂא"}, {"kind": "text", "text": "לְכֹל לְרֹאשׁ:"}, {"kind": "text", "text": "וְהָעֽשֶׁר וְהַכָּבוֹד מִלְּ֒פָנֶֽיךָ"}, {"kind": "text", "text": "וְאַתָּה מוֹשֵׁל בַּכֹּל,"}, {"kind": "text", "text": "וּבְיָדְ֒ךָ כֹּֽחַ וּגְ֒בוּרָה,"}, {"kind": "text", "text": "וּבְ֒יָדְ֒ךָ"}, {"kind": "text", "text": "לְגַדֵּל וּלְ֒חַזֵּק לַכֹּל:"}, {"kind": "text", "text": "וְעַתָּה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "מוֹדִים אֲנַֽחְנוּ לָךְ"}, {"kind": "text", "text": "וּמְ֒הַלְ֒לִים לְשֵׁם תִּפְאַרְתֶּֽךָ:"}, {"kind": "text", "text": "וִיבָרְ֒כוּ שֵׁם כְּבֹדֶֽךָ"}, {"kind": "text", "text": "וּמְרוֹמַם"}, {"kind": "text", "text": "עַל כָּל בְּרָכָה וּתְהִלָּה:"}, {"kind": "text", "text": "אַתָּה־הוּא יְהֹוָה לְבַדֶּֽךָ,"}, {"kind": "text", "text": "אַתָּה עָשִֽׂיתָ אֶת־הַשָּׁמַֽיִם"}, {"kind": "text", "text": "שְׁמֵי הַשָּׁמַֽיִם וְכָל־צְבָאָם,"}, {"kind": "text", "text": "הָאָֽרֶץ וְכָל־אֲשֶׁר עָלֶֽיהָ"}, {"kind": "text", "text": "הַיַּמִּים וְכָל־אֲשֶׁר בָּהֶם,"}, {"kind": "text", "text": "וְאַתָּה מְחַיֶּה אֶת־כֻּלָּם"}, {"kind": "text", "text": "וּצְ֒בָא הַשָּׁמַֽיִם לְךָ מִשְׁתַּחֲוִים:"}, {"kind": "text", "text": "❖אַתָּה הוּא יְהֹוָה הָאֱלֹהִים"}, {"kind": "text", "text": "אֲשֶׁר בָּחַֽרְתָּ בְּאַבְרָם"}, {"kind": "text", "text": "וְהוֹצֵאתוֹ מֵאוּר כַּשְׂדִּים"}, {"kind": "text", "text": "וְשַֽׂמְתָּ שְׁמוֹ אַבְרָהָם:"}, {"kind": "text", "text": "וּמָצָֽאתָ אֶת־לְבָבוֹ"}, {"kind": "text", "text": "נֶאֱמָן לְפָנֶֽיךָ"}, {"kind": "text", "text": "וְכָרוֹת עִמּוֹ הַבְּ֒רִית"}, {"kind": "text", "text": "לָתֵת אֶת־אֶֽרֶץ הַכְּ֒נַעֲנִי"}, {"kind": "text", "text": "הַחִתִּי הָאֱמֹרִי וְהַפְּ֒רִזִּי"}, {"kind": "text", "text": "וְהַיְ֒בוּסִי וְהַגִּרְגָּשִׁי"}, {"kind": "text", "text": "לָתֵת לְזַרְעוֹ"}, {"kind": "text", "text": "וַתָּֽקֶם אֶת־דְּבָרֶֽיךָ"}, {"kind": "text", "text": "כִּי צַדִּיק אָֽתָּה:"}, {"kind": "text", "text": "וַתֵּֽרֶא אֶת־עֳנִי"}, {"kind": "text", "text": "אֲבֹתֵֽינוּ בְּמִצְרָֽיִם"}, {"kind": "text", "text": "וְאֶת־זַעֲקָתָם שָׁמַֽעְתָּ"}, {"kind": "text", "text": "עַל־יַם־סוּף:"}, {"kind": "text", "text": "וַתִּתֵּן אֹתֹת וּמֹפְ֒תִים"}, {"kind": "text", "text": "בְּפַרְעֹה וּבְ֒כָל־עֲבָדָיו"}, {"kind": "text", "text": "וּבְ֒כָל־עַם אַרְצוֹ"}, {"kind": "text", "text": "כִּי יָדַֽעְתָּ"}, {"kind": "text", "text": "כִּי הֵזִֽידוּ עֲלֵיהֶם"}, {"kind": "text", "text": "וַתַּֽעַשׂ־לְךָ שֵׁם"}, {"kind": "text", "text": "כְּהַיּוֹם הַזֶּה:"}, {"kind": "text", "text": "❖וְהַיָּם בָּקַֽעְתָּ לִפְ֒נֵיהֶם"}, {"kind": "text", "text": "וַיַּעַבְ֒רוּ בְתוֹךְ־הַיָּם"}, {"kind": "text", "text": "בַּיַּבָּשָׁה"}, {"kind": "text", "text": "וְאֶת־רֹדְ֒פֵיהֶם"}, {"kind": "text", "text": "הִשְׁלַֽכְתָּ בִמְצוֹלֹת"}, {"kind": "text", "text": "כְּמוֹ־אֶֽבֶן בְּמַֽיִם עַזִּים:"}, {"kind": "header", "text": "שירת הים"}, {"kind": "text", "text": "וַיּֽוֹשַׁע יְהֹוָה בַּיּוֹם הַהוּא"}, {"kind": "text", "text": "אֶת־יִשְׂרָאֵל מִיַּד מִצְרָֽיִם"}, {"kind": "text", "text": "וַיַּרְא יִשְׂרָאֵל אֶת־מִצְרַֽיִם"}, {"kind": "text", "text": "מֵת עַל־שְׂפַת הַיָּם:"}, {"kind": "text", "text": "❖וַיַּרְא יִשְׂרָאֵל"}, {"kind": "text", "text": "אֶת־הַיָּד הַגְּ֒דֹלָה"}, {"kind": "text", "text": "אֲשֶׁר עָשָׂה יְהֹוָה בְּמִצְרַֽיִם"}, {"kind": "text", "text": "וַיִּירְ֒אוּ הָעָם אֶת יְהֹוָה"}, {"kind": "text", "text": "וַיַּאֲמִֽינוּ בַּיהֹוָה"}, {"kind": "text", "text": "וּבְ֒משֶׁה עַבְדּוֹ:"}, {"kind": "text", "text": "אָז יָשִׁיר משֶׁה וּבְ֒נֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "אֶת־הַשִּׁירָה הַזֹּאת לַיהֹוָה"}, {"kind": "text", "text": "וַיֹּאמְ֒רוּ לֵאמֹר"}, {"kind": "text", "text": "אָשִֽׁירָה לַיהֹוָה כִּי־גָאֹה גָּאָה"}, {"kind": "text", "text": "סוּס וְרֹכְ֒בוֹ רָמָה בַיָּם:"}, {"kind": "text", "text": "עָזִּי וְזִמְרָת יָהּ"}, {"kind": "text", "text": "וַיְ֒הִי־לִי לִישׁוּעָה"}, {"kind": "text", "text": "זֶה אֵלִי וְאַנְוֵֽהוּ"}, {"kind": "text", "text": "אֱלֹהֵי אָבִי וַאֲרֹמְ֒מֶֽנְהוּ:"}, {"kind": "text", "text": "יְהֹוָה אִישׁ מִלְחָמָה"}, {"kind": "text", "text": "יְהֹוָה שְׁמוֹ:"}, {"kind": "text", "text": "מַרְכְּבֹת פַּרְעֹה וְחֵילוֹ"}, {"kind": "text", "text": "יָרָה בַיָּם"}, {"kind": "text", "text": "וּמִבְחַר שָׁלִשָׁיו טֻבְּ֒עוּ"}, {"kind": "text", "text": "בְיַם־סוּף:"}, {"kind": "text", "text": "תְּהֹמֹת יְכַסְ֒יֻֽמוּ"}, {"kind": "text", "text": "יָרְ֒דוּ בִמְצוֹלֹת כְּמוֹ־אָֽבֶן:"}, {"kind": "text", "text": "יְמִינְ֒ךָ יְהֹוָה"}, {"kind": "text", "text": "נֶאְדָּרִי בַּכֹּֽחַ"}, {"kind": "text", "text": "יְמִֽינְ֒ךָ יְהֹוָה תִּרְעַץ אוֹיֵב:"}, {"kind": "text", "text": "וּבְ֒רֹב גְּאוֹנְ֒ךָ"}, {"kind": "text", "text": "תַּהֲרֹס קָמֶֽיךָ"}, {"kind": "text", "text": "תְּשַׁלַּח חֲרֹנְ֒ךָ"}, {"kind": "text", "text": "יֹֽאכְ֒לֵמוֹ כַּקַּשׁ:"}, {"kind": "text", "text": "וּבְ֒רֽוּחַ אַפֶּֽיךָ"}, {"kind": "text", "text": "נֶֽעֶרְ֒מוּ מַֽיִם"}, {"kind": "text", "text": "נִצְּ֒בוּ כְמוֹ־נֵד נֹזְ֒לִים"}, {"kind": "text", "text": "קָפְ֒אוּ תְהֹמֹת"}, {"kind": "text", "text": "בְּלֶב־יָם:"}, {"kind": "text", "text": "אָמַר אוֹיֵב"}, {"kind": "text", "text": "אֶרְדֹּף אַשִּׂיג"}, {"kind": "text", "text": "אֲחַלֵּק שָׁלָל תִּמְלָאֵֽמוֹ נַפְשִׁי"}, {"kind": "text", "text": "אָרִיק חַרְבִּי"}, {"kind": "text", "text": "תּוֹרִישֵֽׁמוֹ יָדִי:"}, {"kind": "text", "text": "נָשַֽׁפְתָּ בְרוּחֲךָ"}, {"kind": "text", "text": "כִּסָּֽמוֹ יָם"}, {"kind": "text", "text": "צָלֲלוּ כַּעוֹפֶֽרֶת בְּמַֽיִם אַדִּירִים:"}, {"kind": "text", "text": "מִי־כָמֹֽכָה בָּאֵלִם יְהֹוָה"}, {"kind": "text", "text": "מִי כָּמֹֽכָה"}, {"kind": "text", "text": "נֶאְדָּר בַּקֹּֽדֶשׁ"}, {"kind": "text", "text": "נוֹרָא תְהִלֹּת עֹֽשֵׂה־פֶֽלֶא:"}, {"kind": "text", "text": "נָטִֽיתָ יְמִינְ֒ךָ"}, {"kind": "text", "text": "תִּבְלָעֵֽמוֹ אָֽרֶץ:"}, {"kind": "text", "text": "נָחִֽיתָ בְחַסְדְּךָ"}, {"kind": "text", "text": "עַם־זוּ גָּאָֽלְתָּ"}, {"kind": "text", "text": "נֵהַֽלְתָּ בְעָזְּ֒ךָ"}, {"kind": "text", "text": "אֶל־נְוֵה קָדְשֶֽׁךָ:"}, {"kind": "text", "text": "שָֽׁמְ֒עוּ עַמִּים יִרְגָּזוּן"}, {"kind": "text", "text": "חִיל אָחַז"}, {"kind": "text", "text": "ישְׁ֒בֵי פְּלָֽשֶׁת:"}, {"kind": "text", "text": "אָז נִבְהֲלוּ אַלּוּפֵי אֱדוֹם"}, {"kind": "text", "text": "אֵילֵי מוֹאָב"}, {"kind": "text", "text": "יֹֽאחֲזֵֽמוֹ רָֽעַד"}, {"kind": "text", "text": "נָמֹֽגוּ כֹּל ישְׁ֒בֵי כְנָֽעַן:"}, {"kind": "text", "text": "תִּפֹּל עֲלֵיהֶם אֵימָֽתָה וָפַֽחַד"}, {"kind": "text", "text": "בִּגְ֒דֹל זְרוֹעֲךָ"}, {"kind": "text", "text": "יִדְּ֒מוּ כָּאָֽבֶן"}, {"kind": "text", "text": "עַד־יַֽעֲבֹר עַמְּ֒ךָ יְהֹוָה"}, {"kind": "text", "text": "עַד־יַֽעֲבֹר"}, {"kind": "text", "text": "עַם־זוּ קָנִֽיתָ:"}, {"kind": "text", "text": "תְּבִאֵֽמוֹ וְתִטָּעֵֽמוֹ"}, {"kind": "text", "text": "בְּהַר נַחֲלָתְ֒ךָ"}, {"kind": "text", "text": "מָכוֹן לְשִׁבְתְּ֒ךָ"}, {"kind": "text", "text": "פָּעַֽלְתָּ יְהֹוָה"}, {"kind": "text", "text": "מִקְּ֒דָשׁ אֲדֹנָי"}, {"kind": "text", "text": "כּוֹנְ֒נוּ יָדֶֽיךָ:"}, {"kind": "text", "text": "יְהֹוָה יִמְלֹךְ לְעֹלָם וָעֶד:"}, {"kind": "text", "text": "יְהֹוָה יִמְלֹךְ לְעֹלָם וָעֶד:"}, {"kind": "text", "text": "יְהֹוָה מַלְ֒כוּתֵהּ קָאֵים"}, {"kind": "text", "text": "לְעָלַם וּלְ֒עָלְ֒מֵי עָלְ֒מַיָּא:"}, {"kind": "text", "text": "כִּי בָא סוּס פַּרְעֹה בְּרִכְבּוֹ"}, {"kind": "text", "text": "וּבְ֒פָרָשָׁיו בַּיָּם"}, {"kind": "text", "text": "וַיָּֽשֶׁב יְהֹוָה עֲלֵהֶם"}, {"kind": "text", "text": "אֶת־מֵי הַיָּם"}, {"kind": "text", "text": "וּבְנֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "הָלְ֒כוּ בַיַּבָּשָׁה בְּתוֹךְ הַיָּֽם:"}, {"kind": "text", "text": "כִּי לַיהֹוָה הַמְּ֒לוּכָה"}, {"kind": "text", "text": "וּמשֵׁל בַּגּוֹיִם:"}, {"kind": "text", "text": "❖וְעָלוּ מוֹשִׁעִים בְּהַר צִיּוֹן"}, {"kind": "text", "text": "לִשְׁפֹּט אֶת־הַר עֵשָׂו,"}, {"kind": "text", "text": "וְהָיְ֒תָה לַיהֹוָה הַמְּ֒לוּכָה:"}, {"kind": "text", "text": "וְהָיָה יְהֹוָה לְמֶֽלֶךְ"}, {"kind": "text", "text": "עַל־כָּל הָאָֽרֶץ"}, {"kind": "text", "text": "בַּיּוֹם הַהוּא"}, {"kind": "text", "text": "יִהְיֶה יְהֹוָה אֶחָד וּשְׁמוֹ אֶחָד:"}, {"kind": "header", "text": "נשמת"}, {"kind": "text", "text": "נִשְׁמַת כָּל חַי"}, {"kind": "text", "text": "תְּבָרֵךְ אֶת שִׁמְךָ יְהֹוָה אֱלֹהֵֽינוּ."}, {"kind": "text", "text": "וְרֽוּחַ כָּל בָּשָׂר"}, {"kind": "text", "text": "תְּפָאֵר וּתְרוֹמֵם"}, {"kind": "text", "text": "זִכְרְ֒ךָ מַלְכֵּֽנוּ תָּמִיד."}, {"kind": "text", "text": "מִן הָעוֹלָם וְעַד הָעוֹלָם"}, {"kind": "text", "text": "אַתָּה אֵל."}, {"kind": "text", "text": "וּמִבַּלְעָדֶֽיךָ"}, {"kind": "text", "text": "אֵין לָנוּ מֶֽלֶךְ גּוֹאֵל וּמוֹשִֽׁיעַ."}, {"kind": "text", "text": "פּוֹדֶה וּמַצִּיל וּמְפַרְנֵס"}, {"kind": "text", "text": "וְעוֹנֶה וּמְרַחֵם"}, {"kind": "text", "text": "בְּכָל עֵת צָרָה וְצוּקָה."}, {"kind": "text", "text": "אֵין לָנוּ מֶֽלֶךְ עוֹזֵר וְסוֹמֵך"}, {"kind": "text", "text": "אֶלָּא אָֽתָּה."}, {"kind": "text", "text": "אֱלֹהֵי הָרִאשׁוֹנִים וְהָאַחֲרוֹנִים."}, {"kind": "text", "text": "אֱלֽוֹהַּ כָּל בְּרִיּוֹת."}, {"kind": "text", "text": "אֲדוֹן כָּל תּוֹלָדוֹת."}, {"kind": "text", "text": "הַמְּ֒הֻלָּל בְּרֹב הַתִּשְׁבָּחוֹת."}, {"kind": "text", "text": "הַמְ֒נַהֵג עוֹלָמוֹ בְּחֶֽסֶד"}, {"kind": "text", "text": "וּבְרִיּוֹתָיו בְּרַחֲמִים."}, {"kind": "text", "text": "וַיהוֹה הִנֵּה לֹא יָנוּם וְלֹא יִישָׁן."}, {"kind": "text", "text": "הַמְּ֒עוֹרֵר יְשֵׁנִים."}, {"kind": "text", "text": "וְהַמֵּקִיץ נִרְדָּמִים."}, {"kind": "text", "text": "מְחַיֵּה מֵתִים."}, {"kind": "text", "text": "וְרוֹפֵא חוֹלִים."}, {"kind": "text", "text": "פּוֹקֵחַ עִוְרִים."}, {"kind": "text", "text": "וְהַמֵּשִֽׂיחַ אִלְּ֒מִים."}, {"kind": "text", "text": "וְהַמַּתִּיר אֲסוּרִים."}, {"kind": "text", "text": "וְהַסּוֹמֵךְ נוֹפְ֒לִים."}, {"kind": "text", "text": "וְהַזּוֹקֵף כְּפוּפִים"}, {"kind": "text", "text": "וְהַמְ֒פַעֲנֵחַ נֶעְלָמִים."}, {"kind": "text", "text": "לְךָ לְבַדְּ֒ךָ אֲנַֽחְנוּ מוֹדִים."}, {"kind": "text", "text": "אִלּוּ פִֽינוּ מָלֵא שִׁירָה"}, {"kind": "text", "text": "כַּיָּם."}, {"kind": "text", "text": "וּלְשׁוֹנֵֽנוּ רִנָּה"}, {"kind": "text", "text": "כַּהֲמוֹן גַּלָּיו."}, {"kind": "text", "text": "וְשִׂפְתוֹתֵֽינוּ שֶֽׁבַח"}, {"kind": "text", "text": "כְּמֶרְחֲבֵי רָקִֽיעַ."}, {"kind": "text", "text": "וְעֵינֵֽינוּ מְאִירוֹת"}, {"kind": "text", "text": "כַּשֶּֽׁמֶשׁ וְכַיָּרֵֽחַ."}, {"kind": "text", "text": "וְיָדֵֽינוּ פְרוּשׂוֹת"}, {"kind": "text", "text": "כְּנִשְׁרֵי שָׁמָֽיִם."}, {"kind": "text", "text": "וְרַגְלֵֽינוּ קַלּוֹת כָּאַיָּלוֹת."}, {"kind": "text", "text": "אֵין אֲנַֽחְנוּ מַסְפִּיקִים"}, {"kind": "text", "text": "לְהוֹדוֹת לְךָ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וֵאלֹהֵי אֲבוֹתֵֽינוּ."}, {"kind": "text", "text": "וּלְבָרֵךְ אֶת שְׁמֶֽךָ מַלְכֵּֽנוּ"}, {"kind": "text", "text": "עַל אַחַת מֵאָֽלֶף"}, {"kind": "text", "text": "אֶֽלֶף אַלְפֵי אֲלָפִים"}, {"kind": "text", "text": "וְרִבֵּי רְבָבוֹת פְּעָמִים."}, {"kind": "text", "text": "הַטּוֹבוֹת נִסִּים וְנִפְלָאוֹת"}, {"kind": "text", "text": "שֶׁעָשִֽׂיתָ עִם אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "וְעִמָּֽנוּ."}, {"kind": "text", "text": "מִמִּצְרַֽיִם גְּאַלְתָּֽנוּ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ."}, {"kind": "text", "text": "וּמִבֵּית עֲבָדִים פְּדִיתָֽנוּ."}, {"kind": "text", "text": "בְּרָעָב זַנְתָּֽנוּ."}, {"kind": "text", "text": "וּבְשָׂבָע כִּלְכַּלְתָּֽנוּ."}, {"kind": "text", "text": "מֵחֶֽרֶב הִצַּלְתָּֽנוּ."}, {"kind": "text", "text": "וּמִדֶּֽבֶר מִלַּטְתָּֽנוּ."}, {"kind": "text", "text": "וּמֵחֳלָיִם רָעִים וְרַבִּים וְנֶאֱמָנִים"}, {"kind": "text", "text": "דִּלִּיתָֽנוּ:"}, {"kind": "text", "text": "עַד הֵֽנָּה"}, {"kind": "text", "text": "עֲזָרֽוּנוּ רַחֲמֶֽיךָ."}, {"kind": "text", "text": "וְלֹא עֲזָבֽוּנוּ חֲסָדֶֽיךָ."}, {"kind": "text", "text": "וְאַל תִּטְּ֒שֵֽׁנוּ יְהֹוָה אֱלֹהֵֽינוּ."}, {"kind": "text", "text": "לָנֶֽצַח:"}, {"kind": "text", "text": "עַל כֵּן"}, {"kind": "text", "text": "אֵבָרִים שֶׁפִּלַּֽגְתָּ בָּֽנוּ."}, {"kind": "text", "text": "וְרֽוּחַ וּנְשָׁמָה"}, {"kind": "text", "text": "שֶׁנָּפַֽחְתָּ בְּאַפֵּֽינוּ."}, {"kind": "text", "text": "וְלָשׁוֹן אֲשֶׁר שַֽׂמְתָּ בְּפִֽינוּ."}, {"kind": "text", "text": "הֵן הֵם יוֹדוּ וִיבָרְ֒כוּ"}, {"kind": "text", "text": "וִישַׁבְּ֒חוּ וִיפָאֲרוּ"}, {"kind": "text", "text": "וִישׁוֹרְ֒רוּ וִירוֹמְ֒מוּ"}, {"kind": "text", "text": "וְיַעֲרִֽיצוּ"}, {"kind": "text", "text": "וְיַקְדִּֽישׁוּ וְיַמְלִֽיכוּ"}, {"kind": "text", "text": "אֶת שִׁמְךָ מַלְכֵּֽנוּ תָּמִיד."}, {"kind": "text", "text": "כִּי כָל פֶּה לְךָ יוֹדֶה."}, {"kind": "text", "text": "וְכָל לָשׁוֹן"}, {"kind": "text", "text": "לְךָ תִשָּׁבַע."}, {"kind": "text", "text": "וְכָל עַֽיִן לְךָ תְּצַפֶּה."}, {"kind": "text", "text": "וְכָל בֶּֽרֶךְ לְךָ תִכְרַע."}, {"kind": "text", "text": "וְכָל קוֹמָה"}, {"kind": "text", "text": "לְפָנֶֽיךָ תִשְׁתַּחֲוֶה."}, {"kind": "text", "text": "וְכָל הַלְבָבוֹת יִירָאֽוּךָ"}, {"kind": "text", "text": "וְכָל קֶֽרֶב וּכְלָיוֹת"}, {"kind": "text", "text": "יְזַמְּ֒רוּ לִשְׁמֶֽךָ"}, {"kind": "text", "text": "כַּדָּבָר שֶׁכָּתוּב"}, {"kind": "text", "text": "כָּל עַצְמוֹתַי תֹּאמַֽרְנָה"}, {"kind": "text", "text": "יְהֹוָה מִי כָמֽוֹךָ."}, {"kind": "text", "text": "מַצִּיל עָנִי"}, {"kind": "text", "text": "מֵחָזָק מִמֶּֽנּוּ."}, {"kind": "text", "text": "וְעָנִי וְאֶבְיוֹן"}, {"kind": "text", "text": "מִגּוֹזְ֒לוֹ"}, {"kind": "text", "text": "שַׁוְעַת עֲנִיִּים אַתָּה תִשְׁמַע."}, {"kind": "text", "text": "צַעֲקַת הַדַּל"}, {"kind": "text", "text": "תַּקְשִׁיב וְתוֹשִֽׁיעַ:"}, {"kind": "text", "text": "מִי יִדְמֶה לָּךְ"}, {"kind": "text", "text": "וּמִי יִשְׁוֶה לָּךְ"}, {"kind": "text", "text": "וּמִי יַעֲרָךְ לָךְ."}, {"kind": "text", "text": "הָאֵל"}, {"kind": "text", "text": "הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא."}, {"kind": "text", "text": "אֵל עֶלְיוֹן"}, {"kind": "text", "text": "קֹנֵה שָׁמַֽיִם וָאָֽרֶץ:"}, {"kind": "text", "text": "❖נְהַלֶּלְךָ וּנְשַׁבֵּחֲךָ"}, {"kind": "text", "text": "וּנְפָאֶרְךָ"}, {"kind": "text", "text": "וּנְבָרֵךְ אֶת שֵׁם קָדְשֶֽׁךָ:"}, {"kind": "text", "text": "כָּאָמוּר"}, {"kind": "text", "text": "לְדָוִד"}, {"kind": "text", "text": "בָּרְכִי נַפְשִׁי אֶת יְהֹוָה."}, {"kind": "text", "text": "וְכָל קְרָבַי"}, {"kind": "text", "text": "אֶת שֵׁם קָדְשׁוֹ:"}, {"kind": "text", "text": "הָאֵל"}, {"kind": "text", "text": "בְּתַעֲצֻמוֹת עֻזֶּֽךָ."}, {"kind": "text", "text": "הַגָּדוֹל בִּכְבוֹד שְׁמֶֽךָ."}, {"kind": "text", "text": "הַגִּבּוֹר לָנֶֽצַח"}, {"kind": "text", "text": "וְהַנּוֹרָא בְּנוֹרְ֒אוֹתֶֽיךָ."}, {"kind": "text", "text": "הַמֶּֽלֶךְ הַיּוֹשֵׁב עַל כִּסֵּא"}, {"kind": "text", "text": "רָם וְנִשָּׂא:"}, {"kind": "text", "text": "שׁוֹכֵן עַד"}, {"kind": "text", "text": "מָרוֹם וְקָדוֹשׁ שְׁמוֹ."}, {"kind": "text", "text": "וְכָתוּב"}, {"kind": "text", "text": "רַנְּ֒נוּ צַדִּיקִים בַּיהוֹה."}, {"kind": "text", "text": "לַיְ֒שָׁרִים נָאוָה תְהִלָּה:"}, {"kind": "text", "text": "בְּפִי יְשָׁרִים"}, {"kind": "text", "text": "תִּתְרוֹמָם."}, {"kind": "text", "text": "וּבְשִׂפְתֵי צַדִּיקִים"}, {"kind": "text", "text": "תִּתְבָּרַךְ."}, {"kind": "text", "text": "וּבִלְשׁוֹן חֲסִידִים"}, {"kind": "text", "text": "תִּתְקַדָּשׁ."}, {"kind": "text", "text": "וּבְקֶֽרֶב קְדוֹשִׁים"}, {"kind": "text", "text": "תִּתְהַלָּל:"}, {"kind": "text", "text": "וּבְמַקְהֲלוֹת"}, {"kind": "text", "text": "רִבְבוֹת"}, {"kind": "text", "text": "עַמְּ֒ךָ בֵּית יִשְׂרָאֵל."}, {"kind": "text", "text": "בְרִנָּה"}, {"kind": "text", "text": "יִתְפָּאַר שִׁמְךָ מַלְכֵּֽנוּ"}, {"kind": "text", "text": "בְּכָל דּוֹר וָדוֹר."}, {"kind": "text", "text": "שֶׁכֵּן חוֹבַת"}, {"kind": "text", "text": "כָּל הַיְ֒צוּרִים לְפָנֶֽיךָ."}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ. וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "❖לְהוֹדוֹת לְהַלֵּל לְשַׁבֵּחַ."}, {"kind": "text", "text": "לְפָאֵר לְרוֹמֵם לְהַדֵּר וּלְנַצֵֽחַ"}, {"kind": "text", "text": "לְבָרֵךְ לְעַלֵּה וּלְקַלֵּס"}, {"kind": "text", "text": "עַל כָּל דִּבְרֵי"}, {"kind": "text", "text": "שִׁירוֹת וְתִשְׁבְּ֒חוֹת"}, {"kind": "text", "text": "דָּוִד בֶּן יִשַׁי."}, {"kind": "text", "text": "עַבְדְּ֒ךָ מְשִׁיחֶךָ:"}, {"kind": "header", "text": "ישתבח"}, {"kind": "text", "text": "וּבְ֒כֵן"}, {"kind": "text", "text": "יִשְׁתַּבַּח שִׁמְ֒ךָ לָעַד מַלְכֵּֽנוּ"}, {"kind": "text", "text": "הָאֵל הַמֶּֽלֶךְ הַגָּדוֹל וְהַקָּדוֹשׁ"}, {"kind": "text", "text": "בַּשָּׁמַֽיִם וּבָאָֽרֶץ,"}, {"kind": "text", "text": "כִּי לְךָ נָאֶה"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "שִׁיר וּשְׁ֒בָחָה הַלֵּל וְזִמְרָה"}, {"kind": "text", "text": "עֹז וּמֶמְשָׁלָה"}, {"kind": "text", "text": "נֶֽצַח גְּדֻלָּה וּגְ֒בוּרָה"}, {"kind": "text", "text": "תְּהִלָּה וְתִפְאֶֽרֶת"}, {"kind": "text", "text": "קְדֻשָּׁה וּמַלְ֒כוּת,"}, {"kind": "text", "text": "בְּרָכוֹת וְהוֹדָאוֹת"}, {"kind": "text", "text": "לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ"}, {"kind": "text", "text": "וּמֵעוֹלָם וְעַד עוֹלָם"}, {"kind": "text", "text": "אַתָּה אֵל:"}, {"kind": "text", "text": "❖בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֵל"}, {"kind": "text", "text": "מֶֽלֶךְ גָּדוֹל וּמְ֒הֻלָּל בַּתִּשְׁבָּחוֹת"}, {"kind": "text", "text": "אֵל"}, {"kind": "text", "text": "הַהוֹדָאוֹת"}, {"kind": "text", "text": "אֲדוֹן הַנִּפְלָאוֹת"}, {"kind": "text", "text": "בּוֹרֵא כָּל הַנְּ֒שָׁמוֹת"}, {"kind": "text", "text": "רִבּוֹן כָּל הַמַעֲשִׂים"}, {"kind": "text", "text": "הַבּוֹחֵר בְּשִׁירֵי זִמְרָה"}, {"kind": "text", "text": "מֶֽלֶךְ יָחִיד"}, {"kind": "text", "text": "אֵל"}, {"kind": "text", "text": "חֵי הָעוֹלָמִים:"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת"}, {"kind": "text", "text": "מִמַּעֲמַקִּים"}, {"kind": "text", "text": "קְרָאתִֽיךָ יְהֹוָה:"}, {"kind": "text", "text": "אֲדֹנָי שִׁמְ֒עָה בְקוֹלִי"}, {"kind": "text", "text": "תִּהְיֶֽינָה אָזְנֶֽיךָ קַשֻּׁבוֹת"}, {"kind": "text", "text": "לְקוֹל תַּחֲנוּנָי:"}, {"kind": "text", "text": "אִם־עֲוֹנוֹת תִּשְׁמָר־יָהּ"}, {"kind": "text", "text": "אֲדֹנָי מִי יַעֲמֹד:"}, {"kind": "text", "text": "כִּי־עִמְּ֒ךָ הַסְּ֒לִיחָה"}, {"kind": "text", "text": "לְמַֽעַן תִּוָּרֵא:"}, {"kind": "text", "text": "קִוִּֽיתִי יְהֹוָה קִוְּ֒תָה נַפְשִׁי"}, {"kind": "text", "text": "וְלִדְ֒בָרוֹ הוֹחָֽלְתִּי:"}, {"kind": "text", "text": "נַפְשִׁי לַאדֹנָי"}, {"kind": "text", "text": "מִשֹּׁמְ֒רִים"}, {"kind": "text", "text": "לַבֹּֽקֶר"}, {"kind": "text", "text": "שֹׁמְ֒רִים"}, {"kind": "text", "text": "לַבֹּֽקֶר:"}, {"kind": "text", "text": "יַחֵל יִשְׂרָאֵל אֶל־יְהֹוָה"}, {"kind": "text", "text": "כִּי־עִם־יְהֹוָה הַחֶֽסֶד"}, {"kind": "text", "text": "וְהַרְבֵּה עִמּוֹ פְדוּת:"}, {"kind": "text", "text": "וְהוּא יִפְדֶּה אֶת־יִשְׂרָאֵל"}, {"kind": "text", "text": "מִכֹּל עֲוֹנוֹתָיו:"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְ֒מָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְ֒עוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְ֒כוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְקָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ"}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְ֒יוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְ֒חַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל,"}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְ֒מַן קָרִיב"}, {"kind": "text", "text": "וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְ֒עָלְ֒מֵי עָלְ֒מַיָּא:"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקוּדְשָׁא, בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵֽלָּא (בעשי\"ת וּלְ֒עֵֽלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְ֒כָתָא וְשִׁירָתָא,"}, {"kind": "text", "text": "תֻּשְׁבְּחָתָא וְנֶחֱמָתָא,"}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְ֒מָא, וְאִמְ֒רוּ אָמֵן:"}, {"kind": "text", "text": "<b>בָּרְ֒כוּ אֶת יְהֹוָה הַמְּ֒בֹרָךְ:</b>"}, {"kind": "text", "text": "<b>בָּרוּךְ יְהֹוָה הַמְּ֒בֹרָךְ</b>"}, {"kind": "text", "text": "<b>לְעוֹלָם וָעֶד:</b>"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "יוֹצֵר אוֹר"}, {"kind": "text", "text": "וּבוֹרֵא חֽשֶׁךְ"}, {"kind": "text", "text": "עֹשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "וּבוֹרֵא אֶת הַכֹּל:"}, {"kind": "text", "text": "הַכֹּל יוֹדֽוּךָ. וְהַכֹּל יְשַׁבְּ֒חֽוּךָ."}, {"kind": "text", "text": "וְהַכֹּל יֹאמְ֒רוּ"}, {"kind": "text", "text": "אֵין־קָדוֹשׁ כַּיהוֹה."}, {"kind": "text", "text": "הַכֹּל יְרוֹמְ֒מֽוּךָ סֶּֽלָה"}, {"kind": "text", "text": "יוֹצֵר הַכֹּל."}, {"kind": "text", "text": "הָאֵל הַפּוֹתֵֽחַ בְּכָל יוֹם"}, {"kind": "text", "text": "דַּלְתוֹת שַׁעֲרֵי מִזְרָח."}, {"kind": "text", "text": "וּבוֹקֵֽעַ חַלּוֹנֵי רָקִֽיעַ."}, {"kind": "text", "text": "מוֹצִיא חַמָּה מִמְּ֒קוֹמָהּ"}, {"kind": "text", "text": "וּלְבָנָה מִמְּ֒כוֹן שִׁבְתָּהּ."}, {"kind": "text", "text": "וּמֵאִיר לְעוֹלָם כֻּלּוֹ"}, {"kind": "text", "text": "וּלְיוֹשְׁ֒בָיו"}, {"kind": "text", "text": "שֶׁבָּרָא"}, {"kind": "text", "text": "בְּמִדַּת הָרַחֲמִים."}, {"kind": "text", "text": "הַמֵּאִיר לָאָֽרֶץ"}, {"kind": "text", "text": "וְלַדָּרִים עָלֶֽיהָ"}, {"kind": "text", "text": "בְּרַחֲמִים."}, {"kind": "text", "text": "וּבְטוּבוֹ"}, {"kind": "text", "text": "מְחַדֵּשׁ בְּכָל־יוֹם תָּמִיד"}, {"kind": "text", "text": "מַעֲשֵׂה בְרֵאשִׁית."}, {"kind": "text", "text": "מָה־רַבּוּ מַעֲשֶֽׂיךָ יְהֹוָה."}, {"kind": "text", "text": "כֻּלָּם בְּחָכְמָה עָשִֽׂיתָ."}, {"kind": "text", "text": "מָלְ֒אָה הָאָֽרֶץ קִנְיָנֶֽךָ:"}, {"kind": "text", "text": "הַמֶּֽלֶךְ הַמְּ֒רוֹמָם לְבַדּוֹ מֵאָז."}, {"kind": "text", "text": "הַמְּ֒שֻׁבָּח וְהַמְּ֒פוֹאָר וְהַמִּתְנַשֵּׂא"}, {"kind": "text", "text": "מִימוֹת עוֹלָם."}, {"kind": "text", "text": "אֱלֹהֵי עוֹלָם"}, {"kind": "text", "text": "בְּרַחֲמֶֽיךָ הָרַבִּים"}, {"kind": "text", "text": "רַחֵם עָלֵֽינוּ."}, {"kind": "text", "text": "אֲדוֹן עֻזֵּֽנוּ."}, {"kind": "text", "text": "צוּר מִשְׂגַּבֵּֽנוּ."}, {"kind": "text", "text": "מָגֵן יִשְׁעֵֽנוּ."}, {"kind": "text", "text": "מִשְׂגָּב בַּעֲדֵֽנוּ."}, {"kind": "text", "text": "אֵין עֲרוֹךְ לְךָ."}, {"kind": "text", "text": "וְאֵין זוּלָתֶֽךָ."}, {"kind": "text", "text": "אֶֽפֶס בִּלְתֶּֽךָ"}, {"kind": "text", "text": "וּמִי דוֹמֶה לָךְ."}, {"kind": "text", "text": "❖אֵין עֲרוֹךְ לְךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בָּעוֹלָם הַזֶּה."}, {"kind": "text", "text": "וְאֵין זוּלָתְ֒ךָ מַלְכֵּֽנוּ"}, {"kind": "text", "text": "לְחַיֵּי הָעוֹלָם הַבָּא."}, {"kind": "text", "text": "אֶֽפֶס בִּלְתְּ֒ךָ"}, {"kind": "text", "text": "גּוֹאֲלֵֽנוּ"}, {"kind": "text", "text": "לִימוֹת הַמָּשִֽׁיחַ."}, {"kind": "text", "text": "וְאֵין דוֹמֶה לְךָ"}, {"kind": "text", "text": "מוֹשִׁיעֵֽנוּ"}, {"kind": "text", "text": "לִתְחִיַּת הַמֵּתִים:"}, {"kind": "header", "text": "אל אדון"}, {"kind": "text", "text": "אֵל"}, {"kind": "text", "text": "אָדוֹן עַל כָּל הַמַּעֲשִׂים."}, {"kind": "text", "text": "בָּרוּךְ"}, {"kind": "text", "text": "וּמְבֹרָךְ בְּפִי כָּל הַנְּשָׁמָה."}, {"kind": "text", "text": "גָּדְלוֹ וְטוּבוֹ מָלֵא עוֹלָם."}, {"kind": "text", "text": "דַּֽעַת וּתְבוּנָה"}, {"kind": "text", "text": "סוֹבְ֒בִים הוֹדוֹ:"}, {"kind": "text", "text": "הַמִּתְגָּאֶה עַל חַיּוֹת הַקֹּֽדֶשׁ."}, {"kind": "text", "text": "וְנֶהְדָּר בְּכָבוֹד עַל הַמֶּרְכָּבָה."}, {"kind": "text", "text": "זְכוּת וּמִישׁוֹר לִפְנֵי כִסְאוֹ."}, {"kind": "text", "text": "חֶֽסֶד וְרַחֲמִים מָלֵא כְבוֹדוֹ:"}, {"kind": "text", "text": "טוֹבִים מְאוֹרוֹת"}, {"kind": "text", "text": "שֶׁבָּרָא אֱלֹהֵֽינוּ."}, {"kind": "text", "text": "יְצָרָם בְּדַֽעַת"}, {"kind": "text", "text": "בְּבִינָה וּבְהַשְׂכֵּל."}, {"kind": "text", "text": "כֹּֽחַ וּגְבוּרָה נָתַן בָּהֶם."}, {"kind": "text", "text": "לִהְיוֹת מוֹשְׁ֒לִים"}, {"kind": "text", "text": "בְּקֶֽרֶב תֵּבֵל:"}, {"kind": "text", "text": "מְלֵאִים זִיו וּמְפִיקִים נֹֽגַהּ."}, {"kind": "text", "text": "נָאֶה זִיוָם בְּכָל הָעוֹלָם."}, {"kind": "text", "text": "שְׂמֵחִים בְּצֵאתָם"}, {"kind": "text", "text": "וְשָׂשִׂים בְּבוֹאָם."}, {"kind": "text", "text": "עוֹשִׂים בְּאֵימָה"}, {"kind": "text", "text": "רְצוֹן קוֹנָם:"}, {"kind": "text", "text": "פְּאֵר וְכָבוֹד נוֹתְ֒נִים לִשְׁמוֹ."}, {"kind": "text", "text": "צָהֳלָה וְרִנָּה"}, {"kind": "text", "text": "לְזֵֽכֶר מַלְכוּתוֹ."}, {"kind": "text", "text": "קָרָא לַשֶּֽׁמֶשׁ"}, {"kind": "text", "text": "וַיִּזְרַח אוֹר."}, {"kind": "text", "text": "רָאָה וְהִתְקִין"}, {"kind": "text", "text": "צוּרַת הַלְּ֒בָנָה:"}, {"kind": "text", "text": "שֶֽׁבַח נוֹתְ֒נִים לוֹ"}, {"kind": "text", "text": "כָּל צְבָא מָרוֹם."}, {"kind": "text", "text": "תִּפְאֶֽרֶת וּגְדֻלָּה"}, {"kind": "text", "text": "שְׂרָפִים וְאוֹפַנִּים וְחַיּוֹת הַקֹּֽדֶשׁ:"}, {"kind": "text", "text": "לָאֵל"}, {"kind": "text", "text": "אֲשֶׁר שָׁבַת מִכָּל הַמַּעֲשִׂים."}, {"kind": "text", "text": "בַּיּוֹם הַשְּׁ֒בִיעִי הִתְעַלָּה"}, {"kind": "text", "text": "וְיָשַׁב עַל כִּסֵּא כְבוֹדוֹ."}, {"kind": "text", "text": "תִּפְאֶֽרֶת עָטָה"}, {"kind": "text", "text": "לְיוֹם הַמְּ֒נוּחָה."}, {"kind": "text", "text": "עֹֽנֶג קָרָא לְיוֹם הַשַּׁבָּת."}, {"kind": "text", "text": "זֶה שֶֽׁבַח שֶׁל יוֹם הַשְּׁ֒בִיעִי"}, {"kind": "text", "text": "שֶׁבּוֹ שָׁבַת אֵל"}, {"kind": "text", "text": "מִכָּל מְלַאכְתּוֹ."}, {"kind": "text", "text": "וְיוֹם הַשְּׁ֒בִיעִי מְשַׁבֵּֽחַ וְאוֹמֵר."}, {"kind": "text", "text": "מִזְמוֹר שִׁיר לְיוֹם הַשַּׁבָּת"}, {"kind": "text", "text": "טוֹב לְהוֹדוֹת לַיהוֹה:"}, {"kind": "text", "text": "לְפִיכָךְ יְפָאֲרוּ וִיבָרְ֒כוּ לָאֵל"}, {"kind": "text", "text": "כָּל יְצוּרָיו."}, {"kind": "text", "text": "שֶֽׁבַח יְקָר וּגְדֻלָּה וְכָבוֹד"}, {"kind": "text", "text": "יִתְּ֒נוּ לָאֵל"}, {"kind": "text", "text": "מֶֽלֶךְ"}, {"kind": "text", "text": "יוֹצֵר כֹּל."}, {"kind": "text", "text": "הַמַּנְחִיל מְנוּחָה"}, {"kind": "text", "text": "לְעַמּוֹ יִשְׂרָאֵל בִּקְדֻשָּׁתוֹ"}, {"kind": "text", "text": "בְּיוֹם שַׁבַּת קֹֽדֶשׁ."}, {"kind": "text", "text": "שִׁמְךָ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "יִתְקַדַּשׁ."}, {"kind": "text", "text": "וְזִכְרְ֒ךָ מַלְכֵּֽנוּ יִתְפָּאַר"}, {"kind": "text", "text": "בַּשָּׁמַֽיִם מִמַּֽעַל"}, {"kind": "text", "text": "וְעַל הָאָֽרֶץ מִתָּֽחַת."}, {"kind": "text", "text": "תִּתְבָּרֵךְ מוֹשִׁיעֵֽנוּ"}, {"kind": "text", "text": "עַל כָּל שֶֽׁבַח מַעֲשֵׂה יָדֶֽיךָ."}, {"kind": "text", "text": "וְעַל מְאוֹרֵי אוֹר"}, {"kind": "text", "text": "שֶׁיָצַֽרְתָּ"}, {"kind": "text", "text": "הֵמָּה יְפָאֲרֽוּךָ סֶּֽלָה:"}, {"kind": "text", "text": "הַמֵּאִיר לָאָֽרֶץ"}, {"kind": "text", "text": "וְלַדָּרִים עָלֶֽיהָ"}, {"kind": "text", "text": "בְּרַחֲמִים,"}, {"kind": "text", "text": "וּבְ֒טוּבוֹ"}, {"kind": "text", "text": "מְחַדֵּשׁ בְּכָל יוֹם תָּמִיד"}, {"kind": "text", "text": "מַעֲשֵׂה בְרֵאשִׁית:"}, {"kind": "text", "text": "מָה־רַבּוּ מַעֲשֶֽׂיךָ יְהֹוָה,"}, {"kind": "text", "text": "כֻּלָּם בְּחָכְמָה עָשִֽׂיתָ,"}, {"kind": "text", "text": "מָלְ֒אָה הָאָֽרֶץ קִנְיָנֶֽךָ:"}, {"kind": "text", "text": "הַמֶּֽלֶךְ הַמְּ֒רוֹמָם לְבַדּוֹ מֵאָז,"}, {"kind": "text", "text": "הַמְּ֒שֻׁבָּח וְהַמְּ֒פֹאָר"}, {"kind": "text", "text": "וְהַמִּתְנַשֵּׂא"}, {"kind": "text", "text": "מִימוֹת עוֹלָם:"}, {"kind": "text", "text": "אֱלֹהֵי עוֹלָם"}, {"kind": "text", "text": "בְּרַחֲמֶֽיךָ הָרַבִּים"}, {"kind": "text", "text": "רַחֵם עָלֵֽינוּ"}, {"kind": "text", "text": "אֲדוֹן עֻזֵּֽנוּ"}, {"kind": "text", "text": "צוּר מִשְׂגַּבֵּֽנוּ"}, {"kind": "text", "text": "מָגֵן יִשְׁעֵֽנוּ"}, {"kind": "text", "text": "מִשְׂגָּב בַּעֲדֵֽנוּ:"}, {"kind": "text", "text": "אֵל בָּרוּךְ גְּדוֹל דֵּעָה,"}, {"kind": "text", "text": "הֵכִין וּפָעַל זָהֳרֵי חַמָּה,"}, {"kind": "text", "text": "טוֹב יָצַר"}, {"kind": "text", "text": "כָּבוֹד לִשְׁ֒מוֹ,"}, {"kind": "text", "text": "מְאוֹרוֹת נָתַן"}, {"kind": "text", "text": "סְבִיבוֹת עֻזּוֹ,"}, {"kind": "text", "text": "פִּנּוֹת צְבָאָיו קְדוֹשִׁים"}, {"kind": "text", "text": "רוֹמְ֒מֵי שַׁדַּי,"}, {"kind": "text", "text": "תָּמִיד מְסַפְּ֒רִים"}, {"kind": "text", "text": "כְּבוֹד אֵל"}, {"kind": "text", "text": "וּקְ֒דֻשָּׁתוֹ:"}, {"kind": "text", "text": "תִּתְבָּרֵךְ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בַּשָּׁמַֽיִם מִמַּֽעַל"}, {"kind": "text", "text": "וְעַל הַאָֽרֶץ מִתָּֽחַת"}, {"kind": "text", "text": "עַל כָּל שֶֽׁבַח מַעֲשֵׂה יָדֶֽיךָ"}, {"kind": "text", "text": "וְעַל מְאֽוֹרֵי אוֹר"}, {"kind": "text", "text": "שֶׁיָצַרְתָּ"}, {"kind": "text", "text": "הֵֽמָּה יְפָאֲרֽוּךָ סֶּֽלָה:"}, {"kind": "text", "text": "תִּתְבָּרֵךְ לָנֶצַח צוּרֵֽנוּ מַלְכֵּֽנוּ"}, {"kind": "text", "text": "וְגוֹאֲלֵֽנוּ, בּוֹרֵא קְדוֹשִׁים"}, {"kind": "text", "text": "יִשְׁתַּבַּח שִׁמְ֒ךָ לָעַד מַלְכֵּֽנוּ,"}, {"kind": "text", "text": "יוֹצֵר מְשָׁרְתִים,"}, {"kind": "text", "text": "וַאֲשֶׁר מְשָׁרְתָיו"}, {"kind": "text", "text": "כֻּלָּם עוֹמְ֒דִים בְּרוּם עוֹלָם"}, {"kind": "text", "text": "וּמַשְׁמִיעִים בְּיִרְאָה יַֽחַד בְּקוֹל"}, {"kind": "text", "text": "דִּבְ֒רֵי אֱלֹהִים חַיִּים"}, {"kind": "text", "text": "וּמֶֽלֶךְ עוֹלָם:"}, {"kind": "text", "text": "כֻּלָם אֲהוּבִים"}, {"kind": "text", "text": "כֻּלָּם בְּרוּרִים"}, {"kind": "text", "text": "כֻּלָּם גִּבּוֹרִים"}, {"kind": "text", "text": "כֻּלָּם קְדוֹשִׁים"}, {"kind": "text", "text": "וְכֻלָּם עֹשִׂים"}, {"kind": "text", "text": "בְּאֵימָה וּבְ֒יִרְאָה"}, {"kind": "text", "text": "רְצוֹן קוֹנָם:"}, {"kind": "text", "text": "❖וְכֻלָּם פּוֹתְ֒חִים אֶת פִּיהֶם"}, {"kind": "text", "text": "בִּקְ֒דֻשָּׁה וּבְ֒טָהֳרָה"}, {"kind": "text", "text": "בְּשִׁירָה וּבְ֒זִמְרָה"}, {"kind": "text", "text": "וּמְ֒בָרְכִין וּמְ֒שַׁבְּ֒חִין וּמְ֒פָאֲרִין"}, {"kind": "text", "text": "וּמַעֲרִיצִין וּמַקְדִּישִׁין"}, {"kind": "text", "text": "וּמַמְלִיכִין:"}, {"kind": "text", "text": "אֶת שֵׁם הָאֵל הַמֶּֽלֶךְ"}, {"kind": "text", "text": "הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא"}, {"kind": "text", "text": "קָדוֹשׁ הוּא:"}, {"kind": "text", "text": "וְכֻלָּם מְקַבְּ֒לִים עֲלֵיהֶם"}, {"kind": "text", "text": "עֹל מַלְ֒כוּת שָׁמַֽיִם"}, {"kind": "text", "text": "זֶה מִזֶּה,"}, {"kind": "text", "text": "וְנוֹתְ֒נִים בְּאַהֲבָה רְשׁוּת זֶה לָזֶה"}, {"kind": "text", "text": "לְהַקְדִּישׁ לְיוֹצְ֒רָם"}, {"kind": "text", "text": "בְּנַֽחַת רֽוּחַ"}, {"kind": "text", "text": "בְּשָׂפָה בְרוּרָה וּבִנְ֒עִימָה,"}, {"kind": "text", "text": "קְדֻשָּׁה כֻּלָּם כְּאֶחָד עוֹנִים"}, {"kind": "text", "text": "בְּאֵימָה"}, {"kind": "text", "text": "וְאוֹמְ֒רִים בְּיִרְאָה"}, {"kind": "text", "text": "<b>קָדוֹשׁ קָדוֹשׁ קָדוֹשׁ</b>"}, {"kind": "text", "text": "<b>יְהֹוָה צְבָאוֹת.</b>"}, {"kind": "text", "text": "<b>מְלֹא כָל־הָאָֽרֶץ כְּבוֹדוֹ:</b>"}, {"kind": "text", "text": "וְהָאוֹפַנִּים וְחַיּוֹת הַקֹּֽדֶשׁ"}, {"kind": "text", "text": "בְּרַֽעַשׁ גָּדוֹל מִתְנַשְּׂ֒אִים"}, {"kind": "text", "text": "לְעֻמַּת שְׂרָפִים"}, {"kind": "text", "text": "לְעֻמָּתָם מְשַׁבְּ֒חִים וְאוֹמְ֒רִים:"}, {"kind": "text", "text": "<b>בָּרוּךְ כְּבוֹד־יְהֹוָה</b>"}, {"kind": "text", "text": "<b>מִמְּ֒קוֹמוֹ:</b>"}, {"kind": "text", "text": "לָאֵל בָּרוּךְ"}, {"kind": "text", "text": "נְעִימוֹת יִתֵּֽנוּ,"}, {"kind": "text", "text": "לַמֶּֽלֶךְ אֵל"}, {"kind": "text", "text": "חַי וְקַיָּם"}, {"kind": "text", "text": "זְמִירוֹת יֹאמֵֽרוּ"}, {"kind": "text", "text": "וְתִשְׁבָּחוֹת יַשְׁמִֽיעוּ,"}, {"kind": "text", "text": "כִּי הוּא לְבַדּוֹ מָרוֹם וְקָדוֹשׁ"}, {"kind": "text", "text": "פּוֹעֵל גְּבוּרוֹת"}, {"kind": "text", "text": "עֹשֶׂה חֲדָשׁוֹת"}, {"kind": "text", "text": "בַּֽעַל מִלְחָמוֹת"}, {"kind": "text", "text": "זוֹרֵֽעַ צְדָקוֹת"}, {"kind": "text", "text": "מַצְמִֽיחַ יְשׁוּעוֹת"}, {"kind": "text", "text": "בּוֹרֵא רְפוּאוֹת"}, {"kind": "text", "text": "נוֹרָא תְהִלּוֹת אֲדוֹן הַנִּפְלָאוֹת:"}, {"kind": "text", "text": "הַמְ֒חַדֵּשׁ בְּטוּבוֹ"}, {"kind": "text", "text": "בְּכָל יוֹם תָּמִיד"}, {"kind": "text", "text": "מַעֲשֵׂה בְרֵאשִׁית:"}, {"kind": "text", "text": "כָּאָמוּר"}, {"kind": "text", "text": "לְעֹשֵׂה אוֹרִים גְּדֹלִים"}, {"kind": "text", "text": "כִּי לְעוֹלָם חַסְדּוֹ:"}, {"kind": "text", "text": "(וְהִתְקִין מְאוֹרוֹת"}, {"kind": "text", "text": "מְשַׂמֵּֽחַ עוֹלָמוֹ אֲשֶׁר בָּרָא.)"}, {"kind": "text", "text": "❖אוֹר חָדָשׁ עַל צִיּוֹן תָּאִיר"}, {"kind": "text", "text": "וְנִזְכֶּה כֻלָּֽנוּ בִּמְ֒הֵרָה"}, {"kind": "text", "text": "לְאוֹרוֹ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "יוֹצֵר הַמְּ֒אוֹרוֹת:"}, {"kind": "text", "text": "אַהֲבַת עוֹלָם אֲהַבְתָּֽנוּ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "חֶמְלָה גְדוֹלָה וִיתֵרָה"}, {"kind": "text", "text": "חָמַֽלְתָּ עָלֵֽינוּ:"}, {"kind": "text", "text": "אָבִֽינוּ מַלְכֵּֽנוּ"}, {"kind": "text", "text": "בַּעֲבוּר שִׁמְ֒ךָ הַגָּדוֹל"}, {"kind": "text", "text": "וּבַעֲבוּר אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "שֶׁבָּטְ֒חוּ בְךָ"}, {"kind": "text", "text": "וַתְּ֒לַמְּ֒דֵם חֻקֵּי חַיִּים"}, {"kind": "text", "text": "לַעֲשׂוֹת רְצוֹנְ֒ךָ"}, {"kind": "text", "text": "בְּלֵבָב שָׁלֵם"}, {"kind": "text", "text": "כֵּן תְּחָנֵּֽנוּ וּתְ֒לַמְּ֒דֵֽנוּ:"}, {"kind": "text", "text": "אָבִֽינוּ אָב הָרַחֲמָן"}, {"kind": "text", "text": "הַמְ֒רַחֵם"}, {"kind": "text", "text": "רַחֵם עָלֵֽינוּ"}, {"kind": "text", "text": "וְתֵן בְּלִבֵּֽנוּ בִּינָה"}, {"kind": "text", "text": "לְהָבִין"}, {"kind": "text", "text": "וּלְ֒הַשְׂכִּיל"}, {"kind": "text", "text": "לִשְׁמֹֽעַ לִלְמוֹד וּלְ֒לַמֵּד"}, {"kind": "text", "text": "לִשְׁמֹר וְלַעֲשׂוֹת וּלְ֒קַיֵּם"}, {"kind": "text", "text": "אֶת כָּל דִּבְ֒רֵי תַלְמוּד תּוֹרָתֶֽךָ"}, {"kind": "text", "text": "בְּאַהֲבָה:"}, {"kind": "text", "text": "וְהָאֵר עֵינֵֽינוּ בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "וְדַבֵּק לִבֵּֽנוּ"}, {"kind": "text", "text": "בְּמִצְוֹתֶֽיךָ"}, {"kind": "text", "text": "וְיַחֵד לְבָבֵֽנוּ"}, {"kind": "text", "text": "לְאַהֲבָה וּלְ֒יִרְאָה אֶת שְׁמֶֽךָ,"}, {"kind": "text", "text": "לְמַֽעַן לֹא נֵבוֹשׁ"}, {"kind": "text", "text": "וְלֹא נִכָּלֵם וְלֹא נִכָּשֵׁל"}, {"kind": "text", "text": "לְעוֹלָם וָעֶד,"}, {"kind": "text", "text": "כִּי בְשֵׁם קָדְ֒שְׁךָ"}, {"kind": "text", "text": "הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא"}, {"kind": "text", "text": "בָּטָֽחְנוּ"}, {"kind": "text", "text": "נָגִֽילָה וְנִשְׂמְחָה בִּישׁוּעָתֶֽךָ:"}, {"kind": "text", "text": "וְרַחֲמֶֽיךָ יְהֹוָה אֶלֹהֵֽינוּ"}, {"kind": "text", "text": "וַחֲסָדֶֽיךָ הָרַבִּים"}, {"kind": "text", "text": "אַל יַעַזְבֽוּנוּ נֶֽצַח סֶֽלָה וָעֶד:"}, {"kind": "text", "text": "מַהֵר וְהָבֵא עָלֵֽינוּ"}, {"kind": "text", "text": "בְּרָכָה וְשָׁלוֹם מְהֵרָה"}, {"kind": "text", "text": "מֵאַרְבַּע כַּנְ֒פוֹת הָאָֽרֶץ"}, {"kind": "text", "text": "וּשְׁ֒בוֹר עוֹל הַגּוֹיִם"}, {"kind": "text", "text": "מֵעַל צַוָּארֵֽנוּ"}, {"kind": "text", "text": "וְתוֹלִיכֵֽנוּ מְהֵרָה"}, {"kind": "text", "text": "קוֹמְ֒מִיּוּת לְאַרְצֵֽנוּ:"}, {"kind": "text", "text": "כִּי אֵל"}, {"kind": "text", "text": "פּוֹעֵל יְשׁוּעוֹת אָֽתָּה"}, {"kind": "text", "text": "וּבָֽנוּ בָחַֽרְתָּ"}, {"kind": "text", "text": "מִכָּל עַם וְלָשׁוֹן"}, {"kind": "text", "text": "❖וְקֵרַבְתָּֽנוּ מַלְכֵּֽנוּ"}, {"kind": "text", "text": "לְשִׁמְ֒ךָ הַגָּדוֹל סֶֽלָה בֶּאֱמֶת"}, {"kind": "text", "text": "בְּאַהֲבָה לְהוֹדוֹת לְךָ"}, {"kind": "text", "text": "וּלְיַחֶדְ֒ךָ בְּאַהֲבָה"}, {"kind": "text", "text": "וּלְ֒אַהֲבָה אֶת שְׁמֶֽךָ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַבּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל בְּאַהֲבָה:"}, {"kind": "header", "text": "קריאת שמע"}, {"kind": "text", "text": "אֵל מֶֽלֶךְ נֶאֱמָן:"}, {"kind": "text", "text": "<b>שְׁמַע יִשְׂרָאֵל</b>"}, {"kind": "text", "text": "<b>יְהֹוָה אֱלֹהֵֽינוּ</b>"}, {"kind": "text", "text": "<b>יְהֹוָה אֶחָד:</b>"}, {"kind": "instruction", "text": "בָּרוּךְ שֵׁם"}, {"kind": "instruction", "text": "כְּבוֹד מַלְ֒כוּתוֹ"}, {"kind": "instruction", "text": "לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "וְאָהַבְתָּ אֵת יְהֹוָה אֱלֹהֶֽיךָ"}, {"kind": "text", "text": "בְּכָלּ־לְּבָבְ֒ךָ"}, {"kind": "text", "text": "וּבְ֒כָל־נַפְשְׁךָ"}, {"kind": "text", "text": "וּבְ֒כָל־מְאֹדֶֽךָ:"}, {"kind": "text", "text": "וְהָיוּ הַדְּ֒בָרִים הָאֵֽלֶּה"}, {"kind": "text", "text": "אֲשֶׁר֯ אָ֯נֹכִי מְצַוְּ֒ךָ הַיּוֹם"}, {"kind": "text", "text": "עַל֯־לְ֯בָבֶֽךָ:"}, {"kind": "text", "text": "וְשִׁנַּנְתָּם"}, {"kind": "text", "text": "לְבָנֶֽיךָ"}, {"kind": "text", "text": "וְדִבַּרְתָּ בָּם"}, {"kind": "text", "text": "בְּשִׁבְתְּ֒ךָ בְּבֵיתֶֽךָ"}, {"kind": "text", "text": "וּבְ֒לֶכְתְּךָ בַדֶּֽרֶךְ"}, {"kind": "text", "text": "וּבְ֒שָׁכְבְּךָ וּבְ֒קוּמֶֽךָ:"}, {"kind": "text", "text": "וּקְ֒שַׁרְתָּם לְאוֹת"}, {"kind": "text", "text": "עַל֯־יָ֯דֶֽךָ"}, {"kind": "text", "text": "וְהָיוּ לְטֹטָפֹת"}, {"kind": "text", "text": "בֵּין עֵינֶֽיךָ:"}, {"kind": "text", "text": "וּכְ֒תַבְתָּם"}, {"kind": "text", "text": "עַל־מְזֻזוֹת בֵּיתֶֽךָ"}, {"kind": "text", "text": "וּבִשְׁ֒עָרֶֽיךָ:"}, {"kind": "text", "text": "וְהָיָה"}, {"kind": "text", "text": "אִם־שָׁמֹֽעַ תִּשְׁמְעוּ אֶל־מִצְוֹתַי"}, {"kind": "text", "text": "אֲשֶׁר֯ אָ֯נֹכִי מְצַוֶּה אֶתְ֒כֶם הַיּוֹם"}, {"kind": "text", "text": "לְאַהֲבָה אֶת־יְהֹוָה אֱלֹהֵיכֶם"}, {"kind": "text", "text": "וּלְ֒עָבְ֒דוֹ"}, {"kind": "text", "text": "בְּכָל֯־לְ֯בַבְ֒כֶם"}, {"kind": "text", "text": "וּבְ֒כָל־נַפְשְׁכֶם:"}, {"kind": "text", "text": "וְנָתַתִּי מְטַר֯־אַ֯רְצְכֶם"}, {"kind": "text", "text": "בְּעִתּוֹ"}, {"kind": "text", "text": "יּוֹרֶה"}, {"kind": "text", "text": "וּמַלְקוֹשׁ"}, {"kind": "text", "text": "וְאָסַפְתָּ דְגָנֶֽךָ"}, {"kind": "text", "text": "וְתִירשְׁךָ וְיִצְהָרֶֽךָ:"}, {"kind": "text", "text": "וְנָתַתִּי עֵֽשֶׂבּ"}, {"kind": "text", "text": "בְּ֯שָׂדְ֒ךָ לִבְ֒הֶמְתֶּֽךָ"}, {"kind": "text", "text": "וְאָכַלְתָּ וְשָׂבָֽעְתָּ:"}, {"kind": "text", "text": "הִשָּׁמְ֒רוּ לָכֶם פֶּן֯־יִ֯פְתֶּה לְבַבְ֒כֶם"}, {"kind": "text", "text": "וְסַרְתֶּם"}, {"kind": "text", "text": "וַעֲבַדְתֶּם אֱלֹהִים֯ אֲ֯חֵרִים"}, {"kind": "text", "text": "וְהִשְׁתַּחֲוִיתֶם לָהֶם:"}, {"kind": "text", "text": "וְחָרָה אַף־יְהֹוָה בָּכֶם"}, {"kind": "text", "text": "וְעָצַר֯ אֶ֯ת־הַשָּׁמַֽיִם"}, {"kind": "text", "text": "וְלֹּא־יִּהְיֶה מָטָר"}, {"kind": "text", "text": "וְהָאֲדָמָה לֹא תִתֵּן אֶתּ־יְּבוּלָהּ"}, {"kind": "text", "text": "וַאֲבַדְתֶּם֯ מְּהֵרָה"}, {"kind": "text", "text": "מֵעַל הָאָֽרֶץ הַטֹּבָה"}, {"kind": "text", "text": "אֲשֶׁר֯ יְ֯הוֹה נֹתֵן לָכֶם:"}, {"kind": "text", "text": "וְשַׂמְתֶּם֯ אֶ֯ת־דְּבָרַיּ אֵֽ֯לֶּה"}, {"kind": "text", "text": "עַלּ־לְּבַבְ֒כֶם וְעַל־נַפְשְׁ֒כֶם"}, {"kind": "text", "text": "וּקְ֒שַׁרְתֶּם֯ אֹ֯תָם לְאוֹת"}, {"kind": "text", "text": "עַלּ־יֶּדְ֒כֶם"}, {"kind": "text", "text": "וְהָיוּ לְטוֹטָפֹת"}, {"kind": "text", "text": "בֵּין עֵינֵיכֶם:"}, {"kind": "text", "text": "וְלִמַּדְתֶּם֯ אֹ֯תָם אֶת־בְּנֵיכֶם"}, {"kind": "text", "text": "לְדַבֵּר בָּם"}, {"kind": "text", "text": "בְּשִׁבְתְּךָ בְּבֵיתֶֽךָ"}, {"kind": "text", "text": "וּבְ֒לֶכְתְּ֒ךָ בַדֶּֽרֶךְ"}, {"kind": "text", "text": "וּבְ֒שָׁכְבְּ֒ךָ וּבְ֒קוּמֶֽךָ:"}, {"kind": "text", "text": "וּכְ֒תַבְתָּם"}, {"kind": "text", "text": "עַל־מְזוּזוֹת בֵּיתֶֽךָ"}, {"kind": "text", "text": "וּבִשְׁ֒עָרֶֽיךָ:"}, {"kind": "text", "text": "לְמַֽעַן֯ יִ֯רְבּוּ יְמֵיכֶם"}, {"kind": "text", "text": "וִימֵי בְנֵיכֶם"}, {"kind": "text", "text": "עַל הָאֲדָמָה"}, {"kind": "text", "text": "אֲשֶׁר נִשְׁבַּע יְהֹוָה לַאֲבֹתֵיכֶם"}, {"kind": "text", "text": "לָתֵת לָהֶם"}, {"kind": "text", "text": "כִּימֵי הַשָּׁמַֽיִם עַל־הָאָֽרֶץ:"}, {"kind": "text", "text": "וַֽיֹּאמֶר֯ יְ֯הוֹהּ אֶ֯ל־משֶׁה לֵּאמֹר:"}, {"kind": "text", "text": "דַּבֵּר֯ אֶ֯ל־בְּנֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאָמַרְתָּ אֲלֵהֶם"}, {"kind": "text", "text": "וְעָשׂוּ לָהֶם צִיצִת"}, {"kind": "text", "text": "עַל־כַּנְ֒פֵי בִגְ֒דֵיהֶם"}, {"kind": "text", "text": "לְדֹרֹתָם"}, {"kind": "text", "text": "וְנָתְ֒נוּ עַל־צִיצִת"}, {"kind": "text", "text": "הַכָּנָף֯"}, {"kind": "text", "text": "פְּתִיל תְּכֵֽלֶת:"}, {"kind": "text", "text": "וְהָיָה לָכֶם לְצִיצִת"}, {"kind": "text", "text": "וּרְ֒אִיתֶם֯ אֹ֯תוֹ"}, {"kind": "text", "text": "וּזְ֒כַרְתֶּם֯"}, {"kind": "text", "text": "אֶ֯ת־כָּל־מִצְוֹת֯ יְ֯הוֹה"}, {"kind": "text", "text": "וַעֲשִׂיתֶם֯ אֹ֯תָם"}, {"kind": "text", "text": "וְלֹא תָתֽוּרוּ אַחֲרֵי לְבַבְ֒כֶם"}, {"kind": "text", "text": "וְאַחֲרֵי עֵינֵיכֶם"}, {"kind": "text", "text": "אֲשֶׁר֯־אַ֯תֶּם זֹנִים֯ אַ֯חֲרֵיהֶם:"}, {"kind": "text", "text": "לְמַֽעַן תִּזְכְּרוּ"}, {"kind": "text", "text": "וַעֲשִׂיתֶם֯ אֶ֯ת־כָּל־מִצְוֹתָי"}, {"kind": "text", "text": "וִהְיִיתֶם קְדשִׁים לֵאלֹהֵיכֶם:"}, {"kind": "text", "text": "אֲנִי יְהֹוָה אֱלֹהֵיכֶם֯"}, {"kind": "text", "text": "אֲ֯שֶׁר הוֹצֵֽאתִי אֶתְ֒כֶם֯"}, {"kind": "text", "text": "מֵּאֶֽרֶץ מִצְרַֽיִם"}, {"kind": "text", "text": "לִהְיוֹת לָכֶם לֵאלֹהִים֯"}, {"kind": "text", "text": "אֲ֯נִי יְהֹוָה אֱלֹהֵיכֶם֯:"}, {"kind": "text", "text": "אֱמֶת"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵיכֶם֯ אֱ֯מֶת:"}, {"kind": "text", "text": "וְיַצִּיב"}, {"kind": "text", "text": "וְנָכוֹן וְקַיָּם"}, {"kind": "text", "text": "וְיָשָׁר וְנֶאֱמָן"}, {"kind": "text", "text": "וְאָהוּב וְחָבִיב"}, {"kind": "text", "text": "וְנֶחְמָד וְנָעִים"}, {"kind": "text", "text": "וְנוֹרָא וְאַדִּיר"}, {"kind": "text", "text": "וּמְ֒תֻקָּן וּמְ֒קֻבָּל"}, {"kind": "text", "text": "וְטוֹב וְיָפֶה"}, {"kind": "text", "text": "הַדָּבָר הַזֶּה עָלֵֽינוּ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "אֱמֶת"}, {"kind": "text", "text": "אֱלֹהֵי עוֹלָם מַלְכֵּֽנוּ"}, {"kind": "text", "text": "צוּר יַעֲקֹב"}, {"kind": "text", "text": "מָגֵן יִשְׁעֵֽנוּ,"}, {"kind": "text", "text": "❖לְדֹר וָדֹר"}, {"kind": "text", "text": "הוּא קַיָּם וּשְׁ֒מוֹ קַיָּם"}, {"kind": "text", "text": "וְכִסְאוֹ נָכוֹן"}, {"kind": "text", "text": "וּמַלְ֒כוּתוֹ וֶאֱמוּנָתוֹ"}, {"kind": "text", "text": "לָעַד קַיָּֽמֶת:"}, {"kind": "text", "text": "וּדְ֒בָרָיו חָיִים וְקַיָּמִים"}, {"kind": "text", "text": "נֶאֱמָנִים וְנֶחֱמָדִים"}, {"kind": "text", "text": "לָעַד וּלְ֒עוֹלְ֒מֵי עוֹלָמִים,"}, {"kind": "text", "text": "עַל אֲבוֹתֵֽינוּ וְעָלֵֽינוּ"}, {"kind": "text", "text": "עַל בָּנֵֽינוּ וְעַל דּוֹרוֹתֵֽינוּ"}, {"kind": "text", "text": "וְעַל כָּל דּוֹרוֹת"}, {"kind": "text", "text": "זֶֽרַע יִשְׂרָאֵל עֲבָדֶֽיךָ:"}, {"kind": "text", "text": "עַל הָרִאשׁוֹנִים"}, {"kind": "text", "text": "וְעַל הָאַחֲרוֹנִים"}, {"kind": "text", "text": "דָּבָר טוֹב וְקַיָּם לְעוֹלָם וָעֶד,"}, {"kind": "text", "text": "אֱמֶת וֶאֱמוּנָה"}, {"kind": "text", "text": "חוֹק וְלֹא יַעֲבֹר:"}, {"kind": "text", "text": "אֱמֶת שָׁאַתָּה הוּא יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "מַלְכֵּֽנוּ מֶֽלֶךְ אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "גֹּאֲלֵֽנוּ גֹּאֵל אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "יוֹצְ֒רֵֽנוּ צוּר יְשׁוּעָתֵֽנוּ"}, {"kind": "text", "text": "קּפּוֹדֵֽנוּ וּמַצִּילֵֽנוּ"}, {"kind": "text", "text": "מֵעוֹלָם הוּא שְׁמֶֽךָ"}, {"kind": "text", "text": "וְאֵין לָֽנוּ עוֹד אֱלֹהִים"}, {"kind": "text", "text": "זוּלָתֶֽךָ סֶֽלָה:"}, {"kind": "text", "text": "עֶזְרַת אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "אַתָּה הוּא מֵעוֹלָם"}, {"kind": "text", "text": "מָגֵן וּמוֹשִֽׁיעַ"}, {"kind": "text", "text": "לָהֶם וְלִבְ֒נֵיהֶם אַחֲרֵיהֶם"}, {"kind": "text", "text": "בְּכָל דּוֹר וָדוֹר:"}, {"kind": "text", "text": "בְּרוּם עוֹלָם"}, {"kind": "text", "text": "מוֹשָׁבֶֽךָ"}, {"kind": "text", "text": "וּמִשְׁפָּטֶֽיךָ וְצִדְקָתְךָ"}, {"kind": "text", "text": "עַד אַפְ֒סֵי אָֽרֶץ:"}, {"kind": "text", "text": "אֶמֶת אַשְׁרֵי אִישׁ"}, {"kind": "text", "text": "שֶׁיִּשְׁמַע לְמִצְוֹתֶֽיךָ"}, {"kind": "text", "text": "וְתוֹרָתְ֒ךָ וּדְבָרְ֒ךָ"}, {"kind": "text", "text": "יָשִׂים עַל לִבּוֹ:"}, {"kind": "text", "text": "אֱמֶת אַתָּה הוּא אָדוֹן לְעַמֶּֽךָ"}, {"kind": "text", "text": "וּמֶֽלֶךְ גִּבּוֹר לָרִיב רִיבָם"}, {"kind": "text", "text": "לְאָבוֹת וּבָנִים:"}, {"kind": "text", "text": "אֱמֶת אַתָּה הוּא רִאשׁוֹן"}, {"kind": "text", "text": "וְאַתָּה הוּא אַחֲרוֹן"}, {"kind": "text", "text": "וּמִבַּלְעָדֶֽיךָ"}, {"kind": "text", "text": "אֵין לָֽנוּ מֶֽלֶךְ גּוֹאֵל וּמוֹשִֽׁיעַ:"}, {"kind": "text", "text": "אֱמֶת מִמִּצְרַֽיִם גְּאַלְתָּֽנוּ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וּמִבֵּית עֲבָדִים פְּדִיתָֽנוּ:"}, {"kind": "text", "text": "כָּל בְּכוֹרֵיהֶם הָרָֽגְתָּ"}, {"kind": "text", "text": "וּבְ֒כוֹרְ֒ךָ יִשְׂרָאֵל גָּאָֽלְתָּ"}, {"kind": "text", "text": "וְיַם סוּף לָהֶם בָּקַֽעְתָּ"}, {"kind": "text", "text": "וְזֵדִים טִבַּֽעְתָּ"}, {"kind": "text", "text": "וִידִידִים הֶעֱבַֽרְתָּ"}, {"kind": "text", "text": "וַיְ֒כַסּוּ מַֽיִם צָרֵיהֶם"}, {"kind": "text", "text": "אֶחָד מֵהֶם לֹא נוֹתָר:"}, {"kind": "text", "text": "עַל זֹאת שִׁבְּ֒חוּ אֲהוּבִים"}, {"kind": "text", "text": "וְרוֹמְ֒מוּ לָאֵל"}, {"kind": "text", "text": "וְנָתְ֒נוּ יְדִידִים"}, {"kind": "text", "text": "זְמִירוֹת שִׁירוֹת וְתִשְׁבָּחוֹת"}, {"kind": "text", "text": "בְּרָכוֹת וְהוֹדָאוֹת"}, {"kind": "text", "text": "לְמֶּֽלֶךְ אֵל"}, {"kind": "text", "text": "חַי וְקַיָּם:"}, {"kind": "text", "text": "רָם וְנִשָּׂא"}, {"kind": "text", "text": "גָּדוֹל וְנוֹרָא"}, {"kind": "text", "text": "מַשְׁפִּיל גֵּאִים עֲדֵי אָֽרֶץ"}, {"kind": "text", "text": "וּמַגְבִּֽיהַּ שְׁפָלִים עֲדֵי מָרוֹם"}, {"kind": "text", "text": "מוֹצִיא אֲסִירִים"}, {"kind": "text", "text": "וּפוֹדֶה עֲנָוִים"}, {"kind": "text", "text": "וְעוֹזֵר דַּלִּים"}, {"kind": "text", "text": "וְעוֹנֶה לְעַמּוֹ יִשְׂרָאֵל"}, {"kind": "text", "text": "בְּעֵת שַׁוְּעָם אֵלָיו:"}, {"kind": "text", "text": "❖תְּהִלּוֹת לְאֵל עֶלְיוֹן"}, {"kind": "text", "text": "גֹּאֲלָם"}, {"kind": "text", "text": "בָּרוּךְ הוּא וּמְ֒בֹרָךְ,"}, {"kind": "text", "text": "משֶׁה וּבְ֒נֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "לְךָ עָנוּ שִׁירָה בְּשִׂמְחָה רַבָּה"}, {"kind": "text", "text": "וְאָמְ֒רוּ כֻלָּם:"}, {"kind": "text", "text": "מִי כָמֹֽכָה בָּאֵלִם יְהֹוָה"}, {"kind": "text", "text": "מִי כָּמֹֽכָה"}, {"kind": "text", "text": "נֶאְדָּר בַּקֹּֽדֶשׁ"}, {"kind": "text", "text": "נוֹרָא תְהִלֹּת עֹֽשֵׂה פֶֽלֶא:"}, {"kind": "text", "text": "שִׁירָה חֲדָשָׁה שִׁבְּ֒חוּ גְאוּלִים"}, {"kind": "text", "text": "לְשִׁמְךָ הַגָּדוֹל עַל שְׂפַת הַיָּם"}, {"kind": "text", "text": "יַֽחַד כֻּלָּם"}, {"kind": "text", "text": "הוֹדוּ"}, {"kind": "text", "text": "וְהִמְלִֽיכוּ"}, {"kind": "text", "text": "וְאָמְרוּ:"}, {"kind": "text", "text": "יְהֹוָה יִמְלֹךְ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "צוּר יִשְׂרָאֵל"}, {"kind": "text", "text": "קֽוּמָה בְּעֶזְרַת יִשְׂרָאֵל"}, {"kind": "text", "text": "וּפְ֒דֵה"}, {"kind": "text", "text": "כִנְ֒אֻמֶֽךָ יְהוּדָה וְיִשְׂרָאֵל,"}, {"kind": "text", "text": "❖גֹּאֲלֵֽנוּ"}, {"kind": "text", "text": "יְהֹוָה צְבָאוֹת שְׁמוֹ"}, {"kind": "text", "text": "קְדוֹשׁ יִשְׂרָאֵל:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "גָּאַל יִשְׂרָאֵל:"}, {"kind": "header", "text": "עמידה לשחרית של שבת"}, {"kind": "text", "text": "<b>אבות</b>"}, {"kind": "text", "text": "אֲדֹנָי שְׂפָתַי תִּפְתָּח"}, {"kind": "text", "text": "וּפִי יַגִּיד תְּהִלָּתֶֽךָ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "אֱלֹהֵי אַבְרָהָם אֱלֹהֵי יִצְחָק"}, {"kind": "text", "text": "וֵאלֹהֵי יַעֲקֹב"}, {"kind": "text", "text": "הָאֵל"}, {"kind": "text", "text": "הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא"}, {"kind": "text", "text": "אֵל עֶלְיוֹן"}, {"kind": "text", "text": "גּוֹמֵל חֲסָדִים טוֹבִים"}, {"kind": "text", "text": "וְקוֹנֵה הַכֹּל"}, {"kind": "text", "text": "וְזוֹכֵר חַסְדֵי אָבוֹת"}, {"kind": "text", "text": "וּמֵבִיא גוֹאֵל"}, {"kind": "text", "text": "לִבְנֵי בְנֵיהֶם"}, {"kind": "text", "text": "לְמַֽעַן שְׁמוֹ בְּאַהֲבָה:"}, {"kind": "instruction", "text": "זָכְרֵֽנוּ לְחַיִּים"}, {"kind": "instruction", "text": "מֶֽלֶךְ חָפֵץ בַּחַיִּים"}, {"kind": "instruction", "text": "וְכָתְבֵֽנוּ בְּסֵֽפֶר הַחַיִּים"}, {"kind": "instruction", "text": "לְמַעַנְךָ אֱלֹהִים חַיִּים:"}, {"kind": "text", "text": "מֶֽלֶךְ עוֹזֵר וּמוֹשִֽׁיעַ וּמָגֵן:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "מָגֵן אַבְרָהָם:"}, {"kind": "text", "text": "<b>גבורות</b>"}, {"kind": "text", "text": "אַתָּה גִבּוֹר לְעוֹלָם אֲדֹנָי"}, {"kind": "text", "text": "מְחַיֶּה מֵתִים אַתָּה"}, {"kind": "text", "text": "רַב לְהוֹשִֽׁיעַ:"}, {"kind": "text", "text": "<b>מוֹרִיד הַטָּל</b>"}, {"kind": "text", "text": "<b>מַשִּׁיב הָרֽוּחַ</b>"}, {"kind": "text", "text": "<b>וּמוֹרִיד הַגֶּֽשֶׁם:</b>"}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶֽסֶד"}, {"kind": "text", "text": "מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים"}, {"kind": "text", "text": "סוֹמֵךְ נוֹפְ֒לִים"}, {"kind": "text", "text": "וְרוֹפֵא חוֹלִים"}, {"kind": "text", "text": "וּמַתִּיר אֲסוּרִים"}, {"kind": "text", "text": "וּמְקַיֵּם אֱמוּנָתוֹ"}, {"kind": "text", "text": "לִישֵׁנֵי עָפָר."}, {"kind": "text", "text": "מִי כָמֽוֹךָ בַּֽעַל גְּבוּרוֹת"}, {"kind": "text", "text": "וּמִי דּֽוֹמֶה לָּךְ"}, {"kind": "text", "text": "מֶֽלֶךְ מֵמִית וּמְחַיֶּה"}, {"kind": "text", "text": "וּמַצְמִֽיחַ יְשׁוּעָה:"}, {"kind": "instruction", "text": "מִי כָמֽוֹךָ אַב הָרַחֲמִים"}, {"kind": "instruction", "text": "זוֹכֵר יְצוּרָיו לְחַיִּים"}, {"kind": "instruction", "text": "בְּרַחֲמִים:"}, {"kind": "text", "text": "וְנֶאֱמָן אַתָּה"}, {"kind": "text", "text": "לְהַחֲיוֹת מֵתִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "מְחַיֵּה הַמֵּתִים:"}, {"kind": "text", "text": "<b>קדושה</b>"}, {"kind": "text", "text": "נַקְדִישָׁךְ וְנַעֲרִיצָךְ"}, {"kind": "text", "text": "כְּנֹֽעַם שִֽׂיחַ"}, {"kind": "text", "text": "סוֹד שַׂרְ֒פֵי קֽוֹדֶשׁ"}, {"kind": "text", "text": "הַמְּ֒שַׁלְּ֒שִׁים לְךָ קְדֻשָּׁה"}, {"kind": "text", "text": "כַּכָּתוּב עַל יַד נְבִיאֶֽךָ"}, {"kind": "text", "text": "וְקָרָא זֶה אֶל זֶה וְאָמַר:"}, {"kind": "text", "text": "<b>קָדוֹשׁ קָדוֹשׁ קָדוֹשׁ</b>"}, {"kind": "text", "text": "<b>יְהֹוָה צְבָאוֹת</b>"}, {"kind": "text", "text": "<b>מְלֹא כָל הָאָֽרֶץ כְּבוֹדוֹ:</b>"}, {"kind": "text", "text": "לְעֻמָּתָם מְשַׁבְּ֒חִים וְאוֹמְ֒רִים:"}, {"kind": "text", "text": "❖אָז בְּקוֹל רַֽעַשׁ גָּדוֹל"}, {"kind": "text", "text": "אַדִּיר וְחָזָק"}, {"kind": "text", "text": "מַשְׁמִיעִים קוֹל"}, {"kind": "text", "text": "מִתְנַשְּׂ֒אִים לְעֻמַּת שְׂרָפִים."}, {"kind": "text", "text": "לְעֻמָּתָם מְשַׁבְּ֒חִים וְאוֹמְ֒רִים:"}, {"kind": "text", "text": "<b>בָּרוּךְ כְּבוֹד יְהֹוָה</b>"}, {"kind": "text", "text": "<b>מִמְּ֒קוֹמוֹ:</b>"}, {"kind": "text", "text": "❖מִמְּ֒קוֹמְךָ מַלְכֵּֽנוּ תוֹפִֽיעַ"}, {"kind": "text", "text": "וְתִמְלוֹךְ עָלֵֽינוּ"}, {"kind": "text", "text": "כִּי מְחַכִּים אֲנַֽחְנוּ לָךְ."}, {"kind": "text", "text": "מָתַי תִּמְלוֹךְ בְּצִיּוֹן"}, {"kind": "text", "text": "בְּקָרוֹב בְּיָמֵֽינוּ"}, {"kind": "text", "text": "לְעוֹלָם וָעֶד תִּשְׁכּוֹן."}, {"kind": "text", "text": "תִּתְגַּדַּל וְתִתְקַדַּשׁ"}, {"kind": "text", "text": "בְּתוֹךְ יְרוּשָׁלַֽםִ עִירְ֒ךָ"}, {"kind": "text", "text": "לְדוֹר וָדוֹר וּלְנֵֽצַח נְצָחִים."}, {"kind": "text", "text": "וְעֵינֵֽינוּ תִרְאֶֽינָה מַלְכוּתֶֽךָ"}, {"kind": "text", "text": "כַּדָּבָר הָאָמוּר בְּשִׁירֵי עֻזֶּֽךָ"}, {"kind": "text", "text": "עַל יְדֵי דָוִד"}, {"kind": "text", "text": "מְשִֽׁיחַ צִדְקֶֽךָ:"}, {"kind": "text", "text": "<b>יִמְלֹךְ יְהֹוָה לְעוֹלָם</b>"}, {"kind": "text", "text": "<b>אֱלֹהַֽיִךְ צִיּוֹן לְדֹר וָדֹר</b>"}, {"kind": "text", "text": "<b>הַלְ֒לוּיָהּ:</b>"}, {"kind": "text", "text": "<b>קדושת השם</b>"}, {"kind": "text", "text": "אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ"}, {"kind": "text", "text": "וּקְדוֹשִׁים"}, {"kind": "text", "text": "בְּכָל יוֹם יְהַלְ֒לֽוּךָ סֶּֽלָה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הָאֵל הַקָּדוֹשׁ:"}, {"kind": "instruction", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "instruction", "text": "הַמֶּֽלֶךְ הַקָּדוֹשׁ:"}, {"kind": "text", "text": "יִשְׂמַח משֶׁה"}, {"kind": "text", "text": "בְּמַתְּ֒נַת חֶלְקוֹ."}, {"kind": "text", "text": "כִּי עֶֽבֶד נֶאֱמָן קָרָֽאתָ־לּוֹ."}, {"kind": "text", "text": "כְּלִיל תִּפְאֶֽרֶת"}, {"kind": "text", "text": "בְּרֹאשׁוֹ נָתַֽתָּ לוֹ"}, {"kind": "text", "text": "בְּעָמְדוֹ לְפָנֶֽיךָ עַל־הַר סִינָי."}, {"kind": "text", "text": "וּשְׁנֵי לוּחוֹת אֲבָנִים"}, {"kind": "text", "text": "הוֹרִיד בְּיָדוֹ"}, {"kind": "text", "text": "וְכָתוּב בָּהֶם"}, {"kind": "text", "text": "שְׁמִירַת שַׁבָּת."}, {"kind": "text", "text": "וְכֵן כָּתוּב בְּתוֹרָתֶֽךָ:"}, {"kind": "text", "text": "וְשָׁמְ֒רוּ בְנֵי־יִשְׂרָאֵל"}, {"kind": "text", "text": "אֶת־הַשַּׁבָּת."}, {"kind": "text", "text": "לַעֲשׂוֹת אֶת־הַשַּׁבָּת לְדֹרֹתָם"}, {"kind": "text", "text": "בְּרִית עוֹלָם:"}, {"kind": "text", "text": "בֵּינִי"}, {"kind": "text", "text": "וּבֵין בְּנֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "אוֹת הִיא לְעֹלָם."}, {"kind": "text", "text": "כִּי־שֵֽׁשֶׁת יָמִים עָשָׂה יְהֹוָה"}, {"kind": "text", "text": "אֶת־הַשָּׁמַֽיִם וְאֶת־הָאָֽרֶץ"}, {"kind": "text", "text": "וּבַיּוֹם הַשְּׁ֒בִיעִי"}, {"kind": "text", "text": "שָׁבַת וַיִּנָּפַשׁ:"}, {"kind": "text", "text": "וְלֹא נְתַתּוֹ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "לְגוֹיֵי הָאֲרָצוֹת."}, {"kind": "text", "text": "וְלֹא הִנְחַלְתּוֹ"}, {"kind": "text", "text": "מַלְכֵּֽנוּ"}, {"kind": "text", "text": "לְעוֹבְ֒דֵי פְסִילִים."}, {"kind": "text", "text": "וְגַם בִּמְנוּחָתוֹ"}, {"kind": "text", "text": "לֹא יִשְׁכְּ֒נוּ עֲרֵלִים."}, {"kind": "text", "text": "כִּי לְיִשְׂרָאֵל עַמְּ֒ךָ"}, {"kind": "text", "text": "נְתַתּוֹ בְּאַהֲבָה."}, {"kind": "text", "text": "לְזֶֽרַע יַעֲקֹב"}, {"kind": "text", "text": "אֲשֶׁר בָּם בָּחָרְתָּ:"}, {"kind": "text", "text": "יִשְׂמְחוּ בְמַלְכוּתְ֒ךָ"}, {"kind": "text", "text": "שׁוֹמְ֒רֵי שַׁבָּת"}, {"kind": "text", "text": "וְקוֹרְ֒אֵי עוֹנֶג."}, {"kind": "text", "text": "עַם מְקַדְּ֒שֵׁי שְׁבִיעִי"}, {"kind": "text", "text": "כֻּלָּם יִשְׂבְּ֒עוּ"}, {"kind": "text", "text": "וְיִתְעַנְּ֒גוּ מִטּוּבֶֽךָ."}, {"kind": "text", "text": "וּבַשְּׁ֒בִיעִי רָצִֽיתָ בּוֹ"}, {"kind": "text", "text": "וְקִדַּשְׁתּוֹ."}, {"kind": "text", "text": "חֶמְדַּת יָמִים אוֹתוֹ קָרָֽאתָ."}, {"kind": "text", "text": "זֵֽכֶר לְמֲַשֵׂה בְרֵאשִׁית:"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "רְצֵה בִמְנוּחָתֵֽנוּ."}, {"kind": "text", "text": "קַדְּ֒שֵֽׁנוּ בְּמִצְוֹתֶֽיךָ"}, {"kind": "text", "text": "וְתֵן חֶלְקֵֽנוּ בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "שַׂבְּ֒עֵֽנוּ מִטּוּבֶֽךָ."}, {"kind": "text", "text": "וְשַׂמְּ֒חֵֽנוּ בִּישׁוּעָתֶֽךָ."}, {"kind": "text", "text": "וְטַהֵר לִבֵּֽנוּ לְעָבְדְּ֒ךָ בֶּאֱמֶת."}, {"kind": "text", "text": "וְהַנְחִילֵֽנוּ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בְּאַהֲבָה וּבְרָצוֹן"}, {"kind": "text", "text": "שַׁבַּת קָדְשֶֽׁךָ."}, {"kind": "text", "text": "וְיָנֽוּחוּ בוֹ יִשְׂרָאֵל"}, {"kind": "text", "text": "מְקַדְּ֒שֵׁי שְׁמֶֽךָ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "מְקַדֵּשׁ הַשַּׁבָּת:"}, {"kind": "text", "text": "<b>עבודה</b>"}, {"kind": "text", "text": "רְצֵה יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בְּעַמְּ֒ךָ יִשְׂרָאֵל וּבִתְפִלָּתָם."}, {"kind": "text", "text": "וְהָשֵׁב אֶת הָעֲבוֹדָה"}, {"kind": "text", "text": "לִדְבִיר בֵּיתֶֽךָ"}, {"kind": "text", "text": "וְאִשֵּׁי יִשְׂרָאֵל."}, {"kind": "text", "text": "וּתְפִלָּתָם בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן"}, {"kind": "text", "text": "וּתְהִי לְרָצוֹן תָּמִיד"}, {"kind": "text", "text": "עֲבוֹדַת יִשְׂרָאֵל עַמֶּֽךָ:"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "יַעֲלֶה וְיָבֹא וְיַגִּֽיעַ"}, {"kind": "text", "text": "וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע"}, {"kind": "text", "text": "וְיִפָּקֵד וְיִזָּכֵר"}, {"kind": "text", "text": "זִכְרוֹנֵֽנוּ וּפִקְדוֹנֵֽנוּ"}, {"kind": "text", "text": "וְזִכְרוֹן אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "וְזִכְרוֹן מָשִֽׁיחַ"}, {"kind": "text", "text": "בֶּן דָּוִד עַבְדֶּֽךָ"}, {"kind": "text", "text": "וְזִכְרוֹן יְרוּשָׁלַֽםִ"}, {"kind": "text", "text": "עִיר קָדְשֶֽׁךָ"}, {"kind": "text", "text": "וְזִכְרוֹן כָּל עַמְּ֒ךָ"}, {"kind": "text", "text": "בֵּית יִשְׂרָאֵל לְפָנֶֽיךָ."}, {"kind": "text", "text": "לִפְלֵיטָה לְטוֹבָה"}, {"kind": "text", "text": "לְחֵן וּלְחֶֽסֶד וּלְרַחֲמִים"}, {"kind": "text", "text": "לְחַיִּים וּלְשָׁלוֹם"}, {"kind": "text", "text": "בְּיוֹם"}, {"kind": "text", "text": "לר\"ח: רֹאשׁ הַחֹֽדֶשׁ הַזֶּה"}, {"kind": "text", "text": "לפסח: חַג הַמַּצּוֹת הַזֶּה"}, {"kind": "text", "text": "לסכות: חַג הַסֻּכּוֹת הַזֶּה"}, {"kind": "text", "text": "זָכְרֵֽנוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בּוֹ לְטוֹבָה."}, {"kind": "text", "text": "וּפָקְדֵֽנוּ בוֹ לִבְרָכָה."}, {"kind": "text", "text": "וְהוֹשִׁיעֵֽנוּ בוֹ לְחַיִּים."}, {"kind": "text", "text": "וּבִדְבַר יְשׁוּעָה"}, {"kind": "text", "text": "וְרַחֲמִים"}, {"kind": "text", "text": "חוּס וְחָנֵּֽנוּ."}, {"kind": "text", "text": "וְרַחֵם עָלֵֽינוּ וְהוֹשִׁיעֵֽנוּ."}, {"kind": "text", "text": "כִּי אֵלֶֽיךָ עֵינֵֽינוּ."}, {"kind": "text", "text": "כִּי אֵל"}, {"kind": "text", "text": "מֶֽלֶךְ חַנּוּן וְרַחוּם אָֽתָּה:"}, {"kind": "text", "text": "וְתֶחֱזֶֽינָה עֵינֵֽינוּ"}, {"kind": "text", "text": "בְּשׁוּבְ֒ךָ לְצִיּוֹן בְּרַחֲמִים."}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן:"}, {"kind": "text", "text": "<b>הודאה</b>"}, {"kind": "text", "text": "מוֹדִים אֲנַֽחְנוּ לָךְ"}, {"kind": "text", "text": "שָׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וֵאלֹהֵי אֲבוֹתֵֽינוּ לְעוֹלָם וָעֶד"}, {"kind": "text", "text": "צוּר חַיֵּֽינוּ"}, {"kind": "text", "text": "מָגֵן יִשְׁעֵֽנוּ"}, {"kind": "text", "text": "אַתָּה הוּא לְדוֹר וָדוֹר"}, {"kind": "text", "text": "נוֹדֶה לְּךָ"}, {"kind": "text", "text": "וּנְסַפֵּר תְּהִלָּתֶֽךָ"}, {"kind": "text", "text": "עַל חַיֵּֽינוּ"}, {"kind": "text", "text": "הַמְּ֒סוּרִים בְּיָדֶֽךָ"}, {"kind": "text", "text": "וְעַל נִשְׁמוֹתֵֽינוּ הַפְּ֒קוּדוֹת לָךְ"}, {"kind": "text", "text": "וְעַל נִסֶּֽיךָ שֶׁבְּ֒כָל יוֹם עִמָּֽנוּ"}, {"kind": "text", "text": "וְעַל נִפְלְ֒אוֹתֶֽיךָ וְטוֹבוֹתֶֽיךָ"}, {"kind": "text", "text": "שֶׁבְּ֒כָל עֵת."}, {"kind": "text", "text": "עֶֽרֶב וָבֹֽקֶר וְצָהֳרָֽיִם."}, {"kind": "text", "text": "הַטּוֹב"}, {"kind": "text", "text": "כִּי לֹא כָלוּ רַחֲמֶֽיךָ"}, {"kind": "text", "text": "וְהַמְ֒רַחֵם"}, {"kind": "text", "text": "כִּי לֹא תַֽמּוּ חֲסָדֶֽיךָ."}, {"kind": "text", "text": "מֵעוֹלָם קִוִּֽינוּ לָךְ:"}, {"kind": "text", "text": "מוֹדִים אֲנַֽחְנוּ לָךְ"}, {"kind": "text", "text": "שָׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "אֱלֹהֵי כָל בָּשָׂר"}, {"kind": "text", "text": "יוֹצְ֒רֵֽנוּ יוֹצֵר בְּרֵאשִׁית"}, {"kind": "text", "text": "בְּרָכוֹת וְהוֹדָאוֹת"}, {"kind": "text", "text": "לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ"}, {"kind": "text", "text": "עַל שֶׁהֶחֱיִיתָֽנוּ וְקִיַּמְתָּֽנוּ"}, {"kind": "text", "text": "כֵּן תְּחַיֵּֽינוּ"}, {"kind": "text", "text": "וּתְקַיְּ֒מֵֽנוּ"}, {"kind": "text", "text": "וְתֶאֱסוֹף גָּלֻיּוֹתֵֽינוּ"}, {"kind": "text", "text": "לְחַצְרוֹת קָדְשֶֽׁךָ"}, {"kind": "text", "text": "לִשְׁמוֹר חֻקֶּֽיךָ"}, {"kind": "text", "text": "וְלַעֲשׂוֹת רְצוֹנֶֽךָ"}, {"kind": "text", "text": "וּלְעָבְדְּ֒ךָ בְּלֵבָב שָׁלֵם"}, {"kind": "text", "text": "עַל שֶׁאָֽנוּ מוֹדִים לָךְ."}, {"kind": "text", "text": "בָּרוּךְ אֵל"}, {"kind": "text", "text": "הַהוֹדָאוֹת:"}, {"kind": "text", "text": "וְעַל הַנִּסִּים"}, {"kind": "text", "text": "וְעַל הַפֻּרְקָן וְעַל הַגְּ֒בוּרוֹת"}, {"kind": "text", "text": "וְעַל הַתְּ֒שׁוּעוֹת וְעַל הַמִּלְחָמוֹת"}, {"kind": "text", "text": "שֶׁעָשִֽׂיתָ לַאֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "בַּיָּמִים הָהֵם בַּזְּ֒מַן הַזֶּה:"}, {"kind": "text", "text": "בִּימֵי מַתִּתְיָֽהוּ"}, {"kind": "text", "text": "בֶּן יוֹחָנָן כֹּהֵן גָּדוֹל"}, {"kind": "text", "text": "חַשְׁמוֹנַאי וּבָנָיו"}, {"kind": "text", "text": "כְּשֶׁעָמְ֒דָה מַלְכוּת יָוָן הָרְ֒שָׁעָה"}, {"kind": "text", "text": "עַל עַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "לְהַשְׁכִּיחָם תּוֹרָתֶֽךָ"}, {"kind": "text", "text": "וּלְהַעֲבִירָם"}, {"kind": "text", "text": "מֵחֻקֵּי רְצוֹנֶֽךָ."}, {"kind": "text", "text": "וְאַתָּה בְּרַחֲמֶֽיךָ הָרַבִּים"}, {"kind": "text", "text": "עָמַֽדְתָּ לָהֶם בְּעֵת צָרָתָם"}, {"kind": "text", "text": "רַֽבְתָּ אֶת רִיבָם"}, {"kind": "text", "text": "דַּֽנְתָּ אֶת דִּינָם"}, {"kind": "text", "text": "נָקַֽמְתָּ אֶת נִקְמָתָם"}, {"kind": "text", "text": "מָסַֽרְתָּ גִבּוֹרִים"}, {"kind": "text", "text": "בְּיַד חַלָּשִׁים"}, {"kind": "text", "text": "וְרַבִּים בְּיַד מְעַטִּים"}, {"kind": "text", "text": "וּטְמֵאִים בְּיַד טְהוֹרִים"}, {"kind": "text", "text": "וּרְשָׁעִים בְּיַד צַדִּיקִים"}, {"kind": "text", "text": "וְזֵדִים בְּיַד"}, {"kind": "text", "text": "עוֹסְ֒קֵי תוֹרָתֶֽךָ"}, {"kind": "text", "text": "וּלְךָ עָשִֽׂיתָ"}, {"kind": "text", "text": "שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶֽךָ"}, {"kind": "text", "text": "וּלְעַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "עָשִֽׂיתָ תְּשׁוּעָה גְדוֹלָה"}, {"kind": "text", "text": "וּפֻרְקָן כְּהַיּוֹם הַזֶּה"}, {"kind": "text", "text": "וְאַחַר כַּךְ בָּֽאוּ בָנֶֽיךָ"}, {"kind": "text", "text": "לִדְבִיר בֵּיתֶֽךָ"}, {"kind": "text", "text": "וּפִנּוּ אֶת הֵיכָלֶֽךָ"}, {"kind": "text", "text": "וְטִהֲרוּ אֶת מִקְדָּשֶֽׁךָ"}, {"kind": "text", "text": "וְהִדְלִֽיקוּ נֵרוֹת"}, {"kind": "text", "text": "בְּחַצְרוֹת קָדְשֶֽׁךָ"}, {"kind": "text", "text": "וְקָבְ֒עוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵֽלּוּ"}, {"kind": "text", "text": "לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל:"}, {"kind": "text", "text": "וְעַל כֻּלָּם"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵׂא"}, {"kind": "text", "text": "שִׁמְ֒ךָ מַלְכֵּֽנוּ"}, {"kind": "text", "text": "תָּמִיד לְעוֹלָם וָעֶד:"}, {"kind": "instruction", "text": "וּכְתֹב לְחַיִּים טוֹבִים"}, {"kind": "instruction", "text": "כָּל בְּנֵי בְרִיתֶֽךָ:"}, {"kind": "text", "text": "וְכֹל הַחַיִּים יוֹדֽוּךָ סֶּֽלָה"}, {"kind": "text", "text": "וִיהַלְ֒לוּ וְיבָרְ֒כוּ"}, {"kind": "text", "text": "אֶת שִׁמְ֒ךָ הַגָּדוֹל בְּאֱמֶת לְעוֹלָם"}, {"kind": "text", "text": "כִּי טוֹב"}, {"kind": "text", "text": "הָאֵל יְשׁוּעָתֵֽנוּ"}, {"kind": "text", "text": "וְעֶזְרָתֵֽנוּ סֶֽלָה"}, {"kind": "text", "text": "הָאֵל הַטּוֹב:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַטּוֹב שִׁמְ֒ךָ"}, {"kind": "text", "text": "וּלְ֒ךָ נָאֶה לְהוֹדוֹת:"}, {"kind": "text", "text": "<b>ברכת כהנים</b>"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ בָּרְ֒כֵֽנוּ"}, {"kind": "text", "text": "בַבְּ֒רָכָה הַמְּ֒שֻׁלֶּֽשֶׁת בַּתּוֹרָה"}, {"kind": "text", "text": "הַכְּ֒תוּבָה עַל יְדֵי משֶׁה עַבְדֶּֽךָ,"}, {"kind": "text", "text": "הָאֲמוּרָה מִפִּי אַהֲרֹן"}, {"kind": "text", "text": "וּבָנָיו כֹּהֲנִים עַם קְדוֹשֶֽׁךָ"}, {"kind": "text", "text": "כָּאָמוּר:"}, {"kind": "text", "text": "יְבָרֶכְךָ יְהֹוָה וְיִשְׁמְ֒רֶֽךָ:"}, {"kind": "text", "text": "יָאֵר יְהֹוָה פָּנָיו אֵלֶֽיךָ"}, {"kind": "text", "text": "וִיחֻנֶּֽךָ:"}, {"kind": "text", "text": "יִשָּׂא יְהֹוָה פָּנָיו אֵלֶֽיךָ"}, {"kind": "text", "text": "וְיָשֵׂם לְךָ שָׁלוֹם:"}, {"kind": "text", "text": "אַדִּיר בַּמָּרוֹם שׁוֹכֵן בִּגְ֒בוּרָה,"}, {"kind": "text", "text": "אַתָּה שָׁלוֹם וְשִׁמְ֒ךָ שָׁלוֹם."}, {"kind": "text", "text": "יְהִי רָצוֹן שֶׁתָּשִׂים עָלֵֽינוּ"}, {"kind": "text", "text": "וְעַל כָּל עַמְּ֒ךָ בֵּית יִשְׂרָאֵל"}, {"kind": "text", "text": "חַיִּים וּבְ֒רָכָה"}, {"kind": "text", "text": "לְמִשְׁמֶֽרֶת שָׁלוֹם:"}, {"kind": "text", "text": "<b>שלום</b>"}, {"kind": "text", "text": "שִׂים שָׁלוֹם טוֹבָה וּבְ֒רָכָה"}, {"kind": "text", "text": "חַיִים חֵן וָחֶֽסֶד וְרַחֲמִים"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּֽךָ,"}, {"kind": "text", "text": "בָּרְ֒כֵֽנוּ אָבִֽינוּ כֻּלָּֽנוּ כְּאֶחָד"}, {"kind": "text", "text": "בְּאוֹר פָּנֶֽיךָ"}, {"kind": "text", "text": "כִּי בְאוֹר פָּנֶֽיךָ"}, {"kind": "text", "text": "נָתַֽתָּ לָּֽנוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "תּוֹרַת חַיִּים וְאַהֲבַת חֶֽסֶד"}, {"kind": "text", "text": "וּצְ֒דָקָה וּבְ֒רָכָה וְרַחֲמִים"}, {"kind": "text", "text": "וְחַיִּים וְשָׁלוֹם,"}, {"kind": "text", "text": "וְטוֹב יִהְיֶה בְּעֵינֶֽיךָ"}, {"kind": "text", "text": "לְבָרְ֒כֵֽנוּ"}, {"kind": "text", "text": "וּלְ֒בָרֵךְ אֶת כָּל עַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "בְּכָל עֵת וּבְכָל שָׁעָה"}, {"kind": "text", "text": "בִּשְׁ֒לוֹמֶֽךָ"}, {"kind": "text", "text": "(בְּרוֹב עוֹז וְשָׁלוֹם)."}, {"kind": "instruction", "text": "בְּסֵֽפֶר חַיִּים בְּרָכָה וְשָׁלוֹם"}, {"kind": "instruction", "text": "וּפַרְנָסָה טוֹבָה"}, {"kind": "instruction", "text": "וּגְ֒זֵרוֹת טוֹבוֹת, יְשׁוּעוֹת וְנֶחָמוֹת,"}, {"kind": "instruction", "text": "נִזָּכֵר וְנִכָּתֵב"}, {"kind": "instruction", "text": "לְפָנֶֽיךָ"}, {"kind": "instruction", "text": "אֲנַֽחְנוּ וְכָל עַמְּ֒ךָ בֵּית יִשְׂרָאֵל"}, {"kind": "instruction", "text": "לְחַיִּים טוֹבִים וּלְ֒שָׁלוֹם:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַמְּ֒בָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל"}, {"kind": "text", "text": "בַּשָּׁלוֹם:"}, {"kind": "text", "text": "יִהְיוּ לְרָצוֹן"}, {"kind": "text", "text": "אִמְ֒רֵי פִי"}, {"kind": "text", "text": "וְהֶגְיוֹן לִבִּי לְפָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה צוּרִי וְגוֹאֲלִי:"}, {"kind": "text", "text": "אֱלֹהַי נְצוֹר לְשׁוֹנִי מֵרָע"}, {"kind": "text", "text": "וּשְׂ֒פָתַי מִדַּבֵּר מִרְמָה"}, {"kind": "text", "text": "וְלִמְ֒קַלְ֒לַי"}, {"kind": "text", "text": "נַפְשִׁי תִדּוֹם"}, {"kind": "text", "text": "וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה"}, {"kind": "text", "text": "פְּתַח לִבִּי בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "וְאַחֲרֵי מִצְוֹתֶֽיךָ תִּרְדּוֹף נַפְשִׁי"}, {"kind": "text", "text": "וְכָל הַקָמִים וְהַחוֹשְׁ֒בִים עָלַי רָעָה"}, {"kind": "text", "text": "מְהֵרָה הָפֵר עֲצָתָם"}, {"kind": "text", "text": "וְקַלְקֵל מַחֲשַׁבְתָּם:"}, {"kind": "text", "text": "(יְהִי רָצוֹן מִלְ֒פָנֶיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי"}, {"kind": "text", "text": "שֶׁלֹּא תַעֲלֶה קִנְאַת אָדָם עָלַי"}, {"kind": "text", "text": "וְלֹא קִנְאָתִי עַל אֲחֵרִים"}, {"kind": "text", "text": "וְשֶׁלֹּא אֶכְעֹס הַיּוֹם"}, {"kind": "text", "text": "וְשֶׁלֹּא אַכְעִיסֶֽךָ"}, {"kind": "text", "text": "וְתַצִּילֵנִי מִיֵּֽצֶר הָרָע"}, {"kind": "text", "text": "וְתֵן בְּלִבִּי הַכְנָעָה וַעֲנָוָה."}, {"kind": "text", "text": "מַלְכֵּֽנוּ וֵאלֹהֵֽינוּ"}, {"kind": "text", "text": "יַחֵד שִׁמְ֒ךָ בְּעוֹלָמֶֽךָ,"}, {"kind": "text", "text": "בְּנֵה עִירְ֒ךָ, יַסֵּד בֵּיתֶֽךָ,"}, {"kind": "text", "text": "וְשַׁכְלֵל הֵיכָלֶֽךָ."}, {"kind": "text", "text": "וְקַבֵּץ קִבּוּץ גָּלֻיּוֹת,"}, {"kind": "text", "text": "וּפְ֒דֵה צֹאנֶֽךָ וְשַׂמַּח עֲדָתֶֽךָ.)"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן שְׁמֶֽךָ,"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן יְמִינֶֽךָ,"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן תּוֹרָתֶֽךָ,"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן קְדֻשָּׁתֶֽךָ."}, {"kind": "text", "text": "לְמַֽעַן יֵחָלְ֒צוּן יְדִידֶֽיךָ"}, {"kind": "text", "text": "הוֹשִֽׁיעָה יְמִינְ֒ךָ וַעֲנֵֽנִי:"}, {"kind": "text", "text": "יִהְיוּ לְרָצוֹן"}, {"kind": "text", "text": "אִמְרֵי פִי"}, {"kind": "text", "text": "וְהֶגְיוֹן לִבִּי לְפָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה צוּרִי וְגוֹאֲלִי:"}, {"kind": "text", "text": "עֹשֶׂה (בעשי\"ת הַשָּׁלוֹם) שָׁלוֹם בִּמְ֒רוֹמָיו"}, {"kind": "text", "text": "הוּא יַעֲשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהִי רָצוֹן מִלְּ֒פָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ"}, {"kind": "text", "text": "בִּמְהֵרָה בְיָמֵֽינוּ"}, {"kind": "text", "text": "וְתֵן חֶלְקֵֽנוּ בְּתוֹרָתֶֽךָ:"}, {"kind": "text", "text": "וְשָׁם נַעֲבָדְ֒ךָ בְּיִרְאָה"}, {"kind": "text", "text": "כִּימֵי עוֹלָם"}, {"kind": "text", "text": "וּכְ֒שָׁנִים קַדְמוֹנִיּוֹת:"}, {"kind": "text", "text": "וְעָרְ֒בָה לַיהוֹה"}, {"kind": "text", "text": "מִנְחַת יְהוּדָה וִירוּשָׁלָֽםִ"}, {"kind": "text", "text": "כִּימֵי עוֹלָם וּכְ֒שָׁנִים קַדְמוֹנִיּוֹת:"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְמָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְעוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְכוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְקָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ."}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְחַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל."}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְמַן קָרִיב"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְעָלְמֵי עָלְמַיָּא:"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקֻדְשָׁא. בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵֽלָּא (בעשי\"ת וּלְעֵֽלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְכָתָא וְשִׁירָתָא."}, {"kind": "text", "text": "תֻּשְׁבְּ֒חָתָא וְנֶחֱמָתָא."}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "תִּתְקַבֵּל"}, {"kind": "text", "text": "צְלוֹתְ֒הוֹן וּבָעוּתְ֒הוֹן"}, {"kind": "text", "text": "דְּכָל בֵּית יִשְׂרָאֵל"}, {"kind": "text", "text": "קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא"}, {"kind": "text", "text": "וְחַיִּים"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו"}, {"kind": "text", "text": "הוּא יַעֲשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "הַיּוֹם שַׁבָּת קֹֽדֶשׁ"}, {"kind": "text", "text": "שֶׁבּוֹ הָיוּ הַלְ֒וִיִּם אוֹמְ֒רִים"}, {"kind": "text", "text": "בְּבֵית הַמִּקְדָּשׁ:"}, {"kind": "text", "text": "מִזְמוֹר שִׁיר לְיוֹם הַשַּׁבָּת:"}, {"kind": "text", "text": "טוֹב לְהֹדוֹת לַיהֹוָה"}, {"kind": "text", "text": "וּלְזַמֵּר לְשִׁמְךָ עֶלְיוֹן:"}, {"kind": "text", "text": "לְהַגִּיד בַּבֹּֽקֶר חַסְדֶּֽךָ"}, {"kind": "text", "text": "וֶאֱמוּנָתְ֒ךָ בַּלֵּילוֹת:"}, {"kind": "text", "text": "עֲלֵי־עָשׂוֹר וַעֲלֵי־נָֽבֶל"}, {"kind": "text", "text": "עֲלֵי הִגָּיוֹן בְּכִנּוֹר:"}, {"kind": "text", "text": "כִּי שִׂמַּחְתַּֽנִי יְהֹוָה"}, {"kind": "text", "text": "בְּפָעֳלֶֽךָ"}, {"kind": "text", "text": "בְּמַעֲשֵׂי יָדֶֽיךָ אֲרַנֵּן:"}, {"kind": "text", "text": "מַה־גָּדְ֒לוּ מַעֲשֶֽׂיךָ יְהֹוָה"}, {"kind": "text", "text": "מְאֹד עָמְ֒קוּ מַחְשְׁ֒בֹתֶֽיךָ:"}, {"kind": "text", "text": "אִישׁ־בַּֽעַר לֹא יֵדָע"}, {"kind": "text", "text": "וּכְסִיל לֹא־יָבִין אֶת־זֹאת:"}, {"kind": "text", "text": "בִּפְרֹֽחַ רְשָׁעִים כְּמוֹ עֵֽשֶׂב"}, {"kind": "text", "text": "וַיָּצִֽיצוּ כָּל־פֹּֽעֲלֵי אָֽוֶן"}, {"kind": "text", "text": "לְהִשָּׁמְדָם עֲדֵי־עַד:"}, {"kind": "text", "text": "וְאַתָּה מָרוֹם לְעֹלָם יְהֹוָה:"}, {"kind": "text", "text": "כִּי הִנֵּה אֹיְ֒בֶֽיךָ יְהֹוָה"}, {"kind": "text", "text": "כִּי־הִנֵּה אֹיְ֒בֶֽיךָ יֹאבֵֽדוּ"}, {"kind": "text", "text": "יִתְפָּרְ֒דוּ כָּל־פֹּֽעֲלֵי אָֽוֶן:"}, {"kind": "text", "text": "וַתָּֽרֶם כִּרְאֵים קַרְנִי"}, {"kind": "text", "text": "בַּלֹּתִי בְּשֶֽׁמֶן רַעֲנָן:"}, {"kind": "text", "text": "וַתַּבֵּט עֵינִי"}, {"kind": "text", "text": "בְּשׁוּרָי"}, {"kind": "text", "text": "בַּקָּמִים עָלַי מְרֵעִים"}, {"kind": "text", "text": "תִּשְׁמַֽעְנָה אָזְנָי:"}, {"kind": "text", "text": "צַדִּיק כַּתָּמָר יִפְרָח"}, {"kind": "text", "text": "כְּאֶֽרֶז בַּלְּ֒בָנוֹן יִשְׂגֶּה:"}, {"kind": "text", "text": "שְׁתוּלִים בְּבֵית יְהֹוָה"}, {"kind": "text", "text": "בְּחַצְרוֹת אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "יַפְרִֽיחוּ:"}, {"kind": "text", "text": "❖עוֹד יְנוּבוּן בְּשֵׂיבָה"}, {"kind": "text", "text": "דְּשֵׁנִים וְרַעֲנַנִּים יִהְיוּ:"}, {"kind": "text", "text": "לְהַגִּיד כִּי־יָשָׁר יְהֹוָה"}, {"kind": "text", "text": "צוּרִי"}, {"kind": "text", "text": "וְלֹא־עַוְלָֽתָה בּוֹ:"}, {"kind": "text", "text": "לְדָוִד"}, {"kind": "text", "text": "יְהֹוָה אוֹרִי וְיִשְׁעִי"}, {"kind": "text", "text": "מִמִּי אִירָא"}, {"kind": "text", "text": "יְהֹוָה מָעוֹז חַיַּי"}, {"kind": "text", "text": "מִמִּי אֶפְחָד:"}, {"kind": "text", "text": "בִּקְרֹב עָלַי מְרֵעִים"}, {"kind": "text", "text": "לֶאֱכֹל אֶת בְּשָׂרִי"}, {"kind": "text", "text": "צָרַי וְאֹיְ֒בַי לִי"}, {"kind": "text", "text": "הֵֽמָּה כָשְׁ֒לוּ וְנָפָֽלוּ:"}, {"kind": "text", "text": "אִם תַּחֲנֶה עָלַי מַחֲנֶה"}, {"kind": "text", "text": "לֹא יִירָא לִבִּי"}, {"kind": "text", "text": "אִם תָּקוּם עָלַי מִלְחָמָה"}, {"kind": "text", "text": "בְּזֹאת אֲנִי בוֹטֵֽחַ:"}, {"kind": "text", "text": "אַחַת שָׁאַֽלְתִּי מֵאֵת יְהֹוָה"}, {"kind": "text", "text": "אוֹתָהּ אֲבַקֵּשׁ"}, {"kind": "text", "text": "שִׁבְתִּי בְּבֵית יְהֹוָה"}, {"kind": "text", "text": "כָּל יְמֵי חַיַּי"}, {"kind": "text", "text": "לַחֲזוֹת בְּנֹֽעַם יְהֹוָה"}, {"kind": "text", "text": "וּלְבַקֵּר בְּהֵיכָלוֹ:"}, {"kind": "text", "text": "כִּי יִצְפְּ֒נֵֽנִי בְּסֻכֹּה"}, {"kind": "text", "text": "בְּיוֹם רָעָה"}, {"kind": "text", "text": "יַסְתִּרֵֽנִי בְּסֵֽתֶר אָהֳלוֹ"}, {"kind": "text", "text": "בְּצוּר יְרוֹמְ֒מֵֽנִי:"}, {"kind": "text", "text": "וְעַתָּה יָרוּם רֹאשִׁי"}, {"kind": "text", "text": "עַל אֹיְ֒בַי סְבִיבוֹתָי"}, {"kind": "text", "text": "וְאֶזְבְּ֒חָה בְאָהֳלוֹ"}, {"kind": "text", "text": "זִבְחֵי תְרוּעָה"}, {"kind": "text", "text": "אָשִֽׁירָה וַאֲזַמְּ֒רָה לַיהֹוָה:"}, {"kind": "text", "text": "שְׁמַע יְהֹוָה קוֹלִי אֶקְרָא"}, {"kind": "text", "text": "וְחָנֵּֽנִי וַעֲנֵֽנִי:"}, {"kind": "text", "text": "לְךָ אָמַר לִבִּי"}, {"kind": "text", "text": "בַּקְּ֒שׁוּ פָנָי"}, {"kind": "text", "text": "אֶת פָּנֶֽיךָ יְהֹוָה אֲבַקֵּשׁ:"}, {"kind": "text", "text": "אַל תַּסְתֵּר פָּנֶֽיךָ מִמֶּֽנִּי"}, {"kind": "text", "text": "אַל תַּט בְּאַף עַבְדֶּֽךָ"}, {"kind": "text", "text": "עֶזְרָתִי הָיִֽיתָ"}, {"kind": "text", "text": "אַל תִּטְּ֒שֵֽׁנִי וְאַל תַּעַזְבֵֽנִי"}, {"kind": "text", "text": "אֱלֹהֵי יִשְׁעִי:"}, {"kind": "text", "text": "כִּי אָבִי וְאִמִּי עֲזָבֽוּנִי"}, {"kind": "text", "text": "וַיהֹוָה יַאַסְפֵֽנִי:"}, {"kind": "text", "text": "הוֹרֵֽנִי יְהֹוָה דַּרְכֶּֽךָ"}, {"kind": "text", "text": "וּנְחֵֽנִי בְּאֹֽרַח מִישׁוֹר"}, {"kind": "text", "text": "לְמַֽעַן שׁוֹרְ֒רָי:"}, {"kind": "text", "text": "אַל תִּתְּ֒נֵֽנִי"}, {"kind": "text", "text": "בְּנֶֽפֶשׁ צָרָי"}, {"kind": "text", "text": "כִּי קָֽמוּ בִי עֵֽדֵי שֶֽׁקֶר"}, {"kind": "text", "text": "וִיפֵֽחַ חָמָס:"}, {"kind": "text", "text": "לוּלֵא הֶאֱמַֽנְתִּי לִרְאוֹת"}, {"kind": "text", "text": "בְּטוּב יְהֹוָה"}, {"kind": "text", "text": "בְּאֶֽרֶץ חַיִּים:"}, {"kind": "text", "text": "❖קַוֵּה אֶל יְהֹוָה"}, {"kind": "text", "text": "חֲזַק וְיַאֲמֵץ לִבֶּךָ"}, {"kind": "text", "text": "וְקַוֵּה אֶל יְהוָה:"}, {"kind": "header", "text": "אשרי"}, {"kind": "text", "text": "אַשְׁרֵי יוֹשְׁ֒בֵי"}, {"kind": "text", "text": "בֵיתֶֽךָ"}, {"kind": "text", "text": "עוֹד יְהַלְ֒לֽוּךָ סֶּֽלָה:"}, {"kind": "text", "text": "אַשְׁרֵי הָעָם שֶׁכָּֽכָה לּוֹ"}, {"kind": "text", "text": "אַשְׁרֵי הָעָם"}, {"kind": "text", "text": "שֶׁיְהֹוָה אֱלֹהָיו:"}, {"kind": "text", "text": "תְּהִלָּה לְדָוִד"}, {"kind": "text", "text": "אֲרוֹמִמְךָ אֱלוֹהַי הַמֶּֽלֶךְ"}, {"kind": "text", "text": "וַאֲבָרְ֒כָה שִׁמְךָ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "בְּכָל־יוֹם אֲבָרְכֶֽךָ"}, {"kind": "text", "text": "וַאֲהַלְ֒לָה שִׁמְךָ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "גָּדוֹל יְהֹוָה וּמְהֻלָּל מְאֹד"}, {"kind": "text", "text": "וְלִגְדֻלָּתוֹ אֵין חֵֽקֶר:"}, {"kind": "text", "text": "דּוֹר לְדוֹר"}, {"kind": "text", "text": "יְשַׁבַּח מַעֲשֶׂיךָ"}, {"kind": "text", "text": "וּגְבוּרֹתֶֽיךָ יַגִּֽידוּ:"}, {"kind": "text", "text": "הֲדַר כְּבוֹד הוֹדֶֽךָ"}, {"kind": "text", "text": "וְדִבְרֵי נִפְלְ֒אֹתֶֽיךָ אָשִֽׂיחָה:"}, {"kind": "text", "text": "וֶעֱזוּז נוֹרְ֒אוֹתֶֽיךָ יֹאמֵֽרוּ"}, {"kind": "text", "text": "וּגְדֻלָּתְ֒ךָ אֲסַפְּ֒רֶֽנָּה:"}, {"kind": "text", "text": "זֵֽכֶר רַב־טוּבְ֒ךָ"}, {"kind": "text", "text": "יַבִּֽיעוּ"}, {"kind": "text", "text": "וְצִדְקָתְ֒ךָ יְרַנֵּֽנוּ:"}, {"kind": "text", "text": "חַנּוּן וְרַחוּם יְהֹוָה"}, {"kind": "text", "text": "אֶֽרֶךְ אַפַּֽיִם וּגְדָל־חָֽסֶד:"}, {"kind": "text", "text": "טוֹב־יְהֹוָה לַכֹּל"}, {"kind": "text", "text": "וְרַחֲמָיו עַל־כָּל־מַעֲשָׂיו:"}, {"kind": "text", "text": "יוֹדֽוּךָ יְהֹוָה כָּל־מַעֲשֶֽׂיךָ"}, {"kind": "text", "text": "וַחֲסִידֶֽיךָ יְבָרְ֒כֽוּכָה:"}, {"kind": "text", "text": "כְּבוֹד מַלְכוּתְ֒ךָ"}, {"kind": "text", "text": "יֹאמֵֽרוּ"}, {"kind": "text", "text": "וּגְבוּרָתְ֒ךָ יְדַבֵּֽרוּ:"}, {"kind": "text", "text": "לְהוֹדִֽיעַ לִבְנֵי הָאָדָם גְּבוּרֹתָיו"}, {"kind": "text", "text": "וּכְבוֹד הֲדַר מַלְכוּתוֹ:"}, {"kind": "text", "text": "מַלְכוּתְ֒ךָ מַלְכוּת כָּל־עֹלָמִים"}, {"kind": "text", "text": "וּמֶמְשַׁלְתְּ֒ךָ בְּכָל־דּוֹר וָדֹר:"}, {"kind": "text", "text": "סוֹמֵךְ יְהֹוָה לְכָל־הַנֹּפְ֒לִים"}, {"kind": "text", "text": "וְזוֹקֵף לְכָל־הַכְּ֒פוּפִים:"}, {"kind": "text", "text": "עֵינֵי־כֹל אֵלֶֽיךָ יְשַׂבֵּֽרוּ"}, {"kind": "text", "text": "וְאַתָּה נוֹתֵן־לָהֶם"}, {"kind": "text", "text": "אֶת־אָכְלָם בְּעִתּוֹ:"}, {"kind": "text", "text": "פּוֹתֵֽחַ אֶת־יָדֶֽךָ"}, {"kind": "text", "text": "וּמַשְׂבִּֽיעַ לְכָל־חַי רָצוֹן:"}, {"kind": "text", "text": "צַדִּיק יְהֹוָה בְּכָל־דְּרָכָיו"}, {"kind": "text", "text": "וְחָסִיד בְּכָל־מַעֲשָׂיו:"}, {"kind": "text", "text": "קָרוֹב יְהֹוָה לְכָל־קֹרְ֒אָיו"}, {"kind": "text", "text": "לְכֹל אֲשֶׁר יִקְרָאֻֽהוּ בֶאֱמֶת:"}, {"kind": "text", "text": "רְצוֹן־יְרֵאָיו יַעֲשֶׂה"}, {"kind": "text", "text": "וְאֶת־שַׁוְעָתָם יִשְׁמַע וְיוֹשִׁיעֵם:"}, {"kind": "text", "text": "שׁוֹמֵר יְהֹוָה אֶת־כָּל־אֹהֲבָיו"}, {"kind": "text", "text": "וְאֵת כָּל־הָרְ֒שָׁעִים יַשְׁמִיד:"}, {"kind": "text", "text": "❖תְּהִלַּת יְהֹוָה יְדַבֶּר פִּי"}, {"kind": "text", "text": "וִיבָרֵךְ כָּל־בָּשָׂר"}, {"kind": "text", "text": "שֵׁם קָדְשׁוֹ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "וַאֲנַֽחְנוּ נְבָרֵךְ יָהּ"}, {"kind": "text", "text": "מֵעַתָּה וְעַד־עוֹלָם"}, {"kind": "text", "text": "הַלְלוּיָהּ:"}, {"kind": "text", "text": "❖יְהַלְ֒לוּ אֶת־שֵׁם יְהֹוָה"}, {"kind": "text", "text": "כִּי־נִשְׂגָּב שְׁמוֹ לְבַדּוֹ:"}, {"kind": "text", "text": "הוֹדוֹ עַל־אֶֽרֶץ וְשָׁמָֽיִם:"}, {"kind": "text", "text": "וַיָּֽרֶם קֶֽרֶן לְעַמּוֹ"}, {"kind": "text", "text": "תְּהִלָּה לְכָל־חֲסִידָיו"}, {"kind": "text", "text": "לִבְנֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "עַם קְרֹבוֹ"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ:"}, {"kind": "text", "text": "מִזְמוֹר לְדָוִד"}, {"kind": "text", "text": "הָבוּ לַיהֹוָה בְּנֵי אֵלִים"}, {"kind": "text", "text": "הָבוּ לַיהֹוָה כָּבוֹד וָעֹז:"}, {"kind": "text", "text": "הָבוּ לַיהֹוָה כְּבוֹד שְׁמוֹ"}, {"kind": "text", "text": "הִשְׁתַּחֲווּ לַיהֹוָה"}, {"kind": "text", "text": "בְּהַדְרַת־קֹֽדֶשׁ:"}, {"kind": "text", "text": "קוֹל יְהֹוָה עַל־הַמָּֽיִם"}, {"kind": "text", "text": "אֵל־הַכָּבוֹד הִרְעִים"}, {"kind": "text", "text": "יְהֹוָה עַל־מַֽיִם רַבִּים:"}, {"kind": "text", "text": "קוֹל־יְהֹוָה בַּכֹּֽחַ"}, {"kind": "text", "text": "קוֹל יְהֹוָה בֶּהָדָר:"}, {"kind": "text", "text": "קוֹל יְהֹוָה שֹׁבֵר אֲרָזִים"}, {"kind": "text", "text": "וַיְשַׁבֵּר יְהֹוָה"}, {"kind": "text", "text": "אֶת־אַרְזֵי הַלְּ֒בָנוֹן:"}, {"kind": "text", "text": "וַיַּרְקִידֵם כְּמוֹ־עֵֽגֶל"}, {"kind": "text", "text": "לְבָנוֹן וְשִׂרְיוֹן כְּמוֹ בֶן־רְאֵמִים:"}, {"kind": "text", "text": "קוֹל־יְהֹוָה חֹצֵב לַהֲבוֹת אֵשׁ:"}, {"kind": "text", "text": "קוֹל יְהֹוָה יָחִיל מִדְבָּר"}, {"kind": "text", "text": "יָחִיל יְהֹוָה מִדְבַּר קָדֵשׁ:"}, {"kind": "text", "text": "קוֹל יְהֹוָה יְחוֹלֵל אַיָּלוֹת"}, {"kind": "text", "text": "וַיֶּחֱשׂף יְעָרוֹת"}, {"kind": "text", "text": "וּבְהֵיכָלוֹ"}, {"kind": "text", "text": "כֻּלּוֹ אֹמֵר כָּבוֹד:"}, {"kind": "text", "text": "יְהֹוָה לַמַבּוּל יָשָׁב"}, {"kind": "text", "text": "וַיֵּֽשֶׁב יְהֹוָה מֶֽלֶךְ לְעוֹלָם:"}, {"kind": "text", "text": "יְהֹוָה עֹז לְעַמּוֹ יִתֵּן"}, {"kind": "text", "text": "יְהֹוָה יְבָרֵךְ אֶת־עַמּוֹ בַשָּׁלוֹם:"}, {"kind": "text", "text": "לְדָוִד מִזְמוֹר"}, {"kind": "text", "text": "לַיהֹוָה הָאָֽרֶץ וּמְלוֹאָהּ"}, {"kind": "text", "text": "תֵּבֵל וְיֽשְׁ֒בֵי בָהּ:"}, {"kind": "text", "text": "כִּי־הוּא עַל־יַמִּים יְסָדָהּ"}, {"kind": "text", "text": "וְעַל־נְהָרוֹת יְכוֹנְ֒נֶֽהָ:"}, {"kind": "text", "text": "מִי־יַעֲלֶה בְהַר־יְהֹוָה"}, {"kind": "text", "text": "וּמִי יָקוּם"}, {"kind": "text", "text": "בִּמְקוֹם קָדְשׁוֹ:"}, {"kind": "text", "text": "נְקִי כַפַּֽיִם וּבַר־לֵבָב"}, {"kind": "text", "text": "אֲשֶׁר לֹא־נָשָׂא לַשָּׁוְא נַפְשִׁי"}, {"kind": "text", "text": "וְלֹא נִשְׁבַּע לְמִרְמָה:"}, {"kind": "text", "text": "יִשָּׂא בְרָכָה מֵאֵת יְהֹוָה"}, {"kind": "text", "text": "וּצְדָקָה"}, {"kind": "text", "text": "מֵאֱלֹהֵי יִשְׁעוֹ:"}, {"kind": "text", "text": "זֶה דּוֹר דּוֹרְשָׁיו"}, {"kind": "text", "text": "מְבַקְשֵׁי פָנֶֽיךָ"}, {"kind": "text", "text": "יַעֲקֹב סֶֽלָה:"}, {"kind": "text", "text": "שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם"}, {"kind": "text", "text": "וְהִנָּשְׂ֒אוּ"}, {"kind": "text", "text": "פִּתְחֵי עוֹלָם"}, {"kind": "text", "text": "וְיָבוֹא מֶֽלֶךְ הַכָּבוֹד:"}, {"kind": "text", "text": "מִי זֶה מֶֽלֶךְ הַכָּבוֹד"}, {"kind": "text", "text": "יְהֹוָה עִזּוּז וְגִבּוֹר"}, {"kind": "text", "text": "יְהֹוָה גִּבּוֹר מִלְחָמָה:"}, {"kind": "text", "text": "שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם"}, {"kind": "text", "text": "וּשְׂאוּ פִּתְחֵי עוֹלָם"}, {"kind": "text", "text": "וְיָבוֹא מֶֽלֶךְ הַכָּבוֹד:"}, {"kind": "text", "text": "מִי הוּא זֶה מֶֽלֶךְ הַכָּבוֹד"}, {"kind": "text", "text": "יְהֹוָה צְבָאוֹת"}, {"kind": "text", "text": "הוּא מֶֽלֶךְ הַכָּבוֹד סֶֽלָה:"}, {"kind": "text", "text": "וּבְנֻחֹה יֹאמַר"}, {"kind": "text", "text": "שׁוּבָה יְהֹוָה"}, {"kind": "text", "text": "רִבְבוֹת אַלְפֵי יִשְׂרָאֵל:"}, {"kind": "text", "text": "קוּמָה יְהֹוָה לִמְנוּחָתֶֽךָ"}, {"kind": "text", "text": "אַתָּה וַאֲרוֹן עֻזֶּֽךָ:"}, {"kind": "text", "text": "כֹּהֲנֶֽיךָ"}, {"kind": "text", "text": "יִלְבְּ֒שׁוּ צֶֽדֶק"}, {"kind": "text", "text": "וַחֲסִידֶֽיךָ יְרַנֵּֽנוּ:"}, {"kind": "text", "text": "בַּעֲבוּר דָּוִד עַבְדֶּֽךָ"}, {"kind": "text", "text": "אַל תָּשֵׁב פְּנֵי מְשִׁיחֶֽךָ:"}, {"kind": "text", "text": "כִּי לֶֽקַח טוֹב נָתַֽתִּי לָכֶם"}, {"kind": "text", "text": "תּוֹרָתִי אַל תַּעֲזֹֽבוּ:"}, {"kind": "text", "text": "עֵץ חַיִּים הִיא לַמַּחֲזִיקִים בָּהּ"}, {"kind": "text", "text": "וְתוֹמְ֒כֶֽיהָ מְאֻשָּׁר:"}, {"kind": "text", "text": "❖דְּרָכֶֽיהָ דַּרְכֵי נֹֽעַם"}, {"kind": "text", "text": "וְכָל נְתִיבוֹתֶֽיהָ שָׁלוֹם:"}, {"kind": "text", "text": "הֲשִׁיבֵֽנוּ יְהֹוָה אֵלֶֽיךָ"}, {"kind": "text", "text": "וְנָשֽׁוּבָה"}, {"kind": "text", "text": "חַדֵּשׁ יָמֵֽינוּ כְּקֶֽדֶם:"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְמָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְעוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְכוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְ֒קָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ."}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְחַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל."}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְמַן קָרִיב."}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְעָלְמֵי עָלְמַיָּא:"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקֻדְשָׁא בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵֽלָּא (בעשי\"ת וּלְעֵֽלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְכָתָא וְשִׁירָתָא."}, {"kind": "text", "text": "תֻּשְׁבְּ֒חָתָא וְנֶחֱמָתָא."}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן:"}, {"kind": "header", "text": "עמידה"}, {"kind": "text", "text": "כִּי שֵׁם יְהֹוָה אֶקְרָא"}, {"kind": "text", "text": "הָבוּ גֹֽדֶל לֵאלֹהֵֽינוּ:"}, {"kind": "text", "text": "אֲדֹנָי שְׂפָתַי תִּפְתָּח"}, {"kind": "text", "text": "וּפִי יַגִּיד תְּהִלָּתֶֽךָ:"}, {"kind": "text", "text": "<b>אבות</b>"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "אֱלֹהֵי אַבְרָהָם אֱלֹהֵי יִצְחָק"}, {"kind": "text", "text": "וֵאלֹהֵי יַעֲקֹב"}, {"kind": "text", "text": "הָאֵל"}, {"kind": "text", "text": "הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא"}, {"kind": "text", "text": "אֵל עֶלְיוֹן"}, {"kind": "text", "text": "גּוֹמֵל חֲסָדִים טוֹבִים"}, {"kind": "text", "text": "וְקוֹנֵה הַכֹּל"}, {"kind": "text", "text": "וְזוֹכֵר חַסְדֵי אָבוֹת"}, {"kind": "text", "text": "וּמֵבִיא גוֹאֵל"}, {"kind": "text", "text": "לִבְנֵי בְנֵיהֶם"}, {"kind": "text", "text": "לְמַֽעַן שְׁמוֹ בְּאַהֲבָה:"}, {"kind": "instruction", "text": "זָכְרֵֽנוּ לְחַיִּים"}, {"kind": "instruction", "text": "מֶֽלֶךְ חָפֵץ בַּחַיִּים"}, {"kind": "instruction", "text": "וְכָתְבֵֽנוּ בְּסֵֽפֶר הַחַיִּים"}, {"kind": "instruction", "text": "לְמַעַנְךָ אֱלֹהִים חַיִּים:"}, {"kind": "text", "text": "מֶֽלֶךְ עוֹזֵר וּמוֹשִֽׁיעַ וּמָגֵן:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "מָגֵן אַבְרָהָם:"}, {"kind": "text", "text": "<b>גבורות</b>"}, {"kind": "text", "text": "אַתָּה גִבּוֹר לְעוֹלָם אֲדֹנָי"}, {"kind": "text", "text": "מְחַיֶּה מֵתִים אַתָּה"}, {"kind": "text", "text": "רַב לְהוֹשִֽׁיעַ:"}, {"kind": "text", "text": "<b>מוֹרִיד הַטָּל</b>"}, {"kind": "text", "text": "<b>מַשִּׁיב הָרֽוּחַ</b>"}, {"kind": "text", "text": "<b>וּמוֹרִיד הַגֶּֽשֶׁם:</b>"}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶֽסֶד"}, {"kind": "text", "text": "מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים"}, {"kind": "text", "text": "סוֹמֵךְ נוֹפְלִים"}, {"kind": "text", "text": "וְרוֹפֵא חוֹלִים"}, {"kind": "text", "text": "וּמַתִּיר אֲסוּרִים"}, {"kind": "text", "text": "וּמְקַיֵּם אֱמוּנָתוֹ"}, {"kind": "text", "text": "לִישֵׁנֵי עָפָר."}, {"kind": "text", "text": "מִי כָמֽוֹךָ בַּֽעַל גְּבוּרוֹת"}, {"kind": "text", "text": "וּמִי דּֽוֹמֶה לָּךְ"}, {"kind": "text", "text": "מֶֽלֶךְ מֵמִית וּמְחַיֶּה"}, {"kind": "text", "text": "וּמַצְמִֽיחַ יְשׁוּעָה:"}, {"kind": "instruction", "text": "מִי כָמֽוֹךָ אַב הָרַחֲמִים"}, {"kind": "instruction", "text": "זוֹכֵר יְצוּרָיו לְחַיִּים"}, {"kind": "instruction", "text": "בְּרַחֲמִים:"}, {"kind": "text", "text": "וְנֶאֱמָן אַתָּה"}, {"kind": "text", "text": "לְהַחֲיוֹת מֵתִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "מְחַיֵּה הַמֵּתִים:"}, {"kind": "text", "text": "<b>קדושה</b>"}, {"kind": "text", "text": "כֶּֽתֶר יִתְּ֒נוּ לְךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "מַלְאָכִים הֲמֽוֹנֵי מַֽעְלָה"}, {"kind": "text", "text": "עִם עַמְּ֒ךָ יִשְׂרָאֵל קְבוּצֵי מַֽטָּה:"}, {"kind": "text", "text": "יַחַד כֻּלָּם"}, {"kind": "text", "text": "קְדֻשָּׁה לְךָ יְשַׁלֵּֽשׁוּ"}, {"kind": "text", "text": "כַּדָּבָר הָאָמוּר עַל יַד נְבִיאֶֽךָ"}, {"kind": "text", "text": "וְקָרָא זֶה אֶל זֶה וְאָמַר:"}, {"kind": "text", "text": "<b>קָדוֹשׁ קָדוֹשׁ קָדוֹשׁ</b>"}, {"kind": "text", "text": "<b>יְהֹוָה צְבָאוֹת</b>"}, {"kind": "text", "text": "<b>מְלֹא כָל הָאָֽרֶץ כְּבוֹדוֹ:</b>"}, {"kind": "text", "text": "❖כְּבוֹדוֹ מָלֵא עוֹלָם"}, {"kind": "text", "text": "מְשָׁרְ֒תָיו שׁוֹאֲלִים זֶה לָזֶה"}, {"kind": "text", "text": "אַיֵּה מְקוֹם כְּבוֹדוֹ"}, {"kind": "text", "text": "לְעֻמָּתָם מְשַׁבְּ֒חִים וְאוֹמְ֒רִים:"}, {"kind": "text", "text": "<b>בָּרוּךְ כְּבוֹד יְהֹוָה</b>"}, {"kind": "text", "text": "<b>מִמְּ֒קוֹמוֹ:</b>"}, {"kind": "text", "text": "❖מִמְּ֒קוֹמוֹ הוּא יִֽפֶן בְּרַחֲמִים"}, {"kind": "text", "text": "וְיָחוֹן עַם"}, {"kind": "text", "text": "הַמְּ֒יַחֲדִים שְׁמוֹ"}, {"kind": "text", "text": "עֶֽרֶב וָבֹֽקֶר בְּכָל יוֹם תָּמִיד"}, {"kind": "text", "text": "פַּעֲמַֽיִם בְּאַהֲבָה שְׁמַע אוֹמְרִים:"}, {"kind": "text", "text": "<b>שְׁמַע יִשְׂרָאֵל</b>"}, {"kind": "text", "text": "<b>יְהֹוָה אֱלֹהֵֽינוּ יְהֹוָה אֶחָד:</b>"}, {"kind": "text", "text": "❖הוּא אֱלֹהֵֽינוּ הוּא אָבִֽינוּ"}, {"kind": "text", "text": "הוּא מַלְכֵּֽנוּ הוּא מוֹשִׁיעֵֽנוּ"}, {"kind": "text", "text": "וְהוּא יוֹשִׁיעֵֽנוּ"}, {"kind": "text", "text": "וְיִּגְאָלֵֽנוּ שֵׁנִית."}, {"kind": "text", "text": "וְיַשְׁמִיעֵֽנוּ בְּרַחֲמָיו"}, {"kind": "text", "text": "שֵׁנִית"}, {"kind": "text", "text": "לְעֵינֵי כָּל חַי"}, {"kind": "text", "text": "לֵאמֹר:"}, {"kind": "text", "text": "הֵן גָּאַֽלְתִּי אֶתְכֶם"}, {"kind": "text", "text": "אַחֲרִית כְרֵאשִׁית."}, {"kind": "text", "text": "לִהְיוֹת לָכֶם לֵאלֹהִים:"}, {"kind": "text", "text": "אֲנִי יְהֹוָה אֱלֹהֵיכֶם:"}, {"kind": "text", "text": "וּבְדִבְרֵי קָדְשְׁ֒ךָ כָּתוּב לֵאמֹר:"}, {"kind": "text", "text": "<b>יִמְלֹךְ יְהֹוָה לְעוֹלָם</b>"}, {"kind": "text", "text": "<b>אֱלֹהַֽיִךְ צִיּוֹן לְדֹר וָדֹר</b>"}, {"kind": "text", "text": "<b>הַלְ֒לוּיָהּ:</b>"}, {"kind": "text", "text": "לְדוֹר וָדוֹר"}, {"kind": "text", "text": "נַגִּיד גָּדְלָךְ"}, {"kind": "text", "text": "וּלְנֵֽצַח נְצָחִים"}, {"kind": "text", "text": "קְדֻשָּׁתְ֒ךָ נַקְדִּישׁ"}, {"kind": "text", "text": "וְשִׁבְחֲךָ אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "מִפִּֽינוּ לֹא יָמוּשׁ"}, {"kind": "text", "text": "לְעוֹלָם וָעֶד"}, {"kind": "text", "text": "כִּי אֵל"}, {"kind": "text", "text": "מֶֽלֶךְ גָּדוֹל וְקָדוֹשׁ אָֽתָּה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הָאֵל הַקָּדוֹשׁ:"}, {"kind": "instruction", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "instruction", "text": "הַמֶּֽלֶךְ הַקָּדוֹשׁ:"}, {"kind": "text", "text": "<b>קדושת השם</b>"}, {"kind": "text", "text": "אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ"}, {"kind": "text", "text": "וּקְדוֹשִׁים"}, {"kind": "text", "text": "בְּכָל יוֹם יְהַלְ֒לֽוּךָ סֶּֽלָה:"}, {"kind": "text", "text": "כִּי אֵל"}, {"kind": "text", "text": "מֶֽלֶךְ גָּדוֹל וְקָדוֹשׁ אָֽתָּה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הָאֵל הַקָּדוֹשׁ:"}, {"kind": "instruction", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "instruction", "text": "הַמֶּֽלֶךְ הַקָּדוֹשׁ:"}, {"kind": "text", "text": "תִּכַּֽנְתָּ שַׁבָּת"}, {"kind": "text", "text": "רָצִֽיתָ קָרְבְּ֒נוֹתֶֽיהָ."}, {"kind": "text", "text": "צִוִּֽיתָ פֵּרוּשֶֽׁיהָ"}, {"kind": "text", "text": "עִם סִדּוּרֵי"}, {"kind": "text", "text": "נְסָכֶֽיהָ."}, {"kind": "text", "text": "מְעַנְּ֒גֶֽיהָ"}, {"kind": "text", "text": "לְעוֹלָם כָּבוֹד יִנְחָֽלוּ."}, {"kind": "text", "text": "טוֹעֲמֶֽיהָ"}, {"kind": "text", "text": "חַיִּים זָכוּ."}, {"kind": "text", "text": "וְגַם הָאוֹהֲבִים דְּבָרֶֽיהָ"}, {"kind": "text", "text": "גְּדֻלָּה בָּחָֽרוּ."}, {"kind": "text", "text": "אָז מִסִּינַי"}, {"kind": "text", "text": "נִצְטַוּוּ"}, {"kind": "text", "text": "צִוּוּי"}, {"kind": "text", "text": "פָּעֳלֶֽיהָ כָּרָאוּי."}, {"kind": "text", "text": "וַתְּצַוֵּֽנוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "לְהַקְרִיב בָּהּ"}, {"kind": "text", "text": "קָרְבַּן מוּסַף שַׁבָּת"}, {"kind": "text", "text": "כָּרָאוּי:"}, {"kind": "text", "text": "יְהִי רָצוֹן מִלְּ֒פָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "שֶׁתַּעֲלֵֽנוּ בְשִׂמְחָה לְאַרְצֵֽנוּ"}, {"kind": "text", "text": "וְתִטָּעֵֽנוּ בִּגְבוּלֵֽנוּ"}, {"kind": "text", "text": "וְשָׁם נַעֲשֶׂה לְפָנֶֽיךָ"}, {"kind": "text", "text": "אֶת קָרְבְּ֒נוֹת חוֹבוֹתֵֽינוּ"}, {"kind": "text", "text": "תְּמִידִים כְּסִדְרָם"}, {"kind": "text", "text": "וּמוּסָפִים"}, {"kind": "text", "text": "כְּהִלְכָתָם."}, {"kind": "text", "text": "וְאֶת מוּסַף יוֹם הַשַּׁבָּת הַזֶּה"}, {"kind": "text", "text": "נַעֲשֶׂה וְנַקְרִיב לְפָנֶֽיךָ"}, {"kind": "text", "text": "בְּאַהֲבָה"}, {"kind": "text", "text": "כְּמִצְוַת רְצוֹנֶֽךָ"}, {"kind": "text", "text": "כְּמוֹ שֶׁכָּתַֽבְתָּ עָלֵֽינוּ בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "עַל יְדֵי משֶׁה עַבְדֶּֽךָ"}, {"kind": "text", "text": "מִפִּי כְבוֹדֶֽךָ כָּאָמוּר:"}, {"kind": "text", "text": "וּבְיוֹם הַשַּׁבָּת"}, {"kind": "text", "text": "שְׁנֵי כְבָשִׂים בְּנֵי שָׁנָה תְּמִימִים"}, {"kind": "text", "text": "וּשְׁנֵי עֶשְׂרֹנִים סֹֽלֶת"}, {"kind": "text", "text": "מִנְחָה"}, {"kind": "text", "text": "בְּלוּלָה בַשֶּֽׁמֶן וְנִסְכּוֹ:"}, {"kind": "text", "text": "עֹלַת שַׁבַּת בְּשַׁבַּתּוֹ"}, {"kind": "text", "text": "עַל עֹלַת הַתָּמִיד"}, {"kind": "text", "text": "וְנִסְכָּהּ:"}, {"kind": "text", "text": "יִשְׂמְ֒חוּ בְמַלְכוּתְ֒ךָ"}, {"kind": "text", "text": "שׁוֹמְ֒רֵי שַׁבָּת"}, {"kind": "text", "text": "וְקֽוֹרְ֒אֵי עֹֽנֶג."}, {"kind": "text", "text": "עַם מְקַדְּ֒שֵׁי שְׁבִיעִי."}, {"kind": "text", "text": "כֻּלָּם יִשְׂבְּ֒עוּ"}, {"kind": "text", "text": "וְיִתְעַנְּ֒גוּ מִטּוּבֶֽךָ."}, {"kind": "text", "text": "וּבַשְּׁ֒בִיעִי רָצִֽיתָ בּוֹ"}, {"kind": "text", "text": "וְקִדַּשְׁתּוֹ"}, {"kind": "text", "text": "חֶמְדַּת יָמִים אוֹתוֹ קָרָֽאתָ."}, {"kind": "text", "text": "זֵֽכֶר לְמַעֲשֵׂה בְרֵאשִׁית:"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "רְצֵה בִמְנוּחָתֵֽנוּ."}, {"kind": "text", "text": "קַדְּ֒שֵֽׁנוּ בְּמִצְוֹתֶֽיךָ"}, {"kind": "text", "text": "וְתֵן חֶלְקֵֽנוּ בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "שַׂבְּ֒עֵֽנוּ מִטּוּבֶֽךָ."}, {"kind": "text", "text": "וְשַׂמַּח נַפְשֵֽׁנוּ בִּישׁוּעָתֶֽךָ."}, {"kind": "text", "text": "וְטַהֵר לִבֵּֽנוּ לְעָבְדְּ֒ךָ בֶּאֱמֶת."}, {"kind": "text", "text": "וְהַנְחִילֵֽנוּ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בְּאַהֲבָה וּבְרָצוֹן"}, {"kind": "text", "text": "שַׁבַּת קָדְשֶֽׁךָ."}, {"kind": "text", "text": "וְיָנֽוּחוּ בוֹ כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "מְקַדְּ֒שֵׁי שְׁמֶֽךָ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "מְקַדֵּשׁ הַשַּׁבָּת:"}, {"kind": "text", "text": "אַתָּה יָצַֽרְתָּ עוֹלָמְ֒ךָ מִקֶּֽדֶם."}, {"kind": "text", "text": "כִּלִּֽיתָ מְלַאכְתְּ֒ךָ"}, {"kind": "text", "text": "בַּיּוֹם הַשְּׁ֒בִיעִי."}, {"kind": "text", "text": "בָּחַרְתָּ בָּנוּ מִכָל עָם."}, {"kind": "text", "text": "אָהַֽבְתָּ אוֹתָֽנוּ וְרָצִֽיתָ בָּֽנוּ"}, {"kind": "text", "text": "וְרוֹמַמְתָּֽנוּ מִכָּל הַלְּ֒שׁוֹנוֹת"}, {"kind": "text", "text": "וְקִדַּשְׁתָּֽנוּ בְּמִצְוֹתֶֽיךָ"}, {"kind": "text", "text": "וְקֵרַבְתָּֽנוּ מַלְכֵּֽנוּ לַעֲבוֹדָתֶֽךָ"}, {"kind": "text", "text": "וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ"}, {"kind": "text", "text": "עָלֵֽינוּ קָרָֽאתָ:"}, {"kind": "text", "text": "וַתִּתֶּן לָֽנוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בְּאַהֲבָה"}, {"kind": "text", "text": "שַׁבָּתוֹת לִמְנוּחָה"}, {"kind": "text", "text": "וְרָאשֵׁי חֳדָשִׁים לְכַפָּרָה."}, {"kind": "text", "text": "וּלְפִי שֶׁחָטָֽאנוּ לְפָנֶֽיךָ"}, {"kind": "text", "text": "אֲנַחְנוּ וַאֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "חָרְ֒בָה עִירֵֽנוּ"}, {"kind": "text", "text": "וְשָׁמֵם בֵּית מִקְדָּשֵֽׁנוּ"}, {"kind": "text", "text": "וְגָלָה יְקָרֵֽנוּ"}, {"kind": "text", "text": "וְנֻטַּל כָּבוֹד"}, {"kind": "text", "text": "מִבֵּית חַיֵּֽינוּ."}, {"kind": "text", "text": "וְאֵין אֲנַֽחְנוּ יְכוֹלִים"}, {"kind": "text", "text": "לַעֲשׂוֹת חוֹבוֹתֵֽינוּ"}, {"kind": "text", "text": "בְּבֵית בְּחִירָתֶֽךָ"}, {"kind": "text", "text": "בַּבַּֽיִת הַגָּדוֹל וְהַקָּדוֹשׁ"}, {"kind": "text", "text": "שֶׁנִּקְרָא שִׁמְךָ עָלָיו"}, {"kind": "text", "text": "מִפְּ֒נֵי הַיָּד"}, {"kind": "text", "text": "שֶׁנִּשְׁתַּלְּ֒חָה בְּמִקְדָּשֶֽׁךָ:"}, {"kind": "text", "text": "יְהִי רָצוֹן מִלְּ֒פָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "שֶׁתַּעֲלֵֽנוּ בְשִׂמְחָה לְאַרְצֵֽנוּ"}, {"kind": "text", "text": "וְתִטָּעֵֽנוּ בִּגְבוּלֵֽנוּ"}, {"kind": "text", "text": "וְשָׁם נַעֲשֶׂה לְפָנֶֽיךָ"}, {"kind": "text", "text": "אֶת קָרְבְּ֒נוֹת חוֹבוֹתֵֽינוּ"}, {"kind": "text", "text": "תְּמִידִים כְּסִדְרָם"}, {"kind": "text", "text": "וּמוּסָפִים כְּהִלְכָתָם:"}, {"kind": "text", "text": "וְאֶת מוּסְ֒פֵי יוֹם הַשַּׁבָּת הַזֶּה"}, {"kind": "text", "text": "וְיוֹם רֹאשׁ הַחֹֽדֶשׁ הַזֶּה"}, {"kind": "text", "text": "נַעֲשֶׂה וְנַקְרִיב לְפָנֶֽיךָ"}, {"kind": "text", "text": "בְּאַהֲבָה"}, {"kind": "text", "text": "כְּמִצְוַת רְצוֹנֶֽךָ"}, {"kind": "text", "text": "כְּמוֹ שֶׁכָּתַבְתָּ עָלֵֽינוּ בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "עַל יְדֵי משֶׁה עַבְדֶּֽךָ"}, {"kind": "text", "text": "מִפִּי כְבוֹדֶֽךָ כָּאָמוּר:"}, {"kind": "text", "text": "וּבְיוֹם הַשַּׁבָּת"}, {"kind": "text", "text": "שְׁנֵי כְבָשִׂים בְּנֵי שָׁנָה תְּמִימִים"}, {"kind": "text", "text": "וּשְׁנֵי עֶשְׂרֹנִים סֹֽלֶת"}, {"kind": "text", "text": "מִנְחָה"}, {"kind": "text", "text": "בְּלוּלָה בַשֶּֽׁמֶן וְנִסְכּוֹ:"}, {"kind": "text", "text": "עֹלַת שַׁבַּת בְּשַׁבַּתּוֹ"}, {"kind": "text", "text": "עַל עֹלַת הַתָּמִיד"}, {"kind": "text", "text": "וְנִסְכָּהּ:"}, {"kind": "text", "text": "זֶה קָרְבַן שַׁבָּת:"}, {"kind": "text", "text": "וְקָרְבַּן הַיוֹם כָּאָמוּר:"}, {"kind": "text", "text": "וּבְרָאשֵׁי חָדְשֵׁיכֶם"}, {"kind": "text", "text": "תַּקְרִֽיבוּ עֹלָה לַיהֹוָה"}, {"kind": "text", "text": "פָּרִים בְּנֵי בָקָר שְׁנַֽיִם"}, {"kind": "text", "text": "וְאַֽיִל אֶחָד"}, {"kind": "text", "text": "כְּבָשִׂים בְּנֵי שָׁנָה שִׁבְעָה"}, {"kind": "text", "text": "תְּמִימִים:"}, {"kind": "text", "text": "וּמִנְחָתָם וְנִסְכֵּיהֶם"}, {"kind": "text", "text": "כִּמְדֻבָּר"}, {"kind": "text", "text": "שְׁלשָׁה עֶשְׂרֹנִים"}, {"kind": "text", "text": "לַפָּר"}, {"kind": "text", "text": "וּשְׁנֵי עֶשְׂרֹנִים לָאָֽיִל"}, {"kind": "text", "text": "וְעִשָּׂרוֹן לַכֶּֽבֶשׂ"}, {"kind": "text", "text": "וְיַֽיִן כְּנִסְכּוֹ"}, {"kind": "text", "text": "וְשָׂעִיר לְכַפֵּר"}, {"kind": "text", "text": "וּשְׁנֵי תְמִידִים"}, {"kind": "text", "text": "כְּהִלְכָתָם:"}, {"kind": "text", "text": "יִשְׂמְ֒חוּ בְמַלְכוּתְ֒ךָ"}, {"kind": "text", "text": "שׁוֹמְ֒רֵי שַׁבָּת"}, {"kind": "text", "text": "וְקֽוֹרְ֒אֵי עֹֽנֶג."}, {"kind": "text", "text": "עַם מְקַדְּ֒שֵׁי שְׁבִיעִי."}, {"kind": "text", "text": "כֻּלָּם יִשְׂבְּ֒עוּ"}, {"kind": "text", "text": "וְיִתְעַנְּ֒גוּ מִטּוּבֶֽךָ."}, {"kind": "text", "text": "וּבַשְּׁ֒בִיעִי רָצִֽיתָ בּוֹ"}, {"kind": "text", "text": "וְקִדַּשְׁתּוֹ"}, {"kind": "text", "text": "חֶמְדַּת יָמִים אוֹתוֹ קָרָֽאתָ."}, {"kind": "text", "text": "זֵֽכֶר לְמַעֲשֵׂה בְרֵאשִׁית:"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "רְצֵה בִמְנוּחָתֵֽנוּ."}, {"kind": "text", "text": "וְחַדֵּשׁ עָלֵֽינוּ בְּיוֹם הַשַּׁבָּת הַזֶּה"}, {"kind": "text", "text": "אֶת הַחֹֽדֶשׁ הַזֶּה"}, {"kind": "text", "text": "לְטוֹבָה וְלִבְרָכָה."}, {"kind": "text", "text": "לְשָׂשׁוֹן וּלְשִׂמְחָה."}, {"kind": "text", "text": "לִישׁוּעָה וּלְנֶחָמָה."}, {"kind": "text", "text": "לְפַרְנָסָה וּלְכַלְכָּלָה."}, {"kind": "text", "text": "לְחַיִּים טוֹבִים וּלְשָׁלוֹם."}, {"kind": "text", "text": "לִמְחִֽילַת חֵטְא"}, {"kind": "text", "text": "וְלִסְלִיחַת עָוֹן"}, {"kind": "text", "text": "וּלְכַפָּֽרַת פָּֽשַׁע)."}, {"kind": "text", "text": "וִיהִי הַחֹדֶשׁ הַזֶּה"}, {"kind": "text", "text": "סוֹף וְקֵץ לְכָל צָרוֹתֵֽינוּ."}, {"kind": "text", "text": "תְּחִילָה וָרֹאשׁ"}, {"kind": "text", "text": "לְפִדְיוֹן נַפְשֵֽׁינוּ."}, {"kind": "text", "text": "כִּי בְעַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "בָּחַֽרְתָּ מִכָּל הָאֻמּוֹת."}, {"kind": "text", "text": "וְשַׁבָּתוֹת"}, {"kind": "text", "text": "לָהֶם הוֹדָֽעְתָּ"}, {"kind": "text", "text": "וְחֻקֵּי רָאשֵׁי חֳדָשִׁים"}, {"kind": "text", "text": "לָהֶם קָבָֽעְתָּ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "מְקַדֵּשׁ הַשַּׁבָּת וְיִשְׂרָאֵל"}, {"kind": "text", "text": "וְרָאשֵׁי חֳדָשִׁים:"}, {"kind": "text", "text": "<b>עבודה</b>"}, {"kind": "text", "text": "רְצֵה יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בְּעַמְּ֒ךָ יִשְׂרָאֵל וּבִתְפִלָּתָם שְׁעֵה."}, {"kind": "text", "text": "וְהָשֵׁב אֶת הָעֲבוֹדָה"}, {"kind": "text", "text": "לִדְבִיר בֵּיתֶֽךָ"}, {"kind": "text", "text": "וְאִשֵּׁי יִשְׂרָאֵל."}, {"kind": "text", "text": "וּתְפִלָּתָם בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן"}, {"kind": "text", "text": "וּתְהִי לְרָצוֹן תָּמִיד"}, {"kind": "text", "text": "עֲבוֹדַת יִשְׂרָאֵל עַמֶּֽךָ:"}, {"kind": "text", "text": "וְתֶחֱזֶֽינָה עֵינֵֽינוּ"}, {"kind": "text", "text": "בְּשׁוּבְ֒ךָ לְצִיּוֹן בְּרַחֲמִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן:"}, {"kind": "text", "text": "<b>הודאה</b>"}, {"kind": "text", "text": "מוֹדִים אֲנַֽחְנוּ לָךְ"}, {"kind": "text", "text": "שָׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וֵאלֹהֵי אֲבוֹתֵֽינוּ לְעוֹלָם וָעֶד"}, {"kind": "text", "text": "צוּר חַיֵּֽינוּ"}, {"kind": "text", "text": "מָגֵן יִשְׁעֵֽנוּ"}, {"kind": "text", "text": "אַתָּה הוּא לְדוֹר וָדוֹר"}, {"kind": "text", "text": "נוֹדֶה לְּךָ"}, {"kind": "text", "text": "וּנְסַפֵּר תְּהִלָּתֶֽךָ"}, {"kind": "text", "text": "עַל חַיֵּֽינוּ"}, {"kind": "text", "text": "הַמְּ֒סוּרִים בְּיָדֶֽךָ"}, {"kind": "text", "text": "וְעַל נִשְׁמוֹתֵֽינוּ הַפְּ֒קוּדוֹת לָךְ"}, {"kind": "text", "text": "וְעַל נִסֶּֽיךָ שֶׁבְּ֒כָל יוֹם עִמָּֽנוּ"}, {"kind": "text", "text": "וְעַל נִפְלְ֒אוֹתֶֽיךָ וְטוֹבוֹתֶֽיךָ"}, {"kind": "text", "text": "שֶׁבְּ֒כָל עֵת."}, {"kind": "text", "text": "עֶֽרֶב וָבֹֽקֶר וְצָהֳרָֽיִם."}, {"kind": "text", "text": "הַטּוֹב"}, {"kind": "text", "text": "כִּי לֹא כָלוּ רַחֲמֶֽיךָ"}, {"kind": "text", "text": "וְהַמְ֒רַחֵם"}, {"kind": "text", "text": "כִּי לֹא תַֽמּוּ חֲסָדֶֽיךָ."}, {"kind": "text", "text": "מֵעוֹלָם קִוִּֽינוּ לָךְ:"}, {"kind": "text", "text": "מוֹדִים אֲנַֽחְנוּ לָךְ"}, {"kind": "text", "text": "שָׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "אֱלֹהֵי כָל בָּשָׂר"}, {"kind": "text", "text": "יוֹצְ֒רֵֽנוּ יוֹצֵר בְּרֵאשִׁית"}, {"kind": "text", "text": "בְּרָכוֹת וְהוֹדָאוֹת"}, {"kind": "text", "text": "לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ"}, {"kind": "text", "text": "עַל שֶׁהֶחֱיִיתָֽנוּ וְקִיַּמְתָּֽנוּ"}, {"kind": "text", "text": "כֵּן תְּחַיֵּֽינוּ"}, {"kind": "text", "text": "וּתְקַיְּ֒מֵֽנוּ"}, {"kind": "text", "text": "וְתֶאֱסוֹף גָּלֻיּוֹתֵֽינוּ"}, {"kind": "text", "text": "לְחַצְרוֹת קָדְשֶֽׁךָ"}, {"kind": "text", "text": "לִשְׁמוֹר חֻקֶּֽיךָ"}, {"kind": "text", "text": "וְלַעֲשׂוֹת רְצוֹנֶֽךָ"}, {"kind": "text", "text": "וּלְעָבְדְּ֒ךָ בְּלֵבָב שָׁלֵם"}, {"kind": "text", "text": "עַל שֶׁאָֽנוּ מוֹדִים לָךְ."}, {"kind": "text", "text": "בָּרוּךְ אֵל"}, {"kind": "text", "text": "הַהוֹדָאוֹת:"}, {"kind": "text", "text": "וְעַל הַנִּסִּים"}, {"kind": "text", "text": "וְעַל הַפֻּרְקָן וְעַל הַגְּ֒בוּרוֹת"}, {"kind": "text", "text": "וְעַל הַתְּ֒שׁוּעוֹת וְעַל הַמִּלְחָמוֹת"}, {"kind": "text", "text": "שֶׁעָשִֽׂיתָ לַאֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "בַּיָּמִים הָהֵם בַּזְּ֒מַן הַזֶּה:"}, {"kind": "text", "text": "בִּימֵי מַתִּתְיָֽהוּ"}, {"kind": "text", "text": "בֶּן יוֹחָנָן כֹּהֵן גָּדוֹל"}, {"kind": "text", "text": "חַשְׁמוֹנַאי וּבָנָיו"}, {"kind": "text", "text": "כְּשֶׁעָמְ֒דָה מַלְכוּת יָוָן הָרְ֒שָׁעָה"}, {"kind": "text", "text": "עַל עַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "לְהַשְׁכִּיחָם תּוֹרָתֶֽךָ"}, {"kind": "text", "text": "וּלְהַעֲבִירָם"}, {"kind": "text", "text": "מֵחֻקֵּי רְצוֹנֶֽךָ."}, {"kind": "text", "text": "וְאַתָּה בְּרַחֲמֶֽיךָ הָרַבִּים"}, {"kind": "text", "text": "עָמַֽדְתָּ לָהֶם בְּעֵת צָרָתָם"}, {"kind": "text", "text": "רַֽבְתָּ אֶת רִיבָם"}, {"kind": "text", "text": "דַּֽנְתָּ אֶת דִּינָם"}, {"kind": "text", "text": "נָקַֽמְתָּ אֶת נִקְמָתָם"}, {"kind": "text", "text": "מָסַֽרְתָּ גִבּוֹרִים"}, {"kind": "text", "text": "בְּיַד חַלָּשִׁים"}, {"kind": "text", "text": "וְרַבִּים בְּיַד מְעַטִּים"}, {"kind": "text", "text": "וּטְמֵאִים בְּיַד טְהוֹרִים"}, {"kind": "text", "text": "וּרְשָׁעִים בְּיַד צַדִּיקִים"}, {"kind": "text", "text": "וְזֵדִים בְּיַד"}, {"kind": "text", "text": "עוֹסְ֒קֵי תוֹרָתֶֽךָ"}, {"kind": "text", "text": "וּלְךָ עָשִֽׂיתָ"}, {"kind": "text", "text": "שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶֽךָ"}, {"kind": "text", "text": "וּלְעַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "עָשִֽׂיתָ תְּשׁוּעָה גְדוֹלָה"}, {"kind": "text", "text": "וּפֻרְקָן כְּהַיּוֹם הַזֶּה"}, {"kind": "text", "text": "וְאַחַר כַּךְ בָּֽאוּ בָנֶֽיךָ"}, {"kind": "text", "text": "לִדְבִיר בֵּיתֶֽךָ"}, {"kind": "text", "text": "וּפִנּוּ אֶת הֵיכָלֶֽךָ"}, {"kind": "text", "text": "וְטִהֲרוּ אֶת מִקְדָּשֶֽׁךָ"}, {"kind": "text", "text": "וְהִדְלִֽיקוּ נֵרוֹת"}, {"kind": "text", "text": "בְּחַצְרוֹת קָדְשֶֽׁךָ"}, {"kind": "text", "text": "וְקָבְ֒עוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵֽלּוּ"}, {"kind": "text", "text": "לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל:"}, {"kind": "text", "text": "וְעַל כֻּלָּם"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵׂא"}, {"kind": "text", "text": "שִׁמְ֒ךָ מַלְכֵּֽנוּ"}, {"kind": "text", "text": "תָּמִיד לְעוֹלָם וָעֶד:"}, {"kind": "instruction", "text": "וּכְתֹב לְחַיִּים טוֹבִים"}, {"kind": "instruction", "text": "כָּל בְּנֵי בְרִיתֶֽךָ:"}, {"kind": "text", "text": "וְכֹל הַחַיִּים יוֹדֽוּךָ סֶּֽלָה"}, {"kind": "text", "text": "וִיהַלְ֒לוּ וְיבָרְ֒כוּ"}, {"kind": "text", "text": "אֶת שִׁמְ֒ךָ הַגָּדוֹל בְּאֱמֶת לְעוֹלָם"}, {"kind": "text", "text": "כִּי טוֹב"}, {"kind": "text", "text": "הָאֵל יְשׁוּעָתֵֽנוּ"}, {"kind": "text", "text": "וְעֶזְרָתֵֽנוּ סֶֽלָה"}, {"kind": "text", "text": "הָאֵל הַטּוֹב:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַטּוֹב שִׁמְ֒ךָ"}, {"kind": "text", "text": "וּלְ֒ךָ נָאֶה לְהוֹדוֹת:"}, {"kind": "text", "text": "<b>ברכת כהנים</b>"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ בָּרְ֒כֵֽנוּ"}, {"kind": "text", "text": "בַבְּ֒רָכָה הַמְּ֒שֻׁלֶּֽשֶׁת בַּתּוֹרָה"}, {"kind": "text", "text": "הַכְּ֒תוּבָה עַל יְדֵי משֶׁה עַבְדֶּֽךָ,"}, {"kind": "text", "text": "הָאֲמוּרָה מִפִּי אַהֲרֹן"}, {"kind": "text", "text": "וּבָנָיו כֹּהֲנִים עַם קְדוֹשֶֽׁךָ"}, {"kind": "text", "text": "כָּאָמוּר:"}, {"kind": "text", "text": "יְבָרֶכְךָ יְהֹוָה וְיִשְׁמְ֒רֶֽךָ:"}, {"kind": "text", "text": "יָאֵר יְהֹוָה פָּנָיו אֵלֶֽיךָ"}, {"kind": "text", "text": "וִיחֻנֶּֽךָ:"}, {"kind": "text", "text": "יִשָּׂא יְהֹוָה פָּנָיו אֵלֶֽיךָ"}, {"kind": "text", "text": "וְיָשֵׂם לְךָ שָׁלוֹם:"}, {"kind": "text", "text": "אַדִּיר בַּמָּרוֹם שׁוֹכֵן בִּגְ֒בוּרָה,"}, {"kind": "text", "text": "אַתָּה שָׁלוֹם וְשִׁמְ֒ךָ שָׁלוֹם."}, {"kind": "text", "text": "יְהִי רָצוֹן שֶׁתָּשִׂים עָלֵֽינוּ"}, {"kind": "text", "text": "וְעַל כָּל עַמְּ֒ךָ בֵּית יִשְׂרָאֵל"}, {"kind": "text", "text": "חַיִּים וּבְ֒רָכָה"}, {"kind": "text", "text": "לְמִשְׁמֶֽרֶת שָׁלוֹם:"}, {"kind": "text", "text": "<b>שלום</b>"}, {"kind": "text", "text": "שִׂים שָׁלוֹם טוֹבָה וּבְ֒רָכָה"}, {"kind": "text", "text": "חַיִים חֵן וָחֶֽסֶד וְרַחֲמִים"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּֽךָ,"}, {"kind": "text", "text": "בָּרְ֒כֵֽנוּ אָבִֽינוּ כֻּלָּֽנוּ כְּאֶחָד"}, {"kind": "text", "text": "בְּאוֹר פָּנֶֽיךָ"}, {"kind": "text", "text": "כִּי בְאוֹר פָּנֶֽיךָ"}, {"kind": "text", "text": "נָתַֽתָּ לָּֽנוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "תּוֹרַת חַיִּים וְאַהֲבַת חֶֽסֶד"}, {"kind": "text", "text": "וּצְ֒דָקָה וּבְ֒רָכָה וְרַחֲמִים"}, {"kind": "text", "text": "וְחַיִּים וְשָׁלוֹם,"}, {"kind": "text", "text": "וְטוֹב יִהְיֶה בְּעֵינֶֽיךָ"}, {"kind": "text", "text": "לְבָרְ֒כֵֽנוּ"}, {"kind": "text", "text": "וּלְ֒בָרֵךְ אֶת כָּל עַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "בְּכָל עֵת וּבְכָל שָׁעָה"}, {"kind": "text", "text": "בִּשְׁ֒לוֹמֶֽךָ"}, {"kind": "text", "text": "(בְּרוֹב עוֹז וְשָׁלוֹם)."}, {"kind": "instruction", "text": "בְּסֵֽפֶר חַיִּים בְּרָכָה וְשָׁלוֹם"}, {"kind": "instruction", "text": "וּפַרְנָסָה טוֹבָה"}, {"kind": "instruction", "text": "וּגְ֒זֵרוֹת טוֹבוֹת, יְשׁוּעוֹת וְנֶחָמוֹת,"}, {"kind": "instruction", "text": "נִזָּכֵר וְנִכָּתֵב"}, {"kind": "instruction", "text": "לְפָנֶֽיךָ"}, {"kind": "instruction", "text": "אֲנַֽחְנוּ וְכָל עַמְּ֒ךָ בֵּית יִשְׂרָאֵל"}, {"kind": "instruction", "text": "לְחַיִּים טוֹבִים וּלְ֒שָׁלוֹם:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַמְּ֒בָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל"}, {"kind": "text", "text": "בַּשָּׁלוֹם:"}, {"kind": "text", "text": "יִהְיוּ לְרָצוֹן"}, {"kind": "text", "text": "אִמְ֒רֵי פִי"}, {"kind": "text", "text": "וְהֶגְיוֹן לִבִּי לְפָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה צוּרִי וְגוֹאֲלִי:"}, {"kind": "text", "text": "אֱלֹהַי נְצוֹר לְשׁוֹנִי מֵרָע"}, {"kind": "text", "text": "וּשְׂ֒פָתַי מִדַּבֵּר מִרְמָה"}, {"kind": "text", "text": "וְלִמְ֒קַלְ֒לַי"}, {"kind": "text", "text": "נַפְשִׁי תִדּוֹם"}, {"kind": "text", "text": "וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה"}, {"kind": "text", "text": "פְּתַח לִבִּי בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "וְאַחֲרֵי מִצְוֹתֶֽיךָ תִּרְדּוֹף נַפְשִׁי"}, {"kind": "text", "text": "וְכָל הַקָמִים וְהַחוֹשְׁ֒בִים עָלַי רָעָה"}, {"kind": "text", "text": "מְהֵרָה הָפֵר עֲצָתָם"}, {"kind": "text", "text": "וְקַלְקֵל מַחֲשַׁבְתָּם:"}, {"kind": "text", "text": "(יְהִי רָצוֹן מִלְ֒פָנֶיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי"}, {"kind": "text", "text": "שֶׁלֹּא תַעֲלֶה קִנְאַת אָדָם עָלַי"}, {"kind": "text", "text": "וְלֹא קִנְאָתִי עַל אֲחֵרִים"}, {"kind": "text", "text": "וְשֶׁלֹּא אֶכְעֹס הַיּוֹם"}, {"kind": "text", "text": "וְשֶׁלֹּא אַכְעִיסֶֽךָ"}, {"kind": "text", "text": "וְתַצִּילֵנִי מִיֵּֽצֶר הָרָע"}, {"kind": "text", "text": "וְתֵן בְּלִבִּי הַכְנָעָה וַעֲנָוָה."}, {"kind": "text", "text": "מַלְכֵּֽנוּ וֵאלֹהֵֽינוּ"}, {"kind": "text", "text": "יַחֵד שִׁמְ֒ךָ בְּעוֹלָמֶֽךָ,"}, {"kind": "text", "text": "בְּנֵה עִירְ֒ךָ, יַסֵּד בֵּיתֶֽךָ,"}, {"kind": "text", "text": "וְשַׁכְלֵל הֵיכָלֶֽךָ."}, {"kind": "text", "text": "וְקַבֵּץ קִבּוּץ גָּלֻיּוֹת,"}, {"kind": "text", "text": "וּפְ֒דֵה צֹאנֶֽךָ וְשַׂמַּח עֲדָתֶֽךָ.)"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן שְׁמֶֽךָ,"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן יְמִינֶֽךָ,"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן תּוֹרָתֶֽךָ,"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן קְדֻשָּׁתֶֽךָ."}, {"kind": "text", "text": "לְמַֽעַן יֵחָלְ֒צוּן יְדִידֶֽיךָ"}, {"kind": "text", "text": "הוֹשִֽׁיעָה יְמִינְ֒ךָ וַעֲנֵֽנִי:"}, {"kind": "text", "text": "יִהְיוּ לְרָצוֹן"}, {"kind": "text", "text": "אִמְרֵי פִי"}, {"kind": "text", "text": "וְהֶגְיוֹן לִבִּי לְפָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה צוּרִי וְגוֹאֲלִי:"}, {"kind": "text", "text": "עֹשֶׂה (בעשי\"ת הַשָּׁלוֹם) שָׁלוֹם בִּמְ֒רוֹמָיו"}, {"kind": "text", "text": "הוּא יַעֲשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהִי רָצוֹן מִלְּ֒פָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ"}, {"kind": "text", "text": "בִּמְהֵרָה בְיָמֵֽינוּ"}, {"kind": "text", "text": "וְתֵן חֶלְקֵֽנוּ בְּתוֹרָתֶֽךָ:"}, {"kind": "text", "text": "וְשָׁם נַעֲבָדְ֒ךָ בְּיִרְאָה"}, {"kind": "text", "text": "כִּימֵי עוֹלָם"}, {"kind": "text", "text": "וּכְ֒שָׁנִים קַדְמוֹנִיּוֹת:"}, {"kind": "text", "text": "וְעָרְ֒בָה לַיהוֹה"}, {"kind": "text", "text": "מִנְחַת יְהוּדָה וִירוּשָׁלָֽםִ"}, {"kind": "text", "text": "כִּימֵי עוֹלָם וּכְ֒שָׁנִים קַדְמוֹנִיּוֹת:"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְמָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְעוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְכוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְ֒קָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ."}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְחַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל."}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְמַן קָרִיב."}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְעָלְמֵי עָלְמַיָּא:"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקֻדְשָׁא. בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵֽלָּא (בעשי\"ת וּלְעֵֽלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְכָתָא וְשִׁירָתָא."}, {"kind": "text", "text": "תֻּשְׁבְּ֒חָתָא וְנֶחֱמָתָא."}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְמָא."}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן."}, {"kind": "text", "text": "תִּתְקַבֵּל"}, {"kind": "text", "text": "צְלוֹתְ֒הוֹן וּבָעוּתְ֒הוֹן"}, {"kind": "text", "text": "דְּכָל בֵּית יִשְׂרָאֵל"}, {"kind": "text", "text": "קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא."}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא"}, {"kind": "text", "text": "וְחַיִּים טוֹבִים"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל."}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו"}, {"kind": "text", "text": "הוּא יַעֲשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל."}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "header", "text": "אין כאלקינו"}, {"kind": "text", "text": "קַוֵּה אֶל יְהֹוָה"}, {"kind": "text", "text": "חֲזַק וְיַאֲמֵץ לִבֶּֽךָ"}, {"kind": "text", "text": "וְקַוֵּה אֶל יְהֹוָה:"}, {"kind": "text", "text": "אֵין קָדוֹשׁ כַּיהֹוָה"}, {"kind": "text", "text": "כִּי אֵין בִּלְתֶּֽךָ"}, {"kind": "text", "text": "וְאֵין צוּר כֵּאלֹהֵֽינוּ:"}, {"kind": "text", "text": "כִּי מִי אֱלֽוֹהַּ מִבַּלְעֲדֵי יְהֹוָה"}, {"kind": "text", "text": "וּמִי צוּר זוּלָתִי אֱלֹהֵֽינוּ:"}, {"kind": "text", "text": "אֵין כֵּאלֹהֵֽינוּ."}, {"kind": "text", "text": "אֵין כַּאדוֹנֵֽנוּ."}, {"kind": "text", "text": "אֵין כְּמַלְכֵּֽנוּ."}, {"kind": "text", "text": "אֵין כְּמוֹשִׁיעֵֽנוּ:"}, {"kind": "text", "text": "מִי כֵאלֹהֵֽינוּ."}, {"kind": "text", "text": "מִי כַאדוֹנֵֽנוּ."}, {"kind": "text", "text": "מִי כְמַלְכֵּֽנוּ."}, {"kind": "text", "text": "מִי כְמוֹשִׁיעֵֽנוּ:"}, {"kind": "text", "text": "נוֹדֶה לֵאלֹהֵֽינוּ."}, {"kind": "text", "text": "נוֹדֶה לַאדוֹנֵֽנוּ."}, {"kind": "text", "text": "נוֹדֶה לְמַלְכֵּֽנוּ."}, {"kind": "text", "text": "נוֹדֶה לְמוֹשִׁיעֵֽנוּ:"}, {"kind": "text", "text": "בָּרוּךְ אֱלֹהֵֽינוּ."}, {"kind": "text", "text": "בָּרוּךְ אֲדוֹנֵֽנוּ."}, {"kind": "text", "text": "בָּרוּךְ מַלְכֵּֽנוּ."}, {"kind": "text", "text": "בָּרוּךְ מוֹשִׁיעֵֽנוּ:"}, {"kind": "text", "text": "אַתָּה הוּא אֱלֹהֵֽינוּ."}, {"kind": "text", "text": "אַתָּה הוּא אֲדוֹנֵֽנוּ."}, {"kind": "text", "text": "אַתָּה הוּא מַלְכֵּֽנוּ."}, {"kind": "text", "text": "אַתָּה הוּא מוֹשִׁיעֵֽנוּ."}, {"kind": "text", "text": "אַתָּה הוּא"}, {"kind": "text", "text": "שֶׁהִקְטִֽרוּ אֲבוֹתֵֽינוּ לְפָנֶֽיךָ"}, {"kind": "text", "text": "אֶת קְטֹֽרֶת הַסַּמִּים"}, {"kind": "text", "text": "פִּטּוּם הַקְּ֒טֹֽרֶת"}, {"kind": "text", "text": "הַצֳּרִי וְהַצִּפֹּֽרֶן"}, {"kind": "text", "text": "הַחֶלְבְּ֒נָה וְהַלְּ֒בוֹנָה"}, {"kind": "text", "text": "מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה."}, {"kind": "text", "text": "מוֹר וּקְצִיעָה"}, {"kind": "text", "text": "שִׁבֹּֽלֶת נֵרְדְּ וְכַרְכֹּם"}, {"kind": "text", "text": "מִשְׁקַל"}, {"kind": "text", "text": "שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה."}, {"kind": "text", "text": "הַקּשְׁטְ שְׁנֵים עָשָׂר"}, {"kind": "text", "text": "וְקִלּוּפָה שְׁלשָׁה"}, {"kind": "text", "text": "וְקִנָּמוֹן תִּשְׁעָה."}, {"kind": "text", "text": "בֹּרִית כַּרְשִׁינָה תִּשְׁעָה קַבִּין."}, {"kind": "text", "text": "יֵין קַפְרִיסִין"}, {"kind": "text", "text": "סְאִין תְּלָתָא וְקַבִּין תְּלָתָא."}, {"kind": "text", "text": "וְאִם אֵין לוֹ יֵין קַפְרִיסִין"}, {"kind": "text", "text": "מֵבִיא חֲמַר חִוַּרְיָן עַתִּיק."}, {"kind": "text", "text": "מֶֽלַח סְדוֹמִית רֹֽבַע הַקָּב."}, {"kind": "text", "text": "מַעֲלֶה עָשָׁן כָּל שֶׁהוּא."}, {"kind": "text", "text": "רַבִּי נָתָן הַבַּבְלִי אוֹמֵר"}, {"kind": "text", "text": "אַף כִּפַּת הַיַּרְדֵּן כָּל שֶׁהוּא."}, {"kind": "text", "text": "וְאִם נָֽתַן בָּהּ דְּבַשׁ פְּסָלָהּ"}, {"kind": "text", "text": "וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶֽיהָ"}, {"kind": "text", "text": "חַיָּב מִיתָה:"}, {"kind": "text", "text": "רַבָּן שִׁמְעוֹן בֶּן גַּמְלִיאֵל אוֹמֵר"}, {"kind": "text", "text": "הַצֳּרִי אֵינוֹ אֶלָּא שְׂרָף"}, {"kind": "text", "text": "הַנּוֹטֵף מֵעֲצֵי הַקְּ֒טָף."}, {"kind": "text", "text": "בֹּרִית כַּרְשִׁינָה לָֽמָּה הִיא בָאָה"}, {"kind": "text", "text": "כְּדֵי לְיַפּוֹת בָּהּ אֶת הַצִּפֹּֽרֶן"}, {"kind": "text", "text": "כְּדֵי שֶׁתְּ֒הֵא נָאָה."}, {"kind": "text", "text": "יֵין קַפְרִיסִין לָֽמָּה הוּא בָא"}, {"kind": "text", "text": "כְּדֵי לִשְׁרוֹת בּוֹ אֶת הַצִּפֹּֽרֶן"}, {"kind": "text", "text": "כְּדֵי שֶׁתְּ֒הֵא עַזָּה."}, {"kind": "text", "text": "וַהֲלֹא מֵי רַגְלַֽיִם"}, {"kind": "text", "text": "יָפִין לָהּ"}, {"kind": "text", "text": "אֶלָּא שֶׁאֵין מַכְנִיסִין"}, {"kind": "text", "text": "מֵי רַגְלַֽיִם בַּמִּקְדָּשׁ"}, {"kind": "text", "text": "מִפְּנֵי הַכָּבוֹד:"}, {"kind": "text", "text": "הַשִּׁיר"}, {"kind": "text", "text": "שֶׁהַלְ֒וִיִּם הָיוּ אוֹמְ֒רִים"}, {"kind": "text", "text": "בְּבֵית הַמִּקְדָּשׁ:"}, {"kind": "text", "text": "בַּיּוֹם הָרִאשׁוֹן הָיוּ אוֹמְ֒רִים."}, {"kind": "text", "text": "לַיהֹוָה הָאָֽרֶץ וּמְלֹאָהּ"}, {"kind": "text", "text": "תֵּבֵל"}, {"kind": "text", "text": "וְיֽשְׁ֒בֵי בָהּ:"}, {"kind": "text", "text": "בַּשֵּׁנִי הָיוּ אוֹמְ֒רִים."}, {"kind": "text", "text": "גָּדוֹל יְהֹוָה וּמְהֻלָּל מְאֹד"}, {"kind": "text", "text": "בְּעִיר אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "הַר קָדְשׁוֹ:"}, {"kind": "text", "text": "בַּשְּׁ֒לִישִׁי הָיוּ אוֹמְ֒רִים."}, {"kind": "text", "text": "אֱלֹהִים נִצָּב"}, {"kind": "text", "text": "בַּעֲדַת אֵל"}, {"kind": "text", "text": "בְּקֶֽרֶב אֱלֹהִים יִשְׁפֹּט:"}, {"kind": "text", "text": "בָּרְ֒בִיעִי הָיוּ אוֹמְ֒רִים."}, {"kind": "text", "text": "אֵל נְקָמוֹת יְהֹוָה"}, {"kind": "text", "text": "אֵל נְקָמוֹת הוֹפִֽיעַ:"}, {"kind": "text", "text": "בַּחֲמִישִׁי הָיוּ אוֹמְ֒רִים."}, {"kind": "text", "text": "הַרְנִֽינוּ לֵאלֹהִים עֻזֵּֽנוּ"}, {"kind": "text", "text": "הָרִֽיעוּ לֵאלֹהֵי יַעֲקֹב:"}, {"kind": "text", "text": "בַּשִּׁשִּׁי הָיוּ אוֹמְ֒רִים."}, {"kind": "text", "text": "יְהֹוָה מָלָךְ"}, {"kind": "text", "text": "גֵּאוּת לָבֵשׁ"}, {"kind": "text", "text": "לָבֵשׁ יְהֹוָה"}, {"kind": "text", "text": "עֹז הִתְאַזָּר"}, {"kind": "text", "text": "אַף תִּכּוֹן תֵּבֵל"}, {"kind": "text", "text": "בַּל תִּמּוֹט:"}, {"kind": "text", "text": "בַּשַּׁבָּת הָיוּ אוֹמְרִים."}, {"kind": "text", "text": "מִזְמוֹר שִׁיר לְיוֹם הַשַּׁבָּת."}, {"kind": "text", "text": "מִזְמוֹר שִׁיר לֶעָתִיד לָבֹא."}, {"kind": "text", "text": "לְיוֹם שֶׁכֻּלּוֹ שַׁבָּת"}, {"kind": "text", "text": "וּמְנוּחָה לְחַיֵּי הָעוֹלָמִים:"}, {"kind": "text", "text": "תָּנָא דְבֵי אֵלִיָּֽהוּ"}, {"kind": "text", "text": "כָּל הַשּׁוֹנֶה הֲלָכוֹת בְּכָל יוֹם"}, {"kind": "text", "text": "מֻבְטָח לוֹ"}, {"kind": "text", "text": "שֶׁהוּא בֶּן עוֹלָם הַבָּא"}, {"kind": "text", "text": "שֶׁנֶּאֱמַר"}, {"kind": "text", "text": "הֲלִיכוֹת עוֹלָם לוֹ"}, {"kind": "text", "text": "אַל תִּקְרֵי הֲלִיכוֹת"}, {"kind": "text", "text": "אֶלָּא הֲלָכוֹת:"}, {"kind": "text", "text": "אָמַר רַבִּי אֶלְעָזָר"}, {"kind": "text", "text": "אָמַר רַבִּי חֲנִינָא."}, {"kind": "text", "text": "תַּלְמִידֵי חֲכָמִים"}, {"kind": "text", "text": "מַרְבִּים שָׁלוֹם בָּעוֹלָם."}, {"kind": "text", "text": "שֶׁנֶּאֱמַר"}, {"kind": "text", "text": "וְכָל בָּנַֽיִךְ"}, {"kind": "text", "text": "לִמּוּדֵי יְהֹוָה"}, {"kind": "text", "text": "וְרַב שְׁלוֹם בָּנָֽיִךְ:"}, {"kind": "text", "text": "אַל תִּקְרֵי בָּנָֽיִךְ"}, {"kind": "text", "text": "אֶלָּא בּוֹנָֽיִךְ:"}, {"kind": "text", "text": "שָׁלוֹם רָב"}, {"kind": "text", "text": "לְאֹהֲבֵי תוֹרָתֶֽךָ"}, {"kind": "text", "text": "וְאֵין"}, {"kind": "text", "text": "לָֽמוֹ מִכְשׁוֹל:"}, {"kind": "text", "text": "יְהִי שָׁלוֹם בְּחֵילֵךְ"}, {"kind": "text", "text": "שַׁלְוָה בְּאַרְמְנוֹתָֽיִךְ:"}, {"kind": "text", "text": "לְמַֽעַן אַחַי וְרֵעָי"}, {"kind": "text", "text": "אֲדַבְּ֒רָה נָא שָׁלוֹם בָּךְ:"}, {"kind": "text", "text": "לְמַֽעַן"}, {"kind": "text", "text": "בֵּית יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "אֲבַקְשָׁה טוֹב לָךְ:"}, {"kind": "text", "text": "יְהֹוָה עֹז לְעַמּוֹ יִתֵּן"}, {"kind": "text", "text": "יְהֹוָה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם:"}, {"kind": "header", "text": "קדיש דרבנן"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְמָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְעוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְכוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְ֒קָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ."}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְחַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל."}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְמַן קָרִיב."}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְעָלְמֵי עָלְמַיָּא:"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקֻדְשָׁא. בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵֽלָּא (בעשי\"ת וּלְעֵֽלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְכָתָא וְשִׁירָתָא."}, {"kind": "text", "text": "תֻּשְׁבְּחָתָא וְנֶחֱמָתָא."}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְמָא וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "עַל יִשְׂרָאֵל וְעַל רַבָּנָן"}, {"kind": "text", "text": "וְעַל תַּלְמִידֵיהוֹן"}, {"kind": "text", "text": "וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן."}, {"kind": "text", "text": "וְעַל כָּל מָאן דְּעָסְקִין"}, {"kind": "text", "text": "בְּאוֹרַיְתָא."}, {"kind": "text", "text": "דִּי בְאַתְרָא הָדֵין"}, {"kind": "text", "text": "וְדִי בְכָל אֲתַר וַאֲתַר."}, {"kind": "text", "text": "יְהֵא לְהוֹן וּלְכוֹן"}, {"kind": "text", "text": "שְׁלָמָא רַבָּא חִנָּא וְחִסְדָּא"}, {"kind": "text", "text": "וְרַחֲמִין וְחַיִּין אֲרִיכִין"}, {"kind": "text", "text": "וּמְזוֹנָא רְוִיחֵי וּפוּרְקָנָא"}, {"kind": "text", "text": "מִן קֳדָם אֲבוּהוֹן"}, {"kind": "text", "text": "דְבִשְׁמַיָּא וְאַרְעָא"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא"}, {"kind": "text", "text": "וְחַיִּים טוֹבִים"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל."}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו"}, {"kind": "text", "text": "הוּא יַעֲשֶׂה בְרַחֲמָיו שָׁלוֹם"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל."}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "header", "text": "עלינו"}, {"kind": "text", "text": "עָלֵֽינוּ לְשַׁבֵּֽחַ"}, {"kind": "text", "text": "לַאֲדוֹן הַכֹּל"}, {"kind": "text", "text": "לָתֵת גְּדֻלָּה"}, {"kind": "text", "text": "לְיוֹצֵר בְּרֵאשִׁית"}, {"kind": "text", "text": "שֶׁלֹּא עָשָֽׂנוּ"}, {"kind": "text", "text": "כְּגוֹיֵי הָאֲרָצוֹת"}, {"kind": "text", "text": "וְלֹא שָׂמָֽנוּ"}, {"kind": "text", "text": "כְּמִשְׁפְּ֒חוֹת הָאֲדָמָה"}, {"kind": "text", "text": "שֶׁלֹּא שָׂם"}, {"kind": "text", "text": "חֶלְקֵֽנוּ כָּהֶם"}, {"kind": "text", "text": "וְגוֹרָלֵֽנוּ כְּכָל הֲמוֹנָם:"}, {"kind": "text", "text": "שֶׁהֵם מִשְׁתַּחֲוִים"}, {"kind": "text", "text": "לַהֶֽבֶל וָרִיק"}, {"kind": "text", "text": "וּמִתְפַּלְּ֒לִים אֶל אֵל לֹא יוֹשִֽׁיעַ."}, {"kind": "text", "text": "וַאֲנַֽחְנוּ כּוֹרְ֒עִים וּמִשְׁתַּחֲוִים"}, {"kind": "text", "text": "וּמוֹדִים"}, {"kind": "text", "text": "לִפְנֵי מֶֽלֶךְ מַלְכֵי הַמְּ֒לָכִים"}, {"kind": "text", "text": "הַקָּדוֹשׁ בָּרוּךְ הוּא."}, {"kind": "text", "text": "שֶׁהוּא נוֹטֶה שָׁמַֽיִם"}, {"kind": "text", "text": "וְיוֹסֵד אָֽרֶץ."}, {"kind": "text", "text": "וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַֽיִם מִמַּֽעַל."}, {"kind": "text", "text": "וּשְׁכִינַת עֻזּוֹ"}, {"kind": "text", "text": "בְּגָבְהֵי מְרוֹמִים."}, {"kind": "text", "text": "הוּא אֱלֹהֵֽינוּ אֵין עוֹד."}, {"kind": "text", "text": "אֱמֶת מַלְכֵּֽנוּ"}, {"kind": "text", "text": "אֶֽפֶס זוּלָתוֹ"}, {"kind": "text", "text": "כַּכָּתוּב בְּתוֹרָתוֹ"}, {"kind": "text", "text": "וְיָדַעְתָּ הַיּוֹם"}, {"kind": "text", "text": "וַהֲשֵׁבֹתָ אֶל לְבָבֶֽךָ"}, {"kind": "text", "text": "כִּי יְהֹוָה הוּא הָאֱלֹהִים"}, {"kind": "text", "text": "בַּשָּׁמַֽיִם מִמַּֽעַל"}, {"kind": "text", "text": "וְעַל הָאָֽרֶץ מִתָּֽחַת"}, {"kind": "text", "text": "אֵין עוֹד:"}, {"kind": "text", "text": "עַל כֵּן נְקַוֶּה לְךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "לִרְאוֹת מְהֵרָה בְּתִפְאֶֽרֶת עֻזֶּֽךָ"}, {"kind": "text", "text": "לְהַעֲבִיר גִּלּוּלִים מִן הָאָֽרֶץ"}, {"kind": "text", "text": "וְהָאֱלִילִים"}, {"kind": "text", "text": "כָּרוֹת יִכָּרֵתוּן"}, {"kind": "text", "text": "לְתַקֵּן עוֹלָם"}, {"kind": "text", "text": "בְּמַלְכוּת שַׁדַּי"}, {"kind": "text", "text": "וְכָל בְּנֵי בָשָׂר יִקְרְ֒אוּ בִשְׁמֶֽךָ."}, {"kind": "text", "text": "לְהַפְנוֹת אֵלֶֽיךָ"}, {"kind": "text", "text": "כָּל רִשְׁעֵי אָֽרֶץ."}, {"kind": "text", "text": "יַכִּֽירוּ וְיֵדְ֒עוּ"}, {"kind": "text", "text": "כָּל יוֹשְׁ֒בֵי תֵבֵל"}, {"kind": "text", "text": "כִּי לְךָ תִכְרַע כָּל בֶּֽרֶךְ"}, {"kind": "text", "text": "תִּשָּׁבַע כָּל לָשׁוֹן:"}, {"kind": "text", "text": "לְפָנֶֽיךָ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "יִכְרְ֒עוּ וְיִפֹּֽלוּ."}, {"kind": "text", "text": "וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּֽנוּ."}, {"kind": "text", "text": "וִיקַבְּ֒לוּ כֻלָּם"}, {"kind": "text", "text": "אֶת עֹל מַלְכוּתֶֽךָ."}, {"kind": "text", "text": "וְתִמְלֹךְ עֲלֵיהֶם מְהֵרָה"}, {"kind": "text", "text": "לְעוֹלָם וָעֶד."}, {"kind": "text", "text": "כִּי הַמַּלְכוּת שֶׁלְּ֒ךָ הִיא"}, {"kind": "text", "text": "וּלְעֽוֹלְ֒מֵי עַד תִּמְלוֹךְ בְּכָבוֹד."}, {"kind": "text", "text": "כַּכָּתוּב בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "יְהֹוָה יִמְלֹךְ לְעֹלָם וָעֶד:"}, {"kind": "text", "text": "❖וְנֶאֱמַר"}, {"kind": "text", "text": "וְהָיָה יְהֹוָה לְמֶֽלֶךְ"}, {"kind": "text", "text": "עַל כָּל הָאָֽרֶץ"}, {"kind": "text", "text": "בַּיּוֹם הַהוּא יִהְיֶה יְהֹוָה אֶחָד"}, {"kind": "text", "text": "וּשְׁמוֹ אֶחָד:"}, {"kind": "header", "text": "קדיש יתום"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְמָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְעוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְכוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְ֒קָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ."}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְחַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל."}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְמַן קָרִיב."}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְעָלְמֵי עָלְמַיָּא:"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקֻדְשָׁא. בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵלָּא (בעשי\"ת וּלְעֵלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְכָתָא וְשִׁירָתָא."}, {"kind": "text", "text": "תֻּשְׁבְּחָתָא וְנֶחֱמָתָא."}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא"}, {"kind": "text", "text": "וְחַיִּים טוֹבִים"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל."}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו"}, {"kind": "text", "text": "הוּא יַעֲשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "אַל תִּירָא מִפַּֽחַד פִּתְאֹם"}, {"kind": "text", "text": "וּמִשֹּׁאַת רְשָׁעִים"}, {"kind": "text", "text": "כִּי תָבֹא:"}, {"kind": "text", "text": "עֻֽצוּ עֵצָה וְתֻפָר"}, {"kind": "text", "text": "דַּבְּ֒רוּ דָבָר וְלֹא יָקוּם"}, {"kind": "text", "text": "כִּי עִמָּֽנוּ אֵל:"}, {"kind": "text", "text": "וְעַד זִקְנָה אֲנִי הוּא"}, {"kind": "text", "text": "וְעַד שֵׂיבָה אֲנִי אֶסְבֹּל:"}, {"kind": "text", "text": "אֲנִי עָשִֽׂיתִי וַאֲנִי אֶשָּׂא"}, {"kind": "text", "text": "וַאֲנִי אֶסְבֹּל וַאֲמַלֵּט:"}, {"kind": "header", "text": "שיר הכבוד"}, {"kind": "text", "text": "חזן: אַנְעִים זְמִירוֹת וְשִׁירִים אֶאֱרוֹג. כִּי אֵלֶֽיךָ נַפְשִׁי תַעֲרוֹג:"}, {"kind": "text", "text": "קהל: נַפְשִׁי חָמְדָה בְּצֵל יָדֶֽיךָ. לָדַֽעַת כָּל רָז סוֹדֶֽךָ:"}, {"kind": "text", "text": "חזן: מִדֵּי דַבְּ֒רִי בִּכְבוֹדֶֽךָ. הוֹמֶה לִבִּי אֶל דּוֹדֶֽיךָ:"}, {"kind": "text", "text": "קהל: עַל כֵּן אֲדַבֵּר בְּךָ נִכְבָּדוֹת. וְשִׁמְךָ אֲכַבֵּד בְּשִׁירֵי יְדִידוֹת:"}, {"kind": "text", "text": "חזן: אֲסַפְּ֒רָה כְּבוֹדְךָ וְלֹא רְאִיתִֽיךָ. אֲדַמְּ֒ךָ אֲכַנְּ֒ךָ וְלֹא יְדַעְתִּֽיךָ:"}, {"kind": "text", "text": "קהל: בְּיַד נְבִיאֶֽיךָ בְּסוֹד עֲבָדֶֽיךָ. דִּמִּֽיתָ הֲדַר כְּבוֹד הוֹדֶֽךָ:"}, {"kind": "text", "text": "חזן: גְּדֻלָּתְ֒ךָ וּגְבוּרָתֶֽךָ. כִּנּוּ לְתֹקֶף פְּעֻלָּתֶֽךָ:"}, {"kind": "text", "text": "קהל: דִּמּוּ אוֹתְ֒ךָ וְלֹא כְּפִי יֶשְׁךָ. וַיַּשְׁוֽוּךָ לְפִי מַעֲשֶֽׂיךָ:"}, {"kind": "text", "text": "חזן: הִמְשִׁילֽוּךָ בְּרוֹב חֶזְיוֹנוֹת. הִנְּ֒ךָ אֶחָד בְּכָל דִּמְיוֹנוֹת:"}, {"kind": "text", "text": "קהל: וַיֶּחֱזוּ בְךָ זִקְנָה וּבַחֲרוּת. וּשְׂעַר רֹאשְׁ֒ךָ בְּשֵׂיבָה וְשַׁחֲרוּת:"}, {"kind": "text", "text": "חזן: זִקְנָה בְּיוֹם דִּין וּבַחֲרוּת בְּיוֹם קְרָב. כְּאִישׁ מִלְחָמוֹת יָדָיו לוֹ רָב:"}, {"kind": "text", "text": "קהל: חָבַשׁ כּוֹבַע יְשׁוּעָה בְּרֹאשׁוֹ. הוֹשִֽׁיעָה לוֹ יְמִינוֹ וּזְרֽוֹעַ קָדְשׁוֹ:"}, {"kind": "text", "text": "חזן: טַלְלֵי אוֹרוֹת רֹאשׁוֹ נִמְלָא. קְוֻצּוֹתָיו רְסִיסֵי לָֽיְלָה:"}, {"kind": "text", "text": "קהל: יִתְפָּאֵר בִּי כִּי חָפֵץ בִּי. וְהוּא יִהְיֶה לִי לַעֲטֶֽרֶת צְבִי:"}, {"kind": "text", "text": "חזן: כֶּֽתֶם טָהוֹר פָּז דְּמוּת רֹאשוֹ. וְחַק עַל מֵֽצַח כְּבוֹד שֵׁם קָדְשׁוֹ:"}, {"kind": "text", "text": "קהל: לְחֵן וּלְכָבוֹד צְבִי תִפְאָרָה. אֻמָּתוֹ לוֹ עִטְּ֒רָה עֲטָרָה:"}, {"kind": "text", "text": "חזן: מַחְלְ֒פוֹת רֹאשׁוֹ כְּבִימֵי בְחֻרוֹת. קְוֻצּוֹתָיו תַּלְתַּלִּים שְׁחוֹרוֹת:"}, {"kind": "text", "text": "קהל: נְוֵה הַצֶּֽדֶק צְבִי תִפְאַרְתּוֹ. יַעֲלֶה נָא עַל רֹאשׁ שִׂמְחָתוֹ:"}, {"kind": "text", "text": "חזן: סְגֻלָּתוֹ תְּהִי בְיָדוֹ עֲטֶֽרֶת. וּצְנִיף מְלוּכָה צְבִי תִפְאֶֽרֶת:"}, {"kind": "text", "text": "קהל: עֲמוּסִים נְשָׂאָם עֲטֶרֶת עִנְּ֒דָם. מֵאֲשֶׁר יָקְ֒רוּ בְּעֵינָיו כִּבְּ֒דָם:"}, {"kind": "text", "text": "חזן: פְּאֵרוֹ עָלַי וּפְאֵרִי עָלָיו. וְקָרוֹב אֵלַי בְּקָרְאִי אֵלָיו:"}, {"kind": "text", "text": "קהל: צַח וְאָדוֹם לִלְבוּשׁוֹ אָדוֹם. פּוּרָה בְּדָרְכוֹ בְּבוֹאוֹ מֵאֱדוֹם:"}, {"kind": "text", "text": "חזן: קֶֽשֶׁר תְּפִלִּין הֶרְאָה לֶעָנָו. תְּמוּנַת יְהֹוָה לְנֶֽגֶד עֵינָיו:"}, {"kind": "text", "text": "קהל: רוֹצֶה בְּעַמּוֹ עֲנָוִים יְפָאֵר. יוֹשֵׁב תְּהִלּוֹת בָּם לְהִתְפָּאֵר:"}, {"kind": "text", "text": "חזן: רֹאשׁ דְּבָרְךָ אֱמֶת קוֹרֵא מֵרֹאשׁ. דּוֹר וָדוֹר עַם דּוֹרְשֶֽׁךָ דְּרוֹשׁ:"}, {"kind": "text", "text": "קהל: שִׁית הֲמוֹן שִׁירַי עָלֶֽיךָ. וְרִנָּתִי תִּקְרַב אֵלֶֽיךָ:"}, {"kind": "text", "text": "חזן: תְּהִלָּתִי תְהִי לְרֹאשְׁ֒ךָ עֲטֶֽרֶת. וּתְפִלָּתִי תִּכּוֹן קְטֹֽרֶת:"}, {"kind": "text", "text": "קהל: תִּיקַר שִׁירַת רָשׁ בְּעֵינֶֽיךָ. כַּשִּׁיר יוּשַׁר עַל קָרְבָּנֶֽיךָ:"}, {"kind": "text", "text": "חזן: בִּרְכָתִי תַעֲלֶה לְרֹאשׁ מַשְׁבִּיר. מְחוֹלֵל וּמוֹלִיד צַדִּיק כַּבִּיר:"}, {"kind": "text", "text": "קהל: וּבְבִרְכָתִי תְנַעֲנַע לִי רֹאשׁ. וְאוֹתָהּ קַח לְךָ כִּבְשָׂמִים רֹאשׁ:"}, {"kind": "text", "text": "חזן: יֶעֱרַב נָא שִׂיחִי עָלֶיךָ. כִּי נַפְשִׁי תַעֲרוֹג אֵלֶיךָ:"}, {"kind": "text", "text": "לְךָ יְהֹוָה הַגְּ֒דֻלָּה וְהַגְּ֒בוּרָה וְהַנֵּֽצַח וְהַהוֹד כִּי כֹל בַּשָּׁמַֽיִם וּבָאָֽרֶץ. לְךָ יְהֹוָה הַמַּמְלָכָה וְהַמִּתְנַשֵּׂא לְכֹל לְרֹאשׁ. מִי יְמַלֵּל גְּבוּרוֹת יְהֹוָה יַשְׁמִֽיעַ כָּל־תְּהִלָּתוֹ:"}, {"kind": "header", "text": "אדון עולם"}, {"kind": "text", "text": "אֲדוֹן עוֹלָם אֲשֶׁר מָלַךְ."}, {"kind": "text", "text": "בְּטֶֽרֶם כָּל יְצִיר נִבְרָא:"}, {"kind": "text", "text": "לְעֵת נַעֲשָׂה בְחֶפְצוֹ כֹּל."}, {"kind": "text", "text": "אֲזַי מֶֽלֶךְ שְׁמוֹ נִקְרָא:"}, {"kind": "text", "text": "וְאַחֲרֵי כִּכְלוֹת הַכֹּל."}, {"kind": "text", "text": "לְבַדּוֹ יִמְלֹךְ נוֹרָא:"}, {"kind": "text", "text": "וְהוּא הָיָה וְהוּא הֹוֶה."}, {"kind": "text", "text": "וְהוּא יִהְיֶה בְּתִפְאָרָה:"}, {"kind": "text", "text": "וְהוּא אֶחָד וְאֵין שֵׁנִי."}, {"kind": "text", "text": "לְהַמְשִׁיל לוֹ לְהַחְבִּֽירָה:"}, {"kind": "text", "text": "בְּלִי רֵאשִׁית בְּלִי תַכְלִית."}, {"kind": "text", "text": "וְלוֹ הָעֹז וְהַמִּשְׂרָה:"}, {"kind": "text", "text": "וְהוּא אֵלִי וְחַי גּוֹאֲלִי."}, {"kind": "text", "text": "וְצוּר חֶבְלִי בְּעֵת צָרָה:"}, {"kind": "text", "text": "וְהוּא נִסִּי וּמָנוֹס לִי."}, {"kind": "text", "text": "מְנָת כּוֹסִי בְּיוֹם אֶקְרָא:"}, {"kind": "text", "text": "בְּיָדוֹ אַפְקִיד רוּחִי."}, {"kind": "text", "text": "בְּעֵת אִישַׁן וְאָעִֽירָה:"}, {"kind": "text", "text": "וְעִם רוּחִי גְּוִיָּתִי."}, {"kind": "text", "text": "יְהוָה לִי וְלֹא אִירָא:"}], "mincha": [{"kind": "header", "text": "קרבנות"}, {"kind": "text", "text": "וַיְדַבֵּר יְהֹוָה אֶל־משֶׁה לֵּאמֹר:"}, {"kind": "text", "text": "וְעָשִֽׂיתָ כִּיּוֹר נְחֽשֶׁת"}, {"kind": "text", "text": "וְכַנּוֹ נְחֽשֶׁת לְרָחְצָה"}, {"kind": "text", "text": "וְנָתַתָּ אֹת֒וֹ"}, {"kind": "text", "text": "בֵּין־אֹֽהֶל מוֹעֵד וּבֵין הַמִּזְבֵּֽחַ"}, {"kind": "text", "text": "וְנָתַתָּ שָֽׁמָּה מָֽיִם:"}, {"kind": "text", "text": "וְרָחֲצוּ אַהֲרֹן וּבָנָיו מִמֶּֽנּוּ"}, {"kind": "text", "text": "אֶת־יְדֵיהֶם וְאֶת־רַגְלֵיהֶם:"}, {"kind": "text", "text": "בְּבֹאָם אֶל־אֹֽהֶל מוֹעֵד"}, {"kind": "text", "text": "יִרְחֲצוּ־מַֽיִם וְלֹא יָמֻֽתוּ"}, {"kind": "text", "text": "אוֹ בְגִשְׁתָּם אֶל־הַמִּזְבֵּֽחַ"}, {"kind": "text", "text": "לְשָׁרֵת לְהַקְטִיר אִשֶּׁה לַיהוֹה:"}, {"kind": "text", "text": "וְרָחֲצוּ יְדֵיהֶם וְרַגְלֵיהֶם"}, {"kind": "text", "text": "וְלֹא יָמֻֽתוּ"}, {"kind": "text", "text": "וְהָיְ֒תָה לָהֶם חָק־עוֹלָם"}, {"kind": "text", "text": "לוֹ וּלְ֒זַרְעוֹ"}, {"kind": "text", "text": "לְדֹרֹתָם:"}, {"kind": "header", "text": "קרבן תמיד"}, {"kind": "text", "text": "יְהִי רָצוֹן מִלְּ֒פָנֶֽיךָ,"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ,"}, {"kind": "text", "text": "שֶׁתְּ֒רַחֵם עָלֵֽינוּ"}, {"kind": "text", "text": "וְתִמְחָל לָֽנוּ עַל כָּל חַטֹּאתֵֽינוּ"}, {"kind": "text", "text": "וּתְ֒כַפֶּר לָֽנוּ אֶת כָּל עֲוֹנוֹתֵֽינוּ"}, {"kind": "text", "text": "וְתִסְלַח לָֽנוּ עַל־כָּל פְּשָׁעֵֽינוּ"}, {"kind": "text", "text": "וְשֶׁתִּבְנֶה בֵּית הַמִּקְדָּשׁ"}, {"kind": "text", "text": "בִּמְ֒הֵרָה בְיָמֵֽינוּ"}, {"kind": "text", "text": "וְנַקְרִיב לְפָנֶֽיךָ"}, {"kind": "text", "text": "קָרְבַּן הַתָּמִיד שֶׁיְּ֒כַפֵּר בַּעֲדֵֽנוּ"}, {"kind": "text", "text": "כְּמוֹ שֶׁכָּתַֽבְתָּ עָלֵֽינוּ בְּתוֹרָתֶֽךָ,"}, {"kind": "text", "text": "עַל יְדֵי משֶׁה עַבְדֶּֽךָ,"}, {"kind": "text", "text": "מִפִּי כְבוֹדֶֽךָ"}, {"kind": "text", "text": "כָּאָמוּר:"}, {"kind": "text", "text": "וַיְ֒דַבֵּר יְהֹוָה אֶל־משֶׁה לֵּאמֹר:"}, {"kind": "text", "text": "צַו אֶת־בְּנֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאָמַרְתָּ אֲלֵהֶם"}, {"kind": "text", "text": "אֶת־קָרְבָּנִי לַחְמִי"}, {"kind": "text", "text": "לְאִשַּׁ֒י"}, {"kind": "text", "text": "רֵֽיחַ נִיחֹחִי"}, {"kind": "text", "text": "תִּשְׁמְ֒רוּ לְהַקְרִיב לִי"}, {"kind": "text", "text": "בְּמוֹעֲדוֹ:"}, {"kind": "text", "text": "וְאָמַרְתָּ לָהֶם"}, {"kind": "text", "text": "זֶה הָאִשֶּׁה"}, {"kind": "text", "text": "אֲשֶׁר תַּקְרִֽיבוּ לַיהוֹה"}, {"kind": "text", "text": "כְּבָשִׂים בְּנֵי־שָׁנָה"}, {"kind": "text", "text": "תְמִימִם"}, {"kind": "text", "text": "שְׁנַֽיִם לַיּוֹם"}, {"kind": "text", "text": "עֹלָה תָמִיד:"}, {"kind": "text", "text": "אֶת־הַכֶּֽבֶשׂ אֶחָד תַּעֲשֶׂה בַבֹּֽקֶר"}, {"kind": "text", "text": "וְאֵת הַכֶּֽבֶשׂ הַשֵּׁנִי"}, {"kind": "text", "text": "תַּעֲשֶׂה בֵּין הָעַרְבָּֽיִם:"}, {"kind": "text", "text": "וַֽעֲשִׂירִית הָאֵיפָה סֹֽלֶת"}, {"kind": "text", "text": "לְמִנְחָה"}, {"kind": "text", "text": "בְּלוּלָה בְּשֶֽׁמֶן כָּתִית"}, {"kind": "text", "text": "רְבִיעִת הַהִין:"}, {"kind": "text", "text": "עֹלַת תָּמִיד"}, {"kind": "text", "text": "הָעֲשֻׂיָה בְּהַר סִינַי"}, {"kind": "text", "text": "לְרֵֽיחַ נִיחֹֽחַ אִשֶּׁה לַיהוֹה:"}, {"kind": "text", "text": "וְנִסְכּוֹ"}, {"kind": "text", "text": "רְבִיעִת הַהִין לַכֶּֽבֶשׂ הָאֶחָד"}, {"kind": "text", "text": "בַּקֹּֽדֶשׁ הַסֵּךְ"}, {"kind": "text", "text": "נֶֽסֶךְ שֵׁכָר לַיהוֹה:"}, {"kind": "text", "text": "וְאֵת הַכֶּֽבֶשׂ הַשֵּׁנִי"}, {"kind": "text", "text": "תַּעֲשֶׂה בֵּין הָעַרְבָּֽיִם"}, {"kind": "text", "text": "כְּמִנְחַת הַבֹּֽקֶר"}, {"kind": "text", "text": "וּכְ֒נִסְכּוֹ תַּעֲשֶׂה"}, {"kind": "text", "text": "אִשֵּׁה רֵֽיחַ נִיחֹֽחַ לַיהוֹה:"}, {"kind": "text", "text": "וְשָׁחַט אֹתוֹ"}, {"kind": "text", "text": "עַל יֶֽרֶךְ הַמִּזְבֵּֽחַ צָפֹֽנָה"}, {"kind": "text", "text": "לִפְ֒נֵי יְהֹוָה"}, {"kind": "text", "text": "וְזָרְקוּ בְּנֵי אַהֲרֹן הַכֹּהֲנִים"}, {"kind": "text", "text": "אֶת־דָּמוֹ עַל־הַמִּזְבֵּֽחַ סָבִיב:"}, {"kind": "text", "text": "יְהִי רָצוֹן מִלְּ֒פָנֶֽיךָ,"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ,"}, {"kind": "text", "text": "שֶׁתְּ֒הֵא אֲמִירָה זוּ,"}, {"kind": "text", "text": "חֲשׁוּבָה וּמְ֒קֻבֶּֽלֶת,"}, {"kind": "text", "text": "וּמְ֒רֻצָּה לְפָנֶֽיךָ,"}, {"kind": "text", "text": "כְּאִלּוּ הִקְרַֽבְנוּ"}, {"kind": "text", "text": "קָרְבַּן הַתָּמִיד"}, {"kind": "text", "text": "בְּמוֹעֲדוֹ,"}, {"kind": "text", "text": "וּבִמְ֒קוֹמוֹ"}, {"kind": "text", "text": "וּכְ֒הִלְ֒כָתוֹ:"}, {"kind": "header", "text": "קטורת"}, {"kind": "text", "text": "אַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "שֶׁהִקְטִֽירוּ אֲבוֹתֵֽינוּ לְפָנֶֽיךָ"}, {"kind": "text", "text": "אֶת קְטֹֽרֶת הַסַּמִּים"}, {"kind": "text", "text": "בִּזְ֒מַן שֶׁבֵּית הַמִּקְדָּשׁ הָיָה קַיָּם"}, {"kind": "text", "text": "כַּאֲשֶׁר צִוִּֽיתָ אוֹתָם"}, {"kind": "text", "text": "עַל יְדֵי משֶׁה נְבִיאֶֽךָ"}, {"kind": "text", "text": "כַּכָּתוּב בְּתוֹרָתֶֽךָ:"}, {"kind": "text", "text": "וַיֹּֽאמֶר יְהֹוָה אֶל־משֶׁה"}, {"kind": "text", "text": "קַח־לְךָ סַמִּים"}, {"kind": "text", "text": "נָטָף וּשְׁ֒חֵֽלֶת וְחֶלְבְּנָה"}, {"kind": "text", "text": "סַמִּים וּלְ֒בֹנָה זַכָּה"}, {"kind": "text", "text": "בַּד בְּבַד יִהְיֶה:"}, {"kind": "text", "text": "וְעָשִֽׂיתָ אֹתָהּ קְטֹֽרֶת"}, {"kind": "text", "text": "רֹֽקַח מַעֲשֵׂה רוֹקֵֽחַ"}, {"kind": "text", "text": "מְמֻלָּח טָהוֹר קֹֽדֶשׁ:"}, {"kind": "text", "text": "וְשָׁחַקְתָּ מִמֶּֽנָּה הָדֵק֒"}, {"kind": "text", "text": "וְנָתַתָּה מִמֶּֽנָּה לִפְ֒נֵי הָעֵדֻת"}, {"kind": "text", "text": "בְּאֹֽהֶל מוֹעֵד"}, {"kind": "text", "text": "אֲשֶׁר אִוָּעֵד לְךָ שָֽׁמָּה"}, {"kind": "text", "text": "קֹֽדֶשׁ קָדָשִׁים תִּהְיֶה לָכֶם:"}, {"kind": "text", "text": "וְנֶאֱמַר"}, {"kind": "text", "text": "וְהִקְטִיר עָלָיו אַהֲרֹן"}, {"kind": "text", "text": "קְטֹֽרֶת סַמִּים בַּבֹּֽקֶר בַּבֹּֽקֶר"}, {"kind": "text", "text": "בְּהֵיטִיבוֹ אֶת־הַנֵּרֹת"}, {"kind": "text", "text": "יַקְטִירֶֽנָּה:"}, {"kind": "text", "text": "וּבְ֒הַעֲלֹת אַהֲרֹן אֶת־הַנֵּרֹת"}, {"kind": "text", "text": "בֵּין הָֽעַרְבַּֽיִם"}, {"kind": "text", "text": "יַקְטִירֶֽנָּה"}, {"kind": "text", "text": "קְטֹֽרֶת תָּמִיד לִפְ֒נֵי יְהֹוָה"}, {"kind": "text", "text": "לְדֹרֹתֵיכֶם:"}, {"kind": "text", "text": "תָּנוּ רַבָּנָן"}, {"kind": "text", "text": "פִּטּוּם הַקְּ֒טֹֽרֶת כֵּיצַד"}, {"kind": "text", "text": "שְׁלֹש מֵאוֹת וְשִׁשִּׁים וּשְׁ֒מוֹנָה"}, {"kind": "text", "text": "מָנִים הָיוּ בָהּ,"}, {"kind": "text", "text": "שְׁלֹש מֵאוֹת וְשִׁשִּׁים וַחֲמִשָּׁה"}, {"kind": "text", "text": "כְּמִנְיַן"}, {"kind": "text", "text": "יְמוֹת הַחַמָּה"}, {"kind": "text", "text": "מָנֶה לְכָל יוֹם,"}, {"kind": "text", "text": "פְּרַס בַּשַּׁחֲרִית"}, {"kind": "text", "text": "וּפְ֒רַס בֵּין הָעַרְבָּֽיִם,"}, {"kind": "text", "text": "וּשְׁ֒לשָׁה מָנִים יְתֵרִים"}, {"kind": "text", "text": "שֶׁמֵּהֶם מַכְנִיס כֹּהֵן גָּדוֹל"}, {"kind": "text", "text": "מְלֹא חָפְנָיו"}, {"kind": "text", "text": "בְּיוֹם הַכִּפּוּרִים,"}, {"kind": "text", "text": "וּמַחֲזִירָן"}, {"kind": "text", "text": "לְמַכְתֶּֽשֶׁת"}, {"kind": "text", "text": "בְּעֶֽרֶב יוֹם הַכִּפּוּרִים,"}, {"kind": "text", "text": "וְשׁוֹחֲקָן יָפֶה יָפֶה"}, {"kind": "text", "text": "כְּדֵי שֶׁתְּ֒הֵא דַקָּה מִן הַדַּקָּה,"}, {"kind": "text", "text": "וְאַחַד עָשָׂר סַמָּנִים הָֽיוּ בָהּ,"}, {"kind": "text", "text": "וְאֵֽלּוּ הֵן"}, {"kind": "text", "text": "הַצֳּרִי וְהַצִּפֹּֽרֶן"}, {"kind": "text", "text": "הַחֶלְבְּנָה וְהַלְּ֒בוֹנָה"}, {"kind": "text", "text": "מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה,"}, {"kind": "text", "text": "מוֹר וּקְ֒צִיעָה"}, {"kind": "text", "text": "שִׁבֹּֽלֶת נֵרְדְּ וְכַרְכֹּם"}, {"kind": "text", "text": "מִשְׁקַל"}, {"kind": "text", "text": "שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה,"}, {"kind": "text", "text": "הַקּשְׁטְ שְׁנֵים עָשָׂר"}, {"kind": "text", "text": "וְקִלּוּפָה שְׁלשָׁה"}, {"kind": "text", "text": "וְקִנָּמוֹן תִּשְׁעָה,"}, {"kind": "text", "text": "בֹּרִית כַּרְשִׁינָה תִּשְׁעָה קַבִּין,"}, {"kind": "text", "text": "יֵין קַפְרִיסִין"}, {"kind": "text", "text": "סְאִין תְּלָתָא וְקַבִּין תְּלָתָא,"}, {"kind": "text", "text": "וְאִם אֵין לוֹ יֵין קַפְרִיסִין"}, {"kind": "text", "text": "מֵבִיא חֲמַר חִוַּרְיָן עַתִּיק,"}, {"kind": "text", "text": "מֶֽלַח סְדוֹמִית רֹֽבַע הַקָּב,"}, {"kind": "text", "text": "מַעֲלֶה עָשָׁן כָּל שֶׁהוּא,"}, {"kind": "text", "text": "רַבִּי נָתָן הַבַּבְלִי אוֹמֵר"}, {"kind": "text", "text": "אַף כִּפַּת הַיַּרְדֵּן"}, {"kind": "text", "text": "כָּל שֶׁהוּא,"}, {"kind": "text", "text": "וְאִם נָֽתַן בָּהּ דְּבַשׁ"}, {"kind": "text", "text": "פְּסָלָהּ"}, {"kind": "text", "text": "וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶֽיהָ"}, {"kind": "text", "text": "חַיָּב מִיתָה:"}, {"kind": "text", "text": "רַבָּן שִׁמְעוֹן בֶּן גַּמְלִיאֵל"}, {"kind": "text", "text": "אוֹמֵר"}, {"kind": "text", "text": "הַצֳּרִי אֵינוֹ אֶלָּא שְׂרָף"}, {"kind": "text", "text": "הַנּוֹטֵף מֵעֲצֵי הַקְּ֒טָף,"}, {"kind": "text", "text": "בֹּרִית כַּרְשִׁינָה"}, {"kind": "text", "text": "שֶׁשָׁפִין בָּה אֶת הַצִפֹּרֶן"}, {"kind": "text", "text": "כִּדֵי שֶׁתְּ֒הֵא נָאֶה"}, {"kind": "text", "text": "יֵין קַפְרִיסִין"}, {"kind": "text", "text": "שֶׁשׁוֹרִין בּוֹ אֶת הַצִפֹּרֶן"}, {"kind": "text", "text": "כְּדֵי שֶׁתְּ֒הֵא עַזָּה,"}, {"kind": "text", "text": "וַהֲלֹא מֵי רַגְלַֽיִם"}, {"kind": "text", "text": "יָפִין לָהּ"}, {"kind": "text", "text": "אֶלָּא שֶׁאֵין מַכְנִיסִין"}, {"kind": "text", "text": "מֵי רַגְלַֽיִם בַּמִּקְדָּשׁ"}, {"kind": "text", "text": "מִפְּנֵי הַכָּבוֹד:"}, {"kind": "text", "text": "תַּנְיָא"}, {"kind": "text", "text": "רַבִּי נָתָן אוֹמֵר"}, {"kind": "text", "text": "כְּשֶׁהוּא שׁוֹחֵק"}, {"kind": "text", "text": "אוֹמֵר"}, {"kind": "text", "text": "הָדֵק הֵיטֵב הֵיטֵב הָדֵק"}, {"kind": "text", "text": "מִפְּ֒נֵי שֶׁהַקּוֹל יָפֶה לַבְּ֒שָׂמִים,"}, {"kind": "text", "text": "פִּטְּ֒מָהּ לַחֲצָאִין"}, {"kind": "text", "text": "כְּשֵׁרָה"}, {"kind": "text", "text": "לִשְׁ֒לִישׁ"}, {"kind": "text", "text": "וְלִרְ֒בִֽיעַ"}, {"kind": "text", "text": "לֹא שָׁמַֽעְנוּ:"}, {"kind": "text", "text": "אָמַר רַבִּי יְהוּדָה"}, {"kind": "text", "text": "זֶה הַכְּ֒לָל"}, {"kind": "text", "text": "אִם"}, {"kind": "text", "text": "כְּמִדָּתָהּ"}, {"kind": "text", "text": "כְּשֵׁרָה"}, {"kind": "text", "text": "לַחֲצָאִין"}, {"kind": "text", "text": "וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶֽיהָ"}, {"kind": "text", "text": "חַיָּב מִיתָה:"}, {"kind": "text", "text": "תַּנְיָא"}, {"kind": "text", "text": "בַּר קַפָּרָא אוֹמֵר"}, {"kind": "text", "text": "אַחַת לְשִׁשִּׁים אוֹ לְשִׁבְעִים שָׁנָה"}, {"kind": "text", "text": "הָיְ֒תָה בָאָה שֶׁל שִׁירַֽיִם"}, {"kind": "text", "text": "לַחֲצָאִין:"}, {"kind": "text", "text": "וְעוֹד תָּנֵי בַּר קַפָּרָא"}, {"kind": "text", "text": "אִלּוּ הָיָה נוֹתֵן בָּהּ"}, {"kind": "text", "text": "קוֹרְ֒טוֹב שֶׁל דְּבַשׁ"}, {"kind": "text", "text": "אֵין אָדָם יָכוֹל לַעֲמֹד מִפְּ֒נֵי רֵיחָהּ"}, {"kind": "text", "text": "וְלָֽמָּה אֵין מְעָרְ֒בִין בָּהּ דְּבַשׁ"}, {"kind": "text", "text": "מִפְּ֒נֵי שֶׁהַתּוֹרָה אָמְ֒רָה"}, {"kind": "text", "text": "כִּי כָל־שְׂאֹר וְכָל־דְּבַשׁ"}, {"kind": "text", "text": "לֹא־תַקְטִֽירוּ מִמֶּֽנּוּ"}, {"kind": "text", "text": "אִשֶּׁה לַיהוֹה:"}, {"kind": "text", "text": "יְהֹוָה צְבָאוֹת עִמָּֽנוּ"}, {"kind": "text", "text": "מִשְׂגָּב לָֽנוּ אֱלֹהֵי יַעֲקֹב"}, {"kind": "text", "text": "סֶֽלָה:"}, {"kind": "text", "text": "יְהֹוָה צְבָאוֹת"}, {"kind": "text", "text": "אַשְׁרֵי אָדָם בֹּטֵֽחַ בָּךְ:"}, {"kind": "text", "text": "יְהֹוָה הוֹשִֽׁיעָה"}, {"kind": "text", "text": "הַמֶּֽלֶךְ יַעֲנֵֽנוּ בְיוֹם־קָרְ֒אֵֽנוּ:"}, {"kind": "text", "text": "אַתָּה סֵֽתֶר לִי"}, {"kind": "text", "text": "מִצַּר תִּצְּ֒רֵֽנִי"}, {"kind": "text", "text": "רָנֵּי פַלֵּט תְּסוֹבְ֒בֵֽנִי"}, {"kind": "text", "text": "סֶֽלָה:"}, {"kind": "text", "text": "וְעָרְ֒בָה לַיהוֹה"}, {"kind": "text", "text": "מִנְחַת יְהוּדָה וִירוּשָׁלָֽםִ"}, {"kind": "text", "text": "כִּימֵי עוֹלָם וּכְ֒שָׁנִים קַדְמֹנִיּוֹת:"}, {"kind": "text", "text": "אָֽנָּא, בְּכֹֽחַ גְּדֻלַּת יְמִינְ֒ךָ"}, {"kind": "text", "text": "תַּתִּיר צְרוּרָה:"}, {"kind": "text", "text": "קַבֵּל רִנַּת עַמְּ֒ךָ"}, {"kind": "text", "text": "שַׂגְּ֒בֵֽנוּ טַהֲרֵֽנוּ נוֹרָא:"}, {"kind": "text", "text": "נָא גִבּוֹר"}, {"kind": "text", "text": "דּוֹרְ֒שֵׁי יִחוּדְ֒ךָ"}, {"kind": "text", "text": "כְּבָבַת שָׁמְ֒רֵם:"}, {"kind": "text", "text": "בָּרְ֒כֵם טַהֲרֵם"}, {"kind": "text", "text": "רַחֲמֵי"}, {"kind": "text", "text": "צִדְ֒קָתְ֒ךָ"}, {"kind": "text", "text": "תָּמִיד גָּמְ֒לֵם:"}, {"kind": "text", "text": "חֲסִין קָדוֹשׁ"}, {"kind": "text", "text": "בְּרֹב טוּבְ֒ךָ"}, {"kind": "text", "text": "נַהֵל עֲדָתֶֽךָ:"}, {"kind": "text", "text": "יָחִיד גֵּאֶה לְעַמְּ֒ךָ פְּנֵה,"}, {"kind": "text", "text": "זוֹכְ֒רֵי קְדֻשָּׁתֶֽךָ:"}, {"kind": "text", "text": "שַׁוְעָתֵֽנוּ קַבֵּל וּשְׁ֒מַע צַעֲקָתֵֽנוּ"}, {"kind": "text", "text": "יוֹדֵֽעַ תַּעֲלוּמוֹת:"}, {"kind": "text", "text": "בָּרוּךְ שֵׁם"}, {"kind": "text", "text": "כְּבוֹד מַלְ֒כוּתוֹ"}, {"kind": "text", "text": "לְעוֹלָם וָעֶד:"}, {"kind": "header", "text": "אשרי"}, {"kind": "text", "text": "אַשְׁרֵי יוֹשְׁ֒בֵי"}, {"kind": "text", "text": "בֵיתֶֽךָ"}, {"kind": "text", "text": "עוֹד יְהַלְ֒לֽוּךָ סֶּֽלָה:"}, {"kind": "text", "text": "אַשְׁרֵי הָעָם שֶׁכָּֽכָה לּוֹ"}, {"kind": "text", "text": "אַשְׁרֵי הָעָם"}, {"kind": "text", "text": "שֶׁיְהֹוָה אֱלֹהָיו:"}, {"kind": "text", "text": "תְּהִלָּה לְדָוִד"}, {"kind": "text", "text": "אֲרוֹמִמְךָ אֱלוֹהַי הַמֶּֽלֶךְ"}, {"kind": "text", "text": "וַאֲבָרְ֒כָה שִׁמְךָ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "בְּכָל־יוֹם אֲבָרְכֶֽךָ"}, {"kind": "text", "text": "וַאֲהַלְ֒לָה שִׁמְךָ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "גָּדוֹל יְהֹוָה וּמְהֻלָּל מְאֹד"}, {"kind": "text", "text": "וְלִגְדֻלָּתוֹ אֵין חֵֽקֶר:"}, {"kind": "text", "text": "דּוֹר לְדוֹר"}, {"kind": "text", "text": "יְשַׁבַּח מַעֲשֶֽׂיךָ"}, {"kind": "text", "text": "וּגְבוּרֹתֶֽיךָ יַגִּֽידוּ:"}, {"kind": "text", "text": "הֲדַר כְּבוֹד הוֹדֶֽךָ"}, {"kind": "text", "text": "וְדִבְרֵי נִפְלְ֒אֹתֶֽיךָ אָשִֽׂיחָה:"}, {"kind": "text", "text": "וֶעֱזוּז נוֹרְ֒אוֹתֶֽיךָ יֹאמֵֽרוּ"}, {"kind": "text", "text": "וּגְדֻלָּתְ֒ךָ אֲסַפְּ֒רֶֽנָּה:"}, {"kind": "text", "text": "זֵֽכֶר רַב־טוּבְ֒ךָ"}, {"kind": "text", "text": "יַבִּֽיעוּ"}, {"kind": "text", "text": "וְצִדְקָתְ֒ךָ יְרַנֵּֽנוּ:"}, {"kind": "text", "text": "חַנּוּן וְרַחוּם יְהֹוָה"}, {"kind": "text", "text": "אֶֽרֶךְ אַפַּֽיִם וּגְדָל־חָֽסֶד:"}, {"kind": "text", "text": "טוֹב־יְהֹוָה לַכֹּל"}, {"kind": "text", "text": "וְרַחֲמָיו עַל־כָּל־מַעֲשָׂיו:"}, {"kind": "text", "text": "יוֹדֽוּךָ יְהֹוָה כָּל־מַעֲשֶֽׂיךָ"}, {"kind": "text", "text": "וַחֲסִידֶֽיךָ יְבָרְ֒כֽוּכָה:"}, {"kind": "text", "text": "כְּבוֹד מַלְכוּתְ֒ךָ"}, {"kind": "text", "text": "יֹאמֵֽרוּ"}, {"kind": "text", "text": "וּגְבוּרָתְ֒ךָ יְדַבֵּֽרוּ:"}, {"kind": "text", "text": "לְהוֹדִֽיעַ לִבְנֵי הָאָדָם גְּבוּרֹתָיו"}, {"kind": "text", "text": "וּכְבוֹד הֲדַר מַלְכוּתוֹ:"}, {"kind": "text", "text": "מַלְכוּתְ֒ךָ מַלְכוּת כָּל־עֹלָמִים"}, {"kind": "text", "text": "וּמֶמְשַׁלְתְּ֒ךָ בְּכָל־דּוֹר וָדֹר:"}, {"kind": "text", "text": "סוֹמֵךְ יְהֹוָה לְכָל־הַנֹּפְ֒לִים"}, {"kind": "text", "text": "וְזוֹקֵף לְכָל־הַכְּ֒פוּפִים:"}, {"kind": "text", "text": "עֵינֵי־כֹל אֵלֶֽיךָ יְשַׂבֵּֽרוּ"}, {"kind": "text", "text": "וְאַתָּה נוֹתֵן־לָהֶם"}, {"kind": "text", "text": "אֶת־אָכְלָם בְּעִתּוֹ:"}, {"kind": "text", "text": "פּוֹתֵֽחַ אֶת־יָדֶֽךָ"}, {"kind": "text", "text": "וּמַשְׂבִּֽיעַ לְכָל־חַי רָצוֹן:"}, {"kind": "text", "text": "צַדִּיק יְהֹוָה בְּכָל־דְּרָכָיו"}, {"kind": "text", "text": "וְחָסִיד בְּכָל־מַעֲשָׂיו:"}, {"kind": "text", "text": "קָרוֹב יְהֹוָה לְכָל־קֹרְ֒אָיו"}, {"kind": "text", "text": "לְכֹל אֲשֶׁר יִקְרָאֻֽהוּ בֶאֱמֶת:"}, {"kind": "text", "text": "רְצוֹן־יְרֵאָיו יַעֲשֶׂה"}, {"kind": "text", "text": "וְאֶת־שַׁוְעָתָם יִשְׁמַע וְיוֹשִׁיעֵם:"}, {"kind": "text", "text": "שׁוֹמֵר יְהֹוָה אֶת־כָּל־אֹהֲבָיו"}, {"kind": "text", "text": "וְאֵת כָּל־הָרְ֒שָׁעִים יַשְׁמִיד:"}, {"kind": "text", "text": "❖תְּהִלַּת יְהֹוָה יְדַבֶּר פִּי"}, {"kind": "text", "text": "וִיבָרֵךְ כָּל־בָּשָׂר"}, {"kind": "text", "text": "שֵׁם קָדְשׁוֹ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "וַאֲנַֽחְנוּ נְבָרֵךְ יָהּ"}, {"kind": "text", "text": "מֵעַתָּה וְעַד־עוֹלָם"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ:"}, {"kind": "header", "text": "ובא לציון"}, {"kind": "text", "text": "וּבָא לְצִיּוֹן גּוֹאֵל"}, {"kind": "text", "text": "וּלְשָׁבֵי פֶֽשַׁע בְּיַעֲקֹב"}, {"kind": "text", "text": "נְאֻם יְהֹוָה:"}, {"kind": "text", "text": "וַאֲנִי זֹאת בְּרִיתִי אֹתָם"}, {"kind": "text", "text": "אָמַר יְהֹוָה"}, {"kind": "text", "text": "רוּחִי אֲשֶׁר עָלֶֽיךָ"}, {"kind": "text", "text": "וּדְבָרַי"}, {"kind": "text", "text": "אֲשֶׁר שַֽׂמְתִּי בְּפִֽיךָ"}, {"kind": "text", "text": "לֹא יָמֽוּשׁוּ מִפִּֽיךָ"}, {"kind": "text", "text": "וּמִפִּי זַרְעֲךָ"}, {"kind": "text", "text": "וּמִפִּי"}, {"kind": "text", "text": "זֶֽרַע זַרְעֲךָ"}, {"kind": "text", "text": "אָמַר יְהֹוָה"}, {"kind": "text", "text": "מֵעַתָּה וְעַד עוֹלָם:"}, {"kind": "text", "text": "וְאַתָּה קָדוֹשׁ"}, {"kind": "text", "text": "יוֹשֵׁב תְּהִלּוֹת יִשְׂרָאֵל:"}, {"kind": "text", "text": "וְקָרָא זֶה אֶל זֶה וְאָמַר"}, {"kind": "text", "text": "קָדוֹשׁ קָדוֹשׁ קָדוֹשׁ"}, {"kind": "text", "text": "יְהֹוָה צְבָאוֹת"}, {"kind": "text", "text": "מְלֹא כָל הָאָֽרֶץ כְּבוֹדוֹ:"}, {"kind": "text", "text": "וּמְקַבְּ֒לִין דֵּין מִן דֵּין"}, {"kind": "text", "text": "וְאָמְרִין"}, {"kind": "text", "text": "קַדִּישׁ בִּשְׁמֵי מְרוֹמָא עִלָּאָה"}, {"kind": "text", "text": "בֵּית שְׁכִינְתֵּהּ"}, {"kind": "text", "text": "קַדִּישׁ עַל אַרְעָא"}, {"kind": "text", "text": "עוֹבַד גְּבוּרְתֵּהּ"}, {"kind": "text", "text": "קַדִּישׁ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא"}, {"kind": "text", "text": "יְהֹוָה צְבָאוֹת."}, {"kind": "text", "text": "מַלְיָא כָל אַרְעָא"}, {"kind": "text", "text": "זִיו יְקָרֵהּ:"}, {"kind": "text", "text": "וַתִּשָּׂאֵֽנִי רֽוּחַ"}, {"kind": "text", "text": "וָאֶשְׁמַע אַחֲרַי"}, {"kind": "text", "text": "קוֹל רַֽעַשׁ גָּדוֹל"}, {"kind": "text", "text": "בָּרוּךְ כְּבוֹד יְהֹוָה"}, {"kind": "text", "text": "מִמְּ֒קוֹמוֹ:"}, {"kind": "text", "text": "וּנְטָלַתְנִי רוּחָא"}, {"kind": "text", "text": "וּשְׁמָעִית בַּתְרַי"}, {"kind": "text", "text": "קָל זִֽיעַ סַגִּיא"}, {"kind": "text", "text": "דִּמְשַׁבְּ֒חִין וְאָמְרִין"}, {"kind": "text", "text": "בְּרִיךְ יְקָרָא דַיהֹוָה"}, {"kind": "text", "text": "מֵאֲתַר"}, {"kind": "text", "text": "בֵּית שְׁכִינְתֵּהּ:"}, {"kind": "text", "text": "יְהֹוָה יִמְלֹךְ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "יְהֹוָה מַלְכוּתֵהּ קָאֵים"}, {"kind": "text", "text": "לְעָלַם וּלְעָלְמֵי עָלְמַיָּא:"}, {"kind": "text", "text": "יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵי אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל"}, {"kind": "text", "text": "אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "שָׁמְרָה זֹאת לְעֹלָם"}, {"kind": "text", "text": "לְיֵֽצֶר מַחְשְׁ֒בוֹת לְבַב עַמֶּֽךָ"}, {"kind": "text", "text": "וְהָכֵן לְבָבָם אֵלֶֽיךָ:"}, {"kind": "text", "text": "וְהוּא רַחוּם"}, {"kind": "text", "text": "יְכַפֵּר עָוֹן וְלֹא יַשְׁחִית"}, {"kind": "text", "text": "וְהִרְבָּה לְהָשִׁיב אַפּוֹ"}, {"kind": "text", "text": "וְלֹא יָעִיר כָּל חֲמָתוֹ:"}, {"kind": "text", "text": "כִּי אַתָּה אֲדֹנָי טוֹב וְסַלָּח"}, {"kind": "text", "text": "וְרַב חֶֽסֶד"}, {"kind": "text", "text": "לְכָל קֹרְ֒אֶֽיךָ:"}, {"kind": "text", "text": "צִדְקָתְ֒ךָ צֶֽדֶק לְעוֹלָם"}, {"kind": "text", "text": "וְתוֹרָתְ֒ךָ אֱמֶת:"}, {"kind": "text", "text": "תִּתֵּן אֱמֶת לְיַעֲקֹב"}, {"kind": "text", "text": "חֶֽסֶד לְאַבְרָהָם"}, {"kind": "text", "text": "אֲשֶׁר נִשְׁבַּֽעְתָּ לַאֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "מִֽימֵי קֶֽדֶם:"}, {"kind": "text", "text": "בָּרוּךְ אֲדֹנָי יוֹם יוֹם"}, {"kind": "text", "text": "יַעֲמָס לָֽנוּ"}, {"kind": "text", "text": "הָאֵל יְשׁוּעָתֵֽנוּ"}, {"kind": "text", "text": "סֶֽלָה:"}, {"kind": "text", "text": "יְהֹוָה צְבָאוֹת עִמָּֽנוּ"}, {"kind": "text", "text": "מִשְׂגָּב לָֽנוּ"}, {"kind": "text", "text": "אֱלֹהֵי יַעֲקֹב סֶֽלָה:"}, {"kind": "text", "text": "יְהֹוָה צְבָאוֹת"}, {"kind": "text", "text": "אַשְׁרֵי אָדָם בֹּטֵֽחַ בָּךְ:"}, {"kind": "text", "text": "יְהֹוָה הוֹשִֽׁיעָה"}, {"kind": "text", "text": "הַמֶּֽלֶךְ יַעֲנֵֽנוּ בְיוֹם קָרְאֵֽנוּ:"}, {"kind": "text", "text": "בָּרוּךְ הוּא אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "שֶׁבְּ֒רָאָֽנוּ לִכְבוֹדוֹ"}, {"kind": "text", "text": "וְהִבְדִּילָֽנוּ מִן הַתּוֹעִים"}, {"kind": "text", "text": "וְנָֽתַן לָֽנוּ תּוֹרַת אֱמֶת"}, {"kind": "text", "text": "וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵֽנוּ"}, {"kind": "text", "text": "הוּא יִפְתַּח לִבֵּֽנוּ בְּתוֹרָתוֹ"}, {"kind": "text", "text": "וְיָשֵׂם בְּלִבֵּֽנוּ אַהֲבָתוֹ וְיִרְאָתוֹ"}, {"kind": "text", "text": "וְלַעֲשׂוֹת רְצוֹנוֹ וּלְעָבְדוֹ"}, {"kind": "text", "text": "בְּלֵבָב שָׁלֵם"}, {"kind": "text", "text": "לְמַֽעַן לֹא נִיגַע לָרִיק"}, {"kind": "text", "text": "וְלֹא נֵלֵד לַבֶּהָלָה:"}, {"kind": "text", "text": "יְהִי רָצוֹן מִלְּפָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "שֶׁנִּשְׁמֹר חֻקֶּֽיךָ בָּעוֹלָם הַזֶּה"}, {"kind": "text", "text": "וְנִזְכֶּה וְנִחְיֶה וְנִרְאֶה"}, {"kind": "text", "text": "וְנִירַשׁ טוֹבָה וּבְרָכָה"}, {"kind": "text", "text": "לִשְׁנֵי יְמוֹת הַמָּשִֽׁיחַ"}, {"kind": "text", "text": "וּלְחַיֵּי הָעוֹלָם הַבָּא:"}, {"kind": "text", "text": "לְמַֽעַן יְזַמֶּרְךָ כָבוֹד"}, {"kind": "text", "text": "וְלֹא יִדֹּם"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהַי לְעוֹלָם אוֹדֶֽךָָ:"}, {"kind": "text", "text": "בָּרוּךְ הַגֶּֽבֶר אֲשֶׁר יִבְטַח בַּיהֹוָה"}, {"kind": "text", "text": "וְהָיָה יְהֹוָה מִבְטַחוֹ:"}, {"kind": "text", "text": "בִּטְחוּ בַיהֹוָה עֲדֵי עַד"}, {"kind": "text", "text": "כִּי בְּיָהּ"}, {"kind": "text", "text": "יְהֹוָה צוּר עוֹלָמִים:"}, {"kind": "text", "text": "וְיִבְטְ֒חוּ בְךָ יוֹדְ֒עֵי שְׁמֶֽךָ"}, {"kind": "text", "text": "כִּי לֹא עָזַֽבְתָּ"}, {"kind": "text", "text": "דֹרְ֒שֶֽׁיךָ יְהֹוָה:"}, {"kind": "text", "text": "❖יְהֹוָה חָפֵץ"}, {"kind": "text", "text": "לְמַֽעַן צִדְקוֹ"}, {"kind": "text", "text": "יַגְדִּיל תּוֹרָה וְיַאְדִּיר:"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְמָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְעוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְכוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְקָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ."}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְחַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל."}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְמַן קָרִיב"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְעָלְמֵי עָלְמַיָּא:"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקֻדְשָׁא. בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵֽלָּא (בעשי\"ת וּלְעֵֽלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְכָתָא וְשִׁירָתָא."}, {"kind": "text", "text": "תֻּשְׁבְּ֒חָתָא וְנֶחֱמָתָא."}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן:"}, {"kind": "header", "text": "קריאת התורה"}, {"kind": "text", "text": "וַאֲנִי"}, {"kind": "text", "text": "תְפִלָּתִי לְךָ יְהֹוָה"}, {"kind": "text", "text": "עֵת רָצוֹן"}, {"kind": "text", "text": "אֱלֹהִים בְּרָב חַסְדֶּֽךָ"}, {"kind": "text", "text": "עֲנֵֽנִי"}, {"kind": "text", "text": "בֶּאֱמֶת יִשְׁעֶֽךָ:"}, {"kind": "text", "text": "וַיְהִי בִּנְסֹֽעַ הָאָרֹן"}, {"kind": "text", "text": "וַיֹּֽאמֶר משֶׁה קוּמָה יְהֹוָה"}, {"kind": "text", "text": "וְיָפֻֽצוּ אֹיְ֒בֶֽיךָ"}, {"kind": "text", "text": "וְיָנֻֽסוּ מְשַׂנְאֶֽיךָ מִפָּנֶֽיךָ:"}, {"kind": "text", "text": "כִּי מִצִּיּוֹן תֵּצֵא תוֹרָה"}, {"kind": "text", "text": "וּדְבַר יְהֹוָה מִירוּשָׁלָֽםִ:"}, {"kind": "text", "text": "בָּרוּךְ שֶׁנָּתַן תּוֹרָה"}, {"kind": "text", "text": "לְעַמּוֹ יִשְׂרָאֵל בִּקְדֻשָּׁתוֹ:"}, {"kind": "header", "text": "בריך שמה"}, {"kind": "text", "text": "בְּרִיךְ שְׁמֵהּ"}, {"kind": "text", "text": "דְּמָרֵא עָלְמָא"}, {"kind": "text", "text": "בְּרִיךְ כִּתְרָךְ וְאַתְרָךְ."}, {"kind": "text", "text": "יְהֵא רְעוּתָךְ"}, {"kind": "text", "text": "עִם עַמָּךְ יִשְׂרָאֵל לְעָלָם."}, {"kind": "text", "text": "וּפֻרְקַן יְמִינָךְ"}, {"kind": "text", "text": "אַחֲזֵי לְעַמָּךְ בְּבֵית מַקְדְּ֒שָׁךְ"}, {"kind": "text", "text": "וּלְאַמְטוּיֵי לָנָא מִטּוּב נְהוֹרָךְ"}, {"kind": "text", "text": "וּלְקַבֵּל צְלוֹתָֽנָא בְּרַחֲמִין."}, {"kind": "text", "text": "יְהֵא רַעֲוָא קֳדָמָךְ"}, {"kind": "text", "text": "דְּתוֹרִיךְ לָן חַיִּין בְּטִיבוּתָא."}, {"kind": "text", "text": "וְלֶהֱוֵי אֲנָא פְקִידָא"}, {"kind": "text", "text": "בְּגוֹ צַדִּיקַיָּא."}, {"kind": "text", "text": "לְמִרְחַם עָלַי"}, {"kind": "text", "text": "וּלְמִנְטַר יָתִי וְיַת כָּל דִּי לִי"}, {"kind": "text", "text": "וְדִי לְעַמָּךְ יִשְׂרָאֵל."}, {"kind": "text", "text": "אַנְתְּ הוּא"}, {"kind": "text", "text": "זָן לְכֹלָּא וּמְפַרְנֵס לְכֹלָּא."}, {"kind": "text", "text": "אַנְתְּ הוּא שַׁלִּיט עַל כֹּלָּא."}, {"kind": "text", "text": "אַנְתְּ הוּא דְּשַׁלִּיט עַל מַלְכַיָּא"}, {"kind": "text", "text": "וּמַלְכוּתָא דִּילָךְ הִיא."}, {"kind": "text", "text": "אֲנָא עַבְדָּא"}, {"kind": "text", "text": "דְקֻדְשָׁא בְּרִיךְ הוּא"}, {"kind": "text", "text": "דְּסָגִֽידְנָא קַמֵּהּ"}, {"kind": "text", "text": "וּמִקַּמֵּהּ דִּיקַר אוֹרַיְתֵהּ"}, {"kind": "text", "text": "בְּכָל עִדָּן וְעִדָּן."}, {"kind": "text", "text": "לָא עַל אֱנָשׁ רָחִיצְנָא."}, {"kind": "text", "text": "וְלָא עַל בַּר אֱלָהִין סָמִיכְנָא."}, {"kind": "text", "text": "אֶלָּא בֶּאֱלָהָא דִשְׁמַיָּא."}, {"kind": "text", "text": "דְּהוּא אֱלָהָא קְשׁוֹט."}, {"kind": "text", "text": "וְאוֹרַיְתֵהּ קְשׁוֹט."}, {"kind": "text", "text": "וּנְבִיאוֹהִי קְשׁוֹט."}, {"kind": "text", "text": "וּמַסְגֵּא לְמֶעְבַּד"}, {"kind": "text", "text": "טַבְוָן וּקְשׁוֹט."}, {"kind": "text", "text": "בֵּהּ אֲנָא רָחִיץ"}, {"kind": "text", "text": "וְלִשְׁמֵהּ קַדִּישָׁא יַקִּירָא"}, {"kind": "text", "text": "אֲנָא אֵמַר תֻּשְׁבְּ֒חָן."}, {"kind": "text", "text": "יְהֵא רַעֲוָא קֳדָמָךְ"}, {"kind": "text", "text": "דְּתִפְתַּח לִבָּאִי בְּאוֹרַיְתָא."}, {"kind": "text", "text": "וְתַשְׁלִים מִשְׁאֲלִין דְּלִבָּאִי."}, {"kind": "text", "text": "וְלִבָּא דְכָל עַמָּךְ יִשְׂרָאֵל."}, {"kind": "text", "text": "לְטַב וּלְחַיִּין וְלִשְׁלָם:"}, {"kind": "text", "text": "❖גַּדְּ֒לוּ לַיהֹוָה אִתִּי"}, {"kind": "text", "text": "וּנְרוֹמְ֒מָה שְׁמוֹ יַחְדָּו:"}, {"kind": "text", "text": "לְךָ יְהֹוָה הַגְּ֒דֻלָּה וְהַגְּ֒בוּרָה"}, {"kind": "text", "text": "וְהַתִּפְאֶֽרֶת וְהַנֵּֽצַח וְהַהוֹד"}, {"kind": "text", "text": "כִּי כֹל בַּשָּׁמַֽיִם וּבָאָֽרֶץ"}, {"kind": "text", "text": "לְךָ יְהֹוָה הַמַּמְלָכָה"}, {"kind": "text", "text": "וְהַמִּתְנַשֵּׂא לְכֹל לְרֹאשׁ:"}, {"kind": "text", "text": "רוֹמְ֒מוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וְהִשְׁתַּחֲווּ לַהֲדֹם רַגְלָיו"}, {"kind": "text", "text": "קָדוֹשׁ הוּא:"}, {"kind": "text", "text": "רוֹמְ֒מוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וְהִשְׁתַּחֲווּ לְהַר קָדְשׁוֹ"}, {"kind": "text", "text": "כִּי קָדוֹשׁ יְהֹוָה אֱלֹהֵֽינוּ:"}, {"kind": "text", "text": "אָב הָרַחֲמִים הוּא יְרַחֵם"}, {"kind": "text", "text": "עַם עֲמוּסִים"}, {"kind": "text", "text": "וְיִזְכֹּר"}, {"kind": "text", "text": "בְּרִית אֵיתָנִים"}, {"kind": "text", "text": "וְיַצִּיל נַפְשׁוֹתֵֽינוּ"}, {"kind": "text", "text": "מִן הַשָּׁעוֹת הָרָעוֹת"}, {"kind": "text", "text": "וְיִגְעַר בְּיֵֽצֶר הָרָע"}, {"kind": "text", "text": "מִן הַנְּ֒שׂוּאִים"}, {"kind": "text", "text": "וְיָחוֹן אוֹתָֽנוּ"}, {"kind": "text", "text": "לִפְלֵטַת עוֹלָמִים"}, {"kind": "text", "text": "וִימַלֵּא מִשְׁאֲלוֹתֵֽינוּ"}, {"kind": "text", "text": "בְּמִדָּה טוֹבָה"}, {"kind": "text", "text": "יְשׁוּעָה וְרַחֲמִים:"}, {"kind": "text", "text": "וְתִגָּלֶה וְתֵרָאֶה מַלְכוּתוֹ"}, {"kind": "text", "text": "עָלֵֽינוּ בִּזְמַן קָרוֹב"}, {"kind": "text", "text": "וְיָחוֹן פְּלֵטָתֵֽנוּ"}, {"kind": "text", "text": "וּפְלֵטַת עַמּוֹ"}, {"kind": "text", "text": "בֵּית יִשְׂרָאֵל"}, {"kind": "text", "text": "לְחֵן וּלְחֶֽסֶד"}, {"kind": "text", "text": "וּלְרַחֲמִים וּלְרָצוֹן"}, {"kind": "text", "text": "וְנֹאמַר אָמֵן."}, {"kind": "text", "text": "הַכֹּל הָבוּ גֹֽדֶל לֵאלֹהֵֽינוּ"}, {"kind": "text", "text": "וּתְנוּ כָבוֹד לַתּוֹרָה."}, {"kind": "text", "text": "כֹּהֵן קְרָב."}, {"kind": "text", "text": "יַעֲמֹד (פב\"פ) הַכֹּהֵן."}, {"kind": "text", "text": "בָּרוּךְ שֶׁנָּתַן תּוֹרָה"}, {"kind": "text", "text": "לְעַמּוֹ יִשְׂרָאֵל בִּקְדֻשָּׁתוֹ:"}, {"kind": "text", "text": "וְאַתֶּם הַדְּ֒בֵקִים בַּיהֹוָה אֱלֹהֵיכֶם"}, {"kind": "text", "text": "חַיִּים כֻּלְּכֶם הַיּוֹם:"}, {"kind": "text", "text": "בָּרְ֒כוּ אֶת יְהֹוָה הַמְּ֒בֹרָךְ:"}, {"kind": "text", "text": "בָּרוּךְ יְהֹוָה הַמְּ֒בֹרָךְ"}, {"kind": "text", "text": "לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "אֲשֶׁר בָּֽחַר בָּֽנוּ מִכָּל הָעַמִּים"}, {"kind": "text", "text": "וְנָֽתַן לָֽנוּ אֶת תּוֹרָתוֹ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "נוֹתֵן הַתּוֹרָה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם"}, {"kind": "text", "text": "אֲשֶׁר נָֽתַן לָֽנוּ תּוֹרַת אֱמֶת"}, {"kind": "text", "text": "וְחַיֵּי עוֹלָם נָטַע בְּתוֹכֵֽנוּ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "נוֹתֵן הַתּוֹרָה:"}, {"kind": "text", "text": "וְזֹאת הַתּוֹרָה אֲשֶׁר שָׂם משֶׁה"}, {"kind": "text", "text": "לִפְנֵי בְּנֵי יִשְׂרָאֵל:"}, {"kind": "text", "text": "עֵץ חַיִּים הִיא"}, {"kind": "text", "text": "לַמַּחֲזִיקִים בָּהּ"}, {"kind": "text", "text": "וְתוֹמְ֒כֶֽיהָ מְאֻשָּׁר:"}, {"kind": "text", "text": "דְּרָכֶֽיהָ דַּרְכֵי נֹֽעַם"}, {"kind": "text", "text": "וְכָל נְתִיבוֹתֶֽיהָ שָׁלוֹם:"}, {"kind": "text", "text": "אֹֽרֶךְ יָמִים בִּימִינָהּ"}, {"kind": "text", "text": "בִּשְׂמֹאלָהּ עֽשֶׁר וְכָבוֹד:"}, {"kind": "text", "text": "יְהֹוָה חָפֵץ"}, {"kind": "text", "text": "לְמַֽעַן צִדְקוֹ"}, {"kind": "text", "text": "יַגְדִּיל תּוֹרָה וְיַאְדִּיר:"}, {"kind": "text", "text": "<b>תהלים קיא</b>"}, {"kind": "text", "text": "הַלְלוּיָהּ"}, {"kind": "text", "text": "אוֹדֶה יְהֹוָה בְּכָל־לֵבָב"}, {"kind": "text", "text": "בְּסוֹד יְשָׁרִים"}, {"kind": "text", "text": "וְעֵדָה:"}, {"kind": "text", "text": "גְּדֹלִים מַעֲשֵׂי יְהֹוָה"}, {"kind": "text", "text": "דְּרוּשִׁים לְכָל־חֶפְצֵיהֶם:"}, {"kind": "text", "text": "הוֹד־וְהָדָר פָּעֳלוֹ"}, {"kind": "text", "text": "וְצִדְקָתוֹ עֹמֶֽדֶת לָעַד:"}, {"kind": "text", "text": "זֵֽכֶר עָשָׂה לְנִפְלְאֹתָיו"}, {"kind": "text", "text": "חַנּוּן וְרַחוּם יְהֹוָה:"}, {"kind": "text", "text": "טֶֽרֶף נָתַן לִירֵאָיו"}, {"kind": "text", "text": "יִזְכֹּר לְעוֹלָם בְּרִיתוֹ:"}, {"kind": "text", "text": "כֹּֽחַ מַעֲשָׂיו"}, {"kind": "text", "text": "הִגִּיד לְעַמּוֹ"}, {"kind": "text", "text": "לָתֵת לָהֶם נַחֲלַת גּוֹיִם:"}, {"kind": "text", "text": "מַעֲשֵׂי יָדָיו אֱמֶת וּמִשְׁפָּט"}, {"kind": "text", "text": "נֶאֱמָנִים כָּל־פִּקּוּדָיו:"}, {"kind": "text", "text": "סְמוּכִים לָעַד לְעוֹלָם"}, {"kind": "text", "text": "עֲשׂוּיִם בֶּאֱמֶת וְיָשָׁר:"}, {"kind": "text", "text": "פְּדוּת שָׁלַח לְעַמּוֹ"}, {"kind": "text", "text": "צִוָּה־לְעוֹלָם בְּרִיתוֹ"}, {"kind": "text", "text": "קָדוֹשׁ וְנוֹרָא שְׁמוֹ:"}, {"kind": "text", "text": "רֵאשִׁית חָכְמָה"}, {"kind": "text", "text": "יִרְאַת יְהֹוָה"}, {"kind": "text", "text": "שֵֽׂכֶל טוֹב"}, {"kind": "text", "text": "לְכָל־עֹשֵׂיהֶם"}, {"kind": "text", "text": "תְּהִלָּתוֹ עֹמֶֽדֶת לָעַד:"}, {"kind": "text", "text": "<b>תהלים קיב</b>"}, {"kind": "text", "text": "הַלְלוּיָהּ"}, {"kind": "text", "text": "אַשְׁרֵי־אִישׁ יָרֵא אֶת־יְהֹוָה"}, {"kind": "text", "text": "בְּמִצְוֹתָיו חָפֵץ מְאֹד:"}, {"kind": "text", "text": "גִּבּוֹר בָּאָֽרֶץ יִהְיֶה זַרְעוֹ"}, {"kind": "text", "text": "דּוֹר יְשָׁרִים"}, {"kind": "text", "text": "יְבֹרָךְ:"}, {"kind": "text", "text": "הוֹן־וָעֽשֶׁר בְּבֵיתוֹ"}, {"kind": "text", "text": "וְצִדְקָתוֹ עֹמֶֽדֶת לָעַד:"}, {"kind": "text", "text": "זָרַח בַּחֽשֶׁךְ"}, {"kind": "text", "text": "אוֹר לַיְשָׁרִים"}, {"kind": "text", "text": "חַנּוּן"}, {"kind": "text", "text": "וְרַחוּם וְצַדִּיק:"}, {"kind": "text", "text": "טוֹב־אִישׁ חוֹנֵן וּמַלְוֶה"}, {"kind": "text", "text": "יְכַלְכֵּל דְּבָרָיו בְּמִשְׁפָּט:"}, {"kind": "text", "text": "כִּי־לְעוֹלָם לֹא־יִמּוֹט"}, {"kind": "text", "text": "לְזֵֽכֶר עוֹלָם"}, {"kind": "text", "text": "יִהְיֶה צַדִּיק:"}, {"kind": "text", "text": "מִשְּׁמוּעָה רָעָה לֹא יִירָא"}, {"kind": "text", "text": "נָכוֹן לִבּוֹ בָּטֻֽחַ בַּיהֹוָה:"}, {"kind": "text", "text": "סָמוּךְ לִבּוֹ לֹא יִירָא"}, {"kind": "text", "text": "עַד אֲשֶׁר־יִרְאֶה בְצָרָיו:"}, {"kind": "text", "text": "פִּזַּר נָתַן לָאֶבְיוֹנִים"}, {"kind": "text", "text": "צִדְקָתוֹ עֹמֶֽדֶת לָעַד"}, {"kind": "text", "text": "קַרְנוֹ תָּרוּם בְּכָבוֹד:"}, {"kind": "text", "text": "רָשָׁע יִרְאֶה וְכָעָס"}, {"kind": "text", "text": "שִׁנָּיו יַחֲרֹק וְנָמָס"}, {"kind": "text", "text": "תַּאֲוַת רְשָׁעִים תֹּאבֵד:"}, {"kind": "text", "text": "יְהַלְ֒לוּ אֶת־שֵׁם יְהֹוָה"}, {"kind": "text", "text": "כִּי־נִשְׂגָּב שְׁמוֹ לְבַדּוֹ:"}, {"kind": "text", "text": "הוֹדוֹ עַל־אֶֽרֶץ וְשָׁמָֽיִם:"}, {"kind": "text", "text": "וַיָּֽרֶם קֶֽרֶן לְעַמּוֹ"}, {"kind": "text", "text": "תְּהִלָּה לְכָל־חֲסִידָיו"}, {"kind": "text", "text": "לִבְנֵי יִשְׂרָאֵל"}, {"kind": "text", "text": "עַם קְרֹבוֹ"}, {"kind": "text", "text": "הַלְ֒לוּיָהּ:"}, {"kind": "text", "text": "לְדָוִד מִזְמוֹר"}, {"kind": "text", "text": "לַיהֹוָה הָאָֽרֶץ וּמְלוֹאָהּ"}, {"kind": "text", "text": "תֵּבֵל"}, {"kind": "text", "text": "וְיֽשְׁ֒בֵי בָהּ:"}, {"kind": "text", "text": "כִּי־הוּא עַל־יַמִּים יְסָדָהּ"}, {"kind": "text", "text": "וְעַל־נְהָרוֹת יְכוֹנְ֒נֶֽהָ:"}, {"kind": "text", "text": "מִי־יַעֲלֶה בְהַר־יְהֹוָה"}, {"kind": "text", "text": "וּמִי יָקוּם"}, {"kind": "text", "text": "בִּמְקוֹם קָדְשׁוֹ:"}, {"kind": "text", "text": "נְקִי כַפַּֽיִם וּבַר־לֵבָב"}, {"kind": "text", "text": "אֲשֶׁר לֹא־נָשָׂא לַשָּׁוְא נַפְשִׁי"}, {"kind": "text", "text": "וְלֹא נִשְׁבַּע לְמִרְמָה:"}, {"kind": "text", "text": "יִשָּׂא בְרָכָה מֵאֵת יְהֹוָה"}, {"kind": "text", "text": "וּצְדָקָה"}, {"kind": "text", "text": "מֵאֱלֹהֵי יִשְׁעוֹ:"}, {"kind": "text", "text": "זֶה דּוֹר דּוֹרְשָׁיו"}, {"kind": "text", "text": "מְבַקְשֵׁי פָנֶֽיךָ"}, {"kind": "text", "text": "יַעֲקֹב סֶֽלָה:"}, {"kind": "text", "text": "שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם"}, {"kind": "text", "text": "וְהִנָּשְׂ֒אוּ"}, {"kind": "text", "text": "פִּתְחֵי עוֹלָם"}, {"kind": "text", "text": "וְיָבוֹא מֶֽלֶךְ הַכָּבוֹד:"}, {"kind": "text", "text": "מִי זֶה מֶֽלֶךְ הַכָּבוֹד"}, {"kind": "text", "text": "יְהֹוָה עִזּוּז וְגִבּוֹר"}, {"kind": "text", "text": "יְהֹוָה גִּבּוֹר מִלְחָמָה:"}, {"kind": "text", "text": "שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם"}, {"kind": "text", "text": "וּשְׂאוּ פִּתְחֵי עוֹלָם"}, {"kind": "text", "text": "וְיָבוֹא מֶֽלֶךְ הַכָּבוֹד:"}, {"kind": "text", "text": "מִי הוּא זֶה מֶֽלֶךְ הַכָּבוֹד"}, {"kind": "text", "text": "יְהֹוָה צְבָאוֹת"}, {"kind": "text", "text": "הוּא מֶֽלֶךְ הַכָּבוֹד סֶֽלָה:"}, {"kind": "text", "text": "וּבְנֻחֹה יֹאמַר"}, {"kind": "text", "text": "שׁוּבָה יְהֹוָה"}, {"kind": "text", "text": "רִבְבוֹת אַלְפֵי יִשְׂרָאֵל:"}, {"kind": "text", "text": "קוּמָה יְהֹוָה לִמְנוּחָתֶֽךָ"}, {"kind": "text", "text": "אַתָּה וַאֲרוֹן עֻזֶּֽךָ:"}, {"kind": "text", "text": "כֹּהֲנֶֽיךָ"}, {"kind": "text", "text": "יִלְבְּ֒שׁוּ צֶֽדֶק"}, {"kind": "text", "text": "וַחֲסִידֶֽיךָ יְרַנֵּֽנוּ:"}, {"kind": "text", "text": "בַּעֲבוּר דָּוִד עַבְדֶּֽךָ"}, {"kind": "text", "text": "אַל תָּשֵׁב פְּנֵי מְשִׁיחֶֽךָ:"}, {"kind": "text", "text": "כִּי לֶֽקַח טוֹב נָתַֽתִּי לָכֶם"}, {"kind": "text", "text": "תּוֹרָתִי אַל תַּעֲזֹֽבוּ:"}, {"kind": "text", "text": "עֵץ חַיִּים הִיא לַמַּחֲזִיקִים בָּהּ"}, {"kind": "text", "text": "וְתוֹמְ֒כֶֽיהָ מְאֻשָּׁר:"}, {"kind": "text", "text": "דְּרָכֶֽיהָ דַּרְכֵי נֹֽעַם"}, {"kind": "text", "text": "וְכָל נְתִיבוֹתֶֽיהָ שָׁלוֹם:"}, {"kind": "text", "text": "❖הֲשִׁיבֵֽנוּ יְהֹוָה אֵלֶֽיךָ"}, {"kind": "text", "text": "וְנָשֽׁוּבָה"}, {"kind": "text", "text": "חַדֵּשׁ יָמֵֽינוּ כְּקֶֽדֶם:"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְמָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְעוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְכוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְקָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ."}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְחַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל."}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְמַן קָרִיב"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְעָלְמֵי עָלְמַיָּא:"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקֻדְשָׁא. בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵֽלָּא (בעשי\"ת וּלְעֵֽלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְכָתָא וְשִׁירָתָא."}, {"kind": "text", "text": "תֻּשְׁבְּ֒חָתָא וְנֶחֱמָתָא."}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן:"}, {"kind": "header", "text": "עמידה"}, {"kind": "text", "text": "כִּי שֵׁם יְהֹוָה אֶקְרָא"}, {"kind": "text", "text": "הָבוּ גֹֽדֶל לֵאלֹהֵֽינוּ:"}, {"kind": "text", "text": "אֲדֹנָי שְׂפָתַי תִּפְתָּח"}, {"kind": "text", "text": "וּפִי יַגִּיד תְּהִלָּתֶֽךָ:"}, {"kind": "text", "text": "<b>אבות</b>"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "אֱלֹהֵי אַבְרָהָם אֱלֹהֵי יִצְחָק"}, {"kind": "text", "text": "וֵאלֹהֵי יַעֲקֹב"}, {"kind": "text", "text": "הָאֵל"}, {"kind": "text", "text": "הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא"}, {"kind": "text", "text": "אֵל עֶלְיוֹן"}, {"kind": "text", "text": "גּוֹמֵל חֲסָדִים טוֹבִים"}, {"kind": "text", "text": "וְקוֹנֵה הַכֹּל"}, {"kind": "text", "text": "וְזוֹכֵר חַסְ֒דֵי אָבוֹת"}, {"kind": "text", "text": "וּמֵבִיא גוֹאֵל"}, {"kind": "text", "text": "לִבְ֒נֵי בְנֵיהֶם"}, {"kind": "text", "text": "לְמַֽעַן שְׁמוֹ בְּאַהֲבָה:"}, {"kind": "instruction", "text": "זָכְ֒רֵֽנוּ לְחַיִּים"}, {"kind": "instruction", "text": "מֶֽלֶךְ חָפֵץ בַּחַיִּים"}, {"kind": "instruction", "text": "וְכָתְ֒בֵֽנוּ בְּסֵֽפֶר הַחַיִּים"}, {"kind": "instruction", "text": "לְמַעַנְ֒ךָ אֱלֹהִים חַיִּים:"}, {"kind": "text", "text": "מֶֽלֶךְ עוֹזֵר וּמוֹשִֽׁיעַ וּמָגֵן:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "מָגֵן אַבְרָהָם:"}, {"kind": "text", "text": "<b>גבורות</b>"}, {"kind": "text", "text": "אַתָּה גִבּוֹר לְעוֹלָם אֲדֹנָי"}, {"kind": "text", "text": "מְחַיֶּה מֵתִים אַתָּה"}, {"kind": "text", "text": "רַב לְהוֹשִֽׁיעַ:"}, {"kind": "text", "text": "<b>מוֹרִיד הַטָּל</b>"}, {"kind": "text", "text": "<b>מַשִּׁיב הָרֽוּחַ</b>"}, {"kind": "text", "text": "<b>וּמוֹרִיד הַגֶּֽשֶׁם:</b>"}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶֽסֶד"}, {"kind": "text", "text": "מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים"}, {"kind": "text", "text": "סוֹמֵךְ נוֹפְ֒לִים"}, {"kind": "text", "text": "וְרוֹפֵא חוֹלִים"}, {"kind": "text", "text": "וּמַתִּיר אֲסוּרִים"}, {"kind": "text", "text": "וּמְ֒קַיֵּם אֱמוּנָתוֹ"}, {"kind": "text", "text": "לִישֵׁנֵי עָפָר,"}, {"kind": "text", "text": "מִי כָמֽוֹךָ בַּֽעַל גְּבוּרוֹת"}, {"kind": "text", "text": "וּמִי דּֽוֹמֶה לָּךְ"}, {"kind": "text", "text": "מֶֽלֶךְ מֵמִית וּמְ֒חַיֶּה"}, {"kind": "text", "text": "וּמַצְמִֽיחַ יְשׁוּעָה:"}, {"kind": "instruction", "text": "מִי כָמֽוֹךָ אָב הָרַחַמָן"}, {"kind": "instruction", "text": "זוֹכֵר יְצוּרָיו לְחַיִּים"}, {"kind": "instruction", "text": "בְּרַחֲמִים:"}, {"kind": "text", "text": "וְנֶאֱמָן אַתָּה"}, {"kind": "text", "text": "לְהַחֲיוֹת מֵתִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "מְחַיֵּה הַמֵּתִים:"}, {"kind": "text", "text": "<b>קדושה</b>"}, {"kind": "text", "text": "נַקְדִישָׁךְ וְנַעֲרִיצָךְ"}, {"kind": "text", "text": "כְּנֹֽעַם שִֽׂיחַ"}, {"kind": "text", "text": "סוֹד שַׂרְ֒פֵי קֽוֹדֶשׁ"}, {"kind": "text", "text": "הַמְּ֒שַׁלְּ֒שִׁים לְךָ קְדֻשָּׁה"}, {"kind": "text", "text": "כַּכָּתוּב עַל יַד נְבִיאֶֽךָ"}, {"kind": "text", "text": "וְקָרָא זֶה אֶל זֶה וְאָמַר:"}, {"kind": "text", "text": "<b>קָדוֹשׁ קָדוֹשׁ קָדוֹשׁ</b>"}, {"kind": "text", "text": "<b>יְהֹוָה צְבָאוֹת</b>"}, {"kind": "text", "text": "<b>מְלֹא כָל הָאָֽרֶץ כְּבוֹדוֹ:</b>"}, {"kind": "text", "text": "לְעֻמָּתָם מְשַׁבְּ֒חִים וְאוֹמְ֒רִים:"}, {"kind": "text", "text": "<b>בָּרוּךְ כְּבוֹד יְהֹוָה</b>"}, {"kind": "text", "text": "<b>מִמְּ֒קוֹמוֹ:</b>"}, {"kind": "text", "text": "וּבְ֒דִבְ֒רֵי קָדְשְׁ֒ךָ כָּתוּב לֵאמֹר:"}, {"kind": "text", "text": "<b>יִמְלֹךְ יְהֹוָה לְעוֹלָם</b>"}, {"kind": "text", "text": "<b>אֱלֹהַֽיִךְ צִיּוֹן לְדֹר וָדֹר:</b>"}, {"kind": "text", "text": "<b>הַלְ֒לוּיָהּ:</b>"}, {"kind": "text", "text": "<b>קדושת השם</b>"}, {"kind": "text", "text": "אַתָּה קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ"}, {"kind": "text", "text": "וּקְ֒דוֹשִׁים"}, {"kind": "text", "text": "בְּכָל יוֹם יְהַלְ֒לֽוּךָ סֶּֽלָה:"}, {"kind": "text", "text": "כִּי אֵל מֶֽלֶךְ"}, {"kind": "text", "text": "גָּדוֹל וְקָדוֹשׁ אָֽתָּה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הָאֵל הַקָּדוֹשׁ:"}, {"kind": "instruction", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "instruction", "text": "הַמֶּֽלֶךְ הַקָּדוֹשׁ:"}, {"kind": "text", "text": "אַתָּה אֶחָד וְשִׁמְךָ אֶחָד."}, {"kind": "text", "text": "וּמִי כְּעַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "גּוֹי אֶחָד בָּאָֽרֶץ."}, {"kind": "text", "text": "תִּפְאֶֽרֶת גְּדֻלָּה"}, {"kind": "text", "text": "וַעֲטֶֽרֶת יְשׁוּעָה."}, {"kind": "text", "text": "יוֹם מְנוּחָה וּקְדֻשָּׁה"}, {"kind": "text", "text": "לְעַמְּ֒ךָ נָתָֽתָּ."}, {"kind": "text", "text": "אַבְרָהָם יָגֵל. יִצְחָק יְרַנֵּן."}, {"kind": "text", "text": "יַעֲקֹב וּבָנָיו יָנֽוּחוּ בוֹ."}, {"kind": "text", "text": "מְנוּחַת אַהֲבָה וּנְדָבָה."}, {"kind": "text", "text": "מְנוּחַת אֱמֶת וֶאֱמוּנָה."}, {"kind": "text", "text": "מְנוּחַת שָׁלוֹם וְשַׁלְוָה"}, {"kind": "text", "text": "וְהַשְׁקֵט וָבֶֽטַח."}, {"kind": "text", "text": "מְנוּחָה שְׁלֵמָה"}, {"kind": "text", "text": "שֶׁאַתָּה רֽוֹצֶה בָהּ."}, {"kind": "text", "text": "יַכִּֽירוּ בָנֶֽיךָ וְיֵדְ֒עוּ"}, {"kind": "text", "text": "כִּי מֵאִתְּ֒ךָ הִיא מְנוּחָתָם."}, {"kind": "text", "text": "וְעַל מְנוּחָתָם"}, {"kind": "text", "text": "יַקְדִּֽישׁוּ אֶת שְׁמֶֽךָ:"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "רְצֵה בִמְנוּחָתֵֽנוּ."}, {"kind": "text", "text": "קַדְּ֒שֵֽׁנוּ בְּמִצְוֹתֶֽיךָ"}, {"kind": "text", "text": "וְתֵן חֶלְקֵֽנוּ בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "שַׂבְּ֒עֵֽנוּ מִטּוּבֶֽךָ."}, {"kind": "text", "text": "וְשַׂמַּח נַפְשֵֽׁנוּ בִּישׁוּעָתֶֽךָ."}, {"kind": "text", "text": "וְטַהֵר לִבֵּֽנוּ לְעָבְדְּ֒ךָ בֶּאֱמֶת."}, {"kind": "text", "text": "וְהַנְחִילֵֽנוּ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בְּאַהֲבָה וּבְרָצוֹן"}, {"kind": "text", "text": "שַׁבַּת קָדְשֶֽׁךָ."}, {"kind": "text", "text": "וְיָנֽוּחוּ בָם יִשְׂרָאֵל"}, {"kind": "text", "text": "מְקַדְּ֒שֵׁי שְׁמֶֽךָ."}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "מְקַדֵּשׁ הַשַּׁבָּת:"}, {"kind": "text", "text": "<b>עבודה</b>"}, {"kind": "text", "text": "רְצֵה יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בְּעַמְּ֒ךָ יִשְׂרָאֵל וּבִתְפִלָּתָם שְׁעֵה."}, {"kind": "text", "text": "וְהָשֵׁב אֶת הָעֲבוֹדָה"}, {"kind": "text", "text": "לִדְבִיר בֵּיתֶֽךָ"}, {"kind": "text", "text": "וְאִשֵּׁי יִשְׂרָאֵל."}, {"kind": "text", "text": "וּתְפִלָּתָם בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן"}, {"kind": "text", "text": "וּתְהִי לְרָצוֹן תָּמִיד"}, {"kind": "text", "text": "עֲבוֹדַת יִשְׂרָאֵל עַמֶּֽךָ:"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "יַעֲלֶה וְיָבֹא וְיַגִּֽיעַ"}, {"kind": "text", "text": "וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע"}, {"kind": "text", "text": "וְיִפָּקֵד וְיִזָּכֵר"}, {"kind": "text", "text": "זִכְרוֹנֵֽנוּ וּפִקְדוֹנֵֽנוּ"}, {"kind": "text", "text": "וְזִכְרוֹן אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "וְזִכְרוֹן מָשִֽׁיחַ"}, {"kind": "text", "text": "בֶּן דָּוִד עַבְדֶּֽךָ"}, {"kind": "text", "text": "וְזִכְרוֹן יְרוּשָׁלַֽםִ"}, {"kind": "text", "text": "עִיר קָדְשֶֽׁךָ"}, {"kind": "text", "text": "וְזִכְרוֹן כָּל עַמְּ֒ךָ"}, {"kind": "text", "text": "בֵּית יִשְׂרָאֵל לְפָנֶֽיךָ."}, {"kind": "text", "text": "לִפְלֵיטָה לְטוֹבָה"}, {"kind": "text", "text": "לְחֵן וּלְחֶֽסֶד וּלְרַחֲמִים"}, {"kind": "text", "text": "לְחַיִּים טוֹבִים וּלְשָׁלוֹם"}, {"kind": "text", "text": "בְּיוֹם"}, {"kind": "text", "text": "לר\"ח: רֹאשׁ הַחֹֽדֶשׁ הַזֶּה"}, {"kind": "text", "text": "לפסח: חַג הַמַּצּוֹת הַזֶּה"}, {"kind": "text", "text": "לסכות: חַג הַסֻּכּוֹת הַזֶּה"}, {"kind": "text", "text": "זָכְרֵֽנוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "בּוֹ לְטוֹבָה."}, {"kind": "text", "text": "וּפָקְדֵֽנוּ בוֹ לִבְרָכָה."}, {"kind": "text", "text": "וְהוֹשִׁיעֵֽנוּ בוֹ לְחַיִּים טוֹבִים."}, {"kind": "text", "text": "וּבִדְבַר יְשׁוּעָה"}, {"kind": "text", "text": "וְרַחֲמִים"}, {"kind": "text", "text": "חוּס וְחָנֵּֽנוּ."}, {"kind": "text", "text": "וְרַחֵם עָלֵֽינוּ וְהוֹשִׁיעֵֽנוּ."}, {"kind": "text", "text": "כִּי אֵלֶֽיךָ עֵינֵֽינוּ."}, {"kind": "text", "text": "כִּי אֵל"}, {"kind": "text", "text": "מֶֽלֶךְ חַנּוּן וְרַחוּם אָֽתָּה:"}, {"kind": "text", "text": "וְתֶחֱזֶֽינָה עֵינֵֽינוּ"}, {"kind": "text", "text": "בְּשׁוּבְ֒ךָ לְצִיּוֹן בְּרַחֲמִים."}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן:"}, {"kind": "text", "text": "<b>הודאה</b>"}, {"kind": "text", "text": "מוֹדִים אֲנַֽחְנוּ לָךְ"}, {"kind": "text", "text": "שָׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וֵאלֹהֵי אֲבוֹתֵֽינוּ לְעוֹלָם וָעֶד"}, {"kind": "text", "text": "צוּרֵֽנוּ צוּר חַיֵּֽינוּ"}, {"kind": "text", "text": "מָגֵן יִשְׁעֵֽנוּ"}, {"kind": "text", "text": "אַתָּה הוּא לְדוֹר וָדוֹר"}, {"kind": "text", "text": "נוֹדֶה לְּךָ"}, {"kind": "text", "text": "וּנְסַפֵּר תְּהִלָּתֶֽךָ"}, {"kind": "text", "text": "עַל חַיֵּֽינוּ"}, {"kind": "text", "text": "הַמְּ֒סוּרִים בְּיָדֶֽךָ"}, {"kind": "text", "text": "וְעַל נִשְׁמוֹתֵֽינוּ הַפְּ֒קוּדוֹת לָךְ"}, {"kind": "text", "text": "וְעַל נִסֶּֽיךָ שֶׁבְּ֒כָל יוֹם עִמָּֽנוּ"}, {"kind": "text", "text": "וְעַל נִפְלְ֒אוֹתֶֽיךָ וְטוֹבוֹתֶֽיךָ"}, {"kind": "text", "text": "שֶׁבְּ֒כָל עֵת."}, {"kind": "text", "text": "עֶֽרֶב וָבֹֽקֶר וְצָהֳרָֽיִם."}, {"kind": "text", "text": "הַטּוֹב"}, {"kind": "text", "text": "כִּי לֹא כָלוּ רַחֲמֶֽיךָ"}, {"kind": "text", "text": "וְהַמְ֒רַחֵם"}, {"kind": "text", "text": "כִּי לֹא תַֽמּוּ חֲסָדֶֽיךָ."}, {"kind": "text", "text": "מֵעוֹלָם קִוִּֽינוּ לָךְ:"}, {"kind": "text", "text": "מוֹדִים אֲנַֽחְנוּ לָךְ"}, {"kind": "text", "text": "שָׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "וֵאלֹהֵי אֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "אֱלֹהֵי כָל בָּשָׂר"}, {"kind": "text", "text": "יוֹצְ֒רֵֽנוּ יוֹצֵר בְּרֵאשִׁית"}, {"kind": "text", "text": "בְּרָכוֹת וְהוֹדָאוֹת"}, {"kind": "text", "text": "לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ"}, {"kind": "text", "text": "עַל שֶׁהֶחֱיִיתָֽנוּ וְקִיַּמְתָּֽנוּ"}, {"kind": "text", "text": "כֵּן תְּחַיֵּֽינוּ"}, {"kind": "text", "text": "וּתְקַיְּ֒מֵֽנוּ"}, {"kind": "text", "text": "וְתֶאֱסוֹף גָּלֻיּוֹתֵֽינוּ"}, {"kind": "text", "text": "לְחַצְרוֹת קָדְשֶֽׁךָ"}, {"kind": "text", "text": "לִשְׁמוֹר חֻקֶּֽיךָ"}, {"kind": "text", "text": "וְלַעֲשׂוֹת רְצוֹנֶֽךָ"}, {"kind": "text", "text": "וּלְעָבְדְּ֒ךָ בְּלֵבָב שָׁלֵם"}, {"kind": "text", "text": "עַל שֶׁאָֽנוּ מוֹדִים לָךְ."}, {"kind": "text", "text": "בָּרוּךְ אֵל"}, {"kind": "text", "text": "הַהוֹדָאוֹת:"}, {"kind": "text", "text": "וְעַל הַנִּסִּים"}, {"kind": "text", "text": "וְעַל הַפֻּרְקָן וְעַל הַגְּ֒בוּרוֹת"}, {"kind": "text", "text": "וְעַל הַתְּ֒שׁוּעוֹת וְעַל הַנִּפְלָאוֹת"}, {"kind": "text", "text": "וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת"}, {"kind": "text", "text": "שֶׁעָשִֽׂיתָ לַאֲבוֹתֵֽינוּ"}, {"kind": "text", "text": "בַּיָּמִים הָהֵם בִּזְּ֒מַן הַזֶּה:"}, {"kind": "text", "text": "בִּימֵי מַתִּתְיָֽהוּ"}, {"kind": "text", "text": "בֶּן יוֹחָנָן כֹּהֵן גָּדוֹל"}, {"kind": "text", "text": "חַשְׁמוֹנָאִי וּבָנָיו"}, {"kind": "text", "text": "כְּשֶׁעָמְ֒דָה מַלְ֒כוּת יָוָן הָרְ֒שָׁעָה"}, {"kind": "text", "text": "עַל עַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "לְהַשְׁכִּיחָם תּוֹרָתֶֽךָ"}, {"kind": "text", "text": "וּלְ֒הַעֲבִירָם"}, {"kind": "text", "text": "מֵחֻקֵּי רְצוֹנֶֽךָ,"}, {"kind": "text", "text": "וְאַתָּה בְּרַחֲמֶֽיךָ הָרַבִּים"}, {"kind": "text", "text": "עָמַֽדְתָּ לָהֶם בְּעֵת צָרָתָם"}, {"kind": "text", "text": "רַֽבְתָּ אֶת רִיבָם"}, {"kind": "text", "text": "דַּֽנְתָּ אֶת דִּינָם"}, {"kind": "text", "text": "נָקַֽמְתָּ אֶת נִקְ֒מָתָם"}, {"kind": "text", "text": "מָסַֽרְתָּ גִבּוֹרִים"}, {"kind": "text", "text": "בְּיַד חַלָּשִׁים"}, {"kind": "text", "text": "וְרַבִּים בְּיַד מְעַטִּים"}, {"kind": "text", "text": "וּטְ֒מֵאִים בְּיַד טְהוֹרִים"}, {"kind": "text", "text": "וּרְ֒שָׁעִים בְּיַד צַדִּיקִים"}, {"kind": "text", "text": "וְזֵדִים בְּיַד"}, {"kind": "text", "text": "עוֹסְ֒קֵי תוֹרָתֶֽךָ"}, {"kind": "text", "text": "וּלְ֒ךָ עָשִֽׂיתָ"}, {"kind": "text", "text": "שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶֽךָ"}, {"kind": "text", "text": "וּלְ֒עַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "עָשִֽׂיתָ תְּשׁוּעָה גְדוֹלָה"}, {"kind": "text", "text": "וּפֻרְקָן כְּהַיּוֹם הַזֶּה"}, {"kind": "text", "text": "וְאַחַר כַּךְ בָּֽאוּ בָנֶֽיךָ"}, {"kind": "text", "text": "לִדְ֒בִיר בֵּיתֶֽךָ"}, {"kind": "text", "text": "וּפִנּוּ אֶת הֵיכָלֶֽךָ"}, {"kind": "text", "text": "וְטִהֲרוּ אֶת מִקְדָּשֶֽׁךָ"}, {"kind": "text", "text": "וְהִדְלִֽיקוּ נֵרוֹת"}, {"kind": "text", "text": "בְּחַצְ֒רוֹת קָדְשֶֽׁךָ"}, {"kind": "text", "text": "וְקָבְ֒עוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵֽלּוּ"}, {"kind": "text", "text": "לְהוֹדוֹת וּלְ֒הַלֵּל לְשִׁמְ֒ךָ הַגָּדוֹל:"}, {"kind": "text", "text": "וְעַל כֻּלָּם"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִתְרוֹמַם וְיִתְנַשֵׂא"}, {"kind": "text", "text": "שִׁמְ֒ךָ מַלְכֵּֽנוּ"}, {"kind": "text", "text": "תָּמִיד"}, {"kind": "text", "text": "לְעוֹלָם וָעֶד:"}, {"kind": "instruction", "text": "וּכְתֹב לְחַיִּים טוֹבִים"}, {"kind": "instruction", "text": "כָּל בְּנֵי בְרִיתֶֽךָ:"}, {"kind": "text", "text": "וְכֹל הַחַיִּים יוֹדֽוּךָ סֶּֽלָה"}, {"kind": "text", "text": "וִיהַלְ֒לוּ וְיבָרְ֒כוּ"}, {"kind": "text", "text": "אֶת שִׁמְ֒ךָ הַגָּדוֹל בְּאֱמֶת לְעוֹלָם"}, {"kind": "text", "text": "כִּי טוֹב"}, {"kind": "text", "text": "הָאֵל יְשׁוּעָתֵֽנוּ"}, {"kind": "text", "text": "וְעֶזְרָתֵֽנוּ סֶֽלָה"}, {"kind": "text", "text": "הָאֵל הַטּוֹב:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַטּוֹב שִׁמְ֒ךָ"}, {"kind": "text", "text": "וּלְ֒ךָ נָאֶה לְהוֹדוֹת:"}, {"kind": "text", "text": "<b>שלום</b>"}, {"kind": "text", "text": "שִׂים שָׁלוֹם טוֹבָה וּבְ֒רָכָה"}, {"kind": "text", "text": "חַיִים חֵן וָחֶֽסֶד וְרַחֲמִים"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּֽךָ,"}, {"kind": "text", "text": "בָּרְ֒כֵֽנוּ אָבִֽינוּ כֻּלָּֽנוּ כְּאֶחָד"}, {"kind": "text", "text": "בְּאוֹר פָּנֶֽיךָ"}, {"kind": "text", "text": "כִּי בְאוֹר פָּנֶֽיךָ"}, {"kind": "text", "text": "נָתַֽתָּ לָּֽנוּ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "תּוֹרַת חַיִּים וְאַהֲבַת חֶֽסֶד"}, {"kind": "text", "text": "וּצְ֒דָקָה וּבְ֒רָכָה וְרַחֲמִים"}, {"kind": "text", "text": "וְחַיִּים וְשָׁלוֹם,"}, {"kind": "text", "text": "וְטוֹב יִהְיֶה בְּעֵינֶֽיךָ"}, {"kind": "text", "text": "לְבָרְ֒כֵֽנוּ"}, {"kind": "text", "text": "וּלְ֒בָרֵךְ אֶת כָּל עַמְּ֒ךָ יִשְׂרָאֵל"}, {"kind": "text", "text": "בְּכָל עֵת וּבְכָל שָׁעָה"}, {"kind": "text", "text": "בִּשְׁ֒לוֹמֶֽךָ"}, {"kind": "text", "text": "(בְּרוֹב עוֹז וְשָׁלוֹם)."}, {"kind": "instruction", "text": "בְּסֵֽפֶר חַיִּים בְּרָכָה וְשָׁלוֹם"}, {"kind": "instruction", "text": "וּפַרְנָסָה טוֹבָה"}, {"kind": "instruction", "text": "וּגְ֒זֵרוֹת טוֹבוֹת, יְשׁוּעוֹת וְנֶחָמוֹת,"}, {"kind": "instruction", "text": "נִזָּכֵר וְנִכָּתֵב"}, {"kind": "instruction", "text": "לְפָנֶֽיךָ"}, {"kind": "instruction", "text": "אֲנַֽחְנוּ וְכָל עַמְּ֒ךָ בֵּית יִשְׂרָאֵל"}, {"kind": "instruction", "text": "לְחַיִּים טוֹבִים וּלְ֒שָׁלוֹם:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה"}, {"kind": "text", "text": "הַמְּ֒בָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל"}, {"kind": "text", "text": "בַּשָּׁלוֹם:"}, {"kind": "text", "text": "יִהְיוּ לְרָצוֹן"}, {"kind": "text", "text": "אִמְ֒רֵי פִי"}, {"kind": "text", "text": "וְהֶגְיוֹן לִבִּי לְפָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה צוּרִי וְגוֹאֲלִי:"}, {"kind": "text", "text": "אֱלֹהַי נְצוֹר לְשׁוֹנִי מֵרָע"}, {"kind": "text", "text": "וּשְׂ֒פָתַי מִדַּבֵּר מִרְמָה"}, {"kind": "text", "text": "וְלִמְ֒קַלְ֒לַי"}, {"kind": "text", "text": "נַפְשִׁי תִדּוֹם"}, {"kind": "text", "text": "וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה"}, {"kind": "text", "text": "פְּתַח לִבִּי בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "וְאַחֲרֵי מִצְוֹתֶֽיךָ תִּרְדּוֹף נַפְשִׁי"}, {"kind": "text", "text": "וְכָל הַקָמִים וְהַחוֹשְׁ֒בִים עָלַי רָעָה"}, {"kind": "text", "text": "מְהֵרָה הָפֵר עֲצָתָם"}, {"kind": "text", "text": "וְקַלְקֵל מַחֲשַׁבְתָּם:"}, {"kind": "text", "text": "(יְהִי רָצוֹן מִלְ֒פָנֶיךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי"}, {"kind": "text", "text": "שֶׁלֹּא תַעֲלֶה קִנְאַת אָדָם עָלַי"}, {"kind": "text", "text": "וְלֹא קִנְאָתִי עַל אֲחֵרִים"}, {"kind": "text", "text": "וְשֶׁלֹּא אֶכְעֹס הַיּוֹם"}, {"kind": "text", "text": "וְשֶׁלֹּא אַכְעִיסֶֽךָ"}, {"kind": "text", "text": "וְתַצִּילֵנִי מִיֵּֽצֶר הָרָע"}, {"kind": "text", "text": "וְתֵן בְּלִבִּי הַכְנָעָה וַעֲנָוָה."}, {"kind": "text", "text": "מַלְכֵּֽנוּ וֵאלֹהֵֽינוּ"}, {"kind": "text", "text": "יַחֵד שִׁמְ֒ךָ בְּעוֹלָמֶֽךָ,"}, {"kind": "text", "text": "בְּנֵה עִירְ֒ךָ, יַסֵּד בֵּיתֶֽךָ,"}, {"kind": "text", "text": "וְשַׁכְלֵל הֵיכָלֶֽךָ."}, {"kind": "text", "text": "וְקַבֵּץ קִבּוּץ גָּלֻיּוֹת,"}, {"kind": "text", "text": "וּפְ֒דֵה צֹאנֶֽךָ וְשַׂמַּח עֲדָתֶֽךָ.)"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן שְׁמֶֽךָ,"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן יְמִינֶֽךָ,"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן תּוֹרָתֶֽךָ,"}, {"kind": "text", "text": "עֲשֵׂה לְמַֽעַן קְדֻשָּׁתֶֽךָ."}, {"kind": "text", "text": "לְמַֽעַן יֵחָלְ֒צוּן יְדִידֶֽיךָ"}, {"kind": "text", "text": "הוֹשִֽׁיעָה יְמִינְ֒ךָ וַעֲנֵֽנִי:"}, {"kind": "text", "text": "יִהְיוּ לְרָצוֹן"}, {"kind": "text", "text": "אִמְרֵי פִי"}, {"kind": "text", "text": "וְהֶגְיוֹן לִבִּי לְפָנֶֽיךָ"}, {"kind": "text", "text": "יְהֹוָה צוּרִי וְגוֹאֲלִי:"}, {"kind": "text", "text": "עֹשֶׂה (בעשי\"ת הַשָּׁלוֹם) שָׁלוֹם"}, {"kind": "text", "text": "בִּמְ֒רוֹמָיו"}, {"kind": "text", "text": "הוּא יַעֲשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "צִדְקָתְ֒ךָ"}, {"kind": "text", "text": "כְּהַֽרְרֵי־אֵל"}, {"kind": "text", "text": "מִשְׁפָּטֶֽיךָ תְּהוֹם רַבָּה."}, {"kind": "text", "text": "אָדָם וּבְהֵמָה תּוֹשִֽׁיעַ יְהֹוָה:"}, {"kind": "text", "text": "וְצִדְקָתְ֒ךָ אֱלֹהִים"}, {"kind": "text", "text": "עַד־מָרוֹם"}, {"kind": "text", "text": "אֲשֶׁר־עָשִֽׂיתָ גְדֹלוֹת."}, {"kind": "text", "text": "אֱלֹהִים מִי כָמֽוֹךָ:"}, {"kind": "text", "text": "צִדְקָתְ֒ךָ צֶֽדֶק לְעוֹלָם."}, {"kind": "text", "text": "וְתוֹרָתְ֒ךָ אֱמֶת:"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְמָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְעוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְכוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְקָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ."}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְחַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל."}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְמַן קָרִיב"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְעָלְמֵי עָלְמַיָּא:"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקֻדְשָׁא. בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵֽלָּא (בעשי\"ת וּלְעֵֽלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְכָתָא וְשִׁירָתָא."}, {"kind": "text", "text": "תֻּשְׁבְּ֒חָתָא וְנֶחֱמָתָא."}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "תִּתְקַבֵּל"}, {"kind": "text", "text": "צְלוֹתְ֒הוֹן וּבָעוּתְ֒הוֹן"}, {"kind": "text", "text": "דְּכָל בֵּית יִשְׂרָאֵל"}, {"kind": "text", "text": "קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא"}, {"kind": "text", "text": "וְחַיִּים טוֹבִים"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו"}, {"kind": "text", "text": "הוּא יַעֲשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "header", "text": "עלינו"}, {"kind": "text", "text": "עָלֵֽינוּ לְשַׁבֵּֽחַ"}, {"kind": "text", "text": "לַאֲדוֹן הַכֹּל"}, {"kind": "text", "text": "לָתֵת גְּדֻלָּה"}, {"kind": "text", "text": "לְיוֹצֵר בְּרֵאשִׁית"}, {"kind": "text", "text": "שֶׁלֹּא עָשָֽׂנוּ"}, {"kind": "text", "text": "כְּגוֹיֵי הָאֲרָצוֹת"}, {"kind": "text", "text": "וְלֹא שָׂמָֽנוּ"}, {"kind": "text", "text": "כְּמִשְׁפְּ֒חוֹת הָאֲדָמָה"}, {"kind": "text", "text": "שֶׁלֹּא שָׂם"}, {"kind": "text", "text": "חֶלְקֵֽנוּ כָּהֶם"}, {"kind": "text", "text": "וְגוֹרָלֵֽנוּ כְּכָל הֲמוֹנָם:"}, {"kind": "text", "text": "שֶׁהֵם מִשְׁתַּחֲוִים"}, {"kind": "text", "text": "לַהֶֽבֶל וָרִיק"}, {"kind": "text", "text": "וּמִתְפַּלְּ֒לִים אֶל אֵל לֹא יוֹשִֽׁיעַ."}, {"kind": "text", "text": "וַאֲנַֽחְנוּ כּוֹרְ֒עִים וּמִשְׁתַּחֲוִים"}, {"kind": "text", "text": "וּמוֹדִים"}, {"kind": "text", "text": "לִפְנֵי מֶֽלֶךְ מַלְכֵי הַמְּ֒לָכִים"}, {"kind": "text", "text": "הַקָּדוֹשׁ בָּרוּךְ הוּא."}, {"kind": "text", "text": "שֶׁהוּא נוֹטֶה שָׁמַֽיִם"}, {"kind": "text", "text": "וְיוֹסֵד אָֽרֶץ."}, {"kind": "text", "text": "וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַֽיִם מִמַּֽעַל."}, {"kind": "text", "text": "וּשְׁכִינַת עֻזּוֹ"}, {"kind": "text", "text": "בְּגָבְהֵי מְרוֹמִים."}, {"kind": "text", "text": "הוּא אֱלֹהֵֽינוּ אֵין עוֹד."}, {"kind": "text", "text": "אֱמֶת מַלְכֵּֽנוּ"}, {"kind": "text", "text": "אֶֽפֶס זוּלָתוֹ"}, {"kind": "text", "text": "כַּכָּתוּב בְּתוֹרָתוֹ"}, {"kind": "text", "text": "וְיָדַעְתָּ הַיּוֹם"}, {"kind": "text", "text": "וַהֲשֵׁבֹתָ אֶל לְבָבֶֽךָ"}, {"kind": "text", "text": "כִּי יְהֹוָה הוּא הָאֱלֹהִים"}, {"kind": "text", "text": "בַּשָּׁמַֽיִם מִמַּֽעַל"}, {"kind": "text", "text": "וְעַל הָאָֽרֶץ מִתָּֽחַת"}, {"kind": "text", "text": "אֵין עוֹד:"}, {"kind": "text", "text": "עַל כֵּן נְקַוֶּה לְךָ"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "לִרְאוֹת מְהֵרָה בְּתִפְאֶֽרֶת עֻזֶּֽךָ"}, {"kind": "text", "text": "לְהַעֲבִיר גִּלּוּלִים מִן הָאָֽרֶץ"}, {"kind": "text", "text": "וְהָאֱלִילִים"}, {"kind": "text", "text": "כָּרוֹת יִכָּרֵתוּן"}, {"kind": "text", "text": "לְתַקֵּן עוֹלָם"}, {"kind": "text", "text": "בְּמַלְכוּת שַׁדַּי"}, {"kind": "text", "text": "וְכָל בְּנֵי בָשָׂר יִקְרְ֒אוּ בִשְׁמֶֽךָ."}, {"kind": "text", "text": "לְהַפְנוֹת אֵלֶֽיךָ"}, {"kind": "text", "text": "כָּל רִשְׁעֵי אָֽרֶץ."}, {"kind": "text", "text": "יַכִּֽירוּ וְיֵדְ֒עוּ"}, {"kind": "text", "text": "כָּל יוֹשְׁ֒בֵי תֵבֵל"}, {"kind": "text", "text": "כִּי לְךָ תִכְרַע כָּל בֶּֽרֶךְ"}, {"kind": "text", "text": "תִּשָּׁבַע כָּל לָשׁוֹן:"}, {"kind": "text", "text": "לְפָנֶֽיךָ יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "יִכְרְ֒עוּ וְיִפֹּֽלוּ."}, {"kind": "text", "text": "וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּֽנוּ."}, {"kind": "text", "text": "וִיקַבְּ֒לוּ כֻלָּם"}, {"kind": "text", "text": "אֶת עֹל מַלְכוּתֶֽךָ."}, {"kind": "text", "text": "וְתִמְלֹךְ עֲלֵיהֶם מְהֵרָה"}, {"kind": "text", "text": "לְעוֹלָם וָעֶד."}, {"kind": "text", "text": "כִּי הַמַּלְכוּת שֶׁלְּ֒ךָ הִיא"}, {"kind": "text", "text": "וּלְעֽוֹלְ֒מֵי עַד תִּמְלוֹךְ בְּכָבוֹד."}, {"kind": "text", "text": "כַּכָּתוּב בְּתוֹרָתֶֽךָ"}, {"kind": "text", "text": "יְהֹוָה יִמְלֹךְ לְעֹלָם וָעֶד:"}, {"kind": "text", "text": "❖וְנֶאֱמַר"}, {"kind": "text", "text": "וְהָיָה יְהֹוָה לְמֶֽלֶךְ"}, {"kind": "text", "text": "עַל כָּל הָאָֽרֶץ"}, {"kind": "text", "text": "בַּיּוֹם הַהוּא יִהְיֶה יְהֹוָה אֶחָד"}, {"kind": "text", "text": "וּשְׁמוֹ אֶחָד:"}, {"kind": "text", "text": "אַל תִּירָא מִפַּֽחַד פִּתְאֹם"}, {"kind": "text", "text": "וּמִשֹּׁאַת רְשָׁעִים"}, {"kind": "text", "text": "כִּי תָבֹא:"}, {"kind": "text", "text": "עֻֽצוּ עֵצָה וְתֻפָר"}, {"kind": "text", "text": "דַּבְּ֒רוּ דָבָר וְלֹא יָקוּם"}, {"kind": "text", "text": "כִּי עִמָּֽנוּ אֵל:"}, {"kind": "text", "text": "וְעַד זִקְנָה אֲנִי הוּא"}, {"kind": "text", "text": "וְעַד שֵׂיבָה אֲנִי אֶסְבֹּל:"}, {"kind": "text", "text": "אֲנִי עָשִֽׂיתִי וַאֲנִי אֶשָּׂא"}, {"kind": "text", "text": "וַאֲנִי אֶסְבֹּל וַאֲמַלֵּט:"}, {"kind": "header", "text": "קדיש יתום"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא"}, {"kind": "text", "text": "בְּעָלְמָא דִּי בְרָא"}, {"kind": "text", "text": "כִרְעוּתֵהּ"}, {"kind": "text", "text": "וְיַמְלִיךְ מַלְכוּתֵהּ"}, {"kind": "text", "text": "וְיַצְמַח פּוּרְ֒קָנֵהּ"}, {"kind": "text", "text": "וִיקָרֵב (קֵץ) מְשִׁיחֵהּ."}, {"kind": "text", "text": "בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן"}, {"kind": "text", "text": "וּבְחַיֵּי"}, {"kind": "text", "text": "דְכָל בֵּית יִשְׂרָאֵל."}, {"kind": "text", "text": "בַּעֲגָלָא וּבִזְמַן קָרִיב."}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ"}, {"kind": "text", "text": "לְעָלַם וּלְעָלְמֵי עָלְמַיָּא:"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח"}, {"kind": "text", "text": "וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא"}, {"kind": "text", "text": "וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל"}, {"kind": "text", "text": "שְׁמֵהּ דְקֻדְשָׁא. בְּרִיךְ הוּא"}, {"kind": "text", "text": "לְעֵלָּא (בעשי\"ת וּלְעֵלָּא מִכָּל)"}, {"kind": "text", "text": "מִן כָּל בִּרְכָתָא וְשִׁירָתָא."}, {"kind": "text", "text": "תֻּשְׁבְּחָתָא וְנֶחֱמָתָא."}, {"kind": "text", "text": "דַּאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא"}, {"kind": "text", "text": "וְחַיִּים טוֹבִים"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל."}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו"}, {"kind": "text", "text": "הוּא יַעֲשֶׂה שָׁלוֹם"}, {"kind": "text", "text": "עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל"}, {"kind": "text", "text": "וְאִמְרוּ אָמֵן:"}, {"kind": "header", "text": "מזמורים לשבתות החורף"}, {"kind": "text", "text": "<b>תהלים קד</b>"}, {"kind": "text", "text": "בָּרְכִי נַפְשִׁי אֶת־יְהֹוָה"}, {"kind": "text", "text": "יְהֹוָה אֱלֹהַי גָּדַֽלְתָּ מְּאֹד"}, {"kind": "text", "text": "הוֹד וְהָדָר לָבָֽשְׁתָּ:"}, {"kind": "text", "text": "עֹֽטֶה־אוֹר כַּשַּׂלְמָה"}, {"kind": "text", "text": "נוֹטֶה שָׁמַֽיִם כַּיְרִיעָה:"}, {"kind": "text", "text": "הַמְקָרֶה בַמַּֽיִם"}, {"kind": "text", "text": "עֲלִיּוֹתָיו"}, {"kind": "text", "text": "הַשָּׂם־עָבִים רְכוּבוֹ"}, {"kind": "text", "text": "הַמְהַלֵּךְ עַל־כַּנְפֵי־רֽוּחַ:"}, {"kind": "text", "text": "עֹשֶׂה מַלְאָכָיו רוּחוֹת"}, {"kind": "text", "text": "מְשָׁרְתָיו אֵשׁ לֹהֵט:"}, {"kind": "text", "text": "יָֽסַד־אֶֽרֶץ"}, {"kind": "text", "text": "עַל־מְכוֹנֶֽיהָ"}, {"kind": "text", "text": "בַּל־תִּמּוֹט עוֹלָם וָעֶד:"}, {"kind": "text", "text": "תְּהוֹם"}, {"kind": "text", "text": "כַּלְּבוּשׁ כִּסִּיתוֹ"}, {"kind": "text", "text": "עַל־הָרִים יַֽעַמְדוּ מָֽיִם:"}, {"kind": "text", "text": "מִן־גַּעֲרָתְךָ יְנוּסוּן"}, {"kind": "text", "text": "מִן־קוֹל רַעַמְךָ"}, {"kind": "text", "text": "יֵחָפֵזוּן:"}, {"kind": "text", "text": "יַעֲלוּ הָרִים יֵרְדוּ בְקָעוֹת"}, {"kind": "text", "text": "אֶל־מְקוֹם זֶה יָסַֽדְתָּ לָהֶם:"}, {"kind": "text", "text": "גְּבוּל־שַֽׂמְתָּ"}, {"kind": "text", "text": "בַּל־יַעֲבֹרוּן"}, {"kind": "text", "text": "בַּל־יְשֻׁבוּן לְכַסּוֹת הָאָֽרֶץ:"}, {"kind": "text", "text": "הַמְשַׁלֵּֽחַ מַעְיָנִים בַּנְּחָלִים"}, {"kind": "text", "text": "בֵּין הָרִים יְהַלֵּכוּן:"}, {"kind": "text", "text": "יַשְׁקוּ כָּל־חַיְתוֹ שָׂדָי"}, {"kind": "text", "text": "יִשְׁבְּרוּ פְרָאִים צְמָאָם:"}, {"kind": "text", "text": "עֲלֵיהֶם עוֹף־הַשָּׁמַֽיִם יִשְׁכּוֹן"}, {"kind": "text", "text": "מִבֵּין עֳפָאיִם יִתְּנוּ־קוֹל:"}, {"kind": "text", "text": "מַשְׁקֶה הָרִים"}, {"kind": "text", "text": "מֵעֲלִיּוֹתָיו"}, {"kind": "text", "text": "מִפְּרִי מַעֲשֶֽׂיךָ"}, {"kind": "text", "text": "תִּשְׂבַּע הָאָֽרֶץ:"}, {"kind": "text", "text": "מַצְמִֽיחַ חָצִיר לַבְּהֵמָה"}, {"kind": "text", "text": "וְעֵֽשֶׂב לַעֲבֹדַת הָאָדָם"}, {"kind": "text", "text": "לְהֽוֹצִיא לֶֽחֶם מִן־הָאָֽרֶץ:"}, {"kind": "text", "text": "וְיַֽיִן יְשַׂמַּח לְבַב־אֱנוֹשׁ"}, {"kind": "text", "text": "לְהַצְהִיל פָּנִים מִשָּֽׁמֶן"}, {"kind": "text", "text": "וְלֶֽחֶם לְבַב־אֱנוֹשׁ יִסְעָד:"}, {"kind": "text", "text": "יִשְׂבְּעוּ עֲצֵי יְהֹוָה"}, {"kind": "text", "text": "אַרְזֵי לְבָנוֹן אֲשֶׁר נָטָע:"}, {"kind": "text", "text": "אֲשֶׁר־שָׁם צִפֳּרִים יְקַנֵּֽנוּ"}, {"kind": "text", "text": "חֲסִידָה בְּרוֹשִׁים בֵּיתָהּ:"}, {"kind": "text", "text": "הָרִים הַגְּבֹהִים לַיְּעֵלִים"}, {"kind": "text", "text": "סְלָעִים מַחְסֶה לַשְׁפַנִּים:"}, {"kind": "text", "text": "עָשָׂה יָרֵֽחַ לְמוֹעֲדִים"}, {"kind": "text", "text": "שֶֽׁמֶשׁ יָדַע מְבוֹאוֹ:"}, {"kind": "text", "text": "תָּֽשֶׁת־חֽשֶׁךְ וִיהִי לָֽיְלָה"}, {"kind": "text", "text": "בּוֹ־תִרְמֹשׂ"}, {"kind": "text", "text": "כָּל־חַיְתוֹ־יָֽעַר:"}, {"kind": "text", "text": "הַכְּפִירִים שֹׁאֲגִים לַטָּֽרֶף"}, {"kind": "text", "text": "וּלְבַקֵּשׁ מֵאֵל אָכְלָם:"}, {"kind": "text", "text": "תִּזְרַח הַשֶּֽׁמֶשׁ יֵאָסֵפוּן"}, {"kind": "text", "text": "וְאֶל־מְעוֹנֹתָם יִרְבָּצוּן:"}, {"kind": "text", "text": "יֵצֵא אָדָם לְפָעֳלוֹ"}, {"kind": "text", "text": "וְלַעֲבֹדָתוֹ עֲדֵי־עָֽרֶב:"}, {"kind": "text", "text": "מָה־רַבּוּ מַעֲשֶֽׂיךָ יְהֹוָה"}, {"kind": "text", "text": "כֻּלָּם בְּחָכְמָה עָשִֽׂיתָ"}, {"kind": "text", "text": "מָלְאָה הָאָֽרֶץ קִנְיָנֶֽךָ:"}, {"kind": "text", "text": "זֶה הַיָּם גָּדוֹל וּרְחַב יָדָֽיִם"}, {"kind": "text", "text": "שָׁם־רֶֽמֶשׂ וְאֵין מִסְפָּר"}, {"kind": "text", "text": "חַיּוֹת קְטַנּוֹת עִם־גְּדֹלוֹת:"}, {"kind": "text", "text": "שָׁם אֳנִיּוֹת יְהַלֵּכוּן"}, {"kind": "text", "text": "לִוְיָתָן זֶה־"}, {"kind": "text", "text": "יָצַֽרְתָּ לְשַֽׂחֶק־בּוֹ:"}, {"kind": "text", "text": "כֻּלָּם אֵלֶֽיךָ יְשַׂבֵּרוּן"}, {"kind": "text", "text": "לָתֵת אָכְלָם בְּעִתּוֹ:"}, {"kind": "text", "text": "תִּתֵּן לָהֶם"}, {"kind": "text", "text": "יִלְקֹטוּן"}, {"kind": "text", "text": "תִּפְתַּח יָדְךָ"}, {"kind": "text", "text": "יִשְׂבְּעוּן טוֹב:"}, {"kind": "text", "text": "תַּסְתִּיר פָּנֶֽיךָ"}, {"kind": "text", "text": "יִבָּהֵלוּן"}, {"kind": "text", "text": "תֹּסֵף רוּחָם יִגְוָעוּן"}, {"kind": "text", "text": "וְאֶל־עֲפָרָם יְשׁוּבוּן:"}, {"kind": "text", "text": "תְּשַׁלַּח רוּחֲךָ"}, {"kind": "text", "text": "יִבָּרֵאוּן"}, {"kind": "text", "text": "וּתְחַדֵּשׁ פְּנֵי אֲדָמָה:"}, {"kind": "text", "text": "יְהִי כְבוֹד יְהֹוָה לְעוֹלָם"}, {"kind": "text", "text": "יִשְׂמַח יְהֹוָה בְּמַעֲשָׂיו:"}, {"kind": "text", "text": "הַמַּבִּיט לָאָֽרֶץ"}, {"kind": "text", "text": "וַתִּרְעָד"}, {"kind": "text", "text": "יִגַּע בֶּהָרִים"}, {"kind": "text", "text": "וְיֶעֱשָֽׁנוּ:"}, {"kind": "text", "text": "אָשִֽׁירָה לַיהֹוָה בְּחַיָּי"}, {"kind": "text", "text": "אֲזַמְּרָה לֵאלֹהַי"}, {"kind": "text", "text": "בְּעוֹדִי:"}, {"kind": "text", "text": "יֶעֱרַב עָלָיו שִׂיחִי"}, {"kind": "text", "text": "אָנֹכִי אֶשְׂמַח בַּיהֹוָה:"}, {"kind": "text", "text": "יִתַּֽמּוּ חַטָּאִים מִן־הָאָֽרֶץ"}, {"kind": "text", "text": "וּרְשָׁעִים עוֹד אֵינָם"}, {"kind": "text", "text": "בָּרְכִי נַפְשִׁי אֶת־יְהֹוָה"}, {"kind": "text", "text": "הַלְלוּיָהּ:"}, {"kind": "text", "text": "<b>תהלים קכ</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת"}, {"kind": "text", "text": "אֶל־יְהֹוָה בַּצָּרָֽתָה לִּי קָרָֽאתִי"}, {"kind": "text", "text": "וַיַּעֲנֵֽנִי:"}, {"kind": "text", "text": "יְהֹוָה"}, {"kind": "text", "text": "הַצִּֽילָה נַפְשִׁי מִשְּׂפַת־שֶֽׁקֶר"}, {"kind": "text", "text": "מִלָּשׁוֹן רְמִיָּה:"}, {"kind": "text", "text": "מַה־יִּתֵּן לְךָ"}, {"kind": "text", "text": "וּמַה־יֹּסִיף לָךְ"}, {"kind": "text", "text": "לָשׁוֹן רְמִיָּה:"}, {"kind": "text", "text": "חִצֵּי גִבּוֹר שְׁנוּנִים"}, {"kind": "text", "text": "עִם גַּחֲלֵי רְתָמִים:"}, {"kind": "text", "text": "אֽוֹיָה־לִּי כִּי־גַֽרְתִּי מֶֽשֶׁךְ"}, {"kind": "text", "text": "שָׁכַֽנְתִּי עִם־אָהֳלֵי קֵדָר:"}, {"kind": "text", "text": "רַבַּת שָֽׁכְנָה־לָּהּ נַפְשִׁי"}, {"kind": "text", "text": "עִם שׂוֹנֵא שָׁלוֹם:"}, {"kind": "text", "text": "אֲנִי־שָׁלוֹם"}, {"kind": "text", "text": "וְכִי אֲדַבֵּר"}, {"kind": "text", "text": "הֵֽמָּה לַמִּלְחָמָה:"}, {"kind": "text", "text": "<b>תהלים קכא</b>"}, {"kind": "text", "text": "שִׁיר לַמַּעֲלוֹת"}, {"kind": "text", "text": "אֶשָּׂא עֵינַי אֶל־הֶהָרִים"}, {"kind": "text", "text": "מֵאַֽיִן יָבֹא עֶזְרִי:"}, {"kind": "text", "text": "עֶזְרִי מֵעִם יְהֹוָה"}, {"kind": "text", "text": "עֹשֵׂה שָׁמַֽיִם וָאָֽרֶץ:"}, {"kind": "text", "text": "אַל־יִתֵּן לַמּוֹט רַגְלֶֽךָ"}, {"kind": "text", "text": "אַל־יָנוּם שֹׁמְרֶֽךָ:"}, {"kind": "text", "text": "הִנֵּה לֹא־יָנוּם"}, {"kind": "text", "text": "וְלֹא יִישָׁן שׁוֹמֵר יִשְׂרָאֵל:"}, {"kind": "text", "text": "יְהֹוָה שֹׁמְרֶֽךָ"}, {"kind": "text", "text": "יְהֹוָה צִלְּךָ עַל־יַד יְמִינֶֽךָ:"}, {"kind": "text", "text": "יוֹמָם הַשֶּֽׁמֶשׁ לֹא־יַכֶּֽכָּה"}, {"kind": "text", "text": "וְיָרֵֽחַ בַּלָּֽיְלָה:"}, {"kind": "text", "text": "יְהֹוָה יִשְׁמָרְךָ מִכָּל־רָע"}, {"kind": "text", "text": "יִשְׁמֹר אֶת־נַפְשֶֽׁךָ:"}, {"kind": "text", "text": "יְהֹוָה יִשְׁמָר־צֵאתְךָ וּבוֹאֶֽךָ"}, {"kind": "text", "text": "מֵעַתָּה וְעַד־עוֹלָם:"}, {"kind": "text", "text": "<b>תהלים קכב</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת לְדָוִד"}, {"kind": "text", "text": "שָׂמַֽחְתִּי בְּאֹמְרִים לִי"}, {"kind": "text", "text": "בֵּית יְהֹוָה נֵלֵךְ:"}, {"kind": "text", "text": "עֹמְדוֹת הָיוּ רַגְלֵֽינוּ"}, {"kind": "text", "text": "בִּשְׁעָרַֽיִךְ יְרוּשָׁלָֽםִ:"}, {"kind": "text", "text": "יְרוּשָׁלַֽםִ הַבְּנוּיָה"}, {"kind": "text", "text": "כְּעִיר שֶׁחֻבְּרָה־לָּהּ יַחְדָּו:"}, {"kind": "text", "text": "שֶׁשָּׁם עָלוּ שְׁבָטִים"}, {"kind": "text", "text": "שִׁבְטֵי־יָהּ"}, {"kind": "text", "text": "עֵדוּת לְיִשְׂרָאֵל"}, {"kind": "text", "text": "לְהֹדוֹת לְשֵׁם יְהֹוָה:"}, {"kind": "text", "text": "כִּי שָֽׁמָּה"}, {"kind": "text", "text": "יָשְׁבוּ כִסְאוֹת לְמִשְׁפָּט"}, {"kind": "text", "text": "כִּסְאוֹת לְבֵית דָּוִד:"}, {"kind": "text", "text": "שַׁאֲלוּ שְׁלוֹם יְרוּשָׁלָֽםִ"}, {"kind": "text", "text": "יִשְׁלָֽיוּ אֹהֲבָֽיִךְ:"}, {"kind": "text", "text": "יְהִי־שָׁלוֹם בְּחֵילֵךְ"}, {"kind": "text", "text": "שַׁלְוָה בְּאַרְמְנוֹתָֽיִךְ:"}, {"kind": "text", "text": "לְמַֽעַן אַחַי וְרֵעָי"}, {"kind": "text", "text": "אֲדַבְּרָה־נָּא שָׁלוֹם בָּךְ:"}, {"kind": "text", "text": "לְמַֽעַן בֵּית־יְהֹוָה"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "אֲבַקְשָׁה טוֹב לָךְ:"}, {"kind": "text", "text": "<b>תהלים קכג</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת"}, {"kind": "text", "text": "אֵלֶֽיךָ נָשָֽׂאתִי אֶת־עֵינַי"}, {"kind": "text", "text": "הַיּשְׁבִי בַּשָּׁמָֽיִם:"}, {"kind": "text", "text": "הִנֵּה כְעֵינֵי עֲבָדִים"}, {"kind": "text", "text": "אֶל־יַד אֲדוֹנֵיהֶם"}, {"kind": "text", "text": "כְּעֵינֵי שִׁפְחָה"}, {"kind": "text", "text": "אֶל־יַד גְּבִרְתָּהּ"}, {"kind": "text", "text": "כֵּן עֵינֵֽינוּ אֶל־יְהֹוָה אֱלֹהֵֽינוּ"}, {"kind": "text", "text": "עַד שֶׁיְּחָנֵּֽנוּ:"}, {"kind": "text", "text": "חָנֵּֽנוּ יְהֹוָה חָנֵּֽנוּ"}, {"kind": "text", "text": "כִּי־רַב שָׂבַֽעְנוּ בוּז:"}, {"kind": "text", "text": "רַבַּת שָֽׂבְעָה־לָּהּ נַפְשֵֽׁנוּ"}, {"kind": "text", "text": "הַלַּֽעַג הַשַּׁאֲנַנִּים"}, {"kind": "text", "text": "הַבּוּז"}, {"kind": "text", "text": "לִגְאֵי יוֹנִֽים:"}, {"kind": "text", "text": "<b>תהלים קכד</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת לְדָוִד"}, {"kind": "text", "text": "לוּלֵי יְהֹוָה"}, {"kind": "text", "text": "שֶׁהָֽיָה לָֽנוּ"}, {"kind": "text", "text": "יֹֽאמַר־נָא יִשְׂרָאֵל:"}, {"kind": "text", "text": "לוּלֵי יְהֹוָה"}, {"kind": "text", "text": "שֶׁהָֽיָה לָֽנוּ"}, {"kind": "text", "text": "בְּקוּם עָלֵֽינוּ אָדָם:"}, {"kind": "text", "text": "אֲזַי חַיִּים בְּלָעֽוּנוּ"}, {"kind": "text", "text": "בַּחֲרוֹת אַפָּם בָּֽנוּ:"}, {"kind": "text", "text": "אֲזַי הַמַּֽיִם שְׁטָפֽוּנוּ"}, {"kind": "text", "text": "נַֽחְלָה עָבַר עַל־נַפְשֵֽׁנוּ:"}, {"kind": "text", "text": "אֲזַי עָבַר עַל־נַפְשֵֽׁנוּ"}, {"kind": "text", "text": "הַמַּֽיִם הַזֵּידוֹנִים:"}, {"kind": "text", "text": "בָּרוּךְ יְהֹוָה"}, {"kind": "text", "text": "שֶׁלֹּא נְתָנָֽנוּ"}, {"kind": "text", "text": "טֶֽרֶף לְשִׁנֵּיהֶם:"}, {"kind": "text", "text": "נַפְשֵֽׁנוּ כְּצִפּוֹר נִמְלְטָה"}, {"kind": "text", "text": "מִפַּח יוֹקְשִׁים"}, {"kind": "text", "text": "הַפַּח נִשְׁבָּר וַאֲנַֽחְנוּ נִמְלָֽטְנוּ:"}, {"kind": "text", "text": "עֶזְרֵֽנוּ בְּשֵׁם יְהֹוָה"}, {"kind": "text", "text": "עֹשֵׂה שָׁמַֽיִם וָאָֽרֶץ:"}, {"kind": "text", "text": "<b>תהלים קכה</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת"}, {"kind": "text", "text": "הַבֹּטְחִים בַּיהֹוָה"}, {"kind": "text", "text": "כְּהַר־צִיּוֹן לֹא־יִמּוֹט"}, {"kind": "text", "text": "לְעוֹלָם יֵשֵׁב:"}, {"kind": "text", "text": "יְרוּשָׁלַֽםִ הָרִים סָבִיב לָהּ"}, {"kind": "text", "text": "וַיהֹוָה סָבִיב לְעַמּוֹ"}, {"kind": "text", "text": "מֵעַתָּה וְעַד־עוֹלָם:"}, {"kind": "text", "text": "כִּי לֹא יָנֽוּחַ"}, {"kind": "text", "text": "שֵֽׁבֶט הָרֶֽשַׁע"}, {"kind": "text", "text": "עַל גּוֹרַל הַצַּדִּיקִים"}, {"kind": "text", "text": "לְמַֽעַן לֹא־יִשְׁלְחוּ הַצַּדִּיקִים"}, {"kind": "text", "text": "בְּעַוְלָֽתָה יְדֵיהֶם:"}, {"kind": "text", "text": "הֵיטִֽיבָה יְהֹוָה לַטּוֹבִים"}, {"kind": "text", "text": "וְלִישָׁרִים בְּלִבּוֹתָם:"}, {"kind": "text", "text": "וְהַמַּטִּים"}, {"kind": "text", "text": "עֲקַלְקַלּוֹתָם"}, {"kind": "text", "text": "יוֹלִיכֵם יְהֹוָה"}, {"kind": "text", "text": "אֶת־פֹּעֲלֵי הָאָֽוֶן"}, {"kind": "text", "text": "שָׁלוֹם עַל־יִשְׂרָאֵל:"}, {"kind": "text", "text": "<b>תהלים קכו</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת"}, {"kind": "text", "text": "בְּשׁוּב יְהֹוָה"}, {"kind": "text", "text": "אֶת־שִׁיבַת צִיּוֹן"}, {"kind": "text", "text": "הָיִֽינוּ כְּחֹלְמִים:"}, {"kind": "text", "text": "אָז"}, {"kind": "text", "text": "יִמָּלֵא שְׂחוֹק פִּֽינוּ"}, {"kind": "text", "text": "וּלְשׁוֹנֵֽנוּ רִנָּה"}, {"kind": "text", "text": "אָז יֹאמְרוּ בַגּוֹיִם"}, {"kind": "text", "text": "הִגְדִּיל יְהֹוָה לַעֲשׂוֹת עִם־אֵֽלֶּה:"}, {"kind": "text", "text": "הִגְדִּיל יְהֹוָה לַעֲשׂוֹת עִמָּֽנוּ"}, {"kind": "text", "text": "הָיִֽינוּ שְׂמֵחִים:"}, {"kind": "text", "text": "שׁוּבָה יְהֹוָה אֶת־שְׁבִיתֵֽנוּ"}, {"kind": "text", "text": "כַּאֲפִיקִים בַּנֶּֽגֶב:"}, {"kind": "text", "text": "הַזֹּרְעִים בְּדִמְעָה"}, {"kind": "text", "text": "בְּרִנָּה יִקְצֹֽרוּ:"}, {"kind": "text", "text": "הָלוֹךְ יֵלֵךְ וּבָכֹה"}, {"kind": "text", "text": "נֹשֵׂא מֶֽשֶׁךְ־הַזָּֽרַע"}, {"kind": "text", "text": "בֹּא־יָבֹא בְרִנָּה"}, {"kind": "text", "text": "נֹשֵׂא אֲלֻמֹּתָיו:"}, {"kind": "text", "text": "<b>תהלים קכז</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת לִשְׁלֹמֹה"}, {"kind": "text", "text": "אִם־יְהֹוָה לֹא־יִבְנֶה בַֽיִת"}, {"kind": "text", "text": "שָׁוְא עָמְלוּ בוֹנָיו בּוֹ"}, {"kind": "text", "text": "אִם־יְהֹוָה לֹא־יִשְׁמָר־עִיר"}, {"kind": "text", "text": "שָׁוְא שָׁקַד שׁוֹמֵר:"}, {"kind": "text", "text": "שָׁוְא לָכֶם"}, {"kind": "text", "text": "מַשְׁכִּֽימֵי קוּם מְאַֽחֲרֵי־שֶֽׁבֶת"}, {"kind": "text", "text": "אֹכְלֵי לֶֽחֶם הָעֲצָבִים"}, {"kind": "text", "text": "כֵּן יִתֵּן"}, {"kind": "text", "text": "לִידִידוֹ"}, {"kind": "text", "text": "שֵׁנָא:"}, {"kind": "text", "text": "הִנֵּה נַחֲלַת יְהֹוָה בָּנִים"}, {"kind": "text", "text": "שָׂכָר פְּרִי הַבָּֽטֶן:"}, {"kind": "text", "text": "כְּחִצִּים בְּיַד־גִּבּוֹר"}, {"kind": "text", "text": "כֵּן בְּנֵי הַנְּעוּרִים:"}, {"kind": "text", "text": "אַשְׁרֵי הַגֶּֽבֶר"}, {"kind": "text", "text": "אֲשֶׁר מִלֵּא אֶת־אַשְׁפָּתוֹ מֵהֶם"}, {"kind": "text", "text": "לֹא־יֵבֽשׁוּ"}, {"kind": "text", "text": "כִּי־יְדַבְּרוּ אֶת־אוֹיְבִים"}, {"kind": "text", "text": "בַּשָּֽׁעַר:"}, {"kind": "text", "text": "<b>תהלים קכח</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת"}, {"kind": "text", "text": "אַשְׁרֵי כָּל־יְרֵא יְהֹוָה"}, {"kind": "text", "text": "הַהֹלֵךְ בִּדְרָכָיו:"}, {"kind": "text", "text": "יְגִֽיעַ כַּפֶּֽיךָ"}, {"kind": "text", "text": "כִּי תֹאכֵל"}, {"kind": "text", "text": "אַשְׁרֶֽיךָ וְטוֹב לָךְ:"}, {"kind": "text", "text": "אֶשְׁתְּךָ כְּגֶֽפֶן פֹּרִיָּה"}, {"kind": "text", "text": "בְּיַרְכְּתֵי בֵיתֶֽךָ"}, {"kind": "text", "text": "בָּנֶֽיךָ כִּשְׁתִלֵי זֵיתִים"}, {"kind": "text", "text": "סָבִיב לְשֻׁלְחָנֶֽךָ:"}, {"kind": "text", "text": "הִנֵּה כִי־כֵן יְבֹֽרַךְ גָּֽבֶר"}, {"kind": "text", "text": "יְרֵא יְהֹוָה:"}, {"kind": "text", "text": "יְבָרֶכְךָ יְהֹוָה מִצִּיּוֹן"}, {"kind": "text", "text": "וּרְאֵה"}, {"kind": "text", "text": "בְּטוּב יְרוּשָׁלָֽםִ"}, {"kind": "text", "text": "כֹּל יְמֵי חַיֶּֽיךָ:"}, {"kind": "text", "text": "וּרְאֵה־בָנִים לְבָנֶֽיךָ"}, {"kind": "text", "text": "שָׁלוֹם עַל־יִשְׂרָאֵל:"}, {"kind": "text", "text": "<b>תהלים קכט</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת"}, {"kind": "text", "text": "רַבַּת צְרָרֽוּנִי"}, {"kind": "text", "text": "מִנְּעוּרַי"}, {"kind": "text", "text": "יֹֽאמַר־נָא יִשְׂרָאֵל:"}, {"kind": "text", "text": "רַבַּת צְרָרֽוּנִי"}, {"kind": "text", "text": "מִנְּעוּרָי"}, {"kind": "text", "text": "גַּם לֹא־יָֽכְלוּ לִי:"}, {"kind": "text", "text": "עַל־גַּבִּי חָרְשׁוּ חֹרְשִׁים"}, {"kind": "text", "text": "הֶאֱרִֽיכוּ לְמַעֲנִיתָם:"}, {"kind": "text", "text": "יְהֹוָה צַדִּיק"}, {"kind": "text", "text": "קִצֵּץ עֲבוֹת רְשָׁעִים:"}, {"kind": "text", "text": "יֵבֽשׁוּ וְיִסֹּֽגוּ אָחוֹר"}, {"kind": "text", "text": "כֹּל שׂנְאֵי צִיּוֹן:"}, {"kind": "text", "text": "יִהְיוּ כַּחֲצִיר גַּגּוֹת"}, {"kind": "text", "text": "שֶׁקַּדְמַת שָׁלַף יָבֵשׁ:"}, {"kind": "text", "text": "שֶׁלֹּא מִלֵּא כַפּוֹ קוֹצֵר"}, {"kind": "text", "text": "וְחִצְנוֹ מְעַמֵּר:"}, {"kind": "text", "text": "וְלֹא אָמְרוּ הָעֹבְרִים"}, {"kind": "text", "text": "בִּרְכַּת־יְהֹוָה אֲלֵיכֶם"}, {"kind": "text", "text": "בֵּרַֽכְנוּ אֶתְכֶם בְּשֵׁם יְהֹוָה:"}, {"kind": "text", "text": "<b>תהלים קל</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת"}, {"kind": "text", "text": "מִמַּעֲמַקִּים"}, {"kind": "text", "text": "קְרָאתִֽיךָ יְהֹוָה:"}, {"kind": "text", "text": "אֲדֹנָי שִׁמְעָה בְקוֹלִי"}, {"kind": "text", "text": "תִּהְיֶֽינָה אָזְנֶֽיךָ קַשֻּׁבוֹת"}, {"kind": "text", "text": "לְקוֹל תַּחֲנוּנָי:"}, {"kind": "text", "text": "אִם־עֲוֹנוֹת תִּשְׁמָר־יָהּ"}, {"kind": "text", "text": "אֲדֹנָי מִי יַעֲמֹד:"}, {"kind": "text", "text": "כִּי־עִמְּךָ הַסְּלִיחָה"}, {"kind": "text", "text": "לְמַֽעַן תִּוָּרֵא:"}, {"kind": "text", "text": "קִוִּֽיתִי יְהֹוָה קִוְּתָה נַפְשִׁי"}, {"kind": "text", "text": "וְלִדְבָרוֹ הוֹחָֽלְתִּי:"}, {"kind": "text", "text": "נַפְשִׁי לַאדֹנָי"}, {"kind": "text", "text": "מִשֹּׁמְרִים"}, {"kind": "text", "text": "לַבֹּֽקֶר"}, {"kind": "text", "text": "שֹׁמְרִים"}, {"kind": "text", "text": "לַבֹּֽקֶר:"}, {"kind": "text", "text": "יַחֵל יִשְׂרָאֵל אֶל־יְהֹוָה"}, {"kind": "text", "text": "כִּי־עִם־יְהֹוָה הַחֶֽסֶד"}, {"kind": "text", "text": "וְהַרְבֵּה עִמּוֹ פְדוּת:"}, {"kind": "text", "text": "וְהוּא יִפְדֶּה אֶת־יִשְׂרָאֵל"}, {"kind": "text", "text": "מִכֹּל עֲוֹנוֹתָיו:"}, {"kind": "text", "text": "<b>תהלים קלא</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת לְדָוִד"}, {"kind": "text", "text": "יְהֹוָה לֹא־גָבַהּ לִבִּי"}, {"kind": "text", "text": "וְלֹא־רָמוּ עֵינַי"}, {"kind": "text", "text": "וְלֹא־הִלַּֽכְתִּי"}, {"kind": "text", "text": "בִּגְדֹלוֹת"}, {"kind": "text", "text": "וּבְנִפְלָאוֹת מִמֶּֽנִּי:"}, {"kind": "text", "text": "אִם־לֹא שִׁוִּֽיתִי"}, {"kind": "text", "text": "וְדוֹמַֽמְתִּי נַפְשִׁי"}, {"kind": "text", "text": "כְּגָמֻל עֲלֵי אִמּוֹ"}, {"kind": "text", "text": "כַּגָּמֻל עָלַי נַפְשִׁי:"}, {"kind": "text", "text": "יַחֵל יִשְׂרָאֵל אֶל־יְהֹוָה"}, {"kind": "text", "text": "מֵעַתָּה וְעַד־עוֹלָם:"}, {"kind": "text", "text": "<b>תהלים קלב</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת"}, {"kind": "text", "text": "זְכוֹר־יְהֹוָה לְדָוִד"}, {"kind": "text", "text": "אֵת כָּל־עֻנּוֹתוֹ:"}, {"kind": "text", "text": "אֲשֶׁר נִשְׁבַּע לַיהֹוָה"}, {"kind": "text", "text": "נָדַר לַאֲבִיר יַעֲקֹב:"}, {"kind": "text", "text": "אִם־אָבֹא"}, {"kind": "text", "text": "בְּאֹֽהֶל בֵּיתִי"}, {"kind": "text", "text": "אִם־אֶעֱלֶה"}, {"kind": "text", "text": "עַל־עֶֽרֶשׂ יְצוּעָי:"}, {"kind": "text", "text": "אִם־אֶתֵּן שְׁנָת לְעֵינָי"}, {"kind": "text", "text": "לְעַפְעַפַּי תְּנוּמָה:"}, {"kind": "text", "text": "עַד־אֶמְצָא מָקוֹם לַיהֹוָה"}, {"kind": "text", "text": "מִשְׁכָּנוֹת לַאֲבִיר יַעֲקֹב:"}, {"kind": "text", "text": "הִנֵּה־שְׁמַעֲנֽוּהָ בְאֶפְרָֽתָה"}, {"kind": "text", "text": "מְצָאנֽוּהָ בִּשְׂדֵי־יָֽעַר:"}, {"kind": "text", "text": "נָבֽוֹאָה לְמִשְׁכְּנוֹתָיו"}, {"kind": "text", "text": "נִשְׁתַּחֲוֶה לַהֲדֹם רַגְלָיו:"}, {"kind": "text", "text": "קוּמָה יְהֹוָה לִמְנוּחָתֶֽךָ"}, {"kind": "text", "text": "אַתָּה וַאֲרוֹן עֻזֶּֽךָ:"}, {"kind": "text", "text": "כֹּהֲנֶֽיךָ"}, {"kind": "text", "text": "יִלְבְּשׁוּ־צֶֽדֶק"}, {"kind": "text", "text": "וַחֲסִידֶֽיךָ יְרַנֵּֽנוּ:"}, {"kind": "text", "text": "בַּעֲבוּר דָּוִד עַבְדֶּֽךָ"}, {"kind": "text", "text": "אַל־תָּשֵׁב פְּנֵי מְשִׁיחֶֽךָ:"}, {"kind": "text", "text": "נִשְׁבַּע־יְהֹוָה לְדָוִד"}, {"kind": "text", "text": "אֱמֶת לֹא־יָשׁוּב מִמֶּֽנָּה"}, {"kind": "text", "text": "מִפְּרִי בִטְנְךָ"}, {"kind": "text", "text": "אָשִׁית לְכִסֵּא־לָךְ:"}, {"kind": "text", "text": "אִם־יִשְׁמְרוּ בָנֶיךָ בְּרִיתִי"}, {"kind": "text", "text": "וְעֵדֹתִי זוֹ אֲלַמְּדֵם"}, {"kind": "text", "text": "גַּם־בְּנֵיהֶם"}, {"kind": "text", "text": "עֲדֵי־עַד יֵשְׁבוּ לְכִסֵּא־לָךְ:"}, {"kind": "text", "text": "כִּי־בָחַר יְהֹוָה בְּצִיּוֹן"}, {"kind": "text", "text": "אִוָּהּ לְמוֹשָׁב לוֹ:"}, {"kind": "text", "text": "זֹאת־מְנוּחָתִי עֲדֵי־עַד"}, {"kind": "text", "text": "פֹּה אֵשֵׁב כִּי אִוִּתִֽיהָ:"}, {"kind": "text", "text": "צֵידָהּ בָּרֵךְ אֲבָרֵךְ"}, {"kind": "text", "text": "אֶבְיוֹנֶֽיהָ אַשְׂבִּֽיעַ לָֽחֶם:"}, {"kind": "text", "text": "וְכֹהֲנֶֽיהָ"}, {"kind": "text", "text": "אַלְבִּישׁ יֶֽשַׁע"}, {"kind": "text", "text": "וַחֲסִידֶֽיהָ רַנֵּן יְרַנֵּֽנוּ:"}, {"kind": "text", "text": "שָׁם אַצְמִֽיחַ"}, {"kind": "text", "text": "קֶֽרֶן לְדָוִד"}, {"kind": "text", "text": "עָרַֽכְתִּי נֵר"}, {"kind": "text", "text": "לִמְשִׁיחִי:"}, {"kind": "text", "text": "אוֹיְבָיו אַלְבִּישׁ בּֽשֶׁת"}, {"kind": "text", "text": "וְעָלָיו יָצִיץ נִזְרוֹ:"}, {"kind": "text", "text": "<b>תהלים קלג</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת לְדָוִד"}, {"kind": "text", "text": "הִנֵּה מַה־טּוֹב וּמַה־נָּעִים"}, {"kind": "text", "text": "שֶֽׁבֶת אַחִים גַּם־יָֽחַד:"}, {"kind": "text", "text": "כַּשֶּֽׁמֶן הַטּוֹב עַל הָרֹאשׁ"}, {"kind": "text", "text": "יֹרֵד עַל־הַזָּקָן"}, {"kind": "text", "text": "זְקַן־אַהֲרֹן"}, {"kind": "text", "text": "שֶׁיֹּרֵד"}, {"kind": "text", "text": "עַל־פִּי מִדּוֹתָיו:"}, {"kind": "text", "text": "כְּטַל־חֶרְמוֹן"}, {"kind": "text", "text": "שֶׁיֹּרֵד"}, {"kind": "text", "text": "עַל־הַרְרֵי צִיּוֹן"}, {"kind": "text", "text": "כִּי שָׁם צִוָּה יְהֹוָה אֶת־הַבְּרָכָה"}, {"kind": "text", "text": "חַיִּים עַד־הָעוֹלָם:"}, {"kind": "text", "text": "<b>תהלים קלד</b>"}, {"kind": "text", "text": "שִׁיר הַמַּעֲלוֹת"}, {"kind": "text", "text": "הִנֵּה בָּרְכוּ אֶת־יְהֹוָה"}, {"kind": "text", "text": "כָּל־עַבְדֵי יְהֹוָה"}, {"kind": "text", "text": "הָעֹמְדִים בְּבֵית־יְהֹוָה"}, {"kind": "text", "text": "בַּלֵּילוֹת:"}, {"kind": "text", "text": "שְׂאוּ־יְדֵכֶם קֹֽדֶשׁ"}, {"kind": "text", "text": "וּבָרְכוּ אֶת־יְהֹוָה:"}, {"kind": "text", "text": "יְבָרֶכְךָ יְהֹוָה מִצִּיּוֹן"}, {"kind": "text", "text": "עֹשֵׂה שָׁמַֽיִם וָאָֽרֶץ:"}]}, "ashkenaz": {"maariv": [{"kind": "header", "text": "ידיד נפש"}, {"kind": "text", "text": "יְדִיד נֶֽפֶשׁ אָב הָרַחֲמָן. מְשׁוֹךְ עַבְדְּ֒ךָ אֶל רְצוֹנֶֽךָ. יָרוּץ עַבְדְּ֒ךָ כְּמוֹ אַיָּל יִשְׁתַּחֲוֶה אֶל מוּל הֲדָרֶֽךָ. יֶעֱרַב לוֹ יְדִידוֹתֶֽיךָ. מִנֹּֽפֶת צוּף וְכָל טָֽעַם:"}, {"kind": "text", "text": "הָדוּר נָאֶה זִיו הָעוֹלָם. נַפְשִׁי חוֹלַת אַהֲבָתֶֽךָ. אָֽנָּא אֵל נָא רְפָא נָא לָהּ. בְּהַרְאוֹת לָהּ נֹֽעַם זִיוֶֽךָ. אָז תִּתְחַזֵּק וְתִתְרַפֵּא. וְהָיְ֒תָה לָהּ שִׂמְחַת עוֹלָם:"}, {"kind": "text", "text": "וָתִיק יֶהֱמוּ נָא רַחֲמֶֽיךָ וְחֽוּסָה נָא עַל בֵּן אֲהוּבֶֽךָ. כִּי זֶה כַּמָּה נִכְסוֹף נִכְסַפְתִּי לִרְאוֹת מְהֵרָה בְּתִפְאֶֽרֶת עֻזֶּֽךָ. אֵֽלֶּה חָמְ֒דָה לִבִּי וְחֽוּסָה נָא וְאַל תִּתְעַלֵּם:"}, {"kind": "text", "text": "הִגָּלֶה נָּא וּפְרוֹס חֲבִיבִי עָלַי אֶת סֻכַּת שְׁלוֹמֶֽךָ. תָּאִיר אֶֽרֶץ מִכְּ֒בוֹדֶֽךָ. נָגִֽילָה וְנִשְׂמְ֒חָה בָּךְ. מַהֵר אֶהֹב כִּי בָא מוֹעֵד וְחָנֵּֽנוּ כִּימֵי עוֹלָם:"}, {"kind": "header", "text": "תהילים צה"}, {"kind": "instruction", "text": "ביום טוב שחל בשבת ובשבת חול המועד מתחילים מזמור לדוד."}, {"kind": "text", "text": "לְכוּ נְרַנְּנָה לַיהֹוָה נָרִֽיעָה לְצוּר יִשְׁעֵֽנוּ: נְקַדְּמָה פָנָיו בְּתוֹדָה בִּזְמִרוֹת נָרִֽיעַ לוֹ: כִּי אֵל גָּדוֹל יְהֹוָה וּמֶֽלֶךְ גָּדוֹל עַל־כָּל־אֱלֹהִים: אֲשֶׁר בְּיָדוֹ מֶחְקְרֵי־אָֽרֶץ וְתוֹעֲפוֹת הָרִים לוֹ: אֲשֶׁר־לוֹ הַיָּם וְהוּא עָשָֽׂהוּ וְיַבֶּֽשֶׁת יָדָיו יָצָֽרוּ: בֹּֽאוּ נִשְׁתַּחֲוֶה וְנִכְרָֽעָה נִבְרְכָה לִפְנֵי־יְהֹוָה עֹשֵֽׂנוּ: כִּי הוּא אֱלֹהֵֽינוּ וַאֲנַֽחְנוּ עַם מַרְעִיתוֹ וְצֹאן יָדוֹ הַיּוֹם אִם־בְּקֹלוֹ תִשְׁמָֽעוּ: אַל־תַּקְשׁוּ לְבַבְכֶם כִּמְרִיבָה כְּיוֹם מַסָּה בַּמִּדְבָּר: אֲשֶׁר נִסּֽוּנִי אֲבוֹתֵיכֶם בְּחָנֽוּנִי גַּם־רָאוּ פָעֳלִי: אַרְבָּעִים שָׁנָה אָקוּט בְּדוֹר וָאֹמַר עַם תֹּעֵי לֵבָב הֵם וְהֵם לֹא־יָדְעוּ דְרָכָי: אֲשֶׁר־נִשְׁבַּֽעְתִּי בְאַפִּי אִם־יְבֹאוּן אֶל־מְנוּחָתִי:"}, {"kind": "header", "text": "תהילים צו"}, {"kind": "text", "text": "שִֽׁירוּ לַיהֹוָה שִׁיר חָדָשׁ שִֽׁירוּ לַיהֹוָה כָּל־הָאָֽרֶץ: שִֽׁירוּ לַיהֹוָה בָּרְכוּ שְׁמוֹ בַּשְּׂרוּ מִיּוֹם־לְיוֹם יְשׁוּעָתוֹ: סַפְּרוּ בַגּוֹיִם כְּבוֹדוֹ בְּכָל־הָעַמִּים נִפְלְאוֹתָיו: כִּי גָדוֹל יְהֹוָה וּמְהֻלָּל מְאֹד נוֹרָא הוּא עַל־כָּל־אֱלֹהִים: כִּי כָּל־אֱלֹהֵי הָעַמִּים אֱלִילִים וַיהֹוָה שָׁמַֽיִם עָשָׂה: הוֹד־וְהָדָר לְפָנָיו עֹז וְתִפְאֶֽרֶת בְּמִקְדָּשׁוֹ: הָבוּ לַיהֹוָה מִשְׁפְּחוֹת עַמִּים הָבוּ לַיהֹוָה כָּבוֹד וָעֹז: הָבוּ לַיהֹוָה כְּבוֹד שְׁמוֹ שְׂאוּ־מִנְחָה וּבֹֽאוּ לְחַצְרוֹתָיו: הִשְׁתַּחֲווּ לַיהֹוָה בְּהַדְרַת־קֹֽדֶשׁ חִֽילוּ מִפָּנָיו כָּל־הָאָֽרֶץ: אִמְרוּ בַגּוֹיִם יְהֹוָה מָלָךְ אַף־תִּכּוֹן תֵּבֵל בַּל־תִּמּוֹט יָדִין עַמִּים בְּמֵישָׁרִים: יִשְׂמְחוּ הַשָּׁמַֽיִם וְתָגֵל הָאָֽרֶץ יִרְעַם הַיָּם וּמְלֹאוֹ: יַעֲלֹז שָׂדַי וְכָל־אֲשֶׁר־בּוֹ אָז יְרַנְּנוּ כָּל־עֲצֵי־יָֽעַר: לִפְנֵי יְהֹוָה כִּי בָא כִּי בָא לִשְׁפֹּט הָאָֽרֶץ יִשְׁפֹּט־תֵּבֵל בְּצֶֽדֶק וְעַמִּים בֶּאֱמוּנָתוֹ:"}, {"kind": "header", "text": "תהילים צז"}, {"kind": "text", "text": "יְהֹוָה מָלָךְ תָּגֵל הָאָֽרֶץ יִשְׂמְחוּ אִיִּים רַבִּים: עָנָן וַעֲרָפֶל סְבִיבָיו צֶֽדֶק וּמִשְׁפָּט מְכוֹן כִּסְאוֹ: אֵשׁ לְפָנָיו תֵּלֵךְ וּתְלַהֵט סָבִיב צָרָיו: הֵאִֽירוּ בְרָקָיו תֵּבֵל רָאֲתָה וַתָּחֵל הָאָֽרֶץ: הָרִים כַּדּוֹנַג נָמַֽסּוּ מִלִּפְנֵי יְהֹוָה מִלִּפְנֵי אֲדוֹן כָּל־הָאָֽרֶץ: הִגִּֽידוּ הַשָּׁמַֽיִם צִדְקוֹ וְרָאוּ כָל־הָעַמִּים כְּבוֹדוֹ: יֵבֽשׁוּ כָּל־עֹֽבְדֵי פֶֽסֶל הַמִּתְהַלְלִים בָּאֱלִילִים הִשְׁתַּחֲווּ־לוֹ כָּל־אֱלֹהִים: שָׁמְעָה וַתִּשְׂמַח צִיּוֹן וַתָּגֵֽלְנָה בְּנוֹת יְהוּדָה לְמַֽעַן מִשְׁפָּטֶֽיךָ יְהֹוָה: כִּי־אַתָּה יְהֹוָה עֶלְיוֹן עַל־כָּל־הָאָֽרֶץ מְאֹד נַעֲלֵֽיתָ עַל־כָּל־אֱלֹהִים: אֹהֲבֵי יְהֹוָה שִׂנְאוּ רָע שֹׁמֵר נַפְשׁוֹת חֲסִידָיו מִיַּד רְשָׁעִים יַצִּילֵם: אוֹר זָרֻֽעַ לַצַּדִּיק וּלְיִשְׁרֵי־לֵב שִׂמְחָה: שִׂמְחוּ צַדִּיקִים בַּיהֹוָה וְהוֹדוּ לְזֵֽכֶר קָדְשׁוֹ:"}, {"kind": "header", "text": "תהילים צח"}, {"kind": "text", "text": "מִזְמוֹר שִֽׁירוּ לַיהֹוָה שִׁיר חָדָשׁ כִּי־נִפְלָאוֹת עָשָׂה הוֹשִֽׁיעָה־לּוֹ יְמִינוֹ וּזְרֽוֹעַ קָדְשׁוֹ: הוֹדִֽיעַ יְהֹוָה יְשׁוּעָתוֹ לְעֵינֵי הַגּוֹיִם גִּלָּה צִדְקָתוֹ: זָכַר חַסְדּוֹ וֶאֱמוּנָתוֹ לְבֵית יִשְׂרָאֵל רָאוּ כָל־אַפְסֵי־אָֽרֶץ אֵת יְשׁוּעַת אֱלֹהֵֽינוּ: הָרִֽיעוּ לַיהֹוָה כָּל־הָאָֽרֶץ פִּצְחוּ וְרַנְּנוּ וְזַמֵּֽרוּ: זַמְּרוּ לַיהֹוָה בְּכִנּוֹר בְּכִנּוֹר וְקוֹל זִמְרָה: בַּחֲצֹצְרוֹת וְקוֹל שׁוֹפָר הָרִֽיעוּ לִפְנֵי הַמֶּֽלֶךְ יְהֹוָה: יִרְעַם הַיָּם וּמְלֹאוֹ תֵּבֵל וְיֽשְׁבֵי בָהּ: נְהָרוֹת יִמְחֲאוּ־כָף יַֽחַד הָרִים יְרַנֵּֽנוּ: לִפְנֵי־יְהֹוָה כִּי בָא לִשְׁפֹּט הָאָֽרֶץ יִשְׁפֹּט־תֵּבֵל בְּצֶֽדֶק וְעַמִּים בְּמֵישָׁרִים:"}, {"kind": "header", "text": "תהילים צט"}, {"kind": "text", "text": "יְהֹוָה מָלָךְ יִרְגְּזוּ עַמִּים ישֵׁב כְּרוּבִים תָּנוּט הָאָֽרֶץ: יְהֹוָה בְּצִיּוֹן גָּדוֹל וְרָם הוּא עַל־כָּל הָעַמִּים: יוֹדוּ שִׁמְךָ גָּדוֹל וְנוֹרָא קָדוֹשׁ הוּא: וְעֹז מֶֽלֶךְ מִשְׁפָּט אָהֵב אַתָּה כּוֹנַֽנְתָּ מֵישָׁרִים מִשְׁפָּט וּצְדָקָה בְּיַעֲקֹב אַתָּה עָשִֽׂיתָ: רוֹמְמוּ יְהֹוָה אֱלֹהֵֽינוּ וְהִשְׁתַּחֲווּ לַהֲדֹם רַגְלָיו קָדוֹשׁ הוּא: משֶׁה וְאַהֲרֹן בְּכֹהֲנָיו וּשְׁמוּאֵל בְּקֹרְאֵי שְׁמוֹ קֹרִאים אֶל־יְהֹוָה וְהוּא יַעֲנֵם: בְּעַמּוּד עָנָן יְדַבֵּר אֲלֵיהֶם שָׁמְרוּ עֵדֹתָיו וְחֹק נָֽתַן־לָֽמוֹ: יְהֹוָה אֱלֹהֵֽינוּ אַתָּה עֲנִיתָם אֵל נֹשֵׂא הָיִֽיתָ לָהֶם וְנֹקֵם עַל־עֲלִילוֹתָם: רוֹמְמוּ יְהֹוָה אֱלֹהֵֽינוּ וְהִשְׁתַּחֲווּ לְהַר קָדְשׁוֹ כִּי־קָדוֹשׁ יְהֹוָה אֱלֹהֵֽינוּ:"}, {"kind": "header", "text": "תהילים כט"}, {"kind": "text", "text": "מִזְמוֹר לְדָוִד הָבוּ לַיהֹוָה בְּנֵי אֵלִים הָבוּ לַיהֹוָה כָּבוֹד וָעֹז: הָבוּ לַיהֹוָה כְּבוֹד שְׁמוֹ הִשְׁתַּחֲווּ לַיהֹוָה בְּהַדְרַת־קֹֽדֶשׁ: קוֹל יְהֹוָה עַל־הַמָּֽיִם אֵל־הַכָּבוֹד הִרְעִים יְהֹוָה עַל־מַֽיִם רַבִּים: קוֹל־יְהֹוָה בַּכֹּֽחַ קוֹל יְהֹוָה בֶּהָדָר: קוֹל יְהֹוָה שֹׁבֵר אֲרָזִים וַיְשַׁבֵּר יְהֹוָה אֶת־אַרְזֵי הַלְּבָנוֹן: וַיַּרְקִידֵם כְּמוֹ־עֵֽגֶל לְבָנוֹן וְשִׂרְיוֹן כְּמוֹ בֶן־רְאֵמִים: קוֹל־יְהֹוָה חֹצֵב לַהֲבוֹת אֵשׁ: קוֹל יְהֹוָה יָחִיל מִדְבָּר יָחִיל יְהֹוָה מִדְבַּר קָדֵשׁ: קוֹל יְהֹוָה יְחוֹלֵל אַיָּלוֹת וַיֶּחֱשׂף יְעָרוֹת וּבְהֵיכָלוֹ כֻּלּוֹ אֹמֵר כָּבוֹד: יְהֹוָה לַמַּבּוּל יָשָׁב וַיֵּֽשֶׁב יְהֹוָה מֶֽלֶךְ לְעוֹלָם: יְהֹוָה עֹז לְעַמּוֹ יִתֵּן יְהֹוָה יְבָרֵךְ אֶת־עַמּוֹ בַשָּׁלוֹם:"}, {"kind": "header", "text": "אנא בכח"}, {"kind": "text", "text": "<b>אָנָּא</b> בְּכֹֽחַ גְּדֻלַּת יְמִינְ֒ךָ תַּתִּיר צְרוּרָה: קַבֵּל רִנַּת עַמְּ֒ךָ שַׂגְּ֒בֵֽנוּ טַהֲרֵֽנוּ נוֹרָא: נָא גִבּוֹר דּוֹרְ֒שֵׁי יִחוּדְ֒ךָ כְּבָבַת שָׁמְרֵם: בָּרְ֒כֵם טַהֲרֵם רַחֲמֵם צִדְקָתְ֒ךָ תָּמִיד גָּמְלֵם: חֲסִין קָדוֹשׁ בְּרֹב טוּבְ֒ךָ נַהֵל עֲדָתֶֽךָ: יָחִיד גֵּאֶה לְעַמְּ֒ךָ פְּנֵה, זוֹכְ֒רֵי קְדֻשָּׁתֶֽךָ: שַׁוְעָתֵֽנוּ קַבֵּל וּשְׁמַע צַעֲקָתֵֽנוּ יוֹדֵֽעַ תַּעֲלוּמוֹת: בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד:"}, {"kind": "header", "text": "לכה דודי"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה. פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "שָׁמוֹר וְזָכוֹר בְּדִבּוּר אֶחָד. הִשְׁמִיעָֽנוּ אֵל הַמְיוּחָד. יְהֹוָה אֶחָד וּשְׁמוֹ אֶחָד. לְשֵׁם וּלְתִפְאֶֽרֶת וְלִתְהִלָּה:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה. פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "לִקְרַאת שַׁבָּת לְכוּ וְנֵלְ֒כָה. כִּי הִיא מְקוֹר הַבְּ֒רָכָה. מֵרֹאשׁ מִקֶּֽדֶם נְסוּכָה. סוֹף מַעֲשֶׂה בְּמַחֲשָׁבָה תְּחִלָּה:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה. פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "מִקְדַּשׁ מֶֽלֶךְ עִיר מְלוּכָה. קֽוּמִי צְאִי מִתּוֹךְ הַהֲפֵכָה. רַב לָךְ שֶֽׁבֶת בְּעֵֽמֶק הַבָּכָא. וְהוּא יַחְמוֹל עָלַֽיִךְ חֶמְלָה:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה. פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "הִתְנַעֲרִי מֵעָפָר קֽוּמִי. לִבְשִׁי בִּגְדֵי תִפְאַרְתֵּךְ עַמִּי. עַל יַד בֶּן יִשַּׁי בֵּית הַלַּחְמִי. קָרְבָה אֶל נַפְשִׁי גְּאָלָהּ:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה. פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "הִתְעוֹרְ֒רִי. הִתְעוֹרְ֒רִי. כִּי בָא אוֹרֵךְ קֽוּמִי אֽוֹרִי. עֽוּרִי עֽוּרִי שִׁיר דַּבֵּֽרִי. כְּבוֹד יְהֹוָה עָלַֽיִךְ נִגְלָה:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה. פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "לֹא תֵבֽוֹשִׁי וְלֹא תִכָּלְ֒מִי. מַה תִּשְׁתּוֹחֲחִי וּמַה תֶּהֱמִי. בָּךְ יֶחֱסוּ עֲנִיֵּי עַמִּי. וְנִבְנְ֒תָה עִיר עַל תִּלָּהּ:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה. פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "וְהָיוּ לִמְשִׁסָּה שֹׁסָֽיִךְ. וְרָחֲקוּ כָּל מְבַלְּ֒עָֽיִךְ. יָשִׂישׂ עָלַֽיִךְ אֱלֹהָֽיִךְ. כִּמְשׂוֹשׂ חָתָן עַל כַּלָּה:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה. פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "יָמִין וּשְׂמֹאל תִּפְרֽוֹצִי. וְאֶת יְהֹוָה תַּעֲרִֽיצִי. עַל יַד אִישׁ בֶּן פַּרְצִי. וְנִשְׂמְ֒חָה וְנָגִֽילָה:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה. פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "text", "text": "בּֽוֹאִי בְשָׁלוֹם עֲטֶֽרֶת בַּעְלָהּ. גַּם בְּשִׂמְחָה וּבְצָהֳלָה. תּוֹךְ אֱמוּנֵי עַם סְגֻלָּה. בֹּֽאִי כַלָּה בֹּֽאִי כַלָּה בֹּֽאִי כַלָּה שַׁבָּת מַלְכְּתָא:"}, {"kind": "instruction", "text": "לְכָה דוֹדִי לִקְרַאת כַּלָּה. פְּנֵי שַׁבָּת נְקַבְּ֒לָה:"}, {"kind": "header", "text": "תהילים צב"}, {"kind": "text", "text": "מִזְמוֹר שִׁיר לְיוֹם הַשַּׁבָּת: טוֹב לְהֹדוֹת לַיהֹוָה וּלְזַמֵּר לְשִׁמְךָ עֶלְיוֹן: לְהַגִּיד בַּבֹּֽקֶר חַסְדֶּֽךָ וֶאֱמוּנָתְךָ בַּלֵּילוֹת: עֲלֵי־עָשׂוֹר וַעֲלֵי־נָֽבֶל עֲלֵי הִגָּיוֹן בְּכִנּוֹר: כִּי שִׂמַּחְתַּֽנִי יְהֹוָה בְּפָעֳלֶֽךָ בְּמַעֲשֵׂי יָדֶֽיךָ אֲרַנֵּן: מַה־גָּדְלוּ מַעֲשֶֽׂיךָ יְהֹוָה מְאֹד עָמְקוּ מַחְשְׁבֹתֶֽיךָ: אִישׁ־בַּֽעַר לֹא יֵדָע וּכְסִיל לֹא־יָבִין אֶת־זֹאת: בִּפְרֹֽחַ רְשָׁעִים כְּמוֹ עֵֽשֶׂב וַיָּצִֽיצוּ כָּל־פֹּֽעֲלֵי אָֽוֶן לְהִשָּׁמְדָם עֲדֵי־עַד: וְאַתָּה מָרוֹם לְעֹלָם יְהֹוָה: כִּי הִנֵּה אֹיְבֶֽיךָ יְהֹוָה כִּי־הִנֵּה אֹיְבֶֽיךָ יֹאבֵֽדוּ יִתְפָּרְדוּ כָּל־פֹּֽעֲלֵי אָֽוֶן: וַתָּֽרֶם כִּרְאֵים קַרְנִי בַּלֹּתִי בְּשֶֽׁמֶן רַעֲנָן: וַתַּבֵּט עֵינִי בְּשׁוּרָי בַּקָּמִים עָלַי מְרֵעִים תִּשְׁמַֽעְנָה אָזְנָי: צַדִּיק כַּתָּמָר יִפְרָח כְּאֶֽרֶז בַּלְּבָנוֹן יִשְׂגֶּה: שְׁתוּלִים בְּבֵית יְהֹוָה בְּחַצְרוֹת אֱלֹהֵֽינוּ יַפְרִֽיחוּ: עוֹד יְנוּבוּן בְּשֵׂיבָה דְּשֵׁנִים וְרַעֲנַנִּים יִהְיוּ: לְהַגִּיד כִּי־יָשָׁר יְהֹוָה צוּרִי וְלֹא־עַוְלָֽתָה בּוֹ:"}, {"kind": "header", "text": "תהילים צג"}, {"kind": "text", "text": "יְהֹוָה מָלָךְ גֵּאוּת לָבֵשׁ לָבֵשׁ יְהֹוָה עֹז הִתְאַזָּר אַף־תִּכּוֹן תֵּבֵל בַּל־תִּמּוֹט: נָכוֹן כִּסְאֲךָ מֵאָז מֵעוֹלָם אָֽתָּה: נָשְׂאוּ נְהָרוֹת יְהֹוָה נָשְׂאוּ נְהָרוֹת קוֹלָם יִשְׂאוּ נְהָרוֹת דָּכְיָם: מִקֹּלוֹת מַֽיִם רַבִּים אַדִּירִים מִשְׁבְּרֵי־יָם אַדִּיר בַּמָּרוֹם יְהֹוָה: עֵדֹתֶֽיךָ נֶאֶמְנוּ מְאֹד לְבֵיתְךָ נָֽאֲוָה־קֹּֽדֶשׁ יְהֹוָה לְאֹֽרֶךְ יָמִים:"}, {"kind": "header", "text": "קדיש יתום"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא (<b>אָמֵן</b>) בְּעָלְ֒מָֽא דִּי־בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל־בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב וְאִמְרוּ <b>אָמֵן</b>: <b>יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְ֒מֵי עָלְ֒מַיָּא</b> יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְקוּדְשָׁא <b>בְּרִיךְ הוּא</b> לְעֵֽלָּא מִן־כָּל־ (בעשי\"ת לְעֵֽלָּא לְעֵֽלָּא מִכָּל) בִּרְכָתָֽא וְשִׁירָתָֽא תֻּשְׁבְּ֒חָתָֽא וְנֶחָמָתָֽא דַּאֲמִירָן בְּעָלְ֒מָֽא וְאִמְרוּ <b>אָמֵן</b>: עַל יִשְׂרָאֵל וְעַל רַבָּנָן וְעַל תַלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן. וְעַל כָּל מָאן דְּעָסְ֒קִין בְּאוֹרַיְתָא. דִּי בְאַתְרָא הָדֵין וְדִי בְכָל אֲתַר וַאֲתַר. יְהֵא לְהוֹן וּלְכוֹן שְׁלָמָא רַבָּא חִנָּא וְחִסְדָּא וְרַחֲמִין וְחַיִּין אֲרִיכִין וּמְזוֹנָא רְוִיחֵי וּפוּרְקָנָא מִן קֳדָם אֲבוּהוֹן דְבִשְׁמַיָּא (וְאַרְעָא) וְאִמְרוּ <b>אָמֵן</b>: יְהֵא שְׁלָמָֽא רַבָּֽא מִן־שְׁמַיָּֽא וְחַיִּים עָלֵֽינוּ וְעַל־כָּל־יִשְׂרָאֵל וְאִמְרוּ <b>אָמֵן</b>: עוֹשֶׂה שָׁלוֹם (בעשי\"ת הַשָּׁלוֹם) בִּמְרוֹמָיו הוּא יַעֲשֶׂה שָׁלוֹם עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "header", "text": "במה מדליקין"}, {"kind": "text", "text": "בַּמֶּה מַדְלִיקִין וּבַמָּה אֵין מַדְלִיקִין. אֵין מַדְלִיקִין לֹא בְלֶכֶשׁ, וְלֹא בְחֹסֶן, וְלֹא בְכָלָךְ, וְלֹא בִפְתִילַת הָאִידָן, וְלֹא בִפְתִילַת הַמִּדְבָּר, וְלֹא בִירוֹקָה שֶׁעַל פְּנֵי הַמָּיִם. וְלֹא בְזֶפֶת, וְלֹא בְשַׁעֲוָה, וְלֹא בְשֶׁמֶן קִיק, וְלֹא בְשֶׁמֶן שְׂרֵפָה, וְלֹא בְאַלְיָה, וְלֹא בְחֵלֶב. נַחוּם הַמָּדִי אוֹמֵר, מַדְלִיקִין בְּחֵלֶב מְבֻשָּׁל. וַחֲכָמִים אוֹמְרִים, אֶחָד מְבֻשָּׁל וְאֶחָד שֶׁאֵינוֹ מְבֻשָּׁל, אֵין מַדְלִיקִין בּוֹ:"}, {"kind": "text", "text": "אֵין מַדְלִיקִין בְּשֶׁמֶן שְׂרֵפָה בְּיוֹם טוֹב. רַבִּי יִשְׁמָעֵאל אוֹמֵר, אֵין מַדְלִיקִין בְּעִטְרָן, מִפְּנֵי כְבוֹד הַשַּׁבָּת. וַחֲכָמִים מַתִּירִין בְּכָל הַשְּׁמָנִים, בְּשֶׁמֶן שֻׁמְשְׁמִין, בְּשֶׁמֶן אֱגוֹזִים, בְּשֶׁמֶן צְנוֹנוֹת, בְּשֶׁמֶן דָּגִים, בְּשֶׁמֶן פַּקּוּעוֹת, בְּעִטְרָן וּבְנֵפְט. רַבִּי טַרְפוֹן אוֹמֵר, אֵין מַדְלִיקִין אֶלָּא בְשֶׁמֶן זַיִת בִּלְבָד:"}, {"kind": "text", "text": "כָּל הַיּוֹצֵא מִן הָעֵץ אֵין מַדְלִיקִין בּוֹ אֶלָּא פִשְׁתָּן. וְכָל הַיּוֹצֵא מִן הָעֵץ אֵינוֹ מִטַּמֵּא טֻמְאַת אֹהָלִים אֶלָּא פִשְׁתָּן. פְּתִילַת הַבֶּגֶד שֶׁקִּפְּלָהּ וְלֹא הִבְהֲבָהּ, רַבִּי אֱלִיעֶזֶר אוֹמֵר, טְמֵאָה, וְאֵין מַדְלִיקִין בָּהּ. רַבִּי עֲקִיבָא אוֹמֵר, טְהוֹרָה, וּמַדְלִיקִין בָּהּ:"}, {"kind": "text", "text": "לֹא יִקֹּב אָדָם שְׁפוֹפֶרֶת שֶׁל בֵּיצָה וִימַלְאֶנָּה שֶׁמֶן וְיִתְּנֶנָּה עַל פִּי הַנֵּר בִּשְׁבִיל שֶׁתְּהֵא מְנַטֶּפֶת, אֲפִלּוּ הִיא שֶׁל חֶרֶס. וְרַבִּי יְהוּדָה מַתִּיר. אֲבָל אִם חִבְּרָהּ הַיּוֹצֵר מִתְּחִלָּה, מֻתָּר, מִפְּנֵי שֶׁהוּא כְלִי אֶחָד. לֹא יְמַלֵּא אָדָם אֶת הַקְּעָרָה שֶׁמֶן וְיִתְּנֶנָּה בְצַד הַנֵּר וְיִתֵּן רֹאשׁ הַפְּתִילָה בְתוֹכָהּ, בִּשְׁבִיל שֶׁתְּהֵא שׁוֹאֶבֶת. וְרַבִּי יְהוּדָה מַתִּיר:"}, {"kind": "text", "text": "הַמְכַבֶּה אֶת הַנֵּר מִפְּנֵי שֶׁהוּא מִתְיָרֵא מִפְּנֵי גוֹיִם, מִפְּנֵי לִסְטִים, מִפְּנֵי רוּחַ רָעָה, וְאִם בִּשְׁבִיל הַחוֹלֶה שֶׁיִּישַׁן, פָּטוּר. כְּחָס עַל הַנֵּר, כְּחָס עַל הַשֶּׁמֶן, כְּחָס עַל הַפְּתִילָה, חַיָּב. וְרַבִּי יוֹסֵי פּוֹטֵר בְּכֻלָּן חוּץ מִן הַפְּתִילָה, מִפְּנֵי שֶׁהוּא עוֹשָׂהּ פֶּחָם:"}, {"kind": "text", "text": "עַל שָׁלשׁ עֲבֵרוֹת נָשִׁים מֵתוֹת בִּשְׁעַת לֵדָתָן, עַל שֶׁאֵינָן זְהִירוֹת בַּנִּדָּה וּבַחַלָּה וּבְהַדְלָקַת הַנֵּר:"}, {"kind": "text", "text": "שְׁלשָׁה דְבָרִים צָרִיךְ אָדָם לוֹמַר בְּתוֹךְ בֵּיתוֹ עֶרֶב שַׁבָּת עִם חֲשֵׁכָה. עִשַּׂרְתֶּם. עֵרַבְתֶּם. הַדְלִיקוּ אֶת הַנֵּר. סָפֵק חֲשֵׁכָה סָפֵק אֵין חֲשֵׁכָה, אֵין מְעַשְּׂרִין אֶת הַוַּדַּאי, וְאֵין מַטְבִּילִין אֶת הַכֵּלִים, וְאֵין מַדְלִיקִין אֶת הַנֵּרוֹת, אֲבָל מְעַשְּׂרִין אֶת הַדְּמַאי, וּמְעָרְבִין, וְטוֹמְנִין אֶת הַחַמִּין:"}, {"kind": "text", "text": "תַּנְיָא, חֲנַנְיָא אוֹמֵר: חַיָּיב אָדָם לְמַשְׁמֵשׁ בְּבִגְדוֹ עֶרֶב שַׁבָּת עִם חֲשֵׁכָה שֶׁמָּא יִשְׁכַּח וְיֵצֵא. אָמַר רַב יוֹסֵף: הִלְכְתָא רַבָּתִי לְשַׁבָּתָא."}, {"kind": "text", "text": "אָמַר רַבִּי אֶלְעָזָר אָמַר רַבִּי חֲנִינָא. תַּלְמִידֵי חֲכָמִים מַרְבִּים שָׁלוֹם בָּעוֹלָם. שֶׁנֶּאֱמַר וְכָל בָּנַֽיִךְ לִמּוּדֵי יְהֹוָה וְרַב שְׁלוֹם בָּנָֽיךְ: אַל תִּקְרֵי בָּנָֽיךְ אֶלָּא בּוֹנָֽיךְ: שָׁלוֹם רָב לְאֹהֲבֵי תוֹרָתֶֽךָ וְאֵין לָֽמוֹ מִכְשׁוֹל: יְהִי שָׁלוֹם בְּחֵילֵךְ שַׁלְוָה בְּאַרְמְּנוֹתָֽיךְ לְמַֽעַן אַחַי וְרֵעָי אֲדַבְּרָה נָא שָׁלוֹם בָּךְ: לְמַֽעַן בֵּית יְהֹוָה אֱלֹהֵֽינוּ אֲבַקְ֒שָׁה טוֹב לָךְ: יְהֹוָה עוֹז לְעַמּוֹ יִתֵּן יְהֹוָה יְבָרֵךְ אֶת־עַמּוֹ בַּשָּׁלוֹם:"}, {"kind": "header", "text": "קדיש דרבנן"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא (<b>אָמֵן</b>)"}, {"kind": "text", "text": "בְּעָלְ֒מָֽא דִּי־בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל־בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "text", "text": "<b>יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְ֒מֵי עָלְ֒מַיָּא</b>"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְקוּדְשָׁא <b>בְּרִיךְ הוּא</b>"}, {"kind": "text", "text": "לְעֵֽלָּא מִן־כָּל־ (בעשי\"ת לְעֵֽלָּא לְעֵֽלָּא מִכָּל) בִּרְכָתָֽא וְשִׁירָתָֽא תֻּשְׁבְּ֒חָתָֽא וְנֶחָמָתָֽא דַּאֲמִירָן בְּעָלְ֒מָֽא וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "text", "text": "עַל יִשְׂרָאֵל וְעַל רַבָּנָן וְעַל תַלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן. וְעַל כָּל מָאן דְּעָסְ֒קִין בְּאוֹרַיְתָא. דִּי בְאַתְרָא הָדֵין וְדִי בְכָל אֲתַר וַאֲתַר. יְהֵא לְהוֹן וּלְכוֹן שְׁלָמָא רַבָּא חִנָּא וְחִסְדָּא וְרַחֲמִין וְחַיִּין אֲרִיכִין וּמְזוֹנָא רְוִיחֵי וּפוּרְקָנָא מִן קֳדָם אֲבוּהוֹן דְבִשְׁמַיָּא (וְאַרְעָא) וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "text", "text": "יְהֵא שְׁלָמָֽא רַבָּֽא מִן־שְׁמַיָּֽא וְחַיִּים עָלֵֽינוּ וְעַל־כָּל־יִשְׂרָאֵל וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "text", "text": "עוֹשֶׂה שָׁלוֹם (בעשי\"ת הַשָּׁלוֹם) בִּמְרוֹמָיו הוּא יַעֲשֶׂה שָׁלוֹם עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "header", "text": "ברכו"}, {"kind": "text", "text": "חזן: <b>בָּרְ֒כוּ אֶת יְהֹוָה הַמְ֒בֹרָךְ:</b>"}, {"kind": "text", "text": "קהל וחזן: <b>בָּרוּךְ</b> יְהֹוָה הַמְ֒בֹרָךְ לְעוֹלָם וָעֶד:"}, {"kind": "header", "text": "המעריב ערבים"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם אֲשֶׁר בִּדְבָרוֹ מַעֲרִיב עֲרָבִים בְּחָכְמָה פּוֹתֵֽחַ שְׁעָרִים וּבִתְבוּנָה מְשַׁנֶּה עִתִּים וּמַחֲלִיף אֶת־הַזְּ֒מַנִּים וּמְסַדֵּר אֶת־הַכּוֹכָבִים בְּמִשְׁמְ֒רוֹתֵיהֶם בָּרָקִֽיעַ כִּרְצוֹנוֹ: בּוֹרֵא יוֹם וָלָֽיְלָה גּוֹלֵל אוֹר מִפְּ֒נֵי חֽשֶׁךְ וְחֽשֶׁךְ מִפְּ֒נֵי אוֹר וּמַעֲבִיר יוֹם וּמֵבִיא לָֽיְלָה וּמַבְדִּיל בֵּין יוֹם וּבֵין לָֽיְלָה יְהֹוָה צְבָאוֹת שְׁמוֹ: אֵל חַי וְקַיָּם תָּמִיד יִמְלֹךְ עָלֵֽינוּ לְעוֹלָם וָעֶד: בָּרוּךְ אַתָּה יְהֹוָה הַמַּעֲרִיב עֲרָבִים:"}, {"kind": "header", "text": "אהבת עולם"}, {"kind": "text", "text": "<b>אַהֲבַת</b> עוֹלָם בֵּית יִשְׂרָאֵל עַמְּ֒ךָ אָהָֽבְתָּ תּוֹרָה וּמִצְוֹת חֻקִּים וּמִשְׁפָּטִים אוֹתָֽנוּ לִמַּֽדְתָּ: עַל כֵּן יְהֹוָה אֱלֹהֵֽינוּ בְּשָׁכְבֵֽנוּ וּבְקוּמֵֽנוּ נָשִֽׂיחַ בְּחֻקֶּֽיךָ וְנִשְׂמַח בְּדִבְרֵי תוֹרָתֶֽךָ וּבְמִצְוֹתֶֽיךָ לְעוֹלָם וָעֶד: כִּי הֵם חַיֵּֽינוּ וְאֹֽרֶךְ יָמֵֽינוּ וּבָהֶם נֶהְגֶּה יוֹמָם וָלָֽיְלָה: וְאַהֲבָתְ֒ךָ אַל תָּסִיר מִמֶּֽנּוּ לְעוֹלָמִים: בָּרוּךְ אַתָּה יְהֹוָה אוֹהֵב עַמּוֹ יִשְׂרָאֵל:"}, {"kind": "header", "text": "שמע"}, {"kind": "text", "text": "יחיד אומר אֵל מֶֽלֶךְ נֶאֱמָן:"}, {"kind": "text", "text": "<b>שְׁמַע יִשְׂרָאֵל יְהֹוָה אֱלֹהֵֽינוּ יְהֹוָה אֶחָד:</b>"}, {"kind": "text", "text": "יש להפסיק מעט בין אחד לברוך כי עיקר קבול עול מלכות שמים היא פסוק ראשון. ויאמר בלחש:<br>בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "<b>וְאָהַבְתָּ</b> אֵת יְהֹוָה אֱלֹהֶֽיךָ בְּכָל֯־לְ֯בָבְ֒ךָ וּבְכָל־נַפְשְׁ֒ךָ וּבְכָל־מְאֹדֶֽךָ: וְהָיוּ הַדְּ֒בָרִים הָאֵֽלֶּה אֲשֶׁר֯ אָ֯נֹכִי מְצַוְּ֒ךָ הַיּוֹם עַל֯־לְ֯בָבֶֽךָ: וְשִׁנַּנְתָּם לְבָנֶֽיךָ וְדִבַּרְתָּ בָּם בְּשִׁבְתְּ֒ךָ בְּבֵיתֶֽךָ וּבְלֶכְתְּ֒ךָ בַדֶּֽרֶךְ וּבְשָׁכְבְּ֒ךָ וּבְקוּמֶֽךָ: וּקְשַׁרְתָּם לְאוֹת עַל֯־יָ֯דֶֽךָ וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶֽיךָ: וּכְתַבְתָּם עַל־מְזֻזוֹת בֵּיתֶֽךָ וּבִשְׁעָרֶֽיךָ:"}, {"kind": "text", "text": "<b>וְהָיָה</b> אִם־שָׁמֹֽעַ תִּשְׁמְעוּ אֶל־מִצְוֹתַי אֲשֶׁר֯ אָ֯נֹכִי מְצַוֶּה אֶתְ֒כֶם הַיּוֹם לְאַהֲבָה אֶת־יְהֹוָה אֱלֹהֵיכֶם וּלְעָבְ֒דוֹ בְּכָל־לְבַבְכֶם וּבְכָל־נַפְשְׁכֶם: וְנָתַתִּי מְטַר֯־אַ֯רְצְכֶם בְּעִתּוֹ יוֹרֶה וּמַלְקוֹשׁ וְאָסַפְתָּ דְגָנֶֽךָ וְתִירשְׁךָ וְיִצְהָרֶֽךָ: וְנָתַתִּי עֵֽשֶׂב֯ בְּ֯שָׂדְ֒ךָ לִבְ֒הֶמְתֶּֽךָ וְאָכַלְתָּ וְשָׂבָֽעְתָּ: הִשָּׁמְ֒רוּ לָכֶם פֶּן֯־יִ֯פְתֶּה לְבַבְכֶם וְסַרְתֶּם וַעֲבַדְתֶּם אֱלֹהִים֯ אֲ֯חֵרִים וְהִשְׁתַּחֲוִיתֶם לָהֶם: וְחָרָה אַף־יְהֹוָה בָּכֶם וְעָצַר֯ אֶ֯ת־הַשָּׁמַֽיִם וְלֹא֯־יִ֯הְיֶה מָטָר וְהָאֲדָמָה לֹא תִתֵּן אֶת֯־יְ֯בוּלָהּ וַאֲבַדְתֶּם֯ מְ֯הֵרָה מֵעַל הָאָֽרֶץ הַטֹּבָה אֲשֶׁר֯ יְ֯הֹוָה נֹתֵן לָכֶם: וְשַׂמְתֶּם֯ אֶ֯ת־דְּבָרַי֯ אֵֽ֯לֶּה עַל֯־לְ֯בַבְכֶם וְעַל־נַפְשְׁ֒כֶם וּקְשַׁרְתֶּם֯ אֹ֯תָם לְאוֹת עַל֯־יֶ֯דְ֒כֶם וְהָיוּ לְטוֹטָפֹת בֵּין עֵינֵיכֶם: וְלִמַּדְתֶּם֯ אֹ֯תָם אֶת־בְּנֵיכֶם לְדַבֵּר בָּם בְּשִׁבְתְּךָ בְּבֵיתֶֽךָ וּבְלֶכְתְּ֒ךָ בַדֶּֽרֶךְ וּבְשָׁכְבְּ֒ךָ וּבְקוּמֶֽךָ: וּכְתַבְתָּם עַל־מְזוּזוֹת בֵּיתֶֽךָ וּבִשְׁ֒עָרֶֽיךָ: לְמַֽעַן֯ יִ֯רְבּוּ יְמֵיכֶם וִימֵי בְנֵיכֶם עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע יְהֹוָה לַאֲבֹתֵיכֶם לָתֵת לָהֶם כִּימֵי הַשָּׁמַֽיִם עַל־הָאָֽרֶץ:"}, {"kind": "text", "text": "<b>וַֽיֹּאמֶר֯</b> יְהֹוָה◌֯ אֶ֯ל־משֶׁה לֵּאמֹר: דַּבֵּר֯ אֶ֯ל־בְּנֵי יִשְׂרָאֵל וְאָמַרְתָּ אֲלֵהֶם וְעָשׂוּ לָהֶם צִיצִת עַל־כַּנְפֵי בִגְ֒דֵיהֶם לְדֹרֹתָם וְנָתְ֒נוּ עַל־צִיצִת הַכָּנָף֯ פְּ֯תִיל תְּכֵֽלֶת: וְהָיָה לָכֶם לְצִיצִת וּרְאִיתֶם֯ אֹ֯תוֹ וּזְכַרְתֶּם֯ אֶ֯ת־כָּל־מִצְוֹת֯ יְ֯הֹוָה וַעֲשִׂיתֶם֯ אֹ֯תָם וְלֹא תָתֽוּרוּ אַחֲרֵי לְבַבְכֶם וְאַחֲרֵי עֵינֵיכֶם אֲשֶׁר֯־אַ֯תֶּם זֹנִים֯ אַ֯חֲרֵיהֶם: לְמַֽעַן תִּזְכְּרוּ וַעֲשִׂיתֶם֯ אֶ֯ת־כָּל־מִצְוֹתָי וִהְיִיתֶם קְדשִׁים לֵאלֹהֵיכֶם: אֲנִי יְהֹוָה אֱלֹהֵיכֶם֯ אֲ֯שֶׁר הוֹצֵֽאתִי אֶתְ֒כֶם֯ מֵ֯אֶֽרֶץ מִצְרַֽיִם לִהְיוֹת לָכֶם לֵאלֹהִים֯ אֲ֯נִי יְהֹוָה אֱלֹהֵיכֶם֯:<br>יש לצרף <b>אֱלֹהֵיכֶם</b> ל<b>אֱמֶת</b> אֱ֯מֶת"}, {"kind": "text", "text": "שליח ציבור: יְהֹוָה אֱלֹהֵיכֶם֯ אֱ֯מֶת:"}, {"kind": "header", "text": "אמת ואמונה"}, {"kind": "text", "text": "<b>וֶאֱמוּנָה</b> כָּל־זֹאת וְקַיָּם עָלֵֽינוּ כִּי הוּא יְהֹוָה אֱלֹהֵֽינוּ וְאֵין זוּלָתוֹ וַאֲנַֽחְנוּ יִשְׂרָאֵל עַמּוֹ: הַפּוֹדֵֽנוּ מִיַּד מְלָכִים מַלְכֵּֽנוּ הַגּוֹאֲלֵֽנוּ מִכַּף כָּל־הֶעָרִיצִים: הָאֵל הַנִּפְרָע לָֽנוּ מִצָּרֵֽינוּ וְהַמְשַׁלֵּם גְּמוּל לְכָל אֹיְ֒בֵי נַפְשֵֽׁנוּ: הָעֹשֶׂה גְדוֹלוֹת עַד־אֵין חֵֽקֶר וְנִפְלָאוֹת עַד־אֵין מִסְפָּר: הַשָּׂם נַפְשֵֽׁנוּ בַּחַיִּים וְלֹא־נָתַן לַמּוֹט רַגְלֵֽנוּ הַמַּדְרִיכֵֽנוּ עַל בָּמוֹת אֹיְ֒בֵֽינוּ וַיָּֽרֶם קַרְנֵֽנוּ עַל כָּל־שׂוֹנְ֒אֵֽינוּ: הָעֹֽשֶׂה לָּֽנוּ נִסִּים וּנְקָמָה בְּפַרְעֹה אוֹתוֹת וּמוֹפְ֒תִים בְּאַדְמַת בְּנֵי חָם: הַמַּכֶּה בְעֶבְרָתוֹ כָּל בְּכוֹרֵי מִצְרָֽיִם וַיּוֹצֵא אֶת־עַמּוֹ יִשְׂרָאֵל מִתּוֹכָם לְחֵרוּת עוֹלָם: הַמַּעֲבִיר בָּנָיו בֵּין גִּזְרֵי יַם סוּף אֶת־רוֹדְ֒פֵיהֶם וְאֶת־שׂוֹנְ֒אֵיהֶם בִּתְהוֹמוֹת טִבַּע: וְרָאוּ בָנָיו גְּבוּרָתוֹ שִׁבְּ֒חוּ וְהוֹדוּ לִשְׁמוֹ: וּמַלְכוּתוֹ בְרָצוֹן קִבְּ֒לוּ עֲלֵיהֶם משֶׁה וּבְנֵי יִשְׂרָאֵל לְךָ עָנוּ שִׁירָה בְּשִׂמְחָה רַבָּה וְאָמְ֒רוּ כֻלָּם:"}, {"kind": "text", "text": "<b>מִי כָמֹֽכָה</b> בָּאֵלִם יְהֹוָה מִי כָּמֹֽכָה נֶאְדָּר בַּקֹּֽדֶשׁ נוֹרָא תְהִלֹּת עֹֽשֵׂה פֶֽלֶא: מַלְכוּתְךָ רָאוּ בָנֶֽיךָ בּוֹקֵֽעַ יָם לִפְנֵי משֶׁה זֶה אֵלִי עָנוּ וְאָמְ֒רוּ:"}, {"kind": "text", "text": "<b>יְהֹוָה</b> יִמְלֹךְ לְעֹלָם וָעֶד: וְנֶאֱמַר כִּי־פָדָה יְהֹוָה אֶת יַעֲקֹב וּגְאָלוֹ מִיַּד חָזָק מִמֶּֽנּוּ. בָּרוּךְ אַתָּה יְהֹוָה גָּאַל יִשְׂרָאֵל:"}, {"kind": "header", "text": "השכיבינו"}, {"kind": "text", "text": "<b>הַשְׁכִּיבֵֽנוּ</b> יְהֹוָה אֱלֹהֵֽינוּ לְשָׁלוֹם וְהַעֲמִידֵֽנוּ מַלְכֵּֽנוּ לְחַיִּים וּפְרוֹשׂ עָלֵֽינוּ סֻכַּת שְׁלוֹמֶֽךָ וְתַקְּ֒נֵֽנוּ בְּעֵצָה טוֹבָה מִלְּ֒פָנֶֽיךָ וְהוֹשִׁיעֵֽנוּ לְמַֽעַן שְׁמֶֽךָ וְהָגֵן בַּעֲדֵֽנוּ וְהָסֵר מֵעָלֵֽינוּ אוֹיֵב דֶּֽבֶר וְחֶֽרֶב וְרָעָב וְיָגוֹן וְהָסֵר שָׂטָן מִלְּ֒פָנֵֽינוּ וּמֵאַחֲרֵֽינוּ וּבְצֵל כְּנָפֶֽיךָ תַּסְתִּירֵֽנוּ כִּי אֵל שׁוֹמְ֒רֵֽנוּ וּמַצִּילֵֽנוּ אָֽתָּה כִּי אֵל מֶֽלֶךְ חַנּוּן וְרַחוּם אָֽתָּה וּשְׁמוֹר צֵאתֵֽנוּ וּבוֹאֵֽנוּ לְחַיִּים וּלְשָׁלוֹם מֵעַתָּה וְעַד עוֹלָם: וּפְרוֹשׂ עָלֵֽינוּ סֻכַּת שְׁלוֹמֶךָ: בָּרוּךְ אַתָּה יְהֹוָה הַפּוֹרֵשׂ סֻכַּת שָׁלוֹם עָלֵֽינוּ וְעַל כָּל עַמּוֹ יִשְׂרָאֵל וְעַל יְרוּשָׁלָֽיִם:"}, {"kind": "header", "text": "ושמרו"}, {"kind": "text", "text": "לשבת: וְשָׁמְ֒רוּ בְנֵי־יִשְׂרָאֵל אֶת־הַשַּׁבָּת. לַעֲשׂוֹת אֶת־הַשַּׁבָּת לְדֹרֹתָם בְּרִית עוֹלָם: בֵּינִי וּבֵין בְּנֵי יִשְׂרָאֵל אוֹת הִיא לְעֹלָם. כִּי־שֵֽׁשֶׁת יָמִים עָשָׂה יְהֹוָה אֶת־הַשָּׁמַֽיִם וְאֶת־הָאָֽרֶץ וּבַיּוֹם הַשְּׁ֒בִיעִי שָׁבַת וַיִּנָּפַשׁ:"}, {"kind": "text", "text": "לשלש רגלים: וַיְדַבֵּר משֶׁה אֶת מוֹעֲדֵי יְהֹוָה אֶל בְּנֵי יִשְׂרָאֵל:"}, {"kind": "header", "text": "חצי קדיש"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא (<b>אָמֵן</b>) בְּעָלְ֒מָֽא דִּי־בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל־בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב וְאִמְרוּ <b>אָמֵן</b>: <b>יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְ֒מֵי עָלְ֒מַיָּא</b> יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְקוּדְשָׁא <b>בְּרִיךְ הוּא</b> לְעֵֽלָּא מִן־כָּל־ (בעשי\"ת לְעֵֽלָּא לְעֵֽלָּא מִכָּל) בִּרְכָתָֽא וְשִׁירָתָֽא תֻּשְׁבְּ֒חָתָֽא וְנֶחָמָתָֽא דַּאֲמִירָן בְּעָלְ֒מָֽא וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "header", "text": "אבות"}, {"kind": "text", "text": "אֲדֹנָי שְׂפָתַי תִּפְתָּח וּפִי יַגִּיד תְּהִלָּתֶֽךָ:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ אֱלֹהֵי אַבְרָהָם אֱלֹהֵי יִצְחָק וֵאלֹהֵי יַעֲקֹב הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא אֵל עֶלְיוֹן גּוֹמֵל חֲסָדִים טוֹבִים וְקוֹנֵה הַכֹּל וְזוֹכֵר חַסְדֵי אָבוֹת וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַֽעַן שְׁמוֹ בְּאַהֲבָה:"}, {"kind": "text", "text": "בעשי\"ת: זָכְרֵֽנוּ לְחַיִּים מֶֽלֶךְ חָפֵץ בַּחַיִּים וְכָתְבֵֽנוּ בְּסֵֽפֶר הַחַיִּים לְמַעַנְךָ אֱלֹהִים חַיִּים:"}, {"kind": "text", "text": "מֶֽלֶךְ עוֹזֵר וּמוֹשִֽׁיעַ וּמָגֵן: בָּרוּךְ אַתָּה יְהֹוָה מָגֵן אַבְרָהָם:"}, {"kind": "header", "text": "גבורות"}, {"kind": "text", "text": "<b>אַתָּה גִבּוֹר</b> לְעוֹלָם אֲדֹנָי מְחַיֶּה מֵתִים אַתָּה רַב לְהוֹשִֽׁיעַ:"}, {"kind": "text", "text": "בחורף: מַשִּׁיב הָרֽוּחַ וּמוֹרִיד הַגֶּֽשֶׁם: בקיץ: מוֹרִיד הַטָּל"}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶֽסֶד מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים סוֹמֵךְ נוֹפְ֒לִים וְרוֹפֵא חוֹלִים וּמַתִּיר אֲסוּרִים וּמְקַיֵּם אֱמוּנָתוֹ לִישֵׁנֵי עָפָר, מִי כָמֽוֹךָ בַּֽעַל גְּבוּרוֹת וּמִי דּֽוֹמֶה לָּךְ מֶֽלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִֽיחַ יְשׁוּעָה:"}, {"kind": "text", "text": "בעשי\"ת: מִי כָמֽוֹךָ אַב הָרַחֲמִים זוֹכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים:"}, {"kind": "text", "text": "וְנֶאֱמָן אַתָּה לְהַחֲיוֹת מֵתִים: בָּרוּךְ אַתָּה יְהֹוָה מְחַיֵּה הַמֵּתִים:"}, {"kind": "header", "text": "קדושת השם"}, {"kind": "text", "text": "<b>אַתָּה קָדוֹשׁ</b> וְשִׁמְךָ קָדוֹשׁ וּקְדוֹשִׁים בְּכָל־יוֹם יְהַלְלֽוּךָ סֶּֽלָה. בָּרוּךְ אַתָּה יְהֹוָה הָאֵל הַקָּדוֹשׁ: בעשי\"ת מסיים: בָּרוּךְ אַתָּה יְהֹוָה הַמֶּֽלֶךְ הַקָּדוֹשׁ:"}, {"kind": "header", "text": "קדושת היום"}, {"kind": "text", "text": "אַתָּה קִדַּֽשְׁתָּ אֶת יוֹם הַשְּׁ֒בִיעִי לִשְׁמֶךָ. תַּכְלִית מַעֲשֵׂה שָׁמַֽיִם וָאָֽרֶץ. וּבֵרַכְתּוֹ מִכָּל הַיָּמִים. וְקִדַּשְׁתּוֹ מִכָּל הַזְּ֒מַנִּים וְכֵן כָּתוּב בְּתוֹרָתֶֽךָ:"}, {"kind": "text", "text": "וַיְכֻלּוּ הַשָּׁמַֽיִם וְהָאָֽרֶץ וְכָל־צְבָאָם: וַיְכַל אֱלֹהִים בַּיּוֹם הַשְּׁ֒בִיעִי מְלַאכְתּוֹ אֲשֶׁר עָשָׂה. וַיִּשְׁבֹּת בַּיּוֹם הַשְּׁ֒בִיעִי מִכָּל־מְלַאכְתּוֹ אֲשֶׁר עָשָׂה: וַיְבָֽרֶךְ אֱלֹהִים אֶת־יוֹם הַשְּׁ֒בִיעִי וַיְקַדֵּשׁ אֹתוֹ. כִּי בוֹ שָׁבַת מִכָּל־מְלַאכְתּוֹ אֲשֶׁר־בָּרָא אֱלֹהִים לַעֲשׂוֹת:"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ רְצֵה בִמְנוּחָתֵֽנוּ. קַדְּ֒שֵֽׁנוּ בְּמִצְוֹתֶֽיךָ וְתֵן חֶלְקֵֽנוּ בְּתוֹרָתֶֽךָ שַׂבְּ֒עֵֽנוּ מִטּוּבֶֽךָ. וְשַׂמְּחֵנוּ בִּישׁוּעָתֶֽךָ. וְטַהֵר לִבֵּֽנוּ לְעָבְדְּ֒ךָ בֶּאֱמֶת. וְהַנְחִילֵֽנוּ יְהֹוָה אֱלֹהֵֽינוּ בְּאַהֲבָה וּבְרָצוֹן שַׁבַּת קָדְשֶֽׁךָ. וְיָנֽוּחוּ בָהּ יִשְׂרָאֵל מְקַדְּ֒שֵׁי שְׁמֶֽךָ. בָּרוּךְ אַתָּה יְהֹוָה מְקַדֵּשׁ הַשַּׁבָּת:"}, {"kind": "header", "text": "עבודה"}, {"kind": "text", "text": "<b>רְצֵה</b> יְהֹוָה אֱלֹהֵֽינוּ בְּעַמְּךָ יִשְׂרָאֵל וּבִתְפִלָּתָם וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶֽךָ וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּֽךָ:"}, {"kind": "text", "text": "בראש חדש ובחול המועד אומרים זה:<br><b>אֱלֹהֵֽינוּ</b> וֵאלֹהֵי אֲבוֹתֵֽינוּ. יַעֲלֶה וְיָבֹא וְיַגִּֽיעַ וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵֽנוּ וּפִקְדוֹנֵֽנוּ וְזִכְרוֹן אֲבוֹתֵֽינוּ. וְזִכְרוֹן מָשִֽׁיחַ בֶּן דָּוִד עַבְדֶּֽךָ. וְזִכְרוֹן יְרוּשָׁלַֽיִם עִיר קָדְשֶֽׁךָ. וְזִכְרוֹן כָּל עַמְּ֒ךָ בֵּית יִשְׂרָאֵל לְפָנֶֽיךָ. לִפְלֵיטָה לְטוֹבָה לְחֵן וּלְחֶֽסֶד וּלְרַחֲמִים לְחַיִּים וּלְשָׁלוֹם. בְּיוֹם לר\"ח: רֹאשׁ הַחֹֽדֶשׁ הַזֶּה: לפסח: חַג הַמַּצּוֹת הַזֶּה: לסכות: חַג הַסֻּכּוֹת הַזֶּה: זָכְרֵֽנוּ יְהֹוָה אֱלֹהֵֽינוּ בּוֹ לְטוֹבָה. וּפָקְדֵֽנוּ בוֹ לִבְרָכָה. וְהוֹשִׁיעֵֽנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּֽנוּ וְרַחֵם עָלֵֽינוּ וְהוֹשִׁיעֵֽנוּ. כִּי אֵלֶֽיךָ עֵינֵֽינוּ כִּי אֵל מֶֽלֶךְ חַנּוּן וְרַחוּם אָֽתָּה:"}, {"kind": "text", "text": "וְתֶחֱזֶֽינָה עֵינֵֽינוּ בְּשׁוּבְ֒ךָ לְצִיּוֹן בְּרַחֲמִים: בָּרוּךְ אַתָּה יְהֹוָה הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן:"}, {"kind": "header", "text": "מודים"}, {"kind": "text", "text": "<b>מוֹדִים</b> אֲנַֽחְנוּ לָךְ שָׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ לְעוֹלָם וָעֶד צוּר חַיֵּֽינוּ מָגֵן יִשְׁעֵֽנוּ אַתָּה הוּא לְדוֹר וָדוֹר נֽוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶֽךָ עַל־חַיֵּֽינוּ הַמְּסוּרִים בְּיָדֶֽךָ וְעַל נִשְׁמוֹתֵֽינוּ הַפְּקוּדוֹת לָךְ וְעַל נִסֶּֽיךָ שֶׁבְּכָל יוֹם עִמָּֽנוּ וְעַל נִפְלְאוֹתֶֽיךָ וְטוֹבוֹתֶֽיךָ שֶׁבְּכָל עֵת עֶֽרֶב וָבֹֽקֶר וְצָהֳרָֽיִם הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶֽיךָ וְהַמְרַחֵם כִּי לֹא תַֽמּוּ חֲסָדֶֽיךָ מֵעוֹלָם קִוִּֽינוּ לָךְ:"}, {"kind": "instruction", "text": "בחנוכה ופורים אומרים כאן ועל הנסים<br>עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּ֒בוּרוֹת וְעַל הַתְּ֒שׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִֽׂיתָ לַאֲבוֹתֵֽינוּ בַּיָּמִים הָהֵם בִּזְּ֒מַן הַזֶּה:"}, {"kind": "text", "text": "בחנוכה: <b>בִּימֵי מַתִּתְיָֽהוּ</b> בֶּן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאִי וּבָנָיו כְּשֶׁעָמְ֒דָה מַלְכוּת יָוָן הָרְ֒שָׁעָה עַל־עַמְּ֒ךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶֽךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶֽךָ, וְאַתָּה בְּרַחֲמֶֽיךָ הָרַבִּים עָמַֽדְתָּ לָהֶם בְּעֵת צָרָתָם רַֽבְתָּ אֶת־רִיבָם דַּֽנְתָּ אֶת־דִּינָם נָקַֽמְתָּ אֶת־נִקְמָתָם מָסַֽרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים וְרַבִּים בְּיַד מְעַטִּים וּטְמֵאִים בְּיַד טְהוֹרִים וּרְשָׁעִים בְּיַד צַדִּיקִים וְזֵדִים בְּיַד עוֹסְ֒קֵי תוֹרָתֶֽךָ וּלְךָ עָשִֽׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶֽךָ וּלְעַמְּ֒ךָ יִשְׂרָאֵל עָשִֽׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה וְאַחַר־כֵּן בָּֽאוּ בָנֶֽיךָ לִדְבִיר בֵּיתֶֽךָ וּפִנּוּ אֶת־הֵיכָלֶֽךָ וְטִהֲרוּ אֶת־מִקְדָּשֶֽׁךָ וְהִדְלִֽיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶֽׁךָ וְקָבְ֒עוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵֽלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל:"}, {"kind": "text", "text": "בפורים: <b>בִּימֵי מָרְדְּ֒כַי וְאֶסְתֵּר</b> בְּשׁוּשַׁן הַבִּירָה כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת־כָּל־הַיְּהוּדִים מִנַּֽעַר וְעַד־זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד בִּשְׁלוֹשָׁה עָשָׂר לְחֹֽדֶשׁ שְׁנֵים־עָשָׂר הוּא־חֹֽדֶשׁ אֲדָר וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶֽיךָ הָרַבִּים הֵפַֽרְתָּ אֶת־עֲצָתוֹ וְקִלְקַֽלְתָּ אֶת־מַחֲשַׁבְתּוֹ וַהֲשֵׁבֽוֹתָ לּוֹ גְּמוּלוֹ בְּרֹאשׁוֹ וְתָלוּ אוֹתוֹ וְאֶת־בָּנָיו עַל־הָעֵץ (וְעָשִׂיתָ עמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הָגָּדוֹל סֶלָה):"}, {"kind": "text", "text": "<b>וְעַל־כֻּלָּם</b> יִתְבָּרַךְ וְיִתְרוֹמַם שִׁמְךָ מַלְכֵּֽנוּ תָּמִיד לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "בעשי\"ת: וּכְתוֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶֽךָ:"}, {"kind": "text", "text": "<b>וְכֹל הַחַיִּים</b> יוֹדֽוּךָ סֶּֽלָה וִיהַלְ֒לוּ אֶת־שִׁמְךָ בֶּאֱמֶת הָאֵל יְשׁוּעָתֵֽנוּ וְעֶזְרָתֵֽנוּ סֶֽלָה: בָּרוּךְ אַתָּה יְהֹוָה הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת:"}, {"kind": "header", "text": "שלום רב"}, {"kind": "text", "text": "<b>שָׁלוֹם רָב</b> עַל יִשְׂרָאֵל עַמְּ֒ךָ תָּשִׂים לְעוֹלָם כִּי אַתָּה הוּא מֶֽלֶךְ אָדוֹן לְכָל־הַשָּׁלוֹם וְטוֹב בְּעֵינֶֽיךָ לְבָרֵךְ אֶת־עַמְּ֒ךָ יִשְׂרָאֵל בְּכָל־עֵת וּבְכָל־שָׁעָה בִּשְׁלוֹמֶֽךָ."}, {"kind": "text", "text": "בעשי\"ת: בְּסֵֽפֶר חַיִּים בְּרָכָה וְשָׁלוֹם וּפַרְנָסָה טוֹבָה נִזָּכֵר וְנִכָּתֵב לְפָנֶֽיךָ אֲנַֽחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל לְחַיִּים טוֹבִים וּלְשָׁלוֹם: (בָּרוּךְ אַתָּה יְהֹוָה עֹשֶׂה הַשָּׁלוֹם:)"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה הַמְבָרֵךְ אֶת־עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם:"}, {"kind": "header", "text": "אלהי נצור"}, {"kind": "text", "text": "יִהְיוּ לְרָצוֹן אִמְ֒רֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶֽיךָ יְהֹוָה צוּרִי וְגוֹאֲלִי:"}, {"kind": "text", "text": "<b>אֱלֹהַי</b> נְצוֹר לְשׁוֹנִי מֵרָע וּשְׂפָתַי מִדַּבֵּר מִרְמָה. וְלִמְקַלְלַי נַפְשִׁי תִדּוֹם וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה. פְּתַח לִבִּי בְּתוֹרָתֶֽךָ וּבְמִצְוֹתֶֽיךָ תִּרְדֹּף נַפְשִׁי. וְכֹל הַחוֹשְׁבִים עָלַי רָעָה מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחֲשַׁבְתָּם: עֲשֵׂה לְמַֽעַן שְׁמֶֽךָ עֲשֵׂה לְמַֽעַן יְמִינֶֽךָ עֲשֵׂה לְמַֽעַן קְדֻשָּׁתֶֽךָ עֲשֵׂה לְמַֽעַן תּוֹרָתֶֽךָ. לְמַֽעַן יֵחָלְצוּן יְדִידֶֽיךָ הוֹשִֽׁיעָה יְמִינְךָ וַעֲנֵֽנִי: יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶֽיךָ יְהֹוָה צוּרִי וְגוֹאֲלִי:"}, {"kind": "text", "text": "עֹשֶׂה (בעשי\"ת הַשָּׁלוֹם) שָׁלוֹם בִּמְרוֹמָיו הוּא יַעֲשֶׂה שָׁלוֹם עָלֵֽינוּ וְעַל כָּל־יִשְׂרָאֵל וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "<b>יְהִי רָצוֹן</b> מִלְּ֒פָנֶֽיךָ יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵֽינוּ וְתֵן חֶלְקֵֽנוּ בְּתוֹרָתֶֽךָ: וְשָׁם נַעֲבָדְ֒ךָ בְּיִרְאָה כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּוֹת: וְעָרְ֒בָה לַיהוָֹה מִנְחַת יְהוּדָה וִירוּשָׁלָֽםִ כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיּוֹת:"}, {"kind": "header", "text": "ויכולו"}, {"kind": "instruction", "text": "הש\"ץ והקהל אומרים ויכלו"}, {"kind": "text", "text": "וַיְכֻלּוּ הַשָּׁמַֽיִם וְהָאָֽרֶץ וְכָל־צְבָאָם: וַיְכַל אֱלֹהִים בַּיּוֹם הַשְּׁ֒בִיעִי מְלַאכְתּוֹ אֲשֶׁר עָשָׂה. וַיִּשְׁבֹּת בַּיּוֹם הַשְּׁ֒בִיעִי מִכָּל־מְלַאכְתּוֹ אֲשֶׁר עָשָׂה: וַיְבָֽרֶךְ אֱלֹהִים אֶת־יוֹם הַשְּׁ֒בִיעִי וַיְקַדֵּשׁ אֹתוֹ. כִּי בוֹ שָׁבַת מִכָּל־מְלַאכְתּוֹ אֲשֶׁר־בָּרָא אֱלֹהִים לַעֲשׂוֹת:"}, {"kind": "header", "text": "ברכה אחת מעין שבע"}, {"kind": "instruction", "text": "אין החזן מחזיר התפלה עצמה אבל חוזר מעין שבע משום י\"ט שחל בשבת שא\"א בו ויכולו. גם להוציא שאינו בקי. וצריך לאומרו בעמידה כעדות."}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ אֱלֹהֵי אַבְרָהָם אֱלֹהֵי יִצְחָק וֵאלֹהֵי יַעֲקֹב הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא. אֵל עֶלְיוֹן קוֹנֵה שָׁמַֽיִם וָאָֽרֶץ:"}, {"kind": "instruction", "text": "מעין ז' יאמרו הקהל בלי פתיחה וחתימה. וכן היחיד אומרו."}, {"kind": "text", "text": "מָגֵן אָבוֹת בִּדְבָרוֹ. מְחַיֵּה מֵתִים בְּמַאֲמָרוֹ. הָאֵל הַקָּדוֹשׁ (הַמֶּלֶךְ הַקָּדוֹשׁ) שֶׁאֵין כָּמֽוֹהוּ. הַמֵּנִֽיחַ לְעַמּוֹ בְּיוֹם שַׁבַּת קָדְשׁוֹ. כִּי בָם רָצָה לְהָנִֽיחַ לָהֶם. לְפָנָיו נַעֲבוֹד בְּיִרְאָה וָפַֽחַד. וְנוֹדֶה לִשְׁמוֹ בְּכָל יוֹם תָּמִיד מֵעֵין הַבְּ֒רָכוֹת: אֵל הַהוֹדָאוֹת. אֲדוֹן הַשָּׁלוֹם. מְקַדֵּשׁ הַשַּׁבָּת וּמְבָרֵךְ שְׁבִיעִי. וּמֵנִֽיחַ בִּקְדֻשָּׁה לְעַם מְדֻשְּׁ֒נֵי עֹֽנֶג זֵֽכֶר לְמַעֲשֵׂה בְרֵאשִׁית:"}, {"kind": "text", "text": "אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ רְצֵה בִמְנוּחָתֵֽנוּ. קַדְּ֒שֵֽׁנוּ בְּמִצְוֹתֶֽיךָ וְתֵן חֶלְקֵֽנוּ בְּתוֹרָתֶֽךָ שַׂבְּ֒עֵֽנוּ מִטּוּבֶֽךָ. וְשַׂמְּחֵנוּ בִּישׁוּעָתֶֽךָ. וְטַהֵר לִבֵּֽנוּ לְעָבְדְּ֒ךָ בֶּאֱמֶת. וְהַנְחִילֵֽנוּ יְהֹוָה אֱלֹהֵֽינוּ בְּאַהֲבָה וּבְרָצוֹן שַׁבַּת קָדְשֶֽׁךָ. וְיָנֽוּחוּ בָהּ יִשְׂרָאֵל מְקַדְּ֒שֵׁי שְׁמֶֽךָ. בָּרוּךְ אַתָּה יְהֹוָה מְקַדֵּשׁ הַשַּׁבָּת:"}, {"kind": "header", "text": "קדיש שלם"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא (<b>אָמֵן</b>)"}, {"kind": "text", "text": "בְּעָלְ֒מָֽא דִּי־בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל־בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "text", "text": "<b>יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְ֒מֵי עָלְ֒מַיָּא</b>"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְקוּדְשָׁא <b>בְּרִיךְ הוּא</b>"}, {"kind": "text", "text": "לְעֵֽלָּא מִן־כָּל־ (בעשי\"ת לְעֵֽלָּא לְעֵֽלָּא מִכָּל) בִּרְכָתָֽא וְשִׁירָתָֽא תֻּשְׁבְּ֒חָתָֽא וְנֶחָמָתָֽא דַּאֲמִירָן בְּעָלְ֒מָֽא וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "text", "text": "תִּתְקַבֵּל צְלוֹתְ֒הוֹן וּבָעוּתְ֒הוֹן דְּכָל בֵּית יִשְׂרָאֵל קֳדָם אֲבוּהוֹן דִּי בִשְׁ֒מַיָּא וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁלָמָֽא רַבָּֽא מִן־שְׁמַיָּֽא וְחַיִּים עָלֵֽינוּ וְעַל־כָּל־יִשְׂרָאֵל וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "text", "text": "עוֹשֶׂה שָׁלוֹם (בעשי\"ת הַשָּׁלוֹם) בִּמְרוֹמָיו הוּא יַעֲשֶׂה שָׁלוֹם עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "header", "text": "ספירת העומר"}, {"kind": "instruction", "text": "ערבית אחר התפלה מתחילין לספור העומר שזמנו מתחלת ליל ט\"ז בניסן ומונה והולך מ\"ט יום. שכח לספור בתחלת הלילה הולך וסופר כל הלילה. ומצוה על כל אחד ואחד לספור לעצמו. וצריך לספור מעומד ולברך תחלה. וסופר הימים והשבועות כיצד ביום הראשון עומד ומברך על ספירת העומר היום יום אחד עד שמגיע לשבעה ימים ואז יאמר היום שבעה ימים שהם שבוע אחד וביום שמונה יאמר היום שמונה ימים שהם שבוע אחד ויום אחד עד שיגיע לי\"ד יאמר היום ארבעה עשר ימים שהם ב' שבועות וכן לעולם. (טור או\"ח תפ\"ט). ועתה בעונותינו שנתבטלה הבאת העומר אין הספירה מן התורה אלא מדרבנן זכר למקדש. ואם נסתפק לו אם מנה או לא מנה חוזר ומונה בלא ברכה. (אבודרהם)."}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם אֲשֶׁר קִדְּ֒שָֽׁנוּ בְּמִצְוֹתָיו וְצִוָּֽנוּ עַל סְפִירַת הָעֹֽמֶר:"}, {"kind": "text", "text": "הַיּוֹם [...]"}, {"kind": "text", "text": "<b>הָרַחֲמָן</b> הוּא יַחֲזִיר לָנוּ עֲבוֹדַת בֵּית הַמִּקְדָּשׁ לִמְקוֹמָהּ בִּמְהֵרָה בְּיָמֵֽינוּ אָמֵן סֶֽלָה:"}, {"kind": "text", "text": "<b>לַמְנַצֵּֽחַ</b> בִּנְגִינוֹת מִזְמוֹר שִׁיר: אֱלֹהִים יְחָנֵּֽנוּ וִיבָרְ֒כֵֽנוּ יָאֵר פָּנָיו אִתָּֽנוּ סֶֽלָה: לָדַֽעַת בָּאָֽרֶץ דַּרְכֶּֽךָ בְּכָל גּוֹיִם יְשׁוּעָתֶֽךָ: יוֹדֽוּךָ עַמִּים אֱלֹהִים יוֹדֽוּךָ עַמִּים כֻּלָּם: יִשְׂמְ֒חוּ וִירַנְּ֒נוּ לְאֻמִּים כִּי תִשְׁפּוֹט עַמִּים מִישׁוֹר וּלְאֻמִּים בָּאָֽרֶץ תַּנְחֵם סֶֽלָה: יוֹדֽוּךָ עַמִּים אֱלֹהִים יוֹדֽוּךָ עַמִּים כֻּלָּם: אֶֽרֶץ נָתְ֒נָה יְבוּלָהּ יְבָרְ֒כֵֽנוּ אֱלֹהִים אֱלֹהֵֽינוּ: יְבָרְ֒כֵֽנוּ אֱלֹהִים וְיִירְ֒אוּ אוֹתוֹ כָּל אַפְסֵי אָֽרֶץ:"}, {"kind": "text", "text": "<b>אָֽנָּא</b> בְּכֹֽחַ גְּדֻלַּת יְמִינְ֒ךָ תַּתִּיר צְרוּרָה:"}, {"kind": "text", "text": "קַבֵּל רִנַּת עַמְּ֒ךָ שַׂגְּ֒בֵֽנוּ טַהֲרֵֽנוּ נוֹרָא:"}, {"kind": "text", "text": "נָא גִבּוֹר דּוֹרְ֒שֵׁי יִחוּדְ֒ךָ כְּבָבַת שָׁמְרֵם:"}, {"kind": "text", "text": "בָּרְכֵם טַהֲרֵם רַחֲמֵם צִדְקָתְ֒ךָ תָּמִיד גָּמְלֵם:"}, {"kind": "text", "text": "חֲסִין קָדוֹשׁ בְּרֹב טוּבְ֒ךָ נַהֵל עֲדָתֶֽךָ:"}, {"kind": "text", "text": "יָחִיד גֵּאֶה לְעַמְּ֒ךָ פְּנֵה זוֹכְ֒רֵי קְדֻשָּׁתֶֽךָ:"}, {"kind": "text", "text": "שַׁוְעָתֵֽנוּ קַבֵּל וּשְׁמַע צַעֲקָתֵֽנוּ יוֹדֵֽעַ תַּעֲלוּמוֹת:"}, {"kind": "text", "text": "בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "<b>רִבּוֹנוֹ</b> שֶׁל עוֹלָם אַתָּה צִוִּיתָֽנוּ עַל יְדֵי משֶׁה עַבְדֶּֽךָ לִסְפֹּר סְפִירַת הָֽעֹמֶר כְּדֵי לְטַהֲרֵֽנוּ מִקְּ֒לִפּוֹתֵֽינוּ וּמִטֻּמְאוֹתֵֽינוּ כְּמוֹ שֶׁכָּתַֽבְתָּ בְּתוֹרָתֶֽךָ וּסְפַרְתֶּם לָכֶם מִמָּחֳרַת הַשַּׁבָּת מִיּוֹם הֲבִיאֲכֶם אֶת־עֹֽמֶר הַתְּ֒נוּפָה שֶֽׁבַע שַׁבָּתוֹת תְּמִימוֹת תִּהְיֶֽינָה עַד מִמָּחֳרַת הַשַּׁבָּת הַשְּׁ֒בִיעִית תִּסְפְּ֒רוּ חֲמִשִּׁים יוֹם כְּדֵי שֶׁיִּטָּהֲרוּ נַפְשׁוֹת עַמְּ֒ךָ יִשְׂרָאֵל מִזֻּהֲמָתָם: וּבְכֵן יְהִי רָצוֹן מִלְּ֒פָנֶֽיךָ יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ שֶׁבִּזְכוּת סְפִירַת הָעֹֽמֶר שֶׁסָּפַֽרְתִּי הַיּוֹם יְתֻקַּן מַה שֶּׁפָּגַֽמְתִּי בִּסְפִירָה (השייכת לאותו הלילה) וְאֶטָּהֵר וְאֶתְקַדֵּשׁ בִּקְדֻשָּׁה שֶׁל מַֽעְלָה וְעַל יְדֵי זֶה יֻשְׁפַּע שֶֽׁפַע רַב בְּכָל־הָעוֹלָמוֹת וּלְתַקֵּן אֶת־נַפְשׁוֹתֵֽינוּ וְרוּחוֹתֵֽינוּ וְנִשְׁמוֹתֵֽינוּ מִכָּל־סִיג וּפְגַם וּלְטַהֲרֵֽנוּ וּלְקַדְּ֒שֵֽׁנוּ בִּקְדֻשָּׁתְ֒ךָ הָעֶלְיוֹנָה אָמֵן סֶֽלָה:"}, {"kind": "header", "text": "עלינו"}, {"kind": "text", "text": "<b>עָלֵֽינוּ</b> לְשַׁבֵּֽחַ לַאֲדוֹן הַכֹּל לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית שֶׁלֺּא עָשָֽׂנוּ כְּגוֹיֵי הָאֲרָצוֹת וְלֺא שָׂמָֽנוּ כְּמִשְׁפְּחוֹת הָאֲדָמָה שֶׁלֺּא שָׂם חֶלְקֵֽנוּ כָּהֶם וְגוֹרָלֵֽנוּ כְּכָל הֲמוֹנָם: שֶׁהֵם מִשְׁתַּחֲוִים לָהֶֽבֶל וָרִיק וּמִתְפַּלְּ֒לִים אֶל אֵל לֹא יוֹשִֽׁיעַ, וַאֲנַֽחְנוּ כּוֹרְ֒עִים וּמִשְׁתַּחֲוִים וּמוֹדִים לִפְנֵי מֶֽלֶךְ מַלְכֵי הַמְּ֒לָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַֽיִם וְיוֹסֵד אָֽרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַֽיִם מִמַּֽעַל, וּשְׁ֒כִינַת עֻזּוֹ בְּגָבְ֒הֵי מְרוֹמִים, הוּא אֱלֺהֵֽינוּ אֵין עוֹד, אֱמֶת מַלְכֵּֽנוּ אֶֽפֶס זוּלָתוֹ כַּכָּתוּב בְּתוֹרָתוֹ וְיָדַעְתָּ הַיּוֹם וַהֲשֵׁבֹתָ אֶל לְבָבֶֽךָ כִּי יְהֹוָה הוּא הָאֱלֺהִים בַּשָּׁמַֽיִם מִמַּֽעַל וְעַל הָאָֽרֶץ מִתָּֽחַת אֵין עוֹד:"}, {"kind": "text", "text": "<b>עַל כֵּן</b> נְקַוֶּה לְךָ יְהֹוָה אֱלֺהֵֽינוּ לִרְאוֹת מְהֵרָה בְּתִפְאֶֽרֶת עֻזֶּֽךָ לְהַעֲבִיר גִּלּוּלִים מִן הָאָֽרֶץ וְהָאֱלִילִים כָּרוֹת יִכָּרֵתוּן לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי וְכָל בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁ֒מֶֽךָ, לְהַפְנוֹת אֵלֶֽיךָ כָּל רִשְׁ֒עֵי אָֽרֶץ, יַכִּֽירוּ וְיֵדְ֒עוּ כָּל יוֹשְׁ֒בֵי תֵבֵל כִּי לְךָ תִכְרַע כָּל בֶּֽרֶךְ תִּשָּׁבַע כָּל לָשׁוֹן: לְפָנֶֽיךָ יְהֹוָה אֱלֺהֵֽינוּ יִכְרְעוּ וְיִפֹּֽלוּ, וְלִכְ֒בוֹד שִׁמְךָ יְקָר יִתֵּֽנוּ, וִיקַבְּ֒לוּ כֻלָּם אֶת עֹל מַלְכוּתֶֽךָ, וְתִמְלֺךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד, כִּי הַמַּלְכוּת שֶׁלְּ֒ךָ הִיא וּלְעֽוֹלְ֒מֵי עַד תִּמְלוֹךְ בְּכָבוֹד, כַּכָּתוּב בְּתוֹרָתֶֽךָ יְהֹוָה יִמְלֺךְ לְעֹלָם וָעֶד: וְנֶאֱמַר וְהָיָה יְהֹוָה לְמֶֽלֶךְ עַל כָּל הָאָֽרֶץ בַּיּוֹם הַהוּא יִהְיֶה יְהֹוָה אֶחָד וּשְׁמוֹ אֶחָד:"}, {"kind": "header", "text": "קדיש יתום"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא (<b>אָמֵן</b>)"}, {"kind": "text", "text": "בְּעָלְ֒מָֽא דִּי־בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל־בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "text", "text": "<b>יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְ֒מֵי עָלְ֒מַיָּא</b>"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְקוּדְשָׁא <b>בְּרִיךְ הוּא</b>"}, {"kind": "text", "text": "לְעֵֽלָּא מִן־כָּל־ (בעשי\"ת לְעֵֽלָּא לְעֵֽלָּא מִכָּל) בִּרְכָתָֽא וְשִׁירָתָֽא תֻּשְׁבְּ֒חָתָֽא וְנֶחָמָתָֽא דַּאֲמִירָן בְּעָלְ֒מָֽא וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "text", "text": "יְהֵא שְׁלָמָֽא רַבָּֽא מִן־שְׁמַיָּֽא וְחַיִּים עָלֵֽינוּ וְעַל־כָּל־יִשְׂרָאֵל וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "text", "text": "עוֹשֶׂה שָׁלוֹם (בעשי\"ת הַשָּׁלוֹם) בִּמְרוֹמָיו הוּא יַעֲשֶׂה שָׁלוֹם עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "header", "text": "לדוד"}, {"kind": "instruction", "text": "מנהג טוב לומר אחר כל תפלה מזמור לדוד ה׳‬ אורי וישעי. ובפרט מר״ח אלול עד הושענא רבא (מורה באצבע סי' לז)."}, {"kind": "text", "text": "לְדָוִד יְהֹוָה אוֹרִי וְיִשְׁעִי מִמִּי אִירָא יְהֹוָה מָעוֹז חַיַּי מִמִּי אֶפְחָד: בִּקְ֒רֹב עָלַי מְרֵעִים לֶאֱכֹל אֶת בְּשָׂרִי צָרַי וְאֹיְ֒בַי לִי הֵֽמָּה כָשְׁ֒לוּ וְנָפָֽלוּ: אִם תַּחֲנֶה עָלַי מַחֲנֶה לֺא יִירָא לִבִּי אִם תָּקוּם עָלַי מִלְחָמָה בְּזֹאת אֲנִי בוֹטֵֽחַ: אַחַת שָׁאַֽלְתִּי מֵאֵת יְהֹוָה אוֹתָהּ אֲבַקֵּשׁ שִׁבְתִּי בְּבֵית יְהֹוָה כָּל יְמֵי חַיַּי לַחֲזוֹת בְּנֹֽעַם יְהֹוָה וּלְבַקֵּר בְּהֵיכָלוֹ: כִּי יִצְפְּ֒נֵֽנִי בְּסֻכֹּה בְּיוֹם רָעָה יַסְתִּרֵֽנִי בְּסֵֽתֶר אָהֳלוֹ בְּצוּר יְרוֹמְ֒מֵֽנִי: וְעַתָּה יָרוּם רֹאשִׁי עַל אֹיְ֒בַי סְבִיבוֹתָי וְאֶזְבְּחָה בְאָהֳלוֹ זִבְחֵי תְרוּעָה אָשִֽׁירָה וַאֲזַמְּ֒רָה לַיהוָֹה: שְׁמַע יְהֹוָה קוֹלִי אֶקְרָא וְחָנֵּֽנִי וַעֲנֵֽנִי: לְךָ אָמַר לִבִּי בַּקְּ֒שׁוּ פָנָי אֶת פָּנֶֽיךָ יְהֹוָה אֲבַקֵּשׁ: אַל תַּסְתֵּר פָּנֶֽיךָ מִמֶּֽנִּי אַל תַּט בְּאַף עַבְדֶּֽךָ עֶזְרָתִי הָיִֽיתָ אַל תִּטְּ֒שֵֽׁנִי וְאַל תַּעַזְבֵֽנִי אֱלֺהֵי יִשְׁעִי: כִּי אָבִי וְאִמִּי עֲזָבֽוּנִי וַיהוָֹה יַאַסְפֵֽנִי: הוֹרֵֽנִי יְהֹוָה דַּרְכֶּֽךָ וּנְחֵֽנִי בְּאֹֽרַח מִישׁוֹר לְמַֽעַן שׁוֹרְ֒רָי: אַל תִּתְּ֒נֵֽנִי בְּנֶֽפֶשׁ צָרָי כִּי קָֽמוּ בִי עֵֽדֵי שֶֽׁקֶר וִיפֵֽחַ חָמָס: לוּלֵא הֶאֱמַֽנְתִּי לִרְאוֹת בְּטוּב יְהֹוָה בְּאֶֽרֶץ חַיִּים: קַוֵּה אֶל יְהֹוָה חֲזַק וְיַאֲמֵץ לִבֶּךָ וְקַוֵּה אֶל יְהֹוָה:"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא (<b>אָמֵן</b>)"}, {"kind": "text", "text": "בְּעָלְ֒מָֽא דִּי־בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל־בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "text", "text": "<b>יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְ֒מֵי עָלְ֒מַיָּא</b>"}, {"kind": "text", "text": "יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְקוּדְשָׁא <b>בְּרִיךְ הוּא</b>"}, {"kind": "text", "text": "לְעֵֽלָּא מִן־כָּל־ (בעשי\"ת לְעֵֽלָּא לְעֵֽלָּא מִכָּל) בִּרְכָתָֽא וְשִׁירָתָֽא תֻּשְׁבְּ֒חָתָֽא וְנֶחָמָתָֽא דַּאֲמִירָן בְּעָלְ֒מָֽא וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "text", "text": "יְהֵא שְׁלָמָֽא רַבָּֽא מִן־שְׁמַיָּֽא וְחַיִּים עָלֵֽינוּ וְעַל־כָּל־יִשְׂרָאֵל וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "text", "text": "עוֹשֶׂה שָׁלוֹם (בעשי\"ת הַשָּׁלוֹם) בִּמְרוֹמָיו הוּא יַעֲשֶׂה שָׁלוֹם עָלֵֽינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ <b>אָמֵן</b>:"}, {"kind": "header", "text": "יגדל"}, {"kind": "instruction", "text": "פיוט המיוסד על שלושה עשר עקרי האמונה. מיוחס לר' דניאל בן יהודה הרומי"}, {"kind": "instruction", "text": "מציאות השם"}, {"kind": "text", "text": "<b>יִגְדַּל</b> אֱלֹהִים חַי וְיִשְׁתַּבַּח, נִמְצָא וְאֵין עֵת אֶל מְצִיאוּתוֹ:"}, {"kind": "instruction", "text": "אחדות השם"}, {"kind": "text", "text": "אֶחָד וְאֵין יָחִיד כְּיִחוּדוֹ, נֶעְלָם וְגַם אֵין סוֹף לְאַחְדּוּתוֹ:"}, {"kind": "instruction", "text": "שאינו גוף"}, {"kind": "text", "text": "אֵין לוֹ דְמוּת הַגּוּף וְאֵינוֹ גוּף, לֹא נַעֲרֹךְ אֵלָיו קְדֻשָּׁתוֹ:"}, {"kind": "instruction", "text": "קדמות השם"}, {"kind": "text", "text": "קַדְמוֹן לְכָל דָּבָר אֲשֶׁר נִבְרָא, רִאשׁוֹן וְאֵין רֵאשִׁית לְרֵאשִׁיתוֹ:"}, {"kind": "instruction", "text": "שרק אותו ראוי לעבוד"}, {"kind": "text", "text": "הִנּוֹ אֲדוֹן עוֹלָם לְכָל נוֹצָר, יוֹרֶה גְדֻלָּתוֹ וּמַלְכוּתוֹ:"}, {"kind": "instruction", "text": "נבואה"}, {"kind": "text", "text": "שֶֽׁפַע נְבוּאָתוֹ נְתָנוֹ, אֶל אַנְשֵׁי סְגֻלָּתוֹ וְתִפְאַרְתּוֹ:"}, {"kind": "instruction", "text": "נבואת משה אמיתית"}, {"kind": "text", "text": "לֹא קָם בְּיִשְׂרָאֵל כְּמשֶׁה עוֹד, נָבִיא וּמַבִּיט אֶת תְּמוּנָתוֹ:"}, {"kind": "instruction", "text": "תורה מן השמים"}, {"kind": "text", "text": "תּוֹרַת אֱמֶת נָתַן לְעַמּוֹ אֵל, עַל יַד נְבִיאוֹ נֶאֱמַן בֵּיתוֹ:"}, {"kind": "instruction", "text": "נצחיות התורה"}, {"kind": "text", "text": "לֹא יַחֲלִיף הָאֵל וְלֹא יָמִיר דָּתוֹ, לְעוֹלָמִים לְזוּלָתוֹ:"}, {"kind": "instruction", "text": "השגחה"}, {"kind": "text", "text": "צוֹפֶה וְיוֹדֵֽעַ סְתָרֵֽינוּ, מַבִּיט לְסוֹף דָּבָר בְּקַדְמָתוֹ:"}, {"kind": "instruction", "text": "שכר ועונש"}, {"kind": "text", "text": "גּוֹמֵל לְאִישׁ חֶֽסֶד כְּמִפְעָלוֹ, נוֹתֵן לְרָשָׁע רָע כְּרִשְׁעָתוֹ:"}, {"kind": "instruction", "text": "ביאת המשיח"}, {"kind": "text", "text": "יִשְׁלַח לְקֵץ הַיָּמִין מְשִׁיחֵֽנוּ, לִפְדּוֹת מְחַכֵּי קֵץ יְשׁוּעָתוֹ:"}, {"kind": "instruction", "text": "תחיית המתים"}, {"kind": "text", "text": "מֵתִים יְחַיֶּה אֵל בְּרֹב חַסְדּוֹ, בָּרוּךְ עֲדֵי עַד שֵׁם תְּהִלָּתוֹ:"}, {"kind": "header", "text": "אדון עולם"}, {"kind": "instruction", "text": "ויאמר פיוט ״אדון עולם״ המדבר ביחוד השם והשגחתו:"}, {"kind": "text", "text": "<b>אֲדוֹן עוֹלָם</b> אֲשֶׁר מָלַךְ, בְּטֶֽרֶם כָּל יְצִיר נִבְרָא:"}, {"kind": "text", "text": "לְעֵת נַעֲשָׂה בְחֶפְצוֹ כֹּל, אֲזַי מֶֽלֶךְ שְׁמוֹ נִקְרָא:"}, {"kind": "text", "text": "וְאַחֲרֵי כִּכְ֒לוֹת הַכֹּל, לְבַדּוֹ יִמְלֹךְ נוֹרָא:"}, {"kind": "text", "text": "וְהוּא הָיָה וְהוּא הֹוֶה, וְהוּא יִהְיֶה בְּתִפְאָרָה:"}, {"kind": "text", "text": "וְהוּא אֶחָד וְאֵין שֵׁנִי, לְהַמְשִׁיל לוֹ לְהַחְבִּֽירָה:"}, {"kind": "text", "text": "בְּלִי רֵאשִׁית בְּלִי תַכְלִית, וְלוֹ הָעֹז וְהַמִּשְׂרָה:"}, {"kind": "text", "text": "וְהוּא אֵלִי וְחַי גּוֹאֲלִי, וְצוּר חֶבְלִי בְּעֵת צָרָה:"}, {"kind": "text", "text": "וְהוּא נִסִּי וּמָנוֹס לִי, מְנָת כּוֹסִי בְּיוֹם אֶקְרָא:"}, {"kind": "text", "text": "בְּיָדוֹ אַפְקִיד רוּחִי, בְּעֵת אִישַׁן וְאָעִֽירָה:"}, {"kind": "text", "text": "וְעִם רוּחִי גְּוִיָּתִי, יְהֹוָה לִי וְלֹא אִירָא:"}], "shacharit": [{"kind": "header", "text": "מודה אני"}, {"kind": "text", "text": "ָמוֹדֶה אֲנִי לְפָנֶיךָ, מֶלֶךְ חַי וְקַיָּם, שֶׁהֶחֱזַרְתָּ בִּי נִשְׁמָתִי בְּחֶמְלָה, רַבָּה אֱמוּנָתֶךָ"}, {"kind": "header", "text": "נטילת ידים"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם אֲשֶׁר קִדְּשָׁנוּ בְּמִצְותָיו וְצִוָּנוּ עַל נְטִילַת יָדַיּם:"}, {"kind": "header", "text": "אשר יצר"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם אֲשֶׁר יָצַר אֶת הָאָדָם בְּחָכְמָה וּבָרָא בו נְקָבִים נְקָבִים חֲלוּלִים חֲלוּלִים. גָּלוּי וְיָדוּעַ לִפְנֵי כִסֵּא כְבודֶךָ שֶׁאִם יִפָּתֵחַ אֶחָד מֵהֶם או יִסָּתֵם אֶחָד מֵהֶם אִי אֶפְשַׁר לְהִתְקַיֵּם וְלַעֲמוד לְפָנֶיךָ אֲפִילוּ שָׁעָה אֶחָת:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' רופֵא כָל בָּשר וּמַפְלִיא לַעֲשות:"}, {"kind": "header", "text": "אלהי נשמה"}, {"kind": "text", "text": "אֱלהַי. נְשָׁמָה שֶׁנָּתַתָּ בִּי טְהורָה הִיא. אַתָּה בְרָאתָהּ. אַתָּה יְצַרְתָּהּ. אַתָּה נְפַחְתָּהּ בִּי. וְאַתָּה מְשַׁמְּרָהּ בְּקִרְבִּי. וְאַתָּה עָתִיד לִטְּלָהּ מִמֶּנִּי. וּלְהַחֲזִירָהּ בִּי לֶעָתִיד לָבוא. כָּל זְמַן שֶׁהַנְּשָׁמָה בְּקִרְבִּי מודֶה אֲנִי לְפָנֶיךָ ה' אֱלהַי וֵאלהֵי אֲבותַי. רִבּון כָּל הַמַּעֲשים אֲדון כָּל הַנְּשָׁמות:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' הַמַּחֲזִיר נְשָׁמות לִפְגָרִים מֵתִים:"}, {"kind": "header", "text": "ציצית"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה'. אֱלהֵינוּ מֶלֶךְ הָעולָם. אֲשֶׁר קִדְּשָׁנוּ בְּמִצְותָיו וְצִוָּנוּ עַל מִצְוַת צִיצִית:"}, {"kind": "text", "text": "יְהִי רָצון מִלְּפָנֶיךָ. ה' אֱלהַי וֵאלהֵי אֲבותַי. שֶׁתְּהֵא חֲשׁוּבָה מִצְוַת צִיצִית לְפָנֶיךָ כְּאִלּוּ קִיַּמְתִּיהָ בְּכָל פְּרָטֶיהָ וְדִקְדּוּקֶיהָ וְכַוָּנותֶיהָ. וְתַרְיַ\"ג מִצְות הַתְּלוּיִם בָּהּ. אָמֵן סֶלָה:"}, {"kind": "text", "text": "מִצְוַת ה' בָּרָה מְאִירַת עֵינָיִם:"}, {"kind": "header", "text": "טלית"}, {"kind": "text", "text": "בָּרְכִי נַפְשִׁי אֶת ה'. ה' אֱלהַי גָּדַלְתָּ מְאד. הוד וְהָדָר לָבָשְׁתָּ:"}, {"kind": "text", "text": "עוטֶה אור כַּשּלְמָה. נוטֶה שָׁמַיִם כַּיְרִיעָה:"}, {"kind": "text", "text": "לְשֵׁם יִחוּד קוּדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּהּ. בִּדְחִילוּ וּרְחִימוּ. לְיַחֵד שֵׁם י\"ה בו\"ה בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשרָאֵל:"}, {"kind": "text", "text": "הֲרֵינִי מִתְעַטֵּף גּוּפִי בַּצִּיצִית. כֵּן תִּתְעַטֵּף נִשְׁמָתִי וּרְמַ\"ח אֵיבָרַי וּשְׁסָ\"ה גִידַי בְּאור הַצִּיצִית הָעולֶה תַרְיַ\"ג. וּכְשֵׁם שֶׁאֲנִי מִתְכַּסֶּה בְּטַלִּית בָּעולָם הַזֶּה. כַּךְ אֶזְכֶּה לַחֲלוּקָא דְרַבָּנָן. וּלְטַלִּית נָאֶה לָעולָם הַבָּא בְּגַן עֵדֶן. וְעַל יְדֵי מִצְוַת צִיצִית. תִּנָּצֵל נַפְשִׁי וְרוּחִי וְנִשְׁמָתִי וּתפילתי מִן הַחִיצונִים. וְהַטַּלִּית יִפְרוש כְּנָפָיו עֲלֵיהֶם. וְיַצִּילֵם כְּנֶשֶׁר יָעִיר קִנּו עַל גּוזָלָיו יְרַחֵף. וּתְהֵא חֲשׁוּבָה מִצְוַת צִיצִית לִפְנֵי הַקָּדושׁ בָּרוּךְ הוּא. כְּאִלּוּ קִיַּמְתִּיהָ בְּכָל פְּרָטֶיהָ וְדִקְדּוּקֶיהָ וְכַוָּנותֶיהָ. וְתַרְיַ\"ג מִצְות הַתְּלוּיִם בָּהּ. אָמֵן סֶלָה:"}, {"kind": "text", "text": "אוחז את הטלית בשתי ידיו ויברך מעומד להתעטף בציצית:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה'. אֱלהֵינוּ מֶלֶךְ הָעולָם. אֲשֶׁר קִדְּשָׁנוּ בְּמִצְותָיו. וְצִוָּנוּ לְהִתְעַטֵּף בַּצִיצִית:"}, {"kind": "text", "text": "מַה יָּקָר חַסְדְּךָ אֱלהִים. וּבְנֵי אָדָם בְּצֵל כְּנָפֶיךָ יֶחֱסָיוּן:"}, {"kind": "text", "text": "יִרְוְיֻן מִדֶּשֶׁן בֵּיתֶךָ וְנַחַל עֲדָנֶיךָ תַשְׁקֵם:"}, {"kind": "text", "text": "כִּי עִמְּךָ מְקור חַיִּים. בְּאורְךָ נִרְאֶה אור:"}, {"kind": "text", "text": "מְשׁוךְ חַסְדְּךָ לְידְעֶיךָ וְצִדְקָתְךָ לְיִשְׁרֵי לֵב:"}, {"kind": "header", "text": "מה טובו"}, {"kind": "text", "text": "מַה טּבוּ אהָלֶיךָ יַעֲקב מִשְׁכְּנתֶיךָ יִשרָאֵל:"}, {"kind": "text", "text": "וַאֲנִי בְּרב חַסְדְּךָ אָבא בֵיתֶךָ אֶשְׁתַּחֲוֶה אֶל הֵיכַל קָדְשְׁךָ בְּיִרְאָתֶךָ:"}, {"kind": "text", "text": "ה' אָהַבְתִּי מְעון בֵּיתֶךָ וּמְקום מִשְׁכַּן כְּבודֶךָ:"}, {"kind": "text", "text": "וַאֲנִי אֶשְׁתַּחֲוֶה וְאֶכְרָעָה אֶבְרְכָה לִפְנֵי ה' עשי:"}, {"kind": "text", "text": "וַאֲנִי תפילתי לְךָ ה' עֵת רָצון אֱלהִים בְּרָב חַסְדֶּךָ עֲנֵנִי בֶּאֱמֶת יִשְׁעֶךָ:"}, {"kind": "header", "text": "אדון עולם"}, {"kind": "text", "text": "אֲדון עולָם אֲשֶׁר מָלַךְ. בְּטֶרֶם כָּל יְצִיר נִבְרָא:"}, {"kind": "text", "text": "לְעֵת נַעֲשה בְחֶפְצו כּל. אֲזַי מֶלֶךְ שְׁמו נִקְרָא:"}, {"kind": "text", "text": "וְאַחֲרֵי כִּכְלות הַכּל. לְבַדּו יִמְלךְ נורָא:"}, {"kind": "text", "text": "וְהוּא הָיָה. וְהוּא הוֶה. וְהוּא יִהְיֶה בְּתִפְאָרָה:"}, {"kind": "text", "text": "וְהוּא אֶחָד וְאֵין שֵׁנִי. לְהַמְשִׁיל לו לְהַחְבִּירָה:"}, {"kind": "text", "text": "בְּלִי רֵאשִׁית בְּלִי תַכְלִית. וְלו הָעז וְהַמִּשרָה:"}, {"kind": "text", "text": "וְהוּא אֵלִי וְחַי גואֲלִי. וְצוּר חֶבְלִי בְּעֵת צָרָה:"}, {"kind": "text", "text": "וְהוּא נִסִּי וּמָנוס לִי. מְנָת כּוסִי בְּיום אֶקְרָא:"}, {"kind": "text", "text": "בְּיָדו אַפְקִיד רוּחִי. בְּעֵת אִישָׁן וְאָעִירָה:"}, {"kind": "text", "text": "וְעִם רוּחִי גְּוִיָּתִי. ה' לִי וְלא אִירָא:"}, {"kind": "header", "text": "יגדל"}, {"kind": "text", "text": "יִגְדַּל אֱלהִים חַי וְיִשְׁתַּבַּח, נִמְצָא וְאֵין עֵת אֶל מְצִיאוּתו. אֶחָד וְאֵין יָחִיד כְּיִחוּדו, נֶעְלָם וְגַם אֵין סוף לְאַחְדוּתו. אֵין לו דְמוּת הַגּוּף וְאֵינו גוּף, לא נַעֲרךְ אֵלָיו קְדֻשָּׁתו. קַדְמון לְכָל דָּבָר אֲשֶׁר נִבְרָא, רִאשׁון וְאֵין רֵאשִׁית לְרֵאשִׁיתו. הִנּו אֲדון עולָם לְכָל נוצָר, יורֶה גְדֻלָּתו וּמַלְכוּתו. שֶׁפַע נְבוּאָתו נְתָנו, אֶל אַנְשֵׁי סְגֻלָּתו וְתִפְאַרְתּו. לא קָם בְּיִשרָאֵל כְּמשֶׁה עוד, נָבִיא וּמַבִּיט אֶת תְּמוּנָתו. תּורַת אֱמֶת נָתַן לְעַמּו אֵל, עַל יַד נְבִיאו נֶאֱמַן בֵּיתו. לא יַחֲלִיף הָאֵל וְלא יָמִיר דָּתו, לְעולָמִים לְזוּלָתו. צופֶה וְיודֵעַ סְתָרֵינוּ, מַבִּיט לְסוף דָּבָר בְּקַדְמוּתו. גּומֵל לְאִישׁ חֶסֶד כְּמִפְעָלו, נותֵן לְרָשָׁע רַע כְּרִשְׁעָתו. יִשְׁלַח לְקֵץ הַיָּמִין מְשִׁיחֵנוּ, לִפְדּות מְחַכֵּי קֵץ יְשׁוּעָתו. מֵתִים יְחַיֶּה אֵל בְּרב חַסְדּו, בָּרוּךְ עֲדֵי עַד שֵׁם תְּהִלָּתו:"}, {"kind": "header", "text": "ברכות השחר"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. אֲשֶׁר נָתַן לַשּכְוִי בִינָה לְהַבְחִין בֵּין יום וּבֵין לָיְלָה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. שֶׁלּא עָשנִי גּוי:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. שֶׁלּא עָשנִי עָבֶד:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. שֶׁלּא עָשנִי אִשָּׁה:"}, {"kind": "text", "text": "נשים מברכות - בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. שֶׁעָשנִי כִּרְצונו:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. פּוקֵחַ עִוְרִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. מַלְבִּישׁ עֲרֻמִּים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. מַתִּיר אֲסוּרִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. זוקֵף כְּפוּפִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. רוקַע הָאָרֶץ עַל הַמָּיִם:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. הַמֵּכִין מִצְעֲדֵי גָבֶר:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. שֶׁעָשה לִּי כָּל צָרְכִּי:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. אוזֵר יִשרָאֵל בִּגְבוּרָה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. עוטֵר יִשרָאֵל בְּתִפְאָרָה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. הַנּותֵן לַיָּעֵף כּחַ:"}, {"kind": "text", "text": "אין לענות אמן אחר ותנומה מעפעפי כי הכל ברכה אחת עד לעמו ישראל <em>דה\"ח</em>:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. הַמַּעֲבִיר שֵׁנָה מֵעֵינָי וּתְנוּמָה מֵעַפְעַפָּי:"}, {"kind": "text", "text": "וִיהִי רָצון מִלְּפָנֶיךָ ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ שֶׁתַּרְגִּילֵנוּ בְּתורָתֶךָ. וְדַבְּקֵנוּ בְּמִצְותֶיךָ. וְאַל תְּבִיאֵנוּ לא לִידֵי חֵטְא. וְלא לִידֵי עֲבֵרָה וְעָון. וְלא לִידֵי נִסָּיון. וְלא לִידֵי בִזָּיון. וְאַל יִשְׁלט בָּנוּ יֵצֶר הָרָע. וְהַרְחִיקֵנוּ מֵאָדָם רָע וּמֵחָבֵר רָע. וְדַבְּקֵנוּ בְּיֵצֶר הַטוב וּבְמַעֲשים טובִים. וְכף אֶת יִצְרֵנוּ לְהִשְׁתַּעְבֶּד לָךְ. וּתְנֵנוּ הַיּום וּבְכָל יום לְחֵן וּלְחֶסֶד וּלְרַחֲמִים בְּעֵינֶיךָ וּבְעֵינֵי כָל רואֵינוּ. וְתִגְמְלֵנוּ חֲסָדִים טובִים."}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' הַגּומֵל חֲסָדִים טובִים לְעַמּו יִשרָאֵל:"}, {"kind": "text", "text": "יְהִי רָצון מִלְּפָנֶיךָ ה' אֱלהַי וֵאלהֵי אֲבותַי שֶׁתַּצִּילֵנִי הַיּום וּבְכָל יום מֵעַזֵּי פָנִים וּמֵעַזּוּת פָּנִים. מֵאָדָם רָע. מִיֵּצֶר רָע. וּמֵחָבֵר רָע. וּמִשָּׁכֵן רָע. וּמִפֶּגַע רָע. מֵעַיִן הָרָע. מִלָּשׁון הָרָע. מִמַּלְשִׁינוּת. מֵעֵדוּת שֶׁקֶר. מִשּנְאַת הַבְּרִיּות. מֵעֲלִילָה. מִמִּיתָה מְשֻׁנָּה. מֵחֳלָיִם רָעִים. מִמִּקְרִים רָעִים וּמִשּטָן הַמַּשְׁחִית. מִדִּין קָשֶׁה וּמִבַּעַל דִּין קָשֶׁה. בֵּין שֶׁהוּא בֶן בְּרִית וּבֵין שֶׁאֵינו בֶן בְּרִית. וּמִדִּינָהּ שֶׁל גֵּיהִנּם:"}, {"kind": "header", "text": "עקדה"}, {"kind": "text", "text": "וַיְהִי אַחַר הַדְּבָרִים הָאֵלֶּה וְהָאֱלהִים נִסָּה אֶת אַבְרָהָם וַיּאמֶר אֵלָיו אַבְרָהָם וַיּאמֶר הִנֵּנִי:"}, {"kind": "text", "text": "וַיּאמֶר קַח נָא אֶת בִּנְךָ אֶת יְחִידְךָ אֲשֶׁר אָהַבְתָּ אֶת יִצְחָק וְלֶךְ לְךָ אֶל אֶרֶץ הַמּרִיָּה וְהַעֲלֵהוּ שָׁם לְעלָה עַל אַחַד הֶהָרִים אֲשֶׁר אמַר אֵלֶיךָ:"}, {"kind": "text", "text": "וַיַּשְׁכֵּם אַבְרָהָם בַּבּקֶר וַיַּחֲבשׁ אֶת חֲמרו וַיִּקַּח אֶת שְׁנֵי נְעָרָיו אִתּו וְאֵת יִצְחָק בְּנו וַיְבַקַּע עֲצֵי עלָה וַיָּקָם וַיֵּלֶךְ אֶל הַמָּקום אֲשֶׁר אָמַר לו הָאֱלהִים:"}, {"kind": "text", "text": "בַּיּום הַשְּׁלִישִׁי וַיִּשּא אַבְרָהָם אֶת עֵינָיו וַיַּרְא אֶת הַמָּקום מֵרָחוק:"}, {"kind": "text", "text": "וַיּאמֶר אַבְרָהָם אֶל נְעָרָיו שְׁבוּ לָכֶם פּה עִם הַחֲמור וַאֲנִי וְהַנַּעַר נֵלְכָה עַד כּה וְנִשְׁתַּחֲוֶה וְנָשׁוּבָה אֲלֵיכֶם:"}, {"kind": "text", "text": "וַיִּקַּח אַבְרָהָם אֶת עֲצֵי הָעלָה וַיָּשם עַל יִצְחָק בְּנו וַיִּקַּח בְּיָדו אֶת הָאֵשׁ וְאֶת הַמַּאֲכֶלֶת וַיֵּלְכוּ שְׁנֵיהֶם יַחְדָּו:"}, {"kind": "text", "text": "וַיּאמֶר יִצְחָק אֶל אַבְרָהָם אָבִיו וַיּאמֶר אָבִי וַיּאמֶר הִנֶּנִּי בְנִי וַיּאמֶר הִנֵּה הָאֵשׁ וְהָעֵצִים וְאַיֵּה הַשּה לְעלָה:"}, {"kind": "text", "text": "וַיּאמֶר אַבְרָהָם אֱלהִים יִרְאֶה לּו הַשּה לְעלָה בְּנִי וַיֵּלְכוּ שְׁנֵיהֶם יַחְדָּו:"}, {"kind": "text", "text": "וַיָּבאוּ אֶל הַמָּקום אֲשֶׁר אָמַר לו הָאֱלהִים וַיִּבֶן שָׁם אַבְרָהָם אֶת הַמִּזְבֵּחַ וַיַּעֲרךְ אֶת הָעֵצִים וַיַּעֲקד אֶת יִצְחָק בְּנו וַיָּשם אתו עַל הַמִּזְבֵּחַ מִמַּעַל לָעֵצִים:"}, {"kind": "text", "text": "וַיִּשְׁלַח אַבְרָהָם אֶת יָדו וַיִּקַּח אֶת הַמַּאֲכֶלֶת לִשְׁחט אֶת בְּנו:"}, {"kind": "text", "text": "וַיִּקְרָא אֵלָיו מַלְאַךְ ה' מִן הַשָּׁמַיִם וַיּאמֶר אַבְרָהָם אַבְרָהָם וַיּאמֶר הִנֵּנִי:"}, {"kind": "text", "text": "וַיּאמֶר אַל תִּשְׁלַח יָדְךָ אֶל הַנַּעַר וְאַל תַּעַש לו מְאוּמָה כִּי עַתָּה יָדַעְתִּי כִּי יְרֵא אֱלהִים אַתָּה וְלא חָשכְתָּ אֶת בִּנְךָ אֶת יְחִידְךָ מִמֶּנִּי:"}, {"kind": "text", "text": "וַיִּשּא אַבְרָהָם אֶת עֵינָיו וַיַּרְא וְהִנֵּה אַיִל אַחַר נֶאֱחַז בַּסְּבַךְ בְּקַרְנָיו וַיֵּלֶךְ אַבְרָהָם וַיִּקַּח אֶת הָאַיִל וַיַּעֲלֵהוּ לְעלָה תַּחַת בְּנו:"}, {"kind": "text", "text": "וַיִּקְרָא אַבְרָהָם שֵׁם הַמָּקום הַהוּא ה' יִרְאֶה אֲשֶׁר יֵאָמֵר הַיּום בְּהַר ה' יֵרָאֶה:"}, {"kind": "text", "text": "וַיִּקְרָא מַלְאַךְ ה' אֶל אַבְרָהָם שֵׁנִית מִן הַשָּׁמָיִם:"}, {"kind": "text", "text": "וַיּאמֶר בִּי נִשְׁבַּעְתִּי נְאֻם ה' כִּי יַעַן אֲשֶׁר עָשיתָ אֶת הַדָּבָר הַזֶּה וְלא חָשכְתָּ אֶת בִּנְךָ אֶת יְחִידֶךָ:"}, {"kind": "text", "text": "כִּי בָרֵךְ אֲבָרֶכְךָ וְהַרְבָּה אַרְבֶּה אֶת זַרְעֲךָ כְּכוכְבֵי הַשָּׁמַיִם וְכַחול אֲשֶׁר עַל שפַת הַיָּם וְיִרַשׁ זַרְעֲךָ אֵת שַׁעַר איְבָיו:"}, {"kind": "text", "text": "וְהִתְבָּרֲכוּ בְזַרְעֲךָ כּל גּויֵי הָאָרֶץ עֵקֶב אֲשֶׁר שָׁמַעְתָּ בְּקלִי:"}, {"kind": "text", "text": "וַיָּשָׁב אַבְרָהָם אֶל נְעָרָיו וַיָּקֻמוּ וַיֵּלְכוּ יַחְדָּו אֶל בְּאֵר שָׁבַע וַיֵּשֶׁב אַבְרָהָם בִּבְאֵר שָׁבַע:"}, {"kind": "header", "text": "עול מלכות שמים"}, {"kind": "text", "text": "לְעולָם יְהֵא אָדָם יְרֵא שָׁמַיִם בַּסֵּתֶר וּבַגָּלוּי וּמודֶה עַל הָאֱמֶת וְדובֵר אֱמֶת בִּלְבָבו וְיַשְׁכֵּם וְיאמַר:"}, {"kind": "text", "text": "רִבּון כָּל הָעולָמִים וַאֲדונֵי הָאֲדונִים. לא עַל צִדְקותֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ כִּי עַל רַחֲמֶיךָ הָרַבִּים. מָה אָנוּ מֶה חַיֵּינוּ מֶה חַסְדֵּנוּ מַה צִּדְקותֵינוּ מַה יְשׁוּעָתֵנוּ מַה כּחֵנוּ מַה גְּבוּרָתֵנוּ. מַה נּאמַר לְפָנֶיךָ ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ הֲלא כָל הַגִּבּורִים כְּאַיִן לְפָנֶיךָ וְאַנְשֵׁי הַשֵּׁם כְּלא הָיוּ וַחֲכָמִים כִּבְלִי מַדָּע וּנְבונִים כִּבְלִי הַשכֵּל כִּי רוב מַעֲשיהֶם תּהוּ וִימֵי חַיֵּיהֶם הֶבֶל לְפָנֶיךָ. וּמותַר הָאָדָם מִן הַבְּהֵמָה אָיִן כִּי הַכּל הָבֶל:"}, {"kind": "text", "text": "לְבַד הַנְּשָׁמָה הַטְּהורָה שֶׁהִיא עֲתִידָה לִתֵּן דִּין וְחֶשְׁבּון לִפְנֵי כִסֵּא כְבודֶךָ:"}, {"kind": "text", "text": "וְכָל הַגּויִם כְּאַיִן נֶגְדֶּךָ. שֶׁנֶּאֱמַר הֵן גּויִם כְּמַר מִדְּלִי וּכְשַׁחַק מאזְנַיִם נֶחְשָׁבוּ הֵן אִיִּים כַּדַּק יִטּל:"}, {"kind": "text", "text": "אֲבָל אֲנַחְנוּ עַמְּךָ בְּנֵי בְרִיתֶךָ. בְּנֵי אַבְרָהָם אהַבְךָ שֶׁנִּשְׁבַּעְתָּ לּו בְּהַר הַמּורִיָּה. זֶרַע יִצְחָק יְחִידו. שֶׁנֶּעֱקַד עַל גַּבֵּי הַמִּזְבֵּחַ. עֲדַת יַעֲקב בִּנְךָ בְּכורֶךָ. שֶׁמֵּאַהֲבָתְךָ שֶׁאָהַבְתָּ אותו וּמִשּמְחָתְךָ שֶׁשּמַחְתָּ בּו. קָרָאתָ אֶת שְׁמו יִשרָאֵל וִישֻׁרוּן:"}, {"kind": "text", "text": "לְפִיכָךְ אֲנַחְנוּ חַיָּבִים לְהודות לְךָ וּלְשַׁבֵּחֲךָ וּלְפָאֶרְךָ וּלְבָרֵךְ וּלְקַדֵּשׁ וְלִתֵּן שֶׁבַח וְהודָיָה לִשְׁמֶךָ:"}, {"kind": "text", "text": "אַשְׁרֵינוּ מַה טּוב חֶלְקֵנוּ וּמַה נָּעִים גּורָלֵנוּ וּמַה יָּפָה יְרֻשָּׁתֵנוּ:"}, {"kind": "text", "text": "אַשְׁרֵינוּ כְּשֶׁאָנוּ מַשְׁכִּימִים וּמַעֲרִיבִים בְּבָתֵּי כְנֵסִיּות וּבְבָתֵּי מִדְרָשׁות וּמְיַחֲדִים שִׁמְךָ בְּכָל יום תָּמִיד וְאומְרִים פַּעֲמַיִם בְּאַהֲבָה:"}, {"kind": "text", "text": "שְׁמַע יִשרָאֵל ה' אֱלהֵינוּ ה' אֶחָד:"}, {"kind": "text", "text": "בלחש - בָּרוּךְ שֵׁם כְּבוד מַלְכוּתו לְעולָם וָעֶד:"}, {"kind": "text", "text": "וְאָהַבְתָּ אֵת ה' אֱלהֶיךָ בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאדֶךָ:"}, {"kind": "text", "text": "וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנכִי מְצַוְּךָ הַיּום עַל לְבָבֶךָ:"}, {"kind": "text", "text": "וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ:"}, {"kind": "text", "text": "וּקְשַׁרְתָּם לְאות עַל יָדֶךָ וְהָיוּ לְטטָפת בֵּין עֵינֶיךָ:"}, {"kind": "text", "text": "וּכְתַבְתָּם עַל מְזֻזות בֵּיתֶךָ וּבִשְׁעָרֶיךָ:"}, {"kind": "text", "text": "אַתָּה הוּא עַד שֶׁלּא נִבְרָא הָעולָם אַתָּה הוּא מִשֶּׁנִּבְרָא הָעולָם. אַתָּה הוּא בָּעולָם הַזֶּה וְאַתָּה הוּא לָעולָם הַבָּא:"}, {"kind": "text", "text": "קַדֵּשׁ אֶת שִׁמְךָ עַל מַקְדִּישֵׁי שְׁמֶךָ וְקַדֵּשׁ אֶת שִׁמְךָ בְּעולָמֶךָ. וּבִישׁוּעָתְךָ תָּרִים וְתַגְבִּיהַּ קַרְנֵנוּ לְמַעְלָה. וְהושִׁיעֵנוּ בְּקָרוב לְמַעַן שְׁמֶךָ:"}, {"kind": "text", "text": "בָּרוּךְ הַמְקַדֵּשׁ שְׁמו בָּרַבִּים:"}, {"kind": "text", "text": "אַתָּה הוּא ה' אֱלהֵינוּ בַּשָּׁמַיִם וּבָאָרֶץ וּבִשְׁמֵי הַשָּׁמַיִם הָעֶלְיונִים. אֱמֶת אַתָּה הוּא רִאשׁון וְאַתָּה הוּא אַחֲרון וּמִבַּלְעָדֶיךָ אֵין אֱלהִים:"}, {"kind": "text", "text": "קַבֵּץ נְפוּצות קוֶיךָ מֵאַרְבַּע כַּנְפות הָאָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל בָּאֵי עולָם כִּי אַתָּה הוּא הָאֱלהִים לְבַדְּךָ עֶלְיון לְכל מַמְלְכות הָאָרֶץ:"}, {"kind": "text", "text": "אַתָּה עָשיתָ אֶת הַשָּׁמַיִם וְאֶת הָאָרֶץ אֶת הַיָּם וְאֶת כָּל אֲשֶׁר בָּם וּמִי בְּכָל מַעֲשה יָדֶיךָ בָּעֶלְיונִים או בַתַּחְתּונִים שֶׁיּאמַר לְךָ מַה תַּעֲשה וּמַה תִּפְעָל:"}, {"kind": "text", "text": "אָבִינוּ שֶׁבַּשָּׁמַיִם <em>חַי וְקַיָּם</em> עֲשה עִמָּנוּ צְדָקָה וָחֶסֶד בַּעֲבוּר שִׁמְךָ הַגָּדול הַגִּבּור וְהַנּורָא שֶׁנִּקְרָא עָלֵינוּ. וְקַיֶּם לָנוּ ה' אֱלהֵינוּ מַה שֶׁכָּתוּב <em>אֶת הַדָּבָר שֶׁהִבְטַחְתָּנוּ עַל יְדֵי צְפַנְיָה חוזָךְ. כָּאָמוּר</em> בָּעֵת הַהִיא אָבִיא אֶתְכֶם וּבָעֵת קַבְּצִי אֶתְכֶם. כִּי אֶתֵּן אֶתְכֶם לְשֵׁם וְלִתְהִלָּה בְּכל עַמֵּי הָאָרֶץ. בְּשׁוּבִי אֶת שְׁבוּתֵיכֶם לְעֵינֵיכֶם. אָמַר ה':"}, {"kind": "header", "text": "פרשת הכיור"}, {"kind": "text", "text": "וַיְדַבֵּר ה' אֶל משֶׁה לֵּאמר:"}, {"kind": "text", "text": "וְעָשיתָ כִּיּור נְחשֶׁת וְכַנּו נְחשֶׁת לְרָחְצָה. וְנָתַתָּ אתו בֵּין אהֶל מועֵד וּבֵין הַמִּזְבֵּחַ. וְנָתַתָּ שָׁמָּה מָיִם:"}, {"kind": "text", "text": "וְרָחֲצוּ אַהֲרן וּבָנָיו מִמֶּנּוּ אֶת יְדֵיהֶם וְאֶת רַגְלֵיהֶם:"}, {"kind": "text", "text": "בְּבאָם אֶל אהֶל מועֵד יִרְחֲצוּ מַיִם וְלא יָמֻתוּ. או בְגִשְׁתָּם אֶל הַמִּזְבֵּחַ לְשָׁרֵת. לְהַקְטִיר אִשֶּׁה לה':"}, {"kind": "text", "text": "וְרָחֲצוּ יְדֵיהֶם וְרַגְלֵיהֶם וְלא יָמֻתוּ. וְהָיְתָה לָהֶם חָק עולָם. לו וּלְזַרְעו לְדרתָם:"}, {"kind": "header", "text": "פרשת תרומת הדשן"}, {"kind": "text", "text": "וַיְדַבֵּר ה' אֶל משֶׁה לֵּאמר:"}, {"kind": "text", "text": "צַו אֶת אַהֲרן וְאֶת בָּנָיו לֵאמר זאת תּורַת הָעלָה הִוא הָעלָה עַל מוקְדָה עַל הַמִּזְבֵּחַ כָּל הַלַּיְלָה עַד הַבּקֶר וְאֵשׁ הַמִּזְבֵּחַ תּוּקַד בּו:"}, {"kind": "text", "text": "וְלָבַשׁ הַכּהֵן מִדּו בַד וּמִכְנְסֵי בַד יִלְבַּשׁ עַל בְּשרו וְהֵרִים אֶת הַדֶּשֶׁן אֲשֶׁר תּאכַל הָאֵשׁ אֶת הָעלָה עַל הַמִּזְבֵּחַ וְשמו אֵצֶל הַמִּזְבֵּחַ:"}, {"kind": "text", "text": "וּפָשַׁט אֶת בְּגָדָיו וְלָבַשׁ בְּגָדִים אֲחֵרִים וְהוצִיא אֶת הַדֶּשֶׁן אֶל מִחוּץ לַמַּחֲנֶה אֶל מָקום טָהור:"}, {"kind": "text", "text": "וְהָאֵשׁ עַל הַמִּזְבֵּחַ תּוּקַד בּו לא תִכְבֶּה וּבִעֵר עָלֶיהָ הַכּהֵן עֵצִים בַּבּקֶר בַּבּקֶר וְעָרַךְ עָלֶיהָ הָעלָה וְהִקְטִיר עָלֶיהָ חֶלְבֵי הַשְּׁלָמִים:"}, {"kind": "text", "text": "אֵשׁ תָּמִיד תּוּקַד עַל הַמִּזְבֵּחַ לא תִכְבֶּה:"}, {"kind": "header", "text": "פרשת קרבן תמיד"}, {"kind": "text", "text": "וַיְדַבֵּר ה' אֶל משֶׁה לֵּאמר:"}, {"kind": "text", "text": "צַו אֶת בְּנֵי יִשרָאֵל וְאָמַרְתָּ אֲלֵהֶם. אֶת קָרְבָּנִי לַחְמִי לְאִשַּׁי רֵיחַ נִיחחִי. תִּשְׁמְרוּ לְהַקְרִיב לִי"}, {"kind": "text", "text": "בְּמועֲדו: וְאָמַרְתָּ לָהֶם. זֶה הָאִשֶּׁה אֲשֶׁר תַּקְרִיבוּ לה'. כְּבָשים בְּנֵי שָׁנָה תְמִימִים. שְׁנַיִם לַיּום עלָה תָמִיד: אֶת הַכֶּבֶש אֶחָד תַּעֲשה בַבּקֶר. וְאֵת הַכֶּבֶש הַשֵּׁנִי תַּעֲשה בֵּין הָעַרְבָּיִם:"}, {"kind": "text", "text": "וַעֲשירִית הָאֵיפָה סלֶת לְמִנְחָה. בְּלוּלָה בְּשֶׁמֶן כָּתִית רְבִיעִת הַהִין:"}, {"kind": "text", "text": "עלַת תָּמִיד הָעֲשיָה בְּהַר סִינַי. לְרֵיחַ נִיחחַ אִשֶּׁה לה':"}, {"kind": "text", "text": "וְנִסְכּו רְבִיעִת הַהִין לַכֶּבֶש הָאֶחָד. בַּקּדֶשׁ הַסֵּךְ נֶסֶךְ שֵׁכָר לה':"}, {"kind": "text", "text": "וְאֵת הַכֶּבֶש הַשֵּׁנִי תַּעֲשה בֵּין הָעַרְבָּיִם. כְּמִנְחַת הַבּקֶר וּכְנִסְכּו תַּעֲשה. אִשֵּׁה רֵיחַ נִיחחַ לה':"}, {"kind": "text", "text": "וְשָׁחַט אתו עַל יֶרֶךְ הַמִּזְבֵּחַ צָפנָה לִפְנֵי ה'. וְזָרְקוּ בְּנֵי אַהֲרן הַכּהֲנִים אֶת דָּמו עַל הַמִּזְבֵּחַ סָבִיב:"}, {"kind": "text", "text": "יְהִי רָצון מִלְּפָנֶיךָ, ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ, שֶׁתְּהֵא אֲמִירָה זוּ חֲשׁוּבָה וּמְקֻבֶּלֶת וּמְרֻצָּה לְפָנֶיךָ כְּאִלּוּ הִקְרַבְנוּ קָרְבַּן הַתָּמִיד בְּמועֲדו וּבִמְקומו וּכְהִלְכָתו:"}, {"kind": "header", "text": "פרשת הקטורת"}, {"kind": "text", "text": "אַתָּה הוּא ה' אֱלהֵינוּ שֶׁהִקְטִירוּ אֲבותֵינוּ לְפָנֶיךָ אֶת קְטרֶת הַסַּמִּים בִּזְמַן שֶׁבֵּית הַמִּקְדָּשׁ הָיָה קַיָּם. כַּאֲשֶׁר צִוִּיתָ אותָם עַל יַד משֶׁה נְבִיאֶךָ כַּכָּתוּב בְּתורָתֶךָ:"}, {"kind": "text", "text": "וַיּאמֶר ה' אֶל משֶׁה קַח לְךָ סַמִּים נָטָף וּשְׁחֵלֶת וְחֶלְבְּנָה סַמִּים וּלְבנָה זַכָּה בַּד בְּבַד יִהְיֶה:"}, {"kind": "text", "text": "וְעָשיתָ אתָהּ קְטרֶת רקַח מַעֲשה רוקֵחַ מְמֻלָּח טָהור קדֶשׁ:"}, {"kind": "text", "text": "וְשָׁחַקְתָּ מִמֶּנָּה הָדֵק וְנָתַתָּה מִמֶּנָּה לִפְנֵי הָעֵדֻת בְּאהֶל מועֵד אֲשֶׁר אִוָּעֵד לְךָ שָׁמָּה קדֶשׁ קָדָשִׁים תִּהְיֶה לָכֶם:"}, {"kind": "text", "text": "וְנֶאֱמַר וְהִקְטִיר עָלָיו אַהֲרן קְטרֶת סַמִּים בַּבּקֶר בַּבּקֶר בְּהֵיטִיבו אֶת הַנֵּרות יַקְטִירֶנָּה:"}, {"kind": "text", "text": "וּבְהַעֲלת אַהֲרן אֶת הַנֵּרות בֵּין הָעַרְבַּיִם יַקְטִירֶנָּה קְטרֶת תָּמִיד לִפְנֵי ה' לְדרתֵיכֶם:"}, {"kind": "text", "text": "תָּנוּ רַבָּנָן פִּטּוּם הַקְּטרֶת כֵּיצַד שְׁלשׁ מֵאות וְשִׁשִּׁים וּשְׁמונָה מָנִים הָיוּ בָהּ. שְׁלשׁ מֵאות וְשִׁשִּׁים וַחֲמִשָּׁה כְּמִנְיַן יְמות הַחַמָּה. מָנֶה לְכָל יום. פְּרַס בְּשַׁחֲרִית וּפְרַס בֵּין הָעַרְבָּיִם. וּשְׁלשָׁה מָנִים יְתֵרִים שֶׁמֵּהֶם מַכְנִיס כּהֵן גָּדול מְלא חָפְנָיו בְּיום הַכִּפּוּרִים. וּמַחֲזִירָן לְמַכְתֶּשֶׁת בְּעֶרֶב יום הַכִּפּוּרִים. וְשׁוחֲקָן יָפֶה יָפֶה כְּדֵי שֶׁתְּהֵא דַקָּה מִן הַדַּקָּה:"}, {"kind": "text", "text": "וְאַחַד עָשר סַמָּנִים הָיוּ בָהּ. וְאֵלּוּ הֵן."}, {"kind": "text", "text": "<em>א</em> הַצֳּרִי <em>ב</em> וְהַצִּפּרֶן <em>ג</em> הַחֶלְבְּנָה <em>ד</em> וְהַלְּבונָה מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה. <em>ה</em> מר <em>ו</em> וּקְצִיעָה <em>ז</em> שִׁבּלֶת נֵרְדְּ <em>ח</em> וְכַרְכּם מִשְׁקַל שִׁשָּׁה עָשר שִׁשָּׁה עָשר מָנֶה. <em>ט</em> הַקּשְׁטְ שְׁנֵים עָשר. <em>י</em> וְקִלּוּפָה שְׁלשָׁה. <em>יא</em> וְקִנָּמון תִּשְׁעָה."}, {"kind": "text", "text": "בּורִית כַּרְשִׁינָה תִּשְׁעָה קַבִּין. יֵין קַפְרִיסִין סְאִין תְּלָתָא וְקַבִּין תְּלָתָא. וְאִם לא מָצָא יֵין קַפְרִיסִין מֵבִיא חֲמַר חִוַּרְיָן עַתִּיק. מֶלַח סְדומִית רובַע מַעֲלֶה עָשָׁן כָּל שֶׁהוּא. רַבִּי נָתָן הַבַּבְלִי אומֵר אַף כִּפַּת הַיַּרְדֵּן כָּל שֶׁהוּא וְאִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ. וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶיהָ חַיָּב מִיתָה:"}, {"kind": "text", "text": "רַבָּן שִׁמְעון בֶּן גַּמְלִיאֵל אומֵר הַצֳּרִי אֵינו אֶלָּא שרָף הַנּוטֵף מֵעֲצֵי הַקְּטָף. בּרִית כַּרְשִׁינָה לָמָה הִיא בָאָה, כְּדֵי לְיַפּות בָּהּ אֶת הַצִּפּרֶן כְּדֵי שֶׁתְּהֵא נָאָה. יֵין קַפְרִיסִין לָמָה הוּא בָא כְּדֵי לִשְׁרות בּו אֶת הַצִּפּרֶן כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלא מֵי רַגְלַיִם יָפִין לָהּ אֶלָּא שֶׁאֵין מַכְנִיסִין מֵי רַגְלַיִם בַּמִּקְדָּשׁ מִפְּנֵי הַכָּבוד:"}, {"kind": "text", "text": "תַּנְיָא רַבִּי נָתָן אומֵר כְּשֶׁהוּא שׁוחֵק אומֵר. הָדֵק הֵיטֵב הֵיטֵב הָדֵק. מִפְּנֵי שֶׁהַקּול יָפֶה לַבְּשמִים. פִּטְּמָהּ לַחֲצָאִין כְּשֵׁרָה. לִשְׁלִישׁ וְלִרְבִיעַ לא שָׁמַעְנוּ:"}, {"kind": "text", "text": "אָמַר רַבִּי יְהוּדָה זֶה הַכְּלָל. אִם כְּמִדָּתָהּ כְּשֵׁרָה לַחֲצָאִין. וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶיהָ חַיָּב מִיתָה:"}, {"kind": "text", "text": "תַּנְיָא בַּר קַפָּרָא אומֵר. אַחַת לְשִׁשִּׁים או לְשִׁבְעִים שָׁנָה הָיְתָה בָאָה שֶׁל שִׁירַיִם לַחֲצָאִין:"}, {"kind": "text", "text": "וְעוד תָּנֵי בַּר קַפָּרָא אִלּוּ הָיָה נותֵן בָּהּ קורְטוב שֶׁל דְּבַשׁ אֵין אָדָם יָכול לַעֲמד מִפְּנֵי רֵיחָהּ. וְלָמָה אֵין מְעָרְבִין בָּהּ דְּבַשׁ. מִפְּנֵי שֶׁהַתּורָה אָמְרָה כִּי כָל שאר וְכָל דְּבַשׁ לא תַקְטִירוּ מִמֶּנּוּ אִשֶּׁה לה':"}, {"kind": "text", "text": "ג\"פ - ה' צְבָאות עִמָּנוּ מִשגָּב לָנוּ אֱלהֵי יַעֲקב סֶלָה:"}, {"kind": "text", "text": "ג\"פ - ה' צְבָאות אַשְׁרֵי אָדָם בּוטֵחַ בָּךְ:"}, {"kind": "text", "text": "ג\"פ - ה' הושִׁיעָה הַמֶּלֶךְ יַעֲנֵנוּ בְיום קָרְאֵנוּ:"}, {"kind": "text", "text": "אַתָּה סֵתֶר לִי מִצַּר תִּצְּרֵנִי רָנֵּי פַלֵּט תְּסובְבֵנִי סֶלָה:"}, {"kind": "text", "text": "וְעָרְבָה לה' מִנְחַת יְהוּדָה וִירוּשָׁלָיִם כִּימֵי עולָם וּכְשָׁנִים קַדְמונִיּות:"}, {"kind": "text", "text": "אַבַּיֵּי הֲוָה מְסַדֵּר סֵדֶר הַמַּעֲרָכָה מִשְּׁמָא דִּגְמָרָא וְאַלִּבָּא דְאַבָּא שָׁאוּל. מַעֲרָכָה גְדולָה קודֶמֶת לְמַעֲרָכָה שְׁנִיָּה שֶׁל קְטרֶת. וּמַעֲרָכָה שְׁנִיָּה שֶׁל קְטרֶת קודֶמֶת לְסִדּוּר שְׁנֵי גִזְרֵי עֵצִים. וְסִדּוּר שְׁנֵי גִזְרֵי עֵצִים קודֶם לְדִשּׁוּן מִזְבֵּחַ הַפְּנִימִי. וְדִשּׁוּן מִזְבֵּחַ הַפְּנִימִי קודֶם לַהֲטָבַת חָמֵשׁ נֵרות. וַהֲטָבַת חָמֵשׁ נֵרות קודֶמֶת לְדַם הַתָּמִיד. וְדַם הַתָּמִיד קודֶם לַהֲטָבַת שְׁתֵּי נֵרות. וַהֲטָבַת שְׁתֵּי נֵרות קודֶמֶת לִקְטרֶת. וּקְטרֶת קודֶמֶת לְאֵבָרִים. וְאֵבָרִים לְמִנְחָה. וּמִנְחָה לַחֲבִתִּין. וַחֲבִתִּין לִנְסָכִין. וּנְסָכִין לְמוּסָפִין. וּמוּסָפִין לְבָזִיכִין. וּבָזִיכִין קודְמִין לְתָמִיד שֶׁל בֵּין הָעַרְבָּיִם. שֶׁנֶּאֱמַר. וְעָרַךְ עָלֶיהָ הָעלָה וְהִקְטִיר עָלֶיהָ חֶלְבֵי הַשְּׁלָמִים. עָלֶיהָ הַשְׁלֵם כָּל הַקָּרְבָּנות כֻּלָּם:"}, {"kind": "header", "text": "סדר המערכה"}, {"kind": "text", "text": "אָנָּא בְּכחַ גְּדֻלַּת יְמִינְךָ תַּתִּיר צְרוּרָה:"}, {"kind": "text", "text": "קַבֵּל רִנַּת עַמְּךָ שגְּבֵנוּ טַהֲרֵנוּ נורָא:"}, {"kind": "text", "text": "נָא גִבּור דּורְשֵׁי יִחוּדְךָ כְּבָבַת שָׁמְרֵם:"}, {"kind": "text", "text": "בָּרְכֵם טַהֲרֵם רַחֲמֵי צִדְקָתְךָ תָּמִיד גָּמְלֵם:"}, {"kind": "text", "text": "חֲסִין קָדושׁ בְּרוב טוּבְךָ נַהֵל עֲדָתֶךָ:"}, {"kind": "text", "text": "יָחִיד גֵּאֶה לְעַמְּךָ פְּנֵה זוכְרֵי קְדֻשָּׁתֶךָ:"}, {"kind": "text", "text": "שַׁוְעָתֵנוּ קַבֵּל וּשְׁמַע צַעֲקָתֵנוּ יודֵעַ תַּעֲלוּמות:"}, {"kind": "text", "text": "בָּרוּךְ שֵׁם כְּבוד מַלְכוּתו לְעולָם וָעֶד:"}, {"kind": "text", "text": "רִבּון הָעולָמִים. אַתָּה צִוִּיתָנוּ לְהַקְרִיב קָרְבַּן הַתָּמִיד בְּמועֲדו וְלִהְיות כּהֲנִים בַּעֲבודָתָם וּלְוִיִּים בְּדוּכָנָם וְיִשרָאֵל בְּמַעֲמָדָם. וְעַתָּה בַּעֲונותֵינוּ חָרַב בֵּית הַמִּקְדָּשׁ וּבֻטַּל הַתָּמִיד. וְאֵין לָנוּ לא כהֵן בַּעֲבודָתו וְלא לֵוִי בְּדוּכָנו וְלא יִשרָאֵל בְּמַעֲמָדו. וְאַתָּה אָמַרְתָּ וּנְשַׁלְּמָה פָרִים שפָתֵינוּ. לָכֵן יְהִי רָצון מִלְּפָנֶיךָ ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ שֶׁיְּהֵא שיחַ שפְתותֵינוּ חָשׁוּב וּמְקֻבָּל וּמְרֻצֶּה לְפָנֶיךָ כְּאִלּוּ הִקְרַבְנוּ קָרְבַּן הַתָּמִיד בְּמועֲדו וּבִמְקומו וּכְהִלְכָתו:"}, {"kind": "text", "text": "לשבת וּבְיום הַשַּׁבָּת שְׁנֵי כְבָשים בְּנֵי שָׁנָה תְּמִימִם, וּשְׁנֵי עֶשרנִים סלֶת מִנְחָה בְּלוּלָה בַשֶּׁמֶן וְנִסְכּו:"}, {"kind": "text", "text": "עלַת שַׁבַּת בְּשַׁבַּתּו, עַל עלַת הַתָּמִיד וְנִסְכָּהּ:"}, {"kind": "text", "text": "לר\"ח וּבְרָאשֵׁי חָדְשֵׁיכֶם תַּקְרִיבוּ עלָה לה', פָּרִים בְּנֵי בָקָר שְׁנַיִם וְאַיִל אֶחָד, כְּבָשים בְּנֵי שָׁנָה שִׁבְעָה תְּמִימִים:"}, {"kind": "text", "text": "וּשְׁלשָׁה עֶשרנִים סלֶת מִנְחָה בְּלוּלָה בַשֶּׁמֶן לַפָּר הָאֶחָד, וּשְׁנֵי עֶשרנִים סלֶת מִנְחָה בְּלוּלָה בַשֶּׁמֶן לָאַיִל הָאֶחָד:"}, {"kind": "text", "text": "וְעִשּרן עִשּרון סלֶת מִנְחָה בְּלוּלָה בַשֶּׁמֶן לַכֶּבֶש הָאֶחָד, עלָה רֵיחַ נִיחחַ אִשֶּׁה לה':"}, {"kind": "text", "text": "וְנִסְכֵּיהֶם, חֲצִי הַהִין יִהְיֶה לַפָּר, וּשְׁלִישִׁת הַהִין לָאַיִל, וּרְבִיעִת הַהִין לַכֶּבֶש יָיִן, זאת עלַת חדֶשׁ בְּחָדְשׁו לְחָדְשֵׁי הַשָּׁנָה:"}, {"kind": "text", "text": "וּשעִיר עִזִּים אֶחָד לְחַטָּאת לה', עַל עלַת הַתָּמִיד יֵעָשה וְנִסְכּו:"}, {"kind": "header", "text": "דיני זבחים"}, {"kind": "text", "text": "אֵיזֶהוּ מְקומָן שֶׁל זְבָחִים. קָדְשֵׁי קָדָשִׁים שְׁחִיטָתָן בַּצָּפון. פָּר וְשעִיר שֶׁל יום הַכִּפּוּרִים שְׁחִיטָתָן בַּצָּפון וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפון וְדָמָן טָעוּן הַזָּיָה עַל בֵּין הַבַּדִּים וְעַל הַפָּרכֶת וְעַל מִזְבַּח הַזָּהָב. מַתָּנָה אַחַת מֵהֶן מְעַכָּבֶת. שְׁיָרֵי הַדָּם הָיָה שׁופֵךְ עַל יְסוד מַעֲרָבִי שֶׁל מִזְבֵּחַ הַחִיצון אִם לא נָתַן לא עִכֵּב:"}, {"kind": "text", "text": "פָּרִים הַנִּשרָפִים וּשעִירִים הַנִּשרָפִים. שְׁחִיטָתָן בַּצָּפון וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפון וְדָמָן טָעוּן הַזָּיָה עַל הַפָּרכֶת וְעַל מִזְבַּח הַזָּהָב. מַתָּנָה אַחַת מֵהֶן מְעַכָּבֶת. שְׁיָרֵי הַדָּם הָיָה שׁופֵךְ עַל יְסוד מַעֲרָבִי שֶׁל מִזְבֵּחַ הַחִיצון. אִם לא נָתַן לא עִכֵּב. אֵלּוּ וָאֵלּוּ נִשרָפִין בְּבֵית הַדָּשֶׁן:"}, {"kind": "text", "text": "חַטּאת הַצִּבּוּר וְהַיָּחִיד. אֵלּוּ הֵן חַטּאת הַצִּבּוּר. שעִירֵי רָאשֵׁי חֳדָשִׁים וְשֶׁל מועֲדות שְׁחִיטָתָן בַּצָּפון וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפון וְדָמָן טָעוּן אַרְבַּע מַתָּנות עַל אַרְבַּע קְרָנות. כֵּיצַד. עָלָה בַכֶּבֶשׁ וּפָנָה לַסּובֵב וּבָא לו לְקֶרֶן דְּרומִית מִזְרָחִית. מִזְרָחִית צְפונִית. צְפונִית"}, {"kind": "text", "text": "מַעֲרָבִית. מַעֲרָבִית דְּרומִית. שְׁיָרֵי הַדָּם הָיָה שׁופֵךְ עַל יְסוד דְּרומִי. וְנֶאֱכָלִין לִפְנִים מִן הַקְּלָעִים. לְזִכְרֵי כְהֻנָּה. בְּכָל מַאֲכָל. לְיום וָלַיְלָה עַד חֲצות:"}, {"kind": "header", "text": "ברייתא דרבי ישמעאל"}, {"kind": "text", "text": "רַבִּי יִשְׁמָעֵאל אומֵר. בִּשְׁלשׁ עֶשרֵה מִדּות הַתּורָה נִדְרֶשֶׁת בָּהֵן:"}, {"kind": "text", "text": "<em>א</em> מִקַּל וָחמֶר"}, {"kind": "text", "text": "<em>ב</em> וּמִגְּזֵרָה שָׁוָה."}, {"kind": "text", "text": "<em>ג</em> מִבִּנְיַן אָב מִכָּתוּב אֶחָד. וּמִבִּנְיַן אָב מִשְּׁנֵי כְתוּבִים."}, {"kind": "text", "text": "<em>ד</em> מִכְּלָל וּפְרָט."}, {"kind": "text", "text": "<em>ה</em> וּמִפְּרָט וּכְלָל."}, {"kind": "text", "text": "<em>ו</em> כְּלָל וּפְרָט וּכְלָל. אִי אַתָּה דָן אֶלָּא כְּעֵין הַפְּרָט."}, {"kind": "text", "text": "<em>ז</em> מִכְּלָל שֶׁהוּא צָרִיךְ לִפְרָט. וּמִפְּרָט שֶׁהוּא צָרִיךְ לִכְלָל."}, {"kind": "text", "text": "<em>ח</em> כָּל דָּבָר שֶׁהָיָה בִּכְלָל וְיָצָא מִן הַכְּלָל לְלַמֵּד. לא לְלַמֵּד עַל עַצְמו יָצָא. אֶלָּא לְלַמֵּד עַל הַכְּלָל כֻּלּו יָצָא."}, {"kind": "text", "text": "<em>ט</em> כָּל דָּבָר שֶׁהָיָה בִּכְלָל וְיָצָא לִטְעון טועַן אֶחָד שֶׁהוּא כְעִנְיָנו. יָצָא לְהָקֵל וְלא לְהַחֲמִיר."}, {"kind": "text", "text": "<em>י</em> כָּל דָּבָר שֶׁהָיָה בִּכְלָל וְיָצָא לִטְעון טועַן אַחֵר שֶׁלּא כְעִנְיָנו. יָצָא לְהָקֵל וּלְהַחֲמִיר."}, {"kind": "text", "text": "<em>יא</em> כָּל דָּבָר שֶׁהָיָה בִּכְלָל וְיָצָא לִדּון בַּדָּבָר הֶחָדָשׁ. אִי אַתָּה יָכול לְהַחֲזִירו לִכְלָלו עַד שֶׁיַּחֲזִירֶנּוּ הַכָּתוּב לִכְלָלו בְּפֵרוּשׁ."}, {"kind": "text", "text": "<em>יב</em> דָּבָר הַלָּמֵד מֵעִנְיָנו. וְדָבָר הַלָּמֵד מִסּופו."}, {"kind": "text", "text": "<em>יג</em> וְכֵן <em>נ\"א וְכַאן</em> שְׁנֵי כְתוּבִים הַמַּכְחִישִׁים זֶה אֶת זֶה. עַד שֶׁיָּבוא הַכָּתוּב הַשְּׁלִישִׁי וְיַכְרִיעַ בֵּינֵיהֶם:"}, {"kind": "text", "text": "יְהִי רָצון מִלְּפָנֶיךָ ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ. וְתֵן חֶלְקֵנוּ בְּתורָתֶךָ: וְשָׁם נַעֲבָדְךָ בְּיִרְאָה כִּימֵי עולָם וּכְשָׁנִים קַדְמונִיּות:"}, {"kind": "header", "text": "קדיש דרבנן"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. אמן:"}, {"kind": "text", "text": "בְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ. אמן:"}, {"kind": "text", "text": "בְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב. וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא:"}, {"kind": "text", "text": "יִתְבָּרַךְ. וְיִשְׁתַּבַּח וְיִתְפָּאֵר וְיִתְרומֵם וְיִתְנַשּא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְקֻדְשָׁא בְּרִיךְ הוּא. לְעֵלָּא מִן כָּל <em>בעשי\"ת וּלְעֵלָּא מִכָּל</em> בִּרְכָתָא וְשִׁירָתָא תֻּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "עַל יִשרָאֵל וְעַל רַבָּנָן. וְעַל תַּלְמִידֵיהון וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהון. וְעַל כָּל מַאן דְּעָסְקִין בְּאורַיְתָא. דִּי בְאַתְרָא <em>קַדִּישָׁא</em> הָדֵין וְדִי בְכָל אֲתַר וַאֲתַר. יְהֵא לְהון וּלְכון שְׁלָמָא רַבָּא חִנָּא וְחִסְדָּא וְרַחֲמֵי וְחַיֵּי אֲרִיכֵי וּמְזונֵי רְוִיחֵי וּפֻרְקָנָא מִן קֳדָם אֲבוּהון דִּי בִשְׁמַיָּא וְאַרְעָא וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טובִים עָלֵינוּ וְעַל כָּל יִשרָאֵל. וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "עושה שָׁלום <em>בעשי\"ת הַשָּׁלום</em> בִּמְרומָיו הוּא בְּרַחֲמָיו יַעֲשה שָׁלום עָלֵינוּ וְעַל כָּל יִשרָאֵל וְאִמְרוּ אָמֵן:"}, {"kind": "header", "text": "מזמור שיר חנוכת הבית"}, {"kind": "text", "text": "מִזְמור שִׁיר חֲנֻכַּת הַבַּיִת לְדָוִד: אֲרומִמְךָ ה' כִּי דִלִּיתָנִי. וְלא שמַּחְתָּ איְבַי לִי: ה' אֱלהָי. שִׁוַּעְתִּי אֵלֶיךָ וַתִּרְפָּאֵנִי: ה' הֶעֱלִיתָ מִן שְׁאול נַפְשִׁי. חִיִּיתַנִי מִיָּרְדִי בור: זַמְּרוּ לה' חֲסִידָיו. וְהודוּ לְזֵכֶר קָדְשׁו: כִּי רֶגַע בְּאַפּו חַיִּים בִּרְצונו. בָּעֶרֶב יָלִין בֶּכִי וְלַבּקֶר רִנָּה: וַאֲנִי אָמַרְתִּי בְשַׁלְוִי. בַּל אֶמּוט לְעולָם: ה' בִּרְצונְךָ הֶעֱמַדְתָּה לְהַרְרִי עז. הִסְתַּרְתָּ פָנֶיךָ הָיִיתִי נִבְהָל: אֵלֶיךָ ה' אֶקְרָא וְאֶל אֲדנָי אֶתְחַנָּן: מַה בֶּצַע בְּדָמִי בְּרִדְתִּי אֶל שָׁחַת. הֲיודְךָ עָפָר הֲיַגִּיד אֲמִתֶּךָ: שְׁמַע ה' וְחָנֵּנִי ה' הֱיֵה עזֵר לִי: הָפַכְתָּ מִסְפְּדִי לְמָחול לִי פִּתַּחְתָּ שקִּי וַתְּאַזְּרֵנִי שמְחָה: לְמַעַן יְזַמֶּרְךָ כָבוד וְלא יִדּם. ה' אֱלהַי לְעולָם אודֶךָּ:"}, {"kind": "header", "text": "קדיש יתום"}, {"kind": "text", "text": "<em>קדיש יתום:</em> <br> <em>אבל:</em> יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [<em>קהל:</em> אמן] <br> בְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן] <br> <em>קהל ואבל:</em> יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא: <br> <em>אבל:</em> יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרומַם וְיִתְנַשּא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא. [<em>קהל:</em> בריך הוא:] <br> לְעֵלָּא מִן כָּל בִּרְכָתָא <em>בעשי”ת: לְעֵלָּא לְעֵלָּא מִכָּל</em> וְשִׁירָתָא תֻּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן] <br> יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשרָאֵל. וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן] <br> עושה שָׁלום <em>בעשי”ת: הַשָּׁלום</em> בִּמְרומָיו הוּא יַעֲשה שָׁלום עָלֵינוּ וְעַל כָּל יִשרָאֵל וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן]"}, {"kind": "header", "text": "ברוך שאמר"}, {"kind": "text", "text": "בָּרוּךְ שֶׁאָמַר וְהָיָה הָעולָם. בָּרוּךְ הוּא. בָּרוּךְ עושה בְרֵאשִׁית. בָּרוּךְ אומֵר וְעושה. בָּרוּךְ גּוזֵר וּמְקַיֵּם. בָּרוּךְ מְרַחֵם עַל הָאָרֶץ. בָּרוּךְ מְרַחֵם עַל הַבְּרִיּות. בָּרוּךְ מְשַׁלֵּם שכָר טוב לִירֵאָיו. בָּרוּךְ חַי לָעַד וְקַיָּם לָנֶצַח. בָּרוּךְ פּודֶה וּמַצִּיל. בָּרוּךְ שְׁמו:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. הָאֵל, הָאָב הָרַחֲמָן הַמְהֻלָּל בְּפִי עַמּו. מְשֻׁבָּח וּמְפאָר בִּלְשׁון חֲסִידָיו וַעֲבָדָיו. וּבְשִׁירֵי דָוִד עַבְדֶּךָ. נְהַלֶּלְךָ ה' אֱלהֵינוּ בִּשְׁבָחות וּבִזְמִרות. וּנְגַדֶּלְךָ וּנְשַׁבֵּחֲךָ וּנְפָאֶרְךָ, וְנַזְכִּיר שִׁמְךָ מַלְכֵּנוּ אֱלהֵינוּ. יָחִיד חֵי הָעולָמִים. מֶלֶךְ מְשֻׁבָּח וּמְפאָר עֲדֵי עַד שְׁמו הַגָּדול: בָּרוּךְ אַתָּה ה' מֶלֶךְ מְהֻלָּל בַּתִּשְׁבָּחות:"}, {"kind": "header", "text": "הודו"}, {"kind": "text", "text": "הודוּ לה' קִרְאוּ בִשְׁמו. הודִיעוּ בָעַמִּים עֲלִילותָיו: שִׁירוּ לו זַמְּרוּ לו. שיחוּ בְּכָל נִפְלְאותָיו: הִתְהַלְלוּ בְּשֵׁם קָדְשׁו. יִשמַח לֵב מְבַקְשֵׁי ה': דִּרְשׁוּ ה' וְעֻזּו. בַּקְּשׁוּ פָנָיו תָּמִיד: זִכְרוּ נִפְלְאותָיו אֲשֶׁר עָשה. מפְתָיו וּמִשְׁפְּטֵי פִיהוּ: זֶרַע יִשרָאֵל עַבְדּו. בְּנֵי יַעֲקב בְּחִירָיו: הוּא ה' אֱלהֵינוּ. בְּכָל הָאָרֶץ מִשְׁפָּטָיו: זִכְרוּ לְעולָם בְּרִיתו. דָּבָר צִוָּה לְאֶלֶף דּור: אֲשֶׁר כָּרַת אֶת אַבְרָהָם. וּשְׁבוּעָתו לְיִצְחָק: וַיַּעֲמִידֶהָ לְיַעֲקב לְחק. לְיִשרָאֵל בְּרִית עולָם: לֵאמר. לְךָ אֶתֵּן אֶרֶץ כְּנָעַן. חֶבֶל נַחֲלַתְכֶם: בִּהְיותְכֶם מְתֵי מִסְפָּר. כִּמְעַט וְגָרִים בָּהּ: וַיִּתְהַלְּכוּ מִגּוי אֶל גּוי. וּמִמַּמְלָכָה אֶל עַם אַחֵר: לא הִנִּיחַ לְאִישׁ לְעָשְׁקָם. וַיּוכַח עֲלֵיהֶם מְלָכִים: אַל תִּגְּעוּ בִּמְשִׁיחָי וּבִנְבִיאַי אַל תָּרֵעוּ: שִׁירוּ לה' כָּל הָאָרֶץ. בַּשּרוּ מִיּום אֶל יום יְשׁוּעָתו: סַפְּרוּ בַגּויִם אֶת כְּבודו. בְּכָל הָעַמִּים נִפְלְאתָיו: כִּי גָדול ה' וּמְהֻלָּל מְאד. וְנורָא הוּא עַל כָּל אֱלהִים: כִּי כָּל אֱלהֵי הָעַמִּים אֱלִילִים <em>כאן צריך להפסיק</em> וה' שָׁמַיִם עָשה: הוד וְהָדָר לְפָנָיו. עז וְחֶדְוָה בִּמְקומו: הָבוּ לה' מִשְׁפְּחות עַמִּים. הָבוּ לה' כָּבוד וָעז: הָבוּ לה' כְּבוד שְׁמו. שאוּ מִנְחָה וּבאוּ לְפָנָיו. הִשְׁתַּחֲווּ לה' בְּהַדְרַת קדֶשׁ: חִילוּ מִלְּפָנָיו כָּל הָאָרֶץ. אַף תִּכּון תֵּבֵל בַּל תִּמּוט: יִשמְחוּ הַשָּׁמַיִם וְתָגֵל הָאָרֶץ. וְיאמְרוּ בַגּויִם ה' מָלָךְ: יִרְעַם הַיָּם וּמְלאו. יַעֲלץ הַשּדֶה וְכָל אֲשֶׁר בּו: אָז יְרַנְּנוּ עֲצֵי הַיָּעַר מִלִּפְנֵי ה'. כִּי בָא לִשְׁפּוט אֶת הָאָרֶץ: הודוּ לה'. כִּי טוב. כִּי לְעולָם חַסְדּו: וְאִמְרוּ. הושִׁיעֵנוּ אֱלהֵי יִשְׁעֵנוּ. וְקַבְּצֵנוּ וְהַצִּילֵנוּ מִן הַגּויִם. לְהדות לְשֵׁם קָדְשֶׁךָ. לְהִשְׁתַּבֵּחַ בִּתְהִלָּתֶךָ: בָּרוּךְ ה' אֱלהֵי יִשרָאֵל מִן הָעולָם וְעַד הָעולָם וַיּאמְרוּ כָל הָעָם אָמֵן וְהַלֵּל לה': רומְמוּ ה' אֱלהֵינוּ וְהִשְׁתַּחֲווּ לַהֲדם רַגְלָיו. קָדושׁ הוּא: רומְמוּ ה' אֱלהֵינוּ וְהִשְׁתַּחֲווּ לְהַר קָדְשׁו. כִּי קָדושׁ ה' אֱלהֵינוּ: וְהוּא רַחוּם יְכַפֵּר עָון וְלא יַשְׁחִית. וְהִרְבָּה לְהָשִׁיב אַפּו וְלא יָעִיר כָּל חֲמָתו: אַתָּה ה' לא תִכְלָא רַחֲמֶיךָ מִמֶּנִּי. חַסְדְּךָ וַאֲמִתְּךָ תָּמִיד יִצְּרוּנִי: זְכר רַחֲמֶיךָ ה'. וַחֲסָדֶיךָ. כִּי מֵעולָם הֵמָּה: תְּנוּ עז לֵאלהִים עַל יִשרָאֵל גַּאֲוָתו. וְעֻזּו בַּשְּׁחָקִים: נורָא אֱלהִים מִמִּקְדָּשֶׁיךָ. אֵל יִשרָאֵל. הוּא נותֵן עז וְתַעֲצֻמות לָעָם. בָּרוּךְ אֱלהִים: אֵל נְקָמות ה'. אֵל נְקָמות הופִיעַ: הִנָּשא שׁפֵט הָאָרֶץ הָשֵׁב גְּמוּל עַל גֵּאִים: לה' הַיְשׁוּעָה. עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: ה' צְבָאות עִמָּנוּ. מִשגָּב לָנוּ אֱלהֵי יַעֲקב סֶלָה: ה' צְבָאות. אַשְׁרֵי אָדָם בּטֵחַ בָּךְ: ה'. הושִׁיעָה. הַמֶּלֶךְ יַעֲנֵנוּ בְיום קָרְאֵנוּ: הושִׁיעָה אֶת עַמֶּךָ וּבָרֵךְ אֶת נַחֲלָתֶךָ. וּרְעֵם וְנַשּאֵם עַד הָעולָם: נַפְשֵׁנוּ חִכְּתָה לה'. עֶזְרֵנוּ וּמָגִנֵּנוּ הוּא: כִּי בו יִשמַח לִבֵּנוּ. כִּי בְשֵׁם קָדְשׁו בָטָחְנוּ: יְהִי חַסְדְּךָ ה' עָלֵינוּ. כַּאֲשֶׁר יִחַלְנוּ לָךְ: הַרְאֵנוּ ה' חַסְדֶּךָ. וְיֶשְׁעֲךָ תִּתֶּן לָנוּ: קוּמָה עֶזְרָתָה לָנוּ. וּפְדֵנוּ לְמַעַן חַסְדֶּךָ: אָנכִי ה' אֱלהֶיךָ הַמַּעַלְךָ מֵאֶרֶץ מִצְרָיִם. הַרְחֶב פִּיךָ וַאֲמַלְאֵהוּ: אַשְׁרֵי הָעָם שֶׁכָּכָה לּו. אַשְׁרֵי הָעָם שֶׁה' אֱלהָיו: וַאֲנִי בְּחַסְדְּךָ בָטַחְתִּי. יָגֵל לִבִּי בִּישׁוּעָתֶךָ. אָשִׁירָה לה' כִּי גָמַל עָלָי:"}, {"kind": "header", "text": "תהילים יט"}, {"kind": "text", "text": "לַמְנַצֵּחַ מִזְמור לְדָוִד: הַשָּׁמַיִם מְסַפְּרִים כְּבוד אֵל. וּמַעֲשה יָדָיו מַגִּיד הָרָקִיעַ: יום לְיום יַבִּיעַ אמֶר. וְלַיְלָה לְלַיְלָה יְחַוֶּה דָּעַת: אֵין אמֶר וְאֵין דְּבָרִים. בְּלִי נִשְׁמָע קולָם: בְּכָל הָאָרֶץ יָצָא קַוָּם. וּבִקְצֵה תֵבֵל מִלֵּיהֶם. לַשֶּׁמֶשׁ שם אהֶל בָּהֶם: וְהוּא כְּחָתָן יצֵא מֵחֻפָּתו. יָשיש כְּגִבּור לָרוּץ ארַח: מִקְצֵה הַשָּׁמַיִם מוצָאו וּתְקוּפָתו עַל קְצותָם. וְאֵין נִסְתָּר מֵחַמָּתו: תּורַת ה' תְּמִימָה מְשִׁיבַת נָפֶשׁ. עֵדוּת ה' נֶאֱמָנָה מַחְכִּימַת פֶּתִי: פִּקּוּדֵי ה' יְשָׁרִים מְשמְּחֵי לֵב. מִצְוַת ה' בָּרָה מְאִירַת עֵינָיִם: יִרְאַת ה' טְהורָה עומֶדֶת לָעַד. מִשְׁפְּטֵי ה' אֱמֶת צָדְקוּ יַחְדָּו: הַנֶחֱמָדִים מִזָּהָב וּמִפָּז רָב. וּמְתוּקִים מִדְּבַשׁ וְנפֶת צוּפִים: גַּם עַבְדְּךָ נִזְהָר בָּהֶם. בְּשָׁמְרָם עֵקֶב רָב: שְׁגִיאות מִי יָבִין מִנִּסְתָּרות נַקֵּנִי: גַּם מִזֵּדִים חֲשךְ עַבְדֶּךָ. אַל יִמְשְׁלוּ בִי אָז אֵיתָם. וְנִקֵּיתִי מִפֶּשַׁע רָב: יִהְיוּ לְרָצון אִמְרֵי פִי וְהֶגְיון לִבִּי. לְפָנֶיךָ ה' צוּרִי וְגאֲלִי:"}, {"kind": "header", "text": "תהילים לד"}, {"kind": "text", "text": "לְדָוִד בְּשַׁנּותו אֶת טַעְמו לִפְנֵי אֲבִימֶלֶךְ. וַיְגָרְשֵׁהוּ וַיֵּלַךְ: אֲבָרְכָה אֶת ה' בְּכָל עֵת. תָּמִיד תְּהִלָּתו בְּפִי: בה' תִּתְהַלֵּל נַפְשִׁי. יִשְׁמְעוּ עֲנָוִים וְיִשמָחוּ: גַדְּלוּ לה' אִתִּי. וּנְרומְמָה שְׁמו יַחְדָּו: דָּרַשְׁתִּי אֶת ה' וְעָנָנִי. וּמִכָּל מְגוּרותַי הִצִּילָנִי: הִבִּיטוּ אֵלָיו וְנָהָרוּ. וּפְנֵיהֶם אַל יֶחְפָּרוּ: זֶה עָנִי קָרָא וה' שָׁמֵעַ. וּמִכָּל צָרותָיו הושִׁיעו: חונֶה מַלְאַךְ ה' סָבִיב לִירֵאָיו וַיְחַלְּצֵם: טַעֲמוּ וּרְאוּ כִּי טוב ה'. אַשְׁרֵי הַגֶּבֶר יֶחֱסֶה בּו: יְראוּ אֶת ה' קְדושָׁיו. כִּי אֵין מַחְסור לִירֵאָיו: כְּפִירִים רָשׁוּ וְרָעֵבוּ. וְדורְשֵׁי ה' לא יַחְסְרוּ כָל טוב: לְכוּ בָנִים שִׁמְעוּ לִי. יִרְאַת ה' אֲלַמֶּדְכֶם: מִי הָאִישׁ הֶחָפֵץ חַיִּים. אהֵב יָמִים לִרְאות טוב: נְצור לְשׁונְךָ מֵרָע. וּשפָתֶיךָ מִדַּבֵּר מִרְמָה: סוּר מֵרָע וַעֲשה טוב. בַּקֵּשׁ שָׁלום וְרָדְפֵהוּ: עֵינֵי ה' אֶל צַדִּיקִים. וְאָזְנָיו אֶל שַׁוְעָתָם: פְּנֵי ה' בְּעושי רָע. לְהַכְרִית מֵאֶרֶץ זִכְרָם: צָעֲקוּ וה' שָׁמֵעַ. וּמִכָּל צָרותָם הִצִּילָם: קָרוב ה' לְנִשְׁבְּרֵי לֵב. וְאֶת דַּכְּאֵי רוּחַ יושִׁיעַ: רַבּות רָעות צַדִּיק. וּמִכֻּלָּם יַצִּילֶנּוּ ה': שׁמֵר כָּל עַצְמותָיו. אַחַת מֵהֵנָּה לא נִשְׁבָּרָה: תְּמותֵת רָשָׁע רָעָה. וְשנְאֵי צַדִּיק יֶאְשָׁמוּ: פּודֶה ה' נֶפֶשׁ עֲבָדָיו. וְלא יֶאְשְׁמוּ כָּל הַחוסִים בּו:"}, {"kind": "header", "text": "תהילים צ"}, {"kind": "text", "text": "תְּפִלָּה לְמשֶׁה אִישׁ הָאֱלהִים. אֲדנָי מָעון אַתָּה הָיִיתָ לָּנוּ. בְּדור וָדר: בְּטֶרֶם הָרִים יֻלָּדוּ וַתְּחולֵל אֶרֶץ וְתֵבֵל. וּמֵעולָם עַד עולָם אַתָּה אֵל: תָּשֵׁב אֱנושׁ עַד דַּכָּא. וַתּאמֶר שׁוּבוּ בְנֵי אָדָם: כִּי אֶלֶף שָׁנִים בְּעֵינֶיךָ כְּיום אֶתְמול כִּי יַעֲבר. וְאַשְׁמוּרָה בַלָּיְלָה: זְרַמְתָּם שֵׁנָה יִהְיוּ. בַּבּקֶר כֶּחָצִיר יַחֲלף: בַּבּקֶר יָצִיץ וְחָלָף. לָעֶרֶב יְמולֵל וְיָבֵשׁ: כִּי כָלִינוּ בְאַפֶּךָ. וּבַחֲמָתְךָ נִבְהָלְנוּ: שַׁתָּה עֲונותֵינוּ לְנֶגְדֶּךָ. עֲלֻמֵנוּ לִמְאור פָּנֶיךָ: כִּי כָל יָמֵינוּ פָּנוּ בְעֶבְרָתֶךָ. כִּלִּינוּ שָׁנֵינוּ כְּמו הֶגֶה: יְמֵי שְׁנותֵינוּ בָּהֶם שִׁבְעִים שָׁנָה. וְאִם בִּגְבוּרת שְׁמונִים שָׁנָה. וְרָהְבָּם עָמָל וָאָוֶן. כִּי גָז חִישׁ וַנָּעֻפָה: מִי יודֵעַ עז אַפֶּךָ. וּכְיִרְאָתְךָ עֶבְרָתֶךָ: לִמְנות יָמֵינוּ כֵּן הודַע. וְנָבִיא לְבַב חָכְמָה: שׁוּבָה ה' עַד מָתָי. וְהִנָּחֵם עַל עֲבָדֶיךָ: שבְּעֵנוּ בַבּקֶר חַסְדֶּךָ. וּנְרַנְּנָה וְנִשמְחָה בְּכָל יָמֵינוּ: שמְּחֵנוּ כִּימות עִנִּיתָנוּ. שְׁנות רָאִינוּ רָעָה: יֵרָאֶה אֶל עֲבָדֶיךָ פָעֳלֶךָ. וַהֲדָרְךָ עַל בְּנֵיהֶם: וִיהִי נעַם אֲדנָי אֱלהֵינוּ עָלֵינוּ. וּמַעֲשה יָדֵינוּ כּונְנָה עָלֵינוּ. וּמַעֲשה יָדֵינוּ כּונְנֵהוּ:"}, {"kind": "header", "text": "תהילים צא"}, {"kind": "text", "text": "ישֵׁב בְּסֵתֶר עֶלְיון. בְּצֵל שַׁדַּי יִתְלונָן: אמַר לה' מַחְסִי וּמְצוּדָתִי. אֱלהַי אֶבְטַח בּו: כִּי הוּא יַצִּילְךָ מִפַּח יָקוּשׁ. מִדֶּבֶר הַוּות: בְּאֶבְרָתו יָסֶךְ לָךְ. וְתַחַת כְּנָפָיו תֶּחְסֶה. צִנָּה וְסוחֵרָה אֲמִתּו: לא תִירָא מִפַּחַד לָיְלָה. מֵחֵץ יָעוּף יומָם: מִדֶּבֶר בָּאפֶל יַהֲלךְ. מִקֶּטֶב יָשׁוּד צָהֳרָיִם: יִפּל מִצִּדְּךָ אֶלֶף וּרְבָבָה מִימִינֶךָ. אֵלֶיךָ לא יִגָּשׁ: רַק בְּעֵינֶיךָ תַבִּיט. וְשִׁלֻּמַת רְשָׁעִים תִּרְאֶה: כִּי אַתָּה ה' מַחְסִי. עֶלְיון שמְתָּ מְעונֶךָ: לא תְאֻנֶּה אֵלֶיךָ רָעָה. וְנֶגַע לא יִקְרַב בְּאָהֳלֶךָ: כִּי מַלְאָכָיו יְצַוֶּה לָּךְ. לִשְׁמָרְךָ בְּכָל דְּרָכֶיךָ: עַל כַּפַּיִם יִשּאוּנְךָ. פֶּן תִּגּוף בָּאֶבֶן רַגְלֶךָ: עַל שַׁחַל וָפֶתֶן תִּדְרוךְ. תִּרְמוס כְּפִיר וְתַנִּין: כִּי בִי חָשַׁק וַאֲפַלְּטֵהוּ. אֲשגְּבֵהוּ כִּי יָדַע שְׁמִי: יִקְרָאֵנִי וְאֶעֱנֵהוּ. עִמּו אָנכִי בְצָרָה. אֲחַלְּצֵהוּ וַאֲכַבְּדֵהוּ: ארֶךְ יָמִים אַשבִּיעֵהוּ. וְאַרְאֵהוּ בִּישׁוּעָתִי: ארֶךְ יָמִים אַשבִּיעֵהוּ. וְאַרְאֵהוּ בִּישׁוּעָתִי:"}, {"kind": "header", "text": "תהילים קלה"}, {"kind": "text", "text": "הַלְלוּיָהּ. הַלְלוּ אֶת שֵׁם ה'. הַלְלוּ עַבְדֵי ה': שֶׁעומְדִים בְּבֵית ה'. בְּחַצְרות בֵּית אֱלהֵינוּ: הַלְלוּיָהּ כִּי טוב ה'. זַמְּרוּ לִשְׁמו כִּי נָעִים: כִּי יַעֲקב בָּחַר לו יָהּ. יִשרָאֵל לִסְגֻלָּתו: כִּי אֲנִי יָדַעְתִּי כִּי גָּדול ה'. וַאֲדנֵינוּ מִכָּל אֱלהִים: כּל אֲשֶׁר חָפֵץ ה' עָשה. בַּשָּׁמַיִם וּבָאָרֶץ בַּיַּמִּים וְכָל תְּהמת: מַעֲלֶה נְשאִים מִקְצֵה הָאָרֶץ. בְּרָקִים לַמָּטָר עָשה. מוצֵא רוּחַ מֵאוצְרותָיו: שֶׁהִכָּה בְּכורֵי מִצְרָיִם. מֵאָדָם עַד בְּהֵמָה: שָׁלַח אותת וּמופְתִים בְּתוכֵכִי מִצְרָיִם. בְּפַרְעה וּבְכָל עֲבָדָיו: שֶׁהִכָּה גּויִם רַבִּים. וְהָרַג מְלָכִים עֲצוּמִים: לְסִיחון מֶלֶךְ הָאֱמרִי וּלְעוג מֶלֶךְ הַבָּשָׁן. וּלְכל מַמְלְכות כְּנָעַן: וְנָתַן אַרְצָם נַחֲלָה. נַחֲלָה לְיִשרָאֵל עַמּו: ה' שִׁמְךָ לְעולָם. ה' זִכְרְךָ לְדר וָדר: כִּי יָדִין ה' עַמּו. וְעַל עֲבָדָיו יִתְנֶחָם: עֲצַבֵּי הַגּויִם כֶּסֶף וְזָהָב. מַעֲשה יְדֵי אָדָם: פֶּה לָהֶם וְלא יְדַבֵּרוּ. עֵינַיִם לָהֶם וְלא יִרְאוּ: אָזְנַיִם לָהֶם וְלא יַאֲזִינוּ. אַף אֵין יֶשׁ רוּחַ בְּפִיהֶם: כְּמוהֶם יִהְיוּ עשיהֶם. כּל אֲשֶׁר בּטֵחַ בָּהֶם: בֵּית יִשרָאֵל בָּרְכוּ אֶת ה'. בֵּית אַהֲרן בָּרְכוּ אֶת ה': בֵּית הַלֵּוִי בָּרְכוּ אֶת ה'. יִרְאֵי ה' בָּרְכוּ אֶת ה': בָּרוּךְ ה' מִצִּיּון. שׁכֵן יְרוּשָׁלָיִם. הַלְלוּיָהּ:"}, {"kind": "header", "text": "תהילים קלו"}, {"kind": "text", "text": "הודוּ לה' כִּי טוב כִּי לְעולָם חַסְדּו:<br> הודוּ לֵאלהֵי הָאֱלהִים כִּי לְעולָם חַסְדּו:<br> הודוּ לַאֲדנֵי הָאֲדנִים כִּי לְעולָם חַסְדּו:<br> לְעשה נִפְלָאות גְּדלות לְבַדּו כִּי לְעולָם חַסְדּו:<br> לְעשה הַשָּׁמַיִם בִּתְבוּנָה כִּי לְעולָם חַסְדּו:<br> לְרוקַע הָאָרֶץ עַל הַמָּיִם כִּי לְעולָם חַסְדּו:<br> לְעשה אורִים גְּדלִים כִּי לְעולָם חַסְדּו:<br> אֶת הַשֶּׁמֶשׁ לְמֶמְשֶׁלֶת בַּיּום כִּי לְעולָם חַסְדּו:<br> אֶת הַיָּרֵחַ וְכוכָבִים לְמֶמְשְׁלות בַּלָּיְלָה כִּי לְעולָם חַסְדּו:<br> לְמַכֵּה מִצְרַיִם בִּבְכורֵיהֶם כִּי לְעולָם חַסְדּו:<br> וַיּוצֵא יִשרָאֵל מִתּוכָם כִּי לְעולָם חַסְדּו:<br> בְּיָד חֲזָקָה וּבִזְרועַ נְטוּיָה כִּי לְעולָם חַסְדּו:<br> לְגזֵר יַם סוּף לִגְזָרִים כִּי לְעולָם חַסְדּו:<br> וְהֶעֱבִיר יִשרָאֵל בְּתוכו כִּי לְעולָם חַסְדּו:<br> וְנִעֵר פַּרְעה וְחֵילו בְיַם סוּף כִּי לְעולָם חַסְדּו:<br> לְמולִיךְ עַמּו בַּמִּדְבָּר כִּי לְעולָם חַסְדּו:<br> לְמַכֵּה מְלָכִים גְּדלִים כִּי לְעולָם חַסְדּו:<br> וַיַּהֲרג מְלָכִים אַדִּירִים כִּי לְעולָם חַסְדּו:<br> לְסִיחון מֶלֶךְ הָאֱמרִי כִּי לְעולָם חַסְדּו:<br> וּלְעוג מֶלֶךְ הַבָּשָׁן כִּי לְעולָם חַסְדּו:<br> וְנָתַן אַרְצָם לְנַחֲלָה כִּי לְעולָם חַסְדּו:<br> נַחֲלָה לְיִשרָאֵל עַבְדּו כִּי לְעולָם חַסְדּו:<br> שֶׁבְּשִׁפְלֵנוּ זָכַר לָנוּ כִּי לְעולָם חַסְדּו:<br> וַיִּפְרְקֵנוּ מִצָּרֵינוּ כִּי לְעולָם חַסְדּו:<br> נותֵן לֶחֶם לְכָל בָּשר כִּי לְעולָם חַסְדּו:<br> הודוּ לְאֵל הַשָּׁמָיִם כִּי לְעולָם חַסְדּו:"}, {"kind": "header", "text": "תהילים לג"}, {"kind": "text", "text": "רַנְּנוּ צַדִּיקִים בה'. לַיְשָׁרִים נָאוָה תְהִלָּה: הודוּ לה' בְּכִנּור. בְּנֵבֶל עָשור זַמְּרוּ לו: שִׁירוּ לו שִׁיר חָדָשׁ. הֵיטִיבוּ נַגֵּן בִּתְרוּעָה: כִּי יָשָׁר דְבַר ה'. וְכָל מַעֲשהוּ בֶּאֱמוּנָה: אהֵב צְדָקָה וּמִשְׁפָּט. חֶסֶד ה' מָלְאָה הָאָרֶץ: בִּדְבַר ה' שָׁמַיִם נַעֲשוּ. וּבְרוּחַ פִּיו כָּל צְבָאָם: כּנֵס כַּנֵּד מֵי הַיָּם. נתֵן בְּאוצָרות תְּהומות: יִירְאוּ מה' כָּל הָאָרֶץ. מִמֶּנּוּ יָגוּרוּ כָּל ישְׁבֵי תֵבֵל: כִּי הוּא אָמַר וַיֶּהִי. הוּא צִוָּה וַיַּעֲמד: ה' הֵפִיר עֲצַת גּויִם. הֵנִיא מַחְשְׁבות עַמִּים: עֲצַת ה' לְעולָם תַּעֲמד. מַחְשְׁבות לִבּו לְדר וָדר: אַשְׁרֵי הַגּוי אֲשֶׁר ה' אֱלהָיו. הָעָם בָּחַר לְנַחֲלָה לו: מִשָּׁמַיִם הִבִּיט ה'. רָאָה אֶת כָּל בְּנֵי הָאָדָם: מִמְּכון שִׁבְתּו הִשְׁגִּיחַ אֶל כָּל ישְׁבֵי הָאָרֶץ: הַיּוצֵר יַחַד לִבָּם. הַמֵּבִין אֶל כָּל מַעֲשיהֶם: אֵין הַמֶּלֶךְ נושָׁע בְּרָב חָיִל. גִּבּור לא יִנָּצֵל בְּרָב כּחַ: שֶׁקֶר הַסּוּס לִתְשׁוּעָה. וּבְרב חֵילו לא יְמַלֵּט: הִנֵּה עֵין ה' אֶל יְרֵאָיו. לַמְיַחֲלִים לְחַסְדּו: לְהַצִּיל מִמָּוֶת נַפְשָׁם. וּלְחַיּותָם בָּרָעָב: נַפְשֵׁנוּ חִכְּתָה לה'. עֶזְרֵנוּ וּמָגִנֵּנוּ הוּא: כִּי בו יִשמַח לִבֵּנוּ. כִּי בְשֵׁם קָדְשׁו בָטָחְנוּ: יְהִי חַסְדְּךָ ה' עָלֵינוּ. כַּאֲשֶׁר יִחַלְנוּ לָךְ:"}, {"kind": "header", "text": "תהילים צב"}, {"kind": "text", "text": "מִזְמור שִׁיר לְיום הַשַּׁבָּת: טוב לְהודות לה'. וּלְזַמֵּר לְשִׁמְךָ עֶלְיון: לְהַגִּיד בַּבּוקֶר חַסְדֶּךָ. וֶאֱמוּנָתְךָ בַּלֵּילות: עֲלֵי עָשור וַעֲלֵי נָבֶל. עֲלֵי הִגָּיון בְּכִנּור: כִּי שמַּחְתַּנִי ה' בְּפָעֳלֶךָ. בְּמַעֲשי יָדֶיךָ אֲרַנֵּן: מַה גָּדְלוּ מַעֲשיךָ ה'. מְאד עָמְקוּ מַחְשְׁבותֶיךָ: אִישׁ בַּעַר לא יֵדָע. וּכְסִיל לא יָבִין אֶת זאת: בִּפְרחַ רְשָׁעִים כְּמו עֵשב. וַיָּצִיצוּ כָּל פּעֲלֵי אָוֶן. לְהִשָּׁמְדָם עֲדֵי עַד: וְאַתָּה מָרום לְעולָם ה': כִּי הִנֵּה איְבֶיךָ ה'. כִּי הִנֵּה איְבֶיךָ יאבֵדוּ. יִתְפָּרְדוּ כָּל פּעֲלֵי אָוֶן: וַתָּרֶם כִּרְאֵים קַרְנִי. בַּלּתִי בְּשֶׁמֶן רַעֲנָן: וַתַּבֵּט עֵינִי בְּשׁוּרָי. בַּקָּמִים עָלַי מְרֵעִים תִּשְׁמַעְנָה אָזְנָי: צַדִּיק כַּתָּמָר יִפְרָח. כְּאֶרֶז בַּלְּבָנון יִשגֶּה: שְׁתוּלִים בְּבֵית ה'. בְּחַצְרות אֱלהֵינוּ יַפְרִיחוּ: עוד יְנוּבוּן בְּשיבָה. דְּשֵׁנִים וְרַעֲנַנִּים יִהְיוּ: לְהַגִּיד כִּי יָשָׁר ה'. צוּרִי וְלא עַוְלָתָה בּו:"}, {"kind": "header", "text": "תהילים צג"}, {"kind": "text", "text": "ה' מָלָךְ גֵּאוּת לָבֵשׁ. לָבֵשׁ ה' עז הִתְאַזָּר. אַף תִּכּון תֵּבֵל בַּל תִּמּוט: נָכון כִּסְאֲךָ מֵאָז. מֵעולָם אָתָּה: נָשאוּ נְהָרות ה'. נָשאוּ נְהָרות קולָם. יִשאוּ נְהָרות דָּכְיָם: מִקּלות מַיִם רַבִּים אַדִּירִים מִשְׁבְּרֵי יָם. אַדִּיר בַּמָּרום ה': עֵדותֶיךָ נֶאֱמְנוּ מְאד. לְבֵיתְךָ נָאֲוָה קּדֶשׁ. ה' לְארֶךְ יָמִים:"}, {"kind": "header", "text": "יהי כבוד"}, {"kind": "text", "text": "יְהִי כְבוד ה' לְעולָם. יִשמַח ה' בְּמַעֲשיו: יְהִי שֵׁם ה' מְברָךְ. מֵעַתָּה וְעַד עולָם: מִמִּזְרַח שֶׁמֶשׁ עַד מְבואו. מְהֻלָּל שֵׁם ה': רָם עַל כָּל גּויִם ה'. עַל הַשָּׁמַיִם כְּבודו: ה' שִׁמְךָ לְעולָם. ה' זִכְרְךָ לְדור וָדור: ה' בַּשָׁמַיִם הֵכִין כִּסְאו. וּמַלְכוּתו בַּכּל מָשָׁלָה: יִשמְחוּ הַשָּׁמַיִם וְתָגֵל הָאָרֶץ. וְיאמְרוּ בַגּויִם ה' מָלָךְ: ה' מֶלֶךְ. ה' מָלָךְ. ה' יִמְלךְ לְעולָם וָעֶד: ה' מֶלֶךְ עולָם וָעֶד. אָבְדוּ גויִם מֵאַרְצו: ה' הֵפִיר עֲצַת גּויִם. הֵנִיא מַחְשְׁבות עַמִּים: רַבּות מַחֲשָׁבות בְּלֶב אִישׁ. וַעֲצַת ה' הִיא תָקוּם: עֲצַת ה' לְעולָם תַּעֲמוד. מַחְשְׁבות לִבּו לְדר וָדר: כִּי הוּא אָמַר וַיֶּהִי. הוּא צִוָּה וַיַּעֲמד: כִּי בָחַר ה' בְּצִיּון. אִוָּהּ לְמושָׁב לו: כִּי יַעֲקב בָּחַר לו יָהּ. יִשרָאֵל לִסְגֻלָּתו: כִּי לא יִטּשׁ ה' עַמּו. וְנַחֲלָתו לא יַעֲזב: וְהוּא רַחוּם יְכַפֵּר עָון וְלא יַשְׁחִית. וְהִרְבָּה לְהָשִׁיב אַפּו. וְלא יָעִיר כָּל חֲמָתו: ה' הושִׁיעָה. הַמֶּלֶךְ יַעֲנֵנוּ בְיום קָרְאֵנוּ:"}, {"kind": "header", "text": "אשרי"}, {"kind": "text", "text": "אַשְׁרֵי יושְׁבֵי בֵיתֶךָ. עוד יְהַלְלוּךָ סֶּלָה: אַשְׁרֵי הָעָם שֶׁכָּכָה לּו. אַשְׁרֵי הָעָם שה' אֱלהָיו: תְּהִלָּה לְדָוִד. אֲרומִמְךָ אֱלוהַי הַמֶּלֶךְ. וַאֲבָרְכָה שִׁמְךָ לְעולָם וָעֶד: בְּכָל יום אֲבָרְכֶךָּ. וַאֲהַלְלָה שִׁמְךָ לְעולָם וָעֶד: גָּדול ה' וּמְהֻלָּל מְאד. וְלִגְדֻלָּתו אֵין חֵקֶר: דּור לְדור יְשַׁבַּח מַעֲשיךָ. וּגְבוּרתֶיךָ יַגִּידוּ: הֲדַר כְּבוד הודֶךָ. וְדִבְרֵי נִפְלְאתֶיךָ אָשיחָה: וֶעֱזוּז נורְאתֶיךָ יאמֵרוּ. וּגְדֻלָּתְךָ אֲסַפְּרֶנָּה: זֵכֶר רַב טוּבְךָ יַבִּיעוּ. וְצִדְקָתְךָ יְרַנֵּנוּ: חַנּוּן וְרַחוּם ה'. אֶרֶךְ אַפַּיִם וּגְדָל חָסֶד: טוב ה' לַכּל. וְרַחֲמָיו עַל כָּל מַעֲשיו: יודוּךָ ה' כָּל מַעֲשיךָ. וַחֲסִידֶיךָ יְבָרְכוּכָה: כְּבוד מַלְכוּתְךָ יאמֵרוּ. וּגְבוּרָתְךָ יְדַבֵּרוּ: לְהודִיעַ לִבְנֵי הָאָדָם גְּבוּרתָיו. וּכְבוד הֲדַר מַלְכוּתו: מַלְכוּתְךָ מַלְכוּת כָּל עולָמִים. וּמֶמְשַׁלְתְּךָ בְּכָל דּור וָדר: סומֵךְ ה' לְכָל הַנּפְלִים. וְזוקֵף לְכָל הַכְּפוּפִים: עֵינֵי כל אֵלֶיךָ יְשבֵּרוּ. וְאַתָּה נותֵן לָהֶם אֶת אָכְלָם בְּעִתּו: פּותֵחַ אֶת יָדֶךָ. וּמַשבִּיעַ לְכָל חַי רָצון: צַדִּיק ה' בְּכָל דְּרָכָיו. וְחָסִיד בְּכָל מַעֲשיו: קָרוב ה' לְכָל קרְאָיו. לְכל אֲשֶׁר יִקְרָאֻהוּ בֶאֱמֶת: רְצון יְרֵאָיו יַעֲשה. וְאֶת שַׁוְעָתָם יִשְׁמַע וְיושִׁיעֵם: שׁומֵר ה' אֶת כָּל אהֲבָיו. וְאֵת כָּל הָרְשָׁעִים יַשְׁמִיד: תְּהִלַּת ה' יְדַבֶּר פִּי. וִיבָרֵךְ כָּל בָּשר שֵׁם קָדְשׁו לְעולָם וָעֶד: וַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד עולָם. הַלְלוּיָהּ:"}, {"kind": "header", "text": "תהילים קמו"}, {"kind": "text", "text": "הַלְלוּיָהּ. הַלְלִי נַפְשִׁי אֶת ה': אֲהַלְלָה ה' בְּחַיָּי. אֲזַמְּרָה לֵאלהַי בְּעודִי: אַל תִּבְטְחוּ בִנְדִיבִים. בְּבֶן אָדָם שֶׁאֵין לו תְשׁוּעָה: תֵּצֵא רוּחו יָשֻׁב לְאַדְמָתו. בַּיּום הַהוּא אָבְדוּ עֶשְׁתּנתָיו: אַשְׁרֵי שֶׁאֵל יַעֲקב בְּעֶזְרו. שבְרו עַל ה' אֱלהָיו: עשה שָׁמַיִם וָאָרֶץ. אֶת הַיָּם וְאֶת כָּל אֲשֶׁר בָּם. הַשּׁמֵר אֱמֶת לְעולָם: עשה מִשְׁפָּט לַעֲשׁוּקִים. נתֵן לֶחֶם לָרְעֵבִים. ה' מַתִּיר אֲסוּרִים: ה' פּקֵחַ עִוְרִים. ה' זוקֵף כְּפוּפִים. ה' אהֵב צַדִּיקִים: ה' שׁמֵר אֶת גֵּרִים. יָתום וְאַלְמָנָה יְעודֵד. וְדֶרֶךְ רְשָׁעִים יְעַוֵּת: יִמְלךְ ה' לְעולָם. אֱלהַיִךְ צִיּון לְדר וָדר. הַלְלוּיָהּ:"}, {"kind": "header", "text": "תהילים קמז"}, {"kind": "text", "text": "הַלְלוּיָהּ. כִּי טוב זַמְּרָה אֱלהֵינוּ. כִּי נָעִים נָאוָה תְהִלָּה: בּונֵה יְרוּשָׁלַיִם ה'. נִדְחֵי יִשרָאֵל יְכַנֵּס: הָרופֵא לִשְׁבוּרֵי לֵב. וּמְחַבֵּשׁ לְעַצְּבותָם: מונֶה מִסְפָּר לַכּוכָבִים. לְכֻלָּם שֵׁמות יִקְרָא: גָּדול אֲדונֵינוּ וְרַב כּחַ. לִתְבוּנָתו אֵין מִסְפָּר: מְעודֵד עֲנָוִים ה'. מַשְׁפִּיל רְשָׁעִים עֲדֵי אָרֶץ: עֱנוּ לה' בְּתודָה. זַמְּרוּ לֵאלהֵינוּ בְכִנּור: הַמְכַסֶּה שָׁמַיִם בְּעָבִים. הַמֵּכִין לָאָרֶץ מָטָר. הַמַּצְמִיחַ הָרִים חָצִיר: נותֵן לִבְהֵמָה לַחְמָהּ. לִבְנֵי ערֵב אֲשֶׁר יִקְרָאוּ: לא בִגְבוּרַת הַסּוּס יֶחְפָּץ. לא בְשׁוקֵי הָאִישׁ יִרְצֶה: רוצֶה ה' אֶת יְרֵאָיו. אֶת הַמְיַחֲלִים לְחַסְדּו: שַׁבְּחִי יְרוּשָׁלַיִם אֶת ה'. הַלְלִי אֱלהַיִךְ צִיּון: כִּי חִזַּק בְּרִיחֵי שְׁעָרָיִךְ. בֵּרַךְ בָּנַיִךְ בְּקִרְבֵּךְ: הַשּם גְּבוּלֵךְ שָׁלום. חֵלֶב חִטִּים יַשבִּיעֵךְ: הַשּׁלֵחַ אִמְרָתו אָרֶץ. עַד מְהֵרָה יָרוּץ דְּבָרו: הַנּתֵן שֶׁלֶג כַּצָּמֶר. כְּפור כָּאֵפֶר יְפַזֵּר: מַשְׁלִיךְ קַרְחו כְפִתִּים. לִפְנֵי קָרָתו מִי יַעֲמד: יִשְׁלַח דְּבָרו וְיַמְסֵם. יַשֵּׁב רוּחו יִזְּלוּ מָיִם: מַגִּיד דְּבָרָיו לְיַעֲקב. חֻקָּיו וּמִשְׁפָּטָיו לְיִשרָאֵל: לא עָשה כֵן לְכָל גּוי. וּמִשְׁפָּטִים בַּל יְדָעוּם. הַלְלוּיָהּ:"}, {"kind": "header", "text": "תהילים קמח"}, {"kind": "text", "text": "הַלְלוּיָהּ. הַלְלוּ אֶת ה' מִן הַשָּׁמַיִם. הַלְלוּהוּ בַּמְּרומִים: הַלְלוּהוּ כָּל מַלְאָכָיו. הַלְלוּהוּ כָּל צְבָאָיו: הַלְלוּהוּ שֶׁמֶשׁ וְיָרֵחַ. הַלְלוּהוּ כָּל כּוכְבֵי אור: הַלְלוּהוּ שְׁמֵי הַשָּׁמָיִם. וְהַמַּיִם אֲשֶׁר מֵעַל הַשָּׁמָיִם יְהַלְלוּ אֶת שֵׁם ה'. כִּי הוּא צִוָּה וְנִבְרָאוּ: וַיַּעֲמִידֵם לָעַד לְעולָם. חָק נָתַן וְלא יַעֲבור: הַלְלוּ אֶת ה' מִן הָאָרֶץ. תַּנִּינִים וְכָל תְּהמות: אֵשׁ וּבָרָד שֶׁלֶג וְקִיטור. רוּחַ סְעָרָה עשה דְבָרו: הֶהָרִים וְכָל גְבָעות. עֵץ פְּרִי וְכָל אֲרָזִים: הַחַיָּה וְכָל בְּהֵמָה. רֶמֶש וְצִפּור כָּנָף: מַלְכֵי אֶרֶץ וְכָל לְאֻמִּים. שרִים וְכָל שׁפְטֵי אָרֶץ: בַּחוּרִים וְגַם בְּתוּלות. זְקֵנִים עִם נְעָרִים: יְהַלְלוּ אֶת שֵׁם ה'. כִּי נִשגָּב שְׁמו לְבַדּו. הודו עַל אֶרֶץ וְשָׁמָיִם: וַיָּרֶם קֶרֶן לְעַמּו. תְּהִלָּה לְכָל חֲסִידָיו. לִבְנֵי יִשרָאֵל עַם קְרבו. הַלְלוּיָהּ:"}, {"kind": "header", "text": "תהילים קמט"}, {"kind": "text", "text": "הַלְלוּיָהּ. שִׁירוּ לה' שִׁיר חָדָשׁ. תְּהִלָּתו בִּקְהַל חֲסִידִים: יִשמַח יִשרָאֵל בְּעשיו. בְּנֵי צִיּון יָגִילוּ בְמַלְכָּם: יְהַלְלוּ שְׁמו בְמָחול. בְּתף וְכִנּור יְזַמְּרוּ לו: כִּי רוצֶה ה' בְּעַמּו. יְפָאֵר עֲנָוִים בִּישׁוּעָה: יַעְלְזוּ חֲסִידִים בְּכָבוד. יְרַנְּנוּ עַל מִשְׁכְּבותָם: רומְמות אֵל בִּגְרונָם. וְחֶרֶב פִּיפִיּות בְּיָדָם: לַעֲשות נְקָמָה בַגּויִם. תּוכֵחות בַּלְאֻמִּים: לֶאְסר מַלְכֵיהֶם בְּזִקִּים. וְנִכְבְּדֵיהֶם בְּכַבְלֵי בַרְזֶל: לַעֲשות בָּהֶם מִשְׁפָּט כָּתוּב. הָדָר הוּא לְכָל חֲסִידָיו. הַלְלוּיָהּ:"}, {"kind": "header", "text": "תהילים קנ"}, {"kind": "text", "text": "הַלְלוּיָהּ. הַלְלוּ אֵל בְּקָדְשׁו. הַלְלוּהוּ בִּרְקִיעַ עֻזּו: הַלְלוּהוּ בִּגְבוּרתָיו. הַלְלוּהוּ כְּרב גֻּדְלו: הַלְלוּהוּ בְּתֵקַע שׁופָר. הַלְלוּהוּ בְּנֵבֶל וְכִנּור: הַלְלוּהוּ בְּתף וּמָחול. הַלְלוּהוּ בְּמִנִּים וְעֻגָב: הַלְלוּהוּ בְּצִלְצְלֵי שָׁמַע. הַלְלוּהוּ בְּצִלְצְלֵי תְרוּעָה: כּל הַנְּשָׁמָה תְּהַלֵּל יָהּ. הַלְלוּיָהּ: כּל הַנְּשָׁמָה תְּהַלֵּל יָהּ. הַלְלוּיָהּ:"}, {"kind": "header", "text": "ברוך ה׳"}, {"kind": "text", "text": "בָּרוּךְ ה' לְעולָם. אָמֵן וְאָמֵן: בָּרוּךְ ה' מִצִּיּון שׁכֵן יְרוּשָׁלָיִם. הַלְלוּיָהּ: בָּרוּךְ ה' אֱלהִים אֱלהֵי יִשרָאֵל. עשה נִפְלָאות לְבַדּו: וּבָרוּךְ שֵׁם כְּבודו לְעולָם. וְיִמָּלֵא כְבודו אֶת כָּל הָאָרֶץ. אָמֵן וְאָמֵן:"}, {"kind": "header", "text": "ויברך דוד"}, {"kind": "text", "text": "וַיְבָרֶךְ דָּוִיד אֶת ה' לְעֵינֵי כָּל הַקָּהָל. וַיּאמֶר דָּוִיד. בָּרוּךְ אַתָּה ה' אֱלהֵי יִשרָאֵל אָבִינוּ. מֵעולָם וְעַד עולָם: לְךָ ה' הַגְּדֻלָּה וְהַגְּבוּרָה וְהַתִּפְאֶרֶת וְהַנֵּצַח וְהַהוד. כִּי כל בַּשָּׁמַיִם וּבָאָרֶץ. לְךָ ה' הַמַּמְלָכָה. וְהַמִּתְנַשּא לְכל לְראשׁ: וְהָעשֶׁר וְהַכָּבוד מִלְּפָנֶיךָ. וְאַתָּה מושֵׁל בַּכּל. וּבְיָדְךָ כּחַ וּגְבוּרָה. וּבְיָדְךָ לְגַדֵּל וּלְחַזֵּק לַכּל: וְעַתָּה אֱלהֵינוּ מודִים אֲנַחְנוּ לָךְ. וּמְהַלְלִים לְשֵׁם תִּפְאַרְתֶּךָ:"}, {"kind": "text", "text": "אַתָּה הוּא ה' לְבַדֶּךָ. אַתָּה עָשיתָ אֶת הַשָּׁמַיִם. שְׁמֵי הַשָּׁמַיִם וְכָל צְבָאָם. הָאָרֶץ וְכָל אֲשֶׁר עָלֶיהָ. הַיַּמִּים וְכָל אֲשֶׁר בָּהֶם. וְאַתָּה מְחַיֶּה אֶת כֻּלָּם. וּצְבָא הַשָּׁמַיִם לְךָ מִשְׁתַּחֲוִים: אַתָּה הוּא ה' הָאֱלהִים. אֲשֶׁר בָּחַרְתָּ בְּאַבְרָם. וְהוצֵאתו מֵאוּר כַּשדִּים. וְשמְתָּ שְׁמו אַבְרָהָם: וּמָצָאתָ אֶת לְבָבו נֶאֱמָן לְפָנֶיךָ:"}, {"kind": "text", "text": "וְכָרות עִמּו הַבְּרִית לָתֵת אֶת אֶרֶץ הַכְּנַעֲנִי. הַחִתִּי הָאֱמרִי וְהַפְּרִזִּי וְהַיְבוּסִי וְהַגִּרְגָּשִׁי לָתֵת לְזַרְעו. וַתָּקֶם אֶת דְּבָרֶיךָ כִּי צַדִּיק אָתָּה: וַתֵּרֶא אֶת עֳנִי אֲבותֵינוּ בְּמִצְרָיִם. וְאֶת זַעֲקָתָם שָׁמַעְתָּ עַל יַם סוּף: וַתִּתֵּן אתת וּמפְתִים בְּפַרְעה וּבְכָל עֲבָדָיו וּבְכָל עַם אַרְצו. כִּי יָדַעְתָּ כִּי הֵזִידוּ עֲלֵיהֶם וַתַּעַש לְךָ שֵׁם כְּהַיּום הַזֶּה: וְהַיָּם בָּקַעְתָּ לִפְנֵיהֶם וַיַּעַבְרוּ בְתוךְ הַיָּם בַּיַּבָּשָׁה."}, {"kind": "text", "text": "וְאֶת רדְפֵיהֶם הִשְׁלַכְתָּ בִמְצולת כְּמו אֶבֶן. בְּמַיִם עַזִּים:"}, {"kind": "header", "text": "אז ישיר"}, {"kind": "text", "text": "וַיּושַׁע ה' בַּיּום הַהוּא אֶת יִשְׂרָאֵל מִיַּד מִצְרָיִם. וַיַּרְא יִשְׂרָאֵל אֶת מִצְרַיִם מֵת. עַל שפַת הַיָּם: וַיַּרְא יִשְׂרָאֵל אֶת הַיָּד הַגְּדלָה אֲשֶׁר עָשה ה' בְּמִצְרַיִם. וַיִּירְאוּ הָעָם אֶת ה'. וַיַּאֲמִינוּ בה' וּבְמשֶׁה עַבְדּו:"}, {"kind": "text", "text": "אָז יָשִׁיר משֶׁה וּבְנֵי יִשְׂרָאֵל אֶת הַשִּׁירָה הַזּאת לה’. וַיּאמְרוּ לֵאמר. אָשִׁירָה לה' כִּי גָּאה גָּאָה. סוּס וְרכְבו רָמָה בַיָּם: עָזִּי וְזִמְרָת יָהּ. וַיְהִי לִי לִישׁוּעָה. זֶה אֵלִי וְאַנְוֵהוּ. אֱלהֵי אָבִי וַאֲרמְמֶנְהוּ: ה' אִישׁ מִלְחָמָה. ה' שְׁמו: מַרְכְּבת פַּרְעה וְחֵילו יָרָה בַיָּם. וּמִבְחַר שָׁלִשָׁיו טֻבְּעוּ בְיַם סוּף: תְּהמת יְכַסְיֻמוּ. יָרְדוּ בִמְצולת כְּמו אָבֶן: יְמִינְךָ ה' נֶאְדָּרִי בַּכּחַ. יְמִינְךָ ה' תִּרְעַץ אויֵב: וּבְרב גְּאונְךָ תַּהֲרס קָמֶיךָ. תְּשַׁלַּח חֲרנְךָ יאכְלֵמו כַּקַּשׁ: וּבְרוּחַ אַפֶּיךָ נֶעֶרְמוּ מַיִם. נִצְּבוּ כְמו נֵד נזְלִים. קָפְאוּ תְהמת בְּלֶב יָם: אָמַר אויֵב אֶרְדּף אַשּיג אֲחַלֵּק שָׁלָל. תִּמְלָאֵמו נַפְשִׁי. אָרִיק חַרְבִּי. תּורִישֵׁמו יָדִי: נָשַׁפְתָּ בְרוּחֲךָ כִּסָּמו יָם. צָלֲלוּ כַּעופֶרֶת בְּמַיִם אַדִּירִים: מִי כָמֹכָה בָּאֵלִם יְהוָה מִי כָּמֹכָה נֶאְדָּר בַּקֹּדֶשׁ נוֹרָא תְהִלֹּת עֹשֵׂה פֶלֶא: נָטִיתָ יְמִינְךָ תִּבְלָעֵמו אָרֶץ: נָחִיתָ בְחַסְדְּךָ עַם זוּ גָּאָלְתָּ. נֵהַלְתָּ בְעָזְּךָ אֶל נְוֵה קָדְשֶׁךָ: שָׁמְעוּ עַמִּים יִרְגָּזוּן. חִיל אָחַז ישְׁבֵי פְּלָשֶׁת: אָז נִבְהֲלוּ אַלּוּפֵי אֱדום. אֵילֵי מואָב יאחֲזֵמו רָעַד. נָמגוּ כּל ישְׁבֵי כְנָעַן: תִּפּל עֲלֵיהֶם אֵימָתָה וָפַחַד. בִּגְדל זְרועֲךָ יִדְּמוּ כָּאָבֶן. עַד יַעֲבר עַמְּךָ ה'. עַד יַעֲבר עַם זוּ קָנִיתָ: תְּבִאֵמו וְתִטָּעֵמו בְּהַר נַחֲלָתְךָ. מָכון לְשִׁבְתְּךָ פָּעַלְתָּ ה'. מִקְּדָשׁ. אֲדנָי כּונְנוּ יָדֶיךָ: ה' יִמְלךְ לְעלָם וָעֶד: ה' יִמְלךְ לְעלָם וָעֶד: ה' מַלְכוּתֵהּ קָאֵם לְעָלַם וּלְעָלְמֵי עָלְמַיָּא: כִּי בָא סוּס פַּרְעה בְּרִכְבּו וּבְפָרָשָׁיו בַּיָּם. וַיָּשֶׁב ה' עֲלֵיהֶם אֶת מֵי הַיָּם. וּבְנֵי יִשְׂרָאֵל הָלְכוּ בַיַּבָּשָׁה בְּתוךְ הַיָּם: כִּי לה' הַמְּלוּכָה. וּמושֵׁל בַּגּויִם: וְעָלוּ מושִׁיעִים בְּהַר צִיּון לִשְׁפּט אֶת הַר עֵשו. וְהָיְתָה לה' הַמְּלוּכָה: וְהָיָה ה' לְמֶלֶךְ עַל כָּל הָאָרֶץ. בַּיּום הַהוּא יִהְיֶה ה' אֶחָד וּשְׁמו אֶחָד:"}, {"kind": "header", "text": "נשמת כל חי"}, {"kind": "text", "text": "נִשְׁמַת כָּל חַי תְּבָרֵךְ אֶת שִׁמְךָ ה' אֱלהֵינוּ. וְרוּחַ כָּל בָּשר תְּפָאֵר וּתְרומֵם זִכְרְךָ מַלְכֵּנוּ תָּמִיד: מִן הָעולָם וְעַד הָעולָם אַתָּה אֵל. וּמִבַּלְעָדֶיךָ אֵין לָנוּ מֶלֶךְ גּואֵל וּמושִׁיעַ. פּודֶה וּמַצִּיל וּמְפַרְנֵס וּמְרַחֵם בְּכָל עֵת צָרָה וְצוּקָה. אֵין לָנוּ מֶלֶךְ עוזֵר וְסומֵךְ אֶלָּא אָתָּה: אֱלהֵי הָרִאשׁונִים וְהָאַחֲרונִים. אֱלוהַּ כָּל בְּרִיות. אֲדון כָּל תּולָדות. הַמְּהֻלָּל בְּרוב הַתִּשְׁבָּחות. הַמְּנַהֵג עולָמו בְּחֶסֶד וּבְרִיּותָיו בְּרַחֲמִים: וה' לא יָנוּם וְלא יִישָׁן. הַמְעורֵר יְשֵׁנִים. וְהַמֵּקִיץ נִרְדָּמִים. וְהַמֵּשיחַ אִלְמִים. וְהַמַּתִּיר אֲסוּרִים. וְהַסּומֵךְ נופְלִים. וְהַזּוקֵף כְּפוּפִים. לְךָ לְבַדְּךָ אֲנַחְנוּ מודִים: אִלּוּ פִינוּ מָלֵא שִׁירָה כַּיָּם. וּלְשׁונֵנוּ רִנָּה כַּהֲמון גַּלָּיו. וְשפְתותֵינוּ שֶׁבַח כְּמֶרְחֲבֵי רָקִיעַ. וְעֵינֵינוּ מְאִירות כַּשֶּׁמֶשׁ וְכַיָּרֵחַ. וְיָדֵינוּ פְרוּשות כְּנִשְׁרֵי שָׁמָיִם. וְרַגְלֵינוּ קַלּות כָּאַיָּלות. אֵין אֲנַחְנוּ מַסְפִּיקִים לְהודות לְךָ ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. וּלְבָרֵךְ אֶת שְׁמֶךָ עַל אַחַת מֵאֶלֶף אַלְפֵי אֲלָפִים וְרִבֵּי רְבָבות פְּעָמִים. הַטּובות שֶׁעָשיתָ עִם אֲבותֵינוּ וְעִמָּנוּ: מִמִּצְרַיִם גְּאַלְתָּנוּ ה' אֱלהֵינוּ. וּמִבֵּית עֲבָדִים פְּדִיתָנוּ. בְּרָעָב זַנְתָּנוּ. וּבְשבָע כִּלְכַּלְתָּנוּ. מֵחֶרֶב הִצַּלְתָּנוּ. וּמִדֶּבֶר מִלַּטְתָּנוּ. וּמֵחֳלָיִם רָעִים וְנֶאֱמָנִים דִּלִּיתָנוּ: עַד הֵנָּה עֲזָרוּנוּ רַחֲמֶיךָ. וְלא עֲזָבוּנוּ חֲסָדֶיךָ וְאַל תִּטְּשֵׁנוּ ה' אֱלהֵינוּ לָנֶצַח: עַל כֵּן אֵבָרִים שֶׁפִּלַּגְתָּ בָּנוּ. וְרוּחַ וּנְשָׁמָה שֶׁנָּפַחְתָּ בְּאַפֵּינוּ. וְלָשׁון אֲשֶׁר שמְתָּ בְּפִינוּ. הֵן הֵם. יודוּ וִיבָרְכוּ וִישַׁבְּחוּ וִיפָאֲרוּ וִירומְמוּ וְיַעֲרִיצוּ וְיַקְדִּישׁוּ וְיַמְלִיכוּ אֶת שִׁמְךָ מַלְכֵּנוּ: כִּי כָל פֶּה לְךָ יודֶה. וְכָל לָשׁון לְךָ תִשָּׁבַע. וְכָל בֶּרֶךְ לְךָ תִכְרַע. וְכָל קומָה לְפָנֶיךָ תִשְׁתַּחֲוֶה. וְכָל לְּבָבות יִירָאוּךָ. וְכָל קֶרֶב וּכְלָיות יְזַמְּרוּ לִשְׁמֶךָ. כַּדָּבָר שֶׁכָּתוּב. כָּל עַצְמותַי תּאמַרְנָה ה' מִי כָמוךָ. מַצִּיל עָנִי מֵחָזָק מִמֶּנּוּ. וְעָנִי וְאֶבְיון מִגּוזְלו. מִי יִדְמֶה לָּךְ. וּמִי יִשְׁוֶה לָּךְ. וּמִי יַעֲרָךְ לָךְ. הָאֵל הַגָּדול הַגִּבּור וְהַנּורָא אֵל עֶלְיון. קונֵה שָׁמַיִם וָאָרֶץ: נְהַלֶּלְךָ וּנְשַׁבֵּחֲךָ וּנְפָאֶרְךָ וּנְבָרֵךְ אֶת שֵׁם קָדְשֶׁךָ. כָּאָמוּר, לְדָוִד, בָּרְכִי נַפְשִׁי אֶת ה'. וְכָל קְרָבַי אֶת שֵׁם קָדְשׁו:"}, {"kind": "header", "text": "שוכן עד"}, {"kind": "text", "text": "<em>ביום טוב ינגן החזן \"האל בתעצומות”:</em> <br> הָאֵל בְּתַעֲצֻמות עֻזֶּךָ. הַגָּדול בִּכְבוד שְׁמֶךָ. הַגִּבּור לָנֶצַח וְהַנּורָא בְּנורְאותֶיךָ: הַמֶּלֶךְ הַיּושֵׁב עַל כִּסֵּא רָם וְנִשּא:"}, {"kind": "text", "text": "<em>בשבת מתחיל החזן \"שוכן עד”:</em> <br> שׁוכֵן עַד מָרום וְקָדושׁ שְׁמו. וְכָתוּב רַנְּנוּ צַדִּיקִים בה'. לַיְשָׁרִים נָאוָה תְהִלָּה:"}, {"kind": "text", "text": "בְּפִי יְשָׁרִים תִּתְהַלָּל. <br> וּבְדִבְרֵי צַדִּיקִים תִּתְבָּרַךְ. <br> וּבִלְשׁון חֲסִידִים תִּתְרומָם. <br> וּבְקֶרֶב קְדושִׁים תִּתְקַדָּשׁ:"}, {"kind": "text", "text": "וּבְמַקְהֲלות רִבְבות עַמְּךָ בֵּית יִשרָאֵל. בְּרִנָּה יִתְפָּאַר שִׁמְךָ מַלְכֵּנוּ בְּכָל דּור וָדור. שֶׁכֵּן חובַת כָּל הַיְצוּרִים. לְפָנֶיךָ ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. לְהודות לְהַלֵּל לְשַׁבֵּחַ לְפָאֵר לְרומֵם לְהַדֵּר לְבָרֵךְ לְעַלֵּה וּלְקַלֵּס. עַל כָּל דִּבְרֵי שִׁירות וְתִשְׁבְּחות דָּוִד בֶּן יִשַׁי עַבְדְּךָ מְשִׁיחֶךָ:"}, {"kind": "header", "text": "ישתבח"}, {"kind": "text", "text": "יִשְׁתַּבַּח שִׁמְךָ לָעַד מַלְכֵּנוּ. הָאֵל הַמֶּלֶךְ הַגָּדול וְהַקָּדושׁ בַּשָּׁמַיִם וּבָאָרֶץ. כִּי לְךָ נָאֶה ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ שִׁיר וּשְׁבָחָה. הַלֵּל וְזִמְרָה. עוז וּמֶמְשָׁלָה. נֶצַח גְּדֻלָּה וּגְבוּרָה. תְּהִלָּה וְתִפְאֶרֶת. קְדֻשָּׁה וּמַלְכוּת: בְּרָכות וְהודָאות מֵעַתָּה וְעַד עולָם: בָּרוּךְ אַתָּה ה'. אֵל מֶלֶךְ גָּדול בַּתִּשְׁבָּחות אֵל הַהודָאות. אֲדון הַנִּפְלָאות. הַבּוחֵר בְּשִׁירֵי זִמְרָה. מֶלֶךְ אֵל חֵי הָעולָמִים:"}, {"kind": "header", "text": "תהילים קל"}, {"kind": "text", "text": "<em>בשבת תשובה אומרים מזמור זה פסוק בפסוק:</em> <br> שִׁיר הַמַּעֲלות. מִמַּעֲמַקִּים קְרָאתִיךָ ה': אֲדנָי שִׁמְעָה בְקולִי. תִּהְיֶינָה אָזְנֶיךָ קַשֻּׁבות לְקול תַּחֲנוּנָי: אִם עֲונות תִּשְׁמָר יָהּ. אֲדנָי מִי יַעֲמוד: כִּי עִמְּךָ הַסְּלִיחָה לְמַעַן תִּוָּרֵא: קִוִּיתִי ה'. קִוְּתָה נַפְשִׁי. וְלִדְבָרו הוחָלְתִּי: נַפְשִׁי לַאדנָי. מִשּׁומְרִים לַבּקֶר שׁומְרִים לַבּקֶר: יַחֵל יִשרָאֵל אֶל ה'. כִּי עִם ה' הַחֶסֶד וְהַרְבֵּה עִמּו פְדוּת: וְהוּא יִפְדֶּה אֶת יִשרָאֵל מִכּל עֲונותָיו:"}, {"kind": "header", "text": "חצי קדיש"}, {"kind": "text", "text": "<em>חזן:</em> יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [<em>קהל:</em> אמן] <br> בְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן] <br> <em>קהל וחזן:</em> יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא: <br> יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרומַם וְיִתְנַשּא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא. [<em>קהל:</em> בריך הוא:] <br> לְעֵלָּא <em>בעשי\"ת לְעֵלָּא לְעֵלָּא מִכָּל</em> מִן כָּל בִּרְכָתָא וְשִׁירָתָא תֻּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן]"}, {"kind": "header", "text": "ברכו"}, {"kind": "text", "text": "<em>חזן:</em> בָּרְכוּ אֶת ה' הַמְברָךְ:"}, {"kind": "text", "text": "<em>קו”ח:</em> בָּרוּךְ ה' הַמְברָךְ לְעולָם וָעֶד: בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. יוצֵר אור וּבורֵא חשֶׁךְ. עשה שָׁלום וּבורֵא אֶת הַכּל:"}, {"kind": "header", "text": "יוצר אור"}, {"kind": "text", "text": "<em>כשחל יום טוב ביום חול אומרים \"המאיר לארץ\" במקום \"הכל יודוך\":</em>"}, {"kind": "text", "text": "הַכּל יוֹדוּךָ. וְהַכּל יְשַׁבְּחוּךָ. וְהַכּל יֹאמְרוּ אֵין קָדושׁ כַּיהוָה: הַכֹּל יְרומְמוּךָ סֶּלָה יוצֵר הַכֹּל: הָאֵל הַפּוֹתֵחַ בְּכָל יוֹם דַּלְתות שַׁעֲרֵי מִזְרָח. וּבוֹקֵעַ חַלּונֵי רָקִיעַ. מוֹצִיא חַמָּה מִמְּקוֹמָהּ. וּלְבָנָה מִמְּכוֹן שִׁבְתָּהּ. וּמֵאִיר לָעוֹלָם כֻּלּו וּלְיוֹשְׁבָיו. שֶׁבָּרָא בְּמִדַּת הָרַחֲמִים: הַמֵּאִיר לָאָרֶץ וְלַדָּרִים עָלֶיהָ בְּרַחֲמִים. וּבְטוּבוֹ מְחַדֵּשׁ בְּכָל יוֹם תָּמִיד. מַעֲשֵׂה בְּרֵאשִׁית: הַמֶּלֶךְ הַמְּרוֹמָם לְבַדּו מֵאָז. הַמְּשֻׁבָּח וְהַמְּפֹאָר וְהַמִּתְנַשֵּׂא מִיְּמוֹת עוֹלָם: אֱלֹהֵי עוֹלָם. בְּרַחֲמֶיךָ הָרַבִּים רַחֵם עָלֵינוּ. אֲדון עֻזֵּנוּ. צוּר מִשְׂגַּבֵּנוּ. מָגֵן יִשְׁעֵנוּ. מִשְׂגָּב בַּעֲדֵנוּ: אֵין כְּעֶרְכֶּךָ. וְאֵין זוּלָתֶךָ. אֶפֶס בִּלְתֶּךָ וּמִי דּוֹמֶה לָּךְ. אֵין כְּעֶרְכֶּךָ ה' אֱלֹהֵינוּ בָּעוֹלָם הַזֶּה. וְאֵין זוּלָתְךָ מַלְכֵּנוּ לְחַיֵּי הָעולָם הַבָּא. אֶפֶס בִּלְתְּךָ גּוֹאֲלֵנוּ לִימות הַמָּשִׁיחַ. וְאֵין דּוֹמֶה לְּךָ מוֹשִׁיעֶנּוּ לִתְחִיַּת הַמֵּתִים:"}, {"kind": "text", "text": "אֵל אָדוֹן עַל כָּל הַמַּעֲשִׂים. בָּרוּךְ וּמְבֹרַךְ בְּפִי כָּל נְּשָׁמָה. גָּדְלוֹ וְטוּבוֹ לִפְנֵי עוֹלָם. דַּעַת וּתְבוּנָה סוֹבְבִים אוֹתוֹ:<br> הַמִּתְגָּאֶה עַל חַיּוֹת הַקּדֶשׁ. וְנֶהְדָּר בְּכָבוֹד עַל הַמֶּרְכָּבָה. זְכוּת וּמִישׁור לִפְנֵי כִסְאו. חֶסֶד וְרַחֲמִים מָלֵא כְבוֹדוֹ:<br> טוֹבִים מְאוֹרוֹת שֶׁבָּרָא אֱלֹהֵינוּ. יְצָרָם בְּדַעַת בְּבִינָה וּבְהַשְׂכֵּל. כֹּחַ וּגְבוּרָה נָתַן בָּהֶם. לִהְיוֹת מוֹשְׁלִים בְּקֶרֶב תֵּבֵל: <br> מְלֵאִים זִיו וּמְפִיקִים נוֹגָהּ. נָאֶה זִיוָם בְּכָל הָעוֹלָם. שְׂמֵחִים בְּצֵאתָם וְשָׂשִׂים בְּבוֹאָם. עוֹשִׂים בְּאֵימָה רְצוֹן קוֹנָם: <br> פְּאֵר וְכָבוֹד נוֹתְנִים לִשְׁמוֹ. צָהֳלָה וְרִנָּה לְזֵכֶר מַלְכוּתוֹ. קָרָא לַשֶּׁמֶשׁ וַיִּזְרַח אוֹר. רָאָה וְהִתְקִין צוּרַת הַלְּבָנָה: שֶׁבַח נוֹתְנִים לוֹ כָּל צְבָא מָרוֹם. תִּפְאֶרֶת וּגְדֻלָּה שְׂרָפִים וְאוֹפַנִּים וְחַיּוֹת הַקֹּדֶשׁ:"}, {"kind": "text", "text": "לָאֵל אֲשֶׁר שָׁבַת מִכָּל הַמַּעֲשִׂים. בַּיּוֹם הַשְּׁבִיעִי הִתְעַלָּה וְיָשַׁב עַל כִּסֵּא כְבוֹדוֹ. תִּפְאֶרֶת עָטָה לְיוֹם הַמְּנוּחָה. עֹנֶג קָרָא לְיוֹם הַשַּׁבָּת. זֶה שֶׁבַח שֶׁל יוֹם הַשְּׁבִיעִי. שֶׁבּו שָׁבַת אֶל מִכָּל מְלַאכְתּו: וְיום הַשְּׁבִיעִי מְשַׁבֵּחַ וְאומֵר. מִזְמוֹר שִׁיר לְיוֹם הַשַּׁבָּת. טוֹב לְהוֹדוֹת לַה': לְפִיכָךְ יְפָאֲרוּ וִיבָרְכוּ לָאֵל כָּל יְצוּרָיו. שֶׁבַח יְקָר וּגְדֻלָּה. יִתְּנוּ לָאֵל מֶלֶךְ יוֹצֵר כָּל. הַמַּנְחִיל מְנוּחָה לְעַמּו יִשרָאֵל בִּקְדֻשָּׁתו בְּיום שַׁבַּת קדֶשׁ: שִׁמְךָ ה' אֱלֹהֵינוּ יִתְקַדַּשׁ. וְזִכְרְךָ מַלְכֵּנוּ יִתְפָּאַר. בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת: תִּתְבָּרַךְ מוֹשִׁיעֶנּוּ עַל שֶׁבַח מַעֲשי יָדֶיךָ. וְעַל מְאוֹרֵי אוֹר שֶׁעָשיתָ יְפָאֲרוּךָ סֶלָה:"}, {"kind": "text", "text": "<em>כְּשֶׁחָל יו\"ט בְּיוֹם חֹל אוֹמְרִים הַמֵּאִיר לָאָרֶץ בִּמְקוֹם \"הַכֹּל יוֹדוּךְ\":</em> <br> הַמֵּאִיר לָאָרֶץ וְלַדָּרִים עָלֶיהָ בְּרַחֲמִים. וּבְטוּבוֹ מְחַדֵּשׁ בְּכָל יוֹם תָּמִיד מַעֲשֵׂה בְרֵאשִׁית. מָה רַבּוּ מַעֲשֶׂיךָ ה'. כֻּלָּם בְּחָכְמָה עָשִׂיתָ. מָלְאָה הָאָרֶץ קִנְיָנֶךָ: הַמֶּלֶךְ הַמְרומָם לְבַדּוֹ מֵאָז. הַמְשֻׁבָּח וְהַמְּפֹאָר וְהַמִּתְנַשֵּׂא מִיְּמוֹת עוֹלָם: אֱלֹהֵי עוֹלָם. בְּרַחֲמֶיךָ הָרַבִּים רַחֵם עָלֵינוּ. אֲדוֹן עֻזֵּנוּ. צוּר מִשְׂגַּבֵּנוּ. מָגֵן יִשְׁעֵנוּ. מִשְׂגָּב בַּעֲדֵנוּ: אֶל בָּרוּךְ גְּדוֹל דֵּעָה. הֵכִין וּפָעַל זָהֳרֵי חַמָּה. טוֹב יָצַר כָּבוֹד לִשְׁמוֹ. מְאוֹרוֹת נָתַן סְבִיבוֹת עֻזּוֹ. פִּנּוֹת צְבָאָיו קְדושִׁים. רוֹמְמֵי שַׁדַּי. תָּמִיד מְסַפְּרִים כְּבוֹד אֶל וּקְדֻשָּׁתו:"}, {"kind": "text", "text": "תִּתְבָּרַךְ ה' אֱלֹהֵינוּ בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת עַל שֶׁבַח מַעֲשֵׂי יָדֶיךָ. וְעַל מְאוֹרֵי אוֹר שֶׁעָשִׂיתָ יְפָאֲרוּךָ סֶלָה:"}, {"kind": "text", "text": "תִּתְבָּרַךְ צוּרֵנוּ מַלְכֵּנוּ וְגואֲלֵנוּ בּוֹרֵא קְדוֹשִׁים. יִשְׁתַּבַּח שִׁמְךָ לָעַד מַלְכֵּנוּ יוֹצֵר מְשָׁרְתִים וַאֲשֶׁר מְשָׁרְתָיו כֻּלָּם עוֹמְדִים בְּרוּם עוֹלָם. וּמַשְׁמִיעִים בְּיִרְאָה יַחַד בְּקוֹל. דִּבְרֵי אֱלֹהִים חַיִּים וּמֶלֶךְ עוֹלָם: כֻּלָּם אֲהוּבִים. כֻּלָּם בְּרוּרִים. כֻּלָּם גִּבּורִים. וְכֻלָּם עוֹשִׂים בְּאֵימָה וּבְיִרְאָה רְצוֹן קוֹנָם: וְכֻלָּם פּוֹתְחִים אֶת פִּיהֶם בִּקְדֻשָּׁה וּבְטָהֳרָה. בְּשִׁירָה וּבְזִמְרָה. וּמְבָרְכִים וּמְשַׁבְּחִים וּמְפָאֲרִים וּמַעֲרִיצִים וּמַקְדִּישִׁים וּמַמְלִיכִים:"}, {"kind": "text", "text": "אֶת שֵׁם הָאֵל, הַמֶּלֶךְ הַגָּדול הַגִּבּוֹר וְהַנּוֹרָא קָדוֹשׁ הוּא. וְכֻלָּם מְקַבְּלִים עֲלֵיהֶם עֹל מַלְכוּת שָׁמַיִם זֶה מִזֶּה. וְנוֹתְנִים רְשׁוּת זֶה לָזֶה לְהַקְדִּישׁ לְיוֹצְרָם בְּנַחַת רוּחַ. בְּשָׂפָה בְרוּרָה וּבִנְעִימָה. קְדֻשָׁה כֻּלָּם כְּאֶחָד. עוֹנִים וְאוֹמְרִים בְּיִרְאָה:<br> קָדוֹשׁ קָדוֹשׁ קָדוֹשׁ ה' צְבָאוֹת. מְלֹא כָל הָאָרֶץ כְּבוֹדוֹ: <br> וְהָאופַנִּים וְחַיּוֹת הַקֹּדֶשׁ בְּרַעַשׁ גָּדול מִתְנַשּאִים לְעֻמַּת שְׂרָפִים. לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים: <br> בָּרוּךְ כְּבוד ה' מִמְּקוֹמוֹ:"}, {"kind": "text", "text": "לְאֵל בָּרוּךְ נְעִימוֹת יִתֵּנוּ. לְמֶּלֶךְ אֶל חַי וְקַיָּם זְמִירוֹת יֹאמֵרוּ וְתִשְׁבָּחות יַשְׁמִיעוּ. כִּי הוּא לְבַדּוֹ פּועֵל גְּבוּרוֹת. עוֹשֶׂה חֲדָשׁוֹת. בַּעַל מִלְחָמוֹת. זורֵעַ צְדָקוֹת. מַצְמִיחַ יְשׁוּעוֹת. בּורֵא רְפוּאוֹת. נורָא תְּהִלּוֹת. אֲדוֹן הַנִּפְלָאוֹת: הַמְחַדֵּשׁ בְּטוּבוֹ בְּכָל יוֹם תָּמִיד מַעֲשֵׂה בְרֵאשִׁית. כָּאָמוּר לְעֹשֶׂה אוּרִים גְּדלִים. כִּי לְעולָם חַסְדּו: אוֹר חָדָשׁ עַל צִיּון תָּאִיר וְנִזְכֶּה כֻלָּנוּ מְהֵרָה לְאוֹרוֹ. בָּרוּךְ אַתָּה ה'. יוֹצֵר הַמְּאוֹרוֹת:"}, {"kind": "header", "text": "אהבת ישראל"}, {"kind": "text", "text": "אַהֲבָה רַבָּה אֲהַבְתָּנוּ ה' אֱלהֵינוּ. חֶמְלָה גְּדולָה וִיתֵרָה חָמַלְתָּ עָלֵינוּ: אָבִינוּ מַלְכֵּנוּ. בַּעֲבוּר אֲבותֵינוּ שֶׁבָּטְחוּ בְךָ. וַתְּלַמְּדֵם חֻקֵּי חַיִּים כֵּן תְּחָנֵּנוּ וּתְלַמְּדֵנוּ: אָבִינוּ הָאָב הָרַחֲמָן. הַמְרַחֵם. רַחֵם עָלֵינוּ. וְתֵן בְּלִבֵּנוּ לְהָבִין וּלְהַשכִּיל. לִשְׁמעַ. לִלְמד וּלְלַמֵּד. לִשְׁמר וְלַעֲשות וּלְקַיֵּם אֶת כָּל דִּבְרֵי תַלְמוּד תּורָתֶךָ בְּאַהֲבָה: וְהָאֵר עֵינֵינוּ בְּתורָתֶךָ. וְדַבֵּק לִבֵּנוּ בְּמִצְותֶיךָ. וְיַחֵד לְבָבֵנוּ לְאַהֲבָה וּלְיִרְאָה אֶת שְׁמֶךָ. וְלא נֵבושׁ לְעולָם וָעֶד: כִּי בְשֵׁם קָדְשְׁךָ הַגָּדול וְהַנּורָא בָּטָחְנוּ. נָגִילָה וְנִשמְחָה בִּישׁוּעָתֶךָ: וַהֲבִיאֵנוּ לְשָׁלום מֵאַרְבַּע כַּנְפות הָאָרֶץ. וְתולִיכֵנוּ קומְמִיּוּת לְאַרְצֵנוּ: כִּי אֵל פּועֵל יְשׁוּעות אָתָּה. וּבָנוּ בָחַרְתָּ מִכָּל עַם וְלָשׁון.וְקֵרַבְתָּנוּ לְשִׁמְךָ הַגָּדול סֶלָה בֶּאֱמֶת: לְהודות לְךָ וּלְיַחֶדְךָ בְּאַהֲבָה: בָּרוּךְ אַתָּה ה'. הַבּוחֵר בְּעַמּו יִשרָאֵל בְּאַהֲבָה:"}, {"kind": "header", "text": "שמע"}, {"kind": "text", "text": "<em>יחיד אומר:</em> אֵל מֶלֶךְ נֶאֱמָן:"}, {"kind": "text", "text": "שְׁמַע יִשרָאֵל ה' אֱלהֵינוּ ה' אֶחָד:"}, {"kind": "text", "text": "<em>בלחש</em> - בָּרוּךְ שֵׁם כְּבוד מַלְכוּתו לְעולָם וָעֶד:"}, {"kind": "text", "text": "וְאָהַבְתָּ אֵת ה' אֱלהֶיךָ בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאדֶךָ: וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנכִי מְצַוְּךָ הַיּום עַל לְבָבֶךָ: וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּקְשַׁרְתָּם לְאות עַל יָדֶךָ וְהָיוּ לְטטָפת בֵּין עֵינֶיךָ: וּכְתַבְתָּם עַל מְזֻזות בֵּיתֶךָ וּבִשְׁעָרֶיךָ:"}, {"kind": "text", "text": "וְהָיָה אִם שָׁמעַ תִּשְׁמְעוּ אֶל מִצְותַי אֲשֶׁר אָנכִי מְצַוֶּה אֶתְכֶם הַיּום לְאַהֲבָה אֶת ה' אֱלהֵיכֶם וּלְעָבְדו בְּכָל לְבַבְכֶם וּבְכָל נַפְשְׁכֶם: וְנָתַתִּי מְטַר אַרְצְכֶם בְּעִתּו יורֶה וּמַלְקושׁ וְאָסַפְתָּ דְגָנֶךָ וְתִירשְׁךָ וְיִצְהָרֶךָ: וְנָתַתִּי עֵשב בְּשדְךָ לִבְהֶמְתֶּךָ וְאָכַלְתָּ וְשָׂבָעְתָּ: הִשָּׁמְרוּ לָכֶם פֶּן יִפְתֶּה לְבַבְכֶם וְסַרְתֶּם וַעֲבַדְתֶּם אֱלהִים אֲחֵרִים וְהִשְׁתַּחֲוִיתֶם לָהֶם: וְחָרָה אַף ה' בָּכֶם וְעָצַר אֶת הַשָּׁמַיִם וְלא יִהְיֶה מָטָר וְהָאֲדָמָה לא תִתֵּן אֶת יְבוּלָהּ וַאֲבַדְתֶּם מְהֵרָה מֵעַל הָאָרֶץ הַטּבָה אֲשֶׁר ה' נתֵן לָכֶם: וְשמְתֶּם אֶת דְּבָרַי אֵלֶּה עַל לְבַבְכֶם וְעַל נַפְשְׁכֶם וּקְשַׁרְתֶּם אתָם לְאות עַל יֶדְכֶם וְהָיוּ לְטוטָפת בֵּין עֵינֵיכֶם: וְלִמַּדְתֶּם אתָם אֶת בְּנֵיכֶם לְדַבֵּר בָּם בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּכְתַבְתָּם עַל מְזוּזות בֵּיתֶךָ וּבִשְׁעָרֶיךָ: לְמַעַן יִרְבּוּ יְמֵיכֶם וִימֵי בְנֵיכֶם עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע ה' לַאֲבתֵיכֶם לָתֵת לָהֶם כִּימֵי הַשָּׁמַיִם עַל הָאָרֶץ:"}, {"kind": "text", "text": "וַיּאמֶר ה' אֶל משֶׁה לֵּאמר: דַּבֵּר אֶל בְּנֵי יִשרָאֵל וְאָמַרְתָּ אֲלֵהֶם וְעָשוּ לָהֶם צִיצִת עַל כַּנְפֵי בִגְדֵיהֶם לְדרתָם וְנָתְנוּ עַל צִיצִת הַכָּנָף פְּתִיל תְּכֵלֶת: וְהָיָה לָכֶם לְצִיצִת וּרְאִיתֶם אתו וּזְכַרְתֶּם אֶת כָּל מִצְות ה' וַעֲשיתֶם אתָם וְלא תָתוּרוּ אַחֲרֵי לְבַבְכֶם וְאַחֲרֵי עֵינֵיכֶם אֲשֶׁר אַתֶּם זנִים אַחֲרֵיהֶם: לְמַעַן תִּזְכְּרוּ וַעֲשיתֶם אֶת כָּל מִצְותָי וִהְיִיתֶם קְדשִׁים לֵאלהֵיכֶם: אֲנִי ה' אֱלהֵיכֶם אֲשֶׁר הוצֵאתִי אֶתְכֶם מֵאֶרֶץ מִצְרַיִם לִהְיות לָכֶם לֵאלהִים אֲנִי ה' אֱלהֵיכֶם. אֱמֶת:"}, {"kind": "text", "text": "<em>הש\"ץ חוזר ואומר:</em> ה' אֱלהֵיכֶם אֱמֶת:"}, {"kind": "header", "text": "גאל ישראל"}, {"kind": "text", "text": "וְיַצִּיב וְנָכון וְקַיָּם וְיָשָׁר וְנֶאֱמָן וְאָהוּב וְחָבִיב וְנֶחְמָד וְנָעִים וְנורָא וְאַדִּיר וּמְתֻקָּן וּמְקֻבָּל וְטוב וְיָפֶה הַדָּבָר הַזֶּה עָלֵינוּ לְעולָם וָעֶד: אֱמֶת. אֱלהֵי עולָם מַלְכֵּנוּ. צוּר יַעֲקב מָגֵן יִשְׁעֵנוּ. לְדר וָדר הוּא קַיָּם וּשְׁמו קַיָּם. וְכִסְאו נָכון. וּמַלְכוּתו וֶאֱמוּנָתו לָעַד קַיָּמֶת: וּדְבָרָיו חָיִים וְקַיָּמִים. נֶאֱמָנִים וְנֶחֱמָדִים לָעַד וּלְעולְמֵי עולָמִים."}, {"kind": "text", "text": "עַל אֲבותֵינוּ וְעָלֵינוּ. עַל בָּנֵינוּ וְעַל דּורותֵינוּ. וְעַל כָּל דּורות זֶרַע יִשרָאֵל עֲבָדֶיךָ: עַל הָרִאשׁונִים וְעַל הָאַחֲרונִים. דָּבָר טוב וְקַיָּם לְעולָם וָעֶד. אֱמֶת וֶאֱמוּנָה. חק וְלא יַעֲבר. אֱמֶת שָׁאַתָּה הוּא ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. מַלְכֵּנוּ מֶלֶךְ אֲבותֵינוּ. גּואֲלֵנוּ גּואֵל אֲבותֵינוּ. יוצְרֵנוּ צוּר יְשׁוּעָתֵנוּ. פּודֵנוּ וּמַצִּילֵנוּ מֵעולָם שְׁמֶךָ. אֵין אֱלהִים זוּלָתֶךָ:"}, {"kind": "text", "text": "עֶזְרַת אֲבותֵינוּ אַתָּה הוּא מֵעולָם. מָגֵן וּמושִׁיעַ לִבְנֵיהֶם אַחֲרֵיהֶם בְּכָל דּור וָדור. בְּרוּם עולָם מושָׁבֶךָ. וּמִשְׁפָּטֶיךָ וְצִדְקָתְךָ עַד אַפְסֵי אָרֶץ: אַשְׁרֵי אִישׁ שֶׁיִּשְׁמַע לְמִצְותֶיךָ וְתורָתְךָ וּדְבָרְךָ יָשים עַל לִבּו: אֱמֶת. אַתָּה הוּא אָדון לְעַמֶּךָ. וּמֶלֶךְ גִּבּור לָרִיב רִיבָם: אֱמֶת. אַתָּה הוּא רִאשׁון וְאַתָּה הוּא אַחֲרון. וּמִבַּלְעָדֶיךָ אֵין לָנוּ מֶלֶךְ גּואֵל וּמושִׁיעַ: מִמִּצְרַיִם גְּאַלְתָּנוּ ה' אֱלהֵינוּ. וּמִבֵּית עֲבָדִים פְּדִיתָנוּ. כָּל בְּכורֵיהֶם הָרָגְתָּ. וּבְכורְךָ גָּאָלְתָּ. וְיַם סוּף בָּקַעְתָּ. וְזֵדִים טִבַּעְתָּ. וִידִידִים הֶעֱבַרְתָּ. וַיְכַסּוּ מַיִם צָרֵיהֶם. אֶחָד מֵהֶם לא נותָר: עַל זאת שִׁבְּחוּ אֲהוּבִים וְרומְמוּ אֵל. וְנָתְנוּ יְדִידִים זְמִירות שִׁירות וְתִשְׁבָּחות. בְּרָכות וְהודָאות לְמֶּלֶךְ אֵל חַי וְקַיָּם: רָם וְנִשּא. גָּדול וְנורָא. מַשְׁפִּיל גֵּאִים. וּמַגְבִּיהַּ שְׁפָלִים. מוצִיא אֲסִירִים. וּפודֶה עֲנָוִים. וְעוזֵר דַּלִּים. וְעונֶה לְעַמּו בְּעֵת שַׁוְּעָם אֵלָיו: תְּהִלּות לְאֵל עֶלְיון. בָּרוּךְ הוּא וּמְברָךְ. משֶׁה וּבְנֵי יִשרָאֵל לְךָ עָנוּ שִׁירָה בְּשמְחָה רַבָּה. וְאָמְרוּ כֻלָּם: מִי כָמכָה בָּאֵלִים ה'. מִי כָּמכָה נֶאְדָּר בַּקּדֶשׁ. נורָא תְהִלּת. עשה פֶלֶא: שִׁירָה חֲדָשָׁה שִׁבְּחוּ גְאוּלִים לְשִׁמְךָ עַל שפַת הַיָּם. יַחַד כֻּלָּם הודוּ וְהִמְלִיכוּ וְאְָמְרוּ: ה' יִמְלךְ לְעולָם וָעֶד: צוּר יִשרָאֵל. קוּמָה בְּעֶזְרַת יִשרָאֵל. וּפְדֵה כִנְאֻמֶךָ יְהוּדָה וְיִשרָאֵל. גּאֲלֵנוּ ה' צְבָאות שְׁמו קְדושׁ יִשרָאֵל: בָּרוּךְ אַתָּה ה'. גָּאַל יִשרָאֵל:"}, {"kind": "header", "text": "אבות"}, {"kind": "text", "text": "אֲדנָי שפָתַי תִּפְתָּח וּפִי יַגִּיד תְּהִלָּתֶךָ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. אֱלהֵי אַבְרָהָם. אֱלהֵי יִצְחָק. וֵאלהֵי יַעֲקב. הָאֵל הַגָּדול הַגִּבּור וְהַנּורָא אֵל עֶלְיון. גּומֵל חֲסָדִים טובִים. וְקונֵה הַכּל. וְזוכֵר חַסְדֵּי אָבות. וּמֵבִיא גואֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמו בְּאַהֲבָה:"}, {"kind": "text", "text": "<em>בעשי”ת: זָכְרֵנוּ לְחַיִּים. מֶלֶךְ חָפֵץ בַּחַיִּים. וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים. לְמַעַנְךָ אֱלהִים חַיִּים:</em>"}, {"kind": "text", "text": "מֶלֶךְ עוזֵר וּמושִׁיעַ וּמָגֵן: בָּרוּךְ אַתָּה ה', מָגֵן אַבְרָהָם:"}, {"kind": "header", "text": "גבורות"}, {"kind": "text", "text": "אַתָּה גִּבּור לְעולָם אֲדנָי. מְחַיֵּה מֵתִים אַתָּה רַב לְהושִׁיעַ:"}, {"kind": "text", "text": "<em>בחורף: מַשִּׁיב הָרוּחַ וּמורִיד הַגָּשֶּׁם:</em>"}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶסֶד. מְחַיֶּה מֵתִים בְּרַחֲמִים רַבִּים. סומֵךְ נופְלִים. וְרופֵא חולִים וּמַתִּיר אֲסוּרִים. וּמְקַיֵּם אֱמוּנָתו לִישֵׁנֵי עָפָר. מִי כָמוךָ בַּעַל גְּבוּרות וּמִי דומֶה לָּךְ. מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה:"}, {"kind": "text", "text": "<em>בעשי”ת: מִי כָמוךָ אַב הָרַחֲמִים. זוכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים:</em>"}, {"kind": "text", "text": "וְנֶאֱמָן אַתָּה לְהַחֲיות מֵתִים: בָּרוּךְ אַתָּה ה', מְחַיֵּה הַמֵּתִים:"}, {"kind": "header", "text": "קדושה"}, {"kind": "instruction", "text": "לחזרת הש\"ץ"}, {"kind": "instruction", "text": "נְקַדֵּשׁ אֶת שִׁמְךָ בָּעוֹלָם כְּשֵׁם שֶׁמַּקְדִּישִׁים אוֹתוֹ בִּשְׁמֵי מָרוֹם. כַּכָּתוּב עַל יַד נְבִיאֶֽךָ. וְקָרָא זֶה אֶל זֶה וְאָמַר: קָדוֹשׁ קָדוֹשׁ קָדוֹשׁ יְהֹוָה צְבָאוֹת מְלֹא כָל־הָאָֽרֶץ כְּבוֹדוֹ: אָז בְּקוֹל רַֽעַשׁ גָּדוֹל אַדִּיר וְחָזָק מַשְׁמִיעִים קוֹל מִתְנַשְּׂאִים לְעֻמַּת שְׂרָפִים. לְעֻמָּתָם בָּרוּךְ יֹאמֵֽרוּ: בָּרוּךְ כְּבוֹד יְהֹוָה מִמְּקוֹמוֹ: מִמְּקוֹמְךָ מַלְכֵּֽנוּ תוֹפִֽיעַ וְתִמְלוֹךְ עָלֵֽינוּ כִּי מְחַכִּים אֲנַחְנוּ לָךְ מָתַי תִּמְלוֹךְ בְּצִיּוֹן בְּקָרוֹב בְּיָמֵֽינוּ לְעוֹלָם וָעֶד תִּשְׁכּוֹן: תִּתְגַּדַּל וְתִתְקַדַּשׁ בְּתוֹךְ יְרוּשָׁלַֽיִם עִירְךָ לְדוֹר וָדוֹר וּלְנֵֽצַח נְצָחִים: וְעֵינֵֽינוּ תִרְאֶֽינָה מַלְכוּתֶֽךָ כַּדָּבָר הָאָמוּר בְּשִׁירֵי עֻזֶּֽךָ עַל יְדֵי דָוִד מְשִֽׁיחַ צִדְקֶֽךָ: יִמְלֹךְ יְהֹוָה לְעוֹלָם אֱלֹהַֽיִךְ צִיּוֹן לְדֹר וָדֹר הַלְלוּיָהּ:"}, {"kind": "text", "text": "לְדוֹר וָדוֹר נַגִּיד גָּדְלֶֽךָ וּלְנֵֽצַח נְצָחִים קְדֻשָּׁתְךָ נַקְדִּישׁ וְשִׁבְחֲךָ אֱלֹהֵֽינוּ מִפִּֽינוּ לֹא יָמוּשׁ לְעוֹלָם וָעֶד כִּי אֵל מֶֽלֶךְ גָּדוֹל וְקָדוֹשׁ אָֽתָּה: בָּרוּךְ אַתָּה ה', הָאֵל <em>בעשי”ת: הַמֶּלֶךְ</em> הַקָּדושׁ:"}, {"kind": "text", "text": "אַתָּה קָדושׁ וְשִׁמְךָ קָדושׁ וּקְדושִׁים בְּכָל יום יְהַלְּלוּךָ סֶּלָה: בָּרוּךְ אַתָּה ה', הָאֵל <em>בעשי”ת: הַמֶּלֶךְ</em> הַקָּדושׁ:"}, {"kind": "header", "text": "קדושת היום"}, {"kind": "text", "text": "יִשמַח משֶׁה בְּמַתְּנַת חֶלְקו. כִּי עֶבֶד נֶאֱמָן קָרָאתָ לּו. כְּלִיל תִּפְאֶרֶת בְּראשׁו נָתַתָּ. בְּעָמְדו לְפָנֶיךָ עַל הַר סִינַי. וּשְׁנֵי לֻחות אֲבָנִים הורִיד בְּיָדו. וְכָתוּב בָּהֶם שְׁמִירַת שַׁבָּת. וְכֵן כָּתוּב בְּתורָתֶךָ:"}, {"kind": "text", "text": "וְשָׁמְרוּ בְנֵי יִשרָאֵל אֶת הַשַּׁבָּת. לַעֲשות אֶת הַשַּׁבָּת לְדרתָם בְּרִית עולָם: בֵּינִי וּבֵין בְּנֵי יִשרָאֵל אות הִיא לְעולָם. כִּי שֵׁשֶׁת יָמִים עָשה ה' אֶת הַשָּׁמַיִם וְאֶת הָאָרֶץ. וּבַיּום הַשְּׁבִיעִי שָׁבַת וַיִּנָּפַשׁ:"}, {"kind": "text", "text": "וְלא נְתַתּו ה' אֱלהֵינוּ לְגויֵי הָאֲרָצות. וְלא הִנְחַלְתּו מַלְכֵּנוּ לְעובְדֵי פְסִילִים. וְגַם בִּמְנוּחָתו לא יִשְׁכְּנוּ עֲרֵלִים. כִּי לְיִשרָאֵל עַמְּךָ נְתַתּו בְּאַהֲבָה. לְזֶרַע יַעֲקב אֲשֶׁר בָּם בָּחָרְתָּ: עַם מְקַדְּשֵׁי שְׁבִיעִי. כֻּלָּם יִשבְּעוּ וְיִתְעַנְּגוּ מִטּוּבֶךָ. וּבַשְּׁבִיעִי רָצִיתָ בּו וְקִדַּשְׁתּו. חֶמְדַת יָמִים אותו קָרָאתָ. זֵכֶר לְמַעֲשה בְרֵאשִׁית:"}, {"kind": "text", "text": "אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ רְצֵה בִמְנוּחָתֵנוּ. קַדְּשֵׁנוּ בְּמִצְותֶיךָ וְתֵן חֶלְקֵנוּ בְּתורָתֶךָ. שבְּעֵנוּ מִטּוּבֶךָ וְשמְּחֵנוּ בִּישׁוּעָתֶךָ וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶּאֱמֶת. וְהַנְחִילֵנוּ ה' אֱלהֵינוּ בְּאַהֲבָה וּבְרָצון שַׁבַּת קָדְשֶׁךָ. וְיָנוּחוּ בו יִשרָאֵל מְקַדְּשֵׁי שְׁמֶךָ: בָּרוּךְ אַתָּה ה' מְקַדֵּשׁ הַשַּׁבָּת:"}, {"kind": "header", "text": "עבודה"}, {"kind": "text", "text": "רְצֵה ה' אֱלהֵינוּ בְּעַמְּךָ יִשרָאֵל וּבִתְפִלָּתָם וְהָשֵׁב אֶת הָעֲבודָה לִדְבִיר בֵּיתֶךָ. וְאִשֵּׁי יִשרָאֵל וּתְפִלָּתָם. בְּאַהֲבָה תְקַבֵּל בְּרָצון. וּתְהִי לְרָצון תָּמִיד עֲבודַת יִשרָאֵל עַמֶּךָ:"}, {"kind": "text", "text": "<em>בראש חודש ובחול המועד אומרים זה: אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. יַעֲלֶה וְיָבוא וְיַגִּיעַ. וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע. וְיִפָּקֵד וְיִזָּכֵר זִכְרונֵנוּ וּפִקְדונֵנוּ וְזִכְרון אֲבותֵינוּ. וְזִכְרון מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ. וְזִכְרון יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ. וְזִכְרון כָּל עַמְּךָ בֵּית יִשרָאֵל. לְפָנֶיךָ. לִפְלֵיטָה לְטובָה. לְחֵן וּלְחֶסֶד וּלְרַחֲמִים. לְחַיִּים וּלְשָׁלום בְּיום: בראש חדש - ראשׁ הַחדֶשׁ: בפסח - חַג הַמַּצּות: בסוכות - חַג הַסֻּכּות: הַזֶּה. זָכְרֵנוּ ה' אֱלהֵינוּ בּו לְטובָה. וּפָקְדֵנוּ בו לִבְרָכָה. וְהושִׁיעֵנוּ בו לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהושִׁיעֵנוּ. כִּי אֵלֶיךָ עֵינֵינוּ. כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה:</em>"}, {"kind": "text", "text": "וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּון בְּרַחֲמִים: בָּרוּךְ אַתָּה ה', הַמַּחֲזִיר שְׁכִינָתו לְצִיּון:"}, {"kind": "header", "text": "מודים"}, {"kind": "text", "text": "מודִים אֲנַחְנוּ לָךְ. שָׁאַתָּה הוּא ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ לְעולָם וָעֶד. צוּר חַיֵּינוּ. מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדור וָדור: נודֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ. וְעַל נִשְׁמותֵינוּ הַפְּקוּדות לָךְ. וְעַל נִסֶּיךָ שֶׁבְּכָל יום עִמָּנוּ. וְעַל נִפְלְאותֶיךָ וְטובותֶיךָ שֶׁבְּכָל עֵת. עֶרֶב וָבקֶר וְצָהֳרָיִם: הַטּוב כִּי לא כָלוּ רַחֲמֶיךָ. וְהַמְרַחֵם כִּי לא תַמּוּ חֲסָדֶיךָ. מֵעולָם קִוִּינוּ לָךְ:"}, {"kind": "text", "text": "<em>מודים דרבנן: מודִים אֲנַחְנוּ לָךְ. שָׁאַתָּה הוּא ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. אֱלהֵי כָל בָּשר. יוצְרֵנוּ יוצֵר בְּרֵאשִׁית. בְּרָכות וְהודָאות לְשִׁמְךָ הַגָּדול וְהַקָּדושׁ. עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְקַיְּמֵנוּ. וְתֶאֱסוף גָּלֻיּותֵינוּ לְחַצְרות קָדְשֶׁךָ. לִשְׁמור חֻקֶּיךָ. וְלַעֲשות רְצונֶךָ. וּלְעָבְדְךָ בְּלֵבָב שָׁלֵם. עַל שֶׁאֲנַחְנוּ מודִים לָךְ. בָּרוּךְ אֵל הַהודָאות:</em>"}, {"kind": "text", "text": "<em>בחנוכה ופורים אומרים כאן ועל הנסים: עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרות וְעַל הַתְּשׁוּעות וְעַל הַמִּלְחָמות שֶׁעָשיתָ לַאֲבותֵינוּ בַּיָּמִים הָהֵם בִּזְּמַן הַזֶּה:</em>"}, {"kind": "text", "text": "לחנוכה: בִּימֵי מַתִּתְיָהוּ בֶּן יוחָנָן כּהֵן גָּדול חַשְׁמונַאִי וּבָנָיו. כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשרָאֵל לְהַשְׁכִּיחָם תּורָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצונֶךָ: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם. רַבְתָּ אֶת רִיבָם. דַנְתָּ אֶת דִּינָם. נָקַמְתָּ אֶת נִקְמָתָם. מָסַרְתָּ גִבּורִים בְּיַד חַלָּשִׁים. וְרַבִּים בְּיַד מְעַטִּים. וּטְמֵאִים בְּיַד טְהורִים. וּרְשָׁעִים בְּיַד צַדִּיקִים. וְזֵדִים בְּיַד עוסְקֵי תורָתֶךָ. וּלְךָ עָשיתָ שֵׁם גָּדול וְקָדושׁ בְּעולָמֶךָ. וּלְעַמְּךָ יִשרָאֵל עָשיתָ תְּשׁוּעָה גְדולָה וּפֻרְקָן כְּהַיּום הַזֶּה: וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ. וּפִנּוּ אֶת הֵיכָלֶךָ. וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ. וְהִדְלִיקוּ נֵרות בְּחַצְרות קָדְשֶׁךָ. וְקָבְעוּ שְׁמונַת יְמֵי חֲנֻכָּה אֵלּוּ. לְהודות וּלְהַלֵּל לְשִׁמְךָ הַגָּדול:"}, {"kind": "text", "text": "לפורים: בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה. כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע. בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיום אֶחָד. בִּשְׁלשָׁה עָשר לְחדֶשׁ שְׁנֵים עָשר. הוּא חדֶשׁ אֲדָר. וּשְׁלָלָם לָבוז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים. הֵפַרְתָּ אֶת עֲצָתו. וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּו. וַהֲשֵׁבותָ לּו גְּמוּלו בְּראשׁו. וְתָלוּ אותו וְאֶת בָּנָיו עַל הָעֵץ. <em>וְעָשיתָ עִמָּהֶם נֵס וָפֶלֶא וְנודֶה לְשִׁמְךָ הַגָּדול סֶלָה:</em>"}, {"kind": "text", "text": "וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרומַם שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעולָם וָעֶד:"}, {"kind": "text", "text": "<em>בעשי\"ת - וּכְתב לְחַיִּים טובִים כָּל בְּנֵי בְרִיתֶךָ: </em>"}, {"kind": "text", "text": "וְכל הַחַיִּים יודוּךָ סֶּלָה וִיהַלְלוּ אֶת שִׁמְךָ בֶּאֱמֶת. הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה. בָּרוּךְ אַתָּה ה', הַטּוב שִׁמְךָ וּלְךָ נָאֶה לְהודות:"}, {"kind": "header", "text": "ברכת כהנים"}, {"kind": "text", "text": "<em>ברכת כהנים בחזרת התפלה</em> אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶׁת בַּתּורָה הַכְּתוּבָה עַל יְדֵי משֶׁה עַבְדֶּךָ. הָאֲמוּרָה מִפִּי אַהֲרן וּבָנָיו כּהֲנִים עַם קְדושֶׁךָ. כָּאָמוּר:"}, {"kind": "text", "text": "יְבָרֶכְךָ ה' וְיִשְׁמְרֶךָ: <br> יָאֵר ה' פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: <br> יִשּא ה' פָּנָיו אֵלֶיךָ וְיָשם לְךָ שָׁלום:"}, {"kind": "header", "text": "שים שלום"}, {"kind": "text", "text": "שים שָׁלום טובָה וּבְרָכָה. חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשרָאֵל עַמֶּךָ. בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד בְּאור פָּנֶיךָ. כִּי בְאור פָּנֶיךָ נָתַתָּ לָּנוּ ה' אֱלהֵינוּ תּורַת חַיִּים וְאַהֲבַת חֶסֶד. וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלום. וְטוב בְּעֵינֶיךָ לְבָרֵךְ אֶת כָּל עַמְּךָ יִשרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלומֶךָ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה', הַמְבָרֵךְ אֶת עַמּו יִשרָאֵל בַּשָּׁלום:"}, {"kind": "header", "text": "אלוהי נצור"}, {"kind": "text", "text": "יִהְיוּ לְרָצון אִמְרֵי פִי וְהֶגְיון לִבִּי לְפָנֶיךָ. ה' צוּרִי וְגואֲלִי: אֱלהַי. נְצר לְשׁונִי מֵרָע וּשפָתַי מִדַּבֵּר מִרְמָה. וְלִמְקַלְלַי נַפְשִׁי תִדּם. וְנַפְשִׁי כֶּעָפָר לַכּל תִּהְיֶה. פְּתַח לִבִּי בְּתורָתֶךָ. וּבְמִצְותֶיךָ תִּרְדּף נַפְשִׁי. וְכָל הַחושְׁבִים עָלַי רָעָה. מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחֲשַׁבְתָּם: עֲשה לְמַעַן שְׁמֶךָ. עֲשה לְמַעַן יְמִינֶךָ. עֲשה לְמַעַן קְדֻשָּׁתֶךָ. עֲשה לְמַעַן תּורָתֶךָ. לְמַעַן יֵחָלְצוּן יְדִידֶיךָ הושִׁיעָה יְמִינְךָ וַעֲנֵנִי: יִהְיוּ לְרָצון אִמְרֵי פִי וְהֶגְיון לִבִּי לְפָנֶיךָ. ה' צוּרִי וְגואֲלִי: עשה שָׁלום <em>בעשי\"ת - הַשָּׁלום</em> בִּמְרומָיו. הוּא יַעֲשה שָׁלום עָלֵינוּ וְעַל כָּל יִשרָאֵל. וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהִי רָצון מִלְּפָנֶיךָ ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ. וְתֵן חֶלְקֵנוּ בְּתורָתֶךָ: וְשָׁם נַעֲבָדְךָ בְּיִרְאָה כִּימֵי עולָם וּכְשָׁנִים קַדְמונִיות: וְעָרְבָה לה' מִנְחַת יְהוּדָה וִירוּשָׁלָיִם. כִּימֵי עולָם וּכְשָׁנִים קַדְמונִיות:"}, {"kind": "header", "text": "קדיש שלם"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ <em>גרסת הגר\"א: יִתְגַּדֵּל וְיִתְקַדֵּשׁ</em> שְׁמֵהּ רַבָּא. <em>ועונים: </em> אמן בְּעָלְמָא דִי בְרָא כִּרְעוּתֵהּ. וְיַמְלִיךְ מַלְכוּתֵהּ, בְּחַיֵיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵי דְּכָל בֵּית יִשְׂרָאֵל, בַּעֲגַלָא וּבִזְמַן קָרִיב וְאִמְרוּ אָמֵן:<br><em>הקהל עונה:</em> אמן. יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָא:<br>יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָא: יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל , שְׁמֵהּ דְּקוּדְשָׁא בְּרִיךְ הוּא <em>ועונים: </em>בְּרִיךְ הוּא<br>לְעֵילָא מִן כָּל <em>בעשרת ימי תשובה במקום לְעֵילָא מִן כָּל: </em> לְעֵילָא וּלְעֵילָא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחָמָתָא, דַאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן: <em>ועונים: </em> אמן<br><em>קהל:<em> קַבֵּל בְּרַחֲמִים וּבְרָצון אֶת תְּפִלָּתֵנוּ: </em></em><em><em><br> תִּתְקַבַּל צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל בֵּית יִשְׂרָאֵל קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא , וְאִמְרוּ אָמֵן. <em>ועונים: </em>אמן<br><em>קהל: </em>יְהִי שֵׁם יְהוָה מְברָךְ מֵעַתָּה וְעַד עולָם: <br>יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָא וְחַיִּים עָלֵינו וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן: <em>ועונים: </em>אמן<br><em>קהל: </em>עֶזְרִי מֵעִם יְהוָה עשֵׂה שָׁמַיִם וָאָרֶץ: <br>עוֹשֶׂה שָׁלוֹם <em>בעשרת ימי תשובה: </em>השלום בִּמְרוֹמָיו הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן: <em>ועונים: </em>אמן</em></em>"}, {"kind": "header", "text": "אין כמוך"}, {"kind": "text", "text": "<em>קודם פתיחת הארון אומרים:</em> <br> אֵין כָּמוךָ בָאֱלהִים אֲדנָי. וְאֵין כְּמַעֲשיךָ: <br> מַלְכוּתְךָ מַלְכוּת כָּל עולָמִים. וּמֶמְשַׁלְתְּךָ בְּכָל דּור וָדור: <br> ה' מֶלֶךְ. ה' מָלָךְ. ה' יִמְלךְ לְעולָם וָעֶד: <br> ה' עז לְעַמּו יִתֵּן. ה' יְבָרֵךְ אֶת עַמּו בַשָּׁלום:"}, {"kind": "text", "text": "אַב הָרַחֲמִים. הֵיטִיבָה בִרְצונְךָ אֶת צִיּון. תִּבְנֶה חומות יְרוּשָׁלָיִם: כִּי בְךָ לְבַד בָּטָחְנוּ. מֶלֶךְ אֵל רָם וְנִשּא אֲדון עולָמִים:"}, {"kind": "header", "text": "ויהי בנסע"}, {"kind": "text", "text": "<em>כשפותחין ארון הקודש אומרים:</em> <br> וַיְהִי בִּנְסעַ הָאָרן וַיּאמֶר משֶׁה. קוּמָה ה' וְיָפֻצוּ איְבֶיךָ. וְיָנֻסוּ מְשנְאֶיךָ מִפָּנֶיךָ: <br> כִּי מִצִּיּון תֵּצֵא תורָה. וּדְבַר ה' מִירוּשָׁלָיִם: <br> בָּרוּךְ שֶׁנָּתַן תּורָה לְעַמּו יִשרָאֵל בִּקְדֻשָּׁתו:"}, {"kind": "text", "text": "<em>ביו\"ט כשחל בחול, ויום כפור, ובהושענא רבה אומרים: <br> ה' ה'. אֵל רַחוּם וְחַנּוּן. אֶרֶךְ אַפַּיִם וְרַב חֶסֶד וֶאֱמֶת: נצֵר חֶסֶד לָאֲלָפִים. נשא עָון וָפֶשַׁע וְחַטָּאָה וְנַקֵּה. <br> ג”פ:</em>"}, {"kind": "text", "text": "לשלוש רגלים ולשמיני עצרת: <br> רִבּונו שֶׁל עולָם מַלֵּא מִשְׁאֲלות לִבִּי לְטובָה וְהָפֵק רְצונִי וְתֵן שְׁאֵלָתִי. וְזַכֵּה לִי <em>פב\"פ</em> וְאִשְׁתִּי וּבָנַי וּבְנותַי וְכָל בְּנֵי בֵיתִי לַעֲשות רְצונְךָ בְּלֵבָב שָׁלֵם. וּמַלְּטֵנוּ מִיֵּצֶר הָרָע וְתֵן חֶלְקֵנוּ בְּתורָתֶךָ. וְזַכֵּנוּ שֶׁתִּשְׁרֶה שְׁכִינָתְךָ עָלֵינוּ. וְהופַע עָלֵינוּ רוּחַ חָכְמָה וּבִינָה. וְיִתְקַיֵּם בָּנוּ מִקְרָא שֶׁכָּתוּב וְנָחָה עָלָיו רוּחַ ה' רוּחַ חָכְמָה וּבִינָה רוּחַ עֵצָה וּגְבוּרָה רוּחַ דַּעַת וְיִרְאַת ה':"}, {"kind": "text", "text": "וּבְכֵן יְהִי רָצון מִלְּפָנֶיךָ ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. שֶׁתְּזַכֵּנוּ לַעֲשות מַעֲשים טובִים בְּעֵינֶיךָ וְלָלֶכֶת בְּדַרְכֵי יְשָׁרִים לְפָנֶיךָ. וְקַדְּשֵׁנוּ בִּקְדֻשָׁתֶךָ כְּדֵי שֶׁנִּזְכֶּה לְחַיִּים טובִים וַאֲרוּכִּים וּלְחַיֵּי הָעולָם הַבָּא. וְתִשְׁמְרֵנוּ מִמַּעֲשּים רָעִים וּמִשָׁעות רָעות הַמִתְרַגְשׁות לָבא לְעולָם. וְהַבּוטֵחַ בה' חֶסֶד יְסובְבֶנְּהוּ אָמֵן:"}, {"kind": "text", "text": "וַאֲנִי תְפִלָּתִי לְךָ ה' עֵת רָצון אֱלהִים בְּרָב חַסְדֶּךָ עֲנֵנִי בֶּאֱמֶת יִשְׁעֶךָ. ג”פ:"}, {"kind": "header", "text": "בריך שמה"}, {"kind": "text", "text": "בְּרִיךְ שְׁמֵהּ דְּמָרֵא עָלְמָא. בְּרִיךְ כִּתְרַךְ וְאַתְּרָךְ. יְהֵא רְעוּתָךְ עִם עַמָּךְ יִשְׂרָאֵל לְעָלַם. וּפוּרְקָן יְמִינָךְ אַחֲזֵי לְעַמָּךְ בְּבֵית מַקְדְּשָׁךְ. וּלְאַמְטוֹיֵי לַנָא מִטּוּב נְהוֹרָךְ וּלְקַבֵּל צְלוֹתַנָא בְּרָחֲמִין. יְהֵא רַעֲוָא קָדָמָךְ דְּתוֹרִיךְ לָן חַיִּין בְּטִיְּבוּ. וְלֶהֱוֵי אֲנָא פְּקִידָא בְּגוֹ צַדִּיקַיָּא. לְמִרְחַם עָלַי וּלְמִנְּטַר יָתִי וְיָת כָּל דִּי לִי וְדִי לְעַמָּךְ יִשְׂרָאֵל. אַנְתְּ הוּא זָן לְכַלָּא וּמְפַרְנֵס לְכַלָּא. אַנְתְּ הוּא שַׁלִּיט עַל כַּלָּא. אַנְתְּ הוּא דְּשַׁלִּיט עַל מַלְכַיָּא. וּמַלְכוּתָא דִּילָךְ הִיא. אֲנָא עַבְדָּא דְּקֻדְשָׁא בְּרִיךְ הוּא דְּסַגִּידְנָא קַמֵּהּ וּמִקַּמֵּי דִּיקָר אוֹרָיְתֵהּ בְּכָל עִדָּן וְעִדָּן. לָא עַל אֱנָשׁ רָחִיצְנָא וְלָא עַל בַּר אֱלָהִין סַמִּיכְנָא. אֶלָּא בֶּאֱלָהָא דִּשְׁמַיָּא. דְּהוּא אֱלָהָא קְשׁוֹט וְאוֹרָיְתֵהּ קְשׁוֹט וּנְבִיאוֹהִי קְשׁוֹט. וּמַסְגֵּא לְמֶעְבַּד טָבְוָן וּקְשׁוֹט. בֵּהּ אֲנָא רָחִיץ. וְלִשְׁמֵהּ קַדִּישָׁא יַקִּירָא אֲנָא אֵמַר תֻּשְׁבְּחָן. יְהֵא רַעֲוָא קָדָמָךְ דְּתִפְתַּח לִבָּאִי בְּאוֹרָיְתָא. וְתַשְׁלִים מִשְׁאָלִין דְּלִבָּאִי וְלִבָּא דְּכָל עַמָּךְ יִשְׂרָאֵל. לְטָב וּלְחַיִּין וְלִשְׁלַם:"}, {"kind": "header", "text": "שמע ישראל"}, {"kind": "text", "text": "<em>חו”ק</em> שְׁמַע יִשרָאֵל ה' אֱלהֵינוּ ה' אֶחָד:"}, {"kind": "text", "text": "<em>חו”ק</em> אֶחָד אֱלהֵינוּ. גָּדול אֲדונֵינוּ. קָדושׁ <em>בראש השנה ויו\"כ ובהו”ר: וְנורָא</em> שְׁמו:"}, {"kind": "text", "text": "<em>חזן:</em> גַּדְּלוּ לה' אִתִּי. וּנְרומְמָה שְׁמו יַחְדָּו:"}, {"kind": "header", "text": "לך השם"}, {"kind": "text", "text": "<em>קהל:</em> לְךָ ה' הַגְּדֻלָּה וְהַגְּבוּרָה וְהַתִּפְאֶרֶת וְהַנֵּצַח וְהַהוד כִּי כל בַּשָּׁמַיִם וּבָאָרֶץ: <br> לְךָ ה' הַמַּמְלָכָה וְהַמִּתְנַשּא לְכל לְראשׁ: <br> רומְמוּ ה' אֱלהֵינוּ וְהִשְׁתַּחֲווּ לַהֲדם רַגְלָיו קָדושׁ הוּא: <br> רומְמוּ ה' אֱלהֵינוּ וְהִשְׁתַּחֲווּ לְהַר קָדְשׁו כִּי קָדושׁ ה' אֱלהֵינוּ:"}, {"kind": "header", "text": "ויעזור ויגן"}, {"kind": "text", "text": "<em>החזן מניח את ספר התורה על הבימה ואומר:</em> <br> וְיַעֲזר וְיָגֵן וְיושִׁיעַ לְכָל הַחוסִים בּו וְנאמַר אָמֵן. הַכּל הָבוּ גדֶל לֵאלהֵינוּ וּתְנוּ כָבוד לַתּורָה. כּהֵן קְרָב. יַעֲמד <em>פלוני בן פלוני</em> הַכּהֵן. בָּרוּךְ שֶׁנָּתַן תּורָה לְעַמּו יִשרָאֵל בִּקְדֻשָּׁתו:"}, {"kind": "header", "text": "ברכת התורה"}, {"kind": "text", "text": "<em>העולה מברך:</em> <br> בָּרְכוּ אֶת ה' הַמְברָךְ:"}, {"kind": "text", "text": "<em>והקהל עונין:</em> <br> בָּרוּךְ ה' הַמְברָךְ לְעולָם וָעֶד:"}, {"kind": "text", "text": "<em>והעולה חוזר ואומר:</em> <br> בָּרוּךְ ה' הַמְברָךְ לְעולָם וָעֶד:"}, {"kind": "text", "text": "<em>ואח\"כ מברך:</em> <br> בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם אֲשֶׁר בָּחַר בָּנוּ מִכָּל הָעַמִּים וְנָתַן לָנוּ אֶת תּורָתו. בָּרוּךְ אַתָּה ה' נותֵן הַתּורָה:"}, {"kind": "text", "text": "<em>אחר קריאת התורה מברך העולה:</em> <br> בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם אֲשֶׁר נָתַן לָנוּ תּורַת אֱמֶת וְחַיֵּי עולָם נָטַע בְּתוכֵנוּ. בָּרוּךְ אַתָּה ה' נותֵן הַתּורָה:"}, {"kind": "header", "text": "ברכת הגומל"}, {"kind": "text", "text": "<em>ברכת הגומל:</em> בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. הַגּומֵל לְחַיָּבִים טובות. שֶׁגְּמָלַנִי כָּל טוב:"}, {"kind": "text", "text": "<em>הקהל עונה אמן. ואומרים:</em> <br> מִי שֶׁגְּמָלְךָ טוב. הוּא יִגְמָלְךָ כָּל טוב סֶלָה:"}, {"kind": "header", "text": "לעולה התורה"}, {"kind": "text", "text": "מִי שֶׁבֵּרַךְ אֲבותֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקב הוּא יְבָרֵךְ אֶת <em>פב\"פ</em> בַּעֲבוּר שֶׁעָלָה לַתּורָה לִכְבוד הַמָּקום לִכְבוד הַתּורָה וְלִכְבוד הַשַּׁבָּת <em>ליו\"ט וְלִכְבוד הַרֶגֶל</em>. <em>לר\"ה ויו\"כ וְלִכְבוד יום הַדִּין</em>, בִשכַר זֶה הַקָּדושׁ בָּרוּךְ הוּא יִשְׁמְרֵהוּ וְיַצִּילֵהוּ מִכָּל צָרָה וְצוּקָה וּמִכָּל נֶגַע וּמַחֲלָה וְיִשְׁלַח בְּרָכָה וְהַצְלָחָה בְּכָל מַעֲשה יָדָיו <em>ליו\"ט וְיִזְכֶּה לַעֲלות לָרֶגֶל</em> <em>לר\"ה ויו\"כ וִיִכְתְּבֵהוּ וְיַחְתְּמֵהוּ לְחַיִּים טובִים בְּיום הַדִּין הַזֶּה</em> עִם כָּל יִשרָאֵל אֶחָיו וְנאמַר אָמֵן:"}, {"kind": "header", "text": "לחולים"}, {"kind": "text", "text": "<em>לזכר:</em> <br> מִי שֶׁבֵּרַךְ אֲבותֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקב משֶׁה וְאַהֲרן דָּוִד וּשְׁלמה הוּא יְבָרֵךְ אֶת הַחולֶה <em>פב\"פ</em> בַּעֲבוּר <em>שפב\"פ</em> נודֵר צְדָקָה בַּעֲבוּרו, בִּשכַר זֶה הַקָּדושׁ בָּרוּךְ הוּא יִמָלֵא רַחֲמִים עָלָיו לְהַחֲלִימו וּלְרַפְּאתו וּלְהַחֲזִיקו וּלְהַחֲיותו, וְיִשְׁלַח לו מְהֵרָה רְפוּאָה שְׁלֵמָה מִן הַשָּׁמַיִם לִרְמַ\"ח אֵבָרָיו וּשְׁסָ\"ה גִּידָיו בְּתוךְ שְׁאָר חולֵי יִשרָאֵל, רְפוּאַת הַנֶּפֶשׁ וּרְפוּאַת הַגּוּף <em>בשבת: שַׁבָּת הִיא מִלִזְּעוק וּרְפוּאָה קְרובָה לָבוא</em>. <em>ביו\"ט: יום טוב הוא מִלְזּעוק וּרְפוּאָה קְרובָה לָבוא</em>, הַשְׁתָּא בַּעֲגָלָא וּבִזְמַן קָרִיב. וְנאמַר אָמֵן:"}, {"kind": "text", "text": "<em>לנקבה:</em> <br> מִי שֶׁבֵּרַךְ אֲבותֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקב משֶׁה וְאַהֲרן דָּוִד וּשְׁלמה הוּא יְבָרֵךְ אֶת הַחולָה <em>פב\"פ</em> בַּעֲבוּר <em>שפב\"פ</em> נודֵר צְדָקָה בַּעֲבוּרָהּ, בִּשכַר זֶה הַקָּדושׁ בָּרוּךְ הוּא יִמָלֵא רַחֲמִים עָלֶיהָ לְהַחֲלִימָהּ וּלְרַפְּאתָהּ וּלְהַחֲזִיקָהּ וּלְהַחֲיותָהּ, וְיִשְׁלַח לָהּ מְהֵרָה רְפוּאָה שְׁלֵמָה מִן הַשָּׁמַיִם לְכָל אֵבָרֶיהּ וּלְכָל גִּידֶיהָ בְּתוךְ שְׁאָר חולֵי יִשרָאֵל, רְפוּאַת הַנֶּפֶשׁ וּרְפוּאַת הַגּוּף <em>בשבת: שַׁבָּת הִיא מִלִזְּעוק וּרְפוּאָה קְרובָה לָבוא</em>. <em>ביו\"ט: יום טוב הוא מִלְזּעוק וּרְפוּאָה קְרובָה לָבוא</em>, הַשְׁתָּא בַּעֲגָלָא וּבִזְמַן קָרִיב. וְנאמַר אָמֵן:"}, {"kind": "header", "text": "יולדת בן"}, {"kind": "text", "text": "<em>ליולדת זכר:</em> <br> מִי שֶׁבֵּרַךְ אֲבותֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקב משֶׁה וְאַהֲרן דָּוִד וּשְׁלמה, שרָה רִבְקָה רָחֵל וְלֵאָה, הוּא יְבָרֵךְ אֶת הָאִשָּׁה הַיּולֶדֶת <em>פב”פ</em> וְאֶת בְּנָהּ שֶֶׁנולַד לָהּ לְמַזָּל טוב, בַּעֲבוּר שֶׁבַּעְלָהּ וְאָבִיו נודֵר צְדָקָה בַּעֲדָם, בִּשכַר זֶה יִזְכּוּ אָבִיו וְאִמו לְהַכְנִיסו בִּבְרִיתו שֶׁל אַבְרָהָם אָבִינוּ וּלְגַדְּלו לְתורָה וּלְחֻפָּה וּלְמַעֲשים טובִים. וְנאמַר אָמֵן:"}, {"kind": "header", "text": "יולדת בת"}, {"kind": "text", "text": "<em>ליולדת נקבה:</em> <br> מִי שֶׁבֵּרַךְ אֲבותֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקב משֶׁה וְאַהֲרן דָּוִד וּשְׁלמה, שרָה רִבְקָה רָחֵל וְלֵאָה, הוּא יְבָרֵךְ אֶת הָאִשָּׁה הַיּולֶדֶת <em>פב\"פ</em> וְאֶת בִּתָּהּ שֶׁנּולְדָה לָהּ לְמַזָּל טוב, וְיִקָּרֵא שְׁמָהּ בְּיִשרָאֵל <em>פב\"פ</em>, בַּעֲבוּר שֶׁבַּעְלָהּ וְאָבִיהָ נודֵר צְדָקָה בַּעֲדָן, בִּשכַר זֶה יִזְכּוּ אָבִיהָ וְאִמָהּ לְגַדְּלָה לְתורָה וּלְחֻפָּה וּלְמַעֲשים טובִים. וְנאמַר אָמֵן:"}, {"kind": "header", "text": "בר מצוה"}, {"kind": "text", "text": "מִי שֶׁבֵּרַךְ אֲבותֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקב הוּא יְבָרֵךְ אֶת <em>פב\"פ</em> שֶׁמָּלְאוּ לו שְׁלשׁ עֶשרֵה שָׁנָה וְהִגִּיעַ לְמִצְות, וְעָלָה לַתּורָה, לָתֵת שֶׁבַח וְהודָיָה לְה' יִתְבָּרַךְ עַל כָּל הַטּובָה שֶׁגָּמַל אִתּו. יִשְׁמְרֵהוּ הַקָּדושׁ בָּרוּךְ הוּא וִיחַיֵּהוּ, וִיכונֵן אֶת לבּו לִהְיות שָׁלֵם עִם ה' וְלָלֶכֶת בִּדְרָכָיו וְלִשְׁמר מִצְותָיו כָּל הַיָּמִים, וְנאמַר אָמֵן:"}, {"kind": "text", "text": "<em>אם קראו לספר תורה נער שנעשה בר מצווה, אחר שבירך ברכה אחרונה, אביו יאמר:</em> <br> בָּרוּךְ שֶׁפְּטָרַנִי מֵעָנְשׁו שֶׁלָזֶה:"}, {"kind": "header", "text": "חצי קדיש"}, {"kind": "text", "text": "<em>חזן:</em> יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [<em>קהל:</em> אמן] <br> בְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן] <br> <em>קהל וחזן:</em> יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא: <br> יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרומַם וְיִתְנַשּא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא. [<em>קהל:</em> בריך הוא:] <br> לְעֵלָּא <em>בעשי\"ת לְעֵלָּא לְעֵלָּא מִכָּל</em> מִן כָּל בִּרְכָתָא וְשִׁירָתָא תֻּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן]"}, {"kind": "header", "text": "הגבהה"}, {"kind": "text", "text": "<em>כשמגביהים ס\"ת מביטים על הכתב של הספר ואומרים:</em> <br> וְזאת הַתּורָה אֲשֶׁר שם משֶׁה לִפְנֵי בְּנֵי יִשרָאֵל: עַל פִּי ה' בְּיַד משֶׁה:"}, {"kind": "header", "text": "הפטרה"}, {"kind": "text", "text": "<em>קודם קריאת ההפטרה יברך המפטיר ברכה זו:</em> <br> בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. אֲשֶׁר בָּחַר בִּנְבִיאִים טובִים. וְרָצָה בְדִבְרֵיהֶם הַנֶּאֱמָרִים בֶּאֱמֶת. בָּרוּךְ אַתָּה ה'. הַבּוחֵר בַּתּורָה וּבְמשֶׁה עַבְדּו. וּבְיִשרָאֵל עַמּו. וּבִנְבִיאֵי הָאֱמֶת וְהַצֶּדֶק:"}, {"kind": "text", "text": "<em>אחרי קריאת ההפטרה אומר המפטיר ברכות אלו:</em> <br> בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם. צוּר כָּל הָעולָמִים. צַדִּיק בְּכָל הַדּורות. הָאֵל הַנֶּאֱמָן הָאומֵר וְעושה. הַמְדַבֵּר וּמְקַיֵּם שֶׁכָּל דְּבָרָיו אֱמֶת וָצֶדֶק:"}, {"kind": "text", "text": "נֶאֱמָן אַתָּה הוּא ה' אֱלהֵינוּ וְנֶאֱמָנִים דְּבָרֶיךָ. וְדָבָר אֶחָד מִדְּבָרֶיךָ אָחור לא יָשׁוּב רֵיקָם. כִּי אֵל מֶלֶךְ נֶאֱמָן וְרַחֲמָן אָתָּה: בָּרוּךְ אַתָּה ה'. הָאֵל הַנֶּאֱמָן בְּכָל דְּבָרָיו:"}, {"kind": "text", "text": "רַחֵם עַל צִיּון כִּי הִיא בֵּית חַיֵּינוּ. וְלַעֲלוּבַת נֶפֶשׁ תּושִׁיעַ בִּמְהֵרָה בְיָמֵינוּ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה'. מְשמֵּחַ צִיּון בְּבָנֶיהָ:"}, {"kind": "text", "text": "שמְּחֵנוּ ה' אֱלהֵינוּ בְּאֵלִיָּהוּ הַנָּבִיא עַבְדֶּךָ וּבְמַלְכוּת בֵּית דָּוִד מְשִׁיחֶךָ. בִּמְהֵרָה יָבוא וְיָגֵל לִבֵּנוּ. עַל כִּסְאו לא יֵשֵׁב זָר וְלא יִנְחֲלוּ עוד אֲחֵרִים אֶת כְּבודו. כִּי בְשֵׁם קָדְשְׁךָ נִשְׁבַּעְתָּ לו שֶׁלּא יִכְבֶּה נֵרו לְעולָם וָעֶד: בָּרוּךְ אַתָּה ה'. מָגֵן דָּוִד: <br> <em>עד כאן אומרים בתענית ציבור ובמנחה יום כיפור</em>"}, {"kind": "text", "text": "<em>בשבת, ובשבת חול המועד פסח אומרים:</em> <br> עַל הַתּורָה וְעַל הָעֲבודָה וְעַל הַנְּבִיאִים וְעַל יום הַשַּׁבָּת הַזֶּה שֶׁנָּתַתָּ לָנוּ ה' אֱלהֵינוּ לִקְדֻשָּׁה וְלִמְנוּחָה לְכָבוד וּלְתִפְאָרֶת: עַל הַכּל. ה' אֱלהֵינוּ אֲנַחְנוּ מודִים לָךְ וּמְבָרְכִים אותָךְ. יִתְבָּרַךְ שִׁמְךָ בְּפִי כָּל חַי תָּמִיד לְעולָם וָעֶד: בָּרוּךְ אַתָּה ה'. מְקַדֵּשׁ הַשַּׁבָּת:"}, {"kind": "text", "text": "<em>בשלוש רגלים ובשבת חוה\"מ סוכות אומרים:</em> <br> עַל הַתּורָה וְעַל הָעֲבודָה וְעַל הַנְּבִיאִים <em>לשבת וְעַל יום הַשַּׁבָּת הַזֶּה</em>, וְעַל יום: <br> <em>לפסח:</em> חַג הַמַּצּות <br> <em>לשבועות:</em> חַג הַשָׁבוּעות <br> <em>סוכות:</em> - חַג הַסֻּכּות <br> <em>לשמ\"ע ולש”ת:</em> הַשְׁמִינִי חַג הָעֲצֶרֶת <br> הַזֶּה שֶׁנָּתַתָּ לָנוּ ה' אֱלהֵינוּ <em>לשבת: לִקְדֻשָּׁה וְלִמְנוּחָה</em> לְששון וּלְשמְחָה, לְכָבוד וּלְתִפְאָרֶת, עַל הַכּל. ה' אֱלהֵינוּ אֲנַחְנוּ מודִים לָךְ וּמְבָרְכִים אותָךְ. יִתְבָּרַךְ שִׁמְךָ בְּפִי כָּל חַי תָּמִיד לְעולָם וָעֶד: בָּרוּךְ אַתָּה ה'. מְקַדֵּשׁ <em>הַשַּׁבָּת וְ</em> יִשרָאֵל וְהַזְמַנִים:"}, {"kind": "text", "text": "<em>בראש השנה:</em> <br> עַל הַתּורָה וְעַל הָעֲבודָה וְעַל הַנְּבִיאִים <em>לשבת: וְעַל יום הַשַּׁבָּת הַזֶּה</em> וְעַל יום הַזִכָּרון הַזֶּה, שֶׁנָּתַתָּ לָנוּ ה' אֱלהֵינוּ <em>לשבת: לִקְדֻשָּׁה וְלִמְנוּחָה</em> לְכָבוד וּלְתִפְאָרֶת: עַל הַכּל. ה' אֱלהֵינוּ אֲנַחְנוּ מודִים לָךְ וּמְבָרְכִים אותָךְ. יִתְבָּרַךְ שִׁמְךָ בְּפִי כָּל חַי תָּמִיד לְעולָם וָעֶד: בָּרוּךְ אַתָּה ה'. מְקַדֵּשׁ <em>הַשַּׁבָּת וְ</em> יִשרָאֵל וְיום הַזִּכָּרון:"}, {"kind": "header", "text": "יקום פרקן"}, {"kind": "text", "text": "<em>אחר ברכות ההפטרה אומרים:</em> <br> יְקוּם פּוּרְקָן מִן שְׁמַיָּא חִנָּא וְחִסְדָּא וְרַחֲמֵי וְחַיֵּי אֲרִיכֵי וּמְזוֹנֵי רְוִיחֵי וְסִיַּעְתָּא דִשְׁמַיָּא וּבַרְיוּת גּוּפָא וּנְהוֹרָא מַעַלְיָא. זַרְעָא חַיָּא וְקַיָּמָא זַרְעָא דִּי לָא יִפְסוֹק וְדִי לָא יִבְטוֹל מִפִּתְגָּמֵי אוֹרַיְתָא. לְמָרָנָן וְרַבָּנָן חֲבוּרָתָא קַדִּישָׁתָא דִּי בְאַרְעָא דְיִשְׂרָאֵל וְדִי בְּבָבֶל לְרֵישֵׁי כַלָּה וּלְרֵישֵׁי גַּלְוָתָא וּלְרֵישֵׁי מְתִיבָתָא וּלְדַיָּנֵי דִי בָבָא. לְכָל תַּלְמִידֵיהוֹן וּלְכָל תַּלְמִידֵי תַּלְמִידֵיהוֹן וּלְכָל מַאן דְּעָסְקִין בְּאוֹרַיְתָא. מַלְכָּא דְעָלְמָא יְבָרֵךְ יַתְהוֹן יַפִּישׁ חַיֵּיהוֹן וְיַסְגֵּא יוֹמֵיהוֹן וְיִתֵּן אַרְכָא לִשְׁנֵיהוֹן. וְיִתְפָּרְקוּן וְיִשְׁתֵּזְבוּן מִן כָּל עָקָא וּמִן כָּל מַרְעִין בִּישִׁין. מָרָן דִּי בִשְׁמַיָּא יְהֵא בְסַעְדְּהוֹן כָּל זְמַן וְעִדָּן. וְנֹאמַר אָמֵן:"}, {"kind": "text", "text": "<em>יחיד המתפלל בביתו אינו אומר יקום פורקן זה ולא מי שברך:</em> יְקוּם פּוּרְקָן מִן שְׁמַיָּא חִנָּא וְחִסְדָּא וְרַחֲמֵי וְחַיֵּי אֲרִיכֵי וּמְזוֹנֵי רְוִיחֵי וְסִיַּעְתָּא דִשְׁמַיָּא וּבַרְיוּת גּוּפָא וּנְהוֹרָא מַעַלְיָא. זַרְעָא חַיָּא וְקַיָּמָא זַרְעָא דִּי לָא יִפְסוֹק וְדִי לָא יִבְטוֹל מִפִּתְגָּמֵי אוֹרַיְתָא. לְכָל קְהָלָא קַדִּישָׁא הָדֵין רַבְרְבַיָּא עִם זְעֵרַיָּא טַפְלָא וּנְשַׁיָּא. מַלְכָּא דְעָלְמָא יְבָרֵךְ יַתְכוֹן יַפִּישׁ חַיֵּיכוֹן וְיַסְגֵּי יוֹמֵיכוֹן וְיִתֵּן אַרְכָא לִשְׁנֵיכוֹן וְתִתְפָּרְקוּן וְתִשְׁתֵּזְבוּן מִן כָּל עָקָא וּמִן כָּל מַרְעִין בִּישִׁין. מָרָן דִּי בִשְׁמַיָּא יְהֵא בְּסַעְדְּכוֹן כָּל זְמַן וְעִדָּן וְנֹאמַר אָמֵן:"}, {"kind": "text", "text": "<em>ברכה לקהל:</em> <br> מִי שֶׁבֵּרַךְ אֲבוֹתֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקֹב. הוּא יְבָרֵךְ אֶת כָּל הַקָּהָל הַקָּדוֹשׁ הַזֶּה עִם כָּל קְהִלּוֹת הַקֹּדֶשׁ. הֵם וּנְשֵׁיהֶם וּבְנֵיהֶם וּבְנוֹתֵיהֶם וְכָל אֲשֶׁר לָהֶם. וּמִי שֶׁמְּיַחֲדִים בָּתֵּי כְנֵסִיּוֹת לִתְפִלָּה. וּמִי שֶׁבָּאִים בְּתוֹכָם לְהִתְפַּלֵּל. וּמִי שֶׁנּוֹתְנִים נֵר לַמָּאוֹר וְיַיִן לְקִדּוּשׁ וּלְהַבְדָּלָה וּפַת לְאוֹרְחִים וּצְדָקָה לָעֲנִיִּים. וְכָל מִי שֶׁעוֹסְקִים בְּצָרְכֵי צִבּוּר בֶּאֱמוּנָה. הַקָּדוֹשׁ בָּרוּךְ הוּא יְשַׁלֵּם שְׂכָרָם וְיָסִיר מֵהֶם כָּל מַחֲלָה וְיִרְפָּא לְכָל גּוּפָם וְיִסְלַח לְכָל עֲוֹנָם. וְיִשְׁלַח בְּרָכָה וְהַצְלָחָה בְּכָל מַעֲשֵׂה יְדֵיהֶם עִם כָּל יִשְׂרָאֵל אֲחֵיהֶם. וְנֹאמַר אָמֵן:"}, {"kind": "header", "text": "תפילה לשלום מדינת ישראל"}, {"kind": "text", "text": "אָבִינוּ שֶׁבַּשָּׁמַיִם,"}, {"kind": "text", "text": "צוּר יִשְׂרָאֵל וְגוֹאֲלוֹ,"}, {"kind": "text", "text": "בָּרֵךְ אֶת מְדִינַת יִשְׂרָאֵל,"}, {"kind": "text", "text": "רֵאשִׁית צְמִיחַת גְּאֻלָּתֵנוּ."}, {"kind": "text", "text": "הָגֵן עָלֶיהָ בְּאֶבְרַת חַסְדֶּךָ,"}, {"kind": "text", "text": "וּפְרֹשׂ עָלֶיהָ סֻכַּת שְׁלוֹמֶךָ,"}, {"kind": "text", "text": "וּשְׁלַח אוֹרְךָ וַאֲמִתְּךָ לְרָאשֶׁיהָ, שָׂרֶיהָ וְיוֹעֲצֶיהָ,"}, {"kind": "text", "text": "וְתַקְּנֵם בְּעֵצָה טוֹבָה מִלְּפָנֶיךָ."}, {"kind": "text", "text": "חַזֵּק אֶת יְדֵי מְגִנֵּי אֶרֶץ קׇדְשֵׁנוּ,"}, {"kind": "text", "text": "וְהַנְחִילֵם אֱלֹהֵינוּ יְשׁוּעָה"}, {"kind": "text", "text": "וַעֲטֶרֶת נִצָּחוֹן תְּעַטְּרֵם,"}, {"kind": "text", "text": "וְנָתַתָּ שָׁלוֹם בָּאָרֶץ,"}, {"kind": "text", "text": "וְשִׂמְחַת עוֹלָם לְיוֹשְׁבֶיהָ."}, {"kind": "text", "text": "וְאֶת אַחֵינוּ כָּל בֵּית יִשְׂרָאֵל,"}, {"kind": "text", "text": "פְּקׇד נָא בְּכָל אַרְצוֹת פְּזוּרֵיהֶם,"}, {"kind": "text", "text": "וְתוֹלִיכֵם מְהֵרָה קוֹמְמִיּוּת לְצִיּוֹן עִירֶךָ"}, {"kind": "text", "text": "וְלִירוּשָׁלַיִם מִשְׁכַּן שְׁמֶךָ,"}, {"kind": "text", "text": "כַּכָּתוּב בְּתוֹרַת מֹשֶׁה עַבְדֶּךְ (דברים ל,ד-ו):"}, {"kind": "text", "text": "\"אִם יִהְיֶה נִדַּחֲךָ בִּקְצֵה הַשָּׁמָיִם,"}, {"kind": "text", "text": "מִשָּׁם יְקַבֶּצְךָ יְיָ אֱלֹהֶיךָ וּמִשָּׁם יִקָּחֶךָ."}, {"kind": "text", "text": "וֶהֱבִיאֲךָ יְיָ אֱלֹהֶיךָ אֶל הָאָרֶץ אֲשֶׁר יָרְשׁוּ אֲבֹתֶיךָ וִירִשְׁתָּהּ,"}, {"kind": "text", "text": "וְהֵיטִבְךָ וְהִרְבְּךָ מֵאֲבֹתֶיךָ."}, {"kind": "text", "text": "וּמָל יְיָ אֱלֹהֶיךָ אֶת לְבָבְךָ וְאֶת לְבַב זַרְעֶךָ,"}, {"kind": "text", "text": "לְאַהֲבָה אֶת יְיָ אֱלֹהֶיךָ בְּכׇל לְבָבְךָ וּבְכׇל נַפְשְׁךָ,"}, {"kind": "text", "text": "לְמַעַן חַיֶּיךָ\"."}, {"kind": "text", "text": "וְיַחֵד לְבָבֵנוּ לְאַהֲבָה וּלְיִרְאָה אֶת שְׁמֶךָ,"}, {"kind": "text", "text": "וְלִשְׁמֹר אֶת כׇּל דִּבְרֵי תּוֹרָתֶךָ,"}, {"kind": "text", "text": "וּשְׁלַח לָנוּ מְהֵרָה בֶּן דָּוִד מְשִׁיחַ צִדְקֶךָ,"}, {"kind": "text", "text": "לִפְדּוֹת מְחַכֵּי קֵץ יְשׁוּעָתֶךָ."}, {"kind": "text", "text": "הוֹפַע בַּהֲדַר גְּאוֹן עֻזֶּךָ"}, {"kind": "text", "text": "עַל כׇּל יוֹשְׁבֵי תֵּבֵל אַרְצֶךָ,"}, {"kind": "text", "text": "וְיֹאמַר כֹּל אֲשֶׁר נְשָׁמָה בְּאַפּוֹ:"}, {"kind": "text", "text": "\"יְיָ אֱלֹהֵי יִשְׂרָאֵל מֶלֶךְ,"}, {"kind": "text", "text": "וּמַלְכוּתוֹ בַּכֹּל מָשָׁלָה!\""}, {"kind": "text", "text": "אָמֵן סֶלָה."}, {"kind": "header", "text": "מי שברך לחיילי צה\"ל"}, {"kind": "text", "text": "מִי שֶׁבֵּרַךְ אֲבוֹתֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקֹב"}, {"kind": "text", "text": "הוּא יְבָרֵךְ אֶת חַיָּלֵי צְבָא הֲגַנָּה לְיִשְׂרָאֵל"}, {"kind": "text", "text": "הָעוֹמְדִים עַל מִשְׁמַר אַרְצֵנוּ וְעָרֵי אֱלֹהֵינוּ"}, {"kind": "text", "text": "מִגְּבוּל הַלְּבָנוֹן וְעַד מִדְבַּר מִצְרַיִם"}, {"kind": "text", "text": "וּמִן הַיָּם הַגָּדוֹל עַד לְבוֹא הָעֲרָבָה בַּיַּבָּשָׁה בָּאֲוִיר וּבַיָּם"}, {"kind": "text", "text": "יִתֵּן ה' אֶת אוֹיְבֵינוּ הַקָּמִים עָלֵינוּ נִגָּפִים לִפְנֵיהֶם"}, {"kind": "text", "text": "הַקָּדוֹשׁ בָּרוּךְ הוּא יִשְׁמֹר וְיַצִּיל אֶת חַיָלֵינוּ מִכָּל צָרָה וְצוּקָה וּמִכָּל נֶגַע וּמַחֲלָה"}, {"kind": "text", "text": "וְיִשְׁלַח בְּרָכָה וְהַצְלָחָה בְּכָל מַעֲשֵׂה יְדֵיהֶם"}, {"kind": "text", "text": "יַדְבֵּר שׂוֹנְאֵינוּ תַּחְתֵּיהֶם וִיעַטְרֵם בְּכֶתֶר יְשׁוּעָה וּבְעֲטֶרֶת נִצָּחוֹן"}, {"kind": "text", "text": "וִיקֻיַּם בָּהֶם הַכָּתוּב:"}, {"kind": "text", "text": "כִּי ה' אֱלֹהֵיכֶם הַהֹלֵךְ עִמָּכֶם לְהִלָּחֵם לָכֶם עִם אֹיְבֵיכֶם לְהוֹשִׁיעַ אֶתְכֶם"}, {"kind": "text", "text": "וְנֹאמַר אָמֵן"}, {"kind": "header", "text": "מי שברך לשבויים"}, {"kind": "text", "text": "מִי שֶׁבֵּרַךְ אֲבוֹתֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקֹב יוֹסֵף מֹשֶׁה וְאַהֲרֹן דָּוִד וּשְׁלֹמֹה, הוּא יְבָרֵךְ וְיִשְׁמֹר וְיִנְצֹר אֶת כָּל הַחֲטוּפִים, הַשְּׁבוּיִים וְהַנֶּעֱדָרִים בְּתוֹךְ שְׁאָר אֲחֵינוּ בֵּית יִשְֹרָאֵל הַנְּתוּנִים בְּצָרָה וּבְשִׁבְיָה. בַּעֲבוּר שֶׁהַקָּהָל מִתְפַּלֵּל בַּעֲבוּרָם, הַקָּדוֹשׁ בָּרוּךְ הוּא יִמָּלֵא רַחֲמִים עֲלֵיהֶם, וְיוֹצִיאֵם מֵחֹשֶׁךְ וְצַלְמָוֶת, וּמוֹסְרוֹתֵיהֶם יְנַתֵּק, וּמִמְּצוּקוֹתֵיהֶם יוֹשִׁיעֵם, וִישִׁיבֵם מְהֵרָה לְחֵיק מִשְׁפְּחוֹתֵיהֶם. יוֹדוּ לַה' חַסְדּוֹ וְנִפְלְאוֹתָיו לִבְנֵי אָדָם. וִיקֻיַּם בָּהֶם מִקְרָא שֶׁכָּתוּב: וּפְדוּיֵי ה' יְשׁוּבוּן וּבָאוּ צִיּוֹן בְּרִנָּה וְשִׂמְחַת עוֹלָם עַל רֹאשָׁם. שָׂשׂוֹן וְשִׂמְחָה יַשִּׂיגוּ וְנָסוּ יָגוֹן וַאֲנָחָה. וְנֹאמַר אָמֵן."}, {"kind": "header", "text": "ברכת החודש"}, {"kind": "text", "text": "הש\"ץ לוקח הספר תורה בידו ואומר:"}, {"kind": "text", "text": "יְהִי רָצון מִלְּפָנֶיךָ ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. שֶׁתְּחַדֵּשׁ עָלֵינוּ אֶת הַחדֶשׁ הַזֶּה לְטובָה וְלִבְרָכָה. וְתִתֶּן לָנוּ חַיִּים אֲרוּכִּים. חַיִּים שֶׁל שָׁלום. חַיִּים שֶׁל טובָה. חַיִּים שֶׁל בְּרָכָה. חַיִּים שֶׁל פַּרְנָסָה. חַיִּים שֶׁל חִלּוּץ עֲצָמות. חַיִּים שֶׁיֵשׁ בָּהֶם יִרְאַת שָׁמַיִם וְיִרְאַת חֵטְא. חַיִּים שֶׁאֵין בָּהֶם בּוּשָׁה וּכְלִמָּה. חַיִּים שֶׁל עשֶׁר וְכָבוד. חַיִּים שֶׁתְּהֵא בָנוּ אַהֲבַת תּורָה וְיִרְאַת שָׁמַיִם. חַיִּים שֶׁיִּמָלְאוּ מִשְׁאֲלות לִבֵּנוּ לְטובָה אָמֵן סֶלָה:"}, {"kind": "text", "text": "מִי שֶׁעָשה נִסִּים לַאֲבותֵינוּ וְגָאַל אותָם מֵעַבְדוּת לְחֵרוּת. הוּא יִגְאַל אותָנוּ בְּקָרוב וִיקַבֵּץ נִדָּחֵינוּ מֵאַרְבַּע כַּנְפות הָאָרֶץ. חֲבֵרִים כָּל יִשרָאֵל וְנאמַר אָמֵן:"}, {"kind": "text", "text": "ראשׁ חדֶשׁ פלוני יִהְיֶה בְּיום פלוני הַבָּא עָלֵינוּ וְעַל כָּל יִשרָאֵל לְטובָה:"}, {"kind": "text", "text": "יְחַדְּשֵׁהוּ הַקָּדושׁ בָּרוּךְ הוּא עָלֵינוּ וְעַל כָּל עַמּו בֵּית יִשרָאֵל בְּכָל מָקום שֶׁהֵם. לְטובָה וְלִבְרָכָה. לְששון וּלְשמְחָה. לִישׁוּעָה וּלְנֶחָמָה. לְפַרְנָסָה טובָה וּלְכַלְכָּלָה. לְחַיִּים וּלְשָׁלום. לִשְׁמוּעות טובות. וְלִבְשורות טובות. <em>בחורף - וְלִגְשָׁמִים בְּעִתָּם</em>. וְלִרְפוּאָה שְׁלֵמָה. וְלִגְאוּלָה קְרובָה וְנאמַר אָמֵן:"}, {"kind": "header", "text": "אב הרחמים"}, {"kind": "text", "text": "<em>אין אומרים \"אב הרחמים\" בשבת שאם היה חל ביום חול לא היו אומרים תחנון, ולא בשבת של ארבע הפרשיות, ולא בשבת שמברכין החודש. אבל כשמברכים את החודשים אייר סיון ואב, אומרים אב הרחמים אפילו אם יש ברית מילה או חתן:</em>"}, {"kind": "text", "text": "אַב הָרַחֲמִים שׁוכֵן מְרומִים. בְּרַחֲמָיו הָעֲצוּמִים הוּא יִפְקד בְּרַחֲמִים הַחֲסִידִים וְהַיְשָׁרִים וְהַתְּמִימִים. קְהִלּות הַקּדֶשׁ שֶׁמָּסְרוּ נַפְשָׁם עַל קְדֻשַּׁת הַשֵּׁם. הַנֶּאֱהָבִים וְהַנְּעִימִים בְּחַיֵּיהֶם וּבְמותָם לא נִפְרָדוּ. מִנְּשָׁרִים קַלּוּ מֵאֲרָיות גָּבֵרוּ לַעֲשות רְצון קונָם וְחֵפֶץ צוּרָם. יִזְכְּרֵם אֱלהֵינוּ לְטובָה עִם שְׁאָר צַדִּיקֵי עולָם. וְיִקום נִקְמַת דַּם עֲבָדָיו הַשָּׁפוּךְ. כַּכָּתוּב בְּתורַת משֶׁה אִישׁ הָאֱלהִים. הַרְנִינוּ גויִם עַמּו כִּי דַם עֲבָדָיו יִקּום וְנָקָם יָשִׁיב לְצָרָיו וְכִפֶּר אַדְמָתו עַמּו: וְעַל יְדֵי עֲבָדֶיךָ הַנְּבִיאִים כָּתוּב לֵאמר. וְנִקֵּיתִי דָּמָם לא נִקֵּיתִי וה' שׁכֵן בְּצִיּון: וּבְכִתְבֵי הַקּדֶשׁ נֶאֱמַר לָמָּה יאמְרוּ הַגּויִם אַיֵּה אֱלהֵיהֶם. יִוָּדַע בַּגּויִם לְעֵינֵינוּ נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ: וְאומֵר, כִּי דרֵשׁ דָּמִים אותָם זָכָר לא שָׁכַח צַעֲקַת עֲנָוִים: וְאומֵר, יָדִין בַּגּויִם מָלֵא גְוִיּות מָחַץ ראשׁ עַל אֶרֶץ רַבָּה. מִנַּחַל בַּדֶּרֶךְ יִשְׁתֶּה עַל כֵּן יָרִים ראשׁ:"}, {"kind": "header", "text": "אשרי"}, {"kind": "text", "text": "אַשְׁרֵי יושְׁבֵי בֵיתֶךָ. עוד יְהַלְלוּךָ סֶּלָה: אַשְׁרֵי הָעָם שֶׁכָּכָה לּו. אַשְׁרֵי הָעָם שה' אֱלהָיו: תְּהִלָּה לְדָוִד. אֲרומִמְךָ אֱלוהַי הַמֶּלֶךְ. וַאֲבָרְכָה שִׁמְךָ לְעולָם וָעֶד: בְּכָל יום אֲבָרְכֶךָּ. וַאֲהַלְלָה שִׁמְךָ לְעולָם וָעֶד: גָּדול ה' וּמְהֻלָּל מְאד. וְלִגְדֻלָּתו אֵין חֵקֶר: דּור לְדור יְשַׁבַּח מַעֲשיךָ. וּגְבוּרתֶיךָ יַגִּידוּ: הֲדַר כְּבוד הודֶךָ. וְדִבְרֵי נִפְלְאתֶיךָ אָשיחָה: וֶעֱזוּז נורְאתֶיךָ יאמֵרוּ. וּגְדֻלָּתְךָ אֲסַפְּרֶנָּה: זֵכֶר רַב טוּבְךָ יַבִּיעוּ. וְצִדְקָתְךָ יְרַנֵּנוּ: חַנּוּן וְרַחוּם ה'. אֶרֶךְ אַפַּיִם וּגְדָל חָסֶד: טוב ה' לַכּל. וְרַחֲמָיו עַל כָּל מַעֲשיו: יודוּךָ ה' כָּל מַעֲשיךָ. וַחֲסִידֶיךָ יְבָרְכוּכָה: כְּבוד מַלְכוּתְךָ יאמֵרוּ. וּגְבוּרָתְךָ יְדַבֵּרוּ: לְהודִיעַ לִבְנֵי הָאָדָם גְּבוּרתָיו. וּכְבוד הֲדַר מַלְכוּתו: מַלְכוּתְךָ מַלְכוּת כָּל עולָמִים. וּמֶמְשַׁלְתְּךָ בְּכָל דּור וָדר: סומֵךְ ה' לְכָל הַנּפְלִים. וְזוקֵף לְכָל הַכְּפוּפִים: עֵינֵי כל אֵלֶיךָ יְשבֵּרוּ. וְאַתָּה נותֵן לָהֶם אֶת אָכְלָם בְּעִתּו: פּותֵחַ אֶת יָדֶךָ. וּמַשבִּיעַ לְכָל חַי רָצון: צַדִּיק ה' בְּכָל דְּרָכָיו. וְחָסִיד בְּכָל מַעֲשיו: קָרוב ה' לְכָל קרְאָיו. לְכל אֲשֶׁר יִקְרָאֻהוּ בֶאֱמֶת: רְצון יְרֵאָיו יַעֲשה. וְאֶת שַׁוְעָתָם יִשְׁמַע וְיושִׁיעֵם: שׁומֵר ה' אֶת כָּל אהֲבָיו. וְאֵת כָּל הָרְשָׁעִים יַשְׁמִיד: תְּהִלַּת ה' יְדַבֶּר פִּי. וִיבָרֵךְ כָּל בָּשר שֵׁם קָדְשׁו לְעולָם וָעֶד: וַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד עולָם. הַלְלוּיָהּ:"}, {"kind": "header", "text": "הכנסת ספר תורה"}, {"kind": "text", "text": "<em>כשמחזירין הספר תורה להיכל אומרים:</em>"}, {"kind": "text", "text": "<em>חזן:</em> יְהַלְלוּ אֶת שֵׁם ה' כִּי נִשגָּב שְׁמו לְבַדּו:"}, {"kind": "text", "text": "<em>קהל:</em> הודו עַל אֶרֶץ וְשָׁמָיִם: וַיָּרֶם קֶרֶן לְעַמּו תְּהִלָּה לְכָל חֲסִידָיו לִבְנֵי יִשרָאֵל עַם קְרבו הַלְלוּיָהּ:"}, {"kind": "text", "text": "<em>בשבת:</em> <br> מִזְמור לְדָוִד. הָבוּ לה' בְּנֵי אֵלִים. הָבוּ לה' כָּבוד וָעז: <br> הָבוּ לה' כְּבוד שְׁמו. הִשְׁתַּחֲווּ לה' בְּהַדְרַת קדֶשׁ: <br> קול ה' עַל הַמָּיִם. אֵל הַכָּבוד הִרְעִים ה' עַל מַיִם רַבִּים: <br> קול ה' בַּכּחַ. קול ה' בֶּהָדָר: <br> קול ה' שׁבֵר אֲרָזִים. וַיְשַׁבֵּר ה' אֶת אַרְזֵי הַלְּבָנון: <br> וַיַּרְקִידֵם כְּמו עֵגֶל. לְבָנון וְשרְיון כְּמו בֶן רְאֵמִים: <br> קול ה' חצֵב לַהֲבות אֵשׁ: <br> קול ה' יָחִיל מִדְבָּר. יָחִיל ה' מִדְבַּר קָדֵשׁ: <br> קול ה' יְחולֵל אַיָּלות. וַיֶּחֱשף יְעָרות וּבְהֵיכָלו כֻּלּו אמֵר כָּבוד: <br> ה' לַמַּבּוּל יָשָׁב. וַיֵּשֶׁב ה' מֶלֶךְ לְעולָם: <br> ה' עז לְעַמּו יִתֵּן. ה' יְבָרֵךְ אֶת עַמּו בַשָׁלום: <br>"}, {"kind": "text", "text": "<em>ביו\"ט כשחל בחול:</em> <br> לְדָוִד מִזְמור. לה' הָאָרֶץ וּמְלואָהּ. תֵּבֵל וְישְׁבֵי בָהּ: <br> כִּי הוּא עַל יַמִּים יְסָדָהּ. וְעַל נְהָרות יְכונְנֶהָ: <br> מִי יַעֲלֶה בְהַר ה'. וּמִי יָקוּם בִּמְקום קָדְשׁו: <br> נְקִי כַפַּיִם וּבַר לֵבָב. אֲשֶׁר לא נָשא לַשָּׁוְא נַפְשִׁי וְלא נִשְׁבַּע לְמִרְמָה: <br> יִשּא בְרָכָה מֵאֵת ה'. וּצְדָקָה מֵאֱלהֵי יִשְׁעו: <br> זֶה דּור דּרְשָׁיו. מְבַקְשֵׁי פָנֶיךָ יַעֲקב סֶלָה: <br> שאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשאוּ פִּתְחֵי עולָם. וְיָבוא מֶלֶךְ הַכָּבוד: <br> מִי זֶה מֶלֶךְ הַכָּבוד. ה' עִזּוּז וְגִבּור. ה' גִּבּור מִלְחָמָה: <br> שאוּ שְׁעָרִים רָאשֵׁיכֶם וּשאוּ פִּתְחֵי עולָם. וְיָבא מֶלֶךְ הַכָּבוד: <br> מִי הוּא זֶה מֶלֶךְ הַכָּבוד. ה' צְבָאות הוּא מֶלֶךְ הַכָּבוד סֶלָה:"}, {"kind": "text", "text": "<em>כשמכניסים ס\"ת להיכל אומרים:</em> <br> וּבְנֻחה יאמַר. שׁוּבָה ה' רִבְבות אַלְפֵי יִשרָאֵל: <br> קוּמָה ה' לִמְנוּחָתֶךָ. אַתָּה וַאֲרון עֻזֶּךָ: <br> כּהֲנֶיךָ יִלְבְּשׁוּ צֶדֶק. וַחֲסִידֶיךָ יְרַנֵּנוּ: <br> בַּעֲבוּר דָּוִד עַבְדֶּךָ אַל תָּשֵׁב פְּנֵי מְשִׁיחֶךָ: <br> כִּי לֶקַח טוב נָתַתִּי לָכֶם. תּורָתִי אַל תַּעֲזבוּ: <br> עֵץ חַיִּים הִיא לַמַּחֲזִיקִים בָּהּ. וְתמְכֶיהָ מְאֻשָּׁר: <br> דְּרָכֶיהָ דַרְכֵי נעַם וְכָל נְתִיבתֶיהָ שָׁלום: <br> הֲשִׁיבֵנוּ ה' אֵלֶיךָ וְנָשׁוּבָה. חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:"}, {"kind": "header", "text": "חצי קדיש"}, {"kind": "text", "text": "<em>חזן:</em> יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [<em>קהל:</em> אמן] <br> בְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן] <br> <em>קהל וחזן:</em> יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא: <br> יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרומַם וְיִתְנַשּא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא. [<em>קהל:</em> בריך הוא:] <br> לְעֵלָּא <em>בעשי\"ת לְעֵלָּא לְעֵלָּא מִכָּל</em> מִן כָּל בִּרְכָתָא וְשִׁירָתָא תֻּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן]"}, {"kind": "header", "text": "אבות"}, {"kind": "text", "text": "כִּי שֵׁם ה' אֶקְרָא הָבוּ גדֶל לֵאלהֵינוּ:"}, {"kind": "text", "text": "אֲדנָי שפָתַי תִּפְתָּח וּפִי יַגִּיד תְּהִלָּתֶךָ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. אֱלהֵי אַבְרָהָם. אֱלהֵי יִצְחָק. וֵאלהֵי יַעֲקב. הָאֵל הַגָּדול הַגִּבּור וְהַנּורָא אֵל עֶלְיון. גּומֵל חֲסָדִים טובִים. וְקונֵה הַכּל. וְזוכֵר חַסְדֵי אָבות. וּמֵבִיא גואֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמו בְּאַהֲבָה:"}, {"kind": "text", "text": "בעש\"ת זָכְרֵנוּ לְחַיִּים. מֶלֶךְ חָפֵץ בַּחַיִּים. וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים. לְמַעַנְךָ אֱלהִים חַיִּים:"}, {"kind": "text", "text": "מֶלֶךְ עוזֵר וּמושִׁיעַ וּמָגֵן:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה'. מָגֵן אַבְרָהָם:"}, {"kind": "header", "text": "גבורות"}, {"kind": "text", "text": "אַתָּה גִבּור לְעולָם אֲדנָי מְחַיֶּה מֵתִים אַתָּה רַב לְהושִׁיעַ:"}, {"kind": "text", "text": "בחורף - מַשִׁיב הָרוּחַ וּמורִיד הַגָּשֶׁם:"}, {"kind": "text", "text": "בקיץ - מורִיד הַטָּל:"}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶסֶד. מְחַיֵּה מֵתִים בְּרַחֲמִים רַבִּים. סומֵךְ נופְלִים וְרופֵא חולִים וּמַתִּיר אֲסוּרִים. וּמְקַיֵּם אֱמוּנָתו לִישֵׁנֵי עָפָר. מִי כָמוךָ בַּעַל גְּבוּרות וּמִי דומֶה לָךְ. מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה:"}, {"kind": "text", "text": "בעש\"ת מִי כָמוךָ אָב הָרַחֲמִים זוכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים:"}, {"kind": "text", "text": "וְנֶאֱמָן אַתָּה לְהַחֲיות מֵתִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' מְחַיֵּה הַמֵּתִים:"}, {"kind": "header", "text": "קדושה"}, {"kind": "text", "text": "קדושה לש\"ץ בחזרת התפלה:"}, {"kind": "text", "text": "נַעֲרִיצְךָ וְנַקְדִישְׁךָ כְּסוד שיחַ שרְפֵי קדֶשׁ הַמַּקְדִּישִׁים שִׁמְךָ בַּקּדֶשׁ כַּכָּתוּב עַל יַד נְבִיאֶךָ. וְקָרָא זֶה אֶל זֶה וְאָמַר:"}, {"kind": "text", "text": "קו\"ח - קָדושׁ קָדושׁ קָדושׁ ה' צְבָאות מְלא כָל הָאָרֶץ כְּבודו:"}, {"kind": "text", "text": "חזן - כְּבודו מָלֵא עולָם. מְשָׁרְתָיו שׁואֲלִים זֶה לָזֶה אַיֵּה מְקום כְּבודו. לְעֻמָּתָם בָּרוּךְ יאמֵרוּ:"}, {"kind": "text", "text": "קו\"ח - בָּרוּךְ כְּבוד ה' מִמְּקומו:"}, {"kind": "text", "text": "חזן - מִמְּקומו הוּא יִפֶן בְּרַחֲמִים וְיָחן עַם הַמְיַחֲדִים שְׁמו עֶרֶב וָבקֶר בְּכָל יום תָּמִיד. פַּעֲמַיִם בְּאַהֲבָה שְׁמַע אומְרִים:"}, {"kind": "text", "text": "קו\"ח שְׁמַע יִשרָאֵל ה' אֱלהֵינוּ ה' אֶחָד:"}, {"kind": "text", "text": "חזן - הוּא אֱלהֵינוּ הוּא אָבִינוּ. הוּא מַלְכֵּנוּ הוּא מושִׁיעֵנוּ. וְהוּא יַשְׁמִיעֵנוּ בְּרַחֲמָיו שֵׁנִית לְעֵינֵי כָּל חָי. לִהְיות לָכֶם לֵאלהִים:"}, {"kind": "text", "text": "קו\"ח - אֲנִי ה' אֱלהֵיכֶם:"}, {"kind": "text", "text": "חזן - וּבְדִבְרֵי קָדְשְׁךָ כָּתוּב לֵאמר:"}, {"kind": "text", "text": "קו\"ח - יִמְלךְ ה' לְעולָם. אֱלהַיִךְ צִיּון לְדר וָדר. הַלְלוּיָהּ:"}, {"kind": "text", "text": "חזן - לְדור וָדור נַגִּיד גָּדְלֶךָ. וּלְנֵצַח נְצָחִים קְדֻשָּׁתְךָ נַקְדִּישׁ. וְשִׁבְחֲךָ אֱלהֵינוּ מִפִּינוּ לא יָמוּשׁ לְעולָם וָעֶד. כִּי אֵל מֶלֶךְ גָּדול וְקָדושׁ אָתָּה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה'. הָאֵל <em>בעש\"ת הַמֶּלֶךְ</em> הַקָּדושׁ:"}, {"kind": "header", "text": "קדושת השם"}, {"kind": "text", "text": "אַתָּה קָדושׁ וְשִׁמְךָ קָדושׁ. וּקְדושִׁים בְּכָל יום יְהַלְלוּךָ סֶּלָה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' הָאֵל <em>בעש\"ת הַמֶּלֶךְ</em> הַקָּדושׁ:"}, {"kind": "header", "text": "לשבת"}, {"kind": "text", "text": "<em>בשבת ראש חודש אומרים כאן אתה יצרת [להלן]:</em> <br> תִּכַּנְתָּ שַׁבָּת רָצִיתָ קָרְבְּנותֶיהָ. צִוִּיתָ פֵּרוּשֶׁיהָ עִם סִדּוּרֵי נְסָכֶיהָ. מְעַנְּגֶיהָ לְעולָם כָּבוד יִנְחָלוּ. טועֲמֶיהָ חַיִּים זָכוּ. וְגַם הָאוהֲבִים דְּבָרֶיהָ גְּדֻלָּה בָּחָרוּ. אָז מִסִּינַי נִצְטַוּוּ עָלֶיהָ. וַתְּצַוֵּנוּ ה' אֱלהֵינוּ לְהַקְרִיב בָּהּ קָרְבַּן מוּסַף שַׁבָּת כָּרָאוּי. יְהִי רָצון מִלְּפָנֶיךָ ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. שֶׁתַּעֲלֵנוּ בְשמְחָה לְאַרְצֵנוּ. וְתִטָּעֵנוּ בִּגְבוּלֵנוּ וְשָׁם נַעֲשה לְפָנֶיךָ אֶת קָרְבְּנות חובותֵינוּ. תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם. וְאֶת מוּסַף יום הַשַּׁבָּת הַזֶּה. נַעֲשה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצונֶךָ. כְּמו שֶׁכָּתַבְתָּ עָלֵינוּ בְּתורָתֶךָ עַל יְדֵי משֶׁה עַבְדֶּךָ מִפִּי כְבודֶךָ כָּאָמוּר:"}, {"kind": "text", "text": "וּבְיום הַשַּׁבָּת. שְׁנֵי כְבָשים בְּנֵי שָׁנָה תְּמִימִם. וּשְׁנֵי עֶשרנִים סלֶת מִנְחָה בְּלוּלָה בַשֶּׁמֶן וְנִסְכּו. עלַת שַׁבַּת בְּשַׁבַּתּו עַל עלַת הַתָּמִיד וְנִסְכָּהּ:"}, {"kind": "text", "text": "יִשמְחוּ בְמַלְכוּתְךָ שׁומְרֵי שַׁבָּת וְקורְאֵי ענֶג. עַם מְקַדְּשֵׁי שְׁבִיעִי. כֻּלָּם יִשבְּעוּ וְיִתְעַנְּגוּ מִטּוּבֶךָ. וּבַשְּׁבִיעִי רָצִיתָ בּו וְקִדַּשְׁתּו חֶמְדַּת יָמִים אותו קָרָאתָ. זֵכֶר לְמַעֲשה בְרֵאשִׁית:"}, {"kind": "text", "text": "אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ רְצֵה בִמְנוּחָתֵנוּ. קַדְּשֵׁנוּ בְּמִצְותֶךָ וְתֵן חֶלְקֵנוּ בְּתורָתֶךָ. שבְּעֵנוּ מִטּוּבֶךָ וְשמְּחֵנוּ בִּישׁוּעָתֶךָ. וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶּאֱמֶת. וְהַנְחִילֵנוּ ה' אֱלהֵינוּ בְּאַהֲבָה וּבְרָצון שַׁבַּת קָדְשֶׁךָ וְיָנוּחוּ בו יִשרָאֵל מְקַדְּשֵׁי שְׁמֶךָ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה'. מְקַדֵּשׁ הַשַּׁבָּת: <br> <em>וממשיכים “רצה\"</em>"}, {"kind": "header", "text": "לשבת ראש חודש"}, {"kind": "text", "text": "<em>בשבת ראש חודש:</em> <br> אַתָּה יָצַרְתָּ עולָמְךָ מִקֶּדֶם כִּלִּיתָ מְלַאכְתְּךָ בַּיּום הַשְּׁבִיעִי. אָהַבְתָּ אותָנוּ וְרָצִיתָ בָּנוּ וְרומַמְתָּנוּ מִכָּל הַלְּשׁונות וְקִדַּשְׁתָּנוּ בְּמִצְותֶיךָ. וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבודָתֶךָ וְשִׁמְךָ הַגָּדול וְהַקָּדושׁ עָלֵינוּ קָרָאתָ:"}, {"kind": "text", "text": "וַתִּתֶּן לָנוּ ה' אֱלהֵינוּ בְּאַהֲבָה שַׁבָּתות לִמְנוּחָה וְרָאשֵׁי חֳדָשִׁים לְכַפָּרָה. וּלְפִי שֶׁחָטָאנוּ לְפָנֶיךָ אֲנַחְנוּ וַאֲבותֵינוּ. חָרְבָה עִירֵנוּ וְשָׁמֵם בֵּית מִקְדָּשֵׁנוּ. וְגָלָה יְקָרֵנוּ וְנֻטַּל כָּבוד מִבֵּית חַיֵּינוּ. וְאֵין אֲנַחְנוּ יְכולִים לַעֲשות חובותֵינוּ בְּבֵית בְּחִירָתֶךָ בַּבַּיִת הַגָּדול וְהַקָּדושׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו. מִפְּנֵי הַיָּד שֶׁנִּשְׁתַּלְּחָה בְּמִקְדָּשֶׁךָ:"}, {"kind": "text", "text": "יְהִי רָצון מִלְּפָנֶיךָ ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. שֶׁתַּעֲלֵנוּ בְשמְחָה לְאַרְצֵנוּ וְתִטָּעֵנוּ בִּגְבוּלֵנוּ. וְשָׁם נַעֲשה לְפָנֶיךָ אֶת קָרְבְּנות חובותֵינוּ תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם. וְאֶת מוּסְפֵי יום הַשַּׁבָּת הַזֶּה וְיום ראשׁ הַחדֶשׁ הַזֶּה. נַעֲשה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצונֶךָ. כְּמו שֶׁכָּתַבְתָּ עָלֵינוּ בְּתורָתֶךָ עַל יְדֵי משֶׁה עַבְדֶּךָ מִפִּי כְבודֶךָ כָּאָמוּר:"}, {"kind": "text", "text": "וּבְיום הַשַּׁבָּת. שְׁנֵי כְבָשים בְּנֵי שָׁנָה תְּמִימִם. וּשְׁנֵי עֶשרנִים סלֶת מִנְחָה בְּלוּלָה בַשֶּׁמֶן וְנִסְכּו:"}, {"kind": "text", "text": "עלַת שַׁבַּת בְּשַׁבַּתּו עַל עלַת הַתָּמִיד וְנִסְכָּהּ:"}, {"kind": "text", "text": "וּבְרָאשֵׁי חָדְשֵׁיכֶם תַּקְרִיבוּ עולָה לה'. פָּרִים בְּנֵי בָקָר שְׁנַיִם וְאַיִל אֶחָד כְּבָשים בְּנֵי שָׁנָה שִׁבְעָה תְּמִימִם: וּמִנְחָתָם וְנִסְכֵּיהֶם כִּמְדֻבָּר. שְׁלשָׁה עֶשרנִים לַפָּר. וּשְׁנֵי עֶשרנִים לָאָיִל וְעִשּרון לַכֶּבֶש וְיַיִן כְּנִסְכּו. וְשעִיר לְכַפֵּר. וּשְׁנֵי תְמִידִים כְּהִלְכָתָם:"}, {"kind": "text", "text": "יִשמְחוּ בְמַלְכוּתְךָ שׁומְרֵי שַׁבָּת וְקורְאֵי ענֶג עַם מְקַדְּשֵׁי שְׁבִיעִי. כֻּלָּם יִשבְּעוּ וְיִתְעַנְּגוּ מִטּוּבֶךָ וּבַשְּׁבִיעִי רָצִיתָ בּו וְקִדַּשְׁתּו חֶמְדַּת יָמִים אותו קָרָאתָ. זֵכֶר לְמַעֲשה בְרֵאשִׁית:"}, {"kind": "text", "text": "אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. רְצֵה בִמְנוּחָתֵנוּ וְחַדֵּשׁ עָלֵינוּ בְּיום הַשַּׁבָּת הַזֶּה אֶת הַחדֶשׁ הַזֶּה. לְטובָה וְלִבְרָכָה. לְששון וּלְשמְחָה. לִישׁוּעָה וּלְנֶחָמָה. לְפַרְנָסָה וּלְכַלְכָּלָה. לְחַיִּים וּלְשָׁלום. לִמְחִילַת חֵטְא וְלִסְלִיחַת עָון. <em>בשנת העיבור עד חודש ניסן וּלְכַפָּרַת פָּשַׁע</em>. קַדְּשֵׁנוּ בְּמִצְותֶךָ וְתֵן חֶלְקֵנוּ בְּתורָתֶךָ. שבְּעֵנוּ מִטּוּבֶךָ וְשמְּחֵנוּ בִּישׁוּעָתֶךָ. וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶּאֱמֶת. וְהַנְחִילֵנוּ ה' אֱלהֵינוּ בְּאַהֲבָה וּבְרָצון שַׁבַּת קָדְשֶׁךָ וְיָנוּחוּ בו יִשרָאֵל מְקַדְּשֵׁי שְׁמֶךָ: כִּי בְעַמְּךָ יִשרָאֵל בָּחַרְתָּ מִכָּל הָאֻמּות וְשַׁבַּת קָדְשְׁךָ לָהֶם הודָעְתָּ וְחֻקֵּי רָאשֵׁי חֳדָשִׁים לָהֶם קָבָעְתָּ: בָּרוּךְ אַתָּה ה'. מְקַדֵּשׁ הַשַּׁבָּת וְיִשרָאֵל וְרָאשֵׁי חֳדָשִׁים:"}, {"kind": "header", "text": "עבודה"}, {"kind": "text", "text": "רְצֵה ה' אֱלהֵינוּ בְּעַמְּךָ יִשרָאֵל וּבִתְפִלָּתָם. וְהָשֵׁב אֶת הָעֲבודָה לִדְבִיר בֵּיתֶךָ. וְאִשֵּׁי יִשרָאֵל וּתְפִלָּתָם. בְּאַהֲבָה תְקַבֵּל בְּרָצון. וּתְהִי לְרָצון תָּמִיד עֲבודַת יִשרָאֵל עַמֶּךָ:"}, {"kind": "text", "text": "וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּון בְּרַחֲמִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה'. הַמַּחֲזִיר שְׁכִינָתו לְצִיּון:"}, {"kind": "header", "text": "מודים"}, {"kind": "text", "text": "מודִים אֲנַחְנוּ לָךְ. שָׁאַתָּה הוּא ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ לְעולָם וָעֶד. צוּר חַיֵּינוּ. מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדור וָדור:"}, {"kind": "text", "text": "נודֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ. וְעַל נִשְׁמותֵינוּ הַפְּקוּדות לָךְ. וְעַל נִסֶּיךָ שֶׁבְּכָל יום עִמָּנוּ. וְעַל נִפְלְאותֶיךָ וְטובותֶיךָ שֶׁבְּכָל עֵת. עֶרֶב וָבקֶר וְצָהֳרָיִם:"}, {"kind": "text", "text": "הַטּוב כִּי לא כָלוּ רַחֲמֶיךָ. וְהַמְרַחֵם כִּי לא תַמּוּ חֲסָדֶיךָ. מֵעולָם קִוִּינוּ לָךְ:"}, {"kind": "text", "text": "מודים דרבנן:"}, {"kind": "text", "text": "מודִים אֲנַחְנוּ לָךְ. שָׁאַתָּה הוּא ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. אֱלהֵי כָל בָּשר. יוצְרֵנוּ יוצֵר בְּרֵאשִׁית. בְּרָכות וְהודָאות לְשִׁמְךָ הַגָּדול וְהַקָּדושׁ. עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְקַיְּמֵנוּ. וְתֶאֱסוף גָּלֻיּותֵינוּ לְחַצְרות קָדְשֶׁךָ. לִשְׁמור חֻקֶּיךָ. וְלַעֲשות רְצונֶךָ. וּלְעָבְדְךָ בְּלֵבָב שָׁלֵם. עַל שֶׁאֲנַחְנוּ מודִים לָךְ. בָּרוּךְ אֵל הַהודָאות:"}, {"kind": "text", "text": "בחנוכה ובפורים דמוקפין אומרים זה:"}, {"kind": "text", "text": "עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרות וְעַל הַתְּשׁוּעות וְעַל הַנִפְלָאות וְעַל הַנֶּחָמות וְעַל הַמִּלְחָמות שֶׁעָשיתָ לַאֲבותֵינוּ בַּיָּמִים הָהֵם בִּזְּמַן הַזֶּה:"}, {"kind": "text", "text": "לחנוכה:"}, {"kind": "text", "text": "בִּימֵי מַתִּתְיָהוּ בֶּן יוחָנָן כּהֵן גָּדול חַשְׁמונַאִי וּבָנָיו. כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשרָאֵל לְהַשְׁכִּיחָם תּורָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצונֶךָ:"}, {"kind": "text", "text": "וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם. רַבְתָּ אֶת רִיבָם. דַנְתָּ אֶת דִּינָם. נָקַמְתָּ אֶת נִקְמָתָם. מָסַרְתָּ גִבּורִים בְּיַד חַלָּשִׁים. וְרַבִּים בְּיַד מְעַטִּים. וּטְמֵאִים בְּיַד טְהורִים. וּרְשָׁעִים בְּיַד צַדִּיקִים. וְזֵדִים בְּיַד עוסְקֵי תורָתֶךָ. וּלְךָ עָשיתָ שֵׁם גָּדול וְקָדושׁ בְּעולָמֶךָ. וּלְעַמְּךָ יִשרָאֵל עָשיתָ תְּשׁוּעָה גְדולָה וּפֻרְקָן כְּהַיּום הַזֶּה:"}, {"kind": "text", "text": "וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ. וּפִנּוּ אֶת הֵיכָלֶךָ. וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ. וְהִדְלִיקוּ נֵרות בְּחַצְרות קָדְשֶׁךָ. וְקָבְעוּ שְׁמונַת יְמֵי חֲנֻכָּה אֵלּוּ. לְהודות וּלְהַלֵּל לְשִׁמְךָ הַגָּדול:"}, {"kind": "text", "text": "לפורים:"}, {"kind": "text", "text": "בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה. כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע. בִּקֵּשׁ לְהַשְׁמִיד לַהֲרג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיום אֶחָד. בִּשְׁלשָׁה עָשר לְחדֶשׁ שְׁנֵים עָשר. הוּא חדֶשׁ אֲדָר. וּשְׁלָלָם לָבוז:"}, {"kind": "text", "text": "וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים. הֵפַרְתָּ אֶת עֲצָתו. וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּו. וַהֲשֵׁבותָ לּו גְּמוּלו בְראשׁו. וְתָלוּ אותו וְאֶת בָּנָיו עַל הָעֵץ:"}, {"kind": "text", "text": "וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרומַם שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעולָם וָעֶד:"}, {"kind": "text", "text": "<em>בעש\"ת</em> וּכְתב לְחַיִּים טובִים כָּל בְּנֵי בְרִיתֶךָ:"}, {"kind": "text", "text": "וְכל הַחַיִּים יודוּךָ סֶּלָה. וִיהַלְלוּ אֶת שִׁמְךָ בֶּאֱמֶת הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה'. הַטּוב שִׁמְךָ וּלְךָ נָאֶה לְהודות:"}, {"kind": "header", "text": "ברכת כהנים"}, {"kind": "text", "text": "אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. בָּרְכֵנוּ בַבְּרָכָה הַמְשֻׁלֶּשֶׁת בַּתּורָה הַכְּתוּבָה עַל יְדֵי משֶׁה עַבְדֶּךָ. הָאֲמוּרָה מִפִּי אַהֲרן וּבָנָיו כּהֲנִים עַם קְדושֶׁךָ. כָּאָמוּר:"}, {"kind": "text", "text": "יְבָרֶכְךָ ה' וְיִשְׁמְרֶךָ:"}, {"kind": "text", "text": "יָאֵר ה' פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ:"}, {"kind": "text", "text": "יִשּא ה' פָּנָיו אֵלֶיךָ וְיָשם לְךָ שָׁלום:"}, {"kind": "text", "text": "והש\"ץ ממשיך \"שים שלום\":"}, {"kind": "text", "text": "אם עלו כהנים לדוכן קוראים להם - כּהֲנִים:"}, {"kind": "text", "text": "והכהנים מברכים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם אֲשֶׁר קִדְּשָׁנוּ בִּקְדֻשָּׁתו שֶׁל אַהֲרן, וְצִוָּנוּ לְבָרֵךְ אֶת עַמּו יִשרָאֵל בְּאַהֲבָה:"}, {"kind": "text", "text": "יְבָרֶכְךָ ה' וְיִשְׁמְרֶךָ:"}, {"kind": "text", "text": "והצבור עונים: אָמֵן:"}, {"kind": "text", "text": "יָאֵר ה' פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ:"}, {"kind": "text", "text": "והצבור עונים: אָמֵן:"}, {"kind": "text", "text": "יִשּא ה' פָּנָיו אֵלֶיךָ וְיָשם לְךָ שָׁלום:"}, {"kind": "text", "text": "והצבור עונים: אָמֵן:"}, {"kind": "text", "text": "הקהל - אַדִּיר בַּמָּרום שׁוכֵן בִּגְבוּרָה אַתָּה שָׁלום וְשִׁמְךָ שָׁלום. יְהִי רָצון שֶׁתָּשים עָלֵינוּ וְעַל כָּל עַמְךָ בֵּית יִשרָאֵל. חַיִּים וּבְרָכָה לְמִשְׁמֶרֶת שָׁלום:"}, {"kind": "header", "text": "שים שלום"}, {"kind": "text", "text": "שים שָׁלום טובָה וּבְרָכָה. חַיִּים חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשרָאֵל עַמֶּךָ. בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד בְּאור פָּנֶיךָ. כִּי בְאור פָּנֶיךָ נָתַתָּ לָּנוּ ה' אֱלהֵינוּ תּורַת חַיִּים וְאַהֲבַת חֶסֶד. וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלום. וְטוב בְּעֵינֶיךָ לְבָרֵךְ אֶת עַמְּךָ יִשרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלומֶךָ:"}, {"kind": "text", "text": "<em>בעש\"ת</em> בְּסֵפֶר חַיִּים. בְּרָכָה וְשָׁלום. וּפַרְנָסָה טובָה. יְשׁוּעות וְנֶחָמות. נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ. אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשרָאֵל. לְחַיִּים טובִים וּלְשָׁלום:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה'. הַמְבָרֵךְ אֶת עַמּו יִשרָאֵל בַּשָּׁלום:"}, {"kind": "header", "text": "אלוהי נצור"}, {"kind": "text", "text": "יִהְיוּ לְרָצון אִמְרֵי פִי וְהֶגְיון לִבִּי לְפָנֶיךָ. ה' צוּרִי וְגואֲלִי:"}, {"kind": "text", "text": "אֱלהַי. נְצר לְשׁונִי מֵרָע וּשפָתַי מִדַּבֵּר מִרְמָה. וְלִמְקַלְלַי נַפְשִׁי תִדּם. וְנַפְשִׁי כֶּעָפָר לַכּל תִּהְיֶה. פְּתַח לִבִּי בְּתורָתֶךָ. וּבְמִצְותֶיךָ תִּרְדּף נַפְשִׁי. וְכָל הַחושְׁבִים עָלַי רָעָה. מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחֲשַׁבְתָּם:"}, {"kind": "text", "text": "עֲשה לְמַעַן שְׁמֶךָ. עֲשה לְמַעַן יְמִינֶךָ. עֲשה לְמַעַן קְדֻשָּׁתֶךָ. עֲשה לְמַעַן תּורָתֶךָ. לְמַעַן יֵחָלְצוּן יְדִידֶיךָ הושִׁיעָה יְמִינְךָ וַעֲנֵנִי:"}, {"kind": "text", "text": "יִהְיוּ לְרָצון אִמְרֵי פִי וְהֶגְיון לִבִּי לְפָנֶיךָ. ה' צוּרִי וְגואֲלִי:"}, {"kind": "text", "text": "עשה שָׁלום <em>בעש\"ת הַשָּׁלום</em> בִּמְרומָיו. הוּא יַעֲשה שָׁלום עָלֵינוּ וְעַל כָּל יִשרָאֵל. וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהִי רָצון מִלְּפָנֶיךָ ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ. וְתֵן חֶלְקֵנוּ בְּתורָתֶךָ:"}, {"kind": "text", "text": "וְשָׁם נַעֲבָדְךָ בְּיִרְאָה כִּימֵי עולָם וּכְשָׁנִים קַדְמונִיות:"}, {"kind": "text", "text": "וְעָרְבָה לה' מִנְחַת יְהוּדָה וִירוּשָׁלָיִם. כִּימֵי עולָם וּכְשָׁנִים קַדְמונִיות:"}, {"kind": "header", "text": "קדיש שלם"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ <em>גרסת הגר\"א: יִתְגַּדֵּל וְיִתְקַדֵּשׁ</em> שְׁמֵהּ רַבָּא. <em>ועונים: </em> אמן בְּעָלְמָא דִי בְרָא כִּרְעוּתֵהּ. וְיַמְלִיךְ מַלְכוּתֵהּ, בְּחַיֵיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵי דְּכָל בֵּית יִשְׂרָאֵל, בַּעֲגַלָא וּבִזְמַן קָרִיב וְאִמְרוּ אָמֵן:<br><em>הקהל עונה:</em> אמן. יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָא:<br>יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָא: יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל , שְׁמֵהּ דְּקוּדְשָׁא בְּרִיךְ הוּא <em>ועונים: </em>בְּרִיךְ הוּא<br>לְעֵילָא מִן כָּל <em>בעשרת ימי תשובה במקום לְעֵילָא מִן כָּל: </em> לְעֵילָא וּלְעֵילָא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחָמָתָא, דַאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן: <em>ועונים: </em> אמן<br><em>קהל:<em> קַבֵּל בְּרַחֲמִים וּבְרָצון אֶת תְּפִלָּתֵנוּ: </em></em><em><em><br> תִּתְקַבַּל צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל בֵּית יִשְׂרָאֵל קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא , וְאִמְרוּ אָמֵן. <em>ועונים: </em>אמן<br><em>קהל: </em>יְהִי שֵׁם יְהוָה מְברָךְ מֵעַתָּה וְעַד עולָם: <br>יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָא וְחַיִּים עָלֵינו וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן: <em>ועונים: </em>אמן<br><em>קהל: </em>עֶזְרִי מֵעִם יְהוָה עשֵׂה שָׁמַיִם וָאָרֶץ: <br>עוֹשֶׂה שָׁלוֹם <em>בעשרת ימי תשובה: </em>השלום בִּמְרוֹמָיו הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן: <em>ועונים: </em>אמן</em></em>"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ <em>גרסת הגר\"א: יִתְגַּדֵּל וְיִתְקַדֵּשׁ</em> שְׁמֵהּ רַבָּא. <em>ועונים: </em> אמן בְּעָלְמָא דִי בְרָא כִּרְעוּתֵהּ. וְיַמְלִיךְ מַלְכוּתֵהּ, בְּחַיֵיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵי דְּכָל בֵּית יִשְׂרָאֵל, בַּעֲגַלָא וּבִזְמַן קָרִיב וְאִמְרוּ אָמֵן:<br><em>הקהל עונה:</em> אמן. יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָא:<br>יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָא: יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל , שְׁמֵהּ דְּקוּדְשָׁא בְּרִיךְ הוּא <em>ועונים: </em>בְּרִיךְ הוּא<br>לְעֵילָא מִן כָּל <em>בעשרת ימי תשובה במקום לְעֵילָא מִן כָּל: </em> לְעֵילָא וּלְעֵילָא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחָמָתָא, דַאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן: <em>ועונים: </em> אמן<br><em>קהל:<em> קַבֵּל בְּרַחֲמִים וּבְרָצון אֶת תְּפִלָּתֵנוּ: </em></em><em><em><br> תִּתְקַבַּל צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל בֵּית יִשְׂרָאֵל קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא , וְאִמְרוּ אָמֵן. <em>ועונים: </em>אמן<br><em>קהל: </em>יְהִי שֵׁם יְהוָה מְברָךְ מֵעַתָּה וְעַד עולָם: <br>יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָא וְחַיִּים עָלֵינו וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן: <em>ועונים: </em>אמן<br><em>קהל: </em>עֶזְרִי מֵעִם יְהוָה עשֵׂה שָׁמַיִם וָאָרֶץ: <br>עוֹשֶׂה שָׁלוֹם <em>בעשרת ימי תשובה: </em>השלום בִּמְרוֹמָיו הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן: <em>ועונים: </em>אמן</em></em>"}, {"kind": "header", "text": "אין כאלוהינו"}, {"kind": "text", "text": "קַוֵּה אֶל ה'. חֲזַק וְיַאֲמֵץ לִבֶּךָ. וְקַוֵּה אֶל ה':"}, {"kind": "text", "text": "אֵין קָדושׁ כַּיהוָה. כִּי אֵין בִּלְתֶּךָ. וְאֵין צוּר כֵּאלהֵינוּ: <br> כִּי מִי אֱלוהַּ מִבַּלְעֲדֵי ה'. וּמִי צוּר זוּלָתִי אֱלהֵינוּ: <br> אֵין כֵּאלהֵינוּ. אֵין כַּאדונֵינוּ. אֵין כְּמַלְכֵּנוּ. אֵין כְּמושִׁיעֵנוּ. מִי כֵאלהֵינוּ. מִי כַאדונֵינוּ. מִי כְמַלְכֵּנוּ. מִי כְמושִׁיעֵנוּ. נודֶה לֵאלהֵינוּ. נודֶה לַאדונֵינוּ. נודֶה לְמַלְכֵּנוּ. נודֶה לְמושִׁיעֵנוּ. בָּרוּךְ אֱלהֵינוּ. בָּרוּךְ אֲדונֵינוּ. בָּרוּךְ מַלְכֵּנוּ. בָּרוּךְ מושִׁיעֵנוּ. אַתָּה הוּא אֱלהֵינוּ. אַתָּה הוּא אֲדונֵינוּ. אַתָּה הוּא מַלְכֵּנוּ. אַתָּה הוּא מושִׁיעֵנוּ. אַתָּה הוּא. שֶׁהִקְטִירוּ אֲבותֵינוּ לְפָנֶיךָ. אֶת קְטרֶת הַסַּמִּים:"}, {"kind": "header", "text": "פיטום הקטורת"}, {"kind": "text", "text": "פִּטּוּם הַקְּטרֶת. הַצֳּרִי. וְהַצִּפּרֶן. הַחֶלְבְּנָה. וְהַלְּבונָה. מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה. מור. וּקְצִיעָה. שִׁבּלֶת נֵרְדְּ. וְכַרְכּום. מִשְׁקַל שִׁשָּׁה עָשר שִׁשָּׁה עָשר מָנֶה. הַקּשְׁטְ שְׁנֵים עָשר. וְקִלּוּפָה שְׁלשָׁה. וְקִנָּמון תִּשְׁעָה. בּרִית כַּרְשִׁינָה תִּשְׁעָה קַבִּין. יֵין קַפְרִיסִין סְאִין תְּלָתָא וְקַבִּין תְּלָתָא. וְאִם אֵין לו יֵין קַפְרִיסִין מֵבִיא חֲמַר חִוַּרְיָן עַתִּיק. מֶלַח סְדומִית רובַע. מַעֲלֶה עָשָׁן כָּל שֶׁהוּא. רַבִּי נָתָן הַבַּבְלִי אומֵר. אַף כִּפַּת הַיַּרְדֵּן כָּל שֶׁהוּא. וְאִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ. וְאִם חִסַּר אַחַת מִכָּל סַמָּנֶיהָ חַיָּב מִיתָה:"}, {"kind": "text", "text": "רַבָּן שִׁמְעון בֶּן גַּמְלִיאֵל אומֵר. הַצֳּרִי אֵינו אֶלָּא שרָף הַנּוטֵף מֵעֲצֵי הַקְּטָף. בּרִית כַּרְשִׁינָה שֶׁשָּׁפִין בָּהּ אֶת הַצִּפּרֶן. כְּדֵי שֶׁתְּהֵא נָאָה. יֵין קַפְרִיסִין שֶׁשּׁורִין בּו אֶת הַצִּפּרֶן. כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלא מֵי רַגְלַיִם יָפִין לָהּ. אֶלָּא שֶׁאֵין מַכְנִיסִין מֵי רַגְלַיִם בַּמִּקְדָּשׁ מִפְּנֵי הַכָּבוד:"}, {"kind": "text", "text": "הַשִׁיר שֶׁהַלְוִיִּם הָיוּ אומְרִים בְּבֵית הַמִּקְדָּשׁ: <br> בַּיּום הָרִאשׁון הָיוּ אומְרִים. לה' הָאָרֶץ וּמְלואָהּ תֵּבֵל וְיושְׁבֵי בָהּ: <br> בַּשֵּׁנִי הָיוּ אומְרִים. גָּדול ה' וּמְהֻלָּל מְאד בְּעִיר אֱלהֵינוּ הַר קָדְשׁו: <br> בַּשְּׁלִישִׁי הָיוּ אומְרִים. אֱלהִים נִצָּב בַּעֲדַת אֵל בְּקֶרֶב אֱלהִים יִשְׁפּט: <br> בָּרְבִיעִי הָיוּ אומְרִים. אֵל נְקָמות ה' אֵל נְקָמות הופִיעַ: <br> בַּחֲמִישִׁי הָיוּ אומְרִים. הַרְנִינוּ לֵאלהִים עוּזֵּנוּ הָרִיעוּ לֵאלהֵי יַעֲקב: <br> בַּשִּׁשִּׁי הָיוּ אומְרִים. ה' מָלָךְ גֵּאוּת לָבֵשׁ לָבֵשׁ ה' עז הִתְאַזָּר אַף תִּכּון תֵּבֵל בַּל תִּמּוט: <br> בַּשַּׁבָּת הָיוּ אומְרִים. מִזְמור שִׁיר לְיום הַשַּׁבָּת. מִזְמור שִׁיר לֶעָתִיד לָבא לְיום שֶׁכֻּלּו שַׁבָּת וּמְנוּחָה לְחַיֵּי הָעולָמִים:"}, {"kind": "text", "text": "תָּנָא דְבֵי אֵלִיָּהוּ. כָּל הַשּׁונֶה הֲלָכות בְּכָל יום. מֻבְטָח לו שֶׁהוּא בֶּן עולָם הַבָּא. שֶׁנֶּאֱמַר, הֲלִיכות עולָם לו. אַל תִּקְרֵי הֲלִיכות אֶלָּא הֲלָכות:"}, {"kind": "text", "text": "אָמַר רַבִּי אֶלְעָזָר אָמַר רַבִּי חֲנִינָא. תַּלְמִידֵי חֲכָמִים מַרְבִּים שָׁלום בָּעולָם. שֶׁנֶּאֱמַר, וְכָל בָּנַיִךְ לִמּוּדֵי ה' וְרַב שְׁלום בָּנָיִךְ: אַל תִּקְרֵי בָּנָיִךְ. אֶלָּא בּונָיִךְ. שָׁלום רָב לְאהֲבֵי תורָתֶךָ. וְאֵין לָמו מִכְשׁול: יְהִי שָׁלום בְּחֵילֵךְ. שַׁלְוָה בְּאַרְמְנותָיִךְ: לְמַעַן אַחַי וְרֵעָי. אֲדַבְּרָה נָּא שָׁלום בָּךְ: לְמַעַן בֵּית ה' אֱלהֵינוּ אֲבַקְשָׁה טוב לָךְ: ה' עז לְעַמּו יִתֵּן. ה' יְבָרֵךְ אֶת עַמּו בַשָּׁלום:"}, {"kind": "header", "text": "קדיש דרבנן"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אמן]"}, {"kind": "text", "text": "בְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן."}, {"kind": "text", "text": "[אמן, יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא]"}, {"kind": "text", "text": "יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא: יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא. בריך הוא. [אמן]"}, {"kind": "text", "text": "לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא תֻּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן. [אמן]"}, {"kind": "text", "text": "עַל יִשְׂרָאֵל וְעַל רַבָּנָן. וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן. וְעַל כָּל מַאן דְּעָסְקִין בְּאוֹרַיְתָא. דִּי בְאַתְרָא קַדִּישָׁא הָדֵין וְדִי בְכָל אֲתַר וַאֲתַר. יְהֵא לְהוֹן וּלְכוֹן שְׁלָמָא רַבָּא חִנָּא וְחִסְדָּא וְרַחֲמִין וְחַיִּין אֲרִיכִין וּמְזוֹנֵי רְוִיחֵי וּפֻרְקָנָא מִן קֳדָם אֲבוּהוֹן דְּבִשְׁמַיָּא וְאַרְעָא וְאִמְרוּ אָמֵן. [אמן]"}, {"kind": "text", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אמן]"}, {"kind": "text", "text": "עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן. [אמן]"}, {"kind": "header", "text": "עלינו"}, {"kind": "text", "text": "עָלֵינוּ לְשַׁבֵּחַ לַאֲדון הַכּל. לָתֵת גְּדֻלָּה לְיוצֵר בְּרֵאשִׁית. שֶׁלּא עָשנוּ כְּגויֵי הָאֲרָצות. וְלא שמָנוּ כְּמִשְׁפְּחות הָאֲדָמָה. שֶׁלּא שם חֶלְקֵנוּ כָּהֶם וְגורָלֵנוּ כְּכָל הֲמונָם: שֶׁהֵם מִשְׁתַּחֲוִים לְהֶבֶל וְרִיק וּמִתְפַּלְלִים אֶל אֵל לא יושִׁיעַ: וַאֲנַחְנוּ כּורְעִים וּמִשְׁתַּחֲוִים וּמודִים לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים הַקָּדושׁ בָּרוּךְ הוּא: שֶׁהוּא נוטֶה שָׁמַיִם וְיוסֵד אָרֶץ. וּמושַׁב יְקָרו בַּשָּׁמַיִם מִמַּעַל. וּשְׁכִינַת עֻזּו בְּגָבְהֵי מְרומִים: הוּא אֱלהֵינוּ אֵין עוד. אֱמֶת מַלְכֵּנוּ. אֶפֶס זוּלָתו. כַּכָּתוּב בְּתורָתו. וְיָדַעְתָּ הַיּום וַהֲשֵׁבתָ אֶל לְבָבֶךָ. כִּי ה' הוּא הָאֱלהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת. אֵין עוד:"}, {"kind": "text", "text": "עַל כֵּן נְקַוֶּה לְּךָ ה' אֱלהֵינוּ לִרְאות מְהֵרָה בְּתִפְאֶרֶת עֻזֶּךָ. לְהַעֲבִיר גִּלּוּלִים מִן הָאָרֶץ. וְהָאֱלִילִים כָּרות יִכָּרֵתוּן. לְתַקֵּן עולָם בְּמַלְכוּת שַׁדַּי. וְכָל בְּנֵי בָשר יִקְרְאוּ בִשְׁמֶךָ לְהַפְנות אֵלֶיךָ כָּל רִשְׁעֵי אָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל יושְׁבֵי תֵבֵל. כִּי לְךָ תִּכְרַע כָּל בֶּרֶךְ. תִּשָּׁבַע כָּל לָשׁון. לְפָנֶיךָ ה' אֱלהֵינוּ יִכְרְעוּ וְיִפּלוּ. וְלִכְבוד שִׁמְךָ יְקָר יִתֵּנוּ. וִיקַבְּלוּ כֻלָּם אֶת על מַלְכוּתֶךָ. וְתִמְלךְ עֲלֵיהֶם מְהֵרָה לְעולָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא וּלְעולְמֵי עַד תִּמְלךְ בְּכָבוד. כַּכָּתוּב בְּתורָתֶךָ. ה' יִמְלךְ לְעולָם וָעֶד: וְנֶאֱמַר. וְהָיָה ה' לְמֶלֶךְ עַל כָּל הָאָרֶץ. בַּיּום הַהוּא יִהְיֶה ה' אֶחָד וּשְׁמו אֶחָד:"}, {"kind": "text", "text": "אַל תִּירָא מִפַּחַד פִּתְאם וּמִשּׁאַת רְשָׁעִים כִּי תָבא: עֻצוּ עֵצָה וְתֻפָר. דַּבְּרוּ דָבָר וְלא יָקוּם. כִּי עִמָּנוּ אֵל: וְעַד זִקְנָה אֲנִי הוּא. וְעַד שיבָה אֲנִי אֶסְבּל. אֲנִי עָשיתִי וַאֲנִי אֶשּא וַאֲנִי אֶסְבּל וַאֲמַלֵּט:"}, {"kind": "header", "text": "מזמור שיר ליום השבת"}, {"kind": "text", "text": "הַיום יום שַׁבָּת קודֶשׁ שֶׁבּו הָיוּ הַלְוִיִּם אומְרִים בְּבֵית הַמִּקְדָּשׁ:<br> מִזְמור שִׁיר לְיום הַשַּׁבָּת:"}, {"kind": "text", "text": "טוב לְהודות לה'. וּלְזַמֵּר לְשִׁמְךָ עֶלְיון: לְהַגִּיד בַּבּוקֶר חַסְדֶּךָ. וֶאֱמוּנָתְךָ בַּלֵּילות: עֲלֵי עָשור וַעֲלֵי נָבֶל. עֲלֵי הִגָּיון בְּכִנּור: כִּי שמַּחְתַּנִי ה' בְּפָעֳלֶךָ. בְּמַעֲשי יָדֶיךָ אֲרַנֵּן: מַה גָּדְלוּ מַעֲשיךָ ה'. מְאד עָמְקוּ מַחְשְׁבתֶיךָ: אִישׁ בַּעַר לא יֵדָע. וּכְסִיל לא יָבִין אֶת זאת: בִּפְרחַ רְשָׁעִים כְּמו עֵשב. וַיָּצִיצוּ כָּל פּעֲלֵי אָוֶן. לְהִשָּׁמְדָם עֲדֵי עַד: וְאַתָּה מָרום לְעולָם ה': כִּי הִנֵּה איְבֶיךָ ה'. כִּי הִנֵּה איְבֶיךָ יאבֵדוּ. יִתְפָּרְדוּ כָּל פּעֲלֵי אָוֶן: וַתָּרֶם כִּרְאֵים קַרְנִי. בַּלּתִי בְּשֶׁמֶן רַעֲנָן: וַתַּבֵּט עֵינִי בְּשׁוּרָי. בַּקָּמִים עָלַי מְרֵעִים תִּשְׁמַעְנָה אָזְנָי: צַדִּיק כַּתָּמָר יִפְרָח. כְּאֶרֶז בַּלְּבָנון יִשגֶּה: שְׁתוּלִים בְּבֵית ה'. בְּחַצְרות אֱלהֵינוּ יַפְרִיחוּ: עוד יְנוּבוּן בְּשיבָה. דְּשֵׁנִים וְרַעֲנַנִּים יִהְיוּ: לְהַגִּיד כִּי יָשָׁר ה'. צוּרִי וְלא עַוְלָתָה בּו:"}, {"kind": "header", "text": "לדוד"}, {"kind": "text", "text": "<em>מא' אלול עד אחר שמיני עצרת אומרים מזמור זה:</em> <br> לְדָוִד. ה' אורִי וְיִשְׁעִי מִמִּי אִירָא. ה' מָעוז חַיַּי מִמִּי אֶפְחָד: בִּקְרב עָלַי מְרֵעִים לֶאֱכל אֶת בְּשרִי. צָרַי וְאיְבַי לִי. הֵמָּה כָּשְׁלוּ וְנָפָלוּ: אִם תַּחֲנֶה עָלַי מַחֲנֶה לא יִירָא לִבִּי. אִם תָּקוּם עָלַי מִלְחָמָה בְּזאת אֲנִי בוטֵחַ: אַחַת שָׁאַלְתִּי מֵאֵת ה'. אותָהּ אֲבַקֵּשׁ. שִׁבְתִּי בְּבֵית ה' כָּל יְמֵי חַיַּי. לַחֲזות בְּנעַם ה' וּלְבַקֵּר בְּהֵיכָלו: כִּי יִצְפְּנֵנִי בְּסֻכּו בְּיום רָעָה יַסְתִּירֵנִי בְּסֵתֶר אָהֳלו. בְּצוּר יְרומְמֵנִי: וְעַתָּה יָרוּם ראשִׁי עַל איְבַי סְבִיבותַי. וְאֶזְבְּחָה בְאָהֳלו זִבְחֵי תְרוּעָה. אָשִׁירָה וַאֲזַמְּרָה לה': שְׁמַע ה' קולִי אֶקְרָא. וְחָנֵּנִי וַעֲנֵנִי: לְךָ אָמַר לִבִּי בַּקְּשׁוּ פָנָי. אֶת פָּנֶיךָ ה' אֲבַקֵּשׁ: אַל תַּסְתֵּר פָּנֶיךָ מִמֶּנִּי. אַל תַּט בְּאַף עַבְדֶּךָ. עֶזְרָתִי הָיִיתָ. אַל תִּטְּשֵׁנִי וְאַל תַּעַזְבֵנִי אֱלהֵי יִשְׁעִי: כִּי אָבִי וְאִמִּי עֲזָבוּנִי. וה' יַאַסְפֵנִי: הורֵנִי ה' דַּרְכֶּךָ וּנְחֵנִי בְּארַח מִישׁור לְמַעַן שׁורְרָי: אַל תִּתְּנֵנִי בְּנֶפֶשׁ צָרָי. כִּי קָמוּ בִי עֵדֵי שֶׁקֶר וִיפֵחַ חָמָס: לוּלֵא הֶאֱמַנְתִּי לִרְאות בְּטוּב ה' בְּאֶרֶץ חַיִּים: קַוֵּה אֶל ה'. חֲזַק וְיַאֲמֵץ לִבֶּךָ. וְקַוֵּה אֶל ה':"}, {"kind": "header", "text": "שיר הכבוד"}, {"kind": "text", "text": "פותחים הארון:"}, {"kind": "text", "text": "<em>חזן:</em> - אַנְעִים זְמִירות וְשִׁירִים אֶאֱרוג. כִּי אֵלֶיךָ נַפְשִׁי תַעֲרוג: <br> <em>קהל:</em> - נַפְשִׁי חָמְדָה בְּצֵל יָדֶךָ. לָדַעַת כָּל רָז סודֶךָ: <br> <em>חזן:</em> - מִדֵּי דַבְּרִי בִּכְבודֶךָ. הומֶה לִבִּי אֶל דּודֶיךָ: <br> <em>קהל:</em> - עַל כֵּן אֲדַבֵּר בְּךָ נִכְבָּדות. וְשִׁמְךָ אֲכַבֵּד בְּשִׁירֵי יְדִידות: <br> <em>חזן:</em> - אֲסַפְּרָה כְבודְךָ וְלא רְאִיתִיךָ. אֲדַמְּךָ אֲכַנְּךָ וְלא יְדַעְתִּיךָ: <br> <em>קהל:</em> - בְּיַד נְבִיאֶיךָ בְּסוד עֲבָדֶיךָ. דִּמִּיתָ הֲדַר כְּבוד הודֶךָ: <br> <em>חזן:</em> - גְּדֻלָּתְךָ וּגְבוּרָתֶךָ. כִּנּוּ לְתוקֶף פְּעֻלָּתֶךָ: <br> <em>קהל:</em> - דִּמּוּ אותְךָ וְלא כְּפִי יֶשְׁךָ. וַיַּשְׁווּךָ לְפִי מַעֲשיךָ: <br> <em>חזן:</em> - הִמְשִׁילוּךָ בְּרוב חֶזְיונות. הִנְּךָ אֶחָד בְּכָל דִּמְיונות: <br> <em>קהל:</em> - וַיֶּחֱזוּ בְךָ זִקְנָה וּבַחֲרוּת. וּשעַר ראשְׁךָ בְּשיבָה וְשַׁחֲרוּת: <br> <em>חזן:</em> - זִקְנָה בְּיום דִּין וּבַחֲרוּת בְּיום קְרָב. כְּאִישׁ מִלְחָמות יָדָיו לו רָב: <br> <em>קהל:</em> - חָבַשׁ כּובַע יְשׁוּעָה בְּראשׁו. הושִׁיעָה לּו יְמִינו וּזְרועַ קָדְשׁו: <br> <em>חזן:</em> - טַלְלֵי אורות ראשׁו נִמְלָא. קְוֻצּותָיו רְסִיסֵי לָיְלָה: <br> <em>קהל:</em> - יִתְפָּאֵר בִּי כִּי חָפֵץ בִּי. וְהוּא יִהְיֶה לִּי לַעֲטֶרֶת צְבִי: <br> <em>חזן:</em> - כֶּתֶם טָהור פָּז דְּמוּת ראשׁו. וְחַק עַל מֵצַח כְּבוד שֵׁם קָדְשׁו: <br> <em>קהל:</em> - לְחֵן וּלְכָבוד צְבִי תִפְאָרָה. אֻמָּתו לו עִטְּרָה עֲטָרָה: <br> <em>חזן:</em> - מַחְלְפות ראשׁו כְּבִימֵי בְחֻרות. קְוֻצּותָיו תַּלְתַּלִּים שְׁחורות: <br> <em>קהל:</em> - נְוֵה הַצֶּדֶק צְבִי תִפְאַרְתּו. יַעֲלֶה נָּא עַל ראשׁ שמְחָתו: <br> <em>חזן:</em> - סְגֻלָּתו תְּהִי נָא בְיָדו עֲטֶרֶת. וּצְנִיף מְלוּכָה צְבִי תִפְאֶרֶת: <br> <em>קהל:</em> - עֲמוּסִים נְשאָם עֲטֶרֶת עִנְּדָם. מֵאֲשֶׁר יָקְרוּ בְעֵינָיו כִּבְּדָם: <br> <em>חזן:</em> - פְּאֵרו עָלַי וּפְאֵרִי עָלָיו. וְקָרוב אֵלַי בְּקָרְאִי אֵלָיו: <br> <em>קהל:</em> - צַח וְאָדום לִלְבוּשׁו אָדום. פּוּרָה בְּדָרְכו בְּבואו מֵאֱדום: <br> <em>חזן:</em> - קֶשֶׁר תְּפִלִּין הֶרְאָה לֶעָנָיו. תְּמוּנַת ה' לְנֶגֶד עֵינָיו: <br> <em>קהל:</em> - רוצֶה בְּעַמּו עֲנָוִים יְפָאֵר. יושֵׁב תְּהִלּות בָּם לְהִתְפָּאֵר: <br> <em>חזן:</em> - ראשׁ דְּבָרְךָ אֱמֶת קורֵא מֵראשׁ. דּור וָדור עַם דּורֶשְׁיךָ דְּרושׁ: <br> <em>קהל:</em> - שִׁית הֲמון שִׁירַי נָא עָלֶיךָ. וְרִנָּתִי תִקְרַב אֵלֶיךָ: <br> <em>חזן:</em> - תְּהִלָּתִי תְּהִי נָא לְראשְׁךָ עֲטֶרֶת. וּתְפִלָּתִי תִּכּון קְטורֶת: <br> <em>קהל:</em> - תִּיקַר שִׁירַת רָשׁ בְּעֵינֶיךָ. כַּשִּׁיר יוּשַׁר עַל קָרְבָּנֶיךָ: <br> <em>חזן:</em> - בִּרְכָתִי תַעֲלֶה לְראשׁ מַשְׁבִּיר. מְחולֵל וּמולִיד צַדִּיק כַּבִּיר: <br> <em>קהל:</em> - וּבְבִרְכָתִי תְנַעֲנַע לִי ראשׁ. וְאותָהּ קַח לְךָ כִּבְשמִים ראשׁ: <br> <em>חזן:</em> - יֶעֱרַב נָא שיחִי עָלֶיךָ. כִּי נַפְשִׁי תַעֲרוג אֵלֶיךָ"}, {"kind": "header", "text": "אדון עולם"}, {"kind": "text", "text": "אֲדון עולָם אֲשֶׁר מָלַךְ. בְּטֶרֶם כָּל יְצִיר נִבְרָא:<br> לְעֵת נַעֲשה בְחֶפְצו כּל. אֲזַי מֶלֶךְ שְׁמו נִקְרָא:<br> וְאַחֲרֵי כִּכְלות הַכּל. לְבַדּו יִמְלךְ נורָא:<br> וְהוּא הָיָה וְהוּא הוֶה. וְהוּא יִהְיֶה בְּתִפְאָרָה:<br> וְהוּא אֶחָד וְאֵין שֵׁנִי. לְהַמְשִׁיל לו לְהַחְבִּירָה:<br> בְּלִי רֵאשִׁית בְּלִי תַכְלִית. וְלו הָעז וְהַמִּשרָה:<br> וְהוּא אֵלִי וְחַי גואֲלִי. וְצוּר חֶבְלִי בְּעֵת צָרָה:<br> וְהוּא נִסִּי וּמָנוס לִי. מְנָת כּוסִי בְּיום אֶקְרָא:<br> בְּיָדו אַפְקִיד רוּחִי. בְּעֵת אִישָׁן וְאָעִירָה:<br> וְעִם רוּחִי גְּוִיָּתִי. ה' לִי וְלא אִירָא:"}], "mincha": [{"kind": "header", "text": "אשרי"}, {"kind": "text", "text": "אַשְׁרֵי יושְׁבֵי בֵיתֶךָ. עוד יְהַלְלוּךָ סֶּלָה: אַשְׁרֵי הָעָם שֶׁכָּכָה לּו. אַשְׁרֵי הָעָם שה' אֱלהָיו: תְּהִלָּה לְדָוִד. אֲרומִמְךָ אֱלוהַי הַמֶּלֶךְ. וַאֲבָרְכָה שִׁמְךָ לְעולָם וָעֶד: בְּכָל יום אֲבָרְכֶךָּ. וַאֲהַלְלָה שִׁמְךָ לְעולָם וָעֶד: גָּדול ה' וּמְהֻלָּל מְאד. וְלִגְדֻלָּתו אֵין חֵקֶר: דּור לְדור יְשַׁבַּח מַעֲשיךָ. וּגְבוּרתֶיךָ יַגִּידוּ: הֲדַר כְּבוד הודֶךָ. וְדִבְרֵי נִפְלְאתֶיךָ אָשיחָה: וֶעֱזוּז נורְאתֶיךָ יאמֵרוּ. וּגְדֻלָּתְךָ אֲסַפְּרֶנָּה: זֵכֶר רַב טוּבְךָ יַבִּיעוּ. וְצִדְקָתְךָ יְרַנֵּנוּ: חַנּוּן וְרַחוּם ה'. אֶרֶךְ אַפַּיִם וּגְדָל חָסֶד: טוב ה' לַכּל. וְרַחֲמָיו עַל כָּל מַעֲשיו: יודוּךָ ה' כָּל מַעֲשיךָ. וַחֲסִידֶיךָ יְבָרְכוּכָה: כְּבוד מַלְכוּתְךָ יאמֵרוּ. וּגְבוּרָתְךָ יְדַבֵּרוּ: לְהודִיעַ לִבְנֵי הָאָדָם גְּבוּרתָיו. וּכְבוד הֲדַר מַלְכוּתו: מַלְכוּתְךָ מַלְכוּת כָּל עולָמִים. וּמֶמְשַׁלְתְּךָ בְּכָל דּור וָדר: סומֵךְ ה' לְכָל הַנּפְלִים. וְזוקֵף לְכָל הַכְּפוּפִים: עֵינֵי כל אֵלֶיךָ יְשבֵּרוּ. וְאַתָּה נותֵן לָהֶם אֶת אָכְלָם בְּעִתּו: פּותֵחַ אֶת יָדֶךָ. וּמַשבִּיעַ לְכָל חַי רָצון: צַדִּיק ה' בְּכָל דְּרָכָיו. וְחָסִיד בְּכָל מַעֲשיו: קָרוב ה' לְכָל קרְאָיו. לְכל אֲשֶׁר יִקְרָאֻהוּ בֶאֱמֶת: רְצון יְרֵאָיו יַעֲשה. וְאֶת שַׁוְעָתָם יִשְׁמַע וְיושִׁיעֵם: שׁומֵר ה' אֶת כָּל אהֲבָיו. וְאֵת כָּל הָרְשָׁעִים יַשְׁמִיד: תְּהִלַּת ה' יְדַבֶּר פִּי. וִיבָרֵךְ כָּל בָּשר שֵׁם קָדְשׁו לְעולָם וָעֶד: וַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד עולָם. הַלְלוּיָהּ:"}, {"kind": "header", "text": "ובא לציון"}, {"kind": "text", "text": "וּבָא לְצִיּון גּואֵל וּלְשָׁבֵי פֶשַׁע בְּיַעֲקב. נְאֻם יְהוָה: וַאֲנִי זאת בְּרִיתִי. אותָם אָמַר יְהוָה. רוּחִי אֲשֶׁר עָלֶיךָ וּדְבָרַי אֲשֶׁר שַׂמְתִּי בְּפִיךָ. לא יָמוּשׁוּ מִפִּיךָ וּמִפִּי זַרְעֲךָ וּמִפִּי זֶרַע זַרְעֲךָ. אָמַר יְהוָה. מֵעַתָּה וְעַד עולָם: <br> וְאַתָּה קָדושׁ יושֵׁב תְּהִלּות יִשְׂרָאֵל. וְקָרָא זֶה אֶל זֶה וְאָמַר: <br> קָדושׁ. קָדושׁ. קָדושׁ יְהוָה צְבָאות. מְלא כָל הָאָרֶץ כְּבודו: <br>וּמְקַבְּלִין דֵּין מִן דֵּין. וְאָמְרִין קַדִּישׁ בִּשְׁמֵי מְרומָא עִלָּאָה בֵּית שְׁכִינְתֵּהּ. קַדִּישׁ עַל אַרְעָא עובַד גְּבוּרְתֵּהּ. קַדִּישׁ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא. יְהוָה צְבָאות. מַלְיָא כָל אַרְעָא זִיו יְקָרֵהּ: <br> וַתִּשָּׂאֵנִי רוּחַ. וָאֶשְׁמַע אַחֲרַי קול רַעַשׁ גָדול.<br> בָּרוּךְ כְּבוד יְהוָה מִמְּקומו: <br> וּנְטָלַתְנִי רוּחָא. וּשְׁמָעִית בַּתְרַי קָל זִיעַ סַגִּיא דִּמְשַׁבְּחִין וְאָמְרִין: בְּרִיךְ יְקָרָא דַיהוָה מֵאֲתַר בֵּית שְׁכִינְתֵּהּ: יְהוָה יִמְלךְ לְעולָם וָעֶד: יְהוָה מַלְכוּתֵהּ קָאֵם לְעָלַם וּלְעָלְמֵי עָלְמַיָּא. יְהוָה אֱלהֵי אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל אֲבותֵינוּ. שָׁמְרָה זּאת לְעולָם לְיֵצֶר מַחְשְׁבות לְבַב עַמֶּךָ. וְהָכֵן לְבָבָם אֵלֶיךָ: וְהוּא רַחוּם. יְכַפֵּר עָון וְלא יַשְׁחִית. וְהִרְבָּה לְהָשִׁיב אַפּו. וְלא יָעִיר כָּל חֲמָתו: כִּי אַתָּה אֲדנָי טוב וְסַלָּח. וְרַב חֶסֶד לְכָל קרְאֶיךָ: צִדְקָתְךָ צֶדֶק לְעולָם וְתורָתְךָ אֱמֶת: תִּתֵּן אֱמֶת לְיַעֲקב. חֶסֶד לְאַבְרָהָם. אֲשֶׁר נִשְׁבַּעְתָּ לַאֲבתֵינוּ מִימֵי קֶדֶם: בָּרוּךְ אֲדנָי יום יום יַעֲמָס לָנוּ. הָאֵל יְשׁוּעָתֵנוּ סֶלָה: יְהוָה צְבָאות עִמָּנוּ. מִשְׂגָּב לָנוּ אֱלהֵי יַעֲקב סֶלָה: יְהוָה צְבָאות אַשְׁרֵי אָדָם בּטֵחַ בָּךְ: יְהוָה הושִׁיעָה. הַמֶּלֶךְ יַעֲנֵנוּ בְיום קָרְאֵנוּ: בָּרוּךְ הוּא אֱלהֵינוּ שֶׁבְּרָאָנוּ לִכְבודו. וְהִבְדִּילָנוּ מִן הַתּועִים. וְנָתַן לָנוּ תּורַת אֱמֶת. וְחַיֵּי עולָם נָטַע בְּתוכֵנוּ. הוּא יִפְתַּח לִבֵּנוּ בְּתורָתו. וְיָשֵׂם בְּלִבֵּנוּ אַהֲבָתו וְיִרְאָתו וְלַעֲשׂות רְצונו וּלְעָבְדו בְּלֵבָב שָׁלֵם. לְמַעַן לא נִיגַע לָרִיק וְלא נֵלֵד לַבֶּהָלָה: יְהִי רָצון מִלְּפָנֶיךָ יְהוָה אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. שֶׁנִּשְׁמר חֻקֶּיךָ בָּעולָם הַזֶּה. וְנִזְכֶּה וְנִחְיֶה וְנִרְאֶה וְנִירַשׁ טובָה וּבְרָכָה לִשְׁנֵי יְמות הַמָּשִׁיחַ וּלְחַיֵּי הָעולָם הַבָּא. לְמַעַן יְזַמֶּרְךָ כָבוד וְלא יִדּם. יְהוָה אֱלהַי לְעולָם אודֶךָּ: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוָה. וְהָיָה יְהוָה מִבְטַחו: בִּטְחוּ בַיהוָה עֲדֵי עַד. כִּי בְּיָהּ יְהוָה צוּר עולָמִים: וְיִבְטְחוּ בְךָ יודְעֵי שְׁמֶךָ. כִּי לא עָזַבְתָּ דּרְשֶׁיךָ יְהוָה: יְהוָה חָפֵץ לְמַעַן צִדְקו. יַגְדִּיל תּורָה וְיַאְדִּיר:"}, {"kind": "header", "text": "חצי קדיש"}, {"kind": "text", "text": "<em>חזן:</em> יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [<em>קהל:</em> אמן] <br> בְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן] <br> <em>קהל וחזן:</em> יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא: <br> יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרומַם וְיִתְנַשּא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא. [<em>קהל:</em> בריך הוא:] <br> לְעֵלָּא <em>בעשי\"ת לְעֵלָּא לְעֵלָּא מִכָּל</em> מִן כָּל בִּרְכָתָא וְשִׁירָתָא תֻּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן]"}, {"kind": "header", "text": "ואני תפילתי"}, {"kind": "text", "text": "וַאֲנִי תְפִלָּתִי לְךָ ה' עֵת רָצון אֱלהִים בְּרָב חַסְדֶּךָ עֲנֵנִי בֶּאֱמֶת יִשְׁעֶךָ:"}, {"kind": "header", "text": "ויהי בנסוע"}, {"kind": "text", "text": "וַיְהִי בִּנְסעַ הָאָרן וַיּאמֶר משֶׁה. קוּמָה ה' וְיָפֻצוּ איְבֶיךָ. וְיָנֻסוּ מְשנְאֶיךָ מִפָּנֶיךָ:"}, {"kind": "text", "text": "כִּי מִצִּיּון תֵּצֵא תורָה. וּדְבַר ה' מִירוּשָׁלָיִם:"}, {"kind": "text", "text": "בָּרוּךְ שֶׁנָּתַן תּורָה לְעַמּו יִשרָאֵל בִּקְדֻשָּׁתו:"}, {"kind": "header", "text": "בריך שמה"}, {"kind": "text", "text": "בְּרִיךְ שְׁמֵהּ דְּמָרֵא עָלְמָא. בְּרִיךְ כִּתְרָךְ וְאַתְרָךְ. יְהֵא רְעוּתָךְ עִם עַמָּךְ יִשרָאֵל לְעָלַם. וּפוּרְקַן יְמִינָךְ אַחֲזֵי לְעַמָּךְ בְּבֵית מַקְדְּשָׁךְ. וּלְאַמְטויֵי לָנָא מִטּוּב נְהורָךְ וּלְקַבֵּל צְלותָנָא בְּרַחֲמִין. יְהֵא רַעֲוָא קֳדָמָךְ דְּתורִיךְ לָן חַיִּין בְּטִיבוּ. וְלֶהֱוֵי אֲנָא פְקִידָא בְּגו צַדִּיקַיָּא. לְמִרְחַם עָלַי וּלְמִנְטַר יָתִי וְיַת כָּל דִּי לִי וְדִי לְעַמָּךְ יִשרָאֵל. אַנְתְּ הוּא זָן לְכלָּא וּמְפַרְנֵס לְכלָּא. אַנְתְּ הוּא שַׁלִּיט עַל כּלָּא. אַנְתְּ הוּא דְשַׁלִּיט עַל מַלְכַיָּא. וּמַלְכוּתָא דִּילָךְ הִיא. אֲנָא עַבְדָּא דְקוּדְשָׁא בְּרִיךְ הוּא דְּסָגִידְנָא קַמֵּהּ וּמִקַּמֵּי דִּיקַר אורַיְתֵהּ בְּכָל עִדָּן וְעִדָּן. לָא עַל אֱנָשׁ רָחִיצְנָא וְלָא עַל בַּר אֱלָהִין סָמִיכְנָא. אֶלָּא בֶּאֱלָהָא דִשְׁמַיָּא. דְּהוּא אֱלָהָא קְשׁוט וְאורַיְתֵהּ קְשׁוט וּנְבִיאוהִי קְשׁוט. וּמַסְגֵּא לְמֶעְבַּד טַבְוָן וּקְשׁוט. בֵּהּ אֲנָא רָחִיץ. וְלִשְׁמֵהּ יַקִּירָא קַדִּישָׁא אֲנָא אֵמַר תֻּשְׁבְּחָן. יְהֵא רַעֲוָא קֳדָמָךְ דְּתִפְתַּח לִבָּאִי בְּאורַיְתָא. וְתַשְׁלִים מִשְׁאֲלִין דְּלִבָּאי וְלִבָּא דְכָל עַמָּךְ יִשרָאֵל. לְטַב וּלְחַיִּין וְלִשְׁלָם:"}, {"kind": "header", "text": "גדלו"}, {"kind": "text", "text": "חזן - גַּדְּלוּ לה' אִתִּי וּנְרומְמָה שְׁמו יַחְדָּו:"}, {"kind": "text", "text": "קהל - לְךָ ה' הַגְּדֻלָּה וְהַגְּבוּרָה וְהַתִּפְאֶרֶת וְהַנֵּצַח וְהַהוד כִּי כל בַּשָּׁמַיִם וּבָאָרֶץ:"}, {"kind": "header", "text": "לך ה׳"}, {"kind": "text", "text": "לְךָ ה' הַמַּמְלָכָה וְהַמִּתְנַשּא לְכל לְראשׁ:"}, {"kind": "text", "text": "רומְמוּ ה' אֱלהֵינוּ וְהִשְׁתַּחֲווּ לַהֲדם רַגְלָיו קָדושׁ הוּא:"}, {"kind": "text", "text": "רומְמוּ ה' אֱלהֵינוּ וְהִשְׁתַּחֲווּ לְהַר קָדְשׁו כִּי קָדושׁ ה' אֱלהֵינוּ:"}, {"kind": "header", "text": "אב הרחמים"}, {"kind": "text", "text": "אָב הָרַחֲמִים הוּא יְרַחֵם עַם עֲמוּסִים וְיִזְכּר בְּרִית אֵיתָנִים. וְיַצִּיל נַפְשׁותֵינוּ מִן הַשָּׁעות הָרָעות. וְיִגְעַר בְּיֵצֶר הָרָע מִן הַנְּשוּאִים. וְיָחן אותָנוּ לִפְלֵיטַת עולָמִים. וִימַלֵּא מִשְׁאֲלותֵינוּ בְּמִדָּה טובָה יְשׁוּעָה וְרַחֲמִים:"}, {"kind": "header", "text": "ותגלה ותראה"}, {"kind": "text", "text": "וְתִגָּלֶה וְתֵרָאֶה מַלְכוּתו עָלֵינוּ בִּזְמַן קָרוב. וְיָחון פְּלֵטָתֵנוּ וּפְלֵטַת עַמּו בֵּית יִשרָאֵל לְחֵן וּלְחֶסֶד וּלְרַחֲמִים וּלְרָצון וְנאמַר אָמֵן. הַכּל הָבוּ גדֶל לֵאלהֵינוּ וּתְנוּ כָבוד לַתּורָה. כּהֵן קְרָב יַעֲמד [פלוני בן פלוני] הַכּהֵן. בָּרוּךְ שֶׁנָּתַן תּורָה לְעַמּו יִשרָאֵל בִּקְדֻשָּׁתו:"}, {"kind": "text", "text": "<em>קהל:</em> וְאַתֶּם הַדְּבֵקִים בה' אֱלהֵיכֶם חַיִּים כֻּלְּכֶם הַיּום:"}, {"kind": "header", "text": "ברכת התורה"}, {"kind": "text", "text": "העולה מברך:"}, {"kind": "text", "text": "בָּרְכוּ אֶת ה' הַמְברָךְ:"}, {"kind": "text", "text": "והקהל עונים:"}, {"kind": "text", "text": "בָּרוּךְ ה' הַמְברָךְ לְעולָם וָעֶד:"}, {"kind": "text", "text": "והעולה חוזר ואומר:"}, {"kind": "text", "text": "בָּרוּךְ ה' הַמְברָךְ לְעולָם וָעֶד:"}, {"kind": "text", "text": "ואח\"כ מברך:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם אֲשֶׁר בָּחַר בָּנוּ מִכָּל הָעַמִּים וְנָתַן לָנוּ אֶת תּורָתו. בָּרוּךְ אַתָּה ה'"}, {"kind": "text", "text": "נותֵן הַתּורָה:"}, {"kind": "text", "text": "אחרי הקריאה מברך העולה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ מֶלֶךְ הָעולָם אֲשֶׁר נָתַן לָנוּ תּורַת אֱמֶת וְחַיֵּי עולָם נָטַע בְּתוכֵנוּ. בָּרוּךְ אַתָּה ה' נותֵן הַתּורָה:"}, {"kind": "header", "text": "הגבהה"}, {"kind": "text", "text": "כשמגביהים הס\"ת אומרים:"}, {"kind": "text", "text": "וְזאת הַתּורָה אֲשֶׁר שם משֶׁה לִפְנֵי בְּנֵי יִשרָאֵל עַל פִּי ה' בְּיַד משֶׁה:"}, {"kind": "header", "text": "יהללו"}, {"kind": "text", "text": "כשמחזירים ספר התורה להיכל אומרים:"}, {"kind": "text", "text": "חזן - יְהַלְלוּ אֶת שֵׁם ה' כִּי נִשגָּב שְׁמו לְבַדּו:"}, {"kind": "text", "text": "קהל - הודו עַל אֶרֶץ וְשָׁמָיִם:"}, {"kind": "text", "text": "וַיָּרֶם קֶרֶן לְעַמּו תְּהִלָּה לְכָל חֲסִידָיו לִבְנֵי יִשרָאֵל עַם קְרבו הַלְלוּיָהּ:"}, {"kind": "header", "text": "לדוד מזמור"}, {"kind": "text", "text": "לְדָוִד מִזְמור. לה' הָאָרֶץ וּמְלואָהּ. תֵּבֵל וְישְׁבֵי בָהּ:"}, {"kind": "text", "text": "כִּי הוּא עַל יַמִּים יְסָדָהּ. וְעַל נְהָרות יְכונְנֶהָ:"}, {"kind": "text", "text": "מִי יַעֲלֶה בְהַר ה'. וּמִי יָקוּם בִּמְקום קָדְשׁו:"}, {"kind": "text", "text": "נְקִי כַפַּיִם וּבַר לֵבָב. אֲשֶׁר לא נָשא לַשָּׁוְא נַפְשִׁי וְלא נִשְׁבַּע לְמִרְמָה:"}, {"kind": "text", "text": "יִשּא בְרָכָה מֵאֵת ה'. וּצְדָקָה מֵאֱלהֵי יִשְׁעו:"}, {"kind": "text", "text": "זֶה דּור דּרְשָׁיו. מְבַקְשֵׁי פָנֶיךָ יַעֲקב סֶלָה:"}, {"kind": "text", "text": "שאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשאוּ פִּתְחֵי עולָם. וְיָבוא מֶלֶךְ הַכָּבוד:"}, {"kind": "text", "text": "מִי זֶה מֶלֶךְ הַכָּבוד. ה' עִזּוּז וְגִבּור. ה' גִּבּור מִלְחָמָה:"}, {"kind": "text", "text": "שאוּ שְׁעָרִים רָאשֵׁיכֶם וּשאוּ פִּתְחֵי עולָם. וְיָבא מֶלֶךְ הַכָּבוד:"}, {"kind": "text", "text": "מִי הוּא זֶה מֶלֶךְ הַכָּבוד. ה' צְבָאות הוּא מֶלֶךְ הַכָּבוד סֶלָה:"}, {"kind": "header", "text": "ובנוחה יאמר"}, {"kind": "text", "text": "כשמכניסים הס\"ת להיכל אומרים זה:"}, {"kind": "text", "text": "וּבְנֻחה יאמַר. שׁוּבָה ה' רִבְבות אַלְפֵי יִשרָאֵל:"}, {"kind": "text", "text": "קוּמָה ה' לִמְנוּחָתֶךָ. אַתָּה וַאֲרון עֻזֶּךָ:"}, {"kind": "text", "text": "כּהֲנֶיךָ יִלְבְּשׁוּ צֶדֶק. וַחֲסִידֶיךָ יְרַנֵּנוּ:"}, {"kind": "text", "text": "בַּעֲבוּר דָּוִד עַבְדֶּךָ אַל תָּשֵׁב פְּנֵי מְשִׁיחֶךָ:"}, {"kind": "text", "text": "כִּי לֶקַח טוב נָתַתִּי לָכֶם. תּורָתִי אַל תַּעֲזבוּ:"}, {"kind": "text", "text": "עֵץ חַיִּים הִיא לַמַּחֲזִיקִים בָּהּ. וְתמְכֶיהָ מְאֻשָּׁר:"}, {"kind": "text", "text": "דְּרָכֶיהָ דַרְכֵי נעַם וְכָל נְתִיבתֶיהָ שָׁלום:"}, {"kind": "text", "text": "הֲשִׁיבֵנוּ ה' אֵלֶיךָ וְנָשׁוּבָה. חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:"}, {"kind": "header", "text": "אבות"}, {"kind": "text", "text": "אֲדנָי שפָתַי תִּפְתָּח וּפִי יַגִּיד תְּהִלָּתֶךָ:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' אֱלהֵינוּ וֵאלהֵי אֲבותֵינוּ. אֱלהֵי אַבְרָהָם. אֱלהֵי יִצְחָק. וֵאלהֵי יַעֲקב. הָאֵל הַגָּדול הַגִּבּור וְהַנּורָא אֵל עֶלְיון. גּומֵל חֲסָדִים טובִים. וְקונֵה הַכּל. וְזוכֵר חַסְדֵּי אָבות. וּמֵבִיא גואֵל לִבְנֵי בְנֵיהֶם לְמַעַן שְׁמו בְּאַהֲבָה:"}, {"kind": "text", "text": "בעשי\"ת זָכְרֵנוּ לְחַיִּים. מֶלֶךְ חָפֵץ בַּחַיִּים. וְכָתְבֵנוּ בְּסֵפֶר הַחַיִּים. לְמַעַנְךָ אֱלהִים חַיִּים:"}, {"kind": "text", "text": "מֶלֶךְ עוזֵר וּמושִׁיעַ וּמָגֵן:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה', מָגֵן אַבְרָהָם:"}, {"kind": "header", "text": "גבורות"}, {"kind": "text", "text": "אַתָּה גִּבּור לְעולָם אֲדנָי. מְחַיֵּה מֵתִים אַתָּה רַב לְהושִׁיעַ:"}, {"kind": "text", "text": "בקיץ - מורִיד הַטָּל:"}, {"kind": "text", "text": "בחורף - מַשִּׁיב הָרוּחַ וּמורִיד הַגָּשֶּׁם:"}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶסֶד. מְחַיֶּה מֵתִים בְּרַחֲמִים רַבִּים. סומֵךְ נופְלִים. וְרופֵא חולִים וּמַתִּיר אֲסוּרִים. וּמְקַיֵּם אֱמוּנָתו לִישֵׁנֵי עָפָר. מִי כָמוךָ בַּעַל גְּבוּרות וּמִי דומֶה לָּךְ. מֶלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִיחַ יְשׁוּעָה:"}, {"kind": "text", "text": "בעשי\"ת - מִי כָמוךָ אַב הָרַחֲמִים. זוכֵר יְצוּרָיו לְחַיִּים בְּרַחֲמִים:"}, {"kind": "text", "text": "וְנֶאֱמָן אַתָּה לְהַחֲיות מֵתִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה', מְחַיֵּה הַמֵּתִים:"}, {"kind": "header", "text": "קדושה"}, {"kind": "text", "text": "קדושה בחזרת הש\"ץ:"}, {"kind": "text", "text": "נְקַדֵּשׁ אֶת שִׁמְךָ בָּעולָם. כְּשֵׁם שֶׁמַּקְדִּישִׁים אותו בִּשְׁמֵי מָרום. כַּכָּתוּב עַל יַד נְבִיאֶךָ:"}, {"kind": "text", "text": "וְקָרָא זֶה אֶל זֶה וְאָמַר:"}, {"kind": "text", "text": "קו\"ח - קָדושׁ. קָדושׁ. קָדושׁ ה' צְבָאות. מְלא כָל הָאָרֶץ כְּבודו:"}, {"kind": "text", "text": "חזן - לְעֻמָתָם בָּרוּךְ יאמֵרוּ:"}, {"kind": "text", "text": "קו\"ח - בָּרוּךְ כְּבוד ה' מִמְּקומו:"}, {"kind": "text", "text": "חזן - וּבְדִבְרֵי קָדְשְׁךָ כָּתוּב לֵאמר:"}, {"kind": "text", "text": "קו\"ח - יִמְלךְ ה' לְעולָם. אֱלהַיִךְ צִיּון לְדר וָדר. הַלְלוּיָהּ:"}, {"kind": "text", "text": "לחזן - לְדור וָדור נַגִּיד גָּדְלֶךָ וּלְנֵצַח נְצָחִים קְדֻשָּׁתְךָ נַקְדִּישׁ. וְשִׁבְחֲךָ אֱלהֵינוּ מִפִּינוּ לא יָמוּשׁ לְעולָם וָעֶד. כִּי אֵל מֶלֶךְ גָּדול וְקָדושׁ אָתָּה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה' הָאֵל <em>בעשי\"ת הַמֶּלֶךְ</em> הַקָּדושׁ:"}, {"kind": "header", "text": "קדושת השם"}, {"kind": "text", "text": "אַתָּה קָדושׁ וְשִׁמְךָ קָדושׁ וּקְדושִׁים בְּכָל יום יְהַלְּלוּךָ סֶּלָה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה ה', הָאֵל <em>בעשי\"ת הַמֶּלֶךְ</em> הַקָּדושׁ:"}, {"kind": "header", "text": "קדושת היום"}, {"kind": "text", "text": "אַתָּה אֶחָד וְשִׁמְךָ אֶחָד וּמִי כְּעַמְּךָ יִשְׂרָאֵל גּוֹי אֶחָד בָּאָרֶץ."}, {"kind": "text", "text": "תִּפְאֶרֶת גְּדֻלָּה וַעֲטֶרֶת יְשׁוּעָה יוֹם מְנוּחָה וּקְדֻשָּׁה לְעַמְּךָ נָתָתָּ."}, {"kind": "text", "text": "אַבְרָהָם יָגֵל יִצְחָק יְרַנֵּן יַעֲקֹב וּבָּנָיו יָנוּחוּ בוֹ."}, {"kind": "text", "text": "מְנוּחַת אַהֲבָה וּנְדָבָה. מְנוּחַת אֱמֶת וֶאֱמוּנָה. מְנוּחַת שָׁלוֹם וְשַׁלְוָה וְהַשְׁקֵט וָבֶטַח"}, {"kind": "text", "text": "מְנוּחָה שְׁלֵמָה שָׁאַתָּה רוֹצֶה בָּהּ."}, {"kind": "text", "text": "יַכִּירוּ בָּנֶיךָ וְיֵדְעוּ כִּי מֵאִתְּךָ הִיא מְנוּחָתָם וְעַל מְנוּחָתָם יַקְדִּישׁוּ אֶת שְׁמֶךָ:"}, {"kind": "header", "text": "עבודה"}, {"kind": "text", "text": "אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ. רְצֵה בִמְנוּחָתֵנוּ. קַדְּשֵׁנוּ בְּמִצְוֹתֶיךָ. וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ. שַׂבְּעֵנוּ מִטּוּבֶךָ. וְשַׂמְּחֵנוּ בִּישׁוּעָתֶךָ. וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶּאֱמֶת. וְהַנְחִילֵנוּ יְהֹוָה אֱלֹהֵינוּ בְּאַהֲבָה וּבְרָצוֹן שַׁבַּת קָדְשֶׁךָ וְיָנוּחוּ בָם יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ: בָּרוּךְ אַתָּה יְהֹוָה מְקַדֵּשׁ הַשַׁבָּת:"}, {"kind": "text", "text": "רְצֵה יְהֹוָה אֱלֹהֵינוּ בְּעַמְּךָ יִשְׂרָאֵל וּבִתְפִלָּתָם. וְהָשֵׁב אֶת הָעֲבוֹדָה לִדְבִיר בֵּיתֶךָ. וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם. בְּאַהֲבָה תְקַבֵּל בְּרָצוֹן. וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּךָ:"}, {"kind": "instruction", "text": "בשבת בראש חודש ובשבת חול המועד אומרים יעלה ויבא:"}, {"kind": "text", "text": "אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ. יַעֲלֶה וְיָבוֹא וְיַגִּיעַ. וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע. וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ. וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ. וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ. וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל. לְפָנֶיךָ. לִפְלֵיטָה לְטוֹבָה. לְחֵן וּלְחֶסֶד וּלְרַחֲמִים. לְחַיִּים וּלְשָׁלוֹם בְּיוֹם:"}, {"kind": "text", "text": "בראש חדש - רֹאשׁ הַחֹדֶשׁ:"}, {"kind": "text", "text": "בחוהמ\"פ - חַג הַמַּצּוֹת:"}, {"kind": "text", "text": "בחוהמ\"ס - חַג הַסֻּכּוֹת:"}, {"kind": "text", "text": "הַזֶּה. זָכְרֵנוּ יְהֹוָה אֱלֹהֵינוּ בּוֹ לְטוֹבָה. וּפָקְדֵנוּ בוֹ לִבְרָכָה. וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ. כִּי אֵלֶיךָ עֵינֵינוּ. כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה:"}, {"kind": "text", "text": "וְתֶחֱזֶינָה עֵינֵינוּ בְּשׁוּבְךָ לְצִיּוֹן בְּרַחֲמִים:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה. הַמַּחֲזִיר שְׁכִינָתוֹ לְצִיּוֹן:"}, {"kind": "header", "text": "מודים ומודים דרבנן"}, {"kind": "text", "text": "מוֹדִים אֲנַחְנוּ לָךְ. שָׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ לְעוֹלָם וָעֶד."}, {"kind": "text", "text": "צוּר חַיֵּינוּ. מָגֵן יִשְׁעֵנוּ אַתָּה הוּא לְדוֹר וָדוֹר:"}, {"kind": "text", "text": "נוֹדֶה לְּךָ וּנְסַפֵּר תְּהִלָּתֶךָ"}, {"kind": "text", "text": "עַל חַיֵּינוּ הַמְּסוּרִים בְּיָדֶךָ. וְעַל נִשְׁמוֹתֵינוּ הַפְּקוּדוֹת לָךְ. וְעַל נִסֶּיךָ שֶׁבְּכָל יוֹם עִמָּנוּ. וְעַל נִפְלְאוֹתֶיךָ וְטוֹבוֹתֶיךָ שֶׁבְּכָל עֵת. עֶרֶב וָבֹקֶר וְצָהֳרָיִם:"}, {"kind": "text", "text": "הַטּוֹב כִּי לֹא כָלוּ רַחֲמֶיךָ. וְהַמְרַחֵם כִּי לֹא תַמּוּ חֲסָדֶיךָ. מֵעוֹלָם קִוִּינוּ לָךְ:"}, {"kind": "text", "text": "מודים דרבנן:"}, {"kind": "text", "text": "מוֹדִים אֲנַחְנוּ לָךְ. שָׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ. אֱלֹהֵי כָל בָּשָׂר. יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית. בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ. עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְקַיְּמֵנוּ. וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ. לִשְׁמוֹר חֻקֶּיךָ. וְלַעֲשׂוֹת רְצוֹנֶךָ. וּלְעָבְדְךָ בְּלֵבָב שָׁלֵם. עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ. בָּרוּךְ אֵל הַהוֹדָאוֹת:"}, {"kind": "header", "text": "על הניסים לחנוכה"}, {"kind": "text", "text": "בחנוכה ובפורים דמוקפין אומרים זה:"}, {"kind": "text", "text": "וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בִּזְּמַן הַזֶּה:"}, {"kind": "text", "text": "לחנוכה:"}, {"kind": "text", "text": "בִּימֵי מַתִּתְיָהוּ בֶּן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנַאִי וּבָנָיו. כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ:"}, {"kind": "text", "text": "וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם. רַבְתָּ אֶת רִיבָם. דַנְתָּ אֶת דִּינָם. נָקַמְתָּ אֶת נִקְמָתָם. מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים. וְרַבִּים בְּיַד מְעַטִּים. וּטְמֵאִים בְּיַד טְהוֹרִים. וּרְשָׁעִים בְּיַד צַדִּיקִים. וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ. וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ. וּלְעַמְּךָ יִשְׂרָאֵל עָשִֹׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה:"}, {"kind": "text", "text": "וְאַחַר כַּךְ בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ. וּפִנּוּ אֶת הֵיכָלֶךָ. וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ. וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ. וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ. לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל:"}, {"kind": "header", "text": "על הניסים לפורים"}, {"kind": "text", "text": "לפורים:"}, {"kind": "text", "text": "בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה. כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע. בִּקֵּשׁ לְהַשְׁמִיד לַהֲרֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד. בִּשְׁלשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר. הוּא חֹדֶשׁ אֲדָר. וּשְׁלָלָם לָבוֹז:"}, {"kind": "text", "text": "וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים. הֵפַרְתָּ אֶת עֲצָתוֹ. וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ. וַהֲשֵׁבוֹתָ לּוֹ גְּמוּלוֹ בְרֹאשׁוֹ. וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ:"}, {"kind": "text", "text": "וְעַל כֻּלָּם יִתְבָּרַךְ וְיִתְרוֹמַם שִׁמְךָ מַלְכֵּנוּ תָּמִיד לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "<em>בש\"ת</em> וּכְתֹב לְחַיִּים טוֹבִים כָּל בְּנֵי בְרִיתֶךָ:"}, {"kind": "text", "text": "וְכֹל הַחַיִּים יוֹדוּךָ סֶּלָה. וִיהַלְלוּ אֶת שִׁמְךָ בֶּאֱמֶת הָאֵל יְשׁוּעָתֵנוּ וְעֶזְרָתֵנוּ סֶלָה:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה. הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת:"}, {"kind": "header", "text": "שים שלום"}, {"kind": "text", "text": "שִׂים שָׁלוֹם טוֹבָה וּבְרָכָה. חַיִּים חֵן וָחֶסֶד וְרַחֲמִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל עַמֶּךָ. בָּרְכֵנוּ אָבִינוּ כֻּלָּנוּ כְּאֶחָד בְּאוֹר פָּנֶיךָ. כִּי בְאוֹר פָּנֶיךָ נָתַתָּ לָּנוּ יְהֹוָה אֱלֹהֵינוּ תּוֹרַת חַיִּים וְאַהֲבַת חֶסֶד. וּצְדָקָה וּבְרָכָה וְרַחֲמִים וְחַיִּים וְשָׁלוֹם. וְטוֹב בְּעֵינֶיךָ לְבָרֵךְ אֶת עַמְּךָ יִשְׂרָאֵל בְּכָל עֵת וּבְכָל שָׁעָה בִּשְׁלוֹמֶךָ:"}, {"kind": "text", "text": "<em>בש\"ת</em> בְּסֵפֶר חַיִּים. בְּרָכָה וְשָׁלוֹם. וּפַרְנָסָה טוֹבָה. יְשׁוּעוֹת וְנֶחָמוֹת. נִזָּכֵר וְנִכָּתֵב לְפָנֶיךָ. אֲנַחְנוּ וְכָל עַמְּךָ בֵּית יִשְׂרָאֵל. לְחַיִּים טוֹבִים וּלְשָׁלוֹם:"}, {"kind": "text", "text": "בָּרוּךְ אַתָּה יְהֹוָה. הַמְבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם:"}, {"kind": "header", "text": "אלוהי נצור"}, {"kind": "text", "text": "יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ. יְהֹוָה צוּרִי וְגוֹאֲלִי:"}, {"kind": "text", "text": "אֱלֹהַי. נְצֹר לְשׁוֹנִי מֵרָע וּשְׂפָתַי מִדַּבֵּר מִרְמָה. וְלִמְקַלְלַי נַפְשִׁי תִדֹּם. וְנַפְשִׁי כֶּעָפָר לַכֹּל תִּהְיֶה. פְּתַח לִבִּי בְּתוֹרָתֶךָ. וּבְמִצְוֹתֶיךָ תִּרְדֹּף נַפְשִׁי. וְכָל הַחוֹשְׁבִים עָלַי רָעָה. מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחֲשַׁבְתָּם:"}, {"kind": "text", "text": "עֲשֵׂה לְמַעַן שְׁמֶךָ. עֲשֵׂה לְמַעַן יְמִינֶךָ. עֲשֵׂה לְמַעַן קְדֻשָּׁתֶךָ. עֲשֵׂה לְמַעַן תּוֹרָתֶךָ. לְמַעַן יֵחָלְצוּן יְדִידֶיךָ הוֹשִׁיעָה יְמִינְךָ וַעֲנֵנִי:"}, {"kind": "text", "text": "יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ. יְהֹוָה צוּרִי וְגוֹאֲלִי:"}, {"kind": "text", "text": "עֹשֶׂה שָׁלוֹם <em>בש\"ת הַשָּׁלוֹם</em> בִּמְרוֹמָיו. הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל. וְאִמְרוּ אָמֵן:"}, {"kind": "text", "text": "יְהִי רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ. שֶׁיִּבָּנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ. וְתֵן חֶלְקֵנוּ בְּתוֹרָתֶךָ:"}, {"kind": "text", "text": "וְשָׁם נַעֲבָדְךָ בְּיִרְאָה כִּימֵי עוֹלָם וּכְשָׁנִים קַדְמוֹנִיוֹת:"}, {"kind": "header", "text": "צדקתך צדק"}, {"kind": "text", "text": "בימים שא\"א בו תחנון בחול וכן בד' פרשיות אין אומרים צדקתך:"}, {"kind": "text", "text": "צִדְקָתְךָ צֶדֶק לְעולָם וְתורָתְךָ אֱמֶת:"}, {"kind": "text", "text": "וְצִדְקָתְךָ אֱלהִים עַד מָרום אֲשֶׁר עָשיתָ גְדולות אֱלהִים מִי כָמוךָ:"}, {"kind": "text", "text": "צִדְקָתְךָ כְּהַרְרֵי אֵל מִשְׁפָּטֶיךָ תְּהום רַבָּה אָדָם וּבְהֵמָה תּושִׁיעַ ה':"}, {"kind": "header", "text": "קדיש שלם"}, {"kind": "text", "text": "יִתְגַּדַּל וְיִתְקַדַּשׁ <em>גרסת הגר\"א: יִתְגַּדֵּל וְיִתְקַדֵּשׁ</em> שְׁמֵהּ רַבָּא. <em>ועונים: </em> אמן בְּעָלְמָא דִי בְרָא כִּרְעוּתֵהּ. וְיַמְלִיךְ מַלְכוּתֵהּ, בְּחַיֵיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵי דְּכָל בֵּית יִשְׂרָאֵל, בַּעֲגַלָא וּבִזְמַן קָרִיב וְאִמְרוּ אָמֵן:<br><em>הקהל עונה:</em> אמן. יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָא:<br>יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָא: יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל , שְׁמֵהּ דְּקוּדְשָׁא בְּרִיךְ הוּא <em>ועונים: </em>בְּרִיךְ הוּא<br>לְעֵילָא מִן כָּל <em>בעשרת ימי תשובה במקום לְעֵילָא מִן כָּל: </em> לְעֵילָא וּלְעֵילָא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחָמָתָא, דַאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן: <em>ועונים: </em> אמן<br><em>קהל:<em> קַבֵּל בְּרַחֲמִים וּבְרָצון אֶת תְּפִלָּתֵנוּ: </em></em><em><em><br> תִּתְקַבַּל צְלוֹתְהוֹן וּבָעוּתְהוֹן דְּכָל בֵּית יִשְׂרָאֵל קֳדָם אֲבוּהוֹן דִּי בִשְׁמַיָּא , וְאִמְרוּ אָמֵן. <em>ועונים: </em>אמן<br><em>קהל: </em>יְהִי שֵׁם יְהוָה מְברָךְ מֵעַתָּה וְעַד עולָם: <br>יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָא וְחַיִּים עָלֵינו וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן: <em>ועונים: </em>אמן<br><em>קהל: </em>עֶזְרִי מֵעִם יְהוָה עשֵׂה שָׁמַיִם וָאָרֶץ: <br>עוֹשֶׂה שָׁלוֹם <em>בעשרת ימי תשובה: </em>השלום בִּמְרוֹמָיו הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן: <em>ועונים: </em>אמן</em></em>"}, {"kind": "header", "text": "עלינו"}, {"kind": "text", "text": "עָלֵינוּ לְשַׁבֵּחַ לַאֲדון הַכּל. לָתֵת גְּדֻלָּה לְיוצֵר בְּרֵאשִׁית. שֶׁלּא עָשנוּ כְּגויֵי הָאֲרָצות. וְלא שמָנוּ כְּמִשְׁפְּחות הָאֲדָמָה. שֶׁלּא שם חֶלְקֵנוּ כָּהֶם וְגורָלֵנוּ כְּכָל הֲמונָם: שֶׁהֵם מִשְׁתַּחֲוִים לְהֶבֶל וְרִיק וּמִתְפַּלְלִים אֶל אֵל לא יושִׁיעַ: וַאֲנַחְנוּ כּורְעִים וּמִשְׁתַּחֲוִים וּמודִים לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים הַקָּדושׁ בָּרוּךְ הוּא: שֶׁהוּא נוטֶה שָׁמַיִם וְיוסֵד אָרֶץ. וּמושַׁב יְקָרו בַּשָּׁמַיִם מִמַּעַל. וּשְׁכִינַת עֻזּו בְּגָבְהֵי מְרומִים: הוּא אֱלהֵינוּ אֵין עוד. אֱמֶת מַלְכֵּנוּ. אֶפֶס זוּלָתו. כַּכָּתוּב בְּתורָתו. וְיָדַעְתָּ הַיּום וַהֲשֵׁבתָ אֶל לְבָבֶךָ. כִּי ה' הוּא הָאֱלהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת. אֵין עוד:"}, {"kind": "text", "text": "עַל כֵּן נְקַוֶּה לְּךָ ה' אֱלהֵינוּ לִרְאות מְהֵרָה בְּתִפְאֶרֶת עֻזֶּךָ. לְהַעֲבִיר גִּלּוּלִים מִן הָאָרֶץ. וְהָאֱלִילִים כָּרות יִכָּרֵתוּן. לְתַקֵּן עולָם בְּמַלְכוּת שַׁדַּי. וְכָל בְּנֵי בָשר יִקְרְאוּ בִשְׁמֶךָ לְהַפְנות אֵלֶיךָ כָּל רִשְׁעֵי אָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל יושְׁבֵי תֵבֵל. כִּי לְךָ תִּכְרַע כָּל בֶּרֶךְ. תִּשָּׁבַע כָּל לָשׁון. לְפָנֶיךָ ה' אֱלהֵינוּ יִכְרְעוּ וְיִפּלוּ. וְלִכְבוד שִׁמְךָ יְקָר יִתֵּנוּ. וִיקַבְּלוּ כֻלָּם אֶת על מַלְכוּתֶךָ. וְתִמְלךְ עֲלֵיהֶם מְהֵרָה לְעולָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא וּלְעולְמֵי עַד תִּמְלךְ בְּכָבוד. כַּכָּתוּב בְּתורָתֶךָ. ה' יִמְלךְ לְעולָם וָעֶד: וְנֶאֱמַר. וְהָיָה ה' לְמֶלֶךְ עַל כָּל הָאָרֶץ. בַּיּום הַהוּא יִהְיֶה ה' אֶחָד וּשְׁמו אֶחָד:"}, {"kind": "text", "text": "אַל תִּירָא מִפַּחַד פִּתְאם וּמִשּׁאַת רְשָׁעִים כִּי תָבא: עֻצוּ עֵצָה וְתֻפָר. דַּבְּרוּ דָבָר וְלא יָקוּם. כִּי עִמָּנוּ אֵל: וְעַד זִקְנָה אֲנִי הוּא. וְעַד שיבָה אֲנִי אֶסְבּל. אֲנִי עָשיתִי וַאֲנִי אֶשּא וַאֲנִי אֶסְבּל וַאֲמַלֵּט:"}, {"kind": "header", "text": "קדיש יתום"}, {"kind": "text", "text": "<em>קדיש יתום:</em> <br> <em>אבל:</em> יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [<em>קהל:</em> אמן] <br> בְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן] <br> <em>קהל ואבל:</em> יְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא: <br> <em>אבל:</em> יִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרומַם וְיִתְנַשּא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא. [<em>קהל:</em> בריך הוא:] <br> לְעֵלָּא מִן כָּל בִּרְכָתָא <em>בעשי”ת: לְעֵלָּא לְעֵלָּא מִכָּל</em> וְשִׁירָתָא תֻּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא. וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן] <br> יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשרָאֵל. וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן] <br> עושה שָׁלום <em>בעשי”ת: הַשָּׁלום</em> בִּמְרומָיו הוּא יַעֲשה שָׁלום עָלֵינוּ וְעַל כָּל יִשרָאֵל וְאִמְרוּ אָמֵן: [<em>קהל:</em> אמן]"}, {"kind": "header", "text": "ברכי נפשי"}, {"kind": "text", "text": "בָּרְכִי נַפְשִׁי אֶת ה'. ה' אֱלהַי גָּדַלְתָּ מְאד. הוד וְהָדָר לָבָשְׁתָּ:"}, {"kind": "text", "text": "עטֶה אור כַּשּלְמָה. נוטֶה שָׁמַיִם כַּיְרִיעָה:"}, {"kind": "text", "text": "הַמְקָרֶה בַמַּיִם עֲלִיּותָיו. הַשּם עָבִים רְכוּבו. הַמְהַלֵּךְ עַל כַּנְפֵי רוּחַ:"}, {"kind": "text", "text": "עשה מַלְאָכָיו רוּחות. מְשָׁרְתָיו אֵשׁ להֵט:"}, {"kind": "text", "text": "יָסַד אֶרֶץ עַל מְכונֶיהָ. בַּל תִּמּוט עולָם וָעֶד:"}, {"kind": "text", "text": "תְּהום כַּלְּבוּשׁ כִּסִּיתו. עַל הָרִים יַעַמְדוּ מָיִם:"}, {"kind": "text", "text": "מִן גַּעֲרָתְךָ יְנוּסוּן. מִן קול רַעַמְךָ יֵחָפֵזוּן:"}, {"kind": "text", "text": "יַעֲלוּ הָרִים יֵרְדוּ בְקָעות. אֶל מְקום זֶה יָסַדְתָּ לָהֶם:"}, {"kind": "text", "text": "גְּבוּל שמְתָּ בַּל יַעֲברוּן. בַּל יְשֻׁבוּן לְכַסּות הָאָרֶץ:"}, {"kind": "text", "text": "הַמְשַׁלֵּחַ מַעְיָנִים. בַּנְּחָלִים בֵּין הָרִים יְהַלֵּכוּן:"}, {"kind": "text", "text": "יַשְׁקוּ כָּל חַיְתו שדָי. יִשְׁבְּרוּ פְרָאִים צְמָאָם:"}, {"kind": "text", "text": "עֲלֵיהֶם עוף הַשָּׁמַיִם יִשְׁכּון. מִבֵּין עֳפָאיִם יִתְּנוּ קול:"}, {"kind": "text", "text": "מַשְׁקֶה הָרִים מֵעֲלִיּותָיו. מִפְּרִי מַעֲשיךָ תִּשבַּע הָאָרֶץ:"}, {"kind": "text", "text": "מַצְמִיחַ חָצִיר לַבְּהֵמָה. וְעֵשב לַעֲבודַת הָאָדָם. לְהוצִיא לֶחֶם מִן הָאָרֶץ:"}, {"kind": "text", "text": "וְיַיִן יְשמַּח לְבַב אֱנושׁ. לְהַצְהִיל פָּנִים מִשָּׁמֶן. וְלֶחֶם לְבַב אֱנושׁ יִסְעָד:"}, {"kind": "text", "text": "יִשבְּעוּ עֲצֵי ה'. אַרְזֵי לְבָנון אֲשֶׁר נָטָע:"}, {"kind": "text", "text": "אֲשֶׁר שָׁם צִפֳּרִים יְקַנֵּנוּ. חֲסִידָה בְּרושִׁים בֵּיתָהּ:"}, {"kind": "text", "text": "הָרִים הַגְּבוהִים לַיְּעֵלִים. סְלָעִים מַחְסֶה לַשְּׁפַנִים:"}, {"kind": "text", "text": "עָשה יָרֵחַ לְמועֲדִים. שֶׁמֶשׁ יָדַע מְבואו:"}, {"kind": "text", "text": "תָּשֶׁת חשֶׁךְ וִיהִי לָיְלָה. בּו תִרְמש כָּל חַיְתו יָעַר:"}, {"kind": "text", "text": "הַכְּפִירִים שׁאֲגִים לַטָּרֶף. וּלְבַקֵּשׁ מֵאֵל אָכְלָם:"}, {"kind": "text", "text": "תִּזְרַח הַשֶּׁמֶשׁ יֵאָסֵפוּן. וְאֶל מְעונתָם יִרְבָּצוּן:"}, {"kind": "text", "text": "יֵצֵא אָדָם לְפָעֳלו. וְלַעֲבודָתו עֲדֵי עָרֶב:"}, {"kind": "text", "text": "מָה רַבּוּ מַעֲשיךָ ה'. כֻּלָּם בְּחָכְמָה עָשיתָ. מָלְאָה הָאָרֶץ קִנְיָנֶךָ:"}, {"kind": "text", "text": "זֶה הַיָּם גָּדול וּרְחַב יָדַיִם. שָׁם רֶמֶש וְאֵין מִסְפָּר. חַיּות קְטַנּות עִם גְּדלות:"}, {"kind": "text", "text": "שָׁם אֳנִיּות יְהַלֵּכוּן. לִוְיָתָן זֶה יָצַרְתָּ לְשחֶק בּו:"}, {"kind": "text", "text": "כֻּלָּם אֵלֶיךָ יְשבֵּרוּן. לָתֵת אָכְלָם בְּעִתּו:"}, {"kind": "text", "text": "תִּתֵּן לָהֶם יִלְקטוּן. תִּפְתַּח יָדְךָ יִשבְּעוּן טוב:"}, {"kind": "text", "text": "תַּסְתִּיר פָּנֶיךָ יִבָּהֵלוּן. תּסֵף רוּחָם יִגְוָעוּן. וְאֶל עֲפָרָם יְשׁוּבוּן:"}, {"kind": "text", "text": "תְּשַׁלַּח רוּחֲךָ יִבָּרֵאוּן. וּתְחַדֵּשׁ פְּנֵי אֲדָמָה:"}, {"kind": "text", "text": "יְהִי כְבוד ה' לְעולָם. יִשמַח ה' בְּמַעֲשיו:"}, {"kind": "text", "text": "הַמַּבִּיט לָאָרֶץ וַתִּרְעָד. יִגַּע בֶּהָרִים וְיֶעֱשָׁנוּ:"}, {"kind": "text", "text": "אָשִׁירָה לה' בְּחַיָּי. אֲזַמְּרָה לֵאלהַי בְּעודִי:"}, {"kind": "text", "text": "יֶעֱרַב עָלָיו שיחִי. אָנכִי אֶשמַח בה':"}, {"kind": "text", "text": "יִתַּמּוּ חַטָּאִים מִן הָאָרֶץ. וּרְשָׁעִים עוד אֵינָם. בָּרְכִי נַפְשִׁי אֶת ה' הַלְלוּיָהּ:"}]}};
window.SIDURON_YOMTOV = {"edot_mizrach": {"maariv": [{"kind": "header", "text": "תפילת ערבית לימי החול"}, {"kind": "instruction", "text": "בליל ראש חודש יש הנוהגים לומר"}, {"kind": "text", "text": "<b>בָּרְכִ֥י</b> (תהילים ק״ד) נַפְשִׁ֗י אֶת־יְהֹ֫וָ֥ה יְהֹוָ֣ה אֱ֭לֹהַי גָּדַ֣לְתָּ מְּאֹ֑ד ה֖וֹד וְהָדָ֣ר לָבָֽשְׁתָּ׃ עֹֽטֶה־א֭וֹר כַּשַּׂלְמָ֑ה נוֹטֶ֥ה שָׁ֝מַ֗יִם כַּיְרִיעָֽה׃ הַ֥מְקָרֶ֥ה בַמַּ֗יִם עֲֽלִיּ֫וֹתָ֥יו הַשָּׂם־עָבִ֥ים רְכוּב֑וֹ הַֽ֝מְהַלֵּ֗ךְ עַל־כַּנְפֵי־רֽוּחַ׃ עֹשֶׂ֣ה מַלְאָכָ֣יו רוּח֑וֹת מְ֝שָׁרְתָ֗יו אֵ֣שׁ לֹהֵֽט׃ יָֽסַד־אֶ֭רֶץ עַל־מְכוֹנֶ֑יהָ בַּל־תִּ֝מּ֗וֹט עוֹלָ֥ם וָעֶֽד׃ תְּ֭הוֹם כַּלְּב֣וּשׁ כִּסִּית֑וֹ עַל־הָ֝רִ֗ים יַ֖עַמְדוּ מָֽיִם׃ מִן־גַּעֲרָ֣תְךָ֣ יְנוּס֑וּן מִן־ק֥וֹל רַֽ֝עַמְךָ֗ יֵחָפֵזֽוּן׃ יַעֲל֣וּ הָ֭רִים יֵרְד֣וּ בְקָע֑וֹת אֶל־מְ֝ק֗וֹם זֶ֤ה ׀ יָסַ֬דְתָּ לָהֶֽם׃ גְּֽבוּל־שַׂ֭מְתָּ בַּל־יַעֲבֹר֑וּן בַּל־יְ֝שֻׁב֗וּן לְכַסּ֥וֹת הָאָֽרֶץ׃ הַֽמְשַׁלֵּ֣חַ מַ֭עְיָנִים בַּנְּחָלִ֑ים בֵּ֥ין הָ֝רִ֗ים יְהַלֵּכֽוּן׃ יַ֭שְׁקוּ כׇּל־חַיְת֣וֹ שָׂדָ֑י יִשְׁבְּר֖וּ פְרָאִ֣ים צְמָאָֽם׃ עֲ֭לֵיהֶם עוֹף־הַשָּׁמַ֣יִם יִשְׁכּ֑וֹן מִבֵּ֥ין עֳ֝פָאיִ֗ם יִתְּנוּ־קֽוֹל׃ מַשְׁקֶ֣ה הָ֭רִים מֵעֲלִיּוֹתָ֑יו מִפְּרִ֥י מַ֝עֲשֶׂ֗יךָ תִּשְׂבַּ֥ע הָאָֽרֶץ׃ מַצְמִ֤יחַ חָצִ֨יר ׀ לַבְּהֵמָ֗ה וְ֭עֵשֶׂב לַעֲבֹדַ֣ת הָאָדָ֑ם לְה֥וֹצִיא לֶ֗֝חֶם מִן־הָאָֽרֶץ׃ וְיַ֤יִן ׀ יְשַׂמַּ֬ח לְֽבַב־אֱנ֗וֹשׁ לְהַצְהִ֣יל פָּנִ֣ים מִשָּׁ֑מֶן וְ֝לֶ֗חֶם לְֽבַב־אֱנ֥וֹשׁ יִסְעָֽד׃ יִ֭שְׂבְּעוּ עֲצֵ֣י יְהֹוָ֑ה אַֽרְזֵ֥י לְ֝בָנ֗וֹן אֲשֶׁ֣ר נָטָֽע׃ אֲשֶׁר־שָׁ֭ם צִפֳּרִ֣ים יְקַנֵּ֑נוּ חֲ֝סִידָ֗ה בְּרוֹשִׁ֥ים בֵּיתָֽהּ׃ הָרִ֣ים הַ֭גְּבֹהִים לַיְּעֵלִ֑ים סְ֝לָעִ֗ים מַחְסֶ֥ה לַֽשְׁפַנִּֽים׃ עָשָׂ֣ה יָ֭רֵחַ לְמוֹעֲדִ֑ים שֶׁ֝֗מֶשׁ יָדַ֥ע מְבוֹאֽוֹ׃ תָּֽשֶׁת־חֹ֭שֶׁךְ וִ֣יהִי לָ֑יְלָה בּוֹ־תִ֝רְמֹ֗שׂ כׇּל־חַיְתוֹ־יָֽעַר׃ הַ֭כְּפִירִים שֹׁאֲגִ֣ים לַטָּ֑רֶף וּלְבַקֵּ֖שׁ מֵאֵ֣ל אׇכְלָֽם׃ תִּזְרַ֣ח הַ֭שֶּׁמֶשׁ יֵאָסֵפ֑וּן וְאֶל־מְ֝עוֹנֹתָ֗ם יִרְבָּצֽוּן׃ יֵצֵ֣א אָדָ֣ם לְפׇעֳל֑וֹ וְֽלַעֲבֹ֖דָת֣וֹ עֲדֵי־עָֽרֶב׃ מָה־רַבּ֬וּ מַעֲשֶׂ֨יךָ ׀ יְֽהֹוָ֗ה כֻּ֭לָּם בְּחׇכְמָ֣ה עָשִׂ֑יתָ מָלְאָ֥ה הָ֝אָ֗רֶץ קִנְיָנֶֽךָ׃ זֶ֤ה ׀ הַיָּ֥ם גָּדוֹל֮ וּרְחַ֢ב יָ֫דָ֥יִם שָֽׁם־רֶ֭מֶשׂ וְאֵ֣ין מִסְפָּ֑ר חַיּ֥וֹת קְ֝טַנּ֗וֹת עִם־גְּדֹלֽוֹת׃ שָׁ֭ם אֳנִיּ֣וֹת יְהַלֵּכ֑וּן לִ֝וְיָתָ֗ן זֶֽה־יָצַ֥רְתָּ לְשַֽׂחֶק־בּֽוֹ׃ כֻּ֭לָּם אֵלֶ֣יךָ יְשַׂבֵּר֑וּן לָתֵ֖ת אׇכְלָ֣ם בְּעִתּֽוֹ׃ תִּתֵּ֣ן לָ֭הֶם יִלְקֹט֑וּן תִּפְתַּ֥ח יָ֝דְךָ֗ יִשְׂבְּע֥וּן טֽוֹב׃ תַּסְתִּ֥יר פָּנֶיךָ֮ יִֽבָּהֵ֫ל֥וּן תֹּסֵ֣ף ר֭וּחָם יִגְוָע֑וּן וְֽאֶל־עֲפָרָ֥ם יְשׁוּבֽוּן׃ תְּשַׁלַּ֣ח ר֭וּחֲךָ יִבָּרֵא֑וּן וּ֝תְחַדֵּ֗שׁ פְּנֵ֣י אֲדָמָֽה׃ יְהִ֤י כְב֣וֹד יְהֹוָ֣ה לְעוֹלָ֑ם יִשְׂמַ֖ח יְהֹוָ֣ה בְּמַעֲשָֽׂיו׃ הַמַּבִּ֣יט לָ֭אָרֶץ וַתִּרְעָ֑ד יִגַּ֖ע בֶּהָרִ֣ים וְֽיֶעֱשָֽׁנוּ׃ אָשִׁ֣ירָה לַיהֹוָ֣ה בְּחַיָּ֑י אֲזַמְּרָ֖ה לֵאלֹהַ֣י בְּעוֹדִֽי׃ יֶעֱרַ֣ב עָלָ֣יו שִׂיחִ֑י אָ֝נֹכִ֗י אֶשְׂמַ֥ח בַּיהֹוָֽה׃ יִתַּ֤מּוּ חַטָּאִ֨ים ׀ מִן־הָאָ֡רֶץ וּרְשָׁעִ֤ים ׀ ע֤וֹד אֵינָ֗ם בָּרְכִ֣י נַ֭פְשִׁי אֶת־יְהֹוָ֗ה הַֽלְלוּיָֽהּ׃"}, {"kind": "instruction", "text": "לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם יוֹד קֵ\"י בְּוָא\"ו קֵ\"י בְּיִחוּדָא שְׁלִים, בְּשֵׁם כָּל יִשְׂרָאֵל, הִנֵּה אֲנַחְנוּ בָּאִים לְהִתְפַּלֵּל תְּפִלַּת עַרְבִית שֶׁתִּקֵּן יַעֲקֹב אָבִינוּ עָלָיו הַשָּׁלוֹם, עִם כָּל־הַמִּצְוֹת הַכְּלוּלוֹת בָּהּ, לְתַקֵּן אֶת שָׁרְשָׁהּ בְּמָקוֹם עֶלְיוֹן, לַעֲשׂות נַחַת רוּחַ לְיוֹצְרֵנוּ וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ׃ שתי פעמים"}, {"kind": "text", "text": "<b>יְהֹוָ֣ה</b> צְבָא֣וֹת עִמָּ֑נוּ מִשְׂגָּֽב־לָ֨נוּ אֱלֹהֵ֖י יַֽעֲקֹ֣ב סֶֽלָה׃ יְהֹוָ֥ה צְבָא֑וֹת אַֽשְׁרֵ֥י אָ֝דָ֗ם בֹּטֵ֥חַ בָּֽךְ׃ יְהֹוָ֥ה הוֹשִׁ֑יעָה הַ֝מֶּ֗לֶךְ יַעֲנֵ֥נוּ בְיוֹם־קׇרְאֵֽנוּ:"}, {"kind": "instruction", "text": "ואומר החזן חצי קדיש"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>וְה֤וּא</b> רַח֨וּם ׀ יְכַפֵּ֥ר עָוֺן֮ וְֽלֹא־יַֽ֫שְׁחִ֥ית וְ֭הִרְבָּה לְהָשִׁ֣יב אַפּ֑וֹ וְלֹא־יָ֝עִ֗יר כׇּל־חֲמָתֽוֹ׃ יְהֹוָ֥ה הוֹשִׁ֑יעָה הַ֝מֶּ֗לֶךְ יַעֲנֵ֥נוּ בְיוֹם־קׇרְאֵֽנוּ:"}, {"kind": "text", "text": "ואומר החזן: בָּרְכוּ אֶת יְהֹוָה הַמְּבֹרָךְ:"}, {"kind": "text", "text": "ועונים הקהל: בָּרוּךְ יְהֹוָה הַמְּבֹרָךְ לְעוֹלָם וָעֵד:"}, {"kind": "text", "text": "ואומר החזן: בָּרוּךְ יְהֹוָה הַמְּבֹרָךְ לְעוֹלָם וָעֵד:"}, {"kind": "header", "text": "ק\"ש וברכותיה"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָֽעוֹלָם, אֲשֶׁר בִּדְבָרוֹ מַֽעֲרִיב עֲרָבִים בְּחָכְמָה, פּוֹתֵֽחַ שְׁעָרִים בִּתְבוּנָה, מְשַׁנֶּה עִתִּים, וּמַֽחֲלִיף אֶת־הַזְּמַנִּים, וּמְסַדֵּר אֶת־הַכּֽוֹכָבִים בְּמִשְׁמְרוֹתֵיהֶם בָּרָקִֽיעַ, כִּרְצוֹנוֹ. בּוֹרֵא יוֹמָם וָלָֽיְלָה, גּוֹלֵל אוֹר מִפְּנֵי חֹֽשֶׁךְ וְחֹֽשֶׁךְ מִפְּנֵי אוֹר. הַמַּֽעֲבִיר יוֹם וּמֵבִיא לָֽיְלָה, וּמַבְדִּיל בֵּין יוֹם וּבֵין לָֽיְלָה, יְהֹוָה צְבָאוֹת שְׁמוֹ: בָּרוּךְ אַתָּה יְהֹוָה, הַמַּֽעֲרִיב עֲרָבִים:"}, {"kind": "text", "text": "<b>אַהֲבַת</b> עוֹלָם בֵּית יִשְׂרָאֵל עַמְּךָ אָהָבְתָּ, תּוֹרָה וּמִצְוֹת חֻקִּים וּמִשְׁפָּטִים אוֹתָֽנוּ לִמַּֽדְתָּ, עַל־כֵּן יְהֹוָה אֱלֹהֵֽינוּ, בְּשָׁכְבֵֽנוּ וּבְקוּמֵֽנוּ נָשִֽׂיחַ בְּחֻקֶּֽיךָ, וְנִשְׂמַח וְנַֽעֲלוֹז בְּדִבְרֵי תַלְמוּד תּֽוֹרָתֶֽךָ וּמִצְוֹתֶֽיךָ וְחֻקּוֹתֶֽיךָ לְעוֹלָם וָעֶד, כִּי־הֵם חַיֵּֽינוּ וְאֹֽרֶךְ יָמֵֽינוּ, וּבָהֶם נֶהְגֶּה יוֹמָם וָלָֽיְלָה, וְאַֽהֲבָֽתְךָ לֹא תָסוּר מִמֶּֽנּוּ לְעֽוֹלָמִים: בָּרוּךְ אַתָּה יְהֹוָה, אוֹהֵב אֶת־עַמּוֹ יִשְׂרָאֵל:"}, {"kind": "instruction", "text": "קודם שיקרא קריאת שמע יכוין לקיים מצוות עשה שנצטוינו לקרא קריאת שמע שתי פעמים ביום, וגם יכוין לקיים מצות עשה ליחד את השם, ויסגור עיניו ביד ימינו בפסוק ראשון עד שישלים ברוך שם, וכן הוא כאן אומר שמע ישראל כלומר קבל דברים אלו והבינם ותדעם שתאמין בם והוא כי ה' הוא אלהינו, ועוד הנה הוא ה' אחד, ונמצא בזה יש קבלה והודאה בשתי דברים האחד הוא קבלת מלכות שמים באומרו ה' אלהינו דמודה שקבלנו אלהותו להיות לנו לאלוה ואנחנו עבדים לו, והשני הוא ענין יחוד השם באומרו ה' אחד שהוא בלי שיתוף אחר (בא\"ח וארא ה\"ו-ז)"}, {"kind": "text", "text": "<b>שְׁמַ֖ע יִשְׂרָאֵ֑ל יְהֹוָ֥ה אֱלֹהֵ֖ינוּ יְהֹוָ֥ה ׀ אֶחָֽד</b>"}, {"kind": "instruction", "text": "בלחש: בָּרוּךְ, שֵּׁם כְּבוֹד מַלְכוּתוֹ, לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "<b>וְאָ֣הַבְתָּ֔</b> (דברים ו ה) אֵ֖ת יְהֹוָ֣ה אֱלֹהֶ֑יךָ בְּכׇל־לְבָבְךָ֥ וּבְכׇל־נַפְשְׁךָ֖ וּבְכׇל־מְאֹדֶֽךָ׃ וְהָי֞וּ הַדְּבָרִ֣ים הָאֵ֗לֶּה אֲשֶׁ֨ר אָנֹכִ֧י מְצַוְּךָ֛ הַיּ֖וֹם עַל־לְבָבֶֽךָ׃ וְשִׁנַּנְתָּ֣ם לְבָנֶ֔יךָ וְדִבַּרְתָּ֖ בָּ֑ם בְּשִׁבְתְּךָ֤ בְּבֵיתֶ֙ךָ֙ וּבְלֶכְתְּךָ֣ בַדֶּ֔רֶךְ וּֽבְשׇׁכְבְּךָ֖ וּבְקוּמֶֽךָ׃ וּקְשַׁרְתָּ֥ם לְא֖וֹת עַל־יָדֶ֑ךָ וְהָי֥וּ לְטֹטָפֹ֖ת בֵּ֥ין עֵינֶֽיךָ׃ וּכְתַבְתָּ֛ם עַל־מְזֻז֥וֹת בֵּיתֶ֖ךָ וּבִשְׁעָרֶֽיךָ׃"}, {"kind": "text", "text": "<b>וְהָיָ֗ה</b> (דברים יא יג) אִם־שָׁמֹ֤עַ תִּשְׁמְעוּ֙ אֶל־מִצְוֺתַ֔י אֲשֶׁ֧ר אָנֹכִ֛י מְצַוֶּ֥ה אֶתְכֶ֖ם הַיּ֑וֹם לְאַהֲבָ֞ה אֶת־יְהֹוָ֤ה אֱלֹֽהֵיכֶם֙ וּלְעׇבְד֔וֹ בְּכׇל־לְבַבְכֶ֖ם וּבְכׇל־נַפְשְׁכֶֽם׃ וְנָתַתִּ֧י מְטַֽר־אַרְצְכֶ֛ם בְּעִתּ֖וֹ יוֹרֶ֣ה וּמַלְק֑וֹשׁ וְאָסַפְתָּ֣ דְגָנֶ֔ךָ וְתִֽירֹשְׁךָ֖ וְיִצְהָרֶֽךָ׃ וְנָתַתִּ֛י עֵ֥שֶׂב בְּשָׂדְךָ֖ לִבְהֶמְתֶּ֑ךָ וְאָכַלְתָּ֖ וְשָׂבָֽעְתָּ׃ הִשָּֽׁמְר֣וּ לָכֶ֔ם פֶּ֥ן יִפְתֶּ֖ה לְבַבְכֶ֑ם וְסַרְתֶּ֗ם וַעֲבַדְתֶּם֙ אֱלֹהִ֣ים אֲחֵרִ֔ים וְהִשְׁתַּחֲוִיתֶ֖ם לָהֶֽם׃ וְחָרָ֨ה אַף־יְהֹוָ֜ה בָּכֶ֗ם וְעָצַ֤ר אֶת־הַשָּׁמַ֙יִם֙ וְלֹֽא־יִהְיֶ֣ה מָטָ֔ר וְהָ֣אֲדָמָ֔ה לֹ֥א תִתֵּ֖ן אֶת־יְבוּלָ֑הּ וַאֲבַדְתֶּ֣ם מְהֵרָ֗ה מֵעַל֙ הָאָ֣רֶץ הַטֹּבָ֔ה אֲשֶׁ֥ר יְהֹוָ֖ה נֹתֵ֥ן לָכֶֽם׃ וְשַׂמְתֶּם֙ אֶת־דְּבָרַ֣י אֵ֔לֶּה עַל־לְבַבְכֶ֖ם וְעַֽל־נַפְשְׁכֶ֑ם וּקְשַׁרְתֶּ֨ם אֹתָ֤ם לְאוֹת֙ עַל־יֶדְכֶ֔ם וְהָי֥וּ לְטוֹטָפֹ֖ת בֵּ֥ין עֵינֵיכֶֽם׃ וְלִמַּדְתֶּ֥ם אֹתָ֛ם אֶת־בְּנֵיכֶ֖ם לְדַבֵּ֣ר בָּ֑ם בְּשִׁבְתְּךָ֤ בְּבֵיתֶ֙ךָ֙ וּבְלֶכְתְּךָ֣ בַדֶּ֔רֶךְ וּֽבְשׇׁכְבְּךָ֖ וּבְקוּמֶֽךָ׃ וּכְתַבְתָּ֛ם עַל־מְזוּז֥וֹת בֵּיתֶ֖ךָ וּבִשְׁעָרֶֽיךָ׃ לְמַ֨עַן יִרְבּ֤וּ יְמֵיכֶם֙ וִימֵ֣י בְנֵיכֶ֔ם עַ֚ל הָֽאֲדָמָ֔ה אֲשֶׁ֨ר נִשְׁבַּ֧ע יְהֹוָ֛ה לַאֲבֹתֵיכֶ֖ם לָתֵ֣ת לָהֶ֑ם כִּימֵ֥י הַשָּׁמַ֖יִם עַל־הָאָֽרֶץ׃"}, {"kind": "text", "text": "<b>וַיֹּ֥אמֶר</b> (במדבר טו לז) יְהֹוָ֖ה אֶל־מֹשֶׁ֥ה לֵּאמֹֽר׃ דַּבֵּ֞ר אֶל־בְּנֵ֤י יִשְׂרָאֵל֙ וְאָמַרְתָּ֣ אֲלֵהֶ֔ם וְעָשׂ֨וּ לָהֶ֥ם צִיצִ֛ת עַל־כַּנְפֵ֥י בִגְדֵיהֶ֖ם לְדֹרֹתָ֑ם וְנָ֥תְנ֛וּ עַל־צִיצִ֥ת הַכָּנָ֖ף פְּתִ֥יל תְּכֵֽלֶת׃ וְהָיָ֣ה לָכֶם֮ לְצִיצִת֒ וּרְאִיתֶ֣ם אֹת֗וֹ וּזְכַרְתֶּם֙ אֶת־כׇּל־מִצְוֺ֣ת יְהֹוָ֔ה וַעֲשִׂיתֶ֖ם אֹתָ֑ם וְלֹֽא־תָת֜וּרוּ אַחֲרֵ֤י לְבַבְכֶם֙ וְאַחֲרֵ֣י עֵֽינֵיכֶ֔ם אֲשֶׁר־אַתֶּ֥ם זֹנִ֖ים אַחֲרֵיהֶֽם׃ לְמַ֣עַן תִּזְכְּר֔וּ וַעֲשִׂיתֶ֖ם אֶת־כׇּל־מִצְוֺתָ֑י וִהְיִיתֶ֥ם קְדֹשִׁ֖ים לֵאלֹֽהֵיכֶֽם׃ אֲנִ֞י יְהֹוָ֣ה אֱלֹֽהֵיכֶ֗ם אֲשֶׁ֨ר הוֹצֵ֤אתִי אֶתְכֶם֙ מֵאֶ֣רֶץ מִצְרַ֔יִם לִהְי֥וֹת לָכֶ֖ם לֵאלֹהִ֑ים אֲנִ֖י יְהֹוָ֥ה אֱלֹהֵיכֶֽם׃ אֱמֶת:<br>וחוזר החזן: יְהֹוָה אֱלֹהֵיכֶם אֱמֶת:"}, {"kind": "text", "text": "<b>וֶֽאֱמוּנָה</b> כָּל־זֹאת וְקַיָּם עָלֵֽינוּ, כִּי הוּא יְהֹוָה אֱלֹהֵֽינוּ וְאֵין זוּלָתוֹ, וַֽאֲנַֽחְנוּ יִשְׂרָאֵל עַמּוֹ. הַפּוֹדֵֽנוּ מִיַּד מְלָכִים, הַגֹּֽאֲלֵֽנוּ מַלְכֵּֽנוּ מִכַּף כָּל־עָֽרִיצִים, הָאֵל הַנִּפְרָע לָֽנוּ מִצָּרֵֽינוּ, הַֽמְשַׁלֵּם גְּמוּל לְכָל־אֽוֹיְבֵי נַפְשֵֽׁנוּ. הַשָּׂם נַפְשֵֽׁנוּ בַּֽחַיִּים, וְלֹא נָתַן לַמּוֹט רַגְלֵֽנוּ, הַמַּדְרִיכֵֽנוּ עַל בָּמוֹת אֽוֹיְבֵֽינוּ, וַיָּֽרֶם קַרְנֵֽנוּ עַל־כָּל־שֽׂוֹנְאֵֽינוּ. הָאֵל הָעֹשֶׂה לָֽנוּ נְקָמָה בְּפַרְעֹה, בְּאוֹתוֹת וּבְמֽוֹפְתִים בְּאַדְמַת בְּנֵי חָם. הַמַּכֶּה בְעֶבְרָתוֹ כָּל־בְּכוֹרֵי מִצְרָֽיִם, וַיּוֹצִיא אֶת־עַמּוֹ יִשְׂרָאֵל מִתּוֹכָם לְחֵרוּת עוֹלָם. הַמַּֽעֲבִיר בָּנָיו בֵּין גִּזְרֵי יַם־סוּף, וְאֶת־רוֹדְפֵיהֶם וְאֶת־שׂוֹנְאֵיהֶם בִּתְהוֹמוֹת טִבַּע. רָאוּ בָנִים אֶת־גְּבוּרָתוֹ, שִׁבְּחוּ וְהוֹדוּ לִשְׁמוֹ, וּמַלְכוּתוֹ בְרָצוֹן קִבְּלוּ עֲלֵיהֶם. מֹשֶׁה וּבְנֵי יִשְׂרָאֵל לְךָ עָנוּ שִׁירָה בְּשִׂמְחָה רַבָּה, וְאָֽמְרוּ כֻלָּם. מִֽי־כָמֹ֤כָה בָּֽאֵלִם֙ יְהֹוָ֔ה מִ֥י כָּמֹ֖כָה נֶאְדָּ֣ר בַּקֹּ֑דֶשׁ נוֹרָ֥א תְהִלֹּ֖ת עֹ֥שֵׂה פֶֽלֶא׃ מַלְכֽוּתְךָ יְהֹוָה אֱלֹהֵֽינוּ רָאוּ בָנֶֽיךָ עַל הַיָּם, יַֽחַד כֻּלָּם הוֹדוּ וְהִמְלִֽיכוּ וְאָמְרוּ. יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד׃ וְנֶֽאֱמַר. כִּֽי־פָדָ֥ה יְהֹוָ֖ה אֶֽת־יַעֲקֹ֑ב וּגְאָל֕וֹ מִיַּ֖ד חָזָ֥ק מִמֶּֽנּוּ׃ בָּרוּךְ אַתָּה יְהֹוָה, גָּאַל יִשְׂרָאֵל:"}, {"kind": "text", "text": "<b>הַשְׁכִּיבֵֽנוּ</b> אָבִֽינוּ לְשָׁלוֹם, וְהַֽעֲמִידֵֽנוּ מַלְכֵּֽנוּ לְחַיִּים טוֹבִים וּלְשָׁלוֹם. וּפְרוֹשׂ עָלֵֽינוּ סֻכַּת שְׁלוֹמֶֽךָ, וְתַקְּנֵֽנוּ מַלְכֵּֽנוּ בְּעֵצָה טוֹבָה מִלְּפָנֶֽיךָ, וְהוֹשִׁיעֵֽנוּ מְהֵרָה לְמַֽעַן שְׁמֶֽךָ. וְהָגֵן בַּֽעֲדֵֽנוּ, וְהָסֵר מֵעָלֵֽינוּ מַכַּת אוֹיֵב, דֶּֽבֶר, חֶֽרֶב, חֽוֹלִי, צָרָה, רָעָה, רָעָב, וְיָגוֹן, וּמַשְׁחִית, וּמַגֵּפָה. שְׁבוֹר וְהָסֵר הַשָּׂטָן מִלְּפָנֵֽינוּ וּמֵאַֽחֲרֵֽינוּ, וּבְצֵל כְּנָפֶֽיךָ תַּסְתִּירֵֽנוּ, וּשְׁמוֹר צֵאתֵֽנוּ וּבוֹאֵֽנוּ לְחַיִּים טוֹבִים וּלְשָׁלוֹם מֵעַתָּה וְעַד עוֹלָם. כִּי אֵל שֽׁוֹמְרֵֽנוּ וּמַצִּילֵֽנוּ אָֽתָּה מִכָּל־דָּבָר רָע וּמִפַּֽחַד לָֽיְלָה. בָּרוּךְ אַתָּה יְהֹוָה, שׁוֹמֵר אֶת־עַמּוֹ יִשְׂרָאֵל לָעַד אָמֵן:"}, {"kind": "instruction", "text": "ואומר החזן חצי קדיש"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "header", "text": "עמידה לשחרית מנחה וערבית שלש רגלים"}, {"kind": "text", "text": "<b>אֲ֭דֹנָי</b> שְׂפָתַ֣י תִּפְתָּ֑ח וּ֝פִ֗י יַגִּ֥יד תְּהִלָּתֶֽךָ׃"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵֽאלֹהֵי יַעֲקֹב. הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, קוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵּי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַֽעַן שְׁמוֹ בְּאַֽהֲבָה: מֶֽלֶךְ עוֹזֵר וּמוֹשִֽׁיעַ וּמָגֵן: בָּרוּךְ אַתָּה יַהַוַהַ, מָגֵן אַבְרָהָם:"}, {"kind": "text", "text": "<b>אַתָּה</b> גִבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֶּה מֵתִים אַתָּה, רַב לְהוֹשִֽׁיעַ."}, {"kind": "text", "text": "בקיץ: מוֹרִיד הַטָּל. בחורף: מַשִּׁיב הָרֽוּחַ וּמוֹרִיד הַגֶּֽשֶׁם."}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶֽסֶד, מְחַיֵּה מֵתִים בְּרַֽחֲמִים רַבִּים, סוֹמֵךְ נֽוֹפְלִים, וְרוֹפֵא חוֹלִים, וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמֽוּנָתוֹ לִֽישֵׁנֵי עָפָר. מִי כָמֽוֹךָ בַּֽעַל גְּבוּרוֹת, וּמִי דֽוֹמֶה לָךְ, מֶֽלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִֽיחַ יְשׁוּעָה. וְנֶֽאֱמָן אַתָּה לְהַֽחֲיוֹת מֵתִים: בָּרוּךְ אַתָּה יֵהֵוֵהֵ, מְחַיֵּה הַמֵּתִים:"}, {"kind": "instruction", "text": "קדושה<br>בחזרת הש\"ץ של שחרית ומנחה אומרים:"}, {"kind": "instruction", "text": "נַקְדִּישָׁךְ וְנַעֲרִיצָךְ, כְּנֹֽעַם שִֽׂיחַ סוֹד שַׂרְפֵי קֹֽדֶשׁ, הַמְשַׁלְּשִׁים לְךָ קְדֻשָּׁה, וְכֵן כָּתוּב עַל יַד נְבִיאָךְ: וְקָרָ֨א זֶ֤ה אֶל־זֶה֙ וְאָמַ֔ר קָד֧וֹשׁ ׀ קָד֛וֹשׁ קָד֖וֹשׁ יְהֹוָ֣ה צְבָא֑וֹת מְלֹ֥א כָל־הָאָ֖רֶץ כְּבוֹדֽוֹ׃ לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים: בָּר֥וּךְ כְּבוֹד־יְהֹוָ֖ה מִמְּקוֹמֽוֹ׃ וּבְדִבְרֵי קָדְשָׁךְ כָּתוּב לֵאמֹר: יִמְלֹ֤ךְ יְהֹוָ֨ה ׀ לְעוֹלָ֗ם אֱלֹהַ֣יִךְ צִ֭יּוֹן לְדֹ֥ר וָדֹ֗ר הַֽלְלוּיָֽהּ:"}, {"kind": "text", "text": "<b>אַתָּה</b> קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ, וּקְדוֹשִׁים בְּכָל־יוֹם יְהַֽלְלֽוּךָ סֶּֽלָה: בָּרוּךְ אַתָּה יֹהֵוָהֵ, הָאֵל הַקָּדוֹשׁ:"}, {"kind": "text", "text": "<b>אַתָּה</b> בְּחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ, וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת, וְקִדַּשְׁתָּנוּ בְּמִצְוֹתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ."}, {"kind": "instruction", "text": "במוצאי שבת אומרים"}, {"kind": "instruction", "text": "וַתּוֹדִיעֵנוּ מִשְׁפְּטֵי צִדְקֶךָ, וַתְּלַמְּדֵנוּ לַעֲשׂוֹת בָּהֶם חֻקֵּי רְצוֹנֶךָ, וַתִּתֶּן לָנוּ יְהֹוָה אֱלֹהֵינוּ בְּאַהֲבָה מִשְׁפָּטִים יְשָׁרִים וְתוֹרוֹת אֱמֶת, חֻקִּים וּמִצְוֹת טוֹבִים, וַתַּנְחִילֵנוּ זְמַנֵּי שָׂשׂוֹן וּמוֹעֲדֵי קֹדֶשׁ וְחַגֵּי נְדָבָה, וַתּוֹרִישֵׁנוּ קְדֻשַּׁת שַׁבָּת וּכְבוֹד מוֹעֵד וַחֲגִיגַת הָרֶגֶל. בֵּין קְדֻשַּׁת שַׁבָּת לִקְדֻשַּׁת יוֹם טוֹב הִבְדַּלְתָּ, וְאֶת יוֹם הַשְּׁבִיעִי מִשֵּׁשֶׁת יְמֵי הַמַּעֲשֶׂה הִקְדַּשְׁתָּ, וְהִבְדַּלְתָּ וְהִקְדַּשְׁתָּ אֶת עַמְּךָ יִשְׂרָאֵל בִּקְדֻשָּׁתָךְ:"}, {"kind": "text", "text": "וַתִּֽתֶּן לָֽנוּ יְהֹוָה אֱלֹהֵֽינוּ בְּאַהֲבָה"}, {"kind": "text", "text": "בשבת שַׁבָּתוֹת לִמְנוּחָה וּ"}, {"kind": "text", "text": "מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן, אֶת יוֹם"}, {"kind": "text", "text": "בשבת הַשַּׁבָּת הַזֶּה, וְאֶת יוֹם"}, {"kind": "text", "text": "בפסח: חַג הַמַּצּוֹת הַזֶּה, אֶת יוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה, זְמַן חֵרוּתֵנוּ:"}, {"kind": "text", "text": "בשבועות: חַג הַשָׁבוּעוֹת הַזֶּה, אֶת יוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה, זְמַן מַתַּן תּוֹרָתֵֽינוּ:"}, {"kind": "text", "text": "בסוכות: חַג הַסֻּכּוֹת הַזֶּה, אֶת יוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה, זְמַן שִׂמְחָתֵֽנוּ:"}, {"kind": "text", "text": "בש''ע: שְׁמִינִי חַג עֲצֶֽרֶת הַזֶּה, אֶת יוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה, זְמַן שִׂמְחָתֵֽנוּ:"}, {"kind": "text", "text": "בְּאַהֲבָה מִקְרָא קֹֽדֶשׁ זֵֽכֶר לִיצִיאַת מִצְרָֽיִם."}, {"kind": "text", "text": "<b>אֱלֹהֵֽינוּ</b> וֵאלֹהֵי אֲבוֹתֵֽינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּֽיעַ וְיֵרָאֶה, וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵֽנוּ וְזִכְרוֹן אֲבוֹתֵֽינוּ, זִכְרוֹן יְרוּשָׁלַֽיִם עִירָךְ, וְזִכְרוֹן מָשִֽׁיחַ בֶּן־דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל־עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶֽיךָ, לִפְלֵיטָה, לְטוֹבָה, לְחֵן, לְחֶֽסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם, בְּיוֹם"}, {"kind": "text", "text": "בשבת הַשַּׁבָּת הַזֶּה, וּבְיוֹם"}, {"kind": "text", "text": "בפסח: חַג הַמַּצּוֹת הַזֶּה,"}, {"kind": "text", "text": "בשבועות: חַג הַשָּׁבוּעוֹת הַזֶּה,"}, {"kind": "text", "text": "בסוכות: חַג הַסֻּכּוֹת הַזֶּה,"}, {"kind": "text", "text": "בש''ע: שְׁמִינִי חַג עֲצֶֽרֶת הַזֶּה,"}, {"kind": "text", "text": "בְּיוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה,לְרַחֵם בּוֹ עָלֵֽינוּ וּלְהוֹשִׁיעֵֽנוּ. זָכְרֵֽנוּ יְהֹוָה אֱלֹהֵֽינוּ בּוֹ לְטוֹבָה, וּפָקְדֵֽנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵֽנוּ בוֹ לְחַיִּים טוֹבִים, בִּדְבַר יְשׁוּעָה וְרַחֲמִים. חוּס וְחָנֵּֽנוּ, וַחֲמוֹל וְרַחֵם עָלֵֽינוּ, וְהוֹשִׁיעֵֽנוּ כִּי אֵלֶֽיךָ עֵינֵֽינוּ, כִּי אֵל מֶֽלֶךְ חַנּוּן וְרַחוּם אָֽתָּה:"}, {"kind": "text", "text": "<b>וְהַשִּׂיאֵנוּ</b> יְהֹוָה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ לְחַיִּים בְּשִׂמְחָה וּבְשָׁלוֹם, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ כֵּן תְּבָרְכֵנוּ סֶלָה."}, {"kind": "text", "text": "בשבת אומרים אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, רְצֵה נָא בִּמְנוּחָתֵנוּ,"}, {"kind": "text", "text": "<b>קַדְּשֵׁנוּ</b> בְּמִצְוֹתֶיךָ, שִׂים חֶלְקֵנוּ בְּתוֹרָתָךְ, שַׂבְּעֵנוּ מִטּוּבָךְ, שַׂמֵּחַ נַפְשֵׁנוּ בִּישׁוּעָתָךְ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶאֱמֶת, וְהַנְחִילֵנוּ יְהֹוָה אֱלֹהֵינוּ בשבת בְּאַהֲבָה וּבְרָצוֹן בְּשִׂמְחָה וּבְשָׂשׂוֹן בשבת שַׁבָּתוֹת וּ מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְּךָ כָּל יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יְהֹוָה, מְקַדֵּשׁ בשבת הַשַּׁבָּת וְיִשְׂרָאֵל וְהַזְּמַנִּים:"}, {"kind": "text", "text": "<b>רְצֵה</b> יְהֹוָה אֱלֹהֵֽינוּ בְּעַמְּךָ יִשְׂרָאֵל וְלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב הָֽעֲבוֹדָה לִדְבִיר בֵּיתֶֽךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, מְהֵרָה בְּאַֽהֲבָה תְקַבֵּל בְּרָצוֹן, וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּֽךָ: וְאַתָּה בְּרַֽחֲמֶֽיךָ הָרַבִּים, תַּחְפֹּץ בָּֽנוּ וְתִרְצֵֽנוּ, וְתֶֽחֱזֶֽינָה עֵינֵֽינוּ בְּשֽׁוּבְךָ לְצִיּוֹן בְּרַֽחֲמִים: בָּרוּךְ אַתָּה יִהִוִהִ, הַמַּֽחֲזִיר שְׁכִֽינָתוֹ לְצִיּוֹן:"}, {"kind": "instruction", "text": "בברכת \"מודים\" יכרע ב\"מודים\" ויזקוף בשם (בא\"ח בשלח הכ\"א)"}, {"kind": "text", "text": "<b>מוֹדִים</b> אֲנַֽחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ לְעוֹלָם וָעֶד, צוּרֵֽנוּ צוּר חַיֵּֽינוּ וּמָגֵן יִשְׁעֵֽנוּ אַתָּה הוּא, לְדוֹר וָדוֹר נוֹדֶה לְךָ וּנְסַפֵּר תְּהִלָּתֶֽךָ, עַל חַיֵּֽינוּ הַמְּסוּרִים בְּיָדֶֽךָ, וְעַל נִשְׁמוֹתֵֽינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּֽיךָ שֶׁבְּכָל־יוֹם עִמָּֽנוּ, וְעַל נִפְלְאוֹתֶֽיךָ וְטֽוֹבוֹתֶֽיךָ שֶׁבְּכָל־עֵת, עֶֽרֶב וָבֹֽקֶר וְצָֽהֳרָֽיִם. הַטּוֹב, כִּי לֹא כָלוּ רַחֲמֶֽיךָ, הַמְּרַחֵם, כִּי לֹא תַֽמּוּ חֲסָדֶֽיךָ, כִּי מֵֽעוֹלָם קִוִּֽינוּ לָךְ:"}, {"kind": "text", "text": "<b>מודים דרבנן</b><br>בחזרת הש\"ץ כשהחזן אומר מודים, הקהל אומרים:<br>מוֹדִים אֲנַחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׁר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית. בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְחָנֵּנוּ וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמֹר חֻקֶּיךָ וְלַעֲשׂוֹת רְצוֹנְךָ וּלְעָבְדְךָ בְלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ, בָּרוּךְ אֵל הַהוֹדָאוֹת."}, {"kind": "text", "text": "<b>וְעַל</b> כֻּלָּם יִתְבָּרַךְ, וְיִתְרוֹמָם, וְיִתְנַשֵּׂא, תָּמִיד, שִׁמְךָ מַלְכֵּֽנוּ, לְעוֹלָם וָעֶד. וְכָל־הַחַיִּים יוֹדֽוּךָ סֶּֽלָה: וִֽיהַֽלְלוּ וִֽיבָֽרְכוּ אֶת־שִׁמְךָ הַגָּדוֹל בֶּֽאֱמֶת לְעוֹלָם כִּי טוֹב, הָאֵל יְשֽׁוּעָתֵֽנוּ וְעֶזְרָתֵֽנוּ סֶֽלָה, הָאֵל הַטּוֹב: משתחוה בברוך וזוקף בשם בָּרוּךְ אַתָּה יֻהֻוֻהֻ, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת:"}, {"kind": "text", "text": "ברכת כהנים"}, {"kind": "text", "text": "כשעוקר הכהן רגליו לישא כפיו יאמר (בא\"ח תצוה י\"ב)<br>לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ. בִּדְחִֽילוּ וּרְחִֽימוּ. וּרְחִֽימוּ וּדְחִֽילוּ. לְיַחֲדָא שֵׁם יוֹ\"ד קֵ\"א בְּוָא\"ו קֵ\"א בְּיִחוּדָא שְׁלִים. בְּשֵׁם כָּל־יִשְׂרָאֵל הִנֵּה אָנֹכִי מוּכָן וּמְזוּמָן לְקַיֵּם מִצְוַת עֲשֵׂה לְבָרֵךְ אֶת יִשְׂרָאֵל בִּרְכַּת כֹּהַנִים בִּנְשִׂיאוּת כַּפַּיִם, לַעֲשׂוֹת נַֽחַת רֽוּחַ לְיֽוֹצְרֵֽנוּ וּלְהַמְשִׁיךְ שֶׁפַע וּבְרָכָה לְכָל־הָעוֹלָמוֹת וְלַעֲשׂוֹת רְצוֹן בּֽוֹרְאֵֽנוּ. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ:"}, {"kind": "text", "text": "וכשעומדים הכהנים על הדוכן לאחר שענו \"מודים דרבנן\", אומרים<br>יְהִי רָצוֹן מִלְּפָנֶֽיךָ יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ שֶׁתִּהְיֶה בְּרָכָה זוֹ שֶׁצִּּוִיתָֽנוּ לְבָרֵךְ אֶת־עַמְּךָ יִשְׂרָאֵל בְּרָכָה שְׁלֵמָה וְלֹא יִהְיֶה בָהּ מִכְשׁוֹל וְעָוֹן מֵעַתָּה וְעַד עוֹלָם:"}, {"kind": "text", "text": "בחזרת הש\"ץ אומרים ברכת כהנים, אם יש יותר מכהן אחד קורא להם החזן: כֹּהֲנִים: הכהנים מברכים:<br>בָּרוּךְ אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָֽעוֹלָם, אֲשֶׁר קִדְּשָֽׁנוּ בִּקְדֻשָּׁתוֹ שֶׁל־אַֽהֲרֹן, וְצִוָּֽנוּ לְבָרֵךְ אֶת־עַמּוֹ יִשְׂרָאֵל בְּאַֽהֲבָה: הקהל עונים אָמֵן:"}, {"kind": "instruction", "text": "ואומר החזן והכהנים אחריו מילה במילה:"}, {"kind": "text", "text": "יְבָרֶכְךָ֥ יְהֹוָ֖ה וְיִשְׁמְרֶֽךָ׃ ועונים אָמֵן:"}, {"kind": "text", "text": "יָאֵ֨ר יְהֹוָ֧ה ׀ פָּנָ֛יו אֵלֶ֖יךָ וִֽיחֻנֶּֽךָּ׃ ועונים אָמֵן:"}, {"kind": "text", "text": "יִשָּׂ֨א יְהֹוָ֤ה ׀ פָּנָיו֙ אֵלֶ֔יךָ וְיָשֵׂ֥ם לְךָ֖ שָׁלֽוֹם׃ ועונים אָמֵן:"}, {"kind": "instruction", "text": "וכשמתחיל שליח ציבור \"שים שלום\" אז מחזירין פניהם כלפי ההיכל, ולא יחזירו פניהם קודם, ואז הכהנים אומרים<br>רִבּוֹן הָעוֹלָמִים עָשִֽׂינוּ מַה־שֶּׁגָּזַֽרְתָּ עָלֵֽינוּ, עַשֵׂה אַתָּה מַה־שֶּׁהִבְטָחְתָּֽנוּ. הַשְׁקִ֩יפָה֩ מִמְּע֨וֹן קׇדְשְׁךָ֜ מִן־הַשָּׁמַ֗יִם וּבָרֵ֤ךְ אֶֽת־עַמְּךָ֙ אֶת־יִשְׂרָאֵ֔ל:"}, {"kind": "instruction", "text": "אם אין עולים כהנים אומר החזן:<br>אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶת בַּתּוֹרָה הַכְּתוּבָה עַל יְדֵי מֹשֶׁה עַבְדֶּֽךָ, הָאֲמוּרָה מִפִּי אַהֲרֹן וּבָנָיו הַכֹּהֲנִים עַם קְדוֹשֶׁיךָ כָּאָמוּר:"}, {"kind": "text", "text": "יְבָרֶכְךָ֥ יְהֹוָ֖ה וְיִשְׁמְרֶֽךָ׃ ועונים כֵּן יְהִי רָצוֹן:"}, {"kind": "text", "text": "יָאֵ֨ר יְהֹוָ֧ה ׀ פָּנָ֛יו אֵלֶ֖יךָ וִֽיחֻנֶּֽךָּ׃ ועונים כֵּן יְהִי רָצוֹן:"}, {"kind": "text", "text": "יִשָּׂ֨א יְהֹוָ֤ה ׀ פָּנָיו֙ אֵלֶ֔יךָ וְיָשֵׂ֥ם לְךָ֖ שָׁלֽוֹם׃ ועונים כֵּן יְהִי רָצוֹן: וְשָׂמ֥וּ אֶת־שְׁמִ֖י עַל־בְּנֵ֣י יִשְׂרָאֵ֑ל וַאֲנִ֖י אֲבָרְכֵֽם:"}, {"kind": "text", "text": "<b>שִׂים</b> שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים חֵן וָחֶֽסֶד וְרַֽחֲמִים, עָלֵֽינוּ וְעַל כָּל־יִשְׂרָאֵל עַמֶּֽךָ. וּבָֽרְכֵֽנוּ אָבִֽינוּ כֻּלָּֽנוּ כְּאֶחָד בְּאוֹר פָּנֶֽיךָ, כִּי בְאוֹר פָּנֶֽיךָ נָתַֽתָּ לָּֽנוּ יְהֹוָה אֱלֹהֵֽינוּ תּוֹרָה וְחַיִּים, אַֽהֲבָה וָחֶֽסֶד, צְדָקָה וְרַֽחֲמִים, בְּרָכָה וְשָׁלוֹם. וְטוֹב בְּעֵינֶֽיךָ לְבָֽרְכֵֽנוּ וּלְבָרֵךְ אֶת־כָּל־עַמְּךָ יִשְׂרָאֵל, בְּרֹב עֹז וְשָׁלוֹם: בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמְּבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם. אָמֵן:"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>אֱלֹהַי</b>, נְצֹר לְשׁוֹנִי מֵרָע וְשִׂפְתוֹתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּֽעָפָר לַכֹּל תִּֽהְיֶה, פְּתַח לִבִּי בְּתוֹרָתֶֽךָ, וְאַחֲרֵי מִצְוֹתֶֽיךָ תִּרְדֹּף נַפְשִׁי. וְכָל־הַקָּמִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחְשְׁבוֹתָם. יִֽהְי֗וּ כְּמֹ֥ץ לִפְנֵי־ר֑וּחַ וּמַלְאַ֖ךְ יְהֹוָ֣ה דּוֹחֶֽה. קַבֵּל רִנַּת עַמֶּךָ. שַׂגְּבֵנוּ טַהֲרֵנוּ נוֹרָא. עֲשֵׂה לְמַֽעַן שְׁמָךְ, עֲשֵׂה לְמַֽעַן יְמִינָךְ, עֲשֵׂה לְמַֽעַן תּֽוֹרָתָךְ, עֲשֵׂה לְמַֽעַן קְדֻשָּׁתָךְ."}, {"kind": "text", "text": "סגולה לומר פסוק המתחיל וגומר באות שמתחיל וגומר שמו לְ֭מַעַן יֵחָלְצ֣וּן יְדִידֶ֑יךָ הוֹשִׁ֖יעָה יְמִֽינְךָ֣ וַעֲנֵֽנִי:"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>עֹשֶׂה</b> שָׁלוֹם בִּמְרוֹמָיו, הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵֽינוּ, וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן:"}, {"kind": "instruction", "text": "יְהִי רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְּיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ, לַעֲשׂוֹת חֻקֵּי רְצוֹנָךְ וּלְעָבְדָךְ בְּלֵבָב שָׁלֵם:"}, {"kind": "instruction", "text": "אחרי החזרה אומרים"}, {"kind": "text", "text": "<b>יְהִ֤י</b> שֵׁ֣ם יְהֹוָ֣ה מְבֹרָ֑ךְ מֵ֝עַתָּ֗ה וְעַד־עוֹלָֽם׃ מִמִּזְרַח־שֶׁ֥מֶשׁ עַד־מְבוֹא֑וֹ מְ֝הֻלָּ֗ל שֵׁ֣ם יְהֹוָֽה׃ רָ֖ם עַל־כׇּל־גּוֹיִ֥ם ׀ יְהֹוָ֑ה עַ֖ל הַשָּׁמַ֣יִם כְּבוֹדֽוֹ׃ יְהֹוָ֥ה אֲדֹנֵ֑ינוּ מָה־אַדִּ֥יר שִׁ֝מְךָ֗ בְּכׇל־הָאָֽרֶץ׃"}, {"kind": "instruction", "text": "בערבית ליל יום טוב, אחרי תפילת העמידה, אם חל בשבת אומרים ויכולו, והחזן אומר ברכת מעין שבע וקדיש תתקבל. ואם חל בחול אומרים יהי שם, והחזן אומר קדיש תתקבל. ובליל יום טוב ראשון של פסח, אחרי העמידה גומרים את ההלל בברכה תחילה וסוף, ואחר כך החזן אומר קדיש תתקבל, ואם חל בשבת אומרים ויכולו ומעין שבע, ויברכו על ההלל."}, {"kind": "text", "text": "אחרי קדיש תתקבל אומרים מזמורים אלו:"}, {"kind": "instruction", "text": "אם חל בשבת מוסיפים מזמור זה"}, {"kind": "text", "text": "<b>מִזְמ֥וֹר</b> (תהילים כ״ג) לְדָוִ֑ד יְהֹוָ֥ה רֹ֝עִ֗י לֹ֣א אֶחְסָֽר׃ בִּנְא֣וֹת דֶּ֭שֶׁא יַרְבִּיצֵ֑נִי עַל מֵ֖י מְנֻח֣וֹת יְנַהֲלֵֽנִי׃ נַפְשִׁ֥י יְשׁוֹבֵ֑ב יַֽנְחֵ֥נִי בְמַעְגְּלֵי־צֶ֝֗דֶק לְמַ֣עַן שְׁמֽוֹ׃ גַּ֤ם כִּֽי־אֵלֵ֨ךְ בְּגֵ֪יא צַלְמָ֡וֶת לֹא־אִ֘ירָ֤א רָ֗ע כִּי־אַתָּ֥ה עִמָּדִ֑י שִׁבְטְךָ֥ וּ֝מִשְׁעַנְתֶּ֗ךָ הֵ֣מָּה יְנַֽחֲמֻֽנִי׃ תַּעֲרֹ֬ךְ לְפָנַ֨י ׀ שֻׁלְחָ֗ן נֶ֥גֶד צֹרְרָ֑י דִּשַּׁ֥נְתָּ בַשֶּׁ֥מֶן רֹ֝אשִׁ֗י כּוֹסִ֥י רְוָיָֽה אַ֤ךְ ׀ ט֤וֹב וָחֶ֣סֶד יִ֭רְדְּפוּנִי כׇּל־יְמֵ֣י חַיָּ֑י וְשַׁבְתִּ֥י בְּבֵית־יְ֝הֹוָ֗ה לְאֹ֣רֶךְ יָמִֽים׃"}, {"kind": "instruction", "text": "בפסח אומרים"}, {"kind": "text", "text": "<b>בְּצֵ֣את</b> (תהילים קי״ד) יִ֭שְׂרָאֵל מִמִּצְרָ֑יִם בֵּ֥ית יַ֝עֲקֹ֗ב מֵעַ֥ם לֹעֵֽז׃ הָיְתָ֣ה יְהוּדָ֣ה לְקׇדְשׁ֑וֹ יִ֝שְׂרָאֵ֗ל מַמְשְׁלוֹתָֽיו׃ הַיָּ֣ם רָ֭אָה וַיָּנֹ֑ס הַ֝יַּרְדֵּ֗ן יִסֹּ֥ב לְאָחֽוֹר׃ הֶ֭הָרִים רָקְד֣וּ כְאֵילִ֑ים גְּ֝בָע֗וֹת כִּבְנֵי־צֹֽאן׃ מַה־לְּךָ֣ הַ֭יָּם כִּ֣י תָנ֑וּס הַ֝יַּרְדֵּ֗ן תִּסֹּ֥ב לְאָחֽוֹר׃ הֶ֭הָרִים תִּרְקְד֣וּ כְאֵילִ֑ים גְּ֝בָע֗וֹת כִּבְנֵי־צֹֽאן׃ מִלִּפְנֵ֣י אָ֭דוֹן ח֣וּלִי אָ֑רֶץ מִ֝לִּפְנֵ֗י אֱל֣וֹהַּ יַעֲקֹֽב׃ הַהֹפְכִ֣י הַצּ֣וּר אֲגַם־מָ֑יִם חַ֝לָּמִ֗ישׁ לְמַעְיְנוֹ־מָֽיִם׃"}, {"kind": "instruction", "text": "בשבועות, סוכות, ושמיני עצרת אומרים"}, {"kind": "text", "text": "<b>שִׁ֥יר</b> (תהילים קכ״ב) הַֽמַּעֲל֗וֹת לְדָ֫וִ֥ד שָׂ֭מַחְתִּי בְּאֹמְרִ֣ים לִ֑י בֵּ֖ית יְהֹוָ֣ה נֵלֵֽךְ׃ עֹ֭מְדוֹת הָי֣וּ רַגְלֵ֑ינוּ בִּ֝שְׁעָרַ֗יִךְ יְרוּשָׁלָֽ‍ִם׃ יְרוּשָׁלַ֥‍ִם הַבְּנוּיָ֑ה כְּ֝עִ֗יר שֶׁחֻבְּרָה־לָּ֥הּ יַחְדָּֽו׃ שֶׁשָּׁ֨ם עָל֪וּ שְׁבָטִ֡ים שִׁבְטֵי־יָ֭הּ עֵד֣וּת לְיִשְׂרָאֵ֑ל לְ֝הֹד֗וֹת לְשֵׁ֣ם יְהֹוָֽה׃ כִּ֤י שָׁ֨מָּה ׀ יָשְׁב֣וּ כִסְא֣וֹת לְמִשְׁפָּ֑ט כִּ֝סְא֗וֹת לְבֵ֣ית דָּוִֽד׃ שַׁ֭אֲלוּ שְׁל֣וֹם יְרוּשָׁלָ֑‍ִם יִ֝שְׁלָ֗יוּ אֹהֲבָֽיִךְ׃ יְהִי־שָׁל֥וֹם בְּחֵילֵ֑ךְ שַׁ֝לְוָ֗ה בְּאַרְמְנוֹתָֽיִךְ׃ לְ֭מַעַן אַחַ֣י וְרֵעָ֑י אֲדַבְּרָה־נָּ֖א שָׁל֣וֹם בָּֽךְ׃ לְ֭מַעַן בֵּית־יְהֹוָ֣ה אֱלֹהֵ֑ינוּ אֲבַקְשָׁ֖ה ט֣וֹב לָֽךְ׃"}, {"kind": "instruction", "text": "ואומרים קדיש יהא שלמא"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>יְהֵא</b> שְׁלָמָא רַבָּא מִן שְׁמַיָּא. חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה. וְשֵׁיזָבָא וּרְפוּאָה וּגְאוּלָה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]<br><br><b>עוֹשֶׂה</b> שָׁלוֹם בִּמְרוֹמָיו. הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>עָלֵֽינוּ</b> לְשַׁבֵּֽחַ לַֽאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָֽׂנוּ כְּגוֹיֵי הָֽאֲרָצוֹת, וְלֹא שָׂמָֽנוּ כְּמִשְׁפְּחוֹת הָֽאֲדָמָה, שֶׁלֹּא שָׂם חֶלְקֵֽנוּ כָּהֶם וְגוֹרָלֵֽנוּ כְּכָל־הֲמוֹנָם, שֶׁהֵם מִשְׁתַּֽחֲוִים לָהֶֽבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל־אֵל לֹֽא יוֹשִׁיעַ. וַֽאֲנַֽחְנוּ מִשְׁתַּחֲוִים לִפְנֵי מֶֽלֶךְ מַלְכֵי הַֽמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַֽיִם וְיוֹסֵד אָֽרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַֽיִם מִמַּֽעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵֽינוּ, וְאֵין עוֹד אַחֵר, אֱמֶת מַלְכֵּֽנוּ וְאֶֽפֶס זוּלָתוֹ. כַּכָּתוּב בַּתּוֹרָה. וְיָדַעְתָּ֣ הַיּ֗וֹם וַהֲשֵׁבֹתָ֮ אֶל־לְבָבֶךָ֒ כִּ֤י יְהֹוָה֙ ה֣וּא הָֽאֱלֹהִ֔ים בַּשָּׁמַ֣יִם מִמַּ֔עַל וְעַל־הָאָ֖רֶץ מִתָּ֑חַת אֵ֖ין עֽוֹד:"}, {"kind": "text", "text": "<b>עַל</b> כֵּן נְקַוֶּה לָךְ, יְהֹוָה אֱלֹהֵֽינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶֽרֶת עֻזָּךְ, לְהַֽעֲבִיר גִּלּוּלִים מִן הָאָֽרֶץ, וְהָֽאֱלִילִים כָּרוֹת יִכָּֽרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל־בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶֽךָ, לְהַפְנוֹת אֵלֶֽיךָ כָּל־רִשְׁעֵי אָֽרֶץ. יַכִּֽירוּ וְיֵֽדְעוּ כָּל־יֽוֹשְׁבֵי תֵבֵֽל, כִּי לְךָ תִכְרַע כָּל־בֶּֽרֶךְ, תִּשָּׁבַע כָּל־לָשׁוֹן. לְפָנֶֽיךָ, יְהֹוָה אֱלֹהֵֽינוּ יִכְרְעוּ וְיִפֹּֽלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּֽנוּ, וִיקַבְּלוּ כֻלָּם אֶת־עֹל מַלְכוּתֶֽךָ, וְתִמְלוֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעֽוֹלְמֵי עַד תִּמְלוֹךְ בְּכָבוֹד. כַּכָּתוּב בְּתוֹרָתָךְ: יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד׃ וְנֶאֱמַר. וְהָיָ֧ה יְהֹוָ֛ה לְמֶ֖לֶךְ עַל־כָּל־הָאָ֑רֶץ בַּיּ֣וֹם הַה֗וּא יִהְיֶ֧ה יְהֹוָ֛ה אֶחָ֖ד וּשְׁמ֥וֹ אֶחָֽד׃"}, {"kind": "instruction", "text": "וּבְתוֹרָתְךָ יְהֹוָה אֱלֹהֵינוּ כָּתוּב לֵּאמֹר. שְׁמַ֖ע יִשְׂרָאֵ֑ל יְהֹוָ֥ה אֱלֹהֵ֖ינוּ יְהֹוָ֥ה ׀ אֶחָֽד׃"}], "shacharit": [{"kind": "header", "text": "סדר השכמת הבוקר"}, {"kind": "header", "text": "מודה אני"}, {"kind": "instruction", "text": "כשיעור משנתו יאמר"}, {"kind": "text", "text": "<b>מוֹדֶה</b> האשה אומרת: מוֹדָה אֲנִי לְפָנֶיךָ מֶלֶךְ חַי וְקַיָּם שֶהֶחֱזַרְתָּ בִּי נִשְׁמָתִי בְחֶמְלָה, רַבָּה אֱמוּנָתֶךָ:"}, {"kind": "header", "text": "ברכות השחר"}, {"kind": "instruction", "text": "יעשה צרכיו תחלה, ואחר כך יברך על נטילת ידים ואשר יצר (בא\"ח ויצא ה\"ב). אחר שנטל ידיו תכף ומיד תזקיף ידיו ואצבעותיו למעלה ותגביהם עד הראש, ולפחות תגביהם עד כנגד הפנים, ותברך על נטילת ידים, (בא\"ח תולדות ה\"ד) ואם היה ער כל הלילה לא יברך אלא יטול בלא ברכה (שם הי\"ג)"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוֹתָיו וְצִוָּנוּ עַל נְטִילַת יָדָיִם:"}, {"kind": "instruction", "text": "אם הטיל מים או עשה צרכיו יברך תוך חצי שעה (בא\"ח ויצא הי\"ב)"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אֲשֶׁר יָצַר אֶת הָאָדָם בְּחָכְמָה, וּבָרָא בוֹ נְקָבִים נְקָבִים, חֲלוּלִים חֲלוּלִים, גָּלוּי וְיָדוּעַ לִפְנֵי כִסֵּא כְבוֹדֶךָ, שֶׁאִם יִסָּתֵם אֶחָד מֵהֶם, אוֹ אִם יִפָּתֵח אֶחָד מֵהֶם, אֵי אֶפְשָׁר לְהִתְקַיֵּם אַפִלּוּ שָׁעָה אֶחָת. בָּרוּךְ אַתָּה יְהֹוָה, רוֹפֵא כָל־בָּשָׂר וּמַפְלִיא לַעֲשׂוֹת:"}, {"kind": "instruction", "text": "יסמוך ברכה זו של אלהי וכו' לברכת אשר יצר (בא\"ח וישב ה\"ב)"}, {"kind": "text", "text": "<b>אֱלֹהַי</b>, נְשָׁמָה שֶׁנָּתַתָּ בִּי טְהוֹרָה, אַתָּה בְרָאתָהּ, אַתָּה יְצַרְתָּהּ, אַתָּה נְפַחְתָּהּ בִּי, וְאַתָּה מְשַׁמְּרָהּ בְּקִרְבִּי, וְאַתָּה עָתִיד לִטְּלָהּ מִמֶּנִּי, וּלְהַחֲזִירָהּ בִּי לֶעָתִיד לָבוֹא, כָּל־זְמַן שֶׁהַנְּשָׁמָה בְקִרְבִּי, מוֹדֶה (האשה אומרת מוֹדָה) אֲנִי לְפָנֶיךָ יְהֹוָה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, רִבּוֹן כָּל־הַמַּעֲשִׂים אֲדוֹן כָּל־הַנְּשָׁמוֹת. בָּרוּךְ אַתָּה יְהֹוָה, הַמַּחֲזִיר נְשָׁמוֹת לִפְגָרִים מֵתִים:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, הַנוֹתֵן לַשֶּׂכְוִי בִינָה, לְהַבְחִין בֵּין יוֹם וּבֵין לָיְלָה:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, פּוֹקֵחַ עִוְרִים:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, מַתִּיר אֲסוּרִים:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, זוֹקֵף כְּפוּפִים:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, מַלְבִּישׁ עֲרֻמִּים:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, הַנּוֹתֵן לַיָּעֵף כֹּחַ:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, רוֹקַע הָאָרֶץ עַל הַמָּיִם:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, הַמֵּכִין מִצְעֲדֵי גָבֶר:"}, {"kind": "instruction", "text": "בתשעה באב ויום הכיפורים אין אומרים ברכה זו (בא\"ח וישב ה\"ט)"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, שֶׁעָשָׂה לִי כָּל־צָרְכִּי:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אוֹזֵר יִשְׂרָאֵל בִּגְבוּרָה:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, עוֹטֵר יִשְׂרָאֵל בְּתִפְאָרָה:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, שֶׁלֹּא עָשַׂנִי גוֹי: האשה אומרת: <b>גּוֹיָה</b>"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, שֶׁלֹּא עָשַׂנִי עָבֶד: האשה אומרת: <b>שִׁפְחָה</b>"}, {"kind": "instruction", "text": "האיש מברך"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, שֶׁלֹּא עָשַׂנִי אִשָּׁה:"}, {"kind": "instruction", "text": "האשה מברכת בלי שם ומלכות"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> שֶׁעָשַׂנִי כִּרְצוֹנוֹ:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, הַמַּעֲבִיר חֶבְלֵי שֵׁנָה מֵעֵינָי וּתְנוּמָה מֵעַפְעַפָּי. וִיהִי רָצוֹן מִלְפָנֶיךָ יְהֹוָה, אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתַרְגִּילֵנִי בְּתוֹרָתֶךָ, וְתַדְבִּיקֵנִי בְּמִצְוֹתֶיךָ, וְאַל תְּבִיאֵנִי לִידֵי חֵטְא, וְלֹא לִידֵי עָוֹן, וְלֹא לִידֵי נִסָיוֹן, וְלֹא לִידֵי בִזָּיוֹן, וְתַרְחִיקֵנִי מִיֵּצֶר הָרָע, וְתַדְבִּיקֵנִי בְּיֵצֶר הַטּוֹב, וְכוֹף אֶת־יִצְרִי לְהִשְׁתַּעְבֶּד לָּךְ, וּתְנֵנִי הַיּוֹם וּבְכָל־יוֹם לְחֵן וּלְחֶסֶד וּלְרַחֲמִים בְּעֵינֶיךָ וּבְעֵינֵי כָל־רוֹאַי, וְגָמְלֵנִי חֲסָדִים טוֹבִים. בָּרוּךְ אַתָּה יְהֹוָה, גּוֹמֵל חֲסָדִים טוֹבִים לְעַמּוֹ יִשְׂרָאֵל:"}, {"kind": "text", "text": "<b>יְהִי</b> רָצוֹן מִלְּפָנֶיךָ יְהֹוָה, אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתַּצִּילֵנִי הַיּוֹם וּבְכָל יוֹם וָיוֹם, מֵעַזֵּי פָנִים, וּמֵעַזּוּת פָּנִים, מֵאָדָם רָע, מִיֵּצֶר רָע, מֵחָבֵר רָע, מִשָּׁכֵן רָע, מִפֶּגַע רָע, מֵעַיִן הָרָע, וּמִלָּשׁוֹן הָרָע, מִדִּין קָשֶׁה, וּמִבַּעַל דִּין קָשֶׁה, בֵּין שֶׁהוּא בֶן־בְּרִית, וּבֵין שֶׁאֵינוֹ בֶן־בְּרִית:"}, {"kind": "header", "text": "ברכות התורה"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוֹתָיו וְצִוָּנוּ עַל דִּבְרֵי תוֹרָה:"}, {"kind": "text", "text": "<b>וְהַעֲרֵב</b> נָא, יְהֹוָה אֱלֹהֵֽינוּ, אֶת־דִּבְרֵי תוֹרָתְךָ בְּפִינוּ וּבְפִיפִיּוֹת עַמְּךָ בֵּית יִשְׂרָאֵל, וְנִהְיֶה אֲנַחְנוּ וְצֶאֱצָאֵינוּ, וְצֶאֱצָאֵי צֶאֱצָאֵינוּ, כֻּלָּנוּ יוֹדְעֵי שְׁמֶךָ, וְלוֹמְדֵי תוֹרָתְךָ לִשְׁמָהּ. בָּרוּךְ אַתָּה יְהֹוָה, הַמְלַמֵּד תּוֹרָה לְעַמּוֹ יִשְׂרָאֵל:"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אֲשֶׁר בָּחַר בָּנוּ מִכָּל־הָעַמִּים וְנָתַן לָנוּ אֶת־תּוֹרָתוֹ. בָּרוּךְ אַתָּה יְהֹוָה נוֹתֵן הַתּוֹרָה:"}, {"kind": "text", "text": "<b>וַיְדַבֵּ֥ר</b> יְהֹוָ֖ה אֶל־מֹשֶׁ֥ה לֵּאמֹֽר׃ דַּבֵּ֤ר אֶֽל־אַהֲרֹן֙ וְאֶל־בָּנָ֣יו לֵאמֹ֔ר כֹּ֥ה תְבָרְכ֖וּ אֶת־בְּנֵ֣י יִשְׂרָאֵ֑ל אָמ֖וֹר לָהֶֽם׃ יְבָרֶכְךָ֥ יְהֹוָ֖ה וְיִשְׁמְרֶֽךָ׃ יָאֵ֨ר יְהֹוָ֧ה ׀ פָּנָ֛יו אֵלֶ֖יךָ וִֽיחֻנֶּֽךָּ׃ יִשָּׂ֨א יְהֹוָ֤ה ׀ פָּנָיו֙ אֵלֶ֔יךָ וְיָשֵׂ֥ם לְךָ֖ שָׁלֽוֹם׃ וְשָׂמ֥וּ אֶת־שְׁמִ֖י עַל־בְּנֵ֣י יִשְׂרָאֵ֑ל וַאֲנִ֖י אֲבָרְכֵֽם׃"}, {"kind": "header", "text": "תפילת שחרית לימי החול"}, {"kind": "header", "text": "פתיחת אליהו"}, {"kind": "instruction", "text": "אחר המזמורים של תיקון לאה המנהג לומר פתיחת אליהו (בא\"ח וישלח הי\"ב)"}, {"kind": "text", "text": "וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ׃"}, {"kind": "text", "text": "<b>פָּתַח אֵלִיָּֽהוּ</b> הַנָּבִיא זָכוּר לְטוֹב וְאָמַר: רִבּוֹן עָֽלְמִֽין דְּאַנְתְּ הוּא חָד וְלָא בְּחֻשְׁבָּן. אַנְתְּ הוּא עִלָּאָה עַל־כָּל־עִלָּאִין סְתִימָא עַל־כָּל־סְתִימִין. לֵית מַחֲשָׁבָה תְּפִיסָא בָךְ כְּלָל: אַנְתְּ הוּא דְאַפַּקְתְּ עֶֽשֶׂר תִּקּוּנִין וְקָרֵינָן לוֹן עֶֽשֶׂר סְפִירָן. לְאַנְהָגָא בְהוֹן עָֽלְמִֽין סְתִימִין דְּלָא אִתְגַּלְיָן וְעָֽלְמִֽין דְּאִתְגַּלְיָן. וּבְהוֹן אִתְכַּסִּיאַת מִבְּנֵי נָשָׁא. וְאַנְתְּ הוּא דְּקָשִׁיר לוֹן וּמְיַחֵד לוֹן: וּבְגִין דְּאַנְתְּ מִלְּגָאו. כָּל־מָאן דְּאַפְרִישׁ חַד מִן חַבְרֵיהּ מֵאִלֵּין עֶֽשֶׂר אִתְחַשִּׁיב לֵיהּ כְּאִלּוּ אַפְרִישׁ בָּֽךְ:"}, {"kind": "text", "text": "וְאִלֵּין עֶֽשֶׂר סְפִירָן אִנּוּן אָֽזְלִֽין כְּסִדְרָן. חַד אָרִיךְ וְחַד קָצֵר וְחַד בֵּינוֹנִי: וְאַנְתְּ הוּא דְּאַנְהִיג לוֹן. וְלֵית מָאן דְּאַנְהִיג לָךְ. לָא לְעֵֽלָּא וְלָא לְתַֽתָּא וְלָא מִכָּל־סִטְרָא. לְבוּשִׁין תַּקַּנְתְּ לוֹן דְּמִנַּֽיְהוּ פָֽרְחִֽין נִשְׁמָתִין לִבְנֵי נָשָׁא: וְכַמָּה גוּפִין תַּקַּנְתְּ לוֹן דְּאִתְקְרִֽיאוּ גוּפָא לְגַבֵּי לְבוּשִׁין דִּמְכַסְיָן עֲלֵיהוֹן: וְאִתְקְרִֽיאוּ בְּתִקּוּנָא דָא. חֶֽסֶד דְּרוֹעָא יְמִינָא. גְּבוּרָה דְּרוֹעָא שְׂמָאלָא. תִּפְאֶֽרֶת גּוּפָא. נֶֽצַח וְהוֹד תְּרֵין שׁוֹקִין. יְסוֹד סִיּוּמָא דְגוּפָא אוֹת בְּרִית קֽוֹדֶשׁ. מַלְכוּת פֶּה תּוֹרָה שֶׁבְּעַל־פֶּה קָרֵֽינָן לָהּ. חָכְמָה מוֹחָא אִֽיהִי מַחֲשָׁבָה מִלְּגָאו. בִּינָה לִבָּא וּבָהּ הַלֵּב מֵבִין. וְעַל אִלֵּין תְּרֵין כְּתִיב הַנִּ֨סְתָּרֹ֔ת לַיהֹוָ֖ה אֱלֹהֵ֑ינוּ. כֶּֽתֶר עֶלְיוֹן אִֽיהוּ כֶּֽתֶר מַלְכוּת. וְעָלֵיהּ אִתְמַר מַגִּיד מֵרֵאשִׁית אַחֲרִית. וְאִֽיהוּ קַרְקַפְתָּא דִתְפִלֵּי: מִלְּגָאו אִֽיהוּ [אוֹת] יוֹ\"ד [וְאוֹת] הֵ\"א [וְאוֹת] וָא\"ו [וְאוֹת] הֵ\"א דְּאִֽיהוּ אֹֽרַח אֲצִילוּת. אִֽיהוּ שַׁקְיוּ דְאִילָנָא בִּדְרוֹעוֹי וְעַנְפּוֹי. כְּמַיָּא דְאַשְׁקֵי לְאִילָנָא וְאִתְרַבֵּי בְּהַהוּא שַׁקְיוּ:"}, {"kind": "text", "text": "<b>רִבּוֹן</b> עָֽלְמִֽין אַנְתְּ הוּא עִלַּת הָעִלּוֹת וְסִבַּת הַסִּבּוֹת דְּאַשְׁקֵי לְאִילָנָא בְּהַהוּא נְבִיעוּ. וְהַהוּא נְבִיעוּ אִֽיהוּ כְּנִשְׁמְתָא לְגוּפָא דְּאִֽיהִי חַיִּים לְגוּפָא: וּבָךְ לֵית דִּמְיוֹן וְלֵית דִּיּוּקְנָא (דְּגוּפָא) מִכָּל־מַה־דִּלְגַאו וּלְבַר. וּבָרָֽאתָ שְׁמַיָּא וְאַרְעָא. וְאַפַּקְתְּ מִנְּהוֹן שִׁמְשָׁא וְסִיהֲרָא וְכוֹכְבַיָּא וּמַזָּלֵי. וּבְאַרְעָא אִילָנִין וּדְשָׁאִין וְגִנְּתָא דְעֵֽדֶן וְעִשְׂבִּין וְחֵיוָן וְעוֹפִין וְנוּנִין וּבְעִירִין וּבְנֵי נָשָׁא. לְאִשְׁתְּמֽוֹדְעָֽא בְהוֹן עִלָּאִין וְאֵיךְ יִתְנַהֲגוּן בְּהוֹן עִלָּאִין וְתַתָּאִין. וְאֵיךְ אִשְׁתְּמֽוֹדְעָֽן מֵעִלָּאֵי וְתַתָּאֵי וְלֵית דְּיָדַע בָּךְ כְּלָל. וּבַר מִנָּךְ לֵית יִחוּדָא בְּעִלָּאֵי וְתַתָּאֵי. וְאַנְתְּ אִשְׁתְּמוֹדָע אָדוֹן עַל־כֹּֽלָּא: וְכָל־סְפִירָן כָּל־חַד אִית לֵיהּ שֵׁם יְדִֽיעַ. וּבְהוֹן אִתְקְרִֽיאוּ מַלְאָכַיָּא. וְאַנְתְּ לֵית לָךְ שֵׁם יְדִֽיעַ. דְּאַנְתְּ הוּא מְמַלֵּא כָּל־שְׁמָהָן וְאַנְתְּ הוּא שְׁלִֽימוּ דְּכֻלְּהוּ: וְכַד אַנְתְּ תִּסְתַּלָּק מִנְּהוֹן. אִשְׁתְּאָֽרוּ כֻּלְּהוּ שְׁמָהָן כְּגוּפָא בְלָא נִשְׁמָתָא: אַנְתְּ הוּא חַכִּים וְלָאו בְּחָכְמָה יְדִיעָא. אַנְתְּ הוּא מֵבִין וְלָאו מִבִּינָה יְדִיעָא. לֵית לָךְ אֲתָר יְדִיעָא. אֶלָּא לְאִשְׁתְּמֽוֹדְעָא תֻּקְפָךְ וְחֵילָךְ לִבְנֵי נָשָׁא. וּלְאַחְזָאָה לוֹן אֵיךְ אִתְנְהִיג עָֽלְמָא בְּדִינָא וּבְרַחֲמֵי דְּאִנּוּן צֶֽדֶק וּמִשְׁפָּט כְּפוּם עוֹבָדֵיהוֹן דִּבְנֵי נָשָׁא: דִּין אִֽיהוּ גְבוּרָה. מִשְׁפָּט עַמּוּדָא דְאֶמְצָעִיתָא. צֶֽדֶק מַלְכוּתָא קַדִּישָׁא. מֹֽאזְנֵֽי צֶֽדֶק תְּרֵין סַמְכֵי קְשׁוֹט. הִין צֶֽדֶק אוֹת בְּרִית. כֹּלָּא לְאַחְזָאָה אֵיךְ אִתְנְהִיג עָֽלְמָא: אֲבָל לָאו דְּאִית לָךְ צֶֽדֶק יְדִיעָא דְּאִֽיהוּ דִין. וְלָאו מִשְׁפָּט יְדִיעָא דְאִֽיהוּ רַחֲמֵי. וְלָאו מִכָּל־אִלֵּין מִדּוֹת כְּלָל: קוּם רִבִּי שִׁמְעוֹן וְיִתְחַדְּשׁוּן מִלִּין עַל יְדָךְ, דְּהָא רְשׁוּתָא אִית לָךְ לְגַלָּאָה רָזִין טְמִירִין עַל יְדָךְ, מַה דְּלָא אִתְיְהִב רְשׁוּ לְגַלָּאָה לָשׂוּם בַּר־נָשׁ עַד כְּעָן:"}, {"kind": "text", "text": "<b>קָם</b> רַבִּי שִׁמְעוֹן פָּתַח וְאָמַר, לְךָ֣ יְ֠הֹוָ֠ה הַגְּדֻלָּ֨ה וְהַגְּבוּרָ֤ה וְהַתִּפְאֶ֙רֶת֙ וְהַנֵּ֣צַח וְהַה֔וֹד כִּי־כֹ֖ל בַּשָּׁמַ֣יִם וּבָאָ֑רֶץ לְךָ֤ יְהֹוָה֙ הַמַּמְלָכָ֔ה וְהַמִּתְנַשֵּׂ֖א לְכֹ֥ל ׀ לְרֹֽאשׁ, עִלָּאִין שִׁמְעוּ אִינוּן דְמִיכִין דְּחֶבְרוֹן, וְרַעְיָא מְהֵימְנָא אִתְּעָרוּ מִשְּׁנַתְכוֹן, הָקִיצוּ וְרַנְּנוּ שׁוֹכְנֵי עָפָר, אִלֵּין אִינוּן צַדִּיקַיָּא דְּאִינוּן מִסִּטְרָא דְּהַהִיא דְּאִתְמַר בָּהּ אֲנִ֥י יְשֵׁנָ֖ה וְלִבִּ֣י עֵ֑ר, וְלָאו אִינוּן מֵתִים, וּבְגִין דָּא אִתְמַר בְּהוֹן הָקִיצוּ וְרַנְּנוּ וְכוּ', רַעְיָא מְהֵימְנָא, אַנְתְּ וַאֲבָהָן הָקִיצוּ וְרַנְּנוּ לְאִתְּעָרוּתָא דִּשְׁכִינְתָּא, דְּאִיהִי יְשֵׁנָהּ בְּגָלוּתָא, דְּעַד כְּעַן צַדִּיקַיָּא כֻּלְּהוּ דְמִיכִין וְשִׁנְתָּא בְּחוֹרֵיהוֹן: מִיַּד יְהִיבַת שְׁכִינְתָּא תְּלָת קָלִין לְגַבֵּי רַעְיָא מְהֵימְנָא, וְיֵימָא לֵיהּ קוּם רַעְיָא מְהֵימְנָא, דְּהָא עֲלָךְ אִתְמַר ק֣וֹל ׀ דּוֹדִ֣י דוֹפֵ֗ק לְגַבָּאי בְּאַרְבַּע אַתְוָן דִּילֵיהּ, וְיֵימָא בְּהוֹן, פִּתְחִי־לִ֞י אֲחֹתִ֤י רַעְיָתִי֙ יוֹנָתִ֣י תַמָּתִ֔י, דְּהָא תַּם־עֲוֺנֵךְ֙ בַּת־צִיּ֔וֹן, לֹ֥א יוֹסִ֖יף לְהַגְלוֹתֵ֑ךְ: שֶׁרֹּאשִׁי֙ נִמְלָא־טָ֔ל, מַאי נִמְלָא טָל, אֶלָּא אָמַר קוּדְשָׁא בְּרִיךְ הוּא, אַנְתְּ חָשַׁבְתְּ דְּמִיּוֹמָא דְאִתְחָרַב בֵּי מַקְדְּשָׁא דְּעָֽאלְנָא בְּבֵיתָא דִילִי, וְעָֽאלְנָא בְיִשּׁוּבָא, לָאו הָכִי, דְּלָא עָֽאלְנָא כָּל זִמְנָא דְּאַנְתְּ בְּגָלוּתָא, הֲרֵי לְךָ סִימָנָא, שֶׁרֹּאשִׁי֙ נִמְלָא־טָ֔ל, הֵ\"א שְׁכִינְתָּא בְּגָלוּתָא, שְׁלִימוּ דִילָהּ וְחַיִּים דִילָהּ אִיהוּ טַ\"ל, וְדָא אִיהוּ [אוֹת] יוֹ\"ד [וְאוֹת] הֵ\"א [וְאוֹת] וָא\"ו, וְהֵ\"א אִיהִי שְׁכִינְתָּא דְּלָא מֵחֻשְׁבָּן טָ\"ל, אֶלָּא [אוֹת] יוֹ\"ד [וְאוֹת] הֵ\"א [וְאוֹת] וָא\"ו, דִּסְלִיקוּ אַתְוָן לְחֻשְׁבָּן טָ\"ל, דְּאִיהִי מַלְיָא לִשְׁכִינְתָּא מִנְּבִיעוּ דְכָל־מְקוֹרִין עִלָּאִין, מִיַּד קָם רַעְיָא מְהֵימְנָא, וַאֲבָהָן קַדִּישִׁין עִמֵּיהּ, עַד כָּאן רָזָא דְיִחוּדָא. בָּר֖וּךְ יְהֹוָ֥ה לְ֝עוֹלָ֗ם אָ֘מֵ֥ן ׀ וְאָמֵֽן:"}, {"kind": "instruction", "text": "יְהֵא רַעֲוָא מִן קֳדָם עַתִּיקָא קַדִּישָׁא דְכָל־קַדִּישִׁין. טְמִירָא דְּכָל־טְמִירִין סְתִימָא דְכֹֽלָּא דְּיִתְמְשָׁךְ טַלָּא עִלָּאָה מִנֵּיהּ לְמַלְיָא רֵישֵׁיהּ דִזְעֵיר אַנְפִּין וּלְהַטִּיל לַחֲקַל תַּפּוּחִין קַדִּישִׁין בִּנְהִֽירוּ דְּאַנְפִּין בְּרַעֲוָא וּבְחֶדְוָתָא דְכֹֽלָּא. וְיִתְמְשָָׁךְ מִן קֳדָם עַתִּיקָא קַדִּישָׁא דְכָל־קַדִּישִׁין טְמִירָא דְכָל־טְמִירִין סְתִימָא דְכֹֽלָא רְעוּתָא וְרַחֲמֵי חִנָּא וְחִסְדָּא בִּנְהִֽירוּ עִלָּאָה בִּרְעוּתָא וְחֶדְוָא עָלַי וְעַל־כָּל־בְּנֵי בֵֽיתִי וְעַל־כָּל־הַנִּלְוִים אֵלַי וְעַל־כָּל־יִשְׂרָאֵל עַמֵּיהּ. וְיִפְרְקִינָן מִכָּל־עַקְתִין בִּישִׁין דְּיֵיתוּן לְעָֽלְמָא וְיַזְמִין וְיִתְיְהִיב לָֽנָא וּלְכָל־נַפְשָׁתָֽנָא חִנָּא וְחִסְדָּא וְחַיֵּי אֲרִיכֵי וּמְזוֹנֵי רְוִיחֵי וְרַחֲמֵי מִן קֳדָמֵיהּ. אָמֵן כֵּן יְהִי רָצוֹן אָמֵן וְאָמֵן:"}, {"kind": "instruction", "text": "אחר פתיחת אליהו זכור לטוב יאמרו מאמר רבי שמעון בר יוחאי הכתוב בזוהר הקדוש פרשת נח דף ס״ה ופקודי דף רס״ה: (בא״ח וישלח י״ב)"}, {"kind": "text", "text": "<b>אָמַר</b> רִבִּי שִׁמְעוֹן: אֲרִימִית יְדָאי בִּצְלוֹתִין לְעֵֽלָא, דְּכַד רְעוּתָא עִלָּאָה לְעֵֽלָא לְעֵֽלָא קַיְמָא עַל הַהוּא רְעוּתָא דְּלָא אִתְיְדַע וְלָא אִתְפַס כְּלָל לְעָֽלְמִֽין, רֵישָׁא דְסָתִים יַתִּיר לְעֵֽלָא, וְהַהוּא רֵישָׁא אַפִּיק מָאי דְּאַפִּיק וְלָא יְדִֽיעַ, וְנָהִיר מָאי דְּנָהִיר כֹּֽלָּא בִּסְתִֽימוּ, רְעוּ דְּמַחֲשָׁבָה עִלָּאָה לְמִרְדַּף אֲבַּתְרֵיהּ וּלְאִתְנַהֲרָא מִנֵּיהּ. חָד פְּרִֽיסוּ אִתְפְּרִיס, וּמִגּוֹ הַהוּא פְרִיסָא בִּרְדִיפוּ דְּהַהִיא מַחֲשָׁבָה עִלָּאָה מָטֵי וְלָא מָטֵי, עַד הַהוּא פְרִיסָא נָהִיר מָאי דְּנָהִיר, וּכְדֵין הַהוּא מַחֲשָׁבָה עִלָּאָה נָהִיר בִּנְהִירוּ סָתִים דְּלָא יְדִֽיעַ, וְהַהוּא מַחֲשָׁבָה לָא יָדַע, כְּדֵין בָּטַשׁ הַאי נְהִֽירוּ דְמַחֲשָׁבָה דְּלָא אִתְיְדַע בִּנְהִֽירוּ דְפַרְסָא דְּקָיְמָא דְּנָהִיר מִמָּה דְלָא יְדִֽיעַ וְלָא אִתְיְדַע וְלָא אִתְגַּלְיָא, וּכְדֵין דָּא נְהִֽירוּ דְמַחֲשָׁבָה דְּלָא אִתְיְדַע בָּטַשׁ בִּנְהִֽירוּ דִפְרִסָא וְנַהֲרִין כַּחֲדָא, וְאִתְעֲבִֽידוּ תִּשְׁעָה הֵיכָלִין. וְהֵיכָלִין לָאו אִנּוּן נְהוֹרִין, וְלָאו אִנּוּן רוּחִין, וְלָאו אִנּוּן נִשְׁמָתִין, וְלָא אִית מָאן דְּקַיְמָא בְהוּ. רְעוּתָא דְכָל־תִּשְׁעָה נְהוֹרִין דְּקַיְמֵי כֻלְּהוּ בְּמַחֲשָׁבָה, דְּאִֽיהוּ חָד מִנַּֽיְהוּ בְּחוּשְׁבָּנָא, כֻלְּהוּ לְמִרְדַּף בַּתְרַֽיְהוּ, בְּשַׁעְתָּא דְקַיְמֵי בְמַחֲשָׁבָה וְלָא מִתְדַּבְּקָן וְלָא אִתְיְדָֽעוּ, וְאִלֵּין לָא קַיְמֵי לָא בִרְעוּתָא וְלָא בְמַחֲשָׁבָה עִלָּאָה תַּפְסִין בָּהּ וְלָא תַּפְסִין, בְּאִלֵּין קַיְמֵי כָּל־רָזֵי דִמְהֵימְנוּתָא. וְכָל־אִנּוּן נְהוֹרִין מֵרָזָא דְמַחֲשָׁבָה עִלָּאָה וּלְתַתָּא, כֻּלְּהוּ אִקְּרוּן אֵין סוֹף. עַד הָכָא מָטוּ נְהוֹרִין, וְלָא מָטוּן וְלָא אִתְיְדָֽעוּ, לָאו הָכָא רְעוּתָא וְלָא מַחֲשָׁבָה כַּד נָהִיר מַחֲשָׁבָה וְלָא אִתְיְדַע מִמָּאן דְּנָהִיר, כְּדֵין אִתְלַבַּשׁ וְאַסְתִּים גּוֹ בִינָה, וְנָהִיר לְמָאן דְּנָהִיר, וְאָעִיל דָּא בְדָא, עַד דְּאִתְכְּלִֽילוּ כֻּלְּהוּ כַּחֲדָא. וּבְרָזָא דְקָרְבָּנָא כַּד סָלִיק, כֹּלָּא אִתְקְשַׁר דָּא בְדָא, וְנָהִיר דָּא בְדָא, כְּדֵין קַיְמֵי כֻלְּהוּ בִּסְלִֽיקוּ וּמַחֲשָׁבָה אִתְעַטָּר בְּאֵין סוֹף. הַהוּא נְהִֽירוּ דְּאִתְנְהִיר מִנֵּיהּ מַחֲשָׁבָה עִלָּאָה (דְּלָא אִתְיְדַע בָּהּ כְּלָל) אִקְּרֵי אֵין סוֹף, דְּמִנֵּיהּ אִשְׁתַּכַּח וְקַיְמָא וְנָהִיר לְמָאן דְּנָהִיר, וְעַל דָּא כֹּֽלָּא קָאִים. זַכָּאָה חוּלָקֵיהוֹן דְּצַדִּיקַיָא בְּעָֽלְמָא דֵין וּבְעָֽלְמָא דְאָתֵי:"}, {"kind": "header", "text": "סדר עטיפת ציצית"}, {"kind": "text", "text": "<b>לְשֵׁם</b> יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם יוֹ\"ד קֵ\"י בְּוָא\"ו קֵ\"י בְּיִחוּדָא שְׁלִים (יהוה) בְּשֵׁם כָּל־יִשְׂרָאֵל. הֲרֵינִי מוּכָן לְקַיֵּם מִצְוַת עֲשֵׂה לִלְבֹּשׁ טַלִּית מְצֻיֶּצֶת כְּהִלְכָתָהּ, כְּמוֹ שֶׁצִּוָּנוּ יְהֹוָה אֱלֹהֵֽינוּ בְּתוֹרָתוֹ הַקְּדוֹשָׁה: (במדבר טו לח) וְעָשׂ֨וּ לָהֶ֥ם צִיצִ֛ת עַל־כַּנְפֵ֥י בִגְדֵיהֶ֖ם. כְדֵי שֶׁנִּזְכֹּר כָּל־מִצְוֹתָיו לַעֲשׂוֹתָם שֶׁנֶּאֱמַר (במדבר טו לט) וּרְאִיתֶ֣ם אֹת֗וֹ וּזְכַרְתֶּם֙ אֶת־כׇּל־מִצְוֺ֣ת יְהֹוָ֔ה וַעֲשִׂיתֶ֖ם אֹתָ֑ם. וַהֲרֵינִי מוּכָן לְבָרֵךְ עַל עֲטִיפַת הַטָּלִית כְּתִקּוּן רַבּוֹתֵינוּ זִכְרוֹנָם לִבְרָכָה. וַהֲרֵינִי מְכַוֵּן לִפְטֹר בִּבְרָכָה זוֹ גַּם טַלִּית הַקָּטָן שֶׁעָלַי. כְּדֵי לַעֲשׂוֹת נַֽחַת רֽוּחַ לְיֽוֹצְרֵֽנוּ וְלַעֲשׂוֹת רְצוֹן בּֽוֹרְאֵֽנוּ. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ׃"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוֹתָיו וְצִוָּנוּ לְהִתְעַטֵּף בְּצִיצִית:"}, {"kind": "header", "text": "סדר הנחת תפילין"}, {"kind": "text", "text": "<b>לְשֵׁם</b> יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם יוֹ\"ד קֵ\"י בְּוָא\"ו קֵ\"י בְּיִחוּדָא שְׁלִים (יהוה) בְּשֵׁם כָּל־יִשְׂרָאֵל. הֲרֵינִי מוּכָן לְקַיֵּם מִצְוַת עֲשֵׂה לְהָנִיחַ תְּפִלִּין בְּיָדִי וּבְרֹאשִׁי, כְּמוֹ שֶׁצִּוָּנוּ יְהֹוָה אֱלֹהֵֽינוּ: (דברים יא יח) וּקְשַׁרְתֶּ֨ם אֹתָ֤ם לְאוֹת֙ עַל־יֶדְכֶ֔ם וְהָי֥וּ לְטוֹטָפֹ֖ת בֵּ֥ין עֵינֵיכֶֽם. וְצִוָּנוּ הַקָּדוֹשׁ בָּרוּךְ הוּא לְהָנִיחַ אַרְבַּע פַּרְשִׁיּוֹת אֵלּוּ שֶׁיֵּשׁ בָּהֶם יִחוּד שְׁמוֹ וִיצִיאַת מִצְרַיִם עַל הַזְּרוֹעַ כְּנֶגֶד הַלֵּב, וְעַל הָרֹאשׁ כְּנֶגֶד הַמֹּחַ, כְּדֵי שֶׁנִּזְכֹּר נִסִּים וְנִפְלָאוֹת שֶׁעָשָׂה עִמָּנוּ. וַהֲרֵינִי מוּכָן לְבָרֵךְ הַבְּרָכָה שֶׁתִּקְנוּ רַבּוֹתֵינוּ זִכְרוֹנָם לִבְרָכָה עַל מִצְוַת הַתְּפִלִּין, וַהֲרֵינִי מְכַוֵּן לִפְטֹר בִּבְרָכָה זוֹ תְּפִלִּין שֶׁל יָד וּתְפִלִּין שֶׁל רֹאשׁ, וְיַעֲלֶה לְפָנֶיךָ יְהֹוָה אֱלֹהֵֽינוּ וֵאלהֵי אֲבוֹתֵינוּ כְּאִלּוּ כִּוַּנְתִּי בְּכָל הַכַּוָּנוֹת הָרְאוּיוֹת לְכַוֵּן בַּהֲנָחַת הַתְּפִלִּין וּבַבְּרָכָה. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ׃"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוֹתָיו, וְצִוָּנוּ לְהָנִיחַ תְּפִלִּין:<br><br>אם הפסיק בין תפלין של יד לתפלין של ראש בדבר דחשיב הפסק, אז יברך על תפלין של ראש (בא\"ח וירא ו')<br><b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָֽׁנוּ בְּמִצְוֹתָיו, וְצִוָּנוּ עַל מִצְוַת תְּפִלִּין:"}, {"kind": "text", "text": "אחר שהניח תפלין של ראש, אז תכף ומיד יגמור הנחת תפלין של יד בשלש כריכות שכורך באצבע האמצעי הנקרא אמה, ויעשה כריכה אחת בפרק האמצעי של האצבע ושתי כריכות בפרק התחתון, ויאמר בעת שעושה הכריכות הנזכרות (בא\"ח וירא ט\"ז)<br>וְאֵרַשְׂתִּ֥יךְ לִ֖י לְעוֹלָ֑ם וְאֵרַשְׂתִּ֥יךְ לִי֙ בְּצֶ֣דֶק וּבְמִשְׁפָּ֔ט וּבְחֶ֖סֶד וּֽבְרַחֲמִֽים׃ וְאֵרַשְׂתִּ֥יךְ לִ֖י בֶּאֱמוּנָ֑ה וְיָדַ֖עַתְּ אֶת־יְהֹוָֽה׃"}, {"kind": "text", "text": "אחר שיניח התפילין יאמר פרשת קדש ווהיה כי יביאך כדי להשלים ארבעת פרשיות בכל יום ואם אינו יכול לאומרם קודם תפלה יאמר אותם אחר תפלה (בא\"ח וירא כ\"ה)<br><b>וַיְדַבֵּ֥ר</b> יְהֹוָ֖ה אֶל־מֹשֶׁ֥ה לֵּאמֹֽר׃ קַדֶּשׁ־לִ֨י כׇל־בְּכ֜וֹר פֶּ֤טֶר כׇּל־רֶ֙חֶם֙ בִּבְנֵ֣י יִשְׂרָאֵ֔ל בָּאָדָ֖ם וּבַבְּהֵמָ֑ה לִ֖י הֽוּא׃ וַיֹּ֨אמֶר מֹשֶׁ֜ה אֶל־הָעָ֗ם זָכ֞וֹר אֶת־הַיּ֤וֹם הַזֶּה֙ אֲשֶׁ֨ר יְצָאתֶ֤ם מִמִּצְרַ֙יִם֙ מִבֵּ֣ית עֲבָדִ֔ים כִּ֚י בְּחֹ֣זֶק יָ֔ד הוֹצִ֧יא יְהֹוָ֛ה אֶתְכֶ֖ם מִזֶּ֑ה וְלֹ֥א יֵאָכֵ֖ל חָמֵֽץ׃ הַיּ֖וֹם אַתֶּ֣ם יֹצְאִ֑ים בְּחֹ֖דֶשׁ הָאָבִֽיב׃ וְהָיָ֣ה כִֽי־יְבִיאֲךָ֣ יְהֹוָ֡ה אֶל־אֶ֣רֶץ הַֽ֠כְּנַעֲנִ֠י וְהַחִתִּ֨י וְהָאֱמֹרִ֜י וְהַחִוִּ֣י וְהַיְבוּסִ֗י אֲשֶׁ֨ר נִשְׁבַּ֤ע לַאֲבֹתֶ֙יךָ֙ לָ֣תֶת לָ֔ךְ אֶ֛רֶץ זָבַ֥ת חָלָ֖ב וּדְבָ֑שׁ וְעָבַדְתָּ֛ אֶת־הָעֲבֹדָ֥ה הַזֹּ֖את בַּחֹ֥דֶשׁ הַזֶּֽה׃ שִׁבְעַ֥ת יָמִ֖ים תֹּאכַ֣ל מַצֹּ֑ת וּבַיּוֹם֙ הַשְּׁבִיעִ֔י חַ֖ג לַיהֹוָֽה׃ מַצּוֹת֙ יֵֽאָכֵ֔ל אֵ֖ת שִׁבְעַ֣ת הַיָּמִ֑ים וְלֹֽא־יֵרָאֶ֨ה לְךָ֜ חָמֵ֗ץ וְלֹֽא־יֵרָאֶ֥ה לְךָ֛ שְׂאֹ֖ר בְּכׇל־גְּבֻלֶֽךָ׃ וְהִגַּדְתָּ֣ לְבִנְךָ֔ בַּיּ֥וֹם הַה֖וּא לֵאמֹ֑ר בַּעֲב֣וּר זֶ֗ה עָשָׂ֤ה יְהֹוָה֙ לִ֔י בְּצֵאתִ֖י מִמִּצְרָֽיִם׃ וְהָיָה֩ לְךָ֨ לְא֜וֹת עַל־יָדְךָ֗ וּלְזִכָּרוֹן֙ בֵּ֣ין עֵינֶ֔יךָ לְמַ֗עַן תִּהְיֶ֛ה תּוֹרַ֥ת יְהֹוָ֖ה בְּפִ֑יךָ כִּ֚י בְּיָ֣ד חֲזָקָ֔ה הוֹצִֽאֲךָ֥ יְהֹוָ֖ה מִמִּצְרָֽיִם׃ וְשָׁמַרְתָּ֛ אֶת־הַחֻקָּ֥ה הַזֹּ֖את לְמוֹעֲדָ֑הּ מִיָּמִ֖ים יָמִֽימָה׃"}, {"kind": "text", "text": "<b>וְהָיָ֞ה</b> כִּֽי־יְבִאֲךָ֤ יְהֹוָה֙ אֶל־אֶ֣רֶץ הַֽכְּנַעֲנִ֔י כַּאֲשֶׁ֛ר נִשְׁבַּ֥ע לְךָ֖ וְלַֽאֲבֹתֶ֑יךָ וּנְתָנָ֖הּ לָֽךְ׃ וְהַעֲבַרְתָּ֥ כׇל־פֶּֽטֶר־רֶ֖חֶם לַֽיהֹוָ֑ה וְכׇל־פֶּ֣טֶר ׀ שֶׁ֣גֶר בְּהֵמָ֗ה אֲשֶׁ֨ר יִהְיֶ֥ה לְךָ֛ הַזְּכָרִ֖ים לַיהֹוָֽה׃ וְכׇל־פֶּ֤טֶר חֲמֹר֙ תִּפְדֶּ֣ה בְשֶׂ֔ה וְאִם־לֹ֥א תִפְדֶּ֖ה וַעֲרַפְתּ֑וֹ וְכֹ֨ל בְּכ֥וֹר אָדָ֛ם בְּבָנֶ֖יךָ תִּפְדֶּֽה׃ וְהָיָ֞ה כִּֽי־יִשְׁאׇלְךָ֥ בִנְךָ֛ מָחָ֖ר לֵאמֹ֣ר מַה־זֹּ֑את וְאָמַרְתָּ֣ אֵלָ֔יו בְּחֹ֣זֶק יָ֗ד הוֹצִיאָ֧נוּ יְהֹוָ֛ה מִמִּצְרַ֖יִם מִבֵּ֥ית עֲבָדִֽים׃ וַיְהִ֗י כִּֽי־הִקְשָׁ֣ה פַרְעֹה֮ לְשַׁלְּחֵ֒נוּ֒ וַיַּהֲרֹ֨ג יְהֹוָ֤ה כׇּל־בְּכוֹר֙ בְּאֶ֣רֶץ מִצְרַ֔יִם מִבְּכֹ֥ר אָדָ֖ם וְעַד־בְּכ֣וֹר בְּהֵמָ֑ה עַל־כֵּן֩ אֲנִ֨י זֹבֵ֜חַ לַֽיהֹוָ֗ה כׇּל־פֶּ֤טֶר רֶ֙חֶם֙ הַזְּכָרִ֔ים וְכׇל־בְּכ֥וֹר בָּנַ֖י אֶפְדֶּֽה׃ וְהָיָ֤ה לְאוֹת֙ עַל־יָ֣דְכָ֔ה וּלְטוֹטָפֹ֖ת בֵּ֣ין עֵינֶ֑יךָ כִּ֚י בְּחֹ֣זֶק יָ֔ד הוֹצִיאָ֥נוּ יְהֹוָ֖ה מִמִּצְרָֽיִם׃"}, {"kind": "header", "text": "תפילת חנה"}, {"kind": "text", "text": "<b>וַתִּתְפַּלֵּ֤ל</b> חַנָּה֙ וַתֹּאמַ֔ר עָלַ֤ץ לִבִּי֙ בַּֽיהֹוָ֔ה רָ֥מָה קַרְנִ֖י בַּֽיהֹוָ֑ה רָ֤חַב פִּי֙ עַל־א֣וֹיְבַ֔י כִּ֥י שָׂמַ֖חְתִּי בִּישׁוּעָתֶֽךָ׃ אֵין־קָד֥וֹשׁ כַּיהֹוָ֖ה כִּ֣י אֵ֣ין בִּלְתֶּ֑ךָ וְאֵ֥ין צ֖וּר כֵּאלֹהֵֽינוּ׃ אַל־תַּרְבּ֤וּ תְדַבְּרוּ֙ גְּבֹהָ֣ה גְבֹהָ֔ה יֵצֵ֥א עָתָ֖ק מִפִּיכֶ֑ם כִּ֣י אֵ֤ל דֵּעוֹת֙ יְהֹוָ֔ה ולא [וְל֥וֹ] נִתְכְּנ֖וּ עֲלִלֽוֹת׃ קֶ֥שֶׁת גִּבֹּרִ֖ים חַתִּ֑ים וְנִכְשָׁלִ֖ים אָ֥זְרוּ חָֽיִל׃ שְׂבֵעִ֤ים בַּלֶּ֙חֶם֙ נִשְׂכָּ֔רוּ וּרְעֵבִ֖ים חָדֵ֑לּוּ עַד־עֲקָרָה֙ יָלְדָ֣ה שִׁבְעָ֔ה וְרַבַּ֥ת בָּנִ֖ים אֻמְלָֽלָה׃ יְהֹוָ֖ה מֵמִ֣ית וּמְחַיֶּ֑ה מוֹרִ֥יד שְׁא֖וֹל וַיָּֽעַל׃ יְהֹוָ֖ה מוֹרִ֣ישׁ וּמַעֲשִׁ֑יר מַשְׁפִּ֖יל אַף־מְרוֹמֵֽם׃ מֵקִ֨ים מֵעָפָ֜ר דָּ֗ל מֵֽאַשְׁפֹּת֙ יָרִ֣ים אֶבְי֔וֹן לְהוֹשִׁיב֙ עִם־נְדִיבִ֔ים וְכִסֵּ֥א כָב֖וֹד יַנְחִלֵ֑ם כִּ֤י לַֽיהֹוָה֙ מְצֻ֣קֵי אֶ֔רֶץ וַיָּ֥שֶׁת עֲלֵיהֶ֖ם תֵּבֵֽל׃ רַגְלֵ֤י חֲסִידָו֙ יִשְׁמֹ֔ר וּרְשָׁעִ֖ים בַּחֹ֣שֶׁךְ יִדָּ֑מּוּ כִּי־לֹ֥א בְכֹ֖חַ יִגְבַּר־אִֽישׁ׃ יְהֹוָ֞ה יֵחַ֣תּוּ מְרִיבָ֗ו עָלָו֙ בַּשָּׁמַ֣יִם יַרְעֵ֔ם יְהֹוָ֖ה יָדִ֣ין אַפְסֵי־אָ֑רֶץ וְיִתֶּן־עֹ֣ז לְמַלְכּ֔וֹ וְיָרֵ֖ם קֶ֥רֶן מְשִׁיחֽוֹ׃ אָת֙וֹהִי֙ כְּמָ֣ה רַבְרְבִ֔ין וְתִמְה֖וֹהִי כְּמָ֣ה תַקִּיפִ֑ין מַלְכוּתֵהּ֙ מַלְכ֣וּת עָלַ֔ם וְשׇׁלְטָנֵ֖הּ עִם־דָּ֥ר וְדָֽר: וַאֲנַ֤חְנוּ עַמְּךָ֨ ׀ וְצֹ֥אן מַרְעִיתֶךָ֮ נ֤וֹדֶ֥ה לְּךָ֗ לְע֫וֹלָ֥ם לְד֥וֹר וָדֹ֑ר נְ֝סַפֵּ֗ר תְּהִלָּתֶֽךָ: עֶ֤רֶב וָבֹ֣קֶר וְ֭צׇהֳרַיִם אָשִׂ֣יחָה וְאֶֽהֱמֶ֑ה וַיִּשְׁמַ֥ע קוֹלִֽי: בְּרׇן־יַ֭חַד כּ֣וֹכְבֵי בֹ֑קֶר וַ֝יָּרִ֗יעוּ כׇּל־בְּנֵ֥י אֱלֹהִֽים: לֹֽא־אִ֭ירָא מֵרִבְב֥וֹת עָ֑ם אֲשֶׁ֥ר סָ֝בִ֗יב שָׁ֣תוּ עָלָֽי: וַֽאֲנִי֙ בַּיהֹוָ֣ה אֲצַפֶּ֔ה אוֹחִ֖ילָה לֵאלֹהֵ֣י יִשְׁעִ֑י יִשְׁמָעֵ֖נִי אֱלֹהָֽי: בשבת ויום טוב אין אומרים פסוק זה אַֽל־תִּשְׂמְחִ֤י אֹיַ֙בְתִּי֙ לִ֔י כִּ֥י נָפַ֖לְתִּי קָ֑מְתִּי כִּֽי־אֵשֵׁ֣ב בַּחֹ֔שֶׁךְ יְהֹוָ֖ה א֥וֹר לִֽי: כִּֽי־לְךָ֣ יְהֹוָ֣ה הוֹחָ֑לְתִּי אַתָּ֥ה תַ֝עֲנֶ֗ה אֲדֹנָ֥י אֱלֹהָֽי: רַ֭גְלִי עָמְדָ֣ה בְמִישׁ֑וֹר בְּ֝מַקְהֵלִ֗ים אֲבָרֵ֥ךְ יְהֹוָֽה:"}, {"kind": "header", "text": "תפילת שחרית"}, {"kind": "text", "text": "יזהר כל אדם לומר קודם פרשת העקידה נוסח זה, ובזה הנוסח שאומר האדם בכל יום קודם תפלה יהיה מוצל מלטותא דרבי שמעון בר יוחאי דלייט באדרא רבא דף קמ\"א עמוד ב (ח\"ג קמא, ב), וה' לא ימנע טוב להולכים בתמים (בא\"ח מקץ י\"ב)<br><b>רִבּוֹן</b> עָֽלְמָא יְהֵא רַעֲוָא קַמָּךְ לְמֵיהַב לָן חֵילָא לְאִתְעֲרָא בִּיקָרָךְ, וּלְמֶעְבַּד רְעוּתָךְ, וּלְסַדְּרָא כֹֽלָּא כִּדְקָא יָאוּת. וְאַף עַל גַּב דְּלֵית אֲנַן יָֽדְעִֽין לְשַׁוְּאָה רְעוּתָא וְלִבָּא לְתַקְּנָא כֹֽלָּא, יְהֵא רַעֲוָא קַמָּךְ דְּתִתְרְעֵי בְמִלִּין וּצְלוֹתָא דִּילָן, לְתַקָּנָא תִּקּוּנָא דִלְעֵֽלָּא כִּדְקָא יָאוּת, וְלֶהֱווּ הֵיכָלִין עִלָּאִין, וְרוּחִין עִלָּאִין עַיְלֵי הֵיכָלָא בְּהֵיכָלָא, וְרוּחָא בְּרוּחָא, עַד דְּמִתְחַבְּרָן בְּדוּכְתַּיְהוּ כִּדְקָא חָזֵי, שַׁיְפָא בְשַׁיְפָא, וְאִשְׁתְּלִימוּ דָּא בְדָא, וְאִתְיַחֲדוּ דָּא בְדָא עַד אִנּוּן חָד, וְנַהֲרִין דָּא בְדָא, וּכְדֵין נִשְׁמְתָא עִלָּאָה דְכֹלָּא אַתְיָא מִלְּעֵלָּא וְנָהִיר לוֹן, וְלֶהֱווּ נְהִירִין כֻּלְּהוּ בוֹצִינִין בִּשְׁלִימוּ כִּדְקָא חָזֵי, עַד דְּהַהוּא נְהוֹרָא עִלָּאָה אִתְּעַר, וְכֹלָּא אָעִיל לְגַבֵּי קֹדֶשׁ קָדָשִׁים, וְאִתְבָּרְכָא וְאִתְמַלְיָא כְּבֵירָא דְמַיִּין נָבְעִין וְלָא פָסְקִין, וְכֻלְּהוּ מִתְבָּרְכָן לְעֵלָּא וְתַתָּא, וְהַהוּא דְלָּא אִתְיְדַע וְלָא אָעִיל בְּחוּשְׁבָּנָא רְעוּתָא דְלָא אִתְּפַס לְעָלְמִין בָּסִים לְגוֹ לְגוֹ בְּגַוָּיְהוּ וְלָא אִתְיְדַע הַהוּא רְעוּתָא וְלָא אִתְּפַס לְמִנְדַּע, וּכְדֵין כֹּלָּא רְעוּתָא חֲדָא עַד אֵין סוֹף וְכֹלָּא אִיהוּ בִּשְׁלִימוּ מִלְּתַתָּא וּמִגּוֹ לְגוֹ עַד דְּאִתְעָבִיד כֹּלָּא חָד, וְאִתְמַלְיָא כֹּלָּא וְאִשְׁתְּלִים כֹּלָּא וְאִתְנְהִיר וְאִתְבַּסָּם כֹּלָּא כִּדְקָא יָאוּת:<br><b>רִבּוֹן</b> עָֽלְמָא יְהֵא רְעוּתָךְ עִם עַמָּךְ יִשְׂרָאֵל לְעָלַם, וּפֻרְקַן יְמִינָךְ אַחֲזֵי לְעַמָּךְ בְּבֵית מַקְדְּשָׁךְ, וּלְאַמְטוּיֵי לָנָא מִטּוּב נְהוֹרָךְ, וּלְקַבְּלָא צְלוֹתָנָא בְּרַחֲמֵי, יְהֵא רַעֲוָא קַמָּךְ דְּתֶהֱוֵי סָעִיד וְסָמִיךְ לָן, דְּנֵימָא מִלִּין בְּאֹרַח מֵישַׁר, בְּתִקּוּנָא דִלְעֵלָּא, בְּתִקּוּנִין דְּמַלְכָּא קַדִּישָׁא וּמַטְרוֹנִיתָא קַדִּישָׁא, וּלְמֶעְבַּד יִחוּדָא שְׁלִים, לְאַשְׁלָפָא לְהַהִיא נִשְׁמְתָה דְכָל־חַיֵי מִדַּרְגָּא לְדַרְגָּא עַד סוֹפָא דְכָל־דַּרְגִּין, בְּגִין דְּתֶהֱוֵי הַהִיא נִשְׁמְתָא מִשְׁתַּכְּחָא בְּכֹלָּא וּמִתְפַּשְּׁטָא בְּכֹלָּא, דְּהָא עֵילָּא וְתַתָּא תַּלְיָן בְּהַהִיא נִשְׁמְתָא וּמִתְקַיְּמֵי בָהּ:"}, {"kind": "instruction", "text": "לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ, בִּדְחִֽילוּ וּרְחִֽימוּ, וּרְחִֽימוּ וּדְחִֽילוּ, לְיַחֲדָא שֵׁם יוֹ\"ד קֵ\"א בְּוָא\"ו קֵ\"א בְּיִחוּדָא שְׁלִים, בְּשֵׁם כָּל־יִשְׂרָאֵל, הִנֵּה אֲנַֽחְנוּ בָּאִים לְהִתְפַּלֵּל תְּפִלַּת שַׁחֲרִית, שֶׁתִּקֵּן אַבְרָהָם אָבִינוּ עָלָיו הַשָּׁלוֹם, עִם כָּל הַמִּצְוֹת הַכְּלוּלוֹת בָּהּ, לְתַקֵּן אֶת שָׁרְשָׁהּ בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַֽחַת רֽוּחַ לְיֽוֹצְרֵֽנוּ וְלַעֲשׂוֹת רְצוֹן בּֽוֹרְאֵֽנוּ. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ׃<br><br>וַהֲרֵינִי מְקַבֵּל עָלַי מִצְוַת עֲשֵׂה שֶׁל \"וְאָהַבְתָּ לְרֵעֲךָ כָּמוֹךָ\" וַהֲרֵינִי אוֹהֵב כָּל אֶחָד מִבְּנֵי יִשְׂרָאֵל כְּנַפְשִׁי וּמְאוֹדִי, וַהֲרֵינִי מְזַמֵּן אֶת פִּי לְהִתְפַּלֵּל לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים, הַקָּדוֹשׁ בָּרוּךְ הוּא:"}, {"kind": "text", "text": "<b>אֱלֹהֵינוּ</b> וֵאלֹהֵי אֲבוֹתֵינוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב מִלְּפָנֶיךָ, וּפָקְדֵנוּ בִּפְקֻדַת יְשׁוּעָה וְרַחֲמִים מִשְּׁמֵי שְׁמֵי קֶדֶם, וּזְכֹר־לָנוּ יְהֹוָה אֱלֹהֵינוּ אַהֲבַת הַקַּדְמוֹנִים אַבְרָהָם יִצְחָק וְיִשְׂרָאֵל עֲבָדֶיךָ, אֶת הַבְּרִית וְאֶת הַחֶסֶד וְאֶת הַשְּׁבוּעָה שֶׁנִּשְׁבַּעְתָּ לְאַבְרָהָם אָבִינוּ בְּהַר הַמּוֹרִיָּה, וְאֶת הָעֲקֵדָה שֶׁעָקַד אֶת יִצְחָק בְּנוֹ עַל־גַּבֵּי הַמִּזְבֵּחַ כַּכָּתוּב בְּתוֹרָתָךְ:"}, {"kind": "text", "text": "<b>וַיְהִ֗י</b> אַחַר֙ הַדְּבָרִ֣ים הָאֵ֔לֶּה וְהָ֣אֱלֹהִ֔ים נִסָּ֖ה אֶת־אַבְרָהָ֑ם וַיֹּ֣אמֶר אֵלָ֔יו אַבְרָהָ֖ם וַיֹּ֥אמֶר הִנֵּֽנִי׃ וַיֹּ֡אמֶר קַח־נָ֠א אֶת־בִּנְךָ֨ אֶת־יְחִֽידְךָ֤ אֲשֶׁר־אָהַ֙בְתָּ֙ אֶת־יִצְחָ֔ק וְלֶ֨ךְ־לְךָ֔ אֶל־אֶ֖רֶץ הַמֹּרִיָּ֑ה וְהַעֲלֵ֤הוּ שָׁם֙ לְעֹלָ֔ה עַ֚ל אַחַ֣ד הֶֽהָרִ֔ים אֲשֶׁ֖ר אֹמַ֥ר אֵלֶֽיךָ׃ וַיַּשְׁכֵּ֨ם אַבְרָהָ֜ם בַּבֹּ֗קֶר וַֽיַּחֲבֹשׁ֙ אֶת־חֲמֹר֔וֹ וַיִּקַּ֞ח אֶת־שְׁנֵ֤י נְעָרָיו֙ אִתּ֔וֹ וְאֵ֖ת יִצְחָ֣ק בְּנ֑וֹ וַיְבַקַּע֙ עֲצֵ֣י עֹלָ֔ה וַיָּ֣קׇם וַיֵּ֔לֶךְ אֶל־הַמָּק֖וֹם אֲשֶׁר־אָֽמַר־ל֥וֹ הָאֱלֹהִֽים׃ בַּיּ֣וֹם הַשְּׁלִישִׁ֗י וַיִּשָּׂ֨א אַבְרָהָ֧ם אֶת־עֵינָ֛יו וַיַּ֥רְא אֶת־הַמָּק֖וֹם מֵרָחֹֽק׃ וַיֹּ֨אמֶר אַבְרָהָ֜ם אֶל־נְעָרָ֗יו שְׁבוּ־לָכֶ֥ם פֹּה֙ עִֽם־הַחֲמ֔וֹר וַאֲנִ֣י וְהַנַּ֔עַר נֵלְכָ֖ה עַד־כֹּ֑ה וְנִֽשְׁתַּחֲוֶ֖ה וְנָשׁ֥וּבָה אֲלֵיכֶֽם׃ וַיִּקַּ֨ח אַבְרָהָ֜ם אֶת־עֲצֵ֣י הָעֹלָ֗ה וַיָּ֙שֶׂם֙ עַל־יִצְחָ֣ק בְּנ֔וֹ וַיִּקַּ֣ח בְּיָד֔וֹ אֶת־הָאֵ֖שׁ וְאֶת־הַֽמַּאֲכֶ֑לֶת וַיֵּלְכ֥וּ שְׁנֵיהֶ֖ם יַחְדָּֽו׃ וַיֹּ֨אמֶר יִצְחָ֜ק אֶל־אַבְרָהָ֤ם אָבִיו֙ וַיֹּ֣אמֶר אָבִ֔י וַיֹּ֖אמֶר הִנֶּ֣נִּֽי בְנִ֑י וַיֹּ֗אמֶר הִנֵּ֤ה הָאֵשׁ֙ וְהָ֣עֵצִ֔ים וְאַיֵּ֥ה הַשֶּׂ֖ה לְעֹלָֽה׃ וַיֹּ֙אמֶר֙ אַבְרָהָ֔ם אֱלֹהִ֞ים יִרְאֶה־לּ֥וֹ הַשֶּׂ֛ה לְעֹלָ֖ה בְּנִ֑י וַיֵּלְכ֥וּ שְׁנֵיהֶ֖ם יַחְדָּֽו׃ וַיָּבֹ֗אוּ אֶֽל־הַמָּקוֹם֮ אֲשֶׁ֣ר אָֽמַר־ל֣וֹ הָאֱלֹהִים֒ וַיִּ֨בֶן שָׁ֤ם אַבְרָהָם֙ אֶת־הַמִּזְבֵּ֔חַ וַֽיַּעֲרֹ֖ךְ אֶת־הָעֵצִ֑ים וַֽיַּעֲקֹד֙ אֶת־יִצְחָ֣ק בְּנ֔וֹ וַיָּ֤שֶׂם אֹתוֹ֙ עַל־הַמִּזְבֵּ֔חַ מִמַּ֖עַל לָעֵצִֽים׃ וַיִּשְׁלַ֤ח אַבְרָהָם֙ אֶת־יָד֔וֹ וַיִּקַּ֖ח אֶת־הַֽמַּאֲכֶ֑לֶת לִשְׁחֹ֖ט אֶת־בְּנֽוֹ׃ וַיִּקְרָ֨א אֵלָ֜יו מַלְאַ֤ךְ יְהֹוָה֙ מִן־הַשָּׁמַ֔יִם וַיֹּ֖אמֶר אַבְרָהָ֣ם ׀ אַבְרָהָ֑ם וַיֹּ֖אמֶר הִנֵּֽנִי׃ וַיֹּ֗אמֶר אַל־תִּשְׁלַ֤ח יָֽדְךָ֙ אֶל־הַנַּ֔עַר וְאַל־תַּ֥עַשׂ ל֖וֹ מְא֑וּמָה כִּ֣י ׀ עַתָּ֣ה יָדַ֗עְתִּי כִּֽי־יְרֵ֤א אֱלֹהִים֙ אַ֔תָּה וְלֹ֥א חָשַׂ֛כְתָּ אֶת־בִּנְךָ֥ אֶת־יְחִידְךָ֖ מִמֶּֽנִּי׃ וַיִּשָּׂ֨א אַבְרָהָ֜ם אֶת־עֵינָ֗יו וַיַּרְא֙ וְהִנֵּה־אַ֔יִל אַחַ֕ר נֶאֱחַ֥ז בַּסְּבַ֖ךְ בְּקַרְנָ֑יו וַיֵּ֤לֶךְ אַבְרָהָם֙ וַיִּקַּ֣ח אֶת־הָאַ֔יִל וַיַּעֲלֵ֥הוּ לְעֹלָ֖ה תַּ֥חַת בְּנֽוֹ׃ וַיִּקְרָ֧א אַבְרָהָ֛ם שֵֽׁם־הַמָּק֥וֹם הַה֖וּא יְהֹוָ֣ה ׀ יִרְאֶ֑ה אֲשֶׁר֙ יֵאָמֵ֣ר הַיּ֔וֹם בְּהַ֥ר יְהֹוָ֖ה יֵרָאֶֽה׃ וַיִּקְרָ֛א מַלְאַ֥ךְ יְהֹוָ֖ה אֶל־אַבְרָהָ֑ם שֵׁנִ֖ית מִן־הַשָּׁמָֽיִם׃ וַיֹּ֕אמֶר בִּ֥י נִשְׁבַּ֖עְתִּי נְאֻם־יְהֹוָ֑ה כִּ֗י יַ֚עַן אֲשֶׁ֤ר עָשִׂ֙יתָ֙ אֶת־הַדָּבָ֣ר הַזֶּ֔ה וְלֹ֥א חָשַׂ֖כְתָּ אֶת־בִּנְךָ֥ אֶת־יְחִידֶֽךָ׃ כִּֽי־בָרֵ֣ךְ אֲבָרֶכְךָ֗ וְהַרְבָּ֨ה אַרְבֶּ֤ה אֶֽת־זַרְעֲךָ֙ כְּכוֹכְבֵ֣י הַשָּׁמַ֔יִם וְכַח֕וֹל אֲשֶׁ֖ר עַל־שְׂפַ֣ת הַיָּ֑ם וְיִרַ֣שׁ זַרְעֲךָ֔ אֵ֖ת שַׁ֥עַר אֹיְבָֽיו׃ וְהִתְבָּרְכ֣וּ בְזַרְעֲךָ֔ כֹּ֖ל גּוֹיֵ֣י הָאָ֑רֶץ עֵ֕קֶב אֲשֶׁ֥ר שָׁמַ֖עְתָּ בְּקֹלִֽי׃ וַיָּ֤שׇׁב אַבְרָהָם֙ אֶל־נְעָרָ֔יו וַיָּקֻ֛מוּ וַיֵּלְכ֥וּ יַחְדָּ֖ו אֶל־בְּאֵ֣ר שָׁ֑בַע וַיֵּ֥שֶׁב אַבְרָהָ֖ם בִּבְאֵ֥ר שָֽׁבַע׃"}, {"kind": "instruction", "text": "יש נוהגים לומר את הקטע הבא"}, {"kind": "text", "text": "וְשָׁחַ֨ט אֹת֜וֹ עַ֣ל יֶ֧רֶךְ הַמִּזְבֵּ֛חַ צָפֹ֖נָה לִפְנֵ֣י יְהֹוָ֑ה וְזָרְק֡וּ בְּנֵי֩ אַהֲרֹ֨ן הַכֹּהֲנִ֧ים אֶת־דָּמ֛וֹ עַל־הַמִּזְבֵּ֖חַ סָבִֽיב:"}, {"kind": "text", "text": "יְהִי רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּתְמַלֵּא רַחֲמִים עָלֵינוּ, וּבְכֵן בְּרוֹב רַחֲמֶיךָ תִּזְכּוֹר לָנוּ עֲקֵדָתוֹ שֶׁל יִצְחָק אָבִינוּ בֶּן אַבְרָהָם אָבִינוּ עָלָיו הַשָּׁלוֹם, כְּאִלּוּ אֶפְרוֹ צָבוּר וּמֻנָּח עַל גַּבֵּי הַמִּזְבֵּחַ, וְתַבִּיט בְּאֶפְרוֹ לְרַחֵם עָלֵינוּ, וּלְבַטֵּל מֵעָלֵינוּ כָּל־גְּזֵירוֹת קָשׁוֹת וְרָעוֹת, וּתְזַכֵּנוּ לָשׁוּב בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ, וְתַצִּילֵנוּ מִיֵּצֶר הָרָע וּמִכָּל חֵטְא וְעָוֹן, וְתַאֲרִיךְ יָמֵינוּ בַּטּוֹב וּשְׁנוֹתֵינוּ בַּנְּעִימִים:"}, {"kind": "text", "text": "<b>רִבּוֹנוֹ</b> שֶׁל עוֹלָם, כְּמוֹ שֶׁכָּבַשׁ אַבְרָהָם אָבִינוּ אֶת רַחֲמָיו לַעֲשׂוֹת רְצוֹנְךָ בְּלֵבָב שָׁלֵם, כֵּן יִכְבְּשׁוּ רַחֲמֶיךָ אֶת כַּעַסֶֽךָ, וְיִּגֹּלוּ רַחֲמֶיךָ עַל מִדּוֹתֶיךָ, וְתִתְנַהֵג עִמָּנוּ יְהֹוָה אֱלֹהֵינוּ בְּמִדַּת הַחֶסֶד וּבְמִדַּת הָרַחֲמִים, וְתִכָּנֵס לָנוּ לִפְנִים מִשּׁוּרַת הַדִּין, וּבְטוּבְךָ הַגָּדוֹל יָשׁוּב חֲרוֹן אַפָּךְ, מֵעַמָּךְ וּמֵעִירָךְ וּמֵאַרְצָךְ וּמִנַּחֲלָתָךְ, וְקַיֵם לָנוּ יְהֹוָה אֱלֹהֵינוּ אֶת הַדָּבָר שֶׁהִבְטַחְתָּנוּ בְּתוֹרָתָךְ עַל יְדֵי מֹשֶׁה עַבְדָּךְ כָּאָמוּר: וְזָכַרְתִּ֖י אֶת־בְּרִיתִ֣י יַעֲק֑וֹב וְאַף֩ אֶת־בְּרִיתִ֨י יִצְחָ֜ק וְאַ֨ף אֶת־בְּרִיתִ֧י אַבְרָהָ֛ם אֶזְכֹּ֖ר וְהָאָ֥רֶץ אֶזְכֹּֽר: וְנֶאֱמַר: וְאַף־גַּם־זֹ֠את בִּֽהְיוֹתָ֞ם בְּאֶ֣רֶץ אֹֽיְבֵיהֶ֗ם לֹֽא־מְאַסְתִּ֤ים וְלֹֽא־גְעַלְתִּים֙ לְכַלֹּתָ֔ם לְהָפֵ֥ר בְּרִיתִ֖י אִתָּ֑ם כִּ֛י אֲנִ֥י יְהֹוָ֖ה אֱלֹהֵיהֶֽם: וְזָכַרְתִּ֥י לָהֶ֖ם בְּרִ֣ית רִאשֹׁנִ֑ים אֲשֶׁ֣ר הוֹצֵֽאתִי־אֹתָם֩ מֵאֶ֨רֶץ מִצְרַ֜יִם לְעֵינֵ֣י הַגּוֹיִ֗ם לִהְי֥וֹת לָהֶ֛ם לֵאלֹהִ֖ים אֲנִ֥י יְהֹוָֽה: וְנֶאֱמַר: וְשָׁ֨ב יְהֹוָ֧ה אֱלֹהֶ֛יךָ אֶת־שְׁבוּתְךָ֖ וְרִחֲמֶ֑ךָ וְשָׁ֗ב וְקִבֶּצְךָ֙ מִכׇּל־הָ֣עַמִּ֔ים אֲשֶׁ֧ר הֱפִֽיצְךָ֛ יְהֹוָ֥ה אֱלֹהֶ֖יךָ שָֽׁמָּה: אִם־יִהְיֶ֥ה נִֽדַּחֲךָ֖ בִּקְצֵ֣ה הַשָּׁמָ֑יִם מִשָּׁ֗ם יְקַבֶּצְךָ֙ יְהֹוָ֣ה אֱלֹהֶ֔יךָ וּמִשָּׁ֖ם יִקָּחֶֽךָ: וֶהֱבִיאֲךָ֞ יְהֹוָ֣ה אֱלֹהֶ֗יךָ אֶל־הָאָ֛רֶץ אֲשֶׁר־יָרְשׁ֥וּ אֲבֹתֶ֖יךָ וִֽירִשְׁתָּ֑הּ וְהֵיטִֽבְךָ֥ וְהִרְבְּךָ֖ מֵאֲבֹתֶֽיךָ: וְנֶאֱמַר עַל יְדֵי נְבִיאֶךָ: יְהֹוָ֥ה חׇנֵּ֖נוּ לְךָ֣ קִוִּ֑ינוּ הֱיֵ֤ה זְרֹעָם֙ לַבְּקָרִ֔ים אַף־יְשׁוּעָתֵ֖נוּ בְּעֵ֥ת צָרָֽה: וְנֶאֱמַר: וְעֵֽת־צָרָ֥ה הִיא֙ לְיַֽעֲקֹ֔ב וּמִמֶּ֖נָּה יִוָּשֵֽׁעַ: וְנֶאֱמַר: בְּֽכׇל־צָרָתָ֣ם ׀ לא [ל֣וֹ] צָ֗ר וּמַלְאַ֤ךְ פָּנָיו֙ הוֹשִׁיעָ֔ם בְּאַהֲבָת֥וֹ וּבְחֶמְלָת֖וֹ ה֣וּא גְאָלָ֑ם וַֽיְנַטְּלֵ֥ם וַֽיְנַשְּׂאֵ֖ם כׇּל־יְמֵ֥י עוֹלָֽם: וְנֶאֱמַר: יכוין לי\"ג מדות מִי־אֵ֣ל כָּמ֗וֹךָ אל נֹשֵׂ֤א עָוֺן֙ רחום וְעֹבֵ֣ר עַל־פֶּ֔שַׁע וחנון לִשְׁאֵרִ֖ית נַחֲלָת֑וֹ ארך לֹֽא־הֶחֱזִ֤יק לָעַד֙ אַפּ֔וֹ אפים כִּֽי־חָפֵ֥ץ חֶ֖סֶד הֽוּא ורב חסד: יָשׁ֣וּב יְרַחֲמֵ֔נוּ ואמת יִכְבֹּ֖שׁ עֲוֺנֹתֵ֑ינוּ נצר חסד וְתַשְׁלִ֛יךְ בִּמְצֻל֥וֹת יָ֖ם כׇּל־חַטֹּאותָֽם לאלפים: תִּתֵּ֤ן אֱמֶת֙ לְיַֽעֲקֹ֔ב נושא עון חֶ֖סֶד לְאַבְרָהָ֑ם ופשע אֲשֶׁר־נִשְׁבַּ֥עְתָּ לַאֲבֹתֵ֖ינוּ וחטאה מִ֥ימֵי קֶֽדֶם ונקה: וְנֶאֱמַר: וַהֲבִיאוֹתִ֞ים אֶל־הַ֣ר קׇדְשִׁ֗י וְשִׂמַּחְתִּים֙ בְּבֵ֣ית תְּפִלָּתִ֔י עוֹלֹתֵיהֶ֧ם וְזִבְחֵיהֶ֛ם לְרָצ֖וֹן עַֽל־מִזְבְּחִ֑י כִּ֣י בֵיתִ֔י בֵּית־תְּפִלָּ֥ה יִקָּרֵ֖א לְכׇל־הָעַמִּֽים:"}, {"kind": "text", "text": "<b>אֵלּוּ</b> דְבָרִים שֶׁאֵין לָהֶם שִׁעוּר: הַפֵּאָה, וְהַבִּכּוּרִים, וְהָרֵאָיוֹן, וּגְמִילוּת חֲסָדִים, וְתַלְמוּד תּוֹרָה: אֵלּוּ דְבָרִים שֶׁאָדָם עוֹשֶׂה אוֹתָם וְאוֹכֵל פֵּרוֹתֵיהֶם בָּעוֹלָם הַזֶּה, וְהַקֶּרֶן קַיֶּמֶת לָעוֹלָם הַבָּא: וְאֵלּוּ הֵן: כִּבּוּד אָב וָאֵם, וּגְמִילוּת חֲסָדִים, וּבִקּוּר חוֹלִים, וְהַכְנָסַת אוֹרְחִים, וְהַשְׁכָּמַת בֵּית הַכְּנֶסֶת, וַהֲבָאַת שָׁלוֹם בֵּין אָדָם לַחֲבֵרוֹ וּבֵין אִישׁ לְאִשְׁתוֹ וְתַלְמוּד תּוֹרָה כְּנֶגֶד כֻּלָּם."}, {"kind": "text", "text": "<b>לְעוֹלָם</b> יְהֵא אָדָם יְרֵא שָׁמַיִם בַּסֵּתֶר כְּבַגָּלוּי, וּמוֹדֶה עַל הָאֱמֶת, וְדוֹבֵר אֱמֶת בִּלְבָבוֹ, וְיַשְׁכִּים וְיֹאמַר: רִבּוֹן הָעוֹלָמִים וַאֲדוֹנֵי הָאֲדוֹנִים, לֹא עַל צִּדְקוֹתֵינוּ אֲנַחְנוּ מַפִּילִים תַּחֲנוּנֵינוּ לְפָנֶיךָ כִּי עַל רַחֲמֶיךָ הָרַבִּים: אֲדֹנָ֤י ׀ שְׁמָ֙עָה֙ אֲדֹנָ֣י ׀ סְלָ֔חָה אֲדֹנָ֛י הַֽקְשִׁ֥יבָה וַעֲשֵׂ֖ה אַל־תְּאַחַ֑ר לְמַֽעַנְךָ֣ אֱלֹהַ֔י כִּֽי־שִׁמְךָ֣ נִקְרָ֔א עַל־עִירְךָ֖ וְעַל־עַמֶּֽךָ׃ מָה אֲנַחְנוּ, מַה חַיֵּינוּ, מַה חַסְדֵנוּ, מַה־צִּדְקוֹתֵינוּ, מַה־כֹּחֵנוּ, מַה־גְּבוּרָתֵנוּ. מַה נֹּאמַר לְפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, הֲלֹא כָּל־הַגִבּוֹרִים כְּאַיִן לְפָנֶיךָ, וְאַנְשֵׁי הַשֵּׁם כְּלֹא הָיוּ, וַחֲכָמִים כִּבְלִי מַדָּע, וּנְבוֹנִים כִּבְלִי הַשְׂכֵּל, כִּי כָל־מַעֲשֵֽׂינוּ תֹֽהוּ, וִימֵי חַיֵּינוּ הֶבֶֶל לְפָנֶיךָ, וּמוֹתַ֨ר הָאָדָ֤ם מִן־הַבְּהֵמָה֙ אָ֔יִן כִּ֥י הַכֹּ֖ל הָֽבֶל׃ לְבַד הַנְּשָׁמָה הַטְּהוֹרָה שֶׁהִיא עֲתִידָה לִתֵּן דִּין וְחֶשְׁבּוֹן לִפְנֵי כִסֵּא כְבוֹדֶךָ. וְכָל־הַגּוֹיִם כְּאַיִן נֶגְדֶּךָ, שֶׁנֶּאֱמַר: הֵ֤ן גּוֹיִם֙ כְּמַ֣ר מִדְּלִ֔י וּכְשַׁ֥חַק מֹאזְנַ֖יִם נֶחְשָׁ֑בוּ הֵ֥ן אִיִּ֖ים כַּדַּ֥ק יִטּֽוֹל׃ אֲבָל אֲנַחְנוּ עַמְּךָ בְּנֵי בְרִיתֶךָ, בְּנֵי אַבְרָהָם אֹהֲבֶךָ שֶׁנִּשְׁבַּעְתָּ־לוֹ בְּהַר הַמּוֹרִיָּה, זֶרַע יִצְחָק עֲקֵדֶךָ שֶׁנֶּעֱקַד עַל־גַּבֵּי הַמִּזְבֵּחַ, עֲדַת יַעֲקֹב בִּנְךָ בְכוֹרֶךָ, שֶׁמֵּאַהֲבָתְךָ שֶׁאָהַבְתָּ אוֹתוֹ, וּמִשִּׂמְחָתְךָ שֶׁשָּׂמַחְתָּ־בּוֹ, קָרָאתָ אוֹתוֹ יִשְׂרָאֵל וִישֻׁרוּן:"}, {"kind": "text", "text": "<b>לְפִיכָךְ</b> אֲנַחְנוּ חַיָּבִים לְהוֹדוֹת לָךְ, וּלְשַׁבְּחָךְ וּלְפָאֲרָךְ וּלְרוֹמְמָךְ, וְלִתֵּן שִׁיר שֶׁבַח וְהוֹדָאָה לְשִׁמְךָ הַגָּדוֹל בְּכָל יוֹם תָּמִיד. אַשְׁרֵינוּ, מַה טוֹב חֶלְקֵינוּ, וּמַה נָעִים גּוֹרָלֵנוּ, וּמַה יָפָה מְאוֹד יְרוּשָׁתֵינוּ, אַשְׁרֵינוּ כְּשֶׁאֲנַחְנוּ מַשְׁכִּימִים וּמַעֲרִיבִים בְּבָתֵּי כְּנֵסִיּוֹת וּבְבָתֵּי מִדְרָשׁוֹת וּמְיַחֲדִים שִׁמְךָ בְּכָל יוֹם תָּמִיד אוֹמְרִים פַּעֲמַיִם בְּאַהֲבָה:"}, {"kind": "text", "text": "כשיגיע לקריאת שמע קודם פרשת התמיד יזהר לומר פסוקים שמע ישראל וברוך בכונה גדולה כמו קריאת שמע דיוצר (בא\"ח מקץ ה\"ז), ואם רואה שזמן קריאת שמע עובר יאמר כאן קריאת שמע כולה"}, {"kind": "text", "text": "<b>שְׁמַ֖ע יִשְׂרָאֵ֑ל יְהֹוָ֥ה אֱלֹהֵ֖ינוּ יְהֹוָ֥ה ׀ אֶחָֽד</b>׃"}, {"kind": "text", "text": "ואומר בלחש בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "<b>אַתָּה</b> הוּא אֶחָד קוֹדֵם שֶׁבָּרָאתָ הָעוֹלָם, וְאַתָּה הוּא אֶחָד לְאַחַר שֶׁבָּרָאתָ הָעוֹלָם, אַתָּה הוּא אֵל בָּעוֹלָם הַזֶּה, וְאַתָּה הוּא אֵל בָּעוֹלָם הַבָּא, וְאַתָּה־ה֑וּא וּ֝שְׁנוֹתֶ֗יךָ לֹ֣א יִתָּֽמּוּ׃ קַדֵּשׁ שְׁמָךְ בְּעוֹלָמָךְ עַל־עַם מְקַדְּשֵׁי שְׁמֶךָ, וּבִישׁוּעָתְךָ מַלְכֵּנוּ תָּרוּם וְתַגְבִּיהַּ קַרְנֵנוּ, וְתוֹשִׁיעֵנוּ בְּקָרוֹב לְמַעַן שְׁמֶךָ, בָּרוּךְ הַמְקַדֵּשׁ שְׁמוֹ בָּרַבִּים:"}, {"kind": "text", "text": "<b>אַתָּה</b> הוּא יְהֹוָה הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל־הָאָרֶץ מִתַּחַת, בִּשְׁמֵי הַשָּׁמַיִם הָעֶלְיוֹנִים וְהַתַּחְתּוֹנִים, אַתָּה הוּא רִאשׁוֹן וְאַתָּה הוּא אַחֲרוֹן וּמִבַּלְעָדֶיךָ אֵין אֱלֹהִים. קַבֵּץ נְפוּצוֹת קֹוֶיךָ מֵאַרְבַּע כַּנְפוֹת הָאָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל בָּאֵי עוֹלָם כִּי אַתָּה הוּא הָאֱלֹהִים לְבַדְּךָ לְכָל מַמְלְכוֹת הָאָרֶץ, אַתָּה עָשִׂיתָ אֶת הַשָּׁמַיִם וְאֶת הָאָרֶץ, אֶת הַיָּם וְאֶת כָּל אֲשֶׁר בָּם, וּמִי בְּכָל מַעֲשֵׂה יָדֶיךָ בָּעֶלְיוֹנִים וּבַתַּחְתּוֹנִים שֶׁיֹּאמַר לָךְ מַה־תַּעֲשֶׂה וּמַה־תִּפְעָל. אָבִינוּ שֶׁבַּשָּׁמַיִם חַי וְקַיָּם, עֲשֵׂה עִמָּנוּ חֶסֶד בַּעֲבוּר כְּבוֹד שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ, וְקַיֵּם לָנוּ יְהֹוָה אֱלֹהֵינוּ אֶת הַדָּבָר שֶׁהִבְטַחְתָּנוּ עַל יְדֵי צְפַנְיָה חוֹזָךְ כָּאָמוּר: בָּעֵ֤ת הַהִיא֙ אָבִ֣יא אֶתְכֶ֔ם וּבָעֵ֖ת קַבְּצִ֣י אֶתְכֶ֑ם כִּֽי־אֶתֵּ֨ן אֶתְכֶ֜ם לְשֵׁ֣ם וְלִתְהִלָּ֗ה בְּכֹל֙ עַמֵּ֣י הָאָ֔רֶץ בְּשׁוּבִ֧י אֶת־שְׁבוּתֵיכֶ֛ם לְעֵינֵיכֶ֖ם אָמַ֥ר יְהֹוָֽה:"}, {"kind": "text", "text": "<b>יְהִי רָצוֹן</b> מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ שֶׁתְּרַחֵם עָלֵינוּ, וְתִמְחוֹל לָנוּ אֶת כָּל חַטְּאוֹתֵינוּ, וּתְכַפֵּר לָנוּ אֶת־כָּל־עֲוֹנוֹתֵינוּ, וְתִמְחוֹל וְתִסְלַח לְכָל פְּשָׁעֵינוּ, וְתִּבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְנַקְרִיב לְפָנֶיךָ קָרְבַּן הַתָּמִיד שֶׁיְּכַפֵּר בַּעֲדֵינוּ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתָךְ עַל יְדֵי מֹשֶׁה עַבְדָּךְ כָּאָמוּר:"}, {"kind": "text", "text": "<b>וַיְדַבֵּ֥ר</b> יְהֹוָ֖ה אֶל־מֹשֶׁ֥ה לֵּאמֹֽר׃ צַ֚ו אֶת־בְּנֵ֣י יִשְׂרָאֵ֔ל וְאָמַרְתָּ֖ אֲלֵהֶ֑ם אֶת־קׇרְבָּנִ֨י לַחְמִ֜י לְאִשַּׁ֗י רֵ֚יחַ נִֽיחֹחִ֔י תִּשְׁמְר֕וּ לְהַקְרִ֥יב לִ֖י בְּמוֹעֲדֽוֹ׃ וְאָמַרְתָּ֣ לָהֶ֔ם זֶ֚ה הָֽאִשֶּׁ֔ה אֲשֶׁ֥ר תַּקְרִ֖יבוּ לַיהֹוָ֑ה כְּבָשִׂ֨ים בְּנֵֽי־שָׁנָ֧ה תְמִימִ֛ם שְׁנַ֥יִם לַיּ֖וֹם עֹלָ֥ה תָמִֽיד׃ אֶת־הַכֶּ֥בֶשׂ אֶחָ֖ד תַּעֲשֶׂ֣ה בַבֹּ֑קֶר וְאֵת֙ הַכֶּ֣בֶשׂ הַשֵּׁנִ֔י תַּעֲשֶׂ֖ה בֵּ֥ין הָֽעַרְבָּֽיִם׃ וַעֲשִׂירִ֧ית הָאֵיפָ֛ה סֹ֖לֶת לְמִנְחָ֑ה בְּלוּלָ֛ה בְּשֶׁ֥מֶן כָּתִ֖ית רְבִיעִ֥ת הַהִֽין׃ עֹלַ֖ת תָּמִ֑יד הָעֲשֻׂיָה֙ בְּהַ֣ר סִינַ֔י לְרֵ֣יחַ נִיחֹ֔חַ אִשֶּׁ֖ה לַֽיהֹוָֽה׃ וְנִסְכּוֹ֙ רְבִיעִ֣ת הַהִ֔ין לַכֶּ֖בֶשׂ הָאֶחָ֑ד בַּקֹּ֗דֶשׁ הַסֵּ֛ךְ נֶ֥סֶךְ שֵׁכָ֖ר לַיהֹוָֽה׃ וְאֵת֙ הַכֶּ֣בֶשׂ הַשֵּׁנִ֔י תַּעֲשֶׂ֖ה בֵּ֣ין הָֽעַרְבָּ֑יִם כְּמִנְחַ֨ת הַבֹּ֤קֶר וּכְנִסְכּוֹ֙ תַּעֲשֶׂ֔ה אִשֵּׁ֛ה רֵ֥יחַ נִיחֹ֖חַ לַיהֹוָֽה׃"}, {"kind": "header", "text": "פטום הקטורת"}, {"kind": "text", "text": "<b>אַתָּה</b> הוּא יְהֹוָה אֱלֹהֵֽינוּ, שֶׁהִקְטִֽירוּ אֲבוֹתֵֽינוּ לְפָנֶֽיךָ אֶת קְטֹֽרֶת הַסַּמִּים, בִּזְמַן שֶׁבֵּית הַמִּקְדָשׁ קַיָּם, כַּאֲשֶׁר צִוִּֽיתָ אוֹתָם עַל־יַד מֹשֶׁה נְבִיאָךְ, כַּכָּתוּב בְּתֽוֹרָתָךְ:"}, {"kind": "text", "text": "<b>וַיֹּ֩אמֶר֩</b> יְהֹוָ֨ה אֶל־מֹשֶׁ֜ה קַח־לְךָ֣ סַמִּ֗ים נָטָ֤ף | וּשְׁחֵ֙לֶת֙ וְחֶלְבְּנָ֔ה סַמִּ֖ים וּלְבֹנָ֣ה זַכָּ֑ה בַּ֥ד בְּבַ֖ד יִהְיֶֽה׃ וְעָשִׂ֤יתָ אֹתָהּ֙ קְטֹ֔רֶת רֹ֖קַח מַעֲשֵׂ֣ה רוֹקֵ֑חַ מְמֻלָּ֖ח טָה֥וֹר קֹֽדֶשׁ׃ וְשָֽׁחַקְתָּ֣ מִמֶּ֘נָּה֮ הָדֵק֒ וְנָתַתָּ֨ה מִמֶּ֜נָּה לִפְנֵ֤י הָעֵדֻת֙ בְּאֹ֣הֶל מוֹעֵ֔ד אֲשֶׁ֛ר אִוָּעֵ֥ד לְךָ֖ שָׁ֑מָּה קֹ֥דֶשׁ קׇֽדָשִׁ֖ים תִּהְיֶ֥ה לָכֶֽם׃ וְנֶֽאֱמַר וְהִקְטִ֥יר עָלָ֛יו אַהֲרֹ֖ן קְטֹ֣רֶת סַמִּ֑ים בַּבֹּ֣קֶר בַּבֹּ֗קֶר בְּהֵיטִיב֛וֹ אֶת־הַנֵּרֹ֖ת יַקְטִירֶֽנָּה: וּבְהַעֲלֹ֨ת אַהֲרֹ֧ן אֶת־הַנֵּרֹ֛ת בֵּ֥ין הָעַרְבַּ֖יִם יַקְטִירֶ֑נָּה קְטֹ֧רֶת תָּמִ֛יד לִפְנֵ֥י יְהֹוָ֖ה לְדֹרֹתֵיכֶֽם:"}, {"kind": "text", "text": "<b>תָּנוּ</b> רַבָּנָן: פִּטּוּם הַקְּטֹֽרֶת כֵּיצַד? שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וּשְׁמוֹנָה מָנִים הָיוּ בָהּ. שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וַֽחֲמִשָּׁה כְּמִנְיַן יְמוֹת הַחַמָּה, מָנֶה בְּכָל־יוֹם, מַֽחֲצִיתוֹ בַּבֹּֽקֶר וּמַֽחֲצִיתוֹ בָּעֶרֶב. וּשְׁלֹשָׁה מָנִים יְתֵרִים, שֶׁמֵּהֶם מַכְנִיס כֹּהֵן גָּדוֹל, וְנוֹטֵל מֵהֶם מְלֹא חָפְנָיו בְּיוֹם הַכִּפּוּרִים, וּמַֽחֲזִירָן לְמַכְתֶּֽשֶׁת בְּעֶֽרֶב יוֹם הַכִּפּוּרִים, כְּדֵי לְקַיֵּם מִצְוַת דַקָּה מִן הַדַּקָּה. וְאַחַד־עָשָׂר סַמָּנִים הָיוּ בָהּ, וְאֵֽלּוּ הֵן:"}, {"kind": "text", "text": "א הַצֳּרִי ב וְהַצִּפֹּֽרֶן ג וְהַחֶלְבְּנָה ד וְהַלְּבוֹנָה, מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה. ה מוֹר, ו וּקְצִיעָה ז וְשִׁבֹּֽלֶת נֵרְדְּ ח וְכַרְכֹּם, מִשְׁקַל שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה. ט קֹשְׁטְ שְׁנֵים עָשָׂר, י קִלּוּפָה שְׁלֹשָׁה, יא קִנָּמוֹן תִּשְׁעָה, בּוֹרִית־כַּרְשִׁינָה תִּשְׁעָה קַבִּין. יֵין קַפְרִיסִין סְאִין תְּלָת וְקַבִּין תְּלָתָא. וְאִם לֹא מָצָא יֵין קַפְרִיסִין, מֵבִיא חֲמַר חִיוָר עַתִּיק. מֶֽלַח סְדוֹמִית, רֽוֹבַע. מַעֲלֶה עָשָׁן, כָּל־שֶׁהוּא. רִבִּי נָתָן הַבַּבְלִי אוֹמֵר: אַף כִּפַּת הַיַּרְדֵּן כָּל־שֶׁהִיא, אִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ, וְאִם חִסֵּר אַחַת מִכָּל־סַמְמָנֶֽיהָ, חַיָּיב מִיתָה:"}, {"kind": "text", "text": "<b>רַבָּן</b> שִׁמְעוֹן בֶּן־גַּמְלִיאֵל אוֹמֵר: הַצֳּרִי אֵינוֹ אֶלָּא שְׁרָף, הַנּוֹטֵף מֵֽעֲצֵי הַקְּטָף. בֹּרִית כַּרְשִׁינָה, לְמָה הִיא בָֽאָה? כְּדֵי לְשַׁפּוֹת בָּהּ אֶת־הַצִּפֹּֽרֶן, כְּדֵי שֶׁתְּהֵא נָאָה. יֵין קַפְרִיסִין, לְמָה הוּא בָא? כְּדֵי לִשְׁרוֹת בּוֹ אֶת־הַצִּפֹּֽרֶן כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלֹא מֵי רַגְלַֽיִם יָפִין לָהּ? אֶלָּא שֶׁאֵין מַכְנִיסִין מֵי רַגְלַֽיִם בַּמִּקְדָּשׁ, מִפְּנֵי הַכָּבוֹד:"}, {"kind": "text", "text": "<b>תַּנְיָא</b> רִבִּי נָתָן אוֹמֵר: כְּשֶׁהוּא שׁוֹחֵק, אוֹמֵר: הָדֵק הֵיטֵב, הֵיטֵב הָדֵק. מִפְּנֵי שֶׁהַקּוֹל יָפֶה לַבְּשָׂמִים. פִּטְּמָהּ לַֽחֲצָאִין, כְּשֵׁרָה. לְשָׁלִישׁ וּלְרָבִֽיעַ, לֹא שָׁמַֽעְנוּ. אָמַר רִבִּי יְהוּדָה: זֶה הַכְּלָל, אִם כְּמִדָּתָהּ, כְּשֵׁרָה לַֽחֲצָאִין. וְאִם חִסֵּר אַחַת מִכָּל־סַמְמָנֶֽיהָ, חַיָּיב מִיתָה:"}, {"kind": "text", "text": "<b>תָּנֵי</b> בַר־קַפָּרָא: אַחַת לְשִׁשִּׁים אוֹ לְשִׁבְעִים שָׁנָה, הָֽיְתָה בָֽאָה שֶׁל שִׁירַֽיִם לַֽחֲצָאִין. וְעוֹד תָּנֵי בַר־קַפָּרָא: אִלּוּ הָיָה נוֹתֵן בָּהּ קָרְטוֹב שֶׁל דְּבַשׁ, אֵין אָדָם יָכוֹל לַֽעֲמֹד מִפְּנֵי רֵיחָהּ. וְלָֽמָּה אֵין מְעָֽרְבִין בָּהּ דְּבַשׁ? מִפְּנֵי שֶׁהַתּוֹרָה אָֽמְרָה: כִּ֤י כָל־שְׂאֹר֙ וְכָל־דְּבַ֔שׁ לֹֽא־תַקְטִ֧ירוּ מִמֶּ֛נּוּ אִשֶּׁ֖ה לַֽיהֹוָֽה: יְהֹוָ֣ה צְבָא֣וֹת עִמָּ֑נוּ מִשְׂגָּֽב־לָ֨נוּ אֱלֹהֵ֖י יַֽעֲקֹ֣ב סֶֽלָה׃ יְהֹוָ֥ה צְבָא֑וֹת אַֽשְׁרֵ֥י אָ֝דָ֗ם בֹּטֵ֥חַ בָּֽךְ׃ יְהֹוָ֥ה הוֹשִׁ֑יעָה הַ֝מֶּ֗לֶךְ יַעֲנֵ֥נוּ בְיוֹם־קׇרְאֵֽנוּ: וְעָֽרְבָה֙ לַֽיהֹוָ֔ה מִנְחַ֥ת יְהוּדָ֖ה וִירֽוּשָׁלָ֑‍ִם כִּימֵ֣י עוֹלָ֔ם וּכְשָׁנִ֖ים קַדְמֹנִיֹּֽת:"}, {"kind": "text", "text": "<b>אַבַּיֵּי</b> יפסיק מעט הֲוָה מְסַדֵּר סֵדֶר הַמַּעֲרָכָה מִשְּׁמָא דִגְמָרָא, וְאַלִבָּא דְאַבָּא שָׁאוּל. מַעֲרָכָה גְּדוֹלָה קוֹדֶמֶת לְמַעֲרָכָה שְׁנִיָּה שֶׁל קְטֹרֶת, וּמַעֲרָכָה שְׁנִיָּה שֶׁל קְטֹרֶת קוֹדֶמֶת לְסִדּוּר שְׁנֵי גְזִירֵי עֵצִים, וְסִדּוּר שְׁנֵי גְזִירֵי עֵצִים קוֹדֵם לְדִישּׁוּן מִזְבַּח הַפְּנִימִי, וְדִישּׁוּן מִזְבַּח הַפְּנִימִי קוֹדֵם לַהֲטָבַת חָמֵשׁ נֵרוֹת, וַהֲטָבַת חָמֵשׁ נֵרוֹת קוֹדֶמֶת לְדַם הַתָּמִיד, וְדַם הַתָּמִיד קוֹדֵם לַהֲטָבַת שְׁתֵּי נֵרוֹת, וַהֲטָבַת שְׁתֵּי נֵרוֹת קוֹדֶמֶת לִקְטֹרֶת, וּקְטֹרֶת לְאֵבָרִים, וְאֵבָרִים לְמִנְחָה, וּמִנְחָה לַחֲבִיתִּין, וַחֲבִיתִּין לִנְסָכִין, וּנְסָכִין לְמוּסָפִין, וּמוּסָפִין לְבָזִיכִין, וּבָזִיכִין קוֹדְמִין לְתָמִיד שֶׁל בֵּין הָעַרְבָּיִם, שֶׁנֶּאֱמַר: וְעָרַ֤ךְ עָלֶ֙יהָ֙ הָֽעֹלָ֔ה וְהִקְטִ֥יר עָלֶ֖יהָ חֶלְבֵ֥י הַשְּׁלָמִֽים: עָלֶיהָ הַשְׁלֵם כָּל הַקָּרְבָּנוֹת כֻּלָּם:"}, {"kind": "text", "text": "אָֽנָּֽא בְּכֹֽחַ. גְּדוּלַת יְמִינֶֽךָ. תַּתִּיר צְרוּרָה: (אב\"ג ית\"ץ)"}, {"kind": "text", "text": "קַבֵּל רִנַּת. עַמֶּֽךָ שַׂגְּבֵֽנוּ. טַהֲרֵֽנוּ נוֹרָא: (קר\"ע שט\"ן)"}, {"kind": "text", "text": "נָא גִבּוֹר. דּֽוֹרְשֵֽׁי יִחוּדֶֽךָ. כְּבָבַת שָׁמְרֵם: (נג\"ד יכ\"ש)"}, {"kind": "text", "text": "בָּֽרְכֵֽם טַהֲרֵם. רַחֲמֵי צִדְקָתֶֽךָ. תָּמִיד גָּמְלֵם: (בט\"ר צת\"ג)"}, {"kind": "text", "text": "חֲסִין קָדוֹשׁ. בְּרֹב טֽוּבְךָֽ. נַהֵל עֲדָתֶֽךָ: (חק\"ב טנ\"ע)"}, {"kind": "text", "text": "יָחִיד גֵּאֶה. לְעַמְּךָ פְנֵה. זֽוֹכְרֵֽי קְדֻשָּׁתֶֽךָ: (יג\"ל פז\"ק)"}, {"kind": "text", "text": "שַׁוְעָתֵֽנוּ קַבֵּל. וּשְׁמַע צַעֲקָתֵֽנוּ. יוֹדֵֽעַ תַּעֲלוּמוֹת: (שק\"ו צי\"ת)"}, {"kind": "instruction", "text": "ואומר בלחש"}, {"kind": "text", "text": "בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "<b>רִבּוֹן</b> הָעוֹלָמִים, אַתָּה צִוִיתָנוּ לְהַקְרִיב קָרְבַּן הַתָּמִיד בְּמוֹעֲדוֹ, וְלִהְיוֹת כֹּהֲנִים בַּעֲבוֹדָתָם, וּלְוִיִּם בְּדוּכָנָם, וְיִשְׂרָאֵל בְּמַעֲמָדָם. וְעַתָּה בַּעֲווֹנוֹתֵינוּ חָרַב בֵּית הַמִּקְדָּשׁ וּבֻטַּל הַתָּמִיד, וְאֵין לָנוּ לֹא כֹּהֵן בַּעֲבוֹדָתוֹ וְלֹא לֵוִי בְּדוּכָנוֹ, וְלֹא יִשְׂרָאֵל בְּמַעֲמָדוֹ, וְאַתָּה אָמַרְתָּ: וּֽנְשַׁלְּמָ֥ה פָרִ֖ים שְׂפָתֵֽינוּ:"}, {"kind": "text", "text": "<b>לָכֵן</b> יְהִי רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁיְּהֵא שִׂיחַ שִׂפְתוֹתֵינוּ זֶה חָשׁוּב וּמְקֻבָּל וּמְרוּצֶה לְפָנֶיךָ כְּאִילוּ הִקְרַבְנוּ קָרְבַּן הַתָּמִיד בְּמוֹעֲדוֹ וְעָמַדְנוּ עַל מַעֲמָדוֹ, כְּמוֹ שֶׁנֶּאֱמַר: וּֽנְשַׁלְּמָ֥ה פָרִ֖ים שְׂפָתֵֽינוּ׃ וְנֶאֱמַר: וְשָׁחַ֨ט אֹת֜וֹ עַ֣ל יֶ֧רֶךְ הַמִּזְבֵּ֛חַ צָפֹ֖נָה לִפְנֵ֣י יְהֹוָ֑ה וְזָרְק֡וּ בְּנֵי֩ אַהֲרֹ֨ן הַכֹּהֲנִ֧ים אֶת־דָּמ֛וֹ עַל־הַמִּזְבֵּ֖חַ סָבִֽיב: וְנֶאֱמַר: זֹ֣את הַתּוֹרָ֗ה לָֽעֹלָה֙ לַמִּנְחָ֔ה וְלַֽחַטָּ֖את וְלָאָשָׁ֑ם וְלַ֨מִּלּוּאִ֔ים וּלְזֶ֖בַח הַשְּׁלָמִֽים:"}, {"kind": "text", "text": "<b>אֵיזֶהוּ</b> מְקוֹמָן שֶׁל זְבָחִים, קָדְשִׁי קָדָשִׁים שְׁחִיטָתָן בַּצָּפוֹן, פַּר וְשָׂעִיר שֶׁל יוֹם הַכִּפּוּרִים שְׁחִיטָתָן בַּצָּפון, וְקִבּוּל דָּמָן בִּכְלֵי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן הַזָּיָה עַל בֵּין הַבַּדִּים וְעַל הַפָּרֹכֶת וְעַל מִזְבַּח הַזָּהָב. מַתָּנָה אַחַת מֵהֶן מְעַכֶּבֶת. שִׁיְּירֵי הַדָּם הָיָה שׁוֹפֵךְ עַל יְסוֹד מַעֲרָבִי שֶׁל מִזְבֵּחַ הַחִיצוֹן. אִם לֹא נָתַן, לֹא עִכֵּב:"}, {"kind": "text", "text": "<b>פָּרִים</b> הַנִּשְׂרָפִים וּשְׂעִירִים הַנִּשְׂרָפִים שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלֵי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן הַזָּיָה עַל הַפָּרֹכֶת וְעַל מִזְבַּח הַזָּהָב. מַתָּנָה אַחַת מֵהֶן מְעַכֶּבֶת. שִׁיְרֵי הַדָּם הָיָה שׁוֹפֵךְ עַל יְסוֹד מַעֲרָבִי שֶׁל מִזְבַּח הַחִיצוֹן. אִם לֹא נָתַן, לֹא עִכֵּב. אֵלּוּ וְאֵלּוּ נִשְׂרָפִין בְּבֵית הַדָּשֶׁן:"}, {"kind": "text", "text": "<b>חַטֹּאת</b> הַצִּבּוּר וְהַיָּחִיד. אֵלּוּ הֵן חַטֹּאת הַצִּבּוּר, שְׂעִירֵי רָאשֵׁי חֳדָשִׁים וְשֶׁל מוֹעֲדוֹת, שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלֵי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן אַרְבַּע מַתָּנוֹת עַל אַרְבַּע קְרָנוֹת, כֵּיצַד, עָלָה בַכֶּבֶשׁ וּפָנָה לַסּוֹבֵב, וּבָא לוֹ לְקֶרֶן דְּרוֹמִית מִזְרָחִית, מִזְרָחִית צְפוֹנִית, צְפוֹנִית מַעֲרָבִית, מַעֲרָבִית דְּרוֹמִית. שְׁיָרֵי הַדָּם הָיָה שׁוֹפֵךְ עַל יְסוֹד דְרוֹמִי, וְנֶאֱכָלִין לִפָנִים מִן הַקְּלָעִים לְזִכְרֵי כְהֻנָּה בְּכָל מַאֲכָל לְיוֹם וָלַיְלָה עַד חֲצוֹת:"}, {"kind": "text", "text": "<b>הָעוֹלָה</b>, קֹדֶשׁ קָדָשִׁים, שְׁחִיטָתָהּ בַּצָּפוֹן, וְקִבּוּל דָּמָהּ בִּכְלֵי שָׁרֵת בַּצָּפוֹן, וְדָמָהּ טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וּטְעוּנָה הֶפְשֵׁט וְנִתּוּחַ וְכָלִיל לָאִשִּׁים:"}, {"kind": "text", "text": "<b>זִבְחֵי</b> שַׁלְמֵי צִבּוּר וַאֲשָׁמוֹת. אֵלּוּ הֵן אֲשָׁמוֹת, אָשָׁם גְּזֵלוֹת, אָשָׁם מְעִילוֹת, אָשָׁם שִׁפְחָה חֲרוּפָה, אָשָׁם נָזִיר, אָשָׁם מְצוֹרָע, אָשָׁם תָּלוּי, שְׁחִיטָתָן בַּצָּפוֹן, וְקִבּוּל דָּמָן בִּכְלִי שָׁרֵת בַּצָּפוֹן, וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וְנֶאֱכָלִין לְפָנִים מִן הַקְּלָעִים לְזִכְרֵי כְהֻנָּה בְּכָל מַאֲכָל לְיוֹם וָלַיְלָה עַד חֲצוֹת:"}, {"kind": "text", "text": "<b>הַתּוֹדָה</b> וְאֵיל נָזִיר, קָדָשִׁים קַלִּים, שְׁחִיטָתָן בְּכָל מָקוֹם בָּעֲזָרָה, וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וְנֶאֱכָלִין בְּכָל הָעִיר, לְכָל אָדָם, בְּכָל מַאֲכָל, לְיוֹם וָלַיְלָה עַד חֲצוֹת. הַמּוּרָם מֵהֶם כַּיּוֹצֵא בָהֶם, אֶלָּא שֶׁהַמּוּרָם נֶאֱכָל לַכֹּהֲנִים לִנְשֵׁיהֶם וְלִבְנֵיהֶם וּלְעַבְדֵיהֶם:"}, {"kind": "text", "text": "<b>שְׁלָמִים</b>, קָדָשִׁים קַלִּים, שְׁחִיטָתָן בְּכָל מָקוֹם בָּעֲזָרָה, וְדָמָן טָעוּן שְׁתֵּי מַתָּנוֹת שֶׁהֵן אַרְבַּע, וְנֶאֱכָלִין בְּכָל הָעִיר לְכָל אָדָם בְּכָל מַאֲכָל לִשְׁנֵי יָמִים וָלַיְלָה אֶחָד. הַמּוּרָם מֵהֶם כַּיּוֹצֵא בָּהֶם, אֶלָּא שֶׁהַמּוּרָם נֶאֱכָל לַכֹּהֲנִים, לִנְשֵׁיהֶם וְלִבְנֵיהֶם וּלְעַבְדֵיהֶם:"}, {"kind": "text", "text": "<b>הַבְּכוֹר</b> וְהַמַּעֲשֵׂר וְהַפֶּסַח, קָדָשִׁים קַלִּים, שְׁחִיטָתָן בְּכָל מָקוֹם בָּעֲזָרָה, וְדָמָן טָעוּן מַתָּנָה אַחַת, וּבִלְבָד שֶׁיִּתֵּן כְּנֶגֶד הַיְסוֹד. שִׁנָּה בַאֲכִילָתָן, הַבְּכוֹר נֶאֱכָל לַכֹּהֲנִים, וְהַמַּעֲשֵׂר לְכָל אָדָם, וְנֶאֱכָלִין בְּכָל הָעִיר בְּכָל מַאֲכָל לִשְׁנֵי יָמִים וָלַיְלָה אֶחָד. הַפֶּסַח אֵינוֹ נֶאֱכָל אֶלָּא בַלַּיְלָה, וְאֵינוֹ נֶאֱכָל אֶלָּא עַד חֲצוֹת, וְאֵינוֹ נֶאֱכָל אֶלָּא לִמְנוּיָו, וְאֵינוֹ נֶאֱכָל אֶלָּא צָלִי:"}, {"kind": "text", "text": "<b>רִבִּי</b> יִשְׁמָעֵאל אוֹמֵר: בִּשְׁלֹשׁ עֶשְׂרֵה מִדּוֹת הַתּוֹרָה נִדְרֶשֶׁת: מִקַּל וָחוֹמֶר, מִגְּזֵרָה שָׁוֶה, מִבִּנְיַן אָב וְכָתוּב אֶחָד, וּמִבִּנְיַן אָב וּשְׁנֵי כְתוּבִים, מִכְּלָל וּפְרָט, מִפְּרָט וּכְלָל, כְּלָל וּפְרָט וּכְלָל, אֵי אַתָּה דָן אֶלָּא כְּעֵין הַפְּרָט, מִכְּלָל שֶׁהוּא צָרִיךְ לִפְרָט, וּמִפְּרָט שֶׁהוּא צָרִיךְ לִכְלַל, וְכָל דָּבָר שֶׁהָיָה בִכְלָל וְיָצָא מִן הַכְּלָל לְלַמֵּד, לֹא לְלַמֵּד עַל עַצְמוֹ יָצָא, אֶלָּא לְלַמֵּד עַל הַכְּלָל כֻּלּוֹ יָצָא, וְכָל דָּבָר שֶׁהָיָה בִכְלָל, וְיָצָא לִטְעוֹן טָעוּן אַחֵר שֶׁהוּא כְעִנְיָנוֹ, יָצָא לְהָקֵל וְלֹא לְהַחְמִיר, וְכָל דָּבָר שֶׁהָיָה בִּכְלָל, וְיָצָא לִטְעֹן טָעוּן אַחֵר שֶׁלֹּא כְעִנְיָנוֹ, יָצָא לְהָקֵל וּלְהַחְמִיר, וְכָל דָּבָר שֶׁהָיָה בִּכְלָל, וְיָצָא לִדּוֹן בְּדָבָר חָדָשׁ, אֵי אַתָּה יָכוֹל לְהַחֲזִירוֹ לִכְלָלוֹ עַד שֶׁיַּחֲזִירֶנּוּ הַכָּתוּב לִכְלָלוֹ בְפֵירוּשׁ, וְדָבָר הַלָּמֵד מֵעִנְיָנוֹ, וְדָבָר הַלָּמֵד מִסּוֹפוֹ, וְכַן שְׁנֵי כְתוּבִים הַמַּכְחִישִׁים זֶה אֶת זֶה, עַד שֶׁיָּבֹא הַכָּתוּב הַשְּׁלִישִׁי וְיַכְרִיעַ בְּנֵיהֶם:"}, {"kind": "text", "text": "<b>יְהוּדָה</b> בֶּן תֵּימָא אוֹמֵר, הֱוֵי עַז כַּנָּמֵר, וְקַל כַּנֶּשֶׁר, וְרָץ כַּצְּבִי, וְגִבּוֹר כַּאֲרִי לַעֲשׂוֹת רְצוֹן אָבִיךָ שֶׁבַּשָּׁמַיִם. הוּא הָיָה אוֹמֵר, עַז פָּנִים לַגֵּיהִנָּם, וּבוֹשֶׁת פָּנִים לְגַן עֵדֶן:"}, {"kind": "text", "text": "<b>יְהִי </b> רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ, לַעֲשׂוֹת חֻקֵּי רְצוֹנָךְ, וּלְעָבְדָךְ בְּלֵבָב שָׁלֵם:"}, {"kind": "instruction", "text": "ואומרים כאן קדיש \"על ישראל\""}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל־בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "עַל יִשְׂרָאֵל וְעַל רַבָּנָן. וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן. דְּעָסְקִין בְּאוֹרַיְתָא קַדִּשְׁתָּא. דִּי בְאַתְרָא הָדֵין וְדִי בְכָל אֲתַר וַאֲתַר. יְהֵא לָנָא וּלְהוֹן וּלְכוֹן חִנָּא וְחִסְדָּא וְרַחֲמֵי. מִן קֳדָם מָארֵי שְׁמַיָּא וְאַרְעָא וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>יְהֵא</b> שְׁלָמָא רַבָּא מִן שְׁמַיָּא. חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה. וְשֵׁיזָבָא וּרְפוּאָה וּגְאוּלָה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]<br><br><b>עוֹשֶׂה</b> שָׁלוֹם בִּמְרוֹמָיו. הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "header", "text": "הודו"}, {"kind": "text", "text": "<b>הוֹד֤וּ</b> לַֽיהֹוָה֙ קִרְא֣וּ בִשְׁמ֔וֹ הוֹדִ֥יעוּ בָעַמִּ֖ים עֲלִילֹתָֽיו׃ שִׁ֤ירוּ לוֹ֙ זַמְּרוּ־ל֔וֹ שִׂ֖יחוּ בְּכׇל־נִפְלְאֹתָֽיו׃ הִֽתְהַלְלוּ֙ בְּשֵׁ֣ם קׇדְשׁ֔וֹ יִשְׂמַ֕ח לֵ֖ב מְבַקְשֵׁ֥י יְהֹוָֽה׃ דִּרְשׁ֤וּ יְהֹוָה֙ וְעֻזּ֔וֹ בַּקְּשׁ֥וּ פָנָ֖יו תָּמִֽיד׃ זִכְר֗וּ נִפְלְאֹתָיו֙ אֲשֶׁ֣ר עָשָׂ֔ה מֹפְתָ֖יו וּמִשְׁפְּטֵי־פִֽיהוּ׃ זֶ֚רַע יִשְׂרָאֵ֣ל עַבְדּ֔וֹ בְּנֵ֥י יַעֲקֹ֖ב בְּחִירָֽיו: ה֚וּא יְהֹוָ֣ה אֱלֹהֵ֔ינוּ בְּכׇל־הָאָ֖רֶץ מִשְׁפָּטָֽיו׃ זִכְר֤וּ לְעוֹלָם֙ בְּרִית֔וֹ דָּבָ֥ר צִוָּ֖ה לְאֶ֥לֶף דּֽוֹר׃ אֲשֶׁ֤ר כָּרַת֙ אֶת־אַבְרָהָ֔ם וּשְׁבוּעָת֖וֹ לְיִצְחָֽק׃ וַיַּעֲמִידֶ֤הָ לְיַֽעֲקֹב֙ לְחֹ֔ק לְיִשְׂרָאֵ֖ל בְּרִ֥ית עוֹלָֽם׃ לֵאמֹ֗ר לְךָ֙ אֶתֵּ֣ן אֶֽרֶץ־כְּנָ֔עַן חֶ֖בֶל נַחֲלַתְכֶֽם׃ בִּהְיֽוֹתְכֶם֙ מְתֵ֣י מִסְפָּ֔ר כִּמְעַ֖ט וְגָרִ֥ים בָּֽהּ׃ וַיִּֽתְהַלְּכוּ֙ מִגּ֣וֹי אֶל־גּ֔וֹי וּמִמַּמְלָכָ֖ה אֶל־עַ֥ם אַחֵֽר׃ לֹֽא־הִנִּ֤יחַ לְאִישׁ֙ לְעׇשְׁקָ֔ם וַיּ֥וֹכַח עֲלֵיהֶ֖ם מְלָכִֽים׃ אַֽל־תִּגְּעוּ֙ בִּמְשִׁיחָ֔י וּבִנְבִיאַ֖י אַל־תָּרֵֽעוּ׃"}, {"kind": "text", "text": "<b>שִׁ֤ירוּ</b> לַֽיהֹוָה֙ כׇּל־הָאָ֔רֶץ בַּשְּׂר֥וּ מִיּֽוֹם־אֶל־י֖וֹם יְשׁוּעָתֽוֹ׃ סַפְּר֤וּ בַגּוֹיִם֙ אֶת־כְּבוֹד֔וֹ בְּכׇל־הָעַמִּ֖ים נִפְלְאֹתָֽיו׃ כִּי֩ גָד֨וֹל יְהֹוָ֤ה וּמְהֻלָּל֙ מְאֹ֔ד וְנוֹרָ֥א ה֖וּא עַל־כׇּל־אֱלֹהִֽים׃ כִּ֠י כׇּל־אֱלֹהֵ֤י הָֽעַמִּים֙ אֱלִילִ֔ים יפסיק מעט וַיהֹוָ֖ה שָׁמַ֥יִם עָשָֽׂה׃ ה֤וֹד וְהָדָר֙ לְפָנָ֔יו עֹ֥ז וְחֶדְוָ֖ה בִּמְקֹמֽוֹ׃ הָב֤וּ לַֽיהֹוָה֙ מִשְׁפְּח֣וֹת עַמִּ֔ים הָב֥וּ לַיהֹוָ֖ה כָּב֥וֹד וָעֹֽז׃ הָב֥וּ לַֽיהֹוָ֖ה כְּב֣וֹד שְׁמ֑וֹ שְׂא֤וּ מִנְחָה֙ וּבֹ֣אוּ לְפָנָ֔יו הִשְׁתַּחֲו֥וּ לַֽיהֹוָ֖ה בְּהַדְרַת־קֹֽדֶשׁ׃ חִ֤ילוּ מִלְּפָנָיו֙ כׇּל־הָאָ֔רֶץ אַף־תִּכּ֥וֹן תֵּבֵ֖ל בַּל־תִּמּֽוֹט׃ יִשְׂמְח֤וּ הַשָּׁמַ֙יִם֙ וְתָגֵ֣ל הָאָ֔רֶץ וְיֹאמְר֥וּ בַגּוֹיִ֖ם יְהֹוָ֥ה מָלָֽךְ׃ יִרְעַ֤ם הַיָּם֙ וּמְלוֹא֔וֹ יַעֲלֹ֥ץ הַשָּׂדֶ֖ה וְכׇל־אֲשֶׁר־בּֽוֹ׃ אָ֥ז יְרַנְּנ֖וּ עֲצֵ֣י הַיָּ֑עַר מִלִּפְנֵ֣י יְהֹוָ֔ה כִּי־בָ֖א לִשְׁפּ֥וֹט אֶת־הָאָֽרֶץ׃ הוֹד֤וּ לַֽיהֹוָה֙ כִּ֣י ט֔וֹב כִּ֥י לְעוֹלָ֖ם חַסְדּֽוֹ׃ וְאִמְר֕וּ הוֹשִׁיעֵ֙נוּ֙ אֱלֹהֵ֣י יִשְׁעֵ֔נוּ וְקַבְּצֵ֥נוּ וְהַצִּילֵ֖נוּ מִן־הַגּוֹיִ֑ם לְהֹדוֹת֙ לְשֵׁ֣ם קׇדְשֶׁ֔ךָ לְהִשְׁתַּבֵּ֖חַ בִּתְהִלָּתֶֽךָ׃ בָּר֤וּךְ יְהֹוָה֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל מִן־הָעוֹלָ֖ם וְעַ֣ד הָעֹלָ֑ם וַיֹּאמְר֤וּ כׇל־הָעָם֙ אָמֵ֔ן וְהַלֵּ֖ל לַיהֹוָֽה׃"}, {"kind": "text", "text": "<b>רוֹמְמ֡וּ</b> יְהֹ֘וָ֤ה אֱלֹהֵ֗ינוּ וְֽ֭הִשְׁתַּחֲווּ לַהֲדֹ֥ם רַגְלָ֗יו קָד֥וֹשׁ הֽוּא: רוֹמְמ֡וּ יְהֹ֘וָ֤ה אֱלֹהֵ֗ינוּ וְֽ֭הִשְׁתַּחֲווּ לְהַ֣ר קׇדְשׁ֑וֹ כִּי־קָ֝ד֗וֹשׁ יְהֹוָ֥ה אֱלֹהֵֽינוּ: וְה֤וּא רַח֨וּם ׀ יְכַפֵּ֥ר עָוֺן֮ וְֽלֹא־יַֽ֫שְׁחִ֥ית וְ֭הִרְבָּה לְהָשִׁ֣יב אַפּ֑וֹ וְלֹא־יָ֝עִ֗יר כׇּל־חֲמָתֽוֹ׃ אַתָּ֤ה יְהֹוָ֗ה לֹֽא־תִכְלָ֣א רַחֲמֶ֣יךָ מִמֶּ֑נִּי חַסְדְּךָ֥ וַ֝אֲמִתְּךָ֗ תָּמִ֥יד יִצְּרֽוּנִי: זְכֹר־רַחֲמֶ֣יךָ יְ֭הֹוָה וַחֲסָדֶ֑יךָ כִּ֖י מֵעוֹלָ֣ם הֵֽמָּה: תְּנ֥וּ עֹ֗ז לֵאלֹ֫הִ֥ים עַֽל־יִשְׂרָאֵ֥ל גַּאֲוָת֑וֹ וְ֝עֻזּ֗וֹ בַּשְּׁחָקִֽים: נ֤וֹרָ֥א אֱלֹהִ֗ים מִֽמִּקְדָּ֫שֶׁ֥יךָ אֵ֤ל יִשְׂרָאֵ֗ל ה֤וּא נֹתֵ֨ן ׀ עֹ֖ז וְתַעֲצֻמ֥וֹת לָעָ֗ם בָּר֥וּךְ אֱלֹהִֽים:"}, {"kind": "text", "text": "<b>אֵל־נְקָמ֥וֹת</b> יְהֹוָ֑ה אֵ֖ל נְקָמ֣וֹת הוֹפִֽיעַ: הִ֭נָּשֵׂא שֹׁפֵ֣ט הָאָ֑רֶץ הָשֵׁ֥ב גְּ֝מ֗וּל עַל־גֵּאִֽים: לַֽיהֹוָ֥ה הַיְשׁוּעָ֑ה עַֽל־עַמְּךָ֖ בִרְכָתֶ֣ךָ סֶּֽלָה: יְהֹוָ֣ה צְבָא֣וֹת עִמָּ֑נוּ מִשְׂגָּֽב־לָ֨נוּ אֱלֹהֵ֖י יַֽעֲקֹ֣ב סֶֽלָה׃ יְהֹוָ֥ה צְבָא֑וֹת אַֽשְׁרֵ֥י אָ֝דָ֗ם בֹּטֵ֥חַ בָּֽךְ׃ יְהֹוָ֥ה הוֹשִׁ֑יעָה הַ֝מֶּ֗לֶךְ יַעֲנֵ֥נוּ בְיוֹם־קׇרְאֵֽנוּ: הוֹשִׁ֤יעָה ׀ אֶת־עַמֶּ֗ךָ וּבָרֵ֥ךְ אֶת־נַחֲלָתֶ֑ךָ וּֽרְעֵ֥ם וְ֝נַשְּׂאֵ֗ם עַד־הָעוֹלָֽם: נַ֭פְשֵׁנוּ חִכְּתָ֣ה לַֽיהֹוָ֑ה עֶזְרֵ֖נוּ וּמָגִנֵּ֣נוּ הֽוּא: כִּי־ב֭וֹ יִשְׂמַ֣ח לִבֵּ֑נוּ כִּ֤י בְשֵׁ֖ם קׇדְשׁ֣וֹ בָטָֽחְנוּ: יְהִי־חַסְדְּךָ֣ יְהֹוָ֣ה עָלֵ֑ינוּ כַּ֝אֲשֶׁ֗ר יִחַ֥לְנוּ לָֽךְ: הַרְאֵ֣נוּ יְהֹוָ֣ה חַסְדֶּ֑ךָ וְ֝יֶשְׁעֲךָ֗ תִּתֶּן־לָֽנוּ: ק֭וּמָֽה עֶזְרָ֣תָה לָּ֑נוּ וּ֝פְדֵ֗נוּ לְמַ֣עַן חַסְדֶּֽךָ: אָֽנֹכִ֨י ׀ יְהֹ֘וָ֤ה אֱלֹהֶ֗יךָ הַֽ֭מַּעַלְךָ מֵאֶ֣רֶץ מִצְרָ֑יִם הַרְחֶב־פִּ֗֝יךָ וַאֲמַלְאֵֽהוּ: אַשְׁרֵ֣י הָ֭עָם שֶׁכָּ֣כָה לּ֑וֹ אַֽשְׁרֵ֥י הָ֝עָ֗ם שֱׁיְהֹוָ֥ה אֱלֹהָֽיו: וַאֲנִ֤י ׀ בְּחַסְדְּךָ֣ בָטַחְתִּי֮ יָ֤גֵ֥ל לִבִּ֗י בִּֽישׁוּעָ֫תֶ֥ךָ אָשִׁ֥ירָה לַֽיהֹוָ֑ה כִּ֖י גָמַ֣ל עָלָֽי:"}, {"kind": "text", "text": "<b>אֲרוֹמִמְךָ֣</b> יְ֭הֹוָה כִּ֣י דִלִּיתָ֑נִי וְלֹֽא־שִׂמַּ֖חְתָּ אֹיְבַ֣י לִֽי׃ יְהֹוָ֥ה אֱלֹהָ֑י שִׁוַּ֥עְתִּי אֵ֝לֶ֗יךָ וַתִּרְפָּאֵֽנִי׃ יְֽהֹוָ֗ה הֶעֱלִ֣יתָ מִן־שְׁא֣וֹל נַפְשִׁ֑י חִ֝יִּיתַ֗נִי מיורדי [מִיׇּֽרְדִי]־בֽוֹר׃ זַמְּר֣וּ לַיהֹוָ֣ה חֲסִידָ֑יו וְ֝הוֹד֗וּ לְזֵ֣כֶר קׇדְשֽׁוֹ׃ כִּ֤י רֶ֨גַע ׀ בְּאַפּוֹ֮ חַיִּ֢ים בִּרְצ֫וֹנ֥וֹ בָּ֭עֶרֶב יָלִ֥ין בֶּ֗כִי וְלַבֹּ֥קֶר רִנָּֽה׃ וַ֭אֲנִי אָמַ֣רְתִּי בְשַׁלְוִ֑י בַּל־אֶמּ֥וֹט לְעוֹלָֽם׃ יְֽהֹוָ֗ה בִּרְצוֹנְךָ֮ הֶעֱמַ֢דְתָּה לְֽהַרְרִ֫י עֹ֥ז הִסְתַּ֥רְתָּ פָנֶ֗יךָ הָיִ֥יתִי נִבְהָֽל׃ אֵלֶ֣יךָ יְהֹוָ֣ה אֶקְרָ֑א וְאֶל־אֲ֝דֹנָ֗י אֶתְחַנָּֽן׃ מַה־בֶּ֥צַע בְּדָמִי֮ בְּרִדְתִּ֢י אֶ֫ל שָׁ֥חַת הֲיוֹדְךָ֥ עָפָ֑ר הֲיַגִּ֥יד אֲמִתֶּֽךָ׃ שְׁמַע־יְהֹוָ֥ה וְחׇנֵּ֑נִי יְ֝הֹוָ֗ה הֱֽיֵה־עֹזֵ֥ר לִֽי׃ הָפַ֣כְתָּ מִסְפְּדִי֮ לְמָח֢וֹל לִ֥י פִּתַּ֥חְתָּ שַׂקִּ֑י וַֽתְּאַזְּרֵ֥נִי שִׂמְחָֽה׃ לְמַ֤עַן ׀ יְזַמֶּרְךָ֣ כָ֭בוֹד וְלֹ֣א יִדֹּ֑ם יְהֹוָ֥ה אֱ֝לֹהַ֗י לְעוֹלָ֥ם אוֹדֶֽךָּ:"}, {"kind": "instruction", "text": "בעשרת ימי תשובה והושענא רבה אומרים"}, {"kind": "instruction", "text": "יְהֹוָה֙ ה֣וּא הָאֱלֹהִ֔ים יְהֹוָ֖ה ה֥וּא הָאֱלֹהִֽים׃ שתי פעמים"}, {"kind": "instruction", "text": "עומדים ואומרים (בא\"ח ויגש ה\"ב)"}, {"kind": "text", "text": "<b>יְהֹוָה מֶֽלֶךְ, יְהֹוָה מָלָֽךְ יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד:</b> שתי פעמים"}, {"kind": "text", "text": "<b>וְהָיָ֧ה</b> יְהֹוָ֛ה לְמֶ֖לֶךְ עַל־כׇּל־הָאָ֑רֶץ בַּיּ֣וֹם הַה֗וּא יִהְיֶ֧ה יְהֹוָ֛ה אֶחָ֖ד וּשְׁמ֥וֹ אֶחָֽד:"}, {"kind": "text", "text": "<b>הוֹשִׁיעֵ֨נוּ</b> ׀ יְהֹ֘וָ֤ה אֱלֹהֵ֗ינוּ וְקַבְּצֵנוּ֮ מִֽן־הַגּ֫וֹיִ֥ם לְ֭הֹדוֹת לְשֵׁ֣ם קׇדְשֶׁ֑ךָ לְ֝הִשְׁתַּבֵּ֗חַ בִּתְהִלָּתֶֽךָ: בָּ֤רֽוּךְ יְהֹוָ֨ה אֱלֹהֵ֪י יִשְׂרָאֵ֡ל מִן־הָ֤עוֹלָ֨ם ׀ וְעַ֬ד הָעוֹלָ֗ם וְאָמַ֖ר כׇּל־הָעָ֥ם אָמֵ֗ן הַֽלְלוּיָֽהּ: כֹּ֣ל הַ֭נְּשָׁמָה תְּהַלֵּ֥ל יָ֗הּ הַֽלְלוּיָֽהּ:"}, {"kind": "instruction", "text": "בשבת ממשיכים מזמור השמים מספרים"}, {"kind": "instruction", "text": "טוב לומר מזמור אלהים יחננו ויברכנו בצורת המנורה (בא\"ח ויגש ה\"ד)"}, {"kind": "text", "text": "<b>לַמְנַצֵּ֥חַ</b> (תהילים ס״ז:א׳-ג׳) בִּנְגִינֹ֗ת מִזְמ֥וֹר שִֽׁיר׃ אֱֽלֹהִ֗ים יְחׇנֵּ֥נוּ וִיבָרְכֵ֑נוּ יָ֤אֵֽר פָּנָ֖יו אִתָּ֣נוּ סֶֽלָה׃ לָדַ֣עַת בָּאָ֣רֶץ דַּרְכֶּ֑ךָ בְּכׇל־גּ֝וֹיִ֗ם יְשׁוּעָתֶֽךָ׃ יוֹד֖וּךָ עַמִּ֥ים ׀ אֱלֹהִ֑ים י֝וֹד֗וּךָ עַמִּ֥ים כֻּלָּֽם׃ יִ֥שְׂמְח֥וּ וִירַנְּנ֗וּ לְאֻ֫מִּ֥ים כִּֽי־תִשְׁפֹּ֣ט עַמִּ֣ים מִישֹׁ֑ר וּלְאֻמִּ֓ים ׀ בָּאָ֖רֶץ תַּנְחֵ֣ם סֶֽלָה׃ יוֹד֖וּךָ עַמִּ֥ים ׀ אֱלֹהִ֑ים י֝וֹד֗וּךָ עַמִּ֥ים כֻּלָּֽם׃ אֶ֭רֶץ נָתְנָ֣ה יְבוּלָ֑הּ יְ֝בָרְכֵ֗נוּ אֱלֹהִ֥ים אֱלֹהֵֽינוּ׃ יְבָרְכֵ֥נוּ אֱלֹהִ֑ים וְיִֽירְא֥וּ א֝וֹת֗וֹ כׇּל־אַפְסֵי־אָֽרֶץ׃"}, {"kind": "header", "text": "פסוקי דזמרה"}, {"kind": "text", "text": "כיון שהתחיל לומר ברוך שאמר, יאחוז הציציות של שתי כנפות שכנגד פניו, וישארו בידו עד סוף ברוך שאמר, ואז ינשקם ויניחם (בא\"ח ויגש ה\"ז)<br><b>בָּרוּךְ שֶׁאָמַר</b> וְהָיָה הָעוֹלָם, בָּרוּךְ הוּא, בָּרוּךְ אוֹמֵר וְעוֹשֶׂה, בָּרוּךְ גּוֹזֵר וּמְקַיֵּם, בָּרוּךְ עוֹשֶׂה בְרֵאשִׁית, בָּרוּךְ מְרַחֵם עַל הָאָרֶץ, בָּרוּךְ מְרַחֵם עַל הַבְּרִיּוֹת, בָּרוּךְ מְשַׁלֵּם שָׂכָר טוֹב לִירֵאָיו, בָּרוּךְ חַי לָעַד וְקַיָּם לָנֶצַח, בָּרוּךְ פּוֹדֶה וּמַצִּיל, בָּרוּךְ שְׁמוֹ. בָּרוּךְ אַתָּה יְהֹוָה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָאֵל, אָב הָרַחֲמָן, הַמְהֻלָּל בְּפֶה עַמּוֹ, מְשֻׁבָּח וּמְפֹאָר בִּלְשׁוֹן חֲסִידָיו וַעֲבָדָיו, וּבְשִׁירֵי דָּוִד עַבְדָּךְ נְהַלְלָךְ יְהֹוָה אֱלֹהֵינוּ בִּשְׁבָחוֹת וּבִזְמִירוֹת, וּנְגַדְּלָךְ וּנְשַׁבְּחָךְ וּנְפָאֲרָךְ וְנַמְלִיכָךְ, וְנַזְכִּיר שִׁמְךָ מַלְכֵּנוּ אֱלֹהֵינוּ, יָחִיד חַי הָעוֹלָמִים, מֶלֶךְ מְשֻׁבָּח וּמְפֹאָר עֲדֵי עַד שְׁמוֹ הַגָּדוֹל. בָּרוּךְ אַתָּה יְהֹוָה, מֶלֶךְ מְהֻלָּל בַּתִּשְׁבָּחוֹת:<br>אם סיים האדם ברוך שאמר קודם שסיים החזן, יזדרז לומר תיכף מזמור לתודה, ויענה אמן על ברכת החזן (בא\"ח ויגש ה\"ח)"}, {"kind": "text", "text": "<b>מִזְמ֥וֹר</b> (תהילים ק׳:א׳-ב׳) לְתוֹדָ֑ה הָרִ֥יעוּ לַ֝יהֹוָ֗ה כׇּל־הָאָֽרֶץ׃ עִבְד֣וּ אֶת־יְהֹוָ֣ה בְּשִׂמְחָ֑ה בֹּ֥אוּ לְ֝פָנָ֗יו בִּרְנָנָֽה׃ דְּע֗וּ כִּֽי־יְהֹוָה֮ ה֤וּא אֱלֹ֫הִ֥ים הֽוּא־עָ֭שָׂנוּ ולא [וְל֣וֹ] אֲנַ֑חְנוּ עַ֝מּ֗וֹ וְצֹ֣אן מַרְעִיתֽוֹ׃ בֹּ֤אוּ שְׁעָרָ֨יו ׀ בְּתוֹדָ֗ה חֲצֵרֹתָ֥יו בִּתְהִלָּ֑ה הוֹדוּ־ל֗֝וֹ בָּרְכ֥וּ שְׁמֽוֹ׃ כִּי־ט֣וֹב יְ֭הֹוָה לְעוֹלָ֣ם חַסְדּ֑וֹ וְעַד־דֹּ֥ר וָ֝דֹ֗ר אֱמוּנָתֽוֹ׃"}, {"kind": "instruction", "text": "שמונה עשרה פסוקים של יהי כבוד, כנגד שמונה עשרה אותיות של ששה צרופי שד\"י (בא\"ח ויגש הי\"א)"}, {"kind": "text", "text": "ש <b>יְהִ֤י כְב֣וֹד</b> יְהֹוָ֣ה לְעוֹלָ֑ם יִשְׂמַ֖ח יְהֹוָ֣ה בְּמַעֲשָֽׂיו: ד יְהִ֤י שֵׁ֣ם יְהֹוָ֣ה מְבֹרָ֑ךְ מֵ֝עַתָּ֗ה וְעַד־עוֹלָֽם: י מִמִּזְרַח־שֶׁ֥מֶשׁ עַד־מְבוֹא֑וֹ מְ֝הֻלָּ֗ל שֵׁ֣ם יְהֹוָֽה: ש רָ֖ם עַל־כָּל־גּוֹיִ֥ם ׀ יְהֹוָ֑ה עַ֖ל הַשָּׁמַ֣יִם כְּבוֹדֽוֹ: י יְ֭הֹוָה שִׁמְךָ֣ לְעוֹלָ֑ם יְ֝הֹוָ֗ה זִכְרְךָ֥ לְדֹר־וָדֹֽר: ד יְֽהֹוָ֗ה בַּ֭שָּׁמַיִם הֵכִ֣ין כִּסְא֑וֹ וּ֝מַלְכוּת֗וֹ בַּכֹּ֥ל מָשָֽׁלָה: ד יִשְׂמְח֤וּ הַשָּׁמַ֙יִם֙ וְתָגֵ֣ל הָאָ֔רֶץ וְיֹאמְר֥וּ בַגּוֹיִ֖ם יְהֹוָ֥ה מָלָֽךְ: ש יְהֹוָה מֶֽלֶךְ, יְהֹוָה מָלָֽךְ, יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד: י יְהֹוָ֣ה מֶ֭לֶךְ עוֹלָ֣ם וָעֶ֑ד אָבְד֥וּ ג֝וֹיִ֗ם מֵאַרְצֽוֹ: ד יְֽהֹוָ֗ה הֵפִ֥יר עֲצַת־גּוֹיִ֑ם הֵ֝נִ֗יא מַחְשְׁב֥וֹת עַמִּֽים: י רַבּ֣וֹת מַחֲשָׁב֣וֹת בְּלֶב־אִ֑ישׁ וַעֲצַ֥ת יְ֝הֹוָ֗ה הִ֣יא תָקֽוּם: ש עֲצַ֣ת יְ֭הֹוָה לְעוֹלָ֣ם תַּעֲמֹ֑ד מַחְשְׁב֥וֹת לִ֝בּ֗וֹ לְדֹ֣ר וָדֹֽר: י כִּ֤י ה֣וּא אָמַ֣ר וַיֶּ֑הִי הֽוּא־צִ֝וָּ֗ה וַֽיַּעֲמֹֽד: ש כִּי־בָחַ֣ר יְהֹוָ֣ה בְּצִיּ֑וֹן אִ֝וָּ֗הּ לְמוֹשָׁ֥ב לֽוֹ: ד כִּֽי־יַעֲקֹ֗ב בָּחַ֣ר ל֣וֹ יָ֑הּ יִ֝שְׂרָאֵ֗ל לִסְגֻלָּתֽוֹ: י כִּ֤י ׀ לֹא־יִטֹּ֣שׁ יְהֹוָ֣ה עַמּ֑וֹ וְ֝נַחֲלָת֗וֹ לֹ֣א יַעֲזֹֽב: ד וְה֤וּא רַח֨וּם ׀ יְכַפֵּ֥ר עָוֺן֮ וְֽלֹא־יַֽ֫שְׁחִ֥ית וְ֭הִרְבָּה לְהָשִׁ֣יב אַפּ֑וֹ וְלֹא־יָ֝עִ֗יר כׇּל־חֲמָתֽוֹ: ש יְהֹוָ֥ה הוֹשִׁ֑יעָה הַ֝מֶּ֗לֶךְ יַעֲנֵ֥נוּ בְיוֹם־קׇרְאֵֽנוּ:"}, {"kind": "text", "text": "<b>אַ֭שְׁרֵי</b> יוֹשְׁבֵ֣י בֵיתֶ֑ךָ ע֝֗וֹד יְֽהַלְל֥וּךָ סֶּֽלָה: אַשְׁרֵ֣י הָ֭עָם שֶׁכָּ֣כָה לּ֑וֹ אַֽשְׁרֵ֥י הָ֝עָ֗ם שֱׁיְהֹוָ֥ה אֱלֹהָֽיו:"}, {"kind": "text", "text": "<b>תְּהִלָּ֗ה לְדָ֫וִ֥ד</b> (תהילים קמ״ה:א׳-ב׳) אֲרוֹמִמְךָ֣ אֱלוֹהַ֣י הַמֶּ֑לֶךְ וַאֲבָרְכָ֥ה שִׁ֝מְךָ֗ לְעוֹלָ֥ם וָעֶֽד׃ בְּכָל־י֥וֹם אֲבָֽרְכֶ֑ךָּ וַאֲהַֽלְלָ֥ה שִׁ֝מְךָ֗ לְעוֹלָ֥ם וָעֶֽד׃ גָּ֘ד֤וֹל יְהֹוָ֣ה וּמְהֻלָּ֣ל מְאֹ֑ד וְ֝לִגְדֻלָּת֗וֹ אֵ֣ין חֵֽקֶר׃ דּ֣וֹר לְ֭דוֹר יְשַׁבַּ֣ח מַעֲשֶׂ֑יךָ וּגְב֖וּרֹתֶ֣יךָ יַגִּֽידוּ׃ הֲ֭דַר כְּב֣וֹד הוֹדֶ֑ךָ וְדִבְרֵ֖י נִפְלְאֹתֶ֣יךָ אָשִֽׂיחָה׃ וֶעֱז֣וּז נֽוֹרְאֹתֶ֣יךָ יֹאמֵ֑רוּ וגדלותיך [וּגְדֻלָּתְךָ֥] אֲסַפְּרֶֽנָּה׃ זֵ֣כֶר רַב־טוּבְךָ֣ יַבִּ֑יעוּ וְצִדְקָתְךָ֥ יְרַנֵּֽנוּ׃ חַנּ֣וּן וְרַח֣וּם יְהֹוָ֑ה אֶ֥רֶךְ אַ֝פַּ֗יִם וּגְדׇל־חָֽסֶד׃ טוֹב־יְהֹוָ֥ה לַכֹּ֑ל וְ֝רַחֲמָ֗יו עַל־כׇּל־מַעֲשָֽׂיו׃ יוֹד֣וּךָ יְ֭הֹוָה כׇּל־מַעֲשֶׂ֑יךָ וַ֝חֲסִידֶ֗יךָ יְבָרְכֽוּכָה׃ כְּב֣וֹד מַלְכוּתְךָ֣ יֹאמֵ֑רוּ וּגְבוּרָתְךָ֥ יְדַבֵּֽרוּ׃ לְהוֹדִ֤יעַ ׀ לִבְנֵ֣י הָ֭אָדָם גְּבוּרֹתָ֑יו וּ֝כְב֗וֹד הֲדַ֣ר מַלְכוּתֽוֹ׃ מַֽלְכוּתְךָ֗ מַלְכ֥וּת כׇּל־עֹלָמִ֑ים וּ֝מֶֽמְשַׁלְתְּךָ֗ בְּכׇל־דּ֥וֹר וָדֹֽר׃ סוֹמֵ֣ךְ יְ֭הֹוָה לְכׇל־הַנֹּפְלִ֑ים וְ֝זוֹקֵ֗ף לְכׇל־הַכְּפוּפִֽים׃ עֵֽינֵי־כֹ֭ל אֵלֶ֣יךָ יְשַׂבֵּ֑רוּ וְאַתָּ֤ה נֽוֹתֵן־לָהֶ֖ם אֶת־אׇכְלָ֣ם בְּעִתּֽוֹ׃ פּוֹתֵ֥חַ אֶת־יָדֶ֑ךָ וּמַשְׂבִּ֖יעַ לְכׇל־חַ֣י רָצֽוֹן׃ צַדִּ֣יק יְ֭הֹוָה בְּכׇל־דְּרָכָ֑יו וְ֝חָסִ֗יד בְּכׇל־מַעֲשָֽׂיו׃ קָר֣וֹב יְ֭הֹוָה לְכׇל־קֹרְאָ֑יו לְכֹ֤ל אֲשֶׁ֖ר יִקְרָאֻ֣הוּ בֶֽאֱמֶֽת׃ רְצוֹן־יְרֵאָ֥יו יַעֲשֶׂ֑ה וְֽאֶת־שַׁוְעָתָ֥ם יִ֝שְׁמַ֗ע וְיוֹשִׁיעֵֽם׃ שׁוֹמֵ֣ר יְ֭הֹוָה אֶת־כׇּל־אֹהֲבָ֑יו וְאֵ֖ת כׇּל־הָרְשָׁעִ֣ים יַשְׁמִֽיד׃ תְּהִלַּ֥ת יְהֹוָ֗ה יְֽדַבֶּ֫ר פִּ֥י וִיבָרֵ֣ךְ כׇּל־בָּ֭שָׂר שֵׁ֥ם קׇדְשׁ֗וֹ לְעוֹלָ֥ם וָעֶֽד׃ וַאֲנַ֤חְנוּ ׀ נְבָ֘רֵ֤ךְ יָ֗הּ מֵעַתָּ֥ה וְעַד־עוֹלָ֗ם הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>הַֽלְלוּיָ֡הּ</b> (תהילים קמ״ו:א׳-ג׳) הַֽלְלִ֥י נַ֝פְשִׁ֗י אֶת־יְהֹוָֽה׃ אֲהַלְלָ֣ה יְהֹוָ֣ה בְּחַיָּ֑י אֲזַמְּרָ֖ה לֵאלֹהַ֣י בְּעוֹדִֽי׃ אַל־תִּבְטְח֥וּ בִנְדִיבִ֑ים בְּבֶן־אָדָ֓ם ׀ שֶׁ֤אֵ֖ין ל֥וֹ תְשׁוּעָֽה׃ תֵּצֵ֣א ר֭וּחוֹ יָשֻׁ֣ב לְאַדְמָת֑וֹ בַּיּ֥וֹם הַ֝ה֗וּא אָבְד֥וּ עֶשְׁתֹּֽנֹתָֽיו׃ אַשְׁרֵ֗י שֶׁ֤אֵ֣ל יַעֲקֹ֣ב בְּעֶזְר֑וֹ שִׂ֝בְר֗וֹ עַל־יְהֹוָ֥ה אֱלֹהָֽיו׃ עֹשֶׂ֤ה ׀ שָׁ֘מַ֤יִם וָאָ֗רֶץ אֶת־הַיָּ֥ם וְאֶת־כׇּל־אֲשֶׁר־בָּ֑ם הַשֹּׁמֵ֖ר אֱמֶ֣ת לְעוֹלָֽם׃ עֹשֶׂ֤ה מִשְׁפָּ֨ט ׀ לָעֲשׁוּקִ֗ים נֹתֵ֣ן לֶ֭חֶם לָרְעֵבִ֑ים יְ֝הֹוָ֗ה מַתִּ֥יר אֲסוּרִֽים׃ יְהֹוָ֤ה ׀ פֹּ֘קֵ֤חַ עִוְרִ֗ים יְ֭הֹוָה זֹקֵ֣ף כְּפוּפִ֑ים יְ֝הֹוָ֗ה אֹהֵ֥ב צַדִּיקִֽים׃ יְהֹוָ֤ה ׀ שֹׁ֘מֵ֤ר אֶת־גֵּרִ֗ים יָת֣וֹם וְאַלְמָנָ֣ה יְעוֹדֵ֑ד וְדֶ֖רֶךְ רְשָׁעִ֣ים יְעַוֵּֽת׃ יִמְלֹ֤ךְ יְהֹוָ֨ה ׀ לְעוֹלָ֗ם אֱלֹהַ֣יִךְ צִ֭יּוֹן לְדֹ֥ר וָדֹ֗ר הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>הַ֥לְלוּיָ֨הּ</b> ׀ (תהילים קמ״ז:א׳-ב׳) כִּי־ט֭וֹב זַמְּרָ֣ה אֱלֹהֵ֑ינוּ כִּי־נָ֝עִ֗ים נָאוָ֥ה תְהִלָּֽה׃ בּוֹנֵ֣ה יְרֽוּשָׁלַ֣‍ִם יְהֹוָ֑ה נִדְחֵ֖י יִשְׂרָאֵ֣ל יְכַנֵּֽס׃ הָ֭רֹפֵא לִשְׁב֣וּרֵי לֵ֑ב וּ֝מְחַבֵּ֗שׁ לְעַצְּבוֹתָֽם׃ מוֹנֶ֣ה מִ֭סְפָּר לַכּוֹכָבִ֑ים לְ֝כֻלָּ֗ם שֵׁמ֥וֹת יִקְרָֽא׃ גָּד֣וֹל אֲדוֹנֵ֣ינוּ וְרַב־כֹּ֑חַ לִ֝תְבוּנָת֗וֹ אֵ֣ין מִסְפָּֽר׃ מְעוֹדֵ֣ד עֲנָוִ֣ים יְהֹוָ֑ה מַשְׁפִּ֖יל רְשָׁעִ֣ים עֲדֵי־אָֽרֶץ׃ עֱנ֣וּ לַֽיהֹוָ֣ה בְּתוֹדָ֑ה זַמְּר֖וּ לֵאלֹהֵ֣ינוּ בְכִנּֽוֹר׃ הַֽמְכַסֶּ֬ה שָׁמַ֨יִם ׀ בְּעָבִ֗ים הַמֵּכִ֣ין לָאָ֣רֶץ מָטָ֑ר הַמַּצְמִ֖יחַ הָרִ֣ים חָצִֽיר׃ נוֹתֵ֣ן לִבְהֵמָ֣ה לַחְמָ֑הּ לִבְנֵ֥י עֹ֝רֵ֗ב אֲשֶׁ֣ר יִקְרָֽאוּ׃ לֹ֤א בִגְבוּרַ֣ת הַסּ֣וּס יֶחְפָּ֑ץ לֹא־בְשׁוֹקֵ֖י הָאִ֣ישׁ יִרְצֶֽה׃ רוֹצֶ֣ה יְ֭הֹוָה אֶת־יְרֵאָ֑יו אֶת־הַֽמְיַחֲלִ֥ים לְחַסְדּֽוֹ׃ שַׁבְּחִ֣י יְ֭רוּשָׁלַ‍ִם אֶת־יְהֹוָ֑ה הַֽלְלִ֖י אֱלֹהַ֣יִךְ צִיּֽוֹן׃ כִּֽי־חִ֭זַּק בְּרִיחֵ֣י שְׁעָרָ֑יִךְ בֵּרַ֖ךְ בָּנַ֣יִךְ בְּקִרְבֵּֽךְ׃ הַשָּׂם־גְּבוּלֵ֥ךְ שָׁל֑וֹם חֵ֥לֶב חִ֝טִּ֗ים יַשְׂבִּיעֵֽךְ׃ הַשֹּׁלֵ֣חַ אִמְרָת֣וֹ אָ֑רֶץ עַד־מְ֝הֵרָ֗ה יָר֥וּץ דְּבָרֽוֹ׃ הַנֹּתֵ֣ן שֶׁ֣לֶג כַּצָּ֑מֶר כְּ֝פ֗וֹר כָּאֵ֥פֶר יְפַזֵּֽר׃ מַשְׁלִ֣יךְ קַֽרְח֣וֹ כְפִתִּ֑ים לִפְנֵ֥י קָ֝רָת֗וֹ מִ֣י יַעֲמֹֽד׃ יִשְׁלַ֣ח דְּבָר֣וֹ וְיַמְסֵ֑ם יַשֵּׁ֥ב ר֝וּח֗וֹ יִזְּלוּ־מָֽיִם׃ מַגִּ֣יד דְּבָרָ֣ו לְיַעֲקֹ֑ב חֻקָּ֥יו וּ֝מִשְׁפָּטָ֗יו לְיִשְׂרָאֵֽל׃ לֹ֘א עָ֤שָׂה כֵ֨ן ׀ לְכׇל־גּ֗וֹי וּמִשְׁפָּטִ֥ים בַּל־יְדָע֗וּם הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>הַ֥לְלוּיָ֨הּ</b> ׀ (תהלים קמח) הַֽלְל֣וּ אֶת־יְ֭הֹוָה מִן־הַשָּׁמַ֑יִם הַֽ֝לְל֗וּהוּ בַּמְּרוֹמִֽים׃ הַֽלְל֥וּהוּ כׇל־מַלְאָכָ֑יו הַ֝לְל֗וּהוּ כׇּל־צְבָאָֽו׃ הַֽ֭לְלוּהוּ שֶׁ֣מֶשׁ וְיָרֵ֑חַ הַֽ֝לְל֗וּהוּ כׇּל־כּ֥וֹכְבֵי אֽוֹר׃ הַֽ֭לְלוּהוּ שְׁמֵ֣י הַשָּׁמָ֑יִם וְ֝הַמַּ֗יִם אֲשֶׁ֤ר ׀ מֵעַ֬ל הַשָּׁמָֽיִם׃ יְֽ֭הַלְלוּ אֶת־שֵׁ֣ם יְהֹוָ֑ה כִּ֤י ה֖וּא צִוָּ֣ה וְנִבְרָֽאוּ׃ וַיַּעֲמִידֵ֣ם לָעַ֣ד לְעוֹלָ֑ם חׇק־נָ֝תַ֗ן וְלֹ֣א יַעֲבֽוֹר׃ הַֽלְל֣וּ אֶת־יְ֭הֹוָה מִן־הָאָ֑רֶץ תַּ֝נִּינִ֗ים וְכׇל־תְּהֹמֽוֹת׃ אֵ֣שׁ וּ֭בָרָד שֶׁ֣לֶג וְקִיט֑וֹר ר֥וּחַ סְ֝עָרָ֗ה עֹשָׂ֥ה דְבָרֽוֹ׃ הֶהָרִ֥ים וְכׇל־גְּבָע֑וֹת עֵ֥ץ פְּ֝רִ֗י וְכׇל־אֲרָזִֽים׃ הַחַיָּ֥ה וְכׇל־בְּהֵמָ֑ה רֶ֗֝מֶשׂ וְצִפּ֥וֹר כָּנָֽף׃ מַלְכֵי־אֶ֭רֶץ וְכׇל־לְאֻמִּ֑ים שָׂ֝רִ֗ים וְכׇל־שֹׁ֥פְטֵי אָֽרֶץ׃ בַּחוּרִ֥ים וְגַם־בְּתוּל֑וֹת זְ֝קֵנִ֗ים עִם־נְעָרִֽים׃ יְהַלְל֤וּ ׀ אֶת־שֵׁ֬ם יְהֹוָ֗ה כִּֽי־נִשְׂגָּ֣ב שְׁמ֣וֹ לְבַדּ֑וֹ ה֝וֹד֗וֹ עַל־אֶ֥רֶץ וְשָׁמָֽיִם׃ וַיָּ֤רֶם קֶ֨רֶן ׀ לְעַמּ֡וֹ תְּהִלָּ֤ה לְֽכׇל־חֲסִידָ֗יו לִבְנֵ֣י יִ֭שְׂרָאֵל עַ֥ם קְרֹב֗וֹ הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>הַ֥לְלוּיָ֨הּ</b> ׀ (תהילים קמ״ט:א׳-ב׳) שִׁ֣ירוּ לַֽ֭יהֹוָה שִׁ֣יר חָדָ֑שׁ תְּ֝הִלָּת֗וֹ בִּקְהַ֥ל חֲסִידִֽים׃ יִשְׂמַ֣ח יִשְׂרָאֵ֣ל בְּעֹשָׂ֑יו בְּנֵֽי־צִ֝יּ֗וֹן יָגִ֥ילוּ בְמַלְכָּֽם׃ יְהַלְל֣וּ שְׁמ֣וֹ בְמָח֑וֹל בְּתֹ֥ף וְ֝כִנּ֗וֹר יְזַמְּרוּ־לֽוֹ׃ כִּֽי־רוֹצֶ֣ה יְהֹוָ֣ה בְּעַמּ֑וֹ יְפָאֵ֥ר עֲ֝נָוִ֗ים בִּישׁוּעָֽה׃ יַעְלְז֣וּ חֲסִידִ֣ים בְּכָב֑וֹד יְ֝רַנְּנ֗וּ עַל־מִשְׁכְּבוֹתָֽם׃ רוֹמְמ֣וֹת אֵ֭ל בִּגְרוֹנָ֑ם וְחֶ֖רֶב פִּיפִיּ֣וֹת בְּיָדָֽם׃ לַעֲשׂ֣וֹת נְ֭קָמָה בַּגּוֹיִ֑ם תּ֝וֹכֵח֗וֹת בַּלְאֻמִּֽים׃ לֶאְסֹ֣ר מַלְכֵיהֶ֣ם בְּזִקִּ֑ים וְ֝נִכְבְּדֵיהֶ֗ם בְּכַבְלֵ֥י בַרְזֶֽל׃ לַעֲשׂ֤וֹת בָּהֶ֨ם ׀ מִשְׁפָּ֬ט כָּת֗וּב הָדָ֣ר ה֭וּא לְכׇל־חֲסִידָ֗יו הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>הַ֥לְלוּיָ֨הּ</b> ׀ (תהילים ק״נ:א׳-ב׳) הַֽלְלוּ־אֵ֥ל בְּקָדְשׁ֑וֹ הַֽ֝לְל֗וּהוּ בִּרְקִ֥יעַ עֻזּֽוֹ׃ הַלְל֥וּהוּ בִגְבוּרֹתָ֑יו הַ֝לְל֗וּהוּ כְּרֹ֣ב גֻּדְלֽוֹ׃ הַ֭לְלוּהוּ בְּתֵ֣קַע שׁוֹפָ֑ר הַ֝לְל֗וּהוּ בְּנֵ֣בֶל וְכִנּֽוֹר׃ הַ֭לְלוּהוּ בְּתֹ֣ף וּמָח֑וֹל הַֽ֝לְל֗וּהוּ בְּמִנִּ֥ים וְעֻגָֽב׃ הַלְל֥וּהוּ בְצִלְצְלֵי־שָׁ֑מַע הַֽ֝לְל֗וּהוּ בְּֽצִלְצְלֵ֥י תְרוּעָֽה׃ כֹּ֣ל הַ֭נְּשָׁמָה תְּהַלֵּ֥ל יָ֗הּ הַֽלְלוּיָֽהּ׃ כֹּ֣ל הַ֭נְּשָׁמָה תְּהַלֵּ֥ל יָ֗הּ הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>בָּר֖וּךְ</b> יְהֹוָ֥ה לְ֝עוֹלָ֗ם אָ֘מֵ֥ן ׀ וְאָמֵֽן: בָּ֘ר֤וּךְ יְהֹוָ֨ה ׀ מִצִּיּ֗וֹן שֹׁ֘כֵ֤ן יְֽרוּשָׁלָ֗‍ִם הַֽלְלוּיָֽהּ: בָּר֤וּךְ ׀ יְהֹוָ֣ה אֱ֭לֹהִים אֱלֹהֵ֣י יִשְׂרָאֵ֑ל עֹשֵׂ֖ה נִפְלָא֣וֹת לְבַדּֽוֹ: וּבָר֤וּךְ ׀ שֵׁ֥ם כְּבוֹד֗וֹ לְע֫וֹלָ֥ם וְיִמָּלֵ֣א כְ֭בוֹדוֹ אֶת־כֹּ֥ל הָאָ֗רֶץ אָ֘מֵ֥ן ׀ וְאָמֵֽן:"}, {"kind": "instruction", "text": "יאמר מעומד"}, {"kind": "text", "text": "<b>וַיְבָ֤רֶךְ דָּוִיד֙</b> אֶת־יְהֹוָ֔ה לְעֵינֵ֖י כׇּל־הַקָּהָ֑ל וַיֹּ֣אמֶר דָּוִ֗יד בָּר֨וּךְ אַתָּ֤ה יְהֹוָה֙ אֱלֹהֵי֙ יִשְׂרָאֵ֣ל אָבִ֔ינוּ מֵעוֹלָ֖ם וְעַד־עוֹלָֽם׃ לְךָ֣ יְ֠הֹוָ֠ה הַגְּדֻלָּ֨ה וְהַגְּבוּרָ֤ה וְהַתִּפְאֶ֙רֶת֙ וְהַנֵּ֣צַח וְהַה֔וֹד כִּי־כֹ֖ל בַּשָּׁמַ֣יִם וּבָאָ֑רֶץ לְךָ֤ יְהֹוָה֙ הַמַּמְלָכָ֔ה וְהַמִּתְנַשֵּׂ֖א לְכֹ֥ל ׀ לְרֹֽאשׁ׃ וְהָעֹ֤שֶׁר וְהַכָּבוֹד֙ מִלְּפָנֶ֔יךָ וְאַתָּה֙ מוֹשֵׁ֣ל בַּכֹּ֔ל יתן צדקה שלש פרוטות, וימסור השתים בבת אחת, ואחריהם השלישית (בא\"ח ויגש הי\"ג) וּבְיָדְךָ֖ כֹּ֣חַ וּגְבוּרָ֑ה וּבְיָ֣דְךָ֔ לְגַדֵּ֥ל וּלְחַזֵּ֖ק לַכֹּֽל׃ וְעַתָּ֣ה אֱלֹהֵ֔ינוּ מוֹדִ֥ים אֲנַ֖חְנוּ לָ֑ךְ וּֽמְהַלְלִ֖ים לְשֵׁ֥ם תִּפְאַרְתֶּֽךָ׃ וִיבָֽרְכוּ֙ שֵׁ֣ם כְּבֹדֶ֔ךָ וּמְרוֹמַ֥ם עַל־כׇּל־בְּרָכָ֖ה וּתְהִלָּֽה׃ אַתָּה־ה֣וּא יְהֹוָה֮ לְבַדֶּ֒ךָ֒ את [אַתָּ֣ה] עָשִׂ֡יתָ אֶֽת־הַשָּׁמַ֩יִם֩ שְׁמֵ֨י הַשָּׁמַ֜יִם וְכׇל־צְבָאָ֗ם הָאָ֜רֶץ וְכׇל־אֲשֶׁ֤ר עָלֶ֙יהָ֙ הַיַּמִּים֙ וְכׇל־אֲשֶׁ֣ר בָּהֶ֔ם וְאַתָּ֖ה מְחַיֶּ֣ה אֶת־כֻּלָּ֑ם וּצְבָ֥א הַשָּׁמַ֖יִם לְךָ֥ מִשְׁתַּחֲוִֽים׃ אַתָּה־הוּא֙ יְהֹוָ֣ה הָאֱלֹהִ֔ים ר״ת אהיה. עד כאן מעומד (כה״ח נג:מג) אֲשֶׁ֤ר בָּחַ֙רְתָּ֙ בְּאַבְרָ֔ם וְהוֹצֵאת֖וֹ מֵא֣וּר כַּשְׂדִּ֑ים וְשַׂ֥מְתָּ שְּׁמ֖וֹ אַבְרָהָֽם׃ וּמָצָ֣אתָ אֶת־לְבָבוֹ֮ נֶאֱמָ֣ן לְפָנֶ֒יךָ֒ וְכָר֨וֹת עִמּ֜וֹ הַבְּרִ֗ית לָתֵ֡ת אֶת־אֶ֩רֶץ֩ הַכְּנַעֲנִ֨י הַחִתִּ֜י הָאֱמֹרִ֧י וְהַפְּרִזִּ֛י וְהַיְבוּסִ֥י וְהַגִּרְגָּשִׁ֖י לָתֵ֣ת לְזַרְע֑וֹ וַתָּ֙קֶם֙ אֶת־דְּבָרֶ֔יךָ כִּ֥י צַדִּ֖יק אָֽתָּה׃ וַתֵּ֛רֶא אֶת־עֳנִ֥י אֲבֹתֵ֖ינוּ בְּמִצְרָ֑יִם וְאֶת־זַעֲקָתָ֥ם שָׁמַ֖עְתָּ עַל־יַם־סֽוּף׃ וַ֠תִּתֵּ֠ן אֹתֹ֨ת וּמֹֽפְתִ֜ים בְּפַרְעֹ֤ה וּבְכׇל־עֲבָדָיו֙ וּבְכׇל־עַ֣ם אַרְצ֔וֹ כִּ֣י יָדַ֔עְתָּ כִּ֥י הֵזִ֖ידוּ עֲלֵיהֶ֑ם וַתַּֽעַשׂ־לְךָ֥ שֵׁ֖ם כְּהַיּ֥וֹם הַזֶּֽה׃ וְהַיָּם֙ בָּקַ֣עְתָּ לִפְנֵיהֶ֔ם וַיַּֽעַבְר֥וּ בְתוֹךְ־הַיָּ֖ם בַּיַּבָּשָׁ֑ה וְֽאֶת־רֹ֨דְפֵיהֶ֜ם הִשְׁלַ֧כְתָּ בִמְצוֹלֹ֛ת כְּמוֹ־אֶ֖בֶן בְּמַ֥יִם עַזִּֽים׃"}, {"kind": "text", "text": "<b>וַיּ֨וֹשַׁע</b> (שמות יד ל) יְהֹוָ֜ה בַּיּ֥וֹם הַה֛וּא אֶת־יִשְׂרָאֵ֖ל מִיַּ֣ד מִצְרָ֑יִם וַיַּ֤רְא יִשְׂרָאֵל֙ אֶת־מִצְרַ֔יִם מֵ֖ת עַל־שְׂפַ֥ת הַיָּֽם׃ וַיַּ֨רְא יִשְׂרָאֵ֜ל אֶת־הַיָּ֣ד הַגְּדֹלָ֗ה אֲשֶׁ֨ר עָשָׂ֤ה יְהֹוָה֙ בְּמִצְרַ֔יִם וַיִּֽירְא֥וּ הָעָ֖ם אֶת־יְהֹוָ֑ה וַיַּֽאֲמִ֙ינוּ֙ בַּֽיהֹוָ֔ה וּבְמֹשֶׁ֖ה עַבְדּֽוֹ׃"}, {"kind": "text", "text": "<b>אָ֣ז</b> (שמות ט״ו) יָשִֽׁיר־מֹשֶׁה֩ וּבְנֵ֨י יִשְׂרָאֵ֜ל אֶת־הַשִּׁירָ֤ה הַזֹּאת֙ לַֽיהֹוָ֔ה וַיֹּאמְר֖וּ לֵאמֹ֑ר אָשִׁ֤ירָה לַֽיהֹוָה֙ כִּֽי־גָאֹ֣ה גָּאָ֔ה ס֥וּס וְרֹכְב֖וֹ רָמָ֥ה בַיָּֽם׃ עָזִּ֤י וְזִמְרָת֙ יָ֔הּ וַֽיְהִי־לִ֖י לִֽישׁוּעָ֑ה זֶ֤ה אֵלִי֙ וְאַנְוֵ֔הוּ אֱלֹהֵ֥י אָבִ֖י וַאֲרֹמְמֶֽנְהוּ׃ יְהֹוָ֖ה אִ֣ישׁ מִלְחָמָ֑ה יְהֹוָ֖ה שְׁמֽוֹ׃ מַרְכְּבֹ֥ת פַּרְעֹ֛ה וְחֵיל֖וֹ יָרָ֣ה בַיָּ֑ם וּמִבְחַ֥ר שָֽׁלִשָׁ֖יו טֻבְּע֥וּ בְיַם־סֽוּף׃ תְּהֹמֹ֖ת יְכַסְיֻ֑מוּ יָרְד֥וּ בִמְצוֹלֹ֖ת כְּמוֹ־אָֽבֶן׃ יְמִֽינְךָ֣ יְהֹוָ֔ה נֶאְדָּרִ֖י בַּכֹּ֑חַ יְמִֽינְךָ֥ יְהֹוָ֖ה תִּרְעַ֥ץ אוֹיֵֽב׃ וּבְרֹ֥ב גְּאוֹנְךָ֖ תַּהֲרֹ֣ס קָמֶ֑יךָ תְּשַׁלַּח֙ חֲרֹ֣נְךָ֔ יֹאכְלֵ֖מוֹ כַּקַּֽשׁ׃ וּבְר֤וּחַ אַפֶּ֙יךָ֙ נֶ֣עֶרְמוּ מַ֔יִם נִצְּב֥וּ כְמוֹ־נֵ֖ד נֹזְלִ֑ים קָֽפְא֥וּ תְהֹמֹ֖ת בְּלֶב־יָֽם׃ אָמַ֥ר אוֹיֵ֛ב אֶרְדֹּ֥ף אַשִּׂ֖יג אֲחַלֵּ֣ק שָׁלָ֑ל תִּמְלָאֵ֣מוֹ נַפְשִׁ֔י אָרִ֣יק חַרְבִּ֔י תּוֹרִישֵׁ֖מוֹ יָדִֽי׃ נָשַׁ֥פְתָּ בְרוּחֲךָ֖ כִּסָּ֣מוֹ יָ֑ם צָֽלְלוּ֙ כַּֽעוֹפֶ֔רֶת בְּמַ֖יִם אַדִּירִֽים׃ מִֽי־כָמֹ֤כָה בָּֽאֵלִם֙ יְהֹוָ֔ה מִ֥י כָּמֹ֖כָה נֶאְדָּ֣ר בַּקֹּ֑דֶשׁ נוֹרָ֥א תְהִלֹּ֖ת עֹ֥שֵׂה פֶֽלֶא׃ נָטִ֙יתָ֙ יְמִ֣ינְךָ֔ תִּבְלָעֵ֖מוֹ אָֽרֶץ׃ נָחִ֥יתָ בְחַסְדְּךָ֖ עַם־ז֣וּ גָּאָ֑לְתָּ נֵהַ֥לְתָּ בְעׇזְּךָ֖ אֶל־נְוֵ֥ה קׇדְשֶֽׁךָ׃ שָֽׁמְע֥וּ עַמִּ֖ים יִרְגָּז֑וּן חִ֣יל אָחַ֔ז יֹשְׁבֵ֖י פְּלָֽשֶׁת׃ אָ֤ז נִבְהֲלוּ֙ אַלּוּפֵ֣י אֱד֔וֹם אֵילֵ֣י מוֹאָ֔ב יֹֽאחֲזֵ֖מוֹ רָ֑עַד נָמֹ֕גוּ כֹּ֖ל יֹשְׁבֵ֥י כְנָֽעַן׃ תִּפֹּ֨ל עֲלֵיהֶ֤ם אֵימָ֙תָה֙ וָפַ֔חַד בִּגְדֹ֥ל זְרוֹעֲךָ֖ יִדְּמ֣וּ כָּאָ֑בֶן עַד־יַעֲבֹ֤ר עַמְּךָ֙ יְהֹוָ֔ה עַֽד־יַעֲבֹ֖ר עַם־ז֥וּ קָנִֽיתָ׃ תְּבִאֵ֗מוֹ וְתִטָּעֵ֙מוֹ֙ בְּהַ֣ר נַחֲלָֽתְךָ֔ מָכ֧וֹן לְשִׁבְתְּךָ֛ פָּעַ֖לְתָּ יְהֹוָ֑ה מִקְּדָ֕שׁ אֲדֹנָ֖י כּוֹנְנ֥וּ יָדֶֽיךָ׃ יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד׃ יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד׃ יְהֹוָה מַלְכוּתֵהּ קָאִים לְעָלַם וּלְעָלְמֵי עָלְמַיָּא: כִּ֣י בָא֩ ס֨וּס פַּרְעֹ֜ה בְּרִכְבּ֤וֹ וּבְפָרָשָׁיו֙ בַּיָּ֔ם וַיָּ֧שֶׁב יְהֹוָ֛ה עֲלֵהֶ֖ם אֶת־מֵ֣י הַיָּ֑ם וּבְנֵ֧י יִשְׂרָאֵ֛ל הָלְכ֥וּ בַיַּבָּשָׁ֖ה בְּת֥וֹךְ הַיָּֽם׃"}, {"kind": "text", "text": "<b>כִּ֣י</b> לַ֭יהֹוָה הַמְּלוּכָ֑ה וּ֝מֹשֵׁ֗ל בַּגּוֹיִֽם׃ וְעָל֤וּ מֽוֹשִׁעִים֙ בְּהַ֣ר צִיּ֔וֹן לִשְׁפֹּ֖ט אֶת־הַ֣ר עֵשָׂ֑ו וְהָיְתָ֥ה לַֽיהֹוָ֖ה הַמְּלוּכָֽה׃ וְהָיָ֧ה יְהֹוָ֛ה לְמֶ֖לֶךְ עַל־כׇּל־הָאָ֑רֶץ בַּיּ֣וֹם הַה֗וּא יִהְיֶ֧ה יְהֹוָ֛ה אֶחָ֖ד וּשְׁמ֥וֹ אֶחָֽד׃"}, {"kind": "text", "text": "<b>יִשְׁתַּבַּח</b> שִׁמְךָ לָעַד מַלְכֵּֽנוּ, הָאֵל הַמֶּֽלֶךְ הַגָּדוֹל וְהַקָּדוֹשׁ, בַּשָּׁמַֽיִם וּבָאָֽרֶץ. כִּי לְךָ נָאֶה יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ לְעוֹלָם וָעֶד. א שִׁיר, ב וּשְׁבָחָה, ג הַלֵּל, ד וְזִמְרָה, ה עֹז, ו וּמֶמְשָׁלָה, ז נֶֽצַח, ח גְּדֻלָּה, ט גְּבוּרָה, י תְּהִלָּה, יא וְתִפְאֶֽרֶת, יב קְדֻשָּׁה, יג וּמַלְכוּת. בְּרָכוֹת וְהוֹדָאוֹת, לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, וּמֵעוֹלָם וְעַד עוֹלָם אַתָּה אֵל. בָּרוּךְ אַתָּה יְהֹוָה, מֶֽלֶךְ גָּדוֹל וּמְהֻלָּל בַּתִּשְׁבָּחוֹת, אֵל הַהוֹדָאוֹת, אֲדוֹן הַנִּפְלָאוֹת, בּוֹרֵא כָּל־הַנְּשָׁמוֹת, רִבּוֹן כָּל־הַמַּעֲשִׂים, הַבּוֹחֵר בְּשִׁירֵי זִמְרָה, מֶֽלֶךְ אֵל חַי הָעוֹלָמִים, אָמֵן:"}, {"kind": "instruction", "text": "בעשרת ימי תשובה מוסיפים"}, {"kind": "text", "text": "שִׁ֥יר הַֽמַּעֲל֑וֹת (תהילים ק״ל:א׳-ב׳) מִמַּעֲמַקִּ֖ים קְרָאתִ֣יךָ יְהֹוָֽה׃ אֲדֹנָי֮ שִׁמְעָ֢ה בְק֫וֹלִ֥י תִּהְיֶ֣ינָה אׇ֭זְנֶיךָ קַשֻּׁב֑וֹת לְ֝ק֗וֹל תַּחֲנוּנָֽי׃ אִם־עֲוֺנ֥וֹת תִּשְׁמׇר־יָ֑הּ אֲ֝דֹנָ֗י מִ֣י יַעֲמֹֽד׃ כִּֽי־עִמְּךָ֥ הַסְּלִיחָ֑ה לְ֝מַ֗עַן תִּוָּרֵֽא׃ קִוִּ֣יתִי יְ֭הֹוָה קִוְּתָ֣ה נַפְשִׁ֑י וְֽלִדְבָר֥וֹ הוֹחָֽלְתִּי׃ נַפְשִׁ֥י לַאדֹנָ֑י מִשֹּׁמְרִ֥ים לַ֝בֹּ֗קֶר שֹׁמְרִ֥ים לַבֹּֽקֶר׃ יַחֵ֥ל יִשְׂרָאֵ֗ל אֶל־יְהֹ֫וָ֥ה כִּֽי־עִם־יְהֹוָ֥ה הַחֶ֑סֶד וְהַרְבֵּ֖ה עִמּ֣וֹ פְדֽוּת׃ וְ֭הוּא יִפְדֶּ֣ה אֶת־יִשְׂרָאֵ֑ל מִ֝כֹּ֗ל עֲוֺנֹתָֽיו׃"}, {"kind": "instruction", "text": "ואומר החזן חצי קדיש"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "ואומר החזן: בָּרְכוּ אֶת יְהֹוָה הַמְּבֹרָךְ:"}, {"kind": "text", "text": "ועונים הקהל: בָּרוּךְ יְהֹוָה הַמְּבֹרָךְ לְעוֹלָם וָעֵד:"}, {"kind": "text", "text": "ואומר החזן: בָּרוּךְ יְהֹוָה הַמְּבֹרָךְ לְעוֹלָם וָעֵד:"}, {"kind": "header", "text": "ק\"ש וברכותיה"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, כשיתחיל יוצר אור ימשמש בתפלין של יד (בא\"ח שמות ה\"א) יוֹצֵר אוֹר וּבוֹרֵא חֹשֶׁךְ עֹשֵׂה שָׁלוֹם וּבוֹרֵא אֶת הַכֹּל. הַמֵּאִיר לָאָרֶץ וְלַדָּרִים עָלֶיהָ בְּרַחֲמִים, וּבְטוּבוֹ מְחַדֵּשׁ בְּכָל יוֹם תָּמִיד מַעֲשֵׂה בְּרֵאשִׁית. מָה רַבּוּ מַעֲשֶׂיךָ יְהֹוָה כֻּלָּם בְּחָכְמָה עָשִׂיתָ, מָלְאָה הָאָרֶץ קִנְיָנֶךָ. הַמֶּלֶךְ הַמְּרוֹמָם לְבַדּוֹ מֵאָז, הַמְּשֻׁבָּח וְהַמְּפוֹאָר וְהַמִּתְנַשֵּׂא מִימוֹת עוֹלָם. אֱלֹהַי עוֹלָם, בְּרַחֲמֶיךָ הָרַבִּים רַחֵם עָלֵינוּ, אֲדוֹן עוּזֵּנוּ, צוּר מִשְׂגַּבֵּנוּ, מָגֵן יִשְׁעֵנוּ, מִשְׂגָּב בַּעֲדֵנוּ. אֵל בָּרוּךְ גְּדוֹל דֵּעָה, הֵכִין וּפָעַל זָהֳרֵי חַמָּה. טוֹב יָצַר כָּבוֹד לִשְׁמוֹ, מְאוֹרוֹת נָתַן סְבִיבוֹת עֻזּוֹ. פִּינוֹת צִבְאוֹת קְדוֹשִׁים, רוֹמְמֵי שַׁדַּי, תָּמִיד מְסַפְּרִים כְּבוֹד אֵל וּקְדוּשָׁתוֹ. תִּתְבָּרַךְ יְהֹוָה אֱלֹהֵינוּ בַּשָּׁמַיִם מִמַּעַל וְעַל־הָאָרֶץ מִתַּחַת עַל־כָּל־שֶׁבַח מַעֲשֵׂה יָדֶיךָ וְעַל מְאוֹרֵי אוֹר שֶׁיָּצַרְתָּ הֵמָּה יְפָאֲרוּךָ סֶּלָה:"}, {"kind": "text", "text": "<b>תִּתְבָּרַךְ</b> לָנֶצַח צוּרֵנוּ מַלְכֵּנוּ וְגוֹאֲלֵנוּ בּוֹרֵא קְדוֹשִׁים, יִשְׁתַּבַּח שִׁמְךָ לָעַד מַלְכֵּנוּ יוֹצֵר מְשָׁרְתִים, וַאֲשֶׁר מְשָׁרְתָיו כֻּלָּם עוֹמְדִים בְּרוּם עוֹלָם וּמַשְׁמִיעִים בְּיִרְאָה יַחַד בְּקוֹל דִּבְרֵי אֱלֹהִים חַיִּים וּמֶלֶךְ עוֹלָם. כֻּלָּם אֲהוּבִים, כֻּלָּם בְּרוּרִים, כֻּלָּם גִּבּוֹרִים, כֻּלָּם קְדוֹשִׁים, כֻּלָּם עוֹשִׂים בְּאֵימָה וּבְיִרְאָה רָצוֹן קוֹנֵיהֶם, וְכֻלָּם פּוֹתְחִים אֶת פִּיהֶם בִּקְדוּשָׁה וּבְטָהֳרָה, בְּשִׁירָה וּבְזִמְרָה, וּמְבָרְכִין וּמְשַׁבְּחִין וּמְפָאֲרִין וּמַקְדִּישִׁין וּמַעֲרִיצִין וּמַמְלִיכִין אֶת שֵׁם הָאֵל הַמֶּלֶךְ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא קָדוֹשׁ הוּא. וְכֻלָּם מְקַבְּלִים עֲלֵיהֶם עֹל מַלְכוּת שָׁמַיִם זֶה מִזֶּה, וְנוֹתְנִים רְשׁוּת זֶה לָזֶה לְהַקְדִּישׁ לְיוֹצְרָם בְּנַחַת רוּחַ בְּשָׂפָה בְּרוּרָה וּבִנְעִימָה קְדוּשָׁה, כֻּלָּם כְּאֶחָד עוֹנִים בְּאֵימָה, וְאוֹמְרִים בְּיִרְאָה:"}, {"kind": "instruction", "text": "קדושת יוצר צריך לאמרה מיושב ואם היה עומד צריך שישב (בא\"ח שמות ה\"ב)"}, {"kind": "text", "text": "<b>קָד֧וֹשׁ</b> ׀ קָד֛וֹשׁ קָד֖וֹשׁ יְהֹוָ֣ה צְבָא֑וֹת מְלֹ֥א כׇל־הָאָ֖רֶץ כְּבוֹדֽוֹ: וְהָאוֹפַנִּים וְחַיּוֹת הַקֹדֶשׁ בְּרַעַשׁ גָּדוֹל מִתְנַשְּׂאִים לְעֻמַּת הַשְׂרָפִים, לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים: בָּר֥וּךְ כְּבוֹד־יְהֹוָ֖ה מִמְּקוֹמֽוֹ:"}, {"kind": "text", "text": "<b>לָאֵל</b> בָּרוּךְ, נְעִימוֹת יִתֵּנוּ, לַמֶּלֶךְ אֵל חַי וְקַיָּם, זְמִירוֹת יֹאמְרוּ וְתִשְׁבָּחוֹת יַשְׁמִיעוּ, כִּי הוּא לְבַדּוֹ מָרוֹם וְקָדוֹשׁ, פּוֹעֵל גְּבוּרוֹת, עוֹשֶׂה חֲדָשׁוֹת, בַּעַל מִלְחָמוֹת, זוֹרֵעַ צְדָקוֹת, מַצְמִיחַ יְשׁוּעוֹת, בּוֹרֵא רְפוּאוֹת, נוֹרָא תְהִלּוֹת, אֲדוֹן הַנִּפְלָאוֹת, הַמְחַדֵּשׁ בְּטוּבוֹ בְּכָל יוֹם תָּמִיד מַעֲשֵׂה בְרֵאשִׁית כָּאָמוּר: לְ֭עֹשֵׂה אוֹרִ֣ים גְּדֹלִ֑ים כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃ בָּרוּךְ אַתָּה יְהֹוָה יוֹצֵר הַמְּאוֹרוֹת:"}, {"kind": "text", "text": "<b>אַהֲבַת</b> עוֹלָם אֲהַבְתָּנוּ יְהֹוָה אֱלֹהֵינוּ, חֶמְלָה גְּדוֹלָה וִיתֵרָה חָמַלְתָּ עָלֵינוּ. אָבִינוּ מַלְכֵּנוּ, בַּעֲבוּר שִׁמְךָ הַגָּדוֹל וּבַעֲבוּר אֲבוֹתֵינוּ שֶׁבָּטְחוּ בָּךְ וַתְּלַמְּדֵמוֹ חֻקֵּי חַיִּים לַעֲשׂוֹת רְצוֹנְךָ בְּלֵבָב שָׁלֵם, כֵּן תְּחָנֵּנוּ אָבִינוּ, אָב הָרַחֲמָן הַמְרַחֵם, רַחֵם נָא עָלֵינוּ, וְתֵן בְּלִבֵּנוּ בִינָה לְהָבִין, לְהַשְׂכִּיל, לִשְׁמֹעַ, לִלְמֹד וּלְלַמֵּד, לִשְׁמֹר וְלַעֲשׂוֹת וּלְקַיֵּם אֶת־כָּל־דִּבְרֵי תַּלְמוּד תוֹרָתְךָ בְּאַהֲבָה:"}, {"kind": "text", "text": "וְהָאֵר עֵינֵינוּ בְּתוֹרָתֶךָ וְדַבֵּק לִבֵּנוּ בְמִצְוֹתֶיךָ, וְיַחֵד לְבָבֵנוּ לְאַהֲבָה וּלְיִרְאָה אֶת־שְׁמֶךָ. לֹא נֵבוֹשׁ וְלֹא נִכָּלֵם וְלֹא נִכָּשֵׁל לְעוֹלָם וָעֶד. כִּי בְשֵׁם קָדְשְׁךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא בָּטָחְנוּ, נָגִילָה וְנִשְׂמְחָה בִּישׁוּעָתֶךָ, וְרַחֲמֶיךָ יְהֹוָה אֱלֹהֵינוּ וַחֲסָדֶיךָ הָרַבִּים, אַל יַעַזְבוּנוּ נֶצַח סֶלָה וָעֶד:"}, {"kind": "text", "text": "כשיאמר מהר והבא עלינו ישים שני צדדי הטלית על כתפיו וכשיאמר ברכה ושלום מהרה מארבע כנפות כל הארץ יקבץ כל ארבע כנפות הטלית ויאחזם בידו השמאלית כנגד הלב שהוא בשמאל<br> (בא\"ח שמות ה\"ה) מַהֵר וְהָבֵא עָלֵינוּ בְּרָכָה וְשָׁלוֹם מְהֵרָה מֵאַרְבַּע כַּנְפוֹת כָּל־הָאָרֶץ, וּשְׁבֹר עֹל הַגּוֹיִם מֵעַל צַוָּארֵנוּ, וְהוֹלִיכֵנוּ מְהֵרָה קוֹמְמִיּוּת לְאַרְצֵנוּ, כִּי אֵל פּוֹעֵל יְשׁוּעוֹת אַתָּה, וּבָנוּ בָחַרְתָּ מִכָּל עַם וְלָשׁוֹן, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לְשִׁמְךָ הַגָּדוֹל בְּאַהֲבָה, לְהוֹדוֹת לָךְ וּלְיַחֶדְךָ לְיִרְאָה וּלְאַהֲבָה אֶת־שִׁמְךָ, בָּרוּךְ אַתָּה יְהֹוָה, הַבּוֹחֵר בְּעַמּוֹ יִשְׂרָאֵל בְּאַהֲבָה:"}, {"kind": "instruction", "text": "קודם שיקרא קריאת שמע יכוין לקיים מצוות עשה שנצטוינו לקרא קריאת שמע שתי פעמים ביום, וגם יכוין לקיים מצות עשה ליחד את השם, ויסגור עיניו ביד ימינו בפסוק ראשון עד שישלים ברוך שם, וכן הוא כאן אומר שמע ישראל כלומר קבל דברים אלו והבינם ותדעם שתאמין בם והוא כי ה' הוא אלהינו, ועוד הנה הוא ה' אחד, ונמצא בזה יש קבלה והודאה בשתי דברים האחד הוא קבלת מלכות שמים באומרו ה' אלהינו דמודה שקבלנו אלהותו להיות לנו לאלוה ואנחנו עבדים לו, והשני הוא ענין יחוד השם באומרו ה' אחד שהוא בלי שיתוף אחר (בא\"ח וארא ה\"ו-ז)"}, {"kind": "text", "text": "<b>שְׁמַ֖ע יִשְׂרָאֵ֑ל יְהֹוָ֥ה אֱלֹהֵ֖ינוּ יְהֹוָ֥ה ׀ אֶחָֽד</b>׃"}, {"kind": "text", "text": "בלחש: בָּרוּךְ, שֵׁם כְּבוֹד מַלְכוּתוֹ, לְעוֹלָם וָעֶד:"}, {"kind": "text", "text": "<b>וְאָ֣הַבְתָּ֔</b> (דברים ו ה) אֵ֖ת יְהֹוָ֣ה אֱלֹהֶ֑יךָ בְּכׇל־לְבָבְךָ֥ וּבְכׇל־נַפְשְׁךָ֖ וּבְכׇל־מְאֹדֶֽךָ׃ וְהָי֞וּ הַדְּבָרִ֣ים הָאֵ֗לֶּה אֲשֶׁ֨ר אָנֹכִ֧י מְצַוְּךָ֛ הַיּ֖וֹם עַל־לְבָבֶֽךָ׃ וְשִׁנַּנְתָּ֣ם לְבָנֶ֔יךָ וְדִבַּרְתָּ֖ בָּ֑ם בְּשִׁבְתְּךָ֤ בְּבֵיתֶ֙ךָ֙ וּבְלֶכְתְּךָ֣ בַדֶּ֔רֶךְ וּֽבְשׇׁכְבְּךָ֖ וּבְקוּמֶֽךָ׃ וּקְשַׁרְתָּ֥ם לְא֖וֹת עַל־יָדֶ֑ךָ ימשמש בתפלין של יד (בא\"ח וארא הכ\"א) וְהָי֥וּ לְטֹטָפֹ֖ת ימשמש בתפלין של ראש בֵּ֥ין עֵינֶֽיךָ׃ וּכְתַבְתָּ֛ם עַל־מְזֻז֥וֹת בֵּיתֶ֖ךָ וּבִשְׁעָרֶֽיךָ׃"}, {"kind": "text", "text": "<b>וְהָיָ֗ה</b> (דברים יא יג) אִם־שָׁמֹ֤עַ תִּשְׁמְעוּ֙ אֶל־מִצְוֺתַ֔י אֲשֶׁ֧ר אָנֹכִ֛י מְצַוֶּ֥ה אֶתְכֶ֖ם הַיּ֑וֹם לְאַהֲבָ֞ה אֶת־יְהֹוָ֤ה אֱלֹֽהֵיכֶם֙ וּלְעׇבְד֔וֹ בְּכׇל־לְבַבְכֶ֖ם וּבְכׇל־נַפְשְׁכֶֽם׃ וְנָתַתִּ֧י מְטַֽר־אַרְצְכֶ֛ם בְּעִתּ֖וֹ יוֹרֶ֣ה וּמַלְק֑וֹשׁ וְאָסַפְתָּ֣ דְגָנֶ֔ךָ וְתִֽירֹשְׁךָ֖ וְיִצְהָרֶֽךָ׃ וְנָתַתִּ֛י עֵ֥שֶׂב בְּשָׂדְךָ֖ לִבְהֶמְתֶּ֑ךָ וְאָכַלְתָּ֖ וְשָׂבָֽעְתָּ׃ הִשָּֽׁמְר֣וּ לָכֶ֔ם פֶּ֥ן יִפְתֶּ֖ה לְבַבְכֶ֑ם וְסַרְתֶּ֗ם וַעֲבַדְתֶּם֙ אֱלֹהִ֣ים אֲחֵרִ֔ים וְהִשְׁתַּחֲוִיתֶ֖ם לָהֶֽם׃ וְחָרָ֨ה אַף־יְהֹוָ֜ה בָּכֶ֗ם וְעָצַ֤ר אֶת־הַשָּׁמַ֙יִם֙ וְלֹֽא־יִהְיֶ֣ה מָטָ֔ר וְהָ֣אֲדָמָ֔ה לֹ֥א תִתֵּ֖ן אֶת־יְבוּלָ֑הּ וַאֲבַדְתֶּ֣ם מְהֵרָ֗ה מֵעַל֙ הָאָ֣רֶץ הַטֹּבָ֔ה אֲשֶׁ֥ר יְהֹוָ֖ה נֹתֵ֥ן לָכֶֽם׃ וְשַׂמְתֶּם֙ אֶת־דְּבָרַ֣י אֵ֔לֶּה עַל־לְבַבְכֶ֖ם וְעַֽל־נַפְשְׁכֶ֑ם וּקְשַׁרְתֶּ֨ם אֹתָ֤ם לְאוֹת֙ עַל־יֶדְכֶ֔ם ימשמש בתפלין של יד וְהָי֥וּ לְטוֹטָפֹ֖ת בֵּ֥ין עֵינֵיכֶֽם ימשמש בתפלין של ראש׃ וְלִמַּדְתֶּ֥ם אֹתָ֛ם אֶת־בְּנֵיכֶ֖ם לְדַבֵּ֣ר בָּ֑ם בְּשִׁבְתְּךָ֤ בְּבֵיתֶ֙ךָ֙ וּבְלֶכְתְּךָ֣ בַדֶּ֔רֶךְ וּֽבְשׇׁכְבְּךָ֖ וּבְקוּמֶֽךָ׃ וּכְתַבְתָּ֛ם עַל־מְזוּז֥וֹת בֵּיתֶ֖ךָ וּבִשְׁעָרֶֽיךָ׃ לְמַ֨עַן יִרְבּ֤וּ יְמֵיכֶם֙ וִימֵ֣י בְנֵיכֶ֔ם עַ֚ל הָֽאֲדָמָ֔ה אֲשֶׁ֨ר נִשְׁבַּ֧ע יְהֹוָ֛ה לַאֲבֹתֵיכֶ֖ם לָתֵ֣ת לָהֶ֑ם כִּימֵ֥י הַשָּׁמַ֖יִם עַל־הָאָֽרֶץ׃"}, {"kind": "text", "text": "<b>וַיֹּ֥אמֶר</b> (במדבר טו לז) יְהֹוָ֖ה אֶל־מֹשֶׁ֥ה לֵּאמֹֽר׃ דַּבֵּ֞ר אֶל־בְּנֵ֤י יִשְׂרָאֵל֙ וְאָמַרְתָּ֣ אֲלֵהֶ֔ם וְעָשׂ֨וּ לָהֶ֥ם צִיצִ֛ת עַל־כַּנְפֵ֥י בִגְדֵיהֶ֖ם לְדֹרֹתָ֑ם וְנָ֥תְנ֛וּ עַל־צִיצִ֥ת הַכָּנָ֖ף פְּתִ֥יל תְּכֵֽלֶת׃ וְהָיָ֣ה לָכֶם֮ לְצִיצִת֒ וּרְאִיתֶ֣ם אֹת֗וֹ יסתכל בציציות שבידיו, יעבירם על גבי עיניו וינשקם שתי פעמים וּזְכַרְתֶּם֙ אֶת־כׇּל־מִצְוֺ֣ת יְהֹוָ֔ה וַעֲשִׂיתֶ֖ם אֹתָ֑ם וְלֹֽא־תָת֜וּרוּ אַחֲרֵ֤י לְבַבְכֶם֙ וְאַחֲרֵ֣י עֵֽינֵיכֶ֔ם יעביר הציציות על גבי עיניו וינשקם אֲשֶׁר־אַתֶּ֥ם זֹנִ֖ים אַחֲרֵיהֶֽם׃ לְמַ֣עַן תִּזְכְּר֔וּ וַעֲשִׂיתֶ֖ם אֶת־כׇּל־מִצְוֺתָ֑י וִהְיִיתֶ֥ם קְדֹשִׁ֖ים לֵאלֹֽהֵיכֶֽם׃ אֲנִ֞י יְהֹוָ֣ה אֱלֹֽהֵיכֶ֗ם אֲשֶׁ֨ר הוֹצֵ֤אתִי אֶתְכֶם֙ מֵאֶ֣רֶץ מִצְרַ֔יִם לִהְי֥וֹת לָכֶ֖ם לֵאלֹהִ֑ים אֲנִ֖י יְהֹוָ֥ה אֱלֹהֵיכֶֽם׃ אֱמֶת."}, {"kind": "text", "text": "וחוזר החזן: יְהֹוָה אֱלֹהֵיכֶם אֱמֶת:"}, {"kind": "text", "text": "<b>וְיַצִּיב</b>, וְנָכוֹן, וְקַיָּם, וְיָשָׁר, וְנֶאֱמָן, וְאָהוּב, וְחָבִיב, וְנֶחְמָד, וְנָעִים, וְנוֹרָא, וְאַדִּיר, וּמְתוּקָן, וּמְקֻבָּל, וְטוֹב, וְיָפֶה, הַדָּבָר הַזֶּה עָלֵינוּ לְעוֹלָם וָעֶד."}, {"kind": "text", "text": "אֱמֶת, אֱלֹהֵי עוֹלָם מַלְכֵּנוּ צוּר יַעֲקֹב מָגֵן יִשְׁעֵנוּ, לְדוֹר וָדוֹר הוּא קַיָּם, וּשְׁמוֹ קַיָּם, וְכִסְאוֹ נָכוֹן, וּמַלְכוּתוֹ וֶאֱמוּנָתוֹ לָעַד קַיֶּמֶת, וּדְבָרָיו חַיִּים וְקַיָּמִים, וְנֶאֱמָנִים וְנֶחֱמָדִים לָעַד ינשק הציציות שהיה אוחז בהם ויעבירם על גבי עיניו ויסירם מידו (בא\"ח שמות ה\"ח) וּלְעוֹלְמֵי עוֹלָמִים. עַל אֲבוֹתֵינוּ, עָלֵינוּ וְעַל בָּנֵינוּ וְעַל דּוֹרוֹתֵינוּ וְעַל כָּל דּוֹרוֹת זֶרַע יִשְׂרָאֵל עֲבָדֶיךָ. עַל הָרִאשׁוֹנִים וְעַל הָאַחֲרוֹנִים דָּבָר טוֹב וְקַיָּם בֶּאֱמֶת וֶאֱמוּנָה חוֹק וְלֹא יַעֲבוֹר. אֱמֶת שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ. מַלְכֵּנוּ מֶלֶךְ אֲבוֹתֵינוּ. גּוֹאֲלֵנוּ גּוֹאֵל אֲבוֹתֵינוּ. יוֹצְרֵנוּ צוּר יְשׁוּעָתֵנוּ. פּוֹדֵנוּ וּמַצִּילֵנוּ מֵעוֹלָם הוּא שְׁמֶךָ, וְאֵין לָנוּ עוֹד אֱלֹהִים זוּלָתְךָ סֶלָה:"}, {"kind": "text", "text": "<b>עֶזְרַת</b> אֲבוֹתֵינוּ אַתָּה הוּא מֵעוֹלָם, מָגֵן וּמוֹשִׁיעַ לָהֶם וְלִבְנֵיהֶם אַחֲרֵיהֶם בְּכָל דּוֹר וָדוֹר, בְּרוּם עוֹלָם מוֹשָׁבֶךָ, וּמִשְׁפָּטֶיךָ, וְצִדְקָתְךָ עַד אַפְסֵי אָרֶץ, אֱמֶת אַשְׁרֵי אִישׁ שֶׁיִּשְׁמַע לְמִצְוֹתֶיךָ וְתוֹרָתְךָ וּדְבָרְךָ יָשִׂים עַל לִבּוֹ. אֱמֶת שֶׁאַתָּה הוּא אֲדוֹן לְעַמֶּךָ וּמֶלֶךְ גִּבּוֹר לָרִיב רִיבָם לְאָבוֹת וּבָנִים, אֱמֶת אַתָּה הוּא רִאשׁוֹן וְאַתָּה הוּא אַחֲרוֹן וּמִבַּלְעָדֶיךָ אֵין לָנוּ מֶלֶךְ גּוֹאֵל וּמוֹשִׁיעַ. אֱמֶת מִמִּצְרַיִם גְּאַלְתָּנוּ יְהֹוָה אֱלֹהֵינוּ, מִבֵּית עֲבָדִים פְּדִיתָנוּ, כָּל בְּכוֹרֵיהֶם הָרַגְתָּ, וּבְכוֹרְךָ יִשְׂרָאֵל גָּאַלְתָּ, וְיַם־סוּף לָהֶם בָּקַעְתָּ, וְזֵדִים טִבַּעְתָּ, וִידִידִים עָבְרוּ יָם. וַיְכַסּוּ מַיִם צָרֵיהֶם אֶחָד מֵהֶם לֹא נוֹתַר. עַל זֹאת שִׁבְּחוּ אֲהוּבִים, וְרוֹמְמוּ לָאֵל, וְנָתְנוּ יְדִידִים זְמִירוֹת שִׁירוֹת וְתִשְׁבָּחוֹת בְּרָכוֹת וְהוֹדָאוֹת לַמֶּלֶךְ אֶל חַי וְקַיָּם, רָם וְנִשָּׂא, גָּדוֹל וְנוֹרָא, מַשְׁפִּיל גֵּאִים עֲדֵי אָרֶץ, מַגְבִּיהַּ שְׁפָלִים עַד מָרוֹם, מוֹצִיא אֲסִירִים, פּוֹדֶה עֲנָוִים, עוֹזֵר דַּלִּים, הָעוֹנֶה לְעַמּוֹ יִשְׂרָאֵל בְּעֵת שַׁוְּעָם אֵלָיו."}, {"kind": "instruction", "text": "תכף בתחלת מלת תהלות יקום לעמוד ויסיים מלת תהלות מעומד (בא\"ח שמות ה\"ח)"}, {"kind": "text", "text": "<b>תְהִילוֹת</b> לָאֵל עֶלְיוֹן גּוֹאֲלָם, בָּרוּךְ הוּא וּמְבוֹרָךְ, מֹשֶׁה וּבְנֵי יִשְׂרָאֵל לְךָ עָנוּ שִׁירָה בְשִׂמְחָה רַבָּה, וְאָמְרוּ כֻלָּם: מִֽי־כָמֹ֤כָה בָּֽאֵלִם֙ יְהֹוָ֔ה מִ֥י כָּמֹ֖כָה נֶאְדָּ֣ר בַּקֹּ֑דֶשׁ נוֹרָ֥א תְהִלֹּ֖ת עֹ֥שֵׂה פֶֽלֶא׃ שִׁירָה חֲדָשָׁה שִׁבְּחוּ גְאוּלִים לְשִׁמְךָ הַגָּדוֹל עַל שְׂפַת הַיָּם, יַחַד כֻלָּם הוֹדוּ וְהִמְלִיכוּ וְאָמְרוּ: יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד׃ וְנֶאֱמַר: גֹּאֲלֵ֕נוּ יְהֹוָ֥ה צְבָא֖וֹת שְׁמ֑וֹ קְד֖וֹשׁ יִשְׂרָאֵֽל׃ בָּרוּךְ אַתָּה יְהֹוָה גָּאַל יִשְׂרָאֵל:"}, {"kind": "header", "text": "מזמור לפסח"}, {"kind": "text", "text": "<b>מזמור לפסח</b>"}, {"kind": "text", "text": "<b>הֹד֣וּ </b> (תהלים קז) לַיהֹוָ֣ה כִּי־ט֑וֹב כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃ יֹ֭אמְרוּ גְּאוּלֵ֣י יְהֹוָ֑ה אֲשֶׁ֥ר גְּ֝אָלָ֗ם מִיַּד־צָֽר׃ וּֽמֵאֲרָצ֗וֹת קִ֫בְּצָ֥ם מִמִּזְרָ֥ח וּמִֽמַּעֲרָ֑ב מִצָּפ֥וֹן וּמִיָּֽם׃ תָּע֣וּ בַ֭מִּדְבָּר בִּישִׁימ֣וֹן דָּ֑רֶךְ עִ֥יר מ֝וֹשָׁ֗ב לֹ֣א מָצָֽאוּ׃ רְעֵבִ֥ים גַּם־צְמֵאִ֑ים נַ֝פְשָׁ֗ם בָּהֶ֥ם תִּתְעַטָּֽף׃ וַיִּצְעֲק֣וּ אֶל־יְ֭הֹוָה בַּצַּ֣ר לָהֶ֑ם מִ֝מְּצ֥וּקוֹתֵיהֶ֗ם יַצִּילֵֽם׃ וַֽ֭יַּדְרִיכֵם בְּדֶ֣רֶךְ יְשָׁרָ֑ה לָ֝לֶ֗כֶת אֶל־עִ֥יר מוֹשָֽׁב׃ יוֹד֣וּ לַיהֹוָ֣ה חַסְדּ֑וֹ וְ֝נִפְלְאוֹתָ֗יו לִבְנֵ֥י אָדָֽם׃ כִּֽי־הִ֭שְׂבִּיעַ נֶ֣פֶשׁ שֹׁקֵקָ֑ה וְנֶ֥פֶשׁ רְ֝עֵבָ֗ה מִלֵּא־טֽוֹב׃ יֹ֭שְׁבֵי חֹ֣שֶׁךְ וְצַלְמָ֑וֶת אֲסִירֵ֖י עֳנִ֣י וּבַרְזֶֽל׃ כִּֽי־הִמְר֥וּ אִמְרֵי־אֵ֑ל וַעֲצַ֖ת עֶלְי֣וֹן נָאָֽצוּ׃ וַיַּכְנַ֣ע בֶּעָמָ֣ל לִבָּ֑ם כָּ֝שְׁל֗וּ וְאֵ֣ין עֹזֵֽר׃ וַיִּזְעֲק֣וּ אֶל־יְ֭הֹוָה בַּצַּ֣ר לָהֶ֑ם מִ֝מְּצֻ֥קוֹתֵיהֶ֗ם יוֹשִׁיעֵֽם׃ י֭וֹצִיאֵם מֵחֹ֣שֶׁךְ וְצַלְמָ֑וֶת וּמוֹסְר֖וֹתֵיהֶ֣ם יְנַתֵּֽק׃ יוֹד֣וּ לַיהֹוָ֣ה חַסְדּ֑וֹ וְ֝נִפְלְאוֹתָ֗יו לִבְנֵ֥י אָדָֽם׃ כִּֽי־שִׁ֭בַּר דַּלְת֣וֹת נְחֹ֑שֶׁת וּבְרִיחֵ֖י בַרְזֶ֣ל גִּדֵּֽעַ׃ אֱ֭וִלִים מִדֶּ֣רֶךְ פִּשְׁעָ֑ם וּֽ֝מֵעֲוֺ֥נֹתֵיהֶ֗ם יִתְעַנּֽוּ׃ כׇּל־אֹ֭כֶל תְּתַעֵ֣ב נַפְשָׁ֑ם וַ֝יַּגִּ֗יעוּ עַד־שַׁ֥עֲרֵי מָֽוֶת׃ וַיִּזְעֲק֣וּ אֶל־יְ֭הֹוָה בַּצַּ֣ר לָהֶ֑ם מִ֝מְּצֻ֥קוֹתֵיהֶ֗ם יוֹשִׁיעֵֽם׃ יִשְׁלַ֣ח דְּ֭בָרוֹ וְיִרְפָּאֵ֑ם וִ֝ימַלֵּ֗ט מִשְּׁחִֽיתוֹתָֽם׃ יוֹד֣וּ לַיהֹוָ֣ה חַסְדּ֑וֹ וְ֝נִפְלְאוֹתָ֗יו לִבְנֵ֥י אָדָֽם׃ וְ֭יִזְבְּחוּ זִבְחֵ֣י תוֹדָ֑ה וִיסַפְּר֖וּ מַעֲשָׂ֣יו בְּרִנָּֽה׃ יוֹרְדֵ֣י הַ֭יָּם בׇּאֳנִיּ֑וֹת עֹשֵׂ֥י מְ֝לָאכָ֗ה בְּמַ֣יִם רַבִּֽים׃ הֵ֣מָּה רָ֭אוּ מַעֲשֵׂ֣י יְהֹוָ֑ה וְ֝נִפְלְאוֹתָ֗יו בִּמְצוּלָֽה׃ וַיֹּ֗אמֶר וַֽ֭יַּעֲמֵד ר֣וּחַ סְעָרָ֑ה וַתְּרוֹמֵ֥ם גַּלָּֽיו׃ יַעֲל֣וּ שָׁ֭מַיִם יֵרְד֣וּ תְהוֹמ֑וֹת נַ֝פְשָׁ֗ם בְּרָעָ֥ה תִתְמוֹגָֽג׃ יָח֣וֹגּוּ וְ֭יָנוּעוּ כַּשִּׁכּ֑וֹר וְכׇל־חׇ֝כְמָתָ֗ם תִּתְבַּלָּֽע׃ וַיִּצְעֲק֣וּ אֶל־יְ֭הֹוָה בַּצַּ֣ר לָהֶ֑ם וּֽ֝מִמְּצ֥וּקֹתֵיהֶ֗ם יוֹצִיאֵֽם׃ יָקֵ֣ם סְ֭עָרָה לִדְמָמָ֑ה וַ֝יֶּחֱשׁ֗וּ גַּלֵּיהֶֽם׃ וַיִּשְׂמְח֥וּ כִֽי־יִשְׁתֹּ֑קוּ וַ֝יַּנְחֵ֗ם אֶל־מְח֥וֹז חֶפְצָֽם׃ יוֹד֣וּ לַיהֹוָ֣ה חַסְדּ֑וֹ וְ֝נִפְלְאוֹתָ֗יו לִבְנֵ֥י אָדָֽם׃ וִֽ֭ירוֹמְמוּהוּ בִּקְהַל־עָ֑ם וּבְמוֹשַׁ֖ב זְקֵנִ֣ים יְהַלְלֽוּהוּ׃ יָשֵׂ֣ם נְהָר֣וֹת לְמִדְבָּ֑ר וּמֹצָ֥אֵי מַ֗֝יִם לְצִמָּאֽוֹן׃ אֶ֣רֶץ פְּ֭רִי לִמְלֵחָ֑ה מֵ֝רָעַ֗ת י֣וֹשְׁבֵי בָֽהּ׃ יָשֵׂ֣ם מִ֭דְבָּר לַאֲגַם־מַ֑יִם וְאֶ֥רֶץ צִ֝יָּ֗ה לְמֹצָ֥אֵי מָֽיִם׃ וַיּ֣וֹשֶׁב שָׁ֣ם רְעֵבִ֑ים וַ֝יְכוֹנְנ֗וּ עִ֣יר מוֹשָֽׁב׃ וַיִּזְרְע֣וּ שָׂ֭דוֹת וַיִּטְּע֣וּ כְרָמִ֑ים וַ֝יַּעֲשׂ֗וּ פְּרִ֣י תְבוּאָֽה׃ וַיְבָרְכֵ֣ם וַיִּרְבּ֣וּ מְאֹ֑ד וּ֝בְהֶמְתָּ֗ם לֹ֣א יַמְעִֽיט׃ וַיִּמְעֲט֥וּ וַיָּשֹׁ֑חוּ מֵעֹ֖צֶר רָעָ֣ה וְיָגֽוֹן׃ שֹׁפֵ֣ךְ בּ֭וּז עַל־נְדִיבִ֑ים וַ֝יַּתְעֵ֗ם בְּתֹ֣הוּ לֹא־דָֽרֶךְ׃ וַיְשַׂגֵּ֣ב אֶבְי֣וֹן מֵע֑וֹנִי וַיָּ֥שֶׂם כַּ֝צֹּ֗אן מִשְׁפָּחֽוֹת׃ יִרְא֣וּ יְשָׁרִ֣ים וְיִשְׂמָ֑חוּ וְכׇל־עַ֝וְלָ֗ה קָ֣פְצָה פִּֽיהָ׃ מִי־חָכָ֥ם וְיִשְׁמׇר־אֵ֑לֶּה וְ֝יִתְבּוֹנְנ֗וּ חַֽסְדֵ֥י יְהֹוָֽה׃"}, {"kind": "instruction", "text": "במוסף לפסח ימשיך קדיש יהא שלמא וקוה עד הסוף"}, {"kind": "header", "text": "מזמור לשבועות"}, {"kind": "text", "text": "<b>לַמְנַצֵּ֥חַ</b> לְדָוִ֗ד מִזְמ֥וֹר שִֽׁיר׃ יָק֣וּם אֱ֭לֹהִים יָפ֣וּצוּ אוֹיְבָ֑יו וְיָנ֥וּסוּ מְ֝שַׂנְאָ֗יו מִפָּנָֽיו׃ כְּהִנְדֹּ֥ף עָשָׁ֗ן תִּ֫נְדֹּ֥ף כְּהִמֵּ֣ס דּ֭וֹנַג מִפְּנֵי־אֵ֑שׁ יֹאבְד֥וּ רְ֝שָׁעִ֗ים מִפְּנֵ֥י אֱלֹהִֽים׃ וְֽצַדִּיקִ֗ים יִשְׂמְח֣וּ יַ֭עַלְצוּ לִפְנֵ֥י אֱלֹהִ֗ים וְיָשִׂ֥ישׂוּ בְשִׂמְחָֽה׃ שִׁ֤ירוּ ׀ לֵאלֹהִים֮ זַמְּר֢וּ שְׁ֫מ֥וֹ סֹ֡לּוּ לָרֹכֵ֣ב בָּ֭עֲרָבוֹת בְּיָ֥הּ שְׁמ֗וֹ וְעִלְז֥וּ לְפָנָֽיו׃ אֲבִ֣י יְ֭תוֹמִים וְדַיַּ֣ן אַלְמָנ֑וֹת אֱ֝לֹהִ֗ים בִּמְע֥וֹן קׇדְשֽׁוֹ׃ אֱלֹהִ֤ים ׀ מ֘וֹשִׁ֤יב יְחִידִ֨ים ׀ בַּ֗יְתָה מוֹצִ֣יא אֲ֭סִירִים בַּכּוֹשָׁר֑וֹת אַ֥ךְ ס֝וֹרְרִ֗ים שָׁכְנ֥וּ צְחִיחָֽה׃ אֱֽלֹהִ֗ים בְּ֭צֵאתְךָ לִפְנֵ֣י עַמֶּ֑ךָ בְּצַעְדְּךָ֖ בִישִׁימ֣וֹן סֶֽלָה׃ אֶ֤רֶץ רָעָ֨שָׁה ׀ אַף־שָׁמַ֣יִם נָטְפוּ֮ מִפְּנֵ֢י אֱלֹ֫הִ֥ים זֶ֥ה סִינַ֑י מִפְּנֵ֥י אֱ֝לֹהִ֗ים אֱלֹהֵ֥י יִשְׂרָאֵֽל׃ גֶּ֣שֶׁם נְ֭דָבוֹת תָּנִ֣יף אֱלֹהִ֑ים נַחֲלָתְךָ֥ וְ֝נִלְאָ֗ה אַתָּ֥ה כוֹנַנְתָּֽהּ׃ חַיָּתְךָ֥ יָשְׁבוּ־בָ֑הּ תָּ֤כִֽין בְּטוֹבָתְךָ֖ לֶֽעָנִ֣י אֱלֹהִֽים׃ אֲדֹנָ֥י יִתֶּן־אֹ֑מֶר הַ֝מְבַשְּׂר֗וֹת צָבָ֥א רָֽב׃ מַלְכֵ֣י צְ֭בָאוֹת יִדֹּד֣וּן יִדֹּד֑וּן וּנְוַת בַּ֗֝יִת תְּחַלֵּ֥ק שָׁלָֽל׃ אִֽם־תִּשְׁכְּבוּן֮ בֵּ֤ין שְׁפַ֫תָּ֥יִם כַּנְפֵ֣י י֭וֹנָה נֶחְפָּ֣ה בַכֶּ֑סֶף וְ֝אֶבְרוֹתֶ֗יהָ בִּירַקְרַ֥ק חָרֽוּץ׃ בְּפָ֘רֵ֤שׂ שַׁדַּ֓י מְלָ֘כִ֤ים בָּ֗הּ תַּשְׁלֵ֥ג בְּצַלְמֽוֹן׃ הַר־אֱ֭לֹהִים הַר־בָּשָׁ֑ן הַ֥ר גַּ֝בְנֻנִּ֗ים הַר־בָּשָֽׁן׃ לָ֤מָּה ׀ תְּֽרַצְּדוּן֮ הָרִ֢ים גַּבְנֻ֫נִּ֥ים הָהָ֗ר חָמַ֣ד אֱלֹהִ֣ים לְשִׁבְתּ֑וֹ אַף־יְ֝הֹוָ֗ה יִשְׁכֹּ֥ן לָנֶֽצַח׃ רֶ֤כֶב אֱלֹהִ֗ים רִבֹּתַ֣יִם אַלְפֵ֣י שִׁנְאָ֑ן אֲדֹנָ֥י בָ֗֝ם סִינַ֥י בַּקֹּֽדֶשׁ׃ עָ֘לִ֤יתָ לַמָּר֨וֹם ׀ שָׁ֘בִ֤יתָ שֶּׁ֗בִי לָקַ֣חְתָּ מַ֭תָּנוֹת בָּאָדָ֑ם וְאַ֥ף ס֝וֹרְרִ֗ים לִשְׁכֹּ֤ן ׀ יָ֬הּ אֱלֹהִֽים׃ בָּ֤ר֣וּךְ אֲדֹנָי֮ י֤וֹם ׀ י֥֫וֹם יַעֲמָס־לָ֗נוּ הָ֘אֵ֤ל יְֽשׁוּעָתֵ֬נוּ סֶֽלָה׃ הָ֤אֵ֣ל ׀  לָנוּ֮ אֵ֤ל לְֽמוֹשָׁ֫ע֥וֹת וְלֵיהֹוִ֥ה אֲדֹנָ֑י לַ֝מָּ֗וֶת תֹּצָאֽוֹת׃ אַךְ־אֱלֹהִ֗ים יִמְחַץ֮ רֹ֤אשׁ אֹ֫יְבָ֥יו קׇדְקֹ֥ד שֵׂעָ֑ר מִ֝תְהַלֵּ֗ךְ בַּאֲשָׁמָֽיו׃ אָמַ֣ר אֲ֭דֹנָי מִבָּשָׁ֣ן אָשִׁ֑יב אָ֝שִׁ֗יב מִֽמְּצֻל֥וֹת יָֽם׃ לְמַ֤עַן ׀ תִּ֥מְחַ֥ץ רַגְלְךָ֗ בְּ֫דָ֥ם לְשׁ֥וֹן כְּלָבֶ֑יךָ מֵאֹיְבִ֥ים מִנֵּֽהוּ׃ רָא֣וּ הֲלִיכוֹתֶ֣יךָ אֱלֹהִ֑ים הֲלִ֘יכ֤וֹת אֵלִ֖י מַלְכִּ֣י בַקֹּֽדֶשׁ׃ קִדְּמ֣וּ שָׁ֭רִים אַחַ֣ר נֹגְנִ֑ים בְּת֥וֹךְ עֲ֝לָמ֗וֹת תּוֹפֵפֽוֹת׃ בְּֽ֭מַקְהֵלוֹת בָּרְכ֣וּ אֱלֹהִ֑ים אֲ֝דֹנָ֗י מִמְּק֥וֹר יִשְׂרָאֵֽל׃ שָׁ֤ם בִּנְיָמִ֨ן ׀ צָעִ֡יר רֹדֵ֗ם שָׂרֵ֣י יְ֭הוּדָה רִגְמָתָ֑ם שָׂרֵ֥י זְ֝בֻל֗וּן שָׂרֵ֥י נַפְתָּלִֽי׃ צִוָּ֥ה אֱלֹהֶ֗יךָ עֻ֫זֶּ֥ךָ עוּזָּ֥ה אֱלֹהִ֑ים ז֗֝וּ פָּעַ֥לְתָּ לָּֽנוּ׃ מֵ֭הֵיכָלֶךָ עַל־יְרוּשָׁלָ֑‍ִם לְךָ֤ יוֹבִ֖ילוּ מְלָכִ֣ים שָֽׁי׃ גְּעַ֨ר חַיַּ֪ת קָנֶ֡ה עֲדַ֤ת אַבִּירִ֨ים ׀ בְּעֶגְלֵ֬י עַמִּ֗ים מִתְרַפֵּ֥ס בְּרַצֵּי־כָ֑סֶף בִּזַּ֥ר עַ֝מִּ֗ים קְרָב֥וֹת יֶחְפָּֽצוּ׃ יֶאֱתָ֣יוּ חַ֭שְׁמַנִּים מִנִּ֣י מִצְרָ֑יִם כּ֥וּשׁ תָּרִ֥יץ יָ֝דָ֗יו לֵאלֹהִֽים׃ מַמְלְכ֣וֹת הָ֭אָרֶץ שִׁ֣ירוּ לֵאלֹהִ֑ים זַמְּר֖וּ אֲדֹנָ֣י סֶֽלָה׃ לָ֭רֹכֵב בִּשְׁמֵ֣י שְׁמֵי־קֶ֑דֶם הֵ֥ן יִתֵּ֥ן בְּ֝קוֹל֗וֹ ק֣וֹל עֹֽז׃ תְּנ֥וּ עֹ֗ז לֵאלֹ֫הִ֥ים עַֽל־יִשְׂרָאֵ֥ל גַּאֲוָת֑וֹ וְ֝עֻזּ֗וֹ בַּשְּׁחָקִֽים׃ נ֤וֹרָ֥א אֱלֹהִ֗ים מִֽמִּקְדָּ֫שֶׁ֥יךָ אֵ֤ל יִשְׂרָאֵ֗ל ה֤וּא נֹתֵ֨ן ׀ עֹ֖ז וְתַעֲצֻמ֥וֹת לָעָ֗ם בָּר֥וּךְ אֱלֹהִֽים׃"}, {"kind": "header", "text": "מזמור לסוכות"}, {"kind": "text", "text": "<b>לַמְנַצֵּ֗חַ</b> מַשְׂכִּ֥יל לִבְנֵי־קֹֽרַח׃ כְּאַיָּ֗ל תַּעֲרֹ֥ג עַל־אֲפִֽיקֵי־מָ֑יִם כֵּ֤ן נַפְשִׁ֨י תַעֲרֹ֖ג אֵלֶ֣יךָ אֱלֹהִֽים׃ צָמְאָ֬ה נַפְשִׁ֨י ׀ לֵאלֹהִים֮ לְאֵ֢ל חָ֥י מָתַ֥י אָב֑וֹא וְ֝אֵרָאֶ֗ה פְּנֵ֣י אֱלֹהִֽים׃ הָיְתָה־לִּ֬י דִמְעָתִ֣י לֶ֭חֶם יוֹמָ֣ם וָלָ֑יְלָה בֶּאֱמֹ֥ר אֵלַ֥י כׇּל־הַ֝יּ֗וֹם אַיֵּ֥ה אֱלֹהֶֽיךָ׃ אֵ֤לֶּה אֶזְכְּרָ֨ה ׀ וְאֶשְׁפְּכָ֬ה עָלַ֨י ׀ נַפְשִׁ֗י כִּ֤י אֶעֱבֹ֨ר ׀ בַּסָּךְ֮ אֶדַּדֵּ֗ם עַד־בֵּ֥ית אֱלֹ֫הִ֥ים בְּקוֹל־רִנָּ֥ה וְתוֹדָ֗ה הָמ֥וֹן חוֹגֵֽג׃ מַה־תִּשְׁתּ֬וֹחֲחִ֨י ׀ נַפְשִׁי֮ וַתֶּהֱמִ֢י עָ֫לָ֥י הוֹחִ֣לִי לֵ֭אלֹהִים כִּי־ע֥וֹד אוֹדֶ֗נּוּ יְשׁוּע֥וֹת פָּנָֽיו׃ אֱלֹהַ֗י עָלַי֮ נַפְשִׁ֢י תִשְׁתּ֫וֹחָ֥ח עַל־כֵּ֗ן אֶ֭זְכׇּרְךָ מֵאֶ֣רֶץ יַרְדֵּ֑ן וְ֝חֶרְמוֹנִ֗ים מֵהַ֥ר מִצְעָֽר׃ תְּהוֹם־אֶל־תְּה֣וֹם ק֭וֹרֵא לְק֣וֹל צִנּוֹרֶ֑יךָ כׇּֽל־מִשְׁבָּרֶ֥יךָ וְ֝גַלֶּ֗יךָ עָלַ֥י עָבָֽרוּ׃ יוֹמָ֤ם ׀ יְצַוֶּ֬ה יְהֹוָ֨ה ׀ חַסְדּ֗וֹ וּ֭בַלַּיְלָה שִׁירֹ֣ה עִמִּ֑י תְּ֝פִלָּ֗ה לְאֵ֣ל חַיָּֽי׃ אוֹמְרָ֤ה ׀ לְאֵ֥ל סַלְעִי֮ לָמָ֢ה שְׁכַ֫חְתָּ֥נִי לָֽמָּה־קֹדֵ֥ר אֵלֵ֗ךְ בְּלַ֣חַץ אוֹיֵֽב׃ בְּרֶ֤צַח ׀ בְּֽעַצְמוֹתַ֗י חֵרְפ֥וּנִי צוֹרְרָ֑י בְּאׇמְרָ֥ם אֵלַ֥י כׇּל־הַ֝יּ֗וֹם אַיֵּ֥ה אֱלֹהֶֽיךָ׃ מַה־תִּשְׁתּ֬וֹחֲחִ֨י ׀ נַפְשִׁי֮ וּֽמַה־תֶּהֱמִ֢י עָ֫לָ֥י הוֹחִ֣ילִי לֵ֭אלֹהִים כִּי־ע֣וֹד אוֹדֶ֑נּוּ יְשׁוּעֹ֥ת פָּ֝נַ֗י וֵאלֹהָֽי׃"}, {"kind": "instruction", "text": "במוסף לסוכות ימשיך קדיש יהא שלמא וקוה עד הסוף"}, {"kind": "header", "text": "מזמור לשמיני עצרת"}, {"kind": "text", "text": "<b>לַמְנַצֵּ֥חַ</b> עַֽל־הַשְּׁמִינִ֗ית מִזְמ֥וֹר לְדָוִֽד׃ הוֹשִׁ֣יעָה יְ֭הֹוָה כִּֽי־גָמַ֣ר חָסִ֑יד כִּי־פַ֥סּוּ אֱ֝מוּנִ֗ים מִבְּנֵ֥י אָדָֽם׃ שָׁ֤וְא ׀ יְֽדַבְּרוּ֮ אִ֤ישׁ אֶת־רֵ֫עֵ֥הוּ שְׂפַ֥ת חֲלָק֑וֹת בְּלֵ֖ב וָלֵ֣ב יְדַבֵּֽרוּ׃ יַכְרֵ֣ת יְ֭הֹוָה כׇּל־שִׂפְתֵ֣י חֲלָק֑וֹת לָ֝שׁ֗וֹן מְדַבֶּ֥רֶת גְּדֹלֽוֹת׃ אֲשֶׁ֤ר אָמְר֨וּ ׀ לִלְשֹׁנֵ֣נוּ נַ֭גְבִּיר שְׂפָתֵ֣ינוּ אִתָּ֑נוּ מִ֖י אָד֣וֹן לָֽנוּ׃ מִשֹּׁ֥ד עֲנִיִּים֮ מֵאֶנְקַ֢ת אֶבְי֫וֹנִ֥ים עַתָּ֣ה אָ֭קוּם יֹאמַ֣ר יְהֹוָ֑ה אָשִׁ֥ית בְּ֝יֵ֗שַׁע יָפִ֥יחַֽ לֽוֹ׃ אִ֥מְר֣וֹת יְהֹוָה֮ אֲמָר֢וֹת טְהֹ֫ר֥וֹת כֶּ֣סֶף צָ֭רוּף בַּעֲלִ֣יל לָאָ֑רֶץ מְ֝זֻקָּ֗ק שִׁבְעָתָֽיִם׃ אַתָּֽה־יְהֹוָ֥ה תִּשְׁמְרֵ֑ם תִּצְּרֶ֓נּוּ ׀ מִן־הַדּ֖וֹר ז֣וּ לְעוֹלָֽם׃ סָבִ֗יב רְשָׁעִ֥ים יִתְהַלָּכ֑וּן כְּרֻ֥ם זֻ֝לּ֗וּת לִבְנֵ֥י אָדָֽם׃"}, {"kind": "instruction", "text": "מתפללים ערבית כמו בשבת ואחר השכיבנו (ובשבת אחר ושמרו) אומרים אלה מועדי"}, {"kind": "text", "text": "<b>אֵ֚לֶּה</b> מוֹעֲדֵ֣י יְהֹוָ֔ה מִקְרָאֵ֖י קֹ֑דֶשׁ אֲשֶׁר־תִּקְרְא֥וּ אֹתָ֖ם בְּמוֹעֲדָֽם׃ וַיְדַבֵּ֣ר מֹשֶׁ֔ה אֶת־מֹעֲדֵ֖י יְהֹוָ֑ה אֶל־בְּנֵ֖י יִשְׂרָאֵֽל׃"}, {"kind": "instruction", "text": "ואומר החזן חצי קדיש"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "header", "text": "עמידה לשחרית מנחה וערבית שלש רגלים"}, {"kind": "text", "text": "<b>אֲ֭דֹנָי</b> שְׂפָתַ֣י תִּפְתָּ֑ח וּ֝פִ֗י יַגִּ֥יד תְּהִלָּתֶֽךָ׃"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵֽאלֹהֵי יַעֲקֹב. הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, קוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵּי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַֽעַן שְׁמוֹ בְּאַֽהֲבָה: מֶֽלֶךְ עוֹזֵר וּמוֹשִֽׁיעַ וּמָגֵן: בָּרוּךְ אַתָּה יַהַוַהַ, מָגֵן אַבְרָהָם:"}, {"kind": "text", "text": "<b>אַתָּה</b> גִבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֶּה מֵתִים אַתָּה, רַב לְהוֹשִֽׁיעַ."}, {"kind": "text", "text": "בקיץ: מוֹרִיד הַטָּל. בחורף: מַשִּׁיב הָרֽוּחַ וּמוֹרִיד הַגֶּֽשֶׁם."}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶֽסֶד, מְחַיֵּה מֵתִים בְּרַֽחֲמִים רַבִּים, סוֹמֵךְ נֽוֹפְלִים, וְרוֹפֵא חוֹלִים, וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמֽוּנָתוֹ לִֽישֵׁנֵי עָפָר. מִי כָמֽוֹךָ בַּֽעַל גְּבוּרוֹת, וּמִי דֽוֹמֶה לָךְ, מֶֽלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִֽיחַ יְשׁוּעָה. וְנֶֽאֱמָן אַתָּה לְהַֽחֲיוֹת מֵתִים: בָּרוּךְ אַתָּה יֵהֵוֵהֵ, מְחַיֵּה הַמֵּתִים:"}, {"kind": "instruction", "text": "קדושה<br>בחזרת הש\"ץ של שחרית ומנחה אומרים:"}, {"kind": "instruction", "text": "נַקְדִּישָׁךְ וְנַעֲרִיצָךְ, כְּנֹֽעַם שִֽׂיחַ סוֹד שַׂרְפֵי קֹֽדֶשׁ, הַמְשַׁלְּשִׁים לְךָ קְדֻשָּׁה, וְכֵן כָּתוּב עַל יַד נְבִיאָךְ: וְקָרָ֨א זֶ֤ה אֶל־זֶה֙ וְאָמַ֔ר קָד֧וֹשׁ ׀ קָד֛וֹשׁ קָד֖וֹשׁ יְהֹוָ֣ה צְבָא֑וֹת מְלֹ֥א כָל־הָאָ֖רֶץ כְּבוֹדֽוֹ׃ לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים: בָּר֥וּךְ כְּבוֹד־יְהֹוָ֖ה מִמְּקוֹמֽוֹ׃ וּבְדִבְרֵי קָדְשָׁךְ כָּתוּב לֵאמֹר: יִמְלֹ֤ךְ יְהֹוָ֨ה ׀ לְעוֹלָ֗ם אֱלֹהַ֣יִךְ צִ֭יּוֹן לְדֹ֥ר וָדֹ֗ר הַֽלְלוּיָֽהּ:"}, {"kind": "text", "text": "<b>אַתָּה</b> קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ, וּקְדוֹשִׁים בְּכָל־יוֹם יְהַֽלְלֽוּךָ סֶּֽלָה: בָּרוּךְ אַתָּה יֹהֵוָהֵ, הָאֵל הַקָּדוֹשׁ:"}, {"kind": "text", "text": "<b>אַתָּה</b> בְּחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ, וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת, וְקִדַּשְׁתָּנוּ בְּמִצְוֹתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ."}, {"kind": "instruction", "text": "במוצאי שבת אומרים"}, {"kind": "instruction", "text": "וַתּוֹדִיעֵנוּ מִשְׁפְּטֵי צִדְקֶךָ, וַתְּלַמְּדֵנוּ לַעֲשׂוֹת בָּהֶם חֻקֵּי רְצוֹנֶךָ, וַתִּתֶּן לָנוּ יְהֹוָה אֱלֹהֵינוּ בְּאַהֲבָה מִשְׁפָּטִים יְשָׁרִים וְתוֹרוֹת אֱמֶת, חֻקִּים וּמִצְוֹת טוֹבִים, וַתַּנְחִילֵנוּ זְמַנֵּי שָׂשׂוֹן וּמוֹעֲדֵי קֹדֶשׁ וְחַגֵּי נְדָבָה, וַתּוֹרִישֵׁנוּ קְדֻשַּׁת שַׁבָּת וּכְבוֹד מוֹעֵד וַחֲגִיגַת הָרֶגֶל. בֵּין קְדֻשַּׁת שַׁבָּת לִקְדֻשַּׁת יוֹם טוֹב הִבְדַּלְתָּ, וְאֶת יוֹם הַשְּׁבִיעִי מִשֵּׁשֶׁת יְמֵי הַמַּעֲשֶׂה הִקְדַּשְׁתָּ, וְהִבְדַּלְתָּ וְהִקְדַּשְׁתָּ אֶת עַמְּךָ יִשְׂרָאֵל בִּקְדֻשָּׁתָךְ:"}, {"kind": "text", "text": "וַתִּֽתֶּן לָֽנוּ יְהֹוָה אֱלֹהֵֽינוּ בְּאַהֲבָה"}, {"kind": "text", "text": "בשבת שַׁבָּתוֹת לִמְנוּחָה וּ"}, {"kind": "text", "text": "מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן, אֶת יוֹם"}, {"kind": "text", "text": "בשבת הַשַּׁבָּת הַזֶּה, וְאֶת יוֹם"}, {"kind": "text", "text": "בפסח: חַג הַמַּצּוֹת הַזֶּה, אֶת יוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה, זְמַן חֵרוּתֵנוּ:"}, {"kind": "text", "text": "בשבועות: חַג הַשָׁבוּעוֹת הַזֶּה, אֶת יוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה, זְמַן מַתַּן תּוֹרָתֵֽינוּ:"}, {"kind": "text", "text": "בסוכות: חַג הַסֻּכּוֹת הַזֶּה, אֶת יוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה, זְמַן שִׂמְחָתֵֽנוּ:"}, {"kind": "text", "text": "בש''ע: שְׁמִינִי חַג עֲצֶֽרֶת הַזֶּה, אֶת יוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה, זְמַן שִׂמְחָתֵֽנוּ:"}, {"kind": "text", "text": "בְּאַהֲבָה מִקְרָא קֹֽדֶשׁ זֵֽכֶר לִיצִיאַת מִצְרָֽיִם."}, {"kind": "text", "text": "<b>אֱלֹהֵֽינוּ</b> וֵאלֹהֵי אֲבוֹתֵֽינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּֽיעַ וְיֵרָאֶה, וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵֽנוּ וְזִכְרוֹן אֲבוֹתֵֽינוּ, זִכְרוֹן יְרוּשָׁלַֽיִם עִירָךְ, וְזִכְרוֹן מָשִֽׁיחַ בֶּן־דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל־עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶֽיךָ, לִפְלֵיטָה, לְטוֹבָה, לְחֵן, לְחֶֽסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם, בְּיוֹם"}, {"kind": "text", "text": "בשבת הַשַּׁבָּת הַזֶּה, וּבְיוֹם"}, {"kind": "text", "text": "בפסח: חַג הַמַּצּוֹת הַזֶּה,"}, {"kind": "text", "text": "בשבועות: חַג הַשָּׁבוּעוֹת הַזֶּה,"}, {"kind": "text", "text": "בסוכות: חַג הַסֻּכּוֹת הַזֶּה,"}, {"kind": "text", "text": "בש''ע: שְׁמִינִי חַג עֲצֶֽרֶת הַזֶּה,"}, {"kind": "text", "text": "בְּיוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה,לְרַחֵם בּוֹ עָלֵֽינוּ וּלְהוֹשִׁיעֵֽנוּ. זָכְרֵֽנוּ יְהֹוָה אֱלֹהֵֽינוּ בּוֹ לְטוֹבָה, וּפָקְדֵֽנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵֽנוּ בוֹ לְחַיִּים טוֹבִים, בִּדְבַר יְשׁוּעָה וְרַחֲמִים. חוּס וְחָנֵּֽנוּ, וַחֲמוֹל וְרַחֵם עָלֵֽינוּ, וְהוֹשִׁיעֵֽנוּ כִּי אֵלֶֽיךָ עֵינֵֽינוּ, כִּי אֵל מֶֽלֶךְ חַנּוּן וְרַחוּם אָֽתָּה:"}, {"kind": "text", "text": "<b>וְהַשִּׂיאֵנוּ</b> יְהֹוָה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ לְחַיִּים בְּשִׂמְחָה וּבְשָׁלוֹם, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ כֵּן תְּבָרְכֵנוּ סֶלָה."}, {"kind": "text", "text": "בשבת אומרים אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, רְצֵה נָא בִּמְנוּחָתֵנוּ,"}, {"kind": "text", "text": "<b>קַדְּשֵׁנוּ</b> בְּמִצְוֹתֶיךָ, שִׂים חֶלְקֵנוּ בְּתוֹרָתָךְ, שַׂבְּעֵנוּ מִטּוּבָךְ, שַׂמֵּחַ נַפְשֵׁנוּ בִּישׁוּעָתָךְ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶאֱמֶת, וְהַנְחִילֵנוּ יְהֹוָה אֱלֹהֵינוּ בשבת בְּאַהֲבָה וּבְרָצוֹן בְּשִׂמְחָה וּבְשָׂשׂוֹן בשבת שַׁבָּתוֹת וּ מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְּךָ כָּל יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יְהֹוָה, מְקַדֵּשׁ בשבת הַשַּׁבָּת וְיִשְׂרָאֵל וְהַזְּמַנִּים:"}, {"kind": "text", "text": "<b>רְצֵה</b> יְהֹוָה אֱלֹהֵֽינוּ בְּעַמְּךָ יִשְׂרָאֵל וְלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב הָֽעֲבוֹדָה לִדְבִיר בֵּיתֶֽךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, מְהֵרָה בְּאַֽהֲבָה תְקַבֵּל בְּרָצוֹן, וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּֽךָ: וְאַתָּה בְּרַֽחֲמֶֽיךָ הָרַבִּים, תַּחְפֹּץ בָּֽנוּ וְתִרְצֵֽנוּ, וְתֶֽחֱזֶֽינָה עֵינֵֽינוּ בְּשֽׁוּבְךָ לְצִיּוֹן בְּרַֽחֲמִים: בָּרוּךְ אַתָּה יִהִוִהִ, הַמַּֽחֲזִיר שְׁכִֽינָתוֹ לְצִיּוֹן:"}, {"kind": "instruction", "text": "בברכת \"מודים\" יכרע ב\"מודים\" ויזקוף בשם (בא\"ח בשלח הכ\"א)"}, {"kind": "text", "text": "<b>מוֹדִים</b> אֲנַֽחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ לְעוֹלָם וָעֶד, צוּרֵֽנוּ צוּר חַיֵּֽינוּ וּמָגֵן יִשְׁעֵֽנוּ אַתָּה הוּא, לְדוֹר וָדוֹר נוֹדֶה לְךָ וּנְסַפֵּר תְּהִלָּתֶֽךָ, עַל חַיֵּֽינוּ הַמְּסוּרִים בְּיָדֶֽךָ, וְעַל נִשְׁמוֹתֵֽינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּֽיךָ שֶׁבְּכָל־יוֹם עִמָּֽנוּ, וְעַל נִפְלְאוֹתֶֽיךָ וְטֽוֹבוֹתֶֽיךָ שֶׁבְּכָל־עֵת, עֶֽרֶב וָבֹֽקֶר וְצָֽהֳרָֽיִם. הַטּוֹב, כִּי לֹא כָלוּ רַחֲמֶֽיךָ, הַמְּרַחֵם, כִּי לֹא תַֽמּוּ חֲסָדֶֽיךָ, כִּי מֵֽעוֹלָם קִוִּֽינוּ לָךְ:"}, {"kind": "text", "text": "<b>מודים דרבנן</b><br>בחזרת הש\"ץ כשהחזן אומר מודים, הקהל אומרים:<br>מוֹדִים אֲנַחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׁר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית. בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְחָנֵּנוּ וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמֹר חֻקֶּיךָ וְלַעֲשׂוֹת רְצוֹנְךָ וּלְעָבְדְךָ בְלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ, בָּרוּךְ אֵל הַהוֹדָאוֹת."}, {"kind": "text", "text": "<b>וְעַל</b> כֻּלָּם יִתְבָּרַךְ, וְיִתְרוֹמָם, וְיִתְנַשֵּׂא, תָּמִיד, שִׁמְךָ מַלְכֵּֽנוּ, לְעוֹלָם וָעֶד. וְכָל־הַחַיִּים יוֹדֽוּךָ סֶּֽלָה: וִֽיהַֽלְלוּ וִֽיבָֽרְכוּ אֶת־שִׁמְךָ הַגָּדוֹל בֶּֽאֱמֶת לְעוֹלָם כִּי טוֹב, הָאֵל יְשֽׁוּעָתֵֽנוּ וְעֶזְרָתֵֽנוּ סֶֽלָה, הָאֵל הַטּוֹב: משתחוה בברוך וזוקף בשם בָּרוּךְ אַתָּה יֻהֻוֻהֻ, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת:"}, {"kind": "text", "text": "ברכת כהנים"}, {"kind": "text", "text": "כשעוקר הכהן רגליו לישא כפיו יאמר (בא\"ח תצוה י\"ב)<br>לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ. בִּדְחִֽילוּ וּרְחִֽימוּ. וּרְחִֽימוּ וּדְחִֽילוּ. לְיַחֲדָא שֵׁם יוֹ\"ד קֵ\"א בְּוָא\"ו קֵ\"א בְּיִחוּדָא שְׁלִים. בְּשֵׁם כָּל־יִשְׂרָאֵל הִנֵּה אָנֹכִי מוּכָן וּמְזוּמָן לְקַיֵּם מִצְוַת עֲשֵׂה לְבָרֵךְ אֶת יִשְׂרָאֵל בִּרְכַּת כֹּהַנִים בִּנְשִׂיאוּת כַּפַּיִם, לַעֲשׂוֹת נַֽחַת רֽוּחַ לְיֽוֹצְרֵֽנוּ וּלְהַמְשִׁיךְ שֶׁפַע וּבְרָכָה לְכָל־הָעוֹלָמוֹת וְלַעֲשׂוֹת רְצוֹן בּֽוֹרְאֵֽנוּ. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ:"}, {"kind": "text", "text": "וכשעומדים הכהנים על הדוכן לאחר שענו \"מודים דרבנן\", אומרים<br>יְהִי רָצוֹן מִלְּפָנֶֽיךָ יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ שֶׁתִּהְיֶה בְּרָכָה זוֹ שֶׁצִּּוִיתָֽנוּ לְבָרֵךְ אֶת־עַמְּךָ יִשְׂרָאֵל בְּרָכָה שְׁלֵמָה וְלֹא יִהְיֶה בָהּ מִכְשׁוֹל וְעָוֹן מֵעַתָּה וְעַד עוֹלָם:"}, {"kind": "text", "text": "בחזרת הש\"ץ אומרים ברכת כהנים, אם יש יותר מכהן אחד קורא להם החזן: כֹּהֲנִים: הכהנים מברכים:<br>בָּרוּךְ אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָֽעוֹלָם, אֲשֶׁר קִדְּשָֽׁנוּ בִּקְדֻשָּׁתוֹ שֶׁל־אַֽהֲרֹן, וְצִוָּֽנוּ לְבָרֵךְ אֶת־עַמּוֹ יִשְׂרָאֵל בְּאַֽהֲבָה: הקהל עונים אָמֵן:"}, {"kind": "instruction", "text": "ואומר החזן והכהנים אחריו מילה במילה:"}, {"kind": "text", "text": "יְבָרֶכְךָ֥ יְהֹוָ֖ה וְיִשְׁמְרֶֽךָ׃ ועונים אָמֵן:"}, {"kind": "text", "text": "יָאֵ֨ר יְהֹוָ֧ה ׀ פָּנָ֛יו אֵלֶ֖יךָ וִֽיחֻנֶּֽךָּ׃ ועונים אָמֵן:"}, {"kind": "text", "text": "יִשָּׂ֨א יְהֹוָ֤ה ׀ פָּנָיו֙ אֵלֶ֔יךָ וְיָשֵׂ֥ם לְךָ֖ שָׁלֽוֹם׃ ועונים אָמֵן:"}, {"kind": "instruction", "text": "וכשמתחיל שליח ציבור \"שים שלום\" אז מחזירין פניהם כלפי ההיכל, ולא יחזירו פניהם קודם, ואז הכהנים אומרים<br>רִבּוֹן הָעוֹלָמִים עָשִֽׂינוּ מַה־שֶּׁגָּזַֽרְתָּ עָלֵֽינוּ, עַשֵׂה אַתָּה מַה־שֶּׁהִבְטָחְתָּֽנוּ. הַשְׁקִ֩יפָה֩ מִמְּע֨וֹן קׇדְשְׁךָ֜ מִן־הַשָּׁמַ֗יִם וּבָרֵ֤ךְ אֶֽת־עַמְּךָ֙ אֶת־יִשְׂרָאֵ֔ל:"}, {"kind": "instruction", "text": "אם אין עולים כהנים אומר החזן:<br>אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶת בַּתּוֹרָה הַכְּתוּבָה עַל יְדֵי מֹשֶׁה עַבְדֶּֽךָ, הָאֲמוּרָה מִפִּי אַהֲרֹן וּבָנָיו הַכֹּהֲנִים עַם קְדוֹשֶׁיךָ כָּאָמוּר:"}, {"kind": "text", "text": "יְבָרֶכְךָ֥ יְהֹוָ֖ה וְיִשְׁמְרֶֽךָ׃ ועונים כֵּן יְהִי רָצוֹן:"}, {"kind": "text", "text": "יָאֵ֨ר יְהֹוָ֧ה ׀ פָּנָ֛יו אֵלֶ֖יךָ וִֽיחֻנֶּֽךָּ׃ ועונים כֵּן יְהִי רָצוֹן:"}, {"kind": "text", "text": "יִשָּׂ֨א יְהֹוָ֤ה ׀ פָּנָיו֙ אֵלֶ֔יךָ וְיָשֵׂ֥ם לְךָ֖ שָׁלֽוֹם׃ ועונים כֵּן יְהִי רָצוֹן: וְשָׂמ֥וּ אֶת־שְׁמִ֖י עַל־בְּנֵ֣י יִשְׂרָאֵ֑ל וַאֲנִ֖י אֲבָרְכֵֽם:"}, {"kind": "text", "text": "<b>שִׂים</b> שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים חֵן וָחֶֽסֶד וְרַֽחֲמִים, עָלֵֽינוּ וְעַל כָּל־יִשְׂרָאֵל עַמֶּֽךָ. וּבָֽרְכֵֽנוּ אָבִֽינוּ כֻּלָּֽנוּ כְּאֶחָד בְּאוֹר פָּנֶֽיךָ, כִּי בְאוֹר פָּנֶֽיךָ נָתַֽתָּ לָּֽנוּ יְהֹוָה אֱלֹהֵֽינוּ תּוֹרָה וְחַיִּים, אַֽהֲבָה וָחֶֽסֶד, צְדָקָה וְרַֽחֲמִים, בְּרָכָה וְשָׁלוֹם. וְטוֹב בְּעֵינֶֽיךָ לְבָֽרְכֵֽנוּ וּלְבָרֵךְ אֶת־כָּל־עַמְּךָ יִשְׂרָאֵל, בְּרֹב עֹז וְשָׁלוֹם: בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמְּבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם. אָמֵן:"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>אֱלֹהַי</b>, נְצֹר לְשׁוֹנִי מֵרָע וְשִׂפְתוֹתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּֽעָפָר לַכֹּל תִּֽהְיֶה, פְּתַח לִבִּי בְּתוֹרָתֶֽךָ, וְאַחֲרֵי מִצְוֹתֶֽיךָ תִּרְדֹּף נַפְשִׁי. וְכָל־הַקָּמִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחְשְׁבוֹתָם. יִֽהְי֗וּ כְּמֹ֥ץ לִפְנֵי־ר֑וּחַ וּמַלְאַ֖ךְ יְהֹוָ֣ה דּוֹחֶֽה. קַבֵּל רִנַּת עַמֶּךָ. שַׂגְּבֵנוּ טַהֲרֵנוּ נוֹרָא. עֲשֵׂה לְמַֽעַן שְׁמָךְ, עֲשֵׂה לְמַֽעַן יְמִינָךְ, עֲשֵׂה לְמַֽעַן תּֽוֹרָתָךְ, עֲשֵׂה לְמַֽעַן קְדֻשָּׁתָךְ."}, {"kind": "text", "text": "סגולה לומר פסוק המתחיל וגומר באות שמתחיל וגומר שמו לְ֭מַעַן יֵחָלְצ֣וּן יְדִידֶ֑יךָ הוֹשִׁ֖יעָה יְמִֽינְךָ֣ וַעֲנֵֽנִי:"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>עֹשֶׂה</b> שָׁלוֹם בִּמְרוֹמָיו, הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵֽינוּ, וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן:"}, {"kind": "instruction", "text": "יְהִי רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְּיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ, לַעֲשׂוֹת חֻקֵּי רְצוֹנָךְ וּלְעָבְדָךְ בְּלֵבָב שָׁלֵם:"}, {"kind": "instruction", "text": "אחרי החזרה אומרים"}, {"kind": "text", "text": "<b>יְהִ֤י</b> שֵׁ֣ם יְהֹוָ֣ה מְבֹרָ֑ךְ מֵ֝עַתָּ֗ה וְעַד־עוֹלָֽם׃ מִמִּזְרַח־שֶׁ֥מֶשׁ עַד־מְבוֹא֑וֹ מְ֝הֻלָּ֗ל שֵׁ֣ם יְהֹוָֽה׃ רָ֖ם עַל־כׇּל־גּוֹיִ֥ם ׀ יְהֹוָ֑ה עַ֖ל הַשָּׁמַ֣יִם כְּבוֹדֽוֹ׃ יְהֹוָ֥ה אֲדֹנֵ֑ינוּ מָה־אַדִּ֥יר שִׁ֝מְךָ֗ בְּכׇל־הָאָֽרֶץ׃"}, {"kind": "instruction", "text": "בערבית ליל יום טוב, אחרי תפילת העמידה, אם חל בשבת אומרים ויכולו, והחזן אומר ברכת מעין שבע וקדיש תתקבל. ואם חל בחול אומרים יהי שם, והחזן אומר קדיש תתקבל. ובליל יום טוב ראשון של פסח, אחרי העמידה גומרים את ההלל בברכה תחילה וסוף, ואחר כך החזן אומר קדיש תתקבל, ואם חל בשבת אומרים ויכולו ומעין שבע, ויברכו על ההלל."}, {"kind": "text", "text": "אחרי קדיש תתקבל אומרים מזמורים אלו:"}, {"kind": "instruction", "text": "אם חל בשבת מוסיפים מזמור זה"}, {"kind": "text", "text": "<b>מִזְמ֥וֹר</b> (תהילים כ״ג) לְדָוִ֑ד יְהֹוָ֥ה רֹ֝עִ֗י לֹ֣א אֶחְסָֽר׃ בִּנְא֣וֹת דֶּ֭שֶׁא יַרְבִּיצֵ֑נִי עַל מֵ֖י מְנֻח֣וֹת יְנַהֲלֵֽנִי׃ נַפְשִׁ֥י יְשׁוֹבֵ֑ב יַֽנְחֵ֥נִי בְמַעְגְּלֵי־צֶ֝֗דֶק לְמַ֣עַן שְׁמֽוֹ׃ גַּ֤ם כִּֽי־אֵלֵ֨ךְ בְּגֵ֪יא צַלְמָ֡וֶת לֹא־אִ֘ירָ֤א רָ֗ע כִּי־אַתָּ֥ה עִמָּדִ֑י שִׁבְטְךָ֥ וּ֝מִשְׁעַנְתֶּ֗ךָ הֵ֣מָּה יְנַֽחֲמֻֽנִי׃ תַּעֲרֹ֬ךְ לְפָנַ֨י ׀ שֻׁלְחָ֗ן נֶ֥גֶד צֹרְרָ֑י דִּשַּׁ֥נְתָּ בַשֶּׁ֥מֶן רֹ֝אשִׁ֗י כּוֹסִ֥י רְוָיָֽה אַ֤ךְ ׀ ט֤וֹב וָחֶ֣סֶד יִ֭רְדְּפוּנִי כׇּל־יְמֵ֣י חַיָּ֑י וְשַׁבְתִּ֥י בְּבֵית־יְ֝הֹוָ֗ה לְאֹ֣רֶךְ יָמִֽים׃"}, {"kind": "instruction", "text": "בפסח אומרים"}, {"kind": "text", "text": "<b>בְּצֵ֣את</b> (תהילים קי״ד) יִ֭שְׂרָאֵל מִמִּצְרָ֑יִם בֵּ֥ית יַ֝עֲקֹ֗ב מֵעַ֥ם לֹעֵֽז׃ הָיְתָ֣ה יְהוּדָ֣ה לְקׇדְשׁ֑וֹ יִ֝שְׂרָאֵ֗ל מַמְשְׁלוֹתָֽיו׃ הַיָּ֣ם רָ֭אָה וַיָּנֹ֑ס הַ֝יַּרְדֵּ֗ן יִסֹּ֥ב לְאָחֽוֹר׃ הֶ֭הָרִים רָקְד֣וּ כְאֵילִ֑ים גְּ֝בָע֗וֹת כִּבְנֵי־צֹֽאן׃ מַה־לְּךָ֣ הַ֭יָּם כִּ֣י תָנ֑וּס הַ֝יַּרְדֵּ֗ן תִּסֹּ֥ב לְאָחֽוֹר׃ הֶ֭הָרִים תִּרְקְד֣וּ כְאֵילִ֑ים גְּ֝בָע֗וֹת כִּבְנֵי־צֹֽאן׃ מִלִּפְנֵ֣י אָ֭דוֹן ח֣וּלִי אָ֑רֶץ מִ֝לִּפְנֵ֗י אֱל֣וֹהַּ יַעֲקֹֽב׃ הַהֹפְכִ֣י הַצּ֣וּר אֲגַם־מָ֑יִם חַ֝לָּמִ֗ישׁ לְמַעְיְנוֹ־מָֽיִם׃"}, {"kind": "instruction", "text": "בשבועות, סוכות, ושמיני עצרת אומרים"}, {"kind": "text", "text": "<b>שִׁ֥יר</b> (תהילים קכ״ב) הַֽמַּעֲל֗וֹת לְדָ֫וִ֥ד שָׂ֭מַחְתִּי בְּאֹמְרִ֣ים לִ֑י בֵּ֖ית יְהֹוָ֣ה נֵלֵֽךְ׃ עֹ֭מְדוֹת הָי֣וּ רַגְלֵ֑ינוּ בִּ֝שְׁעָרַ֗יִךְ יְרוּשָׁלָֽ‍ִם׃ יְרוּשָׁלַ֥‍ִם הַבְּנוּיָ֑ה כְּ֝עִ֗יר שֶׁחֻבְּרָה־לָּ֥הּ יַחְדָּֽו׃ שֶׁשָּׁ֨ם עָל֪וּ שְׁבָטִ֡ים שִׁבְטֵי־יָ֭הּ עֵד֣וּת לְיִשְׂרָאֵ֑ל לְ֝הֹד֗וֹת לְשֵׁ֣ם יְהֹוָֽה׃ כִּ֤י שָׁ֨מָּה ׀ יָשְׁב֣וּ כִסְא֣וֹת לְמִשְׁפָּ֑ט כִּ֝סְא֗וֹת לְבֵ֣ית דָּוִֽד׃ שַׁ֭אֲלוּ שְׁל֣וֹם יְרוּשָׁלָ֑‍ִם יִ֝שְׁלָ֗יוּ אֹהֲבָֽיִךְ׃ יְהִי־שָׁל֥וֹם בְּחֵילֵ֑ךְ שַׁ֝לְוָ֗ה בְּאַרְמְנוֹתָֽיִךְ׃ לְ֭מַעַן אַחַ֣י וְרֵעָ֑י אֲדַבְּרָה־נָּ֖א שָׁל֣וֹם בָּֽךְ׃ לְ֭מַעַן בֵּית־יְהֹוָ֣ה אֱלֹהֵ֑ינוּ אֲבַקְשָׁ֖ה ט֣וֹב לָֽךְ׃"}, {"kind": "instruction", "text": "ואומרים קדיש יהא שלמא"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>יְהֵא</b> שְׁלָמָא רַבָּא מִן שְׁמַיָּא. חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה. וְשֵׁיזָבָא וּרְפוּאָה וּגְאוּלָה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]<br><br><b>עוֹשֶׂה</b> שָׁלוֹם בִּמְרוֹמָיו. הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>עָלֵֽינוּ</b> לְשַׁבֵּֽחַ לַֽאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָֽׂנוּ כְּגוֹיֵי הָֽאֲרָצוֹת, וְלֹא שָׂמָֽנוּ כְּמִשְׁפְּחוֹת הָֽאֲדָמָה, שֶׁלֹּא שָׂם חֶלְקֵֽנוּ כָּהֶם וְגוֹרָלֵֽנוּ כְּכָל־הֲמוֹנָם, שֶׁהֵם מִשְׁתַּֽחֲוִים לָהֶֽבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל־אֵל לֹֽא יוֹשִׁיעַ. וַֽאֲנַֽחְנוּ מִשְׁתַּחֲוִים לִפְנֵי מֶֽלֶךְ מַלְכֵי הַֽמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַֽיִם וְיוֹסֵד אָֽרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַֽיִם מִמַּֽעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵֽינוּ, וְאֵין עוֹד אַחֵר, אֱמֶת מַלְכֵּֽנוּ וְאֶֽפֶס זוּלָתוֹ. כַּכָּתוּב בַּתּוֹרָה. וְיָדַעְתָּ֣ הַיּ֗וֹם וַהֲשֵׁבֹתָ֮ אֶל־לְבָבֶךָ֒ כִּ֤י יְהֹוָה֙ ה֣וּא הָֽאֱלֹהִ֔ים בַּשָּׁמַ֣יִם מִמַּ֔עַל וְעַל־הָאָ֖רֶץ מִתָּ֑חַת אֵ֖ין עֽוֹד:"}, {"kind": "text", "text": "<b>עַל</b> כֵּן נְקַוֶּה לָךְ, יְהֹוָה אֱלֹהֵֽינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶֽרֶת עֻזָּךְ, לְהַֽעֲבִיר גִּלּוּלִים מִן הָאָֽרֶץ, וְהָֽאֱלִילִים כָּרוֹת יִכָּֽרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל־בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶֽךָ, לְהַפְנוֹת אֵלֶֽיךָ כָּל־רִשְׁעֵי אָֽרֶץ. יַכִּֽירוּ וְיֵֽדְעוּ כָּל־יֽוֹשְׁבֵי תֵבֵֽל, כִּי לְךָ תִכְרַע כָּל־בֶּֽרֶךְ, תִּשָּׁבַע כָּל־לָשׁוֹן. לְפָנֶֽיךָ, יְהֹוָה אֱלֹהֵֽינוּ יִכְרְעוּ וְיִפֹּֽלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּֽנוּ, וִיקַבְּלוּ כֻלָּם אֶת־עֹל מַלְכוּתֶֽךָ, וְתִמְלוֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעֽוֹלְמֵי עַד תִּמְלוֹךְ בְּכָבוֹד. כַּכָּתוּב בְּתוֹרָתָךְ: יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד׃ וְנֶאֱמַר. וְהָיָ֧ה יְהֹוָ֛ה לְמֶ֖לֶךְ עַל־כָּל־הָאָ֑רֶץ בַּיּ֣וֹם הַה֗וּא יִהְיֶ֧ה יְהֹוָ֛ה אֶחָ֖ד וּשְׁמ֥וֹ אֶחָֽד׃"}, {"kind": "instruction", "text": "וּבְתוֹרָתְךָ יְהֹוָה אֱלֹהֵינוּ כָּתוּב לֵּאמֹר. שְׁמַ֖ע יִשְׂרָאֵ֑ל יְהֹוָ֥ה אֱלֹהֵ֖ינוּ יְהֹוָ֥ה ׀ אֶחָֽד׃"}, {"kind": "header", "text": "הלל לראש חודש ולמועדים"}, {"kind": "instruction", "text": "בימים שגומרים את ההלל אומר החזן:"}, {"kind": "text", "text": "בִּרְשׁוּת מוֹרַי וְרַבּוֹתַי. והציבור עונים: שָׁמַיִם."}, {"kind": "instruction", "text": "והחזן מברך ואחר כך הציבור מברכים"}, {"kind": "instruction", "text": "בָּרוּךְ אַתָּה יְהֹוָה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוֹתָיו, וְצִוָּנוּ לִגְמוֹר אֶת הַהַלֵּל:"}, {"kind": "text", "text": "<b>הַ֥לְלוּיָ֨הּ</b> ׀ (תהילים קי״ג:א׳-ב׳) הַ֭לְלוּ עַבְדֵ֣י יְהֹוָ֑ה הַֽ֝לְל֗וּ אֶת־שֵׁ֥ם יְהֹוָֽה׃ יְהִ֤י שֵׁ֣ם יְהֹוָ֣ה מְבֹרָ֑ךְ מֵ֝עַתָּ֗ה וְעַד־עוֹלָֽם׃ מִמִּזְרַח־שֶׁ֥מֶשׁ עַד־מְבוֹא֑וֹ מְ֝הֻלָּ֗ל שֵׁ֣ם יְהֹוָֽה׃ רָ֖ם עַל־כׇּל־גּוֹיִ֥ם ׀ יְהֹוָ֑ה עַ֖ל הַשָּׁמַ֣יִם כְּבוֹדֽוֹ׃ מִ֭י כַּיהֹוָ֣ה אֱלֹהֵ֑ינוּ הַֽמַּגְבִּיהִ֥י לָשָֽׁבֶת׃ הַֽמַּשְׁפִּילִ֥י לִרְא֑וֹת בַּשָּׁמַ֥יִם וּבָאָֽרֶץ׃ מְקִ֥ימִ֣י מֵעָפָ֣ר דָּ֑ל מֵ֝אַשְׁפֹּ֗ת יָרִ֥ים אֶבְיֽוֹן׃ לְהוֹשִׁיבִ֥י עִם־נְדִיבִ֑ים עִ֗֝ם נְדִיבֵ֥י עַמּֽוֹ׃ מֽוֹשִׁיבִ֨י ׀ עֲקֶ֬רֶת הַבַּ֗יִת אֵֽם־הַבָּנִ֥ים שְׂמֵחָ֗ה הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>בְּצֵ֣את</b> (תהילים קי״ד:א׳-ב׳) יִ֭שְׂרָאֵל מִמִּצְרָ֑יִם בֵּ֥ית יַ֝עֲקֹ֗ב מֵעַ֥ם לֹעֵֽז׃ הָיְתָ֣ה יְהוּדָ֣ה לְקׇדְשׁ֑וֹ יִ֝שְׂרָאֵ֗ל מַמְשְׁלוֹתָֽיו׃ הַיָּ֣ם רָ֭אָה וַיָּנֹ֑ס הַ֝יַּרְדֵּ֗ן יִסֹּ֥ב לְאָחֽוֹר׃ הֶ֭הָרִים רָקְד֣וּ כְאֵילִ֑ים גְּ֝בָע֗וֹת כִּבְנֵי־צֹֽאן׃ מַה־לְּךָ֣ הַ֭יָּם כִּ֣י תָנ֑וּס הַ֝יַּרְדֵּ֗ן תִּסֹּ֥ב לְאָחֽוֹר׃ הֶ֭הָרִים תִּרְקְד֣וּ כְאֵילִ֑ים גְּ֝בָע֗וֹת כִּבְנֵי־צֹֽאן׃ מִלִּפְנֵ֣י אָ֭דוֹן ח֣וּלִי אָ֑רֶץ מִ֝לִּפְנֵ֗י אֱל֣וֹהַּ יַעֲקֹֽב׃ הַהֹפְכִ֣י הַצּ֣וּר אֲגַם־מָ֑יִם חַ֝לָּמִ֗ישׁ לְמַעְיְנוֹ־מָֽיִם׃"}, {"kind": "instruction", "text": "בימים שאין גומרים את ההלל מדלגים"}, {"kind": "text", "text": "<b>לֹ֤א</b> (תהילים קט״ו:א׳-ב׳) לָ֥נוּ יְהֹוָ֗ה לֹ֫א לָ֥נוּ כִּֽי־לְ֭שִׁמְךָ תֵּ֣ן כָּב֑וֹד עַל־חַ֝סְדְּךָ֗ עַל־אֲמִתֶּֽךָ׃ לָ֭מָּה יֹאמְר֣וּ הַגּוֹיִ֑ם אַיֵּה־נָ֗֝א אֱלֹהֵיהֶֽם׃ וֵאלֹהֵ֥ינוּ בַשָּׁמָ֑יִם כֹּ֖ל אֲשֶׁר־חָפֵ֣ץ עָשָֽׂה׃ עֲֽ֭צַבֵּיהֶם כֶּ֣סֶף וְזָהָ֑ב מַ֝עֲשֵׂ֗ה יְדֵ֣י אָדָֽם׃ פֶּֽה־לָ֭הֶם וְלֹ֣א יְדַבֵּ֑רוּ עֵינַ֥יִם לָ֝הֶ֗ם וְלֹ֣א יִרְאֽוּ׃ אׇזְנַ֣יִם לָ֭הֶם וְלֹ֣א יִשְׁמָ֑עוּ אַ֥ף לָ֝הֶ֗ם וְלֹ֣א יְרִיחֽוּן׃ יְדֵיהֶ֤ם ׀ וְלֹ֬א יְמִישׁ֗וּן רַ֭גְלֵיהֶם וְלֹ֣א יְהַלֵּ֑כוּ לֹא־יֶ֝הְגּ֗וּ בִּגְרוֹנָֽם׃ כְּ֭מוֹהֶם יִהְי֣וּ עֹשֵׂיהֶ֑ם כֹּ֖ל אֲשֶׁר־בֹּטֵ֣חַ בָּהֶֽם׃ יִ֭שְׂרָאֵל בְּטַ֣ח בַּיהֹוָ֑ה עֶזְרָ֖ם וּמָגִנָּ֣ם הֽוּא׃ בֵּ֣ית אַ֭הֲרֹן בִּטְח֣וּ בַיהֹוָ֑ה עֶזְרָ֖ם וּמָגִנָּ֣ם הֽוּא׃ יִרְאֵ֣י יְ֭הֹוָה בִּטְח֣וּ בַיהֹוָ֑ה עֶזְרָ֖ם וּמָגִנָּ֣ם הֽוּא׃"}, {"kind": "text", "text": "<b>יְהֹוָה֮</b> זְכָרָ֢נוּ יְבָ֫רֵ֥ךְ יְ֭בָרֵךְ אֶת־בֵּ֣ית יִשְׂרָאֵ֑ל יְ֝בָרֵ֗ךְ אֶת־בֵּ֥ית אַהֲרֹֽן׃ יְ֭בָרֵךְ יִרְאֵ֣י יְהֹוָ֑ה הַ֝קְּטַנִּ֗ים עִם־הַגְּדֹלִֽים׃ יֹסֵ֣ף יְהֹוָ֣ה עֲלֵיכֶ֑ם עֲ֝לֵיכֶ֗ם וְעַל־בְּנֵיכֶֽם׃ בְּרוּכִ֣ים אַ֭תֶּם לַיהֹוָ֑ה עֹ֝שֵׂ֗ה שָׁמַ֥יִם וָאָֽרֶץ׃ הַשָּׁמַ֣יִם שָׁ֭מַיִם לַיהֹוָ֑ה וְ֝הָאָ֗רֶץ נָתַ֥ן לִבְנֵי־אָדָֽם׃ לֹ֣א הַ֭מֵּתִים יְהַֽלְלוּ־יָ֑הּ וְ֝לֹ֗א כׇּל־יֹרְדֵ֥י דוּמָֽה׃ וַאֲנַ֤חְנוּ ׀ נְבָ֘רֵ֤ךְ יָ֗הּ מֵעַתָּ֥ה וְעַד־עוֹלָ֗ם הַֽלְלוּ יָֽהּ׃"}, {"kind": "instruction", "text": "בימים שאין גומרים את ההלל מדלגים"}, {"kind": "text", "text": "<b>אָ֭הַבְתִּי</b> (תהילים קט״ז:א׳-ב׳) כִּי־יִשְׁמַ֥ע ׀ יְהֹוָ֑ה אֶת־ק֝וֹלִ֗י תַּחֲנוּנָֽי׃ כִּי־הִטָּ֣ה אׇזְנ֣וֹ לִ֑י וּבְיָמַ֥י אֶקְרָֽא׃ אֲפָפ֤וּנִי ׀ חֶבְלֵי־מָ֗וֶת וּמְצָרֵ֣י שְׁא֣וֹל מְצָא֑וּנִי צָרָ֖ה וְיָג֣וֹן אֶמְצָֽא׃ וּבְשֵֽׁם־יְהֹוָ֥ה אֶקְרָ֑א אָנָּ֥ה יְ֝הֹוָ֗ה מַלְּטָ֥ה נַפְשִֽׁי׃ חַנּ֣וּן יְהֹוָ֣ה וְצַדִּ֑יק וֵ֖אלֹהֵ֣ינוּ מְרַחֵֽם׃ שֹׁמֵ֣ר פְּתָאיִ֣ם יְהֹוָ֑ה דַּ֝לֹּתִ֗י וְלִ֣י יְהוֹשִֽׁיעַ׃ שׁוּבִ֣י נַ֭פְשִׁי לִמְנוּחָ֑יְכִי כִּֽי־יְ֝הֹוָ֗ה גָּמַ֥ל עָלָֽיְכִי׃ כִּ֤י חִלַּ֥צְתָּ נַפְשִׁ֗י מִ֫מָּ֥וֶת אֶת־עֵינִ֥י מִן־דִּמְעָ֑ה אֶת־רַגְלִ֥י מִדֶּֽחִי׃ אֶ֭תְהַלֵּךְ לִפְנֵ֣י יְהֹוָ֑ה בְּ֝אַרְצ֗וֹת הַחַיִּֽים׃ הֶ֭אֱמַנְתִּי כִּ֣י אֲדַבֵּ֑ר אֲ֝נִ֗י עָנִ֥יתִי מְאֹֽד׃ אֲ֭נִי אָמַ֣רְתִּי בְחׇפְזִ֑י כׇּֽל־הָאָדָ֥ם כֹּזֵֽב׃"}, {"kind": "text", "text": "<b>מָה־אָשִׁ֥יב</b> לַיהֹוָ֑ה כׇּֽל־תַּגְמוּל֥וֹהִי עָלָֽי׃ כּוֹס־יְשׁוּע֥וֹת אֶשָּׂ֑א וּבְשֵׁ֖ם יְהֹוָ֣ה אֶקְרָֽא׃ נְ֭דָרַי לַיהֹוָ֣ה אֲשַׁלֵּ֑ם נֶגְדָה־נָּ֗֝א לְכׇל־עַמּֽוֹ׃ יָ֭קָר בְּעֵינֵ֣י יְהֹוָ֑ה הַ֝מָּ֗וְתָה לַחֲסִידָֽיו׃ אָנָּ֣ה יְהֹוָה֮ כִּֽי־אֲנִ֢י עַ֫בְדֶּ֥ךָ אֲנִי־עַ֭בְדְּךָ בֶּן־אֲמָתֶ֑ךָ פִּ֝תַּ֗חְתָּ לְמֽוֹסֵרָֽי׃ לְֽךָ־אֶ֭זְבַּח זֶ֣בַח תּוֹדָ֑ה וּבְשֵׁ֖ם יְהֹוָ֣ה אֶקְרָֽא׃ נְ֭דָרַי לַיהֹוָ֣ה אֲשַׁלֵּ֑ם נֶגְדָה־נָּ֗֝א לְכׇל־עַמּֽוֹ׃ בְּחַצְר֤וֹת ׀ בֵּ֤ית יְהֹוָ֗ה בְּֽת֘וֹכֵ֤כִי יְֽרוּשָׁלָ֗‍ִם הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>הַֽלְל֣וּ</b> (תהילים קי״ז:א׳-ב׳) אֶת־יְ֭הֹוָה כׇּל־גּוֹיִ֑ם שַׁ֝בְּח֗וּהוּ כׇּל־הָאֻמִּֽים׃ כִּ֥י גָ֘בַ֤ר עָלֵ֨ינוּ ׀ חַסְדּ֗וֹ וֶאֱמֶת־יְהֹוָ֥ה לְעוֹלָ֗ם הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>הוֹד֣וּ</b> (תהילים קי״ח:א׳) לַיהֹוָ֣ה כִּי־ט֑וֹב כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "יֹאמַר־נָ֥א יִשְׂרָאֵ֑ל כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "יֹאמְרוּ־נָ֥א בֵֽית־אַהֲרֹ֑ן כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "יֹאמְרוּ־נָ֭א יִרְאֵ֣י יְהֹוָ֑ה כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "text", "text": "<b>מִֽן־הַ֭מֵּצַר</b> קָרָ֣אתִי יָּ֑הּ עָנָ֖נִי בַמֶּרְחָ֣ב יָֽהּ׃ יְהֹוָ֣ה לִ֭י לֹ֣א אִירָ֑א מַה־יַּעֲשֶׂ֖ה לִ֣י אָדָֽם׃ יְהֹוָ֣ה לִ֭י בְּעֹזְרָ֑י וַ֝אֲנִ֗י אֶרְאֶ֥ה בְשֹׂנְאָֽי׃ ט֗וֹב לַחֲס֥וֹת בַּיהֹוָ֑ה מִ֝בְּטֹ֗חַ בָּאָדָֽם׃ ט֗וֹב לַחֲס֥וֹת בַּיהֹוָ֑ה מִ֝בְּטֹ֗חַ בִּנְדִיבִֽים׃ כׇּל־גּוֹיִ֥ם סְבָב֑וּנִי בְּשֵׁ֥ם יְ֝הֹוָ֗ה כִּ֣י אֲמִילַֽם׃ סַבּ֥וּנִי גַם־סְבָב֑וּנִי בְּשֵׁ֥ם יְ֝הֹוָ֗ה כִּ֣י אֲמִילַֽם׃ סַבּ֤וּנִי כִדְבוֹרִ֗ים דֹּ֭עֲכוּ כְּאֵ֣שׁ קוֹצִ֑ים בְּשֵׁ֥ם יְ֝הֹוָ֗ה כִּ֣י אֲמִילַֽם׃ דַּחֹ֣ה דְחִיתַ֣נִי לִנְפֹּ֑ל וַ֖יהֹוָ֣ה עֲזָרָֽנִי׃ עָזִּ֣י וְזִמְרָ֣ת יָ֑הּ וַֽיְהִי־לִ֗֝י לִישׁוּעָֽה׃ ק֤וֹל ׀ רִנָּ֬ה וִישׁוּעָ֗ה בְּאׇהֳלֵ֥י צַדִּיקִ֑ים יְמִ֥ין יְ֝הֹוָ֗ה עֹ֣שָׂה חָֽיִל׃ יְמִ֣ין יְ֭הֹוָה רוֹמֵמָ֑ה יְמִ֥ין יְ֝הֹוָ֗ה עֹ֣שָׂה חָֽיִל׃ לֹא־אָמ֥וּת כִּֽי־אֶחְיֶ֑ה וַ֝אֲסַפֵּ֗ר מַעֲשֵׂ֥י יָֽהּ׃ יַסֹּ֣ר יִסְּרַ֣נִּי יָּ֑הּ וְ֝לַמָּ֗וֶת לֹ֣א נְתָנָֽנִי׃ פִּתְחוּ־לִ֥י שַׁעֲרֵי־צֶ֑דֶק אָבֹא־בָ֗֝ם אוֹדֶ֥ה יָֽהּ׃ זֶה־הַשַּׁ֥עַר לַיהֹוָ֑ה צַ֝דִּיקִ֗ים יָבֹ֥אוּ בֽוֹ׃"}, {"kind": "text", "text": "<b>א֭וֹדְךָ</b> כִּ֣י עֲנִיתָ֑נִי וַתְּהִי־לִ֗֝י לִישׁוּעָֽה׃ א֭וֹדְךָ כִּ֣י עֲנִיתָ֑נִי וַתְּהִי־לִ֗֝י לִישׁוּעָֽה׃ אֶ֭בֶן מָאֲס֣וּ הַבּוֹנִ֑ים הָ֝יְתָ֗ה לְרֹ֣אשׁ פִּנָּֽה׃ אֶ֭בֶן מָאֲס֣וּ הַבּוֹנִ֑ים הָ֝יְתָ֗ה לְרֹ֣אשׁ פִּנָּֽה׃ מֵאֵ֣ת יְ֭הֹוָה הָ֣יְתָה זֹּ֑את הִ֖יא נִפְלָ֣את בְּעֵינֵֽינוּ׃ מֵאֵ֣ת יְ֭הֹוָה הָ֣יְתָה זֹּ֑את הִ֖יא נִפְלָ֣את בְּעֵינֵֽינוּ׃ זֶה־הַ֭יּוֹם עָשָׂ֣ה יְהֹוָ֑ה נָגִ֖ילָה וְנִשְׂמְחָ֣ה בֽוֹ׃ זֶה־הַ֭יּוֹם עָשָׂ֣ה יְהֹוָ֑ה נָגִ֖ילָה וְנִשְׂמְחָ֣ה בֽוֹ׃"}, {"kind": "text", "text": "<b>אָנָּא</b> יְ֭הֹוָה הוֹשִׁ֘יעָ֥ה נָּ֑א, אָנָּ֣א יְ֭הֹוָה הוֹשִׁ֘יעָ֥ה נָּ֑א"}, {"kind": "text", "text": "<b>אָנָּ֥א</b> יְ֝הֹוָ֗ה הַצְלִ֘יחָ֥ה נָֽא, אָנָּ֥א יְ֝הֹוָ֗ה הַצְלִ֘יחָ֥ה נָֽא׃"}, {"kind": "text", "text": "<b>בָּר֣וּךְ</b> הַ֭בָּא בְּשֵׁ֣ם יְהֹוָ֑ה בֵּ֝רַ֥כְנוּכֶ֗ם מִבֵּ֥ית יְהֹוָֽה׃ בָּר֣וּךְ הַ֭בָּא בְּשֵׁ֣ם יְהֹוָ֑ה בֵּ֝רַ֥כְנוּכֶ֗ם מִבֵּ֥ית יְהֹוָֽה׃ אֵ֤ל ׀ יְהֹוָה֮ וַיָּ֢אֶ֫ר לָ֥נוּ אִסְרוּ־חַ֥ג בַּעֲבֹתִ֑ים עַד־קַ֝רְנ֗וֹת הַמִּזְבֵּֽחַ׃ אֵ֤ל ׀ יְהֹוָה֮ וַיָּ֢אֶ֫ר לָ֥נוּ אִסְרוּ־חַ֥ג בַּעֲבֹתִ֑ים עַד־קַ֝רְנ֗וֹת הַמִּזְבֵּֽחַ׃ אֵלִ֣י אַתָּ֣ה וְאוֹדֶ֑ךָּ אֱ֝לֹהַ֗י אֲרוֹמְמֶֽךָּ׃ אֵלִ֣י אַתָּ֣ה וְאוֹדֶ֑ךָּ אֱ֝לֹהַ֗י אֲרוֹמְמֶֽךָּ׃ הוֹד֣וּ לַיהֹוָ֣ה כִּי־ט֑וֹב כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃ הוֹד֣וּ לַיהֹוָ֣ה כִּי־ט֑וֹב כִּ֖י לְעוֹלָ֣ם חַסְדּֽוֹ׃"}, {"kind": "instruction", "text": "בימים שאין גומרים את ההלל אין אומרים"}, {"kind": "instruction", "text": "יְהַלְלוּךָ יְהֹוָה אֱלֹהֵינוּ כָּל מַעֲשֶׂיךָ, וַחֲסִידֶיךָ וְצַדִּיקִים עוֹשֵׂי רְצוֹנֶךָ וְעַמְּךָ בֵּית יִשְׂרָאֵל, כֻּלָּם בְּרִנָּה יוֹדוּ וִיבָרְכוּ וִישַׁבְּחוּ וִיפָאֲרוּ אֶת שֵׁם כְּבוֹדֶךָ, כִּי לְךָ טוֹב לְהוֹדוֹת, וּלְשִׁמְךָ נָעִים לְזַמֵּר. וּמֵעוֹלָם וְעַד עוֹלָם אַתָּה אֵל. בָּרוּךְ אַתָּה יְהֹוָה, מֶלֶךְ מְהֻלָּל בַּתִּשְׁבָּחוֹת. אָמֵן:"}, {"kind": "instruction", "text": "ואומר החזן קדיש תתקבל, ובחנוכה אומר רק חצי קדיש:"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "תִּתְקַבַּל צְלוֹתָֽנָא וּבָֽעוּתָֽנָא, עִם צְלֽוֹתְהוֹן וּבָעֽוּתְהוֹן דְּכָל־בֵּית יִשְׂרָאֵל, קֳדָם אֲבוּנָא דְּבִשְׁמַיָּא וְאַרְעָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא. חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה. וְשֵׁיזָבָא וּרְפוּאָה וּגְאוּלָה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "יפסע שלש פסיעות לאחור<br>עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו. הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "instruction", "text": "יש אומרים פסוק זה אחר ההלל שלש פעמים"}, {"kind": "instruction", "text": "וְאַבְרָהָ֣ם זָקֵ֔ן בָּ֖א בַּיָּמִ֑ים וַֽיהֹוָ֛ה בֵּרַ֥ךְ אֶת־אַבְרָהָ֖ם בַּכֹּֽל׃"}, {"kind": "instruction", "text": "ואחר כך יאמר"}, {"kind": "instruction", "text": "ה' יִשְׁמְרֵנִי וִיחַיֵנִי, כֵּן יְהִי רָצוֹן מִלְּפָנֶיךָ אֱלֹהִים חַיִּים וּמֶלֶךְ עוֹלָם אֲשֶׁר בְּיָדוֹ נֶפֶשׁ כָּל חַי אָמֵן כֵּן יְהִי רָצוֹן:"}, {"kind": "instruction", "text": "קודם הוצאת ספר תורה אומרים"}, {"kind": "text", "text": "<b>יְהִ֨י</b> יְהֹוָ֤ה אֱלֹהֵ֙ינוּ֙ עִמָּ֔נוּ כַּאֲשֶׁ֥ר הָיָ֖ה עִם־אֲבֹתֵ֑ינוּ אַל־יַעַזְבֵ֖נוּ וְאַֽל־יִטְּשֵֽׁנוּ׃ הוֹשִׁ֤יעָה ׀ אֶת־עַמֶּ֗ךָ וּבָרֵ֥ךְ אֶת־נַחֲלָתֶ֑ךָ וּֽרְעֵ֥ם וְ֝נַשְּׂאֵ֗ם עַד־הָעוֹלָֽם׃ בַּֽ֭עֲבוּר דָּוִ֣ד עַבְדֶּ֑ךָ אַל־תָּ֝שֵׁ֗ב פְּנֵ֣י מְשִׁיחֶֽךָ׃"}, {"kind": "instruction", "text": "פותחים ההיכל ואומרים"}, {"kind": "text", "text": "<b>בְּרִיךְ</b> שְׁמֵהּ שְׁמֵהּ דְּמָארֵי עָלְמָא, בְּרִיךְ כִּתְרָךְ וְאַתְרָךְ. יְהֵא רְעוּתָךְ, עִם עַמָּךְ יִשְׂרָאֵל לְעָלַם, וּפוּרְקַן יְמִינָךְ אַחְזֵי לְעַמָּךְ בְּבֵית מִקְדָּשָׁךְ, לְאַמְטוּיֵי לָנָא מִטּוּב נְהוֹרָךְ, וּלְקַבְּלָא צְלוֹתָנָא בְּרַחֲמֵי. יְהֵא רַעֲוָא קֳדָמָךְ דְּתוֹרִיךְ לָן חַיִּין בּטִיבוּ, וְלֶהֱוֵי אֲנָא עַבְדָּךְ פְּקִידָא בְּגוֹ צַדִּיקַיָּא, לְמִרְחַם עָלַי וּלְמִנְטַר יָתִי, וְיַת כּל דִּי לִי, וְדִי לְעַמָּךְ יִשְׂרָאֵל. אַנְתְּ הוּא זָן לְכֹלָא וּמְפַרְנֵס לְכֹלָא. אַנְתְּ הוּא שַׁלִּיט עַל כֹּלָא, אַנְתְּ הוּא דְשַׁלִּיט עַל מַלְכַיָּא, וּמַלְכוּתָא דִילָךְ הִיא. אֲנָא עַבְדָּא דְקֻדְשָׁא בְּרִיךְ הוּא, דְסָגִידְנָא קַמֵּהּ מִקַמֵּי דִּיקַר אוֹרַיְתֵהּ בְּכל עִידָּן וְעִידָּן. לָא עַל אֱנָשׁ רָחִיצְנָא, וְלָא עַל בַּר אֱלָהִין סְמִיכְנָא, אֶלָּא בֵאלָהָא דִשְׁמַיָּא, דְּהוּא אֱלָהָא דִקְשׁוֹט, וְאוֹרַיְתֵהּ קְשׁוֹט, וּנְבִיאוֹהִי קְשׁוֹט, וּמַסְגֵּי לְמֶעְבַּד טַבְוָן וּקְשׁוֹט, בֵּהּ אֲנָא רְחִיץ וְלִשְׁמֵהּ יַקִּירָא קַדִּישָׁא אֲנָא אֵמַר תֻּשְׁבְּחָן. יְהֵא רַעֲוָא קֳדָמָךְ דְּתִפְתַּח לִבִּי בְּאוֹרַיְתָךְ, (וְתִיהַב לִי בְּנִין דִּכְרִין דְּעַבְדִּין רְעוּתָךְ) וְתַשְׁלִים מִשְׁאֲלִין דְּלִבָּאי וְלִבָּא דכל עַמָּךְ יִשְׂרָאֵל לְטַב וּלְחַיִּין וְלִשְׁלָם אָמֵן:"}, {"kind": "instruction", "text": "מוציאים ספר תורה וקוראים ד' עולים"}, {"kind": "text", "text": "<b>וַיְדַבֵּ֥ר</b> (במדבר כ״ח:א׳-ב׳) יְהֹוָ֖ה אֶל־מֹשֶׁ֥ה לֵּאמֹֽר׃ צַ֚ו אֶת־בְּנֵ֣י יִשְׂרָאֵ֔ל וְאָמַרְתָּ֖ אֲלֵהֶ֑ם אֶת־קׇרְבָּנִ֨י לַחְמִ֜י לְאִשַּׁ֗י רֵ֚יחַ נִֽיחֹחִ֔י תִּשְׁמְר֕וּ לְהַקְרִ֥יב לִ֖י בְּמוֹעֲדֽוֹ׃ וְאָמַרְתָּ֣ לָהֶ֔ם זֶ֚ה הָֽאִשֶּׁ֔ה אֲשֶׁ֥ר תַּקְרִ֖יבוּ לַיהֹוָ֑ה כְּבָשִׂ֨ים בְּנֵֽי־שָׁנָ֧ה תְמִימִ֛ם שְׁנַ֥יִם לַיּ֖וֹם עֹלָ֥ה תָמִֽיד׃ <br><br>לוי חוזר מ''ואמרת להם'' וְאָמַרְתָּ֣ לָהֶ֔ם זֶ֚ה הָֽאִשֶּׁ֔ה אֲשֶׁ֥ר תַּקְרִ֖יבוּ לַיהֹוָ֑ה כְּבָשִׂ֨ים בְּנֵֽי־שָׁנָ֧ה תְמִימִ֛ם שְׁנַ֥יִם לַיּ֖וֹם עֹלָ֥ה תָמִֽיד׃ אֶת־הַכֶּ֥בֶשׂ אֶחָ֖ד תַּעֲשֶׂ֣ה בַבֹּ֑קֶר וְאֵת֙ הַכֶּ֣בֶשׂ הַשֵּׁנִ֔י תַּעֲשֶׂ֖ה בֵּ֥ין הָֽעַרְבָּֽיִם׃ וַעֲשִׂירִ֧ית הָאֵיפָ֛ה סֹ֖לֶת לְמִנְחָ֑ה בְּלוּלָ֛ה בְּשֶׁ֥מֶן כָּתִ֖ית רְבִיעִ֥ת הַהִֽין׃ <br><br>ישראל עֹלַ֖ת תָּמִ֑יד הָעֲשֻׂיָה֙ בְּהַ֣ר סִינַ֔י לְרֵ֣יחַ נִיחֹ֔חַ אִשֶּׁ֖ה לַֽיהֹוָֽה׃ וְנִסְכּוֹ֙ רְבִיעִ֣ת הַהִ֔ין לַכֶּ֖בֶשׂ הָאֶחָ֑ד בַּקֹּ֗דֶשׁ הַסֵּ֛ךְ נֶ֥סֶךְ שֵׁכָ֖ר לַיהֹוָֽה׃ וְאֵת֙ הַכֶּ֣בֶשׂ הַשֵּׁנִ֔י תַּעֲשֶׂ֖ה בֵּ֣ין הָֽעַרְבָּ֑יִם כְּמִנְחַ֨ת הַבֹּ֤קֶר וּכְנִסְכּוֹ֙ תַּעֲשֶׂ֔ה אִשֵּׁ֛ה רֵ֥יחַ נִיחֹ֖חַ לַיהֹוָֽה׃ <br>וּבְיוֹם֙ הַשַּׁבָּ֔ת שְׁנֵֽי־כְבָשִׂ֥ים בְּנֵֽי־שָׁנָ֖ה תְּמִימִ֑ם וּשְׁנֵ֣י עֶשְׂרֹנִ֗ים סֹ֧לֶת מִנְחָ֛ה בְּלוּלָ֥ה בַשֶּׁ֖מֶן וְנִסְכּֽוֹ׃ עֹלַ֥ת שַׁבַּ֖ת בְּשַׁבַּתּ֑וֹ עַל־עֹלַ֥ת הַתָּמִ֖יד וְנִסְכָּֽהּ׃ <br><br>רביעי וּבְרָאשֵׁי֙ חׇדְשֵׁיכֶ֔ם תַּקְרִ֥יבוּ עֹלָ֖ה לַיהֹוָ֑ה פָּרִ֨ים בְּנֵֽי־בָקָ֤ר שְׁנַ֙יִם֙ וְאַ֣יִל אֶחָ֔ד כְּבָשִׂ֧ים בְּנֵי־שָׁנָ֛ה שִׁבְעָ֖ה תְּמִימִֽם׃ וּשְׁלֹשָׁ֣ה עֶשְׂרֹנִ֗ים סֹ֤לֶת מִנְחָה֙ בְּלוּלָ֣ה בַשֶּׁ֔מֶן לַפָּ֖ר הָאֶחָ֑ד וּשְׁנֵ֣י עֶשְׂרֹנִ֗ים סֹ֤לֶת מִנְחָה֙ בְּלוּלָ֣ה בַשֶּׁ֔מֶן לָאַ֖יִל הָֽאֶחָֽד׃ וְעִשָּׂרֹ֣ן עִשָּׂר֗וֹן סֹ֤לֶת מִנְחָה֙ בְּלוּלָ֣ה בַשֶּׁ֔מֶן לַכֶּ֖בֶשׂ הָאֶחָ֑ד עֹלָה֙ רֵ֣יחַ נִיחֹ֔חַ אִשֶּׁ֖ה לַיהֹוָֽה׃ וְנִסְכֵּיהֶ֗ם חֲצִ֣י הַהִין֩ יִהְיֶ֨ה לַפָּ֜ר וּשְׁלִישִׁ֧ת הַהִ֣ין לָאַ֗יִל וּרְבִיעִ֥ת הַהִ֛ין לַכֶּ֖בֶשׂ יָ֑יִן זֹ֣את עֹלַ֥ת חֹ֙דֶשׁ֙ בְּחׇדְשׁ֔וֹ לְחׇדְשֵׁ֖י הַשָּׁנָֽה׃ וּשְׂעִ֨יר עִזִּ֥ים אֶחָ֛ד לְחַטָּ֖את לַיהֹוָ֑ה עַל־עֹלַ֧ת הַתָּמִ֛יד יֵעָשֶׂ֖ה וְנִסְכּֽוֹ׃"}, {"kind": "instruction", "text": "בסיום הקריאה אומר המשלים חצי קדיש"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>יְהִי־חַסְדְּךָ֣</b> יְהֹוָ֣ה עָלֵ֑ינוּ כַּ֝אֲשֶׁ֗ר יִחַ֥לְנוּ לָֽךְ׃"}, {"kind": "text", "text": "<b>אַ֭שְׁרֵי</b> יוֹשְׁבֵ֣י בֵיתֶ֑ךָ ע֝֗וֹד יְֽהַלְל֥וּךָ סֶּֽלָה: אַשְׁרֵ֣י הָ֭עָם שֶׁכָּ֣כָה לּ֑וֹ אַֽשְׁרֵ֥י הָ֝עָ֗ם שֱׁיְהֹוָ֥ה אֱלֹהָֽיו: תְּהִלָּ֗ה לְדָ֫וִ֥ד (תהילים קמ״ה:א׳-ב׳) אֲרוֹמִמְךָ֣ אֱלוֹהַ֣י הַמֶּ֑לֶךְ וַאֲבָרְכָ֥ה שִׁ֝מְךָ֗ לְעוֹלָ֥ם וָעֶֽד׃ בְּכָל־י֥וֹם אֲבָֽרְכֶ֑ךָּ וַאֲהַֽלְלָ֥ה שִׁ֝מְךָ֗ לְעוֹלָ֥ם וָעֶֽד׃ גָּ֘ד֤וֹל יְהֹוָ֣ה וּמְהֻלָּ֣ל מְאֹ֑ד וְ֝לִגְדֻלָּת֗וֹ אֵ֣ין חֵֽקֶר׃ דּ֣וֹר לְ֭דוֹר יְשַׁבַּ֣ח מַעֲשֶׂ֑יךָ וּגְב֖וּרֹתֶ֣יךָ יַגִּֽידוּ׃ הֲ֭דַר כְּב֣וֹד הוֹדֶ֑ךָ וְדִבְרֵ֖י נִפְלְאֹתֶ֣יךָ אָשִֽׂיחָה׃ וֶעֱז֣וּז נֽוֹרְאֹתֶ֣יךָ יֹאמֵ֑רוּ וגדלותיך [וּגְדֻלָּתְךָ֥] אֲסַפְּרֶֽנָּה׃ זֵ֣כֶר רַב־טוּבְךָ֣ יַבִּ֑יעוּ וְצִדְקָתְךָ֥ יְרַנֵּֽנוּ׃ חַנּ֣וּן וְרַח֣וּם יְהֹוָ֑ה אֶ֥רֶךְ אַ֝פַּ֗יִם וּגְדׇל־חָֽסֶד׃ טוֹב־יְהֹוָ֥ה לַכֹּ֑ל וְ֝רַחֲמָ֗יו עַל־כׇּל־מַעֲשָֽׂיו׃ יוֹד֣וּךָ יְ֭הֹוָה כׇּל־מַעֲשֶׂ֑יךָ וַ֝חֲסִידֶ֗יךָ יְבָרְכֽוּכָה׃ כְּב֣וֹד מַלְכוּתְךָ֣ יֹאמֵ֑רוּ וּגְבוּרָתְךָ֥ יְדַבֵּֽרוּ׃ לְהוֹדִ֤יעַ ׀ לִבְנֵ֣י הָ֭אָדָם גְּבוּרֹתָ֑יו וּ֝כְב֗וֹד הֲדַ֣ר מַלְכוּתֽוֹ׃ מַֽלְכוּתְךָ֗ מַלְכ֥וּת כׇּל־עֹלָמִ֑ים וּ֝מֶֽמְשַׁלְתְּךָ֗ בְּכׇל־דּ֥וֹר וָדֹֽר׃ סוֹמֵ֣ךְ יְ֭הֹוָה לְכׇל־הַנֹּפְלִ֑ים וְ֝זוֹקֵ֗ף לְכׇל־הַכְּפוּפִֽים׃ עֵֽינֵי־כֹ֭ל אֵלֶ֣יךָ יְשַׂבֵּ֑רוּ וְאַתָּ֤ה נֽוֹתֵן־לָהֶ֖ם אֶת־אׇכְלָ֣ם בְּעִתּֽוֹ׃ פּוֹתֵ֥חַ אֶת־יָדֶ֑ךָ וּמַשְׂבִּ֖יעַ לְכׇל־חַ֣י רָצֽוֹן׃ צַדִּ֣יק יְ֭הֹוָה בְּכׇל־דְּרָכָ֑יו וְ֝חָסִ֗יד בְּכׇל־מַעֲשָֽׂיו׃ קָר֣וֹב יְ֭הֹוָה לְכׇל־קֹרְאָ֑יו לְכֹ֤ל אֲשֶׁ֖ר יִקְרָאֻ֣הוּ בֶֽאֱמֶֽת׃ רְצוֹן־יְרֵאָ֥יו יַעֲשֶׂ֑ה וְֽאֶת־שַׁוְעָתָ֥ם יִ֝שְׁמַ֗ע וְיוֹשִׁיעֵֽם׃ שׁוֹמֵ֣ר יְ֭הֹוָה אֶת־כׇּל־אֹהֲבָ֑יו וְאֵ֖ת כׇּל־הָרְשָׁעִ֣ים יַשְׁמִֽיד׃ תְּהִלַּ֥ת יְהֹוָ֗ה יְֽדַבֶּ֫ר פִּ֥י וִיבָרֵ֣ךְ כׇּל־בָּ֭שָׂר שֵׁ֥ם קׇדְשׁ֗וֹ לְעוֹלָ֥ם וָעֶֽד׃ וַאֲנַ֤חְנוּ ׀ נְבָ֘רֵ֤ךְ יָ֗הּ מֵעַתָּ֥ה וְעַד־עוֹלָ֗ם הַֽלְלוּיָֽהּ׃"}, {"kind": "instruction", "text": "כאן מוציאים ספר תורה וקוראים את קריאת היום של החג (מן החומש), ואחריה ההפטרה."}, {"kind": "header", "text": "מוסף לשלש רגלים"}, {"kind": "text", "text": "<b>אֲ֭דֹנָי</b> שְׂפָתַ֣י תִּפְתָּ֑ח וּ֝פִ֗י יַגִּ֥יד תְּהִלָּתֶֽךָ׃"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵֽאלֹהֵי יַעֲקֹב. הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, קוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵּי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַֽעַן שְׁמוֹ בְּאַֽהֲבָה: מֶֽלֶךְ עוֹזֵר וּמוֹשִֽׁיעַ וּמָגֵן: בָּרוּךְ אַתָּה יַהַוַהַ, מָגֵן אַבְרָהָם:"}, {"kind": "text", "text": "<b>אַתָּה</b> גִבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֶּה מֵתִים אַתָּה, רַב לְהוֹשִֽׁיעַ."}, {"kind": "text", "text": "בקיץ: מוֹרִיד הַטָּל. בחורף: מַשִּׁיב הָרֽוּחַ וּמוֹרִיד הַגֶּֽשֶׁם."}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶֽסֶד, מְחַיֵּה מֵתִים בְּרַֽחֲמִים רַבִּים, סוֹמֵךְ נֽוֹפְלִים, וְרוֹפֵא חוֹלִים, וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמֽוּנָתוֹ לִֽישֵׁנֵי עָפָר. מִי כָמֽוֹךָ בַּֽעַל גְּבוּרוֹת, וּמִי דֽוֹמֶה לָךְ, מֶֽלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִֽיחַ יְשׁוּעָה. וְנֶֽאֱמָן אַתָּה לְהַֽחֲיוֹת מֵתִים: בָּרוּךְ אַתָּה יֵהֵוֵהֵ, מְחַיֵּה הַמֵּתִים:"}, {"kind": "instruction", "text": "בחזרת הש\"ץ במוסף של יו\"ט או שבת אומרים"}, {"kind": "text", "text": "<b>כֶּתֶר</b> יִתְּנוּ לְךָ, יְהֹוָה אֱלֹהֵינוּ, מַלְאָכִים הֲמוֹנֵי מַעְלָה, עִם עַמְּךָ יִשְׂרָאֵל קְבוּצֵי מַטָּה. יַחַד כֻּלָּם קְדֻשָּׁה לְךָ יְשַׁלֵּשׁוּ, כַּדָּבָר הָאָמוּר עַל יַד נְבִיאָךְ וְקָרָ֨א זֶ֤ה אֶל־זֶה֙ וְאָמַ֔ר <b>קָד֧וֹשׁ ׀ קָד֛וֹשׁ קָד֖וֹשׁ יְהֹוָ֣ה צְבָא֑וֹת מְלֹ֥א כָל־הָאָ֖רֶץ כְּבוֹדֽוֹ׃</b> כְּבוֹדוֹ מָלֵא עוֹלָם, וּמְשָׁרְתָיו שׁוֹאֲלִים אַיֵּה מְקוֹם כְּבוֹדוֹ לְהַעֲרִיצוֹ: לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים <b>בָּר֥וּךְ כְּבוֹד־יְהֹוָ֖ה מִמְּקוֹמֽוֹ׃</b> מִמְּקוֹמוֹ הוּא יִפֶן בְּרַחֲמָיו לְעַמּוֹ הַמְיַחֲדִים שְׁמוֹ עֶרֶב וָבֹקֶר, בְּכָל יוֹם תָּמִיד אוֹמְרִים פַּעֲמַיִם בְּאַהֲבָה <b>שְׁמַ֖ע יִשְׂרָאֵ֑ל יְהֹוָ֥ה אֱלֹהֵ֖ינוּ יְהֹוָ֥ה ׀ אֶחָֽד׃</b> בתיבת אחד יכון שהוא מוכן למסור נפשו על קידוש השם הוּא אֱלֹהֵינוּ, הוּא אָבִינוּ, הוּא מַלְכֵּנוּ, הוּא מוֹשִׁיעֵנוּ, הוּא יוֹשִׁיעֵנוּ וְיִגְאָלֵנוּ שֵׁנִית, וְיַשְׁמִיעֵנוּ בְּרַחֲמָיו לְעֵינֵי כָּל חַי לֵאמֹר, הֵן גָּאַלְתִּי אֶתְכֶם אַחֲרִית כְּרֵאשִׁית לִהְיוֹת לָכֶם לֵאלֹהִים, אֲנִי יְהֹוָה אֱלֹהֵיכֶם: וּבְדִבְרֵי קָדְשְׁךָ כָּתוּב לֵאמֹר <b>יִמְלֹ֤ךְ יְהֹוָ֨ה ׀ לְעוֹלָ֗ם אֱלֹהַ֣יִךְ צִ֭יּוֹן לְדֹ֥ר וָדֹ֗ר הַֽלְלוּיָֽהּ:</b>"}, {"kind": "instruction", "text": "בחזרת הש\"ץ במוסף של חול המועד אומרים"}, {"kind": "instruction", "text": "כֶּתֶר יִתְּנוּ לְךָ, יְהֹוָה אֱלֹהֵינוּ, מַלְאָכִים הֲמוֹנֵי מַעְלָה, וְעַמְּךָ יִשְׂרָאֵל קְבוּצֵי מַטָּה. יַחַד כֻּלָּם קְדֻשָּׁה לְךָ יְשַׁלֵּשׁוּ, כַּדָּבָר הָאָמוּר עַל יַד נְבִיאָךְ וְקָרָ֨א זֶ֤ה אֶל־זֶה֙ וְאָמַ֔ר קָד֧וֹשׁ ׀ קָד֛וֹשׁ קָד֖וֹשׁ יְהֹוָ֣ה צְבָא֑וֹת מְלֹ֥א כָל־הָאָ֖רֶץ כְּבוֹדֽוֹ׃ לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים בָּר֥וּךְ כְּבוֹד־יְהֹוָ֖ה מִמְּקוֹמֽוֹ׃ וּבְדִבְרֵי קָדְשְׁךָ כָּתוּב לֵאמֹר יִמְלֹ֤ךְ יְהֹוָ֨ה ׀ לְעוֹלָ֗ם אֱלֹהַ֣יִךְ צִ֭יּוֹן לְדֹ֥ר וָדֹ֗ר הַֽלְלוּיָֽהּ:"}, {"kind": "text", "text": "<b>אַתָּה</b> קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ, וּקְדוֹשִׁים בְּכָל־יוֹם יְהַֽלְלֽוּךָ סֶּֽלָה: בָּרוּךְ אַתָּה יֹהֵוָהֵ, הָאֵל הַקָּדוֹשׁ:"}, {"kind": "text", "text": "<b>אַתָּה</b> בְּחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ, וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת, וְקִדַּשְׁתָּנוּ בְּמִצְוֹתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ."}, {"kind": "text", "text": "וַתִּֽתֶּן לָֽנוּ יְהֹוָה אֱלֹהֵֽינוּ בְּאַהֲבָה בשבת (שַׁבָּתוֹת לִמְנוּחָה וּ)מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן, אֶת יוֹם"}, {"kind": "text", "text": "בשבת הַשַּׁבָּת הַזֶּה, וְאֶת יוֹם"}, {"kind": "text", "text": "בפסח: חַג הַמַּצּוֹת הַזֶּה, אֶת יוֹם ביו\"ט מוסיף טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה, זְמַן חֵרוּתֵנוּ:"}, {"kind": "text", "text": "בשבועות: חַג הַשָׁבוּעוֹת הַזֶּה, אֶת יוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה, זְמַן מַתַּן תּוֹרָתֵֽינוּ:"}, {"kind": "text", "text": "בסוכות: חַג הַסֻּכּוֹת הַזֶּה, אֶת יוֹם ביו\"ט מוסיף טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה, זְמַן שִׂמְחָתֵֽנוּ:"}, {"kind": "text", "text": "בש''ע: שְׁמִינִי חַג עֲצֶרֶת הַזֶּה, אֶת יוֹם טוֹב מִקְרָא קֹדֶשׁ הַזֶּה, זְמַן שִׂמְחָתֵנוּ."}, {"kind": "text", "text": "בְּאַהֲבָה מִקְרָא קֹֽדֶשׁ זֵֽכֶר לִיצִיאַת מִצְרָֽיִם."}, {"kind": "text", "text": "<b>אֱלֹהֵֽינוּ</b> וֵאלֹהֵי אֲבוֹתֵֽינוּ, מִפְּנֵי חֲטָאֵינוּ גָּלִינוּ מֵאַרְצֵנוּ, וְנִתְרַחַקְנוּ מֵעַל אַדְמָתֵנוּ, וְאֵין אֲנַחְנוּ יְכוֹלִים לַעֲלוֹת וְלֵרָאוֹת וּלְהִשְׁתַּחֲוֹת לְפָנֶיךָ בְּבֵית בְּחִירָתָךְ, בִּנְוֵה הֲדָרָךְ, בַּבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, מִפְּנֵי הַיָּד שֶׁנִּשְׁתַּלְּחָה בְּמִקְדָּשָׁךְ."}, {"kind": "text", "text": "<b>יְהִי</b> רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן, שֶׁתָּשׁוּב וּתְרַחֵם עָלֵינוּ וְעַל מִקְדָּשְׁךָ בְּרַחֲמֶיךָ הָרַבִּים, וְתִבְנֵהוּ מְהֵרָה וּתְגַדֵּל כְּבוֹדוֹ. אָבִינוּ, מַלְכֵּנוּ, אֱלֹהֵינוּ, גַּלֵּה כְּבוֹד מַלְכוּתְךָ עָלֵינוּ מְהֵרָה, וְהוֹפַע וְהִנָּשֵׂא עָלֵינוּ לְעֵינֵי כָל חַי, וְקָרֵב פְּזוּרֵינוּ מִבֵּין הַגּוֹיִם, וּנְפוּצוֹתֵינוּ כַּנֵּס מִיַּרְכְּתֵי אָרֶץ, וַהֲבִיאֵנוּ יְהֹוָה אֱלֹהֵינוּ לְצִיּוֹן עִירָךְ בְּרִנָּה, וְלִירוּשָׁלַיִם עִיר מִקְדָּשְׁךָ בְּשִׂמְחַת עוֹלָם, אָנָּא אֱלֹהֵינוּ, וְשָׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חוֹבוֹתֵינוּ, תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם."}, {"kind": "text", "text": "אֶת מוּסָף בשבת מוּסְפֵי יוֹם הַשַּׁבָּת הַזֶּה, וְ יוֹם"}, {"kind": "text", "text": "בפסח: חַג הַמַּצּוֹת"}, {"kind": "text", "text": "בשבועות: חַג הַשָּׁבוּעוֹת"}, {"kind": "text", "text": "בסוכות: חַג הַסֻּכּוֹת"}, {"kind": "text", "text": "בש''ע: שְׁמִינִי חַג עֲצֶֽרֶת"}, {"kind": "text", "text": "הַזֶּה, וְיוֹם ביו\"ט מוסיף טוֹב מִקְרָא קֹדֶשׁ הַזֶּה, נַעֲשֶׂה וְנַקְרִיב לְפָנֶיךָ בְּאַהֲבָה כְּמִצְוַת רְצוֹנָךְ, כְּמוֹ שֶׁכָּתַבְתָּ עָלֵינוּ בְּתוֹרָתָךְ, עַל יְדֵי מֹשֶׁה עַבְדֶּךָ."}, {"kind": "text", "text": "<b>אֱלֹהֵינוּ</b> וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה עָלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ, בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ, בְּנֵה בֵיתְךָ כְּבַתְּחִלָּה, כּוֹנֵן בֵּית מִקְדָּשְׁךָ עַל מְכוֹנוֹ, הַרְאֵנוּ בְּבִנְיָנוֹ, שַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב שְׁכִינָתְךָ לְתוֹכוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם, וּלְוִיִּים לְדוּכָנָם, לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ בְּשָׁלֹשׁ פַּעֲמֵי רְגָלֵינוּ בְּכָל שָׁנָה וְשָׁנָה, כַּכָּתוּב בַּתּוֹרָה שָׁל֣וֹשׁ פְּעָמִ֣ים ׀ בַּשָּׁנָ֡ה יֵרָאֶ֨ה כׇל־זְכוּרְךָ֜ אֶת־פְּנֵ֣י ׀ יְהֹוָ֣ה אֱלֹהֶ֗יךָ בַּמָּקוֹם֙ אֲשֶׁ֣ר יִבְחָ֔ר בְּחַ֧ג הַמַּצּ֛וֹת וּבְחַ֥ג הַשָּׁבֻע֖וֹת וּבְחַ֣ג הַסֻּכּ֑וֹת וְלֹ֧א יֵרָאֶ֛ה אֶת־פְּנֵ֥י יְהֹוָ֖ה רֵיקָֽם׃ אִ֖ישׁ כְּמַתְּנַ֣ת יָד֑וֹ כְּבִרְכַּ֛ת יְהֹוָ֥ה אֱלֹהֶ֖יךָ אֲשֶׁ֥ר נָֽתַן־לָֽךְ׃"}, {"kind": "text", "text": "<b>וְהַשִּׂיאֵנוּ</b> יְהֹוָה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ לְחַיִּים בְּשִׂמְחָה וּבְשָׁלוֹם, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ כֵּן תְּבָרְכֵנוּ סֶלָה."}, {"kind": "instruction", "text": "בשבת אומרים"}, {"kind": "instruction", "text": "אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, רְצֵה נָא בִּמְנוּחָתֵנוּ,"}, {"kind": "text", "text": "<b>קַדְּשֵׁנוּ</b> בְּמִצְוֹתֶיךָ, שִׂים חֶלְקֵנוּ בְּתוֹרָתָךְ, שַׂבְּעֵנוּ מִטּוּבָךְ, שַׂמֵּחַ נַפְשֵׁנוּ בִּישׁוּעָתָךְ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶאֱמֶת, וְהַנְחִילֵנוּ יְהֹוָה אֱלֹהֵינוּ בשבת בְּאַהֲבָה וּבְרָצוֹן בְּשִׂמְחָה וּבְשָׂשׂוֹן בשבת שַׁבָּתוֹת וּ מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְךָ כָּל יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יְהֹוָה, מְקַדֵּשׁ בשבת הַשַּׁבָּת וְיִשְׂרָאֵל וְהַזְּמַנִּים:"}, {"kind": "text", "text": "<b>רְצֵה</b> יְהֹוָה אֱלֹהֵֽינוּ בְּעַמְּךָ יִשְׂרָאֵל וְלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב הָֽעֲבוֹדָה לִדְבִיר בֵּיתֶֽךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, מְהֵרָה בְּאַֽהֲבָה תְקַבֵּל בְּרָצוֹן, וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּֽךָ: וְאַתָּה בְּרַֽחֲמֶֽיךָ הָרַבִּים, תַּחְפֹּץ בָּֽנוּ וְתִרְצֵֽנוּ, וְתֶֽחֱזֶֽינָה עֵינֵֽינוּ בְּשֽׁוּבְךָ לְצִיּוֹן בְּרַֽחֲמִים: בָּרוּךְ אַתָּה יִהִוִהִ, הַמַּֽחֲזִיר שְׁכִֽינָתוֹ לְצִיּוֹן:"}, {"kind": "instruction", "text": "בברכת \"מודים\" יכרע ב\"מודים\" ויזקוף בשם (בא\"ח בשלח הכ\"א)"}, {"kind": "text", "text": "<b>מוֹדִים</b> אֲנַֽחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ לְעוֹלָם וָעֶד, צוּרֵֽנוּ צוּר חַיֵּֽינוּ וּמָגֵן יִשְׁעֵֽנוּ אַתָּה הוּא, לְדוֹר וָדוֹר נוֹדֶה לְךָ וּנְסַפֵּר תְּהִלָּתֶֽךָ, עַל חַיֵּֽינוּ הַמְּסוּרִים בְּיָדֶֽךָ, וְעַל נִשְׁמוֹתֵֽינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּֽיךָ שֶׁבְּכָל־יוֹם עִמָּֽנוּ, וְעַל נִפְלְאוֹתֶֽיךָ וְטֽוֹבוֹתֶֽיךָ שֶׁבְּכָל־עֵת, עֶֽרֶב וָבֹֽקֶר וְצָֽהֳרָֽיִם. הַטּוֹב, כִּי לֹא כָלוּ רַחֲמֶֽיךָ, הַמְּרַחֵם, כִּי לֹא תַֽמּוּ חֲסָדֶֽיךָ, כִּי מֵֽעוֹלָם קִוִּֽינוּ לָךְ:"}, {"kind": "text", "text": "<b>מודים דרבנן</b><br>בחזרת הש\"ץ כשהחזן אומר מודים, הקהל אומרים:<br>מוֹדִים אֲנַחְנוּ לָךְ, שָׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׁר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית. בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְחָנֵּנוּ וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמֹר חֻקֶּיךָ וְלַעֲשׂוֹת רְצוֹנְךָ וּלְעָבְדְךָ בְלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ, בָּרוּךְ אֵל הַהוֹדָאוֹת."}, {"kind": "text", "text": "<b>וְעַל</b> כֻּלָּם יִתְבָּרַךְ, וְיִתְרוֹמָם, וְיִתְנַשֵּׂא, תָּמִיד, שִׁמְךָ מַלְכֵּֽנוּ, לְעוֹלָם וָעֶד. וְכָל־הַחַיִּים יוֹדֽוּךָ סֶּֽלָה: וִֽיהַֽלְלוּ וִֽיבָֽרְכוּ אֶת־שִׁמְךָ הַגָּדוֹל בֶּֽאֱמֶת לְעוֹלָם כִּי טוֹב, הָאֵל יְשֽׁוּעָתֵֽנוּ וְעֶזְרָתֵֽנוּ סֶֽלָה, הָאֵל הַטּוֹב: בָּרוּךְ אַתָּה יֻהֻוֻהֻ, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת:"}, {"kind": "text", "text": "ברכת כהנים"}, {"kind": "text", "text": "כשעוקר הכהן רגליו לישא כפיו יאמר (בא\"ח תצוה י\"ב)<br>לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ. בִּדְחִֽילוּ וּרְחִֽימוּ. וּרְחִֽימוּ וּדְחִֽילוּ. לְיַחֲדָא שֵׁם יוֹ\"ד קֵ\"א בְּוָא\"ו קֵ\"א בְּיִחוּדָא שְׁלִים. בְּשֵׁם כָּל־יִשְׂרָאֵל הִנֵּה אָנֹכִי מוּכָן וּמְזוּמָן לְקַיֵּם מִצְוַת עֲשֵׂה לְבָרֵךְ אֶת יִשְׂרָאֵל בִּרְכַּת כֹּהַנִים בִּנְשִׂיאוּת כַּפַּיִם, לַעֲשׂוֹת נַֽחַת רֽוּחַ לְיֽוֹצְרֵֽנוּ וּלְהַמְשִׁיךְ שֶׁפַע וּבְרָכָה לְכָל־הָעוֹלָמוֹת וְלַעֲשׂוֹת רְצוֹן בּֽוֹרְאֵֽנוּ. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ:"}, {"kind": "text", "text": "וכשעומדים הכהנים על הדוכן לאחר שענו \"מודים דרבנן\", אומרים<br>יְהִי רָצוֹן מִלְּפָנֶֽיךָ יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ שֶׁתִּהְיֶה בְּרָכָה זוֹ שֶׁצִּּוִיתָֽנוּ לְבָרֵךְ אֶת־עַמְּךָ יִשְׂרָאֵל בְּרָכָה שְׁלֵמָה וְלֹא יִהְיֶה בָהּ מִכְשׁוֹל וְעָוֹן מֵעַתָּה וְעַד עוֹלָם:"}, {"kind": "text", "text": "בחזרת הש\"ץ אומרים ברכת כהנים, אם יש יותר מכהן אחד קורא להם החזן: כֹּהֲנִים: הכהנים מברכים:<br>בָּרוּךְ אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָֽעוֹלָם, אֲשֶׁר קִדְּשָֽׁנוּ בִּקְדֻשָּׁתוֹ שֶׁל־אַֽהֲרֹן, וְצִוָּֽנוּ לְבָרֵךְ אֶת־עַמּוֹ יִשְׂרָאֵל בְּאַֽהֲבָה: הקהל עונים אָמֵן:"}, {"kind": "instruction", "text": "ואומר החזן והכהנים אחריו מילה במילה:"}, {"kind": "text", "text": "יְבָרֶכְךָ֥ יְהֹוָ֖ה וְיִשְׁמְרֶֽךָ׃ ועונים אָמֵן:"}, {"kind": "text", "text": "יָאֵ֨ר יְהֹוָ֧ה ׀ פָּנָ֛יו אֵלֶ֖יךָ וִֽיחֻנֶּֽךָּ׃ ועונים אָמֵן:"}, {"kind": "text", "text": "יִשָּׂ֨א יְהֹוָ֤ה ׀ פָּנָיו֙ אֵלֶ֔יךָ וְיָשֵׂ֥ם לְךָ֖ שָׁלֽוֹם׃ ועונים אָמֵן:"}, {"kind": "instruction", "text": "וכשמתחיל שליח ציבור \"שים שלום\" אז מחזירין פניהם כלפי ההיכל, ולא יחזירו פניהם קודם, ואז הכהנים אומרים<br>רִבּוֹן הָעוֹלָמִים עָשִֽׂינוּ מַה־שֶּׁגָּזַֽרְתָּ עָלֵֽינוּ, עַשֵׂה אַתָּה מַה־שֶּׁהִבְטָחְתָּֽנוּ. הַשְׁקִ֩יפָה֩ מִמְּע֨וֹן קׇדְשְׁךָ֜ מִן־הַשָּׁמַ֗יִם וּבָרֵ֤ךְ אֶֽת־עַמְּךָ֙ אֶת־יִשְׂרָאֵ֔ל:"}, {"kind": "text", "text": "אם אין כהנים אומר החזן:<br><b>אֱלֹהֵינוּ</b> וֵאלֹהֵי אֲבוֹתֵינוּ, בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶת בַּתּוֹרָה הַכְּתוּבָה עַל יְדֵי מֹשֶׁה עַבְדֶּֽךָ, הָאֲמוּרָה מִפִּי אַהֲרֹן וּבָנָיו הַכֹּהֲנִים עַם קְדוֹשֶׁיךָ כָּאָמוּר:"}, {"kind": "text", "text": "יְבָרֶכְךָ֥ יְהֹוָ֖ה וְיִשְׁמְרֶֽךָ׃ ועונים כֵּן יְהִי רָצוֹן:"}, {"kind": "text", "text": "יָאֵ֨ר יְהֹוָ֧ה ׀ פָּנָ֛יו אֵלֶ֖יךָ וִֽיחֻנֶּֽךָּ׃ ועונים כֵּן יְהִי רָצוֹן:"}, {"kind": "text", "text": "יִשָּׂ֨א יְהֹוָ֤ה ׀ פָּנָיו֙ אֵלֶ֔יךָ וְיָשֵׂ֥ם לְךָ֖ שָׁלֽוֹם׃ ועונים כֵּן יְהִי רָצוֹן: וְשָׂמ֥וּ אֶת־שְׁמִ֖י עַל־בְּנֵ֣י יִשְׂרָאֵ֑ל וַאֲנִ֖י אֲבָרְכֵֽם:"}, {"kind": "text", "text": "<b>שִׂים</b> שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים חֵן וָחֶֽסֶד וְרַֽחֲמִים, עָלֵֽינוּ וְעַל כָּל־יִשְׂרָאֵל עַמֶּֽךָ. וּבָֽרְכֵֽנוּ אָבִֽינוּ כֻּלָּֽנוּ כְּאֶחָד בְּאוֹר פָּנֶֽיךָ, כִּי בְאוֹר פָּנֶֽיךָ נָתַֽתָּ לָּֽנוּ יְהֹוָה אֱלֹהֵֽינוּ תּוֹרָה וְחַיִּים, אַֽהֲבָה וָחֶֽסֶד, צְדָקָה וְרַֽחֲמִים, בְּרָכָה וְשָׁלוֹם. וְטוֹב בְּעֵינֶֽיךָ לְבָֽרְכֵֽנוּ וּלְבָרֵךְ אֶת־כָּל־עַמְּךָ יִשְׂרָאֵל, בְּרֹב עֹז וְשָׁלוֹם: בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמְּבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם. אָמֵן:"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>אֱלֹהַי</b>, נְצֹר לְשׁוֹנִי מֵרָע וְשִׂפְתוֹתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּֽעָפָר לַכֹּל תִּֽהְיֶה, פְּתַח לִבִּי בְּתוֹרָתֶֽךָ, וְאַחֲרֵי מִצְוֹתֶֽיךָ תִּרְדֹּף נַפְשִׁי. וְכָל־הַקָּמִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחְשְׁבוֹתָם. יִֽהְי֗וּ כְּמֹ֥ץ לִפְנֵי־ר֑וּחַ וּמַלְאַ֖ךְ יְהֹוָ֣ה דּוֹחֶֽה. קַבֵּל רִנַּת עַמֶּךָ. שַׂגְּבֵנוּ טַהֲרֵנוּ נוֹרָא. עֲשֵׂה לְמַֽעַן שְׁמָךְ, עֲשֵׂה לְמַֽעַן יְמִינָךְ, עֲשֵׂה לְמַֽעַן תּֽוֹרָתָךְ, עֲשֵׂה לְמַֽעַן קְדֻשָּׁתָךְ."}, {"kind": "text", "text": "סגולה לומר פסוק המתחיל וגומר באות שמתחיל וגומר שמו לְ֭מַעַן יֵחָלְצ֣וּן יְדִידֶ֑יךָ הוֹשִׁ֖יעָה יְמִֽינְךָ֣ וַעֲנֵֽנִי:"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>עֹשֶׂה</b> שָׁלוֹם בִּמְרוֹמָיו, הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵֽינוּ, וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן:"}, {"kind": "instruction", "text": "יְהִי רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְּיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ, לַעֲשׂוֹת חֻקֵּי רְצוֹנָךְ וּלְעָבְדָךְ בְּלֵבָב שָׁלֵם:"}, {"kind": "instruction", "text": "ביום טוב אחרי החזרה אומרים יהי שם, ואחריו אומר הש\"ץ קדיש תתקבל. וממשיכים כל ישראל כמו בשבת."}, {"kind": "instruction", "text": "בחול המועד אחרי החזרה אומרים יהי שם, ואחריו אומר הש\"ץ קדיש תתקבל ואומרים המזמור השיך לאותו יום טוב, וקדיש יהא שלמא וקוה עד הסוף."}], "mincha": [{"kind": "header", "text": "תפילת מנחה לימי החול"}, {"kind": "instruction", "text": "לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם יוֹד קֵ\"י בְּוָא\"ו קֵ\"י בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל־יִשְׂרָאֵל. הִנֵּה אֲנַחְנוּ בָּאִים לְהִתְפַּלֵּל תְּפִלַּת מִנְחָה, שֶׁתִּקֵּן יִצְחָק אָבִינוּ עָלָיו הַשָּׁלוֹם, עִם כָּל־הַמִּצְוֹת הַכְּלוּלוֹת בָּהּ, לְתַקֵּן אֶת־שָׁרְשָׁהּ בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַחַת רוּחַ לְיוֹצְרֵנוּ וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ׃"}, {"kind": "text", "text": "<b>לַמְנַצֵּ֥חַ</b> עַֽל־הַגִּתִּ֑ית לִבְנֵי־קֹ֥רַח מִזְמֽוֹר׃ מַה־יְּדִיד֥וֹת מִשְׁכְּנוֹתֶ֗יךָ יְהֹוָ֥ה צְבָאֽוֹת׃ נִכְסְפָ֬ה וְגַם־כָּֽלְתָ֨ה ׀ נַפְשִׁי֮ לְחַצְר֢וֹת יְהֹ֫וָ֥ה לִבִּ֥י וּבְשָׂרִ֑י יְ֝רַנְּנ֗וּ אֶ֣ל אֵֽל־חָֽי׃ גַּם־צִפּ֨וֹר מָ֪צְאָה בַ֡יִת וּדְר֤וֹר ׀ קֵ֥ן לָהּ֮ אֲשֶׁר־שָׁ֢תָה אֶפְרֹ֫חֶ֥יהָ אֶֽת־מִ֭זְבְּחוֹתֶיךָ יְהֹוָ֣ה צְבָא֑וֹת מַ֝לְכִּ֗י וֵאלֹהָֽי׃ אַ֭שְׁרֵי יוֹשְׁבֵ֣י בֵיתֶ֑ךָ ע֗֝וֹד יְֽהַלְל֥וּךָ סֶּֽלָה׃ אַשְׁרֵ֣י אָ֭דָם עֽוֹז־ל֥וֹ בָ֑ךְ מְ֝סִלּ֗וֹת בִּלְבָבָֽם׃ עֹבְרֵ֤י ׀ בְּעֵ֣מֶק הַ֭בָּכָא מַעְיָ֣ן יְשִׁית֑וּהוּ גַּם־בְּ֝רָכ֗וֹת יַעְטֶ֥ה מוֹרֶֽה׃ יֵ֭לְכוּ מֵחַ֣יִל אֶל־חָ֑יִל יֵרָאֶ֖ה אֶל־אֱלֹהִ֣ים בְּצִיּֽוֹן׃ יְהֹ֘וָ֤ה אֱלֹהִ֣ים צְ֭בָאוֹת שִׁמְעָ֣ה תְפִלָּתִ֑י הַאֲזִ֨ינָה אֱלֹהֵ֖י יַעֲקֹ֣ב סֶֽלָה׃ מָ֭גִנֵּנוּ רְאֵ֣ה אֱלֹהִ֑ים וְ֝הַבֵּ֗ט פְּנֵ֣י מְשִׁיחֶֽךָ׃ כִּ֤י טֽוֹב־י֥וֹם בַּחֲצֵרֶ֗יךָ מֵ֫אָ֥לֶף בָּחַ֗רְתִּי הִ֭סְתּוֹפֵף בְּבֵ֣ית אֱלֹהַ֑י מִ֝דּ֗וּר בְּאׇהֳלֵי־רֶֽשַׁע׃ כִּ֤י שֶׁ֨מֶשׁ ׀ וּמָגֵן֮ יְהֹוָ֢ה אֱלֹ֫הִ֥ים חֵ֣ן וְ֭כָבוֹד יִתֵּ֣ן יְהֹוָ֑ה לֹ֥א יִמְנַע־ט֗֝וֹב לַֽהֹלְכִ֥ים בְּתָמִֽים׃ יְהֹוָ֥ה צְבָא֑וֹת אַֽשְׁרֵ֥י אָ֝דָ֗ם בֹּטֵ֥חַ בָּֽךְ׃"}, {"kind": "text", "text": "<b>וַיְדַבֵּ֥ר</b> יְהֹוָ֖ה אֶל־מֹשֶׁ֥ה לֵּאמֹֽר׃ צַ֚ו אֶת־בְּנֵ֣י יִשְׂרָאֵ֔ל וְאָמַרְתָּ֖ אֲלֵהֶ֑ם אֶת־קׇרְבָּנִ֨י לַחְמִ֜י לְאִשַּׁ֗י רֵ֚יחַ נִֽיחֹחִ֔י תִּשְׁמְר֕וּ לְהַקְרִ֥יב לִ֖י בְּמוֹעֲדֽוֹ׃ וְאָמַרְתָּ֣ לָהֶ֔ם זֶ֚ה הָֽאִשֶּׁ֔ה אֲשֶׁ֥ר תַּקְרִ֖יבוּ לַיהֹוָ֑ה כְּבָשִׂ֨ים בְּנֵֽי־שָׁנָ֧ה תְמִימִ֛ם שְׁנַ֥יִם לַיּ֖וֹם עֹלָ֥ה תָמִֽיד׃ אֶת־הַכֶּ֥בֶשׂ אֶחָ֖ד תַּעֲשֶׂ֣ה בַבֹּ֑קֶר וְאֵת֙ הַכֶּ֣בֶשׂ הַשֵּׁנִ֔י תַּעֲשֶׂ֖ה בֵּ֥ין הָֽעַרְבָּֽיִם׃ וַעֲשִׂירִ֧ית הָאֵיפָ֛ה סֹ֖לֶת לְמִנְחָ֑ה בְּלוּלָ֛ה בְּשֶׁ֥מֶן כָּתִ֖ית רְבִיעִ֥ת הַהִֽין׃ עֹלַ֖ת תָּמִ֑יד הָעֲשֻׂיָה֙ בְּהַ֣ר סִינַ֔י לְרֵ֣יחַ נִיחֹ֔חַ אִשֶּׁ֖ה לַֽיהֹוָֽה׃ וְנִסְכּוֹ֙ רְבִיעִ֣ת הַהִ֔ין לַכֶּ֖בֶשׂ הָאֶחָ֑ד בַּקֹּ֗דֶשׁ הַסֵּ֛ךְ נֶ֥סֶךְ שֵׁכָ֖ר לַיהֹוָֽה׃ וְאֵת֙ הַכֶּ֣בֶשׂ הַשֵּׁנִ֔י תַּעֲשֶׂ֖ה בֵּ֣ין הָֽעַרְבָּ֑יִם כְּמִנְחַ֨ת הַבֹּ֤קֶר וּכְנִסְכּוֹ֙ תַּעֲשֶׂ֔ה אִשֵּׁ֛ה רֵ֥יחַ נִיחֹ֖חַ לַיהֹוָֽה׃"}, {"kind": "text", "text": "<b>אַתָּה</b> הוּא יְהֹוָה אֱלֹהֵֽינוּ, שֶׁהִקְטִֽירוּ אֲבוֹתֵֽינוּ לְפָנֶֽיךָ אֶת קְטֹֽרֶת הַסַּמִּים, בִּזְמַן שֶׁבֵּית הַמִּקְדָשׁ קַיָּם, כַּאֲשֶׁר צִוִּֽיתָ אוֹתָם עַל־יַד מֹשֶׁה נְבִיאָךְ, כַּכָּתוּב בְּתֽוֹרָתָךְ:"}, {"kind": "text", "text": "<b>וַיֹּ֩אמֶר֩</b> יְהֹוָ֨ה אֶל־מֹשֶׁ֜ה קַח־לְךָ֣ סַמִּ֗ים נָטָ֤ף | וּשְׁחֵ֙לֶת֙ וְחֶלְבְּנָ֔ה סַמִּ֖ים וּלְבֹנָ֣ה זַכָּ֑ה בַּ֥ד בְּבַ֖ד יִהְיֶֽה׃ וְעָשִׂ֤יתָ אֹתָהּ֙ קְטֹ֔רֶת רֹ֖קַח מַעֲשֵׂ֣ה רוֹקֵ֑חַ מְמֻלָּ֖ח טָה֥וֹר קֹֽדֶשׁ׃ וְשָֽׁחַקְתָּ֣ מִמֶּ֘נָּה֮ הָדֵק֒ וְנָתַתָּ֨ה מִמֶּ֜נָּה לִפְנֵ֤י הָעֵדֻת֙ בְּאֹ֣הֶל מוֹעֵ֔ד אֲשֶׁ֛ר אִוָּעֵ֥ד לְךָ֖ שָׁ֑מָּה קֹ֥דֶשׁ קׇֽדָשִׁ֖ים תִּהְיֶ֥ה לָכֶֽם׃ וְנֶֽאֱמַר וְהִקְטִ֥יר עָלָ֛יו אַהֲרֹ֖ן קְטֹ֣רֶת סַמִּ֑ים בַּבֹּ֣קֶר בַּבֹּ֗קֶר בְּהֵיטִיב֛וֹ אֶת־הַנֵּרֹ֖ת יַקְטִירֶֽנָּה: וּבְהַעֲלֹ֨ת אַהֲרֹ֧ן אֶת־הַנֵּרֹ֛ת בֵּ֥ין הָעַרְבַּ֖יִם יַקְטִירֶ֑נָּה קְטֹ֧רֶת תָּמִ֛יד לִפְנֵ֥י יְהֹוָ֖ה לְדֹרֹתֵיכֶֽם:"}, {"kind": "text", "text": "<b>תָּנוּ</b> רַבָּנָן: פִּטּוּם הַקְּטֹֽרֶת כֵּיצַד? שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וּשְׁמוֹנָה מָנִים הָיוּ בָהּ. שְׁלֹשׁ מֵאוֹת וְשִׁשִּׁים וַֽחֲמִשָּׁה כְּמִנְיַן יְמוֹת הַחַמָּה, מָנֶה בְּכָל־יוֹם, מַֽחֲצִיתוֹ בַּבֹּֽקֶר וּמַֽחֲצִיתוֹ בָּעֶרֶב. וּשְׁלֹשָׁה מָנִים יְתֵרִים, שֶׁמֵּהֶם מַכְנִיס כֹּהֵן גָּדוֹל, וְנוֹטֵל מֵהֶם מְלֹא חָפְנָיו בְּיוֹם הַכִּפּוּרִים, וּמַֽחֲזִירָן לְמַכְתֶּֽשֶׁת בְּעֶֽרֶב יוֹם הַכִּפּוּרִים, כְּדֵי לְקַיֵּם מִצְוַת דַקָּה מִן הַדַּקָּה. וְאַחַד־עָשָׂר סַמָּנִים הָיוּ בָהּ, וְאֵֽלּוּ הֵן:"}, {"kind": "text", "text": "א הַצֳּרִי ב וְהַצִּפֹּֽרֶן ג וְהַחֶלְבְּנָה ד וְהַלְּבוֹנָה, מִשְׁקַל שִׁבְעִים שִׁבְעִים מָנֶה. ה מוֹר, ו וּקְצִיעָה ז וְשִׁבֹּֽלֶת נֵרְדְּ ח וְכַרְכֹּם, מִשְׁקַל שִׁשָּׁה עָשָׂר שִׁשָּׁה עָשָׂר מָנֶה. ט קֹשְׁטְ שְׁנֵים עָשָׂר, י קִלּוּפָה שְׁלֹשָׁה, יא קִנָּמוֹן תִּשְׁעָה, בּוֹרִית־כַּרְשִׁינָה תִּשְׁעָה קַבִּין. יֵין קַפְרִיסִין סְאִין תְּלָת וְקַבִּין תְּלָתָא. וְאִם לֹא מָצָא יֵין קַפְרִיסִין, מֵבִיא חֲמַר חִיוָר עַתִּיק. מֶֽלַח סְדוֹמִית, רֽוֹבַע. מַעֲלֶה עָשָׁן, כָּל־שֶׁהוּא. רִבִּי נָתָן הַבַּבְלִי אוֹמֵר: אַף כִּפַּת הַיַּרְדֵּן כָּל־שֶׁהִיא, אִם נָתַן בָּהּ דְּבַשׁ פְּסָלָהּ, וְאִם חִסֵּר אַחַת מִכָּל־סַמְמָנֶֽיהָ, חַיָּיב מִיתָה:"}, {"kind": "text", "text": "<b>רַבָּן</b> שִׁמְעוֹן בֶּן־גַּמְלִיאֵל אוֹמֵר: הַצֳּרִי אֵינוֹ אֶלָּא שְׁרָף, הַנּוֹטֵף מֵֽעֲצֵי הַקְּטָף. בֹּרִית כַּרְשִׁינָה, לְמָה הִיא בָֽאָה? כְּדֵי לְשַׁפּוֹת בָּהּ אֶת־הַצִּפֹּֽרֶן, כְּדֵי שֶׁתְּהֵא נָאָה. יֵין קַפְרִיסִין, לְמָה הוּא בָא? כְּדֵי לִשְׁרוֹת בּוֹ אֶת־הַצִּפֹּֽרֶן כְּדֵי שֶׁתְּהֵא עַזָּה. וַהֲלֹא מֵי רַגְלַֽיִם יָפִין לָהּ? אֶלָּא שֶׁאֵין מַכְנִיסִין מֵי רַגְלַֽיִם בַּמִּקְדָּשׁ, מִפְּנֵי הַכָּבוֹד:"}, {"kind": "text", "text": "<b>תַּנְיָא</b> רִבִּי נָתָן אוֹמֵר: כְּשֶׁהוּא שׁוֹחֵק, אוֹמֵר: הָדֵק הֵיטֵב, הֵיטֵב הָדֵק. מִפְּנֵי שֶׁהַקּוֹל יָפֶה לַבְּשָׂמִים. פִּטְּמָהּ לַֽחֲצָאִין, כְּשֵׁרָה. לְשָׁלִישׁ וּלְרָבִֽיעַ, לֹא שָׁמַֽעְנוּ. אָמַר רִבִּי יְהוּדָה: זֶה הַכְּלָל, אִם כְּמִדָּתָהּ, כְּשֵׁרָה לַֽחֲצָאִין. וְאִם חִסֵּר אַחַת מִכָּל־סַמְמָנֶֽיהָ, חַיָּיב מִיתָה:"}, {"kind": "text", "text": "<b>תָּנֵי</b> בַר־קַפָּרָא: אַחַת לְשִׁשִּׁים אוֹ לְשִׁבְעִים שָׁנָה, הָֽיְתָה בָֽאָה שֶׁל שִׁירַֽיִם לַֽחֲצָאִין. וְעוֹד תָּנֵי בַר־קַפָּרָא: אִלּוּ הָיָה נוֹתֵן בָּהּ קָרְטוֹב שֶׁל דְּבַשׁ, אֵין אָדָם יָכוֹל לַֽעֲמֹד מִפְּנֵי רֵיחָהּ. וְלָֽמָּה אֵין מְעָֽרְבִין בָּהּ דְּבַשׁ, מִפְּנֵי שֶׁהַתּוֹרָה אָֽמְרָה: כִּ֤י כָל־שְׂאֹר֙ וְכָל־דְּבַ֔שׁ לֹֽא־תַקְטִ֧ירוּ מִמֶּ֛נּוּ אִשֶּׁ֖ה לַֽיהֹוָֽה: יְהֹוָ֣ה צְבָא֣וֹת עִמָּ֑נוּ מִשְׂגָּֽב־לָ֨נוּ אֱלֹהֵ֖י יַֽעֲקֹ֣ב סֶֽלָה׃ יְהֹוָ֥ה צְבָא֑וֹת אַֽשְׁרֵ֥י אָ֝דָ֗ם בֹּטֵ֥חַ בָּֽךְ׃ יְהֹוָ֥ה הוֹשִׁ֑יעָה הַ֝מֶּ֗לֶךְ יַעֲנֵ֥נוּ בְיוֹם־קׇרְאֵֽנוּ: וְעָֽרְבָה֙ לַֽיהֹוָ֔ה מִנְחַ֥ת יְהוּדָ֖ה וִירֽוּשָׁלָ֑‍ִם כִּימֵ֣י עוֹלָ֔ם וּכְשָׁנִ֖ים קַדְמֹנִיֹּֽת:"}, {"kind": "text", "text": "<b>אַ֭שְׁרֵי</b> יוֹשְׁבֵ֣י בֵיתֶ֑ךָ ע֝֗וֹד יְֽהַלְל֥וּךָ סֶּֽלָה: אַשְׁרֵ֣י הָ֭עָם שֶׁכָּ֣כָה לּ֑וֹ אַֽשְׁרֵ֥י הָ֝עָ֗ם שֱׁיְהֹוָ֥ה אֱלֹהָֽיו:"}, {"kind": "text", "text": "<b>תְּהִלָּ֗ה</b> לְדָ֫וִ֥ד אֲרוֹמִמְךָ֣ אֱלוֹהַ֣י הַמֶּ֑לֶךְ וַאֲבָרְכָ֥ה שִׁ֝מְךָ֗ לְעוֹלָ֥ם וָעֶֽד׃ בְּכָל־י֥וֹם אֲבָֽרְכֶ֑ךָּ וַאֲהַֽלְלָ֥ה שִׁ֝מְךָ֗ לְעוֹלָ֥ם וָעֶֽד׃ גָּ֘ד֤וֹל יְהֹוָ֣ה וּמְהֻלָּ֣ל מְאֹ֑ד וְ֝לִגְדֻלָּת֗וֹ אֵ֣ין חֵֽקֶר׃ דּ֣וֹר לְ֭דוֹר יְשַׁבַּ֣ח מַעֲשֶׂ֑יךָ וּגְב֖וּרֹתֶ֣יךָ יַגִּֽידוּ׃ הֲ֭דַר כְּב֣וֹד הוֹדֶ֑ךָ וְדִבְרֵ֖י נִפְלְאֹתֶ֣יךָ אָשִֽׂיחָה׃ וֶעֱז֣וּז נֽוֹרְאֹתֶ֣יךָ יֹאמֵ֑רוּ וגדלותיך [וּגְדֻלָּתְךָ֥] אֲסַפְּרֶֽנָּה׃ זֵ֣כֶר רַב־טוּבְךָ֣ יַבִּ֑יעוּ וְצִדְקָתְךָ֥ יְרַנֵּֽנוּ׃ חַנּ֣וּן וְרַח֣וּם יְהֹוָ֑ה אֶ֥רֶךְ אַ֝פַּ֗יִם וּגְדׇל־חָֽסֶד׃ טוֹב־יְהֹוָ֥ה לַכֹּ֑ל וְ֝רַחֲמָ֗יו עַל־כׇּל־מַעֲשָֽׂיו׃ יוֹד֣וּךָ יְ֭הֹוָה כׇּל־מַעֲשֶׂ֑יךָ וַ֝חֲסִידֶ֗יךָ יְבָרְכֽוּכָה׃ כְּב֣וֹד מַלְכוּתְךָ֣ יֹאמֵ֑רוּ וּגְבוּרָתְךָ֥ יְדַבֵּֽרוּ׃ לְהוֹדִ֤יעַ ׀ לִבְנֵ֣י הָ֭אָדָם גְּבוּרֹתָ֑יו וּ֝כְב֗וֹד הֲדַ֣ר מַלְכוּתֽוֹ׃ מַֽלְכוּתְךָ֗ מַלְכ֥וּת כׇּל־עֹלָמִ֑ים וּ֝מֶֽמְשַׁלְתְּךָ֗ בְּכׇל־דּ֥וֹר וָדֹֽר׃ סוֹמֵ֣ךְ יְ֭הֹוָה לְכׇל־הַנֹּפְלִ֑ים וְ֝זוֹקֵ֗ף לְכׇל־הַכְּפוּפִֽים׃ עֵֽינֵי־כֹ֭ל אֵלֶ֣יךָ יְשַׂבֵּ֑רוּ וְאַתָּ֤ה נֽוֹתֵן־לָהֶ֖ם אֶת־אׇכְלָ֣ם בְּעִתּֽוֹ׃ פּוֹתֵ֥חַ אֶת־יָדֶ֑ךָ וּמַשְׂבִּ֖יעַ לְכׇל־חַ֣י רָצֽוֹן׃ צַדִּ֣יק יְ֭הֹוָה בְּכׇל־דְּרָכָ֑יו וְ֝חָסִ֗יד בְּכׇל־מַעֲשָֽׂיו׃ קָר֣וֹב יְ֭הֹוָה לְכׇל־קֹרְאָ֑יו לְכֹ֤ל אֲשֶׁ֖ר יִקְרָאֻ֣הוּ בֶֽאֱמֶֽת׃ רְצוֹן־יְרֵאָ֥יו יַעֲשֶׂ֑ה וְֽאֶת־שַׁוְעָתָ֥ם יִ֝שְׁמַ֗ע וְיוֹשִׁיעֵֽם׃ שׁוֹמֵ֣ר יְ֭הֹוָה אֶת־כׇּל־אֹהֲבָ֑יו וְאֵ֖ת כׇּל־הָרְשָׁעִ֣ים יַשְׁמִֽיד׃ תְּהִלַּ֥ת יְהֹוָ֗ה יְֽדַבֶּ֫ר פִּ֥י וִיבָרֵ֣ךְ כׇּל־בָּ֭שָׂר שֵׁ֥ם קׇדְשׁ֗וֹ לְעוֹלָ֥ם וָעֶֽד׃ וַאֲנַ֤חְנוּ ׀ נְבָ֘רֵ֤ךְ יָ֗הּ מֵעַתָּ֥ה וְעַד־עוֹלָ֗ם הַֽלְלוּיָֽהּ׃"}, {"kind": "text", "text": "<b>תִּכּ֤וֹן</b> תְּפִלָּתִ֣י קְטֹ֣רֶת לְפָנֶ֑יךָ מַֽשְׂאַ֥ת כַּ֝פַּ֗י מִנְחַת־עָֽרֶב: הַקְשִׁ֤יבָה ׀ לְק֬וֹל שַׁוְעִ֗י מַלְכִּ֥י וֵאלֹהָ֑י כִּֽי־אֵ֝לֶ֗יךָ אֶתְפַּלָּֽל:"}, {"kind": "instruction", "text": "ואומר החזן חצי קדיש"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "header", "text": "עמידה לשחרית מנחה וערבית שלש רגלים"}, {"kind": "text", "text": "<b>אֲ֭דֹנָי</b> שְׂפָתַ֣י תִּפְתָּ֑ח וּ֝פִ֗י יַגִּ֥יד תְּהִלָּתֶֽךָ׃"}, {"kind": "text", "text": "<b>בָּרוּךְ</b> אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ, אֱלֹהֵי אַבְרָהָם, אֱלֹהֵי יִצְחָק, וֵֽאלֹהֵי יַעֲקֹב. הָאֵל הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא, אֵל עֶלְיוֹן, גּוֹמֵל חֲסָדִים טוֹבִים, קוֹנֵה הַכֹּל, וְזוֹכֵר חַסְדֵּי אָבוֹת, וּמֵבִיא גוֹאֵל לִבְנֵי בְנֵיהֶם לְמַֽעַן שְׁמוֹ בְּאַֽהֲבָה: מֶֽלֶךְ עוֹזֵר וּמוֹשִֽׁיעַ וּמָגֵן: בָּרוּךְ אַתָּה יַהַוַהַ, מָגֵן אַבְרָהָם:"}, {"kind": "text", "text": "<b>אַתָּה</b> גִבּוֹר לְעוֹלָם אֲדֹנָי, מְחַיֶּה מֵתִים אַתָּה, רַב לְהוֹשִֽׁיעַ."}, {"kind": "text", "text": "בקיץ: מוֹרִיד הַטָּל. בחורף: מַשִּׁיב הָרֽוּחַ וּמוֹרִיד הַגֶּֽשֶׁם."}, {"kind": "text", "text": "מְכַלְכֵּל חַיִּים בְּחֶֽסֶד, מְחַיֵּה מֵתִים בְּרַֽחֲמִים רַבִּים, סוֹמֵךְ נֽוֹפְלִים, וְרוֹפֵא חוֹלִים, וּמַתִּיר אֲסוּרִים, וּמְקַיֵּם אֱמֽוּנָתוֹ לִֽישֵׁנֵי עָפָר. מִי כָמֽוֹךָ בַּֽעַל גְּבוּרוֹת, וּמִי דֽוֹמֶה לָךְ, מֶֽלֶךְ מֵמִית וּמְחַיֶּה וּמַצְמִֽיחַ יְשׁוּעָה. וְנֶֽאֱמָן אַתָּה לְהַֽחֲיוֹת מֵתִים: בָּרוּךְ אַתָּה יֵהֵוֵהֵ, מְחַיֵּה הַמֵּתִים:"}, {"kind": "instruction", "text": "קדושה<br>בחזרת הש\"ץ של שחרית ומנחה אומרים:"}, {"kind": "instruction", "text": "נַקְדִּישָׁךְ וְנַעֲרִיצָךְ, כְּנֹֽעַם שִֽׂיחַ סוֹד שַׂרְפֵי קֹֽדֶשׁ, הַמְשַׁלְּשִׁים לְךָ קְדֻשָּׁה, וְכֵן כָּתוּב עַל יַד נְבִיאָךְ: וְקָרָ֨א זֶ֤ה אֶל־זֶה֙ וְאָמַ֔ר קָד֧וֹשׁ ׀ קָד֛וֹשׁ קָד֖וֹשׁ יְהֹוָ֣ה צְבָא֑וֹת מְלֹ֥א כָל־הָאָ֖רֶץ כְּבוֹדֽוֹ׃ לְעֻמָּתָם מְשַׁבְּחִים וְאוֹמְרִים: בָּר֥וּךְ כְּבוֹד־יְהֹוָ֖ה מִמְּקוֹמֽוֹ׃ וּבְדִבְרֵי קָדְשָׁךְ כָּתוּב לֵאמֹר: יִמְלֹ֤ךְ יְהֹוָ֨ה ׀ לְעוֹלָ֗ם אֱלֹהַ֣יִךְ צִ֭יּוֹן לְדֹ֥ר וָדֹ֗ר הַֽלְלוּיָֽהּ:"}, {"kind": "text", "text": "<b>אַתָּה</b> קָדוֹשׁ וְשִׁמְךָ קָדוֹשׁ, וּקְדוֹשִׁים בְּכָל־יוֹם יְהַֽלְלֽוּךָ סֶּֽלָה: בָּרוּךְ אַתָּה יֹהֵוָהֵ, הָאֵל הַקָּדוֹשׁ:"}, {"kind": "text", "text": "<b>אַתָּה</b> בְּחַרְתָּנוּ מִכָּל הָעַמִּים, אָהַבְתָּ אוֹתָנוּ וְרָצִיתָ בָּנוּ, וְרוֹמַמְתָּנוּ מִכָּל הַלְּשׁוֹנוֹת, וְקִדַּשְׁתָּנוּ בְּמִצְוֹתֶיךָ, וְקֵרַבְתָּנוּ מַלְכֵּנוּ לַעֲבוֹדָתֶךָ, וְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ עָלֵינוּ קָרָאתָ."}, {"kind": "instruction", "text": "במוצאי שבת אומרים"}, {"kind": "instruction", "text": "וַתּוֹדִיעֵנוּ מִשְׁפְּטֵי צִדְקֶךָ, וַתְּלַמְּדֵנוּ לַעֲשׂוֹת בָּהֶם חֻקֵּי רְצוֹנֶךָ, וַתִּתֶּן לָנוּ יְהֹוָה אֱלֹהֵינוּ בְּאַהֲבָה מִשְׁפָּטִים יְשָׁרִים וְתוֹרוֹת אֱמֶת, חֻקִּים וּמִצְוֹת טוֹבִים, וַתַּנְחִילֵנוּ זְמַנֵּי שָׂשׂוֹן וּמוֹעֲדֵי קֹדֶשׁ וְחַגֵּי נְדָבָה, וַתּוֹרִישֵׁנוּ קְדֻשַּׁת שַׁבָּת וּכְבוֹד מוֹעֵד וַחֲגִיגַת הָרֶגֶל. בֵּין קְדֻשַּׁת שַׁבָּת לִקְדֻשַּׁת יוֹם טוֹב הִבְדַּלְתָּ, וְאֶת יוֹם הַשְּׁבִיעִי מִשֵּׁשֶׁת יְמֵי הַמַּעֲשֶׂה הִקְדַּשְׁתָּ, וְהִבְדַּלְתָּ וְהִקְדַּשְׁתָּ אֶת עַמְּךָ יִשְׂרָאֵל בִּקְדֻשָּׁתָךְ:"}, {"kind": "text", "text": "וַתִּֽתֶּן לָֽנוּ יְהֹוָה אֱלֹהֵֽינוּ בְּאַהֲבָה"}, {"kind": "text", "text": "בשבת שַׁבָּתוֹת לִמְנוּחָה וּ"}, {"kind": "text", "text": "מוֹעֲדִים לְשִׂמְחָה, חַגִּים וּזְמַנִּים לְשָׂשׂוֹן, אֶת יוֹם"}, {"kind": "text", "text": "בשבת הַשַּׁבָּת הַזֶּה, וְאֶת יוֹם"}, {"kind": "text", "text": "בפסח: חַג הַמַּצּוֹת הַזֶּה, אֶת יוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה, זְמַן חֵרוּתֵנוּ:"}, {"kind": "text", "text": "בשבועות: חַג הַשָׁבוּעוֹת הַזֶּה, אֶת יוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה, זְמַן מַתַּן תּוֹרָתֵֽינוּ:"}, {"kind": "text", "text": "בסוכות: חַג הַסֻּכּוֹת הַזֶּה, אֶת יוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה, זְמַן שִׂמְחָתֵֽנוּ:"}, {"kind": "text", "text": "בש''ע: שְׁמִינִי חַג עֲצֶֽרֶת הַזֶּה, אֶת יוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה, זְמַן שִׂמְחָתֵֽנוּ:"}, {"kind": "text", "text": "בְּאַהֲבָה מִקְרָא קֹֽדֶשׁ זֵֽכֶר לִיצִיאַת מִצְרָֽיִם."}, {"kind": "text", "text": "<b>אֱלֹהֵֽינוּ</b> וֵאלֹהֵי אֲבוֹתֵֽינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּֽיעַ וְיֵרָאֶה, וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵֽנוּ וְזִכְרוֹן אֲבוֹתֵֽינוּ, זִכְרוֹן יְרוּשָׁלַֽיִם עִירָךְ, וְזִכְרוֹן מָשִֽׁיחַ בֶּן־דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל־עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶֽיךָ, לִפְלֵיטָה, לְטוֹבָה, לְחֵן, לְחֶֽסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם, בְּיוֹם"}, {"kind": "text", "text": "בשבת הַשַּׁבָּת הַזֶּה, וּבְיוֹם"}, {"kind": "text", "text": "בפסח: חַג הַמַּצּוֹת הַזֶּה,"}, {"kind": "text", "text": "בשבועות: חַג הַשָּׁבוּעוֹת הַזֶּה,"}, {"kind": "text", "text": "בסוכות: חַג הַסֻּכּוֹת הַזֶּה,"}, {"kind": "text", "text": "בש''ע: שְׁמִינִי חַג עֲצֶֽרֶת הַזֶּה,"}, {"kind": "text", "text": "בְּיוֹם טוֹב מִקְרָא קֹֽדֶשׁ הַזֶּה,לְרַחֵם בּוֹ עָלֵֽינוּ וּלְהוֹשִׁיעֵֽנוּ. זָכְרֵֽנוּ יְהֹוָה אֱלֹהֵֽינוּ בּוֹ לְטוֹבָה, וּפָקְדֵֽנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵֽנוּ בוֹ לְחַיִּים טוֹבִים, בִּדְבַר יְשׁוּעָה וְרַחֲמִים. חוּס וְחָנֵּֽנוּ, וַחֲמוֹל וְרַחֵם עָלֵֽינוּ, וְהוֹשִׁיעֵֽנוּ כִּי אֵלֶֽיךָ עֵינֵֽינוּ, כִּי אֵל מֶֽלֶךְ חַנּוּן וְרַחוּם אָֽתָּה:"}, {"kind": "text", "text": "<b>וְהַשִּׂיאֵנוּ</b> יְהֹוָה אֱלֹהֵינוּ אֶת בִּרְכַּת מוֹעֲדֶיךָ לְחַיִּים בְּשִׂמְחָה וּבְשָׁלוֹם, כַּאֲשֶׁר רָצִיתָ וְאָמַרְתָּ לְבָרְכֵנוּ כֵּן תְּבָרְכֵנוּ סֶלָה."}, {"kind": "text", "text": "בשבת אומרים אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, רְצֵה נָא בִּמְנוּחָתֵנוּ,"}, {"kind": "text", "text": "<b>קַדְּשֵׁנוּ</b> בְּמִצְוֹתֶיךָ, שִׂים חֶלְקֵנוּ בְּתוֹרָתָךְ, שַׂבְּעֵנוּ מִטּוּבָךְ, שַׂמֵּחַ נַפְשֵׁנוּ בִּישׁוּעָתָךְ, וְטַהֵר לִבֵּנוּ לְעָבְדְּךָ בֶאֱמֶת, וְהַנְחִילֵנוּ יְהֹוָה אֱלֹהֵינוּ בשבת בְּאַהֲבָה וּבְרָצוֹן בְּשִׂמְחָה וּבְשָׂשׂוֹן בשבת שַׁבָּתוֹת וּ מוֹעֲדֵי קָדְשֶׁךָ, וְיִשְׂמְחוּ בְּךָ כָּל יִשְׂרָאֵל מְקַדְּשֵׁי שְׁמֶךָ. בָּרוּךְ אַתָּה יְהֹוָה, מְקַדֵּשׁ בשבת הַשַּׁבָּת וְיִשְׂרָאֵל וְהַזְּמַנִּים:"}, {"kind": "text", "text": "<b>רְצֵה</b> יְהֹוָה אֱלֹהֵֽינוּ בְּעַמְּךָ יִשְׂרָאֵל וְלִתְפִלָּתָם שְׁעֵה, וְהָשֵׁב הָֽעֲבוֹדָה לִדְבִיר בֵּיתֶֽךָ, וְאִשֵּׁי יִשְׂרָאֵל וּתְפִלָּתָם, מְהֵרָה בְּאַֽהֲבָה תְקַבֵּל בְּרָצוֹן, וּתְהִי לְרָצוֹן תָּמִיד עֲבוֹדַת יִשְׂרָאֵל עַמֶּֽךָ: וְאַתָּה בְּרַֽחֲמֶֽיךָ הָרַבִּים, תַּחְפֹּץ בָּֽנוּ וְתִרְצֵֽנוּ, וְתֶֽחֱזֶֽינָה עֵינֵֽינוּ בְּשֽׁוּבְךָ לְצִיּוֹן בְּרַֽחֲמִים: בָּרוּךְ אַתָּה יִהִוִהִ, הַמַּֽחֲזִיר שְׁכִֽינָתוֹ לְצִיּוֹן:"}, {"kind": "instruction", "text": "בברכת \"מודים\" יכרע ב\"מודים\" ויזקוף בשם (בא\"ח בשלח הכ\"א)"}, {"kind": "text", "text": "<b>מוֹדִים</b> אֲנַֽחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵֽינוּ וֵֽאלֹהֵי אֲבוֹתֵֽינוּ לְעוֹלָם וָעֶד, צוּרֵֽנוּ צוּר חַיֵּֽינוּ וּמָגֵן יִשְׁעֵֽנוּ אַתָּה הוּא, לְדוֹר וָדוֹר נוֹדֶה לְךָ וּנְסַפֵּר תְּהִלָּתֶֽךָ, עַל חַיֵּֽינוּ הַמְּסוּרִים בְּיָדֶֽךָ, וְעַל נִשְׁמוֹתֵֽינוּ הַפְּקוּדוֹת לָךְ, וְעַל נִסֶּֽיךָ שֶׁבְּכָל־יוֹם עִמָּֽנוּ, וְעַל נִפְלְאוֹתֶֽיךָ וְטֽוֹבוֹתֶֽיךָ שֶׁבְּכָל־עֵת, עֶֽרֶב וָבֹֽקֶר וְצָֽהֳרָֽיִם. הַטּוֹב, כִּי לֹא כָלוּ רַחֲמֶֽיךָ, הַמְּרַחֵם, כִּי לֹא תַֽמּוּ חֲסָדֶֽיךָ, כִּי מֵֽעוֹלָם קִוִּֽינוּ לָךְ:"}, {"kind": "text", "text": "<b>מודים דרבנן</b><br>בחזרת הש\"ץ כשהחזן אומר מודים, הקהל אומרים:<br>מוֹדִים אֲנַחְנוּ לָךְ, שֶׁאַתָּה הוּא יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, אֱלֹהֵי כָל בָּשָׁר, יוֹצְרֵנוּ יוֹצֵר בְּרֵאשִׁית. בְּרָכוֹת וְהוֹדָאוֹת לְשִׁמְךָ הַגָּדוֹל וְהַקָּדוֹשׁ, עַל שֶׁהֶחֱיִיתָנוּ וְקִיַּמְתָּנוּ. כֵּן תְּחַיֵּנוּ וּתְחָנֵּנוּ וְתֶאֱסוֹף גָּלֻיּוֹתֵינוּ לְחַצְרוֹת קָדְשֶׁךָ, לִשְׁמֹר חֻקֶּיךָ וְלַעֲשׂוֹת רְצוֹנְךָ וּלְעָבְדְךָ בְלֵבָב שָׁלֵם, עַל שֶׁאֲנַחְנוּ מוֹדִים לָךְ, בָּרוּךְ אֵל הַהוֹדָאוֹת."}, {"kind": "text", "text": "<b>וְעַל</b> כֻּלָּם יִתְבָּרַךְ, וְיִתְרוֹמָם, וְיִתְנַשֵּׂא, תָּמִיד, שִׁמְךָ מַלְכֵּֽנוּ, לְעוֹלָם וָעֶד. וְכָל־הַחַיִּים יוֹדֽוּךָ סֶּֽלָה: וִֽיהַֽלְלוּ וִֽיבָֽרְכוּ אֶת־שִׁמְךָ הַגָּדוֹל בֶּֽאֱמֶת לְעוֹלָם כִּי טוֹב, הָאֵל יְשֽׁוּעָתֵֽנוּ וְעֶזְרָתֵֽנוּ סֶֽלָה, הָאֵל הַטּוֹב: משתחוה בברוך וזוקף בשם בָּרוּךְ אַתָּה יֻהֻוֻהֻ, הַטּוֹב שִׁמְךָ וּלְךָ נָאֶה לְהוֹדוֹת:"}, {"kind": "text", "text": "ברכת כהנים"}, {"kind": "text", "text": "כשעוקר הכהן רגליו לישא כפיו יאמר (בא\"ח תצוה י\"ב)<br>לְשֵׁם יִחוּד קֻדְשָׁא בְּרִיךְ הוּא וּשְׁכִינְתֵּיהּ. בִּדְחִֽילוּ וּרְחִֽימוּ. וּרְחִֽימוּ וּדְחִֽילוּ. לְיַחֲדָא שֵׁם יוֹ\"ד קֵ\"א בְּוָא\"ו קֵ\"א בְּיִחוּדָא שְׁלִים. בְּשֵׁם כָּל־יִשְׂרָאֵל הִנֵּה אָנֹכִי מוּכָן וּמְזוּמָן לְקַיֵּם מִצְוַת עֲשֵׂה לְבָרֵךְ אֶת יִשְׂרָאֵל בִּרְכַּת כֹּהַנִים בִּנְשִׂיאוּת כַּפַּיִם, לַעֲשׂוֹת נַֽחַת רֽוּחַ לְיֽוֹצְרֵֽנוּ וּלְהַמְשִׁיךְ שֶׁפַע וּבְרָכָה לְכָל־הָעוֹלָמוֹת וְלַעֲשׂוֹת רְצוֹן בּֽוֹרְאֵֽנוּ. וִיהִ֤י ׀ נֹ֤עַם אֲדֹנָ֥י אֱלֹהֵ֗ינוּ עָ֫לֵ֥ינוּ וּמַעֲשֵׂ֣ה יָ֭דֵינוּ כּוֹנְנָ֥ה עָלֵ֑ינוּ וּֽמַעֲשֵׂ֥ה יָ֝דֵ֗ינוּ כּוֹנְנֵֽהוּ:"}, {"kind": "text", "text": "וכשעומדים הכהנים על הדוכן לאחר שענו \"מודים דרבנן\", אומרים<br>יְהִי רָצוֹן מִלְּפָנֶֽיךָ יְהֹוָה אֱלֹהֵֽינוּ וֵאלֹהֵי אֲבוֹתֵֽינוּ שֶׁתִּהְיֶה בְּרָכָה זוֹ שֶׁצִּּוִיתָֽנוּ לְבָרֵךְ אֶת־עַמְּךָ יִשְׂרָאֵל בְּרָכָה שְׁלֵמָה וְלֹא יִהְיֶה בָהּ מִכְשׁוֹל וְעָוֹן מֵעַתָּה וְעַד עוֹלָם:"}, {"kind": "text", "text": "בחזרת הש\"ץ אומרים ברכת כהנים, אם יש יותר מכהן אחד קורא להם החזן: כֹּהֲנִים: הכהנים מברכים:<br>בָּרוּךְ אַתָּה יְהֹוָה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָֽעוֹלָם, אֲשֶׁר קִדְּשָֽׁנוּ בִּקְדֻשָּׁתוֹ שֶׁל־אַֽהֲרֹן, וְצִוָּֽנוּ לְבָרֵךְ אֶת־עַמּוֹ יִשְׂרָאֵל בְּאַֽהֲבָה: הקהל עונים אָמֵן:"}, {"kind": "instruction", "text": "ואומר החזן והכהנים אחריו מילה במילה:"}, {"kind": "text", "text": "יְבָרֶכְךָ֥ יְהֹוָ֖ה וְיִשְׁמְרֶֽךָ׃ ועונים אָמֵן:"}, {"kind": "text", "text": "יָאֵ֨ר יְהֹוָ֧ה ׀ פָּנָ֛יו אֵלֶ֖יךָ וִֽיחֻנֶּֽךָּ׃ ועונים אָמֵן:"}, {"kind": "text", "text": "יִשָּׂ֨א יְהֹוָ֤ה ׀ פָּנָיו֙ אֵלֶ֔יךָ וְיָשֵׂ֥ם לְךָ֖ שָׁלֽוֹם׃ ועונים אָמֵן:"}, {"kind": "instruction", "text": "וכשמתחיל שליח ציבור \"שים שלום\" אז מחזירין פניהם כלפי ההיכל, ולא יחזירו פניהם קודם, ואז הכהנים אומרים<br>רִבּוֹן הָעוֹלָמִים עָשִֽׂינוּ מַה־שֶּׁגָּזַֽרְתָּ עָלֵֽינוּ, עַשֵׂה אַתָּה מַה־שֶּׁהִבְטָחְתָּֽנוּ. הַשְׁקִ֩יפָה֩ מִמְּע֨וֹן קׇדְשְׁךָ֜ מִן־הַשָּׁמַ֗יִם וּבָרֵ֤ךְ אֶֽת־עַמְּךָ֙ אֶת־יִשְׂרָאֵ֔ל:"}, {"kind": "instruction", "text": "אם אין עולים כהנים אומר החזן:<br>אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, בָּרְכֵנוּ בַּבְּרָכָה הַמְשֻׁלֶּשֶת בַּתּוֹרָה הַכְּתוּבָה עַל יְדֵי מֹשֶׁה עַבְדֶּֽךָ, הָאֲמוּרָה מִפִּי אַהֲרֹן וּבָנָיו הַכֹּהֲנִים עַם קְדוֹשֶׁיךָ כָּאָמוּר:"}, {"kind": "text", "text": "יְבָרֶכְךָ֥ יְהֹוָ֖ה וְיִשְׁמְרֶֽךָ׃ ועונים כֵּן יְהִי רָצוֹן:"}, {"kind": "text", "text": "יָאֵ֨ר יְהֹוָ֧ה ׀ פָּנָ֛יו אֵלֶ֖יךָ וִֽיחֻנֶּֽךָּ׃ ועונים כֵּן יְהִי רָצוֹן:"}, {"kind": "text", "text": "יִשָּׂ֨א יְהֹוָ֤ה ׀ פָּנָיו֙ אֵלֶ֔יךָ וְיָשֵׂ֥ם לְךָ֖ שָׁלֽוֹם׃ ועונים כֵּן יְהִי רָצוֹן: וְשָׂמ֥וּ אֶת־שְׁמִ֖י עַל־בְּנֵ֣י יִשְׂרָאֵ֑ל וַאֲנִ֖י אֲבָרְכֵֽם:"}, {"kind": "text", "text": "<b>שִׂים</b> שָׁלוֹם טוֹבָה וּבְרָכָה, חַיִּים חֵן וָחֶֽסֶד וְרַֽחֲמִים, עָלֵֽינוּ וְעַל כָּל־יִשְׂרָאֵל עַמֶּֽךָ. וּבָֽרְכֵֽנוּ אָבִֽינוּ כֻּלָּֽנוּ כְּאֶחָד בְּאוֹר פָּנֶֽיךָ, כִּי בְאוֹר פָּנֶֽיךָ נָתַֽתָּ לָּֽנוּ יְהֹוָה אֱלֹהֵֽינוּ תּוֹרָה וְחַיִּים, אַֽהֲבָה וָחֶֽסֶד, צְדָקָה וְרַֽחֲמִים, בְּרָכָה וְשָׁלוֹם. וְטוֹב בְּעֵינֶֽיךָ לְבָֽרְכֵֽנוּ וּלְבָרֵךְ אֶת־כָּל־עַמְּךָ יִשְׂרָאֵל, בְּרֹב עֹז וְשָׁלוֹם: בָּרוּךְ אַתָּה יוּהוּווּהוּ, הַמְּבָרֵךְ אֶת עַמּוֹ יִשְׂרָאֵל בַּשָּׁלוֹם. אָמֵן:"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>אֱלֹהַי</b>, נְצֹר לְשׁוֹנִי מֵרָע וְשִׂפְתוֹתַי מִדַּבֵּר מִרְמָה, וְלִמְקַלְלַי נַפְשִׁי תִדֹּם, וְנַפְשִׁי כֶּֽעָפָר לַכֹּל תִּֽהְיֶה, פְּתַח לִבִּי בְּתוֹרָתֶֽךָ, וְאַחֲרֵי מִצְוֹתֶֽיךָ תִּרְדֹּף נַפְשִׁי. וְכָל־הַקָּמִים עָלַי לְרָעָה, מְהֵרָה הָפֵר עֲצָתָם וְקַלְקֵל מַחְשְׁבוֹתָם. יִֽהְי֗וּ כְּמֹ֥ץ לִפְנֵי־ר֑וּחַ וּמַלְאַ֖ךְ יְהֹוָ֣ה דּוֹחֶֽה. קַבֵּל רִנַּת עַמֶּךָ. שַׂגְּבֵנוּ טַהֲרֵנוּ נוֹרָא. עֲשֵׂה לְמַֽעַן שְׁמָךְ, עֲשֵׂה לְמַֽעַן יְמִינָךְ, עֲשֵׂה לְמַֽעַן תּֽוֹרָתָךְ, עֲשֵׂה לְמַֽעַן קְדֻשָּׁתָךְ."}, {"kind": "text", "text": "סגולה לומר פסוק המתחיל וגומר באות שמתחיל וגומר שמו לְ֭מַעַן יֵחָלְצ֣וּן יְדִידֶ֑יךָ הוֹשִׁ֖יעָה יְמִֽינְךָ֣ וַעֲנֵֽנִי:"}, {"kind": "text", "text": "<b>יִֽהְי֥וּ</b> לְרָצ֨וֹן ׀ אִמְרֵי־פִ֡י וְהֶגְי֣וֹן לִבִּ֣י לְפָנֶ֑יךָ יְ֝הֹוָ֗ה צוּרִ֥י וְגֹאֲלִֽי׃"}, {"kind": "text", "text": "<b>עֹשֶׂה</b> שָׁלוֹם בִּמְרוֹמָיו, הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵֽינוּ, וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן:"}, {"kind": "instruction", "text": "יְהִי רָצוֹן מִלְּפָנֶיךָ יְהֹוָה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּבְנֶה בֵּית הַמִּקְדָּשׁ בִּמְהֵרָה בְּיָמֵינוּ, וְתֵן חֶלְקֵנוּ בְּתוֹרָתָךְ, לַעֲשׂוֹת חֻקֵּי רְצוֹנָךְ וּלְעָבְדָךְ בְּלֵבָב שָׁלֵם:"}, {"kind": "instruction", "text": "אחרי החזרה אומרים"}, {"kind": "text", "text": "<b>יְהִ֤י</b> שֵׁ֣ם יְהֹוָ֣ה מְבֹרָ֑ךְ מֵ֝עַתָּ֗ה וְעַד־עוֹלָֽם׃ מִמִּזְרַח־שֶׁ֥מֶשׁ עַד־מְבוֹא֑וֹ מְ֝הֻלָּ֗ל שֵׁ֣ם יְהֹוָֽה׃ רָ֖ם עַל־כׇּל־גּוֹיִ֥ם ׀ יְהֹוָ֑ה עַ֖ל הַשָּׁמַ֣יִם כְּבוֹדֽוֹ׃ יְהֹוָ֥ה אֲדֹנֵ֑ינוּ מָה־אַדִּ֥יר שִׁ֝מְךָ֗ בְּכׇל־הָאָֽרֶץ׃"}, {"kind": "instruction", "text": "בערבית ליל יום טוב, אחרי תפילת העמידה, אם חל בשבת אומרים ויכולו, והחזן אומר ברכת מעין שבע וקדיש תתקבל. ואם חל בחול אומרים יהי שם, והחזן אומר קדיש תתקבל. ובליל יום טוב ראשון של פסח, אחרי העמידה גומרים את ההלל בברכה תחילה וסוף, ואחר כך החזן אומר קדיש תתקבל, ואם חל בשבת אומרים ויכולו ומעין שבע, ויברכו על ההלל."}, {"kind": "text", "text": "אחרי קדיש תתקבל אומרים מזמורים אלו:"}, {"kind": "instruction", "text": "אם חל בשבת מוסיפים מזמור זה"}, {"kind": "text", "text": "<b>מִזְמ֥וֹר</b> (תהילים כ״ג) לְדָוִ֑ד יְהֹוָ֥ה רֹ֝עִ֗י לֹ֣א אֶחְסָֽר׃ בִּנְא֣וֹת דֶּ֭שֶׁא יַרְבִּיצֵ֑נִי עַל מֵ֖י מְנֻח֣וֹת יְנַהֲלֵֽנִי׃ נַפְשִׁ֥י יְשׁוֹבֵ֑ב יַֽנְחֵ֥נִי בְמַעְגְּלֵי־צֶ֝֗דֶק לְמַ֣עַן שְׁמֽוֹ׃ גַּ֤ם כִּֽי־אֵלֵ֨ךְ בְּגֵ֪יא צַלְמָ֡וֶת לֹא־אִ֘ירָ֤א רָ֗ע כִּי־אַתָּ֥ה עִמָּדִ֑י שִׁבְטְךָ֥ וּ֝מִשְׁעַנְתֶּ֗ךָ הֵ֣מָּה יְנַֽחֲמֻֽנִי׃ תַּעֲרֹ֬ךְ לְפָנַ֨י ׀ שֻׁלְחָ֗ן נֶ֥גֶד צֹרְרָ֑י דִּשַּׁ֥נְתָּ בַשֶּׁ֥מֶן רֹ֝אשִׁ֗י כּוֹסִ֥י רְוָיָֽה אַ֤ךְ ׀ ט֤וֹב וָחֶ֣סֶד יִ֭רְדְּפוּנִי כׇּל־יְמֵ֣י חַיָּ֑י וְשַׁבְתִּ֥י בְּבֵית־יְ֝הֹוָ֗ה לְאֹ֣רֶךְ יָמִֽים׃"}, {"kind": "instruction", "text": "בפסח אומרים"}, {"kind": "text", "text": "<b>בְּצֵ֣את</b> (תהילים קי״ד) יִ֭שְׂרָאֵל מִמִּצְרָ֑יִם בֵּ֥ית יַ֝עֲקֹ֗ב מֵעַ֥ם לֹעֵֽז׃ הָיְתָ֣ה יְהוּדָ֣ה לְקׇדְשׁ֑וֹ יִ֝שְׂרָאֵ֗ל מַמְשְׁלוֹתָֽיו׃ הַיָּ֣ם רָ֭אָה וַיָּנֹ֑ס הַ֝יַּרְדֵּ֗ן יִסֹּ֥ב לְאָחֽוֹר׃ הֶ֭הָרִים רָקְד֣וּ כְאֵילִ֑ים גְּ֝בָע֗וֹת כִּבְנֵי־צֹֽאן׃ מַה־לְּךָ֣ הַ֭יָּם כִּ֣י תָנ֑וּס הַ֝יַּרְדֵּ֗ן תִּסֹּ֥ב לְאָחֽוֹר׃ הֶ֭הָרִים תִּרְקְד֣וּ כְאֵילִ֑ים גְּ֝בָע֗וֹת כִּבְנֵי־צֹֽאן׃ מִלִּפְנֵ֣י אָ֭דוֹן ח֣וּלִי אָ֑רֶץ מִ֝לִּפְנֵ֗י אֱל֣וֹהַּ יַעֲקֹֽב׃ הַהֹפְכִ֣י הַצּ֣וּר אֲגַם־מָ֑יִם חַ֝לָּמִ֗ישׁ לְמַעְיְנוֹ־מָֽיִם׃"}, {"kind": "instruction", "text": "בשבועות, סוכות, ושמיני עצרת אומרים"}, {"kind": "text", "text": "<b>שִׁ֥יר</b> (תהילים קכ״ב) הַֽמַּעֲל֗וֹת לְדָ֫וִ֥ד שָׂ֭מַחְתִּי בְּאֹמְרִ֣ים לִ֑י בֵּ֖ית יְהֹוָ֣ה נֵלֵֽךְ׃ עֹ֭מְדוֹת הָי֣וּ רַגְלֵ֑ינוּ בִּ֝שְׁעָרַ֗יִךְ יְרוּשָׁלָֽ‍ִם׃ יְרוּשָׁלַ֥‍ִם הַבְּנוּיָ֑ה כְּ֝עִ֗יר שֶׁחֻבְּרָה־לָּ֥הּ יַחְדָּֽו׃ שֶׁשָּׁ֨ם עָל֪וּ שְׁבָטִ֡ים שִׁבְטֵי־יָ֭הּ עֵד֣וּת לְיִשְׂרָאֵ֑ל לְ֝הֹד֗וֹת לְשֵׁ֣ם יְהֹוָֽה׃ כִּ֤י שָׁ֨מָּה ׀ יָשְׁב֣וּ כִסְא֣וֹת לְמִשְׁפָּ֑ט כִּ֝סְא֗וֹת לְבֵ֣ית דָּוִֽד׃ שַׁ֭אֲלוּ שְׁל֣וֹם יְרוּשָׁלָ֑‍ִם יִ֝שְׁלָ֗יוּ אֹהֲבָֽיִךְ׃ יְהִי־שָׁל֥וֹם בְּחֵילֵ֑ךְ שַׁ֝לְוָ֗ה בְּאַרְמְנוֹתָֽיִךְ׃ לְ֭מַעַן אַחַ֣י וְרֵעָ֑י אֲדַבְּרָה־נָּ֖א שָׁל֣וֹם בָּֽךְ׃ לְ֭מַעַן בֵּית־יְהֹוָ֣ה אֱלֹהֵ֑ינוּ אֲבַקְשָׁ֖ה ט֣וֹב לָֽךְ׃"}, {"kind": "instruction", "text": "ואומרים קדיש יהא שלמא"}, {"kind": "text", "text": "<b>יִתְגַּדַּל</b> וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא. [אָמֵן] בְּעָלְמָא דִּי בְרָא, כִּרְעוּתֵה, וְיַמְלִיךְ מַלְכוּתֵה, וְיַצְמַח פֻּרְקָנֵה, וִיקָרֵב מְשִׁיחֵהּ. [אָמֵן] בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן. [אָמֵן] יְהֵא שְׁמֵיהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא, בְּרִיךְ הוּא. [אָמֵן] לְעֵלָּא מִן כָּל בִּרְכָתָא שִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>יְהֵא</b> שְׁלָמָא רַבָּא מִן שְׁמַיָּא. חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה. וְשֵׁיזָבָא וּרְפוּאָה וּגְאוּלָה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]<br><br><b>עוֹשֶׂה</b> שָׁלוֹם בִּמְרוֹמָיו. הוּא בְּרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל־עַמּוֹ יִשְׂרָאֵל. וְאִמְרוּ אָמֵן. [אָמֵן]"}, {"kind": "text", "text": "<b>עָלֵֽינוּ</b> לְשַׁבֵּֽחַ לַֽאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָֽׂנוּ כְּגוֹיֵי הָֽאֲרָצוֹת, וְלֹא שָׂמָֽנוּ כְּמִשְׁפְּחוֹת הָֽאֲדָמָה, שֶׁלֹּא שָׂם חֶלְקֵֽנוּ כָּהֶם וְגוֹרָלֵֽנוּ כְּכָל־הֲמוֹנָם, שֶׁהֵם מִשְׁתַּֽחֲוִים לָהֶֽבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל־אֵל לֹֽא יוֹשִׁיעַ. וַֽאֲנַֽחְנוּ מִשְׁתַּחֲוִים לִפְנֵי מֶֽלֶךְ מַלְכֵי הַֽמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַֽיִם וְיוֹסֵד אָֽרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַֽיִם מִמַּֽעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵֽינוּ, וְאֵין עוֹד אַחֵר, אֱמֶת מַלְכֵּֽנוּ וְאֶֽפֶס זוּלָתוֹ. כַּכָּתוּב בַּתּוֹרָה. וְיָדַעְתָּ֣ הַיּ֗וֹם וַהֲשֵׁבֹתָ֮ אֶל־לְבָבֶךָ֒ כִּ֤י יְהֹוָה֙ ה֣וּא הָֽאֱלֹהִ֔ים בַּשָּׁמַ֣יִם מִמַּ֔עַל וְעַל־הָאָ֖רֶץ מִתָּ֑חַת אֵ֖ין עֽוֹד:"}, {"kind": "text", "text": "<b>עַל</b> כֵּן נְקַוֶּה לָךְ, יְהֹוָה אֱלֹהֵֽינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶֽרֶת עֻזָּךְ, לְהַֽעֲבִיר גִּלּוּלִים מִן הָאָֽרֶץ, וְהָֽאֱלִילִים כָּרוֹת יִכָּֽרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל־בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶֽךָ, לְהַפְנוֹת אֵלֶֽיךָ כָּל־רִשְׁעֵי אָֽרֶץ. יַכִּֽירוּ וְיֵֽדְעוּ כָּל־יֽוֹשְׁבֵי תֵבֵֽל, כִּי לְךָ תִכְרַע כָּל־בֶּֽרֶךְ, תִּשָּׁבַע כָּל־לָשׁוֹן. לְפָנֶֽיךָ, יְהֹוָה אֱלֹהֵֽינוּ יִכְרְעוּ וְיִפֹּֽלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּֽנוּ, וִיקַבְּלוּ כֻלָּם אֶת־עֹל מַלְכוּתֶֽךָ, וְתִמְלוֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעֽוֹלְמֵי עַד תִּמְלוֹךְ בְּכָבוֹד. כַּכָּתוּב בְּתוֹרָתָךְ: יְהֹוָ֥ה ׀ יִמְלֹ֖ךְ לְעֹלָ֥ם וָעֶֽד׃ וְנֶאֱמַר. וְהָיָ֧ה יְהֹוָ֛ה לְמֶ֖לֶךְ עַל־כָּל־הָאָ֑רֶץ בַּיּ֣וֹם הַה֗וּא יִהְיֶ֧ה יְהֹוָ֛ה אֶחָ֖ד וּשְׁמ֥וֹ אֶחָֽד׃"}, {"kind": "instruction", "text": "וּבְתוֹרָתְךָ יְהֹוָה אֱלֹהֵינוּ כָּתוּב לֵּאמֹר. שְׁמַ֖ע יִשְׂרָאֵ֑ל יְהֹוָ֥ה אֱלֹהֵ֖ינוּ יְהֹוָ֥ה ׀ אֶחָֽד׃"}]}};
